INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20885, 'Starorzecze Rogalinek', 'starorzecze-rogalinek-rogalinek-20885', 'OXBOW', 52.2578051, 16.8912883, 'Wielkopolskie', 'Rogalinek', 'To malownicze starorzecze, położone w pobliżu Rogalinka, charakteryzuje się spokojnym charakterem i bogactwem przyrodniczym. Dno jest przeważnie muliste, z twardszymi fragmentami gliniastymi w głębszych partiach. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je gęsta roślinność szuwarowa, co wymaga ostrożności. Obficie występują tu grążele i lilie wodne, tworzące doskonałe kryjówki dla ryb. W starorzeczu dominują takie gatunki jak lin, szczupak, płoć i leszcz, a w cieplejszych miesiącach można liczyć na spotkanie z karpiem. Łowisko jest połączone z Wartą podczas wysokiego stanu wody, co sprzyja migracji ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20885, 3.2, 1.8, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Szczupak,Płoć,Leszcz', 'Miejscami dostępny, zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20886, 'Starorzecze Warta (Poznań)', 'starorzecze-warta-poznan-poznan-20886', 'OXBOW', 52.3444007, 16.9143779, 'Wielkopolskie', 'Poznań', 'To niewielkie starorzecze w granicach Poznania, stanowi typowy przykład zbiornika silnie zarośniętego. Dno jest bardzo muliste, z grubą warstwą osadów dennych, co świadczy o zaawansowanym procesie zamulania. Brzegi są niemal w całości niedostępne, gęsto porośnięte trzciną i inną roślinnością szuwarową. Latem bujna roślinność podwodna, taka jak rdestnice i moczarka, jest wszechobecna, co może utrudniać wędkowanie. Zbiornik jest domem dla licznych karasi pospolitych, linów, wzdręg i płoci. Ze względu na płytkość i silne zarośnięcie, istnieje ryzyko przyduchy, zwłaszcza w upalne lata i zimą pod lodem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20886, 1.5, 1.2, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20887, 'Starorzecze Warta (Poznań) Północne', 'starorzecze-warta-poznan-polnocne-poznan-20887', 'OXBOW', 52.3445004, 16.915488, 'Wielkopolskie', 'Poznań', 'To starorzecze, również położone w obrębie Poznania, oferuje nieco lepsze warunki dostępu niż sąsiednie zbiorniki. Dno jest mieszane, z przewagą mułu, ale z twardszymi partiami żwirowo-piaszczystymi. Brzegi są częściowo dostępne, zwłaszcza od strony południowej, gdzie teren jest bardziej ukształtowany. Roślinność wodna jest umiarkowana, z dominacją trzcin i grążeli w płytszych zatokach. Łowisko to jest znane z populacji leszczy, płoci, okoni i szczupaków, które znajdują tu dogodne warunki do żerowania. Brak stałego połączenia z rzeką sprawia, że ekosystem jest stabilny, choć wymaga uwagi w okresach suszy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20887, 1.8, 1.5, 3.2, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak', 'Dobry z jednej strony, reszta zarośnięta', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20888, 'Starorzecze Radzewice Północne', 'starorzecze-radzewice-polnocne-radzewice-20888', 'OXBOW', 52.209734, 16.9848884, 'Wielkopolskie', 'Radzewice', 'To płytkie starorzecze w pobliżu Radzewic jest przykładem zbiornika o zaawansowanym procesie sukcesji. Dno jest bardzo muliste i miękkie, co utrudnia brodzenie i ustawienie sprzętu. Brzegi są w większości bagniste i silnie zarośnięte, co sprawia, że dostęp do wody jest wyjątkowo trudny. Latem zbiornik jest niemal całkowicie pokryty roślinnością nawodną i podwodną, taką jak rzęsa wodna i moczarka kanadyjska. W okresach długotrwałej suszy starorzecze potrafi całkowicie wyschnąć, co ma negatywny wpływ na populację ryb. Dominują tu gatunki odporne, takie jak karaś pospolity, lin i wzdręga, które potrafią przetrwać trudne warunki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20888, 2.1, 1, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna, pojedyncze gałęzie', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20889, 'Starorzecze Radzewice Środkowe', 'starorzecze-radzewice-srodkowe-radzewice-20889', 'OXBOW', 52.2082568, 16.9842939, 'Wielkopolskie', 'Radzewice', 'To starorzecze, zlokalizowane w środkowej części kompleksu w Radzewicach, oferuje bardziej zróżnicowane warunki. Dno jest muliste, ale z twardszymi, piaszczystymi fragmentami, szczególnie wzdłuż dawnego nurtu rzeki. Brzegi są częściowo dostępne, choć wędkarz musi liczyć się z koniecznością przedzierania się przez zarośla i miejscowe podmokłości. Roślinność wodna jest umiarkowana, z dominacją trzcin i grążeli w płytszych rejonach. Łowisko to jest atrakcyjne dla miłośników drapieżników, takich jak szczupak i okoń, ale także dla wędkarzy białorybu, polujących na płocie i leszcze. Połączenie z Wartą podczas wysokiej wody co roku odświeża populację ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20889, 2.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Miejscami dostępny, zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20890, 'Starorzecze Radzewice Południowe', 'starorzecze-radzewice-poludniowe-radzewice-20890', 'OXBOW', 52.2077107, 16.9863678, 'Wielkopolskie', 'Radzewice', 'Ostatnie z radzewickich starorzeczy jest najpłytsze i najbardziej zarośnięte, co sprawia, że jest to łowisko dla wytrwałych. Dno jest niemal w całości pokryte grubą warstwą miękkiego mułu, a głębokość rzadko przekracza dwa metry. Brzegi są praktycznie niedostępne dla wędkarzy, chronione przez gęste kępy trzcin i krzewów, a także podmokłe tereny. Roślinność wodna jest ekstremalnie bujna, tworząc zielony dywan na powierzchni wody latem. W zbiorniku dominują karasie (srebrzysty i pospolity) oraz wzdręgi, które doskonale radzą sobie w trudnych warunkach. Wysokie ryzyko przyduchy i możliwość całkowitego wyschnięcia latem czynią to miejsce wymagającym.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20890, 1.9, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Karaś pospolity,Wzdręga', 'Bardzo trudny, gęste zarośla i muł', TRUE, 'Gęsta roślinność podwodna, dużo zatopionych gałęzi', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20891, 'Starorzecze Rogalin Północne', 'starorzecze-rogalin-polnocne-rogalin-20891', 'OXBOW', 52.240283, 16.907879, 'Wielkopolskie', 'Rogalin', 'To jedno z większych starorzeczy w kompleksie rogalńskim, znane z dobrego dostępu i różnorodności ryb. Dno jest zróżnicowane, z przewagą gliny i piasku, choć w głębszych partiach występuje warstwa mułu. Brzegi są w dużej mierze dostępne dla wędkarzy, z kilkoma utwardzonymi stanowiskami, co jest rzadkością w starorzeczach. Roślinność wodna jest umiarkowana, z pasami trzcin i grążeli, które nie utrudniają znacząco wędkowania. W zbiorniku występują duże okazy szczupaków, linów i karpi, a także liczne leszcze i okonie. Łowisko jest regularnie zasilane wodami Warty podczas wiosennych roztopów, co sprzyja rozwojowi populacji ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20891, 4, 2, 5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Karp,Leszcz,Okoń', 'Dobry z obu stron, miejscami utwardzony', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20892, 'Starorzecze Rogalin Zachodnie', 'starorzecze-rogalin-zachodnie-rogalin-20892', 'OXBOW', 52.2404747, 16.9073109, 'Wielkopolskie', 'Rogalin', 'To starorzecze charakteryzuje się bardziej dzikim charakterem, z licznymi zatopionymi drzewami i gałęziami, które tworzą doskonałe kryjówki dla ryb. Dno jest muliste, ale z twardszymi fragmentami, gdzie można znaleźć żwir i piasek. Brzegi są częściowo dostępne, jednak w wielu miejscach są bagniste i wymagają użycia woderów. Roślinność wodna jest obfita, zwłaszcza w postaci grążeli i rdestnic, które tworzą gęste dywany. W zbiorniku można liczyć na spotkanie z okazałymi linami i karpiami, a także licznymi płociami i sporadycznie węgorzami. Zaczepy są częste, co wymaga stosowania mocniejszego sprzętu i cierpliwości.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20892, 3.5, 1.7, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karp,Płoć,Węgorz', 'Trudny, bagnisty w niektórych miejscach', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20893, 'Starorzecze Rogalin Południowe', 'starorzecze-rogalin-poludniowe-rogalin-20893', 'OXBOW', 52.2374669, 16.9142278, 'Wielkopolskie', 'Rogalin', 'To starorzecze, położone w południowej części Rogalina, jest typowym zbiornikiem o wysokim stopniu zamulenia i zarośnięcia. Dno jest bardzo miękkie i muliste, co utrudnia poruszanie się w wodzie i stwarza ryzyko utknięcia. Brzegi są niemal w całości pokryte gęstymi pasami trzcin i innych roślin szuwarowych, co znacznie ogranicza dostęp do wody. Roślinność podwodna jest bujna przez większość sezonu, tworząc gęste zarośla. W zbiorniku dominują gatunki takie jak karaś pospolity, karaś srebrzysty, wzdręga i lin, które doskonale adaptują się do trudnych warunków. W upalne lato istnieje podwyższone ryzyko przyduchy, co może negatywnie wpływać na populację ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20893, 2.8, 1.4, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Karaś srebrzysty,Wzdręga,Lin', 'Mocno zarośnięty trzciną, ograniczony dostęp', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20894, 'Starorzecze Baranowo Północne', 'starorzecze-baranowo-polnocne-baranowo-20894', 'OXBOW', 52.2357638, 16.9150131, 'Wielkopolskie', 'Baranowo', 'To niewielkie starorzecze w Baranowie jest jednym z najbardziej wymagających łowisk w okolicy. Charakteryzuje się bardzo płytkim i mulistym dnem, które w wielu miejscach jest miękkie i grząskie. Brzegi są niemal całkowicie niedostępne, chronione przez gęste zarośla krzewów i trzcin, a także podmokłe tereny. Roślinność wodna jest ekstremalnie bujna, tworząc latem niemal jednolity zielony dywan na powierzchni. W okresach suszy starorzecze często wysycha, co sprawia, że jest to środowisko dla najbardziej odpornych gatunków, takich jak karaś pospolity, wzdręga i płoć. Ryzyko przyduchy jest bardzo wysokie, szczególnie w upalne lata.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20894, 1.2, 0.8, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Bardzo trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna, muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20895, 'Starorzecze Baranowo Środkowe', 'starorzecze-baranowo-srodkowe-baranowo-20895', 'OXBOW', 52.2358493, 16.9144777, 'Wielkopolskie', 'Baranowo', 'To starorzecze w Baranowie, choć niewielkie, oferuje lepsze warunki wędkowania niż jego sąsiedzi. Dno jest muliste, ale z twardszymi, gliniastymi fragmentami, co ułatwia brodzenie w niektórych miejscach. Brzegi są częściowo dostępne, choć wędkarz musi liczyć się z koniecznością przedzierania się przez zarośla i miejscowe podmokłości. Roślinność wodna jest umiarkowana, z dominacją trzcin i grążeli w płytszych zatokach. W zbiorniku można znaleźć liny, szczupaki, płocie i okonie, które chętnie żerują w zacisznych zakamarkach. Połączenie z Wartą podczas wysokiej wody co jakiś czas odświeża populację ryb, wprowadzając nowe osobniki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20895, 1.5, 1, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Szczupak,Płoć,Okoń', 'Miejscami dostępny, zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20896, 'Starorzecze Baranowo Południowe', 'starorzecze-baranowo-poludniowe-baranowo-20896', 'OXBOW', 52.2352029, 16.9135634, 'Wielkopolskie', 'Baranowo', 'To najmniejsze i najpłytsze ze starorzeczy w Baranowie, charakteryzujące się ekstremalnie trudnym dostępem. Dno jest bardzo miękkie i grząskie, w całości pokryte grubą warstwą mułu, co sprawia, że poruszanie się jest niemal niemożliwe. Brzegi są całkowicie niedostępne, chronione przez gęste zarośla, bagniste tereny i zwalone drzewa. Roślinność wodna jest dominująca, tworząc niemal jednolity zielony dywan na powierzchni wody. Ze względu na płytkość i brak połączenia z rzeką, zbiornik często wysycha w okresach suszy i jest narażony na przyduchy. Występują tu jedynie najbardziej odporne gatunki, takie jak karaś pospolity i wzdręga.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20896, 1, 0.7, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga', 'Ekstremalnie trudny, bagnisty, gęste zarośla', TRUE, 'Gęsta roślinność podwodna, zwalone gałęzie', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20897, 'Starorzecze Rogalin Wschodnie', 'starorzecze-rogalin-wschodnie-rogalin-20897', 'OXBOW', 52.2363435, 16.9126076, 'Wielkopolskie', 'Rogalin', 'To starorzecze w Rogalinie oferuje zróżnicowane warunki dla wędkarzy, z częściowo dobrym dostępem. Dno jest mieszane, z przewagą mułu, ale z twardszymi partiami gliniastymi, co umożliwia wygodne ustawienie sprzętu. Brzegi są dostępne od strony wschodniej, gdzie teren jest bardziej otwarty, natomiast zachodnia strona jest bardziej zarośnięta. Roślinność wodna jest umiarkowana, z pasami trzcin i grążeli, które tworzą atrakcyjne kryjówki dla ryb. W zbiorniku można liczyć na połów leszczy, płoci, karpi, a także okazjonalnie suma i szczupaka. Połączenie z Wartą podczas wysokiej wody sprzyja wzbogacaniu populacji rybnej.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20897, 3, 1.6, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sum,Szczupak', 'Dobry z jednej strony, reszta zarośnięta', FALSE, 'Pojedyncze korzenie i gałęzie, zwalone drzewa', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20898, 'Starorzecze Rogalin Centralne', 'starorzecze-rogalin-centralne-rogalin-20898', 'OXBOW', 52.238343, 16.909724, 'Wielkopolskie', 'Rogalin', 'To jedno z najbardziej atrakcyjnych starorzeczy w okolicy Rogalina, charakteryzujące się stałym połączeniem z Wartą. Dzięki temu woda jest dobrze natleniona, a populacja ryb dynamicznie się odnawia. Dno jest przeważnie piaszczysto-gliniaste, z niewielką ilością mułu, co świadczy o aktywnym przepływie wody. Brzegi są dobrze dostępne z obu stron, co ułatwia wędkowanie i poruszanie się wokół zbiornika. Roślinność wodna jest słaba do umiarkowanej, z przewagą trzcin w płytszych zatokach. W zbiorniku występują liczne szczupaki, sandacze, leszcze, płocie i okonie, co czyni go rajem dla wędkarzy. Jest to idealne miejsce na całosezonowe wypady, oferujące różnorodne możliwości połowu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20898, 4.5, 2.2, 5.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno, pojedyncze korzenie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20899, 'Starorzecze Rogalin Północno-Zachodnie', 'starorzecze-rogalin-polnocno-zachodnie-rogalin-20899', 'OXBOW', 52.2396717, 16.907662, 'Wielkopolskie', 'Rogalin', 'To starorzecze, usytuowane w północno-zachodniej części Rogalina, jest cenionym łowiskiem, choć wymaga pewnego wysiłku. Dno jest zróżnicowane, z przewagą mułu, ale z licznymi twardszymi fragmentami gliniastymi i piaszczystymi. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je gęsta trzcina, co utrudnia dojście do wody. W zbiorniku występuje sporo zatopionych drzew i gałęzi, które stanowią doskonałe kryjówki dla ryb, ale także potencjalne zaczepy. Dominują tu liny, szczupaki, karpie, okonie, a także sporadycznie można spotkać węgorza. Połączenie z Wartą podczas wysokiej wody wzbogaca bioróżnorodność i sprzyja utrzymaniu zdrowej populacji ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20899, 3.8, 1.9, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Szczupak,Karp,Okoń,Węgorz', 'Miejscami dostępny, zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew i gałęzi', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20900, 'Starorzecze (Sowiniec)', 'starorzecze-sowiniec-sowiniec-20900', 'OXBOW', 52.2356927, 16.9025002, 'Wielkopolskie', 'Sowiniec', 'To malownicze starorzecze, położone w pobliżu miejscowości Sowiniec, charakteryzuje się umiarkowanym zarośnięciem brzegów i dna. Dno jest muliste z licznymi zatopionymi korzeniami, co sprzyja bytności drapieżników takich jak szczupak i okoń. Brzegi są stosunkowo łatwo dostępne, choć miejscami występują kępy trzcin i pałki wodnej. Wiosną i wczesną jesienią wędkarze mogą liczyć na obfite połowy lina i płoci, które chętnie żerują w płytszych partiach. Łowisko jest zasilane wodą z Warty podczas wysokich stanów, co zapewnia dopływ świeżej wody i ryb. Pomimo obecności roślinności, ryzyko przyduchy jest niskie, co sprzyja rozwojowi zdrowej populacji ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20900, 3.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Płoć,Leszcz,Okoń', 'Dobry z niektórych stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20901, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20901', 'OXBOW', 52.2364265, 16.9097495, 'Wielkopolskie', 'Rogalin', 'To starorzecze w Rogalinie to typowy, silnie zarośnięty akwen, idealny dla wędkarzy ceniących dziką przyrodę. Charakteryzuje się wysokim poziomem zamulenia i gęstą roślinnością podwodną, co utrudnia wędkowanie, ale sprzyja występowaniu karasia pospolitego i lina. Brzegi są mocno zarośnięte trzciną, co wymaga użycia wodoodpornych spodni i dużej cierpliwości. Ze względu na brak stałego połączenia z rzeką i dużą ilość materii organicznej, istnieje podwyższone ryzyko przyduchy, zwłaszcza w upalne lata. Najlepsze wyniki można osiągnąć późną wiosną i latem, polując na ryby spokojnego żeru w prześwitach między roślinnością. Wzdręga i płoć również licznie występują w tym płytkim i ciepłym środowisku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20901, 2.8, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20902, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20902', 'OXBOW', 52.2354586, 16.908285, 'Wielkopolskie', 'Rogalin', 'To starorzecze oferuje dobre warunki do wędkowania, z łatwo dostępnymi brzegami i umiarkowanym zarośnięciem. Dno jest zróżnicowane, z miejscami mulistymi i twardszymi partiami, gdzie można znaleźć pojedyncze korzenie i gałęzie. Podczas wysokiego poziomu wody, akwen łączy się z głównym nurtem Warty, co wzbogaca populację ryb o nowe osobniki. Jest to doskonałe miejsce na szczupaka i okonia, które często kryją się wśród roślinności i w pobliżu zatopionych przeszkód. Lin, leszcz i płoć również występują licznie, szczególnie w głębszych partiach starorzecza. Ryzyko przyduchy jest niskie, co zapewnia stabilne warunki przez większość sezonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20902, 4.1, 1.8, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20903, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20903', 'OXBOW', 52.2421535, 16.90569, 'Wielkopolskie', 'Rogalin', 'To większe starorzecze w Rogalinie jest cenionym łowiskiem, charakteryzującym się stosunkowo niskim poziomem zamulenia i umiarkowanym zarośnięciem. Dno jest urozmaicone, z licznymi zatopionymi drzewami, które stanowią doskonałe kryjówki dla drapieżników, takich jak szczupak i sandacz. Brzegi są dostępne z kilku stron, co ułatwia wybór stanowiska. Akwen łączy się z rzeką podczas wysokiej wody, co zapewnia regularne zarybienia naturalne i utrzymanie zdrowej populacji ryb. Jest to świetne miejsce na leszcza i płoć przez cały sezon, a także na okonia. Ryzyko przyduchy jest minimalne dzięki dobrej cyrkulacji wody. Wędkarze mogą spodziewać się udanych połowów od wiosny do jesieni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20903, 7.2, 2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Okoń', 'Dobry z niektórych stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20904, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20904', 'OXBOW', 52.239054, 16.9056668, 'Wielkopolskie', 'Rogalin', 'To niewielkie starorzecze to prawdziwa ostoja dla ryb spokojnego żeru, lecz jego dostępność jest ograniczona. Charakteryzuje się wysokim poziomem zamulenia i bardzo gęstą roślinnością podwodną, co sprawia, że wędkowanie jest wyzwaniem. Brzegi są trudne, bagniste i mocno zarośnięte, co wymaga użycia wodoodpornych spodni i odpowiedniego sprzętu. Akwen nie ma stałego połączenia z rzeką, co w połączeniu z płytką wodą i dużą ilością materii organicznej, prowadzi do wysokiego ryzyka przyduchy, a w skrajnych suszach może nawet wysychać. Dominują tu karasie pospolite, liny i wzdręgi, które dobrze radzą sobie w trudnych warunkach. Najlepsze efekty daje wędkowanie wczesnym latem, zanim roślinność osiągnie swój szczyt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20904, 1.9, 1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20905, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20905', 'OXBOW', 52.2328974, 16.9270867, 'Wielkopolskie', 'Rogalin', 'To starorzecze wyróżnia się stałym połączeniem z Wartą, co zapewnia doskonałe warunki tlenowe i regularne zarybienia naturalne. Dno jest stosunkowo czyste, z niewielkim zamuleniem, co sprzyja różnorodności gatunkowej ryb. Brzegi są łatwo dostępne z obu stron, co czyni to miejsce atrakcyjnym dla wędkarzy. Jest to idealne łowisko na leszcza, płoć i karpia, które chętnie żerują na twardszym dnie. Drapieżniki takie jak szczupak i okoń również licznie występują, wykorzystując otwarte przestrzenie i dostępność pokarmu. Brak ryzyka przyduchy i wysychania sprawia, że jest to łowisko całoroczne, oferujące stabilne warunki przez cały sezon. Można tu spodziewać się dużych okazów ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20905, 5, 1.7, 3.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20906, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20906', 'OXBOW', 52.2247998, 16.9343929, 'Wielkopolskie', 'Rogalin', 'To rozległe starorzecze jest znane z głębszych partii i obfitości zatopionych drzew, które stanowią schronienie dla dużych drapieżników, w tym suma i szczupaka. Dno jest średnio zamulone, z licznymi zaczepami, co wymaga ostrożności podczas wędkowania. Brzegi są dostępne z niektórych stron, ale miejscami mogą być zarośnięte. Akwen łączy się z Wartą podczas wysokiej wody, co odświeża wodę i wprowadza nowe ryby. Poza drapieżnikami, licznie występują tu leszcze, okonie i płocie, które żerują w otwartych przestrzeniach. Jest to doskonałe miejsce na wędkowanie wiosną i wczesną jesienią, kiedy ryby są najbardziej aktywne. Ryzyko przyduchy jest niskie dzięki rozmiarom i okresowemu połączeniu z rzeką.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20906, 6.5, 2.2, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Leszcz,Okoń,Płoć', 'Dobry z niektórych stron', FALSE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20907, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20907', 'OXBOW', 52.2250119, 16.9331604, 'Wielkopolskie', 'Rogalin', 'To starorzecze charakteryzuje się wysokim poziomem zamulenia i bardzo silnym zarośnięciem, co czyni je trudnym, ale satysfakcjonującym łowiskiem dla miłośników karasi i linów. Brzegi są mocno zarośnięte trzciną, co wymaga cierpliwości i często brodzenia w wodzie. Brak połączenia z rzeką sprawia, że akwen jest bardziej podatny na wahania poziomu wody i temperatury. Istnieje podwyższone ryzyko przyduchy, zwłaszcza w okresie letnich upałów. Wzdręga i płoć również stanowią ważną część populacji ryb. Najlepszy okres na wędkowanie to późna wiosna i lato, kiedy ryby są aktywne w cieplejszej wodzie. Warto poszukać prześwitów w roślinności, aby skutecznie zarzucić wędkę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20907, 3, 1.4, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20908, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20908', 'OXBOW', 52.2252778, 16.933034, 'Wielkopolskie', 'Rogalin', 'To płytkie i silnie zarośnięte starorzecze jest typowym przykładem akwenu, który w skrajnych warunkach może wysychać. Wysoki poziom zamulenia i gęsta roślinność podwodna sprawiają, że jest to środowisko wymagające dla większości gatunków ryb. Brzegi są trudne do pokonania, często bagniste i mocno zarośnięte, co wymaga użycia wodoodpornych spodni i dużej ostrożności. Brak połączenia z rzeką potęguje ryzyko przyduchy, szczególnie w okresach długotrwałego braku opadów. Dominują tu karasie pospolite i srebrzyste, a także liny i wzdręgi, które są odporne na trudne warunki. Najlepsze wyniki można osiągnąć wczesnym latem, celując w ryby żerujące w płytszych partiach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20908, 2.1, 1.1, 2.4, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Karaś srebrzysty,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20909, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20909', 'OXBOW', 52.2260973, 16.9321609, 'Wielkopolskie', 'Rogalin', 'To starorzecze oferuje umiarkowane warunki do wędkowania, z brzegami dostępnymi z niektórych stron i średnim poziomem zamulenia. Dno jest zróżnicowane, z pojedynczymi korzeniami i gałęziami, które stanowią atrakcyjne kryjówki dla ryb. Akwen łączy się z rzeką podczas wysokiej wody, co zapewnia dopływ świeżej wody i uzupełnianie populacji ryb. Jest to dobre miejsce na szczupaka, okonia, leszcza, płoć i lina, które chętnie żerują w tym środowisku. Roślinność wodna jest umiarkowana, co ułatwia zarzucanie wędki. Ryzyko przyduchy jest niskie. Najlepsze efekty można osiągnąć wiosną i wczesną jesienią, kiedy ryby są najbardziej aktywne. Warto eksplorować różne partie akwenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20909, 4.5, 1.6, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Lin', 'Dobry z niektórych stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20910, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20910', 'OXBOW', 52.2273839, 16.9315816, 'Wielkopolskie', 'Rogalin', 'To wydłużone starorzecze charakteryzuje się stosunkowo niskim poziomem zamulenia i czystym dnem, co sprzyja różnorodności gatunkowej ryb. Brzegi są dobrze dostępne z obu stron, co ułatwia wędkowanie. Akwen łączy się z Wartą podczas wysokiej wody, co zapewnia doskonałe warunki tlenowe i regularne zarybienia naturalne. Jest to idealne miejsce na leszcza, płoć i karpia, które chętnie żerują na twardszym dnie. Drapieżniki takie jak szczupak i okoń również licznie występują, wykorzystując otwarte przestrzenie i dostępność pokarmu. Ryzyko przyduchy jest minimalne, co zapewnia stabilne warunki przez cały sezon. To łowisko oferuje udane połowy przez cały rok, z naciskiem na wiosnę i jesień.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20910, 5.8, 1.9, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20911, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20911', 'OXBOW', 52.2319157, 16.9256068, 'Wielkopolskie', 'Rogalin', 'To starorzecze położone blisko głównego nurtu Warty, charakteryzuje się stałym połączeniem z rzeką, co gwarantuje doskonałe warunki środowiskowe i bogactwo ryb. Dno jest czyste, z niskim poziomem zamulenia i niewielką ilością roślinności, co ułatwia wędkowanie. Brzegi są łatwo dostępne z obu stron, co czyni to miejsce idealnym dla wędkarzy ceniących komfort. Jest to doskonałe łowisko na bolenia, jazia i klenia, które często wpływają tu z rzeki. Płoć i leszcz również licznie występują, żerując na czystym dnie. Ryzyko przyduchy jest praktycznie zerowe, co zapewnia stabilne warunki przez cały rok. Wiosna i wczesna jesień to najlepsze pory na udane połowy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20911, 4, 1.5, 3, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Boleń,Jaź,Kleń,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20912, 'Starorzecze (Świątniki)', 'starorzecze-swiatniki-swiatniki-20912', 'OXBOW', 52.2219624, 16.9459879, 'Wielkopolskie', 'Świątniki', 'To starorzecze w Świątnikach to płytki i silnie zarośnięty akwen, który w suchych latach może całkowicie wyschnąć. Charakteryzuje się wysokim poziomem zamulenia i gęstą roślinnością podwodną, co sprawia, że jest to trudne łowisko. Brzegi są bagniste i mocno zarośnięte, co wymaga użycia wodoodpornych spodni i dużej cierpliwości. Brak połączenia z rzeką i duża ilość materii organicznej prowadzą do wysokiego ryzyka przyduchy. Dominują tu karasie pospolite, liny i wzdręgi, które są odporne na trudne warunki środowiskowe. Płoć również występuje, ale w mniejszych ilościach. Najlepsze efekty można osiągnąć późną wiosną i wczesnym latem, celując w ryby żerujące w prześwitach między roślinnością.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20912, 2.3, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20913, 'Starorzecze (Świątniki)', 'starorzecze-swiatniki-swiatniki-20913', 'OXBOW', 52.2226697, 16.9447725, 'Wielkopolskie', 'Świątniki', 'To starorzecze w Świątnikach oferuje dobre warunki do wędkowania, z brzegami dostępnymi z niektórych stron i umiarkowanym zarośnięciem. Dno jest zróżnicowane, z pojedynczymi korzeniami i gałęziami, które stanowią atrakcyjne kryjówki dla ryb. Akwen łączy się z rzeką podczas wysokiej wody, co zapewnia dopływ świeżej wody i uzupełnianie populacji ryb. Jest to dobre miejsce na szczupaka, okonia, lina, płoć i leszcza, które chętnie żerują w tym środowisku. Roślinność wodna jest umiarkowana, co ułatwia zarzucanie wędki. Ryzyko przyduchy jest niskie dzięki okresowemu połączeniu z rzeką. Najlepsze efekty można osiągnąć wiosną i wczesną jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20913, 3.2, 1.3, 2.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Lin,Płoć,Leszcz', 'Dobry z niektórych stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20914, 'Starorzecze (Świątniki)', 'starorzecze-swiatniki-swiatniki-20914', 'OXBOW', 52.222891, 16.9436098, 'Wielkopolskie', 'Świątniki', 'To starorzecze wyróżnia się stałym połączeniem z Wartą, co gwarantuje doskonałe warunki tlenowe i bogactwo różnorodnych gatunków ryb. Dno jest stosunkowo czyste, z niskim poziomem zamulenia, ale z licznymi zatopionymi drzewami, które stanowią idealne kryjówki dla drapieżników. Brzegi są łatwo dostępne z obu stron, co ułatwia wybór stanowiska wędkarskiego. Jest to doskonałe łowisko na suma, sandacza i szczupaka, które chętnie polują w okolicach zatopionych przeszkód. Leszcz i płoć również licznie występują, żerując na otwartych przestrzeniach. Brak ryzyka przyduchy i wysychania sprawia, że jest to łowisko całoroczne, oferujące stabilne warunki przez cały sezon. Można tu liczyć na duże okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20914, 5.5, 2, 4.2, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Sandacz,Szczupak,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20915, 'Starorzecze Świątniki 1', 'starorzecze-swiatniki-1-swiatniki-20915', 'OXBOW', 52.2231853, 16.9423874, 'Wielkopolskie', 'Świątniki', 'To malownicze starorzecze, położone w pobliżu wsi Świątniki, charakteryzuje się typowym dla takich zbiorników dnem mulistym, przeplatanym miejscami twardszymi fragmentami. Brzegi są w większości porośnięte gęstą trzciną i inną roślinnością szuwarową, co utrudnia dostęp, ale tworzy doskonałe kryjówki dla ryb. Wędkarze mogą liczyć na spotkanie z okazałymi linami i szczupakami, które preferują takie środowiska. Płoć i leszcz również występują licznie, szczególnie w głębszych partiach zbiornika. Ze względu na bujną roślinność podwodną, ryzyko zaczepów jest umiarkowane, a do efektywnego wędkowania często przydadzą się wodery. Najlepsze wyniki osiąga się tu wiosną i wczesną jesienią, kiedy aktywność ryb jest największa, a roślinność nie jest jeszcze zbyt gęsta.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20915, 3.2, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Płoć,Leszcz', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20916, 'Starorzecze Świątniki 2', 'starorzecze-swiatniki-2-swiatniki-20916', 'OXBOW', 52.2232616, 16.9409433, 'Wielkopolskie', 'Świątniki', 'Drugie starorzecze w rejonie Świątnik to typowy, silnie zarośnięty zbiornik o charakterze bagiennym. Dno jest bardzo muliste, z dużą ilością detrytusu, co sprzyja rozwojowi bujnej roślinności podwodnej i szuwarowej. Dostęp do wody jest utrudniony przez bagniste brzegi i gęste zarośla, wymagające użycia woderów i cierpliwości. Jest to idealne siedlisko dla karasia pospolitego i lina, które doskonale czują się w takich warunkach. Wzdręga i mniejsze okonie również licznie zamieszkują ten akwen, często żerując wśród roślinności. Ze względu na silne zarastanie i ryzyko przyduchy latem, najlepszym okresem na wędkowanie jest późna wiosna i wczesne lato, zanim upały obniżą poziom tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20916, 2.8, 1.5, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20917, 'Starorzecze Rogalin 1', 'starorzecze-rogalin-1-rogalin-20917', 'OXBOW', 52.2231266, 16.9383265, 'Wielkopolskie', 'Rogalin', 'To rozległe starorzecze w okolicach Rogalina oferuje zróżnicowane warunki do wędkowania. Dno jest mieszane, z przewagą mułu, ale z licznymi twardszymi fragmentami i zatopionymi korzeniami drzew. Brzegi są stosunkowo łatwo dostępne, co ułatwia wędkowanie z brzegu bez konieczności użycia woderów. W starorzeczu tym można spotkać zarówno drapieżniki, takie jak szczupak i okoń, jak i ryby spokojnego żeru, w tym płoć, leszcz i lina. Okresowe połączenie z rzeką podczas wysokiej wody sprzyja odnawianiu populacji ryb i utrzymaniu dobrej jakości wody. Jest to łowisko atrakcyjne przez cały sezon, choć w upalne lato warto szukać ryb w głębszych partiach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20917, 4.5, 2, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20918, 'Starorzecze Rogalin 2', 'starorzecze-rogalin-2-rogalin-20918', 'OXBOW', 52.2242051, 16.9368995, 'Wielkopolskie', 'Rogalin', 'Kolejne starorzecze w Rogalinie to zbiornik o imponujących rozmiarach i dobrej dostępności. Dno jest stabilne, z mniejszym zamuleniem niż w innych starorzeczach, co sprzyja rozwojowi różnorodnej fauny dennej. Brzegi są w większości otwarte, co umożliwia wygodne wędkowanie z brzegu, bez większych przeszkód. Jest to znane łowisko szczupaków i okoni, które często patrolują zatopione zwaliska i podwodne łąki. Licznie występują tu również leszcz i płoć, a w ostatnich latach zaobserwowano także karpie, które znalazły tu dogodne warunki do życia. Okresowe połączenie z rzeką zapewnia stały dopływ świeżej wody i ryb, co czyni to miejsce bardzo atrakcyjnym dla wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20918, 5.1, 2.2, 5.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20919, 'Starorzecze Rogalin 3', 'starorzecze-rogalin-3-rogalin-20919', 'OXBOW', 52.2246946, 16.935369, 'Wielkopolskie', 'Rogalin', 'To starorzecze w Rogalinie charakteryzuje się znacznym zarastaniem, co czyni je rajem dla miłośników spokojnego żeru. Dno jest w większości muliste, z grubą warstwą osadów, idealne dla roślinności wodnej. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co wymaga użycia woderów i cierpliwości, aby znaleźć dogodne stanowisko. Dominują tu lin i karaś pospolity, które doskonale czują się w ciepłej, płytkiej wodzie. Wzdręga i płoć również są licznie reprezentowane, często żerując wśród grążeli i lilii wodnych. W upalne lato istnieje ryzyko przyduchy, dlatego najlepszym okresem na wędkowanie jest późna wiosna i początek lata, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20919, 3.8, 1.9, 4.2, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20920, 'Starorzecze Świątniki 3', 'starorzecze-swiatniki-3-swiatniki-20920', 'OXBOW', 52.2216173, 16.9527066, 'Wielkopolskie', 'Świątniki', 'To niewielkie i płytkie starorzecze w pobliżu Świątnik jest mocno zamulone i silnie zarośnięte, co sprawia, że jest to środowisko wymagające dla wędkarza. Dno jest bardzo miękkie i bagniste, a brzegi są praktycznie niedostępne bez odpowiedniego sprzętu i woderów. W upalne, suche lata zbiornik ma tendencję do wysychania, co wpływa na populacje ryb. Dominują tu gatunki odporne na trudne warunki, takie jak karaś pospolity, wzdręga i płoć, które potrafią przetrwać w płytkich, mulistych wodach. Wędkowanie jest najbardziej efektywne wczesną wiosną, kiedy poziom wody jest wyższy, a roślinność nie jest jeszcze w pełni rozwinięta, minimalizując ryzyko braku tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20920, 1.9, 1.2, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20921, 'Starorzecze Radzewice', 'starorzecze-radzewice-radzewice-20921', 'OXBOW', 52.2204612, 16.9556174, 'Wielkopolskie', 'Radzewice', 'Starorzecze w Radzewicach to prawdziwa perła dla wędkarzy, wyróżniająca się stałym połączeniem z rzeką, co zapewnia doskonałą wymianę wody i bogactwo gatunkowe. Dno jest zróżnicowane, z twardszymi partiami żwiru i piasku, przeplatanymi miejscami z lekkim mułem, oraz licznymi zatopionymi drzewami stanowiącymi kryjówki. Brzegi są łatwo dostępne, co umożliwia komfortowe wędkowanie z wielu dogodnych miejsc. Jest to doskonałe łowisko na szczupaka, okonia, leszcza i płoć, a dzięki połączeniu z rzeką, można tu spotkać również suma i sandacza. Niskie zamulenie i umiarkowane zarastanie sprawiają, że woda jest czysta, a ryzyko przyduchy jest minimalne. To łowisko oferuje wspaniałe możliwości przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20921, 6, 2.5, 6, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Sum', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20922, 'Starorzecze Baranowo 1', 'starorzecze-baranowo-1-baranowo-20922', 'OXBOW', 52.2328334, 16.9206904, 'Wielkopolskie', 'Baranowo', 'Pierwsze starorzecze w okolicy Baranowa to zbiornik o umiarkowanym zamuleniu i zróżnicowanej roślinności. Dno jest przeważnie muliste, ale z twardszymi fragmentami, które są atrakcyjne dla ryb. Brzegi są częściowo dostępne, jednak w wielu miejscach gęste zarośla trzcinowe wymagają użycia woderów, aby dotrzeć do najlepszych stanowisk. Łowisko jest znane z populacji lina i szczupaka, które znajdują tu idealne warunki do żerowania i ukrywania się. Płoć i karaś pospolity również występują licznie, szczególnie w płytszych, cieplejszych partiach. Okresowe połączenie z rzeką wspomaga odnawianie zasobów rybnych, ale w upalne lata może wystąpić ryzyko niedoboru tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20922, 2.5, 1.7, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Płoć,Karaś pospolity', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20923, 'Starorzecze Rogalin 4', 'starorzecze-rogalin-4-rogalin-20923', 'OXBOW', 52.2331436, 16.9227312, 'Wielkopolskie', 'Rogalin', 'To starorzecze w Rogalinie jest płytkie, silnie zamulone i gęsto zarośnięte, co czyni je typowym siedliskiem dla ryb preferujących takie warunki. Dno jest bardzo miękkie i bogate w materię organiczną, sprzyjającą rozwojowi bujnej roślinności. Dostęp do wody jest bardzo trudny, z bagnistymi brzegami i gęstymi szuwarami, co praktycznie wymusza użycie woderów. Dominują tu karaś pospolity, lin i wzdręga, które doskonale radzą sobie w środowiskach o zmiennym poziomie tlenu. Ze względu na brak stałego połączenia z rzeką, w upalne lata ryzyko przyduchy jest wysokie, dlatego najlepsze efekty daje wędkowanie w chłodniejszych miesiącach późnej wiosny i wczesnego lata, zanim temperatura wody osiągnie szczyt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20923, 3, 1.6, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20924, 'Starorzecze Baranowo 2', 'starorzecze-baranowo-2-baranowo-20924', 'OXBOW', 52.2328196, 16.9228581, 'Wielkopolskie', 'Baranowo', 'Drugie starorzecze w Baranowie to niewielki zbiornik o charakterze silnie zarośniętym i zamulonym. Dno jest miękkie, z dużą ilością osadów organicznych, co sprzyja rozwojowi gęstej roślinności podwodnej. Brzegi są trudne do przejścia z powodu gęstych trzcinowisk, co wymaga od wędkarza użycia woderów i cierpliwości. W tym starorzeczu dominują gatunki odporne na trudne warunki, takie jak karaś pospolity, lin, płoć i wzdręga. Wędkowanie jest najbardziej efektywne wczesną wiosną, kiedy roślinność nie jest jeszcze w pełni rozwinięta, a poziom tlenu w wodzie jest stabilny. Latem ryzyko przyduchy jest znaczne, co może wpływać na aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20924, 2.1, 1.4, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20925, 'Starorzecze Baranowo 3', 'starorzecze-baranowo-3-baranowo-20925', 'OXBOW', 52.232031, 16.9234855, 'Wielkopolskie', 'Baranowo', 'To najmniejsze i najbardziej płytkie starorzecze w rejonie Baranowa, charakteryzujące się ekstremalnym zamuleniem i silnym zarastaniem. Dno jest bardzo miękkie, a w wielu miejscach trudno odróżnić wodę od lądu, co czyni je praktycznie niedostępnym bez woderów. W upalne, suche lata zbiornik regularnie wysycha, co drastycznie ogranicza populacje ryb. Dominują tu jedynie najbardziej odporne gatunki, takie jak karaś pospolity i wzdręga, które są w stanie przetrwać w tak ekstremalnych warunkach. Wędkowanie jest możliwe tylko wczesną wiosną, kiedy poziom wody jest najwyższy, a ryzyko wyschnięcia i przyduchy jest minimalne. Jest to łowisko dla prawdziwych pasjonatów, szukających wyzwań.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20925, 1.5, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20926, 'Starorzecze Rogalin 5', 'starorzecze-rogalin-5-rogalin-20926', 'OXBOW', 52.2286175, 16.925233, 'Wielkopolskie', 'Rogalin', 'Piąte starorzecze w Rogalinie to zbiornik o zróżnicowanej głębokości i umiarkowanym zamuleniu, idealny dla wielu gatunków ryb. Dno jest mieszane, z twardszymi fragmentami piasku i żwiru oraz miejscowymi skupiskami mułu. Brzegi są w większości łatwo dostępne, co umożliwia swobodne przemieszczanie się i wędkowanie z różnych stanowisk. Jest to popularne miejsce dla wędkarzy polujących na szczupaka i okonia, które często ukrywają się wśród zatopionych gałęzi i podwodnej roślinności. Licznie występują tu również leszcz, płoć i lin, oferując dobre możliwości dla wędkarzy spławikowych i gruntowych. Okresowe połączenie z rzeką zapewnia stały dopływ świeżej wody i ryb, utrzymując wysoką jakość łowiska przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20926, 4, 2.1, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20927, 'Starorzecze Rogalin 6', 'starorzecze-rogalin-6-rogalin-20927', 'OXBOW', 52.2274212, 16.9248195, 'Wielkopolskie', 'Rogalin', 'To starorzecze w Rogalinie jest zbiornikiem o znacznym zamuleniu i silnym zarastaniu, co tworzy specyficzne, bogate w życie środowisko. Dno jest przeważnie muliste, z grubą warstwą osadów, idealne dla rozwoju gęstej roślinności wodnej. Brzegi są trudne do przejścia z powodu gęstych trzcinowisk i krzewów, co wymaga użycia woderów i cierpliwości. Dominują tu lin, karaś pospolity, wzdręga i płoć, które doskonale adaptują się do warunków ze zmiennym poziomem tlenu. Ze względu na brak stałego połączenia z rzeką, w upalne lata ryzyko przyduchy jest wysokie, dlatego najlepszym okresem na wędkowanie jest późna wiosna i wczesne lato, zanim temperatura wody osiągnie szczyt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20927, 3.5, 1.8, 4, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20928, 'Starorzecze Rogalin 7', 'starorzecze-rogalin-7-rogalin-20928', 'OXBOW', 52.2277412, 16.9246258, 'Wielkopolskie', 'Rogalin', 'Kolejne starorzecze w Rogalinie to zbiornik o umiarkowanym zamuleniu i zróżnicowanej roślinności, oferujący dobre warunki dla wędkarzy. Dno jest muliste, z twardszymi fragmentami, a brzegi są częściowo dostępne, choć w wielu miejscach gęste zarośla trzcinowe wymagają użycia woderów. Łowisko jest atrakcyjne dla miłośników szczupaka i lina, które znajdują tu doskonałe kryjówki i miejsca żerowania. Płoć i okoń również występują licznie, często żerując w okolicach podwodnych łąk. Okresowe połączenie z rzeką podczas wysokiej wody wspomaga odnawianie zasobów rybnych, ale w upalne lata może wystąpić ryzyko niedoboru tlenu, zwłaszcza w płytszych partiach. Najlepsze wyniki osiąga się wiosną i wczesną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20928, 2.9, 1.7, 3.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20929, 'Starorzecze Rogalin 8', 'starorzecze-rogalin-8-rogalin-20929', 'OXBOW', 52.2280359, 16.9245733, 'Wielkopolskie', 'Rogalin', 'Ostatnie starorzecze w Rogalinie to zbiornik o dobrej dostępności i zróżnicowanym dnie, co czyni je atrakcyjnym dla wielu wędkarzy. Dno jest stabilne, z mniejszym zamuleniem niż w sąsiednich zbiornikach, co sprzyja rozwojowi różnorodnej fauny dennej. Brzegi są w większości otwarte, co umożliwia wygodne wędkowanie z brzegu bez większych przeszkód. Jest to znane łowisko szczupaków i okoni, które często patrolują zatopione zwaliska i podwodne łąki. Licznie występują tu również leszcz i płoć, a w ostatnich latach zaobserwowano także karpie, które znalazły tu dogodne warunki do życia. Okresowe połączenie z rzeką zapewnia stały dopływ świeżej wody i ryb, co czyni to miejsce bardzo atrakcyjnym dla wędkarzy przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20929, 3.3, 2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20930, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20930', 'OXBOW', 52.2235455, 16.9313704, 'Wielkopolskie', 'Rogalin', 'To malownicze starorzecze, położone w zakolu Warty nieopodal Rogalina, stanowi doskonałe miejsce dla wędkarzy poszukujących spokoju i bogactwa gatunkowego. Dno jest muliste z miejscowymi twardymi plamami, co sprzyja rozwojowi bujnej roślinności podwodnej, takiej jak grążele i rdestnice. Brzegi są często podmokłe i trudno dostępne, porośnięte gęstymi pasami trzcin i krzaków, co wymaga ostrożności i często użycia brodzenia. Akwen ten jest domem dla licznej populacji szczupaków i okoni, a także linów, płoci i karasi pospolitych. Poziom zamulenia jest średni, a silne zarastanie może utrudniać swobodne wędkowanie, zwłaszcza w pełni lata. Wędkowanie z pontonu lub łódki daje tutaj przewagę, umożliwiając dotarcie do najciekawszych zakamarków i zatopionych przeszkód.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20930, 3.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Płoć,Leszcz,Karaś pospolity', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20931, 'Starorzecze (Sowiniec)', 'starorzecze-sowiniec-sowiniec-20931', 'OXBOW', 52.2372904, 16.9038751, 'Wielkopolskie', 'Sowiniec', 'Starorzecze w Sowinicach to typowy akwen śródlądowy, który charakteryzuje się płytkim dnem i intensywnym zarastaniem, będąc ostoją dla wielu gatunków ryb spokojnego żeru. Dno jest w przeważającej części muliste, z licznymi osadami organicznymi, co sprzyja rozwojowi bujnej roślinności wodnej, takiej jak moczarka kanadyjska i rogatek. Brzegi są trudno dostępne, często bagniste i mocno zarośnięte trzciną, co sprawia, że dostęp do wody jest wyzwaniem i wymaga użycia woderów. W starorzeczu dominują liny, karasie pospolite, wzdręgi oraz płocie, które znajdują tu idealne warunki do życia i rozrodu. W cieplejszych miesiącach istnieje ryzyko przyduchy z powodu intensywnego rozkładu materii organicznej i wysokiego poziomu zarastania. Miejscami można natrafić na zatopione gałęzie i korzenie, które stanowią doskonałe kryjówki dla ryb, ale mogą utrudniać hol.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20931, 2.8, 1, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20932, 'Starorzecze (Krzętów)', 'starorzecze-krzetow-krzetow-20932', 'OXBOW', 50.9784633, 19.8299025, 'Łódzkie', 'Krzętów', 'To niewielkie starorzecze w Krzętowie jest przykładem akwenu o silnym stopniu izolacji od głównego nurtu rzeki, co prowadzi do specyficznych warunków środowiskowych. Dno jest bardzo mocno zamulone, a w wielu miejscach osady sięgają znacznej grubości, co utrudnia tradycyjne metody wędkowania. Brzegi są niezwykle trudne do pokonania, często bagniste i gęsto zarośnięte, wymagając od wędkarza dużej cierpliwości i odpowiedniego sprzętu, w tym woderów. Akwen ten jest królestwem karasi pospolitych i wzdręg, które doskonale radzą sobie w trudnych warunkach, a także mniejszych płoci i linów. Ze względu na płytkość i brak stałego połączenia z rzeką, istnieje wysokie ryzyko wysychania w okresach długotrwałej suszy oraz przyduchy zimą. Występuje tu dużo zatopionych drzew i gałęzi, które stanowią naturalne schronienia dla ryb, ale również pułapki dla zestawów wędkarskich.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20932, 1.5, 0.8, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć,Lin', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20933, 'Starorzecze (Rogalinek) Górne', 'starorzecze-rogalinek-gorne-rogalinek-20933', 'OXBOW', 52.2447426, 16.9001314, 'Wielkopolskie', 'Rogalinek', 'To starorzecze, zlokalizowane w kompleksie starorzeczy Rogalińskich, wyróżnia się nieco lepszym dostępem i większą głębokością w porównaniu do sąsiednich, mniejszych akwenów. Dno jest zróżnicowane, od mulistego po twardsze, piaszczyste fragmenty, co sprzyja różnorodności gatunkowej ryb. Brzegi są umiarkowanie zarośnięte, miejscami dostępne dla wędkarzy, ale zaleca się ostrożność ze względu na lokalne podmokłości. Akwen ten jest atrakcyjny dla wędkarzy szukających szczupaków i okoni, a także leszczy, płoci i linów. Połączenie z Wartą podczas wysokiej wody zapewnia regularne zarybienia i odświeżanie wody, minimalizując ryzyko przyduchy. Występują tu pojedyncze korzenie i gałęzie, które stanowią naturalne kryjówki dla ryb drapieżnych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20933, 4, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20934, 'Starorzecze (Rogalinek) Środkowe', 'starorzecze-rogalinek-srodkowe-rogalinek-20934', 'OXBOW', 52.245125, 16.897373, 'Wielkopolskie', 'Rogalinek', 'To starorzecze charakteryzuje się typowym dla regionu, mulistym dnem i intensywnym zarastaniem, co czyni je idealnym środowiskiem dla ryb spokojnego żeru. Dno jest jednolicie muliste, z grubą warstwą osadów organicznych, co stwarza trudności w dotarciu do ryb. Brzegi są mocno zarośnięte trzciną i inną roślinnością przybrzeżną, co utrudnia swobodny dostęp i wymaga użycia woderów. W akwenie dominują liny, karasie pospolite, wzdręgi oraz liczne płocie, które doskonale odnajdują się w gęstej roślinności. Wysokie temperatury i intensywny rozkład materii organicznej mogą prowadzić do ryzyka przyduchy, szczególnie w upalne lata. Mimo trudności, starorzecze oferuje obfite połowy dla cierpliwych wędkarzy, którzy potrafią odnaleźć wolne od zaczepów miejsca.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20934, 2, 1, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20935, 'Starorzecze (Rogalinek) Wschodnie', 'starorzecze-rogalinek-wschodnie-rogalinek-20935', 'OXBOW', 52.244986, 16.8959978, 'Wielkopolskie', 'Rogalinek', 'To starorzecze jest jednym z bardziej izolowanych akwenów w rejonie Rogalinka, charakteryzującym się wysokim stopniem zamulenia i bujną roślinnością. Dno jest bardzo miękkie i głęboko zamulone, co sprawia, że wędkowanie z gruntu jest wyzwaniem i wymaga specjalistycznego sprzętu. Brzegi są praktycznie niedostępne, bagniste i gęsto porośnięte, co czyni brodzenie niezbędnym elementem wyposażenia każdego wędkarza. W akwenie królują karasie srebrzyste i wzdręgi, które doskonale adaptują się do trudnych warunków, a także mniejsze płocie. Brak stałego połączenia z rzeką zwiększa ryzyko wysychania w okresach suszy i przyduchy zimą, co wpływa na niestabilność populacji ryb. Występuje tu dużo zatopionych drzew i gałęzi, które są zarówno schronieniem dla ryb, jak i pułapką dla zestawów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20935, 1.8, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20936, 'Starorzecze (Rogalinek) Zachodnie', 'starorzecze-rogalinek-zachodnie-rogalinek-20936', 'OXBOW', 52.2414818, 16.8953839, 'Wielkopolskie', 'Rogalinek', 'Ten akwen, będący częścią kompleksu starorzeczy Rogalińskich, oferuje dobre warunki do wędkowania, zwłaszcza dla miłośników drapieżników. Dno jest zróżnicowane, z przewagą twardszych fragmentów, co sprzyja obecności ryb żerujących przy dnie i drapieżników. Brzegi są stosunkowo łatwo dostępne, miejscami utwardzone, co umożliwia komfortowe wędkowanie bez potrzeby brodzenia. W starorzeczu licznie występują szczupaki i okonie, a także płocie i leszcze, które stanowią ich bazę pokarmową. Okresowe połączenie z rzeką podczas wysokiej wody zapewnia dopływ świeżej wody i nowych ryb, co pozytywnie wpływa na kondycję akwenu. Niewielka ilość pojedynczych korzeni i gałęzi stanowi naturalne kryjówki, nie utrudniając jednocześnie znacząco wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20936, 2.5, 1.3, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20937, 'Starorzecze (Rogalinek) Południowe', 'starorzecze-rogalinek-poludniowe-rogalinek-20937', 'OXBOW', 52.2430933, 16.8948348, 'Wielkopolskie', 'Rogalinek', 'To mniejsze starorzecze, położone w południowej części kompleksu Rogalińskiego, charakteryzuje się znacznym zamuleniem i bujną roślinnością wodną. Dno jest bardzo miękkie, z grubą warstwą mułu, co sprawia, że jest to idealne siedlisko dla ryb ciepłolubnych i spokojnego żeru. Brzegi są mocno zarośnięte i bagniste, co znacznie utrudnia dostęp do wody i wymaga użycia woderów do skutecznego wędkowania. Akwen jest domem dla karasi pospolitych, wzdręg i linów, które doskonale radzą sobie w tych specyficznych warunkach. Ze względu na płytkość i brak stałego połączenia z rzeką, akwen jest narażony na wysychanie w upalne lata i przyduchy zimą. Występuje tu gęsta roślinność podwodna, która stanowi schronienie dla ryb, ale również liczne zaczepy dla zestawów wędkarskich.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20937, 1.2, 0.7, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20938, 'Starorzecze (Rogalinek) Główne', 'starorzecze-rogalinek-glowne-rogalinek-20938', 'OXBOW', 52.2442409, 16.8935521, 'Wielkopolskie', 'Rogalinek', 'To jedno z większych starorzeczy w rejonie Rogalinka, cieszące się popularnością wśród wędkarzy ze względu na różnorodność gatunkową i dobre warunki do wędkowania. Dno jest zróżnicowane, od mulistych zatok po twardsze, piaszczysto-żwirowe fragmenty w głębszych partiach, co sprzyja występowaniu zarówno drapieżników, jak i ryb spokojnego żeru. Brzegi są w większości dostępne, choć miejscami mogą być zarośnięte, co wymaga krótkiego przedzierania się przez roślinność. Akwen ten jest bogaty w szczupaki, liny, leszcze, płocie i okonie, oferując satysfakcjonujące połowy. Połączenie z rzeką podczas wysokiej wody zapewnia stały dopływ świeżej wody i pokarmu, co wpływa na zdrowie i wzrost populacji ryb. Występują tu pojedyncze korzenie i gałęzie, które stanowią naturalne kryjówki, ale nie utrudniają znacząco wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20938, 3, 1.4, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20939, 'Starorzecze (Rogalinek) Małe', 'starorzecze-rogalinek-male-rogalinek-20939', 'OXBOW', 52.2414736, 16.8906287, 'Wielkopolskie', 'Rogalinek', 'To niewielkie i płytkie starorzecze w Rogalinku jest przykładem akwenu o wysokim stopniu izolacji i intensywnym zarastaniu. Dno jest bardzo miękkie, głęboko zamulone, co utrudnia tradycyjne metody wędkowania i wymaga cierpliwości. Brzegi są niezwykle trudne do pokonania, bagniste i gęsto porośnięte, co czyni dostęp do wody bardzo ograniczonym i wymaga użycia woderów. Akwen ten jest królestwem karasi pospolitych i wzdręg, które doskonale adaptują się do trudnych warunków środowiskowych. Ze względu na płytkość i brak połączenia z rzeką, istnieje wysokie ryzyko wysychania w okresach suszy oraz przyduchy zimą, co wpływa na niestabilność populacji ryb. Występuje tu dużo zatopionych drzew i gałęzi, które stanowią naturalne schronienia, ale również liczne zaczepy dla zestawów wędkarskich.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20939, 1, 0.6, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20940, 'Starorzecze (Włochówka) Duże', 'starorzecze-wlochowka-duze-wlochowka-20940', 'OXBOW', 53.2141994, 22.4421898, 'Podlaskie', 'Włochówka', 'To rozległe starorzecze w Włochówce, będące częścią kompleksu starorzeczy Narwi, oferuje znakomite warunki dla wędkarzy poszukujących dużych okazów. Dno jest zróżnicowane, z głębszymi rynnami i mulistymi zatokami, a także twardszymi, piaszczystymi fragmentami, co sprzyja różnorodności gatunkowej. Brzegi są dobrze dostępne, miejscami utwardzone, co ułatwia wędkowanie z brzegu i rozstawienie sprzętu. Akwen ten jest znany z licznej populacji sumów, szczupaków, leszczy, karpi i płoci, które osiągają tutaj imponujące rozmiary. Stałe połączenie z Narwią podczas wysokiej wody zapewnia regularny dopływ świeżej wody i ryb, minimalizując ryzyko przyduchy. Występują tu pojedyncze korzenie i gałęzie, które stanowią naturalne kryjówki, ale nie utrudniają znacząco wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20940, 5, 2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Leszcz,Karp,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20941, 'Starorzecze (Włochówka) Mniejsze', 'starorzecze-wlochowka-mniejsze-wlochowka-20941', 'OXBOW', 53.2134549, 22.4527411, 'Podlaskie', 'Włochówka', 'To starorzecze w Włochówce charakteryzuje się umiarkowanym rozmiarem i silnym zarastaniem, co czyni je idealnym środowiskiem dla ryb spokojnego żeru i mniejszych drapieżników. Dno jest w przeważającej części muliste, z licznymi osadami organicznymi, co sprzyja rozwojowi bujnej roślinności wodnej. Brzegi są mocno zarośnięte trzciną i inną roślinnością przybrzeżną, co utrudnia swobodny dostęp i wymaga użycia woderów do skutecznego wędkowania. W akwenie dominują liny, szczupaki, okonie oraz płocie, które znajdują tu idealne warunki do życia i rozrodu. Okresowe połączenie z Narwią podczas wysokiej wody zapewnia odświeżanie wody, ale w upalne lata nadal istnieje ryzyko przyduchy z powodu intensywnego rozkładu materii organicznej. Gęsta roślinność podwodna stanowi schronienie dla ryb, ale również liczne zaczepy dla zestawów wędkarskich.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20941, 3, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Szczupak,Okoń,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20942, 'Starorzecze (Włochówka) Izolowane', 'starorzecze-wlochowka-izolowane-wlochowka-20942', 'OXBOW', 53.2116758, 22.4782061, 'Podlaskie', 'Włochówka', 'To starorzecze jest przykładem akwenu o wysokim stopniu izolacji od głównego nurtu Narwi, co prowadzi do specyficznych warunków środowiskowych i ograniczonej różnorodności gatunkowej. Dno jest bardzo mocno zamulone, a w wielu miejscach osady sięgają znacznej grubości, co utrudnia tradycyjne metody wędkowania. Brzegi są niezwykle trudne do pokonania, bagniste i gęsto zarośnięte, wymagając od wędkarza dużej cierpliwości i odpowiedniego sprzętu, w tym woderów. Akwen ten jest królestwem karasi pospolitych, wzdręg i linów, które doskonale radzą sobie w trudnych warunkach. Ze względu na płytkość i brak stałego połączenia z rzeką, istnieje wysokie ryzyko wysychania w okresach długotrwałej suszy oraz przyduchy zimą. Występuje tu dużo zatopionych drzew i gałęzi, które stanowią naturalne schronienia dla ryb, ale również pułapki dla zestawów wędkarskich.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20942, 2.2, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20943, 'Starorzecze (Parchatka) Główne', 'starorzecze-parchatka-glowne-parchatka-20943', 'OXBOW', 51.3756433, 21.9840964, 'Lubelskie', 'Parchatka', 'To rozległe starorzecze w Parchatce, będące częścią kompleksu starorzeczy Wisły, oferuje znakomite warunki dla wędkarzy poszukujących dużych okazów ryb. Dno jest zróżnicowane, z głębszymi rynnami i mulistymi zatokami, a także twardszymi, piaszczystymi fragmentami, co sprzyja różnorodności gatunkowej. Brzegi są dobrze dostępne, miejscami utwardzone, co ułatwia wędkowanie z brzegu i rozstawienie sprzętu. Akwen ten jest znany z licznej populacji szczupaków, sumów, leszczy, karpi i płoci, które osiągają tutaj imponujące rozmiary. Stałe połączenie z Wisłą podczas wysokiej wody zapewnia regularny dopływ świeżej wody i ryb, minimalizując ryzyko przyduchy. Występują tu pojedyncze korzenie i gałęzie, które stanowią naturalne kryjówki, ale nie utrudniają znacząco wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20943, 4.5, 1.8, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sum,Leszcz,Karp,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20944, 'Starorzecze (Parchatka) Boczne', 'starorzecze-parchatka-boczne-parchatka-20944', 'OXBOW', 51.3725266, 21.9878352, 'Lubelskie', 'Parchatka', 'To starorzecze w Parchatce charakteryzuje się umiarkowanym rozmiarem i silnym zamuleniem, co czyni je idealnym środowiskiem dla ryb spokojnego żeru. Dno jest w przeważającej części muliste, z licznymi osadami organicznymi, co sprzyja rozwojowi bujnej roślinności wodnej i bogactwu bezkręgowców. Brzegi są mocno zarośnięte trzciną i inną roślinnością przybrzeżną, co utrudnia swobodny dostęp i wymaga użycia woderów do skutecznego wędkowania. W akwenie dominują liny, karasie pospolite, wzdręgi oraz okonie, które znajdują tu idealne warunki do życia i rozrodu. Brak stałego połączenia z Wisłą sprawia, że akwen jest bardziej narażony na wahania poziomu wody i ryzyko przyduchy, szczególnie w upalne lata. Gęsta roślinność podwodna stanowi schronienie dla ryb, ale również liczne zaczepy dla zestawów wędkarskich.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20944, 2.7, 1.2, 2.7, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20945, 'Starorzecze (Puszczykowo)', 'starorzecze-puszczykowo-puszczykowo-20945', 'OXBOW', 52.2580309, 16.8864328, 'Wielkopolskie', 'Puszczykowo', 'To starorzecze, położone w malowniczej okolicy Puszczykowa, stanowi typowy przykład akwenu połączonego z Wartą jedynie podczas wyższych stanów wody. Charakteryzuje się mulistym dnem, bogatym w osady organiczne, co sprzyja rozwojowi bujnej roślinności podwodnej i brzegowej. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je gęsta trzcina i krzewy, utrudniające swobodne dotarcie do wody. W akwenie dominują takie gatunki ryb jak lin, płoć, szczupak oraz karaś pospolity, które znajdują tu idealne warunki do żerowania i rozmnażania. Wędkarze powinni przygotować się na konieczność brodzenia, zwłaszcza przy próbach dotarcia do mniej uczęszczanych stanowisk, a także uważać na pojedyncze zatopione gałęzie. Ze względu na umiarkowane zamulenie i ryzyko przyduchy latem, najlepsze efekty połowowe uzyskuje się wiosną i wczesną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20945, 3.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Płoć,Szczupak,Karaś pospolity', 'Dobry w niektórych miejscach, lokalnie zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20946, 'Starorzecze (Puszczykowo)', 'starorzecze-puszczykowo-puszczykowo-20946', 'OXBOW', 52.2573471, 16.8862993, 'Wielkopolskie', 'Puszczykowo', 'To niewielkie starorzecze w pobliżu Puszczykowa jest silnie zarośniętym i zamulonym akwenem, co czyni je wyzwaniem dla wędkarzy. Dno jest grząskie, pokryte grubą warstwą mułu i obficie porośnięte roślinnością wodną, taką jak grążele i rdestnice. Brzegi są trudne do pokonania, często bagniste i gęsto obsadzone trzciną oraz krzewami, co wymaga użycia brodzących spodni. Mimo tych trudności, łowisko to jest ostoją dla karasia pospolitego, lina, wzdręgi i płoci, które doskonale czują się w tych specyficznych warunkach. Ze względu na wysoki poziom zamulenia i silne zarastanie, istnieje znaczne ryzyko przyduchy w okresach upałów. Najlepsze wyniki wędkarskie można osiągnąć późną wiosną i latem, kiedy ryby aktywnie żerują wśród roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20946, 2.8, 1.2, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20947, 'Starorzecze (Puszczykowo)', 'starorzecze-puszczykowo-puszczykowo-20947', 'OXBOW', 52.2588065, 16.8841598, 'Wielkopolskie', 'Puszczykowo', 'Trzecie starorzecze w rejonie Puszczykowa wyróżnia się brakiem stałego połączenia z główną rzeką, co przyczynia się do większej stabilności warunków wodnych. Dno jest tu mniej zamulone niż w sąsiednich akwenach, z przewagą podłoża piaszczysto-mulistego, choć miejscami występują pojedyncze korzenie i gałęzie. Brzegi są stosunkowo dobrze dostępne, z kilkoma utwardzonymi stanowiskami dla wędkarzy, co ułatwia komfortowe wędkowanie. Akwen ten jest znany z populacji szczupaka i okonia, a także leszcza i płoci, które osiągają tu imponujące rozmiary. Umiarkowane zarastanie i niskie ryzyko przyduchy sprawiają, że jest to atrakcyjne łowisko przez cały sezon wędkarski. Brak konieczności brodzenia jest dodatkowym atutem tego miejsca.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20947, 4.1, 1.8, 3.5, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z niektórych stron, utwardzone stanowiska', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20948, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20948', 'OXBOW', 52.2314192, 16.9350387, 'Wielkopolskie', 'Rogalin', 'To starorzecze w Rogalinie charakteryzuje się stałym połączeniem z rzeką Wartą, co zapewnia regularną wymianę wody i stabilne warunki. Dno jest przeważnie czyste, piaszczysto-żwirowe, z niewielką ilością mułu, co sprzyja występowaniu drapieżników. Brzegi są dobrze dostępne, częściowo umocnione i niezarośnięte, co ułatwia wędkowanie z brzegu. Akwen ten jest ceniony przez wędkarzy za bogactwo leszczy i płoci, a także za obecność sandacza, bolenia i suma, które wpływają z Warty. Niskie zamulenie i umiarkowane zarastanie sprawiają, że ryzyko przyduchy jest minimalne. Starorzecze to jest atrakcyjne przez cały sezon, oferując różnorodne możliwości połowu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20948, 5.2, 2, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Sandacz,Boleń,Sum', 'Dobry, częściowo umocnione brzegi', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20949, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20949', 'OXBOW', 52.2272599, 16.9387803, 'Wielkopolskie', 'Rogalin', 'Niewielkie starorzecze w Rogalinie, połączone z rzeką jedynie podczas wysokich stanów wody, to typowe łowisko dla miłośników trudniejszych wyzwań. Charakteryzuje się bardzo wysokim poziomem zamulenia i silnym zarastaniem, co tworzy gęste zarośla podwodne i brzegowe. Brzegi są niemal w całości porośnięte gęstą trzciną, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga użycia brodzących spodni. Mimo to, w akwenie tym doskonale prosperują karasie pospolite, liny i wzdręgi, które znajdują tu schronienie i obfitość pokarmu. Ze względu na płytkość i silne zarastanie, ryzyko przyduchy w upalne lato jest wysokie. Najlepsze efekty wędkarskie uzyskuje się tu późną wiosną i latem, celując w ciepłolubne gatunki ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20949, 1.9, 1, 2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20950, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-rogalin-20950', 'OXBOW', 52.2269546, 16.9370727, 'Wielkopolskie', 'Rogalin', 'To starorzecze, zlokalizowane w rejonie Rogalina, jest akwenem bez stałego połączenia z rzeką, co nadaje mu charakter bardziej stabilnego, choć zamkniętego ekosystemu. Dno jest średnio zamulone, z miejscowymi skupiskami zatopionych drzew i gałęzi, które stanowią doskonałe kryjówki dla ryb. Dostęp do brzegu jest dobry tylko z jednej strony, reszta jest gęsto zarośnięta krzewami i trzciną, co ogranicza swobodne przemieszczanie się. W akwenie tym z powodzeniem bytują szczupaki, okonie, płocie i leszcze, które dobrze czują się w zróżnicowanym środowisku. Umiarkowane zarastanie i ryzyko przyduchy w okresach suszy sprawiają, że wiosna i jesień to najlepsze pory na udane wędkowanie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20950, 3.1, 1.7, 3.2, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry z jednej strony, reszta zarośnięta', FALSE, 'Pojedyncze zatopione drzewa', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20951, 'Starorzecze (Puszczykowo)', 'starorzecze-puszczykowo-puszczykowo-20951', 'OXBOW', 52.2770104, 16.8588565, 'Wielkopolskie', 'Puszczykowo', 'To rozległe starorzecze w pobliżu Puszczykowa, okresowo łączące się z Wartą, jest jednym z najatrakcyjniejszych łowisk w regionie. Charakteryzuje się stosunkowo czystym dnem, z przewagą podłoża piaszczysto-żwirowego, co sprzyja występowaniu drapieżników. Brzegi są w większości dobrze dostępne, z licznymi dogodnymi miejscami do wędkowania, co czyni je popularnym celem dla wielu wędkarzy. W akwenie tym dominują sandacze i szczupaki, a także duże leszcze, płocie i okonie, które wpływają z rzeki. Niskie zamulenie i umiarkowane zarastanie minimalizują ryzyko przyduchy, co pozwala na udane połowy przez cały sezon. To idealne miejsce dla wędkarzy poszukujących różnorodnych gatunków ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20951, 6, 2.5, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sandacz,Szczupak,Leszcz,Płoć,Okoń', 'Dobry, z licznymi dogodnymi miejscami', FALSE, 'Czyste dno z nielicznymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20952, 'Starorzecze (Tychy)', 'starorzecze-tychy-tychy-20952', 'OXBOW', 50.1652707, 18.9979585, 'Śląskie', 'Tychy', 'Niewielkie starorzecze w Tychach to płytki i silnie zdegradowany akwen, który stanowi wyzwanie dla wędkarzy. Dno jest bardzo mocno zamulone, a w upalne lata istnieje ryzyko całkowitego wyschnięcia, co czyni je niestabilnym środowiskiem. Brzegi są trudne do pokonania, bagniste i gęsto porośnięte trzciną oraz inną roślinnością, wymagając użycia brodzących spodni. Mimo tych trudności, w akwenie tym przetrwały odporne gatunki, takie jak karaś srebrzysty, wzdręga i płoć, które dostosowały się do trudnych warunków. Ze względu na ekstremalne zamulenie i ryzyko przyduchy, najlepszym okresem na wędkowanie jest wczesna wiosna, zanim roślinność osiągnie pełnię rozwoju. To łowisko dla wytrwałych i cierpliwych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20952, 1.5, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, mocno zarośnięty i bagnisty', TRUE, 'Gęsta roślinność podwodna i muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20953, 'Starorzecze (Krajkowo)', 'starorzecze-krajkowo-krajkowo-20953', 'OXBOW', 52.2138269, 16.9236139, 'Wielkopolskie', 'Krajkowo', 'To starorzecze w Krajkowie, okresowo połączone z Wartą, oferuje typowe warunki dla tego typu akwenów. Dno jest średnio zamulone, z licznymi miejscami porośniętymi roślinnością podwodną, a także pojedynczymi korzeniami i gałęziami, które stanowią naturalne kryjówki dla ryb. Brzegi są mocno zarośnięte gęstą trzciną, co sprawia, że dostęp do wody jest utrudniony i często wymaga użycia brodzących spodni oraz wcześniejszego przygotowania stanowiska. W akwenie tym występują liny, karasie pospolite, płocie oraz szczupaki, które dobrze czują się w spokojnych i zarośniętych wodach. Ryzyko przyduchy w upalne lata jest umiarkowane, dlatego najlepsze efekty wędkarskie uzyskuje się wiosną i wczesnym latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20953, 2.3, 1.4, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Mocno zarośnięty trzciną, wymaga przygotowania', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20954, 'Starorzecze (Krajkowo)', 'starorzecze-krajkowo-krajkowo-20954', 'OXBOW', 52.2127466, 16.9237001, 'Wielkopolskie', 'Krajkowo', 'Drugie starorzecze w Krajkowie to niewielki, izolowany akwen o bardzo trudnym charakterze. Dno jest ekstremalnie zamulone, a płytkość zbiornika w połączeniu z gęstą roślinnością podwodną sprzyja silnemu zarastaniu. Brzegi są niemal nieprzystępne, pokryte gęstymi zaroślami i grząskim mułem, co wymaga od wędkarzy sporego wysiłku i konieczności brodzenia. Mimo tych trudności, w starorzeczu tym świetnie prosperują odporne gatunki, takie jak karaś srebrzysty, wzdręga oraz lin, które znajdują tu schronienie. Wysokie ryzyko przyduchy latem sprawia, że najlepszym czasem na wędkowanie jest późna wiosna, kiedy ryby są aktywne, a warunki jeszcze nie są ekstremalne. To łowisko dedykowane cierpliwym poszukiwaczom spokojnych wód.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20954, 1.8, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś srebrzysty,Wzdręga,Lin', 'Bardzo trudny, gęste zarośla i muł', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20955, 'Starorzecze (Krajkowo)', 'starorzecze-krajkowo-krajkowo-20955', 'OXBOW', 52.2129861, 16.925412, 'Wielkopolskie', 'Krajkowo', 'To starorzecze, również w rejonie Krajkowa, charakteryzuje się okresowym połączeniem z rzeką, co wpływa na jego dynamikę i różnorodność biologiczną. Dno jest średnio zamulone, z miejscowymi skupiskami roślinności podwodnej i pojedynczymi korzeniami, które stanowią atrakcyjne miejsca dla ryb. Dostęp do brzegów jest zróżnicowany – z niektórych stron jest dobry i wygodny, natomiast w innych miejscach brzegi są zarośnięte, choć nadal dostępne bez konieczności brodzenia. W akwenie tym dominują szczupaki i okonie, a także płocie i leszcze, które znajdują tu dobre warunki do żerowania. Umiarkowane zarastanie i niskie ryzyko przyduchy sprawiają, że jest to atrakcyjne łowisko przez cały sezon wędkarski, oferujące satysfakcjonujące połowy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20955, 2.5, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry z niektórych stron, reszta zarośnięta', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20956, 'Starorzecze (Jaszkowo)', 'starorzecze-jaszkowo-jaszkowo-20956', 'OXBOW', 52.13776, 16.9796216, 'Wielkopolskie', 'Jaszkowo', 'Starorzecze w Jaszkowie to odizolowany akwen o stabilnych warunkach, ceniony przez wędkarzy za swoją dostępność i różnorodność gatunkową. Dno jest przeważnie czyste, piaszczysto-muliste, z niewielkimi skupiskami roślinności, co ułatwia komfortowe wędkowanie. Brzegi są dobrze dostępne, z licznymi dogodnymi stanowiskami, co sprawia, że jest to popularne miejsce dla rodzin i początkujących wędkarzy. W akwenie tym z powodzeniem bytują karpie, liny, szczupaki, leszcze i płocie, które osiągają tu imponujące rozmiary. Niskie zamulenie i umiarkowane zarastanie minimalizują ryzyko przyduchy, co pozwala na udane połowy przez cały sezon. To doskonałe miejsce do relaksu i wędkowania w spokojnej okolicy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20956, 4, 2, 3.8, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Karp,Lin,Szczupak,Leszcz,Płoć', 'Dobry, z dogodnymi stanowiskami', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20957, 'Starorzecze (Wawrzeńczyce)', 'starorzecze-wawrzenczyce-wawrzenczyce-20957', 'OXBOW', 50.1074998, 20.3277516, 'Małopolskie', 'Wawrzeńczyce', 'Duże starorzecze w Wawrzeńczycach, na terenie Małopolski, utrzymuje stałe połączenie z Wisłą, co zapewnia ciągłą wymianę wody i bogactwo ryb. Dno jest czyste, z przewagą podłoża piaszczysto-żwirowego, z jedynie nielicznymi zaczepami, co sprzyja różnym technikom wędkarskim. Brzegi są bardzo dobrze dostępne, z licznymi utwardzonymi miejscami, idealnymi do wędkowania z brzegu lub z łodzi. W akwenie tym występują imponujące sumy i sandacze, a także duże leszcze, płocie i karpie, które regularnie wpływają z głównego koryta rzeki. Słabe zarastanie i niskie zamulenie sprawiają, że ryzyko przyduchy jest praktycznie zerowe, co pozwala na udane połowy przez cały rok. To prawdziwy raj dla wędkarzy poszukujących dużych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20957, 7.5, 3, 6, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Sandacz,Leszcz,Płoć,Karp', 'Dobry, liczne utwardzone miejsca', FALSE, 'Czyste dno z nielicznymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20958, 'Starorzecze (Krobielewko)', 'starorzecze-krobielewko-krobielewko-20958', 'OXBOW', 52.634496, 15.7031419, 'Lubuskie', 'Krobielewko', 'Starorzecze w Krobielewku, zlokalizowane w województwie lubuskim, to rozległy akwen okresowo połączony z Wartą. Charakteryzuje się dnem o średnim zamuleniu, z miejscowymi skupiskami zatopionych drzew i konarów, które stanowią idealne kryjówki dla drapieżników. Brzegi są w większości dobrze dostępne, co umożliwia swobodne przemieszczanie się i wybór odpowiedniego stanowiska. W akwenie tym z powodzeniem łowione są szczupaki, okonie, jazie, klenie oraz płocie, które cenią sobie zróżnicowane środowisko. Umiarkowane zarastanie i brak ryzyka przyduchy sprawiają, że jest to atrakcyjne łowisko, szczególnie wiosną i jesienią, kiedy drapieżniki są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20958, 5, 2.2, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Jaź,Kleń,Płoć', 'Dobry, z dostępem do większości brzegów', FALSE, 'Pojedyncze zatopione drzewa i konary', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20959, 'Starorzecze (Wawrzeńczyce)', 'starorzecze-wawrzenczyce-wawrzenczyce-20959', 'OXBOW', 50.113065, 20.3425438, 'Małopolskie', 'Wawrzeńczyce', 'To mniejsze starorzecze w Wawrzeńczycach jest akwenem izolowanym od Wisły, co prowadzi do specyficznych warunków środowiskowych. Dno jest mocno zamulone, z grubą warstwą osadów organicznych i gęstą roślinnością podwodną, co sprawia, że łowienie jest wyzwaniem. Brzegi są trudne do pokonania, często bagniste i gęsto porośnięte trzciną, co wymaga użycia brodzących spodni. Mimo tych trudności, starorzecze to jest ostoją dla lina, karasia pospolitego, wzdręgi i płoci, które doskonale prosperują w tych spokojnych, zarośniętych wodach. Wysokie zamulenie i silne zarastanie niosą ze sobą ryzyko przyduchy w okresie letnim, dlatego najlepsze efekty połowowe uzyskuje się późną wiosną i latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20959, 3, 1.5, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty i gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna i muł', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20960, 'Starorzecze Stręgoborzyce', 'starorzecze-stregoborzyce-proszowice-20960', 'OXBOW', 50.1282216, 20.2879277, 'Małopolskie', 'Proszowice', 'To malownicze starorzecze charakteryzuje się płytką wodą i mulistym dnem, co sprzyja rozwojowi bujnej roślinności podwodnej. Brzegi są częściowo dostępne, lecz w wielu miejscach porasta je gęsta trzcina, utrudniając dostęp do wody. Jest to idealne łowisko dla wędkarzy poszukujących spokojnych miejsc i ryb typowych dla wód stojących. Występują tu liczne zatopione drzewa i konary, stanowiące doskonałe kryjówki dla drapieżników. Latem, przy wysokich temperaturach, istnieje umiarkowane ryzyko spadku poziomu tlenu, co może wpływać na aktywność ryb. Wędkowanie z brodzeniem jest często konieczne, aby dotrzeć do najlepszych miejscówek.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20960, 3.8, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20961, 'Starorzecze Ispina (zachodnie)', 'starorzecze-ispina-zachodnie-niepolomice-20961', 'OXBOW', 50.1131752, 20.3579698, 'Małopolskie', 'Niepołomice', 'Starorzecze w Ispinie to rozległy akwen z dnem pokrytym grubą warstwą mułu i resztek roślinnych. Charakteryzuje się zróżnicowaną głębokością, z kilkoma głębszymi rynnami, które stanowią schronienie dla większych okazów ryb. Brzegi są stosunkowo łatwo dostępne, choć miejscami występują podmokłe obszary. Woda jest bogata w roślinność zanurzoną i wynurzoną, co zapewnia doskonałe warunki bytowania dla wielu gatunków. Połączenie z rzeką macierzystą jest nieregularne, co wpływa na dynamikę populacji ryb. Wędkarze mogą liczyć na obfite brania, szczególnie w cieplejszych miesiącach. Wymaga to jednak cierpliwości i umiejętności odnajdywania ryb w gęstej roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20961, 6.2, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Okoń,Sum,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20962, 'Starorzecze Ispina (wschodnie)', 'starorzecze-ispina-wschodnie-niepolomice-20962', 'OXBOW', 50.1130651, 20.3570103, 'Małopolskie', 'Niepołomice', 'To mniejsze starorzecze w pobliżu Ispiny jest silnie zarośnięte, co czyni je trudnym, ale potencjalnie bardzo rewardingowym łowiskiem. Dno jest głównie muliste, z licznymi zatopionymi roślinami i gałęziami, które tworzą naturalne kryjówki. Brzegi są bagniste i wymagają ostrożności, a dostęp do wody jest ograniczony. Połączenie z rzeką występuje jedynie podczas bardzo wysokich stanów wody, co sprzyja stabilizacji ekosystemu. Ryzyko niedoboru tlenu jest podwyższone w upalne lata, co należy brać pod uwagę planując wyprawę. Jest to idealne miejsce dla wędkarzy poszukujących lina i karasia, które doskonale prosperują w takich warunkach. Użycie długich wędek i precyzyjne zarzucanie jest kluczem do sukcesu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20962, 2.5, 1, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20963, 'Starorzecze Trawniki', 'starorzecze-trawniki-bochnia-20963', 'OXBOW', 50.1380853, 20.4074252, 'Małopolskie', 'Bochnia', 'Starorzecze w Trawnikach to zbiornik o umiarkowanej wielkości, charakteryzujący się czystym dnem w części środkowej i mulistymi brzegami. Roślinność podwodna jest obecna, ale nie dominująca, co ułatwia wędkowanie. Brzegi są w większości dobrze dostępne, z kilkoma dogodnymi stanowiskami wędkarskimi. Połączenie z rzeką jest rzadkie, co sprzyja stabilnym warunkom wodnym. Ryzyko niedoboru tlenu jest niskie dzięki umiarkowanemu zarośnięciu. Wędkarze mogą spodziewać się różnorodności gatunków, od płoci po większe karpie i leszcze. Jest to dobre miejsce na rodzinne wypady, nie wymagające specjalistycznego sprzętu ani brodzenia. Regularne zarybienia zwiększają atrakcyjność łowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20963, 5.1, 1.8, 3.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20964, 'Starorzecze Kamień Łukawski', 'starorzecze-kamien-lukawski-stalowa-wola-20964', 'OXBOW', 50.6832684, 21.7859811, 'Podkarpackie', 'Stalowa Wola', 'To starorzecze, położone w pobliżu Kamienia Łukawskiego, wyróżnia się znaczną głębokością w niektórych partiach, co czyni je atrakcyjnym dla sumów i sandaczy. Dno jest zróżnicowane, od piaszczystego po muliste, z licznymi przeszkodami w postaci zatopionych drzew. Brzegi są trudne do pokonania, często bagniste i zarośnięte, co wymaga użycia brodzeń. Starorzecze ma stałe, choć ograniczone, połączenie z rzeką, co zapewnia regularną wymianę wody i dobre natlenienie. Ze względu na głębokość i połączenie z rzeką, ryzyko przyduchy jest minimalne. Jest to wymagające łowisko, ale oferujące szansę na naprawdę duże ryby. Wędkarstwo spinningowe i gruntowe są tutaj szczególnie efektywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20964, 12, 2.5, 6, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Sandacz,Szczupak,Leszcz,Okoń', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20965, 'Starorzecze Harklowa', 'starorzecze-harklowa-nowy-targ-20965', 'OXBOW', 49.474896, 20.1463105, 'Małopolskie', 'Nowy Targ', 'Starorzecze w Harklowej to niewielki, urokliwy zbiornik o charakterystycznym mulistym dnie i gęstej roślinności wynurzonej. Brzegi są łatwo dostępne w kilku miejscach, ale dominują tam zarośla i trzciny. Akwen jest całkowicie odcięty od rzeki, co sprawia, że jego ekosystem jest bardzo stabilny, choć podatny na wahania poziomu wody. Latem, przy wysokich temperaturach, istnieje podwyższone ryzyko niedoboru tlenu, co może wpływać na aktywność ryb. Jest to doskonałe miejsce do łowienia lina i karasia, które dobrze czują się w takich warunkach. Wędkarstwo spławikowe jest tutaj najskuteczniejsze. Cisza i spokój tego miejsca przyciągają wędkarzy szukających relaksu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20965, 1.5, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', FALSE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20966, 'Starorzecze Świątniki (północne)', 'starorzecze-swiatniki-polnocne-kornik-20966', 'OXBOW', 52.2199875, 16.9489633, 'Wielkopolskie', 'Kórnik', 'To starorzecze w Świątnikach charakteryzuje się dość płytką wodą i dnem pokrytym grubą warstwą mułu. Brzegi są w większości mocno zarośnięte trzciną, co utrudnia dostęp do wody, ale zapewnia doskonałe schronienie dla ryb. Występuje tu umiarkowane połączenie z rzeką podczas wiosennych roztopów, co sprzyja odświeżaniu wody. Ryzyko niedoboru tlenu jest średnie, zwłaszcza w suchsze lata. Jest to typowe łowisko dla karasia i lina, ale można tu również spotkać płocie i okonie. Wymaga to cierpliwości i często brodzenia, aby znaleźć dogodne miejsca do wędkowania. Warto eksplorować miejsca z niewielkimi prześwitami w roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20966, 4.2, 1.2, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20967, 'Starorzecze Świątniki (południowe)', 'starorzecze-swiatniki-poludniowe-kornik-20967', 'OXBOW', 52.2212997, 16.9484264, 'Wielkopolskie', 'Kórnik', 'Drugie starorzecze w Świątnikach jest nieco głębsze i mniej zarośnięte niż jego północny odpowiednik. Dno jest mulisto-piaszczyste, z mniejszą ilością zatopionych przeszkód. Brzegi są bardziej dostępne, choć nadal w niektórych miejscach występują zarośla. Połączenie z rzeką jest rzadkie, co sprzyja stabilnym warunkom, ale może prowadzić do spadków tlenu w upalne lata. Jest to dobre miejsce na połów leszcza i karpia, a także drapieżników takich jak szczupak. Wędkarstwo gruntowe i spławikowe są tutaj skuteczne. Starorzecze oferuje przyjemne warunki do wędkowania dla wędkarzy na każdym poziomie zaawansowania. Warto szukać głębszych partii wody, gdzie ryby często żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20967, 3.5, 1.7, 3.2, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Szczupak,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20968, 'Starorzecze Bielice', 'starorzecze-bielice-nysa-20968', 'OXBOW', 50.5715717, 17.4798658, 'Opolskie', 'Nysa', 'Starorzecze w Bielicach to akwen o zróżnicowanej głębokości, z przewagą mulistego dna, ale także z twardszymi, piaszczystymi fragmentami. Brzegi są dość łatwo dostępne, z kilkoma dogodnymi miejscami do rozłożenia sprzętu. Roślinność wodna jest umiarkowana, co pozwala na swobodne zarzucanie. Połączenie z rzeką jest rzadkie, co sprzyja spokojnemu charakterowi łowiska. Ryzyko niedoboru tlenu jest niskie, dzięki czemu ryby są aktywne przez większość sezonu. Jest to idealne miejsce dla wędkarzy poszukujących leszczy, płoci, a także karpi. Występują tu również okonie i szczupaki, zwłaszcza w pobliżu zatopionych przeszkód. Warto spróbować różnych technik wędkowania, aby odkryć najlepsze metody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20968, 7, 2.1, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Płoć,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20969, 'Starorzecze Gorzędziej (północne)', 'starorzecze-gorzedziej-polnocne-kwidzyn-20969', 'OXBOW', 54.0300479, 18.8234216, 'Pomorskie', 'Kwidzyn', 'To starorzecze w Gorzędzieju charakteryzuje się głęboką wodą i dnem częściowo piaszczystym, częściowo mulistym. Brzegi są zróżnicowane – od łatwo dostępnych po mocno zarośnięte. Stałe połączenie z Wisłą zapewnia doskonałe natlenienie i regularne zasilanie w ryby, co czyni je bardzo atrakcyjnym łowiskiem. Dzięki temu ryzyko niedoboru tlenu jest minimalne. Występują tu liczne gatunki rzeczne i starorzeczne, w tym duże sumy, sandacze i szczupaki. Jest to wymagające łowisko, ale oferujące szansę na rekordowe okazy. Wędkarstwo spinningowe i gruntowe są szczególnie efektywne. Warto zwrócić uwagę na prądy wodne, które mogą wpływać na prezentację przynęty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20969, 9.5, 3, 7, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Sandacz,Szczupak,Leszcz,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20970, 'Starorzecze Gorzędziej (środkowe)', 'starorzecze-gorzedziej-srodkowe-kwidzyn-20970', 'OXBOW', 54.0220492, 18.8247146, 'Pomorskie', 'Kwidzyn', 'Środkowe starorzecze w Gorzędzieju to akwen o umiarkowanej głębokości, z dnem typowo mulistym i bogatą roślinnością podwodną. Brzegi są trudne do pokonania, często bagniste i zarośnięte, co wymaga użycia brodzeń. Połączenie z rzeką jest nieregularne, występując tylko podczas wysokich stanów wody. Ryzyko niedoboru tlenu jest średnie, zwłaszcza w upalne lata. Jest to idealne miejsce dla wędkarzy poszukujących lina, karasia i leszcza, które doskonale prosperują w takich warunkach. Występują tu również szczupaki, ukrywające się w gęstej roślinności. Wędkarstwo spławikowe i spinningowe z łódki lub pontonu są tutaj najbardziej efektywne. Cierpliwość jest kluczem do sukcesu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20970, 6.8, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Leszcz,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20971, 'Starorzecze Mała Słońca (zachodnie)', 'starorzecze-mala-slonca-zachodnie-kwidzyn-20971', 'OXBOW', 54.0150933, 18.8285477, 'Pomorskie', 'Kwidzyn', 'Starorzecze w Małej Słońcy to stosunkowo płytki akwen z dnem pokrytym grubą warstwą mułu i obfitą roślinnością. Brzegi są mocno zarośnięte trzciną, co znacząco utrudnia dostęp do wody i wymaga brodzenia. Brak stałego połączenia z rzeką sprawia, że jest to środowisko bardzo stabilne, ale jednocześnie podatne na spadki tlenu w upalne lata. Jest to doskonałe miejsce do łowienia karasia i lina, które doskonale czują się w takich warunkach. Występują tu również liczne wzdręgi i płocie. Wędkarstwo spławikowe jest tutaj najskuteczniejsze. Warto pamiętać o zabraniu repelentów na owady. Cisza i spokój tego miejsca sprzyjają relaksowi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20971, 2.1, 0.9, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20972, 'Starorzecze Mała Słońca (wschodnie)', 'starorzecze-mala-slonca-wschodnie-kwidzyn-20972', 'OXBOW', 54.0158595, 18.8272636, 'Pomorskie', 'Kwidzyn', 'To starorzecze w Małej Słońcy jest nieco głębsze niż jego zachodni odpowiednik i charakteryzuje się dnem mulisto-piaszczystym. Brzegi są miejscami dostępne, ale w większości zarośnięte, choć mniej bagniste. Połączenie z rzeką występuje podczas wysokich stanów wody, co zapewnia odświeżanie akwenu. Ryzyko niedoboru tlenu jest umiarkowane. Jest to dobre miejsce na połów leszcza, karpia i płoci, a także szczupaka, który poluje na mniejsze ryby. Wędkarstwo gruntowe i spławikowe są tutaj skuteczne. Warto poszukać miejsc z prześwitami w roślinności, gdzie ryby często żerują. Starorzecze oferuje przyjemne warunki do wędkowania dla wędkarzy ceniących spokój.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20972, 2.8, 1.4, 2.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Płoć,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20973, 'Starorzecze Gorzędziej (południowe)', 'starorzecze-gorzedziej-poludniowe-kwidzyn-20973', 'OXBOW', 54.0325871, 18.8211707, 'Pomorskie', 'Kwidzyn', 'Południowe starorzecze w Gorzędzieju to jeden z większych akwenów w kompleksie, charakteryzujący się zróżnicowaną głębokością i dnem od piaszczystego po muliste. Brzegi są w większości dobrze dostępne, z licznymi dogodnymi stanowiskami wędkarskimi. Stałe, choć ograniczone, połączenie z Wisłą zapewnia dobre natlenienie i regularne zasilanie w ryby. Ryzyko niedoboru tlenu jest niskie. Jest to doskonałe miejsce dla wędkarzy poszukujących dużych leszczy, karpi, a także drapieżników takich jak szczupak i okoń. Wędkarstwo gruntowe i spławikowe są tutaj bardzo efektywne. Warto eksplorować różne głębokości i typy dna. To łowisko oferuje wiele możliwości dla wędkarzy na każdym poziomie zaawansowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20973, 11.2, 2.8, 6.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Szczupak,Okoń,Sum', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20974, 'Starorzecze Orkowo', 'starorzecze-orkowo-sroda-wielkopolska-20974', 'OXBOW', 52.1638937, 17.0021721, 'Wielkopolskie', 'Środa Wielkopolska', 'Starorzecze w Orkowo to malowniczy zbiornik o umiarkowanej wielkości, z dnem mulistym i bogatą roślinnością podwodną. Brzegi są częściowo dostępne, ale w wielu miejscach porasta je gęsta trzcina, utrudniając dostęp do wody. Połączenie z rzeką jest nieregularne, występując tylko podczas bardzo wysokich stanów wody. Ryzyko niedoboru tlenu jest podwyższone w upalne lata, co należy brać pod uwagę. Jest to idealne miejsce dla wędkarzy poszukujących lina i karasia, które doskonale prosperują w takich warunkach. Występują tu również płocie i wzdręgi. Wędkarstwo spławikowe jest tutaj najskuteczniejsze. Cierpliwość i precyzja są kluczem do sukcesu. Warto szukać prześwitów w roślinności, gdzie ryby często żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20974, 4.5, 1.3, 2.7, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20975, 'Starorzecze (Orkowo) 1', 'starorzecze-orkowo-1-orkowo-20975', 'OXBOW', 52.1657711, 17.0015797, 'Wielkopolskie', 'Orkowo', 'To starorzecze, położone w malowniczej dolinie Warty, charakteryzuje się typowym dla tego regionu, płytkim profilem. Dno jest tu w przeważającej części muliste, z lokalnymi twardszymi fragmentami piaskowo-żwirowymi, co sprzyja rozwojowi bogatej fauny dennej. Brzegi są w większości porośnięte gęstymi pasami trzcin i pałki wodnej, co utrudnia dostęp, ale jednocześnie tworzy doskonałe schronienie dla ryb. Wędkarze mogą spodziewać się tu obfitości płoci, leszczy oraz linów, które doskonale czują się w zarośniętych partiach. Latem silne nasłonecznienie i bujna roślinność mogą prowadzić do lokalnych spadków tlenu, co jest typowe dla starorzeczy. Mimo trudności w dostępie, łowisko oferuje spokój i kontakt z dziką przyrodą, a największe szanse na sukces są wczesną wiosną i jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20975, 3.8, 1.5, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Płoć,Leszcz,Lin,Szczupak', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna i pojedyncze korzenie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20976, 'Starorzecze (Orkowo) 2', 'starorzecze-orkowo-2-orkowo-20976', 'OXBOW', 52.1672539, 17.0013859, 'Wielkopolskie', 'Orkowo', 'Drugie z serii starorzeczy w okolicy Orkowo, charakteryzuje się nieco głębszym korytem w centralnej części, co sprzyja występowaniu większych okazów ryb. Dno jest tu zróżnicowane, od mulistych zatok po twardsze, piaszczyste płycizny. Brzegi są częściowo dostępne, zwłaszcza od strony pól uprawnych, gdzie roślinność jest mniej bujna. Akwen jest bogato porośnięty liliami wodnymi i rdestnicami, tworząc idealne kryjówki dla drapieżników. Występują tu liczne okonie, szczupaki oraz karasie pospolite, które dobrze radzą sobie w zarośniętych wodach. Obfitość owadów i drobnych bezkręgowców stanowi solidną bazę pokarmową dla ryb. Wędkowanie z pontonu lub łódki jest często najefektywniejsze ze względu na rozległe zarośla.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20976, 4.5, 1.8, 3.5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Okoń,Szczupak,Karaś pospolity,Wzdręga', 'Częściowo dostępny, miejscami zarośnięty', FALSE, 'Gęsta roślinność podwodna', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20977, 'Starorzecze (Orkowo) 3', 'starorzecze-orkowo-3-orkowo-20977', 'OXBOW', 52.167973, 17.0004435, 'Wielkopolskie', 'Orkowo', 'To starorzecze wyróżnia się bardziej otwartą przestrzenią wodną w porównaniu do sąsiednich akwenów. Dno jest przeważnie piaszczysto-muliste, z nielicznymi zaczepami w postaci zatopionych gałęzi. Brzegi są dość łatwo dostępne, z miejscowymi fragmentami porośniętymi trawą i kępami trzcin. Roślinność podwodna jest umiarkowana, co sprzyja wędkarstwu spławikowemu i gruntowemu. Głównymi gatunkami ryb są płoć, leszcz oraz karp, który znajduje tu dogodne warunki do żerowania. Wczesną wiosną można liczyć na dobre brania, gdy ryby intensywnie żerują po zimie. Latem, w upalne dni, aktywność ryb może spadać, ale poranne i wieczorne godziny nadal oferują szanse na udany połów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20977, 2.9, 1.2, 2.5, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Płoć,Leszcz,Karp,Karaś srebrzysty', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20978, 'Starorzecze (Orkowo) 4', 'starorzecze-orkowo-4-orkowo-20978', 'OXBOW', 52.171002, 17.0033441, 'Wielkopolskie', 'Orkowo', 'To starorzecze jest jednym z bardziej odizolowanych akwenów w kompleksie Orkowo, co sprzyja zachowaniu jego dzikiego charakteru. Dno jest głęboko muliste, z licznymi osadami organicznymi, co wskazuje na zaawansowany proces starzenia się zbiornika. Brzegi są trudne do pokonania, gęsto porośnięte zaroślami i podmokłe, co wymaga użycia wodoodpornego obuwia. Roślinność wodna jest bardzo bujna, dominują moczarka kanadyjska i rdestnice, tworząc podwodne łąki. Jest to idealne środowisko dla linów, karasi pospolitych i węgorzy. Wędkowanie wymaga cierpliwości i precyzji, ale nagrodą mogą być piękne okazy ryb, które rzadko widują wędkarzy. Najlepsze wyniki osiąga się w miejscach z niewielkimi prześwitami w roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20978, 5.1, 1.6, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Węgorz,Szczupak', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna, dużo zatopionych gałęzi', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20979, 'Starorzecze (Orkowo) 5', 'starorzecze-orkowo-5-orkowo-20979', 'OXBOW', 52.171946, 17.0039375, 'Wielkopolskie', 'Orkowo', 'Starorzecze to charakteryzuje się dość regularnym kształtem i umiarkowanym zarośnięciem, co ułatwia wędkarstwo z brzegu. Dno jest mieszane, z przewagą mułu, ale z licznymi twardszymi plamami żwiru i piasku, szczególnie w pobliżu dawnego koryta rzeki. Brzegi są stabilne i stosunkowo łatwo dostępne, z pojedynczymi kępami trzcin. Występuje tu zróżnicowana roślinność podwodna, tworząca schronienia dla ryb, ale nie utrudniająca zbytnio zarzucania. Akwen jest znany z populacji leszczy i płoci, a także okazjonalnie trafiających się sandaczy, zwłaszcza w głębszych partiach. Wędkowanie gruntowe i spławikowe przynosi tu najlepsze rezultaty, szczególnie w okresach umiarkowanej pogody. To dobre miejsce na rodzinne wypady wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20979, 2.7, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Sandacz,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20980, 'Starorzecze (Orkowo) 6', 'starorzecze-orkowo-6-orkowo-20980', 'OXBOW', 52.1749592, 17.0021215, 'Wielkopolskie', 'Orkowo', 'To starorzecze jest jednym z większych w kompleksie Orkowo, oferującym różnorodne warunki dla wędkarzy. Dno jest w większości muliste, ale z wyraźnymi głęboczkami i miejscami twardymi, gdzie kiedyś znajdowało się główne koryto rzeki. Brzegi są miejscami podmokłe i zarośnięte, ale istnieją też wygodne stanowiska, zwłaszcza od strony lasu. Roślinność podwodna jest bujna w płytszych zatokach, tworząc idealne środowisko dla drobnicy i drapieżników. Akwen słynie z obecności dużych szczupaków i sumów, które polują na licznie występujące płocie i leszcze. Wędkowanie na spinning lub żywca jest tu bardzo efektywne. Warto eksplorować różne partie zbiornika, aby znaleźć najbardziej obiecujące miejsca.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20980, 6.2, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sum,Leszcz,Płoć,Okoń', 'Miejscami dobry, miejscami mocno zarośnięty', FALSE, 'Dużo zatopionych drzew i gęsta roślinność podwodna', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20981, 'Starorzecze (Orkowo) 7', 'starorzecze-orkowo-7-orkowo-20981', 'OXBOW', 52.1723385, 17.002815, 'Wielkopolskie', 'Orkowo', 'To niewielkie, ale urokliwe starorzecze charakteryzuje się dużą ilością roślinności wodnej, co tworzy raj dla ryb spokojnego żeru. Dno jest w przeważającej części muliste, z grubą warstwą osadów organicznych, co jest typowe dla płytkich, zarośniętych akwenów. Brzegi są dość mocno porośnięte trzcinami i krzewami, co wymaga poszukiwania dogodnych miejsc do zarzucenia. Występują tu głównie liny, karasie pospolite i wzdręgi, które doskonale maskują się w gęstwinie roślin. Mimo niewielkiej powierzchni, akwen potrafi zaskoczyć wielkością złowionych ryb. Wędkowanie na spławik z użyciem naturalnych przynęt daje najlepsze rezultaty. Warto pamiętać o zabraniu podbieraka z długą rączką.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20981, 1.9, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20982, 'Starorzecze (Orkowo) 8', 'starorzecze-orkowo-8-orkowo-20982', 'OXBOW', 52.17453, 16.9995068, 'Wielkopolskie', 'Orkowo', 'Starorzecze to, położone w bliskim sąsiedztwie pól uprawnych, charakteryzuje się otwartym charakterem i mniejszym zalesieniem brzegów. Dno jest stosunkowo twarde, piaszczysto-żwirowe, z miejscowymi osadami mułu. Brzegi są łatwo dostępne, z licznymi przetrzcinieniami i miejscami dogodnymi do rozłożenia sprzętu. Roślinność podwodna jest umiarkowana, co sprzyja wędkarstwu spinningowemu. Akwen jest domem dla licznych okoni i szczupaków, które aktywnie polują na drobnicę. Występują tu również płocie i leszcze, szczególnie w głębszych partiach. Ze względu na łatwy dostęp, jest to popularne miejsce wśród lokalnych wędkarzy. Najlepsze wyniki osiąga się wczesnym rankiem lub późnym wieczorem, szczególnie w cieplejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20982, 3.5, 1.3, 2.7, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Okoń,Szczupak,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20983, 'Starorzecze (Orkowo) 9', 'starorzecze-orkowo-9-orkowo-20983', 'OXBOW', 52.1767349, 17.0020306, 'Wielkopolskie', 'Orkowo', 'Ostatnie z grupy starorzeczy w Orkowo, to akwen o wydłużonym kształcie, przypominającym dawne koryto rzeki. Dno jest zróżnicowane, od mulistych dołków po twardsze, piaszczyste wypłycenia, idealne dla ryb żerujących. Brzegi są częściowo dostępne, z licznymi zatokami porośniętymi trzciną, które stanowią doskonałe kryjówki dla ryb. Roślinność podwodna jest umiarkowana, ale w niektórych miejscach tworzy gęste zarośla. Występują tu liczne leszcze, płocie, a także karpie i liny, które doceniają bogactwo naturalnego pokarmu. Wędkowanie z gruntu lub na spławik daje tu dobre rezultaty. Akwen jest ceniony za swoje walory krajobrazowe i spokój, co sprzyja relaksowi nad wodą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20983, 4.1, 1.4, 2.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Lin', 'Częściowo dostępny, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gęsta roślinność podwodna', 'Wiosna, lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20984, 'Starorzecze (Niesłabin)', 'starorzecze-nieslabin-nieslabin-20984', 'OXBOW', 52.1501208, 16.9911731, 'Wielkopolskie', 'Niesłabin', 'Starorzecze w Niesłabinie to malowniczy akwen o bogatej historii, będący pozostałością po meandrach Warty. Dno jest w większości muliste, z grubą warstwą osadów, co sprzyja rozwojowi bentosu. Brzegi są miejscami podmokłe, ale w wielu punktach dostępne, zwłaszcza od strony lasu, gdzie teren jest bardziej stabilny. Roślinność wodna jest bardzo bujna, dominują lilie wodne i rdestnice, tworząc rozległe podwodne dywany. Akwen jest prawdziwym rajem dla linów, karasi pospolitych i wzdręg, a także dla okazjonalnie występujących sumów. Wędkowanie wymaga cierpliwości i precyzji, najlepiej z użyciem pontonu lub łódki. To idealne miejsce dla wędkarzy ceniących dziką przyrodę i wyzwania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20984, 5.5, 1.9, 4, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Sum,Wzdręga', 'Trudny, bagnisty, miejscami mocno zarośnięty', TRUE, 'Dużo zatopionych drzew i gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20985, 'Starorzecze (Brzumin)', 'starorzecze-brzumin-brzumin-20985', 'OXBOW', 51.9441879, 21.2538335, 'Mazowieckie', 'Brzumin', 'Starorzecze w Brzuminie, położone w dolinie Wisły, charakteryzuje się silnym wpływem rzeki, szczególnie podczas wiosennych roztopów. Dno jest zróżnicowane, od piaszczystych płycizn po muliste zagłębienia, z licznymi zaczepami w postaci zatopionych drzew. Brzegi są częściowo umocnione, ale w wielu miejscach podmywane przez wodę, co tworzy naturalne kryjówki dla ryb. Roślinność wodna jest umiarkowana, ale w zatokach pojawiają się gęste zarośla. Akwen jest domem dla wielu gatunków rzecznych, takich jak leszcze, płocie, bolenie, jazie i klenie, które wpływają tu z Wisły. Wędkowanie gruntowe i spinningowe jest tu bardzo efektywne. To dynamiczne łowisko, które zmienia swój charakter w zależności od poziomu wody w Wiśle.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20985, 7, 2.2, 5, 'Stałe połączenie', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Boleń,Jaź,Kleń', 'Częściowo dobry, miejscami trudny z powodu podmyć', FALSE, 'Dużo zatopionych drzew i korzeni', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20986, 'Starorzecze (Ostrówik)', 'starorzecze-ostrowik-ostrowik-20986', 'OXBOW', 51.9450227, 21.2554224, 'Mazowieckie', 'Ostrówik', 'To starorzecze, sąsiadujące z Brzuminem, ma nieco bardziej odizolowany charakter, choć również jest pod wpływem Wisły. Dno jest przeważnie muliste, z lokalnymi płyciznami piaszczystymi, które są popularnymi miejscami żerowania. Brzegi są w większości stabilne, z pojedynczymi kępami trzcin, co ułatwia dostęp. Roślinność podwodna jest umiarkowana, ale tworzy liczne schronienia dla ryb. Akwen jest znany z populacji karpi, leszczy i płoci, a także drapieżników takich jak szczupak i okoń. Wędkowanie z gruntu i na spławik daje tu dobre rezultaty. Jest to spokojne łowisko, idealne na relaksujące dni nad wodą, z szansą na złowienie dorodnych okazów. Warto szukać ryb w pobliżu zatopionych pni i gałęzi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20986, 6.5, 2, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Leszcz,Płoć,Szczupak,Okoń', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20987, 'Starorzecze (Jaszkowo)', 'starorzecze-jaszkowo-jaszkowo-20987', 'OXBOW', 52.2217149, 17.1563606, 'Wielkopolskie', 'Jaszkowo', 'Starorzecze w Jaszkowie, położone w pobliżu Warty, wyróżnia się znacznym zarośnięciem i wysokim poziomem zamulenia. Dno jest głęboko muliste, z dużą ilością detrytusu, co sprzyja rozwojowi specyficznej fauny dennej. Brzegi są trudne do pokonania, gęsto porośnięte trzciną, pałką wodną i krzewami, co wymaga od wędkarza determinacji. Roślinność wodna jest ekstremalnie bujna, tworząc liczne pływające wyspy i podwodne gąszcze. Akwen jest ostoją dla linów, karasi pospolitych i węgorzy, które doskonale czują się w tak trudnym środowisku. Wędkowanie jest tu wyzwaniem, ale nagrodą mogą być piękne, dzikie okazy. Najlepsze efekty daje wędkarstwo spławikowe w wykoszonych miejscach lub z pontonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20987, 3.2, 1.1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Węgorz,Wzdręga', 'Trudny, mocno zarośnięty trzciną i bagnisty', TRUE, 'Gęsta roślinność podwodna i dużo zatopionych gałęzi', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20988, 'Starorzecze (Wszebory)', 'starorzecze-wszebory-wszebory-20988', 'OXBOW', 52.6801511, 22.1992635, 'Mazowieckie', 'Wszebory', 'Starorzecze we Wszeborach to akwen o charakterze typowo nadrzecznym, zlokalizowany w bliskości Bugu. Dno jest zróżnicowane, od piaszczystych łach po muliste dołki, z licznymi naturalnymi kryjówkami. Brzegi są miejscami łatwo dostępne, a w innych zarośnięte drzewami i krzewami, co tworzy idealne warunki dla drapieżników. Roślinność podwodna jest umiarkowana, ale w zatokach pojawiają się gęste zarośla. Akwen jest znany z populacji szczupaków i okoni, a także leszczy i płoci, które regularnie wpływają tu z rzeki. Wędkowanie na spinning jest tu bardzo efektywne, zwłaszcza wzdłuż linii brzegowej i wokół zatopionych drzew. To łowisko oferuje zarówno emocje z polowania na drapieżniki, jak i spokojne zasiadki na ryby spokojnego żeru.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20988, 4.8, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Jaź', 'Miejscami dobry, miejscami zarośnięty drzewami', FALSE, 'Dużo zatopionych drzew i pojedyncze korzenie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20989, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-20989', 'OXBOW', 53.5252796, 22.809842, 'Podlaskie', 'Wólka Piaseczna', 'To starorzecze, położone w malowniczej Krainie Wielkich Jezior, charakteryzuje się czystą wodą i umiarkowanym zarośnięciem. Dno jest zróżnicowane, od piaszczystych blatów po muliste dołki, z twardym podłożem w centralnej części. Brzegi są w większości łatwo dostępne, z naturalnymi trawami i rzadkimi kępami trzcin. Roślinność podwodna jest umiarkowana, co sprzyja różnym technikom wędkowania. Akwen jest domem dla licznych płoci, leszczy, a także karpi i linów, które znajdują tu bogactwo naturalnego pokarmu. Występują tu również sandacze i szczupaki, polujące na drobnicę. To łowisko oferuje komfortowe warunki dla wędkarzy i jest cenione za swoje walory rekreacyjne. Najlepsze wyniki osiąga się wczesnym rankiem i późnym wieczorem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20989, 8, 2.5, 6, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Płoć,Leszcz,Karp,Sandacz,Szczupak', 'Dobry z większości stron', FALSE, 'Czyste dno, pojedyncze korzenie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20990, 'Starorzecze Wroceń 1', 'starorzecze-wrocen-1-goniadz-20990', 'OXBOW', 53.5257336, 22.8182257, 'Podlaskie', 'Goniądz', 'To starorzecze, położone w malowniczej dolinie Biebrzy, charakteryzuje się dość regularnym kształtem i średnią głębokością. Dno jest muliste z miejscowymi twardszymi partiami, co sprzyja bytności różnorodnych gatunków ryb. Brzegi są w większości dostępne, porośnięte trawami i pojedynczymi krzewami, co ułatwia wędkowanie z brzegu. Roślinność podwodna jest umiarkowana, tworząc idealne kryjówki dla drapieżników, takich jak szczupak i okoń. W starorzeczu tym z powodzeniem można łowić liny, płocie i leszcze, szczególnie w cieplejszych miesiącach. Wędkowanie jest tu przyjemne, choć w niektórych miejscach mogą występować zaczepy w postaci zatopionych gałęzi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20990, 3.2, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20991, 'Starorzecze Wroceń 2', 'starorzecze-wrocen-2-goniadz-20991', 'OXBOW', 53.5235416, 22.8127957, 'Podlaskie', 'Goniądz', 'Drugie starorzecze w okolicy Wrocnia jest znacznie bardziej zarośnięte i płytsze, co nadaje mu charakter typowego, powoli umierającego zbiornika. Dno jest w przeważającej części mocno zamulone, co utrudnia skuteczne wędkowanie z gruntu. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co wymaga użycia brodzących spodniobutów. Obfitość roślinności podwodnej, choć utrudniająca, tworzy doskonałe środowisko dla linów, karasi pospolitych i wzdręg. W ciepłe lata istnieje ryzyko przyduchy, dlatego wędkarze powinni być świadomi tego zagrożenia. Mimo trudności, to starorzecze oferuje unikalne doświadczenia wędkarskie dla cierpliwych miłośników spokojnych wód.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20991, 2.5, 1.5, 2.8, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20992, 'Starorzecze Wroceń 3', 'starorzecze-wrocen-3-goniadz-20992', 'OXBOW', 53.5281904, 22.826495, 'Podlaskie', 'Goniądz', 'To największe ze starorzeczy w rejonie Wrocnia, charakteryzujące się stosunkowo czystą wodą i brakiem stałego połączenia z rzeką, co zapewnia stabilne warunki. Dno jest zróżnicowane, od piaszczystych płycizn po głębsze partie z twardszym podłożem, co sprzyja różnorodności gatunków. Brzegi są łatwo dostępne, z licznymi dogodnymi stanowiskami wędkarskimi, otoczone lasem łęgowym. Roślinność podwodna jest obecna, ale nie utrudnia znacząco wędkowania, tworząc naturalne schronienia. Starorzecze to jest znane z dużych szczupaków i okoni, a także obfitych populacji leszczy i płoci. Występują tu również karpie, oferując dodatkowe wyzwanie. Brak ryzyka przyduchy sprawia, że jest to atrakcyjne łowisko przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20992, 4.1, 2.1, 4, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Karp,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20993, 'Starorzecze Kobyle', 'starorzecze-kobyle-frysztak-20993', 'OXBOW', 49.8434935, 21.6250458, 'Podkarpackie', 'Frysztak', 'Starorzecze w Kobylem to niewielki, silnie zamulony zbiornik, który w okresach suszy potrafi całkowicie wyschnąć. Dno jest niemal w całości pokryte grubą warstwą mułu, co świadczy o zaawansowanym procesie sukcesji. Brzegi są podmokłe i trudno dostępne, porośnięte gęstymi zaroślami i trzciną, co wymaga użycia specjalistycznego sprzętu, takiego jak spodniobuty. Obfitość roślinności podwodnej jest niezwykle bujna, tworząc gęste dywany, które są schronieniem dla niewielkich ryb. Dominują tu karasie pospolite i srebrzyste, wzdręgi oraz płocie, które dobrze radzą sobie w trudnych warunkach. Wędkarstwo w tym miejscu to wyzwanie, ale może nagrodzić cierpliwych wędkarzy. Ze względu na płytkość i zamulenie, ryzyko przyduchy jest wysokie, szczególnie zimą i w upalne lata.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20993, 1.8, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20994, 'Starorzecze Glinik Dolny', 'starorzecze-glinik-dolny-frysztak-20994', 'OXBOW', 49.8167738, 21.6277848, 'Podkarpackie', 'Frysztak', 'To starorzecze w Gliniku Dolnym oferuje zróżnicowane warunki, będąc atrakcyjnym łowiskiem dla wielu wędkarzy. Jego dno jest mozaiką mułu i twardszych, piaszczystych fragmentów, co sprzyja różnym technikom wędkowania. Brzegi są przeważnie łatwo dostępne, z dobrze utrzymanymi ścieżkami i miejscami do wędkowania, otoczone drzewami i krzewami. Połączenie z rzeką podczas wysokiej wody odświeża wodę i zasila zbiornik w nowe populacje ryb. Roślinność podwodna jest umiarkowana, tworząc idealne schronienia dla szczupaków i okoni, które są tu często łowione. W starorzeczu tym licznie występują również leszcze, płocie i liny, gwarantując udane połowy białej ryby. Brak ryzyka przyduchy sprawia, że jest to stabilne łowisko przez większość roku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20994, 2.9, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20995, 'Starorzecze Łęki Strzyżowskie 1', 'starorzecze-leki-strzyzowskie-1-strzyzow-20995', 'OXBOW', 49.8150014, 21.6428097, 'Podkarpackie', 'Strzyżów', 'Pierwsze ze starorzeczy w Łękach Strzyżowskich to płytki i silnie zamulony zbiornik, który w okresach długotrwałej suszy może wyschnąć. Dno jest miękkie i bogate w materię organiczną, co sprzyja rozwojowi bujnej roślinności wodnej. Brzegi są podmokłe i gęsto zarośnięte trzciną oraz krzewami, co wymaga od wędkarzy dużej determinacji i użycia brodzących spodniobutów. Obfitość roślinności podwodnej, choć utrudniająca, stanowi doskonałe środowisko dla karasi pospolitych i wzdręg. Występują tu również płocie, które dostosowały się do trudnych warunków. Ze względu na płytkość i silne zamulenie, ryzyko przyduchy, zwłaszcza zimą, jest bardzo wysokie, co może prowadzić do śnięcia ryb. Wędkowanie tutaj to wyzwanie, ale pozwala na kontakt z dziką przyrodą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20995, 1.5, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20996, 'Starorzecze Łęki Strzyżowskie 2', 'starorzecze-leki-strzyzowskie-2-strzyzow-20996', 'OXBOW', 49.8124315, 21.6418291, 'Podkarpackie', 'Strzyżów', 'Drugie starorzecze w Łękach Strzyżowskich to nieco głębszy i mniej zamulony zbiornik, który ma sezonowe połączenie z rzeką. Dno jest mieszane, z partiami mulistymi i twardszymi, piaszczystymi, co sprzyja różnorodności fauny dennej. Brzegi są częściowo dostępne, ale w wielu miejscach gęsto porośnięte trzciną, co wymaga od wędkarzy znalezienia odpowiednich stanowisk lub użycia spodniobutów. Roślinność podwodna jest umiarkowana, tworząc dobre kryjówki dla ryb drapieżnych i spokojnego żeru. W starorzeczu tym z powodzeniem można łowić liny, szczupaki, okonie oraz płocie, które są tu licznie reprezentowane. Wędkowanie jest tu satysfakcjonujące, choć wymaga pewnej wprawy w poruszaniu się po zarośniętych brzegach. Okresowe połączenie z rzeką wzbogaca zbiornik o nowe gatunki i odświeża wodę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20996, 2.1, 1.2, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Szczupak,Okoń,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20997, 'Starorzecze Łęki Strzyżowskie 3', 'starorzecze-leki-strzyzowskie-3-strzyzow-20997', 'OXBOW', 49.8104967, 21.6435173, 'Podkarpackie', 'Strzyżów', 'To niewielkie starorzecze w Łękach Strzyżowskich jest jednym z najbardziej zaniedbanych, charakteryzującym się ekstremalnie płytką wodą i silnym zamuleniem. Dno jest niemal w całości pokryte grubą warstwą osadów organicznych, co świadczy o zaawansowanym stadium zarastania. Brzegi są bagniste i całkowicie niedostępne bez specjalistycznego sprzętu, gęsto porośnięte trzciną i krzewami. Roślinność podwodna jest tak bujna, że w wielu miejscach tworzy niemal jednolitą matę, ograniczając otwarte przestrzenie do minimum. W takich warunkach najlepiej radzą sobie karasie pospolite i wzdręgi, które są odporne na niską zawartość tlenu. Zbiornik ten często wysycha w upalne lata, a zimą jest silnie narażony na przyduchę, co czyni wędkowanie bardzo trudnym i sezonowym. Jest to łowisko dla prawdziwych pasjonatów dzikich i wymagających miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20997, 0.9, 0.7, 1.3, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20998, 'Starorzecze Przybówka', 'starorzecze-przybowka-strzyzow-20998', 'OXBOW', 49.8056904, 21.6420519, 'Podkarpackie', 'Strzyżów', 'Starorzecze w Przybówce to jedno z głębszych i lepiej utrzymanych łowisk w regionie, z okresowym połączeniem z rzeką, które zapewnia dopływ świeżej wody. Dno jest zróżnicowane, od twardych, żwirowych partii po muliste zagłębienia, co sprzyja różnorodności gatunkowej. Brzegi są łatwo dostępne, z licznymi dogodnymi stanowiskami wędkarskimi, otoczone lasem łęgowym i polami. Roślinność podwodna jest umiarkowana, tworząc naturalne schronienia, ale nie utrudniając znacząco wędkowania. Zbiornik ten słynie z dużych szczupaków i okoni, a także obfitych populacji leszczy i karpi. Odnotowano tu również obecność sumów, co dodaje emocji podczas wędkowania. Brak ryzyka przyduchy i dobra dostępność sprawiają, że jest to atrakcyjne łowisko przez cały rok dla wędkarzy preferujących różne metody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20998, 3.5, 2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Karp,Sum', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (20999, 'Starorzecze Narwi (Nowogród)', 'starorzecze-narwi-nowogrod-nowogrod-20999', 'OXBOW', 53.22621, 22.0642015, 'Podlaskie', 'Nowogród', 'To starorzecze, będące częścią rozległej doliny Narwi, charakteryzuje się stałym połączeniem z głównym nurtem rzeki, co zapewnia doskonałą wymianę wody i bogactwo gatunkowe. Dno jest zróżnicowane, z przewagą piasku i żwiru, ale również z mulistymi zatokami, idealnymi dla białej ryby. Brzegi są w większości łatwo dostępne, często z piaszczystymi plażami i miejscami do biwakowania, otoczone łąkami i lasami. Roślinność podwodna jest obecna, ale nie utrudnia znacząco wędkowania, tworząc naturalne schronienia dla ryb. W starorzeczu tym licznie występują szczupaki, leszcze i płocie, a bliskość Narwi sprawia, że często spotyka się tu również bolenie i jazie. Jest to idealne miejsce dla wędkarzy ceniących aktywne metody spinningowe oraz klasyczne wędkarstwo spławikowe. Stabilne warunki i brak ryzyka przyduchy sprawiają, że jest to atrakcyjne łowisko przez większość roku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (20999, 5.8, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Boleń,Jaź', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21000, 'Starorzecze Ceber 1', 'starorzecze-ceber-1-nowa-sol-21000', 'OXBOW', 51.6985867, 15.9988266, 'Lubuskie', 'Nowa Sól', 'Pierwsze starorzecze w Cebrze to zbiornik o umiarkowanej głębokości, z okresowym połączeniem z Odrą podczas wysokich stanów wody. Dno jest zróżnicowane, z przewagą mulistego podłoża, ale z twardszymi partiami wzdłuż brzegów, co sprzyja różnorodności fauny dennej. Brzegi są łatwo dostępne, częściowo utwardzone, otoczone łąkami i pojedynczymi drzewami, co ułatwia wędkowanie z brzegu. Roślinność podwodna jest umiarkowana, tworząc dobre kryjówki dla ryb, ale nie utrudniając znacząco wędkowania. W starorzeczu tym licznie występują szczupaki, liny, leszcze, płocie i okonie, co czyni je atrakcyjnym dla różnych metod wędkowania. Wędkowanie jest tu przyjemne, choć w niektórych miejscach mogą występować zaczepy w postaci zatopionych gałęzi. Brak ryzyka przyduchy sprawia, że jest to stabilne łowisko przez większość roku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21000, 3.8, 1.9, 3.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21001, 'Starorzecze Ceber 2', 'starorzecze-ceber-2-nowa-sol-21001', 'OXBOW', 51.6891149, 16.0193234, 'Lubuskie', 'Nowa Sól', 'Drugie starorzecze w Cebrze jest mniejsze i bardziej zarośnięte, bez stałego połączenia z rzeką, co sprzyja jego naturalnej ewolucji. Dno jest w przeważającej części mocno zamulone, co utrudnia skuteczne wędkowanie z gruntu, ale jest idealne dla ryb żerujących w mule. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co wymaga użycia brodzących spodniobutów, aby dotrzeć do otwartych partii wody. Obfitość roślinności podwodnej, choć utrudniająca, tworzy doskonałe środowisko dla linów, karasi pospolitych i wzdręg. W ciepłe lata istnieje ryzyko przyduchy, co może negatywnie wpłynąć na populację ryb. Mimo trudności, to starorzecze oferuje unikalne doświadczenia wędkarskie dla cierpliwych miłośników spokojnych, dzikich wód. Wędkowanie jest tu wyzwaniem, ale może przynieść satysfakcjonujące rezultaty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21001, 2.3, 1.4, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21002, 'Starorzecze Kwidzyn', 'starorzecze-kwidzyn-kwidzyn-21002', 'OXBOW', 53.777423, 19.0686263, 'Pomorskie', 'Kwidzyn', 'To starorzecze, zlokalizowane w pobliżu Kwidzyna, charakteryzuje się dość dużą powierzchnią i głębokością, co sprzyja rozwojowi zróżnicowanej fauny. Dno jest mieszane, z partiami piaszczystymi, żwirowymi i mulistymi, co oferuje różnorodne środowiska dla ryb. Brzegi są w większości łatwo dostępne, z licznymi dogodnymi stanowiskami wędkarskimi, otoczone lasami łęgowymi i polami. Okresowe połączenie z Wisłą zapewnia dopływ świeżej wody i zasila zbiornik w nowe populacje ryb, w tym cenne drapieżniki. Roślinność podwodna jest umiarkowana, tworząc idealne kryjówki dla szczupaków i sandaczy, które są tu często łowione. W starorzeczu tym licznie występują również leszcze, płocie i okonie, gwarantując udane połowy białej ryby. Brak ryzyka przyduchy sprawia, że jest to atrakcyjne łowisko przez większość roku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21002, 4.5, 2.3, 4.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21003, 'Starorzecze Ośno', 'starorzecze-osno-kwidzyn-21003', 'OXBOW', 53.7729441, 19.0548339, 'Pomorskie', 'Kwidzyn', 'Starorzecze w Ośnie to niewielki i płytki zbiornik, który w okresach suszy może całkowicie wyschnąć, co jest typowe dla wielu starorzeczy. Dno jest niemal w całości pokryte grubą warstwą mułu, co świadczy o zaawansowanym procesie sukcesji i zarastania. Brzegi są podmokłe i trudno dostępne, gęsto porośnięte trzciną i inną roślinnością szuwarową, co wymaga od wędkarzy użycia brodzących spodniobutów. Obfitość roślinności podwodnej, choć utrudniająca, tworzy doskonałe środowisko dla karasi pospolitych i srebrzystych, wzdręg oraz linów. Wędkarstwo w tym miejscu to wyzwanie, ale może nagrodzić cierpliwych wędkarzy poszukujących dzikich ryb. Ze względu na płytkość i zamulenie, ryzyko przyduchy jest wysokie, szczególnie zimą i w upalne lata, co wymaga monitorowania warunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21003, 1.9, 1.1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Karaś srebrzysty,Wzdręga,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21004, 'Starorzecze Międzyrzecze', 'starorzecze-miedzyrzecze-chelmek-21004', 'OXBOW', 50.0199267, 19.0641831, 'Śląskie', 'Chełmek', 'Starorzecze w Międzyrzeczu to jeden z większych i głębszych zbiorników tego typu, charakteryzujący się stałym połączeniem z Wisłą, co zapewnia ciągły dopływ świeżej wody i bogactwo ryb. Dno jest zróżnicowane, z głębokimi rynnami, twardymi grądzikami i mulistymi zatokami, co sprzyja różnorodności gatunkowej. Brzegi są łatwo dostępne, z licznymi dogodnymi stanowiskami wędkarskimi, otoczone lasami łęgowymi i polami uprawnymi. W wodzie znajduje się sporo zatopionych drzew i korzeni, co stanowi doskonałe kryjówki dla drapieżników, ale wymaga uwagi podczas wędkowania. Zbiornik ten słynie z obecności dużych sumów, szczupaków i sandaczy, a także obfitych populacji leszczy i karpi. Brak ryzyka przyduchy i stałe połączenie z rzeką sprawiają, że jest to atrakcyjne łowisko przez cały rok dla wędkarzy preferujących różne metody i gatunki ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21004, 6.2, 2.8, 5.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Sandacz,Leszcz,Karp', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21005, 'Starorzecze (Międzyrzecze)', 'starorzecze-miedzyrzecze-pszczyna-21005', 'OXBOW', 50.0194409, 19.0636487, 'Śląskie', 'Pszczyna', 'To starorzecze, położone w malowniczej okolicy Międzyrzecza, charakteryzuje się umiarkowanymi rozmiarami i stabilnym poziomem wody. Dno jest zróżnicowane, miejscami piaszczyste, a w głębszych partiach pokryte warstwą mułu, co sprzyja rozwojowi bogatej fauny dennej. Brzegi są częściowo dostępne, z fragmentami porośniętymi trzciną i wierzbami, oferując schronienie dla wielu gatunków ryb. Roślinność podwodna jest umiarkowana, tworząc idealne miejsca do zasadzek dla drapieżników. Jest to doskonałe łowisko dla wędkarzy poszukujących szczupaków i okoni, ale także leszczy i linów. Dostęp do wody jest dobry od strony pól, jednak od strony lasu może być nieco trudniejszy, wymagając użycia brodźców.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21005, 3.5, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Lin,Okoń,Płoć', 'Dobry w niektórych miejscach, trudniejszy od strony lasu', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21006, 'Starorzecze (Frydek) 1', 'starorzecze-frydek-1-pszczyna-21006', 'OXBOW', 50.0158316, 19.0556427, 'Śląskie', 'Pszczyna', 'To starorzecze w pobliżu Frydka jest typowym przykładem zbiornika o zaawansowanym stadium starzenia. Charakteryzuje się stosunkowo niewielką powierzchnią i znacznym stopniem zamulenia dna, które jest w większości miękkie i bogate w materię organiczną. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co utrudnia dostęp do wody. Roślinność podwodna jest bardzo silna, tworząc gęste dywany, szczególnie w płytszych partiach. Zbiornik ten jest ostoją dla karasi pospolitych, linów i wzdręg, które doskonale radzą sobie w takich warunkach. W cieplejszych miesiącach istnieje podwyższone ryzyko przyduchy z powodu rozkładu materii organicznej. Wędkowanie wymaga cierpliwości i często brodzenia w trudnym terenie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21006, 2, 1.5, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21007, 'Starorzecze (Frydek) 2', 'starorzecze-frydek-2-pszczyna-21007', 'OXBOW', 50.0159412, 19.0551022, 'Śląskie', 'Pszczyna', 'Kolejne starorzecze w okolicy Frydka, o zbliżonej charakterystyce do sąsiednich, lecz z nieco łatwiejszym dostępem w wybranych miejscach. Dno jest silnie zamulone, z grubą warstwą osadów organicznych, co jest typowe dla starorzeczy bez stałego przepływu. Brzegi są zróżnicowane, od gęsto zarośniętych po fragmenty z niewielkimi prześwitami. Gęsta roślinność podwodna stanowi doskonałe kryjówki dla drobnicy i mniejszych drapieżników. W zbiorniku dominują karasie pospolite, liny oraz płocie, które dobrze znoszą trudniejsze warunki tlenowe. Wędkowanie tutaj to wyzwanie, ale może przynieść satysfakcjonujące efekty, szczególnie dla miłośników spokojnego łowienia. Należy być przygotowanym na trudne warunki brzegowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21007, 1.8, 1.3, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć,Okoń', 'Trudny, miejscami bagnisty', TRUE, 'Gęsta roślinność podwodna i pojedyncze konary', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21008, 'Starorzecze (Frydek) 3', 'starorzecze-frydek-3-pszczyna-21008', 'OXBOW', 50.0160657, 19.0554501, 'Śląskie', 'Pszczyna', 'To starorzecze w Frydku wyróżnia się nieco większą głębokością w centralnej części, co zapewnia stabilniejsze warunki środowiskowe. Dno jest średnio zamulone, z twardszymi partiami żwirowymi wzdłuż dawnego koryta rzeki. Brzegi są częściowo dostępne, szczególnie z jednej strony, gdzie teren jest bardziej suchy i mniej zarośnięty. Roślinność wodna jest umiarkowana, tworząc zróżnicowane środowisko dla ryb. Jest to atrakcyjne łowisko dla szczupaków i okoni, które polują wśród podwodnych struktur. Występują tu również liczne płocie i leszcze, stanowiące bazę pokarmową dla drapieżników. Łowienie wymaga często przemieszczania się w poszukiwaniu dogodnych stanowisk.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21008, 2.2, 1.6, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z jednej strony, reszta zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21009, 'Starorzecze (Frydek) 4', 'starorzecze-frydek-4-pszczyna-21009', 'OXBOW', 50.0129939, 19.0521288, 'Śląskie', 'Pszczyna', 'Niewielkie i kameralne starorzecze w Frydku, charakteryzujące się płytką wodą i intensywnym zarastaniem. Dno jest w przeważającej części pokryte grubą warstwą mułu, co świadczy o zaawansowanym procesie sedymentacji. Brzegi są bardzo trudne do pokonania, gęsto porośnięte krzewami, drzewami i wysokimi trawami, tworząc niemal niedostępną barierę. Gęsta roślinność podwodna, taka jak rdestnice i moczarka, dominuje w całym zbiorniku. W takich warunkach najlepiej czują się karasie pospolite, wzdręgi i płocie, które są odporne na niedobory tlenowe. Zbiornik ten może okresowo wysychać w czasie długotrwałych susz, co dodatkowo wpływa na jego ekosystem. Wędkowanie jest tu prawdziwym wyzwaniem dla wytrwałych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21009, 1.5, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Bardzo trudny, gęste zarośla', TRUE, 'Gęsta roślinność podwodna', 'Lato (wczesne)');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21010, 'Starorzecze (Frydek) 5', 'starorzecze-frydek-5-pszczyna-21010', 'OXBOW', 50.0144862, 19.0526158, 'Śląskie', 'Pszczyna', 'To starorzecze w Frydku to zbiornik o umiarkowanych rozmiarach, z potencjałem do łowienia większych ryb spokojnego żeru. Dno jest mieszane, z partiami mulistymi i twardszymi, co sprzyja różnorodności gatunkowej. Brzegi są dostępne w kilku wyznaczonych miejscach, jednak większość linii brzegowej jest zarośnięta. Umiarkowana roślinność podwodna tworzy doskonałe kryjówki dla linów i karpi, a także dla mniejszych drapieżników. Zbiornik ten jest zasilany podczas wysokich stanów wody, co wpływa na jego żyzność i skład gatunkowy. Wędkowanie tu jest bardzo satysfakcjonujące, zwłaszcza dla miłośników karpi i linów. Należy jednak liczyć się z koniecznością brodzenia w niektórych partiach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21010, 2.8, 1.7, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karp,Leszcz,Szczupak', 'Dobry w kilku miejscach, reszta zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21011, 'Starorzecze (Frydek) 6', 'starorzecze-frydek-6-pszczyna-21011', 'OXBOW', 50.0118656, 19.0494905, 'Śląskie', 'Pszczyna', 'Bardzo małe i płytkie starorzecze w Frydku, które reprezentuje zaawansowany etap sukcesji ekologicznej. Dno jest niemal w całości pokryte grubą warstwą miękkiego mułu, co ogranicza różnorodność biologiczną. Brzegi są niezwykle trudne do pokonania, bagniste i gęsto porośnięte, co sprawia, że dostęp do wody jest praktycznie niemożliwy bez specjalistycznego sprzętu. Gęsta roślinność podwodna, w połączeniu z płytką wodą, prowadzi do wysokiego ryzyka przyduchy, zwłaszcza latem. W zbiorniku dominują najbardziej odporne gatunki, takie jak karaś pospolity, wzdręga i płoć. Wędkowanie jest tu bardzo utrudnione i wymaga dużej determinacji oraz odpowiedniego ubioru, w tym brodźców.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21011, 1.2, 0.8, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Bardzo trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna i muł', 'Wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21012, 'Starorzecze (Ćwiklice) 1', 'starorzecze-cwiklice-1-pszczyna-21012', 'OXBOW', 50.0038964, 19.0293456, 'Śląskie', 'Pszczyna', 'To starorzecze w Ćwiklicach jest jednym z głębszych i bardziej stabilnych zbiorników w okolicy, co czyni je atrakcyjnym dla wędkarzy. Dno jest zróżnicowane, z twardszymi partiami żwirowo-piaszczystymi i głębszymi dołkami z mulistym osadem. Brzegi są w większości dobrze dostępne, co ułatwia swobodne przemieszczanie się i wybór stanowiska. Roślinność wodna jest umiarkowana, tworząc idealne środowisko dla wielu gatunków ryb, w tym dużych drapieżników. W zbiorniku występują liczne szczupaki, okonie, a także leszcze, sandacze i sumy, co świadczy o jego bogactwie. Jest to łowisko, które oferuje dobre warunki przez cały sezon, z niskim ryzykiem niedoborów tlenu. Wędkarstwo spinningowe i gruntowe są tu szczególnie skuteczne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21012, 4, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Sandacz,Sum', 'Dobry w większości miejsc', FALSE, 'Pojedyncze korzenie i zatopione gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21013, 'Starorzecze (Ćwiklice) 2', 'starorzecze-cwiklice-2-pszczyna-21013', 'OXBOW', 50.0047582, 19.0323963, 'Śląskie', 'Pszczyna', 'Kolejne starorzecze w Ćwiklicach, nieznacznie płytsze od sąsiedniego, ale równie atrakcyjne pod względem wędkarskim. Dno charakteryzuje się mieszanym podłożem, z twardszymi partiami i miejscami z mulistym osadem. Brzegi są dobrze dostępne z obu stron, co ułatwia swobodne przemieszczanie się i wybór dogodnego miejsca do wędkowania. Roślinność wodna jest umiarkowana, z przewagą trzcin i roślinności szuwarowej w strefie brzegowej. W zbiorniku dominują szczupaki, okonie, leszcze i karpie, które znajdują tu obfitość pokarmu. Brak ryzyka przyduchy sprawia, że jest to stabilne łowisko przez większość roku. Idealne dla wędkarzy preferujących różne metody połowu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21013, 3.8, 1.9, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno w wielu miejscach, zarośla na brzegach', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21014, 'Starorzecze (Ćwiklice) 3', 'starorzecze-cwiklice-3-pszczyna-21014', 'OXBOW', 50.0033211, 19.0262858, 'Śląskie', 'Pszczyna', 'To starorzecze w Ćwiklicach jest mniejsze i bardziej typowe dla zbiorników o zaawansowanym stadium sukcesji. Dno jest silnie zamulone, z grubą warstwą osadów organicznych, co jest naturalnym procesem dla tego typu akwenów. Brzegi są gęsto zarośnięte, co znacznie utrudnia dostęp do wody i wymaga cierpliwości od wędkarza. Roślinność podwodna jest bardzo bujna, tworząc gęste zarośla i idealne kryjówki dla ryb. W zbiorniku dominują liny, karasie pospolite, płocie i wzdręgi, które doskonale adaptują się do warunków o zmiennym poziomie tlenu. Istnieje podwyższone ryzyko przyduchy w okresach upałów lub mrozów. Wędkowanie tu to wyzwanie, ale nagrodą mogą być piękne okazy ryb spokojnego żeru.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21014, 2.5, 1.5, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Trudny, gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21015, 'Starorzecze (Frydek) 7', 'starorzecze-frydek-7-pszczyna-21015', 'OXBOW', 50.0062351, 19.0378892, 'Śląskie', 'Pszczyna', 'Średniej wielkości starorzecze w Frydku, znane z różnorodności gatunków ryb i umiarkowanych warunków wędkarskich. Dno jest zróżnicowane, z mulistymi zatokami i twardszymi partiami w centralnej części, co sprzyja rozwojowi bogatego ekosystemu. Brzegi są częściowo dostępne, z licznymi miejscami do wędkowania, choć niektóre odcinki są gęsto zarośnięte. Roślinność podwodna jest umiarkowana, tworząc dogodne miejsca dla drapieżników i ryb spokojnego żeru. W zbiorniku występują szczupaki, leszcze, liny, okonie i karpie, co czyni go atrakcyjnym dla wielu wędkarzy. Zbiornik jest zasilany podczas wysokich stanów wody, co pozytywnie wpływa na jego biologię. Wędkowanie tu jest przyjemne i często obfituje w sukcesy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21015, 3, 1.7, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Lin,Okoń,Karp', 'Dobry w niektórych miejscach, reszta zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21016, 'Starorzecze (Frydek) 8', 'starorzecze-frydek-8-pszczyna-21016', 'OXBOW', 50.0066267, 19.0389939, 'Śląskie', 'Pszczyna', 'To bardzo małe i płytkie starorzecze w Frydku jest przykładem zbiornika o silnym procesie zarastania i zamulania. Dno jest niemal w całości pokryte grubą warstwą miękkiego mułu, co świadczy o jego zaawansowanym wieku. Brzegi są niezwykle trudne do pokonania, bagniste i gęsto zarośnięte, co sprawia, że dostęp do wody jest bardzo ograniczony. Gęsta roślinność podwodna, wraz z płytką wodą, prowadzi do wysokiego ryzyka przyduchy, zwłaszcza w ekstremalnych warunkach pogodowych. W zbiorniku dominują najbardziej odporne gatunki, takie jak karaś pospolity, wzdręga i płoć. Wędkowanie tu to wyzwanie, ale może przynieść satysfakcję wędkarzom poszukującym dziewiczych miejsc. Wymaga użycia brodźców i dużej ostrożności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21016, 1, 0.7, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Bardzo trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna i gruby muł', 'Wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21017, 'Starorzecze (Frydek) 9', 'starorzecze-frydek-9-pszczyna-21017', 'OXBOW', 50.010884, 19.0458429, 'Śląskie', 'Pszczyna', 'To starorzecze w Frydku charakteryzuje się umiarkowaną głębokością i dobrym potencjałem wędkarskim. Dno jest zróżnicowane, z partiami mulistymi i twardszymi, co sprzyja obecności różnorodnych gatunków ryb. Brzegi są dostępne w kilku miejscach, co ułatwia wybór stanowiska, choć niektóre odcinki są gęsto zarośnięte. Umiarkowana roślinność podwodna tworzy doskonałe kryjówki dla drapieżników i ryb spokojnego żeru. W zbiorniku występują szczupaki, okonie, leszcze, liny i płocie, co czyni go atrakcyjnym dla wędkarzy preferujących różne metody. Zbiornik jest zasilany podczas wysokich stanów wody, co wpływa na jego żyzność. Jest to dobre miejsce na całosezonowe wędkowanie, z wyjątkiem okresu zimowego.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21017, 2.7, 1.6, 3.3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Lin,Płoć', 'Dobry w kilku miejscach', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon (z wyjątkiem zimy)');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21018, 'Starorzecze (Frydek) 10', 'starorzecze-frydek-10-pszczyna-21018', 'OXBOW', 50.0086177, 19.0432528, 'Śląskie', 'Pszczyna', 'Mniejsze starorzecze w Frydku, charakteryzujące się dużą ilością roślinności i poczuciem odosobnienia. Dno jest silnie zamulone, z grubą warstwą osadów organicznych, co jest typowe dla starorzeczy bez stałego przepływu. Brzegi są trudne do pokonania, gęsto zarośnięte krzewami i trzciną, co wymaga od wędkarza cierpliwości i często brodzenia. Gęsta roślinność podwodna, taka jak grążele i moczarka, dominuje w całym zbiorniku, tworząc schronienie dla wielu gatunków. W zbiorniku dominują liny, karasie pospolite, wzdręgi i płocie, które doskonale radzą sobie w takich warunkach. Istnieje podwyższone ryzyko przyduchy w okresach upałów. Wędkowanie tu to wyzwanie dla poszukiwaczy spokoju i dzikiej przyrody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21018, 1.9, 1.2, 2.7, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21019, 'Starorzecze (Frydek) 11', 'starorzecze-frydek-11-pszczyna-21019', 'OXBOW', 50.0085935, 19.0445858, 'Śląskie', 'Pszczyna', 'To starorzecze w Frydku jest połączone z sąsiednimi zbiornikami podczas wysokich stanów wody, co sprzyja wymianie gatunkowej. Charakteryzuje się umiarkowaną głębokością i zróżnicowanym dnem, z partiami mulistymi i twardszymi. Brzegi są częściowo dostępne, z licznymi prześwitami wśród trzcin, co ułatwia dotarcie do wody. Umiarkowana roślinność podwodna tworzy idealne warunki dla rozwoju życia wodnego. W zbiorniku występują szczupaki, okonie, liny i płocie, co czyni go atrakcyjnym dla wędkarzy preferujących różnorodne metody. Ryzyko niedoboru tlenu jest niskie, co zapewnia stabilne warunki przez większość roku. Jest to dobre miejsce na wędkowanie wiosną i wczesną jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21019, 2.1, 1.4, 2.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Lin,Płoć', 'Dobry w niektórych miejscach', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21020, 'Starorzecze Frydek', 'starorzecze-frydek-bierun-21020', 'OXBOW', 50.0181047, 19.0621627, 'Śląskie', 'Bieruń', 'Starorzecze Frydek to malowniczy zbiornik wodny położony w dolinie Wisły, charakteryzujący się wydłużonym kształtem i bogatą roślinnością przybrzeżną. Dno jest muliste, z licznymi osadami dennymi, co sprzyja rozwojowi makrofitów. Brzegi są częściowo dostępne, z jednej strony utwardzone, z drugiej zaś podmokłe i porośnięte gęstą trzciną, utrudniającą dostęp do wody. W starorzeczu dominują takie gatunki ryb jak szczupak, lin, płoć oraz leszcz, które znajdują tu idealne warunki do żerowania i rozrodu. Wędkowanie utrudniają sporadycznie zatopione gałęzie i korzenie, jednak przy odpowiednim przygotowaniu można liczyć na udane połowy. Zbiornik łączy się z rzeką podczas wysokich stanów wody, co wzbogaca jego ichtiofaunę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21020, 3.2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Płoć,Leszcz', 'Dobry z jednej strony, druga bagnista', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21021, 'Starorzecze Jama Roma', 'starorzecze-jama-roma-wlodawa-21021', 'OXBOW', 51.4248716, 23.6811782, 'Lubelskie', 'Włodawa', 'Jama Roma to rozległe starorzecze o głębszym charakterze, zlokalizowane w pobliżu Włodawy, oferujące komfortowe warunki dla wędkarzy. Charakteryzuje się stosunkowo czystym, piaszczysto-żwirowym dnem, co jest rzadkością w tego typu zbiornikach. Brzegi są łatwo dostępne, pozbawione gęstych zarośli, co umożliwia swobodne poruszanie się i wybór stanowiska. Roślinność podwodna jest umiarkowana, skupiająca się głównie w płytszych zatoczkach, stanowiąc schronienie dla narybku. W zbiorniku dominują leszcze i płocie, ale często spotkać można także okonie i karpie, szczególnie w cieplejszych miesiącach. Brak stałego połączenia z rzeką sprzyja stabilności ekosystemu, a niskie zamulenie gwarantuje dobrą jakość wody. Jest to idealne miejsce na całosezonowe wyprawy wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21021, 5.8, 2.2, 4.5, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21022, 'Starorzecze koło Sulechowa 1', 'starorzecze-kolo-sulechowa-1-sulechow-21022', 'OXBOW', 52.0345403, 15.517748, 'Lubuskie', 'Sulechów', 'To niewielkie starorzecze w okolicach Sulechowa to typowy, silnie zarośnięty zbiornik, idealny dla miłośników trudniejszych wyzwań. Dno jest bardzo muliste, z grubą warstwą osadów organicznych, co jest charakterystyczne dla starorzeczy o słabym przepływie. Brzegi są gęsto porośnięte trzciną i inną roślinnością bagienną, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga użycia wodoodpornego obuwia. Roślinność podwodna jest niezwykle bujna, tworząc liczne kryjówki dla ryb, ale jednocześnie utrudniając prowadzenie przynęty. W zbiorniku królują karasie pospolite, liny oraz wzdręgi, a także szczupaki, które polują w gęstwinie. Istnieje ryzyko przyduchy w okresie letnim, dlatego wędkarstwo jest najbardziej efektywne w późnej wiośnie i wczesnym lecie, zanim roślinność osiągnie swój szczyt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21022, 1.8, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Szczupak', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21023, 'Starorzecze koło Sulechowa 2', 'starorzecze-kolo-sulechowa-2-sulechow-21023', 'OXBOW', 52.0334542, 15.5132712, 'Lubuskie', 'Sulechów', 'Drugie starorzecze w rejonie Sulechowa, podobnie jak sąsiednie, to zbiornik o silnym zarośnięciu i mulistym dnie. Jest to typowe starorzecze z dużą ilością osadów dennych, co sprzyja rozwojowi bujnej roślinności wodnej. Brzegi są bagniste i trudno dostępne, wymagające użycia wodoodpornych butów lub brodzenia, aby dotrzeć do otwartych partii wody. Gęsta roślinność podwodna stanowi doskonałe schronienie dla ryb, ale jednocześnie stwarza wyzwanie dla wędkarzy, którzy muszą precyzyjnie prowadzić swoje zestawy. Dominujące gatunki to lin, karaś pospolity i płoć, a także drapieżny szczupak, który czai się w zaroślach. Ze względu na ryzyko niedoboru tlenu w upalne lata, najlepszym okresem na wędkowanie jest późna wiosna i wczesne lato, gdy warunki są najbardziej sprzyjające.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21023, 2.1, 1.1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21024, 'Starorzecze Lubliniec 1', 'starorzecze-lubliniec-1-lubliniec-21024', 'OXBOW', 50.6000693, 18.710849, 'Śląskie', 'Lubliniec', 'Pierwsze starorzecze w okolicy Lublińca to średniej wielkości zbiornik, charakteryzujący się umiarkowanym zamuleniem i dobrą dostępnością brzegów. Dno jest mieszane, z przewagą mułu, ale z miejscowymi przejaśnieniami piaszczystymi, co sprzyja różnorodności gatunkowej. Brzegi są w większości łatwo dostępne, z dobrze wydeptanymi ścieżkami, idealnymi do spędzania czasu z wędką. Roślinność przybrzeżna jest obecna, ale nie utrudnia znacząco dostępu do wody, a roślinność podwodna tworzy naturalne kryjówki. W starorzeczu licznie występują płocie, okonie, leszcze, a także szczupaki, które chętnie polują w okolicach zarośli. Połączenie z rzeką podczas wysokich stanów wody zapewnia regularne zasilanie w świeżą wodę i nowe osobniki ryb, co utrzymuje populację w dobrej kondycji.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21024, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21025, 'Starorzecze Lubliniec 2', 'starorzecze-lubliniec-2-lubliniec-21025', 'OXBOW', 50.600878, 18.7116949, 'Śląskie', 'Lubliniec', 'Drugie starorzecze w Lublińcu to zbiornik o podobnej charakterystyce do sąsiedniego, lecz z nieco inną strukturą ichtiofauny. Dno jest przeważnie muliste, z miejscami twardszymi, co sprzyja różnorodności siedlisk dla ryb. Brzegi są w większości łatwo dostępne, choć miejscami mogą być porośnięte gęstszą roślinnością, oferującą cień w upalne dni. Roślinność podwodna jest umiarkowana, tworząc idealne miejsca do zasadzek dla drapieżników i żerowania dla ryb spokojnego żeru. W zbiorniku dominują leszcze i płocie, ale można tu także spotkać karpie, a nawet sumy, które osiągają imponujące rozmiary. Połączenie z rzeką podczas wezbrań jest kluczowe dla utrzymania zdrowego ekosystemu i uzupełniania populacji ryb. Wędkowanie jest tu przyjemne przez większość sezonu, z najlepszymi wynikami wiosną i jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21025, 4, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sum', 'Dobry, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21026, 'Starorzecze Cigacice 1', 'starorzecze-cigacice-1-zielona-gora-21026', 'OXBOW', 52.0296952, 15.6075283, 'Lubuskie', 'Zielona Góra', 'Pierwsze starorzecze w Cigacicach to duży i głęboki zbiornik zlokalizowany w bliskim sąsiedztwie Odry, z którą ma stałe połączenie. Dno jest przeważnie piaszczysto-żwirowe, z niewielką ilością mułu, co świadczy o aktywnym przepływie wody. Brzegi są łatwo dostępne i dobrze utrzymane, co czyni to miejsce bardzo popularnym wśród wędkarzy. Roślinność wodna jest słaba, skupiająca się głównie w płytszych partiach, co ułatwia swobodne wędkowanie. Dzięki stałemu połączeniu z rzeką, w starorzeczu występuje bogactwo gatunków, w tym leszcze, płocie, sandacze, bolenie i jazie, które regularnie wpływają z Odry. Niskie zamulenie i brak ryzyka niedoboru tlenu sprawiają, że jest to doskonałe łowisko przez cały rok, oferujące komfortowe warunki i szanse na złowienie naprawdę dużych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21026, 6.5, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Sandacz,Boleń,Jaź', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21027, 'Starorzecze Cigacice 2', 'starorzecze-cigacice-2-zielona-gora-21027', 'OXBOW', 52.0295488, 15.6079061, 'Lubuskie', 'Zielona Góra', 'Drugie starorzecze w Cigacicach jest niemal lustrzanym odbiciem sąsiedniego zbiornika, również posiadającym stałe połączenie z Odrą. Charakteryzuje się czystym, twardym dnem, co jest wynikiem regularnej wymiany wody i niskiego poziomu zamulenia. Brzegi są bardzo dobrze dostępne, z licznymi dogodnymi miejscami do wędkowania, co przyciąga wielu entuzjastów. Roślinność wodna jest skąpa, co ułatwia prowadzenie przynęt i minimalizuje ryzyko zaczepów. W starorzeczu obficie występują leszcze i płocie, a także drapieżne sandacze i okonie, które chętnie żerują na mniejszej rybie. Co więcej, dzięki połączeniu z rzeką, można tu liczyć na złowienie węgorza. Jest to idealne miejsce dla wędkarzy ceniących sobie komfort i różnorodność gatunkową przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21027, 6, 2.4, 4.8, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Sandacz,Okoń,Węgorz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21028, 'Starorzecze Górki Małe 1', 'starorzecze-gorki-male-1-zielona-gora-21028', 'OXBOW', 52.0301824, 15.6023403, 'Lubuskie', 'Zielona Góra', 'Pierwsze starorzecze w Górkach Małych to zbiornik o średnim rozmiarze, zlokalizowany w malowniczej okolicy. Dno jest muliste, z miejscowymi twardszymi fragmentami, co tworzy zróżnicowane siedliska dla ryb. Brzegi są częściowo dostępne, ale miejscami gęsto porośnięte trzciną, co wymaga użycia wodoodpornego obuwia do skutecznego wędkowania. Roślinność podwodna jest umiarkowana, z kępami moczarki i wywłócznika, stanowiącymi kryjówki dla drobnicy i drapieżników. W starorzeczu dominują płocie, okonie, liny oraz szczupaki, które są częstym celem wędkarzy. Zbiornik łączy się z rzeką podczas podwyższonych stanów wody, co wpływa pozytywnie na wymianę genetyczną i uzupełnianie populacji. Najlepsze wyniki osiąga się wiosną i wczesną jesienią, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21028, 2.8, 1.3, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Okoń,Lin,Szczupak', 'Miejscami trudny, zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21029, 'Starorzecze Górki Małe 2', 'starorzecze-gorki-male-2-zielona-gora-21029', 'OXBOW', 52.0308885, 15.6011569, 'Lubuskie', 'Zielona Góra', 'Drugie starorzecze w Górkach Małych to płytki i silnie zarośnięty zbiornik, typowy dla starorzeczy odciętych od głównego nurtu rzeki. Dno jest bardzo muliste, z grubą warstwą osadów organicznych, co sprzyja bujnemu rozwojowi roślinności. Brzegi są gęsto porośnięte trzciną i inną roślinnością, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga brodzenia. Roślinność podwodna jest niezwykle obfita, tworząc gęste dywany, które są schronieniem dla wielu gatunków ryb, ale jednocześnie stanowią wyzwanie dla wędkarzy. W zbiorniku dominują karasie pospolite, liny, wzdręgi i płocie, doskonale przystosowane do trudnych warunków. Ze względu na ryzyko przyduchy w upalne lata, najlepszy okres na wędkowanie to późna wiosna i wczesne lato, zanim temperatura wody stanie się zbyt wysoka.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21029, 2.5, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21030, 'Starorzecze Górki Małe 3', 'starorzecze-gorki-male-3-zielona-gora-21030', 'OXBOW', 52.0309906, 15.5989961, 'Lubuskie', 'Zielona Góra', 'Trzecie starorzecze w Górkach Małych to zbiornik o zróżnicowanej charakterystyce, oferujący ciekawe możliwości wędkarskie. Dno jest mieszane, od mulistego po twardsze, piaszczyste fragmenty, co sprzyja różnorodności gatunkowej ryb. Brzegi są dostępne z jednej strony, natomiast druga jest gęsto porośnięta roślinnością, co wymaga użycia wodoodpornego obuwia. Roślinność podwodna jest umiarkowana, tworząc naturalne kryjówki i miejsca żerowania. W starorzeczu licznie występują szczupaki i okonie, które aktywnie polują na płocie i leszcze, stanowiące główny pokarm. Połączenie z rzeką podczas wysokich stanów wody zapewnia dopływ świeżej wody i uzupełnianie populacji ryb. Wędkowanie jest tu najbardziej efektywne wiosną i jesienią, kiedy drapieżniki są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21030, 3, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry z jednej strony, druga zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21031, 'Starorzecze Górki Małe 4', 'starorzecze-gorki-male-4-zielona-gora-21031', 'OXBOW', 52.0313171, 15.5997445, 'Lubuskie', 'Zielona Góra', 'To niewielkie starorzecze w Górkach Małych jest zbiornikiem o bardzo trudnym dostępie i specyficznych warunkach środowiskowych. Dno jest ekstremalnie muliste, z dużą ilością osadów dennych, co prowadzi do intensywnego rozwoju roślinności. Brzegi są bagniste i gęsto porośnięte, co sprawia, że dotarcie do wody jest prawdziwym wyzwaniem i wymaga użycia wodoodpornego obuwia. Roślinność podwodna tworzy gęste zarośla, w których ukrywają się ryby, a także liczne zatopione gałęzie. W zbiorniku dominują karasie srebrzyste, wzdręgi i płocie, które są odporne na trudne warunki. Istnieje wysokie ryzyko wysychania w upalne lata oraz niedoboru tlenu, dlatego najlepszy okres na wędkowanie to wczesne lato, zanim warunki staną się zbyt ekstremalne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21031, 2, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna, zatopione gałęzie', 'Wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21032, 'Starorzecze Górki Małe 5', 'starorzecze-gorki-male-5-zielona-gora-21032', 'OXBOW', 52.0325718, 15.5985803, 'Lubuskie', 'Zielona Góra', 'Piąte starorzecze w Górkach Małych to zbiornik o umiarkowanym zamuleniu, oferujący zróżnicowane możliwości wędkarskie. Dno jest przeważnie muliste, ale z twardszymi fragmentami, co sprzyja występowaniu różnorodnych gatunków ryb. Brzegi są dostępne w kilku miejscach, natomiast pozostałe partie są porośnięte roślinnością, co wymaga brodzenia lub poszukiwania otwartych stanowisk. Roślinność podwodna jest umiarkowana, tworząc naturalne kryjówki i miejsca żerowania dla ryb. W starorzeczu występują liny, karpie, leszcze, a także drapieżne szczupaki, które są częstym celem wędkarzy. Zbiornik łączy się z rzeką podczas wysokich stanów wody, co zapewnia dopływ świeżej wody i ryb. Najlepszy okres na wędkowanie to wiosna i lato, gdy ryby są aktywne i chętnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21032, 3.5, 1.6, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karp,Leszcz,Szczupak', 'Dobry z kilku miejsc, reszta zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21033, 'Starorzecze Górki Małe 6', 'starorzecze-gorki-male-6-zielona-gora-21033', 'OXBOW', 52.0322266, 15.5974316, 'Lubuskie', 'Zielona Góra', 'Szóste starorzecze w Górkach Małych to bardzo płytki i silnie zarośnięty zbiornik, stanowiący wyzwanie dla każdego wędkarza. Dno jest w całości pokryte grubą warstwą mułu i rozkładających się resztek roślinnych. Brzegi są niezwykle trudne do pokonania, bagniste i gęsto porośnięte, co praktycznie uniemożliwia swobodny dostęp do wody bez specjalistycznego sprzętu. Roślinność podwodna jest dominująca, tworząc gęste zarośla, w których ryby znajdują schronienie i pożywienie. W zbiorniku królują wytrzymałe gatunki, takie jak karaś pospolity, wzdręga i lin, które potrafią przetrwać w trudnych warunkach. Ze względu na wysokie ryzyko wysychania i przyduchy, najlepszy czas na wędkowanie to późna wiosna, zanim zbiornik stanie się zbyt płytki i ubogi w tlen.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21033, 2.3, 1.1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Bardzo trudny, bagnisty i gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna, dużo zatopionych gałęzi', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21034, 'Starorzecze Górki Małe 7', 'starorzecze-gorki-male-7-zielona-gora-21034', 'OXBOW', 52.0334311, 15.5919503, 'Lubuskie', 'Zielona Góra', 'Siódme starorzecze w Górkach Małych to dobrze utrzymany zbiornik o umiarkowanym zamuleniu i łatwym dostępie do brzegów. Dno jest zróżnicowane, z przewagą mułu, ale z licznymi twardszymi fragmentami, co sprzyja różnorodności siedlisk dla ryb. Brzegi są w większości łatwo dostępne, z dobrze wydeptanymi ścieżkami i miejscami do wędkowania, co czyni go popularnym łowiskiem. Roślinność podwodna jest umiarkowana, tworząc naturalne kryjówki dla ryb, ale nie utrudniając znacząco wędkowania. W starorzeczu licznie występują szczupaki, okonie, leszcze, płocie, a także karpie, które osiągają tu imponujące rozmiary. Połączenie z rzeką podczas wysokich stanów wody zapewnia regularne zasilanie w świeżą wodę i nowe osobniki ryb, co utrzymuje populację w dobrej kondycji. Jest to idealne miejsce na całosezonowe wyprawy wędkarskie dla całej rodziny.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21034, 3.8, 1.9, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21035, 'Starorzecze Górki Małe I', 'starorzecze-gorki-male-i-zielona-gora-21035', 'OXBOW', 52.0325482, 15.5914783, 'Lubuskie', 'Zielona Góra', 'To starorzecze, położone w pobliżu Górek Małych, stanowi typowy przykład meandra Odry. Charakteryzuje się mulistym dnem z licznymi osadami organicznymi, co sprzyja rozwojowi bogatej roślinności podwodnej. Brzegi są częściowo dostępne, jednak w wielu miejscach porastają je gęste trzcinowiska i krzewy, utrudniając dostęp do wody. Wiosną i jesienią, podczas podwyższonego stanu wody, starorzecze łączy się z głównym nurtem rzeki, co umożliwia migrację ryb. Dominującymi gatunkami są lin, szczupak, płoć i okoń, które znajdują tu idealne warunki do żerowania i rozmnażania. Wędkarstwo wymaga cierpliwości i często użycia brodzących butów, ze względu na grząskie dno przy brzegach. W upalne lata istnieje ryzyko przyduchy, co należy brać pod uwagę planując wędkowanie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21035, 3.2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Płoć,Okoń', 'Trudny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21036, 'Starorzecze Górki Małe II', 'starorzecze-gorki-male-ii-zielona-gora-21036', 'OXBOW', 52.0322357, 15.5904657, 'Lubuskie', 'Zielona Góra', 'To niewielkie starorzecze jest całkowicie odcięte od głównego nurtu Odry, co sprawia, że jego ekosystem jest bardziej stabilny, lecz jednocześnie podatny na stagnację. Dno jest bardzo muliste i gęsto pokryte osadami organicznymi, co sprzyja bujnemu rozwojowi roślinności wodnej. Brzegi są niemal w całości porośnięte gęstymi trzcinami i szuwarami, co znacząco utrudnia dostęp do wody i wymaga stosowania specjalistycznego sprzętu lub brodzenia. Ze względu na płytkość i brak przepływu, w okresie letnim istnieje wysokie ryzyko przyduchy, co wpływa na aktywność ryb. Dominują tu gatunki tolerujące trudne warunki, takie jak karaś pospolity, lin, wzdręga i płoć. Łowisko jest idealne dla wędkarzy poszukujących spokoju i wyzwań związanych z przedzieraniem się przez roślinność.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21036, 2.8, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21037, 'Starorzecze Górki Małe III', 'starorzecze-gorki-male-iii-zielona-gora-21037', 'OXBOW', 52.032566, 15.5898402, 'Lubuskie', 'Zielona Góra', 'To rozległe starorzecze wyróżnia się stałym połączeniem z Odrą, co zapewnia regularną wymianę wody i stabilne warunki tlenowe. Dno jest twardsze niż w wielu innych starorzeczach, z mniejszą ilością mułu, co sprzyja różnorodności gatunkowej ryb. Brzegi są w większości łatwo dostępne, z naturalnymi miejscami do wędkowania, co czyni to łowisko popularnym wśród lokalnych wędkarzy. Roślinność wodna jest obecna, ale nie utrudnia znacząco wędkowania, tworząc raczej atrakcyjne kryjówki dla ryb. W starorzeczu tym można spotkać wiele gatunków, w tym duże szczupaki, okonie, leszcze, płocie, a także karpie. Dzięki dobremu dostępowi i stabilnym warunkom, jest to doskonałe miejsce do wędkowania przez cały rok, oferujące różnorodne możliwości dla wędkarzy spinningowych i gruntowych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21037, 4.5, 1.8, 3.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21038, 'Starorzecze Górki Małe IV', 'starorzecze-gorki-male-iv-zielona-gora-21038', 'OXBOW', 52.0326977, 15.5886121, 'Lubuskie', 'Zielona Góra', 'To niewielkie, płytkie starorzecze charakteryzuje się dynamicznym ekosystemem, zależnym od poziomu wody w Odrze. Dno jest silnie zamulone i bogate w materię organiczną, co przekłada się na bujny rozwój roślinności podwodnej i nawodnej. Brzegi są często bagniste i trudno dostępne, wymagające od wędkarza przygotowania i użycia brodzących butów. Połączenie z rzeką następuje sporadycznie, podczas wiosennych roztopów lub intensywnych opadów, co odświeża wodę i umożliwia migracje. Występuje tu wysokie ryzyko przyduchy w okresach suszy i upałów, co ogranicza populacje ryb do najbardziej odpornych gatunków. Dominują lin, karaś pospolity i wzdręga, które doskonale radzą sobie w takich warunkach. Jest to łowisko dla cierpliwych, ceniących dziką przyrodę wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21038, 1.9, 1, 2, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21039, 'Starorzecze Górki Małe V', 'starorzecze-gorki-male-v-zielona-gora-21039', 'OXBOW', 52.0330941, 15.5878276, 'Lubuskie', 'Zielona Góra', 'To starorzecze, choć odcięte od głównego nurtu, utrzymuje stabilny poziom wody i jest cenione za swoje walory wędkarskie. Dno jest zróżnicowane, z miejscami mulistymi i twardszymi, co tworzy mozaikę siedlisk dla różnych gatunków ryb. Brzegi są częściowo dostępne, zwłaszcza od strony pól, jednak pozostałe odcinki są gęsto porośnięte krzewami i trzcinami, wymagającymi przedzierania się. Roślinność podwodna jest umiarkowana, ale stanowi doskonałe kryjówki dla drapieżników. Występuje ryzyko przyduchy w skrajnych warunkach pogodowych, jednak zazwyczaj jest to łowisko produktywne. Dominują tu szczupaki, liny, okonie i płocie, oferując dobre możliwości dla wędkarzy spinningowych i spławikowych. Warto eksplorować różne partie starorzecza, aby znaleźć najlepsze miejsca żerowania ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21039, 3.8, 1.6, 3.2, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Okoń,Płoć', 'Dobry z jednej strony, reszta zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21040, 'Starorzecze Górki Małe VI', 'starorzecze-gorki-male-vi-zielona-gora-21040', 'OXBOW', 52.0332496, 15.5865568, 'Lubuskie', 'Zielona Góra', 'To jedno z najbardziej płytkich i silnie zarośniętych starorzeczy w okolicy, co nadaje mu unikalny charakter. Dno jest bardzo muliste, a cała powierzchnia wody, zwłaszcza latem, pokryta jest gęstą roślinnością nawodną i podwodną. Brzegi są niemal niedostępne, bagniste i gęsto porośnięte, co sprawia, że wędkowanie jest tu prawdziwym wyzwaniem. Starorzecze to jest całkowicie odcięte od rzeki i w okresach długotrwałej suszy może całkowicie wysychać, co znacząco wpływa na populacje ryb. Ryzyko przyduchy jest bardzo wysokie, szczególnie w upalne lata i zimą pod lodem. Dominują gatunki najbardziej odporne, takie jak karaś srebrzysty, wzdręga i płoć, które potrafią przetrwać w ekstremalnych warunkach. Jest to łowisko dla wędkarzy poszukujących dzikich, nieuregulowanych miejsc i ryb walczących o przetrwanie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21040, 2.1, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21041, 'Starorzecze Górki Małe VII', 'starorzecze-gorki-male-vii-zielona-gora-21041', 'OXBOW', 52.032952, 15.5866275, 'Lubuskie', 'Zielona Góra', 'To starorzecze charakteryzuje się umiarkowanym zamuleniem i zróżnicowaną głębokością, co tworzy dogodne warunki dla wielu gatunków ryb. Połączenie z Odrą następuje podczas wysokich stanów wody, co sprzyja migracji ryb i odświeżaniu zbiornika. Brzegi są częściowo dostępne, jednak w wielu miejscach porastają je gęste krzewy i trzciny, utrudniając swobodne wędkowanie. Roślinność wodna jest obecna, tworząc kryjówki dla ryb, ale nie uniemożliwia zarzucania zestawu. Występuje tu ryzyko przyduchy w upalne lata, co jest typowe dla starorzeczy. Dominują lin, szczupak, leszcz i płoć, które dobrze adaptują się do zmiennych warunków. Jest to łowisko dla wędkarzy ceniących różnorodność technik wędkarskich, od spławikowej po spinningową.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21041, 3.5, 1.4, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Leszcz,Płoć', 'Częściowo dostępny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21042, 'Starorzecze Górki Małe VIII', 'starorzecze-gorki-male-viii-zielona-gora-21042', 'OXBOW', 52.0330768, 15.5846453, 'Lubuskie', 'Zielona Góra', 'To jedno z lepiej utrzymanych starorzeczy w okolicy, ze stałym połączeniem z Odrą, co gwarantuje doskonałe warunki tlenowe i regularną wymianę wody. Dno jest w dużej mierze twarde, z niewielkim zamuleniem, co sprzyja różnorodności gatunkowej ryb. Brzegi są łatwo dostępne, z licznymi dogodnymi stanowiskami wędkarskimi, co czyni to miejsce bardzo popularnym. Roślinność wodna jest rzadka i nie stanowi przeszkody w wędkowaniu, a jedynie urozmaica krajobraz. Dzięki stabilnym warunkom, ryzyko przyduchy jest minimalne, co pozwala na całoroczne wędkowanie. W starorzeczu tym można złowić okazałe szczupaki, okonie, leszcze, karpie, a nawet sumy, które migrują z rzeki. Jest to idealne łowisko dla wędkarzy szukających komfortu i pewnych wyników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21042, 4, 1.7, 3.3, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Karp,Sum', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21043, 'Starorzecze Zielona Góra I', 'starorzecze-zielona-gora-i-zielona-gora-21043', 'OXBOW', 52.0313481, 15.582069, 'Lubuskie', 'Zielona Góra', 'To starorzecze, położone bliżej Zielonej Góry, jest typowym, odciętym zbiornikiem o charakterze silnie eutroficznym. Dno jest bardzo muliste, a woda płytka, co sprzyja intensywnemu rozwojowi roślinności wodnej, zarówno zanurzonej, jak i wynurzonej. Brzegi są niemal w całości porośnięte gęstymi szuwarami, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga brodzenia. Brak połączenia z rzeką sprawia, że woda jest stojąca, a ryzyko przyduchy w upalne lata jest wysokie. Dominującymi gatunkami są karaś pospolity, lin, wzdręga i płoć, które doskonale radzą sobie w takich warunkach. Łowisko to jest idealne dla wędkarzy ceniących spokój i wyzwania związane z przedzieraniem się przez dziką roślinność, oferując jednocześnie szansę na złowienie okazałych linów i karasi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21043, 2.5, 1.1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21044, 'Starorzecze Zielona Góra II', 'starorzecze-zielona-gora-ii-zielona-gora-21044', 'OXBOW', 52.0307071, 15.5840494, 'Lubuskie', 'Zielona Góra', 'To starorzecze, choć nie ma stałego połączenia z Odrą, jest zasilane wodą podczas wyższych stanów rzeki, co pozytywnie wpływa na jego ekosystem. Dno jest zróżnicowane, z miejscami mulistymi i twardszymi, pokrytymi umiarkowaną ilością roślinności podwodnej. Brzegi są częściowo dostępne, szczególnie w miejscach, gdzie teren jest bardziej suchy, jednak w wielu innych partiach są zarośnięte i bagniste. Występuje tu ryzyko przyduchy w okresach długotrwałych upałów, co jest typowe dla tego typu zbiorników. Dominującymi gatunkami ryb są szczupak, okoń, leszcz i płoć, które znajdują tu dobre warunki do żerowania i ukrycia. Jest to atrakcyjne łowisko dla wędkarzy spinningowych i spławikowych, oferujące różnorodne możliwości wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21044, 3, 1.3, 2.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Częściowo dostępny', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21045, 'Starorzecze Zielona Góra III', 'starorzecze-zielona-gora-iii-zielona-gora-21045', 'OXBOW', 52.0303485, 15.5858652, 'Lubuskie', 'Zielona Góra', 'To bardzo płytkie i silnie zarośnięte starorzecze jest przykładem zbiornika w zaawansowanym stadium sukcesji ekologicznej. Dno jest niemal całkowicie pokryte grubą warstwą mułu i rozkładających się roślin, co sprawia, że woda jest płytka i bogata w materię organiczną. Brzegi są bagniste i niemal niedostępne, gęsto porośnięte trzcinami i inną roślinnością szuwarową. Starorzecze to jest całkowicie odcięte od rzeki i w okresach suszy może całkowicie wysychać, co czyni je bardzo trudnym środowiskiem dla ryb. Ryzyko przyduchy jest ekstremalnie wysokie, co ogranicza populacje do najbardziej odpornych gatunków, takich jak karaś pospolity i wzdręga. Jest to łowisko dla prawdziwych entuzjastów dzikiej przyrody, którzy cenią wyzwania i unikalne doświadczenia wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21045, 1.8, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21046, 'Starorzecze Górki Małe IX', 'starorzecze-gorki-male-ix-zielona-gora-21046', 'OXBOW', 52.0304955, 15.5931837, 'Lubuskie', 'Zielona Góra', 'To starorzecze, podobnie jak wiele w okolicy Górek Małych, łączy się z Odrą w okresach wysokiego stanu wody, co wpływa na jego bioróżnorodność. Dno jest muliste, ale z miejscami twardszymi, a roślinność wodna jest umiarkowana, tworząc dobre warunki dla ryb. Brzegi są dostępne w niektórych miejscach, jednak w innych są zarośnięte i mogą wymagać brodzenia. Ryzyko przyduchy jest obecne w upalne lata, co należy brać pod uwagę planując wędkowanie. Dominującymi gatunkami są lin, szczupak, płoć i okoń, które znajdują tu obfitość pokarmu. Jest to łowisko uniwersalne, oferujące możliwości zarówno dla wędkarzy gruntowych, jak i spinningowych, ceniących kontakt z naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21046, 2.9, 1.4, 2.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Płoć,Okoń', 'Częściowo dostępny', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21047, 'Starorzecze Górki Małe X', 'starorzecze-gorki-male-x-zielona-gora-21047', 'OXBOW', 52.0301439, 15.5893514, 'Lubuskie', 'Zielona Góra', 'To starorzecze, choć odcięte od rzeki, jest stosunkowo głębokie jak na tego typu zbiornik, co sprzyja utrzymaniu stabilnych warunków. Dno jest zróżnicowane, z mulistymi zatokami i twardszymi partiami, gdzie roślinność podwodna jest umiarkowana. Brzegi są częściowo dostępne, szczególnie od strony drogi lub ścieżki, jednak w innych miejscach są gęsto porośnięte krzewami i trzcinami. Mimo braku stałego połączenia, zbiornik utrzymuje dobrą jakość wody, choć w upalne lata ryzyko przyduchy jest realne. Dominują tu karpie, liny, leszcze i szczupaki, które osiągają tu imponujące rozmiary. Jest to łowisko dla wędkarzy ceniących spokój i możliwość złowienia dużych okazów, szczególnie w cieplejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21047, 3.1, 1.6, 3.1, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Karp,Lin,Leszcz,Szczupak', 'Dobry z jednej strony, reszta zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21048, 'Starorzecze Karp', 'starorzecze-karp-karp-21048', 'OXBOW', 52.7515548, 22.7085315, 'Podlaskie', 'Karp', 'To malownicze starorzecze, położone w pobliżu miejscowości Karp, jest częścią systemu rzecznego Bugu lub Nurca. Charakteryzuje się stosunkowo głęboką wodą i umiarkowanym zamuleniem, co sprzyja rozwojowi bogatej ichtiofauny. Połączenie z głównym nurtem rzeki następuje podczas wiosennych roztopów i jesiennych wezbrań, co zapewnia regularną wymianę wody i migrację ryb. Brzegi są w większości dostępne, z naturalnymi miejscami do wędkowania, choć miejscami mogą być porośnięte roślinnością. Roślinność wodna jest obecna, ale nie utrudnia znacząco wędkowania, tworząc raczej atrakcyjne kryjówki dla ryb. W starorzeczu tym dominują szczupaki, okonie, leszcze, płocie oraz jazie, które cenią sobie czystszą wodę. Jest to doskonałe łowisko dla wędkarzy spinningowych i spławikowych, oferujące dobre perspektywy na udane połowy przez większość sezonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21048, 5.5, 2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Jaź', 'Dobry z jednej strony', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21049, 'Starorzecze Puławy', 'starorzecze-pulawy-pulawy-21049', 'OXBOW', 51.4061612, 21.9681893, 'Lubelskie', 'Puławy', 'To rozległe i głębokie starorzecze Wisły w okolicach Puław stanowi jedno z najbardziej atrakcyjnych łowisk w regionie. Posiada stałe połączenie z głównym nurtem rzeki, co zapewnia ciągłą wymianę wody, doskonałe warunki tlenowe i bogactwo gatunkowe ryb. Dno jest zróżnicowane, z twardszymi partiami i głębszymi rynnami, z niewielkim zamuleniem. Brzegi są w większości łatwo dostępne, z naturalnymi plażami i miejscami do wędkowania, co sprawia, że jest to popularne miejsce rekreacji. Roślinność wodna jest umiarkowana, tworząc idealne kryjówki dla drapieżników. W starorzeczu tym można spotkać imponujące okazy szczupaków, sandaczy, leszczy, karpi, sumów, a także boleni, które regularnie wpływają z Wisły. Jest to idealne łowisko dla wędkarzy szukających różnorodnych wyzwań i możliwości złowienia dużych ryb przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21049, 6, 2.2, 6, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Karp,Sum,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21050, 'Koperung', 'koperung-wloclawek-21050', 'OXBOW', 52.9404005, 18.7071609, 'Kujawsko-Pomorskie', 'Włocławek', 'Starorzecze Koperung to malowniczy zbiornik wodny położony w dolinie Wisły, charakteryzujący się typową dla tego typu akwenów bogatą bioróżnorodnością. Dno jest muliste, miejscami twardsze, z licznymi zatopionymi gałęziami i korzeniami, które stanowią doskonałe kryjówki dla ryb. Brzegi są częściowo dostępne, lecz w wielu miejscach porastają je gęste trzcinowiska i krzewy, utrudniające dostęp do wody. Roślinność podwodna jest umiarkowana, tworząc zarośla rdestnic i moczarki, szczególnie w płytszych partiach. Zbiornik jest domem dla licznych linów, karasi pospolitych i płoci, a także drapieżnych szczupaków, które czyhają w zaroślach. Wiosną i wczesną jesienią wędkarze mogą liczyć na udane połowy, choć miejscami trudności sprawia gęsta roślinność i zaczepy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21050, 5.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak,Leszcz', 'Dobry, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21051, 'Starorzecze Częstochowa', 'starorzecze-czestochowa-czestochowa-21051', 'OXBOW', 50.8281932, 19.1645627, 'Śląskie', 'Częstochowa', 'To niewielkie starorzecze w okolicach Częstochowy jest typowym przykładem akwenu o silnym stopniu zarastania i zamulenia. Dno jest w przeważającej części muliste, miękkie, co utrudnia brodzenie i wymaga ostrożności. Brzegi są trudno dostępne, bagniste i gęsto porośnięte trzciną oraz inną roślinnością szuwarową, co sprawia, że wędkarstwo z brzegu jest wyzwaniem. Roślinność podwodna jest bardzo silna, tworząc gęste dywany rdestnic, moczarki i wywłócznika, co sprzyja rozwojowi karasia pospolitego, wzdręgi i lina. W lecie, ze względu na płytkość i obfitość materii organicznej, istnieje wysokie ryzyko przyduchy, dlatego najlepsze okresy na wędkowanie to późna wiosna i wczesne lato. Wędkarze powinni przygotować się na użycie brodzących spodniobutów, aby dotrzeć do lepszych miejsc połowowych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21051, 3, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć,Lin', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna i muł', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21052, 'Starorzecze Szczyty-Nowodwory (Północne)', 'starorzecze-szczyty-nowodwory-polnocne-hajnowka-21052', 'OXBOW', 52.7328391, 23.3278456, 'Podlaskie', 'Hajnówka', 'To płytkie starorzecze, położone w malowniczej okolicy Szczytów-Nowodworów, charakteryzuje się silnym stopniem zarastania, co tworzy idealne warunki dla wielu gatunków ryb. Dno jest głównie muliste, z licznymi fragmentami zatopionej roślinności, która stanowi naturalne schronienie dla drobnicy. Brzegi są trudno dostępne, gęsto porośnięte trzciną i inną roślinnością szuwarową, co wymaga użycia brodzących spodniobutów do efektywnego wędkowania. Akwen ten łączy się z rzeką podczas wysokich stanów wody, co umożliwia migrację ryb i odświeża wodę. Dominują tu płoć, wzdręga, karaś pospolity oraz okoń, które licznie żerują wśród gęstej roślinności. Wędkarstwo jest najbardziej efektywne późną wiosną i latem, kiedy ryby są aktywne, jednak trzeba liczyć się z licznymi zaczepami o podwodną roślinność.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21052, 1.8, 0.8, 2, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Płoć,Wzdręga,Karaś pospolity,Okoń', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21053, 'Starorzecze Szczyty-Nowodwory (Środkowe)', 'starorzecze-szczyty-nowodwory-srodkowe-hajnowka-21053', 'OXBOW', 52.7323749, 23.3293343, 'Podlaskie', 'Hajnówka', 'To starorzecze, będące częścią kompleksu w okolicy Szczytów-Nowodworów, charakteryzuje się płytką wodą i znacznym stopniem zamulenia. Dno jest w większości miękkie, muliste, co sprzyja rozwojowi bujnej roślinności podwodnej, takiej jak rdestnice i moczarka kanadyjska. Brzegi są wyjątkowo trudno dostępne, bagniste i gęsto porośnięte trzciną, co wymaga od wędkarzy użycia brodzących spodniobutów do komfortowego wędkowania. Akwen ten jest okresowo zasilany wodą podczas wiosennych roztopów i wysokich stanów rzeki, co odświeża jego ekosystem. Wśród dominujących gatunków ryb znajdują się płoć, karaś pospolity, wzdręga oraz lin, które doskonale odnajdują się w tak zarośniętym środowisku. Z uwagi na płytkość i obfitość materii organicznej, w okresie letnich upałów może występować ryzyko przyduchy, dlatego najlepsze połowy są możliwe późną wiosną i wczesnym latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21053, 1.5, 0.7, 1.8, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Płoć,Karaś pospolity,Wzdręga,Lin', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna i muł', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21054, 'Starorzecze Szczyty-Nowodwory (Południowe)', 'starorzecze-szczyty-nowodwory-poludniowe-hajnowka-21054', 'OXBOW', 52.7319714, 23.329669, 'Podlaskie', 'Hajnówka', 'To starorzecze w pobliżu Szczytów-Nowodworów stanowi atrakcyjne, choć wymagające łowisko, charakteryzujące się znacznym stopniem zarastania. Dno jest mieszane, z przewagą mułu, ale występują też twardsze fragmenty oraz liczne zatopione gałęzie i roślinność, stanowiące doskonałe kryjówki dla ryb. Brzegi są w większości trudno dostępne, gęsto porośnięte trzciną i krzewami, jednak miejscami można znaleźć niewielkie prześwity umożliwiające zarzucenie wędki. Akwen ten jest okresowo zasilany wodami powodziowymi, co wpływa na jego ekosystem i skład gatunkowy ryb. Dominujące gatunki to lin, szczupak, płoć i karaś pospolity, które doskonale prosperują w tym środowisku bogatym w roślinność. Wędkarstwo jest najbardziej efektywne wiosną i latem, ale wymaga cierpliwości i umiejętności poruszania się w trudnym terenie oraz unikania licznych zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21054, 2, 0.9, 2.2, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Szczupak,Płoć,Karaś pospolity', 'Trudny, zarośnięty, ale z kilkoma prześwitami', TRUE, 'Gęsta roślinność podwodna i pojedyncze konary', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21055, 'Starorzecze Stary Górnik (Południowe)', 'starorzecze-stary-gornik-poludniowe-olawa-21055', 'OXBOW', 50.9746414, 17.3363545, 'Dolnośląskie', 'Oława', 'To starorzecze w okolicach Starego Górnika, położone w dolinie Odry, jest popularnym i stosunkowo łatwo dostępnym łowiskiem. Dno jest zróżnicowane, od twardych, piaszczystych fragmentów po miękkie, muliste obszary, z nielicznymi zaczepami w postaci zatopionych gałęzi. Brzegi są w większości dobrze dostępne, co ułatwia wędkowanie z gruntu i spławika, choć miejscami występują pasy trzcin. Roślinność podwodna jest umiarkowana, tworząc idealne środowisko dla różnorodnych gatunków ryb. Zbiornik słynie z obfitości leszczy i płoci, a także większych karpi i sumów, które stanowią wyzwanie dla doświadczonych wędkarzy. Występują tu również szczupaki, polujące na drobną rybę w zaroślach. Wędkarstwo jest możliwe przez cały sezon, a ryzyko przyduchy jest niskie dzięki okresowemu połączeniu z rzeką podczas wysokich stanów wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21055, 4, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sum,Szczupak', 'Dobry z niektórych stron, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21056, 'Starorzecze Stary Górnik (Północne)', 'starorzecze-stary-gornik-polnocne-olawa-21056', 'OXBOW', 50.9759541, 17.3365442, 'Dolnośląskie', 'Oława', 'To starorzecze, sąsiadujące z południowym, jest również cenionym łowiskiem, charakteryzującym się dobrą dostępnością i stosunkowo czystym dnem. Dno jest głównie twarde, piaszczysto-żwirowe, z niewielką ilością mułu, co ułatwia prowadzenie przynęt i minimalizuje zaczepy. Brzegi są dobrze utrzymane, z kilkoma pomostami wędkarskimi, co sprzyja komfortowemu wędkowaniu. Roślinność podwodna jest umiarkowana, skupiając się w płytszych zatoczkach, gdzie stanowi schronienie dla drobnicy. Akwen ten jest szczególnie atrakcyjny dla wędkarzy poszukujących drapieżników, takich jak szczupak i okoń, które licznie występują w jego wodach. Poza drapieżnikami, można tu złowić również leszcze i płocie, zwłaszcza wiosną i jesienią. Okresowe połączenie z Odrą zapewnia świeżą wodę i migrację ryb, co utrzymuje ekosystem w dobrej kondycji i minimalizuje ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21056, 3.5, 1.3, 2.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry, z kilkoma pomostami wędkarskimi', FALSE, 'Czyste dno, z pojedynczymi kępami roślinności', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21057, 'Starorzecze Czmoniec (Wschodnie)', 'starorzecze-czmoniec-wschodnie-kornik-21057', 'OXBOW', 52.1792763, 17.0015187, 'Wielkopolskie', 'Kórnik', 'To starorzecze, położone w malowniczym kompleksie Czmoniec, jest typowym łowiskiem dla wędkarzy ceniących spokój i kontakt z naturą. Dno jest zróżnicowane, z przewagą mulistych fragmentów, ale również z twardszymi, piaszczystymi odcinkami, które są atrakcyjne dla żerujących ryb. Brzegi są częściowo dostępne, z licznymi zatoczkami i miejscami, gdzie można swobodnie zarzucić wędkę, choć miejscami porastają je gęste trzcinowiska. Roślinność podwodna jest umiarkowana, tworząc naturalne kryjówki dla ryb i sprzyjając rozwojowi ekosystemu. W zbiorniku dominują lin, karaś pospolity, płoć oraz okoń, które stanowią główny cel wędkarzy. Akwen ten okresowo łączy się z rzeką Wartą podczas wiosennych wezbrań, co sprzyja odświeżaniu wody i migracji ryb. Najlepsze wyniki wędkarskie osiąga się wiosną i wczesną jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21057, 2.2, 1, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Okoń', 'Dobry w części, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21058, 'Starorzecze Czmoniec (Północno-Wschodnie)', 'starorzecze-czmoniec-polnocno-wschodnie-kornik-21058', 'OXBOW', 52.1798241, 17.0006838, 'Wielkopolskie', 'Kórnik', 'To niewielkie starorzecze w kompleksie Czmoniec jest przykładem akwenu o wysokim stopniu izolacji i silnego zarastania. Dno jest w przeważającej części muliste, miękkie, co utrudnia brodzenie i wymaga ostrożności podczas wędkowania. Brzegi są wyjątkowo trudno dostępne, bagniste i gęsto porośnięte trzciną oraz inną roślinnością szuwarową, co sprawia, że wędkarstwo z brzegu jest praktycznie niemożliwe bez użycia brodzących spodniobutów. Roślinność podwodna jest bardzo silna, tworząc gęste dywany rdestnic i moczarki, co sprzyja rozwojowi karasia pospolitego, wzdręgi i lina. W lecie, ze względu na płytkość i obfitość materii organicznej, istnieje wysokie ryzyko przyduchy, dlatego najlepsze okresy na wędkowanie to późna wiosna i wczesne lato. Wędkarze powinni być przygotowani na liczne zaczepy o podwodną roślinność.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21058, 1.5, 0.9, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Lin', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna i muł', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21059, 'Starorzecze Czmoniec (Centralne Północne)', 'starorzecze-czmoniec-centralne-polnocne-kornik-21059', 'OXBOW', 52.1798469, 16.9999008, 'Wielkopolskie', 'Kórnik', 'To jedno z najmniejszych i najbardziej zarośniętych starorzeczy w kompleksie Czmoniec, charakteryzujące się ekstremalnie trudnym dostępem. Dno jest w całości muliste, miękkie i pełne zatopionych gałęzi oraz gęstej roślinności, co czyni wędkowanie wyzwaniem. Brzegi są niemal nieprzejezdne, zarośnięte krzewami, drzewami i wysokimi szuwarami, wymagającymi przedzierania się. Akwen jest całkowicie odcięty od rzeki, co sprzyja szybkiemu zamulaniu i zarastaniu, a w okresach suszy może całkowicie wysychać. Dominują tu gatunki odporne na trudne warunki, takie jak karaś srebrzysty, wzdręga i płoć, które potrafią przetrwać w tak wymagającym środowisku. Z uwagi na ryzyko wysychania i przyduchy, najlepszym okresem na wędkowanie jest wczesna wiosna, zanim roślinność osiągnie pełnię wzrostu, a temperatura wody nie jest zbyt wysoka.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21059, 1, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Bardzo trudny, gęste zarośla', TRUE, 'Gęsta roślinność podwodna i zatopione gałęzie', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21060, 'Starorzecze Czmoniec (Centralne Zachodnie)', 'starorzecze-czmoniec-centralne-zachodnie-kornik-21060', 'OXBOW', 52.1798282, 16.9997528, 'Wielkopolskie', 'Kórnik', 'To starorzecze, podobnie jak sąsiednie, jest bardzo płytkie i silnie zarośnięte, co czyni je trudnym, lecz potencjalnie ciekawym łowiskiem. Dno jest niemal w całości pokryte grubą warstwą mułu i gęstą roślinnością podwodną, co wymaga precyzyjnego prowadzenia przynęt. Brzegi są niezwykle trudne do pokonania, porośnięte bagnistymi zaroślami i wysokimi trawami, co wymusza użycie brodzących spodniobutów. Akwen jest odizolowany od głównego nurtu rzeki, co prowadzi do szybkiego zamulania i zwiększa ryzyko przyduchy w upalne lata. W okresach długotrwałej suszy zbiornik ten może całkowicie wyschnąć. Dominują tu gatunki ryb wysoce odporne na trudne warunki środowiskowe, takie jak karaś srebrzysty, wzdręga i płoć. Wędkowanie jest najbardziej efektywne wczesną wiosną, kiedy poziom wody jest wyższy, a roślinność nie jest jeszcze tak bujna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21060, 0.8, 0.7, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Bardzo trudny, gęste zarośla i muł', TRUE, 'Gęsta roślinność podwodna, muł i gałęzie', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21061, 'Starorzecze Czmoniec (Centralne Południowe)', 'starorzecze-czmoniec-centralne-poludniowe-kornik-21061', 'OXBOW', 52.1790573, 17.000011, 'Wielkopolskie', 'Kórnik', 'To starorzecze w kompleksie Czmoniec jest typowym przykładem akwenu o znacznym stopniu zamulenia i silnego zarastania, co stanowi wyzwanie dla wędkarzy. Dno jest w dużej mierze muliste, z licznymi fragmentami zatopionej roślinności, tworzącej naturalne kryjówki dla ryb. Brzegi są trudno dostępne, bagniste i gęsto porośnięte trzciną oraz krzewami, co wymaga użycia brodzących spodniobutów. Akwen jest odizolowany od głównego nurtu rzeki, co sprzyja rozwojowi bujnej roślinności wodnej i zwiększa ryzyko przyduchy w okresach letnich upałów. Dominują tu lin, karaś pospolity i płoć, które doskonale odnajdują się w tak zarośniętym środowisku. Wędkowanie jest najbardziej efektywne późną wiosną, kiedy ryby są aktywne, a roślinność nie jest jeszcze w pełni rozwinięta, co ułatwia prowadzenie przynęt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21061, 1.2, 0.9, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć', 'Trudny, bagnisty, zarośnięty', TRUE, 'Gęsta roślinność podwodna i muł', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21062, 'Starorzecze Czmoniec (Północne Skrajne)', 'starorzecze-czmoniec-polnocne-skrajne-kornik-21062', 'OXBOW', 52.1816357, 17.0024268, 'Wielkopolskie', 'Kórnik', 'To starorzecze, położone na północnym skraju kompleksu Czmoniec, wyróżnia się lepszą dostępnością i mniejszym stopniem zamulenia. Dno jest zróżnicowane, z przewagą twardszych, piaszczysto-żwirowych fragmentów, co ułatwia wędkowanie i minimalizuje zaczepy. Brzegi są dobrze dostępne, z kilkoma naturalnymi stanowiskami wędkarskimi, co sprzyja komfortowemu spędzaniu czasu nad wodą. Roślinność podwodna jest umiarkowana, tworząc idealne środowisko dla drapieżników i ryb spokojnego żeru. Akwen ten okresowo łączy się z rzeką Wartą podczas wysokich stanów wody, co zapewnia odświeżanie i migrację ryb. Dominują tu szczupak, okoń, leszcz i płoć, oferując wędkarzom różnorodne możliwości połowu. Najlepsze wyniki osiąga się wiosną i jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21062, 1.8, 1.1, 2.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry, z kilkoma dogodnymi stanowiskami', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21063, 'Starorzecze Czmoniec (Zachodnie)', 'starorzecze-czmoniec-zachodnie-kornik-21063', 'OXBOW', 52.1790464, 16.9984007, 'Wielkopolskie', 'Kórnik', 'To starorzecze, położone w zachodniej części kompleksu Czmoniec, jest cenionym łowiskiem, choć wymaga pewnego wysiłku w dotarciu. Dno jest zróżnicowane, z przewagą mułu, ale również z twardszymi fragmentami, a także z licznymi zatopionymi korzeniami i gęstą roślinnością podwodną, które stanowią doskonałe kryjówki dla ryb. Brzegi są w większości zarośnięte, co utrudnia dostęp, jednak z pewnym trudem można znaleźć dogodne miejsca do wędkowania. Akwen ten, choć odizolowany od głównego nurtu rzeki, utrzymuje stabilny poziom wody i bogaty ekosystem. Dominują tu lin, karp, leszcz oraz szczupak, oferując wędkarzom różnorodne możliwości połowu przez cały sezon. Ze względu na gęstą roślinność i zaczepy, wędkarstwo wymaga precyzji i użycia odpowiedniego sprzętu, a brodzące spodniobuty mogą okazać się przydatne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21063, 2, 1.2, 2.7, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karp,Leszcz,Szczupak', 'Trudny, zarośnięty, ale z możliwością dojścia', TRUE, 'Pojedyncze korzenie i gęsta roślinność podwodna', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21064, 'Starorzecze Czmoniec (Skrajne Zachodnie)', 'starorzecze-czmoniec-skrajne-zachodnie-kornik-21064', 'OXBOW', 52.1797203, 16.9962933, 'Wielkopolskie', 'Kórnik', 'To starorzecze, położone na skrajnym zachodzie kompleksu Czmoniec, jest jednym z głębszych i mniej zarośniętych akwenów, co czyni go atrakcyjnym dla wędkarzy. Dno jest w dużej mierze twarde, piaszczysto-żwirowe, z niewielką ilością mułu i pojedynczymi zatopionymi konarami, które stanowią kryjówki dla drapieżników. Brzegi są w częściach dobrze dostępne, co ułatwia wędkowanie z gruntu i spławika, choć miejscami występują pasy trzcin. Roślinność podwodna jest umiarkowana, skupiając się w płytszych zatoczkach. Akwen ten słynie z występowania dużych drapieżników, takich jak sandacz, sum i szczupak, a także dorodnych leszczy i karpi. Choć jest odizolowany od głównego nurtu rzeki, jego głębokość i stabilny ekosystem minimalizują ryzyko przyduchy. Najlepsze wyniki osiąga się latem i jesienią, szczególnie podczas wieczornych i nocnych zasiadek.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21064, 2.5, 1.3, 3, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sandacz,Sum,Szczupak,Leszcz,Karp', 'Dobry w części, miejscami zarośnięty', FALSE, 'Czyste dno, z pojedynczymi zatopionymi konarami', 'Lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21065, 'Starorzecze (Czmoniec)', 'starorzecze-czmoniec-kornik-21065', 'OXBOW', 52.1799652, 16.9956468, 'Wielkopolskie', 'Kórnik', 'To starorzecze, położone w pobliżu Czmońca, charakteryzuje się podłużnym kształtem i umiarkowaną głębokością, idealną dla wielu gatunków ryb. Dno jest muliste z miejscowymi twardymi blatami, co sprzyja bytowania lina i karasia pospolitego. Brzegi są częściowo zarośnięte trzciną i pałką wodną, oferując schronienie drapieżnikom takim jak szczupak. Występuje tu również bogata populacja płoci, stanowiąca dobrą bazę pokarmową. Łowisko łączy się z rzeką podczas wysokich stanów wody, co zasila je w świeżą wodę i ryby, jednak w upalne lata może występować ryzyko przyduchy. Dostęp do wody jest dobry, choć w niektórych miejscach wskazane jest użycie podbieraka z długim uchwytem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21065, 3.2, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21066, 'Starorzecze (Czmoniec)', 'starorzecze-czmoniec-kornik-21066', 'OXBOW', 52.1805524, 16.9964946, 'Wielkopolskie', 'Kórnik', 'Drugie starorzecze w rejonie Czmońca, choć nieco mniejsze, oferuje podobne warunki wędkarskie, z głębokością do 3 metrów. Dno jest głównie muliste, z licznymi zatopionymi gałęziami, co tworzy doskonałe kryjówki dla szczupaków i okoni. Brzegi są łatwo dostępne, choć miejscami porasta je bujna roślinność przybrzeżna, w tym grążele i lilie wodne. Wiosną i jesienią można liczyć na obfite brania lina i karasia pospolitego, które preferują płytkie, dobrze nasłonecznione zatoki. Połączenie z rzeką podczas wysokich stanów wody zapewnia stałe zarybianie, ale w okresach suszy poziom wody może spadać, zwiększając ryzyko niedoboru tlenu. Jest to idealne miejsce dla wędkarzy ceniących spokój i bliskość natury.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21066, 2.8, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21067, 'Starorzecze (Tworzykowo)', 'starorzecze-tworzykowo-kornik-21067', 'OXBOW', 52.1810193, 16.9901574, 'Wielkopolskie', 'Kórnik', 'Starorzecze w Tworzykowie to rozległe i głębokie łowisko, cenione przez wędkarzy za stabilne warunki i bogactwo ryb. Dno jest zróżnicowane, od twardego piasku po umiarkowany muł, z niewielką ilością zaczepów, co ułatwia wędkowanie. Brzegi są przeważnie łatwo dostępne, z nielicznymi, ale urokliwymi, zaroślami, które stanowią naturalne stanowiska. Akwen słynie z pięknych szczupaków i leszczy, a także licznych populacji płoci i okoni. Połączenie z głównym nurtem rzeki podczas wezbrań gwarantuje regularny dopływ świeżej wody i ryb, co minimalizuje ryzyko przyduchy. To doskonałe miejsce do wędkowania przez cały sezon, oferujące zarówno drapieżniki, jak i ryby spokojnego żeru.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21067, 4.1, 2.1, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21068, 'Starorzecze (nieznanej okolicy)', 'starorzecze-nieznanej-okolicy-kornik-21068', 'OXBOW', 52.181721, 16.9911911, 'Wielkopolskie', 'Kórnik', 'To niewielkie starorzecze, położone w nieznanej okolicy, jest płytkim i silnie zarośniętym akwenem, co czyni je wyzwaniem dla wędkarzy. Dno jest grubo pokryte mułem i gęstą roślinnością podwodną, co utrudnia prowadzenie przynęt. Brzegi są trudne do pokonania, często bagniste i mocno zarośnięte, co wymaga użycia wodoodpornych spodni. Występuje tu silne ryzyko przyduchy, zwłaszcza latem, a w skrajnych przypadkach zbiornik może wysychać, co wpływa na populację ryb. Mimo trudności, wędkarze mogą liczyć na okazałe karasie pospolite, liny i wzdręgi, które doskonale radzą sobie w tych warunkach. Jest to łowisko dla cierpliwych i doświadczonych wędkarzy, poszukujących dzikich, nieuregulowanych miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21068, 1.9, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21069, 'Starorzecze (Orkowo)', 'starorzecze-orkowo-kornik-21069', 'OXBOW', 52.1776007, 16.9910784, 'Wielkopolskie', 'Kórnik', 'Starorzecze w Orkowo to malowniczy zbiornik o umiarkowanej wielkości, charakteryzujący się bogatą roślinnością i urozmaiconym dnem. Dno jest muliste, z licznymi korzeniami i zatopionymi gałęziami, stanowiącymi idealne kryjówki dla drapieżników. Brzegi są mocno zarośnięte trzciną, co utrudnia dostęp do wody i wymaga użycia wodoodpornych spodni. Akwen jest domem dla licznych populacji lina i karasia pospolitego, a także szczupaka i płoci, które znajdują tu obfitość pokarmu i schronienia. Okresowe połączenie z rzeką podczas wysokich stanów wody odświeża zbiornik, jednak w upalne lata istnieje ryzyko niedoboru tlenu. Wędkarstwo tutaj to prawdziwa przygoda, wymagająca precyzji i znajomości terenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21069, 2.5, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21070, 'Starorzecze (Orkowo)', 'starorzecze-orkowo-kornik-21070', 'OXBOW', 52.1783738, 16.9934012, 'Wielkopolskie', 'Kórnik', 'Drugie starorzecze w Orkowo to nieco głębsze łowisko, oferujące bardziej zróżnicowane warunki, z dobrą dostępnością do brzegów. Dno jest przeważnie czyste, z niewielką ilością mułu i sporadycznymi zaczepami, co sprzyja różnym technikom wędkarskim. Brzegi są łatwo dostępne, z licznymi dogodnymi stanowiskami, otoczonymi naturalną roślinnością. W akwenie dominują szczupaki i okonie, a także licznie występujące leszcze i płocie, które osiągają tu imponujące rozmiary. Połączenie z rzeką podczas wezbrań zapewnia stały dopływ świeżej wody i ryb, utrzymując stabilne środowisko. To świetne miejsce dla wędkarzy poszukujących zarówno drapieżników, jak i ryb spokojnego żeru przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21070, 3, 1.9, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21071, 'Starorzecze (Opatkowice)', 'starorzecze-opatkowice-kozienice-21071', 'OXBOW', 51.4631196, 21.8702332, 'Mazowieckie', 'Kozienice', 'To duże starorzecze w Opatkowicach charakteryzuje się stałym połączeniem z rzeką, co zapewnia doskonałe warunki dla bogatej ichtiofauny. Dno jest zróżnicowane, od piaszczystych blatów po umiarkowanie muliste obszary, z nielicznymi zaczepami. Brzegi są dobrze dostępne, z licznymi miejscami do wędkowania, otoczone lasami łęgowymi. Akwen słynie z dużych szczupaków, sandaczy i sumów, a także obfitych populacji leszczy i płoci. Stały przepływ wody minimalizuje ryzyko przyduchy i zapewnia rybom optymalne warunki do wzrostu. Jest to jedno z najlepszych starorzeczy w regionie, idealne dla wędkarzy ceniących sobie różnorodność i szansę na naprawdę dużą rybę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21071, 5.5, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Sandacz,Płoć,Sum', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21072, 'Starorzecze (Opatkowice)', 'starorzecze-opatkowice-kozienice-21072', 'OXBOW', 51.4607022, 21.8759203, 'Mazowieckie', 'Kozienice', 'Kolejne starorzecze w Opatkowicach, również ze stałym połączeniem z rzeką, oferuje stabilne i atrakcyjne warunki wędkarskie. Dno jest czyste, z przewagą piasku i żwiru, co sprzyja występowaniu sandaczy i okoni. Brzegi są łatwo dostępne, z licznymi pomostami i naturalnymi stanowiskami, idealnymi do spędzania czasu nad wodą. W zbiorniku występują liczne szczupaki, leszcze i płocie, stanowiące podstawę diety większych drapieżników. Ciągły dopływ świeżej wody gwarantuje wysoką jakość wody i minimalizuje ryzyko niedoboru tlenu. To doskonałe miejsce dla wędkarzy preferujących spinning, jak i metody gruntowe, z szansą na obfite połowy przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21072, 4.8, 2.2, 4.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Sandacz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21073, 'Starorzecze (Opatkowice)', 'starorzecze-opatkowice-kozienice-21073', 'OXBOW', 51.4592605, 21.8796131, 'Mazowieckie', 'Kozienice', 'To starorzecze w Opatkowicach, charakteryzujące się okresowym połączeniem z rzeką, jest łowiskiem o umiarkowanej głębokości i bogatej roślinności. Dno jest muliste, z gęstą roślinnością podwodną, co wymaga precyzyjnego prowadzenia zestawów. Brzegi są mocno zarośnięte trzciną i inną roślinnością przybrzeżną, co utrudnia dostęp do wody i wymaga użycia wodoodpornych spodni. W akwenie dominują liny i karasie pospolite, a także liczne szczupaki i płocie, które znajdują tu schronienie i pokarm. Podczas upalnych miesięcy istnieje podwyższone ryzyko przyduchy, co może wpływać na aktywność ryb. Jest to miejsce dla wędkarzy szukających spokoju i ceniących sobie wędkowanie w naturalnym, nieco dzikim otoczeniu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21073, 3.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21074, 'Starorzecze (Opatkowice)', 'starorzecze-opatkowice-kozienice-21074', 'OXBOW', 51.4575852, 21.8779852, 'Mazowieckie', 'Kozienice', 'Niewielkie i płytkie starorzecze w Opatkowicach, bez stałego połączenia z rzeką, jest silnie zamulone i zarośnięte, co sprawia, że jest to łowisko dla wytrwałych. Dno pokryte jest grubą warstwą mułu i dużą ilością zatopionych drzew, tworząc liczne zaczepy. Brzegi są trudne do pokonania, często bagniste i nieprzystępne, co wymaga użycia wodoodpornych spodni. Zbiornik jest podatny na wysychanie w okresach suszy i ma wysokie ryzyko przyduchy, co ogranicza populację ryb. Mimo to, można tu spotkać okazałe karasie pospolite, liny i wzdręgi, które są przystosowane do trudnych warunków. To wyzwanie dla wędkarzy poszukujących dzikich, nietkniętych miejsc, gdzie natura rządzi się swoimi prawami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21074, 2.9, 1.5, 3, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21075, 'Starorzecze (Opatkowice)', 'starorzecze-opatkowice-kozienice-21075', 'OXBOW', 51.4574786, 21.8764926, 'Mazowieckie', 'Kozienice', 'To starorzecze w Opatkowicach, choć bez stałego połączenia z rzeką, utrzymuje stały poziom wody, jednak jest silnie zarośnięte. Dno jest muliste i gęsto pokryte roślinnością podwodną, co utrudnia skuteczne wędkowanie, ale sprzyja bytowania lina i karasia. Brzegi są mocno zarośnięte trzciną, co wymaga użycia wodoodpornych spodni i poszukiwania dogodnych prześwitów. Mimo to, w akwenie występują liczne populacje karasia pospolitego, lina, wzdręgi i płoci, które doskonale czują się w tym środowisku. W upalne lata istnieje ryzyko przyduchy, co może wpływać na aktywność ryb, jednak zbiornik rzadko wysycha. To łowisko dla wędkarzy ceniących sobie spokój i poszukujących ryb spokojnego żeru w gęstych zaroślach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21075, 3.1, 1.6, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21076, 'Starorzecze (Opatkowice)', 'starorzecze-opatkowice-kozienice-21076', 'OXBOW', 51.4570502, 21.867807, 'Mazowieckie', 'Kozienice', 'Duże starorzecze w Opatkowicach, ze stałym połączeniem z rzeką, to jedno z najbardziej atrakcyjnych łowisk w regionie. Charakteryzuje się znaczną głębokością i czystym dnem, co sprzyja występowaniu różnorodnych gatunków ryb. Brzegi są łatwo dostępne, z licznymi miejscami do wędkowania, otoczone malowniczymi krajobrazami. Akwen jest znany z dużych szczupaków, sandaczy i sumów, a także obfitych populacji leszczy i karpi, które osiągają tu imponujące rozmiary. Stały dopływ świeżej wody gwarantuje doskonałą jakość wody i minimalizuje ryzyko przyduchy. To idealne miejsce dla wędkarzy preferujących spinning, grunt, jak i spławik, z gwarancją emocjonujących połowów przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21076, 6, 2.8, 5.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Karp,Sum', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21077, 'Starorzecze (Karolewo)', 'starorzecze-karolewo-grudziadz-21077', 'OXBOW', 53.4431396, 19.1680191, 'Kujawsko-Pomorskie', 'Grudziądz', 'Starorzecze w Karolewie to rozległy i głęboki akwen, posiadający stałe połączenie z rzeką, co czyni je niezwykle atrakcyjnym łowiskiem. Dno jest zróżnicowane, od twardego po umiarkowanie muliste, z pojedynczymi korzeniami i gałęziami, stanowiącymi kryjówki dla ryb. Brzegi są dobrze dostępne, z wieloma dogodnymi stanowiskami, otoczone bujną roślinnością. Akwen słynie z dużych szczupaków, sandaczy, okoni i węgorzy, a także licznych populacji leszczy. Stały przepływ wody gwarantuje stabilne warunki tlenowe i obfitość pokarmu, co sprzyja wzrostowi ryb. Jest to łowisko dla wędkarzy poszukujących zarówno drapieżników, jak i ryb spokojnego żeru, oferujące niezapomniane wrażenia przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21077, 7.5, 3, 6, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Okoń,Węgorz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21078, 'Starorzecze (Łęg)', 'starorzecze-leg-otwock-21078', 'OXBOW', 52.1048309, 21.1982476, 'Mazowieckie', 'Otwock', 'To starorzecze w Łęgu to malowniczy zbiornik o umiarkowanej głębokości, charakteryzujący się okresowym połączeniem z Wisłą. Dno jest muliste, z licznymi roślinami podwodnymi i pojedynczymi zaczepami, które stanowią schronienie dla ryb. Brzegi są dobrze dostępne, choć miejscami porasta je trzcina, co dodaje uroku i naturalności. Akwen jest domem dla licznych populacji szczupaka, lina, leszcza, płoci i okonia, które znajdują tu obfitość pokarmu. Połączenie z rzeką podczas wysokich stanów wody odświeża zbiornik, jednak w upalne lata istnieje ryzyko niedoboru tlenu. To świetne miejsce dla wędkarzy ceniących sobie spokój i różnorodność gatunków ryb, zwłaszcza wiosną i wczesną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21078, 4, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21079, 'Starorzecze (Łęg)', 'starorzecze-leg-otwock-21079', 'OXBOW', 52.102109, 21.2012321, 'Mazowieckie', 'Otwock', 'Drugie starorzecze w Łęgu, położone w bliskim sąsiedztwie pierwszego, oferuje podobne, ale równie atrakcyjne warunki wędkarskie. Dno jest przeważnie muliste, z gęstszą roślinnością podwodną w płytszych partiach, co sprzyja bytowania lina i płoci. Brzegi są łatwo dostępne, z licznymi dogodnymi stanowiskami, choć miejscami występują zarośla trzcinowe. W akwenie dominują szczupaki, leszcze i okonie, a także liczne populacje lina i płoci, które osiągają tu dobre rozmiary. Okresowe połączenie z Wisłą zapewnia dopływ świeżej wody i ryb, jednak w upalne miesiące może wystąpić ryzyko przyduchy. To starorzecze jest idealne dla wędkarzy szukających różnorodności i ceniących sobie wędkowanie w naturalnym, podmiejskim krajobrazie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21079, 3.8, 1.7, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21080, 'Starorzecze (Ściejowice #1)', 'starorzecze-sciejowice-1-sciejowice-21080', 'OXBOW', 50.008696, 19.7873254, 'Małopolskie', 'Ściejowice', 'To starorzecze, położone w malowniczej dolinie Wisły, stanowi atrakcyjne łowisko dla wędkarzy ceniących spokój i różnorodność gatunków. Dno jest muliste, z twardszymi partiami żwiru w pobliżu dawnego koryta rzeki. Brzegi są przeważnie stabilne, porośnięte trawą i pojedynczymi drzewami, co ułatwia dostęp. Roślinność podwodna jest umiarkowana, tworząc schronienie dla ryb, ale nie utrudniając znacząco wędkowania. Można tu liczyć na duże leszcze i płocie, a także piękne liny i szczupaki, szczególnie aktywne wczesną wiosną i jesienią. Okresowo, podczas wysokich stanów wody, łączy się z Wisłą, co sprzyja migracji ryb i odnawianiu populacji.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21080, 3.2, 1.8, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21081, 'Starorzecze (Ściejowice #2)', 'starorzecze-sciejowice-2-sciejowice-21081', 'OXBOW', 50.0087376, 19.788481, 'Małopolskie', 'Ściejowice', 'Ta część starorzecza charakteryzuje się bardziej odciętym od rzeki charakterem, co sprzyja rozwojowi bujnej roślinności. Dno jest bardzo muliste, a brzegi gęsto porośnięte trzciną i pałką wodną, co sprawia, że dostęp do wody jest utrudniony i wymaga użycia spodniobutów. Silne zarośnięcie roślinnością podwodną, zwłaszcza latem, stanowi wyzwanie dla wędkarzy, ale jednocześnie tworzy idealne środowisko dla karasi pospolitych, linów i wzdręg. W ciepłych miesiącach istnieje ryzyko przyduchy, dlatego wędkarze powinni być świadomi tego zagrożenia. To idealne miejsce dla miłośników wędkowania spławikowego w gęstych zaroślach, szukających okazów ryb spokojnego żeru.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21081, 2.8, 1.5, 3.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21082, 'Starorzecze (Ściejowice #3)', 'starorzecze-sciejowice-3-sciejowice-21082', 'OXBOW', 50.0086099, 19.7888386, 'Małopolskie', 'Ściejowice', 'To dynamiczne starorzecze utrzymuje stałe połączenie z Wisłą, co gwarantuje ciągłą wymianę wody i niskie zamulenie. Charakteryzuje się stosunkowo czystym dnem i słabym zarośnięciem, co sprzyja drapieżnikom. Brzegi są łatwo dostępne, z licznymi dogodnymi miejscami do wędkowania. Roślinność podwodna jest rzadka, głównie skupiona w płytszych zatokach. Jest to prawdziwy raj dla spinningistów, poszukujących szczupaków, okoni i boleni, które często wpływają tu z głównego nurtu rzeki. Można tu również złowić duże jazie i płocie, zwłaszcza w miejscach o umiarkowanym prądzie. Dzięki stałemu połączeniu, ryzyko przyduchy jest minimalne, a łowisko jest atrakcyjne przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21082, 4.1, 2.2, 5.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Boleń,Jaź,Płoć', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21083, 'Starorzecze (Ściejowice #4)', 'starorzecze-sciejowice-4-sciejowice-21083', 'OXBOW', 50.008431, 19.7887669, 'Małopolskie', 'Ściejowice', 'Ostatnie z starorzeczy w rejonie Ściejowic to płytki, silnie zarośnięty akwen, który w upalne lata potrafi wysychać. Dno jest bardzo muliste, a brzegi bagniste i trudno dostępne, wymagające użycia spodniobutów. Dominująca roślinność podwodna i nawodna tworzy gęste dywany, co utrudnia wędkowanie, ale sprzyja gatunkom odpornym na trudne warunki. Królują tu karasie srebrzyste i wzdręgi, które doskonale radzą sobie w płytkich, ciepłych wodach. Ryzyko przyduchy jest wysokie, szczególnie zimą pod lodem i latem w czasie upałów. Jest to łowisko dla cierpliwych wędkarzy, poszukujących specyficznych gatunków w trudnym terenie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21083, 1.9, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21084, 'Starorzecze (Drohiczyn)', 'starorzecze-drohiczyn-drohiczyn-21084', 'OXBOW', 52.3969691, 22.6294995, 'Podlaskie', 'Drohiczyn', 'To rozległe starorzecze w pobliżu Drohiczyna jest perłą Podlasia, słynącą z bogactwa gatunków ryb, w tym dużych sumów i sandaczy. Dno jest zróżnicowane, z głębokimi rynnami i zatopionymi drzewami, które stanowią doskonałe kryjówki dla drapieżników. Brzegi są łatwo dostępne, z licznymi polankami i miejscami do rozbicia obozu. Roślinność podwodna jest umiarkowana, skupiona głównie w płytszych zatokach. Łowisko łączy się z rzeką Bug podczas wysokich stanów wody, co sprzyja migracji ryb i utrzymywaniu zdrowej populacji. Wędkarze spinningowi i gruntowi znajdą tu doskonałe warunki do połowu dużych ryb, a obecność licznych zaczepów wymaga pewnego doświadczenia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21084, 7.5, 2.5, 6, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Sandacz,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21085, 'Starorzecze (Gostomia #1)', 'starorzecze-gostomia-1-gostomia-21085', 'OXBOW', 51.6117555, 20.6529457, 'Mazowieckie', 'Gostomia', 'To starorzecze w Gostomi jest popularnym łowiskiem, cenionym za stabilną populację karpi i linów. Dno jest muliste, z twardszymi fragmentami wzdłuż dawnego koryta. Brzegi są łatwo dostępne, z licznymi stanowiskami wędkarskimi i dogodnym dojazdem. Roślinność podwodna jest umiarkowana, głównie w postaci grążeli i moczarki, stanowiąc schronienie dla ryb. Brak stałego połączenia z rzeką sprawia, że woda jest spokojna, idealna dla wędkarzy spławikowych i gruntowych. Ryzyko przyduchy jest niskie dzięki odpowiedniej głębokości i wielkości akwenu. Wędkowanie jest tu przyjemne przez cały sezon, oferując szansę na złowienie dorodnych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21085, 5, 2, 4, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Lin,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21086, 'Starorzecze (Gostomia #2)', 'starorzecze-gostomia-2-gostomia-21086', 'OXBOW', 51.6115157, 20.6526118, 'Mazowieckie', 'Gostomia', 'Ta część starorzecza, charakteryzująca się okresowym połączeniem z rzeką, oferuje czyste dno i słabe zarośnięcie, co sprzyja drapieżnikom. Dno jest piaszczysto-żwirowe, z niewielką ilością mułu. Brzegi są łatwo dostępne, idealne do spinningowania. Roślinność podwodna jest rzadka, głównie skupiona w płytszych zatoczkach. Wiosną i jesienią można tu liczyć na aktywne szczupaki i okonie, które wpływają z rzeki. Płocie i wzdręgi również są liczne, stanowiąc bazę pokarmową dla drapieżników. Jest to doskonałe miejsce dla wędkarzy preferujących aktywny połów, bez obawy o zaczepy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21086, 3.5, 1.5, 3, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Wzdręga', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21087, 'Starorzecze (Gostomia #3)', 'starorzecze-gostomia-3-gostomia-21087', 'OXBOW', 51.611651, 20.6518936, 'Mazowieckie', 'Gostomia', 'To płytkie i silnie zamulone starorzecze jest prawdziwym wyzwaniem dla wędkarzy, ale obfituje w ryby spokojnego żeru. Dno jest bardzo miękkie i bagniste, a brzegi gęsto porośnięte trzciną, co wymaga użycia spodniobutów. Gęsta roślinność podwodna i nawodna tworzy labirynt, w którym królują karasie pospolite, liny i wzdręgi. W upalne lata i mroźne zimy występuje wysokie ryzyko przyduchy, co wymaga monitorowania warunków. Jest to idealne miejsce dla wędkarzy spławikowych, którzy cenią sobie dziki charakter łowiska i potrafią dostosować technikę do trudnych warunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21087, 2.1, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21088, 'Starorzecze (Gostomia #4)', 'starorzecze-gostomia-4-gostomia-21088', 'OXBOW', 51.6131326, 20.651635, 'Mazowieckie', 'Gostomia', 'To głębokie starorzecze z stałym połączeniem z rzeką jest magnesem dla drapieżników. Dno jest zróżnicowane, z twardszymi partiami żwiru i pojedynczymi zatopionymi korzeniami. Brzegi są łatwo dostępne, z licznymi miejscami do wędkowania z brzegu i z łodzi. Roślinność podwodna jest umiarkowana, tworząc idealne kryjówki dla sandaczy, szczupaków i okoni. Boleń często wpływa tu z rzeki, polując na drobną rybę. Dzięki stałej wymianie wody, ryzyko przyduchy jest minimalne, a łowisko jest atrakcyjne przez cały rok. To doskonałe miejsce dla wędkarzy spinningowych i gruntowych, szukających dużych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21088, 4.8, 2.8, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sandacz,Szczupak,Okoń,Boleń,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21089, 'Starorzecze (Gostomia #5)', 'starorzecze-gostomia-5-gostomia-21089', 'OXBOW', 51.6117184, 20.6494554, 'Mazowieckie', 'Gostomia', 'To płytkie i silnie zarośnięte starorzecze jest klasycznym przykładem akwenu, który w okresach suszy może całkowicie wyschnąć. Dno jest bardzo muliste, a brzegi gęsto porośnięte trzciną, co sprawia, że dostęp do wody jest bardzo trudny i wymaga użycia spodniobutów. Dominująca roślinność podwodna tworzy gęste zarośla, w których doskonale czują się karasie srebrzyste i wzdręgi. Ze względu na małą głębokość i brak połączenia z rzeką, ryzyko przyduchy jest bardzo wysokie. Jest to łowisko dla wędkarzy, którzy cenią sobie dzikie, nietknięte miejsca i potrafią dostosować się do trudnych warunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21089, 1.5, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21090, 'Starorzecze (Gostomia #6)', 'starorzecze-gostomia-6-gostomia-21090', 'OXBOW', 51.6096272, 20.6574766, 'Mazowieckie', 'Gostomia', 'To duże starorzecze oferuje zróżnicowane warunki wędkarskie, z licznymi zatopionymi drzewami stanowiącymi kryjówki dla dużych ryb. Dno jest muliste, z twardszymi partiami w głębszych miejscach. Brzegi są łatwo dostępne, co ułatwia wędkowanie z brzegu i z łodzi. Roślinność podwodna jest umiarkowana, skupiona głównie w płytszych zatokach. Łowisko łączy się z rzeką podczas wysokich stanów wody, co sprzyja migracji karpi i sumów. Wędkarze mogą liczyć na duże okazy szczupaków, leszczy i płoci. Jest to wszechstronne łowisko, odpowiednie dla różnych technik wędkarskich, choć obecność zaczepów wymaga uwagi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21090, 6.2, 2.3, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Sum,Szczupak,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21091, 'Starorzecze (Gostomia #7)', 'starorzecze-gostomia-7-gostomia-21091', 'OXBOW', 51.6102935, 20.6535378, 'Mazowieckie', 'Gostomia', 'To starorzecze jest przykładem akwenu o wysokim stopniu zamulenia i silnym zarośnięciu. Dno jest bardzo muliste i bagniste, a brzegi gęsto porośnięte trzciną i inną roślinnością, co sprawia, że dostęp do wody jest utrudniony. Gęsta roślinność podwodna tworzy doskonałe kryjówki dla linów, karasi pospolitych i wzdręg. W ciepłych miesiącach istnieje ryzyko przyduchy, co wymaga ostrożności. Jest to łowisko dla doświadczonych wędkarzy, którzy potrafią poruszać się w trudnym terenie i cenią sobie połów ryb spokojnego żeru w naturalnych warunkach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21091, 3, 1.7, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21092, 'Starorzecze (Gostomia #8)', 'starorzecze-gostomia-8-gostomia-21092', 'OXBOW', 51.61061, 20.6544927, 'Mazowieckie', 'Gostomia', 'To starorzecze, zlokalizowane w malowniczej okolicy, charakteryzuje się okresowym połączeniem z rzeką, co sprzyja różnorodności gatunków. Dno jest zróżnicowane, z twardszymi partiami piasku i żwiru oraz pojedynczymi korzeniami. Brzegi są łatwo dostępne, z licznymi dogodnymi miejscami do wędkowania. Roślinność podwodna jest umiarkowana, tworząc schronienie dla ryb, ale nie utrudniając znacząco wędkowania. Można tu liczyć na aktywne szczupaki i okonie, a także dorodne leszcze i płocie. Wiosna i wczesna jesień to najlepsze pory na wędkowanie, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21092, 4, 2.1, 4.2, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21093, 'Starorzecze (Gostomia #9)', 'starorzecze-gostomia-9-gostomia-21093', 'OXBOW', 51.6121356, 20.6573197, 'Mazowieckie', 'Gostomia', 'To płytkie i silnie zarośnięte starorzecze jest klasycznym przykładem akwenu, który w okresach suszy może całkowicie wyschnąć. Dno jest bardzo muliste, a brzegi gęsto porośnięte trzciną, co sprawia, że dostęp do wody jest bardzo trudny i wymaga użycia spodniobutów. Dominująca roślinność podwodna tworzy gęste zarośla, w których doskonale czują się karasie srebrzyste i wzdręgi. Ze względu na małą głębokość i brak połączenia z rzeką, ryzyko przyduchy jest bardzo wysokie. Jest to łowisko dla wędkarzy, którzy cenią sobie dzikie, nietknięte miejsca i potrafią dostosować się do trudnych warunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21093, 2.6, 1.3, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21094, 'Starorzecze (Gostomia #10)', 'starorzecze-gostomia-10-gostomia-21094', 'OXBOW', 51.6087407, 20.6380393, 'Mazowieckie', 'Gostomia', 'To rozległe starorzecze utrzymuje stałe połączenie z rzeką, co zapewnia doskonałe warunki dla drapieżników. Dno jest przeważnie czyste, z piaszczystymi i żwirowymi partiami oraz minimalnym zamuleniem. Brzegi są łatwo dostępne, oferując wiele dogodnych miejsc do wędkowania z brzegu i z łodzi. Roślinność podwodna jest słaba, co ułatwia spinningowanie i połów na żywca. Wędkarze mogą tu liczyć na liczne szczupaki, sandacze i okonie, a także na bolenie i jazie, które regularnie wpływają z rzeki. Dzięki stałemu przepływowi wody, ryzyko przyduchy jest praktycznie zerowe, co czyni to łowisko atrakcyjnym przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21094, 5.5, 2.4, 5.2, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Okoń,Boleń,Jaź', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21095, 'Starorzecze (Ulaski Gostomskie) - Północne', 'starorzecze-ulaski-gostomskie-polnocne-warka-21095', 'OXBOW', 51.6227193, 20.6743142, 'Mazowieckie', 'Warka', 'Długie i wąskie starorzecze Wisły, charakteryzujące się spokojną wodą i licznymi zatokami. Dno jest muliste z twardymi fragmentami żwiru w głębszych partiach, co sprzyja różnorodności gatunkowej ryb. Brzegi są w większości porośnięte gęstymi krzewami i drzewami, oferując schronienie dla ryb i utrudniając dostęp w niektórych miejscach. Roślinność podwodna jest umiarkowana, z przewagą rdestnic i moczarki kanadyjskiej. Jest to idealne miejsce dla wędkarzy poszukujących lina i karasia, choć szczupaki również często patrolują te wody. Wiosenne i jesienne miesiące to najlepszy czas na udane połowy, zwłaszcza wcześnie rano lub późnym wieczorem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21095, 3.2, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21096, 'Starorzecze (Ulaski Gostomskie) - Południowe', 'starorzecze-ulaski-gostomskie-poludniowe-warka-21096', 'OXBOW', 51.612201, 20.6672477, 'Mazowieckie', 'Warka', 'Mniejsze, bardziej odizolowane starorzecze, położone w bliskim sąsiedztwie głównego koryta rzeki. Charakteryzuje się płytkimi, silnie zarośniętymi partiami, które stanowią doskonałe tarliska dla wielu gatunków ryb. Dno jest głównie muliste, z grubą warstwą osadów organicznych, co sprzyja rozwojowi bogatej roślinności wodnej. Brzegi są bagniste i trudno dostępne, wymagające ostrożności i odpowiedniego sprzętu. Występuje tu obfita roślinność zanurzona i wynurzona, tworząca naturalne kryjówki. Jest to raj dla wędkarzy ceniących sobie spokój i poszukujących karasia, wzdręgi oraz okonia. Ryzyko przyduchy w upalne lata jest podwyższone ze względu na płytkość i obfitość materii organicznej, co wymaga uwagi. Najlepsze połowy można osiągnąć wczesnym latem, zanim roślinność osiągnie szczyt rozwoju.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21096, 1.5, 0.9, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Okoń,Lin', 'Bardzo trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21097, 'Starorzecze (Stobnica)', 'starorzecze-stobnica-przedborz-21097', 'OXBOW', 51.2542675, 19.8946512, 'Łódzkie', 'Przedbórz', 'Starorzecze rzeki Pilicy, o nieregularnym kształcie i zmiennej głębokości, otoczone malowniczymi lasami. Dno jest zróżnicowane, od piaszczystych płycizn po głębokie, muliste rynny, co sprzyja różnorodności gatunków ryb. Brzegi są częściowo dostępne, z fragmentami piaszczystych plaż, ale również z odcinkami gęsto porośniętymi olchami i wierzbami. Roślinność wodna jest umiarkowana, skupiająca się w zatokach i płytszych partiach, tworząc idealne schronienia. Akwen ten słynie z dużych leszczy i płoci, a także z obecności drapieżników takich jak szczupak i okoń. Wędkarze często łowią tu również karpie, które znajdują obfitość pokarmu. Najlepsze wyniki osiąga się w miejscach o zmiennym dnie, gdzie ryby żerują aktywnie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21097, 5.8, 2, 5.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Karp', 'Dobry z niektórych stron, miejscami utrudniony', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21098, 'Starorzecze (Rożnowice) - Zachodnie', 'starorzecze-roznowice-zachodnie-oborniki-21098', 'OXBOW', 52.6969393, 16.862183, 'Wielkopolskie', 'Oborniki', 'Jedno z kilku starorzeczy Warty w okolicy Rożnowic, charakteryzujące się wydłużonym kształtem. Dno jest przeważnie muliste, z licznymi zagłębieniami i nierównościami, które są atrakcyjne dla ryb. Brzegi są zróżnicowane, od łatwo dostępnych łąk po gęste zarośla trzcinowe, wymagające poszukiwania dogodnych stanowisk. Roślinność wodna jest obfita, szczególnie w płytszych partiach, tworząc idealne kryjówki dla drobnicy i drapieżników. Jest to znane łowisko leszczy i płoci, ale również sandacze i sumy pojawiają się tu regularnie, zwłaszcza w cieplejszych miesiącach. Wędkarze cenią sobie to miejsce za spokój i możliwość złowienia dużych okazów. Należy pamiętać o zmienności poziomu wody, która może wpływać na dostępność łowiska i aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21098, 4.1, 2.2, 6, 'Podczas wysokiej wody', 'Średnie', 'Silne', FALSE, FALSE, 'Leszcz,Płoć,Sandacz,Sum', 'Mocno zarośnięty trzciną, miejscami dostępny', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21099, 'Starorzecze (Rożnowice) - Środkowe', 'starorzecze-roznowice-srodkowe-oborniki-21099', 'OXBOW', 52.6996594, 16.8596629, 'Wielkopolskie', 'Oborniki', 'Położone blisko poprzedniego, to starorzecze jest nieco mniejsze i bardziej płytkie, co sprzyja szybszemu nagrzewaniu się wody. Dno jest przeważnie muliste, z dużą ilością zalegających liści i gałęzi, tworzących naturalne kryjówki. Brzegi są w większości porośnięte trzciną i inną roślinnością przybrzeżną, co utrudnia dostęp, ale jednocześnie zapewnia schronienie dla ryb. Roślinność wodna jest bardzo obfita, tworząc gęste dywany wodorostów w płytszych partiach. Jest to doskonałe miejsce dla wędkarzy poszukujących lina, karasia pospolitego oraz wzdręgi. Występują tu również liczne okonie, które polują wśród roślinności. Ze względu na płytkość, w upalne lata istnieje ryzyko przyduchy, dlatego warto monitorować warunki tlenowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21099, 2.8, 1.5, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21100, 'Starorzecze (Rożnowice) - Wschodnie', 'starorzecze-roznowice-wschodnie-oborniki-21100', 'OXBOW', 52.7049659, 16.861865, 'Wielkopolskie', 'Oborniki', 'Największe z kompleksu starorzeczy w Rożnowicach, charakteryzujące się dużą powierzchnią i zróżnicowaną głębokością. Dno jest mieszane, z partiami piaszczysto-żwirowymi oraz rozległymi obszarami mulistymi, co zapewnia różnorodne środowiska dla ryb. Brzegi są częściowo zagospodarowane, z kilkoma dogodnymi stanowiskami wędkarskimi, ale również z dzikimi, zarośniętymi odcinkami. Roślinność podwodna jest umiarkowana, z większym zagęszczeniem w płytszych zatokach. Występują tu liczne leszcze, płocie, a także drapieżniki takie jak szczupak i sandacz, które często patrolują głębsze rynny. Węgorze również są tu obecne, zwłaszcza w nocy. To starorzecze jest popularne wśród wędkarzy ze względu na potencjał dużych ryb i różnorodność gatunkową, oferując wiele możliwości połowu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21100, 7.5, 2.5, 7, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Sandacz,Węgorz', 'Dobry z niektórych stron, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21101, 'Starorzecze (Pustki)', 'starorzecze-pustki-nowe-miasto-lubawskie-21101', 'OXBOW', 53.4930677, 19.606988, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Malownicze starorzecze Drwęcy, otoczone lasami i łąkami, co nadaje mu dziki charakter. Dno jest zróżnicowane, z fragmentami piaszczystymi, żwirowymi oraz mulistymi, co tworzy idealne warunki dla wielu gatunków ryb. Brzegi są w większości łatwo dostępne, choć miejscami mogą być porośnięte krzewami, wymagającymi niewielkiego wysiłku w dotarciu do wody. Roślinność wodna jest umiarkowana, głównie w postaci rdestnic i grążeli, tworzących atrakcyjne miejsca dla ryb. Jest to doskonałe łowisko dla szczupaka i okonia, które znajdują tu obfitość pokarmu. Liny i karasie również licznie zamieszkują płytsze, zarośnięte partie. Wędkarze cenią sobie to miejsce za piękno krajobrazu i możliwość złowienia okazałych ryb, szczególnie wczesną wiosną.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21101, 3.8, 1.7, 4.2, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Lin,Karaś pospolity', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21102, 'Starorzecze (Biała Góra)', 'starorzecze-biala-gora-nowe-miasto-lubawskie-21102', 'OXBOW', 53.4970854, 19.6134446, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Kolejne starorzecze Drwęcy, nieco bardziej odsłonięte i węższe niż poprzednie, co sprzyja silniejszym prądom podczas wysokiej wody. Dno jest przeważnie piaszczysto-żwirowe, z nielicznymi zagłębieniami mulistymi, co preferują gatunki rzeczne. Brzegi są dość łatwo dostępne, z miejscami do rozłożenia sprzętu, choć gdzieniegdzie występują zarośla. Roślinność wodna jest skąpa, głównie ze względu na przepływ wody, ale w spokojniejszych zatoczkach można znaleźć niewielkie kępy. Jest to idealne miejsce dla bolenia, jazia i klenia, które często wpływają tu z głównego koryta rzeki. Szczupaki również polują wzdłuż brzegów. Wędkarze cenią sobie dynamikę tego łowiska i możliwość złowienia silnych ryb. Najlepsze wyniki osiąga się wczesnym latem, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21102, 2.1, 1.5, 3.8, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Boleń,Jaź,Kleń,Szczupak', 'Dobry, miejscami zarośnięty', FALSE, 'Czyste dno', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21103, 'Starorzecze (Nietków)', 'starorzecze-nietkow-sulechow-21103', 'OXBOW', 52.03147, 15.3431065, 'Lubuskie', 'Sulechów', 'Rozległe starorzecze Odry, charakteryzujące się otwartą przestrzenią i zróżnicowanym dnem. Dno jest mieszane, z przewagą piasku i żwiru w płytszych partiach oraz głębokimi rynnami z mulistym osadem, co zapewnia bogactwo środowisk. Brzegi są w większości łatwo dostępne, z wieloma dogodnymi miejscami do wędkowania, choć niektóre odcinki mogą być zadrzewione. Roślinność wodna jest umiarkowana, skupiając się w zatokach i osłoniętych miejscach, tworząc idealne kryjówki. Jest to doskonałe łowisko dla leszcza, płoci i okonia, a także dla drapieżników takich jak sandacz i sum, które często patrolują głębsze rewiry. Węgorze również są tu obecne, zwłaszcza w nocy. Wędkarze cenią sobie to starorzecze za jego potencjał i dużą powierzchnię.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21103, 10.5, 2.8, 8, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Sandacz,Sum,Okoń', 'Dobry z wielu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21104, 'Starorzecze (Opatkowice)', 'starorzecze-opatkowice-deblin-21104', 'OXBOW', 51.4685201, 21.872759, 'Lubelskie', 'Dęblin', 'Długie i wąskie starorzecze Wisły, charakteryzujące się spokojną wodą i licznymi zatokami. Dno jest muliste z twardymi fragmentami żwiru w głębszych partiach, co sprzyja różnorodności gatunkowej ryb. Brzegi są w większości porośnięte gęstymi krzewami i drzewami, oferując schronienie dla ryb i utrudniając dostęp w niektórych miejscach. Roślinność podwodna jest umiarkowana, z przewagą rdestnic i moczarki kanadyjskiej. Jest to idealne miejsce dla wędkarzy poszukujących lina i karasia, choć szczupaki również często patrolują te wody. Wiosenne i jesienne miesiące to najlepszy czas na udane połowy, zwłaszcza wcześnie rano lub późnym wieczorem. Warto szukać ryb w pobliżu zatopionych przeszkód, które stanowią doskonałe kryjówki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21104, 3.5, 1.9, 4.3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21105, 'Starorzecze (Modrzewie)', 'starorzecze-modrzewie-stepnica-21105', 'OXBOW', 53.565307, 14.7764501, 'Zachodniopomorskie', 'Stepnica', 'Płytkie i rozległe starorzecze Dziwny, charakteryzujące się dużą ilością zarośli i bogatą roślinnością wodną. Dno jest w większości muliste, z grubą warstwą osadów organicznych, co sprzyja rozwojowi makrofitów. Brzegi są trudno dostępne, bagniste i silnie porośnięte trzciną, co wymaga użycia brodów. Roślinność podwodna jest bardzo silna, tworząc gęste dywany, które są idealnym schronieniem dla wielu gatunków ryb. Jest to raj dla lina, karasia pospolitego i wzdręgi, które znajdują tu obfitość pokarmu i kryjówek. Występują tu również liczne szczupaki i okonie, polujące wśród roślinności. Ze względu na płytkość i obfitość materii organicznej, w upalne lata istnieje wysokie ryzyko przyduchy, co jest kluczowym czynnikiem dla wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21105, 6, 1, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak,Okoń', 'Bardzo trudny, bagnisty i mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21106, 'Starorzecze (Kobylnica)', 'starorzecze-kobylnica-slupsk-21106', 'OXBOW', 54.4370569, 17.0208918, 'Pomorskie', 'Słupsk', 'Niewielkie, ale głębokie starorzecze rzeki Słupi, otoczone lasami, co zapewnia malownicze widoki i spokój. Dno jest zróżnicowane, z głębokimi mulistymi rynnami i twardszymi, piaszczystymi płyciznami, co sprzyja różnorodności gatunkowej. Brzegi są częściowo dostępne, z kilkoma dogodnymi miejscami do wędkowania, ale również z odcinkami zarośniętymi drzewami i krzewami. Roślinność wodna jest umiarkowana, skupiająca się w osłoniętych zatokach. Jest to znane łowisko dla szczupaka i okonia, które znajdują tu doskonałe warunki do polowania. Liny i karasie również licznie zamieszkują płytsze partie. Węgorze są tu obecne, zwłaszcza w nocy, poszukując pokarmu na dnie. Wędkarze cenią sobie to miejsce za spokój i możliwość złowienia dużych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21106, 2, 2.5, 6.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Lin,Węgorz', 'Dobry z niektórych stron, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21107, 'Starorzecze (Zakalew) - Wschodnie', 'starorzecze-zakalew-wschodnie-leczna-21107', 'OXBOW', 51.5902411, 22.3498016, 'Lubelskie', 'Łęczna', 'Długie i malownicze starorzecze Wieprza, charakteryzujące się spokojną wodą i licznymi zatokami. Dno jest muliste z twardymi fragmentami żwiru w głębszych partiach, co sprzyja różnorodności gatunkowej ryb. Brzegi są w większości porośnięte gęstymi krzewami i drzewami, oferując schronienie dla ryb i utrudniając dostęp w niektórych miejscach. Roślinność podwodna jest umiarkowana, z przewagą rdestnic i moczarki kanadyjskiej. Jest to idealne miejsce dla wędkarzy poszukujących lina i karasia, choć szczupaki również często patrolują te wody. Wiosenne i jesienne miesiące to najlepszy czas na udane połowy, zwłaszcza wcześnie rano lub późnym wieczorem. Warto szukać ryb w pobliżu zatopionych przeszkód, które stanowią doskonałe kryjówki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21107, 4, 1.8, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21108, 'Starorzecze (Zakalew) - Środkowe', 'starorzecze-zakalew-srodkowe-leczna-21108', 'OXBOW', 51.5909209, 22.3447698, 'Lubelskie', 'Łęczna', 'Mniejsze, bardziej odizolowane starorzecze, położone w bliskim sąsiedztwie głównego koryta rzeki. Charakteryzuje się płytkimi, silnie zarośniętymi partiami, które stanowią doskonałe tarliska dla wielu gatunków ryb. Dno jest głównie muliste, z grubą warstwą osadów organicznych, co sprzyja rozwojowi bogatej roślinności wodnej. Brzegi są bagniste i trudno dostępne, wymagające ostrożności i odpowiedniego sprzętu. Występuje tu obfita roślinność zanurzona i wynurzona, tworząca naturalne kryjówki. Jest to raj dla wędkarzy ceniących sobie spokój i poszukujących karasia, wzdręgi oraz okonia. Ryzyko przyduchy w upalne lata jest podwyższone ze względu na płytkość i obfitość materii organicznej. Najlepsze połowy można osiągnąć wczesnym latem, zanim roślinność osiągnie szczyt rozwoju.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21108, 1.8, 1, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Okoń,Lin', 'Bardzo trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21109, 'Starorzecze (Zakalew) - Zachodnie', 'starorzecze-zakalew-zachodnie-leczna-21109', 'OXBOW', 51.5925523, 22.344578, 'Lubelskie', 'Łęczna', 'Średniej wielkości starorzecze, charakteryzujące się umiarkowaną głębokością i zróżnicowanym dnem. Dno jest mieszane, z partiami piaszczysto-mulistymi i licznymi zagłębieniami, które są atrakcyjne dla ryb. Brzegi są częściowo dostępne, z fragmentami łąk i miejscami porośniętymi krzewami, co zapewnia różnorodność stanowisk. Roślinność wodna jest umiarkowana, skupiając się w zatokach i płytszych partiach, tworząc idealne schronienia. Akwen ten słynie z dużych leszczy i płoci, a także z obecności drapieżników takich jak szczupak i okoń. Wędkarze często łowią tu również karpie, które znajdują obfitość pokarmu. Najlepsze wyniki osiąga się w miejscach o zmiennym dnie, gdzie ryby żerują aktywnie. Warto eksplorować różne głębokości, aby znaleźć żerujące stada.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21109, 2.9, 1.6, 3.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Karp', 'Dobry z niektórych stron, miejscami utrudniony', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21110, 'Starorzecze Szuminka', 'starorzecze-szuminka-wlodawa-21110', 'OXBOW', 51.5931418, 23.5458932, 'Lubelskie', 'Włodawa', 'To starorzecze, położone w malowniczej okolicy Szuminki, stanowi typowy przykład meandru rzeki Bug, który został odcięty od głównego nurtu. Charakteryzuje się ono stosunkowo płytkim, ale urozmaiconym dnem, z licznymi zagłębieniami i mulistymi osadami. Brzegi są częściowo zalesione, co zapewnia cień i tworzy naturalne kryjówki dla ryb, a częściowo pokryte gęstą roślinnością szuwarową. Wędkarze mogą spodziewać się tu obfitości leszczy, płoci, a także drapieżników takich jak szczupak i okoń. Ze względu na umiarkowane zamulenie i rozwój roślinności podwodnej, łowienie może wymagać precyzji, szczególnie w cieplejszych miesiącach. Dostęp do wody jest dobry z kilku miejsc, ale warto przygotować się na przedzieranie przez zarośla.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21110, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Karaś pospolity', 'Dobry z jednej strony, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21111, 'Starorzecze Gołąb', 'starorzecze-golab-golab-21111', 'OXBOW', 51.4876351, 21.8737603, 'Lubelskie', 'Gołąb', 'Starorzecze w Gołębiu to rozległy akwen, będący pozostałością po dawnym korycie Wisły, charakteryzujący się znaczną głębokością w niektórych partiach. Jego dno jest zróżnicowane, od twardych, piaszczystych fragmentów po głębokie, muliste rynny, co sprzyja różnorodności gatunkowej ryb. Brzegi są łatwo dostępne na większości odcinków, choć miejscami porastają je kępy trzcin i pojedyncze drzewa, stanowiące doskonałe kryjówki dla drapieżników. W starorzeczu tym z powodzeniem można łowić duże leszcze, płocie, a także okazałe szczupaki, sandacze i sumy. Połączenie z Wisłą podczas wysokich stanów wody zapewnia stałe zarybianie i wymianę populacji ryb. Wędkarstwo tutaj jest satysfakcjonujące przez cały rok, oferując szanse na rekordowe okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21111, 12, 2.5, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Sandacz,Sum', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21112, 'Starorzecze Trzykolne Młyny 1', 'starorzecze-trzykolne-mlyny-1-czmoniec-21112', 'OXBOW', 52.1923753, 16.9976806, 'Wielkopolskie', 'Czmoniec', 'To niewielkie starorzecze w kompleksie Trzykolnych Młynów jest płytkim, silnie zamulonym zbiornikiem, idealnym dla miłośników spokojnego wędkowania. Dno jest w większości muliste, pokryte gęstą roślinnością podwodną, co sprawia, że jest to doskonałe siedlisko dla ryb karpiowatych. Brzegi są trudne do pokonania, często bagniste i mocno zarośnięte trzciną, co wymaga użycia wodery. Głównymi gatunkami ryb są lin, karaś pospolity oraz wzdręga, które świetnie czują się w takich warunkach. Niska głębokość i silne zarastanie mogą prowadzić do niedoborów tlenu latem, dlatego najlepsze efekty osiąga się wiosną i wczesną jesienią. Łowienie tutaj to wyzwanie, ale nagrodą są piękne okazy ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21112, 1.5, 1, 2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21113, 'Starorzecze Trzykolne Młyny 2', 'starorzecze-trzykolne-mlyny-2-czmoniec-21113', 'OXBOW', 52.1935457, 16.9970335, 'Wielkopolskie', 'Czmoniec', 'Drugie starorzecze w Trzykolnych Młynach charakteryzuje się nieco większą powierzchnią i bardziej zróżnicowaną głębokością niż jego sąsiad. Dno jest średnio zamulone, z twardszymi fragmentami w głębszych rynnach, co sprzyja bytności zarówno drapieżników, jak i ryb spokojnego żeru. Brzegi są mocno zarośnięte trzciną, co utrudnia dostęp, ale jednocześnie tworzy doskonałe schronienia dla ryb. Wędkarze mogą liczyć na szczupaki, okonie oraz liny i płocie. Brak stałego połączenia z rzeką sprawia, że ekosystem jest bardziej stabilny, choć w upalne lata istnieje ryzyko deficytu tlenu. Wymagane są wodery, aby dotrzeć do najlepszych miejscówek, które obfitują w zaczepy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21113, 2, 1.2, 2.5, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Lin,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21114, 'Starorzecze Trzykolne Młyny 3', 'starorzecze-trzykolne-mlyny-3-czmoniec-21114', 'OXBOW', 52.1923181, 16.9980407, 'Wielkopolskie', 'Czmoniec', 'To starorzecze wyróżnia się spośród okolicznych akwenów nieco większym rozmiarem i dobrym dostępem do brzegów, co czyni je popularnym miejscem wśród wędkarzy. Dno jest stosunkowo czyste, z niewielkim zamuleniem, co sprzyja rozwojowi zdrowego ekosystemu. Roślinność podwodna jest umiarkowana, tworząc idealne warunki dla różnorodnych gatunków ryb. W starorzeczu można złowić okazałe leszcze, płocie, a także karpie i szczupaki, które znajdują tu obfitość pokarmu. Połączenie z rzeką podczas wysokich stanów wody odświeża wodę i zasila populacje ryb. Jest to łowisko odpowiednie dla wędkarzy ceniących komfortowy dostęp i różnorodność wędkarskich wyzwań. Czyste dno minimalizuje ryzyko utraty sprzętu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21114, 2.5, 1.5, 3, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak', 'Dobry z jednej strony', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21115, 'Starorzecze Czmoniec 1', 'starorzecze-czmoniec-1-czmoniec-21115', 'OXBOW', 52.1897084, 16.9987977, 'Wielkopolskie', 'Czmoniec', 'Starorzecze Czmoniec 1 to długi, wąski zbiornik, charakteryzujący się gęstą roślinnością wodną i brzegową, co stanowi wyzwanie dla wędkarzy, ale i bogactwo dla ryb. Dno jest średnio zamulone, z licznymi zatopionymi gałęziami i korzeniami, które są naturalnymi kryjówkami. Brzegi są mocno zarośnięte trzciną, co wymaga użycia woderów i cierpliwości w poszukiwaniu dogodnych stanowisk. Wędkarze mogą liczyć na liny, karasie pospolite, szczupaki i wzdręgi. Brak stałego połączenia z rzeką sprawia, że woda jest spokojna, ale latem może występować ryzyko niedotlenienia. Jest to idealne miejsce dla tych, którzy szukają dzikiego charakteru łowiska i cenią sobie walkę z rybą w trudnych warunkach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21115, 3, 1.5, 3.2, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21116, 'Starorzecze Czmoniec 2', 'starorzecze-czmoniec-2-czmoniec-21116', 'OXBOW', 52.1885021, 16.9997841, 'Wielkopolskie', 'Czmoniec', 'To starorzecze w Czmońcu wyróżnia się położeniem w pobliżu lasu, co wpływa na jego malowniczy charakter i czystość wody. Dno jest mało zamulone, z licznymi spadkami i zagłębieniami, które stanowią atrakcyjne miejsca dla ryb. Brzegi są częściowo dostępne, choć miejscami występują zarośla, które mogą wymagać przygotowania stanowiska. Wędkarze mogą liczyć na szczupaki, okonie, leszcze i płocie, które chętnie żerują w tym akwenie. Połączenie z rzeką podczas wysokiej wody zapewnia regularne odświeżanie wody i dopływ nowych ryb. Jest to łowisko o umiarkowanym poziomie trudności, oferujące dobre warunki do wędkowania przez większość sezonu. Niewielka ilość zaczepów ułatwia wędkowanie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21116, 2.8, 1.7, 3.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z jednej strony, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21117, 'Starorzecze Czmoniec 3', 'starorzecze-czmoniec-3-czmoniec-21117', 'OXBOW', 52.1843749, 17.0027396, 'Wielkopolskie', 'Czmoniec', 'To jedno z głębszych starorzeczy w okolicy Czmońca, oferujące duży potencjał dla wędkarzy poszukujących dużych drapieżników. Dno jest zróżnicowane, z głębokimi rynnami i zatopionymi drzewami, które stanowią idealne kryjówki dla sumów, sandaczy i dużych szczupaków. Brzegi są w większości łatwo dostępne, co ułatwia dotarcie do najlepszych miejscówek. Roślinność podwodna jest umiarkowana, ale liczne zaczepy wymagają ostrożności i odpowiedniego sprzętu. Stałe połączenie z rzeką zapewnia doskonałe warunki tlenowe i regularne zarybianie, co gwarantuje bogactwo ryb. Jest to łowisko dla doświadczonych wędkarzy, którzy cenią sobie wyzwanie i możliwość złowienia naprawdę dużego okazu. Tutaj można spędzić cały sezon z wędką.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21117, 3.5, 2, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Sandacz,Szczupak,Leszcz,Karp', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21118, 'Starorzecze Czmoniec 4', 'starorzecze-czmoniec-4-czmoniec-21118', 'OXBOW', 52.1816628, 16.9951535, 'Wielkopolskie', 'Czmoniec', 'To małe starorzecze w Czmońcu jest przykładem płytkiego zbiornika z bogatą roślinnością zanurzoną, co czyni je idealnym środowiskiem dla ryb karpiowatych. Dno jest silnie zamulone, a gęsta roślinność podwodna tworzy liczne kryjówki i utrudnia wędkowanie. Brzegi są trudne do pokonania, często bagniste i zarośnięte, co wymaga użycia woderów. Wędkarze mogą liczyć na karasie pospolite, liny, wzdręgi i płocie. Ze względu na niewielką głębokość i silne zarastanie, starorzecze to jest podatne na wysychanie w upalne lata i ryzyko deficytu tlenu. Najlepszy okres na wędkowanie to późna wiosna i lato, kiedy ryby są najbardziej aktywne. Jest to łowisko dla cierpliwych i wytrwałych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21118, 1, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21119, 'Starorzecze Czmoniec 5', 'starorzecze-czmoniec-5-czmoniec-21119', 'OXBOW', 52.1814512, 16.9937012, 'Wielkopolskie', 'Czmoniec', 'To starorzecze, choć płytkie, oferuje liczne kryjówki dla ryb dzięki gęstej roślinności podwodnej i pojedynczym zatopionym gałęziom. Dno jest silnie zamulone, co sprzyja rozwojowi bogatej fauny dennej, będącej pokarmem dla ryb. Brzegi są mocno zarośnięte trzciną, co wymaga od wędkarzy sprytu i cierpliwości w poszukiwaniu dogodnych miejscówek. Dominującymi gatunkami są lin, karaś pospolity, wzdręga i okoń, które świetnie adaptują się do tych warunków. Połączenie z rzeką podczas wysokiej wody jest nieregularne, co oznacza, że ekosystem jest dość zamknięty. Ze względu na płytkość, istnieje ryzyko wysychania w okresach suszy i niedoborów tlenu. Najlepsze efekty osiąga się w późnej wiośnie i latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21119, 0.8, 0.9, 1.8, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21120, 'Starorzecze Czmoniec 6', 'starorzecze-czmoniec-6-czmoniec-21120', 'OXBOW', 52.1816483, 16.9942039, 'Wielkopolskie', 'Czmoniec', 'Starorzecze Czmoniec 6 to akwen średniej wielkości, charakteryzujący się mulistym dnem i umiarkowanym poziomem zarastania. Jest to typowe starorzecze, które oferuje stabilne warunki dla wielu gatunków ryb spokojnego żeru. Brzegi są częściowo dostępne, choć miejscami występują zarośla i pojedyncze korzenie. Wędkarze mogą liczyć na obfitość płoci, leszczy, linów i karasi pospolitych. Brak stałego połączenia z rzeką oznacza, że zbiornik jest bardziej wrażliwy na zmiany pogodowe, co może prowadzić do niedoborów tlenu w upalne lata. Najlepsze wyniki osiąga się wiosną i wczesną jesienią, kiedy ryby są najbardziej aktywne. To łowisko dla tych, którzy cenią sobie klasyczne wędkowanie na spławik lub grunt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21120, 1.2, 1.1, 2.2, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Lin,Karaś pospolity', 'Dobry z jednej strony', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21121, 'Starorzecze Czmoniec 7', 'starorzecze-czmoniec-7-czmoniec-21121', 'OXBOW', 52.1823763, 16.9945146, 'Wielkopolskie', 'Czmoniec', 'To starorzecze jest wyjątkowe ze względu na swoje położenie blisko głównego nurtu rzeki, co sprzyja regularnej wymianie wody i utrzymaniu dobrych warunków tlenowych. Dno jest mało zamulone i stosunkowo czyste, z niewielką ilością roślinności podwodnej, co ułatwia wędkowanie. Brzegi są łatwo dostępne z obu stron, oferując komfortowe stanowiska dla wędkarzy. W zbiorniku dominują szczupaki, okonie, leszcze i płocie, które korzystają z bogactwa pokarmu dostarczanego przez rzekę. Jest to idealne miejsce dla wędkarzy ceniących sobie dynamikę łowiska i możliwość złowienia różnorodnych gatunków. Można tu wędkować przez cały sezon, ciesząc się stabilnymi warunkami i dobrą kondycją ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21121, 1.8, 1.4, 2.8, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21122, 'Starorzecze Czmoniec 8', 'starorzecze-czmoniec-8-czmoniec-21122', 'OXBOW', 52.1828881, 16.9939306, 'Wielkopolskie', 'Czmoniec', 'Starorzecze Czmoniec 8 charakteryzuje się zróżnicowanym dnem i brzegami, co tworzy mozaikę siedlisk dla wielu gatunków ryb. Dno jest średnio zamulone, z miejscowymi zagłębieniami i pojedynczymi korzeniami, które są atrakcyjnymi miejscami dla ryb. Brzegi są mocno zarośnięte trzciną, co utrudnia dostęp, ale jednocześnie zapewnia spokój i naturalne kryjówki. Wędkarze mogą liczyć na liny, karasie pospolite, szczupaki i płocie. Brak stałego połączenia z rzeką sprawia, że zbiornik jest bardziej stabilny, ale w upalne lata może występować ryzyko niedoborów tlenu. Wymagane są wodery, aby dotrzeć do najlepszych miejscówek, które obfitują w zaczepy. Najlepsze wyniki osiąga się wiosną i wczesną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21122, 1.5, 1.3, 2.5, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21123, 'Starorzecze Żarki', 'starorzecze-zarki-zarki-21123', 'OXBOW', 50.0542954, 19.3603331, 'Małopolskie', 'Żarki', 'Starorzecze w Żarkach to rozległy akwen, będący typową pozostałością po dawnym korycie Wisły, oferujący zróżnicowane warunki do wędkowania. Dno jest średnio zamulone, z licznymi zatopionymi drzewami i nierównościami, które tworzą idealne kryjówki dla ryb. Brzegi są w większości łatwo dostępne, choć miejscami porastają je kępy trzcin i pojedyncze drzewa. W zbiorniku z powodzeniem można łowić duże leszcze, karpie, płocie, a także okazałe szczupaki i sandacze. Połączenie z Wisłą podczas wysokich stanów wody zapewnia stałe zarybianie i wymianę populacji ryb, co gwarantuje wysoką jakość łowiska. Wędkarstwo tutaj jest satysfakcjonujące przez cały rok, oferując szanse na rekordowe okazy w otoczeniu dzikiej przyrody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21123, 7, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Płoć,Szczupak,Sandacz', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21124, 'Starorzecze Mętków', 'starorzecze-metkow-metkow-21124', 'OXBOW', 50.0627468, 19.3672207, 'Małopolskie', 'Mętków', 'Starorzecze w Mętkowie to nieco mniejszy, ale za to głęboki akwen, charakteryzujący się bogatym i urozmaiconym dnem. Liczne zagłębienia, podwodne górki i pojedyncze korzenie tworzą doskonałe siedliska dla wielu gatunków ryb, w tym dużych drapieżników. Brzegi są dobrze dostępne z jednej strony, co ułatwia dotarcie do najlepszych miejscówek, podczas gdy druga strona jest bardziej zarośnięta, zapewniając spokój. W starorzeczu tym można liczyć na okazałe sumy, węgorze, sandacze, szczupaki oraz leszcze. Stałe połączenie z rzeką zapewnia doskonałe warunki tlenowe i regularne zarybianie, co gwarantuje wysoką jakość łowiska. Jest to idealne miejsce dla wędkarzy poszukujących wyzwań i szansy na złowienie naprawdę dużego okazu, szczególnie wiosną i wczesną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21124, 5.5, 2.2, 6, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Węgorz,Sandacz,Szczupak,Leszcz', 'Dobry z jednej strony', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21125, 'Starorzecze (Ostrów, Wiślica)', 'starorzecze-ostrow-wislica-wislica-21125', 'OXBOW', 50.3258243, 20.6903577, 'Świętokrzyskie', 'Wiślica', 'To starorzecze, zlokalizowane w malowniczej dolinie Nidy, charakteryzuje się typowo mulistym dnem, miejscami pokrytym grubą warstwą detrytusu. Brzegi są przeważnie łagodne, ale silnie zarośnięte trzciną i inną roślinnością szuwarową, co utrudnia dostęp do wody. W akwenie dominuje roślinność podwodna, w tym grążele i rdestnice, tworzące liczne kryjówki dla ryb. Jest to idealne środowisko dla gatunków karpiowatych i drapieżników czatujących w zaroślach. Wiosenne i jesienne wylewy Nidy często odświeżają wodę i zasilają starorzecze w nowe osobniki, co korzystnie wpływa na populację ryb. Wędkarstwo wymaga cierpliwości i często użycia sprzętu do brodzenia, aby dotrzeć do najlepszych miejscówek.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21125, 3.2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21126, 'Starorzecze (Wiślica, Nida)', 'starorzecze-wislica-nida-wislica-21126', 'OXBOW', 50.3316025, 20.690207, 'Świętokrzyskie', 'Wiślica', 'Starorzecze to jest położone w bezpośrednim sąsiedztwie Wiślicy, stanowiąc popularne miejsce dla lokalnych wędkarzy. Charakteryzuje się zróżnicowanym dnem, gdzie muliste fragmenty przeplatają się z twardszymi, gliniasto-piaszczystymi. Brzegi są częściowo dostępne, choć miejscami występują gęste kępy trzcin i krzewów, które zapewniają schronienie dzikiej zwierzynie. Roślinność podwodna jest umiarkowana, co ułatwia prowadzenie przynęt, ale jednocześnie oferuje rybom odpowiednie kryjówki. W starorzeczu można liczyć na obfite połowy płoci i leszczy, a także na spotkanie z większymi drapieżnikami. Akwen jest stosunkowo stabilny pod względem poziomu wody, rzadko wysycha, co sprzyja rozwojowi populacji ryb. Wędkowanie jest tu przyjemne, zwłaszcza z pomostów lub z łodzi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21126, 4.8, 1.8, 3.5, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21127, 'Starorzecze (Ostrów, Nida)', 'starorzecze-ostrow-nida-wislica-21127', 'OXBOW', 50.3228945, 20.6979614, 'Świętokrzyskie', 'Wiślica', 'To starorzecze położone niedaleko Ostrowa, jest typowym, płytkim zbiornikiem ze znacznym zamuleniem. Dno jest w większości miękkie i muliste, co sprzyja rozwojowi bujnej roślinności podwodnej, takiej jak moczarka kanadyjska i wywłócznik. Brzegi są niskie i podmokłe, często porośnięte gęstymi szuwarami, co sprawia, że dostęp do wody jest utrudniony. Wysokie temperatury latem mogą prowadzić do niedoborów tlenu, szczególnie w głębszych partiach, dlatego ryby często gromadzą się w płytszych, lepiej natlenionych strefach. Wędkowanie w tym miejscu wymaga cierpliwości i umiejętności łowienia w zarośniętych miejscach, a najlepsze efekty przynosi często z użyciem spławika. Pomimo trudności, starorzecze obfituje w cenne gatunki ryb, które doskonale czują się w tym środowisku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21127, 2.5, 1.2, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21128, 'Starorzecze (Szczytniki, Nida)', 'starorzecze-szczytniki-nida-wislica-21128', 'OXBOW', 50.3215974, 20.6991053, 'Świętokrzyskie', 'Wiślica', 'Starorzecze w okolicy Szczytników to malowniczy, choć wymagający akwen. Dno jest głównie muliste, z licznymi zatopionymi gałęziami i korzeniami, co stanowi wyzwanie dla wędkarzy, ale jednocześnie doskonałe schronienie dla ryb. Brzegi są zróżnicowane – od łatwo dostępnych fragmentów, po te gęsto porośnięte olchami i wierzbami, tworzącymi naturalne tunele nad wodą. Roślinność podwodna jest umiarkowana, ale w miejscach płytszych tworzy gęste zarośla. W starorzeczu dominują drapieżniki, takie jak szczupak i okoń, które aktywnie polują wśród podwodnych struktur. Wędkarstwo gruntowe i spławikowe może przynieść dobre rezultaty, zwłaszcza w poszukiwaniu lina i karasia. Akwen ten jest znany z różnorodności gatunkowej i stanowi atrakcyjne miejsce dla doświadczonych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21128, 3.9, 1.7, 3.8, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Lin,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21129, 'Starorzecze (Szczytniki Dolne)', 'starorzecze-szczytniki-dolne-wislica-21129', 'OXBOW', 50.3185486, 20.7034308, 'Świętokrzyskie', 'Wiślica', 'To starorzecze, położone nieco niżej w biegu Nidy, charakteryzuje się bardziej odciętym charakterem od głównego nurtu rzeki. Dno jest głęboko zamulone, co sprzyja bujnemu rozwojowi roślinności wodnej, takiej jak rzęsa wodna i grążele. Brzegi są w większości strome i trudno dostępne, porośnięte gęstymi krzewami i drzewami, które tworzą naturalne zadaszenie nad wodą. Woda w starorzeczu jest często mętna, a w upalne lata może dochodzić do znacznych spadków poziomu tlenu, co stanowi wyzwanie dla ryb. Wędkowanie w tym miejscu jest trudne, ale może przynieść nagrody w postaci dużych linów i karasi pospolitych, które doskonale radzą sobie w takich warunkach. Należy przygotować się na łowienie w trudnych, zarośniętych miejscach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21129, 1.8, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21130, 'Starorzecze (Czarkowy)', 'starorzecze-czarkowy-wislica-21130', 'OXBOW', 50.3071968, 20.715221, 'Świętokrzyskie', 'Wiślica', 'Starorzecze w Czarkowych to rozległy akwen o stosunkowo płytkim charakterze, ale z wyraźnymi głęboczkami. Dno jest mieszane – od twardego, piaszczystego w płytszych partiach, po miękkie i muliste w głębszych dołach. Brzegi są przeważnie łatwo dostępne, z nielicznymi zaroślami, co sprzyja wędkarstwu z brzegu. Roślinność podwodna jest umiarkowana, skupiona głównie wzdłuż brzegów i na płyciznach, tworząc idealne miejsca do żerowania dla ryb. W starorzeczu można spotkać wiele gatunków, od płoci i leszczy, po większe okazy szczupaków i sumów, które sporadycznie wpływają z Nidy. Wędkowanie jest tu komfortowe, a różnorodność miejscówek pozwala na stosowanie różnych technik. Jest to popularne miejsce dla rodzinnych wypadów wędkarskich.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21130, 7.5, 2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Sum,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21131, 'Starorzecze (Będów, Odra)', 'starorzecze-bedow-odra-cigacice-21131', 'OXBOW', 52.0601585, 15.2859552, 'Lubuskie', 'Cigacice', 'To starorzecze, położone w rozległej dolinie Odry w pobliżu Będowa, charakteryzuje się dynamicznym charakterem, często zasilanym wodami powodziowymi rzeki. Dno jest zróżnicowane, z przewagą piasku i żwiru, choć w zatokach gromadzi się muł. Brzegi są częściowo strome, a częściowo łagodne, porośnięte wierzbami i topolami, które tworzą cień i kryjówki dla ryb. Roślinność podwodna jest umiarkowana, z przewagą rdestnic i rogatka. Starorzecze jest znane z obfitości leszczy, płoci i okoni, a także sporadycznych połowów sandaczy i sumów, które wpływają z Odry. Wędkowanie jest tu bardzo atrakcyjne, zwłaszcza wczesną wiosną i jesienią, kiedy ryby aktywnie żerują. Dostęp do wody jest dobry, co sprzyja zarówno wędkarstwu z brzegu, jak i z łodzi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21131, 9, 2.2, 5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Sandacz,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21132, 'Starorzecze (Będów, Zatoka Zachodnia)', 'starorzecze-bedow-zatoka-zachodnia-cigacice-21132', 'OXBOW', 52.0604417, 15.2820025, 'Lubuskie', 'Cigacice', 'To starorzecze stanowi zachodnią zatokę większego kompleksu starorzeczy Odry. Charakteryzuje się bardziej mulistym dnem niż główny nurt, co sprzyja rozwojowi bujnej roślinności wodnej, takiej jak grążele i lilie wodne. Brzegi są niskie i podmokłe, często porośnięte gęstymi trzcinami, co utrudnia dostęp do wody. W akwenie dominują gatunki typowe dla wód stojących, takie jak lin, karaś pospolity i wzdręga, które znajdują tu doskonałe warunki do życia i rozrodu. Wędkowanie w tym miejscu wymaga precyzji i często użycia długich wędek spławikowych lub metody gruntowej. W upalne lata istnieje ryzyko spadków tlenu, dlatego warto obserwować zachowanie ryb. Jest to spokojne miejsce, idealne dla wędkarzy ceniących ciszę i obcowanie z naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21132, 4.1, 1.6, 3.2, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21133, 'Starorzecze (Będów, Północne)', 'starorzecze-bedow-polnocne-cigacice-21133', 'OXBOW', 52.0605602, 15.279741, 'Lubuskie', 'Cigacice', 'Północna część kompleksu starorzeczy w Będowie to akwen o umiarkowanej głębokości i zróżnicowanym dnie, gdzie piaszczyste płycizny przeplatają się z mulistymi zagłębieniami. Brzegi są w większości dostępne, choć miejscami występują kępy trzcin i pojedyncze drzewa, które zapewniają cień. Roślinność podwodna jest umiarkowana, co sprzyja różnorodności gatunkowej ryb. W starorzeczu można liczyć na obfite połowy płoci, leszczy i okoni, a także na spotkanie z większymi drapieżnikami, takimi jak szczupak. Połączenie z Odrą podczas wysokiej wody odświeża wodę i zasila akwen w nowe osobniki. Jest to doskonałe miejsce do wędkowania spinningowego i spławikowego, oferujące wiele potencjalnych miejscówek. Wędkarze cenią je za łatwy dostęp i różnorodność rybostanu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21133, 5.5, 1.9, 3.9, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak,Karaś srebrzysty', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21134, 'Starorzecze (Będów, Wschodnie)', 'starorzecze-bedow-wschodnie-cigacice-21134', 'OXBOW', 52.0608685, 15.2784893, 'Lubuskie', 'Cigacice', 'Wschodnie starorzecze w Będowie to akwen o stosunkowo niewielkiej powierzchni, ale znacznym zróżnicowaniu głębokości. Dno jest w przeważającej części muliste, z licznymi zatopionymi gałęziami i korzeniami, co stanowi doskonałe schronienie dla ryb. Brzegi są niskie i podmokłe, gęsto porośnięte trzciną i krzewami, co sprawia, że dostęp do wody jest utrudniony i często wymaga brodzenia. Roślinność podwodna jest bardzo bujna, tworząc gęste dywany grążeli i moczarki. W starorzeczu dominują liny i karasie, które doskonale radzą sobie w takim środowisku, a także szczupaki, polujące w zaroślach. Wędkowanie jest tu wyzwaniem, ale może przynieść satysfakcjonujące połowy dużych okazów. Należy być przygotowanym na trudne warunki i cierpliwość.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21134, 2.8, 1.3, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21135, 'Starorzecze (Będów, Centralne)', 'starorzecze-bedow-centralne-cigacice-21135', 'OXBOW', 52.062981, 15.2772587, 'Lubuskie', 'Cigacice', 'Centralne starorzecze w Będowie to jeden z większych akwenów w kompleksie, charakteryzujący się stabilnym poziomem wody i umiarkowanym zamuleniem. Dno jest zróżnicowane, z fragmentami piaszczystymi, gliniastymi i mulistymi, co sprzyja różnorodności gatunkowej. Brzegi są częściowo zagospodarowane, z kilkoma dogodnymi miejscami do wędkowania, ale również z obszarami gęsto porośniętymi roślinnością. Roślinność podwodna jest umiarkowana, zapewniając rybom schronienie bez nadmiernego utrudniania wędkarstwa. W starorzeczu można spotkać zarówno gatunki spokojnego żeru, takie jak leszcz i płoć, jak i drapieżniki – szczupaka i okonia. Wędkowanie jest tu przyjemne, a akwen oferuje dobre warunki zarówno dla początkujących, jak i doświadczonych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21135, 6.7, 2.1, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21136, 'Starorzecze (Będów, Kładka)', 'starorzecze-bedow-kladka-cigacice-21136', 'OXBOW', 52.0601578, 15.2839956, 'Lubuskie', 'Cigacice', 'To starorzecze w Będowie, położone w pobliżu starej kładki, jest stosunkowo płytkie i charakteryzuje się znacznym zamuleniem. Dno jest miękkie, muliste, z licznymi zatopionymi gałęziami i resztkami roślinności. Brzegi są niskie i podmokłe, gęsto porośnięte trzciną, co sprawia, że dostęp do wody jest utrudniony i wymaga brodzenia. Roślinność podwodna jest bardzo bujna, tworząc gęste zarośla, które są doskonałym schronieniem dla ryb, ale jednocześnie utrudniają wędkarstwo. W starorzeczu dominują gatunki takie jak lin, karaś pospolity i wzdręga, które doskonale czują się w takim środowisku. W upalne lata ryzyko niedoboru tlenu jest wysokie, co może wpływać na aktywność ryb. Jest to miejsce dla cierpliwych wędkarzy, poszukujących ciszy i kontaktu z dziką przyrodą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21136, 1.5, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21137, 'Starorzecze (Ostrowiec, Noteć)', 'starorzecze-ostrowiec-notec-czarnkow-21137', 'OXBOW', 53.3033744, 16.5306977, 'Wielkopolskie', 'Czarnków', 'To starorzecze, położone w pobliżu Ostrowca w dolinie Noteci, jest akwenem o umiarkowanej głębokości i zróżnicowanym dnie. Dno jest mieszane, z przewagą piasku i gliny, ale z mulistymi zatokami. Brzegi są częściowo strome, a częściowo łagodne, porośnięte wierzbami i olchami, które tworzą naturalne kryjówki dla ryb. Roślinność podwodna jest umiarkowana, skupiona głównie wzdłuż brzegów, co sprzyja wędkarstwu. W starorzeczu można liczyć na obfite połowy płoci, leszczy i okoni, a także na spotkanie z większymi drapieżnikami, takimi jak szczupak i sandacz, które wpływają z Noteci. Wędkowanie jest tu bardzo atrakcyjne, zwłaszcza wczesną wiosną i jesienią, kiedy ryby aktywnie żerują. Dostęp do wody jest dobry, co sprzyja zarówno wędkarstwu z brzegu, jak i z łodzi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21137, 8, 2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Sandacz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21138, 'Starorzecze (Ostrowiec, Zatoka Wschodnia)', 'starorzecze-ostrowiec-zatoka-wschodnia-czarnkow-21138', 'OXBOW', 53.3030603, 16.5325952, 'Wielkopolskie', 'Czarnków', 'Ta wschodnia zatoka starorzecza w Ostrowcu jest akwenem o bardziej odciętym charakterze od głównego nurtu Noteci. Dno jest głęboko zamulone, co sprzyja bujnemu rozwojowi roślinności wodnej, takiej jak grążele i rzęsa wodna. Brzegi są niskie i podmokłe, często porośnięte gęstymi szuwarami, co sprawia, że dostęp do wody jest utrudniony. Woda w starorzeczu jest często mętna, a w upalne lata może dochodzić do znacznych spadków poziomu tlenu, co stanowi wyzwanie dla ryb. Wędkowanie w tym miejscu jest trudne, ale może przynieść nagrody w postaci dużych linów i karasi pospolitych, które doskonale radzą sobie w takich warunkach. Należy przygotować się na łowienie w trudnych, zarośniętych miejscach i użycie sprzętu do brodzenia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21138, 3, 1.1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21139, 'Starorzecze (Szczechy Małe, Pisa)', 'starorzecze-szczechy-male-pisa-pisz-21139', 'OXBOW', 53.6991171, 21.8713123, 'Warmińsko-Mazurskie', 'Pisz', 'To starorzecze, położone w malowniczej okolicy Szczech Małych, jest typowym akwenem połączonym z rzeką Pisą podczas wysokiej wody. Dno jest zróżnicowane, z przewagą piasku i gliny, ale z mulistymi zagłębieniami, które stanowią doskonałe żerowiska. Brzegi są przeważnie łagodne, ale miejscami porośnięte gęstymi krzewami i drzewami, co utrudnia dostęp. Roślinność podwodna jest umiarkowana, z licznymi kępami moczarki i rdestnic, tworzącymi kryjówki dla ryb. W starorzeczu można liczyć na obfite połowy płoci, leszczy i okoni, a także na spotkanie z większymi drapieżnikami, takimi jak szczupak i sum, które sporadycznie wpływają z Pisy. Wędkowanie jest tu bardzo atrakcyjne, a różnorodność miejscówek pozwala na stosowanie różnych technik. Jest to popularne miejsce dla wędkarzy ceniących dziką przyrodę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21139, 6.5, 2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak,Sum', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21140, 'Starorzecze (Pilchy)', 'starorzecze-pilchy-orzysz-21140', 'OXBOW', 53.6987779, 21.8775525, 'Warmińsko-Mazurskie', 'Orzysz', 'To malownicze starorzecze, położone w pobliżu Pilch, stanowi urokliwy zakątek dla wędkarzy poszukujących spokoju. Dno akwenu jest muliste, z licznymi osadami, co sprzyja rozwojowi bogatej roślinności podwodnej i brzegowej. Brzegi są miejscami podmokłe i porośnięte gęstymi trzcinami, co utrudnia dostęp, ale jednocześnie zapewnia doskonałe kryjówki dla ryb. W starorzeczu dominują szczupaki, liny, płocie i leszcze, które znajdują tu idealne warunki do żerowania i rozrodu. Wiosną i wczesną jesienią wędkarze mogą liczyć na najlepsze brania, szczególnie podczas poszukiwania drapieżników w zaroślach. Wymagane są wodery, aby skutecznie dotrzeć do najlepszych stanowisk, a także cierpliwość ze względu na sporadyczne zaczepy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21140, 3.8, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Płoć,Leszcz', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21141, 'Starorzecze (Szczechy Małe)', 'starorzecze-szczechy-male-orzysz-21141', 'OXBOW', 53.7017824, 21.8714728, 'Warmińsko-Mazurskie', 'Orzysz', 'Starorzecze w Szczechach Małych to płytki zbiornik o silnym zarastaniu, co czyni je prawdziwym wyzwaniem dla wędkarzy. Dno jest grube, muliste, z dużą ilością detrytusu, co sprzyja rozwojowi bujnej roślinności zanurzonej i wynurzonej. Brzegi są niemal całkowicie opanowane przez gęste trzcinowiska i pałki wodne, przez co dostęp do wody jest bardzo utrudniony i wymaga użycia brodzących. Akwen ten jest domem dla licznych karasi pospolitych, linów, wzdręg i płoci, które doskonale czują się w tak zarośniętym środowisku. Latem, przy wysokich temperaturach, istnieje ryzyko przyduchy z powodu rozkładającej się materii organicznej. Najlepsze wyniki można osiągnąć w późnej wiośnie i lecie, stosując lekkie zestawy i szukając prześwitów w roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21141, 2.1, 1, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21142, 'Stare Koryto Warty', 'stare-koryto-warty-slupca-21142', 'OXBOW', 52.1700235, 17.742669, 'Wielkopolskie', 'Słupca', 'To rozległe starorzecze Warty, zlokalizowane w okolicach Słupcy, stanowi atrakcyjne łowisko o zróżnicowanym charakterze. Dno jest przeważnie muliste, ale miejscami występują twardsze, piaszczyste odcinki, będące pozostałością dawnego nurtu rzeki. Brzegi są stosunkowo łatwo dostępne, z licznymi dogodnymi stanowiskami wędkarskimi, choć miejscami występują zarośla krzewów i drzew. W akwenie tym można spotkać wiele gatunków ryb, w tym duże leszcze, płocie, karpie, a także drapieżniki takie jak sumy i szczupaki. Występują tu liczne zatopione drzewa i konary, które stanowią doskonałe kryjówki dla ryb, ale jednocześnie zwiększają ryzyko zaczepów. Łowienie jest możliwe przez cały sezon, jednak wiosenne i jesienne miesiące są szczególnie obfite w brania dużych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21142, 12.5, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sum,Szczupak', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21143, 'Starorzecze (Chylice-Pólko)', 'starorzecze-chylice-polko-konstancin-jeziorna-21143', 'OXBOW', 52.0695491, 21.0465173, 'Mazowieckie', 'Konstancin-Jeziorna', 'Jedno z mniejszych starorzeczy kompleksu Chylice-Pólko, charakteryzujące się silnym zarastaniem i płytką wodą. Dno jest bardzo muliste, z grubą warstwą osadów organicznych, co sprzyja bujnemu rozwojowi roślinności wodnej. Brzegi są niemal nieprzejezdne, gęsto porośnięte trzcinami i krzewami, co wymaga użycia brodzących dla skutecznego łowienia. Akwen ten jest typowym siedliskiem dla karasi pospolitych, linów i wzdręg, które doskonale adaptują się do trudnych warunków. Ze względu na brak stałego połączenia z rzeką i silne zarastanie, ryzyko przyduchy jest wysokie, zwłaszcza w upalne lata. Wędkarze powinni przygotować się na liczne zaczepy i konieczność precyzyjnego zarzucania zestawów w wolne od zarośli miejsca.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21143, 1.5, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21144, 'Starorzecze (Chylice-Pólko)', 'starorzecze-chylice-polko-konstancin-jeziorna-21144', 'OXBOW', 52.0703812, 21.0473165, 'Mazowieckie', 'Konstancin-Jeziorna', 'Kolejne starorzecze w obrębie Chylice-Pólko, o podobnych cechach do sąsiednich zbiorników, lecz z nieco większą powierzchnią. Dno jest grube, muliste, z dużą ilością rozkładającej się materii organicznej, co sprzyja obfitości roślinności wodnej. Brzegi są bagniste i trudno dostępne, z licznymi zaroślami, co utrudnia swobodne poruszanie się wzdłuż akwenu. Wśród dominujących gatunków ryb znajdują się karaś pospolity, lin, płoć i wzdręga, które świetnie radzą sobie w płytkich, zarośniętych wodach. Ryzyko niedoboru tlenu, szczególnie w okresie letnim, jest znaczące, co może wpływać na aktywność ryb. Wędkarze muszą liczyć się z koniecznością brodzenia i precyzyjnego poszukiwania wolnych od zarośli miejsc do łowienia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21144, 1.8, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21145, 'Starorzecze (Chylice-Pólko)', 'starorzecze-chylice-polko-konstancin-jeziorna-21145', 'OXBOW', 52.0729999, 21.0510374, 'Mazowieckie', 'Konstancin-Jeziorna', 'To starorzecze, choć wciąż płytkie, oferuje nieco większą głębokość i mniejsze zarastanie niż jego najbliżsi sąsiedzi w kompleksie Chylice-Pólko. Dno jest muliste, ale miejscami pojawiają się twardsze fragmenty, a roślinność wodna jest umiarkowana, co pozwala na swobodniejsze łowienie. Brzegi są nadal trudne i bagniste, z licznymi zaroślami, co wymaga ostrożności i użycia woderów. W wodach tego starorzecza można spotkać szczupaki i okonie, które polują na licznie występujące płocie i leszcze. Brak stałego połączenia z rzeką sprawia, że w okresach suszy poziom wody może spadać, a ryzyko przyduchy wzrasta. Najlepsze wyniki osiąga się wiosną i wczesną jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21145, 2, 1.3, 2.8, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21146, 'Starorzecze (Chylice-Pólko)', 'starorzecze-chylice-polko-konstancin-jeziorna-21146', 'OXBOW', 52.073318, 21.0512109, 'Mazowieckie', 'Konstancin-Jeziorna', 'To jedno z najbardziej płytkich i silnie zarośniętych starorzeczy w rejonie Chylice-Pólko, charakteryzujące się wysokim poziomem zamulenia. Dno jest miękkie, bardzo muliste, z grubą warstwą osadów, co sprzyja rozwojowi gęstej roślinności zanurzonej i wynurzonej. Brzegi są praktycznie nieprzystępne, opanowane przez szuwary i trzciny, co czyni dostęp do wody niezwykle trudnym. W tym akwenie królują gatunki odporne na trudne warunki, takie jak karaś pospolity, wzdręga i lin. Istnieje realne ryzyko wyschnięcia zbiornika w okresach długotrwałej suszy, co dodatkowo utrudnia utrzymanie stabilnej populacji ryb. Wędkarstwo w tym miejscu to wyzwanie, wymagające cierpliwości, odpowiedniego sprzętu i umiejętności odnajdywania wolnych od zarośli miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21146, 1.6, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21147, 'Starorzecze (Chylice-Pólko)', 'starorzecze-chylice-polko-konstancin-jeziorna-21147', 'OXBOW', 52.0726866, 21.051603, 'Mazowieckie', 'Konstancin-Jeziorna', 'Kolejne starorzecze w kompleksie Chylice-Pólko, charakteryzujące się znacznym zamuleniem i gęstą roślinnością. Dno jest miękkie i bardzo muliste, co jest typowe dla starorzeczy pozbawionych silnego nurtu. Brzegi są podmokłe i porośnięte gęstymi zaroślami, co sprawia, że dostęp do wody jest utrudniony i wymaga użycia woderów. W zbiorniku dominują karaś pospolity, lin oraz płoć, które doskonale odnajdują się w płytkich, bogatych w roślinność wodach. W cieplejszych miesiącach, z powodu rozkładu materii organicznej, istnieje ryzyko deficytu tlenu, co może wpływać na aktywność ryb. Wędkarze powinni przygotować się na liczne zaczepy i konieczność precyzyjnego łowienia w niewielkich prześwitach roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21147, 1.9, 1.1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21148, 'Starorzecze (Chylice-Pólko)', 'starorzecze-chylice-polko-konstancin-jeziorna-21148', 'OXBOW', 52.0720401, 21.0512554, 'Mazowieckie', 'Konstancin-Jeziorna', 'To starorzecze wyróżnia się nieco większą głębokością i mniejszym stopniem zarastania w porównaniu do innych zbiorników w rejonie Chylice-Pólko. Dno jest muliste, ale w niektórych miejscach twardsze, co świadczy o mniejszym nagromadzeniu osadów. Brzegi są wciąż bagniste i zarośnięte, co wymaga użycia woderów, jednak dostęp do wody jest nieco łatwiejszy. Akwen ten jest atrakcyjny dla wędkarzy poszukujących drapieżników, takich jak szczupak i okoń, które polują na licznie występujące płocie i leszcze. Mimo braku stałego połączenia z rzeką, większa głębokość zmniejsza ryzyko całkowitej przyduchy, choć wciąż jest ono obecne. Wiosenne i wczesnojesienne miesiące są najbardziej produktywne dla łowienia drapieżników i białorybu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21148, 2.2, 1.4, 2.7, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21149, 'Starorzecze (Skalisze)', 'starorzecze-skalisze-goldap-21149', 'OXBOW', 54.2887511, 21.9630721, 'Warmińsko-Mazurskie', 'Gołdap', 'Starorzecze w Skaliszach to stosunkowo czysty i głębszy akwen, oferujący dobre warunki wędkarskie. Dno jest zróżnicowane, z fragmentami piaszczystymi i mulistymi, co sprzyja różnorodności gatunków ryb. Brzegi są w większości łatwo dostępne, z miejscami do rozłożenia sprzętu, choć miejscami występują kępy trzcin. Akwen ten jest domem dla szczupaków, okoni, płoci, leszczy i linów, co czyni go atrakcyjnym zarówno dla spinningistów, jak i wędkarzy gruntowych. Połączenie z rzeką podczas wysokiej wody zapewnia świeżą wodę i migrację ryb, co pozytywnie wpływa na kondycję populacji. Niski poziom zamulenia i umiarkowane zarastanie sprawiają, że wędkarstwo jest tu przyjemne przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21149, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21150, 'Starorzecze (Dąbrówka Polska)', 'starorzecze-dabrowka-polska-banie-mazurskie-21150', 'OXBOW', 54.2490332, 22.0206238, 'Warmińsko-Mazurskie', 'Banie Mazurskie', 'Starorzecze w Dąbrówce Polskiej to średniej wielkości zbiornik, który zasilany jest wodą z rzeki podczas wiosennych roztopów. Dno jest przeważnie muliste, ale miejscami można znaleźć twardsze fragmenty, idealne dla karpi i linów. Brzegi są stosunkowo łatwo dostępne, z rozproszonymi kępami trzcin, które stanowią schronienie dla ryb. W akwenie tym dominują szczupaki, liny, karpie i płocie, oferując różnorodne możliwości wędkarskie. Umiarkowane zarastanie i średnie zamulenie sprawiają, że łowienie jest komfortowe, a ryzyko zaczepów jest akceptowalne. Najlepsze wyniki osiąga się wiosną, gdy ryby są po tarle, oraz wczesną jesienią, kiedy intensywnie żerują przed zimą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21150, 3.2, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Karp,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21151, 'Starorzecze (Banie Mazurskie)', 'starorzecze-banie-mazurskie-banie-mazurskie-21151', 'OXBOW', 54.2449257, 22.0565717, 'Warmińsko-Mazurskie', 'Banie Mazurskie', 'Pierwsze z serii starorzeczy w okolicach Bań Mazurskich, charakteryzujące się znacznym zamuleniem i gęstą roślinnością. Dno jest bardzo muliste, z grubą warstwą osadów organicznych, co sprzyja rozwojowi bujnej roślinności wodnej. Brzegi są niemal całkowicie opanowane przez trzcinowiska i zarośla, przez co dostęp do wody jest bardzo utrudniony i wymaga użycia brodzących. Akwen ten jest typowym siedliskiem dla karasi pospolitych, linów i wzdręg, które doskonale adaptują się do trudnych warunków. Ze względu na brak stałego połączenia z rzeką i silne zarastanie, ryzyko przyduchy jest wysokie, zwłaszcza w upalne lata. Wędkarze powinni przygotować się na liczne zaczepy i konieczność precyzyjnego zarzucania zestawów w wolne od zarośli miejsca.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21151, 2.5, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21152, 'Starorzecze (Banie Mazurskie)', 'starorzecze-banie-mazurskie-banie-mazurskie-21152', 'OXBOW', 54.2421573, 22.0641418, 'Warmińsko-Mazurskie', 'Banie Mazurskie', 'To starorzecze w Bańach Mazurskich jest jednym z najbardziej płytkich i podatnych na wysychanie w regionie. Dno jest ekstremalnie muliste, z minimalną warstwą twardego podłoża, co sprzyja intensywnemu rozwojowi roślinności wodnej. Brzegi są bagniste i niemal całkowicie zarośnięte, co sprawia, że dostęp do wody jest bardzo trudny i często wymaga przedzierania się przez gęste zarośla. W akwenie tym dominują najbardziej odporne gatunki, takie jak karaś pospolity i wzdręga, które są w stanie przetrwać w tak ekstremalnych warunkach. Ryzyko wyschnięcia zbiornika w okresach długotrwałej suszy jest realne, co dodatkowo ogranicza populację ryb. Wędkarstwo w tym miejscu to prawdziwe wyzwanie, wymagające cierpliwości i specjalistycznego sprzętu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21152, 2, 1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21153, 'Starorzecze (Banie Mazurskie)', 'starorzecze-banie-mazurskie-banie-mazurskie-21153', 'OXBOW', 54.2424032, 22.0641312, 'Warmińsko-Mazurskie', 'Banie Mazurskie', 'Kolejne starorzecze w kompleksie Bań Mazurskich, charakteryzujące się znacznym zamuleniem i gęstą roślinnością, typową dla tego typu akwenów. Dno jest miękkie i bardzo muliste, z grubą warstwą osadów, co jest idealnym środowiskiem dla wielu gatunków roślin wodnych. Brzegi są podmokłe i porośnięte gęstymi zaroślami, co sprawia, że dostęp do wody jest utrudniony i wymaga użycia woderów. W zbiorniku dominują karaś pospolity, lin oraz płoć, które doskonale odnajdują się w płytkich, bogatych w roślinność wodach. W cieplejszych miesiącach, z powodu rozkładu materii organicznej, istnieje ryzyko deficytu tlenu, co może wpływać na aktywność ryb. Wędkarze powinni przygotować się na liczne zaczepy i konieczność precyzyjnego łowienia w niewielkich prześwitach roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21153, 2.1, 1.1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21154, 'Starorzecze (Sapałówka)', 'starorzecze-sapalowka-banie-mazurskie-21154', 'OXBOW', 54.2403497, 22.0684716, 'Warmińsko-Mazurskie', 'Banie Mazurskie', 'Starorzecze w Sapałówce to malowniczy akwen, który podczas wysokiej wody łączy się z pobliską rzeką, co wpływa na jego bioróżnorodność. Dno jest muliste, ale miejscami występują twardsze fragmenty, a roślinność wodna jest umiarkowana, co pozwala na swobodniejsze łowienie. Brzegi są w większości bagniste i zarośnięte, co wymaga użycia woderów, jednak dostęp do wody jest możliwy w kilku miejscach. W wodach tego starorzecza można spotkać szczupaki i okonie, które polują na licznie występujące płocie i liny. Połączenie z rzeką zapobiega całkowitemu odizolowaniu, choć ryzyko przyduchy w upalne lato nadal istnieje. Wiosenne i wczesnojesienne miesiące są najbardziej produktywne dla łowienia drapieżników i białorybu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21154, 2.8, 1.3, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Płoć,Lin', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21155, 'Starorzecze Kośmidry', 'starorzecze-kosmidry-goldap-21155', 'OXBOW', 54.308667, 22.2256785, 'Warmińsko-Mazurskie', 'Gołdap', 'To malownicze starorzecze, położone w pobliżu Kośmidr, charakteryzuje się typowym dla regionu dnem mulistym, bogatym w materię organiczną. Brzegi są w dużej mierze bagniste i trudno dostępne, co wymaga użycia wodoodpornego obuwia lub pontonu. Roślinność podwodna jest umiarkowana, ale miejscami tworzy gęste zarośla, idealne dla drapieżników. Akwen ten jest okresowo połączony z rzeką Gołdapą podczas wysokiego stanu wody, co umożliwia migrację ryb. Dominującymi gatunkami są lin, szczupak, płoć oraz karaś pospolity, które znajdują tu doskonałe warunki do żerowania. Wędkarstwo może być wyzwaniem ze względu na liczne zaczepy w postaci pojedynczych korzeni i gałęzi, jednak nagrodą są często okazałe okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21155, 3.2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Płoć,Karaś pospolity', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21156, 'Starorzecze Bałupiany', 'starorzecze-balupiany-goldap-21156', 'OXBOW', 54.3117124, 22.242984, 'Warmińsko-Mazurskie', 'Gołdap', 'To starorzecze, położone w okolicach Bałupian, jest typowym, mocno zarośniętym akwenem, charakteryzującym się wysokim poziomem zamulenia dna. Brzegi są gęsto porośnięte trzciną i inną roślinnością przybrzeżną, co znacznie utrudnia dostęp do wody. Podwodna roślinność jest niezwykle bujna, tworząc liczne kryjówki dla ryb, ale także stanowiąc wyzwanie dla wędkarzy. Brak stałego połączenia z rzeką sprawia, że woda jest tu spokojna, ale latem istnieje ryzyko przyduchy. Dominujące gatunki to lin, karaś pospolity, wzdręga oraz mniejsze szczupaki, które doskonale czują się w takim środowisku. Wędkowanie wymaga cierpliwości i precyzji, szczególnie przy zarzucaniu zestawu w przerwach między roślinnością.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21156, 2.8, 1.8, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21157, 'Starorzecze Gołdapskie (Wschodnie)', 'starorzecze-goldapskie-wschodnie-goldap-21157', 'OXBOW', 54.312247, 22.2758001, 'Warmińsko-Mazurskie', 'Gołdap', 'To jedno z większych starorzeczy w okolicach Gołdapi, charakteryzujące się stałym połączeniem z rzeką Gołdapą, co zapewnia dobrą wymianę wody i stabilne warunki tlenowe. Dno jest stosunkowo czyste, z niewielkim zamuleniem, co sprzyja różnorodności gatunkowej ryb. Brzegi są łatwo dostępne, miejscami piaszczyste, co czyni je idealnym miejscem do wędkowania z brzegu. Roślinność podwodna jest umiarkowana, skupiająca się głównie w płytszych zatoczkach. Akwen ten jest znany z populacji szczupaka i okonia, ale z powodzeniem łowione są tu również płocie, leszcze i jazie. Ze względu na dobre warunki i dostępność, jest to popularne miejsce wśród lokalnych wędkarzy przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21157, 4.5, 2, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz,Jaź', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21158, 'Starorzecze Gołdapskie (Centralne)', 'starorzecze-goldapskie-centralne-goldap-21158', 'OXBOW', 54.3126707, 22.2782967, 'Warmińsko-Mazurskie', 'Gołdap', 'To starorzecze, leżące w bezpośrednim sąsiedztwie Gołdapi, charakteryzuje się średnim zamuleniem dna, z licznymi, choć pojedynczymi, zatopionymi korzeniami i gałęziami. Brzegi są przeważnie łatwo dostępne, co ułatwia wędkowanie z brzegu. Połączenie z rzeką Gołdapą występuje głównie podczas wysokich stanów wody, co wpływa na różnorodność rybostanu. Roślinność podwodna jest umiarkowana, tworząc schronienie dla mniejszych ryb. Dominujące gatunki to płoć, leszcz, okoń i wzdręga, które licznie występują w tym akwenie. Wędkarze mogą liczyć na udane połowy, szczególnie wczesną wiosną i jesienią, kiedy ryby intensywnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21158, 3.8, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Wzdręga', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21159, 'Starorzecze Gołdapskie (Zachodnie)', 'starorzecze-goldapskie-zachodnie-goldap-21159', 'OXBOW', 54.3122185, 22.2934872, 'Warmińsko-Mazurskie', 'Gołdap', 'To niewielkie, płytkie starorzecze na zachód od Gołdapi jest przykładem akwenu o silnym stopniu zarastania i wysokim zamuleniu. Brak połączenia z główną rzeką sprawia, że woda jest tu bardzo spokojna, ale podatna na wahania poziomu tlenu w cieplejszych miesiącach. Brzegi są gęsto porośnięte trzciną i inną roślinnością, co wymaga użycia wodoodpornego obuwia lub pontonu do dotarcia do dobrych miejscówek. Podwodna roślinność jest obfita, tworząc labirynt kryjówek dla ryb. Królują tu karasie pospolite i liny, a także wzdręgi i płocie, które doskonale radzą sobie w takim środowisku. Wędkowanie jest tu wyzwaniem, ale może przynieść satysfakcję w postaci pięknych, zdrowych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21159, 2.1, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21160, 'Starorzecze Słubickie (Północne)', 'starorzecze-slubickie-polnocne-slubice-21160', 'OXBOW', 52.3467136, 14.5734033, 'Lubuskie', 'Słubice', 'To rozległe starorzecze w pobliżu Słubic, charakteryzujące się stałym połączeniem z Odrą, co zapewnia dynamiczną wymianę wody i bogaty rybostan. Dno jest przeważnie piaszczysto-żwirowe z niewielkim zamuleniem, co sprzyja drapieżnikom. Brzegi są dobrze dostępne, miejscami umocnione, co ułatwia wędkowanie z brzegu. Roślinność podwodna jest słaba, skupiona głównie w płytkich zatoczkach i przy brzegach. Akwen ten jest ceniony przez wędkarzy za obecność dużych szczupaków i sandaczy, a także leszczy, płoci i okoni. Jest to idealne miejsce dla spinningistów i wędkarzy gruntowych, oferujące dobre warunki przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21160, 7, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21161, 'Starorzecze Słubickie (Południowe)', 'starorzecze-slubickie-poludniowe-slubice-21161', 'OXBOW', 52.3428392, 14.5793378, 'Lubuskie', 'Słubice', 'Starorzecze to, położone nieopodal Słubic, charakteryzuje się bardziej dzikim charakterem, z brzegami często bagnistymi i trudnymi do przejścia. Dno jest muliste, z licznymi zatopionymi drzewami i gałęziami, co tworzy doskonałe kryjówki dla dużych ryb, ale także stanowi wyzwanie dla wędkarzy. Połączenie z Odrą następuje głównie podczas wysokich stanów wody, co wzbogaca rybostan o gatunki rzeczne. Akwen ten słynie z obecności dużych karpi i sumów, a także licznych leszczy i płoci. Wędkowanie wymaga użycia mocnego sprzętu i ostrożności ze względu na zaczepy, ale może przynieść rekordowe okazy. Jest to idealne miejsce dla wędkarzy szukających prawdziwej przygody i dzikiego łowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21161, 5.5, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Sum,Leszcz,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21162, 'Starorzecze Raba Niżna', 'starorzecze-raba-nizna-raba-nizna-21162', 'OXBOW', 49.6261289, 20.0051137, 'Małopolskie', 'Raba Niżna', 'To niewielkie i płytkie starorzecze w Małopolsce, w pobliżu Raby Niżnej, cechuje się silnym zamuleniem i gęstym zarastaniem. Dno jest miękkie i muliste, a brzegi są praktycznie niedostępne bez brodzenia w wodzie lub użycia pontonu, ze względu na gęste zarośla trzcinowe. Akwen ten jest połączony z rzeką Rabą jedynie podczas wiosennych roztopów i silnych deszczy, co ogranicza migrację ryb. W suchych latach starorzecze to może całkowicie wyschnąć, co stanowi ryzyko dla jego ekosystemu. Dominującymi gatunkami są odporne karasie pospolite, liny i wzdręgi, które dobrze adaptują się do trudnych warunków. Wędkowanie jest tu wyzwaniem, ale może być satysfakcjonujące dla miłośników dzikich, naturalnych łowisk.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21162, 1.8, 1, 2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21163, 'Starorzecze Katowickie (Murcki)', 'starorzecze-katowickie-murcki-katowice-21163', 'OXBOW', 50.1670498, 18.9481836, 'Śląskie', 'Katowice', 'To niewielkie starorzecze, zlokalizowane w obrębie Katowic, w dzielnicy Murcki, stanowi cenny fragment miejskiej przyrody. Jest to akwen o wysokim stopniu zamulenia i intensywnym zarastaniu, co jest typowe dla starorzeczy miejskich. Dno jest miękkie, a brzegi często bagniste i trudno dostępne, wymagające użycia odpowiedniego obuwia. Brak połączenia z większymi ciekami wodnymi sprawia, że jest to środowisko zamknięte, podatne na wahania poziomu tlenu. Dominującymi gatunkami są wytrzymałe karasie srebrzyste, płocie i wzdręgi, które doskonale radzą sobie w tych warunkach. Mimo trudności, to łowisko oferuje spokój i możliwość obcowania z naturą w środku aglomeracji.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21163, 0.9, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś srebrzysty,Płoć,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21164, 'Starorzecze Mareckie', 'starorzecze-mareckie-marki-21164', 'OXBOW', 52.3655836, 21.1271495, 'Mazowieckie', 'Marki', 'Rozległe starorzecze w pobliżu Marek, stanowiące atrakcyjne łowisko w bliskości Warszawy. Akwen ten charakteryzuje się umiarkowanym zamuleniem dna i dobrze dostępnymi brzegami, co ułatwia wędkowanie z wielu miejsc. Połączenie z Wisłą następuje podczas wyższych stanów wody, co sprzyja migracji ryb i utrzymaniu dobrej jakości wody. Roślinność podwodna jest umiarkowana, tworząc schronienia dla ryb, ale nie utrudniając nadmiernie wędkowania. Występują tu liczne karpie, liny, szczupaki, leszcze i płocie, co czyni to miejsce idealnym dla różnorodnych metod wędkarskich. Jest to popularne łowisko, cenione za dobre warunki i bogactwo ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21164, 6, 2.2, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Lin,Szczupak,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21165, 'Starorzecze Tarnica', 'starorzecze-tarnica-brzeg-21165', 'OXBOW', 50.6833503, 17.5008666, 'Opolskie', 'Brzeg', 'Starorzecze w okolicach Tarnicy, niedaleko Brzegu, jest akwenem o spokojnym charakterze, całkowicie odciętym od głównego nurtu rzeki. Dno jest muliste, ze średnim stopniem zamulenia, a brzegi są często bagniste i zarośnięte, co wymaga ostrożności i użycia wodoodpornego obuwia. Roślinność podwodna jest umiarkowana, ale w niektórych miejscach tworzy gęste skupiska. Brak połączenia z rzeką może prowadzić do ryzyka przyduchy w upalne lata. Dominującymi gatunkami są lin, karaś pospolity, szczupak i okoń, które dobrze adaptują się do tych warunków. Wędkowanie w tym miejscu to prawdziwa gratka dla miłośników spokojnych, dzikich łowisk, oferujących szansę na złowienie pięknych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21165, 3.5, 1.6, 3, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21166, 'Starorzecze Lubawskie', 'starorzecze-lubawskie-lubawa-21166', 'OXBOW', 53.5059375, 19.7206863, 'Warmińsko-Mazurskie', 'Lubawa', 'To niewielkie starorzecze w pobliżu Lubawy jest mocno zarośnięte i zamulone, co tworzy idealne warunki dla ryb typowych dla płytkich, ciepłych wód. Dno jest miękkie, a brzegi gęsto porośnięte trzciną, co utrudnia dostęp do wody i wymaga użycia wodoodpornego obuwia. Połączenie z rzeką Drwęcą następuje sporadycznie, podczas wiosennych wezbrań. Ze względu na płytkość i gęstą roślinność, w cieplejszych miesiącach istnieje ryzyko niedoboru tlenu. Dominującymi gatunkami są karaś pospolity, lin, wzdręga i płoć, które doskonale czują się w tym środowisku. Wędkowanie to wymaga cierpliwości i umiejętności, ale może przynieść satysfakcję z połowu pięknych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21166, 2, 1.3, 2.8, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21167, 'Starorzecze Drezdenko (Zachodnie)', 'starorzecze-drezdenko-zachodnie-drezdenko-21167', 'OXBOW', 52.8488645, 15.8236395, 'Lubuskie', 'Drezdenko', 'To starorzecze, zlokalizowane w pobliżu Drezdenka, charakteryzuje się stałym połączeniem z rzeką Noteć, co zapewnia dobrą wymianę wody i stabilne warunki. Dno jest stosunkowo czyste, z niewielkim zamuleniem i pojedynczymi zaczepami. Brzegi są łatwo dostępne, co ułatwia wędkowanie z brzegu. Roślinność podwodna jest umiarkowana, tworząc dobre kryjówki dla ryb, ale nie utrudniając nadmiernie łowienia. Akwen ten jest znany z populacji szczupaka, okonia, leszcza i płoci, a także okazjonalnie węgorza. Jest to popularne miejsce dla wędkarzy, którzy cenią sobie dobre warunki i różnorodność gatunkową ryb przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21167, 4, 1.8, 3.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Węgorz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21168, 'Starorzecze Drezdenko (Centralne)', 'starorzecze-drezdenko-centralne-drezdenko-21168', 'OXBOW', 52.8483715, 15.8288377, 'Lubuskie', 'Drezdenko', 'Starorzecze to, położone centralnie w kompleksie starorzeczy Drezdenka, charakteryzuje się średnim zamuleniem dna i umiarkowaną roślinnością podwodną. Brzegi są łatwo dostępne, co sprawia, że jest to wygodne miejsce do wędkowania z brzegu. Połączenie z rzeką Noteć następuje głównie podczas wysokich stanów wody, co sprzyja odświeżaniu wody i migracji ryb. Akwen ten jest domem dla licznych karpi, linów, płoci i leszczy, które znajdują tu dobre warunki do żerowania. Wędkowanie jest tu przyjemne i często nagradzane dobrymi połowami, szczególnie w cieplejszych miesiącach. To idealne miejsce na spokojny dzień nad wodą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21168, 3, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Lin,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21169, 'Starorzecze Drezdenko (Wschodnie)', 'starorzecze-drezdenko-wschodnie-drezdenko-21169', 'OXBOW', 52.8480886, 15.8266558, 'Lubuskie', 'Drezdenko', 'To najmniejsze z drezdenkowskich starorzeczy, charakteryzujące się wysokim stopniem zamulenia i silnym zarastaniem. Dno jest miękkie, a brzegi gęsto porośnięte trzciną, co utrudnia dostęp do wody i wymaga użycia wodoodpornego obuwia. Brak stałego połączenia z Noteć sprawia, że jest to akwen o bardziej stabilnym, choć czasem stagnującym charakterze. W cieplejszych miesiącach istnieje ryzyko niedoboru tlenu. Dominującymi gatunkami są karaś pospolity, lin, wzdręga oraz mniejsze okonie, które doskonale adaptują się do tych warunków. Wędkowanie jest tu wyzwaniem, ale może przynieść satysfakcję z połowu ryb w dzikim, naturalnym środowisku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21169, 2.5, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21170, 'Starorzecze w Pcimiu', 'starorzecze-w-pcimiu-pcim-21170', 'OXBOW', 49.7416429, 19.9967691, 'Małopolskie', 'Pcim', 'To malownicze starorzecze, zlokalizowane w okolicach Pcimia, stanowi pozostałość po dawnych meandrach rzeki Raby. Charakteryzuje się średnim zamuleniem dna, które w większości jest muliste z licznymi zatopionymi korzeniami i gałęziami, co tworzy doskonałe kryjówki dla ryb. Brzegi są miejscami trudno dostępne, bagniste i porośnięte gęstą roślinnością szuwarową, co wymaga użycia wodoodpornych spodniobutów. Wiosną i wczesną jesienią wędkarze mogą liczyć na udane połowy lina, karasia pospolitego, szczupaka oraz okonia. Ze względu na ograniczoną cyrkulację wody, zwłaszcza w upalne lata, istnieje ryzyko przyduchy. Starorzecze to oferuje jednak dziki charakter i spokój, co docenią miłośnicy natury i cierpliwego wędkarstwa.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21170, 3.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Trudny, miejscami bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21171, 'Jezioro Łężyca', 'jezioro-lezyca-zielona-gora-21171', 'OXBOW', 52.0251035, 15.5036973, 'Lubuskie', 'Zielona Góra', 'Jezioro Łężyca, będące starorzeczem Odry, to akwen o umiarkowanej powierzchni, położony w pobliżu Zielonej Góry. Charakteryzuje się dość głębokim dnem jak na starorzecze, z miejscami mulistymi, ale też z twardszymi partiami. Roślinność podwodna jest silna, tworząc rozległe podwodne łąki, idealne dla drapieżników i ryb spokojnego żeru. Brzegi są częściowo dostępne, choć miejscami gęsto porośnięte trzciną, co wymaga znalezienia odpowiednich stanowisk. W jeziorze dominują leszcze, płocie, liny i szczupaki, a sporadycznie łowi się także karpie. Zimą, pod lodem, może wystąpić ryzyko niedoboru tlenu, jednak zazwyczaj jest ono niewielkie. Jest to popularne łowisko, oferujące różnorodne możliwości wędkowania przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21171, 12.5, 2.2, 5.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', FALSE, FALSE, 'Leszcz,Płoć,Lin,Szczupak,Karp', 'Częściowo dobry, miejscami zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21172, 'Starorzecze w Osieczanach', 'starorzecze-w-osieczanach-osieczany-21172', 'OXBOW', 49.8498029, 19.9755633, 'Małopolskie', 'Osieczany', 'Starorzecze w Osieczanach to niewielki, lecz urokliwy zbiornik, będący reliktem dawnej rzeki Raby. Jego dno jest w dużej mierze zamulone, z licznymi zatopionymi gałęziami i krzewami, które stanowią schronienie dla wielu gatunków ryb. Brzegi są mocno zarośnięte trzciną i inną roślinnością szuwarową, co utrudnia dostęp do wody, ale jednocześnie zapewnia spokój i odosobnienie. Występuje tu bogata populacja karasia pospolitego i lina, a także wzdręgi i płoci. Ze względu na płytkość i izolację, w upalne lata może pojawić się ryzyko przyduchy. Wędkowanie tutaj wymaga cierpliwości i często użycia brodzących, ale nagrodą są piękne okazy i bliskość natury.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21172, 2.1, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21173, 'Starorzecze w okolicach Gardei', 'starorzecze-w-okolicach-gardei-gardeya-21173', 'OXBOW', 53.4670363, 19.0676373, 'Kujawsko-Pomorskie', 'Gardeya', 'To starorzecze, położone w malowniczych okolicach Gardei, charakteryzuje się umiarkowanym zamuleniem i zróżnicowanym dnem, gdzie obok mułu występują twardsze, piaszczyste partie. Jest to typowy akwen dla starorzeczy Wisły, z okresowym połączeniem z rzeką podczas wysokiej wody. Brzegi są dość łatwo dostępne, choć miejscami mogą być porośnięte trawą i pojedynczymi krzewami. W starorzeczu tym dominują płocie, leszcze i okonie, a także często spotyka się szczupaki, które znajdują tu idealne warunki do żerowania. Poziom roślinności podwodnej jest umiarkowany, co ułatwia łowienie, ale jednocześnie zapewnia rybom wystarczającą ilość kryjówek. Ryzyko przyduchy jest niskie ze względu na okresowe połączenie z Wisłą. To dobre miejsce na wędkowanie przez cały rok, szczególnie dla miłośników spławika i spinningu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21173, 7.8, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21174, 'Starorzecze w Szarnosiu (północne)', 'starorzecze-w-szarnosiu-polnocne-szarnos-21174', 'OXBOW', 53.4474116, 19.1372365, 'Kujawsko-Pomorskie', 'Szarnoś', 'To jedno z dwóch starorzeczy w okolicach Szarnosia, charakteryzujące się znacznym zamuleniem dna i bogatą roślinnością przybrzeżną. Jest to typowy akwen dla miłośników lina i karasia pospolitego, które znajdują tu idealne warunki do życia. Brzegi są miejscami trudno dostępne, bagniste i gęsto porośnięte, co wymaga ostrożności i często użycia brodzących. Połączenie z rzeką (Wisłą) jest sporadyczne, tylko podczas bardzo wysokich stanów wody, co sprzyja izolacji i rozwojowi specyficznej ichtiofauny. W miesiącach letnich, ze względu na płytkość i bujną roślinność, istnieje podwyższone ryzyko przyduchy. Mimo to, starorzecze oferuje wędkarzom unikalne doświadczenia i szansę na złowienie pięknych, dzikich ryb w spokojnej scenerii. Najlepsze wyniki osiąga się tu wczesnym latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21174, 4.5, 1.3, 3, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21175, 'Starorzecze w Szarnosiu (południowe)', 'starorzecze-w-szarnosiu-poludniowe-szarnos-21175', 'OXBOW', 53.4494464, 19.127711, 'Kujawsko-Pomorskie', 'Szarnoś', 'Drugie ze starorzeczy w rejonie Szarnosia, nieco większe i głębsze od swojego północnego sąsiada, oferuje zróżnicowane środowisko. Dno jest mieszane, z partiami mulistymi i twardszymi, a roślinność podwodna jest umiarkowana, co sprzyja różnorodności gatunków ryb. Brzegi są w większości dobrze dostępne, co ułatwia wędkowanie z brzegu, choć miejscami można natknąć się na pojedyncze zarośla. Starorzecze to ma rzadkie połączenie z Wisłą, głównie podczas wiosennych roztopów, co pomaga w odświeżaniu wody. Wśród dominujących gatunków ryb znajdują się leszcze, płocie, szczupaki i okonie, a także karasie srebrzyste. Ryzyko przyduchy jest niższe niż w mniejszych, bardziej zarośniętych akwenach. Jest to atrakcyjne łowisko dla wędkarzy szukających różnorodnych gatunków i komfortowego dostępu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21175, 6.1, 1.8, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Karaś srebrzysty', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21176, 'Starorzecze w Świeciu nad Osą', 'starorzecze-w-swieciu-nad-osa-swiecie-nad-osa-21176', 'OXBOW', 53.4517984, 19.1226638, 'Kujawsko-Pomorskie', 'Świecie nad Osą', 'To starorzecze, położone w pobliżu Świecia nad Osą, jest stosunkowo płytkim akwenem, charakteryzującym się wysokim poziomem zamulenia dna. Jest to idealne środowisko dla gatunków ryb preferujących ciepłe i płytkie wody, takich jak lin i karaś pospolity. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest utrudniony i często wymaga użycia brodzących. Połączenie z rzeką Osą jest bardzo rzadkie, co prowadzi do znacznej izolacji zbiornika. Z tego powodu, w okresach długotrwałych upałów lub mroźnych zim, ryzyko przyduchy jest wysokie. Mimo trudności w dostępie, starorzecze to oferuje wędkarzom spokój i szansę na złowienie dorodnych linów i karasi w dzikiej scenerii.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21176, 3, 0.9, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21177, 'Starorzecze w Grudziądzu (północne)', 'starorzecze-w-grudziadzu-polnocne-grudziadz-21177', 'OXBOW', 53.5026924, 18.8600445, 'Kujawsko-Pomorskie', 'Grudziądz', 'To starorzecze, zlokalizowane w okolicach Grudziądza, jest jednym z większych akwenów tego typu w regionie. Charakteryzuje się umiarkowanym zamuleniem i zróżnicowanym dnem, z miejscami twardszymi oraz mulistymi. Brzegi są w większości dobrze dostępne, co czyni je popularnym miejscem wśród wędkarzy. Posiada okresowe połączenie z Wisłą, głównie podczas wiosennych wezbrań, co sprzyja wymianie wody i zarybianiu. W starorzeczu tym występują liczne szczupaki i okonie, a także płocie i leszcze. Poziom roślinności podwodnej jest umiarkowany, co zapewnia rybom schronienie, a wędkarzom komfort łowienia. Ryzyko przyduchy jest niskie. Jest to doskonałe łowisko dla spinningistów i wędkarzy spławikowych, oferujące dobre warunki przez większość sezonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21177, 15, 2.5, 6, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz,Sum', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21178, 'Starorzecze w Grudziądzu (południowe)', 'starorzecze-w-grudziadzu-poludniowe-grudziadz-21178', 'OXBOW', 53.5023824, 18.860988, 'Kujawsko-Pomorskie', 'Grudziądz', 'Sąsiadujące starorzecze w Grudziądzu, choć mniejsze, również oferuje atrakcyjne warunki dla wędkarzy. Jego dno jest bardziej muliste, a roślinność przybrzeżna gęstsza, co sprzyja rozwojowi lina i karasia pospolitego. Brzegi są trudniej dostępne niż w większym akwenie, z licznymi zaroślami i miejscami bagnistymi, co wymaga użycia wodoodpornych spodniobutów. Podobnie jak inne starorzecza wiślane, ma ono okresowe połączenie z rzeką, co zapewnia dopływ świeżej wody i migrację ryb. Oprócz lina i karasia, można tu złowić także szczupaka i okonia. W cieplejszych miesiącach, ze względu na gęstą roślinność, warto monitorować poziom tlenu. To miejsce dla tych, którzy cenią sobie spokój i wyzwanie wędkarstwa w bardziej dzikim środowisku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21178, 9, 1.7, 3.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21179, 'Starorzecze w Żabach', 'starorzecze-w-zabach-zaby-21179', 'OXBOW', 51.1752178, 19.4219365, 'Łódzkie', 'Żaby', 'To starorzecze, zlokalizowane w miejscowości Żaby, jest typowym płytkim zbiornikiem o silnie zamulonym dnie. Charakteryzuje się gęstą roślinnością wodną i przybrzeżną, co tworzy doskonałe środowisko dla karasia pospolitego, lina i wzdręgi. Brzegi są w większości trudno dostępne, porośnięte trzciną i inną roślinnością szuwarową, co wymaga cierpliwości i często użycia brodzących. Zbiornik nie ma stałego połączenia z żadną rzeką, co prowadzi do jego izolacji i szybkiego nagrzewania się wody w lecie. Z tego powodu ryzyko przyduchy jest wysokie, zwłaszcza w upalne lata i mroźne zimy. Mimo to, wczesną wiosną i późną jesienią można tu liczyć na udane połowy, szczególnie karasi i linów. Jest to idealne miejsce dla wędkarzy ceniących sobie spokój i dziką przyrodę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21179, 2.8, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, późna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21180, 'Starorzecze Burzysko', 'starorzecze-burzysko-wlodawa-21180', 'OXBOW', 51.5270991, 23.5749857, 'Lubelskie', 'Włodawa', 'Starorzecze Burzysko, położone w pobliżu Włodawy, to rozległy i stosunkowo głęboki akwen, będący pozostałością po rzece Bug. Jego dno jest zróżnicowane, z partiami mulistymi, ale także z twardszymi, piaszczystymi odcinkami. Brzegi są w większości dobrze dostępne, choć miejscami mogą pojawić się pojedyncze zarośla. Starorzecze posiada stałe, choć niewielkie, połączenie z Bugiem, co zapewnia dopływ świeżej wody i migrację ryb, w tym suma. W Burzysku dominują leszcze, płocie, okonie i szczupaki, a także można tu złowić dorodne sumy. Poziom roślinności podwodnej jest umiarkowany, co ułatwia wędkowanie na spinning. Ryzyko przyduchy jest niskie ze względu na stałe połączenie. To doskonałe łowisko dla wędkarzy ceniących sobie różnorodność gatunków i komfortowy dostęp.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21180, 18, 2.8, 6.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Sum', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21181, 'Starorzecze w Spytkowicach', 'starorzecze-w-spytkowicach-spytkowice-21181', 'OXBOW', 50.0106219, 19.5365873, 'Małopolskie', 'Spytkowice', 'Starorzecze w Spytkowicach to niewielki, lecz rybny zbiornik, będący pozostałością po dawnych meandrach Wisły. Charakteryzuje się średnim zamuleniem dna, które jest zróżnicowane, z partiami mulistymi i piaszczystymi. Brzegi są w większości dostępne, choć miejscami mogą być porośnięte trawą i pojedynczymi krzewami. Starorzecze to ma okresowe połączenie z Wisłą podczas wysokiej wody, co sprzyja odświeżaniu wody i migracji ryb. Wśród dominujących gatunków znajdują się płocie, leszcze, okonie i szczupaki. Roślinność podwodna jest umiarkowana, co ułatwia łowienie, ale jednocześnie zapewnia rybom wystarczające kryjówki. Ryzyko przyduchy jest niskie. Jest to popularne miejsce dla wędkarzy poszukujących różnorodnych gatunków w spokojnej scenerii.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21181, 5.5, 1.6, 3.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21182, 'Starorzecze w Kukadle (północne)', 'starorzecze-w-kukadle-polnocne-kukadlo-21182', 'OXBOW', 51.9384011, 15.1250315, 'Lubuskie', 'Kukadło', 'To starorzecze, zlokalizowane w okolicach Kukadła, jest akwenem o umiarkowanej wielkości i znacznym zamuleniu dna. Jest to typowy zbiornik dla lina i karasia pospolitego, które znajdują tu idealne warunki do życia. Brzegi są miejscami trudno dostępne, bagniste i gęsto porośnięte trzciną, co wymaga użycia brodzących. Starorzecze nie ma stałego połączenia z rzeką, co sprzyja jego izolacji i rozwojowi specyficznej ichtiofauny. W miesiącach letnich, ze względu na płytkość i bujną roślinność, istnieje podwyższone ryzyko przyduchy. Mimo to, starorzecze oferuje wędkarzom unikalne doświadczenia i szansę na złowienie pięknych, dzikich ryb w spokojnej scenerii. Najlepsze wyniki osiąga się tu wczesnym latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21182, 4, 1.2, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21183, 'Starorzecze w Kukadle (południowe)', 'starorzecze-w-kukadle-poludniowe-kukadlo-21183', 'OXBOW', 51.9386737, 15.1221336, 'Lubuskie', 'Kukadło', 'Drugie starorzecze w rejonie Kukadła, nieco mniejsze i płytsze, charakteryzuje się bardzo wysokim zamuleniem dna i niezwykle gęstą roślinnością podwodną. Jest to prawdziwa ostoja dla karasia pospolitego i lina, które doskonale radzą sobie w tych warunkach. Brzegi są niemal w całości niedostępne z powodu gęstych zarośli i bagnistego terenu, co sprawia, że wędkowanie jest tu prawdziwym wyzwaniem. Zbiornik jest całkowicie odizolowany, co w połączeniu z jego płytkością i bujną roślinnością, powoduje bardzo wysokie ryzyko przyduchy, szczególnie w lecie. Mimo tych trudności, dla wędkarzy poszukujących dzikich i nieskażonych miejsc, starorzecze to oferuje unikalne doświadczenie i szansę na złowienie okazałych karasi w dziewiczej scenerii.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21183, 2.5, 0.7, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21184, 'Starorzecze w Mysłowicach', 'starorzecze-w-myslowicach-myslowice-21184', 'OXBOW', 50.1677613, 18.9475185, 'Śląskie', 'Mysłowice', 'To starorzecze, zlokalizowane w rejonie Mysłowic, stanowi cenny fragment przyrody w uprzemysłowionym regionie. Charakteryzuje się umiarkowanym zamuleniem dna i zróżnicowaną roślinnością, co tworzy dogodne warunki dla wielu gatunków ryb. Brzegi są częściowo dostępne, choć miejscami mogą być zarośnięte, co wymaga znalezienia odpowiednich stanowisk. Starorzecze to ma okresowe połączenie z lokalnym ciekiem wodnym, co pomaga w odświeżaniu wody. Wśród dominujących gatunków ryb znajdują się płocie, leszcze, okonie i karasie srebrzyste, a także sporadycznie szczupaki. Poziom roślinności podwodnej jest umiarkowany. Ryzyko przyduchy jest niskie ze względu na cyrkulację wody. Jest to popularne łowisko dla mieszkańców regionu, oferujące relaks i możliwość wędkowania w bliskości miasta.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21184, 6.8, 1.9, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Karaś srebrzysty,Szczupak', 'Częściowo dobry, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21185, 'Starorzecze (Biała Podlaska)', 'starorzecze-biala-podlaska-biala-podlaska-21185', 'OXBOW', 52.0214422, 23.1856828, 'Lubelskie', 'Biała Podlaska', 'To malownicze starorzecze, położone w bliskim sąsiedztwie Białej Podlaskiej, charakteryzuje się typowym dla tego regionu, płytkim dnem mulistym. Brzegi są gęsto porośnięte trzciną i inną roślinnością przybrzeżną, co utrudnia dostęp do wody, ale jednocześnie tworzy doskonałe kryjówki dla ryb. Wiosną, podczas wysokiego stanu wody, starorzecze łączy się z rzeką Krzną, co sprzyja migracji ryb. Wśród dominujących gatunków można spotkać liny, karasie pospolite, płocie oraz szczupaki, które chętnie polują w zaroślach. Ryzyko przyduchy tlenowej jest umiarkowane, zwłaszcza w upalne lata. Wędkarstwo tutaj wymaga cierpliwości i często brodzenia, ale może nagrodzić pięknymi okazami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21185, 2.8, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21186, 'Starorzecze (Biała Podlaska)', 'starorzecze-biala-podlaska-biala-podlaska-21186', 'OXBOW', 52.0269749, 23.1755601, 'Lubelskie', 'Biała Podlaska', 'Drugie starorzecze w okolicach Białej Podlaskiej to zbiornik o nieco większej powierzchni i zróżnicowanym dnie, gdzie dominują osady mułowe. Charakteryzuje się ono bardzo silnym zarośnięciem, zarówno brzegów, jak i dna, co stanowi wyzwanie dla wędkarzy, ale jednocześnie jest ostoją dla wielu gatunków ryb. Regularne połączenie z rzeką Krzną podczas wiosennych roztopów wzbogaca populację ryb. Najczęściej łowionymi gatunkami są liny, karasie pospolite, płocie oraz okonie, które doskonale czują się w gęstych zaroślach. Dostęp do wody jest utrudniony ze względu na bagniste brzegi i wymaga użycia spodniobutów. Latem istnieje podwyższone ryzyko przyduchy, dlatego najlepsze są pory roku z umiarkowanymi temperaturami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21186, 3.1, 1.7, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21187, 'Starorzecze (Biała Podlaska)', 'starorzecze-biala-podlaska-biala-podlaska-21187', 'OXBOW', 52.0275549, 23.1732121, 'Lubelskie', 'Biała Podlaska', 'To mniejsze starorzecze, również w pobliżu Białej Podlaskiej, jest przykładem zbiornika o stabilnym, choć wysokim poziomie zamulenia. Charakteryzuje się stosunkowo czystym dnem, wolnym od większych zaczepów, co ułatwia wędkowanie. Brzegi są łatwo dostępne, co czyni je popularnym miejscem dla rodzinnych wypadów. Brak stałego połączenia z rzeką sprawia, że ekosystem jest bardziej zamknięty, co sprzyja rozwojowi karasi pospolitych, wzdręg i płoci. Liny również są obecne, często osiągając imponujące rozmiary. Niestety, w okresach długotrwałych upałów, zbiornik jest podatny na przyduchy tlenowe, co wymaga monitorowania. Wiosna i wczesna jesień to najlepsze pory na udane połowy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21187, 2.5, 1.4, 2.8, 'Brak', 'Wysokie', 'Umiarkowane', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć,Lin', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21188, 'Starorzecze (Biała Podlaska)', 'starorzecze-biala-podlaska-biala-podlaska-21188', 'OXBOW', 52.028394, 23.1734666, 'Lubelskie', 'Biała Podlaska', 'To starorzecze, położone w malowniczej okolicy Białej Podlaskiej, stanowi atrakcyjne łowisko dla miłośników drapieżników. Dno jest muliste z pojedynczymi zaczepami w postaci korzeni i gałęzi, co sprzyja bytności szczupaków i okoni. Brzegi są miejscami trudno dostępne z powodu gęstych zarośli trzcinowych, co wymaga użycia spodniobutów. Okresowe połączenie z rzeką Krzną zapewnia stały dopływ świeżej wody i ryb, wzbogacając ekosystem. Poza drapieżnikami, w zbiorniku licznie występują płocie i leszcze, stanowiące bazę pokarmową. Ryzyko przyduchy tlenowej jest obecne w upalne lata, jednak ogólnie zbiornik jest stabilny. Wędkowanie jest możliwe przez cały sezon, z najlepszymi wynikami wiosną i jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21188, 3, 1.6, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21189, 'Starorzecze (Biała Podlaska)', 'starorzecze-biala-podlaska-biala-podlaska-21189', 'OXBOW', 52.0313281, 23.1707261, 'Lubelskie', 'Biała Podlaska', 'To niewielkie starorzecze w okolicach Białej Podlaskiej charakteryzuje się znacznym zamuleniem dna i bardzo silnym zarośnięciem, co sprawia, że jest to łowisko dla wytrwałych wędkarzy. Brak połączenia z rzeką sprawia, że jest to typowy zbiornik starorzeczny, idealny dla ryb ciepłolubnych i odpornych na niedobory tlenu. Dominującymi gatunkami są liny, karasie pospolite oraz wzdręgi, które doskonale radzą sobie w gęstej roślinności podwodnej. Dostęp do wody jest utrudniony przez bagniste brzegi i wymaga użycia spodniobutów. W miesiącach letnich ryzyko przyduchy tlenowej jest wysokie, dlatego należy zachować ostrożność. Najlepsze wyniki osiąga się późną wiosną i latem, zwłaszcza wczesnym rankiem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21189, 2.2, 1.3, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21190, 'Starorzecze (Biała Podlaska)', 'starorzecze-biala-podlaska-biala-podlaska-21190', 'OXBOW', 52.0322496, 23.1700077, 'Lubelskie', 'Biała Podlaska', 'Kolejne starorzecze w okolicy Białej Podlaskiej to zbiornik o umiarkowanym zamuleniu i dobrym dostępie do brzegów, co czyni go atrakcyjnym dla wędkarzy. Dno jest zróżnicowane, z miejscami mulistymi i piaszczystymi, a także pojedynczymi zaczepami. Połączenie z rzeką Krzną podczas wiosennych wezbrań zapewnia dynamikę ekosystemu i dopływ świeżej ryby. Wśród dominujących gatunków znajdują się szczupaki i okonie, które chętnie polują w zaroślach, a także liczne płocie i leszcze. Ryzyko przyduchy tlenowej jest obecne w upalne lata, ale ogólnie zbiornik jest stabilny. Dzięki dobremu dostępowi, jest to idealne miejsce na całosezonowe wędkowanie, zarówno z brzegu, jak i z pontonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21190, 2.9, 1.6, 3.1, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21191, 'Starorzecze (Biała Podlaska)', 'starorzecze-biala-podlaska-biala-podlaska-21191', 'OXBOW', 52.0327653, 23.1703093, 'Lubelskie', 'Biała Podlaska', 'Ostatnie z serii starorzeczy w rejonie Białej Podlaskiej to zbiornik o wyraźnym charakterze starorzecza, bez stałego połączenia z rzeką. Charakteryzuje się wysokim poziomem zamulenia i bardzo silnym zarośnięciem, co tworzy idealne warunki dla ryb typowych dla takich środowisk. Brzegi są bagniste i trudno dostępne, co wymaga użycia specjalistycznego sprzętu, takiego jak spodniobuty. Dominującymi gatunkami są karasie pospolite, liny, wzdręgi i płocie, które doskonale radzą sobie w gęstej roślinności i płytkich wodach. W miesiącach letnich istnieje podwyższone ryzyko przyduchy tlenowej, dlatego wędkarze powinni być świadomi tych warunków. Najlepsze wyniki osiąga się późną wiosną i latem, wykorzystując pływające przynęty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21191, 2.7, 1.5, 2.9, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21192, 'Kątowskie', 'katowskie-blachownia-21192', 'OXBOW', 51.091188, 18.9436531, 'Śląskie', 'Blachownia', 'Starorzecze Kątowskie, położone niedaleko Blachowni na Śląsku, jest stosunkowo dużym i głębokim zbiornikiem, idealnym dla różnorodnych gatunków ryb. Dno jest zróżnicowane, z miejscami mulistymi i twardszymi, a także pojedynczymi zatopionymi korzeniami. Brzegi są w większości łatwo dostępne, co sprzyja rekreacyjnemu wędkowaniu. Starorzecze okresowo łączy się z rzeką Wartą, co zapewnia dopływ świeżej wody i ryb, wzbogacając populację. Dominującymi gatunkami są szczupaki, leszcze, płocie, okonie oraz karpie, które osiągają tu imponujące rozmiary. Ryzyko przyduchy tlenowej jest niskie dzięki większej głębokości i okresowej wymianie wody. Jest to doskonałe łowisko na cały sezon, oferujące wiele możliwości dla wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21192, 7.5, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21193, 'Starorzecze (Dalewo)', 'starorzecze-dalewo-drawsko-pomorskie-21193', 'OXBOW', 53.538836, 15.8804939, 'Zachodniopomorskie', 'Drawsko Pomorskie', 'Starorzecze w okolicach Dalewa, w sercu Pomorza Zachodniego, to malowniczy zbiornik o stosunkowo niskim poziomie zamulenia i czystej wodzie. Dno jest zróżnicowane, z piaszczystymi płyciznami i głębszymi partiami z mulistym osadem. Brzegi są łatwo dostępne, często otoczone lasami, co tworzy przyjemną atmosferę do wędkowania. Podczas wiosennych roztopów starorzecze łączy się z rzeką Drawą, co sprzyja migracjom ryb i utrzymaniu zdrowego ekosystemu. Dominującymi gatunkami są szczupaki, okonie, płocie, wzdręgi i liny, które osiągają tu piękne rozmiary. Ryzyko przyduchy tlenowej jest znikome, co gwarantuje stabilne warunki przez większość roku. Najlepsze pory na wędkowanie to wiosna i wczesna jesień.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21193, 5.2, 1.8, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Wzdręga,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21194, 'Starorzecze Wisły', 'starorzecze-wisly-torun-21194', 'OXBOW', 53.0131469, 18.6781315, 'Kujawsko-Pomorskie', 'Toruń', 'To imponujące starorzecze Wisły, położone w bezpośrednim sąsiedztwie Torunia, jest jednym z największych i najgłębszych w regionie. Charakteryzuje się stałym połączeniem z głównym nurtem rzeki, co zapewnia doskonałą wymianę wody i bogactwo gatunkowe. Dno jest zróżnicowane, z głębokimi rynnami i licznymi zatopionymi drzewami, które stanowią idealne kryjówki dla drapieżników. Brzegi są w większości dobrze dostępne, choć miejscami można natknąć się na trudniejsze odcinki. Dominującymi gatunkami są leszcze, płocie, karpie, sandacze oraz sumy, które osiągają tu rekordowe rozmiary. Ze względu na stałe połączenie z Wisłą, ryzyko przyduchy tlenowej jest praktycznie zerowe. To łowisko oferuje niezliczone możliwości przez cały rok, przyciągając wędkarzy z całej Polski.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21194, 18, 3, 6.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sandacz,Sum', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21195, 'Starorzecze (Pysząca)', 'starorzecze-pyszaca-swidnica-21195', 'OXBOW', 51.254379, 16.6811639, 'Dolnośląskie', 'Świdnica', 'Starorzecze w okolicach Pyszącej na Dolnym Śląsku to urokliwy zbiornik o umiarkowanej głębokości, często odwiedzany przez lokalnych wędkarzy. Dno jest zróżnicowane, z miejscami mulistymi i twardszymi, a także pojedynczymi zaczepami, które sprzyjają bytności drapieżników. Brzegi są w większości łatwo dostępne, co ułatwia wędkowanie z gruntu i spławika. Okresowe połączenie z lokalną rzeką (np. Bystrzycą lub Odrą) podczas wysokich stanów wody zapewnia dopływ świeżej wody i ryb. Wśród dominujących gatunków można znaleźć szczupaki, okonie, leszcze, płocie oraz karpie. Ryzyko przyduchy tlenowej jest niskie dzięki okresowej wymianie wody. Wiosna i wczesna jesień to najlepsze pory na udane połowy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21195, 6, 2.2, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21196, 'Starorzecze (Dąbrówka Królewska)', 'starorzecze-dabrowka-krolewska-grudziadz-21196', 'OXBOW', 53.5010633, 18.9018757, 'Kujawsko-Pomorskie', 'Grudziądz', 'Starorzecze w Dąbrówce Królewskiej, niedaleko Grudziądza, to duży i głęboki zbiornik, będący częścią systemu starorzeczy Wisły. Charakteryzuje się stałym połączeniem z rzeką, co gwarantuje bogactwo gatunków i doskonałą jakość wody. Dno jest zróżnicowane, z licznymi zatopionymi drzewami i podwodnymi przeszkodami, które stanowią schronienie dla wielu ryb. Brzegi są w większości łatwo dostępne, choć w niektórych miejscach mogą być zarośnięte. Dominującymi gatunkami są leszcze, płocie, karpie, sandacze oraz szczupaki, które osiągają tu imponujące rozmiary. Dzięki stałemu połączeniu z Wisłą, ryzyko przyduchy tlenowej jest minimalne. To łowisko jest idealne dla wędkarzy poszukujących dużych okazów przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21196, 9, 2.5, 5.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sandacz,Szczupak', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21197, 'Starorzecze (Rogóźno-Zamek)', 'starorzecze-rogozno-zamek-rogozno-21197', 'OXBOW', 53.5160712, 18.949504, 'Kujawsko-Pomorskie', 'Rogóźno', 'Pierwsze ze starorzeczy w okolicach Rogóźna-Zamek, w województwie kujawsko-pomorskim, to średniej wielkości zbiornik charakteryzujący się umiarkowaną głębokością i zróżnicowanym dnem. Dno jest mieszane, z mulistymi i twardszymi fragmentami, wzbogacone o pojedyncze zatopione korzenie i gałęzie. Brzegi są ogólnie dobrze dostępne, co sprzyja wędkowaniu z brzegu. Starorzecze okresowo łączy się z pobliską rzeką, co zapewnia regularne odświeżanie wody i dopływ nowych ryb. Wśród dominujących gatunków znajdują się szczupaki, okonie, płocie i leszcze, które dobrze czują się w tym środowisku. Ryzyko przyduchy tlenowej jest niskie, co czyni je stabilnym łowiskiem. Najlepsze pory na wędkowanie to wiosna i wczesna jesień, zwłaszcza na spinning.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21197, 4.5, 1.9, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21198, 'Starorzecze (Rogóźno-Zamek)', 'starorzecze-rogozno-zamek-rogozno-21198', 'OXBOW', 53.5082068, 18.9656224, 'Kujawsko-Pomorskie', 'Rogóźno', 'Drugie starorzecze w pobliżu Rogóźna-Zamek to mniejszy zbiornik, który utracił stałe połączenie z rzeką, stając się typowym, zamkniętym ekosystemem. Charakteryzuje się wysokim poziomem zamulenia i bardzo silnym zarośnięciem, co tworzy idealne warunki dla ryb odpornych na trudne warunki. Dno jest w dużej mierze pokryte gęstą roślinnością podwodną, co utrudnia wędkowanie, ale sprzyja bytowaniu linów, karasi pospolitych, wzdręg i płoci. Brzegi są bagniste i trudno dostępne, często wymagając użycia spodniobutów. Niestety, w miesiącach letnich istnieje podwyższone ryzyko przyduchy tlenowej, dlatego należy zachować ostrożność. Najlepsze wyniki osiąga się późną wiosną i latem, zwłaszcza wczesnym rankiem lub późnym wieczorem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21198, 3.8, 1.7, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21199, 'Starorzecze (Warszawa)', 'starorzecze-warszawa-warszawa-21199', 'OXBOW', 52.2097176, 21.0962567, 'Mazowieckie', 'Warszawa', 'To obszerne starorzecze, położone w granicach Warszawy, jest jednym z najbardziej dostępnych i popularnych łowisk w regionie. Charakteryzuje się stałym połączeniem z Wisłą, co zapewnia ciągły dopływ świeżej wody i różnorodność gatunkową ryb. Dno jest zróżnicowane, z głębszymi partiami i licznymi podwodnymi przeszkodami, takimi jak pojedyncze korzenie i gałęzie. Brzegi są w większości dobrze utrzymane i łatwo dostępne, co sprzyja rekreacyjnemu wędkowaniu. Wśród dominujących gatunków znajdują się leszcze, płocie, karpie, sandacze, szczupaki, a także bolenie, które często polują na powierzchni. Dzięki stałemu połączeniu z rzeką, ryzyko przyduchy tlenowej jest minimalne. To łowisko oferuje doskonałe możliwości wędkarskie przez cały rok, zarówno dla początkujących, jak i doświadczonych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21199, 10.5, 2.8, 6, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sandacz,Szczupak,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21200, 'Starorzecze (Waniewo)', 'starorzecze-waniewo-waniewo-21200', 'OXBOW', 53.0714255, 22.8271679, 'Podlaskie', 'Waniewo', 'To starorzecze, zlokalizowane w malowniczej dolinie Narwi, charakteryzuje się typowym dla tego regionu, bogatym ekosystemem. Dno jest muliste, miejscami twarde, z licznymi zatopionymi gałęziami i korzeniami, co sprzyja bytności wielu gatunków ryb. Brzegi są w większości porośnięte gęstą trzciną i inną roślinnością szuwarową, co utrudnia dostęp, ale jednocześnie stanowi doskonałe schronienie dla ryb i ptactwa wodnego. Wiosną i podczas wysokiej wody starorzecze łączy się z głównym nurtem Narwi, co zapewnia wymianę fauny. Dominującymi gatunkami są szczupak, lin i karaś pospolity, a także liczne płocie i wzdręgi. Wędkowanie wymaga cierpliwości i często brodzenia, ale może przynieść satysfakcjonujące rezultaty, zwłaszcza w poszukiwaniu większych drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21200, 4.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć,Okoń', 'Trudny, miejscami bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21201, 'Starorzecze (Jeńki)', 'starorzecze-jenki-jenki-21201', 'OXBOW', 53.071609, 22.8313643, 'Podlaskie', 'Jeńki', 'Starorzecze w Jeńkach to typowy akwen doliny Narwi, cechujący się znacznym zarastaniem i płytkim dnem. Muliste podłoże, bogate w materię organiczną, sprzyja rozwojowi bujnej roślinności podwodnej, takiej jak rdestnice i wywłócznik. Brzegi są gęsto porośnięte trzciną i krzewami, co sprawia, że dostęp do wody jest bardzo ograniczony i wymaga często użycia brodzaków. Łowisko jest idealne dla wędkarzy poszukujących lina, karasia pospolitego oraz wzdręgi, które znajdują tu doskonałe warunki do życia i rozrodu. W cieplejszych miesiącach, szczególnie przy niskim poziomie wody, istnieje ryzyko przyduchy. Wędkowanie z pontonu lub kajaka może być efektywniejsze niż z brzegu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21201, 3.1, 1.2, 2.9, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21202, 'Starorzecze (Izbiszcze)', 'starorzecze-izbiszcze-izbiszcze-21202', 'OXBOW', 53.0756536, 22.8383984, 'Podlaskie', 'Izbiszcze', 'Akwen w Izbiszczach to rozległe starorzecze o charakterze typowo nadrzecznym, zlokalizowane w obrębie obszarów chronionych. Dno jest zróżnicowane – od piaszczystych płycizn po głębsze, muliste rynny, a brzegi są częściowo dostępne, choć w wielu miejscach osłonięte wysoką roślinnością szuwarową. Starorzecze to jest prawdziwym rajem dla miłośników spławika i lekkiego gruntu, oferując obfitość płoci, leszczy i karasi srebrzystych. Zdarzają się tu również dorodne szczupaki i okonie, polujące w zaroślach. Połączenie z rzeką podczas wiosennych rozlewisk sprzyja odświeżaniu wody i zasilaniu populacji ryb. Wędkowanie w tym miejscu wymaga niekiedy długich spacerów, ale nagrodą jest cisza, spokój i możliwość obcowania z dziką naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21202, 6.8, 1.8, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Karaś srebrzysty', 'Częściowo dobry, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21203, 'Starorzecze (Brzoza)', 'starorzecze-brzoza-brzoza-21203', 'OXBOW', 52.9434005, 18.7045395, 'Kujawsko-Pomorskie', 'Brzoza', 'To starorzecze, położone w pobliżu Brzozy, jest reliktem dawnego koryta Wisły, co nadaje mu specyficzny charakter. Dno jest przeważnie muliste, ale miejscami występują twardsze, piaszczyste odcinki, szczególnie w dawnych zakolach. Brzegi są zróżnicowane – od łatwo dostępnych, trawiastych fragmentów, po gęsto zarośnięte pasy trzcin i krzewów, które stanowią doskonałe kryjówki dla ryb. W starorzeczu tym dominuje leszcz, płoć i okoń, a także można spotkać okazałe karpie, które żerują na mulistym dnie. Akwen ten jest dość stabilny pod względem poziomu wody, co ogranicza ryzyko przyduchy. Wędkowanie gruntowe i spławikowe jest tutaj bardzo popularne i często przynosi dobre wyniki, zwłaszcza w cieplejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21203, 8.5, 2, 5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Okoń,Szczupak', 'Dobry z niektórych miejsc, inne mocno zarośnięte', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21204, 'Kamienny Dół', 'kamienny-dol-brzoza-21204', 'OXBOW', 52.944693, 18.703867, 'Kujawsko-Pomorskie', 'Brzoza', 'Kamienny Dół to niewielkie, ale głębokie starorzecze, które wyróżnia się na tle innych akwenów w regionie. Dno jest częściowo kamieniste, co jest rzadkością dla starorzeczy, a częściowo muliste w głębszych partiach. Brzegi są strome i miejscami skaliste, ale dostępne w kilku punktach, co ułatwia wędkowanie. To wyjątkowe miejsce jest znane z występowania dużych okoni i szczupaków, które znajdują tu idealne warunki do polowania. Można tu również złowić lina i karasia pospolitego, zwłaszcza w płytszych, bardziej zarośniętych zatokach. Wędkarze spinningowi cenią sobie to łowisko za jego potencjał drapieżników. Należy jednak uważać na liczne zaczepy, szczególnie w pobliżu kamienistego dna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21204, 2.1, 2.8, 6.2, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Okoń,Szczupak,Lin,Karaś pospolity', 'Trudny, strome brzegi, ale kilka dobrych stanowisk', FALSE, 'Dużo kamieni i zatopionych gałęzi', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21205, 'Starorzecze (Grodzisko) - Zator 1', 'starorzecze-grodzisko-zator-1-zator-21205', 'OXBOW', 49.9567921, 19.4585763, 'Małopolskie', 'Zator', 'Starorzecze w Grodzisku koło Zatora to jeden z wielu akwenów tego typu w regionie, charakteryzujący się typowo rzecznym pochodzeniem. Dno jest przeważnie muliste, z lokalnymi płyciznami i zalanymi krzewami, które tworzą doskonałe kryjówki dla ryb. Brzegi są w większości mocno zarośnięte trzciną i inną roślinnością szuwarową, co utrudnia dostęp, ale jednocześnie świadczy o naturalnym charakterze łowiska. W akwenie tym dominują leszcze, płocie i karasie, a także można liczyć na spotkanie z dorodnym linem. Wędkowanie wymaga cierpliwości i często poszukiwania wolnych miejsc między zaroślami. Wiosenne rozlewiska Wisły mogą czasowo łączyć starorzecze z rzeką, wzbogacając jego faunę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21205, 5.5, 1.7, 4, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Leszcz,Płoć,Karaś pospolity,Lin,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21206, 'Starorzecze (Grodzisko) - Zator 2', 'starorzecze-grodzisko-zator-2-zator-21206', 'OXBOW', 49.954404, 19.4615011, 'Małopolskie', 'Zator', 'To starorzecze, również w okolicy Grodziska, jest nieco bardziej otwarte i charakteryzuje się większą powierzchnią lustra wody. Dno jest zróżnicowane, z przewagą mułu, ale z kilkoma twardszymi, piaszczystymi fragmentami. Brzegi są częściowo dostępne, z kilkoma wygodnymi stanowiskami wędkarskimi, jednak w wielu miejscach nadal dominują trzcinowiska. Jest to doskonałe miejsce do łowienia płoci, leszczy i karasi srebrzystych, które występują tu licznie. W głębszych partiach można liczyć na spotkanie z okazałym szczupakiem lub sumem, zwłaszcza w pobliżu zatopionych krzewów. Wędkowanie gruntowe i spławikowe jest tutaj bardzo efektywne. Akwen ten jest stosunkowo stabilny, co minimalizuje ryzyko problemów z natlenieniem wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21206, 7.2, 2.1, 5.2, 'Brak', 'Umiarkowane', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Karaś srebrzysty,Szczupak,Sum', 'Dobry z niektórych miejsc', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21207, 'Starorzecze (Grodzisko) - Zator 3', 'starorzecze-grodzisko-zator-3-zator-21207', 'OXBOW', 49.954888, 19.4575381, 'Małopolskie', 'Zator', 'Starorzecze to jest mniejsze i bardziej kameralne, zlokalizowane w gęstych zaroślach. Dno jest w przeważającej części muliste, z dużą ilością zalegających liści i gałęzi, co tworzy idealne warunki dla ryb dennych. Brzegi są bardzo trudne do pokonania, gęsto porośnięte krzewami i drzewami, które zwisają nad wodą, tworząc naturalne daszki. Jest to typowe łowisko linowo-karasiowe, gdzie cierpliwy wędkarz może liczyć na naprawdę piękne okazy. Występują tu również wzdręgi i niewielkie okonie. Ze względu na swoje położenie i otoczenie, starorzecze to jest idealne dla wędkarzy ceniących sobie ciszę i spokój, z dala od zgiełku. Wędkowanie wymaga precyzyjnych rzutów i umiejętności omijania zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21207, 1.8, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Trudny, mocno zarośnięty', TRUE, 'Dużo zatopionych drzew i gałęzi', 'Późna wiosna i wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21208, 'Starorzecze (Grodzisko) - Zator 4', 'starorzecze-grodzisko-zator-4-zator-21208', 'OXBOW', 49.9505788, 19.4578318, 'Małopolskie', 'Zator', 'To starorzecze stanowi część większego kompleksu wodnego w okolicach Grodziska, charakteryzując się umiarkowanym rozmiarem i dobrym potencjałem wędkarskim. Dno jest mieszane – od twardych, żwirowych partii po miękkie, muliste osady, co sprzyja różnorodności gatunków ryb. Brzegi są stosunkowo łatwo dostępne w kilku miejscach, co ułatwia wędkowanie z brzegu, choć wciąż występują obszary zarośnięte trzciną. W akwenie tym można liczyć na dobre połowy leszczy, płoci i karasi srebrzystych. Często spotyka się tu również szczupaki i okonie, zwłaszcza w pobliżu podwodnych zarośli i zatopionych przeszkód. Starorzecze to jest popularne wśród lokalnych wędkarzy ze względu na stabilne warunki i regularne zarybienia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21208, 4, 1.6, 3.7, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karaś srebrzysty,Szczupak,Okoń', 'Dobry z niektórych stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21209, 'Starorzecze (Siemiechów)', 'starorzecze-siemiechow-siemiechow-21209', 'OXBOW', 51.4333264, 18.8302992, 'Łódzkie', 'Siemiechów', 'Starorzecze w Siemiechowie to malowniczy zbiornik wodny, będący pozostałością po dawnych meandrach rzeki Warty. Charakteryzuje się płytkim dnem, które w większości pokryte jest grubą warstwą mułu i bogatą roślinnością podwodną, tworzącą doskonałe siedliska dla wielu gatunków ryb. Brzegi są przeważnie zarośnięte trzciną i inną roślinnością szuwarową, co utrudnia dostęp, ale jednocześnie zapewnia spokój i intymność wędkowania. W akwenie tym dominują liny, karasie pospolite i wzdręgi, które znajdują tu idealne warunki do życia. W cieplejszych miesiącach, zwłaszcza latem, istnieje podwyższone ryzyko przyduchy ze względu na dużą ilość materii organicznej. Wędkowanie wymaga cierpliwości i często poszukiwania wolnych od zarośli miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21209, 2.7, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21210, 'Starorzecze (Arciechów)', 'starorzecze-arciechow-arciechow-21210', 'OXBOW', 52.5008172, 21.089889, 'Mazowieckie', 'Arciechów', 'Starorzecze w Arciechowie to rozległy akwen, położony w bliskim sąsiedztwie Narwi i Jeziora Zegrzyńskiego, co wpływa na jego bogactwo ichtiofauny. Dno jest zróżnicowane, od piaszczystych płycizn po głębsze, muliste rynny, a brzegi są częściowo zagospodarowane, z kilkoma pomostami i łatwo dostępnymi stanowiskami. Jest to popularne łowisko, gdzie można złowić leszcze, płocie, liny, a także okazałe szczupaki i sandacze, które wpływają tu z Narwi. Okresowe połączenia z rzeką zapewniają stałe zasilanie w świeżą wodę i migrację ryb. Wędkowanie z brzegu jest wygodne, ale warto również spróbować z łodzi, aby dotrzeć do głębszych partii i podwodnych przeszkód. To starorzecze oferuje dobre warunki przez większość sezonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21210, 12.5, 2.5, 6, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Sandacz,Lin', 'Dobry z wielu stron, częściowo zagospodarowany', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21211, 'Starorzecze (Brzoza) - drugie', 'starorzecze-brzoza-drugie-brzoza-21211', 'OXBOW', 52.9537433, 18.7032814, 'Kujawsko-Pomorskie', 'Brzoza', 'To drugie starorzecze w pobliżu Brzozy, choć mniejsze od poprzedniego, oferuje równie ciekawe warunki wędkarskie. Dno jest głównie muliste, z licznymi podwodnymi zaroślami i zatopionymi gałęziami, które stanowią doskonałe kryjówki dla ryb. Brzegi są gęsto porośnięte trzciną i roślinnością szuwarową, co sprawia, że dostęp jest utrudniony i wymaga często brodzenia. Jest to idealne miejsce dla wędkarzy poszukujących lina, karasia pospolitego oraz wzdręgi. Występują tu również szczupaki i okonie, polujące w zaroślach. Akwen jest dość płytki, co w upalne lata zwiększa ryzyko niedoboru tlenu. Cierpliwość i odpowiedni sprzęt są kluczem do sukcesu na tym łowisku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21211, 3.5, 1.3, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak,Okoń', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21212, 'Starorzecze (Ruda Śląska)', 'starorzecze-ruda-slaska-ruda-slaska-21212', 'OXBOW', 50.2335863, 18.88466, 'Śląskie', 'Ruda Śląska', 'Starorzecze w Rudzie Śląskiej to unikalny akwen, położony w silnie zurbanizowanym terenie, co nadaje mu specyficzny charakter. Dno jest przeważnie muliste, z lokalnymi zanieczyszczeniami, ale wciąż stanowi schronienie dla ryb. Brzegi są częściowo utwardzone, a częściowo porośnięte roślinnością, co zapewnia zmienny dostęp do wody. Mimo bliskości miasta, w starorzeczu tym można złowić leszcze, płocie i karasie srebrzyste, które przystosowały się do lokalnych warunków. Zdarzają się tu również okonie i niewielkie szczupaki. Akwen ten jest poddawany okresowym kontrolom jakości wody, co minimalizuje ryzyko poważnych zanieczyszczeń. Wędkowanie tutaj to dobra okazja na szybki wypad po pracy, bez konieczności dalekich podróży.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21212, 1.5, 1.1, 2.8, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Karaś srebrzysty,Okoń', 'Częściowo dobry, częściowo zarośnięty', FALSE, 'Pojedyncze korzenie i śmieci', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21213, 'Starorzecze (Międzyrzecze)', 'starorzecze-miedzyrzecze-miedzyrzecze-gorne-21213', 'OXBOW', 50.0243824, 19.0796187, 'Śląskie', 'Międzyrzecze Górne', 'Starorzecze w Międzyrzeczu to malowniczy akwen, położony w zielonym otoczeniu, będący pozostałością po dawnych meandrach rzeki. Dno jest przeważnie muliste, z licznymi podwodnymi zaroślami i zatopionymi gałęziami, co tworzy idealne warunki dla ryb. Brzegi są w większości mocno zarośnięte trzciną i krzewami, co wymaga poszukiwania wolnych stanowisk lub użycia brodzaków. W akwenie tym dominują liny, karasie pospolite i wzdręgi, a także można liczyć na spotkanie z okazałym szczupakiem, który poluje w zaroślach. Starorzecze to jest stosunkowo płytkie, co w upalne lato może prowadzić do niedoboru tlenu. Wędkowanie tutaj to prawdziwa gratka dla miłośników spokojnego łowienia w naturalnym środowisku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21213, 3.8, 1.4, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga,Okoń', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21214, 'Starorzecze (Zajki)', 'starorzecze-zajki-zajki-21214', 'OXBOW', 53.2111261, 22.5885239, 'Podlaskie', 'Zajki', 'Starorzecze w Zajkach to rozległy akwen, położony w sercu Podlasia, charakteryzujący się dzikim i naturalnym charakterem. Dno jest muliste, z licznymi nierównościami i dużą ilością zatopionych drzew oraz gałęzi, co tworzy doskonałe kryjówki dla ryb drapieżnych. Brzegi są w większości niedostępne, porośnięte gęstymi zaroślami, trzciną i bagnistymi terenami, co sprawia, że wędkowanie jest wyzwaniem. Jest to prawdziwy raj dla szczupaków i sumów, które osiągają tu imponujące rozmiary. Można tu również złowić liny i karasie pospolite, szczególnie w płytszych, bardziej zarośniętych zatokach. Akwen ten jest głęboki i stabilny, co ogranicza ryzyko problemów z natlenieniem. Wędkowanie z łodzi lub pontonu jest tutaj zdecydowanie najbardziej efektywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21214, 9.5, 2.2, 5.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', FALSE, FALSE, 'Szczupak,Sum,Lin,Karaś pospolity,Okoń', 'Bardzo trudny, bagnisty i zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21215, 'Starorzecze (Zajki)', 'starorzecze-zajki-wizna-21215', 'OXBOW', 53.2106538, 22.581058, 'Podlaskie', 'Wizna', 'To malownicze starorzecze, położone w zakolu rzeki Narew, stanowi klasyczne łowisko dla wędkarzy poszukujących spokoju i dzikiej przyrody. Dno jest muliste z licznymi zatopionymi drzewami i korzeniami, co utrudnia wędkowanie, ale sprzyja ukrywaniu się ryb. Brzegi są często bagniste i trudno dostępne, co wymaga użycia wodoodpornego obuwia lub pontonu. Roślinność podwodna i przybrzeżna jest umiarkowana, ale w niektórych miejscach tworzy gęste zarośla. W starorzeczu dominują takie gatunki jak lin, szczupak, karaś pospolity i płoć. Ze względu na ograniczoną wymianę wody, w upalne lata istnieje ryzyko przyduchy, co może wpływać na aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21215, 3.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Karaś pospolity,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21216, 'Starorzecze (Kopanka 1)', 'starorzecze-kopanka-1-skawina-21216', 'OXBOW', 49.989374, 19.7874045, 'Małopolskie', 'Skawina', 'To starorzecze, ściśle związane z Wisłą, charakteryzuje się stałym połączeniem z rzeką, co zapewnia doskonałą wymianę wody i bogactwo gatunkowe. Dno jest przeważnie twarde, piaszczysto-żwirowe, z niewielką ilością mułu i pojedynczymi zaczepami. Brzegi są łatwo dostępne z obu stron, co ułatwia wędkowanie z brzegu. Roślinność wodna jest umiarkowana, głównie w postaci pasów trzcin i grążeli, tworząc naturalne kryjówki dla ryb. Wśród dominujących gatunków ryb znajdziemy tu leszcza, płoć, karpia, suma, szczupaka i jazia, co czyni to miejsce atrakcyjnym dla różnych technik. Łowisko to jest polecane przez cały sezon, oferując stabilne warunki do wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21216, 2.8, 1.8, 3.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sum,Szczupak,Jaź', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21217, 'Starorzecze (Kopanka 2)', 'starorzecze-kopanka-2-skawina-21217', 'OXBOW', 49.9885342, 19.7872144, 'Małopolskie', 'Skawina', 'To mniejsze starorzecze w okolicy Kopanki, odcinane od głównego nurtu Wisły, ma połączenie z rzeką jedynie podczas wysokich stanów wody. Dno jest mocno zamulone, a w wielu miejscach pokryte gęstą roślinnością podwodną, co stanowi wyzwanie dla wędkarzy. Brzegi są silnie zarośnięte trzciną i inną roślinnością przybrzeżną, co znacznie utrudnia dostęp do wody i wymaga brodzenia. W płytkich partiach zbiornika silne nasłonecznienie i brak tlenu mogą stanowić problem latem. Dominujące gatunki to lin, karaś pospolity, wzdręga i mniejsze szczupaki, doskonale przystosowane do trudniejszych warunków. Najlepsze efekty daje tu wędkowanie późną wiosną i latem, zwłaszcza na spławik.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21217, 1.5, 1.2, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21218, 'Starorzecze (Piotrowo 1)', 'starorzecze-piotrowo-1-grudziadz-21218', 'OXBOW', 53.5058589, 18.9740024, 'Kujawsko-Pomorskie', 'Grudziądz', 'Obszerne starorzecze w pobliżu Piotrowa, posiadające stałe połączenie z Wisłą, jest cenionym łowiskiem o stabilnych warunkach. Dno jest zróżnicowane, od piaszczystych płycizn po głębsze, muliste rynny, lecz ogólnie czyste od większych zaczepów. Brzegi są w większości dobrze dostępne, oferując komfortowe miejsca do wędkowania z brzegu. Roślinność wodna jest umiarkowana, głównie w postaci pasów trzcin i niewielkich skupisk grążeli. W starorzeczu licznie występują leszcz, płoć, sandacz, szczupak, okoń i kleń, co przyciąga zarówno spinningistów, jak i wędkarzy gruntowych. Jest to łowisko całoroczne, atrakcyjne dla wielu technik wędkarskich, choć zimą wymaga cierpliwości.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21218, 4.2, 2, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Sandacz,Szczupak,Okoń,Kleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21219, 'Starorzecze (Piotrowo 2)', 'starorzecze-piotrowo-2-grudziadz-21219', 'OXBOW', 53.5073311, 18.9675684, 'Kujawsko-Pomorskie', 'Grudziądz', 'To mniejsze starorzecze w okolicy Piotrowa, które łączy się z Wisłą tylko podczas wiosennych roztopów lub jesiennych wezbrań, co wpływa na jego charakter. Dno jest muliste, z pojedynczymi korzeniami i gałęziami, które mogą stanowić zaczepy. Brzegi są trudne do pokonania, często bagniste, wymagające użycia wodoodpornego obuwia. Roślinność wodna jest umiarkowana, ale w cieplejszych miesiącach może tworzyć gęste dywany. W upalne lato istnieje ryzyko niedoboru tlenu, zwłaszcza w płytkich partiach. Dominujące gatunki to lin, karaś pospolity, szczupak i okoń, które dobrze radzą sobie w tych warunkach. Wędkowanie jest najbardziej efektywne wiosną i wczesną jesienią, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21219, 2.1, 1.3, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21220, 'Starorzecze (Michalków)', 'starorzecze-michalkow-terespol-21220', 'OXBOW', 52.0502627, 23.6497037, 'Lubelskie', 'Terespol', 'To płytkie starorzecze w rejonie Michalkowa, charakteryzujące się znacznym stopniem zamulenia i silnym zarastaniem. Dno jest bardzo miękkie, muliste, z gęstą roślinnością podwodną, co sprawia, że wędkowanie jest tu prawdziwym wyzwaniem. Brzegi są praktycznie niedostępne, gęsto porośnięte trzciną i inną roślinnością szuwarową, wymuszając brodzenie lub poszukiwanie nielicznych prześwitów. Ze względu na małą głębokość i ograniczoną wymianę wody, zbiornik jest podatny na wysychanie w okresach suszy oraz na przyduchę. Głównymi mieszkańcami są karaś pospolity, lin, wzdręga, karaś srebrzysty i płoć, które są odporne na trudne warunki środowiskowe. Najlepsze efekty daje tu wędkowanie w miesiącach ciepłych, zwłaszcza na spławik lub lekką gruntówkę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21220, 1.8, 1, 2.2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Karaś srebrzysty,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21221, 'Starorzecze (Grudziądz 1)', 'starorzecze-grudziadz-1-grudziadz-21221', 'OXBOW', 53.5141431, 18.8509161, 'Kujawsko-Pomorskie', 'Grudziądz', 'To duże starorzecze w granicach Grudziądza, odznaczające się stałym połączeniem z Wisłą, co gwarantuje dynamiczną wymianę wody i obfitość ryb. Dno jest twarde, przeważnie piaszczyste, z niewielką ilością mułu i praktycznie pozbawione zaczepów, co ułatwia wędkowanie. Brzegi są łatwo dostępne z obu stron, często utwardzone i przygotowane dla wędkarzy. Roślinność wodna jest umiarkowana, ograniczająca się do pasów trzcin i niewielkich kęp grążeli, zapewniając rybom schronienie. W starorzeczu dominują leszcz, płoć, sum, sandacz i szczupak, co czyni je atrakcyjnym dla szerokiego spektrum technik wędkarskich. Jest to popularne łowisko całoroczne, szczególnie cenione przez wędkarzy gruntowych i spinningistów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21221, 5, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Sum,Sandacz,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21222, 'Starorzecze (Grudziądz 2)', 'starorzecze-grudziadz-2-grudziadz-21222', 'OXBOW', 53.5148921, 18.8492734, 'Kujawsko-Pomorskie', 'Grudziądz', 'Mniejsze starorzecze w Grudziądzu, które łączy się z Wisłą podczas wyższych stanów wody, oferuje nieco odmienny charakter niż jego większy sąsiad. Dno jest muliste, z pojedynczymi korzeniami i gałęziami, które mogą stanowić naturalne zaczepy. Brzegi są dobrze dostępne, jednak miejscami mogą być bardziej miękkie, co wymaga ostrożności. Roślinność wodna jest umiarkowana, tworząc dogodne kryjówki dla drapieżników i ryb spokojnego żeru. Ryzyko niedoboru tlenu jest niskie, co zapewnia stabilne warunki dla ryb. Wśród dominujących gatunków znajdziemy tu karpia, lina, szczupaka i okonia, które dobrze czują się w tym środowisku. Najlepsze okresy na wędkowanie to wiosna i wczesna jesień, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21222, 3.1, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Lin,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21223, 'Starorzecze (Łęgi)', 'starorzecze-legi-biala-podlaska-21223', 'OXBOW', 52.1691085, 23.4765797, 'Lubelskie', 'Biała Podlaska', 'To urokliwe starorzecze w okolicach Łęgów, charakteryzujące się okresowym połączeniem z rzeką Bug, co wpływa na jego ekosystem. Dno jest mocno zamulone i obfituje w gęstą roślinność podwodną, co stanowi wyzwanie dla wędkarzy, ale jednocześnie jest idealnym środowiskiem dla ryb. Brzegi są silnie zarośnięte trzciną i inną roślinnością szuwarową, co utrudnia dostęp do wody i często wymaga brodzenia. Istnieje podwyższone ryzyko niedoboru tlenu w upalne lata, co może wpływać na aktywność ryb. Dominujące gatunki to lin, karaś pospolity, wzdręga i szczupak, które dobrze adaptują się do tych warunków. Najlepsze efekty wędkarskie osiąga się późną wiosną i latem, zwłaszcza wczesnym rankiem lub wieczorem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21223, 2, 1.4, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21224, 'Starorzecze (Kraski Górne)', 'starorzecze-kraski-gorne-maciejowice-21224', 'OXBOW', 51.6998351, 21.4650925, 'Mazowieckie', 'Maciejowice', 'To duże, izolowane starorzecze w rejonie Krasków Górnych, które utraciło stałe połączenie z Wisłą, co nadało mu charakter zbiornika zamkniętego. Dno jest silnie zamulone, a w wodzie znajduje się wiele zatopionych drzew i gałęzi, co tworzy liczne zaczepy i utrudnia wędkowanie. Brzegi są trudne do pokonania, często bagniste i porośnięte gęstą roślinnością, co wymaga użycia wodoodpornego obuwia. Roślinność wodna jest umiarkowana, ale w niektórych miejscach tworzy rozległe dywany, będące schronieniem dla ryb. Ze względu na brak wymiany wody, w upalne lata istnieje wysokie ryzyko przyduchy. W starorzeczu dominują lin, karaś pospolity, szczupak, okoń i karp, które dobrze radzą sobie w tych specyficznych warunkach. Najlepsze pory na wędkowanie to wiosna i wczesna jesień.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21224, 6, 2.2, 4.5, 'Brak', 'Wysokie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń,Karp', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21225, 'Starorzecze (Rygol 1)', 'starorzecze-rygol-1-augustow-21225', 'OXBOW', 53.8856751, 23.4574356, 'Podlaskie', 'Augustów', 'To starorzecze w okolicach Rygola, charakteryzujące się stałym połączeniem z systemem rzecznym Czarna Hańcza/Kanał Augustowski, co zapewnia dobrą jakość wody. Dno jest zróżnicowane, od piaszczystych po lekko muliste, z pojedynczymi korzeniami i gałęziami, które mogą stanowić zaczepy. Brzegi są w większości dobrze dostępne, co ułatwia wędkowanie z brzegu. Roślinność wodna jest umiarkowana, głównie w postaci pasów trzcin i grążeli, tworząc naturalne kryjówki dla ryb. W starorzeczu licznie występują szczupak, okoń, płoć, leszcz i węgorz, co przyciąga zarówno spinningistów, jak i wędkarzy gruntowych. Jest to łowisko całoroczne, oferujące stabilne warunki do wędkowania i różnorodność gatunkową.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21225, 2.5, 1.5, 3, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz,Węgorz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21226, 'Starorzecze (Rygol 2)', 'starorzecze-rygol-2-augustow-21226', 'OXBOW', 53.886999, 23.4559865, 'Podlaskie', 'Augustów', 'Mniejsze i płytsze starorzecze w rejonie Rygola, które łączy się z głównym nurtem jedynie podczas wysokich stanów wody, co wpływa na jego ekosystem. Dno jest silnie zamulone i obfituje w gęstą roślinność podwodną, co sprawia, że wędkowanie jest tu wyzwaniem. Brzegi są trudne do pokonania, często bagniste i gęsto porośnięte trzciną, wymagając brodzenia lub poszukiwania otwartych miejsc. Ze względu na małą głębokość i ograniczoną wymianę wody, w upalne lata istnieje wysokie ryzyko przyduchy. Głównymi mieszkańcami są lin, karaś pospolity i wzdręga, które są doskonale przystosowane do trudnych warunków. Najlepsze efekty daje tu wędkowanie późną wiosną i latem, zwłaszcza w płytkich, zarośniętych partiach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21226, 1.2, 0.8, 1.8, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21227, 'Starorzecze (Santok 1)', 'starorzecze-santok-1-santok-21227', 'OXBOW', 52.7544413, 15.4660007, 'Lubuskie', 'Santok', 'To rozległe starorzecze w pobliżu Santoka, z permanentnym połączeniem z Wartą, co zapewnia doskonałą jakość wody i bogactwo ichtiofauny. Dno jest przeważnie twarde, piaszczyste lub żwirowe, z minimalną ilością mułu i praktycznie bez zaczepów, co sprzyja różnym technikom wędkarskim. Brzegi są dobrze dostępne z większości stron, często z wygodnymi stanowiskami dla wędkarzy. Roślinność wodna jest umiarkowana, ograniczająca się do pasów trzcin i niewielkich skupisk grążeli, zapewniając rybom schronienie. W starorzeczu dominują sum, sandacz, leszcz, szczupak i boleń, co czyni je atrakcyjnym dla wędkarzy poszukujących dużych drapieżników i ryb spokojnego żeru. Jest to łowisko całoroczne, cenione za stabilne warunki i obfitość ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21227, 7, 2.8, 6, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Sandacz,Leszcz,Szczupak,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21228, 'Starorzecze (Santok 2)', 'starorzecze-santok-2-santok-21228', 'OXBOW', 52.7520095, 15.4586247, 'Lubuskie', 'Santok', 'To starorzecze w okolicach Santoka, które łączy się z Wartą jedynie podczas wysokich stanów wody, co wpływa na jego dynamikę. Dno jest muliste, z licznymi zatopionymi drzewami i korzeniami, które stanowią naturalne zaczepy, ale także schronienia dla ryb. Brzegi są trudne do pokonania, często bagniste i porośnięte gęstą roślinnością, co wymaga użycia wodoodpornego obuwia. Roślinność wodna jest umiarkowana, ale w cieplejszych miesiącach może tworzyć rozległe dywany. W upalne lato istnieje podwyższone ryzyko niedoboru tlenu, co może wpływać na aktywność ryb. Dominujące gatunki to lin, karaś pospolity, szczupak i okoń, które dobrze radzą sobie w tych warunkach. Najlepsze pory na wędkowanie to wiosna i wczesna jesień.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21228, 3, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21229, 'Starorzecze (Santok 3)', 'starorzecze-santok-3-santok-21229', 'OXBOW', 52.747988, 15.4506424, 'Lubuskie', 'Santok', 'To najmniejsze i najbardziej izolowane starorzecze w rejonie Santoka, całkowicie odcięte od rzeki Warty, co sprawia, że jest bardzo podatne na zmiany warunków. Dno jest silnie zamulone i pokryte gęstą roślinnością podwodną, co bardzo utrudnia wędkowanie. Brzegi są mocno zarośnięte trzciną, praktycznie uniemożliwiając swobodny dostęp do wody bez brodzenia. Ze względu na małą głębokość i brak wymiany wody, zbiornik jest bardzo podatny na wysychanie w okresach suszy oraz na przyduchę. Głównymi mieszkańcami są karaś pospolity, wzdręga i lin, które są wyjątkowo odporne na trudne warunki środowiskowe. Najlepsze efekty daje tu wędkowanie późną wiosną i latem, zwłaszcza na lekkie zestawy spławikowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21229, 1, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21230, 'Starorzecze Rędziny A', 'starorzecze-redziny-a-redziny-21230', 'OXBOW', 50.9936511, 19.4519358, 'Województwo Śląskie', 'Rędziny', 'To starorzecze, zlokalizowane w pobliżu Rędzin, stanowi klasyczny przykład dawnego koryta rzeki, charakteryzującego się wydłużonym kształtem i stosunkowo płytkimi wodami. Średnia głębokość akwenu wynosi około 1.5 metra, lecz w najgłębszych partiach może sięgać do 3.0 metrów. Dno jest przeważnie muliste, z licznymi osadami organicznymi, co sprzyja rozwojowi bogatej roślinności podwodnej i nawodnej, takiej jak trzcina i grążele. Brzegi są miejscami trudno dostępne, bagniste, co wymaga użycia wodoodpornego obuwia. Wędkarze mogą tu liczyć na obfite populacje płoci, leszcza i lina, a także na okazjonalne brania szczupaka. W cieplejszych miesiącach, ze względu na umiarkowane zarośnięcie i muliste dno, istnieje podwyższone ryzyko przyduchy, co może wpływać na aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21230, 2.8, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Lin,Szczupak,Karaś pospolity', 'Trudny, miejscami bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21231, 'Starorzecze Rędziny B', 'starorzecze-redziny-b-redziny-21231', 'OXBOW', 50.9929716, 19.4512008, 'Województwo Śląskie', 'Rędziny', 'To niewielkie starorzecze w okolicy Rędzin charakteryzuje się bardziej odizolowanym charakterem od głównego nurtu rzeki. Jego powierzchnia to zaledwie 1.2 hektara, a średnia głębokość nie przekracza 1.0 metra, z maksymalnym zagłębieniem do 2.0 metrów. Dno jest silnie zarośnięte i muliste, co sprzyja rozwojowi bujnej roślinności podwodnej, stanowiącej idealne schronienie dla ryb. Brzegi są gęsto porośnięte trzciną i inną roślinnością, co czyni dostęp do wody bardzo trudnym i wymaga brodzenia. W tych warunkach królują karasie pospolite i srebrzyste, wzdręgi oraz liny, które doskonale radzą sobie w płytkich, ciepłych wodach. Ze względu na niewielką głębokość i silne zarośnięcie, ryzyko przyduchy jest wysokie, szczególnie podczas upalnego lata. W wodzie występuje dużo zatopionych gałęzi i roślinności, co może utrudniać wędkowanie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21231, 1.2, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Karaś srebrzysty,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21232, 'Starorzecze Rędziny C', 'starorzecze-redziny-c-redziny-21232', 'OXBOW', 50.996338, 19.4511848, 'Województwo Śląskie', 'Rędziny', 'To starorzecze, położone niedaleko Rędzin, wyróżnia się nieco większą powierzchnią i umiarkowanym połączeniem z rzeką, co zapewnia dopływ świeżej wody podczas wyższych stanów. Akwen ma około 4.5 hektara, a jego średnia głębokość wynosi 1.8 metra, z maksymalnym zagłębieniem do 3.5 metra. Dno jest zróżnicowane, od mulistego po piaskowo-żwirowe w miejscach bliżej dawnego nurtu, a brzegi są częściowo dostępne, choć miejscami porośnięte krzewami i trawami. Roślinność wodna jest umiarkowana, z przewagą rdestnic i moczarki, co tworzy dobre warunki dla drapieżników. W starorzeczu tym dominują szczupaki i okonie, a także leszcze i płocie, które żerują na otwartych przestrzeniach. Ryzyko przyduchy jest niższe niż w mniejszych zbiornikach, ale nadal obecne w upalne lata. Dostęp do wody jest możliwy w wielu miejscach, ale warto mieć ze sobą wodery, aby dotrzeć do najlepszych stanowisk.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21232, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z niektórych stron', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21233, 'Starorzecze Rędziny D', 'starorzecze-redziny-d-redziny-21233', 'OXBOW', 50.9979523, 19.4504437, 'Województwo Śląskie', 'Rędziny', 'To starorzecze, zlokalizowane w kompleksie wodnym koło Rędzin, jest stosunkowo płytkie i mocno zarośnięte, co nadaje mu dziki charakter. Jego powierzchnia wynosi około 1.8 hektara, a średnia głębokość to zaledwie 0.8 metra, z maksymalnym zagłębieniem do 1.5 metra. Dno jest w całości pokryte grubą warstwą mułu i obfituje w gęstą roślinność podwodną, taką jak wywłócznik i rogatek, tworząc labirynt dla ryb. Brzegi są praktycznie niedostępne bez brodzenia, z dominacją szuwarów i podmokłych terenów. W tych warunkach królują karasie pospolite, liny i wzdręgi, które doskonale adaptują się do niskiej zawartości tlenu i gęstych zarośli. Ze względu na ekstremalną płytkość i silne zarośnięcie, ryzyko przyduchy jest bardzo wysokie, a w szczególnie suchych latach starorzecze może częściowo wyschnąć. Wędkowanie jest tu wyzwaniem, wymagającym cierpliwości i sprzętu do łowienia w zarośniętych miejscach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21233, 1.8, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21234, 'Starorzecze Rędziny E', 'starorzecze-redziny-e-redziny-21234', 'OXBOW', 50.9974307, 19.4509432, 'Województwo Śląskie', 'Rędziny', 'To starorzecze, znajdujące się w pobliżu Rędzin, jest przykładem zbiornika o umiarkowanej głębokości i rozwiniętej linii brzegowej. Zajmuje powierzchnię około 3.5 hektara, ze średnią głębokością 1.7 metra i maksymalną dochodzącą do 3.2 metra. Dno jest przeważnie muliste, ale w niektórych miejscach można znaleźć twardsze fragmenty, co świadczy o zmiennym charakterze osadów. Brzegi są częściowo dostępne, z pasami trzcin i pojedynczymi drzewami, które oferują cień i kryjówki dla ryb. W starorzeczu tym z powodzeniem żerują leszcz, płoć i lin, a także drapieżniki takie jak szczupak i okoń. Połączenie z rzeką jest sporadyczne, głównie podczas wiosennych roztopów, co pomaga w odnawianiu zasobów tlenu. Ryzyko przyduchy jest umiarkowane, lecz warto być świadomym tej możliwości. Wędkowanie jest tu przyjemne, zwłaszcza z użyciem pontonu lub brodząc w woderach, aby dotrzeć do środkowych partii zbiornika.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21234, 3.5, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Lin,Szczupak,Okoń', 'Częściowo dostępny, zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21235, 'Starorzecze Kijów', 'starorzecze-kijow-kijow-21235', 'OXBOW', 51.0338612, 19.2571107, 'Województwo Śląskie', 'Kijów', 'Starorzecze w Kijowie to malowniczy zbiornik o powierzchni około 5.0 hektarów, który zachował wiele cech naturalnego środowiska. Jego średnia głębokość wynosi 2.0 metry, a maksymalna dochodzi do 4.0 metrów, co zapewnia stabilne warunki wodne. Dno jest przeważnie muliste, z licznymi fragmentami twardego piasku i żwiru, świadczącymi o dawnym nurcie rzeki. Brzegi są dobrze utrzymane i w większości dostępne, z umiarkowanym pasem trzcin i pojedynczymi drzewami, oferującymi cień w upalne dni. Akwen ten jest domem dla licznej populacji leszczy, płoci i karpi, a także dla drapieżników takich jak szczupak i sum, który znajduje tu dogodne warunki do życia. Połączenie z rzeką jest sporadyczne, co sprzyja rozwojowi stabilnego ekosystemu. Ryzyko przyduchy jest niskie dzięki większej głębokości i regularnym dopływom świeżej wody, a wędkowanie jest komfortowe i owocne przez większość roku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21235, 5, 2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Sum', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21236, 'Starorzecze Jankowice A', 'starorzecze-jankowice-a-jankowice-21236', 'OXBOW', 51.0402626, 19.2527306, 'Województwo Śląskie', 'Jankowice', 'To starorzecze w Jankowicach to zbiornik o średniej wielkości, charakteryzujący się dynamicznym środowiskiem wodnym. Jego powierzchnia wynosi około 3.2 hektara, a głębokość waha się od 1.2 metra średnio do 2.8 metra maksymalnie. Dno jest zróżnicowane, z przewagą mułu, ale z licznymi miejscami z twardszym podłożem, co świadczy o aktywnym przepływie wody w przeszłości. Brzegi są częściowo dostępne, z pasami trzcin i krzewów, które zapewniają schronienie dla ryb i ptactwa wodnego. Roślinność wodna jest umiarkowana, co sprzyja rozwojowi zarówno ryb spokojnego żeru, jak i drapieżników. W starorzeczu tym dominują płocie, leszcze i okonie, a także liny i karasie pospolite. Połączenie z rzeką jest częste podczas podwyższonych stanów wody, co zapewnia dobre natlenienie i migrację ryb. Ryzyko przyduchy jest niskie, a wędkowanie jest tu zazwyczaj bardzo owocne, szczególnie w miejscach z dostępem do otwartej wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21236, 3.2, 1.2, 2.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Lin,Karaś pospolity', 'Częściowo dostępny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21237, 'Starorzecze Jankowice B', 'starorzecze-jankowice-b-jankowice-21237', 'OXBOW', 51.0380503, 19.2462365, 'Województwo Śląskie', 'Jankowice', 'To starorzecze w Jankowicach to niewielki, lecz głęboki zbiornik, co czyni go wyjątkowym wśród okolicznych akwenów. Mimo powierzchni zaledwie 0.9 hektara, jego średnia głębokość wynosi aż 2.5 metra, a maksymalna dochodzi do 5.0 metrów. Dno jest głównie muliste, z lokalnymi zagłębieniami i zatopionymi drzewami, które tworzą doskonałe kryjówki dla dużych ryb. Brzegi są strome i porośnięte gęstą roślinnością, co utrudnia dostęp, ale jednocześnie chroni zbiornik przed nadmierną presją wędkarską. W głębokich wodach tego starorzecza dominują sumy, węgorze i duże leszcze, a także szczupaki, które polują w pobliżu zatopionych przeszkód. Połączenie z rzeką jest rzadkie, co sprzyja stabilizacji warunków, ale jednocześnie może prowadzić do kumulacji osadów. Ryzyko przyduchy jest niskie dzięki znacznej głębokości, a wędkowanie jest tu wyzwaniem, ale może przynieść imponujące okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21237, 0.9, 2.5, 5, 'Brak', 'Średnie', 'Słabe', FALSE, FALSE, 'Sum,Węgorz,Leszcz,Szczupak', 'Trudny, strome brzegi', TRUE, 'Dużo zatopionych drzew', 'Lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21238, 'Starorzecze Jankowice C', 'starorzecze-jankowice-c-jankowice-21238', 'OXBOW', 51.0381163, 19.2434909, 'Województwo Śląskie', 'Jankowice', 'To starorzecze w Jankowicach to płytki, ale rozległy zbiornik o powierzchni 4.0 hektarów, który jest typowym siedliskiem dla ryb preferujących wody stojące i zarośnięte. Średnia głębokość wynosi zaledwie 1.0 metra, a maksymalna nie przekracza 2.0 metrów. Dno jest jednolicie muliste, z grubą warstwą osadów, co sprzyja intensywnemu rozwojowi roślinności podwodnej, takiej jak rdestnica i moczarka. Brzegi są mocno zarośnięte trzciną i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga brodzenia. W takich warunkach doskonale czują się karasie pospolite i srebrzyste, liny oraz wzdręgi, które są głównymi gatunkami występującymi w tym akwenie. Ze względu na płytkość i silne zarośnięcie, ryzyko przyduchy jest wysokie, zwłaszcza w upalne, bezwietrzne dni. Wędkowanie jest tu wyzwaniem, ale może przynieść obfite połowy, szczególnie dla miłośników spławika i łowienia w zaroślach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21238, 4, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Karaś srebrzysty,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21239, 'Starorzecze Zakrzówek Szlachecki A', 'starorzecze-zakrzowek-szlachecki-a-zakrzowek-szlachecki-21239', 'OXBOW', 51.0422379, 19.2102844, 'Województwo Śląskie', 'Zakrzówek Szlachecki', 'Starorzecze w Zakrzówku Szlacheckim to zbiornik o umiarkowanej wielkości, który przez lata stał się ważnym elementem lokalnego ekosystemu. Zajmuje powierzchnię około 2.7 hektara, a jego średnia głębokość wynosi 1.6 metra, z maksymalnym zagłębieniem do 3.0 metrów. Dno jest przeważnie muliste, z licznymi fragmentami zatopionej roślinności i gałęzi, które stanowią kryjówki dla ryb. Brzegi są częściowo dostępne, z pasami trzcin i krzewów, które zapewniają naturalne schronienie. Roślinność wodna jest umiarkowana, z przewagą rdestnic i moczarki, co tworzy dobre warunki dla ryb spokojnego żeru i drapieżników. W starorzeczu tym dominują płocie, leszcze i okonie, a także szczupaki, które aktywnie polują wzdłuż brzegów. Połączenie z rzeką jest sporadyczne, głównie podczas wiosennych wezbrań, co sprzyja odnawianiu zasobów tlenu. Ryzyko przyduchy jest umiarkowane, a wędkowanie jest tu przyjemne, zwłaszcza z użyciem pontonu lub brodząc w woderach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21239, 2.7, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Częściowo dostępny, zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21240, 'Starorzecze Zakrzówek Szlachecki B', 'starorzecze-zakrzowek-szlachecki-b-zakrzowek-szlachecki-21240', 'OXBOW', 51.0418688, 19.2099119, 'Województwo Śląskie', 'Zakrzówek Szlachecki', 'To starorzecze w Zakrzówku Szlacheckim to mniejszy, bardziej odizolowany zbiornik, idealny dla wędkarzy poszukujących spokoju i dzikiego charakteru. Jego powierzchnia to około 1.5 hektara, ze średnią głębokością 1.0 metra i maksymalnym zagłębieniem do 2.0 metrów. Dno jest silnie zamulone i obfituje w gęstą roślinność podwodną, tworząc skomplikowany labirynt dla ryb. Brzegi są bardzo trudno dostępne, z dominacją trzcinowisk i podmokłych terenów, co wymaga brodzenia. W takich warunkach doskonale prosperują karasie pospolite i srebrzyste, liny oraz wzdręgi, które są odporne na trudne warunki środowiskowe. Ze względu na płytkość i silne zarośnięcie, ryzyko przyduchy jest wysokie, a w szczególnie upalne lata starorzecze może częściowo wyschnąć. Wędkowanie jest tu wyzwaniem, ale może przynieść satysfakcjonujące wyniki dla cierpliwych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21240, 1.5, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Karaś srebrzysty,Lin,Wzdręga', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21241, 'Starorzecze Racisław A', 'starorzecze-racislaw-a-racislaw-21241', 'OXBOW', 54.4110493, 16.4268853, 'Województwo Zachodniopomorskie', 'Racisław', 'To starorzecze w Racisławiu to rozległy akwen o powierzchni około 6.0 hektarów, charakteryzujący się stosunkowo dużą głębokością i zróżnicowanym dnem. Średnia głębokość wynosi 2.5 metra, a maksymalna dochodzi do 5.5 metra, co zapewnia stabilne warunki wodne. Dno jest mieszane, od mulistego po piaszczyste i żwirowe, z licznymi zatopionymi drzewami i korzeniami, które tworzą doskonałe kryjówki dla ryb. Brzegi są częściowo dostępne, z pasami trzcin i gęstych krzewów, które stanowią naturalne schronienie. W starorzeczu tym dominują leszcze, płocie i karpie, a także drapieżniki takie jak szczupak i okoń, które aktywnie polują wzdłuż brzegów i w okolicach zatopionych przeszkód. Połączenie z rzeką jest stałe, co zapewnia regularny dopływ świeżej wody i migrację ryb. Ryzyko przyduchy jest niskie, a wędkowanie jest tu bardzo owocne przez większość sezonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21241, 6, 2.5, 5.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Okoń', 'Dobry z niektórych stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21242, 'Starorzecze Racisław B', 'starorzecze-racislaw-b-racislaw-21242', 'OXBOW', 54.4114314, 16.4287193, 'Województwo Zachodniopomorskie', 'Racisław', 'To starorzecze w Racisławiu to mniejszy, ale głęboki zbiornik, który stanowi cenną ostoję dla wielu gatunków ryb. Jego powierzchnia wynosi około 1.8 hektara, a średnia głębokość to 2.8 metra, z maksymalnym zagłębieniem do 6.0 metrów. Dno jest głównie muliste, z licznymi zatopionymi przeszkodami, takimi jak pnie drzew i gałęzie, które tworzą idealne schronienia. Brzegi są strome i gęsto porośnięte roślinnością, co utrudnia dostęp, ale jednocześnie chroni zbiornik przed nadmierną presją wędkarską. W głębokich wodach tego starorzecza dominują sumy, węgorze i duże leszcze, a także sandacze, które znajdują tu dogodne warunki do żerowania. Połączenie z rzeką jest sporadyczne, co sprzyja stabilizacji warunków, ale jednocześnie może prowadzić do kumulacji osadów. Ryzyko przyduchy jest niskie dzięki znacznej głębokości, a wędkowanie jest tu wyzwaniem, ale może przynieść imponujące okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21242, 1.8, 2.8, 6, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Sum,Węgorz,Leszcz,Sandacz', 'Trudny, strome brzegi', TRUE, 'Dużo zatopionych drzew', 'Lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21243, 'Starorzecze Racisław C', 'starorzecze-racislaw-c-racislaw-21243', 'OXBOW', 54.4116426, 16.4261191, 'Województwo Zachodniopomorskie', 'Racisław', 'To starorzecze w Racisławiu to płytki, ale bardzo rozległy zbiornik o powierzchni 7.5 hektara, który jest typowym siedliskiem dla ryb preferujących wody stojące i zarośnięte. Średnia głębokość wynosi zaledwie 1.5 metra, a maksymalna nie przekracza 3.0 metrów. Dno jest jednolicie muliste, z grubą warstwą osadów, co sprzyja intensywnemu rozwojowi roślinności podwodnej, takiej jak rdestnica i moczarka. Brzegi są mocno zarośnięte trzciną i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga brodzenia. W takich warunkach doskonale czują się karasie pospolite i srebrzyste, liny oraz wzdręgi, które są głównymi gatunkami występującymi w tym akwenie. Ze względu na płytkość i silne zarośnięcie, ryzyko przyduchy jest wysokie, zwłaszcza w upalne, bezwietrzne dni. Wędkowanie jest tu wyzwaniem, ale może przynieść obfite połowy, szczególnie dla miłośników spławika i łowienia w zaroślach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21243, 7.5, 1.5, 3, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Karaś srebrzysty,Lin,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21244, 'Starorzecze Masłowo', 'starorzecze-maslowo-maslowo-21244', 'OXBOW', 52.0150132, 17.0640136, 'Województwo Wielkopolskie', 'Masłowo', 'Starorzecze w Masłowie to średniej wielkości zbiornik o powierzchni około 4.2 hektara, który stanowi popularne łowisko dla okolicznych wędkarzy. Jego średnia głębokość wynosi 1.8 metra, a maksymalna dochodzi do 3.8 metra, co zapewnia stabilne warunki wodne przez większość roku. Dno jest zróżnicowane, od mulistego po piaszczysto-żwirowe w miejscach bliżej dawnego nurtu, co sprzyja różnorodności gatunkowej. Brzegi są dobrze utrzymane i w większości dostępne, z umiarkowanym pasem trzcin i pojedynczymi drzewami, oferującymi cień w upalne dni. Akwen ten jest domem dla licznej populacji leszczy, płoci i karpi, a także dla drapieżników takich jak szczupak i okoń, które znajdują tu dogodne warunki do życia. Połączenie z rzeką jest sporadyczne, co sprzyja rozwojowi stabilnego ekosystemu. Ryzyko przyduchy jest niskie dzięki większej głębokości i umiarkowanemu zarośnięciu, a wędkowanie jest komfortowe i owocne przez większość roku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21244, 4.2, 1.8, 3.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21245, 'Starorzecze Opatkowickie (A)', 'starorzecze-opatkowickie-a-opatkowice-21245', 'OXBOW', 51.4604923, 21.8732469, 'Lubelskie', 'Opatkowice', 'To starorzecze, położone w pobliżu Opatkowic, charakteryzuje się typowym dla tego typu zbiorników, wydłużonym kształtem. Dno jest muliste, z domieszką piasku w płytszych partiach, co sprzyja rozwojowi bogatej roślinności podwodnej. Brzegi są w dużej mierze porośnięte trzciną i inną roślinnością szuwarową, utrudniając dostęp do wody w wielu miejscach. Wiosną i wczesną jesienią można tu liczyć na udane połowy lina, szczupaka oraz okazałych płoci i okoni. Zbiornik łączy się z rzeką jedynie podczas wysokich stanów wody, co ogranicza migrację ryb, ale sprzyja stabilizacji populacji. Ze względu na umiarkowane zamulenie i ryzyko niedoboru tlenu latem, najlepsze wyniki osiąga się w chłodniejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21245, 3.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Okoń,Płoć,Leszcz', 'Trudny, bagnisty w niektórych miejscach', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21246, 'Starorzecze Opatkowickie (B)', 'starorzecze-opatkowickie-b-opatkowice-21246', 'OXBOW', 51.4608428, 21.8718585, 'Lubelskie', 'Opatkowice', 'Drugie z opatkowickich starorzeczy jest mniejszym i bardziej odizolowanym zbiornikiem, cechującym się znacznym stopniem zamulenia. Jego dno jest w przeważającej części pokryte grubą warstwą mułu, co sprzyja bujnemu rozwojowi roślinności wodnej, zarówno podwodnej, jak i wynurzonej. Brzegi są gęsto porośnięte trzciną i krzewami, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga użycia brodzących spodni. W tym starorzeczu dominują gatunki ryb odporne na trudniejsze warunki, takie jak karaś pospolity oraz lin, które znajdują tu idealne warunki do życia. Ryzyko niedoboru tlenu w upalne lata jest wysokie, dlatego najlepsze efekty wędkarskie osiąga się wiosną oraz wczesnym latem, zwłaszcza o świcie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21246, 2.8, 1.2, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, lato (wczesne poranki)');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21247, 'Starorzecze Zbereże (1)', 'starorzecze-zbereze-1-zbereze-21247', 'OXBOW', 51.4114771, 23.6948054, 'Lubelskie', 'Zbereże', 'To malownicze starorzecze w okolicach Zbereża, charakteryzuje się dość stabilnym poziomem wody i umiarkowanym zamuleniem dna. Brzegi są częściowo dostępne, z piaszczystymi odcinkami, ale w wielu miejscach porasta je gęsta roślinność szuwarowa. W zbiorniku tym występują liczne okazy szczupaka i okonia, co czyni go atrakcyjnym dla wędkarzy spinningowych. Obfitość roślinności podwodnej stanowi doskonałe schronienie i żerowisko dla drobnicy, co z kolei przyciąga drapieżniki. Połączenie z rzeką Bug podczas wiosennych roztopów wzbogaca populację ryb. Ryzyko przyduchy jest niskie dzięki większej głębokości i okresowym połączeniom z rzeką, co pozwala na wędkowanie przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21247, 4.5, 1.8, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz,Wzdręga', 'Dobry z jednej strony, zarośnięty z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21248, 'Starorzecze Zbereże (2)', 'starorzecze-zbereze-2-zbereze-21248', 'OXBOW', 51.4115704, 23.6916532, 'Lubelskie', 'Zbereże', 'To rozległe starorzecze wyróżnia się stałym, choć wąskim, połączeniem z rzeką Bug, co zapewnia ciągłą wymianę wody i niskie zamulenie. Dno jest tu w dużej mierze piaszczysto-żwirowe, z nielicznymi partiami mulistymi, co sprzyja występowaniu różnorodnych gatunków ryb. Brzegi są łatwo dostępne, z naturalnymi miejscami do wędkowania, bez konieczności brodzenia. W zbiorniku tym można spotkać okazałe leszcze, płocie, a także karpie i sumy, które migrują z głównego nurtu rzeki. Okresowo pojawiają się również sandacze, zwłaszcza w miejscach o twardszym dnie. Dzięki dobrej cyrkulacji wody, ryzyko przyduchy jest minimalne, co czyni to łowisko atrakcyjnym przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21248, 6.1, 2.1, 5, 'Stałe połączenie (wąski kanał)', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sum,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21249, 'Starorzecze Zbereże (3)', 'starorzecze-zbereze-3-zbereze-21249', 'OXBOW', 51.4100538, 23.6928273, 'Lubelskie', 'Zbereże', 'To niewielkie i płytkie starorzecze, które uległo znacznemu zamuleniu i zarastaniu, jest typowym przykładem zbiornika w zaawansowanym stadium sukcesji. Dno jest w całości pokryte grubą warstwą organicznego mułu, a woda często przybiera brunatny odcień. Brzegi są niezwykle trudne do pokonania, bagniste i gęsto porośnięte trzciną oraz krzakami, co wymaga użycia brodzących spodni. W upalne lata istnieje realne ryzyko wyschnięcia zbiornika oraz całkowitego braku tlenu, co mocno ogranicza populację ryb. Dominują tu gatunki bardzo odporne, takie jak karaś pospolity, lin i wzdręga, które najlepiej żerują wczesną wiosną, zanim zbiornik nadmiernie się nagrzeje i zarośnie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21249, 2.9, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna i zatopione gałęzie', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21250, 'Starorzecze Zbereże (4)', 'starorzecze-zbereze-4-zbereze-21250', 'OXBOW', 51.4107306, 23.6824733, 'Lubelskie', 'Zbereże', 'To starorzecze charakteryzuje się nieregularnym kształtem i zróżnicowanym dnem, gdzie muliste partie przeplatają się z twardszymi fragmentami. Brzegi są dostępne w kilku miejscach, oferując wygodne stanowiska, jednak duża część linii brzegowej jest porośnięta gęstymi zaroślami. Zbiornik ten jest znany z występowania szczupaków, które chętnie polują w okolicach zatopionych drzew i gęstej roślinności. Połączenie z rzeką podczas wiosennych wezbrań dostarcza świeżej wody i nowych ryb, co pozytywnie wpływa na ekosystem. Latem, przy niskich stanach wody i wysokich temperaturach, ryzyko niedoboru tlenu wzrasta, dlatego najlepsze rezultaty osiąga się wiosną i jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21250, 3.8, 1.6, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Okoń,Płoć', 'Miejscami dobry, miejscami zarośnięty', FALSE, 'Pojedyncze zatopione drzewa', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21251, 'Starorzecze Zbereże (5)', 'starorzecze-zbereze-5-zbereze-21251', 'OXBOW', 51.4104291, 23.6958568, 'Lubelskie', 'Zbereże', 'Rozległe starorzecze o dość głębokiej rynnie, które zachowuje dobrą jakość wody dzięki okresowym połączeniom z rzeką Bug. Dno jest w większości piaszczysto-muliste, z twardszymi fragmentami na zakrętach, co sprzyja różnorodności gatunkowej. Brzegi są łatwo dostępne, z licznymi naturalnymi stanowiskami wędkarskimi, co czyni je popularnym łowiskiem. W zbiorniku tym można liczyć na obfite połowy leszczy i płoci, a także na spotkanie z okazałymi karpiami i drapieżnikami takimi jak szczupak i okoń. Niskie zamulenie i dobra wymiana wody minimalizują ryzyko przyduchy, umożliwiając wędkowanie przez cały rok. To idealne miejsce dla wędkarzy ceniących komfort i różnorodność gatunkową.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21251, 5, 2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21252, 'Starorzecze Zbereże (6)', 'starorzecze-zbereze-6-zbereze-21252', 'OXBOW', 51.410987, 23.6971249, 'Lubelskie', 'Zbereże', 'To starorzecze jest przykładem zbiornika w zaawansowanym stadium starzenia się, charakteryzującego się wysokim stopniem zamulenia i intensywnym zarastaniem. Dno jest miękkie i muliste, a woda często ma ograniczoną przejrzystość z powodu obfitości materii organicznej. Brzegi są praktycznie niedostępne bez brodzących spodni, gęsto porośnięte trzciną i inną roślinnością szuwarową. W tym środowisku dominują ryby odporne na trudne warunki, takie jak lin, karaś pospolity i wzdręga, które doskonale adaptują się do płytkich, zarośniętych wód. Ryzyko niedoboru tlenu w upalne miesiące jest znaczne, dlatego najlepsze okresy na wędkowanie to wiosna i wczesne lato, kiedy warunki są jeszcze stabilne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21252, 3.5, 1.4, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21253, 'Starorzecze Zbereże (7)', 'starorzecze-zbereze-7-zbereze-21253', 'OXBOW', 51.4086621, 23.6930007, 'Lubelskie', 'Zbereże', 'Niewielkie i bardzo płytkie starorzecze, które w upalne lata często całkowicie wysycha, co czyni je łowiskiem o zmiennych warunkach. Dno jest niemal w całości pokryte grubą warstwą mułu, a roślinność wodna jest niezwykle bujna, tworząc gęste dywany. Dostęp do wody jest ekstremalnie utrudniony ze względu na bagniste i gęsto zarośnięte brzegi, wymagające użycia brodzących spodni. W tym zbiorniku dominują najbardziej odporne gatunki, takie jak karaś srebrzysty i pospolity, które potrafią przetrwać w ekstremalnych warunkach. Wędkowanie jest efektywne głównie wczesną wiosną, zanim zbiornik nadmiernie się nagrzeje i zacznie wysychać. Jest to wyzwanie dla wędkarzy ceniących dzikie i trudno dostępne łowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21253, 2.5, 1.1, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Karaś pospolity,Wzdręga', 'Bardzo trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna i muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21254, 'Starorzecze Zbereże (8)', 'starorzecze-zbereze-8-zbereze-21254', 'OXBOW', 51.4062359, 23.6943944, 'Lubelskie', 'Zbereże', 'To starorzecze oferuje zróżnicowane warunki wędkarskie, z głębszymi partiami i mieliznami, co przyciąga różnorodne gatunki ryb. Dno jest mieszane, z przewagą mułu, ale z twardszymi fragmentami wzdłuż dawnego nurtu rzeki. Brzegi są częściowo dostępne, z wygodnymi miejscami do zarzucania wędki, choć niektóre odcinki wymagają przedzierania się przez zarośla. W zbiorniku tym można skutecznie polować na szczupaki i okonie, zwłaszcza w okolicach zatopionych pni i gęstszej roślinności. Okresowe połączenia z Bugiem zapewniają dopływ świeżej wody i nowych osobników, co utrzymuje populację ryb w dobrej kondycji. Ryzyko niedoboru tlenu jest niskie, a łowisko jest atrakcyjne szczególnie wiosną i jesienią, gdy drapieżniki są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21254, 4, 1.7, 3.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry w części, reszta zarośnięta', FALSE, 'Pojedyncze zatopione pnie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21255, 'Starorzecze Zbereże (9)', 'starorzecze-zbereze-9-zbereze-21255', 'OXBOW', 51.4053035, 23.6969404, 'Lubelskie', 'Zbereże', 'To jedno z najmniejszych i najpłytszych starorzeczy w okolicy Zbereża, charakteryzujące się bardzo szybkim procesem zamulania i zarastania. Dno jest w całości pokryte grubą warstwą organicznego mułu, a głębokość rzadko przekracza dwa metry. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga użycia brodzących spodni. W upalne, suche lata zbiornik ten ma tendencję do całkowitego wysychania, co mocno ogranicza możliwość bytowania ryb. Dominują tu gatunki wysoce odporne, takie jak karaś pospolity, wzdręga i lin, które najlepiej żerują wczesną wiosną, zanim zbiornik osiągnie krytyczne temperatury i poziom wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21255, 1.9, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Trudny, gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna i muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21256, 'Starorzecze Zbereże (10)', 'starorzecze-zbereze-10-zbereze-21256', 'OXBOW', 51.4186833, 23.6967171, 'Lubelskie', 'Zbereże', 'To duże starorzecze utrzymuje stałe, choć sezonowo zwężające się, połączenie z rzeką Bug, co zapewnia mu dynamiczną wymianę wody. Dno jest zróżnicowane, z partiami piaszczystymi, żwirowymi i mulistymi, oferując różnorodne środowiska dla ryb. Brzegi są w większości łatwo dostępne, z naturalnymi miejscami do wędkowania, co sprzyja dłuższemu pobytowi nad wodą. W zbiorniku tym można liczyć na spotkanie z dużymi karpiami, leszcze i płocie, a także na drapieżniki takie jak szczupak i sum. Dzięki dobrej cyrkulacji i głębokości, ryzyko niedoboru tlenu jest minimalne, co pozwala na udane wędkowanie przez cały rok. To jedno z najbardziej atrakcyjnych łowisk w okolicy Zbereża.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21256, 5.5, 2.2, 4.8, 'Stałe połączenie (sezonowe zwężenie)', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Karp,Leszcz,Płoć,Szczupak,Sum', 'Dobry z większości stron', FALSE, 'Pojedyncze zatopione gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21257, 'Starorzecze Zbereże (11)', 'starorzecze-zbereze-11-zbereze-21257', 'OXBOW', 51.4186239, 23.6986537, 'Lubelskie', 'Zbereże', 'Charakterystyczne dla tego starorzecza są liczne zatopione drzewa i korzenie, tworzące idealne kryjówki dla drapieżników. Dno jest muliste, ale z twardszymi fragmentami w pobliżu brzegów i zatopionych przeszkód. Brzegi są zróżnicowane, od łatwo dostępnych po te, które wymagają brodzących spodni ze względu na bagnisty teren. Zbiornik ten jest doskonałym miejscem do połowu szczupaków i okoni, które chętnie żerują wśród podwodnych przeszkód. Okresowe połączenia z rzeką Bug wzbogacają populację ryb i utrzymują stabilne warunki wodne. Ryzyko niedoboru tlenu jest niskie, co sprawia, że łowisko jest produktywne przez większość sezonu, zwłaszcza w chłodniejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21257, 4.2, 1.7, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Lin,Leszcz', 'Zróżnicowany, miejscami wymaga brodzenia', TRUE, 'Dużo zatopionych drzew i korzeni', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21258, 'Starorzecze Zbereże (12)', 'starorzecze-zbereze-12-zbereze-21258', 'OXBOW', 51.3897508, 23.6730179, 'Lubelskie', 'Zbereże', 'To starorzecze jest silnie zamulone i zarośnięte, co sprawia, że jest to łowisko dla wędkarzy ceniących spokój i wyzwania. Dno jest miękkie, pokryte grubą warstwą osadów organicznych, a woda często ma niską przejrzystość. Brzegi są bardzo trudne do pokonania, bagniste i gęsto porośnięte trzciną, co wymaga użycia brodzących spodni. W zbiorniku tym dominują gatunki ryb odporne na trudne warunki, takie jak karaś pospolity, lin i wzdręga, które dobrze czują się w zarośniętych i płytkich wodach. Ryzyko niedoboru tlenu w upalne lata jest wysokie, dlatego najlepsze wyniki osiąga się wiosną i wczesnym latem. Jest to miejsce dla cierpliwych wędkarzy, poszukujących dzikich ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21258, 3.1, 1.3, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty, gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna i muł', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21259, 'Starorzecze Zbereże (13)', 'starorzecze-zbereze-13-zbereze-21259', 'OXBOW', 51.3900236, 23.673046, 'Lubelskie', 'Zbereże', 'Ostatnie z zbereżskich starorzeczy to niewielki i bardzo płytki zbiornik, który w okresach suszy ma tendencję do całkowitego wysychania. Dno jest w całości pokryte grubą warstwą organicznego mułu, a woda jest często płytka i mocno nagrzana. Brzegi są niezwykle trudne do pokonania, bagniste i gęsto porośnięte wszelkiego rodzaju roślinnością szuwarową. W tym ekstremalnym środowisku najlepiej radzą sobie karasie srebrzyste i pospolite oraz wzdręgi, które są odporne na niskie poziomy tlenu i wysokie temperatury. Wędkowanie jest najbardziej efektywne wczesną wiosną, zanim zbiornik nadmiernie się nagrzeje i zacznie wysychać. Jest to miejsce dla prawdziwych poszukiwaczy przygód, ceniących dziką przyrodę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21259, 2.7, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Karaś pospolity', 'Bardzo trudny, mocno zarośnięty i bagnisty', TRUE, 'Gęsta roślinność podwodna i muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21260, 'Starorzecze (Zbereże)', 'starorzecze-zbereze-wlodawa-21260', 'OXBOW', 51.4177946, 23.6928179, 'Lubelskie', 'Włodawa', 'To malownicze starorzecze, położone w pobliżu Zbereża, jest typowym akwenem doliny Bugu, charakteryzującym się bogatą roślinnością. Dno jest tu w większości muliste, z licznymi zatopionymi gałęziami i roślinnością podwodną, co stanowi doskonałe schronienie dla ryb. Brzegi są mocno porośnięte trzciną i inną roślinnością szuwarową, utrudniając dostęp do wody. Wiosną i podczas wysokich stanów wód, starorzecze łączy się z rzeką Bug, co sprzyja migracji ryb i wzbogaca populację. Jest to idealne łowisko dla wędkarzy poszukujących lina i karasia pospolitego, ale można tu również spotkać szczupaka czy dużą płoć. Ze względu na gęste zarośla i potencjalne zaczepy, niezbędne jest użycie długich wędek i mocnych zestawów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21260, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21261, 'Starorzecze (Mielnik)', 'starorzecze-mielnik-mielnik-21261', 'OXBOW', 52.3224928, 23.0564583, 'Podlaskie', 'Mielnik', 'Starorzecze w okolicach Mielnika to rozległy akwen, będący pozostałością po meandrach rzeki Bug, oferujący zróżnicowane warunki do wędkowania. Charakteryzuje się umiarkowanym poziomem zamulenia i bogatą, lecz nieprzesadzoną roślinnością podwodną, co sprzyja rozwojowi wielu gatunków ryb. Dno jest zróżnicowane, od piaszczystych fragmentów po te pokryte warstwą mułu, z pojedynczymi zaczepami w postaci korzeni. Brzegi są stosunkowo łatwo dostępne, co ułatwia dotarcie do wielu stanowisk wędkarskich, choć lokalnie mogą występować strefy zarośnięte. Wiosenne wylewy Bugu zapewniają regularne połączenie z rzeką, co pozytywnie wpływa na populację ryb, zwłaszcza leszczy i płoci. Jest to doskonałe miejsce na połów okazałych leszczy, szczupaków i okoni, a także lina w zarośniętych zatokach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21261, 8.2, 2.2, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21262, 'Starorzecze (Bachury) 1', 'starorzecze-bachury-1-narew-21262', 'OXBOW', 52.9601923, 23.7788585, 'Podlaskie', 'Narew', 'To jedno z wielu starorzeczy w malowniczej dolinie Narwi koło Bachur, charakteryzujące się niewielką powierzchnią i znacznym stopniem zarastania. Dno jest silnie zamulone, a płytkie partie akwenu są gęsto porośnięte roślinnością podwodną, co stwarza idealne warunki dla ryb typowych dla płytkich, ciepłych wód. Brzegi są trudne do pokonania, często bagniste i mocno zarośnięte trzciną, co wymaga użycia wodoodpornego obuwia lub brodzenia. Wiosenne wezbrania Narwi sporadycznie łączą starorzecze z głównym nurtem, co pozwala na uzupełnianie populacji. Jest to raj dla wędkarzy poszukujących karasia pospolitego, lina i wzdręgi, które osiągają tu imponujące rozmiary. Wędkowanie wymaga cierpliwości i precyzji, ze względu na liczne zaczepy i gęstą roślinność.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21262, 2.1, 1.5, 3, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21263, 'Starorzecze (Bachury) 2', 'starorzecze-bachury-2-narew-21263', 'OXBOW', 52.9592157, 23.7786586, 'Podlaskie', 'Narew', 'Drugie z blisko położonych starorzeczy w okolicach Bachur to płytki i mocno zarośnięty zbiornik, który w okresach suszy może częściowo wysychać. Jego dno jest w przeważającej części muliste, z grubą warstwą osadów dennych, co sprzyja rozwojowi bujnej roślinności wodnej. Brzegi są niezwykle trudne do pokonania, często bagniste i gęsto porośnięte, co czyni dostęp do wody wyzwaniem nawet dla doświadczonych wędkarzy. Brak stałego połączenia z Narwią sprawia, że ekosystem jest bardziej wrażliwy na zmiany poziomu wody i temperatury, zwiększając ryzyko przyduchy. Dominują tu gatunki odporne na trudne warunki, takie jak karaś pospolity, wzdręga i płoć, które dostosowały się do specyfiki tego środowiska. Wędkowanie wymaga elastyczności i dostosowania sprzętu do bardzo zarośniętego terenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21263, 1.8, 1.3, 2.8, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21264, 'Starorzecze (Bachury) 3', 'starorzecze-bachury-3-narew-21264', 'OXBOW', 52.9581719, 23.7790422, 'Podlaskie', 'Narew', 'To starorzecze w Bachurach jest nieco głębsze niż sąsiednie, ale nadal charakteryzuje się znacznym stopniem zarastania i mulistym dnem. Brzegi są mocno zarośnięte trzciną, co utrudnia swobodny dostęp do wody, jednak w niektórych miejscach można znaleźć dogodne stanowiska. Brak bezpośredniego połączenia z rzeką Narew sprawia, że akwen jest bardziej stabilny pod względem poziomu wody, choć wciąż podatny na letnie przyduchy. W wodzie występują liczne korzenie i pojedyncze gałęzie, które stanowią schronienie dla ryb, ale mogą być źródłem zaczepów. Jest to świetne miejsce na połów lina i karasia pospolitego, a także szczupaka i okonia, które polują wśród podwodnej roślinności. Wędkowanie tutaj wymaga cierpliwości i umiejętności łowienia w trudnych, zarośniętych warunkach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21264, 2.5, 1.6, 3.2, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21265, 'Starorzecze (Bachury) 4', 'starorzecze-bachury-4-narew-21265', 'OXBOW', 52.9573987, 23.7788464, 'Podlaskie', 'Narew', 'Ostatnie z grupy starorzeczy w Bachurach to bardzo płytki i silnie zamulony zbiornik, który w okresach długotrwałej suszy może całkowicie wyschnąć. Dno jest tu gęsto pokryte osadami i bujną roślinnością podwodną, tworząc skomplikowany labirynt dla ryb i wędkarzy. Brzegi są niezwykle trudne do pokonania, często grząskie i zarośnięte, co sprawia, że dotarcie do wody jest prawdziwym wyzwaniem. Ze względu na brak połączenia z rzeką Narew i niewielką głębokość, akwen jest bardzo wrażliwy na warunki atmosferyczne i ma wysokie ryzyko przyduchy. Dominują tu gatunki ryb, które doskonale radzą sobie w trudnych warunkach, takie jak karaś pospolity, wzdręga i płoć. Wędkowanie w tym miejscu jest przeznaczone dla wędkarzy szukających dzikiej przygody i gotowych na trudne warunki terenowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21265, 1.5, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21266, 'Jezioro Rudawickie', 'jezioro-rudawickie-ilowa-21266', 'OXBOW', 51.5347186, 15.3841855, 'Lubuskie', 'Iłowa', 'Jezioro Rudawickie to rozległe starorzecze rzeki Kwisy, wyróżniające się na tle innych akwenów tej kategorii stosunkowo dużą powierzchnią i głębokością. Dno jest zróżnicowane, od piaszczystych płycizn po muliste zagłębienia, z umiarkowaną ilością roślinności podwodnej, co sprzyja różnorodności gatunkowej. Brzegi są w większości łatwo dostępne, co czyni to miejsce popularnym wśród wędkarzy, choć w niektórych partiach występują pasy trzcin. Stałe połączenie z rzeką Kwisą zapewnia regularną wymianę wody i swobodną migrację ryb, co pozytywnie wpływa na zdrowie ekosystemu. Jest to doskonałe łowisko dla miłośników szczupaka i okonia, a także leszczy, płoci i karpi, które osiągają tu imponujące rozmiary. Wędkowanie jest tu komfortowe i oferuje szansę na naprawdę dużą rybę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21266, 12, 2.5, 5.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21267, 'Starorzecze Kwisy', 'starorzecze-kwisy-ilowa-21267', 'OXBOW', 51.5491695, 15.3936846, 'Lubuskie', 'Iłowa', 'Starorzecze Kwisy, położone w malowniczej dolinie rzeki, to akwen o wydłużonym kształcie, charakteryzujący się czystą wodą i umiarkowanym stopniem zarastania. Dno jest głównie piaszczysto-muliste, z pojedynczymi korzeniami i gałęziami, które stanowią naturalne kryjówki dla ryb. Brzegi są dobrze dostępne, co ułatwia swobodne przemieszczanie się wzdłuż łowiska i znalezienie dogodnego miejsca do zarzucenia wędki. Dzięki stałemu połączeniu z rzeką Kwisą, starorzecze jest regularnie zasilane świeżą wodą, co zapobiega przyduchom i wspiera zdrową populację ryb. Jest to znakomite miejsce dla wędkarzy polujących na szczupaka, okonia, leszcza i płoć, a także bolenia, który często wpływa tu z głównego nurtu. Wędkowanie jest tu przyjemne i oferuje dobre perspektywy na udany połów, szczególnie wiosną i wczesną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21267, 7.8, 2, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21268, 'Starorzecze (Okopy) 1', 'starorzecze-okopy-1-dorohusk-21268', 'OXBOW', 51.17739, 23.7736854, 'Lubelskie', 'Dorohusk', 'To starorzecze, zlokalizowane w pobliżu Okopów, jest typowym dla doliny Bugu, charakteryzującym się znacznym zarastaniem i mulistym dnem. Akwen jest stosunkowo płytki, co w połączeniu z gęstą roślinnością podwodną tworzy idealne warunki dla ryb ciepłolubnych i drapieżników czających się w zaczepach. Brzegi są mocno zarośnięte trzciną i inną roślinnością szuwarową, co utrudnia dostęp do wody i wymaga cierpliwości od wędkarza. Połączenie z rzeką Bug następuje podczas wysokich stanów wody, co pozwala na migrację ryb i odświeżenie ekosystemu. Jest to doskonałe łowisko dla miłośników lina i karasia pospolitego, ale także szczupaka i płoci, które znajdują tu obfitość pokarmu. Ze względu na gęste zarośla i liczne zaczepy, zaleca się użycie mocnego sprzętu i ostrożne prowadzenie przynęty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21268, 3.2, 1.7, 3.4, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21269, 'Starorzecze (Okopy) 2', 'starorzecze-okopy-2-dorohusk-21269', 'OXBOW', 51.1773204, 23.7759701, 'Lubelskie', 'Dorohusk', 'Drugie starorzecze w rejonie Okopów to mniejszy, bardziej izolowany akwen, cechujący się znacznym stopniem zamulenia i bujną roślinnością. Płytkie dno pokryte jest grubą warstwą mułu, a brzegi są trudne do pokonania, często bagniste i gęsto zarośnięte, co wymaga brodzenia. Połączenie z rzeką Bug jest sporadyczne i następuje tylko podczas bardzo wysokich wód, co sprawia, że zbiornik jest bardziej wrażliwy na przyduchy. Gęsta roślinność podwodna stanowi doskonałe schronienie dla ryb, ale jednocześnie utrudnia wędkowanie, tworząc liczne zaczepy. Dominują tu gatunki takie jak lin, karaś pospolity, wzdręga i okoń, które doskonale adaptują się do tych specyficznych warunków. Wędkowanie w tym miejscu to wyzwanie, ale może przynieść satysfakcję w postaci pięknych okazów ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21269, 2.8, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21270, 'Starorzecze (Berdyszcze) 1', 'starorzecze-berdyszcze-1-dorohusk-21270', 'OXBOW', 51.1760218, 23.790427, 'Lubelskie', 'Dorohusk', 'To starorzecze w Berdyszczach to jeden z bardziej atrakcyjnych akwenów w dolinie Bugu, charakteryzujący się stosunkowo dobrą głębokością i umiarkowanym stopniem zarastania. Dno jest zróżnicowane, od twardszych fragmentów po muliste zagłębienia, z pojedynczymi zaczepami w postaci korzeni. Brzegi są w większości łatwo dostępne, co ułatwia wybór stanowiska i swobodne przemieszczanie się wzdłuż łowiska. Połączenie z rzeką Bug podczas wysokich wód zapewnia regularne odświeżanie wody i dopływ nowych ryb, co pozytywnie wpływa na populację. Jest to doskonałe miejsce na połów szczupaka, leszcza, płoci, lina i okonia, które znajdują tu idealne warunki do żerowania i rozwoju. Wędkowanie jest tu przyjemne i oferuje szansę na różnorodne połowy przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21270, 4, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Lin,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21271, 'Starorzecze (Berdyszcze) 2', 'starorzecze-berdyszcze-2-dorohusk-21271', 'OXBOW', 51.1830858, 23.795111, 'Lubelskie', 'Dorohusk', 'Drugie starorzecze w Berdyszczach jest akwenem izolowanym od głównego nurtu Bugu, co sprawia, że jego ekosystem jest bardziej stabilny, ale też podatny na stagnację. Dno jest silnie zamulone, a brzegi mocno zarośnięte trzciną, co utrudnia dostęp do wody i wymaga od wędkarza cierpliwości. Gęsta roślinność podwodna tworzy liczne schronienia dla ryb, ale także stanowi wyzwanie podczas prowadzenia przynęty. Brak stałego połączenia z rzeką główną oznacza, że zbiornik jest bardziej narażony na przyduchy w okresach letnich upałów i zimowych mrozów. Dominują tu gatunki takie jak lin, karaś pospolity, wzdręga i płoć, które dobrze radzą sobie w takich warunkach. Wędkowanie w tym miejscu to prawdziwa gratka dla miłośników spokojnego łowienia w dzikiej scenerii.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21271, 3.5, 1.8, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21272, 'Starorzecze (Berdyszcze) 3', 'starorzecze-berdyszcze-3-dorohusk-21272', 'OXBOW', 51.182682, 23.7963559, 'Lubelskie', 'Dorohusk', 'To starorzecze w Berdyszczach to akwen o średniej głębokości, charakteryzujący się znacznym stopniem zarastania i licznymi zatopionymi drzewami, które tworzą idealne kryjówki dla drapieżników. Dno jest muliste, a brzegi trudne do pokonania i często bagniste, co wymaga użycia wodoodpornego obuwia. Połączenie z rzeką Bug podczas wysokich wód jest nieregularne, ale wystarczające, by odświeżyć wodę i wprowadzić nowe osobniki ryb. Gęsta roślinność podwodna i liczne zatopione drzewa sprawiają, że wędkowanie jest tu wyzwaniem, ale jednocześnie oferuje szansę na złowienie naprawdę dużych okazów. Jest to doskonałe miejsce na połów karasia pospolitego, lina, okonia i szczupaka, które cenią sobie obfitość zaczepów. Wędkowanie wymaga precyzji i umiejętności operowania sprzętem w trudnym terenie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21272, 2.9, 1.6, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Okoń,Szczupak', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21273, 'Starorzecze (Berdyszcze) 4', 'starorzecze-berdyszcze-4-dorohusk-21273', 'OXBOW', 51.185643, 23.7960035, 'Lubelskie', 'Dorohusk', 'Ostatnie z grupy starorzeczy w Berdyszczach to płytki i silnie zamulony zbiornik, który w okresach suszy może częściowo wyschnąć, a nawet całkowicie zniknąć. Dno jest gęsto pokryte osadami i bujną roślinnością podwodną, tworząc skomplikowany ekosystem. Brzegi są niezwykle trudne do pokonania, często grząskie i zarośnięte, co sprawia, że dotarcie do wody jest prawdziwym wyzwaniem. Brak stałego połączenia z rzeką Bug i niewielka głębokość sprawiają, że akwen jest bardzo wrażliwy na warunki atmosferyczne i ma wysokie ryzyko przyduchy. Dominują tu gatunki ryb, które doskonale radzą sobie w trudnych warunkach, takie jak karaś pospolity, wzdręga i płoć. Wędkowanie w tym miejscu jest przeznaczone dla wędkarzy szukających dzikiej przygody i gotowych na trudne warunki terenowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21273, 2.1, 1.4, 2.9, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21274, 'Starorzecze (Świerże)', 'starorzecze-swierze-dorohusk-21274', 'OXBOW', 51.1992843, 23.7670541, 'Lubelskie', 'Dorohusk', 'Starorzecze w Świerżach to malowniczy akwen położony w dolinie Bugu, charakteryzujący się umiarkowanym stopniem zarastania i zróżnicowaną głębokością. Dno jest głównie piaszczysto-muliste, z pojedynczymi korzeniami i gałęziami, które stanowią naturalne kryjówki dla ryb. Brzegi są w większości dobrze dostępne, co ułatwia swobodne przemieszczanie się wzdłuż łowiska i znalezienie dogodnego miejsca do zarzucenia wędki. Połączenie z rzeką Bug podczas wysokich wód zapewnia regularne odświeżanie wody i dopływ nowych ryb, co pozytywnie wpływa na populację. Jest to znakomite miejsce dla wędkarzy polujących na szczupaka, leszcza, płoć, lina i okonia, które znajdują tu idealne warunki do żerowania i rozwoju. Wędkowanie jest tu przyjemne i oferuje dobre perspektywy na udany połów przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21274, 5, 2.1, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Lin,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21275, 'Starorzecze (Świerże) - Południowe', 'starorzecze-swierze-poludniowe-swierze-21275', 'OXBOW', 51.1985877, 23.7733444, 'Lubelskie', 'Świerże', 'To starorzecze, zlokalizowane w malowniczej dolinie rzeki Bug, charakteryzuje się typowym dla tego regionu, mulistym dnem, które w głębszych partiach przechodzi w twardsze podłoże. Brzegi są częściowo zarośnięte bujną roślinnością szuwarową i krzewami, co utrudnia dostęp, ale jednocześnie tworzy doskonałe kryjówki dla ryb. Wędkarze mogą spodziewać się tu licznych okazów lina, karasia pospolitego oraz płoci, a także drapieżników takich jak szczupak, czatujących w zaroślach. Wiosenne wylewy Bugu zapewniają regularne odświeżanie wody i uzupełnianie populacji ryb, jednak w okresach suszy poziom wody może znacząco spaść. Łowisko to wymaga cierpliwości i często brodzenia w wodzie, co jest rekompensowane możliwością złowienia naprawdę okazałych ryb. Ze względu na bogatą roślinność podwodną, zaleca się stosowanie mocniejszych zestawów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21275, 3.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Trudny, miejscami bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21276, 'Starorzecze (Świerże) - Północne', 'starorzecze-swierze-polnocne-swierze-21276', 'OXBOW', 51.1969051, 23.772289, 'Lubelskie', 'Świerże', 'To mniejsze starorzecze w pobliżu Świerży jest klasycznym przykładem silnie zeutrofizowanego zbiornika, charakteryzującego się znacznym zamuleniem dna i gęstym porostem roślinności wodnej. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga użycia brodzaków. Dominują tu gatunki ryb dobrze adaptujące się do trudnych warunków, takie jak lin, karaś pospolity oraz wzdręga. Wędkarstwo w tym miejscu to prawdziwe wyzwanie, ale dla miłośników spokojnego łowienia w dzikiej scenerii może być bardzo satysfakcjonujące. Należy liczyć się z wysokim ryzykiem przyduchy w gorące lata lub zimą pod lodem, co wpływa na populację ryb. Gęsta roślinność podwodna stanowi naturalne schronienie dla drobnicy, ale też utrudnia prowadzenie przynęt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21276, 2.8, 1.2, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21277, 'Starorzecze (Okopy)', 'starorzecze-okopy-okopy-21277', 'OXBOW', 51.1835275, 23.7831046, 'Lubelskie', 'Okopy', 'Starorzecze w Okopach to średniej wielkości zbiornik, którego dno jest zróżnicowane – od miękkiego mułu po twardsze, piaszczyste fragmenty, szczególnie w pobliżu dawnego nurtu rzeki. Brzegi są dostępne z jednej strony, natomiast druga jest gęsto zarośnięta, co tworzy idealne warunki dla drapieżników. Akwen ten słynie z populacji szczupaka i okonia, ale także występują tu liczne leszcze, płocie i liny. Wiosenne wylewy rzeki Bug okresowo łączą starorzecze z głównym nurtem, co sprzyja migracji ryb i odświeżaniu wody. Duża ilość zatopionych drzew i gałęzi stanowi zarówno wyzwanie dla wędkarzy, jak i doskonałe schronienie dla ryb. Wędkarstwo tutaj wymaga często użycia brodzaków, aby dotrzeć do najlepszych miejscówek. Jest to łowisko o dużym potencjale, szczególnie dla spinningistów i łowiących na żywca.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21277, 4.1, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Leszcz,Płoć,Lin,Okoń', 'Dobry z jednej strony, druga zarośnięta', TRUE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21278, 'Starorzecze (Budomierz)', 'starorzecze-budomierz-budomierz-21278', 'OXBOW', 50.1014486, 23.2772354, 'Podkarpackie', 'Budomierz', 'To niewielkie starorzecze w Budomierzu to typowy, silnie zeutrofizowany zbiornik, charakteryzujący się bardzo wysokim poziomem zamulenia i gęstą roślinnością podwodną. Brzegi są trudne do pokonania, mocno zarośnięte i bagniste, co sprawia, że dostęp do wody jest prawdziwym wyzwaniem. Akwen ten, ze względu na brak stałego połączenia z rzeką, jest domem głównie dla gatunków odpornych na niską zawartość tlenu i wysokie temperatury, takich jak karaś pospolity, lin i wzdręga. W okresach długotrwałej suszy istnieje ryzyko całkowitego wyschnięcia zbiornika, co dodatkowo utrudnia utrzymanie stabilnej populacji ryb. Wędkarstwo tutaj to przede wszystkim poszukiwanie spokojnych miejsc i cierpliwe oczekiwanie na branie. Ze względu na płycizny i gęste zarośla, wymagane są brodzaki i lekkie zestawy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21278, 1.9, 1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna i korzenie', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21279, 'Starorzecze (Dorohusk) - Główne', 'starorzecze-dorohusk-glowne-dorohusk-21279', 'OXBOW', 51.1681934, 23.8134973, 'Lubelskie', 'Dorohusk', 'Główne starorzecze w rejonie Dorohuska to rozległy akwen o zróżnicowanym dnie, gdzie muliste osady przeplatają się z twardszymi, piaszczystymi partiami. Brzegi są częściowo dostępne, co ułatwia wędkowanie z gruntu lub spławika, jednak niektóre odcinki są gęsto zarośnięte. Akwen ten jest znany z obfitości leszczy, płoci i szczupaków, a także z występowania suma i okonia, co czyni go atrakcyjnym dla różnych technik wędkarskich. Okresowe połączenia z rzeką Bug podczas wyższych stanów wody zapewniają stałe odświeżanie zbiornika i migrację ryb, co pozytywnie wpływa na ich kondycję. Wędkarze mogą tu liczyć na udane połowy przez cały sezon, zwłaszcza w miejscach z pojedynczymi zatopionymi pniami, które stanowią doskonałe kryjówki. Woda jest stosunkowo głęboka, co minimalizuje ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21279, 5.2, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Sum', 'Dobry z jednej strony, druga zarośnięta', FALSE, 'Pojedyncze zatopione pnie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21280, 'Starorzecze (Dorohusk) - Zachodnie', 'starorzecze-dorohusk-zachodnie-dorohusk-21280', 'OXBOW', 51.1692802, 23.8131049, 'Lubelskie', 'Dorohusk', 'Zachodnie starorzecze w Dorohusku to zbiornik o umiarkowanym zamuleniu dna, z licznymi zatopionymi drzewami, które stanowią doskonałe schronienie dla ryb, ale także wyzwanie dla wędkarzy. Brzegi są bagniste i trudne do przejścia, co wymaga od wędkarzy cierpliwości i odpowiedniego sprzętu, w tym brodzaków. W akwenie tym dominują lin, karaś pospolity, szczupak i płoć, które znajdują tu idealne warunki do życia i rozrodu. Okresowe połączenia z rzeką Bug podczas wiosennych roztopów i jesiennych opadów zapewniają dopływ świeżej wody i nowych osobników. Łowisko to jest szczególnie atrakcyjne wczesną wiosną i latem, gdy ryby są najbardziej aktywne. Ze względu na gęste zaczepy, zaleca się stosowanie mocniejszych żyłek i plecionek, aby zminimalizować ryzyko utraty sprzętu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21280, 3.8, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21281, 'Starorzecze (Dorohusk) - Małe', 'starorzecze-dorohusk-male-dorohusk-21281', 'OXBOW', 51.1698033, 23.8144308, 'Lubelskie', 'Dorohusk', 'To niewielkie starorzecze w Dorohusku jest przykładem płytkiego, silnie zarośniętego i zamulonego zbiornika, który nie ma stałego połączenia z głównym nurtem rzeki. Dno jest bardzo miękkie, a brzegi gęsto porośnięte trzciną i krzewami, co czyni dostęp do wody niezwykle trudnym. W akwenie tym dominują gatunki ryb wyjątkowo odporne na trudne warunki środowiskowe, takie jak karaś pospolity, wzdręga i lin. Wysokie ryzyko przyduchy, zwłaszcza w okresach upałów i mroźnych zim, sprawia, że populacja ryb jest zmienna i często wymaga odnowienia. Wędkarstwo tutaj to raczej forma rekreacji i obcowania z dziką przyrodą niż nastawienie na spektakularne połowy. Ze względu na gęstą roślinność podwodną, wędkarze muszą być przygotowani na częste zaczepy. Jest to idealne miejsce dla cierpliwych miłośników spławika.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21281, 2.5, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21282, 'Starorzecze (Dorohusk) - Południowe', 'starorzecze-dorohusk-poludniowe-dorohusk-21282', 'OXBOW', 51.1634747, 23.8124349, 'Lubelskie', 'Dorohusk', 'Południowe starorzecze w Dorohusku to jeden z większych i lepiej zachowanych zbiorników tego typu w okolicy, charakteryzujący się stosunkowo czystym dnem z pojedynczymi zaczepami. Posiada częste, a czasem stałe połączenie z rzeką Bug, co zapewnia doskonałą jakość wody i bogactwo gatunkowe ryb. Brzegi są dobrze dostępne z obu stron, co ułatwia wędkarstwo z brzegu i umożliwia swobodne poruszanie się. W akwenie tym można spodziewać się okazałych leszczy, płoci, szczupaków, sandaczy, a także okoni, co czyni go atrakcyjnym dla wędkarzy preferujących różnorodne metody. Jest to łowisko o dużym potencjale, dostępne przez cały sezon, idealne zarówno dla początkujących, jak i doświadczonych wędkarzy. Brak ryzyka przyduchy i stabilny poziom wody sprzyjają utrzymaniu zdrowej populacji ryb. Wędkarze cenią je za komfort łowienia i różnorodność gatunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21282, 6, 2.2, 4.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Sandacz,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21283, 'Starorzecze (Łabędziów)', 'starorzecze-labedziow-labedziow-21283', 'OXBOW', 50.7577818, 20.6571563, 'Świętokrzyskie', 'Łabędziów', 'Starorzecze w Łabędziowie, położone w malowniczym regionie świętokrzyskim, to zbiornik o średnim stopniu zamulenia dna, z licznymi zatopionymi drzewami i gałęziami, które tworzą idealne kryjówki dla ryb. Brzegi są bagniste i trudne do pokonania, co wymaga od wędkarzy użycia brodzaków i ostrożności. W akwenie tym dominują lin, karaś pospolity, płoć oraz szczupak, które dobrze adaptują się do warunków starorzecza. Okresowe połączenia z lokalną rzeką podczas wysokiej wody zapewniają odświeżanie zbiornika i migrację ryb, co wzbogaca jego faunę. Łowisko to jest szczególnie atrakcyjne wiosną i latem, gdy roślinność wodna jest bujna, a ryby żerują aktywnie. Wędkarze cenią to miejsce za jego dziki charakter i możliwość złowienia okazałych linów. Należy pamiętać o ryzyku zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21283, 3, 1.4, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21284, 'Starorzecze (Łuszków)', 'starorzecze-luszkow-luszkow-21284', 'OXBOW', 50.8687318, 24.1439315, 'Lubelskie', 'Łuszków', 'Starorzecze w Łuszkowie to niewielki, silnie zamulony zbiornik, charakteryzujący się gęstym porostem roślinności podwodnej i przybrzeżnej, co sprawia, że dostęp do wody jest bardzo utrudniony. Brak stałego połączenia z rzeką Bug powoduje, że jest to akwen o specyficznych warunkach, gdzie dominują gatunki ryb odporne na niską zawartość tlenu i wysokie temperatury, takie jak karaś pospolity, wzdręga i lin. W okresach długotrwałej suszy istnieje realne ryzyko całkowitego wyschnięcia starorzecza, co wpływa na niestabilność populacji ryb. Wędkarstwo tutaj to przede wszystkim poszukiwanie spokojnych miejsc i cierpliwe oczekiwanie na branie, często z wykorzystaniem brodzaków. Ze względu na gęste zarośla i muł, zaleca się stosowanie lekkich zestawów i delikatnych przynęt, aby uniknąć zaczepów. Jest to miejsce dla prawdziwych entuzjastów dzikiego wędkarstwa.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21284, 2.1, 1.1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Mocno zarośnięty trzciną i krzewami', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21285, 'Starorzecze (Sztabin) - Duże', 'starorzecze-sztabin-duze-sztabin-21285', 'OXBOW', 53.6791639, 23.1274867, 'Podlaskie', 'Sztabin', 'Duże starorzecze w Sztabinie, położone w sercu Puszczy Augustowskiej, to rozległy akwen o zróżnicowanym dnie, z umiarkowanym zamuleniem i licznymi zatopionymi drzewami, które tworzą doskonałe schronienie dla ryb. Posiada stałe połączenie z rzeką Biebrzą, co zapewnia doskonałą jakość wody i bogactwo gatunkowe. Brzegi są ogólnie dostępne, choć miejscami mogą być zarośnięte, co dodaje łowisku dzikiego charakteru. Akwen ten słynie z populacji szczupaka, leszcza, płoci, okonia, a także suma, co czyni go atrakcyjnym dla wędkarzy preferujących różne techniki. Jest to łowisko o dużym potencjale, dostępne przez cały sezon, oferujące niezapomniane wrażenia z wędkowania w otoczeniu dzikiej przyrody. Brak ryzyka przyduchy i stabilny poziom wody sprzyjają utrzymaniu zdrowej populacji ryb. Wędkarze cenią je za komfort i różnorodność gatunków, a także za możliwość złowienia naprawdę dużych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21285, 7.5, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Sum', 'Dobry, miejscami zarośnięty', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21286, 'Starorzecze (Sztabin) - Małe', 'starorzecze-sztabin-male-sztabin-21286', 'OXBOW', 53.6786944, 23.1261617, 'Podlaskie', 'Sztabin', 'Mniejsze starorzecze w Sztabinie to zbiornik o średnim zamuleniu dna, z gęstą roślinnością podwodną i licznymi korzeniami, które stanowią naturalne kryjówki dla ryb. Brzegi są trudne do pokonania, bagniste i wymagają użycia brodzaków, co dodaje łowisku dzikiego charakteru. W akwenie tym dominują lin, karaś pospolity, szczupak i płoć, które dobrze adaptują się do specyficznych warunków starorzecza. Okresowe połączenia z rzeką Biebrzą podczas wysokiej wody zapewniają odświeżanie zbiornika i migrację ryb, co wzbogaca jego faunę. Łowisko to jest szczególnie atrakcyjne wiosną i latem, gdy ryby są najbardziej aktywne i żerują w zaroślach. Wędkarze cenią to miejsce za jego dziki charakter i możliwość złowienia okazałych linów. Ze względu na gęste zaczepy, zaleca się stosowanie mocniejszych żyłek i plecionek.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21286, 4, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna i korzenie', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21287, 'Starorzecze (Horodnianka)', 'starorzecze-horodnianka-horodnianka-21287', 'OXBOW', 53.671543, 23.114309, 'Podlaskie', 'Horodnianka', 'Starorzecze w Horodnianka to zbiornik o średnim zamuleniu dna, z bardzo silnym porostem roślinności wodnej i licznymi zatopionymi drzewami, co tworzy idealne warunki dla ryb, ale utrudnia wędkowanie. Brzegi są mocno zarośnięte trzciną, co sprawia, że dostęp do wody jest bardzo trudny i wymaga użycia brodzaków. W akwenie tym dominują lin, karaś pospolity, wzdręga i szczupak, które znajdują tu doskonałe warunki do życia i rozrodu. Okresowe połączenia z rzeką Biebrzą podczas wysokiej wody zapewniają odświeżanie zbiornika i migrację ryb. Łowisko to jest szczególnie atrakcyjne wiosną i wczesnym latem, gdy roślinność wodna nie jest jeszcze tak gęsta, a ryby są najbardziej aktywne. Wędkarze cenią to miejsce za jego dziki charakter i możliwość złowienia okazów w naturalnym środowisku. Należy pamiętać o ryzyku zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21287, 3.2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew i gęsta roślinność', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21288, 'Starorzecze (Karpowicze)', 'starorzecze-karpowicze-karpowicze-21288', 'OXBOW', 53.6362362, 23.0535744, 'Podlaskie', 'Karpowicze', 'Starorzecze w Karpowiczach to jeden z lepiej utrzymanych zbiorników tego typu w regionie, charakteryzujący się stosunkowo czystym dnem z pojedynczymi zaczepami. Posiada stałe połączenie z rzeką Biebrzą, co zapewnia doskonałą jakość wody i bogactwo gatunkowe ryb, minimalizując ryzyko przyduchy. Brzegi są dobrze dostępne z obu stron, co ułatwia wędkarstwo z brzegu i umożliwia swobodne poruszanie się wzdłuż łowiska. W akwenie tym można spodziewać się okazów szczupaka, leszcza, okonia, płoci, a także jazia, co czyni go atrakcyjnym dla wędkarzy preferujących różnorodne metody. Jest to łowisko o dużym potencjale, dostępne przez cały sezon, idealne zarówno dla początkujących, jak i doświadczonych wędkarzy. Stabilny poziom wody i bogactwo fauny wodnej gwarantują udane połowy. Wędkarze cenią je za komfort łowienia i różnorodność gatunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21288, 5.5, 2, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Płoć,Jaź', 'Dobry z obu stron', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21289, 'Starorzecze (Czarniewo)', 'starorzecze-czarniewo-czarniewo-21289', 'OXBOW', 53.635352, 23.0524801, 'Podlaskie', 'Czarniewo', 'Starorzecze w Czarniewie to płytki, silnie zamulony zbiornik, charakteryzujący się gęstym porostem roślinności podwodnej i bagnistymi brzegami, co sprawia, że dostęp do wody jest bardzo trudny. Brak stałego połączenia z rzeką Biebrzą powoduje, że jest to akwen o specyficznych warunkach, gdzie dominują gatunki ryb odporne na niską zawartość tlenu i wysokie temperatury, takie jak karaś pospolity, lin i wzdręga. W okresach długotrwałej suszy istnieje realne ryzyko całkowitego wyschnięcia starorzecza, co wpływa na niestabilność populacji ryb. Wędkarstwo tutaj to przede wszystkim poszukiwanie spokojnych miejsc i cierpliwe oczekiwanie na branie, często z wykorzystaniem brodzaków. Ze względu na gęste zarośla i muł, zaleca się stosowanie lekkich zestawów i delikatnych przynęt, aby uniknąć zaczepów. Jest to miejsce dla prawdziwych entuzjastów dzikiego wędkarstwa, ceniących sobie spokój i obcowanie z naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21289, 2.7, 1.3, 2.7, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna i muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21290, 'Starorzecze (Czarny Las)', 'starorzecze-czarny-las-lipsk-21290', 'OXBOW', 53.6621391, 23.0721755, 'Podlaskie', 'Lipsk', 'To starorzecze, położone w malowniczym obszarze Czarnego Lasu, charakteryzuje się typowym dla Biebrzy, mulistym dnem, bogatym w osady organiczne. Brzegi są gęsto porośnięte trzcinami i szuwarami, co sprawia, że dostęp do wody jest utrudniony, szczególnie bez odpowiedniego obuwia. Woda jest płytka, a jej przejrzystość niska, co sprzyja rozwojowi bujnej roślinności podwodnej, stanowiącej schronienie dla wielu gatunków ryb. Dominują tu gatunki takie jak szczupak, lin i karaś pospolity, które doskonale adaptują się do warunków niskiej zawartości tlenu w okresach letnich. Wędkowanie wymaga cierpliwości i precyzji, często z użyciem pontonu lub brodzenia. Jest to idealne miejsce dla wędkarzy poszukujących spokoju i wyzwań.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21290, 3.2, 1, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21291, 'Starorzecze (Czarny Las)', 'starorzecze-czarny-las-lipsk-21291', 'OXBOW', 53.664841, 23.0713964, 'Podlaskie', 'Lipsk', 'To fragment rozległego kompleksu starorzeczy w rejonie Czarnego Lasu, cechujący się umiarkowaną powierzchnią i typowo mulistym dnem. Brzegi są tu nieco bardziej dostępne niż w sąsiednich odcinkach, choć nadal dominują zarośla krzewów i pojedyncze kępy trzcin. Roślinność podwodna jest obfita, tworząc idealne kryjówki dla drapieżników. W starorzeczu tym można spodziewać się przede wszystkim szczupaków i okoni, a także leszczy i płoci, które żerują na otwartych plosach. Połączenie z rzeką Biebrzą jest sporadyczne, głównie podczas wiosennych roztopów, co sprzyja stabilizacji populacji ryb. Wędkowanie spinningowe i spławikowe przynosi najlepsze rezultaty, zwłaszcza wzdłuż pasów roślinności. Należy jednak uważać na liczne zaczepy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21291, 4.5, 1.3, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21292, 'Starorzecze (Czarny Las)', 'starorzecze-czarny-las-lipsk-21292', 'OXBOW', 53.6648902, 23.0730868, 'Podlaskie', 'Lipsk', 'Kolejne starorzecze w obrębie Czarnego Lasu, charakteryzujące się wydłużonym kształtem i stosunkowo płytką wodą. Dno jest tu głównie muliste, z domieszką piasku w płytszych partiach, co sprzyja występowaniu różnorodnej roślinności. Brzegi są zmienne, od łatwo dostępnych, trawiastych fragmentów, po gęste zarośla trzcin i olch, wymagające brodzenia. W starorzeczu tym często spotyka się karasie pospolite i liny, które preferują spokojne, zarośnięte wody, a także liczne wzdręgi i płocie. Ryby drapieżne, takie jak szczupak i okoń, patrolują granice roślinności, czekając na dogodny moment do ataku. Wędkowanie jest najbardziej efektywne metodami spławikowymi i gruntowymi, szczególnie w ciepłych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21292, 2.8, 0.9, 2.2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć,Szczupak', 'Miejscami trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna i zatopione gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21293, 'Starorzecze (Dolistowo Stare)', 'starorzecze-dolistowo-stare-dolistowo-stare-21293', 'OXBOW', 53.5703175, 22.9238186, 'Podlaskie', 'Dolistowo Stare', 'To starorzecze, położone w pobliżu Dolistowa Starego, jest typowym przykładem zbiornika o umiarkowanej wielkości, silnie związanego z cyklem wylewów Biebrzy. Charakteryzuje się mulisto-piaszczystym dnem i bogatą roślinnością zanurzoną oraz wynurzoną, która stanowi doskonałe schronienie dla ryb. Brzegi są częściowo dostępne, ale w wielu miejscach porastają je gęste trzciny i krzewy wierzbowe, co wymaga ostrożności i często użycia brodów. W starorzeczu tym dominują leszcze, płocie i okonie, a także często spotyka się liny w zacisznych zatoczkach. Wiosenne wylewy rzeki przynoszą świeżą wodę i odżywiają ekosystem, co sprzyja dynamicznemu rozwojowi populacji ryb. Wędkowanie jest tu bardzo satysfakcjonujące.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21293, 6.1, 1.5, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Lin,Szczupak', 'Umiarkowany, miejscami wymaga brodzenia', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21294, 'Starorzecze (Dolistowo Stare)', 'starorzecze-dolistowo-stare-dolistowo-stare-21294', 'OXBOW', 53.5632578, 22.9143128, 'Podlaskie', 'Dolistowo Stare', 'Mniejsze starorzecze w rejonie Dolistowa Starego, które charakteryzuje się silnym zarośnięciem i postępującym zamulaniem. Dno jest głęboko muliste, co sprzyja rozwojowi bujnej roślinności podwodnej, utrudniającej wędkowanie. Brzegi są bagniste i trudno dostępne, gęsto porośnięte sitowiem i trzcinami, wymagającymi użycia brodów lub pontonu. Woda jest płytka i często nagrzewa się w lecie, co zwiększa ryzyko przyduchy, szczególnie w okresach bezdeszczowych. Dominującymi gatunkami są tu karasie pospolite i liny, które dobrze znoszą trudne warunki, a także wzdręgi i nieliczne szczupaki. Wędkowanie jest wyzwaniem, ale może przynieść satysfakcjonujące efekty dla cierpliwych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21294, 1.8, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21295, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-21295', 'OXBOW', 53.5376849, 22.852461, 'Podlaskie', 'Wólka Piaseczna', 'To starorzecze, zlokalizowane w pobliżu Wólki Piasecznej, stanowi część większego kompleksu starorzeczy Biebrzy. Charakteryzuje się piaszczysto-mulistym dnem i umiarkowanym zarośnięciem, co ułatwia wędkowanie z brzegu. Brzegi są stosunkowo stabilne, choć miejscami mogą być podmokłe, porośnięte trawą i rzadkimi kępami trzcin. Jest to doskonałe miejsce dla wędkarzy poszukujących płoci, leszczy i okoni, które licznie występują w tym zbiorniku. Połączenie z rzeką jest okresowe, co zapewnia regularne zarybianie naturalne podczas wysokich stanów wody. Wędkowanie spławikowe i gruntowe jest tutaj najbardziej efektywne, zwłaszcza w okolicach podwodnych górek i zagłębień. Można liczyć na ciekawe brania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21295, 5.5, 1.4, 3.2, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry z jednej strony, miejscami zarośnięty', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21296, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-21296', 'OXBOW', 53.540293, 22.8590513, 'Podlaskie', 'Wólka Piaseczna', 'Długie i wąskie starorzecze w rejonie Wólki Piasecznej, charakteryzujące się głębszymi partiami wody i dobrze ukształtowanym dnem. Dno jest zróżnicowane, od mulistego po piaszczyste, z licznymi zatopionymi korzeniami i gałęziami, które stanowią schronienie dla ryb. Brzegi są w większości stabilne i dostępne, choć w niektórych miejscach mogą być pokryte gęstą roślinnością przybrzeżną. W starorzeczu tym często łowi się szczupaki i sumy, które polują wzdłuż brzegów i na otwartych wodach. Licznie występują tu również leszcze i karpie, zwłaszcza w miejscach o bogatszym dnie. Wędkowanie spinningowe i gruntowe przynosi najlepsze rezultaty, oferując szansę na złowienie naprawdę dużych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21296, 7, 2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sum,Leszcz,Karp,Okoń', 'Dobry z obu stron, miejscami utrudniony przez roślinność', FALSE, 'Dużo zatopionych drzew i korzeni', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21297, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-21297', 'OXBOW', 53.5403329, 22.8658318, 'Podlaskie', 'Wólka Piaseczna', 'To starorzecze, choć położone blisko innych, ma swój unikalny charakter, będąc bardziej odizolowanym od głównego koryta rzeki. Dno jest tu głównie muliste, z grubą warstwą osadów, co sprzyja rozwojowi specyficznej flory i fauny. Brzegi są bagniste i gęsto zarośnięte, co sprawia, że dostęp do wody jest bardzo trudny, a brodzenie często niezbędne. Dominującymi gatunkami ryb są karasie pospolite i liny, które doskonale radzą sobie w płytkich, zarośniętych wodach. Występują tu również wzdręgi i nieliczne szczupaki, polujące z zasadzki. Wędkowanie wymaga specjalistycznego sprzętu i cierpliwości, ale może nagrodzić okazowymi egzemplarzami dla wytrwałych wędkarzy. Ryzyko przyduchy jest wysokie w upalne lata.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21297, 2.1, 0.7, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Bardzo trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna i muł', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21298, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-21298', 'OXBOW', 53.5407362, 22.862463, 'Podlaskie', 'Wólka Piaseczna', 'To starorzecze cechuje się umiarkowanym rozmiarem i dobrym połączeniem z systemem rzecznym podczas wysokiej wody. Dno jest zróżnicowane, od mulistego po piaszczyste, z miejscowymi twardymi fragmentami, co sprzyja różnorodności siedlisk. Brzegi są w większości dostępne, z licznymi polankami wolnymi od gęstych zarośli, choć miejscami występują trzciny. W wodach tego starorzecza często spotyka się leszcze, płocie i okonie, a także szczupaki, które aktywnie żerują wzdłuż pasów roślinności. Okresowe wylewy Biebrzy wzbogacają zbiornik w nowe gatunki i pokarm, utrzymując jego ekosystem w dobrej kondycji. Idealne miejsce na wędkowanie spławikowe i spinningowe, oferujące zróżnicowane doświadczenia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21298, 4.8, 1.2, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak', 'Dobry, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21299, 'Starorzecze (Dolistowo Nowe)', 'starorzecze-dolistowo-nowe-dolistowo-nowe-21299', 'OXBOW', 53.5425994, 22.8674411, 'Podlaskie', 'Dolistowo Nowe', 'To starorzecze, położone w pobliżu Dolistowa Nowego, jest przykładem zbiornika o stabilnym, choć okresowym, połączeniu z rzeką. Dno jest głównie muliste, z bogatą warstwą osadów organicznych, co sprzyja rozwojowi bujnej roślinności podwodnej. Brzegi są częściowo dostępne, ale w wielu miejscach porastają je gęste trzciny i krzewy, które mogą utrudniać swobodne poruszanie się. W starorzeczu tym dominują leszcze, płocie i karasie srebrzyste, które dobrze adaptują się do zmiennych warunków wodnych. Występują tu również szczupaki i okonie, polujące w zaroślach. Wędkowanie jest najbardziej efektywne metodami spławikowymi i gruntowymi, szczególnie wczesną wiosną i jesienią, kiedy roślinność nie jest jeszcze tak bujna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21299, 3.9, 1.1, 2.6, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Leszcz,Płoć,Karaś srebrzysty,Szczupak,Okoń', 'Umiarkowany, miejscami mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21300, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-21300', 'OXBOW', 53.5389781, 22.8557698, 'Podlaskie', 'Wólka Piaseczna', 'To stosunkowo młode starorzecze w kompleksie Wólki Piasecznej, charakteryzujące się dobrze zachowanym korytem i mniejszym stopniem zamulenia. Dno jest zróżnicowane, z przewagą piasku i żwiru w głębszych partiach, co sprzyja występowaniu różnorodnych gatunków ryb. Brzegi są w większości łatwo dostępne, porośnięte trawą i pojedynczymi krzewami, co ułatwia swobodne wędkowanie z brzegu. W starorzeczu tym licznie występują płocie, leszcze i okonie, a także bolenie i jazie, które preferują czystszą wodę. Okresowe połączenie z Biebrzą zapewnia stały dopływ świeżej wody i ryb. Wędkowanie spinningowe i spławikowe jest tu bardzo efektywne, oferując dynamiczne doświadczenia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21300, 6.5, 1.8, 4, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Boleń,Jaź', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21301, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-trzcianne-21301', 'OXBOW', 53.5036712, 22.7741217, 'Podlaskie', 'Trzcianne', 'To odizolowane starorzecze, położone bardziej na południe w rejonie Wólki Piasecznej, blisko miejscowości Trzcianne. Charakteryzuje się bardzo płytką wodą i silnym zamuleniem, co sprzyja intensywnemu rozwojowi roślinności wodnej. Brzegi są bagniste i trudno dostępne, gęsto porośnięte trzcinami i szuwarami, wymagającymi użycia brodów. Woda w lecie często nagrzewa się do wysokich temperatur, zwiększając ryzyko przyduchy. Dominującymi gatunkami są tu karasie pospolite i liny, które doskonale radzą sobie w takich warunkach. Występują również wzdręgi i nieliczne płocie. Wędkowanie jest wyzwaniem, ale może przynieść satysfakcję w postaci okazowych ryb dla cierpliwych i doświadczonych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21301, 2, 0.6, 1.4, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Bardzo trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna i muł', 'Późna wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21302, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-trzcianne-21302', 'OXBOW', 53.5187589, 22.7912812, 'Podlaskie', 'Trzcianne', 'To starorzecze, położone w obszarze rozlewisk Biebrzy, cechuje się umiarkowaną wielkością i okresowym połączeniem z rzeką. Dno jest mulisto-piaszczyste, z licznymi zagłębieniami i podwodnymi przeszkodami, które stanowią doskonałe kryjówki dla ryb. Brzegi są częściowo dostępne, ale w wielu miejscach porastają je gęste zarośla krzewów i trzcin, wymagające ostrożności. W starorzeczu tym często spotyka się szczupaki i okonie, które polują wśród roślinności, a także leszcze i płocie. Okresowe wylewy Biebrzy wzbogacają zbiornik w pokarm i świeżą wodę, co sprzyja rozwojowi populacji ryb. Wędkowanie spinningowe i spławikowe jest tu najbardziej efektywne, zwłaszcza wzdłuż brzegów i na otwartej wodzie. Warto spróbować swoich sił.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21302, 4, 1.3, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21303, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-trzcianne-21303', 'OXBOW', 53.5100743, 22.7822435, 'Podlaskie', 'Trzcianne', 'To starorzecze, odznaczające się stosunkowo dużą powierzchnią i zróżnicowanym dnem, jest popularnym miejscem wśród lokalnych wędkarzy. Dno jest tu mieszane, od piaszczystego po muliste, z licznymi podwodnymi górami i dołkami, które przyciągają ryby. Brzegi są w większości dostępne, choć miejscami mogą być porośnięte trzcinami, co wymaga znalezienia odpowiedniego stanowiska. W starorzeczu tym licznie występują leszcze, płocie i karpie, a także drapieżniki takie jak szczupak i okoń. Stałe, choć okresowe, połączenie z Biebrzą zapewnia zdrową populację ryb. Wędkowanie gruntowe i spławikowe jest tu bardzo efektywne, szczególnie w cieplejszych miesiącach, gdy ryby są aktywne. Jest to doskonałe miejsce na rodzinny wypad.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21303, 8.2, 1.6, 3.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21304, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-trzcianne-21304', 'OXBOW', 53.5100918, 22.7850089, 'Podlaskie', 'Trzcianne', 'Mniejsze starorzecze w pobliżu Trzciannego, charakteryzujące się płytką wodą i silnym zarośnięciem, typowym dla starzejących się zbiorników. Dno jest głęboko muliste, z grubą warstwą osadów organicznych, co sprzyja rozwojowi bujnej roślinności wodnej. Brzegi są bagniste i bardzo trudno dostępne, gęsto porośnięte trzcinami i sitowiem, co wymaga użycia specjalistycznego sprzętu lub pontonu. Woda w lecie często nagrzewa się, zwiększając ryzyko przyduchy, co wpływa na skład gatunkowy ryb. Dominującymi gatunkami są tu karasie pospolite, liny i wzdręgi, które dobrze znoszą trudne warunki. Wędkowanie jest wyzwaniem, ale może przynieść satysfakcję w postaci okazowych ryb dla wytrwałych wędkarzy. Warto przygotować się na trudności w dostępie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21304, 2.3, 0.7, 1.6, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Bardzo trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna i muł', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21305, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-21305', 'OXBOW', 53.5178144, 22.7922964, 'Podlaskie', 'Wólka Piaseczna', 'To typowe starorzecze rzeki Biebrzy, charakteryzujące się malowniczym położeniem wśród łąk i lasów. Dno jest przeważnie muliste, z miejscowymi twardszymi fragmentami, co sprzyja rozwojowi bogatej roślinności podwodnej. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co utrudnia dostęp do wody, ale jednocześnie stanowi doskonałe schronienie dla ryb. Wędkarze mogą liczyć na obfite populacje szczupaka, który czai się w zaroślach, a także lina i płoci. Latem, zwłaszcza w okresach upałów, istnieje ryzyko przyduchy ze względu na płytkość i obfitość materii organicznej. Wędkowanie wymaga cierpliwości i często brodzenia w woderach, aby dotrzeć do najlepszych miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21305, 3.2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Płoć,Leszcz', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21306, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-21306', 'OXBOW', 53.5144365, 22.7932509, 'Podlaskie', 'Wólka Piaseczna', 'To nieco mniejsze starorzecze, położone w bliskim sąsiedztwie głównego koryta Biebrzy, co zapewnia mu częstsze połączenie z rzeką podczas wezbrań. Dno jest zróżnicowane, od mulistego po gliniasto-piaszczyste, z licznymi zatopionymi gałęziami i korzeniami. Brzegi są dostępne w niektórych miejscach, jednak w większości porośnięte gęstymi krzewami i wysokimi trawami. Jest to doskonałe miejsce dla wędkarzy poszukujących karasia pospolitego i lina, a także okazowych płoci. Ze względu na płytsze partie, w upalne lata może dochodzić do spadku poziomu tlenu, co stanowi wyzwanie. Wędkowanie z gruntu i spławikowe jest najbardziej efektywne, zwłaszcza w pobliżu zarośli.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21306, 2.5, 1.2, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć,Okoń', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21307, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-21307', 'OXBOW', 53.5133488, 22.7893514, 'Podlaskie', 'Wólka Piaseczna', 'To starorzecze charakteryzuje się bardziej otwartymi brzegami w niektórych partiach, co ułatwia dostęp wędkarzom. Dno jest przeważnie twarde, piaszczysto-muliste, z mniejszą ilością roślinności podwodnej w centralnej części. Obszar ten jest znany z występowania dużych leszczy i płoci, które żerują na otwartej wodzie. Na płytszych, zarośniętych fragmentach brzegowych można spotkać szczupaka i okonia. Połączenie z rzeką jest sporadyczne, tylko przy bardzo wysokich stanach wody, co sprzyja stabilności ekosystemu. Ryzyko przyduchy jest niższe niż w innych, bardziej zarośniętych starorzeczach. Wędkowanie z brzegu jest możliwe, ale warto mieć ze sobą podbierak z długą rączką.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21307, 4, 1.8, 3.5, 'Podczas bardzo wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21308, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-21308', 'OXBOW', 53.5126343, 22.7895873, 'Podlaskie', 'Wólka Piaseczna', 'To niewielkie, ale głębokie starorzecze, które jest pozostałością po dawnych meandrach Biebrzy. Charakteryzuje się stromymi brzegami i dużą ilością zatopionych drzew, co tworzy idealne kryjówki dla dużych drapieżników. Dno jest głęboko muliste, z licznymi zaczepami, co stanowi wyzwanie dla wędkarzy. Głównymi gatunkami są sum, szczupak i duży okoń, które znajdują tu idealne warunki do życia. Połączenie z rzeką jest rzadkie, co sprzyja rozwojowi specyficznego ekosystemu. Wędkowanie wymaga ciężkiego sprzętu i umiejętności radzenia sobie z zaczepami. Ze względu na głębokość, ryzyko przyduchy jest minimalne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21308, 1.8, 2.5, 5, 'Brak', 'Wysokie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Okoń,Węgorz', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21309, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-21309', 'OXBOW', 53.5139963, 22.7898181, 'Podlaskie', 'Wólka Piaseczna', 'To starorzecze o kształcie podkowy, częściowo odcięte od głównego nurtu Biebrzy, ale z okresowym połączeniem podczas wiosennych roztopów. Dno jest piaszczysto-muliste, z licznymi podwodnymi łąkami rdestnic i moczarki, co stanowi bogate żerowisko dla ryb. Brzegi są zróżnicowane: od łatwo dostępnych piaszczystych plażek po gęste zarośla trzcinowe. Jest to idealne miejsce dla wędkarzy szukających leszczy, płoci oraz karasi srebrzystych, które licznie występują w tej wodzie. Obfitość roślinności podwodnej wymaga precyzyjnego zarzucania zestawów, aby uniknąć zaczepów. Ryzyko niedoboru tlenu jest umiarkowane, głównie w upalne i bezwietrzne dni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21309, 2.9, 1.4, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Leszcz,Płoć,Karaś srebrzysty,Wzdręga', 'Dobry z obu stron', FALSE, 'Gęsta roślinność podwodna', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21310, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-21310', 'OXBOW', 53.5146311, 22.7891421, 'Podlaskie', 'Wólka Piaseczna', 'To starorzecze jest wyjątkowo malownicze, otoczone starodrzewem, co zapewnia cień i tworzy liczne podwodne kryjówki. Dno jest twarde, żwirowo-piaszczyste w niektórych miejscach, ale dominują tu osady muliste, bogate w naturalne pożywienie dla ryb. Brzegi są miejscami strome, porośnięte drzewami, co utrudnia dostęp, ale jednocześnie chroni łowisko przed wiatrem. Jest to doskonałe miejsce dla wędkarzy poszukujących okazałych płoci i wzdręg, a także drapieżników takich jak szczupak i okoń. Połączenie z rzeką jest sporadyczne, co sprzyja rozwojowi stabilnej populacji ryb. Wędkowanie na spławik i lekką gruntówkę daje najlepsze rezultaty. Ze względu na zacienienie i umiarkowaną głębokość, ryzyko niedoboru tlenu jest niskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21310, 3.5, 1.7, 3.2, 'Podczas bardzo wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Płoć,Wzdręga,Szczupak,Okoń', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21311, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-21311', 'OXBOW', 53.5162897, 22.7873182, 'Podlaskie', 'Wólka Piaseczna', 'To starorzecze jest jednym z bardziej odciętych od głównego nurtu Biebrzy, co sprawia, że jego ekosystem jest bardzo stabilny, ale też podatny na stagnację. Dno jest w przeważającej części mocno zamulone, z grubą warstwą osadów organicznych, co sprzyja rozwojowi gęstej roślinności podwodnej. Brzegi są silnie zarośnięte trzciną i krzewami, co wymaga wysiłku, aby znaleźć dogodne miejsce do wędkowania. Dominującymi gatunkami są lin, karaś pospolity oraz duża płoć, które doskonale czują się w takich warunkach. Latem, zwłaszcza w upalne dni, istnieje wysokie ryzyko przyduchy, dlatego warto monitorować warunki. Wędkowanie z pontonu lub brodzenie w woderach jest często jedyną opcją.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21311, 2, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21312, 'Starorzecze (Goniądz)', 'starorzecze-goniadz-goniadz-21312', 'OXBOW', 53.4943851, 22.7246988, 'Podlaskie', 'Goniądz', 'To obszerne starorzecze położone w pobliżu Goniądza, charakteryzujące się regularnym połączeniem z rzeką Biebrzą podczas wiosennych i jesiennych wezbrań. Dno jest zróżnicowane, od piaszczystych płycizn po głębsze, muliste rynny, co sprzyja różnorodności gatunkowej ryb. Brzegi są miejscami łatwo dostępne, zwłaszcza od strony pól i łąk, ale występują też partie gęsto zarośnięte trzciną. Wędkarze mogą liczyć tu na obfite populacje leszczy, płoci, a także szczupaków i okoni, które wpływają z Biebrzy. Obfitość naturalnego pokarmu sprawia, że ryby są w doskonałej kondycji. Wędkowanie zarówno z gruntu, jak i spinningowe jest bardzo efektywne, zwłaszcza w okresach żerowania drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21312, 5.5, 1.8, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21313, 'Starorzecze (Goniądz)', 'starorzecze-goniadz-goniadz-21313', 'OXBOW', 53.4973414, 22.7407344, 'Podlaskie', 'Goniądz', 'To mniejsze starorzecze, które jest bardziej odizolowane od głównego nurtu, co sprzyja rozwojowi specyficznego środowiska. Dno jest głęboko muliste, z dużą ilością zgnilizny, co jednak nie przeszkadza w rozwoju bujnej roślinności podwodnej. Brzegi są w większości mocno zarośnięte, bagniste, co sprawia, że dostęp do wody jest utrudniony i często wymaga brodzenia. W zbiorniku dominują liny, karasie pospolite oraz wzdręgi, które doskonale radzą sobie w płytkich i ciepłych wodach. Ze względu na izolację i płytkość, ryzyko przyduchy w upalne lato jest wysokie. Wędkowanie na spławik w pobliżu zarośli trzcinowych jest najbardziej skuteczne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21313, 1.5, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21314, 'Starorzecze (Goniądz)', 'starorzecze-goniadz-goniadz-21314', 'OXBOW', 53.4983486, 22.7427729, 'Podlaskie', 'Goniądz', 'To starorzecze jest połączone z Biebrzą stałym, choć wąskim kanałem, co zapewnia ciągłą wymianę wody i bogactwo gatunkowe. Dno jest twarde, piaszczysto-żwirowe, z niewielką ilością mułu w głębszych partiach, co sprzyja występowaniu ryb rzecznych. Brzegi są w większości dostępne, z miejscowymi zaroślami trzcinowymi, które stanowią schronienie dla drobnicy. W zbiorniku występują takie gatunki jak jaź, kleń, boleń, a także szczupak i sandacz, które wpływają z głównego nurtu rzeki. Stałe połączenie minimalizuje ryzyko przyduchy, czyniąc to łowisko stabilnym. Wędkowanie spinningowe i na przepływankę jest tu szczególnie efektywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21314, 4.2, 2, 4, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Jaź,Kleń,Boleń,Szczupak,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21315, 'Starorzecze (Dawidowizna)', 'starorzecze-dawidowizna-dawidowizna-21315', 'OXBOW', 53.5006927, 22.7446754, 'Podlaskie', 'Dawidowizna', 'To starorzecze położone jest w bezpośrednim sąsiedztwie Dawidowizny, charakteryzuje się rozległymi płyciznami i bogactwem roślinności wodnej. Dno jest miękkie, muliste, z grubą warstwą osadów, co sprzyja rozwojowi lilii wodnych i grążeli. Brzegi są gęsto zarośnięte trzciną, co utrudnia dostęp, ale tworzy idealne warunki dla lina i karasia pospolitego. W zbiorniku licznie występuje również wzdręga i płoć, żerujące wśród roślinności. Połączenie z rzeką Biebrzą jest sporadyczne, tylko podczas bardzo wysokich stanów wody. Ze względu na płytkość i obfitość materii organicznej, ryzyko przyduchy jest wysokie. Wędkowanie wymaga cierpliwości i precyzji, często z użyciem woderów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21315, 3, 0.9, 1.8, 'Podczas bardzo wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21316, 'Starorzecze (Dawidowizna)', 'starorzecze-dawidowizna-dawidowizna-21316', 'OXBOW', 53.4996047, 22.7497702, 'Podlaskie', 'Dawidowizna', 'To starorzecze jest średniej wielkości, zlokalizowane nieco dalej od zabudowań, w otoczeniu dzikich łąk. Dno jest mieszane, od twardszych, piaszczystych fragmentów po miękkie, muliste zagłębienia, co sprzyja różnorodności gatunkowej. Brzegi są w większości dostępne, choć miejscami porasta je wysoka trawa i pojedyncze krzewy. Jest to doskonałe miejsce dla wędkarzy szukających szczupaków, które aktywnie polują wzdłuż zarośli, a także leszczy i płoci. Połączenie z rzeką Biebrzą jest okresowe, co odświeża wodę i sprzyja migracji ryb. Ryzyko niedoboru tlenu jest umiarkowane, głównie w skrajnych warunkach pogodowych. Wędkowanie spinningowe i na spławik są tu najbardziej efektywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21316, 3.8, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21317, 'Starorzecze (Dawidowizna)', 'starorzecze-dawidowizna-dawidowizna-21317', 'OXBOW', 53.4999588, 22.7572239, 'Podlaskie', 'Dawidowizna', 'To starorzecze jest jednym z bardziej odizolowanych, co sprzyja rozwojowi bujnej roślinności wodnej i szuwarowej. Dno jest bardzo miękkie, głęboko muliste, z licznymi zaczepami w postaci zatopionych gałęzi i korzeni. Brzegi są trudno dostępne, bagniste i mocno zarośnięte, co wymaga użycia woderów i często przecierania drogi. W zbiorniku dominują liny, karasie pospolite oraz duże wzdręgi, które doskonale czują się w ciepłych i płytkich wodach. Ze względu na brak stałego połączenia i dużą ilość materii organicznej, ryzyko przyduchy jest bardzo wysokie, zwłaszcza latem. Wędkowanie jest wyzwaniem, ale może przynieść satysfakcjonujące efekty w postaci okazowych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21317, 2.2, 0.7, 1.4, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21318, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-21318', 'OXBOW', 53.5034271, 22.7700193, 'Podlaskie', 'Wólka Piaseczna', 'To starorzecze charakteryzuje się umiarkowanym połączeniem z Biebrzą, co zapewnia świeżą wodę i regularne zarybienia naturalne. Dno jest piaszczysto-muliste, z licznymi podwodnymi górkami i dołkami, co tworzy zróżnicowane siedliska dla ryb. Brzegi są miejscami łatwo dostępne, z otwartymi przestrzeniami, ale również z partiami gęsto porośniętymi trzciną. W zbiorniku licznie występują leszcze, płocie, a także szczupaki i okonie, które chętnie żerują na otwartej wodzie i w zaroślach. Ryzyko przyduchy jest niskie ze względu na wymianę wody. Wędkowanie z gruntu i spinning jest tu bardzo popularne i skuteczne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21318, 4.5, 1.9, 3.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21319, 'Starorzecze (Wólka Piaseczna)', 'starorzecze-wolka-piaseczna-wolka-piaseczna-21319', 'OXBOW', 53.5127155, 22.7818251, 'Podlaskie', 'Wólka Piaseczna', 'To starorzecze jest stosunkowo głębokie jak na warunki biebrzańskie, co sprawia, że jest mniej podatne na wahania poziomu wody i temperatury. Dno jest zróżnicowane, od twardych, żwirowych fragmentów po głębokie, muliste rynny, z nieliczną, ale bujną roślinnością podwodną. Brzegi są przeważnie strome i zalesione, co zapewnia naturalny cień i liczne kryjówki dla ryb. W zbiorniku występują duże szczupaki, sandacze, a także sumy i węgorze, które doceniają głębokość i stabilność środowiska. Połączenie z rzeką jest rzadkie, co sprzyja rozwojowi okazowych ryb. Wędkowanie spinningowe i z gruntu na żywca jest tu najbardziej efektywne. Ryzyko przyduchy jest minimalne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21319, 2.8, 2.2, 4.5, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Sum,Węgorz', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21320, 'Starorzecze (Budne)', 'starorzecze-budne-budne-21320', 'OXBOW', 53.4862015, 22.6596692, 'Podlaskie', 'Budne', 'To starorzecze, położone w malowniczej dolinie Biebrzy, charakteryzuje się typowym dla regionu dnem mulistym, z licznymi osadami organicznymi. Brzegi są w większości trudno dostępne i bagniste, co wymaga użycia wodoodpornego obuwia. Roślinność podwodna jest umiarkowana, ale wzdłuż brzegów dominują trzciny i pałki wodne, stanowiące doskonałe kryjówki dla ryb. Wędkowanie utrudniają pojedyncze zatopione korzenie i gałęzie, jednak są to miejsca, gdzie często żerują większe okazy. Dominującymi gatunkami są lin i karaś pospolity, ale z powodzeniem można tu złowić także szczupaka i płocie. Najlepsze efekty osiąga się wiosną i wczesną jesienią, kiedy aktywność ryb jest największa.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21320, 3.2, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21321, 'Starorzecze (Budne)', 'starorzecze-budne-budne-21321', 'OXBOW', 53.4864384, 22.6562172, 'Podlaskie', 'Budne', 'To płytkie starorzecze, zlokalizowane nieopodal Budnych, wyróżnia się wysokim poziomem zamulenia i silnym zarośnięciem. Dno jest gęsto pokryte mułem i roślinnością podwodną, co stanowi wyzwanie dla wędkarzy. Brzegi są mocno zarośnięte trzciną, co utrudnia dostęp do wody i wymaga brodzenia. Wędkowanie z brzegu jest praktycznie niemożliwe bez specjalistycznego sprzętu lub pontonu. Akwen jest ostoją dla karasia pospolitego i lina, a także wzdręgi i płoci, które doskonale czują się w tak zarośniętych środowiskach. Niestety, w okresie letnich upałów istnieje wysokie ryzyko przyduchy, dlatego najlepszy okres na połów to późna wiosna i lato.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21321, 2.5, 1.5, 3, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21322, 'Starorzecze (Budne)', 'starorzecze-budne-budne-21322', 'OXBOW', 53.4867943, 22.6511854, 'Podlaskie', 'Budne', 'Ten akwen, choć położony w bliskim sąsiedztwie innych starorzeczy, wyróżnia się brakiem stałego połączenia z rzeką, co sprzyja stabilności ekosystemu. Dno jest piaszczysto-muliste, z umiarkowaną ilością roślinności, co ułatwia wędkowanie. Dostęp do brzegu jest dobry z jednej strony, podczas gdy druga jest bardziej zarośnięta, oferując różnorodne miejsca do wędkowania. W wodach tego starorzecza dominują leszcze i płocie, często spotyka się również okonie i szczupaki. Brak konieczności używania woderów to duży atut, a pojedyncze korzenie na dnie stanowią naturalne kryjówki dla drapieżników. Jest to łowisko całoroczne, jednak wiosną i jesienią ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21322, 4.1, 2.1, 4.2, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak', 'Dobry z jednej strony, druga zarośnięta', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21323, 'Starorzecze (Osowiec)', 'starorzecze-osowiec-osowiec-twierdza-21323', 'OXBOW', 53.489343, 22.6555654, 'Podlaskie', 'Osowiec-Twierdza', 'To rozległe starorzecze w pobliżu Osowca-Twierdzy wyróżnia się stosunkowo niskim poziomem zamulenia i głębszymi partiami, sięgającymi nawet 5 metrów. Dno jest zróżnicowane, z licznymi zatopionymi drzewami, które stanowią doskonałe miejsca żerowania dla wielu gatunków ryb, ale jednocześnie mogą powodować zaczepy. Dostęp do brzegów jest umiarkowany, miejscami podmokły, co wymaga użycia woderów. Akwen jest prawdziwym eldorado dla wędkarzy poszukujących szczupaków, okoni, leszczy, a nawet sumów i węgorzy. Starorzecze to łączy się z rzeką podczas wysokich stanów wody, co sprzyja migracji ryb i odświeżaniu wody. Najlepsze sezony na wędkowanie to wiosna i jesień, kiedy drapieżniki są szczególnie aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21323, 5.8, 2.5, 5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Węgorz,Sum', 'Umiarkowany, miejscami podmokły', TRUE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21324, 'Starorzecze (Budne)', 'starorzecze-budne-budne-21324', 'OXBOW', 53.4849813, 22.6531729, 'Podlaskie', 'Budne', 'To jedno z płytszych starorzeczy w okolicy Budnych, charakteryzujące się wysokim poziomem zamulenia i silnym zarośnięciem, co sprawia, że jest to łowisko wymagające. Dno jest gęsto pokryte mułem i bujną roślinnością podwodną, która w upalne lata może prowadzić do przyduchy. Brzegi są bardzo trudne do pokonania, bagniste i zarośnięte, co czyni brodzenie w woderach niemal koniecznością. Akwen ten jest domem dla karasia pospolitego, wzdręgi i płoci, które doskonale radzą sobie w trudnych warunkach. Niestety, w szczególnie suchych latach starorzecze może całkowicie wyschnąć, co ogranicza sezon wędkarski głównie do wiosny. Wędkowanie tutaj to wyzwanie, ale może przynieść satysfakcjonujące efekty dla cierpliwych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21324, 1.9, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21325, 'Starorzecze (Szafranki)', 'starorzecze-szafranki-szafranki-21325', 'OXBOW', 53.4867752, 22.6650202, 'Podlaskie', 'Szafranki', 'Położone w pobliżu Szafranek, to starorzecze oferuje zróżnicowane warunki wędkowania, z dnem o umiarkowanym zamuleniu i roślinnością. Akwen łączy się z rzeką podczas wysokich stanów wody, co zapewnia regularne odświeżanie i wzbogacanie ichtiofauny. Dostęp do brzegu jest dobry z jednej strony, co ułatwia rozstawienie sprzętu, choć miejscami jest on lekko zarośnięty. Na dnie występują pojedyncze korzenie i gałęzie, które są naturalnymi kryjówkami dla ryb, szczególnie szczupaków i okoni. Lin i płoć również licznie występują w tym starorzeczu. Najlepsze efekty można osiągnąć wiosną i latem, zwłaszcza w miejscach z dostępem do głębszej wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21325, 3.8, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Okoń,Płoć', 'Dobry z jednej strony, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21326, 'Starorzecze (Szafranki)', 'starorzecze-szafranki-szafranki-21326', 'OXBOW', 53.4863012, 22.6677855, 'Podlaskie', 'Szafranki', 'To starorzecze, charakteryzujące się całkowitym brakiem połączenia z rzeką, jest typowym przykładem zbiornika o zaawansowanym stadium zarastania. Wysoki poziom zamulenia i silne zarośnięcie gęstą roślinnością podwodną sprawiają, że jest to łowisko dla wytrwałych. Brzegi są mocno zarośnięte trzciną i krzewami, co praktycznie uniemożliwia wędkowanie bez brodzenia w woderach. W takich warunkach doskonale czują się liny, karasie pospolite i wzdręgi, które znajdują tu obfite pożywienie i schronienie. Ryzyko przyduchy w miesiącach letnich jest wysokie, dlatego optymalny czas na połów to późna wiosna, zanim roślinność osiągnie szczyt rozwoju. Wędkowanie w tym miejscu to prawdziwe wyzwanie, ale często nagradzane pięknymi okazami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21326, 2.1, 1.7, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną i krzewami', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21327, 'Starorzecze (Szafranki)', 'starorzecze-szafranki-szafranki-21327', 'OXBOW', 53.4869284, 22.6676703, 'Podlaskie', 'Szafranki', 'To stosunkowo niewielkie starorzecze w okolicy Szafranek, oferujące łatwiejsze warunki wędkowania dzięki czystemu dnu. Połączenie z rzeką podczas wysokiej wody sprzyja utrzymaniu zdrowego ekosystemu i różnorodności gatunkowej. Dostęp do brzegu jest umiarkowany, wymaga przejścia przez łąki, ale nie jest bagnisty ani mocno zarośnięty. W akwenie dominują płocie, wzdręgi i okonie, które chętnie żerują na otwartych przestrzeniach. Brak dużej ilości zaczepów sprawia, że jest to dobre miejsce dla początkujących wędkarzy. Jest to łowisko całoroczne, jednak wiosną i jesienią ryby są szczególnie aktywne. Niskie ryzyko przyduchy zapewnia komfort wędkowania nawet w cieplejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21327, 1.5, 1.2, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Wzdręga,Okoń', 'Umiarkowany, wymaga przejścia przez łąki', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21328, 'Starorzecze (Budne)', 'starorzecze-budne-budne-21328', 'OXBOW', 53.4879976, 22.6631078, 'Podlaskie', 'Budne', 'To jedno z większych i głębszych starorzeczy w rejonie Budnych, wyróżniające się stałym połączeniem z rzeką, co zapewnia doskonałą jakość wody i bogactwo ichtiofauny. Niskie zamulenie i słabe zarośnięcie sprawiają, że jest to bardzo atrakcyjne łowisko. Dostęp do brzegu jest dobry z obu stron, co pozwala na swobodne przemieszczanie się i wybór najlepszych miejsc. Akwen ten jest znany z występowania dużych szczupaków, leszczy i okoni, a także sandaczy i boleni, co czyni go rajem dla wędkarzy drapieżników. Brak ryzyka przyduchy i czyste dno z pojedynczymi zaczepami to dodatkowe atuty. Jest to łowisko całoroczne, oferujące emocje przez wszystkie sezony.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21328, 6, 2.8, 5.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Sandacz,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21329, 'Starorzecze (Budne)', 'starorzecze-budne-budne-21329', 'OXBOW', 53.4894004, 22.6623514, 'Podlaskie', 'Budne', 'To starorzecze, położone w malowniczej okolicy Budnych, charakteryzuje się umiarkowanym zamuleniem i roślinnością, co zapewnia dobre warunki dla wielu gatunków ryb. Łączy się z rzeką podczas wysokich stanów wody, co sprzyja migracji i odświeżaniu zasobów. Brzegi są niestety trudne i bagniste, co wymaga użycia woderów i ostrożności podczas poruszania się. Dno obfituje w zatopione drzewa, które stanowią doskonałe kryjówki dla drapieżników, ale jednocześnie mogą być źródłem zaczepów. W wodach dominują liny, karasie pospolite, szczupaki i płocie, które doskonale czują się w tym środowisku. Najlepszy czas na połów to wiosna i wczesna jesień, kiedy ryby intensywnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21329, 4.5, 2.2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21330, 'Starorzecze (Szafranki)', 'starorzecze-szafranki-szafranki-21330', 'OXBOW', 53.4872268, 22.67293, 'Podlaskie', 'Szafranki', 'To starorzecze, położone w pobliżu Szafranek, jest przykładem zbiornika o wysokim stopniu zamulenia i silnym zarośnięciu, co sprawia, że jest to łowisko wymagające specjalistycznego podejścia. Całkowity brak połączenia z rzeką sprzyja stabilizacji warunków, choć w upalne lata może zwiększać ryzyko przyduchy. Brzegi są mocno zarośnięte trzciną, co utrudnia dostęp i wymaga brodzenia w woderach. W takich warunkach doskonale prosperują karasie pospolite, liny, wzdręgi i płocie, które są odporne na trudniejsze warunki środowiskowe. Gęsta roślinność podwodna stanowi naturalne schronienie i źródło pokarmu. Najlepszy okres na połów to późna wiosna, zanim roślinność osiągnie apogeum rozwoju.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21330, 2.9, 1.6, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21331, 'Starorzecze (Szafranki)', 'starorzecze-szafranki-szafranki-21331', 'OXBOW', 53.4875078, 22.6750543, 'Podlaskie', 'Szafranki', 'To starorzecze, zlokalizowane w okolicy Szafranek, charakteryzuje się umiarkowanym zamuleniem i roślinnością, oferując dobre warunki do wędkowania. Połączenie z rzeką podczas wysokich stanów wody wspiera różnorodność gatunkową i zdrowie akwenu. Dostęp do brzegu jest dobry z jednej strony, choć miejscami teren może być podmokły, co warto wziąć pod uwagę. Na dnie występują pojedyncze korzenie i gałęzie, które są atrakcyjnymi miejscami dla drapieżników. W starorzeczu dominują szczupaki, okonie, leszcze i płocie, co czyni je atrakcyjnym dla wędkarzy preferujących różne metody. Najlepsze efekty osiąga się wiosną i jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21331, 3.5, 1.9, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z jednej strony, miejscami podmokły', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21332, 'Starorzecze (Budne)', 'starorzecze-budne-budne-21332', 'OXBOW', 53.4917798, 22.6747272, 'Podlaskie', 'Budne', 'To rozległe starorzecze w rejonie Budnych, cieszące się stałym połączeniem z rzeką, co gwarantuje dynamiczny ekosystem i obfitość ryb. Niskie zamulenie i umiarkowane zarośnięcie sprawiają, że jest to łowisko o wysokim potencjale. Dostęp do brzegu jest dobry z obu stron, umożliwiając komfortowe wędkowanie. Na dnie znajdują się zatopione drzewa, które tworzą idealne kryjówki dla dużych drapieżników. Akwen jest domem dla szczupaków, sandaczy, leszczy, okoni, a także karpi, co przyciąga wędkarzy z różnych specjalizacji. Brak ryzyka przyduchy i dobre warunki wodne sprawiają, że jest to łowisko całoroczne, idealne do spędzania czasu nad wodą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21332, 5.2, 2.4, 4.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21333, 'Starorzecze (Budne)', 'starorzecze-budne-budne-21333', 'OXBOW', 53.4913027, 22.6757652, 'Podlaskie', 'Budne', 'To starorzecze, jedno z płytszych w okolicy Budnych, charakteryzuje się wysokim poziomem zamulenia i silnym zarośnięciem, co czyni je trudnym, ale potencjalnie nagradzającym łowiskiem. Całkowity brak połączenia z rzeką w połączeniu z płytkością sprawia, że w suchych latach może całkowicie wyschnąć. Brzegi są trudne, bagniste i gęsto zarośnięte, co wymaga użycia woderów. Dno jest pokryte gęstą roślinnością podwodną, stanowiącą schronienie i pożywienie dla karasia pospolitego, wzdręgi i lina. Wędkowanie w tym miejscu to prawdziwe wyzwanie, ale dla miłośników starorzeczy może przynieść piękne okazy. Najlepszy okres na połów to wiosna, zanim upały i susza zbytnio obniżą poziom wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21333, 1.8, 1.1, 2.6, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21334, 'Starorzecze (Budne)', 'starorzecze-budne-budne-21334', 'OXBOW', 53.4902446, 22.6735898, 'Podlaskie', 'Budne', 'To starorzecze, położone w malowniczej dolinie Biebrzy niedaleko Budnych, charakteryzuje się umiarkowanym zamuleniem i roślinnością, co sprzyja różnorodności gatunkowej. Łączy się z rzeką podczas wysokich stanów wody, co zapewnia regularne odświeżanie i wzbogacanie ichtiofauny. Dostęp do brzegu jest dobry z jednej strony, choć miejscami może być lekko zarośnięty, co wymaga uwagi. Na dnie występują pojedyncze korzenie i gałęzie, które są naturalnymi kryjówkami dla ryb, szczególnie szczupaków i okoni. Lin i płoć również licznie występują w tym starorzeczu. Najlepsze efekty można osiągnąć wiosną i wczesną jesienią, kiedy ryby intensywnie żerują, a ryzyko przyduchy jest umiarkowane.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21334, 4, 2, 3.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Okoń,Płoć', 'Dobry z jednej strony, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21335, 'Starorzecze (Budne)', 'starorzecze-budne-goniadz-21335', 'OXBOW', 53.489402, 22.6782784, 'Podlaskie', 'Goniądz', 'To malownicze starorzecze, położone w rozległej dolinie Narwi, charakteryzuje się umiarkowaną głębokością i bogatą roślinnością wodną. Dno jest przeważnie muliste, z licznymi zatopionymi korzeniami i gałęziami, co stanowi doskonałe kryjówki dla ryb. Brzegi są miejscami trudno dostępne, gęsto porośnięte trzciną i krzewami, wymagające ostrożności podczas wędkowania. Wędkowanie z pontonu lub brodzenie w woderach może znacznie ułatwić dostęp do atrakcyjnych miejsc. Akwen ten jest znany z populacji szczupaka i lina, ale można tu również złowić dorodne płocie i okonie. Ryzyko przyduchy jest umiarkowane, zwłaszcza w upalne lata.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21335, 4.8, 1.5, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Płoć,Okoń', 'Umiarkowany, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21336, 'Starorzecze (Budne)', 'starorzecze-budne-goniadz-21336', 'OXBOW', 53.4916585, 22.6806736, 'Podlaskie', 'Goniądz', 'Ten fragment starorzecza wyróżnia się nieco większą głębokością w centralnej części, co sprzyja występowaniu większych okazów ryb. Dno jest zróżnicowane, od mulistego po twardsze, piaszczyste odcinki, szczególnie w pobliżu dawnego nurtu rzeki. Gęste zarośla trzcin i pałki wodnej dominują na brzegach, tworząc naturalne bariery, ale i doskonałe miejsca do bytowania ryb. Wędkarze mogą spodziewać się tu imponujących linów i karpi, a także aktywnych okoni i szczupaków. Połączenie z rzeką Narew występuje sporadycznie, głównie podczas wiosennych roztopów. Należy pamiętać o ryzyku przyduchy w okresach długotrwałych upałów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21336, 6.2, 1.8, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karp,Okoń,Szczupak,Leszcz', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21337, 'Starorzecze (Szafranki)', 'starorzecze-szafranki-goniadz-21337', 'OXBOW', 53.4855128, 22.6768649, 'Podlaskie', 'Goniądz', 'To płytkie starorzecze, usytuowane niedaleko miejscowości Szafranki, jest idealnym miejscem dla wędkarzy poszukujących karasia pospolitego i wzdręgi. Dno jest w większości muliste, z grubą warstwą osadów organicznych, co sprzyja rozwojowi bogatej roślinności podwodnej. Brzegi są stosunkowo łatwo dostępne w niektórych miejscach, jednak w wielu innych są mocno zarośnięte bujnymi szuwarami. Wędkowanie z brzegu wymaga często wycięcia niewielkiego stanowiska. Występuje tu również płoć i okoń, a szczupaki patrolują granice zarośli. Ze względu na płytkość, w upalne lata istnieje wysokie ryzyko niedoboru tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21337, 3.5, 1.1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć,Okoń', 'Umiarkowany, miejscami zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21338, 'Starorzecze (Budne)', 'starorzecze-budne-goniadz-21338', 'OXBOW', 53.4970701, 22.7082131, 'Podlaskie', 'Goniądz', 'Ten rozległy akwen to jedno z większych starorzeczy w okolicy Budnego, oferujące zróżnicowane warunki do wędkowania. Głębokość jest zmienna, z wyraźnymi rynnami i płytszymi zatokami, co przyciąga różnorodne gatunki ryb. Dno jest mozaiką mułu, piasku i zatopionych drzew, stanowiących schronienie dla drapieżników. Brzegi są miejscami dostępne, ale w wielu odcinkach bagniste i gęsto porośnięte olchami i wierzbami. Wędkowanie na tym starorzeczu jest wyzwaniem, ale nagradza dużymi szczupakami, sumami i leszczami. Połączenie z rzeką jest rzadkie, co sprzyja stabilizacji populacji ryb. Warto zabrać ze sobą wędki na różne metody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21338, 12, 2.2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sum,Leszcz,Karp,Okoń', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21339, 'Starorzecze (Szafranki)', 'starorzecze-szafranki-goniadz-21339', 'OXBOW', 53.489584, 22.6971719, 'Podlaskie', 'Goniądz', 'To starorzecze charakteryzuje się dość regularnym kształtem i umiarkowaną głębokością, co czyni je atrakcyjnym dla wielu wędkarzy. Dno jest przeważnie muliste, ale bez nadmiernego zamulenia, z rozproszonymi kępami roślinności podwodnej. Brzegi są w większości stabilne i dostępne, choć miejscami mogą być zarośnięte niską roślinnością. Występuje tu dobra populacja płoci i leszczy, a także aktywnych okoni. Starorzecze to jest również znane z obecności karasia srebrzystego, który dobrze adaptuje się do lokalnych warunków. Połączenie z rzeką Narew jest sporadyczne, głównie podczas wiosennych wezbrań. Akwen ten jest stosunkowo odporny na przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21339, 5.1, 1.6, 3, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Karaś srebrzysty,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21340, 'Starorzecze (Szafranki)', 'starorzecze-szafranki-goniadz-21340', 'OXBOW', 53.4897834, 22.694428, 'Podlaskie', 'Goniądz', 'Ten odcinek starorzecza w okolicy Szafranek jest stosunkowo płytki i mocno zarośnięty, co czyni go rajem dla gatunków preferujących płytkie, ciepłe wody. Dno jest bardzo muliste, z grubą warstwą osadów i gęstą roślinnością zanurzoną. Brzegi są trudne do pokonania, porośnięte gęstą trzciną i krzewami, wymagającymi użycia brodzenia. Wędkowanie jest tu wyzwaniem, ale można liczyć na dorodne liny, karasie pospolite i wzdręgi. Obecność szczupaka jest również zauważalna, zwłaszcza w miejscach z większymi prześwitami. Ze względu na płytkość i obfitość materii organicznej, ryzyko przyduchy jest wysokie w okresie letnim.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21340, 2.8, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21341, 'Starorzecze (Szafranki)', 'starorzecze-szafranki-goniadz-21341', 'OXBOW', 53.4879482, 22.6957289, 'Podlaskie', 'Goniądz', 'To starorzecze, choć niewielkie, oferuje ciekawe możliwości dla wędkarzy ceniących spokój i kontakt z naturą. Charakteryzuje się umiarkowaną głębokością i zróżnicowanym dnem, gdzie muł miesza się z twardszymi fragmentami. Brzegi są miejscami dostępne, ale w innych odcinkach gęsto porośnięte roślinnością szuwarową, co utrudnia swobodne poruszanie się. Występują tu liczne płocie i leszcze, a także okonie polujące na narybek. Można również natrafić na lina, szczególnie w cieplejszych miesiącach, gdy żeruje aktywnie. Ryzyko przyduchy jest niskie, dzięki stosunkowo dobrej cyrkulacji wody. Wędkowanie jest najbardziej efektywne wczesną wiosną i jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21341, 3.1, 1.4, 2.8, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Lin', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21342, 'Starorzecze (Szafranki)', 'starorzecze-szafranki-goniadz-21342', 'OXBOW', 53.487629, 22.6945915, 'Podlaskie', 'Goniądz', 'Ten fragment starorzecza to typowy akwen z mulistym dnem i bogatą roślinnością zanurzoną, co stanowi idealne środowisko dla wielu gatunków ryb. Głębokość jest stosunkowo niewielka, co sprzyja szybkiemu nagrzewaniu się wody w lecie. Brzegi są mocno zarośnięte trzciną i krzewami, co sprawia, że dostęp do wody jest utrudniony i często wymaga brodzenia. Wędkarze mogą liczyć na karasie pospolite, wzdręgi i liny, które doskonale czują się w takich warunkach. Występuje tu również populacja szczupaka, polującego wzdłuż pasów roślinności. Ze względu na płytkość i bujną roślinność, ryzyko przyduchy jest wysokie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21342, 2.5, 1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Lin,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21343, 'Starorzecze (Szafranki)', 'starorzecze-szafranki-goniadz-21343', 'OXBOW', 53.4874423, 22.6927891, 'Podlaskie', 'Goniądz', 'To starorzecze charakteryzuje się bardziej otwartym charakterem niż sąsiednie, z mniejszą ilością gęstych zarośli wodnych w centralnej części. Dno jest przeważnie muliste, ale z miejscowymi prześwitami twardszego podłoża, co urozmaica łowisko. Brzegi są w miarę dostępne, choć miejscami mogą pojawić się pasy trzcin. Występuje tu dobra populacja płoci, leszczy i okoni, a także karasia srebrzystego, który dobrze radzi sobie w tych warunkach. Sporadycznie można trafić na szczupaka, zwłaszcza na granicy roślinności. Akwen ten jest stosunkowo stabilny pod względem warunków tlenowych, co sprzyja całorocznemu wędkowaniu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21343, 4, 1.3, 2.7, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Karaś srebrzysty', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21344, 'Starorzecze (Szafranki)', 'starorzecze-szafranki-goniadz-21344', 'OXBOW', 53.4863586, 22.6895866, 'Podlaskie', 'Goniądz', 'Ten odcinek starorzecza to idealne miejsce dla wędkarzy ceniących spokój i możliwość złowienia dużego lina lub karasia. Akwen jest stosunkowo płytki, z bardzo mulistym dnem i obfitością roślinności podwodnej, co sprzyja rozwojowi bogatego ekosystemu. Brzegi są mocno zarośnięte, co wymaga wysiłku w dotarciu do wody, ale zapewnia doskonałe kryjówki dla ryb. Występują tu również wzdręgi i płocie, które żerują wśród roślinności. Połączenie z rzeką Narew jest bardzo rzadkie, co sprzyja stabilizacji warunków. W upalne lata ryzyko przyduchy jest wysokie, dlatego warto monitorować pogodę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21344, 3.2, 1, 2.4, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21345, 'Starorzecze (Szafranki)', 'starorzecze-szafranki-goniadz-21345', 'OXBOW', 53.4863204, 22.6875051, 'Podlaskie', 'Goniądz', 'To starorzecze, choć płytkie, jest bardzo produktywne i oferuje dobre warunki do połowu wielu gatunków ryb. Dno jest muliste z dużą ilością detrytusu, co sprzyja rozwojowi bezkręgowców, stanowiących bazę pokarmową dla ryb. Brzegi są zróżnicowane – miejscami dostępne, a w innych odcinkach gęsto porośnięte trzciną i wierzbami. Można tu złowić piękne liny, karasie pospolite i wzdręgi, a także aktywne okonie. Ze względu na bogactwo roślinności, szczupaki również znajdują tu idealne warunki do bytowania i polowania. Ryzyko przyduchy jest umiarkowane, ale warto zachować czujność w okresach suszy i upałów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21345, 3.8, 1.1, 2.6, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń,Szczupak', 'Umiarkowany, miejscami zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21346, 'Starorzecze (Budne)', 'starorzecze-budne-goniadz-21346', 'OXBOW', 53.494419, 22.6966193, 'Podlaskie', 'Goniądz', 'Ten fragment starorzecza w Budnym jest jednym z bardziej zróżnicowanych, z miejscami głębszymi i płytszymi partiami, co sprzyja różnorodności gatunkowej ryb. Dno jest mozaiką mułu, piasku i zatopionych pni, co tworzy liczne kryjówki. Brzegi są w dużej mierze dostępne, choć w niektórych miejscach mogą pojawić się zarośla. Wędkarze mogą spodziewać się tu szczupaków, okoni, a także leszczy i płoci. W głębszych partiach można trafić na większe okazy karpia. Połączenie z rzeką Narew występuje podczas wysokich stanów wody, co wzbogaca populację ryb. Akwen ten jest stosunkowo odporny na przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21346, 7.5, 1.9, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21347, 'Starorzecze (Budne)', 'starorzecze-budne-goniadz-21347', 'OXBOW', 53.4920829, 22.7009618, 'Podlaskie', 'Goniądz', 'To starorzecze charakteryzuje się znaczną długością i zmienną szerokością, co tworzy wiele interesujących miejsc do wędkowania. Dno jest przeważnie muliste, ale z twardszymi odcinkami wzdłuż dawnego nurtu. Brzegi są miejscami bagniste i trudno dostępne, porośnięte gęstymi zaroślami, co wymaga użycia woderów. Występuje tu silna populacja szczupaka i okonia, a także leszczy i płoci. Lin i karaś pospolity również są obecne, szczególnie w płytszych, bardziej zarośniętych zatokach. Połączenie z rzeką Narew jest dość regularne podczas wezbrań, co sprzyja migracji ryb. Ryzyko przyduchy jest umiarkowane.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21347, 9, 2.1, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Leszcz,Lin,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21348, 'Starorzecze (Budne)', 'starorzecze-budne-goniadz-21348', 'OXBOW', 53.4920542, 22.7018738, 'Podlaskie', 'Goniądz', 'Ten odcinek starorzecza to głębsze partie, które sprzyjają występowaniu większych okazów ryb i gatunków preferujących chłodniejsze wody. Dno jest zróżnicowane, z mulistymi zatokami i twardszymi, piaszczystymi garami. Brzegi są w większości stabilne i dostępne, choć miejscami mogą pojawić się kępy trzcin. Wędkarze mogą liczyć na dorodne leszcze, płocie i karpie, a także na sumy, które znajdują tu odpowiednie warunki do życia. Szczupak i okoń również są licznie reprezentowane. Akwen ten rzadko doświadcza problemów z przyduchą, co czyni go atrakcyjnym przez cały sezon. Jest to jedno z bardziej cenionych łowisk w okolicy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21348, 10.5, 2.5, 5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Karp,Sum,Szczupak,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21349, 'Starorzecze (Budne)', 'starorzecze-budne-goniadz-21349', 'OXBOW', 53.4925808, 22.7026704, 'Podlaskie', 'Goniądz', 'To starorzecze stanowi urozmaicone łowisko, charakteryzujące się zmienną głębokością i bogactwem podwodnych struktur. Dno jest mozaiką mułu, piasku i zatopionych gałęzi, co tworzy idealne warunki dla drapieżników i ryb spokojnego żeru. Brzegi są częściowo dostępne, ale w wielu miejscach porośnięte gęstymi zaroślami, co utrudnia swobodne poruszanie się. Występuje tu silna populacja okonia i szczupaka, a także karasi pospolitych i linów, które preferują zarośnięte zatoki. Połączenie z rzeką Narew jest sporadyczne, głównie podczas wiosennych wezbrań. W upalne lata istnieje umiarkowane ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21349, 6.8, 1.7, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Okoń,Szczupak,Karaś pospolity,Lin,Płoć', 'Umiarkowany, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21350, 'Starorzecze (Budne)', 'starorzecze-budne-goniadz-21350', 'OXBOW', 53.4961591, 22.7042569, 'Podlaskie', 'Goniądz', 'To rozległe starorzecze, położone w malowniczej dolinie Biebrzy, stanowi typowe łowisko dla wędkarzy poszukujących dzikich ostoi. Charakteryzuje się mulistym dnem z licznymi zatopionymi drzewami i gałęziami, co tworzy doskonałe kryjówki dla drapieżników. Brzegi są gęsto porośnięte trzciną i inną roślinnością przybrzeżną, co utrudnia dostęp do wody i wymaga użycia spodniobutów. Poziom zamulenia jest średni, a zarastanie roślinnością wodną, zwłaszcza w okresie letnim, jest bardzo silne, co zwiększa ryzyko przyduchy. Starorzecze to jest domem dla licznych gatunków ryb, w tym dużych szczupaków, linów, karasi pospolitych oraz płoci, które znajdują tu obfitość pokarmu i schronienia. Połączenie z rzeką główną następuje zazwyczaj podczas wysokich stanów wody, co sprzyja migracji ryb i odnawia ekosystem. Najlepsze efekty wędkarskie można osiągnąć wiosną oraz wczesną jesienią, kiedy roślinność nie jest jeszcze tak bujna, a ryby aktywnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21350, 4.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21351, 'Starorzecze (Olszowa Droga)', 'starorzecze-olszowa-droga-goniadz-21351', 'OXBOW', 53.4225644, 22.548271, 'Podlaskie', 'Goniądz', 'To malownicze starorzecze, położone w pobliżu Olszowej Drogi, jest klasycznym przykładem zbiornika w dolinie rzecznej. Charakteryzuje się piaszczysto-mulistym dnem z miejscowymi osadami organicznymi, sprzyjającymi rozwojowi bezkręgowców. Brzegi są częściowo dostępne, jednak w wielu miejscach porastają je zwarte kępy olsów i krzewów, wymagające ostrożności podczas poruszania się. Roślinność podwodna jest umiarkowana, z przewagą rdestnic i moczarki, co zapewnia schronienie dla drobnicy. Akwen ten jest bogaty w leszcze, płocie i karasie srebrzyste, a także okonie, które chętnie żerują w pobliżu zarośli. Połączenie z rzeką macierzystą jest sporadyczne, głównie podczas wiosennych roztopów. Poziom zamulenia jest umiarkowany, a ryzyko przyduchy występuje głównie w upalne lata. Wędkowanie jest najbardziej efektywne przez cały sezon, zwłaszcza w strefach z roślinnością.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21351, 3.1, 1.2, 2.8, 'Podczas wysokiej wody', 'Umiarkowane', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karaś srebrzysty,Okoń', 'Częściowo dostępny, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21352, 'Starorzecze (Olszowa Droga)', 'starorzecze-olszowa-droga-goniadz-21352', 'OXBOW', 53.4194308, 22.5471103, 'Podlaskie', 'Goniądz', 'To mniejsze starorzecze, położone w kompleksie Olszowej Drogi, stanowi spokojne i urokliwe łowisko. Dno jest przeważnie muliste, z grubą warstwą osadów organicznych, co świadczy o zaawansowanym procesie sukcesji. Brzegi są trudno dostępne, otoczone gęstymi zaroślami wierzb i wysokiej trawy, co wymaga cierpliwości i często użycia spodniobutów. Roślinność wodna jest obfita, szczególnie latem, tworząc liczne podwodne łąki i zarośla. W starorzeczu tym dominują liny, karasie pospolite oraz wzdręgi, które doskonale czują się w takim środowisku. Połączenie z rzeką główną jest rzadkie, co sprzyja rozwojowi specyficznej ichtiofauny. Poziom zamulenia jest wysoki, a silne zarastanie zwiększa ryzyko przyduchy w upalne, bezwietrzne dni. Najlepsze wyniki osiąga się wczesną wiosną i późnym latem, gdy roślinność jest mniej uciążliwa.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21352, 1.8, 0.9, 2.1, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Wczesna wiosna, późne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21353, 'Starorzecze (Klimaszewnica)', 'starorzecze-klimaszewnica-monki-21353', 'OXBOW', 53.4474006, 22.5634138, 'Podlaskie', 'Mońki', 'Starorzecze w Klimaszewnicy to średniej wielkości akwen, charakteryzujący się zróżnicowanym dnem, od twardego piasku po miękki muł w głębszych partiach. Brzegi są stosunkowo łatwo dostępne, z nielicznymi zaroślami, co sprzyja wędkowaniu z brzegu. Roślinność wodna jest umiarkowana, skupiająca się głównie w płytszych zatoczkach i przy brzegach. Jest to doskonałe miejsce dla wędkarzy poszukujących szczupaków, okoni oraz płoci, które licznie występują w tym zbiorniku. Połączenie z rzeką macierzystą jest stabilne podczas wysokich stanów wody, co zapewnia regularne zasilanie w świeżą wodę i migrację ryb. Poziom zamulenia jest niski, a ryzyko przyduchy minimalne dzięki dobrej wymianie wody. Wędkowanie jest komfortowe przez większość sezonu, z dobrymi wynikami od wiosny do jesieni. Akwen ten jest ceniony za czystość wody i różnorodność gatunkową.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21353, 5.5, 1.8, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21354, 'Starorzecze (Klimaszewnica)', 'starorzecze-klimaszewnica-monki-21354', 'OXBOW', 53.4392164, 22.5595531, 'Podlaskie', 'Mońki', 'To drugie starorzecze w rejonie Klimaszewnicy, nieco mniejsze, ale równie atrakcyjne dla wędkarzy. Dno jest przeważnie muliste, z dużą ilością zatopionych gałęzi i liści, co tworzy idealne warunki dla ryb spokojnego żeru. Brzegi są częściowo zarośnięte, lecz znajdują się miejsca umożliwiające swobodne łowienie. Roślinność podwodna jest dość gęsta, szczególnie w środkowej części akwenu, tworząc podwodne łąki. Dominującymi gatunkami ryb są karasie pospolite, liny oraz leszcze, które osiągają tu imponujące rozmiary. Połączenie z rzeką jest rzadkie, co sprzyja stabilizacji warunków wodnych i rozwojowi bujnej roślinności. Poziom zamulenia jest średni, a silne zarastanie może powodować niedobory tlenu w upalne dni. Najlepsze okresy na wędkowanie to późna wiosna i lato, kiedy ryby aktywnie żerują wśród roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21354, 2.7, 1.1, 2.9, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Leszcz,Płoć', 'Częściowo zarośnięty, wymaga poszukiwania miejscówek', FALSE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21355, 'Starorzecze (Downary)', 'starorzecze-downary-goniadz-21355', 'OXBOW', 53.4629619, 22.6100966, 'Podlaskie', 'Goniądz', 'Starorzecze w Downarach to rozległy zbiornik wodny, charakteryzujący się głębokimi rynnami i rozległymi płyciznami. Dno jest zróżnicowane, od twardego piasku po miękki muł, z licznymi zatopionymi drzewami i krzewami stanowiącymi doskonałe kryjówki dla ryb. Brzegi są w większości trudno dostępne, otoczone gęstymi zaroślami, co wymaga użycia pontonu lub długich rzutów. Roślinność wodna jest bardzo obfita, tworząc rozległe dywany moczarki i wywłócznika. Akwen ten słynie z dużych sumów i szczupaków, a także sandaczy, które wchodzą tu podczas wysokich wód. Połączenie z rzeką Biebrzą jest stałe podczas większości roku, co zapewnia doskonałą wymianę wody i zasilanie w ryby. Poziom zamulenia jest średni, a ryzyko przyduchy minimalne dzięki stałemu przepływowi. Wędkowanie jest najbardziej efektywne od wiosny do późnej jesieni, ze szczególnym uwzględnieniem stref z zaczepami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21355, 12, 2.5, 6, 'Stałe połączenie', 'Średnie', 'Silne', FALSE, FALSE, 'Sum,Szczupak,Sandacz,Leszcz,Płoć', 'Trudny, wymaga pontonu lub długich rzutów', TRUE, 'Dużo zatopionych drzew', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21356, 'Starorzecze (okolice Goniądza)', 'starorzecze-okolice-goniadza-goniadz-21356', 'OXBOW', 53.3543104, 22.5212913, 'Podlaskie', 'Goniądz', 'To niewielkie, lecz urokliwe starorzecze, położone w dzikich zakątkach doliny Biebrzy. Charakteryzuje się bardzo mulistym dnem, bogatym w substancje organiczne, co sprzyja rozwojowi bujnej roślinności wodnej. Brzegi są praktycznie niedostępne, otoczone gęstymi szuwarami i podmokłymi łąkami, co wymaga specjalistycznego sprzętu lub brodzenia. Roślinność podwodna jest ekstremalnie gęsta, tworząc naturalne labirynty. W zbiorniku tym dominują liny, karasie pospolite oraz wzdręgi, które doskonale adaptują się do trudnych warunków. Połączenie z rzeką jest bardzo rzadkie, występujące tylko podczas ekstremalnie wysokich wód. Poziom zamulenia jest wysoki, a silne zarastanie prowadzi do częstych przyduch, zwłaszcza zimą i w upalne lata. Wędkowanie jest tu wyzwaniem, ale może przynieść nagrody w postaci okazowych ryb, najlepiej wczesną wiosną.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21356, 1.5, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Wczesna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21357, 'Starorzecze (okolice Goniądza)', 'starorzecze-okolice-goniadza-goniadz-21357', 'OXBOW', 53.3570031, 22.5189793, 'Podlaskie', 'Goniądz', 'Kolejne starorzecze w bliskiej odległości od Goniądza, nieco większe i głębsze niż poprzednie, oferujące odmienne warunki wędkarskie. Dno jest zróżnicowane, z przewagą mułu, ale z twardszymi partiami wzdłuż dawnego koryta rzeki. Brzegi są częściowo dostępne, z licznymi pomostami wędkarskimi zbudowanymi przez lokalnych wędkarzy. Roślinność wodna jest umiarkowana, z przewagą grążeli i grzybieni, tworzących malownicze skupiska. Akwen ten jest bogaty w leszcze, płocie, szczupaki i okonie, które chętnie przebywają w pobliżu roślinności. Połączenie z rzeką jest sporadyczne, ale wystarczające do utrzymania zdrowej populacji ryb. Poziom zamulenia jest średni, a ryzyko przyduchy występuje tylko w ekstremalnych warunkach. Wędkowanie jest tu przyjemne przez cały sezon, z dobrymi wynikami zarówno na spławik, jak i spinning.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21357, 3.5, 1.6, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń', 'Dobry, z licznymi pomostami', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21358, 'Starorzecze (Jaziewo)', 'starorzecze-jaziewo-augustow-21358', 'OXBOW', 53.6654053, 22.8894477, 'Podlaskie', 'Augustów', 'To rozległe starorzecze w pobliżu Jaziewa, położone w malowniczej okolicy Puszczy Augustowskiej, stanowi atrakcyjne łowisko dla wielu wędkarzy. Charakteryzuje się głębokimi rynnami i piaszczysto-mulistym dnem, z licznymi zatopionymi pniami drzew i gałęziami. Brzegi są częściowo dostępne, z występującymi miejscami zarośniętymi trzciną. Roślinność wodna jest umiarkowana, skupiająca się w płytszych partiach, tworząc naturalne kryjówki dla ryb. W starorzeczu tym licznie występują szczupaki, sandacze, okonie oraz leszcze, a także sporadycznie sumy. Połączenie z pobliskimi ciekami wodnymi jest stałe, co zapewnia doskonałą wymianę wody i migrację ryb. Poziom zamulenia jest niski do średniego, a ryzyko przyduchy jest minimalne. Wędkowanie jest efektywne przez cały sezon, z najlepszymi wynikami na spinning i grunt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21358, 7.8, 2, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Okoń,Leszcz,Sum', 'Częściowo dostępny, miejscami zarośnięty trzciną', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21359, 'Starorzecze (Tajenko)', 'starorzecze-tajenko-augustow-21359', 'OXBOW', 53.6600501, 22.8909033, 'Podlaskie', 'Augustów', 'Starorzecze w Tajenku to mniejszy, ale bardzo obfity w ryby akwen, otoczony gęstymi lasami. Dno jest przeważnie muliste, z grubą warstwą osadów, co sprzyja rozwojowi bujnej roślinności podwodnej. Brzegi są trudno dostępne, otoczone zaroślami i podmokłymi terenami, co wymaga użycia spodniobutów i cierpliwości. Roślinność wodna jest bardzo silna, tworząc rozległe dywany rdestnic i grążeli. W zbiorniku tym dominują liny, karasie pospolite oraz wzdręgi, które osiągają tu imponujące rozmiary. Połączenie z rzeką jest bardzo sporadyczne, występujące tylko podczas długotrwałych opadów. Poziom zamulenia jest wysoki, a silne zarastanie zwiększa ryzyko przyduchy, zwłaszcza w upalne lata. Wędkowanie jest tu wyzwaniem, ale nagradza okazowymi rybami spokojnego żeru, najlepiej wczesną wiosną lub późnym latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21359, 2, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Wczesna wiosna, późne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21360, 'Starorzecze (Polkowo)', 'starorzecze-polkowo-grajewo-21360', 'OXBOW', 53.6390113, 22.9127065, 'Podlaskie', 'Grajewo', 'Starorzecze w Polkowo to średniej wielkości zbiornik, charakteryzujący się czystą wodą i piaszczysto-żwirowym dnem w wielu miejscach. Brzegi są dobrze dostępne, z nielicznymi zaroślami, co umożliwia swobodne wędkowanie z brzegu. Roślinność wodna jest umiarkowana, skupiająca się w płytszych zatoczkach, stanowiąc schronienie dla drobnicy. Akwen ten jest bogaty w leszcze, płocie, okonie oraz szczupaki, które chętnie żerują w pobliżu podwodnych przeszkód. Połączenie z rzeką macierzystą jest stabilne podczas większości roku, co zapewnia dobrą wymianę wody i zasilanie w ryby. Poziom zamulenia jest niski, a ryzyko przyduchy minimalne. Wędkowanie jest komfortowe przez cały sezon, z dobrymi wynikami zarówno na spinning, jak i metody gruntowe. To idealne miejsce na rodzinne wypady wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21360, 6, 1.7, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno z pojedynczymi korzeniami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21361, 'Starorzecze (Tajenko)', 'starorzecze-tajenko-augustow-21361', 'OXBOW', 53.6477141, 22.8998418, 'Podlaskie', 'Augustów', 'To rozległe starorzecze w Tajenku, charakteryzujące się głębokimi partiami i mulistym dnem, bogatym w zatopione drzewa i konary. Brzegi są mocno zarośnięte trzciną i inną roślinnością przybrzeżną, co utrudnia dostęp i wymaga użycia spodniobutów lub pontonu. Roślinność podwodna jest gęsta, tworząc doskonałe kryjówki dla drapieżników. W starorzeczu tym dominują szczupaki, sumy, leszcze oraz płocie, które osiągają tu imponujące rozmiary. Połączenie z rzeką jest sporadyczne, ale wystarczające do utrzymania zdrowej populacji ryb. Poziom zamulenia jest średni, a silne zarastanie może powodować niedobory tlenu w upalne dni. Wędkowanie jest najbardziej efektywne wiosną i jesienią, kiedy ryby aktywnie żerują, a roślinność nie jest tak bujna. To miejsce dla wędkarzy lubiących wyzwania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21361, 8.5, 2.2, 5.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Sum,Leszcz,Płoć', 'Mocno zarośnięty trzciną, trudny', TRUE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21362, 'Starorzecze (Jaziewo)', 'starorzecze-jaziewo-augustow-21362', 'OXBOW', 53.6355705, 22.9198557, 'Podlaskie', 'Augustów', 'To niewielkie, ale głębokie starorzecze w Jaziewie, o charakterystycznym, twardym dnie w wielu miejscach, przeplatanym z mulistymi zatokami. Brzegi są stosunkowo łatwo dostępne, z miejscowymi zaroślami, co sprzyja wędkowaniu z brzegu. Roślinność wodna jest umiarkowana, z przewagą rdestnic i moczarki, tworząc dogodne warunki dla drapieżników. Akwen ten jest domem dla szczupaków, okoni, boleni oraz jazi, które chętnie polują w czystszych partiach wody. Połączenie z rzeką jest stałe, co zapewnia doskonałą wymianę wody i zasilanie w świeże ryby. Poziom zamulenia jest niski, a ryzyko przyduchy jest minimalne. Wędkowanie jest bardzo efektywne przez cały sezon, zwłaszcza na spinning. To idealne miejsce dla wędkarzy ceniących aktywny połów i różnorodność gatunkową.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21362, 3, 1.9, 4.2, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Boleń,Jaź', 'Dobry, z miejscowymi zaroślami', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21363, 'Starorzecze (Jaziewo)', 'starorzecze-jaziewo-augustow-21363', 'OXBOW', 53.636358, 22.9174013, 'Podlaskie', 'Augustów', 'Kolejne starorzecze w Jaziewie, charakteryzujące się mulistym dnem i licznymi zatopionymi konarami, tworzącymi skomplikowany podwodny krajobraz. Brzegi są mocno zarośnięte trzciną i krzewami, co wymaga użycia spodniobutów lub pontonu. Roślinność podwodna jest bardzo gęsta, szczególnie w płytszych partiach, co zapewnia schronienie dla wielu gatunków ryb. W starorzeczu tym dominują liny, karasie pospolite, leszcze oraz płocie, a także sporadycznie szczupaki. Połączenie z rzeką jest sporadyczne, występujące głównie podczas wysokich stanów wody. Poziom zamulenia jest wysoki, a silne zarastanie powoduje znaczne ryzyko przyduchy, zwłaszcza w upalne lata. Wędkowanie jest tu wyzwaniem, ale może przynieść nagrody w postaci okazowych ryb spokojnego żeru, najlepiej wczesną wiosną lub późnym latem. Wymaga cierpliwości i precyzji.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21363, 4.5, 1.3, 3, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Leszcz,Płoć,Szczupak', 'Mocno zarośnięty trzciną, trudny', TRUE, 'Dużo zatopionych drzew i gęsta roślinność', 'Wczesna wiosna, późne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21364, 'Starorzecze (Polkowo)', 'starorzecze-polkowo-grajewo-21364', 'OXBOW', 53.6365315, 22.9193469, 'Podlaskie', 'Grajewo', 'To malownicze starorzecze w Polkowo, o zróżnicowanym dnie, od piaszczystego po muliste, z licznymi podwodnymi górami i dołkami. Brzegi są dobrze dostępne, z miejscowymi partiami zarośniętymi, co oferuje różnorodne stanowiska wędkarskie. Roślinność wodna jest umiarkowana, tworząc naturalne kryjówki dla ryb. Akwen ten jest domem dla wielu gatunków, w tym szczupaków, okoni, leszczy oraz płoci, które licznie występują w tym zbiorniku. Połączenie z rzeką macierzystą jest stałe, co zapewnia doskonałą wymianę wody i zasilanie w ryby. Poziom zamulenia jest niski, a ryzyko przyduchy minimalne. Wędkowanie jest bardzo efektywne przez cały sezon, zarówno na spinning, jak i metody gruntowe. To idealne miejsce na długie sesje wędkarskie, oferujące zarówno spokój, jak i szansę na dużą rybę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21364, 5.8, 1.6, 3.9, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry, z miejscowymi zaroślami', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21365, 'Starorzecze Polkowo A', 'starorzecze-polkowo-a-augustow-21365', 'OXBOW', 53.6351854, 22.9223102, 'Podlaskie', 'Augustów', 'To starorzecze, położone w malowniczej okolicy Polkowo, charakteryzuje się dość zróżnicowaną linią brzegową z przewagą trzcinowisk i podmokłych łąk, co utrudnia dostęp do wody bez odpowiedniego obuwia. Dno jest muliste, jednak w głębszych partiach można natrafić na twardsze miejsca, idealne dla leszczy i linów. Roślinność podwodna jest umiarkowana, co sprzyja drapieżnikom, takim jak szczupak i okoń, które licznie zamieszkują te wody. Poziom zamulenia jest średni, co wskazuje na stabilny ekosystem, ale wymaga ostrożności przy poruszaniu się. Wiosna i wczesna jesień to najlepsze pory na wędkowanie, oferujące szansę na złowienie dorodnych okazów. W okresach wysokiej wody starorzecze łączy się z głównym nurtem rzeki, co wzbogaca populację ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21365, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Płoć,Leszcz', 'Trudny, miejscami bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21366, 'Starorzecze Polkowo B', 'starorzecze-polkowo-b-augustow-21366', 'OXBOW', 53.6342302, 22.9238646, 'Podlaskie', 'Augustów', 'Starorzecze Polkowo B to mniejsze i bardziej płytkie łowisko, całkowicie odizolowane od głównego nurtu rzeki, co sprzyja rozwojowi specyficznej ichtiofauny. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga brodzenia. Dno jest mocno zamulone, a roślinność podwodna jest bardzo silna, co stanowi idealne środowisko dla karasi pospolitych, linów i wzdręg. Istnieje ryzyko przyduchy w gorące lata, dlatego wędkarze powinni być świadomi tego zagrożenia. Najlepsze wyniki osiąga się tutaj późną wiosną i latem, zwłaszcza na spławik. Wędkarstwo w tym miejscu to prawdziwe wyzwanie, ale nagrodą mogą być piękne, dzikie karasie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21366, 2.8, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21367, 'Starorzecze Tajenko', 'starorzecze-tajenko-augustow-21367', 'OXBOW', 53.6787913, 22.9049036, 'Podlaskie', 'Augustów', 'Starorzecze Tajenko to wyjątkowo atrakcyjne łowisko, charakteryzujące się stałym połączeniem z rzeką, co zapewnia ciągły dopływ świeżej wody i ryb. Brzegi są w większości łatwo dostępne, z nielicznymi zaroślami, co ułatwia swobodne poruszanie się wzdłuż akwenu. Dno jest stosunkowo czyste, z niewielkim zamuleniem, co sprzyja rozwojowi różnorodnej fauny dennej i sprawia, że jest to idealne miejsce dla wędkarzy. Roślinność podwodna jest słaba, co umożliwia swobodne prowadzenie przynęt spinningowych. W starorzeczu tym dominują drapieżniki takie jak szczupak i okoń, ale można tu również złowić dorodne leszcze, płocie oraz bolenie. Łowisko to jest dostępne przez cały sezon, oferując dobre warunki do wędkowania niezależnie od pory roku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21367, 6.1, 2.1, 4, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21368, 'Starorzecze Giełczyn A', 'starorzecze-gielczyn-a-lomza-21368', 'OXBOW', 53.2171994, 22.4778503, 'Podlaskie', 'Łomża', 'To starorzecze w Giełczynie jest typowym przykładem akwenu o zmiennym połączeniu z rzeką, co wpływa na jego bogactwo ichtiofauny. Brzegi są częściowo dostępne, ale w wielu miejscach porastają je gęste krzewy i trzciny, wymagające użycia woderów. Dno jest muliste ze średnim poziomem zamulenia, z licznymi zatopionymi korzeniami, które stanowią doskonałe kryjówki dla ryb. Roślinność podwodna jest umiarkowana, tworząc zarośla, w których żerują liny i karasie. Wiosną i latem można liczyć na udane połowy leszczy, płoci, a także szczupaków. Wędkarstwo spławikowe i gruntowe są tutaj najbardziej efektywne, zwłaszcza w pobliżu podwodnych przeszkód.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21368, 3.2, 1.5, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Miejscami dobry, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21369, 'Starorzecze Giełczyn B', 'starorzecze-gielczyn-b-lomza-21369', 'OXBOW', 53.2184298, 22.4708175, 'Podlaskie', 'Łomża', 'Starorzecze Giełczyn B to niewielki i płytki zbiornik, całkowicie odcięty od głównego nurtu rzeki, co czyni go podatnym na wysychanie w upalne lata. Brzegi są niezwykle trudne do pokonania, bagniste i gęsto zarośnięte, co skutecznie utrudnia dostęp do wody bez woderów. Dno jest mocno zamulone, a podwodna roślinność tworzy gęste dywany, stanowiące schronienie dla nielicznych gatunków ryb. Dominują tu odporne na trudne warunki karasie pospolite oraz wzdręgi. Istnieje wysokie ryzyko przyduchy, dlatego wędkarstwo jest tu możliwe głównie w chłodniejszych okresach późnej wiosny, zanim woda nadmiernie się nagrzeje. To łowisko dla cierpliwych wędkarzy, szukających dzikich, choć niewielkich ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21369, 1.9, 0.9, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21370, 'Starorzecze Giełczyn C', 'starorzecze-gielczyn-c-lomza-21370', 'OXBOW', 53.216976, 22.4632913, 'Podlaskie', 'Łomża', 'Starorzecze Giełczyn C to rozległy akwen z dobrze rozwiniętą populacją drapieżników i ryb spokojnego żeru. Dostęp do łowiska jest ułatwiony z jednej strony, gdzie znajdują się dogodne stanowiska, natomiast druga strona jest bardziej dzika i zarośnięta. Dno jest zróżnicowane, z mulistymi zatokami i twardszymi, piaszczystymi blatami, gdzie często żerują leszcze. Roślinność podwodna jest umiarkowana, co sprzyja polowaniu szczupaków i okoni, które są tu liczne. Poziom zamulenia jest średni, co świadczy o zdrowym ekosystemie. W okresach wysokiej wody starorzecze łączy się z rzeką, co dodatkowo wzbogaca jego bioróżnorodność. Wiosna i jesień to najlepsze pory na wędkowanie, oferujące szansę na złowienie okazałych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21370, 5, 2, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Lin', 'Dobry z jednej strony, zarośnięty z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21371, 'Starorzecze Giełczyn D', 'starorzecze-gielczyn-d-lomza-21371', 'OXBOW', 53.218558, 22.4591285, 'Podlaskie', 'Łomża', 'To starorzecze w Giełczynie, całkowicie odizolowane od rzeki, jest małym i płytkim zbiornikiem, gdzie dominują ryby tolerujące trudne warunki. Brzegi są gęsto porośnięte wysoką trzciną, co sprawia, że dostęp do wody jest bardzo ograniczony i wymaga przedzierania się przez gąszcz. Dno jest mocno zamulone, a podwodna roślinność tworzy prawdziwe zielone dywany, gdzie ukrywają się karasie srebrzyste i wzdręgi. Ze względu na płytkość i silne zarośnięcie, istnieje wysokie ryzyko przyduchy w upalne, bezwietrzne dni. Najlepsze wyniki osiąga się tutaj latem, łowiąc na spławik w niewielkich, otwartych przestrzeniach między roślinnością. Wędkarstwo w tym miejscu to wyzwanie, ale może przynieść satysfakcję ze złowienia dzikich, choć często niezbyt dużych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21371, 2.1, 1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21372, 'Starorzecze Giełczyn E', 'starorzecze-gielczyn-e-lomza-21372', 'OXBOW', 53.2170613, 22.4587101, 'Podlaskie', 'Łomża', 'Starorzecze Giełczyn E to jedno z większych i głębszych łowisk w okolicy, charakteryzujące się stałym połączeniem z rzeką, co zapewnia doskonałe warunki dla wielu gatunków ryb. Brzegi są w większości łatwo dostępne, miejscami nawet utwardzone, co sprzyja wygodnemu wędkowaniu. Dno jest zróżnicowane, z twardszymi partiami i umiarkowanym zamuleniem, co jest idealne dla ryb spokojnego żeru, takich jak leszcze i karpie. Roślinność podwodna jest słaba, co ułatwia prowadzenie przynęt i manewrowanie sprzętem. W starorzeczu tym można spotkać okazałe sumy i szczupaki, co czyni je atrakcyjnym dla wędkarzy spinningowych i gruntowych. Brak ryzyka przyduchy i całoroczna dostępność sprawiają, że jest to popularne miejsce wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21372, 7.5, 2.5, 4.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Szczupak,Leszcz,Karp', 'Dobry, miejscami utwardzony', FALSE, 'Pojedyncze korzenie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21373, 'Starorzecze Giełczyn F', 'starorzecze-gielczyn-f-lomza-21373', 'OXBOW', 53.2158888, 22.4552822, 'Podlaskie', 'Łomża', 'Starorzecze Giełczyn F to bardzo mały i płytki zbiornik, który w okresach suszy często wysycha, co drastycznie ogranicza populację ryb. Brzegi są niezwykle trudne do pokonania, bagniste i gęsto porośnięte, wymagające użycia woderów i cierpliwości. Dno jest mocno zamulone, a podwodna roślinność tworzy niemalże nieprzeniknione gąszcze, w których bytują nieliczne, ale dzikie karasie pospolite i wzdręgi. Istnieje bardzo wysokie ryzyko przyduchy, co sprawia, że łowisko jest atrakcyjne tylko wczesną wiosną, zanim temperatura wody wzrośnie. To miejsce dla wędkarzy poszukujących prawdziwej dziczy i gotowych na ekstremalne warunki, gdzie liczy się każdy złowiony okaz.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21373, 1.5, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga', 'Trudny, bagnisty i gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna i zatopione gałęzie', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21374, 'Starorzecze Giełczyn G', 'starorzecze-gielczyn-g-lomza-21374', 'OXBOW', 53.2165808, 22.4418624, 'Podlaskie', 'Łomża', 'Starorzecze Giełczyn G to średniej wielkości zbiornik, który okresowo łączy się z rzeką, co sprzyja migracji ryb i utrzymaniu zdrowej populacji. Dostęp do brzegów jest zróżnicowany – część jest łatwo dostępna, natomiast inne fragmenty są bardziej zarośnięte, oferując dzikie zakątki. Dno jest muliste, ale z twardszymi partiami, gdzie można liczyć na leszcze i płocie. Roślinność podwodna jest umiarkowana, tworząc schronienia dla okoni i szczupaków, które aktywnie polują w tych wodach. Poziom zamulenia jest średni, co wskazuje na stabilny ekosystem. Najlepsze pory na wędkowanie to wiosna i jesień, kiedy ryby są najbardziej aktywne. Jest to łowisko uniwersalne, odpowiednie zarówno dla wędkarzy spławikowych, jak i spinningistów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21374, 4, 1.7, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Miejscami dobry, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i kamienie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21375, 'Starorzecze Włochówka', 'starorzecze-wlochowka-lomza-21375', 'OXBOW', 53.216274, 22.4344494, 'Podlaskie', 'Łomża', 'Starorzecze Włochówka to typowe, dość płytkie łowisko bez stałego połączenia z rzeką, co sprzyja rozwojowi bujnej roślinności. Brzegi są silnie zarośnięte trzciną i krzewami, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga użycia woderów. Dno jest mocno zamulone, a podwodna roślinność tworzy gęste zarośla, które stanowią idealne siedlisko dla linów, karasi pospolitych i wzdręg. Ze względu na te warunki, istnieje ryzyko przyduchy w upalne, bezwietrzne dni. Najlepsze wyniki osiąga się tutaj późną wiosną i wczesnym latem, łowiąc na spławik w otwartych przestrzeniach. Wędkarstwo w tym miejscu to prawdziwe wyzwanie, ale nagrodą mogą być piękne, dzikie liny.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21375, 3.5, 1.4, 2.7, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną i krzewami', TRUE, 'Gęsta roślinność podwodna i zatopione gałęzie', 'Późna wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21376, 'Starorzecze Giełczyn H', 'starorzecze-gielczyn-h-lomza-21376', 'OXBOW', 53.2228956, 22.4384594, 'Podlaskie', 'Łomża', 'Starorzecze Giełczyn H to niewielki i płytki zbiornik, całkowicie odizolowany od nurtu rzeki, co sprzyja jego szybkiemu zamulaniu i zarastaniu. Brzegi są bagniste i gęsto zarośnięte, co znacznie utrudnia dostęp do wody i wymaga użycia woderów. Dno jest mocno zamulone, a roślinność podwodna jest bardzo silna, tworząc trudne do wędkowania miejsca. Dominują tu karasie pospolite, wzdręgi i niewielkie płocie, które dobrze radzą sobie w trudnych warunkach. Ze względu na płytkość i silne zamulenie, istnieje wysokie ryzyko przyduchy, zwłaszcza latem. Wiosna to najlepszy czas na wędkowanie, zanim roślinność osiągnie pełny rozrost i woda nadmiernie się nagrzeje.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21376, 2.9, 1.1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21377, 'Starorzecze Giełczyn I', 'starorzecze-gielczyn-i-lomza-21377', 'OXBOW', 53.2260414, 22.4470908, 'Podlaskie', 'Łomża', 'Starorzecze Giełczyn I to duży i głęboki akwen, który podczas wysokich stanów wody łączy się z rzeką, co sprzyja bogactwu gatunkowemu. Dostęp do brzegów jest w większości dobry, z licznymi dogodnymi stanowiskami dla wędkarzy. Dno jest zróżnicowane, z mulistymi i twardszymi partiami, co tworzy idealne warunki dla leszczy, karpi, a także drapieżników. Roślinność podwodna jest umiarkowana, oferując schronienie dla szczupaków i okoni, które są tu licznie reprezentowane. Poziom zamulenia jest średni, co świadczy o zdrowym i stabilnym ekosystemie. Jest to łowisko atrakcyjne przez cały sezon, oferujące szanse na złowienie dużych ryb spokojnego żeru oraz drapieżników. Wędkarze gruntowi i spinningowi znajdą tu coś dla siebie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21377, 6.8, 2.3, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Szczupak,Okoń', 'Dobry z większości stron', FALSE, 'Pojedyncze zatopione pnie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21378, 'Starorzecze Giełczyn J', 'starorzecze-gielczyn-j-lomza-21378', 'OXBOW', 53.2421085, 22.4540242, 'Podlaskie', 'Łomża', 'Starorzecze Giełczyn J to najmniejsze i najbardziej płytkie z opisywanych starorzeczy, które w okresach letnich susz często wysycha całkowicie. Brzegi są niezwykle trudne do pokonania, bardzo bagniste i gęsto zarośnięte, co czyni dostęp do wody niemal niemożliwym bez specjalistycznego sprzętu i woderów. Dno jest ekstremalnie zamulone, a podwodna roślinność tworzy nieprzeniknione gąszcze, w których bytują jedynie najbardziej odporne gatunki ryb, takie jak karaś pospolity i wzdręga. Istnieje bardzo wysokie ryzyko przyduchy, co sprawia, że wędkarstwo jest tu możliwe tylko wczesną wiosną, gdy poziom wody jest wyższy. To łowisko dla prawdziwych pasjonatów dzikiej przyrody, gotowych na trudne warunki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21378, 1.2, 0.7, 1.3, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga', 'Trudny, bardzo bagnisty', TRUE, 'Bardzo gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21379, 'Starorzecze Giełczyn K', 'starorzecze-gielczyn-k-lomza-21379', 'OXBOW', 53.2415009, 22.4520787, 'Podlaskie', 'Łomża', 'Starorzecze Giełczyn K to rozległy akwen, który charakteryzuje się okresowym połączeniem z rzeką, co zapewnia dynamiczną wymianę ryb i utrzymanie zdrowego ekosystemu. Dostęp do brzegów jest w większości dobry, z licznymi dogodnymi miejscami do wędkowania, choć miejscami występują zarośla. Dno jest zróżnicowane, z mulistymi i twardszymi partiami, co tworzy idealne warunki dla leszczy, linów oraz drapieżników. Roślinność podwodna jest umiarkowana, oferując schronienie dla szczupaków i okoni, które są tu licznie reprezentowane. Poziom zamulenia jest średni, co świadczy o stabilnym środowisku wodnym. Łowisko to jest atrakcyjne przez cały sezon, oferując różnorodne możliwości wędkowania, zarówno na spławik, grunt, jak i spinning.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21379, 5.5, 1.9, 3.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry, miejscami zarośnięty', FALSE, 'Pojedyncze zatopione gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21380, 'Starorzecze (Giełczyn)', 'starorzecze-gielczyn-gielczyn-21380', 'OXBOW', 53.2443428, 22.4514949, 'Województwo Podlaskie', 'Giełczyn', 'To starorzecze, położone w malowniczej dolinie Narwi, stanowi doskonałe miejsce do wędkowania dla osób ceniących spokój. Dno jest muliste z domieszką piasku w płytszych partiach, co sprzyja rozwojowi roślinności wodnej. Brzegi są przeważnie stabilne, miejscami porośnięte trzciną, oferując dobrą dostępność dla wędkarzy. Występuje tu bogata populacja szczupaka, lina oraz płoci, co gwarantuje udane połowy. Należy jednak pamiętać, że w upalne lata, ze względu na umiarkowane wypłycenie i bujną roślinność, może występować ryzyko przyduchy. Wiosną i jesienią zbiornik ten tętni życiem, oferując najlepsze warunki do połowu drapieżników i ryb spokojnego żeru.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21380, 3.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21381, 'Starorzecze koło Giełczyna', 'starorzecze-kolo-gielczyna-gielczyn-21381', 'OXBOW', 53.2800883, 22.4745619, 'Województwo Podlaskie', 'Giełczyn', 'To rozległe starorzecze charakteryzuje się głębszymi partiami i czystszą wodą, co odróżnia je od wielu innych zbiorników w regionie. Dno jest zróżnicowane, od mulistego po twarde, piaszczysto-żwirowe odcinki, szczególnie w pobliżu dawnego nurtu. Brzegi są jednak bagniste i mocno zarośnięte, co znacznie utrudnia dostęp do wody, wymagając użycia woderów. W starorzeczu tym licznie występują szczupaki, leszcze i okonie, a także dorodne liny, które preferują spokojne, zarośnięte zatoki. Wędkarze powinni przygotować się na obecność licznych zaczepów w postaci zatopionych drzew i gałęzi. Mimo trudnego dostępu, łowisko to jest bardzo perspektywiczne i oferuje możliwość złowienia naprawdę dużych egzemplarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21381, 5.1, 2, 5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Płoć,Lin', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21382, 'Starorzecze (Giełczyn)', 'starorzecze-gielczyn-gielczyn-21382', 'OXBOW', 53.2733971, 22.4680737, 'Województwo Podlaskie', 'Giełczyn', 'To niewielkie, silnie zarośnięte starorzecze jest typowym zbiornikiem dla miłośników lina i karasia. Dno jest bardzo muliste, a płytkie partie charakteryzują się gęstą roślinnością podwodną, co stanowi idealne schronienie dla ryb spokojnego żeru. Brzegi są niemal w całości pokryte pasem trzcin i innej roślinności szuwarowej, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga brodzenia. Ze względu na płytkość i silne zarastanie, w okresie letnich upałów istnieje wysokie ryzyko niedoboru tlenu. Łowienie tutaj wymaga cierpliwości i precyzji, ale nagrodą mogą być piękne liny i karasie pospolite.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21382, 2.8, 1.2, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21383, 'Starorzecze (Giełczyn)', 'starorzecze-gielczyn-gielczyn-21383', 'OXBOW', 53.2691801, 22.4648282, 'Województwo Podlaskie', 'Giełczyn', 'Kolejne starorzecze w okolicy Giełczyna, cechujące się umiarkowaną wielkością i znacznym zarastaniem. Dno jest typowo muliste, z licznymi skupiskami roślinności podwodnej, która stanowi schronienie i żerowisko dla ryb. Brzegi są gęsto porośnięte trzciną, co wymaga od wędkarza użycia woderów, aby dotrzeć do otwartych partii wody. Połączenie z rzeką Narew następuje tylko podczas wiosennych roztopów lub długotrwałych deszczy, co pozwala na migrację ryb. Dominują tu lin, karaś pospolity oraz płoć, a także mniejsze okonie. Łowisko to jest idealne dla wędkarzy ceniących sobie spokój i wyzwanie związane z łowieniem w trudnych warunkach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21383, 1.9, 1, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21384, 'Starorzecze (Giełczyn)', 'starorzecze-gielczyn-gielczyn-21384', 'OXBOW', 53.2574272, 22.4699712, 'Województwo Podlaskie', 'Giełczyn', 'To stosunkowo duże starorzecze oferuje zróżnicowane warunki do wędkowania, będąc atrakcyjnym miejscem dla wielu gatunków ryb. Dno jest mozaiką mułu, piasku i żwiru, co sprzyja różnorodności środowiskowej. Brzegi są łatwo dostępne, z licznymi miejscami do komfortowego rozłożenia sprzętu wędkarskiego. Połączenie z Narwią podczas wysokich stanów wody zapewnia regularne zasilanie w świeżą wodę i migrację ryb. W zbiorniku tym dominują drapieżniki takie jak szczupak i okoń, ale nie brakuje również leszczy i płoci. Brak silnego zarastania i głębsze partie wody sprawiają, że ryzyko przyduchy jest minimalne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21384, 4.5, 1.8, 4.2, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21385, 'Starorzecze (Giełczyn)', 'starorzecze-gielczyn-gielczyn-21385', 'OXBOW', 53.2551261, 22.4650802, 'Województwo Podlaskie', 'Giełczyn', 'To starorzecze, charakteryzujące się znacznym wypłyceniem i brakiem stałego połączenia z rzeką, jest siedliskiem typowych dla takich warunków gatunków. Dno jest bardzo muliste i miękkie, co utrudnia brodzenie i wymaga ostrożności. Brzegi są bagniste i gęsto porośnięte, co sprawia, że dostęp do wody jest bardzo problematyczny, a wędkarze często muszą korzystać z woderów. W okresach suszy zbiornik ten potrafi częściowo lub całkowicie wyschnąć, co ma wpływ na populację ryb. Dominują tu odporne na trudne warunki karasie pospolite, wzdręgi oraz mniejsze liny. Jest to łowisko dla cierpliwych i wytrwałych, szukających ryb w wymagającym środowisku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21385, 2.1, 1.1, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21386, 'Starorzecze (Giełczyn)', 'starorzecze-gielczyn-gielczyn-21386', 'OXBOW', 53.252707, 22.4621093, 'Województwo Podlaskie', 'Giełczyn', 'To jedno z mniejszych i najbardziej płytkich starorzeczy w okolicy Giełczyna, będące typowym przykładem zbiornika o zaawansowanym procesie sukcesji. Dno jest głęboko muliste, a cała powierzchnia wody jest często pokryta kożuchem roślinności pływającej i podwodnej. Brzegi są praktycznie niedostępne bez woderów, ze względu na gęste zarośla trzcinowe i bagniste podłoże. W upalne lata zbiornik ten regularnie wysycha, co sprawia, że jego populacja ryb jest niestabilna i składa się głównie z odpornych gatunków. Można tu jednak spotkać dorodne karasie pospolite, wzdręgi, a także pojedyncze, ale waleczne szczupaki, które przetrwały trudne warunki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21386, 0.8, 0.7, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21387, 'Starorzecze (Giełczyn)', 'starorzecze-gielczyn-gielczyn-21387', 'OXBOW', 53.253152, 22.460837, 'Województwo Podlaskie', 'Giełczyn', 'To starorzecze, choć niewielkie, oferuje interesujące możliwości dla wędkarzy poszukujących lina i karasia. Dno jest mocno zamulone, a woda w wielu miejscach płytka i gęsto porośnięta, co sprzyja rozwojowi tych gatunków. Brzegi są trudne do pokonania, często bagniste i wymagające użycia woderów, aby dotrzeć do dogodnych stanowisk. Połączenie z rzeką Narew, choć nieregularne, pozwala na odświeżenie wody i migrację ryb. W zbiorniku tym można liczyć na spotkanie z okazałymi linami, licznymi karasiami pospolitymi, a także płociami i mniejszymi okoniami. Wędkarstwo tutaj wymaga cierpliwości i umiejętności odczytywania łowiska, ale może przynieść satysfakcjonujące rezultaty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21387, 1.2, 0.9, 2.2, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21388, 'Starorzecze (Giełczyn)', 'starorzecze-gielczyn-gielczyn-21388', 'OXBOW', 53.251866, 22.4575558, 'Województwo Podlaskie', 'Giełczyn', 'Charakteryzujące się znacznym stopniem zamulenia i silnym zarastaniem, to starorzecze jest typowym siedliskiem dla ryb preferujących ciepłe i płytkie wody. Dno jest głęboko muliste, co stanowi wyzwanie dla wędkarzy, ale jednocześnie bogate w pokarm dla ryb. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest bardzo ograniczony i praktycznie niemożliwy bez odpowiedniego ubioru. Brak połączenia z głównym nurtem rzeki oznacza, że zbiornik jest bardziej wrażliwy na zmiany warunków środowiskowych. Dominują tu lin, karaś pospolity oraz wzdręga, które doskonale radzą sobie w tych specyficznych warunkach. Łowienie tutaj to prawdziwa szkoła cierpliwości i umiejętności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21388, 1.5, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21389, 'Starorzecze (Giełczyn)', 'starorzecze-gielczyn-gielczyn-21389', 'OXBOW', 53.249331, 22.4536059, 'Województwo Podlaskie', 'Giełczyn', 'To starorzecze, zlokalizowane w pobliżu Giełczyna, stanowi atrakcyjne łowisko o zróżnicowanej głębokości i umiarkowanym zarastaniu. Dno jest mieszane, od mulistego po twardsze, piaszczyste fragmenty, co sprzyja różnym gatunkom ryb. Brzegi są w większości łatwo dostępne, z dogodnymi miejscami do wędkowania z brzegu. Połączenie z Narwią podczas wiosennych wezbrań umożliwia migrację ryb i odświeżenie wody. W zbiorniku tym można liczyć na udane połowy szczupaka, lina, okonia oraz płoci. Jest to łowisko uniwersalne, odpowiednie zarówno dla wędkarzy spinningowych, jak i tych preferujących metody spławikowe czy gruntowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21389, 2.3, 1.3, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Okoń,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21390, 'Starorzecze (Rutkowskie)', 'starorzecze-rutkowskie-rutkowskie-21390', 'OXBOW', 53.2498297, 22.4497788, 'Województwo Podlaskie', 'Rutkowskie', 'To starorzecze wyróżnia się stałym połączeniem z rzeką Narew, co zapewnia ciągły przepływ wody i bogactwo gatunkowe. Dno jest przeważnie twarde, piaszczysto-żwirowe, z niewielkimi osadami mułu, co sprzyja bytowania wielu gatunków ryb. Brzegi są łatwo dostępne, z licznymi dogodnymi stanowiskami dla wędkarzy, co czyni je popularnym miejscem. Dzięki stałemu połączeniu, ryzyko przyduchy jest praktycznie zerowe, a woda jest dobrze natleniona. W zbiorniku tym można spotkać zarówno drapieżniki takie jak szczupak, okoń i boleń, jak i ryby spokojnego żeru – leszcze i płocie. Jest to jedno z najlepszych łowisk starorzecznych w regionie, oferujące wędkarzom różnorodne wrażenia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21390, 3.5, 1.7, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Płoć,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21391, 'Starorzecze (Giełczyn)', 'starorzecze-gielczyn-gielczyn-21391', 'OXBOW', 53.2619894, 22.4648336, 'Województwo Podlaskie', 'Giełczyn', 'To starorzecze jest przykładem zbiornika o zaawansowanym stopniu eutrofizacji i silnego zarastania. Dno jest głęboko muliste, co świadczy o nagromadzeniu materii organicznej i stanowi doskonałe środowisko dla ryb dennych. Brzegi są praktycznie niedostępne z powodu gęstych zarośli trzcinowych i podmokłego terenu, co wymusza użycie woderów. Brak połączenia z rzeką sprawia, że zbiornik jest bardziej podatny na wahania poziomu wody i temperatury. Występują tu głównie lin, karaś pospolity oraz wzdręga, które doskonale znoszą trudne warunki tlenowe. Wędkarstwo w tym miejscu to wyzwanie, ale szansa na złowienie okazałego lina jest realna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21391, 2, 1.2, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21392, 'Starorzecze (Giełczyn)', 'starorzecze-gielczyn-gielczyn-21392', 'OXBOW', 53.2652851, 22.4676257, 'Województwo Podlaskie', 'Giełczyn', 'To płytkie starorzecze, położone w malowniczej okolicy Giełczyna, jest typowym zbiornikiem ulegającym stopniowemu wypłycaniu. Dno jest mocno zamulone, a woda w okresie letnim często pokryta jest kożuchem roślinności. Brzegi są trudne do pokonania, często bagniste i porośnięte gęstymi zaroślami, co wymaga użycia woderów. Połączenie z rzeką Narew następuje sporadycznie, podczas wysokich stanów wody, co pozwala na częściowe odświeżenie ekosystemu. W okresach suszy zbiornik może częściowo wyschnąć, co wpływa na jego biologię. Dominują tu odporne na trudne warunki karasie pospolite, wzdręgi oraz płoć.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21392, 1.7, 0.9, 2, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21393, 'Starorzecze (Giełczyn)', 'starorzecze-gielczyn-gielczyn-21393', 'OXBOW', 53.27409, 22.4731457, 'Województwo Podlaskie', 'Giełczyn', 'To średniej wielkości starorzecze oferuje dobre warunki do wędkowania, będąc popularnym miejscem wśród lokalnych wędkarzy. Dno jest zróżnicowane, z przewagą mułu, ale z twardszymi partiami wzdłuż dawnego nurtu. Brzegi są w większości łatwo dostępne, choć w niektórych miejscach mogą być porośnięte trzciną, co wymaga znalezienia odpowiedniego stanowiska. Połączenie z Narwią podczas wysokich wód zapewnia migrację ryb i utrzymanie zdrowego ekosystemu. W zbiorniku tym można liczyć na udane połowy szczupaka, okonia, leszcza oraz płoci. Jest to łowisko, które zadowoli zarówno spinningistów, jak i wędkarzy spławikowych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21393, 4, 1.6, 3.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z niektórych stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21394, 'Starorzecze (Włochówka)', 'starorzecze-wlochowka-wlochowka-21394', 'OXBOW', 53.2149546, 22.4329448, 'Województwo Podlaskie', 'Włochówka', 'To jedno z większych i głębszych starorzeczy w dolinie Narwi, charakteryzujące się stałym połączeniem z głównym nurtem rzeki. Dno jest zróżnicowane, od mulistego po twarde, piaszczyste i żwirowe, z licznymi zatopionymi drzewami stanowiącymi kryjówki dla ryb. Brzegi są łatwo dostępne, oferując wiele komfortowych miejsc do wędkowania. Dzięki stałemu połączeniu z Narwią, zbiornik jest bogato zarybiony i tętni życiem przez cały rok. Występują tu okazałe szczupaki, sumy, karpie, leszcze i płocie, co czyni go atrakcyjnym dla wędkarzy poszukujących różnorodnych gatunków. Mimo licznych zaczepów, łowisko to jest bardzo cenione za potencjał dużych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21394, 6, 2.2, 5.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sum,Karp,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21395, 'Starorzecze (Włochówka)', 'starorzecze-wlochowka-wizna-21395', 'OXBOW', 53.2157538, 22.428774, 'Podlaskie', 'Wizna', 'To starorzecze charakteryzuje się umiarkowaną wielkością i średnią głębokością, co czyni je atrakcyjnym łowiskiem dla wielu gatunków ryb. Dno jest przeważnie muliste, z lokalnymi twardszymi partiami, a brzegi są łatwo dostępne, choć miejscami porośnięte trzciną. Roślinność podwodna jest umiarkowana, tworząc dobre kryjówki dla drapieżników i miejsca żerowania dla ryb spokojnego żeru. Połączenie z rzeką macierzystą następuje podczas wysokich stanów wody, co sprzyja migracji ryb i odświeżaniu zbiornika. Występuje tu bogata populacja szczupaka, lina, karasia pospolitego, płoci i leszcza. Łowienie nie przedstawia większych trudności, jednak warto pamiętać o pojedynczych zatopionych gałęziach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21395, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21396, 'Starorzecze (Giełczyn)', 'starorzecze-gielczyn-gielczyn-21396', 'OXBOW', 53.2364084, 22.4433357, 'Podlaskie', 'Giełczyn', 'To niewielkie i stosunkowo płytkie starorzecze jest typowym siedliskiem dla gatunków preferujących zarośnięte zbiorniki. Dno jest silnie zamulone, a brzegi są podmokłe i trudno dostępne, gęsto porośnięte trzciną i krzewami. Roślinność wodna jest bardzo obfita, co sprzyja rozwojowi lina, karasia pospolitego i wzdręgi. Brak stałego połączenia z rzeką sprawia, że w okresach suszy poziom wody może znacznie spadać, a ryzyko przyduchy jest wysokie. Wymaga to cierpliwości i precyzyjnych rzutów, aby ominąć gęste zarośla. Wędkarstwo gruntowe i spławikowe jest tutaj najbardziej efektywne, zwłaszcza w czystszych partiach wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21396, 2.8, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć,Karp', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21397, 'Starorzecze (Włochówka)', 'starorzecze-wlochowka-wizna-21397', 'OXBOW', 53.2124451, 22.427069, 'Podlaskie', 'Wizna', 'To starorzecze, podobnie jak inne w rejonie Włochówki, oferuje dobre warunki do wędkowania. Jest nieco głębsze niż sąsiednie zbiorniki, co sprzyja występowaniu większych okazów ryb. Dno jest zróżnicowane, z przewagą mułu, ale z twardszymi fragmentami wzdłuż brzegów. Brzegi są ogólnie łatwo dostępne, choć w niektórych miejscach mogą być zarośnięte. Roślinność wodna jest umiarkowana, zapewniając rybom schronienie i miejsca żerowania. Podczas wysokich stanów wody łączy się z głównym nurtem rzeki, co wzbogaca populację ryb. Dominują tu szczupaki, liny, leszcze, okonie i płocie. Łowisko jest stosunkowo łatwe do obłowienia, jednak warto zabrać ze sobą podstawowe wyposażenie do brodzenia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21397, 3.9, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Okoń,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21398, 'Starorzecze (Włochówka)', 'starorzecze-wlochowka-wizna-21398', 'OXBOW', 53.2106816, 22.4240527, 'Podlaskie', 'Wizna', 'To mniejsze i bardziej odizolowane starorzecze jest idealne dla wędkarzy szukających spokoju i skupiających się na mniejszych, ale licznych gatunkach. Zbiornik jest płytki, z silnie zamulonym dnem, co sprzyja rozwojowi gęstej roślinności podwodnej. Brzegi są mocno zarośnięte trzciną, co utrudnia dostęp do wody i wymaga ostrożności. Brak połączenia z rzeką sprawia, że ekosystem jest bardziej stabilny, ale jednocześnie podatny na niedobory tlenu w upalne lata. Głównymi mieszkańcami są karasie pospolite, wzdręgi, płocie i okonie. Wędkowanie tutaj to wyzwanie ze względu na gęste zarośla, ale może przynieść satysfakcjonujące rezultaty dla miłośników spławika.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21398, 1.8, 1, 2.2, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21399, 'Starorzecze (Włochówka)', 'starorzecze-wlochowka-wizna-21399', 'OXBOW', 53.2102753, 22.4538874, 'Podlaskie', 'Wizna', 'To starorzecze wyróżnia się większą powierzchnią i głębokością, co sprzyja występowaniu większych drapieżników. Dno jest mniej zamulone niż w innych mniejszych starorzeczach, z przewagą twardszych partii. Brzegi są dobrze dostępne, co ułatwia swobodne poruszanie się wędkarzom. Roślinność podwodna jest umiarkowana, zapewniając odpowiednie kryjówki, ale nie utrudniając łowienia. Okresowe połączenie z rzeką macierzystą zapewnia stały dopływ świeżej wody i ryb. Można tu liczyć na szczupaki, okonie, leszcze, płocie, a nawet sandacze. To doskonałe miejsce do spinningu i łowienia na żywca, oferujące dobre warunki przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21399, 6.2, 2.2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21400, 'Starorzecze (Zajki)', 'starorzecze-zajki-zajki-21400', 'OXBOW', 53.2116581, 22.5736731, 'Podlaskie', 'Zajki', 'To starorzecze charakteryzuje się podłużnym kształtem i umiarkowaną głębokością, co sprawia, że jest doskonałym miejscem do spinningowania. Dno jest przeważnie piaszczysto-muliste, z pojedynczymi zaczepami w postaci korzeni i gałęzi. Brzegi są stosunkowo łatwo dostępne, choć miejscami mogą być zarośnięte trawami. Roślinność wodna jest umiarkowana, tworząc idealne środowisko dla drapieżników. Okresowe połączenie z rzeką zapewnia wymianę ryb i odświeżanie wody. W zbiorniku dominują szczupaki, okonie, płocie, leszcze i bolenie, co czyni go atrakcyjnym dla wędkarzy poszukujących różnorodności. Warto eksplorować je zarówno z brzegu, jak i z pontonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21400, 3.5, 1.7, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21401, 'Starorzecze (Kleszcze)', 'starorzecze-kleszcze-kleszcze-21401', 'OXBOW', 53.2105879, 22.5640248, 'Podlaskie', 'Kleszcze', 'To starorzecze jest mniejszym, bardziej ukrytym zbiornikiem, idealnym dla wędkarzy ceniących spokój i łowienie metodami gruntowymi. Dno jest silnie zamulone, a brzegi są bagniste i trudno dostępne, gęsto porośnięte roślinnością. Roślinność podwodna jest bardzo obfita, co sprzyja rozwojowi ryb spokojnego żeru. Brak połączenia z rzeką główną sprawia, że jest to ekosystem zamknięty, z wysokim ryzykiem niedoboru tlenu w upalne lata. Głównymi mieszkańcami są liny, karasie pospolite, leszcze i karpie, które doskonale czują się w takich warunkach. Wędkowanie wymaga użycia wodzień i cierpliwości, ale może przynieść satysfakcję w postaci pięknych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21401, 2.1, 1.5, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Leszcz,Karp', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21402, 'Starorzecze (Kleszcze)', 'starorzecze-kleszcze-kleszcze-21402', 'OXBOW', 53.2126571, 22.5652098, 'Podlaskie', 'Kleszcze', 'To starorzecze wyróżnia się stałym połączeniem z rzeką, co zapewnia ciągły przepływ wody i bogactwo gatunkowe ryb. Dno jest zróżnicowane, z przewagą piasku i żwiru, co sprzyja występowaniu ryb rzecznych. Brzegi są dobrze dostępne, co ułatwia swobodne poruszanie się wędkarzom. Roślinność podwodna jest umiarkowana, tworząc idealne kryjówki dla ryb. Stałe połączenie z rzeką minimalizuje ryzyko niedoboru tlenu i zapewnia dynamiczny ekosystem. Można tu liczyć na szczupaki, okonie, płocie, leszcze i jazie, które cenią sobie przepływową wodę. To doskonałe miejsce na wędkarstwo spinningowe i spławikowe przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21402, 3, 1.9, 3.2, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz,Jaź', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21403, 'Starorzecze (Włochówka)', 'starorzecze-wlochowka-wizna-21403', 'OXBOW', 53.1927801, 22.4095273, 'Podlaskie', 'Wizna', 'To starorzecze jest jednym z głębszych w rejonie Włochówki, co czyni je atrakcyjnym dla wędkarzy poszukujących większych okazów ryb. Dno jest stosunkowo czyste, z niewielkim zamuleniem i twardszymi partiami, co sprzyja występowaniu drapieżników. Brzegi są dobrze dostępne, co ułatwia swobodne poruszanie się i zajmowanie stanowisk. Roślinność podwodna jest słaba, co sprzyja łowieniu na spinning i metody gruntowe. Okresowe połączenie z rzeką zapewnia dopływ świeżej wody i ryb, a ryzyko przyduchy jest minimalne. Dominują tu szczupaki, sandacze, leszcze, okonie i sumy, co gwarantuje emocjonujące połowy. To idealne miejsce na wiosenne i jesienne wyprawy wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21403, 5, 2.5, 5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Okoń,Sum', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21404, 'Starorzecze (Włochówka)', 'starorzecze-wlochowka-wizna-21404', 'OXBOW', 53.1763478, 22.400249, 'Podlaskie', 'Wizna', 'To starorzecze o średniej wielkości i głębokości oferuje zróżnicowane warunki do wędkowania, co czyni je uniwersalnym łowiskiem. Dno jest muliste, ale z twardszymi partiami, a brzegi są ogólnie łatwo dostępne, choć miejscami mogą być zarośnięte. Roślinność podwodna jest umiarkowana, tworząc dobre kryjówki dla ryb i struktury do obławiania. Połączenie z rzeką macierzystą następuje podczas wysokich stanów wody, co sprzyja migracji ryb i odświeżaniu zbiornika. Występuje tu bogata populacja szczupaka, lina, leszcza, płoci i okonia. Łowienie jest przyjemne i nie nastręcza większych trudności, a różnorodność metod wędkarskich jest możliwa.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21404, 4.2, 1.8, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21405, 'Starorzecze (Włochówka)', 'starorzecze-wlochowka-wizna-21405', 'OXBOW', 53.1747496, 22.3973044, 'Podlaskie', 'Wizna', 'To płytkie i silnie zarośnięte starorzecze jest klasycznym siedliskiem dla lina i karasia pospolitego. Dno jest bardzo mocno zamulone, a brzegi są bagniste i gęsto porośnięte trzciną, co znacząco utrudnia dostęp. Roślinność podwodna jest niezwykle obfita, tworząc labirynt dla ryb, ale także wyzwanie dla wędkarzy. Brak połączenia z rzeką sprawia, że w okresach suszy poziom wody może drastycznie spaść, a zbiornik jest podatny na całkowite wysychanie i przyduchy. Występują tu głównie lin, karaś pospolity, wzdręga i płoć, które doskonale radzą sobie w trudnych warunkach. Wędkowanie wymaga specjalistycznego sprzętu i cierpliwości, ale może nagrodzić pięknymi okazami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21405, 2.3, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21406, 'Starorzecze (Grądy-Woniecko)', 'starorzecze-grady-woniecko-grady-woniecko-21406', 'OXBOW', 53.1711454, 22.4044055, 'Podlaskie', 'Grądy-Woniecko', 'To starorzecze stanowi część większego kompleksu wodnego, oferując zróżnicowane warunki do wędkowania. Dno jest muliste, z lokalnymi twardszymi partiami, a brzegi są miejscami mocno zarośnięte trzciną, co wymaga użycia wodzień. Roślinność podwodna jest umiarkowana, tworząc dobre schronienia dla ryb i miejsca do zasadzek drapieżników. Połączenie z rzeką macierzystą podczas wysokich wód zapewnia regularne odświeżanie zbiornika i migrację ryb. Występuje tu bogata populacja szczupaka, lina, leszcza, okonia i płoci. Wędkowanie jest satysfakcjonujące, ale wymaga pewnej znajomości terenu i umiejętności poruszania się w zaroślach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21406, 3.8, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Okoń,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21407, 'Starorzecze (Grądy-Woniecko)', 'starorzecze-grady-woniecko-grady-woniecko-21407', 'OXBOW', 53.1650911, 22.3967791, 'Podlaskie', 'Grądy-Woniecko', 'To jedno z większych i bardziej otwartych starorzeczy w okolicy, oferujące doskonałe warunki dla różnorodnych gatunków ryb. Dno jest czyste, z niewielkim zamuleniem, co sprzyja występowaniu ryb drapieżnych i spokojnego żeru. Brzegi są dobrze dostępne z obu stron, co ułatwia swobodne poruszanie się i wybór stanowiska. Roślinność podwodna jest umiarkowana, zapewniając rybom schronienie, ale nie utrudniając łowienia. Stałe połączenie z rzeką zapewnia ciągły przepływ wody i bogactwo gatunkowe, minimalizując ryzyko niedoboru tlenu. Dominują tu szczupaki, leszcze, okonie, płocie i bolenie, co gwarantuje udane połowy. To idealne miejsce do spinningu i feedera przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21407, 7, 2, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Płoć,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21408, 'Starorzecze (Grądy-Woniecko)', 'starorzecze-grady-woniecko-grady-woniecko-21408', 'OXBOW', 53.1638018, 22.3821856, 'Podlaskie', 'Grądy-Woniecko', 'To starorzecze jest najgłębszym w tym kompleksie, co czyni je idealnym siedliskiem dla większych ryb dennych i drapieżników. Dno jest zróżnicowane, z głębokimi rynnami i zatopionymi drzewami, które stanowią doskonałe kryjówki. Brzegi są dobrze dostępne, co ułatwia dotarcie do wody, choć należy uważać na zaczepy. Roślinność podwodna jest słaba, co sprzyja łowieniu na grunt i z użyciem echosondy. Okresowe połączenie z rzeką zapewnia dopływ świeżej wody i ryb, a głębokość zbiornika minimalizuje ryzyko niedoboru tlenu. Można tu liczyć na sumy, sandacze, leszcze, karpie i węgorze. Wędkowanie wymaga mocnego sprzętu ze względu na potencjalne zaczepy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21408, 5.5, 2.8, 6, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Sandacz,Leszcz,Karp,Węgorz', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21409, 'Starorzecze (Grądy-Woniecko)', 'starorzecze-grady-woniecko-grady-woniecko-21409', 'OXBOW', 53.1635986, 22.3841734, 'Podlaskie', 'Grądy-Woniecko', 'To starorzecze o średniej wielkości oferuje zróżnicowane warunki, co czyni je dobrym łowiskiem dla wędkarzy poszukujących różnych gatunków ryb. Dno jest muliste, z twardszymi partiami, a brzegi są ogólnie łatwo dostępne, choć miejscami mogą być zarośnięte. Roślinność podwodna jest umiarkowana, tworząc dobre kryjówki dla ryb i struktury do obławiania. Okresowe połączenie z rzeką macierzystą podczas wysokich stanów wody zapewnia regularne odświeżanie zbiornika i migrację ryb. Występuje tu bogata populacja szczupaka, lina, leszcza, płoci i okonia. Łowienie jest przyjemne i nie nastręcza większych trudności, a różnorodność metod wędkarskich jest możliwa przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21409, 4, 1.9, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21410, 'Starorzecze Włochówka 1', 'starorzecze-wlochowka-1-wlochowka-21410', 'OXBOW', 53.1966741, 22.4086105, 'Podlaskie', 'Włochówka', 'To starorzecze, położone w malowniczej dolinie Narwi, charakteryzuje się typowym dla tego regionu mulistym dnem, bogatym w substancje organiczne. Brzegi są w większości mocno zarośnięte trzciną i pałką wodną, co utrudnia dostęp do wody, ale tworzy doskonałe schronienie dla ryb. W płytkich zatokach dominuje roślinność zanurzona, taka jak moczarka i rogatek, a także pływające grążele. Zbiornik jest ostoją dla lina, karasia pospolitego oraz licznych płoci, a także drapieżnych szczupaków, które czyhają w zaroślach. Wędkarstwo wymaga cierpliwości i często brodzenia, ale może przynieść satysfakcjonujące efekty, zwłaszcza w poszukiwaniu okazałych linów. Latem istnieje ryzyko przyduchy ze względu na dużą ilość rozkładającej się materii organicznej i ograniczoną cyrkulację wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21410, 3.2, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć', 'Trudny, miejscami bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21411, 'Starorzecze Włochówka 2', 'starorzecze-wlochowka-2-wlochowka-21411', 'OXBOW', 53.1895722, 22.3928381, 'Podlaskie', 'Włochówka', 'Drugie starorzecze w rejonie Włochówki to płytki zbiornik o silnym zamuleniu i bujnej roślinności. Jego dno jest niemal całkowicie pokryte grubą warstwą mułu i zalegających liści, co sprzyja rozwojowi bogatej flory podwodnej. Brzegi są gęsto porośnięte trzciną i pałką wodną, tworząc niemal nieprzeniknioną barierę dla wędkarzy, dlatego dostęp jest mocno ograniczony. Woda jest domem dla licznych karasi pospolitych i wzdręg, które doskonale czują się w tak zarośniętym środowisku. Niskie stany wody i wysoka temperatura latem mogą prowadzić do niedoborów tlenu, co stanowi wyzwanie dla ryb. Wymaga to specyficznego podejścia do wędkowania, często z użyciem długich tyczek i lekkich zestawów, aby ominąć gęste zarośla.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21411, 2.8, 1.5, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, późna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21412, 'Starorzecze Włochówka 3', 'starorzecze-wlochowka-3-wlochowka-21412', 'OXBOW', 53.1851717, 22.3909264, 'Podlaskie', 'Włochówka', 'To niewielkie, lecz urokliwe starorzecze charakteryzuje się płytkim dnem, które w większości pokryte jest warstwą mułu i resztek roślinnych, co stanowi idealne siedlisko dla bezkręgowców. Brzegi są silnie zarośnięte, miejscami bagniste, co sprawia, że dostęp do wody jest utrudniony i wymaga użycia wodoodpornego obuwia. Akwen jest gęsto porośnięty roślinnością zanurzoną i pływającą, tworząc labirynt zieleni. Dominujące gatunki ryb to lin, karaś pospolity, wzdręga oraz mniejsze okonie, które polują wśród roślin. W cieplejszych miesiącach, szczególnie przy niskim poziomie wody, występuje podwyższone ryzyko przyduchy, co należy wziąć pod uwagę planując wędkowanie. Mimo trudności, starorzecze oferuje intymne doświadczenie wędkarskie dla miłośników spokojnych łowisk.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21412, 1.9, 1.2, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna, pojedyncze gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21413, 'Starorzecze Włochówka 4', 'starorzecze-wlochowka-4-wlochowka-21413', 'OXBOW', 53.1876467, 22.3958039, 'Podlaskie', 'Włochówka', 'To jedno z lepiej dostępnych starorzeczy w kompleksie Włochówki, charakteryzujące się stosunkowo czystym dnem, miejscami piaszczystym, a miejscami z drobnym żwirem, co jest rzadkością w tych okolicach. Dzięki stałemu połączeniu z rzeką główną, woda jest dobrze natleniona, a ryzyko przyduchy jest minimalne. Brzegi są w dużej mierze dostępne, z licznymi dogodnymi stanowiskami dla wędkarzy, choć miejscami występują kępy trzcin. Roślinność podwodna jest umiarkowana, co ułatwia prowadzenie przynęt i sprzyja różnorodności gatunkowej ryb. W akwenie występują liczne szczupaki, leszcze, płocie i okonie, a także węgorze, które migrują z rzeki. Jest to doskonałe miejsce na całosezonowe wędkowanie, oferujące dobre warunki zarówno dla spinningistów, jak i wędkarzy spławikowych czy gruntowych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21413, 4.1, 2, 4.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Węgorz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21414, 'Starorzecze Bronowo 1', 'starorzecze-bronowo-1-bronowo-21414', 'OXBOW', 53.1439316, 22.3317326, 'Podlaskie', 'Bronowo', 'Starorzecze w Bronowie to rozległy akwen o zróżnicowanej głębokości i dnie, gdzie muliste obszary przeplatają się z twardszymi fragmentami. Brzegi są częściowo dostępne, ale w wielu miejscach porastają je gęste zarośla krzewów i drzew, które tworzą liczne zaczepy pod wodą. Zbiornik jest znany z obecności licznych zatopionych drzew i konarów, co stanowi wyzwanie dla wędkarzy, ale jednocześnie doskonałe kryjówki dla dużych drapieżników. Występują tu okazałe szczupaki, dorodne leszcze, liny oraz okonie, a także karpie. Połączenie z rzeką główną podczas wysokiej wody sprzyja wymianie genetycznej i uzupełnianiu populacji ryb. Wędkowanie wymaga precyzji i użycia odpowiednio mocnego sprzętu, aby sprostać warunkom i uniknąć utraty zestawów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21414, 5.5, 2.5, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Leszcz,Lin,Okoń,Karp', 'Miejscami dobry, miejscami zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21415, 'Starorzecze Bronowo 2', 'starorzecze-bronowo-2-bronowo-21415', 'OXBOW', 53.1411018, 22.3288196, 'Podlaskie', 'Bronowo', 'To starorzecze w Bronowie jest typowym przykładem zbiornika o zaawansowanym stadium zarastania i zamulania. Dno jest niemal w całości pokryte grubą warstwą miękkiego mułu, co sprawia, że woda jest często mętna, szczególnie po opadach. Brzegi są bardzo trudno dostępne, otoczone gęstymi pasami trzcin i bagnistymi terenami, co praktycznie uniemożliwia wędkowanie z brzegu bez odpowiedniego przygotowania. W zbiorniku dominują gatunki odporne na trudne warunki, takie jak karaś pospolity, lin, wzdręga i płoć, które doskonale radzą sobie w gęstej roślinności. Wysokie temperatury latem i intensywna wegetacja sprzyjają występowaniu przyduchy. Wędkowanie jest tu wyzwaniem, ale może przynieść satysfakcję w postaci pięknych linów i karasi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21415, 3.8, 1.7, 3.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, zarośnięty i bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21416, 'Starorzecze Niwkowo', 'starorzecze-niwkowo-niwkowo-21416', 'OXBOW', 53.1532195, 22.3573095, 'Podlaskie', 'Niwkowo', 'Starorzecze w Niwkowie to stosunkowo duże i głębokie łowisko, które oferuje zróżnicowane warunki dla wędkarzy. Dno jest mieszane, z przewagą mulistych osadów, ale z twardszymi fragmentami w głębszych partiach. Brzegi są w wielu miejscach dostępne, z pasami trzcin i niewielkimi drzewami, które zapewniają cień. Roślinność podwodna jest umiarkowana, co sprzyja swobodnemu poruszaniu się ryb i ułatwia prowadzenie przynęt. Akwen jest domem dla wielu gatunków, w tym dużych szczupaków, dorodnych leszczy, okoni, linów i karpi. Połączenie z głównym nurtem rzeki podczas wezbrań wzbogaca populację ryb. Mimo to, w upalne lata może wystąpić ryzyko niedotlenienia wody, zwłaszcza w płytszych zatokach. To popularne miejsce na wędkarskie wyprawy, cenione za różnorodność rybostanu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21416, 6, 2.2, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Leszcz,Okoń,Lin,Karp', 'Miejscami dobry, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21417, 'Starorzecze Grądy-Woniecko 1', 'starorzecze-grady-woniecko-1-grady-woniecko-21417', 'OXBOW', 53.1534905, 22.3709193, 'Podlaskie', 'Grądy-Woniecko', 'To starorzecze w Grądach-Woniecku jest płytkim, silnie zamulonym zbiornikiem, którego dno pokrywa gruba warstwa osadów organicznych. Charakteryzuje się bardzo bujną roślinnością, zarówno brzegową, jak i podwodną, tworzącą gęste dywany i labirynty. Brzegi są praktycznie nieprzystępne z powodu gęstych trzcinowisk i bagnistego terenu, co wymaga użycia wodoodpornego obuwia i dużej determinacji. W tak trudnych warunkach najlepiej czują się karasie pospolite, wzdręgi, liny i płocie, które doskonale maskują się w zaroślach. Ze względu na płytkość i intensywną wegetację, ryzyko przyduchy jest wysokie, szczególnie w upalne lata lub pod lodem. Wędkowanie jest tu prawdziwym wyzwaniem, ale dla miłośników natury i dzikich łowisk może być niezwykle satysfakcjonujące.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21417, 2.5, 1.4, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Lin,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21418, 'Starorzecze Grądy-Woniecko 2', 'starorzecze-grady-woniecko-2-grady-woniecko-21418', 'OXBOW', 53.1526445, 22.3703505, 'Podlaskie', 'Grądy-Woniecko', 'To bardzo płytkie starorzecze, które w okresach suszy może całkowicie wysychać, co czyni je łowiskiem sezonowym. Dno jest ekstremalnie zamulone, a woda często mętna i płytka, co sprzyja rozwojowi inwazyjnego karasia srebrzystego, który doskonale radzi sobie w tak trudnych warunkach. Brzegi są niemal nieprzystępne, otoczone gęstymi zaroślami i bagnami, co sprawia, że dostęp jest możliwy tylko w nielicznych miejscach i wymaga brodzenia. Roślinność podwodna jest niezwykle bujna, tworząc gęste zarośla, w których kryją się wzdręgi i płocie. Ryzyko przyduchy jest tu permanentne, co ogranicza populacje bardziej wrażliwych gatunków. Wędkowanie jest tu przede wszystkim wyzwaniem, ale dla poszukiwaczy karasia srebrzystego, który jest tu bardzo liczny, może być owocne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21418, 1.8, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Bardzo trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna, muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21419, 'Starorzecze Grądy-Woniecko 3', 'starorzecze-grady-woniecko-3-grady-woniecko-21419', 'OXBOW', 53.1525042, 22.3699261, 'Podlaskie', 'Grądy-Woniecko', 'To starorzecze oferuje bardziej zróżnicowane warunki niż jego sąsiedzi, z dnem mulistym, ale z twardszymi fragmentami w głębszych partiach. Połączenie z rzeką podczas wezbrań sprzyja odświeżaniu wody i uzupełnianiu rybostanu, co pozytywnie wpływa na populacje szczupaków, linów i okoni. Brzegi są częściowo dostępne, choć w wielu miejscach porastają je gęste trzciny i krzewy, co wymaga znalezienia odpowiedniego stanowiska. Roślinność podwodna jest umiarkowana, ale wciąż stanowi dobre schronienie dla ryb i miejsce żerowania. Mimo połączenia z rzeką, w upalne lata ryzyko przyduchy wciąż istnieje, zwłaszcza w płytszych zatokach. Wędkowanie jest tu przyjemne i może przynieść dobre wyniki, szczególnie w poszukiwaniu drapieżników i linów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21419, 3, 1.6, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Okoń,Płoć', 'Miejscami dobry, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie, roślinność', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21420, 'Starorzecze Grądy-Woniecko 4', 'starorzecze-grady-woniecko-4-grady-woniecko-21420', 'OXBOW', 53.1548326, 22.3712922, 'Podlaskie', 'Grądy-Woniecko', 'Charakterystyczne dla tego starorzecza jest bardzo płytkie i mocno zamulone dno, które w dużej mierze pokryte jest rozkładającą się materią organiczną. Brzegi są praktycznie nieprzystępne, otoczone gęstymi pasami trzcin, pałki wodnej i bagnistego terenu, co sprawia, że dostęp do wody jest bardzo utrudniony. Roślinność podwodna jest niezwykle bujna, tworząc gęste zarośla moczarki, rogatka i grążeli, które zajmują znaczną część powierzchni. W takich warunkach doskonale odnajdują się karasie pospolite, wzdręgi, płocie oraz liny, które żerują wśród roślinności. Ze względu na płytkość i gęstą roślinność, ryzyko przyduchy jest bardzo wysokie, szczególnie w letnie upały. Jest to łowisko dla cierpliwych wędkarzy, którzy cenią sobie dzikie i mało uczęszczane miejsca.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21420, 2.2, 1.3, 2.9, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć,Lin', 'Trudny, bagnisty, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna, muł', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21421, 'Starorzecze Grądy-Woniecko 5', 'starorzecze-grady-woniecko-5-grady-woniecko-21421', 'OXBOW', 53.1601029, 22.3784847, 'Podlaskie', 'Grądy-Woniecko', 'To starorzecze wyróżnia się większą głębokością i zróżnicowanym dnem, gdzie muliste obszary przeplatają się z twardszymi fragmentami. Mimo że brzegi są w wielu miejscach dostępne, występują tam również pasy trzcin i krzewów, które tworzą naturalne kryjówki dla ryb. Roślinność podwodna jest umiarkowana, co sprzyja rozwojowi różnorodnych gatunków ryb, w tym szczupaków, linów, leszczy i okoni. Połączenie z rzeką podczas wysokiej wody zapewnia dopływ świeżej wody i migrację ryb, co pozytywnie wpływa na ich kondycję. W upalne lata, zwłaszcza w płytszych strefach, może występować ryzyko obniżonego poziomu tlenu. Jest to atrakcyjne łowisko dla wędkarzy poszukujących zarówno drapieżników, jak i ryb spokojnego żeru, oferujące dobre warunki w sprzyjających porach roku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21421, 4.5, 2.1, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Okoń', 'Miejscami dobry, miejscami zarośnięty', TRUE, 'Pojedyncze zatopione gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21422, 'Starorzecze Krzewo 1', 'starorzecze-krzewo-1-krzewo-21422', 'OXBOW', 53.1273907, 22.2764647, 'Podlaskie', 'Krzewo', 'Starorzecze w Krzewie charakteryzuje się mulistym dnem i licznymi zatopionymi drzewami, które stanowią doskonałe kryjówki dla ryb, ale również pułapki dla wędkarzy. Brzegi są w większości bagniste i trudno dostępne, porośnięte gęstymi krzewami i trzcinami, co wymaga ostrożności i odpowiedniego obuwia. Roślinność podwodna jest umiarkowana, z przewagą grążeli i lilii wodnych, tworzących malownicze kobierce na powierzchni. W akwenie występują piękne liny, karasie pospolite, drapieżne szczupaki oraz liczne płocie. Brak stałego połączenia z rzeką sprawia, że woda jest spokojna, ale latem może występować ryzyko niedotlenienia, szczególnie w płytszych partiach. To miejsce dla wędkarzy ceniących sobie wyzwania i dzikie, naturalne środowisko.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21422, 3.5, 1.9, 4, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21423, 'Starorzecze Krzewo 2', 'starorzecze-krzewo-2-krzewo-21423', 'OXBOW', 53.1259648, 22.2737664, 'Podlaskie', 'Krzewo', 'Drugie starorzecze w Krzewie to płytki zbiornik o silnym zamuleniu i bardzo bujnej roślinności, co czyni go trudnym, ale interesującym łowiskiem. Dno jest miękkie, pokryte grubą warstwą mułu, a woda często mętna. Brzegi są gęsto porośnięte trzciną i pałką wodną, co sprawia, że dostęp do wody jest mocno ograniczony i wymaga brodzenia. W akwenie dominują gatunki odporne na trudne warunki, takie jak karaś srebrzysty, wzdręga, płoć i lin, które doskonale odnajdują się w gęstych zaroślach. Połączenie z rzeką podczas wezbrań jest sporadyczne, co nie zawsze zapobiega problemom z natlenieniem w upalne lata. Wędkowanie jest tu wyzwaniem, ale dla miłośników łowienia w zaroślach i poszukiwaczy karasia srebrzystego może być bardzo owocne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21423, 2.7, 1.5, 3.3, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś srebrzysty,Wzdręga,Płoć,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna, muł', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21424, 'Starorzecze Bronowo 3', 'starorzecze-bronowo-3-bronowo-21424', 'OXBOW', 53.1328198, 22.2936241, 'Podlaskie', 'Bronowo', 'To starorzecze wyróżnia się stałym połączeniem z rzeką główną, co zapewnia doskonałą cyrkulację wody i wysokie natlenienie przez cały rok. Dno jest zróżnicowane, z przewagą twardszych fragmentów, choć miejscami występują muliste osady. Brzegi są w większości łatwo dostępne, z nielicznymi pasami trzcin, co ułatwia wędkowanie z wielu stanowisk. Roślinność podwodna jest umiarkowana, co sprzyja rozwojowi bogatego rybostanu, w tym dużych szczupaków, dorodnych leszczy, okoni, a także węgorzy i sumów, które migrują z rzeki. Brak ryzyka przyduchy i dobre warunki sprawiają, że jest to jedno z najbardziej atrakcyjnych łowisk w regionie. To idealne miejsce dla wędkarzy poszukujących różnorodności gatunkowej i komfortowych warunków do wędkowania przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21424, 4.8, 2.3, 4.7, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Węgorz,Sum', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21425, 'Starorzecze (Bronowo)', 'starorzecze-bronowo-bronowo-21425', 'OXBOW', 53.1343196, 22.2933425, 'Województwo podlaskie', 'Bronowo', 'To starorzecze charakteryzuje się typowym dla tego typu zbiorników wydłużonym kształtem, będącym pozostałością po dawnym korycie rzeki Narew. Dno jest przeważnie muliste, z lokalnymi twardszymi partiami, co sprzyja rozwojowi bogatej roślinności podwodnej i wynurzonej. Brzegi są w wielu miejscach trudno dostępne, gęsto porośnięte trzciną, pałką wodną oraz krzewami, co stanowi doskonałe schronienie dla ryb. Wędkarze mogą spodziewać się tu obfitości leszczy, płoci, linów oraz karasi, a także drapieżników takich jak szczupak i okoń, zwłaszcza w głębszych partiach. Wysoki poziom roślinności może utrudniać swobodne zarzucanie, dlatego często wymagane jest użycie pontonu lub brodzenie. Wiosną i jesienią zbiornik oferuje najlepsze warunki do połowów, gdy aktywność ryb jest najwyższa, a zarośla nieco mniej dokuczliwe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21425, 3.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Płoć,Leszcz,Lin,Szczupak,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21426, 'Starorzecze (Kosaki)', 'starorzecze-kosaki-kosaki-21426', 'OXBOW', 53.1301533, 22.2859718, 'Województwo podlaskie', 'Kosaki', 'Zbiornik ten to klasyczne starorzecze, charakteryzujące się łagodnymi brzegami i stosunkowo płytkim dnem, które w dużej mierze pokryte jest warstwą mułu. Roślinność wodna jest tu bardzo bujna, tworząc liczne tarliska i kryjówki dla ryb, co sprzyja rozwojowi populacji lina i karasia. Dostęp do wody jest utrudniony ze względu na gęste zarośla trzcinowe, jednak w kilku miejscach znajdują się naturalne prześwity. Występują tu liczne zatopione gałęzie i korzenie, które stanowią doskonałe miejsca żerowania dla drapieżników takich jak szczupak i okoń. W okresach letnich, przy niskim stanie wody, może wystąpić ryzyko niedoboru tlenu, co należy wziąć pod uwagę planując wędkowanie. Najlepsze wyniki osiąga się tu wiosną, gdy ryby są najbardziej aktywne po zimie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21426, 2.8, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21427, 'Starorzecze (Kosaki)', 'starorzecze-kosaki-kosaki-21427', 'OXBOW', 53.130193, 22.2826136, 'Województwo podlaskie', 'Kosaki', 'To starorzecze, położone niedaleko wsi Kosaki, wyróżnia się nieco większą głębokością w centralnych partiach, co sprzyja występowaniu większych okazów leszczy i karpi. Dno jest zróżnicowane – od twardszych, piaszczystych fragmentów po głębokie, muliste doły, które są ulubionymi miejscami żerowania sumów. Brzegi są częściowo dostępne, z kilkoma dogodnymi stanowiskami wędkarskimi, jednak w większości porośnięte są gęstymi krzewami i drzewami. Roślinność podwodna jest umiarkowana, co ułatwia prowadzenie przynęt, ale jednocześnie zapewnia rybom wystarczające kryjówki. W okresach intensywnych opadów zbiornik może łączyć się z głównym nurtem rzeki, co wzbogaca jego ichtiofaunę. Wędkarze powinni przygotować się na zróżnicowane warunki i możliwość spotkania z dużymi rybami, szczególnie podczas wczesnej jesieni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21427, 4.1, 1.8, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Sum,Szczupak,Płoć', 'Częściowo dostępny, zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21428, 'Starorzecze (Bronowo)', 'starorzecze-bronowo-bronowo-21428', 'OXBOW', 53.1221021, 22.2889885, 'Województwo podlaskie', 'Bronowo', 'To niewielkie starorzecze w pobliżu Bronowa jest idealnym miejscem dla wędkarzy poszukujących spokoju i kontaktu z naturą. Charakteryzuje się płytkim, mulistym dnem i bardzo silnym zarastaniem, co czyni je ostoją dla ryb ciepłolubnych i ceniących gęste zarośla. Brzegi są trudne do pokonania, porośnięte gęstą roślinnością szuwarową i bagnistym podłożem, dlatego brodzenie jest często koniecznością. Mimo trudności w dostępie, zbiornik ten jest domem dla licznych karasi, linów i wzdręg, które doskonale czują się w zarośniętych partiach. Połów drapieżników, takich jak szczupak, wymaga precyzyjnych rzutów w wolne od roślinności okna. W upalne lata ryzyko przyduchy jest wysokie, co może wpływać na aktywność ryb. Najlepsze wyniki osiąga się tu wczesnym latem, zanim roślinność osiągnie swój szczyt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21428, 2.1, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21429, 'Starorzecze (Bronowo)', 'starorzecze-bronowo-bronowo-21429', 'OXBOW', 53.1193713, 22.2834284, 'Województwo podlaskie', 'Bronowo', 'To starorzecze jest jednym z bardziej urozmaiconych pod względem głębokości i struktury dna w okolicy Bronowa. Posiada zarówno płytkie zatoki, idealne dla płoci i wzdręg, jak i głębsze rynny, gdzie można spotkać większe leszcze i sandacze. Dno jest mieszane – od piaszczysto-żwirowych blatów po muliste zagłębienia, co sprzyja różnorodności gatunkowej. Brzegi są stosunkowo łatwo dostępne z jednej strony, natomiast druga strona jest bardziej zarośnięta i wymaga brodzenia. W zbiorniku występuje umiarkowana ilość zatopionych drzew i korzeni, które stanowią atrakcyjne kryjówki dla drapieżników. Starorzecze to ma tendencję do łączenia się z rzeką Narew podczas wiosennych roztopów, co odświeża wodę i zasila populację ryb. Wędkarze cenią je za możliwość łowienia wielu gatunków, a najlepsze efekty daje wczesna wiosna i późna jesień.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21429, 5.2, 2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Sandacz,Szczupak,Okoń', 'Dobry z jednej strony, trudny z drugiej', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21430, 'Starorzecze (Bronowo)', 'starorzecze-bronowo-bronowo-21430', 'OXBOW', 53.1256533, 22.2964323, 'Województwo podlaskie', 'Bronowo', 'To starorzecze to typowy, silnie zarośnięty akwen, charakteryzujący się stosunkowo płytkim dnem i wysokim stopniem zamulenia. Jest to idealne środowisko dla gatunków ryb preferujących ciepłe, płytkie wody z obfitą roślinnością. Brzegi są w większości niedostępne z brzegu, gęsto porośnięte trzciną i krzewami, co wymaga użycia pontonu lub brodzenia w woderach. W zbiorniku dominują leszcze, płocie, liny oraz karasie, które znajdują tu doskonałe warunki do żerowania i rozmnażania. Obecność licznych zatopionych gałęzi i kęp roślinności podwodnej stwarza idealne kryjówki dla szczupaków i okoni. Mimo trudności w dostępie, zbiornik ten jest ceniony przez wędkarzy za swoją dzikość i potencjał do łowienia pięknych okazów. Najlepsze pory na wędkowanie to wiosna i wczesne lato, zanim roślinność stanie się zbyt gęsta.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21430, 3, 1.3, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Leszcz,Płoć,Lin,Karaś pospolity,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21431, 'Starorzecze (Bronowo)', 'starorzecze-bronowo-bronowo-21431', 'OXBOW', 53.1262323, 22.2930084, 'Województwo podlaskie', 'Bronowo', 'Ten zbiornik to typowe starorzecze o charakterze przejściowym, które podczas wysokich stanów wody regularnie łączy się z rzeką Narew, co wpływa na jego bogatą ichtiofaunę. Dno jest zróżnicowane, z przewagą mulistych osadów, ale z licznymi twardszymi partiami, gdzie można spotkać leszcze i karpie. Brzegi są w większości zarośnięte, lecz na kilku odcinkach dostęp jest ułatwiony dzięki naturalnym prześwitom w roślinności. W starorzeczu występuje umiarkowana ilość roślinności podwodnej, która zapewnia schronienie dla ryb, ale nie utrudnia nadmiernie wędkowania. Wśród drapieżników dominują szczupaki i okonie, które często polują w płytszych, bardziej zarośniętych strefach. Wędkarze cenią to miejsce za dynamikę i różnorodność połowów, a najlepsze efekty przynosi wędkowanie wczesną wiosną i jesienią, po ustąpieniu letnich upałów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21431, 4, 1.7, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Karp', 'Częściowo dostępny', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21432, 'Starorzecze (Lisno)', 'starorzecze-lisno-lisno-21432', 'OXBOW', 53.1472795, 22.3396405, 'Województwo podlaskie', 'Lisno', 'To starorzecze w pobliżu Lisna charakteryzuje się rozległą powierzchnią i stosunkowo niewielką głębokością, co sprzyja silnemu nagrzewaniu się wody w lecie. Dno jest w przeważającej części muliste, z licznymi podwodnymi górami i dołkami, które stanowią atrakcyjne miejsca dla ryb. Brzegi są bardzo zróżnicowane – od łatwo dostępnych, trawiastych odcinków po gęsto zarośnięte trzciną i krzewami partie. Roślinność wodna jest obfita, tworząc idealne warunki dla linów, karasi i wzdręg, a także dla drapieżników takich jak szczupak i okoń, które polują wśród zarośli. Starorzecze to jest znane z występowania dużych okazów karasi srebrzystych. Z uwagi na dużą powierzchnię, wędkarze często korzystają z łodzi lub pontonów, aby dotrzeć do najbardziej obiecujących miejsc. Cały sezon oferuje dobre warunki do wędkowania, z naciskiem na późną wiosnę i lato.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21432, 12, 1.8, 3.5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś srebrzysty,Szczupak,Okoń,Wzdręga', 'Zróżnicowany, od dobrego do mocno zarośniętego', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21433, 'Starorzecze (Bronowo)', 'starorzecze-bronowo-bronowo-21433', 'OXBOW', 53.1466332, 22.3371234, 'Województwo podlaskie', 'Bronowo', 'To starorzecze to jeden z głębszych i mniej zarośniętych akwenów w okolicy Bronowa, co czyni je atrakcyjnym dla wędkarzy poszukujących sandaczy i sumów. Dno jest twarde, piaszczysto-żwirowe, z nielicznymi, ale wyraźnymi dołami i rynnami, gdzie gromadzą się większe ryby. Brzegi są w większości łatwo dostępne, z naturalnymi pomostami i miejscami do wędkowania, co jest rzadkością w przypadku starorzeczy. Roślinność podwodna jest słaba, co sprzyja swobodnemu prowadzeniu przynęt i minimalizuje ryzyko zaczepów. Starorzecze to ma stałe połączenie z rzeką, co zapewnia ciągły dopływ świeżej wody i ryb, zwiększając różnorodność gatunkową. Wędkarze mogą liczyć na udane połowy leszczy, płoci, a także drapieżników takich jak szczupak i sandacz. Najlepsze pory to wiosna i jesień, kiedy drapieżniki są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21433, 6.5, 2.2, 5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sandacz,Sum,Szczupak,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21434, 'Starorzecze (Krzewo)', 'starorzecze-krzewo-krzewo-21434', 'OXBOW', 53.1318534, 22.25369, 'Województwo podlaskie', 'Krzewo', 'Starorzecze w Krzewie to płytki i silnie zamulony zbiornik, który stanowi ostoję dla gatunków ryb preferujących środowiska o bujnej roślinności. Dno jest miękkie, pokryte grubą warstwą osadów organicznych, co sprzyja rozwojowi makrofitów. Brzegi są w większości niedostępne, gęsto porośnięte trzciną, krzewami i drzewami, co utrudnia swobodne wędkowanie z brzegu. Zbiornik jest domem dla licznych linów, karasi pospolitych i wzdręg, które doskonale maskują się wśród zarośli. Występują tu również szczupaki i okonie, polujące na drobnicę w wolnych od roślinności partiach. Wędkarze powinni przygotować się na konieczność brodzenia i precyzyjnego zarzucania przynęt. W upalne lata ryzyko przyduchy jest wysokie, dlatego najlepsze efekty osiąga się wiosną i wczesnym latem, zanim temperatura wody osiągnie szczyt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21434, 2.3, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21435, 'Starorzecze (Pniewo)', 'starorzecze-pniewo-pniewo-21435', 'OXBOW', 53.1261986, 22.25452, 'Województwo podlaskie', 'Pniewo', 'To starorzecze w Pniewie charakteryzuje się umiarkowaną głębokością i zróżnicowanym dnem, z przewagą mulistych osadów, ale z twardszymi partiami wzdłuż brzegów. Jest to typowy zbiornik dla ryb karpiowatych, takich jak leszcz, płoć i karp, które znajdują tu obfitość pokarmu. Brzegi są częściowo dostępne, z kilkoma dogodnymi stanowiskami wędkarskimi, jednak w większości porośnięte są trzciną i krzewami. Roślinność podwodna jest umiarkowana, co ułatwia prowadzenie przynęt, ale jednocześnie zapewnia rybom wystarczające kryjówki. W zbiorniku występują również drapieżniki, takie jak szczupak i okoń, które polują na drobnicę w okolicach zarośli. Starorzecze to jest cenione przez wędkarzy za stabilne warunki i możliwość regularnych połowów. Najlepsze efekty osiąga się tu w całym sezonie, szczególnie w ciepłych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21435, 4.5, 1.6, 3.2, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Okoń', 'Częściowo dostępny', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21436, 'Starorzecze (Pniewo)', 'starorzecze-pniewo-pniewo-21436', 'OXBOW', 53.118699, 22.266688, 'Województwo podlaskie', 'Pniewo', 'To starorzecze to jeden z bardziej dzikich i trudno dostępnych akwenów w okolicy Pniewa, idealny dla wędkarzy ceniących spokój i wyzwania. Charakteryzuje się bardzo silnym zarastaniem i wysokim stopniem zamulenia, co czyni je ostoją dla linów i karasi. Dno jest miękkie, z grubą warstwą osadów, a brzegi są niemal całkowicie niedostępne z powodu gęstej trzciny i bagnistego terenu. Wymaga to brodzenia lub użycia pontonu, aby dotrzeć do otwartych partii wody. Mimo trudności, zbiornik ten jest domem dla wielu okazów karasi pospolitych, linów i wzdręg, które doskonale czują się w gęstych zaroślach. Występują tu również szczupaki, które polują w wolnych od roślinności korytarzach. W upalne lata ryzyko niedoboru tlenu jest wysokie, co należy wziąć pod uwagę. Najlepsze efekty daje tu wędkowanie wczesnym latem, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21436, 2.6, 1.1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21437, 'Starorzecze (Pniewo)', 'starorzecze-pniewo-pniewo-21437', 'OXBOW', 53.1208817, 22.2525926, 'Województwo podlaskie', 'Pniewo', 'To starorzecze w Pniewie to zbiornik o zróżnicowanej głębokości i dnie, które jest mieszanką mulistych osadów i twardszych, piaszczystych fragmentów. Jest to idealne miejsce dla leszczy, płoci oraz okoni, które znajdują tu bogactwo pokarmu. Brzegi są w większości dostępne, z kilkoma wygodnymi miejscami do wędkowania, choć lokalnie mogą występować zarośla. Roślinność podwodna jest umiarkowana, co pozwala na swobodne prowadzenie przynęt, a jednocześnie zapewnia rybom schronienie. W zbiorniku występuje umiarkowana ilość zatopionych korzeni i gałęzi, które stanowią atrakcyjne kryjówki dla drapieżników. Starorzecze to ma tendencję do łączenia się z rzeką podczas wiosennych roztopów, co odświeża wodę i zasila populację ryb. Wędkarze cenią to miejsce za różnorodność gatunkową i stabilne warunki. Najlepsze efekty daje wczesna wiosna i jesień.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21437, 3.8, 1.9, 3.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Karp', 'Dobry z jednej strony, umiarkowany z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21438, 'Starorzecze (Pniewo)', 'starorzecze-pniewo-pniewo-21438', 'OXBOW', 53.1227666, 22.2512949, 'Województwo podlaskie', 'Pniewo', 'To starorzecze to stosunkowo płytki zbiornik z dominującym mulistym dnem, które w upalne lata może prowadzić do silnego zarastania i niedoborów tlenu. Jest to środowisko sprzyjające rozwojowi populacji karasia pospolitego, lina i wzdręgi. Brzegi są w większości trudno dostępne, gęsto porośnięte trzciną i inną roślinnością szuwarową, co wymaga użycia sprzętu do brodzenia. W zbiorniku występują liczne zatopione gałęzie i kępy roślinności, które stanowią doskonałe kryjówki dla ryb. Mimo trudności w dostępie, wędkarze mogą liczyć na udane połowy, zwłaszcza wczesnym latem, kiedy ryby są bardzo aktywne. Połów drapieżników, takich jak szczupak, wymaga precyzyjnych rzutów w wolne od roślinności miejsca. Warto pamiętać o wysokim ryzyku przyduchy w okresach długotrwałych upałów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21438, 2.9, 1, 2.1, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21439, 'Starorzecze (Pniewo)', 'starorzecze-pniewo-pniewo-21439', 'OXBOW', 53.1245839, 22.2653926, 'Województwo podlaskie', 'Pniewo', 'To starorzecze w Pniewie to zbiornik o umiarkowanej głębokości i zróżnicowanym dnie, z przewagą mulistych osadów, ale z twardszymi partiami wzdłuż brzegów. Jest to idealne miejsce dla leszczy, płoci oraz okoni, które znajdują tu bogactwo pokarmu. Brzegi są w większości dostępne, z kilkoma wygodnymi miejscami do wędkowania, choć lokalnie mogą występować zarośla. Roślinność podwodna jest umiarkowana, co pozwala na swobodne prowadzenie przynęt, a jednocześnie zapewnia rybom schronienie. W zbiorniku występuje umiarkowana ilość zatopionych korzeni i gałęzi, które stanowią atrakcyjne kryjówki dla drapieżników. Starorzecze to ma tendencję do łączenia się z rzeką podczas wiosennych roztopów, co odświeża wodę i zasila populację ryb. Wędkarze cenią to miejsce za różnorodność gatunkową i stabilne warunki. Najlepsze efekty daje wczesna wiosna i jesień.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21439, 3.8, 1.9, 3.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Karp', 'Dobry z jednej strony, umiarkowany z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21440, 'Starorzecze (Rakowo-Boginie)', 'starorzecze-rakowo-boginie-rakowo-boginie-21440', 'OXBOW', 53.1217355, 22.2149862, 'Podlaskie', 'Rakowo-Boginie', 'To starorzecze, położone w malowniczej okolicy Rakowa-Bogini, charakteryzuje się dość stabilnym ekosystemem. Dno jest muliste z miejscowymi twardszymi partiami, a brzegi są łatwo dostępne, choć miejscami porośnięte trawą. Roślinność podwodna jest umiarkowana, co sprzyja różnorodności gatunków ryb. Można tu liczyć na udane połowy szczupaka, lina, leszcza, płoci oraz okonia, szczególnie w okolicach podwodnych zaczepów. Połączenie z rzeką Narew następuje podczas wysokich stanów wody, co zasila starorzecze w świeżą wodę i nowe ryby. Łowisko jest ogólnie przystępne i nie wymaga specjalistycznego sprzętu, co czyni je atrakcyjnym dla wędkarzy o różnym doświadczeniu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21440, 4.8, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21441, 'Starorzecze (Rakowo-Czachy)', 'starorzecze-rakowo-czachy-rakowo-czachy-21441', 'OXBOW', 53.1345521, 22.1951577, 'Podlaskie', 'Rakowo-Czachy', 'Starorzecze w Rakowie-Czachach to typowe, silnie zarośnięte łowisko, wymagające od wędkarza cierpliwości i precyzji. Dno jest bardzo muliste i miękkie, co utrudnia brodzenie, a brzegi gęsto porasta trzcina i inna roślinność wodna. Silne zarastanie i ograniczona wymiana wody sprzyjają wysokiemu poziomowi zamulenia i ryzyku przyduchy w gorące lata. Dominują tu gatunki ryb preferujące płytkie, zarośnięte wody, takie jak lin, karaś pospolity, wzdręga oraz szczupak, który czai się w gęstwinie. Dostęp do wody jest trudny, często wymaga użycia brodzących spodni i odpowiedniego sprzętu do przedzierania się przez roślinność. Jest to idealne miejsce dla miłośników spokojnego wędkowania na spławik lub lekką gruntówkę, poszukujących okazałych linów i karasi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21441, 3.2, 1.5, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21442, 'Starorzecze (Niewodowo)', 'starorzecze-niewodowo-niewodowo-21442', 'OXBOW', 53.1350252, 22.1810947, 'Podlaskie', 'Niewodowo', 'Starorzecze Niewodowo wyróżnia się stałym połączeniem z rzeką, co zapewnia doskonałą wymianę wody i bogactwo gatunkowe. Jest to jedno z głębszych starorzeczy w okolicy, z dnem zróżnicowanym od mulistego po piaszczyste. Brzegi są przeważnie łatwo dostępne, z nielicznymi zaroślami trzcinowymi, co ułatwia wybór stanowiska. Umiarkowana roślinność podwodna tworzy idealne kryjówki dla drapieżników i miejsca żerowania dla ryb spokojnego żeru. Wędkarze mogą tu liczyć na szczupaka, okonia, leszcza, płoci, a nawet sandacza, który migruje z głównego nurtu rzeki. Łowisko jest cenione za dobre warunki do spinningowania i wędkarstwa gruntowego przez cały sezon. Brak dużego zamulenia i dobre natlenienie minimalizują ryzyko przyduchy, co czyni je stabilnym i pewnym miejscem do wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21442, 6.1, 2.2, 4.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Sandacz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21443, 'Starorzecze (Pniewo)', 'starorzecze-pniewo-pniewo-21443', 'OXBOW', 53.1301219, 22.1960568, 'Podlaskie', 'Pniewo', 'To starorzecze w Pniewie jest klasycznym przykładem łowiska o charakterze białorybowym, z mulistym dnem i obfitością roślinności. Brzegi są częściowo dostępne, ale miejscami bagniste i wymagają ostrożności oraz odpowiedniego obuwia. Połączenie z rzeką występuje tylko podczas wysokich stanów wody, co wpływa na cykliczne odnawianie populacji ryb. Dominują tu płocie, leszcze, karasie pospolite oraz wzdręgi, które doskonale czują się w zarośniętych partiach. Poziom zamulenia jest średni, a umiarkowane zarastanie może utrudniać niektóre techniki wędkarskie. W ciepłe miesiące istnieje umiarkowane ryzyko niedoboru tlenu, dlatego warto monitorować warunki. To doskonałe miejsce dla wędkarzy preferujących spławik i metody gruntowe, poszukujących obfitych brań.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21443, 2.9, 1.4, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21444, 'Starorzecze (Rybno)', 'starorzecze-rybno-rybno-21444', 'OXBOW', 53.124275, 22.1926889, 'Podlaskie', 'Rybno', 'Starorzecze w Rybnie to niewielkie i bardzo urokliwe łowisko, idealne dla poszukujących spokoju i intymności. Charakteryzuje się bardzo mulistym dnem i gęstymi zaroślami trzcin, co sprawia, że dostęp do wody jest trudny i wymaga brodzenia. Brak stałego połączenia z rzeką oraz wysokie zamulenie i silne zarastanie sprawiają, że starorzecze jest podatne na wysychanie w okresach suszy. Występuje tu również wysokie ryzyko przyduchy, zwłaszcza latem i zimą pod lodem. Dominującymi gatunkami są lin, karp, karaś pospolity i wzdręga, które doskonale radzą sobie w trudnych warunkach. Duża ilość zatopionych drzew i gęstej roślinności podwodnej stanowi wyzwanie, ale i doskonałe kryjówki dla ryb. To łowisko dla cierpliwych wędkarzy, ceniących sobie dziką przyrodę i możliwość złowienia medalowego lina.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21444, 1.8, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karp,Karaś pospolity,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21445, 'Starorzecze (Pniewo)', 'starorzecze-pniewo-pniewo-21445', 'OXBOW', 53.1237754, 22.194421, 'Podlaskie', 'Pniewo', 'To starorzecze, położone w Pniewie, jest ściśle związane z pobliskim systemem starorzeczy, dzieląc z nimi wiele cech. Dno jest przeważnie muliste, z lokalnymi zagłębieniami, a brzegi są częściowo bagniste, co utrudnia swobodny dostęp. Połączenie z rzeką Narew następuje tylko podczas wiosennych roztopów i wysokich stanów wody, co zapewnia odświeżenie wód. Roślinność podwodna jest umiarkowana, ale miejscami tworzy gęste skupiska, idealne dla drapieżników. Wędkarze mogą tu liczyć na szczupaka, okonia, leszcza i płoci, które są typowymi mieszkańcami tych wód. Poziom zamulenia jest średni, a ryzyko przyduchy niskie, jeśli starorzecze jest regularnie zasilane świeżą wodą. To dobre miejsce na wędkowanie z gruntu lub na spławik, oferujące relaksujące doświadczenie wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21445, 2.5, 1.3, 2.3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Szczupak,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21446, 'Starorzecze (Pniewo)', 'starorzecze-pniewo-pniewo-21446', 'OXBOW', 53.1260664, 22.2053563, 'Podlaskie', 'Pniewo', 'To większe starorzecze w Pniewie oferuje bardziej otwarty charakter i zróżnicowane możliwości wędkarskie. Dno jest czyste w wielu miejscach, z twardszymi partiami i umiarkowanym zamuleniem, co sprzyja różnorodności ryb. Brzegi są ogólnie łatwo dostępne, umożliwiając swobodne poruszanie się i wybór stanowiska. Stałe połączenie z rzeką Narew gwarantuje dobrą wymianę wody i ciągły dopływ nowych okazów. Występuje tu bogata populacja szczupaka, leszcza, płoci, okonia, a także węgorza, co czyni to łowisko atrakcyjnym dla wielu technik. Roślinność podwodna jest umiarkowana, nie utrudniając w znacznym stopniu wędkowania. Niskie ryzyko przyduchy i brak wysychania czynią je niezawodnym miejscem przez cały sezon. To idealne miejsce dla wędkarzy poszukujących stabilnych warunków i różnorodnych gatunków ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21446, 7.2, 2, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Węgorz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21447, 'Starorzecze (Pniewo)', 'starorzecze-pniewo-pniewo-21447', 'OXBOW', 53.1153061, 22.2136806, 'Podlaskie', 'Pniewo', 'Starorzecze w Pniewie, charakteryzujące się dzikim i nieco odizolowanym charakterem, jest prawdziwym rajem dla wędkarzy ceniących spokój. Dno jest muliste i miękkie, z licznymi zatopionymi korzeniami i gałęziami, co tworzy doskonałe kryjówki dla ryb. Brzegi są trudne do pokonania, często bagniste i gęsto zarośnięte, wymagające użycia brodzących spodni. Brak stałego połączenia z rzeką oraz silne zarastanie roślinnością wodną zwiększają ryzyko przyduchy, szczególnie w upalne lata. Dominują tu lin, karaś pospolity, szczupak i okoń, które doskonale adaptują się do tych warunków. To łowisko dla doświadczonych wędkarzy, którzy potrafią odnaleźć się w trudnym terenie i cenią sobie wyzwania. Najlepsze wyniki osiąga się tu wczesnym latem, gdy roślinność nie jest jeszcze zbyt gęsta.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21447, 3.5, 1.6, 3, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21448, 'Starorzecze (Pniewo)', 'starorzecze-pniewo-pniewo-21448', 'OXBOW', 53.116091, 22.2092619, 'Podlaskie', 'Pniewo', 'To starorzecze, położone w Pniewie, jest płytkie i silnie zarośnięte, co sprawia, że jest szczególnie wrażliwe na zmiany poziomu wody. Dno jest bardzo muliste i z dużą ilością zatopionych drzew, co utrudnia wędkowanie, ale zapewnia rybom liczne schronienia. Brzegi są mocno zarośnięte trzciną i inną roślinnością, co czyni dostęp do wody bardzo trudnym i wymaga brodzenia. Wysokie zamulenie i silne zarastanie sprawiają, że starorzecze jest podatne na wysychanie w okresach suszy i ma wysokie ryzyko przyduchy. Dominują tu karasie pospolite, wzdręgi, liny oraz płocie, które doskonale radzą sobie w płytkich i ciepłych wodach. Jest to łowisko dla wędkarzy preferujących spokojne metody, takich jak spławik, i gotowych na wyzwania związane z gęstą roślinnością.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21448, 2.1, 1, 2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21449, 'Starorzecze (Pniewo)', 'starorzecze-pniewo-pniewo-21449', 'OXBOW', 53.1245533, 22.2106221, 'Podlaskie', 'Pniewo', 'Starorzecze w Pniewie o umiarkowanej wielkości oferuje zrównoważony ekosystem i dobre warunki wędkarskie. Dno jest muliste, ale z twardszymi fragmentami, a brzegi są łatwo dostępne, co ułatwia wybór miejscówki. Połączenie z rzeką podczas wysokiej wody zapewnia regularne odświeżanie wód i dopływ nowych ryb. Roślinność podwodna jest umiarkowana, tworząc naturalne kryjówki, ale nie utrudniając zbytnio wędkowania. Wędkarze mogą tu liczyć na szczupaka, okonia, leszcza, płoci i lina, które są typowymi gatunkami dla starorzeczy Narwi. Poziom zamulenia jest średni, a ryzyko przyduchy niskie, co zapewnia stabilne warunki przez większość sezonu. To łowisko jest polecane dla wędkarzy poszukujących różnorodności i komfortowych warunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21449, 4, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21450, 'Starorzecze (Drozdowo)', 'starorzecze-drozdowo-drozdowo-21450', 'OXBOW', 53.1415836, 22.155782, 'Podlaskie', 'Drozdowo', 'To malownicze starorzecze, położone w pobliżu Drozdowa, jest znane z krystalicznie czystej wody i pięknych krajobrazów. Dno jest zróżnicowane, z twardszymi partiami i umiarkowanym zamuleniem, co sprzyja bogatej faunie. Brzegi są dobrze utrzymane i łatwo dostępne, co czyni to łowisko idealnym dla całej rodziny. Stałe połączenie z rzeką zapewnia doskonałą wymianę wody i obecność wielu gatunków ryb, w tym szczupaka, leszcza, płoci, okonia i węgorza. Roślinność podwodna jest umiarkowana, tworząc naturalne habitaty, ale nie przeszkadzając w wędkowaniu. Niskie ryzyko przyduchy i brak problemów z wysychaniem gwarantują udane wyprawy przez cały rok. To jedno z najbardziej atrakcyjnych starorzeczy w regionie, oferujące zarówno relaks, jak i emocjonujące połowy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21450, 5.5, 1.9, 3.8, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Węgorz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21451, 'Starorzecze (Niewodowo)', 'starorzecze-niewodowo-niewodowo-21451', 'OXBOW', 53.1407051, 22.1752569, 'Podlaskie', 'Niewodowo', 'Starorzecze w Niewodowie to łowisko o nieco dzikim charakterze, idealne dla wędkarzy poszukujących prawdziwych wyzwań i dużych okazów. Dno jest muliste, z licznymi zatopionymi drzewami i korzeniami, co stanowi doskonałe kryjówki dla dużych ryb. Brzegi są trudne do pokonania, często bagniste i gęsto zarośnięte, co wymaga cierpliwości i odpowiedniego przygotowania. Połączenie z rzeką następuje tylko podczas wysokich stanów wody, co wzbogaca populację, ale nie zawsze zapewnia idealną wymianę. Dominują tu sum, szczupak, leszcz i karp, które osiągają imponujące rozmiary. Poziom zamulenia jest średni, a umiarkowane zarastanie wymaga od wędkarza umiejętności manewrowania. To łowisko dla zaawansowanych, ceniących sobie walkę z potężnymi rybami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21451, 4.2, 2.1, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Leszcz,Karp', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21452, 'Starorzecze (Drozdowo)', 'starorzecze-drozdowo-drozdowo-21452', 'OXBOW', 53.1521655, 22.1427915, 'Podlaskie', 'Drozdowo', 'To starorzecze, część kompleksu w Drozdowie, jest płytkie i silnie zarośnięte, co nadaje mu specyficzny charakter. Dno jest bardzo muliste, a gęsta roślinność podwodna stanowi wyzwanie, ale i schronienie dla ryb. Brzegi są mocno zarośnięte trzciną, co sprawia, że dostęp do wody jest bardzo trudny i często wymaga brodzenia. Brak połączenia z rzeką, wysokie zamulenie i silne zarastanie zwiększają ryzyko wysychania i przyduchy, szczególnie w okresach suszy. Dominują tu karasie pospolite, liny, wzdręgi i płocie, które doskonale radzą sobie w tych trudnych warunkach. Jest to łowisko dla wędkarzy preferujących spokojne metody i gotowych na zmagania z roślinnością. Najlepsze wyniki osiąga się tu wczesnym latem, zanim roślinność osiągnie swój szczyt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21452, 2.8, 1.2, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21453, 'Starorzecze (Drozdowo)', 'starorzecze-drozdowo-drozdowo-21453', 'OXBOW', 53.1518809, 22.1410882, 'Podlaskie', 'Drozdowo', 'To starorzecze, sąsiadujące z innymi w Drozdowie, jest nieco głębsze i bardziej stabilne, oferując lepsze warunki niż jego płytsi sąsiedzi. Dno jest muliste z pojedynczymi korzeniami i gałęziami, co zapewnia rybom kryjówki bez nadmiernego utrudniania wędkowania. Brzegi są częściowo bagniste, ale z możliwością znalezienia dogodnych stanowisk, choć brodzenie może być wskazane. Połączenie z rzeką podczas wysokich stanów wody zapewnia regularne odświeżanie wód i dopływ nowych ryb. Wędkarze mogą tu liczyć na szczupaka, lina, leszcza i okonia, które są typowymi gatunkami dla tych wód. Poziom zamulenia jest średni, a ryzyko przyduchy niskie, co zapewnia stabilne warunki przez większość sezonu. To dobre miejsce na wędkowanie z gruntu lub na spławik, oferujące relaksujące doświadczenie wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21453, 3, 1.5, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Okoń', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21454, 'Starorzecze (Drozdowo)', 'starorzecze-drozdowo-drozdowo-21454', 'OXBOW', 53.1462008, 22.1421438, 'Podlaskie', 'Drozdowo', 'To długie i wąskie starorzecze w Drozdowie wyróżnia się zróżnicowaną głębokością i czystym dnem w wielu miejscach. Stałe połączenie z rzeką Narew zapewnia doskonałą wymianę wody i bogactwo gatunkowe przez cały rok. Brzegi są ogólnie łatwo dostępne, z nielicznymi zaroślami, co ułatwia wybór stanowiska i swobodne poruszanie się. Umiarkowana roślinność podwodna tworzy idealne kryjówki dla drapieżników i miejsca żerowania dla ryb spokojnego żeru. Wędkarze mogą tu liczyć na szczupaka, okonia, leszcza, płoci, a nawet suma, który migruje z głównego nurtu rzeki. Łowisko jest cenione za dobre warunki do spinningowania i wędkarstwa gruntowego. Niskie ryzyko przyduchy i brak wysychania czynią je niezawodnym i atrakcyjnym miejscem do wędkowania przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21454, 6, 1.8, 3.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Sum', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21455, 'Starorzecze Drozdowo', 'starorzecze-drozdowo-drozdowo-21455', 'OXBOW', 53.1479753, 22.1391792, 'Podlaskie', 'Drozdowo', 'Starorzecze w okolicach Drozdowa to malowniczy akwen charakteryzujący się typową dla doliny Narwi bogatą roślinnością przybrzeżną. Dno jest w większości muliste, ale miejscami można natrafić na twardsze, piaszczyste odcinki, szczególnie w pobliżu dawnego nurtu. Brzegi są gęsto porośnięte trzcinami i krzewami, co utrudnia dostęp, ale jednocześnie stanowi doskonałe schronienie dla wielu gatunków ryb. Zbiornik ten słynie z występowania pięknych linów i dorodnych szczupaków, które preferują zarośnięte partie wody. Występuje tu również obficie płoć i karaś pospolity, co czyni to łowisko atrakcyjnym dla wędkarzy spławikowych i gruntowych. Należy jednak liczyć się z licznymi zaczepami oraz koniecznością użycia woderów, aby dotrzeć do najlepszych miejscówek. Ryzyko przyduchy jest realne w upalne lata, dlatego najlepsze wyniki osiąga się wiosną i wczesną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21455, 3.5, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Płoć,Karaś pospolity', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21456, 'Starorzecze Kalinowo (1)', 'starorzecze-kalinowo-1-kalinowo-21456', 'OXBOW', 53.1558778, 22.137258, 'Podlaskie', 'Kalinowo', 'To starorzecze, położone w pobliżu Kalinowa, jest typowym, płytkim zbiornikiem z bogatą florą wodną. Dno jest jednolicie muliste, co sprzyja rozwojowi gęstej roślinności podwodnej, takiej jak rogatek czy moczarka. Brzegi są łatwo dostępne w kilku miejscach, ale dominują tam rozległe pola trzcin, które stanowią naturalne tarliska. Łowisko jest znane z populacji karasi pospolitych i srebrzystych, a także licznych wzdręg i płoci. Okonie również często polują wśród zarośli, oferując emocjonujące brania na lekkie zestawy spinningowe. Ze względu na płytkość i obfitość materii organicznej, w upalne lata istnieje wysokie ryzyko niedoboru tlenu. Wędkarze powinni przygotować się na liczne zaczepy o roślinność, dlatego zaleca się łowienie na spławik lub metodą gruntową z odpowiednio dobranymi zestawami. Najlepsze wyniki osiąga się w chłodniejszych miesiącach, gdy aktywność ryb jest większa.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21456, 1.2, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Karaś srebrzysty,Wzdręga,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21457, 'Starorzecze Kalinowo (2)', 'starorzecze-kalinowo-2-kalinowo-21457', 'OXBOW', 53.1559036, 22.134904, 'Podlaskie', 'Kalinowo', 'Drugie starorzecze koło Kalinowa wyróżnia się nieco większą głębokością i bardziej zróżnicowanym dnem. Przeważa tu mulisty osad, ale na środku zbiornika można znaleźć twardsze partie, pozostałości po dawnym nurcie rzeki. Brzegi są częściowo zalesione, co zapewnia cień i tworzy dogodne stanowiska dla drapieżników. Jest to doskonałe łowisko dla szczupaków i okoni, które często czyhają na swoje ofiary wśród zatopionych gałęzi i podwodnych zarośli. Występują tu także duże leszcze i płocie, stanowiące podstawę diety drapieżników. Dostęp do wody jest utrudniony przez gęstą roślinność i powalone drzewa, co wymaga ostrożności i często użycia woderów. Starorzecze to łączy się z rzeką tylko podczas bardzo wysokich stanów wody, co sprzyja utrzymaniu stabilnej populacji ryb. Wędkarze spinningowi znajdą tu wiele wyzwań, a gruntowcy mogą liczyć na dorodne okazy białorybu. Ryzyko przyduchy jest umiarkowane, ale warto monitorować poziom tlenu w upalne dni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21457, 2.8, 2.2, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21458, 'Starorzecze Kalinowo (3)', 'starorzecze-kalinowo-3-kalinowo-21458', 'OXBOW', 53.155071, 22.1332133, 'Podlaskie', 'Kalinowo', 'Trzecie starorzecze w rejonie Kalinowa to mniejsze, ale bardzo urokliwe łowisko, idealne dla poszukiwaczy spokoju i kontaktu z naturą. Charakteryzuje się dość płytkim dnem, w większości pokrytym warstwą mułu i obfitą roślinnością. Brzegi są porośnięte gęstą trzciną, co wymaga cierpliwości i znalezienia dogodnego dojścia. Dominującymi gatunkami są tu liny, które doskonale czują się w zarośniętych i spokojnych wodach, oraz liczne płocie i karasie pospolite. Można tu również trafić na wzdręgi, żerujące na powierzchni. Ze względu na niewielką głębokość i brak stałego połączenia z rzeką, starorzecze to jest podatne na wahania poziomu wody i ryzyko przyduchy w okresach suszy lub upałów. Wędkarze łowiący na spławik lub lekką gruntówkę z pewnością znajdą tu swoje miejsce. Wymagane są wodery, aby skutecznie obławiać przybrzeżne partie zbiornika. Brak silnych prądów i liczne kryjówki sprzyjają rozwojowi bogatej ichtiofauny.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21458, 0.9, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Płoć,Karaś pospolity,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21459, 'Starorzecze Piątnica Włościańska', 'starorzecze-piatnica-wloscianska-piatnica-wloscianska-21459', 'OXBOW', 53.1751127, 22.109237, 'Podlaskie', 'Piątnica Włościańska', 'To rozległe starorzecze w pobliżu Piątnicy Włościańskiej jest jednym z bardziej atrakcyjnych łowisk w regionie. Charakteryzuje się zróżnicowanym dnem, gdzie muliste partie przeplatają się z twardszymi, żwirowymi odcinkami, pozostałościami po dawnym korycie rzeki. Brzegi są częściowo dostępne, z kilkoma dogodnymi miejscami do rozłożenia sprzętu, choć dominują tu zarośla i trzciny. Akwen ten jest znany z obfitości leszczy i płoci, a także z występowania pięknych karpi i sandaczy, które żerują w głębszych partiach. Szczupaki i okonie również są częstymi bywalcami, zwłaszcza w okolicach podwodnych zaczepów. Starorzecze ma okresowe połączenie z Narwią, co sprzyja migracji ryb i odnawianiu populacji. Wędkarze gruntowi i spławikowi znajdą tu wiele satysfakcji, a spinningiści mogą liczyć na spotkanie z drapieżnikami. Wymagane jest ostrożne poruszanie się po brzegach ze względu na bagniste podłoże, ale dostępność jest ogólnie dobra. Ryzyko przyduchy jest niskie dzięki większej objętości wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21459, 7, 2.5, 6, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sandacz,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21460, 'Starorzecze Czarnocin (1)', 'starorzecze-czarnocin-1-czarnocin-21460', 'OXBOW', 53.2097937, 22.068607, 'Podlaskie', 'Czarnocin', 'Pierwsze starorzecze w okolicach Czarnocina to płytki, silnie zarośnięty zbiornik, będący ostoją dla wielu gatunków ryb. Dno jest w całości pokryte grubą warstwą mułu, co sprzyja rozwojowi bogatej roślinności podwodnej i nawodnej, takiej jak grążele i lilie wodne. Brzegi są bardzo trudne do pokonania, gęsto porośnięte trzciną i krzewami, co wymaga użycia woderów i często maczety. Dominującymi gatunkami są tu karasie pospolite i srebrzyste, wzdręgi oraz liny, które doskonale maskują się wśród zarośli. Należy również spodziewać się okoni, polujących na drobnicę. Ze względu na płytkość i intensywne procesy gnilne, ryzyko przyduchy jest wysokie, szczególnie w upalne i bezwietrzne dni. Łowienie wymaga precyzji i cierpliwości, najlepiej na spławik lub lekką gruntówkę, unikając zaczepów. Starorzecze to jest idealne dla wędkarzy ceniących dziką przyrodę i wyzwania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21460, 1.5, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Karaś srebrzysty,Wzdręga,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21461, 'Starorzecze Czarnocin (2)', 'starorzecze-czarnocin-2-czarnocin-21461', 'OXBOW', 53.2081022, 22.0684504, 'Podlaskie', 'Czarnocin', 'Drugie starorzecze w Czarnocinie jest nieco głębsze i mniej zarośnięte niż jego sąsiad. Dno jest muliste, ale na głębszych partiach można znaleźć twardsze fragmenty. Brzegi są częściowo dostępne, choć w niektórych miejscach wymagają przedzierania się przez zarośla. Jest to doskonałe łowisko dla szczupaków i okoni, które znajdują tu obfitość pokarmu w postaci płoci i leszczy. Występują tu także dorodne liny, szczególnie w zatoczkach z gęstą roślinnością. Zbiornik ten ma okresowe połączenie z Narwią, co wzbogaca jego ichtiofaunę. Wędkarze spinningowi docenią liczne kryjówki i zaczepy, które stanowią idealne miejsca do zasadzek drapieżników. Dostęp do wody jest umiarkowany, a w niektórych miejscach wodery mogą okazać się pomocne. Ryzyko przyduchy jest umiarkowane, ale w upalne lata warto zachować ostrożność. Łowisko oferuje ciekawe możliwości zarówno dla wędkarzy gruntowych, jak i spinningistów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21461, 2.1, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Leszcz,Lin', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21462, 'Starorzecze Czarnocin (3)', 'starorzecze-czarnocin-3-czarnocin-21462', 'OXBOW', 53.2202925, 22.0625639, 'Podlaskie', 'Czarnocin', 'Trzecie starorzecze w Czarnocinie to długi i wąski akwen, który zachował wiele cech dawnego koryta rzeki. Dno jest zróżnicowane, z mulistymi zatokami i twardszymi, piaszczystymi odcinkami wzdłuż dawnego nurtu. Brzegi są częściowo dostępne, ale w wielu miejscach gęsto porośnięte krzewami i drzewami, co tworzy naturalne stanowiska dla ryb. Jest to znakomite łowisko dla boleni i jazi, które często patrolują otwarte partie wody, oraz kleni, które chętnie przebywają w pobliżu zwalonych drzew. Występują tu również płocie, leszcze i okonie. Starorzecze to ma stałe połączenie z Narwią, co zapewnia ciągłą wymianę wody i ryb, a także minimalizuje ryzyko przyduchy. Dostęp do wody jest umiarkowany, a w niektórych miejscach można skorzystać z pomostów wędkarskich, choć większość łowisk wymaga dojścia przez zarośla. Wędkarze spinningowi znajdą tu wiele okazji do spotkania z drapieżnikami rzecznymi, a gruntowcy mogą liczyć na dorodne okazy białorybu. To łowisko jest aktywne przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21462, 4, 2, 4.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Boleń,Jaź,Kleń,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21463, 'Starorzecze Kijów (1)', 'starorzecze-kijow-1-kijow-21463', 'OXBOW', 51.0325762, 19.2685336, 'Śląskie', 'Kijów', 'Starorzecze w Kijowie, w dolinie Warty, to kameralny zbiornik o charakterze typowym dla wód stojących. Dno jest w dużej mierze muliste, z licznymi osadami dennymi, co sprzyja rozwojowi bogatej roślinności. Brzegi są gęsto porośnięte trzcinami i tatarakiem, co utrudnia dostęp, ale jednocześnie tworzy idealne kryjówki dla ryb. Łowisko słynie z dużych linów i karasi pospolitych, a także z występowania pięknych wzdręg. W płytkich partiach często żerują płocie i okonie. Ze względu na brak stałego połączenia z rzeką i niewielką głębokość, w upalne lata istnieje wysokie ryzyko niedoboru tlenu. Wędkarze powinni przygotować się na łowienie w zaroślach, często z użyciem woderów, co jest typowe dla tego typu starorzeczy. Mimo trudności, cierpliwi wędkarze mogą liczyć na wspaniałe okazy. Najlepsze wyniki osiąga się wiosną i wczesną jesienią, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21463, 1.8, 1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21464, 'Starorzecze Kijów (2)', 'starorzecze-kijow-2-kijow-21464', 'OXBOW', 51.03282, 19.2673371, 'Śląskie', 'Kijów', 'Drugie starorzecze w Kijowie jest nieco większe i głębsze, co czyni je bardziej stabilnym ekosystemem. Dno jest zróżnicowane, z przewagą mułu, ale z twardszymi partiami w centralnej części. Brzegi są częściowo dostępne, z kilkoma dogodnymi miejscami do wędkowania, choć dominują tam zarośla i powalone drzewa. Akwen ten jest znany z występowania dorodnych szczupaków i okoni, które doskonale czują się w bogato urozmaiconym środowisku. Występują tu także duże leszcze i płocie, stanowiące obfity pokarm dla drapieżników. Starorzecze ma okresowe połączenie z Wartą, co sprzyja migracji ryb i odnawianiu populacji. Wędkarze spinningowi znajdą tu wiele wyzwań, a gruntowcy mogą liczyć na dorodne okazy białorybu. Wymagane jest ostrożne poruszanie się po brzegach ze względu na bagniste podłoże, ale dostępność jest ogólnie dobra. Ryzyko przyduchy jest umiarkowane dzięki większej objętości wody i okresowemu połączeniu z rzeką.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21464, 2.5, 1.7, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21465, 'Starorzecze Czarnocin (4)', 'starorzecze-czarnocin-4-czarnocin-21465', 'OXBOW', 53.2164123, 22.0623412, 'Podlaskie', 'Czarnocin', 'Czwarte starorzecze w Czarnocinie to niewielki, ale głęboki zbiornik, otoczony gęstymi zaroślami. Dno jest w dużej mierze muliste, z lokalnymi zagłębieniami, gdzie gromadzą się ryby. Brzegi są strome i trudno dostępne, co sprzyja zachowaniu dzikiego charakteru łowiska. Jest to idealne miejsce dla sumów, które znajdują tu doskonałe kryjówki, a także dla dużych karpi i leszczy. Występują tu również szczupaki i okonie, polujące na drobnicę. Starorzecze to ma stałe połączenie z Narwią, co zapewnia ciągłą wymianę wody i ryb, a także minimalizuje ryzyko przyduchy. Dostęp do wody jest utrudniony, często wymaga użycia woderów i sprzętu do przedzierania się przez roślinność. Wędkarze szukający dużych okazów ryb drapieżnych i karpiowatych znajdą tu wiele wyzwań i satysfakcji. Pomimo trudności, to łowisko jest bardzo cenione przez doświadczonych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21465, 1.5, 2.5, 6.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Karp,Leszcz,Szczupak', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21466, 'Starorzecze Pęza', 'starorzecze-peza-peza-21466', 'OXBOW', 53.2287775, 22.0443409, 'Podlaskie', 'Pęza', 'Starorzecze w Pęzie to średniej wielkości zbiornik, charakteryzujący się dość płytkim dnem i obfitością roślinności wodnej. Dno jest w większości muliste, ale w niektórych miejscach można znaleźć twardsze fragmenty. Brzegi są częściowo dostępne, choć dominują tu gęste zarośla trzcin i krzewów. Łowisko jest znane z populacji linów, karasi pospolitych i wzdręg, które doskonale czują się w zarośniętych i spokojnych wodach. Występują tu również liczne płocie i okonie. Ze względu na brak stałego połączenia z Narwią i niewielką głębokość, starorzecze to jest podatne na wahania poziomu wody i ryzyko przyduchy w okresach suszy lub upałów. Wędkarze łowiący na spławik lub lekką gruntówkę z pewnością znajdą tu swoje miejsce. Wymagane są wodery, aby skutecznie obławiać przybrzeżne partie zbiornika. Mimo tych wyzwań, to łowisko oferuje wspaniałe możliwości dla wędkarzy ceniących spokój i kontakt z naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21466, 2, 1.1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21467, 'Starorzecze Jednaczewo', 'starorzecze-jednaczewo-jednaczewo-21467', 'OXBOW', 53.2432322, 22.0222637, 'Podlaskie', 'Jednaczewo', 'Starorzecze w Jednaczewie to rozległy i zróżnicowany akwen, który oferuje wiele możliwości wędkarskich. Dno jest zmienne, od mulistych zatok po twardsze, piaszczysto-żwirowe odcinki, będące pozostałością po dawnym korycie Narwi. Brzegi są częściowo dostępne, z licznymi dogodnymi miejscami do wędkowania, choć w niektórych partiach dominują zarośla i trzciny. Jest to doskonałe łowisko dla leszczy, płoci i karpi, a także dla sandaczy i szczupaków, które znajdują tu obfitość pokarmu. Starorzecze ma okresowe połączenie z Narwią, co sprzyja migracji ryb i odnawianiu populacji. Wędkarze gruntowi i spławikowi znajdą tu wiele satysfakcji, a spinningiści mogą liczyć na spotkanie z drapieżnikami. Dostęp do wody jest dobry, choć w niektórych miejscach wodery mogą okazać się pomocne. Ryzyko przyduchy jest niskie dzięki większej objętości wody i okresowemu połączeniu z rzeką. To łowisko jest aktywne przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21467, 5.5, 2, 5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sandacz,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21468, 'Starorzecze Jankowice (1)', 'starorzecze-jankowice-1-jankowice-21468', 'OXBOW', 51.0325243, 19.2607909, 'Śląskie', 'Jankowice', 'Starorzecze w Jankowicach, w dolinie Warty, to urokliwy zbiornik o charakterze typowym dla wód starorzecznych. Dno jest w dużej mierze muliste, z licznymi osadami dennymi, co sprzyja rozwojowi bogatej roślinności podwodnej. Brzegi są gęsto porośnięte trzcinami i krzewami, co utrudnia dostęp, ale jednocześnie tworzy idealne kryjówki dla ryb. Łowisko słynie z dużych linów i karasi pospolitych, a także z występowania pięknych wzdręg. W płytkich partiach często żerują płocie i okonie. Ze względu na brak stałego połączenia z rzeką i niewielką głębokość, w upalne lata istnieje wysokie ryzyko niedoboru tlenu. Wędkarze powinni przygotować się na łowienie w zaroślach, często z użyciem woderów, co jest typowe dla tego typu starorzeczy. Mimo trudności, cierpliwi wędkarze mogą liczyć na wspaniałe okazy. Najlepsze wyniki osiąga się wiosną i wczesną jesienią, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21468, 1, 0.9, 1.7, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21469, 'Starorzecze Jankowice (2)', 'starorzecze-jankowice-2-jankowice-21469', 'OXBOW', 51.031783, 19.2605438, 'Śląskie', 'Jankowice', 'Drugie starorzecze w Jankowicach jest nieco głębsze i bardziej rozległe, co zapewnia większą stabilność ekosystemu. Dno jest zróżnicowane, z przewagą mułu, ale z twardszymi partiami w centralnej części, gdzie nurt rzeki był silniejszy. Brzegi są częściowo dostępne, z kilkoma dogodnymi miejscami do wędkowania, choć dominują tam zarośla i powalone drzewa. Akwen ten jest znany z występowania dorodnych szczupaków i okoni, które doskonale czują się w bogato urozmaiconym środowisku. Występują tu także duże leszcze i płocie, stanowiące obfity pokarm dla drapieżników. Starorzecze ma okresowe połączenie z Wartą, co sprzyja migracji ryb i odnawianiu populacji. Wędkarze spinningowi znajdą tu wiele wyzwań, a gruntowcy mogą liczyć na dorodne okazy białorybu. Wymagane jest ostrożne poruszanie się po brzegach ze względu na bagniste podłoże, ale dostępność jest ogólnie dobra. Ryzyko przyduchy jest umiarkowane dzięki większej objętości wody i okresowemu połączeniu z rzeką.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21469, 2.3, 1.6, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21470, 'Starorzecze (Jankowice)', 'starorzecze-jankowice-radomsko-21470', 'OXBOW', 51.0315964, 19.2611322, 'Łódzkie', 'Radomsko', 'To malownicze starorzecze, położone w dolinie rzeki Warty, stanowi atrakcyjne łowisko dla wędkarzy. Charakteryzuje się urozmaiconym dnem, gdzie piaszczyste płycizny przeplatają się z mulistymi zagłębieniami, a w niektórych miejscach występują pojedyncze zatopione korzenie. Brzegi są w większości łatwo dostępne, porośnięte trawą i pojedynczymi krzewami, co sprzyja swobodnemu poruszaniu się. Roślinność podwodna jest umiarkowana, z przewagą rdestnic i moczarki kanadyjskiej, tworząc dogodne kryjówki dla ryb drapieżnych i białorybu. W starorzeczu dominują szczupaki, liny, płocie, leszcze oraz okonie, które żerują aktywnie w cieplejszych porach roku. Starorzecze łączy się z rzeką podczas wiosennych roztopów i wysokich stanów wody, co zapewnia regularne zasilanie w tlen i migrację ryb, minimalizując ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21470, 3.2, 1.8, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Płoć,Leszcz,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21471, 'Starorzecze (Drożęcin-Lubiejewo)', 'starorzecze-drozecin-lubiejewo-lomza-21471', 'OXBOW', 53.2508648, 22.0029397, 'Podlaskie', 'Łomża', 'To rozległe starorzecze, będące pozostałością po dawnych meandrach Narwi, jest cenionym łowiskiem wśród lokalnych wędkarzy. Dno jest przeważnie muliste, z licznymi osadami dennymi, jednak w głębszych partiach można znaleźć twardsze, piaszczyste miejsca. Brzegi są częściowo zarośnięte trzcinami i pałką wodną, co utrudnia dostęp w niektórych rejonach, ale jednocześnie tworzy schronienie dla ryb. Obfita roślinność podwodna, w tym grążele i lilie wodne, pokrywa znaczną część akwenu, stanowiąc idealne siedlisko dla lina i karasia. W wodach starorzecza królują liny, karasie pospolite, płocie, leszcze oraz sumy, które znajdują tu doskonałe warunki do bytowania. Połączenie z rzeką Narew podczas wiosennych wylewów wzbogaca ekosystem, wprowadzając nowe gatunki i zapewniając ciągłość populacji.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21471, 12.5, 2.5, 6, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Leszcz,Sum', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21472, 'Starorzecze (Jednaczewo)', 'starorzecze-jednaczewo-lomza-21472', 'OXBOW', 53.2479701, 22.0091289, 'Podlaskie', 'Łomża', 'Starorzecze w Jednaczewie to malowniczy, choć nieco trudny do wędkowania akwen, położony niedaleko Narwi. Charakteryzuje się dnem pokrytym grubą warstwą mułu, co wymaga odpowiedniego sprzętu i technik wędkarskich, zwłaszcza przy łowieniu białorybu. Brzegi są gęsto porośnięte krzewami i drzewami, a dostęp do wody jest miejscami ograniczony, co dodaje łowisku dzikiego charakteru. Roślinność wodna jest obfita, z przewagą grążeli i trzcin, tworzących rozległe pasy przybrzeżne, idealne dla drapieżników. W starorzeczu licznie występują szczupaki, karasie srebrzyste, wzdręgi, płocie oraz okonie, które znajdują tu bogate zasoby pokarmowe. Brak stałego połączenia z rzeką sprawia, że w okresach suszy poziom wody może spadać, zwiększając ryzyko przyduchy w zimie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21472, 5.8, 1.5, 3.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Szczupak,Karaś srebrzysty,Wzdręga,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21473, 'Starorzecze (Kijów)', 'starorzecze-kijow-radomsko-21473', 'OXBOW', 51.0381144, 19.2487181, 'Łódzkie', 'Radomsko', 'To niewielkie, ale urokliwe starorzecze w Kijowie, usytuowane w bliskości Warty, jest idealnym miejscem na spokojne wędkowanie. Dno jest zróżnicowane, z przewagą piasku i żwiru w płytszych częściach oraz mulistymi osadami w głębszych dołkach. Brzegi są w większości łatwo dostępne, z miejscowymi zaroślami, które zapewniają cień i kryjówki. Roślinność podwodna jest umiarkowana, z kępami moczarki i wywłócznika, które stanowią schronienie dla narybku i drobnego białorybu. W starorzeczu występują liczne populacje płoci, okoni, leszczy, a także sporadycznie większe szczupaki. Brak bezpośredniego połączenia z rzeką sprawia, że jest to środowisko stabilne, choć wymaga uwagi w okresach długotrwałej suszy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21473, 1.5, 1, 2.5, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Okoń,Leszcz,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21474, 'Starorzecze (Prusicko)', 'starorzecze-prusicko-radomsko-21474', 'OXBOW', 51.0419708, 19.2023096, 'Łódzkie', 'Radomsko', 'Starorzecze w Prusicku to typowy akwen dolinowy, charakteryzujący się wydłużonym kształtem i dość głębokim korytem. Dno jest w przeważającej części muliste, z twardszymi fragmentami wzdłuż dawnego nurtu rzeki. Brzegi są częściowo zalesione, co utrudnia dostęp, ale tworzy urokliwe, zaciszne zakątki. Roślinność wodna jest obfita, zwłaszcza w płytszych zatokach, gdzie dominują trzciny i pałka wodna, stanowiące idealne tarliska. W starorzeczu licznie występują leszcze, płocie, karpie oraz okonie, a także sporadycznie można natrafić na sandacza, który migruje z Warty. Połączenie z rzeką podczas wysokiej wody jest kluczowe dla utrzymania zdrowej populacji ryb i zapobiega nadmiernemu zamulaniu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21474, 7, 2.2, 5.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', FALSE, FALSE, 'Leszcz,Płoć,Karp,Okoń,Sandacz', 'Trudny, zalesiony', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21475, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21475', 'OXBOW', 51.7083626, 23.5458382, 'Lubelskie', 'Hanna', 'To jedno z licznych starorzeczy w okolicach Hanny, położone w malowniczej dolinie Bugu, oferujące wędkarzom dzikie i naturalne środowisko. Dno jest bardzo zróżnicowane, od piaszczystych blatów po głębokie, muliste rynny, z licznymi zatopionymi drzewami i gałęziami. Brzegi są trudne do pokonania, często bagniste i gęsto porośnięte krzewami, co wymaga wysiłku, ale nagradza ciszą i spokojem. Roślinność wodna jest bardzo obfita, z dominacją grążeli, rdestnic i jeżogłówki, tworzących doskonałe kryjówki dla ryb. W starorzeczu dominują szczupaki, liny, karasie pospolite, wzdręgi oraz sumy, które znajdują tu idealne warunki do rozwoju. Brak stałego połączenia z Bugiem sprawia, że jest to zbiornik odizolowany, co sprzyja rozwojowi stabilnych populacji.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21475, 4, 1.5, 3, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Wzdręga,Sum', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21476, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21476', 'OXBOW', 51.7087468, 23.5457681, 'Lubelskie', 'Hanna', 'Kolejne starorzecze w rejonie Hanny, charakteryzujące się mniejszą powierzchnią, ale znaczną głębokością w centralnej części. Dno jest przeważnie muliste, z licznymi osadami organicznymi, co świadczy o bogatym życiu biologicznym. Brzegi są częściowo dostępne, ale w wielu miejscach wymagają brodzenia, ze względu na podmokły teren i gęste zarośla. Roślinność podwodna jest intensywna, tworząc gęste dywany, które są schronieniem dla wielu gatunków ryb. W starorzeczu można spotkać liny, karasie pospolite, płocie, wzdręgi oraz okonie, które doskonale adaptują się do tego typu środowiska. W okresach letnich, przy wysokich temperaturach, istnieje umiarkowane ryzyko niedoboru tlenu, co wymaga monitorowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21476, 2.1, 1.7, 4, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21477, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21477', 'OXBOW', 51.708977, 23.5461532, 'Lubelskie', 'Hanna', 'To płytkie starorzecze w okolicach Hanny, które stanowi unikalny ekosystem, choć bywa wyzwaniem dla wędkarzy. Dno jest w większości piaszczysto-muliste, z licznymi płyciznami i obszarami porośniętymi roślinnością. Brzegi są stosunkowo łatwo dostępne, ale miejscami mogą być podmokłe, szczególnie po obfitych deszczach. Roślinność wodna jest bardzo obfita, z dominacją moczarki, rdestnic i traw wodnych, które pokrywają znaczną część akwenu. W starorzeczu dominują karasie pospolite, wzdręgi, płocie oraz liny, które doskonale czują się w płytkich, zarośniętych wodach. Ze względu na niewielką głębokość, w okresach upałów istnieje wysokie ryzyko wysychania i niedoboru tlenu, co wymaga od wędkarzy elastyczności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21477, 1.8, 0.8, 1.5, 'Brak', 'Średnie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć,Lin', 'Dobry, ale miejscami podmokły', FALSE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21478, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21478', 'OXBOW', 51.7090588, 23.5464189, 'Lubelskie', 'Hanna', 'Kolejny akwen w okolicy Hanny, charakteryzujący się dzikim i naturalnym charakterem, co przyciąga miłośników spokojnego wędkowania. Dno jest zróżnicowane, z przewagą mułu w głębszych partiach i piasku na płyciznach, a także licznymi zatopionymi gałęziami. Brzegi są mocno zarośnięte trzciną i krzewami, co wymaga poszukiwania dogodnych miejsc do zarzucenia wędki, ale zapewnia poczucie intymności. Roślinność podwodna jest bardzo obfita, tworząc gęste zarośla, które są idealnym schronieniem dla ryb i narybku. W starorzeczu dominują szczupaki, okonie, leszcze, płocie oraz liny, które dobrze radzą sobie w tym zarośniętym środowisku. Starorzecze sporadycznie łączy się z Bugiem podczas bardzo wysokich stanów wody, co zasila je w świeżą wodę i ryby.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21478, 3.5, 1.6, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Silne', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21479, 'Starorzecze (Kuzawka)', 'starorzecze-kuzawka-kuzawka-21479', 'OXBOW', 51.7223632, 23.5429616, 'Lubelskie', 'Kuzawka', 'To jedno z większych starorzeczy w okolicy Kuzawki, charakteryzujące się długim i wąskim kształtem, typowym dla dawnego koryta rzeki Bug. Dno jest przeważnie muliste, z licznymi zagłębieniami i twardszymi odcinkami wzdłuż dawnego nurtu, co sprzyja różnorodności gatunkowej. Brzegi są częściowo zalesione, a częściowo pokryte łąkami, co zapewnia zróżnicowany dostęp do wody. Roślinność wodna jest umiarkowana, z przewagą rdestnic i traw wodnych, które tworzą naturalne kryjówki dla ryb. W starorzeczu można z powodzeniem łowić leszcze, płocie, karpie, szczupaki oraz sumy, które osiągają tu imponujące rozmiary. Stałe połączenie z Bugiem podczas wysokich wód zapewnia regularne zarybianie i utrzymanie dobrej jakości wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21479, 9, 2, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Sum', 'Dobry, ale miejscami zalesiony', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21480, 'Starorzecze (Kuzawka)', 'starorzecze-kuzawka-kuzawka-21480', 'OXBOW', 51.7204646, 23.5314585, 'Lubelskie', 'Kuzawka', 'To mniejsze starorzecze w pobliżu Kuzawki, charakteryzujące się spokojnym i zacisznym otoczeniem, idealnym dla wędkarzy szukających relaksu. Dno jest w większości muliste, z grubą warstwą osadów, co sprzyja rozwojowi bogatej fauny dennej, będącej pokarmem dla ryb. Brzegi są mocno zarośnięte trzciną i krzewami, co utrudnia dostęp, ale jednocześnie chroni łowisko przed nadmierną presją wędkarską. Roślinność wodna jest bardzo obfita, z dominacją grążeli i lilii wodnych, tworzących rozległe pola, w których ukrywają się ryby. W starorzeczu licznie występują liny, karasie pospolite, wzdręgi oraz płocie, które doskonale czują się w płytkich i zarośniętych wodach. Brak połączenia z rzeką sprawia, że zbiornik jest wrażliwy na długotrwałe susze i wysokie temperatury, co może prowadzić do niedoborów tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21480, 2.8, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21481, 'Starorzecze (Kuzawka)', 'starorzecze-kuzawka-kuzawka-21481', 'OXBOW', 51.7165997, 23.5278225, 'Lubelskie', 'Kuzawka', 'To stosunkowo głębokie starorzecze w okolicach Kuzawki, które wyróżnia się czystą wodą i różnorodnym dnem. Dno jest mieszane, z przewagą piasku i żwiru w płytszych partiach oraz mulistymi dołkami w głębszych rejonach, co sprzyja różnorodności gatunkowej. Brzegi są w większości łatwo dostępne, porośnięte trawą i pojedynczymi drzewami, co ułatwia wędkowanie z brzegu. Roślinność podwodna jest umiarkowana, z kępami rdestnic i moczarki, które stanowią doskonałe kryjówki dla ryb drapieżnych i białorybu. W starorzeczu dominują szczupaki, okonie, leszcze, płocie oraz węgorze, które znajdują tu dobre warunki do żerowania i rozwoju. Połączenie z rzeką Bug podczas wysokich stanów wody zapewnia stałe zasilanie w tlen i migrację ryb, co utrzymuje zdrowy ekosystem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21481, 6.5, 2.8, 6, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Węgorz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21482, 'Starorzecze (Kuzawka)', 'starorzecze-kuzawka-kuzawka-21482', 'OXBOW', 51.7140423, 23.5324822, 'Lubelskie', 'Kuzawka', 'To malownicze starorzecze, charakteryzujące się dużą ilością zatopionych drzew i korzeni, co stanowi zarówno wyzwanie, jak i atrakcję dla wędkarzy. Dno jest bardzo zróżnicowane, z przewagą mułu i osadów organicznych, ale także z twardszymi miejscami wokół zwalonych pni. Brzegi są trudne do pokonania, często bagniste i gęsto zarośnięte, co wymaga użycia brodzących butów i cierpliwości. Roślinność wodna jest obfita, z pasami trzcin i grążeli, które tworzą idealne kryjówki dla drapieżników. W starorzeczu dominują szczupaki, sumy, okonie, liny oraz karasie pospolite, które doskonale adaptują się do tego typu środowiska. Okresowe połączenie z Bugiem podczas wiosennych wylewów odgrywa kluczową rolę w odświeżaniu wody i wspieraniu populacji ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21482, 4.8, 1.9, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Silne', FALSE, FALSE, 'Szczupak,Sum,Okoń,Lin,Karaś pospolity', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21483, 'Starorzecze (Kuzawka)', 'starorzecze-kuzawka-kuzawka-21483', 'OXBOW', 51.7136549, 23.5340492, 'Lubelskie', 'Kuzawka', 'To niewielkie, ale głębokie starorzecze, położone w urokliwej scenerii, idealne dla poszukiwaczy dużych ryb. Dno jest głównie muliste, z głębokimi rynnami i dołkami, które stanowią schronienie dla większych okazów. Brzegi są w większości łatwo dostępne, choć miejscami porośnięte krzewami, co zapewnia naturalne stanowiska wędkarskie. Roślinność podwodna jest umiarkowana, z przewagą rdestnic i moczarki, tworzących pasy przybrzeżne. W starorzeczu dominują karpie, leszcze, płocie, liny oraz sandacze, które znajdują tu bogate zasoby pokarmowe. Brak stałego połączenia z rzeką sprawia, że w okresach suszy poziom wody może spadać, ale głębokość minimalizuje ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21483, 2.3, 2.5, 5.8, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Leszcz,Płoć,Lin,Sandacz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21484, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21484', 'OXBOW', 51.7074937, 23.5506515, 'Lubelskie', 'Hanna', 'To dzikie i trudno dostępne starorzecze, będące prawdziwą ostoją dla wielu gatunków ryb, położone w zacisznym zakątku doliny Bugu. Dno jest bardzo zróżnicowane, z dominacją mułu, ale także z twardszymi fragmentami i licznymi zatopionymi drzewami. Brzegi są mocno zarośnięte gęstą trzciną i krzewami, co sprawia, że dostęp do wody jest utrudniony i wymaga brodzenia. Roślinność wodna jest niezwykle obfita, tworząc gęste zarośla, które są idealnym schronieniem dla drapieżników i białorybu. W starorzeczu królują szczupaki, sumy, liny, karasie pospolite oraz węgorze, które osiągają tu imponujące rozmiary. Brak stałego połączenia z rzeką sprawia, że zbiornik jest wrażliwy na długotrwałe susze, ale jego głębokość zapewnia stabilność ekosystemu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21484, 5, 2.1, 4.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Szczupak,Sum,Lin,Karaś pospolity,Węgorz', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21485, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21485', 'OXBOW', 51.7083146, 23.5503148, 'Lubelskie', 'Hanna', 'To starorzecze charakteryzuje się płytką, mulistą wodą i jest typowym przykładem zbiornika o powolnym przepływie. Brzegi są w większości porośnięte gęstą trzciną i pałką wodną, co utrudnia dostęp do wody w wielu miejscach. Dno jest miękkie, pokryte grubą warstwą osadów organicznych, co sprzyja rozwojowi bogatej roślinności podwodnej, takiej jak rdestnica i moczarka kanadyjska. Jest to idealne środowisko dla gatunków preferujących płytkie, zarośnięte wody, takich jak lin czy karaś. Wędkowanie wymaga cierpliwości i umiejętności odnalezienia czystych fragmentów dna lub łowienia z pontonu. Ryzyko przyduchy występuje głównie w upalne lata, gdy poziom tlenu może drastycznie spadać, zwłaszcza w płytkich zatokach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21485, 3.2, 1.1, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21486, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21486', 'OXBOW', 51.7086179, 23.5491689, 'Lubelskie', 'Hanna', 'Ten odcinek starorzecza, choć bliski innym, wyróżnia się nieco większą głębokością w centralnej części, co pozwala na występowanie większych okazów ryb. Brzegi są częściowo dostępne, z kilkoma naturalnymi pomostami z twardego gruntu, jednak większość linii brzegowej to podmokłe tereny. Dno jest zróżnicowane, od mulistego po twardsze, piaszczysto-żwirowe fragmenty, zwłaszcza w miejscach dawnych zakrętów rzeki. Roślinność podwodna jest obfita, ale występują też otwarte lustra wody, idealne do spinningu. Występuje tu bogata populacja płoci i leszczy, a także drapieżników takich jak okoń i szczupak. Starorzecze to jest stosunkowo stabilne pod względem poziomu wody, rzadko wysycha, co sprzyja rozwojowi ekosystemu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21486, 4.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak,Karp', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21487, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21487', 'OXBOW', 51.708432, 23.5429165, 'Lubelskie', 'Hanna', 'Starorzecze to jest jednym z bardziej odizolowanych fragmentów kompleksu, charakteryzującym się brakiem bezpośredniego połączenia z rzeką, co czyni je ostoją dla ryb spokojnego żeru. Brzegi są w większości łatwo dostępne, z wyjątkiem kilku odcinków zarośniętych krzewami i wikliną. Dno jest głównie piaszczysto-muliste, z lokalnymi zagłębieniami, gdzie gromadzi się osad. Roślinność podwodna jest umiarkowana, co ułatwia wędkowanie z gruntu i spławikowe. Występują tu liczne karasie pospolite oraz liny, które doskonale czują się w spokojnych wodach. Brak silnych prądów i niewielkie wahania poziomu wody zapewniają stabilne warunki. Warto jednak pamiętać o możliwości wystąpienia przyduchy w przypadku długotrwałych upałów i niskiego poziomu tlenu, szczególnie w płytkich partiach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21487, 2.8, 1, 2.2, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć,Wzdręga', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21488, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21488', 'OXBOW', 51.7099688, 23.5461299, 'Lubelskie', 'Hanna', 'Ten fragment starorzecza jest stosunkowo szeroki i charakteryzuje się dobrze rozwiniętą strefą litoralu, co sprzyja występowaniu drapieżników. Brzegi są miejscami podmokłe, jednak liczne kępy drzew i krzewów dają schronienie wędkarzom. Dno jest nieregularne, z licznymi zatopionymi korzeniami i gałęziami, które stanowią doskonałe kryjówki dla ryb. Roślinność podwodna jest gęsta w płytszych partiach, ale w głębszych rejonach woda jest czysta. Jest to znane łowisko szczupaków i okoni, które polują wśród zarośli. Występują tu również duże leszcze i płocie. Wędkowanie wymaga ostrożności ze względu na zaczepy, ale potencjał na dużą rybę jest wysoki. Połączenie z rzeką jest sporadyczne, tylko przy bardzo wysokim stanie wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21488, 5.1, 1.8, 3.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21489, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21489', 'OXBOW', 51.7101929, 23.5450795, 'Lubelskie', 'Hanna', 'Starorzecze to jest stosunkowo płytkie i silnie zarośnięte, co czyni je idealnym siedliskiem dla gatunków ciepłolubnych i odpornych na niedobory tlenu. Brzegi są trudne do pokonania, porośnięte gęstą roślinnością szuwarową i bagnistym terenem. Dno jest w całości pokryte grubą warstwą mułu i rozkładającej się materii organicznej, co świadczy o zaawansowanym procesie sedymentacji. Roślinność podwodna, taka jak grążele i rzęsa, pokrywa znaczną część powierzchni wody. Dominują tu karasie srebrzyste i liny, które doskonale radzą sobie w takich warunkach. Wędkowanie jest wyzwaniem, często wymaga użycia długich tyczek lub pontonu. Ryzyko przyduchy jest wysokie, zwłaszcza latem, co może prowadzić do śnięcia ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21489, 2.5, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21490, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21490', 'OXBOW', 51.7101852, 23.5430279, 'Lubelskie', 'Hanna', 'Ten odcinek starorzecza charakteryzuje się długim, wąskim kształtem i umiarkowaną głębokością, co sprzyja rozwojowi zróżnicowanej fauny. Brzegi są miejscami dostępne, z twardszym podłożem, ale występują też odcinki zarośnięte drzewami i krzewami. Dno jest mieszane, od mulistego po piaszczyste, z pojedynczymi zatopionymi kłodami. Roślinność podwodna jest obecna, ale nie dominuje, co pozwala na różnorodne techniki wędkarskie. Jest to dobre miejsce na leszcze, płocie i okonie. Wiosną i jesienią można tu spotkać również szczupaki. Połączenie z rzeką jest rzadkie, co stabilizuje ekosystem. Zbiornik nie wysycha, ale wahania poziomu wody mogą wpływać na dostępność łowisk.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21490, 3.8, 1.3, 2.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21491, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21491', 'OXBOW', 51.7092453, 23.5440036, 'Lubelskie', 'Hanna', 'To starorzecze jest jednym z bardziej urokliwych miejsc, z częściowo zadrzewionymi brzegami, które oferują cień w upalne dni. Zbiornik jest stosunkowo płytki, ale ma kilka głębszych rynien, które stanowią ostoję dla ryb. Dno jest muliste, z licznymi miejscami porośniętymi liliami wodnymi i grążelami. Roślinność podwodna jest gęsta, tworząc idealne środowisko dla lina i karasia. Występują tu również wzdręgi i płocie, które żerują wśród roślinności. Dostęp do wody jest utrudniony przez gęste zarośla, ale w kilku miejscach są naturalne prześwity. Wędkowanie wymaga precyzji i umiejętności operowania zestawem w zarośniętym środowisku. Starorzecze to jest narażone na przyduchy w przypadku długotrwałego braku opadów i wysokich temperatur.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21491, 3, 1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21492, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21492', 'OXBOW', 51.7072857, 23.5405872, 'Lubelskie', 'Hanna', 'Ten fragment starorzecza wyróżnia się nieco twardszym dnem w porównaniu do innych, co jest pozostałością po dawnym korycie rzeki. Brzegi są częściowo dostępne, z piaszczystymi odcinkami, ale również z fragmentami porośniętymi trzciną. Głębokość jest umiarkowana, z kilkoma głębszymi dołkami, które są atrakcyjne dla większych ryb. Roślinność podwodna jest umiarkowana, co sprzyja różnorodnym metodom wędkowania. Jest to dobre miejsce na leszcze, płocie i okonie, a także na karpia, który znajduje tu obfitość naturalnego pokarmu. Połączenie z rzeką jest sporadyczne, co pomaga w utrzymaniu stabilnej populacji ryb. Wędkowanie jest tu stosunkowo komfortowe, z mniejszą ilością zaczepów. Ryzyko wyschnięcia jest minimalne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21492, 4.1, 1.6, 3.3, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Karp,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21493, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21493', 'OXBOW', 51.7026961, 23.5400902, 'Lubelskie', 'Hanna', 'To starorzecze jest jednym z najgłębszych w kompleksie, co pozwala na występowanie sumów i sandaczy, zwłaszcza gdy ma połączenie z rzeką. Brzegi są zróżnicowane, od łatwo dostępnych po mocno zarośnięte krzewami i drzewami. Dno jest twarde, żwirowo-piaszczyste w głębszych partiach, z mulistymi zatokami. Roślinność podwodna jest umiarkowana, z dominacją traw i rdestnic. Jest to doskonałe łowisko dla wędkarzy poszukujących większych drapieżników. Występują tu również duże płocie i leszcze. Połączenie z rzeką jest kluczowe dla migracji ryb, choć nie jest stałe. Wędkowanie z łodzi lub pontonu jest często najlepszym rozwiązaniem, aby dotrzeć do najciekawszych miejsc. Ryzyko przyduchy jest niskie ze względu na głębokość.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21493, 6, 2.2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Sandacz,Szczupak,Leszcz,Płoć', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21494, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21494', 'OXBOW', 51.7042647, 23.5404637, 'Lubelskie', 'Hanna', 'Starorzecze to jest stosunkowo małe i bardzo płytkie, co sprawia, że jest szczególnie wrażliwe na zmiany poziomu wody i temperatury. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, utrudniając dostęp. Dno jest całkowicie muliste, z grubą warstwą osadów, co sprzyja rozwojowi bogatej roślinności podwodnej i nawodnej. Jest to typowe siedlisko dla karasia pospolitego i wzdręgi, które doskonale adaptują się do trudnych warunków. Wędkowanie jest tu wyzwaniem, często wymaga brodzenia lub użycia pontonu. Ze względu na płytkość i obfitość materii organicznej, ryzyko przyduchy jest bardzo wysokie, a zbiornik może częściowo wysychać w czasie długotrwałej suszy. To miejsce jest cenną ostoją dla drobnych gatunków ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21494, 1.8, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21495, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21495', 'OXBOW', 51.7074339, 23.5385778, 'Lubelskie', 'Hanna', 'Ten odcinek starorzecza charakteryzuje się umiarkowaną głębokością i zróżnicowanym dnem, co stwarza dobre warunki dla wielu gatunków ryb. Brzegi są częściowo dostępne, z kilkoma naturalnymi stanowiskami wędkarskimi, ale również z obszarami zarośniętymi krzewami. Dno jest mieszane, od piaszczystego po muliste, z pojedynczymi zatopionymi korzeniami. Roślinność podwodna jest umiarkowana, z licznymi prześwitami. Jest to dobre miejsce na leszcze, płocie i okonie, a także na szczupaki, które polują wzdłuż brzegów. Połączenie z rzeką jest sporadyczne, co wpływa na migrację ryb. Wędkowanie jest tu stosunkowo komfortowe, z mniejszą ilością zaczepów. Zbiornik nie wysycha, a ryzyko przyduchy jest niskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21495, 3.9, 1.4, 2.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21496, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21496', 'OXBOW', 51.709969, 23.5367777, 'Lubelskie', 'Hanna', 'To starorzecze jest jednym z bardziej odizolowanych, z minimalnym wpływem rzeki, co sprzyja rozwojowi stabilnej populacji ryb. Brzegi są w większości trudne do pokonania, z gęstymi zaroślami i podmokłym terenem. Dno jest muliste, z grubą warstwą osadów organicznych, co jest typowe dla starzejących się starorzeczy. Roślinność podwodna jest silnie rozwinięta, z przewagą grążeli i rdestnic. Dominują tu liny i karasie pospolite, które doskonale radzą sobie w takim środowisku. Wędkowanie jest wyzwaniem, często wymaga brodzenia lub użycia pontonu, aby dotrzeć do czystych miejsc. Ryzyko przyduchy jest wysokie w upalne lata, ze względu na płytkość i dużą ilość materii organicznej. Zbiornik rzadko wysycha całkowicie, ale poziom wody może znacznie spadać.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21496, 2.7, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21497, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21497', 'OXBOW', 51.7097224, 23.5398488, 'Lubelskie', 'Hanna', 'Ten odcinek starorzecza charakteryzuje się stosunkowo czystym dnem i umiarkowaną roślinnością, co czyni go atrakcyjnym dla wędkarzy preferujących różne metody. Brzegi są w większości łatwo dostępne, z twardym podłożem i kilkoma miejscami do siedzenia. Głębokość jest zróżnicowana, z głębszymi rynnami w środkowej części zbiornika. Roślinność podwodna jest obecna, ale nie utrudnia wędkowania, tworząc naturalne kryjówki dla ryb. Jest to dobre miejsce na płocie, leszcze i okonie. Występują tu również karpie, które znajdują obfitość pokarmu. Połączenie z rzeką jest sporadyczne, co stabilizuje populacje ryb. Wędkowanie jest tu komfortowe, a ryzyko zaczepów jest niskie. Zbiornik nie wysycha, a ryzyko przyduchy jest minimalne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21497, 4.3, 1.7, 3.5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Płoć,Leszcz,Karp,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21498, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21498', 'OXBOW', 51.7101001, 23.5407694, 'Lubelskie', 'Hanna', 'Starorzecze to jest jednym z najbardziej zarośniętych i mulistych fragmentów, co sprawia, że jest to środowisko typowe dla starzejących się zbiorników. Brzegi są praktycznie niedostępne, porośnięte gęstą trzciną, krzewami i podmokłym terenem. Dno jest całkowicie pokryte grubą warstwą mułu i rozkładającej się materii organicznej. Roślinność podwodna i nawodna, w tym grążele i rzęsa, pokrywa znaczną część powierzchni wody. Dominują tu karasie srebrzyste i liny, które są odporne na niedobory tlenu i preferują takie środowiska. Wędkowanie jest tu niezwykle trudne i wymaga specjalistycznego sprzętu lub łowienia z pontonu. Ryzyko przyduchy jest bardzo wysokie, szczególnie latem, co może prowadzić do śnięcia ryb. Zbiornik jest płytki i w czasie suszy może częściowo wysychać.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21498, 2.2, 0.9, 1.7, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21499, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21499', 'OXBOW', 51.7107513, 23.5407292, 'Lubelskie', 'Hanna', 'Ten fragment starorzecza charakteryzuje się umiarkowaną głębokością i zróżnicowanym dnem, co sprzyja występowaniu szerokiego spektrum gatunków ryb. Brzegi są częściowo dostępne, z twardszymi odcinkami, ale również z fragmentami zarośniętymi krzewami i wikliną. Dno jest mieszane, od piaszczystego po muliste, z pojedynczymi zatopionymi gałęziami. Roślinność podwodna jest obecna, ale nie dominuje, co pozwala na różnorodne techniki wędkarskie. Jest to dobre miejsce na leszcze, płocie, okonie, a także sporadycznie szczupaki. Połączenie z rzeką jest sporadyczne, co stabilizuje ekosystem. Zbiornik nie wysycha, a wahania poziomu wody są umiarkowane. Ryzyko przyduchy jest niskie, co czyni go atrakcyjnym łowiskiem przez większość sezonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21499, 4, 1.5, 3.1, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21500, 'Starorzecze koło Hanny A', 'starorzecze-kolo-hanny-a-hanna-21500', 'OXBOW', 51.7119648, 23.5352777, 'Lubelskie', 'Hanna', 'To starorzecze, położone w malowniczej dolinie Bugu, charakteryzuje się podłużnym kształtem i umiarkowaną wielkością. Dno jest muliste, choć w niektórych miejscach można natrafić na twardsze, piaszczyste fragmenty, co sprzyja różnorodności gatunkowej. Brzegi są częściowo dostępne, jednak w wielu miejscach porastają je gęste zarośla krzewów i trzcin, utrudniając swobodne poruszanie się. W zbiorniku dominuje roślinność podwodna, tworząca idealne kryjówki dla ryb, a także liczne grążele i lilie wodne. Wśród dominujących gatunków ryb znajdziemy liny, karasie pospolite, płocie oraz szczupaki, które aktywnie polują w zaroślach. Wędkarze powinni być przygotowani na trudny dostęp do niektórych stanowisk i konieczność brodzenia w wodzie, co wymaga odpowiedniego sprzętu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21500, 4.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21501, 'Starorzecze koło Hanny B', 'starorzecze-kolo-hanny-b-hanna-21501', 'OXBOW', 51.7126121, 23.5370218, 'Lubelskie', 'Hanna', 'To niewielkie starorzecze jest klasycznym przykładem zbiornika o silnym stopniu naturalnego zarastania i zamulania. Jego dno jest w przeważającej części muliste i miękkie, co utrudnia wędkowanie z gruntu, ale jednocześnie tworzy bogate środowisko dla bezkręgowców. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest bardzo ograniczony i wymaga użycia brodzaków. Roślinność podwodna jest wyjątkowo bujna, tworząc podwodne łąki, które są ostoją dla wielu gatunków. W zbiorniku królują karasie pospolite, wzdręgi oraz liny, doskonale przystosowane do życia w płytkich i zarośniętych wodach. Ryzyko deficytu tlenowego jest wysokie, szczególnie w upalne lata i pod pokrywą lodu. Wędkarstwo tutaj to wyzwanie, ale nagrodą mogą być piękne okazy ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21501, 3.2, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21502, 'Starorzecze koło Hanny C', 'starorzecze-kolo-hanny-c-hanna-21502', 'OXBOW', 51.7118349, 23.5406572, 'Lubelskie', 'Hanna', 'Starorzecze to wyróżnia się stabilnym, choć niewielkim połączeniem z rzeką, co zapewnia stałą wymianę wody i lepsze warunki środowiskowe. Dno jest zróżnicowane, z przewagą piasku i żwiru w pobliżu połączenia z rzeką, a muliste w głębszych partiach. Brzegi są w większości dobrze dostępne, co ułatwia wędkowanie z brzegu, choć miejscami występują kępy trzcin. Roślinność wodna jest umiarkowana, skupiając się głównie na płytszych partiach, co pozwala na swobodne prowadzenie przynęt. W zbiorniku dominują drapieżniki takie jak szczupak i okoń, a także liczne leszcze i płocie, które korzystają z dostatku pokarmu. Brak wysokiego ryzyka deficytu tlenowego oraz stabilne warunki sprawiają, że jest to atrakcyjne łowisko przez cały sezon. Wędkarze znajdą tu wiele dogodnych miejsc do zasiadki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21502, 6, 1.8, 3.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21503, 'Starorzecze koło Hanny D', 'starorzecze-kolo-hanny-d-hanna-21503', 'OXBOW', 51.7117695, 23.5399454, 'Lubelskie', 'Hanna', 'To płytkie i niewielkie starorzecze jest typowym zbiornikiem okresowo wysychającym, co znacząco wpływa na jego biologię. Dno jest silnie zamulone, a w okresach suszy często twardnieje i pęka, co świadczy o jego niestabilnym charakterze. Brzegi są trudne do pokonania, często bagniste i mocno zarośnięte, co wymaga dużej ostrożności i odpowiedniego obuwia. Roślinność podwodna jest bardzo gęsta, tworząc istne labirynty dla ryb, ale utrudniając wędkowanie. W zbiorniku przeważają ryby odporne na trudne warunki, takie jak karasie srebrzyste, wzdręgi i płocie, które potrafią przetrwać w płytkiej wodzie. Wiosną, po roztopach, łowisko tętni życiem, oferując szansę na ciekawe połowy. Należy pamiętać o wysokim ryzyku deficytu tlenowego w lecie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21503, 2.8, 1, 2, 'Brak', 'Średnie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21504, 'Starorzecze koło Hanny E', 'starorzecze-kolo-hanny-e-hanna-21504', 'OXBOW', 51.712025, 23.5396437, 'Lubelskie', 'Hanna', 'To starorzecze charakteryzuje się umiarkowaną wielkością i okresowym połączeniem z rzeką podczas wysokiej wody, co zasila je w świeżą wodę i nowe ryby. Dno jest zróżnicowane, od twardszych, piaszczystych fragmentów po bardziej muliste w głębszych zagłębieniach, co sprzyja różnym gatunkom. Brzegi są dostępne z jednej strony, oferując dogodne miejsca do wędkowania, podczas gdy druga strona jest bardziej zarośnięta. Roślinność wodna jest umiarkowana, z przewagą trzcin i roślinności wynurzonej wzdłuż brzegów. W zbiorniku można liczyć na liny, szczupaki, leszcze i okonie, które znajdują tu dobre warunki do żerowania i ukrycia. Starorzecze to jest stosunkowo stabilne pod względem tlenowym, co czyni je atrakcyjnym łowiskiem przez większość roku. Wędkarze cenią sobie to miejsce za różnorodność i potencjał na ładne ryby.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21504, 5.1, 1.6, 3.2, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Lin,Szczupak,Leszcz,Okoń', 'Dobry z jednej strony, druga zarośnięta', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21505, 'Starorzecze koło Hanny F', 'starorzecze-kolo-hanny-f-hanna-21505', 'OXBOW', 51.7128354, 23.5408305, 'Lubelskie', 'Hanna', 'To starorzecze jest całkowicie odcięte od głównego nurtu rzeki, co sprzyja jego powolnemu, naturalnemu procesowi starzenia. Dno jest w dużej mierze pokryte grubą warstwą mułu, co świadczy o zaawansowanym stadium zamulania zbiornika. Brzegi są mocno zarośnięte trzciną i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest bardzo trudny i wymaga użycia brodzaków lub łódki. Roślinność podwodna jest bujna, tworząc podwodne łąki i liczne zaczepy, które są schronieniem dla ryb. Wśród dominujących gatunków ryb znajdziemy karasie pospolite, liny oraz wzdręgi, doskonale przystosowane do życia w płytkich i zarośniętych wodach. W zbiorniku występuje również dużo zatopionych drzew i gałęzi, co stanowi dodatkowe wyzwanie dla wędkarzy. Jest to łowisko dla cierpliwych, poszukujących dzikich i nieskażonych miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21505, 3.8, 1.3, 2.8, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21506, 'Starorzecze koło Hanny G', 'starorzecze-kolo-hanny-g-hanna-21506', 'OXBOW', 51.7130016, 23.540274, 'Lubelskie', 'Hanna', 'To jedno z większych i głębszych starorzeczy w okolicy, utrzymujące stałe połączenie z rzeką, co gwarantuje doskonałe warunki wodne. Dno jest w dużej mierze twarde, piaszczysto-żwirowe, z niewielkimi obszarami mulistymi w najgłębszych partiach. Brzegi są dobrze dostępne z obu stron, co pozwala na komfortowe wędkowanie z brzegu, bez konieczności brodzenia. Roślinność wodna jest słaba, skupiając się głównie na płytszych obrzeżach, co sprzyja swobodnemu prowadzeniu przynęt. W zbiorniku występują liczne drapieżniki, takie jak szczupak, sandacz i okoń, a także duże populacje leszczy i płoci. Stały przepływ wody minimalizuje ryzyko deficytu tlenowego, czyniąc to łowisko atrakcyjnym przez cały rok. To idealne miejsce dla wędkarzy ceniących sobie komfort i różnorodność gatunkową.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21506, 7.2, 2, 4.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21507, 'Starorzecze koło Hanny H', 'starorzecze-kolo-hanny-h-hanna-21507', 'OXBOW', 51.713752, 23.5413066, 'Lubelskie', 'Hanna', 'To najmniejsze i najpłytsze starorzecze w tej grupie, charakteryzujące się silnym zamuleniem i tendencją do wysychania w okresach długotrwałej suszy. Dno jest niemal w całości pokryte grubą warstwą miękkiego mułu, co czyni je trudnym do wędkowania z gruntu. Brzegi są trudne do pokonania, często bagniste i mocno zarośnięte, wymagające użycia brodzaków lub specjalistycznego sprzętu. Roślinność podwodna jest niezwykle gęsta, tworząc podwodne labirynty, które są ostoją dla drobnych ryb. W zbiorniku dominują karasie srebrzyste i wzdręgi, doskonale przystosowane do życia w tak ekstremalnych warunkach. Łowisko to jest bardzo wrażliwe na zmiany poziomu wody i temperatury, co przekłada się na wysokie ryzyko deficytu tlenowego. Wędkowanie tutaj to prawdziwe wyzwanie, ale może przynieść satysfakcję w postaci ryb odpornych na trudne warunki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21507, 2.1, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21508, 'Starorzecze koło Hanny I', 'starorzecze-kolo-hanny-i-hanna-21508', 'OXBOW', 51.7139023, 23.5418893, 'Lubelskie', 'Hanna', 'To starorzecze o umiarkowanej wielkości, które utrzymuje okresowe połączenie z rzeką podczas wiosennych roztopów i wysokich stanów wody, co wzbogaca jego faunę. Dno jest zróżnicowane, z przewagą mulistych osadów, ale z twardszymi fragmentami w pobliżu brzegów, gdzie woda jest płytsza. Brzegi są dostępne z jednej strony, oferując kilka dogodnych stanowisk wędkarskich, natomiast druga strona jest bardziej niedostępna z powodu zarośli. Roślinność wodna jest umiarkowana, z licznymi kępami trzcin i grążeli, które stanowią doskonałe kryjówki dla ryb. W zbiorniku można liczyć na liny, karasie pospolite, szczupaki i okonie, które doskonale odnajdują się w tym środowisku. Warto zwrócić uwagę na pojedyncze korzenie i gałęzie na dnie, które mogą stanowić zaczepy. Łowisko to jest cenione za potencjał na ładne okazy ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21508, 4, 1.4, 2.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Dobry z jednej strony', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21509, 'Starorzecze koło Hanny J', 'starorzecze-kolo-hanny-j-hanna-21509', 'OXBOW', 51.7135959, 23.5433806, 'Lubelskie', 'Hanna', 'To stosunkowo duże starorzecze jest całkowicie odizolowane od głównego nurtu rzeki, co sprzyja rozwojowi stabilnego ekosystemu. Dno jest w przeważającej części czyste, z niewielkimi obszarami mulistymi w głębszych partiach, co ułatwia wędkowanie z gruntu. Brzegi są dobrze dostępne z obu stron, oferując liczne, wygodne stanowiska dla wędkarzy, bez konieczności brodzenia. Roślinność wodna jest umiarkowana, z przewagą trzcin i roślinności wynurzonej wzdłuż brzegów, zapewniając rybom schronienie. W zbiorniku dominują leszcze, płocie, okonie, a także liczne karpie, które znajdują tu sprzyjające warunki do wzrostu. Brak bezpośredniego połączenia z rzeką sprawia, że woda jest spokojna i bogata w pokarm. Jest to łowisko idealne dla rodzinnych wypadów i wędkarzy ceniących sobie spokój i komfort.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21509, 5.5, 1.7, 3.3, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21510, 'Starorzecze koło Hanny K', 'starorzecze-kolo-hanny-k-hanna-21510', 'OXBOW', 51.7137812, 23.5440442, 'Lubelskie', 'Hanna', 'To starorzecze, choć niewielkie, jest interesującym łowiskiem, które łączy się z rzeką podczas wysokich stanów wody, co odświeża jego biologię. Dno jest silnie zamulone, co jest typowe dla starorzeczy o ograniczonym przepływie, i wymaga ostrożności podczas brodzenia. Brzegi są trudne do pokonania, często bagniste i mocno zarośnięte, co wymaga użycia brodzaków lub poszukiwania nielicznych, dostępnych miejsc. Roślinność podwodna jest bardzo gęsta, tworząc podwodne łąki i liczne zaczepy, które są schronieniem dla ryb. W zbiorniku dominują liny, karasie pospolite oraz wzdręgi, doskonale przystosowane do życia w tak trudnych warunkach. Występuje tu również sporo zatopionych drzew, co jest wyzwaniem, ale i atrakcją dla wędkarzy. Jest to miejsce dla tych, którzy cenią sobie dzikość i nie boją się trudności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21510, 3, 1.1, 2.3, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21511, 'Starorzecze koło Hanny L', 'starorzecze-kolo-hanny-l-hanna-21511', 'OXBOW', 51.7139882, 23.543101, 'Lubelskie', 'Hanna', 'To rozległe starorzecze o stałym połączeniu z rzeką, co zapewnia doskonałe warunki tlenowe i bogactwo gatunkowe. Dno jest zróżnicowane, z twardszymi, piaszczysto-żwirowymi fragmentami w pobliżu nurtu i bardziej mulistymi w głębszych zakamarkach. Brzegi są w większości dobrze dostępne, co umożliwia komfortowe wędkowanie z brzegu lub z pomostów. Roślinność wodna jest słaba, co pozwala na swobodne operowanie różnymi technikami wędkarskimi. W zbiorniku można spotkać wiele gatunków ryb, w tym duże szczupaki, sumy, leszcze, płocie i okonie, które korzystają z dostatku pokarmu i przestrzeni. Brak ryzyka deficytu tlenowego oraz stały dopływ świeżej wody sprawiają, że jest to łowisko atrakcyjne przez cały rok. To doskonałe miejsce dla wędkarzy szukających dużych ryb i różnorodnych wyzwań.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21511, 6.8, 2.2, 4.8, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sum,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21512, 'Starorzecze koło Kuzawki A', 'starorzecze-kolo-kuzawki-a-hanna-21512', 'OXBOW', 51.7143679, 23.5430309, 'Lubelskie', 'Hanna', 'To starorzecze, położone w pobliżu miejscowości Kuzawka, jest zbiornikiem odciętym od głównego nurtu rzeki, co sprzyja rozwojowi specyficznej fauny. Dno jest średnio zamulone, z miejscami twardszymi, co oferuje różnorodne siedliska dla ryb i bezkręgowców. Brzegi są mocno zarośnięte trzciną, co sprawia, że dostęp do wody jest utrudniony i wymaga użycia brodzaków lub odnalezienia nielicznych, otwartych stanowisk. Roślinność podwodna jest gęsta, tworząc podwodne łąki, które są doskonałymi kryjówkami dla ryb. W zbiorniku dominują liny, karasie pospolite oraz płocie, które doskonale radzą sobie w zarośniętych i spokojnych wodach. Wędkarze powinni być przygotowani na konieczność przebijania się przez zarośla i na potencjalne zaczepy. Mimo trudności, łowisko oferuje szansę na piękne okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21512, 4.2, 1.4, 2.7, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21513, 'Starorzecze koło Kuzawki B', 'starorzecze-kolo-kuzawki-b-hanna-21513', 'OXBOW', 51.7146787, 23.545627, 'Lubelskie', 'Hanna', 'To bardzo płytkie i niewielkie starorzecze w okolicach Kuzawki, charakteryzujące się silnym zamuleniem i tendencją do wysychania w okresach suszy. Dno jest niemal w całości pokryte grubą warstwą miękkiego mułu, co świadczy o zaawansowanym stadium starzenia się zbiornika. Brzegi są trudne do pokonania, często bagniste i mocno zarośnięte, wymagające użycia brodzaków i dużej ostrożności. Roślinność podwodna jest niezwykle gęsta, tworząc podwodne labirynty, które są ostoją dla drobnych ryb. W zbiorniku dominują karasie srebrzyste i wzdręgi, gatunki odporne na trudne warunki i wysokie temperatury wody. Łowisko to jest bardzo wrażliwe na zmiany poziomu wody i temperatury, co przekłada się na wysokie ryzyko deficytu tlenowego. Wędkowanie tutaj to prawdziwe wyzwanie, ale może przynieść satysfakcję w postaci ryb przystosowanych do trudnych warunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21513, 2.6, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21514, 'Starorzecze koło Kuzawki C', 'starorzecze-kolo-kuzawki-c-hanna-21514', 'OXBOW', 51.7154742, 23.5422008, 'Lubelskie', 'Hanna', 'To średniej wielkości starorzecze w rejonie Kuzawki, które okresowo łączy się z rzeką podczas wysokich stanów wody, co wzbogaca jego ekosystem. Dno jest zróżnicowane, z przewagą twardszych fragmentów w pobliżu dawnego nurtu i bardziej mulistymi w głębszych, spokojniejszych partiach. Brzegi są dostępne z jednej strony, oferując dogodne miejsca do wędkowania, podczas gdy druga strona jest bardziej zarośnięta i trudniejsza do pokonania. Roślinność wodna jest umiarkowana, z licznymi kępami trzcin i roślinności wynurzonej, stanowiącej doskonałe kryjówki dla ryb. W zbiorniku można liczyć na szczupaki, liny, leszcze, okonie oraz karpie, które znajdują tu dobre warunki do wzrostu i żerowania. Wędkarze cenią sobie to łowisko za jego potencjał i możliwość złowienia różnorodnych gatunków. Jest to miejsce, które oferuje ciekawe wędkarskie wyzwania przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21514, 5.8, 1.9, 3.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Okoń,Karp', 'Dobry z jednej strony', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21515, 'Starorzecze Kuzawka 1', 'starorzecze-kuzawka-1-kuzawka-21515', 'OXBOW', 51.7199034, 23.5405274, 'Województwo Lubelskie', 'Kuzawka', 'To starorzecze charakteryzuje się typowym dla tego typu zbiorników, mulistym dnem, które w wielu miejscach pokryte jest gęstą roślinnością podwodną. Brzegi są częściowo dostępne, jednak w dużej mierze porośnięte trzciną i inną roślinnością szuwarową, co utrudnia swobodne poruszanie się. W zbiorniku dominuje populacja lina, karasia pospolitego oraz płoci, a w głębszych partiach można spotkać dorodne szczupaki. Wędkarstwo gruntowe oraz spławikowe przynosi najlepsze efekty, zwłaszcza wczesnym rankiem i wieczorem. Należy przygotować się na liczne zaczepy spowodowane podwodną roślinnością i zatopionymi gałęziami, co wymaga stosowania mocniejszego sprzętu. W okresie letnich upałów może występować ryzyko przyduchy, dlatego warto monitorować warunki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21515, 3.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Trudny, miejscami zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21516, 'Starorzecze Kuzawka 2', 'starorzecze-kuzawka-2-kuzawka-21516', 'OXBOW', 51.7169865, 23.5409385, 'Województwo Lubelskie', 'Kuzawka', 'Starorzecze to jest typowym zbiornikiem o charakterze starorzecza, z dnem bogatym w osady organiczne i miejscowe wypłycenia. Brzegi są stabilne, choć w niektórych rejonach mogą być podmokłe, co wymaga ostrożności. Akwen jest bardzo atrakcyjny dla wędkarzy poszukujących leszczy, płoci i karpi, które obficie występują w jego wodach. Miejsca z zatopionymi drzewami i krzewami stanowią doskonałe kryjówki dla okoni i sumów. Wymaga to precyzyjnego zarzucania przynęty, aby uniknąć zaczepów, których jest sporo w strefie przybrzeżnej. Latem, przy niskim stanie wody, można zaobserwować zwiększone zakwity glonów, co wpływa na aktywność ryb. Wędkowanie z pontonu może ułatwić dostęp do trudno dostępnych miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21516, 4.1, 1.8, 4.5, 'Brak', 'Wysokie', 'Umiarkowane', TRUE, FALSE, 'Leszcz,Płoć,Karp,Okoń,Sum', 'Dobry w wyznaczonych miejscach, miejscami podmokły', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21517, 'Starorzecze Kuzawka 3', 'starorzecze-kuzawka-3-kuzawka-21517', 'OXBOW', 51.7183292, 23.5336804, 'Województwo Lubelskie', 'Kuzawka', 'To starorzecze, położone w malowniczej okolicy, charakteryzuje się różnorodnym dnem, od piaszczystych płycizn po głębokie, muliste rynny. Brzegi są stosunkowo łatwo dostępne, choć miejscami występują kępy trzcin i krzewów, które zapewniają schronienie rybom. W wodach tego zbiornika licznie występują wzdręgi, płocie oraz karasie srebrzyste, a także drapieżne szczupaki, szczególnie aktywne wczesną wiosną. Wędkarstwo spinningowe i spławikowe jest tutaj bardzo popularne. Należy zwrócić uwagę na zmienną głębokość, która wymaga elastycznego podejścia do technik łowienia. Zbiornik jest stosunkowo czysty, co sprzyja rozwojowi populacji ryb. W okresach suszy poziom wody może nieco opaść, ale rzadko dochodzi do całkowitego wyschnięcia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21517, 2.8, 1.3, 3.2, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Wzdręga,Płoć,Karaś srebrzysty,Szczupak', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21518, 'Starorzecze Kuzawka 4', 'starorzecze-kuzawka-4-kuzawka-21518', 'OXBOW', 51.719004, 23.5339151, 'Województwo Lubelskie', 'Kuzawka', 'Starorzecze to, o wydłużonym kształcie, posiada dno w dużej mierze pokryte grubą warstwą mułu, co sprzyja rozwojowi bujnej roślinności podwodnej. Brzegi są miejscami bardzo zarośnięte, szczególnie od strony lasu, co utrudnia swobodny dostęp do wody. Jest to idealne łowisko dla miłośników lina i karasia pospolitego, które osiągają tu imponujące rozmiary. W zbiorniku występują również liczne okonie, czające się wśród podwodnych zarośli. Wędkarstwo spławikowe i gruntowe z użyciem naturalnych przynęt jest najbardziej efektywne. Warto przygotować się na walkę z gęstą roślinnością, która może utrudniać hol ryb. Ryzyko przyduchy jest realne w upalne lata, co należy brać pod uwagę planując wędkowanie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21518, 3.5, 1.6, 4, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Okoń,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21519, 'Starorzecze Kuzawka 5', 'starorzecze-kuzawka-5-kuzawka-21519', 'OXBOW', 51.7207297, 23.5345951, 'Województwo Lubelskie', 'Kuzawka', 'To starorzecze wyróżnia się głębszymi partiami i bardziej zróżnicowanym dnem, gdzie obok mułu występują twardsze, piaszczyste fragmenty. Brzegi są stabilne i stosunkowo łatwo dostępne, z nielicznymi kępami trzcin. W zbiorniku dominują leszcze, płocie i karpie, a także dorodne szczupaki, które preferują głębsze partie. Wędkarstwo gruntowe i feederowe jest szczególnie skuteczne, zwłaszcza w poszukiwaniu większych egzemplarzy. Należy zwrócić uwagę na prądy wodne, które mogą pojawiać się podczas wysokiego stanu rzeki, z którą starorzecze ma okresowe połączenie. Zbiornik jest regularnie zarybiany, co sprzyja obfitości ryb. Jest to łowisko o dużym potencjale, z mniejszą presją wędkarską niż inne pobliskie akweny.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21519, 5, 2.2, 5.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21520, 'Starorzecze Zakrzówek Szlachecki', 'starorzecze-zakrzowek-szlachecki-zakrzowek-szlachecki-21520', 'OXBOW', 51.040584, 19.2168299, 'Województwo Łódzkie', 'Zakrzówek Szlachecki', 'Starorzecze w Zakrzówku Szlacheckim to urokliwy zbiornik o zróżnicowanej głębokości, z przewagą mulistego dna, ale z twardszymi fragmentami w centralnej części. Brzegi są dość strome i miejscami zarośnięte, co wymaga ostrożności i wyboru odpowiedniego stanowiska. W wodach tego starorzecza królują liny, karasie pospolite oraz leszcze, a także drapieżne okonie i szczupaki, które aktywnie żerują w strefie przybrzeżnej. Wędkarstwo spławikowe i gruntowe jest tutaj bardzo efektywne, zwłaszcza przy użyciu naturalnych przynęt. Należy uważać na liczne zaczepy w postaci zatopionych gałęzi i podwodnej roślinności. Zbiornik jest stosunkowo stabilny pod względem poziomu wody, rzadko wysycha, jednak w upalne lata może wystąpić ryzyko niedoboru tlenu. Jest to doskonałe miejsce dla wędkarzy ceniących spokój i kontakt z naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21520, 6.5, 2, 6, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Leszcz,Okoń,Szczupak', 'Trudny, strome brzegi, miejscami zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21521, 'Starorzecze Sławatycze-Kolonia 1', 'starorzecze-slawatycze-kolonia-1-slawatycze-kolonia-21521', 'OXBOW', 51.760615, 23.5334236, 'Województwo Lubelskie', 'Sławatycze-Kolonia', 'To starorzecze charakteryzuje się płytkim, mulistym dnem, obficie porośniętym roślinnością wodną, co tworzy idealne warunki dla ryb spokojnego żeru. Brzegi są w większości bagniste i mocno zarośnięte trzciną, co sprawia, że dostęp do wody jest utrudniony i wymaga użycia brodzących. W zbiorniku dominują liny, karasie pospolite i wzdręgi, a także mniejsze okonie. Wędkarstwo spławikowe jest tutaj najbardziej efektywne, szczególnie w miejscach o niewielkich prześwitach w roślinności. Ze względu na płytkość i obfitość materii organicznej, ryzyko przyduchy w okresie letnim jest wysokie. Warto przygotować się na liczne zaczepy o podwodną roślinność. Jest to idealne miejsce dla wędkarzy ceniących wyzwania i poszukujących medalowych linów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21521, 2.1, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Trudny, bagnisty, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21522, 'Starorzecze Sławatycze-Kolonia 2', 'starorzecze-slawatycze-kolonia-2-slawatycze-kolonia-21522', 'OXBOW', 51.7600714, 23.5353857, 'Województwo Lubelskie', 'Sławatycze-Kolonia', 'Starorzecze to jest nieco głębsze niż sąsiednie, z dnem częściowo mulistym, a częściowo piaszczysto-żwirowym, co sprzyja różnorodności gatunkowej ryb. Brzegi są umiarkowanie dostępne, z pojedynczymi kępami trzcin i drzewami dającymi cień. W zbiorniku licznie występują płocie, leszcze i karpie, a także drapieżne szczupaki i sumy, które znajdują schronienie w głębszych partiach. Wędkarstwo gruntowe i spinningowe jest tutaj bardzo popularne i efektywne. Należy zwrócić uwagę na zatopione drzewa i konary, które stanowią doskonałe kryjówki dla ryb, ale jednocześnie są potencjalnymi zaczepami. Połączenie z rzeką podczas wysokiej wody sprzyja wymianie genetycznej i uzupełnianiu populacji ryb. Jest to atrakcyjne łowisko dla wędkarzy poszukujących zarówno ryb spokojnego żeru, jak i drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21522, 4.5, 1.9, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Karp,Szczupak,Sum', 'Umiarkowany, z pojedynczymi zaroślami', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21523, 'Starorzecze Sławatycze-Kolonia 3', 'starorzecze-slawatycze-kolonia-3-slawatycze-kolonia-21523', 'OXBOW', 51.7509233, 23.5409043, 'Województwo Lubelskie', 'Sławatycze-Kolonia', 'To starorzecze jest stosunkowo niewielkie, o jednolitym, mulistym dnie i gęsto zarośniętych brzegach. Roślinność wodna jest bardzo obfita, tworząc liczne tarliska i kryjówki dla ryb. Dominują tu karasie pospolite, wzdręgi i liny, które doskonale czują się w takim środowisku. Wędkowanie wymaga precyzji i cierpliwości, często z wykorzystaniem długich wędek spławikowych do dotarcia do wolnych od zarośli miejsc. Ze względu na dużą ilość materii organicznej i niewielką głębokość, ryzyko przyduchy jest bardzo wysokie, szczególnie w upalne, bezwietrzne dni. Dostęp do wody jest mocno utrudniony, co sprawia, że łowisko jest mniej oblegane przez wędkarzy. Jest to raj dla miłośników natury i spokojnego wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21523, 1.5, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Bardzo trudny, gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21524, 'Starorzecze Sławatycze-Kolonia 4', 'starorzecze-slawatycze-kolonia-4-slawatycze-kolonia-21524', 'OXBOW', 51.75138, 23.5420697, 'Województwo Lubelskie', 'Sławatycze-Kolonia', 'Starorzecze to, o wydłużonym kształcie, charakteryzuje się dnem częściowo piaszczystym, częściowo mulistym, z wyraźnymi spadkami głębokości. Brzegi są stosunkowo łatwo dostępne, z nielicznymi kępami trzcin i drzewami liściastymi. W wodach tego zbiornika licznie występują płocie, leszcze i okonie, a także dorodne szczupaki, które preferują rejony z zatopionymi gałęziami. Wędkarstwo spinningowe, a także gruntowe z użyciem koszyczka zanętowego, przynosi tutaj dobre rezultaty. Połączenie z rzeką podczas wysokiej wody zapewnia regularne zasilanie w wodę i ryby. Należy uważać na zmienne warunki pogodowe i nagłe zmiany poziomu wody po intensywnych opadach. Jest to łowisko o dużym potencjale, z różnorodnymi stanowiskami dla wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21524, 3.8, 1.7, 4.2, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21525, 'Starorzecze Sławatycze-Kolonia 5', 'starorzecze-slawatycze-kolonia-5-slawatycze-kolonia-21525', 'OXBOW', 51.7520716, 23.5426591, 'Województwo Lubelskie', 'Sławatycze-Kolonia', 'To starorzecze charakteryzuje się bardziej otwartymi przestrzeniami wodnymi i głębszymi partiami, z dnem mulistym, ale z twardszymi fragmentami w środkowej części. Brzegi są umiarkowanie dostępne, z pasami trzcin i krzewów. W zbiorniku dominują leszcze, karpie i płocie, a także sandacze i sumy, które znajdują schronienie w głębszych dołkach. Wędkarstwo gruntowe i spinningowe jest tutaj bardzo efektywne, zwłaszcza w poszukiwaniu większych egzemplarzy. Należy zwrócić uwagę na zmienną głębokość i podwodne przeszkody, takie jak zatopione pnie. Zbiornik jest regularnie zarybiany, co sprzyja obfitości ryb. W okresach suszy poziom wody może nieco opaść, ale rzadko dochodzi do całkowitego wyschnięcia. Jest to atrakcyjne łowisko dla wędkarzy ceniących różnorodność gatunkową.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21525, 5.2, 2.1, 5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Płoć,Sandacz,Sum', 'Umiarkowany, z pasami trzcin', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21526, 'Starorzecze Sławatycze 1', 'starorzecze-slawatycze-1-slawatycze-21526', 'OXBOW', 51.7516531, 23.5434879, 'Województwo Lubelskie', 'Sławatycze', 'Starorzecze to jest jednym z większych w okolicy Sławatycz, charakteryzującym się zróżnicowanym dnem – od piaszczystych blatów po głębokie, muliste rynny. Brzegi są w większości łatwo dostępne, z miejscowymi zaroślami, które zapewniają dobre kryjówki dla ryb. W wodach tego starorzecza licznie występują leszcze, płocie, karpie, a także drapieżne szczupaki i okonie, które aktywnie żerują w strefie przybrzeżnej. Wędkarstwo gruntowe, spławikowe i spinningowe przynosi tutaj bardzo dobre rezultaty. Należy zwrócić uwagę na zmienną głębokość, która wymaga elastycznego podejścia do technik łowienia. Zbiornik jest stosunkowo czysty, co sprzyja rozwojowi populacji ryb. W okresach suszy poziom wody może nieco opaść, ale rzadko dochodzi do całkowitego wyschnięcia. Jest to łowisko o dużym potencjale dla każdego wędkarza.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21526, 7, 2.5, 6.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Okoń', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21527, 'Starorzecze Sławatycze 2', 'starorzecze-slawatycze-2-slawatycze-21527', 'OXBOW', 51.7504411, 23.5452244, 'Województwo Lubelskie', 'Sławatycze', 'To starorzecze jest wyjątkowo malownicze, z dnem w dużej mierze mulistym, ale z licznymi podwodnymi górami i dołkami, które stanowią idealne miejsca dla ryb. Brzegi są częściowo zarośnięte, ale istnieją liczne pomosty i dogodne miejsca do wędkowania. W zbiorniku dominują liny, karasie pospolite i leszcze, a także dorodne sumy i węgorze, które preferują zaciszne i głębokie partie. Wędkarstwo gruntowe i spławikowe z użyciem naturalnych przynęt jest tutaj najbardziej efektywne. Należy uważać na liczne zaczepy w postaci zatopionych drzew i konarów, które są jednocześnie ostoją dla drapieżników. Akwen jest stosunkowo głęboki, co minimalizuje ryzyko przyduchy. Jest to łowisko o dużym potencjale dla wędkarzy poszukujących dużych okazów ryb spokojnego żeru i drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21527, 5.8, 2.8, 7, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Leszcz,Sum,Węgorz', 'Dobry z pomostów, miejscami zarośnięty', FALSE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21528, 'Starorzecze Sławatycze 3', 'starorzecze-slawatycze-3-slawatycze-21528', 'OXBOW', 51.7502066, 23.5440027, 'Województwo Lubelskie', 'Sławatycze', 'To starorzecze charakteryzuje się płytkim, ale rozległym obszarem, z dnem w dużej mierze mulistym i gęsto porośniętym roślinnością wodną. Brzegi są w większości łatwo dostępne, choć miejscami występują kępy trzcin, które zapewniają schronienie rybom. W zbiorniku dominują płocie, wzdręgi i karasie srebrzyste, a także mniejsze okonie, które aktywnie żerują w strefie przybrzeżnej. Wędkarstwo spławikowe jest tutaj najbardziej efektywne, zwłaszcza w miejscach o niewielkich prześwitach w roślinności. Ze względu na płytkość i obfitość materii organicznej, ryzyko przyduchy w okresie letnim jest wysokie. Warto przygotować się na liczne zaczepy o podwodną roślinność. Jest to idealne miejsce dla wędkarzy ceniących spokój i poszukujących ryb spokojnego żeru.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21528, 4, 1.1, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Płoć,Wzdręga,Karaś srebrzysty,Okoń', 'Dobry z większości stron, miejscami zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21529, 'Starorzecze Kuzawka-Kolonia', 'starorzecze-kuzawka-kolonia-kuzawka-kolonia-21529', 'OXBOW', 51.7493503, 23.5436267, 'Województwo Lubelskie', 'Kuzawka-Kolonia', 'Starorzecze w Kuzawce-Kolonii to zbiornik o umiarkowanej wielkości, z dnem zróżnicowanym, gdzie dominują osady muliste, ale występują także twardsze fragmenty. Brzegi są częściowo dostępne, jednak w wielu miejscach porośnięte gęstą roślinnością szuwarową, co utrudnia swobodne poruszanie się. W zbiorniku licznie występują liny, karasie pospolite oraz płocie, a w głębszych partiach można spotkać dorodne szczupaki. Wędkarstwo gruntowe i spławikowe przynosi najlepsze efekty, zwłaszcza wczesnym rankiem i wieczorem. Należy przygotować się na liczne zaczepy spowodowane podwodną roślinnością i zatopionymi gałęziami. W okresie letnich upałów może występować ryzyko przyduchy, dlatego warto monitorować warunki. Jest to łowisko o dużym potencjale, z mniejszą presją wędkarską niż inne pobliskie akweny.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21529, 3, 1.4, 3.5, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Trudny, miejscami zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21530, 'Starorzecze Sławatycze I', 'starorzecze-slawatycze-i-slawatycze-21530', 'OXBOW', 51.7695844, 23.5678216, 'Lubelskie', 'Sławatycze', 'To starorzecze, położone w malowniczej okolicy Sławatycz, charakteryzuje się typowym dla takich zbiorników mulistym dnem, bogatym w substancje organiczne. Brzegi są w większości porośnięte gęstą trzciną i inną roślinnością przybrzeżną, co utrudnia dostęp do wody, ale jednocześnie stanowi doskonałe schronienie dla ryb. W płytkich partiach dominują lilie wodne i moczarka kanadyjska, tworząc idealne środowisko dla lina i karasia. W głębszych miejscach można spodziewać się okazów szczupaka i leszcza, często ukrywających się wśród zatopionych gałęzi. Wędkowanie tutaj wymaga cierpliwości i często użycia sprzętu pływającego lub brodzenia, jednak nagrodą mogą być naprawdę piękne ryby. Ryzyko zaplątania zestawu w podwodną roślinność jest wysokie, zwłaszcza latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21530, 3.2, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć,Leszcz', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna i pojedyncze korzenie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21531, 'Starorzecze Sławatycze II', 'starorzecze-slawatycze-ii-slawatycze-21531', 'OXBOW', 51.7704235, 23.5809289, 'Lubelskie', 'Sławatycze', 'Starorzecze to cechuje się wydłużonym kształtem i piaszczysto-mulistym dnem, które w niektórych miejscach przechodzi w twarde podłoże. Brzegi są stosunkowo łatwo dostępne na kilku odcinkach, choć dominują tam zarośla olch i wierzb, dające cień i schronienie. Roślinność podwodna jest umiarkowana, z przewagą rdestnic i grążeli, co sprzyja drapieżnikom takim jak szczupak i okoń. Licznie występują tu płocie i wzdręgi, żerujące w toni wodnej. Wędkowanie z gruntu może przynieść sukces w postaci okazałych leszczy, szczególnie w pobliżu głębszych rynien. Zbiornik jest ceniony za stabilną populację ryb i nieco łatwiejszy dostęp niż inne okoliczne starorzecza.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21531, 4.5, 2.1, 4.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz,Wzdręga', 'Dobry w kilku miejscach, reszta zarośnięta', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21532, 'Starorzecze Sławatycze III', 'starorzecze-slawatycze-iii-slawatycze-21532', 'OXBOW', 51.7703991, 23.5845821, 'Lubelskie', 'Sławatycze', 'To głębsze starorzecze charakteryzuje się bardziej zróżnicowanym dnem z partiami mulistymi i gliniastymi. Linia brzegowa jest mocno zarośnięta gęstymi krzewami i drzewami, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga przedzierania się przez gęstwiny. Roślinność podwodna jest bujna, szczególnie w płytszych zatokach, gdzie królują lilie wodne i moczarka. Jest to idealne siedlisko dla dużych linów i karasi pospolitych, które znajdują tu obfitość pokarmu i schronienie. W głębszych partiach starorzecza można spotkać sumy oraz okazałe karpie, które często żerują w pobliżu zatopionych drzew. Wędkowanie z pontonu lub łódki jest tu znacznie bardziej efektywne, a cierpliwi wędkarze mogą liczyć na prawdziwe okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21532, 5.8, 2.5, 5.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Sum,Karp,Węgorz', 'Bardzo trudny, gęste zarośla', TRUE, 'Dużo zatopionych drzew i gęsta roślinność', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21533, 'Starorzecze Mościce Dolne I', 'starorzecze-moscice-dolne-i-slawatycze-21533', 'OXBOW', 51.7642753, 23.5747504, 'Lubelskie', 'Sławatycze', 'Starorzecze to, położone w pobliżu Mościc Dolnych, jest typowym płytkim zbiornikiem z dominującym mulistym dnem i obfitością roślinności wodnej. Brzegi są w większości bagniste i porośnięte trzciną, co utrudnia swobodny dostęp, ale jednocześnie tworzy naturalne schronienie dla wielu gatunków ryb. Charakterystyczne dla tego miejsca są duże łany grążeli i rdestnic, które stanowią idealne żerowiska dla karasi i linów. Wędkowanie na spławik lub z lekkim gruntem w prześwitach między roślinnością może przynieść obfite połowy płoci i wzdręg. Zbiornik jest bardzo wrażliwy na letnie upały, co zwiększa ryzyko przyduchy, dlatego najlepsze są tu wiosenne i jesienne wyprawy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21533, 2, 1.2, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć,Wzdręga', 'Trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21534, 'Starorzecze Mościce Dolne II', 'starorzecze-moscice-dolne-ii-slawatycze-21534', 'OXBOW', 51.7638481, 23.574104, 'Lubelskie', 'Sławatycze', 'To niewielkie starorzecze charakteryzuje się dość jednolitym, mulistym dnem oraz gęstymi zaroślami trzcinowymi wzdłuż całej linii brzegowej. Dostęp do wody jest mocno ograniczony, co sprawia, że łowisko jest mało uczęszczane i zachowało swój dziki charakter. Roślinność podwodna jest bardzo obfita, z dominacją moczarki i wywłócznika, co stanowi doskonałe schronienie dla drobnicy. Wśród tej roślinności kryją się liczne okonie i szczupaki, polujące na płocie i wzdręgi. Wędkowanie wymaga precyzji i cierpliwości, często z wykorzystaniem długich wędek lub technik spławikowych w niewielkich prześwitach. Jest to idealne miejsce dla wędkarzy ceniących spokój i wyzwania związane z trudnym terenem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21534, 1.5, 1.5, 3, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Okoń,Szczupak,Płoć,Wzdręga', 'Bardzo trudny, gęsta trzcina', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21535, 'Starorzecze Sławatycze IV', 'starorzecze-slawatycze-iv-slawatycze-21535', 'OXBOW', 51.7636437, 23.5637071, 'Lubelskie', 'Sławatycze', 'Starorzecze to wyróżnia się relatywnie twardszym, piaszczysto-gliniastym dnem, co jest rzadkością w tej okolicy. Brzegi są częściowo dostępne, z niewielkimi polankami wśród drzew i krzewów, które ułatwiają rozstawienie sprzętu. Roślinność podwodna jest umiarkowana, z przewagą rdestnic i traw wodnych, co tworzy dogodne warunki dla drapieżników. Zbiornik słynie z populacji leszczy i płoci, które osiągają tu znaczne rozmiary, a także z licznych okoni. Wędkowanie gruntowe jest tu bardzo efektywne, zwłaszcza w głębszych partiach. Okresowo, podczas wysokich stanów wody, starorzecze łączy się z rzeką, co sprzyja migracji ryb i wzbogaca jego ichtiofaunę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21535, 3.8, 2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak', 'Umiarkowany, z dostępnymi miejscami', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21536, 'Starorzecze Sławatycze V', 'starorzecze-slawatycze-v-slawatycze-21536', 'OXBOW', 51.7647671, 23.5641148, 'Lubelskie', 'Sławatycze', 'To starorzecze charakteryzuje się silnym zamuleniem dna i gęstą roślinnością przybrzeżną, głównie trzciną i pałką wodną, co czyni je trudnym do wędkowania. Woda jest zazwyczaj płytka, a dno miękkie, co utrudnia brodzenie. Roślinność podwodna jest bardzo bujna, z dominacją lilii wodnych i rzęsy, tworząc doskonałe schronienie dla drobnicy. Jest to raj dla karasi pospolitych i linów, które osiągają tu imponujące rozmiary. Wędkowanie wymaga cierpliwości i umiejętności łowienia w zarośniętych miejscach, często z użyciem spławika. Ze względu na płytkość i roślinność, latem występuje podwyższone ryzyko przyduchy, co może wpływać na aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21536, 2.7, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21537, 'Starorzecze Sławatycze VI', 'starorzecze-slawatycze-vi-slawatycze-21537', 'OXBOW', 51.765383, 23.5634902, 'Lubelskie', 'Sławatycze', 'Starorzecze to jest znane z głębszych rynien i częściowo twardego dna, przeplatanego z mulistymi zatokami. Brzegi są zróżnicowane – od łatwo dostępnych, trawiastych odcinków po gęsto zarośnięte krzewami i drzewami, które zapewniają cień. Roślinność podwodna jest umiarkowana, z skupiskami rdestnic i moczarki, co stanowi dobre miejsca do zasadzki dla szczupaków. W zbiorniku występują duże populacje leszczy i płoci, a także liczne okonie. Okresowe połączenie z rzeką sprzyja migracji ryb, wprowadzając do starorzecza świeże geny i nowe osobniki. Wędkowanie z gruntu i na spinning jest tu bardzo efektywne, zwłaszcza w pobliżu głębszych partii.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21537, 5.1, 2.3, 5.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Karp', 'Dobry z niektórych stron, reszta umiarkowana', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21538, 'Starorzecze Sławatycze VII', 'starorzecze-slawatycze-vii-slawatycze-21538', 'OXBOW', 51.7657308, 23.5639133, 'Lubelskie', 'Sławatycze', 'To starorzecze charakteryzuje się mulistym dnem i gęstymi zaroślami trzcinowymi wzdłuż całej linii brzegowej, co utrudnia dostęp do wody. Jest to typowe, płytkie łowisko, idealne dla gatunków odpornych na trudne warunki. Roślinność podwodna jest bardzo bujna, z dominacją lilii wodnych i moczarki, co tworzy doskonałe schronienie i żerowiska. W zbiorniku licznie występują karasie srebrzyste i pospolite, a także liny, które osiągają tu znaczne rozmiary. Wędkowanie z gruntu lub na spławik w niewielkich prześwitach między roślinnością jest najbardziej efektywne. Ze względu na płytkość i obfitość roślinności, latem występuje ryzyko niedoboru tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21538, 2.9, 1.1, 2.7, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś srebrzysty,Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21539, 'Starorzecze Sławatycze VIII', 'starorzecze-slawatycze-viii-slawatycze-21539', 'OXBOW', 51.7704581, 23.5654251, 'Lubelskie', 'Sławatycze', 'To starorzecze jest jednym z większych w okolicy, z wyraźnie zróżnicowanym dnem, gdzie partie muliste przeplatają się z piaszczystymi. Brzegi są dość łatwo dostępne w kilku miejscach, z otwartymi przestrzeniami umożliwiającymi wędkowanie z brzegu. Roślinność podwodna jest umiarkowana, z rozproszonymi kępami rdestnic i moczarki, co sprzyja drapieżnikom. Zbiornik ten słynie z populacji leszczy i płoci, które osiągają tu imponujące rozmiary, a także z licznych szczupaków i okoni. Wędkowanie spinningowe wzdłuż brzegów i na otwartej wodzie jest bardzo efektywne, podobnie jak gruntowe na karpie i sumy. Stałe połączenie z rzeką zapewnia świeżą wodę i migrację ryb, co utrzymuje wysoką jakość łowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21539, 8, 3, 6, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Karp,Sum,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21540, 'Starorzecze Sławatycze IX', 'starorzecze-slawatycze-ix-slawatycze-21540', 'OXBOW', 51.7696474, 23.5748296, 'Lubelskie', 'Sławatycze', 'To starorzecze charakteryzuje się mulistym dnem i gęstymi zaroślami trzcinowymi wzdłuż całej linii brzegowej, co utrudnia dostęp do wody. Jest to typowe, płytkie łowisko, idealne dla gatunków odpornych na trudne warunki. Roślinność podwodna jest bardzo bujna, z dominacją lilii wodnych i moczarki, co tworzy doskonałe schronienie i żerowiska. W zbiorniku licznie występują karasie srebrzyste i pospolite, a także liny, które osiągają tu znaczne rozmiary. Wędkowanie z gruntu lub na spławik w niewielkich prześwitach między roślinnością jest najbardziej efektywne. Ze względu na płytkość i obfitość roślinności, latem występuje ryzyko niedoboru tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21540, 2.9, 1.1, 2.7, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś srebrzysty,Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21541, 'Starorzecze Sławatycze X', 'starorzecze-slawatycze-x-slawatycze-21541', 'OXBOW', 51.7694563, 23.5619237, 'Lubelskie', 'Sławatycze', 'To mniejsze starorzecze charakteryzuje się płytkim, mulistym dnem i bardzo gęstą roślinnością przybrzeżną, głównie trzciną i pałką wodną. Dostęp do wody jest niezwykle trudny, co sprawia, że łowisko jest praktycznie dziewicze. Roślinność podwodna jest obfita, z dominacją lilii wodnych i rzęsy, tworząc idealne schronienie dla ryb. W zbiorniku licznie występują karasie pospolite i liny, które doskonale czują się w tych warunkach. Wędkowanie wymaga brodzenia lub użycia pontonu, a także dużej cierpliwości i precyzji w zarzucaniu zestawu. Jest to miejsce dla wędkarzy poszukujących wyzwań i ceniących dziką przyrodę, z szansą na medalowe okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21541, 1.8, 0.9, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Płoć', 'Bardzo trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna i muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21542, 'Starorzecze Sławatycze XI', 'starorzecze-slawatycze-xi-slawatycze-21542', 'OXBOW', 51.7692198, 23.5615376, 'Lubelskie', 'Sławatycze', 'To starorzecze jest nieco głębsze niż sąsiednie, z dnem gliniasto-mulistym, co sprzyja występowaniu większych ryb. Brzegi są zarośnięte drzewami i krzewami, ale istnieją nieliczne, wydeptane miejsca do wędkowania. Roślinność podwodna jest umiarkowana, z kępami rdestnic i moczarki, tworząc dogodne kryjówki dla drapieżników. Zbiornik słynie z populacji leszczy i karpi, które osiągają tu pokaźne rozmiary, a także z licznych szczupaków i okoni. Okresowe połączenie z rzeką podczas wiosennych roztopów wzbogaca ichtiofaunę. Wędkowanie z gruntu i na spinning jest tu bardzo efektywne, szczególnie w pobliżu zatopionych pni i gałęzi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21542, 4, 2.2, 4.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Szczupak,Okoń', 'Umiarkowany, z pojedynczymi miejscami', FALSE, 'Pojedyncze zatopione drzewa i korzenie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21543, 'Starorzecze Sławatycze XII', 'starorzecze-slawatycze-xii-slawatycze-21543', 'OXBOW', 51.7642359, 23.5568912, 'Lubelskie', 'Sławatycze', 'Starorzecze to jest stosunkowo płytkie i charakteryzuje się bardzo mulistym dnem, które w upalne lata może być problematyczne. Brzegi są w większości mocno zarośnięte trzciną i inną roślinnością przybrzeżną, co utrudnia swobodny dostęp. Roślinność podwodna jest bardzo bujna, z dominacją lilii wodnych i rzęsy, tworząc idealne środowisko dla ryb spokojnego żeru. Zbiornik ten jest prawdziwym rajem dla karasi pospolitych i linów, które osiągają tu imponujące rozmiary. Wędkowanie wymaga cierpliwości i precyzji, często z użyciem długich wędek i zestawów spławikowych. Ze względu na płytkość i obfitość roślinności, latem występuje podwyższone ryzyko przyduchy, co wymaga uwagi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21543, 2.5, 1, 2.4, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć,Wzdręga', 'Trudny, bagnisty i zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna i muł', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21544, 'Starorzecze Sławatycze XIII', 'starorzecze-slawatycze-xiii-slawatycze-21544', 'OXBOW', 51.7630428, 23.5571005, 'Lubelskie', 'Sławatycze', 'To starorzecze, choć niewielkie, oferuje zróżnicowane warunki, od mulistych do piaszczysto-gliniastych partii dna. Brzegi są częściowo dostępne, z niewielkimi prześwitami wśród drzew i krzewów, które ułatwiają wędkowanie. Roślinność podwodna jest umiarkowana, z przewagą rdestnic i traw wodnych, co tworzy dogodne warunki dla drapieżników. Zbiornik słynie z populacji płoci i leszczy, które osiągają tu znaczne rozmiary, a także z licznych okoni. Wędkowanie gruntowe jest tu bardzo efektywne, zwłaszcza w głębszych partiach, a spinningowe wzdłuż zarośniętych brzegów. Okresowo, podczas wysokich stanów wody, starorzecze łączy się z rzeką, co sprzyja migracji ryb i wzbogaca jego ichtiofaunę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21544, 3, 1.7, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Umiarkowany, z dostępnymi miejscami', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21545, 'Starorzecze (Sławatycze)', 'starorzecze-slawatycze-slawatycze-21545', 'OXBOW', 51.7601893, 23.555059, 'Lubelskie', 'Sławatycze', 'Starorzecze to, położone w pobliżu Sławatycz, jest typowym przykładem dawnego meandru rzeki Bug, charakteryzującego się malowniczym, choć dzikim krajobrazem. Dno jest przeważnie muliste, z lokalnymi twardszymi partiami, co sprzyja rozwojowi bogatej roślinności podwodnej i nawodnej. Brzegi są często podmokłe i gęsto porośnięte trzciną oraz krzewami, co utrudnia dostęp do wody, lecz jednocześnie stanowi doskonałe schronienie dla ryb. Wśród dominujących gatunków można wyróżnić szczupaka, lina, karasia pospolitego, płocie i leszcze, które znajdują tu idealne warunki do żerowania i rozrodu. Wędkowanie wymaga cierpliwości i często brodzenia, ale nagrodą są często okazałe egzemplarze. Latem, w okresach upałów, istnieje ryzyko przyduchy, co należy wziąć pod uwagę planując wyprawę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21545, 3, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć,Leszcz', 'Trudny, miejscami podmokły', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21546, 'Starorzecze (Mościce Dolne)', 'starorzecze-moscice-dolne-moscice-dolne-21546', 'OXBOW', 51.7671701, 23.579907, 'Lubelskie', 'Mościce Dolne', 'To starorzecze w okolicach Mościc Dolnych jest płytkim i silnie zarośniętym zbiornikiem, idealnym dla wędkarzy poszukujących spokojnych łowisk z bogactwem roślinności. Dno jest w większości pokryte grubą warstwą mułu, co sprzyja bujnemu rozwojowi trzcin, grążeli i moczarki kanadyjskiej. Brzegi są trudno dostępne, często bagniste i wymagają użycia brodzących spodni, aby dotrzeć do otwartych partii wody. Jest to raj dla lina, karasia pospolitego i wzdręgi, które doskonale czują się w tak zarośniętych środowiskach, a także dla szczupaka polującego w zaroślach. Wędkowanie z gruntu lub spławikowe w wolnych od roślinności "oknach" jest najbardziej efektywne. Ze względu na obfitość materii organicznej, ryzyko niedoboru tlenu w upalne dni jest podwyższone.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21546, 2.8, 1.4, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć,Szczupak', 'Trudny, gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna, pojedyncze gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21547, 'Starorzecze (Mościce Dolne)', 'starorzecze-moscice-dolne-moscice-dolne-21547', 'OXBOW', 51.7667427, 23.5819602, 'Lubelskie', 'Mościce Dolne', 'Kolejne starorzecze w pobliżu Mościc Dolnych, charakteryzujące się jeszcze większym stopniem zarośnięcia niż poprzednie, co czyni je prawdziwą ostoją dla ryb ceniących spokój i ukrycie. Dno jest głęboko zamulone, a powierzchnia wody często pokryta kożuchem roślinności, z nielicznymi otwartymi przestrzeniami. Dostęp do łowiska jest ekstremalnie utrudniony przez gęste zarośla trzcin i krzewów, wymagając od wędkarza determinacji i odpowiedniego sprzętu. Jest to idealne miejsce do poszukiwania okazałych linów i karasi pospolitych, które doskonale prosperują w takich warunkach. Płoć i wzdręga również licznie zasiedlają ten zbiornik, żerując wśród roślinności. W upalne, bezwietrzne dni należy liczyć się z ryzykiem przyduchy, co może wpływać na aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21547, 2.2, 1.3, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Bardzo trudny, gęsto zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21548, 'Starorzecze (Sławatycze)', 'starorzecze-slawatycze-slawatycze-21548', 'OXBOW', 51.769607, 23.5814465, 'Lubelskie', 'Sławatycze', 'To starorzecze, położone na północ od Sławatycz, wyróżnia się nieco większą głębokością i mniejszym stopniem zamulenia w porównaniu do sąsiednich zbiorników, co czyni je atrakcyjnym dla różnorodnych gatunków ryb. Dno jest częściowo twarde, piaszczysto-żwirowe, przeplatane z obszarami mulistymi, co sprzyja zarówno rybom drapieżnym, jak i spokojnego żeru. Brzegi są stosunkowo łatwo dostępne z jednej strony, z drugiej zaś mogą być porośnięte, lecz bez większych trudności. Jest to doskonałe łowisko dla szczupaka i okonia, które często patrolują głębsze partie i okolice zatopionych przeszkód. Licznie występują tu również leszcze, płocie i karpie, szczególnie w cieplejszych miesiącach. Dobra cyrkulacja wody podczas wezbrań Bugu minimalizuje ryzyko przyduchy, zapewniając stabilne warunki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21548, 3.5, 1.6, 3.2, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Karp', 'Dobry z jednej strony, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21549, 'Starorzecze (Wólka Nadbużna)', 'starorzecze-wolka-nadbuzna-wolka-nadbuzna-21549', 'OXBOW', 52.3636338, 22.8556883, 'Podlaskie', 'Wólka Nadbużna', 'Starorzecze w okolicach Wólki Nadbużnej, leżące w malowniczej dolinie Bugu, to rozległy i zróżnicowany akwen, oferujący wędkarzom wiele możliwości. Charakteryzuje się urozmaiconym dnem, gdzie muliste obszary przeplatają się z twardszymi, piaszczystymi fragmentami, a liczne zatopione drzewa i konary stanowią idealne kryjówki dla ryb. Brzegi są miejscami łatwo dostępne, w innych partiach zaś porośnięte trzciną i krzewami, wymagającymi odrobiny wysiłku. Jest to znakomite łowisko dla szczupaków i okoni, a także dla sumów, które często bytują w pobliżu zatopionych przeszkód. Leszcz i płoć licznie zasiedlają ten zbiornik, szczególnie w spokojniejszych zatoczkach. Ze względu na obecność dużej ilości materii organicznej, w szczycie lata istnieje umiarkowane ryzyko przyduchy, co może wpływać na aktywność żerową.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21549, 4, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Sum', 'Dobry w niektórych miejscach, inne zarośnięte', FALSE, 'Dużo zatopionych drzew i gałęzi', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21550, 'Starorzecze (Mościce Dolne)', 'starorzecze-moscice-dolne-moscice-dolne-21550', 'OXBOW', 51.7596812, 23.5697139, 'Lubelskie', 'Mościce Dolne', 'To płytkie i silnie zamulone starorzecze w pobliżu Mościc Dolnych jest przykładem zbiornika, który w okresach suszy może znacząco zmniejszyć swoją powierzchnię, a nawet częściowo wyschnąć. Dno jest niemal w całości pokryte grubą warstwą mułu, co sprzyja intensywnemu rozwojowi roślinności wodnej, tworząc gęste zarośla. Brzegi są niezwykle trudne do pokonania, często bagniste i gęsto porośnięte, co wymaga od wędkarza dużej ostrożności i użycia brodzących spodni. Jest to idealne środowisko dla karasia pospolitego i lina, które doskonale radzą sobie w trudnych warunkach, a także dla wzdręgi i płoci. Wędkowanie jest tu wyzwaniem, ale może przynieść satysfakcję w postaci okazałych egzemplarzy tych gatunków. Wysoki poziom zamulenia i bujna roślinność sprawiają, że ryzyko przyduchy jest bardzo wysokie, szczególnie latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21550, 2, 1, 2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Bardzo trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21551, 'Starorzecze (Liszna)', 'starorzecze-liszna-liszna-21551', 'OXBOW', 51.7737885, 23.5719771, 'Lubelskie', 'Liszna', 'Starorzecze w okolicach Liszny to akwen o umiarkowanej głębokości i zróżnicowanym charakterze, atrakcyjny dla wędkarzy. Dno jest mieszane, z partiami mulistymi i twardszymi, piaszczystymi, co sprzyja różnorodności fauny dennej i roślinności. Brzegi są dostępne w wielu miejscach, choć lokalnie mogą być porośnięte trzciną, co wymaga znalezienia odpowiedniego stanowiska. Jest to dobre łowisko na szczupaka, który poluje wzdłuż brzegów i w okolicach zatopionych przeszkód. Lin, leszcz, płoć i okoń również licznie zasiedlają ten zbiornik, oferując szeroki wachlarz możliwości wędkarskich. Okresowe połączenie z rzeką Bug podczas wysokich stanów wody odświeża akwen, jednak w upalne lato ryzyko przyduchy nadal występuje, zwłaszcza w płytkich zatokach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21551, 2.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry w niektórych miejscach, inne zarośnięte', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21552, 'Zalew Prężycki', 'zalew-prezycki-prezyce-21552', 'OXBOW', 51.2463875, 16.8381806, 'Dolnośląskie', 'Prężyce', 'Zalew Prężycki, położony w pobliżu Wrocławia, to znacznie większy i prawdopodobnie bardziej uregulowany akwen niż typowe starorzecza Bugu, często stanowiący kompleks połączonych zbiorników lub rozległe starorzecze z modyfikacjami. Charakteryzuje się zróżnicowanym dnem, z głębszymi rynnami i płytszymi blatami, co sprzyja różnorodności gatunkowej. Brzegi są w dużej mierze łatwo dostępne, z licznymi dogodnymi miejscami do wędkowania, a nawet przygotowanymi stanowiskami. Jest to doskonałe łowisko dla wędkarzy poszukujących dużych drapieżników, takich jak szczupak, sandacz i sum, a także dla karpiarzy i miłośników białorybu – leszczy i okoni. Stałe połączenie z systemem rzecznym (prawdopodobnie Odry) zapewnia dobrą cyrkulację wody i minimalizuje ryzyko przyduchy. Akwen ten jest popularny przez cały sezon, oferując stabilne warunki do wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21552, 15, 2.5, 6, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Karp,Leszcz,Okoń,Sum', 'Dobry, miejscami przygotowane stanowiska', FALSE, 'Czyste dno, pojedyncze korzenie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21553, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21553', 'OXBOW', 51.7797426, 23.6123882, 'Lubelskie', 'Nowosiółki', 'To starorzecze w okolicach Nowosiółek jest typowym, średniej wielkości akwenem doliny Bugu, oferującym wędkarzom dzikie i naturalne środowisko. Dno jest przeważnie muliste, z lokalnymi, twardszymi partiami, co sprzyja rozwojowi zróżnicowanej roślinności wodnej. Brzegi są miejscami trudno dostępne, gęsto porośnięte trzciną i krzewami, co wymaga od wędkarza cierpliwości i często brodzenia. Jest to dobre łowisko na szczupaka, który czai się w zaroślach, a także na lina i karasia pospolitego, które doskonale czują się w mulistym dnie. Płoć również licznie zasiedla ten zbiornik, żerując wśród roślinności. W okresach letnich upałów, ryzyko przyduchy jest umiarkowane, co należy uwzględnić podczas planowania wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21553, 2.7, 1.4, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć', 'Trudny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21554, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21554', 'OXBOW', 51.7786311, 23.6146171, 'Lubelskie', 'Nowosiółki', 'Kolejne starorzecze w pobliżu Nowosiółek, charakteryzujące się znacznym stopniem zamulenia i bujną roślinnością wodną, co czyni je idealnym siedliskiem dla ryb ceniących spokój i schronienie. Dno jest głęboko muliste, a powierzchnia wody często pokryta dywanem liści grążeli i innych roślin. Dostęp do łowiska jest bardzo trudny, ze względu na gęste zarośla trzcin i podmokłe brzegi, co wymaga od wędkarza użycia brodzących spodni. Jest to doskonałe miejsce do poszukiwania okazałych linów i karasi pospolitych, które doskonale prosperują w takich warunkach. Wzdręga i płoć również licznie występują, żerując wśród roślinności. Ze względu na dużą ilość materii organicznej i ograniczoną cyrkulację wody, ryzyko przyduchy w upalne dni jest wysokie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21554, 2.3, 1.2, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Bardzo trudny, gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21555, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21555', 'OXBOW', 51.7743366, 23.5989594, 'Lubelskie', 'Nowosiółki', 'To starorzecze, również położone w okolicach Nowosiółek, wyróżnia się nieco większą powierzchnią i umiarkowaną głębokością, co sprzyja różnorodności gatunków ryb. Dno jest zróżnicowane, z mulistymi obszarami przeplatanymi twardszymi fragmentami, a nieliczne zatopione korzenie i gałęzie stanowią atrakcyjne kryjówki. Brzegi są w części łatwo dostępne, co ułatwia dotarcie do wody, choć w innych partiach mogą być porośnięte. Jest to dobre łowisko dla szczupaka i okonia, które aktywnie polują w tym akwenie. Licznie występują tu również leszcze, płocie i karpie, szczególnie w cieplejszych miesiącach. Okresowe połączenie z rzeką Bug podczas wezbrań odświeża wodę, jednak w szczycie lata ryzyko przyduchy jest umiarkowane, zwłaszcza w płytszych zatokach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21555, 3.1, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Karp', 'Dobry z jednej strony, inne zarośnięte', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21556, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21556', 'OXBOW', 51.7889709, 23.6272993, 'Lubelskie', 'Nowosiółki', 'To starorzecze, położone w północnej części obszaru Nowosiółek, jest typowym, silnie zarośniętym akwenem, charakteryzującym się bogactwem roślinności wodnej i mulistym dnem. Dno jest w dużej mierze pokryte grubą warstwą mułu, co sprzyja bujnemu rozwojowi trzcin, grążeli i moczarki. Brzegi są trudno dostępne, często podmokłe i gęsto porośnięte, co wymaga użycia brodzących spodni. Jest to raj dla lina, karasia pospolitego i wzdręgi, które doskonale czują się w tak zarośniętych środowiskach, a także dla szczupaka polującego w ukryciu. Wędkowanie z gruntu lub spławikowe w wolnych od roślinności "oknach" jest najbardziej efektywne. Ze względu na obfitość materii organicznej, ryzyko niedoboru tlenu w upalne dni jest podwyższone.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21556, 2.6, 1.3, 2.7, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć,Szczupak', 'Trudny, gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna, pojedyncze gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21557, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21557', 'OXBOW', 51.7883701, 23.627034, 'Lubelskie', 'Nowosiółki', 'To płytkie i silnie zamulone starorzecze, położone w bliskim sąsiedztwie poprzedniego, jest szczególnie wrażliwe na zmiany poziomu wody i w okresach suszy może częściowo wyschnąć. Dno jest niemal w całości pokryte grubą warstwą mułu, co sprzyja intensywnemu rozwojowi roślinności wodnej, tworząc gęste zarośla. Brzegi są niezwykle trudne do pokonania, często bagniste i gęsto porośnięte, co wymaga od wędkarza dużej ostrożności i użycia brodzących spodni. Jest to idealne środowisko dla karasia pospolitego i lina, które doskonale radzą sobie w trudnych warunkach, a także dla wzdręgi i płoci. Wędkowanie jest tu wyzwaniem, ale może przynieść satysfakcję w postaci okazałych egzemplarzy tych gatunków. Wysoki poziom zamulenia i bujna roślinność sprawiają, że ryzyko przyduchy jest bardzo wysokie, szczególnie latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21557, 2.4, 1.1, 2.2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Bardzo trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21558, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21558', 'OXBOW', 51.7891833, 23.6202323, 'Lubelskie', 'Nowosiółki', 'To starorzecze, zlokalizowane w północno-zachodniej części obszaru Nowosiółek, charakteryzuje się umiarkowaną głębokością i zróżnicowanym dnem, co czyni je atrakcyjnym dla różnorodnych gatunków ryb. Dno jest mieszane, z partiami mulistymi i twardszymi, piaszczystymi, co sprzyja różnorodności fauny dennej i roślinności. Brzegi są dostępne w wielu miejscach, choć lokalnie mogą być porośnięte trzciną, co wymaga znalezienia odpowiedniego stanowiska. Jest to dobre łowisko na szczupaka, który poluje wzdłuż brzegów i w okolicach zatopionych przeszkód. Lin, leszcz, płoć i okoń również licznie zasiedlają ten zbiornik, oferując szeroki wachlarz możliwości wędkarskich. Okresowe połączenie z rzeką Bug podczas wysokich stanów wody odświeża akwen, jednak w upalne lato ryzyko przyduchy nadal występuje, zwłaszcza w płytkich zatokach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21558, 2.9, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry z jednej strony, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21559, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21559', 'OXBOW', 51.7888419, 23.6201998, 'Lubelskie', 'Nowosiółki', 'Ostatnie starorzecze z tej grupy, położone bardzo blisko poprzedniego w rejonie Nowosiółek, posiada zbliżoną charakterystykę, będąc atrakcyjnym łowiskiem o zróżnicowanym profilu. Dno jest mieszane, z partiami mulistymi i twardszymi, piaszczystymi, co sprzyja różnorodności fauny dennej i roślinności. Brzegi są dostępne w wielu miejscach, choć lokalnie mogą być porośnięte trzciną, co wymaga znalezienia odpowiedniego stanowiska. Jest to dobre łowisko na szczupaka, który poluje wzdłuż brzegów i w okolicach zatopionych przeszkód. Lin, leszcz, płoć i okoń również licznie zasiedlają ten zbiornik, oferując szeroki wachlarz możliwości wędkarskich. Okresowe połączenie z rzeką Bug podczas wysokich stanów wody odświeża akwen, jednak w upalne lato ryzyko przyduchy nadal występuje, zwłaszcza w płytkich zatokach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21559, 2.8, 1.4, 2.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry z jednej strony, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21560, 'Starorzecze Nowosiółki 1', 'starorzecze-nowosiolki-1-koden-21560', 'OXBOW', 51.7882805, 23.6185861, 'Województwo Lubelskie', 'Kodeń', 'To starorzecze charakteryzuje się typowym dla doliny Bugu, mulistym dnem, bogatym w osady organiczne. Brzegi są gęsto porośnięte trzciną i inną roślinnością przybrzeżną, co utrudnia dostęp do wody w wielu miejscach. W akwenie dominują liczne skupiska lilii wodnych i rdestnic, tworząc idealne schronienia dla ryb. Jest to łowisko płytkie, ale z wyraźnymi głębszymi rynienkami, szczególnie atrakcyjne dla wędkarzy poszukujących lina i karasia. Wiosną i wczesną jesienią można liczyć na dobre brania szczupaków, które aktywnie polują wśród zarośli. Z uwagi na dużą ilość roślinności, latem istnieje ryzyko przyduchy, co może wpływać na aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21560, 3.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21561, 'Starorzecze Nowosiółki 2', 'starorzecze-nowosiolki-2-koden-21561', 'OXBOW', 51.7878492, 23.6190419, 'Województwo Lubelskie', 'Kodeń', 'Ten fragment starorzecza, choć niewielki, oferuje ciekawe warunki dla wędkarzy. Dno jest zróżnicowane, z przewagą mułu, ale z twardszymi partiami żwirowo-piaszczystymi. Brzegi są częściowo dostępne, jednak w wielu miejscach otoczone przez podmokłe tereny i gęste krzewy. Roślinność podwodna, taka jak rogatek i moczarka, tworzy bogate siedliska dla drobnej ryby, przyciągając drapieżniki. Łowisko to jest znane z populacji okonia i wzdręgi, które często żerują w pobliżu powierzchni. Warto szukać głębszych miejsc, gdzie zimują większe leszcze i płocie. Ze względu na niewielką powierzchnię, starorzecze szybko nagrzewa się latem, co może prowadzić do spadku poziomu tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21561, 2.1, 1.2, 3, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Okoń,Wzdręga,Płoć,Leszcz', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21562, 'Starorzecze Nowosiółki 3', 'starorzecze-nowosiolki-3-koden-21562', 'OXBOW', 51.7873387, 23.6174063, 'Województwo Lubelskie', 'Kodeń', 'Starorzecze to wyróżnia się relatywnie czystym dnem w centralnej części, choć brzegi są silnie zamulone. Otoczone jest wysokimi trawami i kępami olch, co nadaje mu dziki charakter. Roślinność wodna jest obfita, z dominacją grążeli i trzcin, które tworzą naturalne kryjówki. Woda jest zazwyczaj klarowna, co sprzyja obserwacji ryb, jednak utrudnia podejście do łowiska. Jest to doskonałe miejsce do łowienia karasia pospolitego i lina, które osiągają tu imponujące rozmiary. Odnotowuje się również obecność szczupaka, szczególnie aktywnego w strefach przybrzeżnych. Należy uważać na liczne zatopione gałęzie i konary, które mogą stanowić przeszkody dla sprzętu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21562, 4.5, 1.8, 4.2, 'Podczas wysokiej wody', 'Niskie', 'Silne', FALSE, FALSE, 'Karaś pospolity,Lin,Szczupak,Leszcz', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21563, 'Starorzecze Nowosiółki 4', 'starorzecze-nowosiolki-4-koden-21563', 'OXBOW', 51.7852553, 23.6127641, 'Województwo Lubelskie', 'Kodeń', 'To starorzecze jest jednym z większych w kompleksie Nowosiółek, charakteryzującym się głęboką rynną wzdłuż jednego z brzegów. Dno jest w większości muliste, z twardszymi fragmentami w pobliżu dawnego koryta rzeki. Brzegi są łatwiej dostępne niż w innych miejscach, choć miejscami nadal podmokłe. Roślinność podwodna jest umiarkowana, co ułatwia prowadzenie przynęt, jednak w zatokach występują gęste skupiska moczarki. Akwen ten jest znany z populacji leszcza i płoci, które często tworzą duże ławice. Można tu również trafić na karpia i suma, szczególnie w głębszych partiach. Okresy suszy mogą obniżać poziom wody, ale starorzecze rzadko wysycha całkowicie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21563, 8, 2.5, 5.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sum,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21564, 'Starorzecze Nowosiółki 5', 'starorzecze-nowosiolki-5-koden-21564', 'OXBOW', 51.7852135, 23.6135955, 'Województwo Lubelskie', 'Kodeń', 'Ten akwen to płytkie, silnie zarośnięte starorzecze, idealne dla miłośników łowienia w trudnych warunkach. Dno jest jednolicie muliste, z grubą warstwą osadów organicznych. Brzegi są praktycznie niedostępne bez brodzenia, z uwagi na gęste szuwary i bagniste podłoże. Cała powierzchnia wody jest pokryta grążelami i rzęsą, co tworzy unikalny mikroklimat. Jest to prawdziwy raj dla lina i karasia pospolitego, które czują się tu doskonale. Wczesną wiosną, zanim roślinność osiągnie pełnię wzrostu, można skutecznie polować na szczupaka. Wędkarstwo wymaga precyzji i cierpliwości, a także użycia odpowiedniego sprzętu do łowienia w zarośniętych miejscach. Wysokie temperatury latem zwiększają ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21564, 2.8, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21565, 'Starorzecze Nowosiółki 6', 'starorzecze-nowosiolki-6-koden-21565', 'OXBOW', 51.7841769, 23.6128693, 'Województwo Lubelskie', 'Kodeń', 'Starorzecze to jest stosunkowo głębokie jak na ten typ akwenu, z wyraźnym spadkiem dna w kierunku środka. Dno jest mieszane, z partiami piasku i mułu, co sprzyja różnorodności gatunkowej. Brzegi są umiarkowanie zarośnięte, z kilkoma dogodnymi miejscami do zarzucenia wędki. Roślinność wodna koncentruje się głównie w strefie przybrzeżnej, pozostawiając otwartą wodę w centrum. Jest to doskonałe miejsce dla leszczy i płoci, które często żerują na otwartej wodzie. W głębszych partiach można spotkać sandacza, a także okazałe karpie i sumy. Starorzecze to jest mniej podatne na wysychanie i przyduchy, co czyni je stabilnym łowiskiem przez cały sezon. Bliskość Bugu zapewnia regularne zasilanie wodą podczas wezbrań.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21565, 6.7, 2.2, 4.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Sandacz,Karp,Sum', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21566, 'Starorzecze Nowosiółki 7', 'starorzecze-nowosiolki-7-koden-21566', 'OXBOW', 51.786333, 23.6050976, 'Województwo Lubelskie', 'Kodeń', 'To starorzecze charakteryzuje się rozległymi płyciznami i mulistym dnem, które sprzyja rozwojowi bogatej roślinności. Brzegi są bagniste i trudno dostępne, co wymaga użycia wodoodpornego obuwia lub brodzenia. Duże połacie wody pokryte są grążelami, rdestnicą i moczarką, tworząc labirynt dla wędkarzy. Akwen ten jest królestwem karasia pospolitego i lina, które doskonale maskują się w gęstwinie roślin. Często występują tu również wzdręgi i płocie, żerujące przy powierzchni. Latem, z powodu intensywnego rozkładu materii organicznej, ryzyko przyduchy jest wysokie, co może wpływać na aktywność ryb. Wędkarstwo wymaga cierpliwości i umiejętności łowienia w silnie zarośniętych miejscach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21566, 3.9, 1.1, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21567, 'Starorzecze Nowosiółki 8', 'starorzecze-nowosiolki-8-koden-21567', 'OXBOW', 51.7836479, 23.5992069, 'Województwo Lubelskie', 'Kodeń', 'Ten odcinek starorzecza wyróżnia się stosunkowo twardym, piaszczysto-żwirowym dnem w wielu miejscach, co jest rzadkością w tej okolicy. Brzegi są częściowo dostępne, z licznymi prześwitami wśród trzcin i krzewów. Roślinność wodna jest umiarkowana, głównie w postaci pasów trzcin i pojedynczych kęp moczarki. Akwen jest znany z populacji okonia i szczupaka, które aktywnie polują wzdłuż brzegów i na otwartej wodzie. Można tu również liczyć na dobre brania płoci i leszczy, zwłaszcza w chłodniejszych miesiącach. Ze względu na lepszą cyrkulację wody, ryzyko przyduchy jest niższe, a starorzecze rzadko wysycha. To dobre miejsce dla wędkarzy preferujących spinning.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21567, 5.1, 1.7, 3.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Okoń,Szczupak,Płoć,Leszcz,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21568, 'Starorzecze Nowosiółki 9', 'starorzecze-nowosiolki-9-koden-21568', 'OXBOW', 51.7851388, 23.6093784, 'Województwo Lubelskie', 'Kodeń', 'To starorzecze jest klasycznym przykładem akwenu z silnie zamulonym dnem i gęstą roślinnością. Brzegi są mocno zarośnięte trzciną i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest bardzo utrudniony. Woda jest często mętna z powodu dużej ilości osadów i rozkładającej się materii organicznej. Jest to idealne środowisko dla karasia pospolitego i lina, które osiągają tu znaczne rozmiary. Występuje tu również szczupak, który czai się w zaroślach na swoje ofiary. Wędkarstwo wymaga cierpliwości i precyzyjnego zarzucania zestawu. Latem, przy wysokich temperaturach, ryzyko niedoboru tlenu jest znaczne, co może wpływać na żerowanie ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21568, 2.9, 1.3, 3.1, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Szczupak,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21569, 'Starorzecze Nowosiółki 10', 'starorzecze-nowosiolki-10-koden-21569', 'OXBOW', 51.7848663, 23.6099517, 'Województwo Lubelskie', 'Kodeń', 'Starorzecze to charakteryzuje się wyraźną głębokością w centralnej części, z łagodnymi spadkami dna ku brzegom. Dno jest muliste, ale z twardszymi partiami wzdłuż dawnego koryta rzeki. Brzegi są stosunkowo łatwo dostępne, z kilkoma dogodnymi stanowiskami wędkarskimi. Roślinność wodna jest umiarkowana, skoncentrowana głównie w strefie przybrzeżnej i w płytkich zatokach. Akwen ten jest znany z populacji leszczy i karpi, które często żerują na otwartej wodzie. Można tu również złowić suma, zwłaszcza po zmroku. Wczesną wiosną i jesienią aktywne są szczupaki i okonie. Starorzecze to jest mniej podatne na przyduchy i wysychanie, co zapewnia stabilne warunki przez większą część roku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21569, 7.5, 2.3, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Sum,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21570, 'Starorzecze Nowosiółki 11', 'starorzecze-nowosiolki-11-koden-21570', 'OXBOW', 51.7837761, 23.6108128, 'Województwo Lubelskie', 'Kodeń', 'Ten odcinek starorzecza jest stosunkowo płytki, z dnem pokrytym grubą warstwą mułu i rozkładającej się materii roślinnej. Brzegi są silnie zarośnięte trzciną i inną roślinnością szuwarową, co utrudnia swobodne poruszanie się. Woda jest często mętna, a jej powierzchnia miejscami pokryta rzęsą i grążelami. Jest to doskonałe środowisko dla karasia pospolitego i lina, które znajdują tu obfitość pokarmu i schronienia. Występuje tu również wzdręga, żerująca wśród roślinności. Wędkarstwo wymaga użycia lekkiego sprzętu i precyzyjnego zarzucania, aby uniknąć zaczepów. Latem, przy wysokich temperaturach, akwen jest narażony na niedobory tlenu, co może negatywnie wpływać na kondycję ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21570, 2.4, 1, 2.6, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21571, 'Starorzecze Nowosiółki 12', 'starorzecze-nowosiolki-12-koden-21571', 'OXBOW', 51.7841575, 23.6088195, 'Województwo Lubelskie', 'Kodeń', 'Starorzecze to cechuje się zróżnicowanym dnem, z partiami mulistymi i twardszymi, piaszczystymi. Brzegi są umiarkowanie zarośnięte, z kilkoma dogodnymi miejscami do wędkowania, zwłaszcza od strony pól. Roślinność wodna jest obfita w strefach przybrzeżnych, z dominacją trzcin i grążeli. Jest to dobre miejsce dla leszczy i płoci, które często tworzą tu duże ławice. Można tu również liczyć na szczupaka, który czai się w zaroślach. Wędkarze spinningowi znajdą tu ciekawe miejsca do obławiania. Starorzecze jest stosunkowo stabilne pod względem poziomu wody i natlenienia, co sprzyja aktywności ryb przez większą część sezonu. Bliskość Bugu zapewnia regularne zasilanie wodą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21571, 4.8, 1.6, 3.4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21572, 'Starorzecze Nowosiółki 13', 'starorzecze-nowosiolki-13-koden-21572', 'OXBOW', 51.783738, 23.6080685, 'Województwo Lubelskie', 'Kodeń', 'Ten niewielki fragment starorzecza jest silnie zamulony i otoczony gęstymi zaroślami, co nadaje mu kameralny charakter. Dno jest jednolicie muliste, z grubą warstwą osadów. Brzegi są praktycznie niedostępne bez brodzenia, z uwagi na bagniste podłoże i gęste szuwary. Roślinność wodna, taka jak rzęsa i grążele, pokrywa znaczną część powierzchni. Jest to idealne środowisko dla karasia pospolitego i lina, które osiągają tu imponujące rozmiary. Występuje tu również wzdręga, żerująca wśród roślinności. Wędkarstwo wymaga cierpliwości i umiejętności łowienia w trudnych warunkach. Latem, przy wysokich temperaturach, ryzyko przyduchy jest bardzo wysokie, co może wpływać na aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21572, 1.9, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21573, 'Starorzecze Nowosiółki 14', 'starorzecze-nowosiolki-14-koden-21573', 'OXBOW', 51.7803122, 23.5999039, 'Województwo Lubelskie', 'Kodeń', 'To starorzecze, choć oddalone od głównego nurtu, charakteryzuje się stabilnym poziomem wody i umiarkowanym zarośnięciem. Dno jest zróżnicowane, z partiami mulistymi i twardszymi, piaszczystymi. Brzegi są częściowo dostępne, z kilkoma dogodnymi miejscami do wędkowania. Roślinność wodna jest obecna, ale nie utrudnia znacząco łowienia, koncentrując się w strefach przybrzeżnych. Jest to dobre miejsce dla leszczy i płoci, które często tworzą tu duże ławice. Można tu również liczyć na szczupaka i okonia, szczególnie w strefach z roślinnością. Starorzecze jest stosunkowo odporne na wysychanie i przyduchy, co zapewnia stabilne warunki przez większą część roku. Bliskość Bugu podczas wezbrań zasila je wodą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21573, 6.2, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21574, 'Starorzecze Nowosiółki 15', 'starorzecze-nowosiolki-15-koden-21574', 'OXBOW', 51.7789278, 23.6016539, 'Województwo Lubelskie', 'Kodeń', 'Ten ostatni fragment starorzecza to płytki i silnie zarośnięty akwen, będący ostoją dla wielu gatunków ryb. Dno jest jednolicie muliste, z grubą warstwą osadów organicznych. Brzegi są praktycznie niedostępne bez brodzenia, z uwagi na gęste szuwary i bagniste podłoże. Cała powierzchnia wody jest pokryta grążelami i rzęsą, co tworzy unikalne środowisko. Jest to prawdziwy raj dla lina i karasia pospolitego, które czują się tu doskonale. Wczesną wiosną, zanim roślinność osiągnie pełnię wzrostu, można skutecznie polować na szczupaka. Wędkarstwo wymaga precyzji i cierpliwości, a także użycia odpowiedniego sprzętu do łowienia w zarośniętych miejscach. Wysokie temperatury latem zwiększają ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21574, 2.7, 1.1, 2.7, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21575, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21575', 'OXBOW', 51.7775735, 23.5990971, 'Województwo Lubelskie', 'Nowosiółki', 'To malownicze starorzecze, położone w pobliżu Nowosiółek, charakteryzuje się umiarkowanym zarośnięciem i średnim zamuleniem dna. Brzegi są w większości dostępne, choć w niektórych miejscach porośnięte trzciną, co zapewnia doskonałe kryjówki dla ryb. Wiosną i wczesną jesienią wędkarze mogą liczyć na udane połowy szczupaka, który aktywnie żeruje w płytszych partiach. Dno jest muliste z twardszymi fragmentami, a roślinność podwodna, taka jak wywłócznik, stanowi naturalne schronienie dla lina i płoci. Okresowo, podczas wysokich stanów wody, starorzecze łączy się z głównym nurtem, co sprzyja migracji ryb i odświeżaniu ekosystemu. Mimo że ryzyko przyduchy jest niskie, warto pamiętać o zachowaniu ciszy i spokoju, aby nie spłoszyć ostrożnych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21575, 3.2, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Płoć,Leszcz', 'Dobry z niektórych stron, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21576, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21576', 'OXBOW', 51.7770737, 23.6009328, 'Województwo Lubelskie', 'Nowosiółki', 'To niewielkie starorzecze w okolicy Nowosiółek jest przykładem akwenu o silnym zarośnięciu i wysokim stopniu zamulenia, co czyni je wymagającym łowiskiem. Brzegi są trudne do pokonania, często bagniste i gęsto porośnięte trzciną oraz inną roślinnością przybrzeżną, dlatego wędkarze muszą liczyć się z koniecznością użycia wodoodpornych spodni. Dno jest bardzo miękkie, bogate w osady organiczne, co sprzyja rozwojowi lina i karasia pospolitego. Ze względu na brak stałego połączenia z rzeką i intensywną wegetację, w upalne lata istnieje ryzyko przyduchy. Najlepsze wyniki osiąga się tutaj późną wiosną i latem, polując na ryby żerujące w gęstwinie roślinności. Występują tu również liczne wzdręgi i płocie, które preferują takie środowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21576, 2.8, 1.5, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, miejscami bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21577, 'Starorzecze (Sławatycze)', 'starorzecze-slawatycze-slawatycze-21577', 'OXBOW', 51.7759896, 23.5923592, 'Województwo Lubelskie', 'Sławatycze', 'To rozległe starorzecze w okolicach Sławatycz wyróżnia się stałym połączeniem z rzeką, co zapewnia doskonałą cyrkulację wody i niskie zamulenie. Dno jest w większości twarde, piaszczysto-żwirowe, z niewielką ilością roślinności podwodnej, co sprzyja aktywności drapieżników. Brzegi są łatwo dostępne z obu stron, oferując wiele wygodnych stanowisk wędkarskich, idealnych dla rodzinnych wypadów. W akwenie dominują szczupaki i okonie, ale licznie występują tu również leszcze i płocie, stanowiące podstawę diety drapieżników. Stały przepływ wody minimalizuje ryzyko przyduchy, czyniąc to łowisko atrakcyjnym przez cały sezon. Można tu także spotkać bolenie, które wpływają z głównego nurtu rzeki w poszukiwaniu drobnicy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21577, 5.5, 2.1, 4, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Boleń', 'Dobry z obu stron, liczne stanowiska', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21578, 'Starorzecze (Liszna)', 'starorzecze-liszna-liszna-21578', 'OXBOW', 51.7782519, 23.5738123, 'Województwo Lubelskie', 'Liszna', 'Starorzecze w Lisznej to mały i płytki akwen, charakteryzujący się bardzo silnym zarośnięciem i wysokim poziomem zamulenia, co czyni go trudnym, ale potencjalnie bardzo satysfakcjonującym łowiskiem. Brzegi są niemal niedostępne bez wodoodpornego obuwia, gęsto porośnięte trzciną i krzewami, co wymaga od wędkarzy cierpliwości i determinacji. Ze względu na niewielką głębokość i brak połączenia z rzeką, starorzecze to jest narażone na wysychanie w upalne lata, a ryzyko przyduchy jest wysokie. Dominują tu odporne gatunki ryb, takie jak karaś pospolity i lin, które doskonale radzą sobie w trudnych warunkach. Wiosna to najlepszy czas na połów, zanim roślinność osiągnie szczyt rozwoju. Dno jest miękkie, muliste, pełne zatopionych gałęzi i korzeni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21578, 1.9, 1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bardzo zarośnięty i bagnisty', TRUE, 'Gęsta roślinność podwodna i zatopione gałęzie', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21579, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21579', 'OXBOW', 51.7758216, 23.5961894, 'Województwo Lubelskie', 'Nowosiółki', 'To starorzecze w Nowosiółkach jest cenionym łowiskiem, oferującym dobre warunki do połowu różnorodnych gatunków ryb. Charakteryzuje się średnim zamuleniem i umiarkowanym zarośnięciem, co stwarza zróżnicowane środowisko dla ryb. Brzegi są dostępne, choć miejscami wymagają przetarcia ścieżek przez wyższą roślinność, co dodaje uroku dzikości. Dno jest zróżnicowane, od twardych, piaszczystych fragmentów po bardziej muliste, bogate w roślinność podwodną. Podczas wysokich stanów wody starorzecze łączy się z rzeką, co sprzyja naturalnemu zarybianiu i migracji ryb. Występują tu piękne okazy karpi i leszczy, a także liny i szczupaki, które chętnie polują w okolicach zatopionych drzew. Ryzyko przyduchy jest niskie, co sprawia, że łowisko jest atrakcyjne przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21579, 4.1, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Leszcz,Lin,Szczupak', 'Dostępny, ale wymaga przetarcia ścieżek', FALSE, 'Pojedyncze zatopione drzewa', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21580, 'Starorzecze (Terebiski)', 'starorzecze-terebiski-terebiski-21580', 'OXBOW', 51.7817696, 23.5893966, 'Województwo Lubelskie', 'Terebiski', 'Starorzecze w Terebiskach to przyjemne łowisko o niskim zamuleniu i słabym zarośnięciu, co ułatwia wędkowanie. Brzegi są dobrze dostępne, oferując sporo otwartych przestrzeni, idealnych do swobodnego rzucania. Dno jest w większości twarde, piaszczyste, z niewielką ilością roślinności, co sprzyja żerowaniu okoni i płoci. Podczas wiosennych roztopów lub obfitych deszczy, akwen łączy się z głównym nurtem rzeki, co wzbogaca populację ryb. Wędkarze mogą liczyć na obfite połowy okoni i płoci, a także na szczupaki, które patrolują płytsze partie wody. Jest to idealne miejsce na relaksujący dzień nad wodą, bez większych trudności technicznych. Ryzyko przyduchy jest minimalne, co zapewnia stabilne warunki przez większość roku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21580, 2.5, 1.7, 3, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Okoń,Płoć,Wzdręga,Szczupak', 'Dobry, sporo otwartych przestrzeni', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21581, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21581', 'OXBOW', 51.7865615, 23.590658, 'Województwo Lubelskie', 'Nowosiółki', 'To starorzecze w Nowosiółkach to spokojne łowisko, charakteryzujące się średnim zamuleniem i umiarkowanym zarośnięciem, co tworzy idealne warunki dla ryb spokojnego żeru. Brzegi są umiarkowanie dostępne, z miejscami porośniętymi trzciną, co zapewnia naturalne kryjówki dla ryb i wędkarzy. Dno jest muliste, bogate w osady organiczne, sprzyjające rozwojowi lina, karpia i karasia pospolitego. Brak stałego połączenia z rzeką oznacza stabilne warunki wodne, choć w upalne lata warto monitorować poziom tlenu. Najlepsze wyniki osiąga się tutaj późną wiosną i latem, kiedy ryby są najbardziej aktywne. Występują tu również leszcze, które chętnie żerują na mulistym dnie. Jest to idealne miejsce dla wędkarzy ceniących sobie ciszę i spokój.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21581, 3.8, 1.9, 3.8, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karp,Leszcz,Karaś pospolity', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i zatopione gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21582, 'Starorzecze (Terebiski)', 'starorzecze-terebiski-terebiski-21582', 'OXBOW', 51.7866715, 23.588474, 'Województwo Lubelskie', 'Terebiski', 'To niewielkie starorzecze w Terebiskach to ekstremalnie trudne, ale fascynujące łowisko, idealne dla poszukiwaczy dzikich miejsc. Charakteryzuje się bardzo płytką wodą, wysokim stopniem zamulenia i silnym zarośnięciem, co wymaga od wędkarzy dużej determinacji. Brzegi są niemal nieprzejezdne, gęsto porośnięte trzciną, krzewami i bagniste, dlatego wodery są absolutnie niezbędne. Ze względu na płytkość i brak połączenia z rzeką, akwen ten często wysycha w upalne lata, a ryzyko przyduchy jest bardzo wysokie. Dominują tu odporne gatunki, takie jak karaś srebrzysty, wzdręga i płoć, które doskonale radzą sobie w trudnych warunkach. Wiosna to najlepsza pora na wędkowanie, zanim roślinność całkowicie zdominuje akwen. Dno jest miękkie i pełne zatopionych korzeni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21582, 1.5, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Bardzo trudny, gęsto zarośnięty i bagnisty', TRUE, 'Gęsta roślinność podwodna i korzenie', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21583, 'Starorzecze (Mościce Dolne)', 'starorzecze-moscice-dolne-moscice-dolne-21583', 'OXBOW', 51.7732972, 23.5937605, 'Województwo Lubelskie', 'Mościce Dolne', 'To duże starorzecze w Mościcach Dolnych to jedno z najlepszych łowisk w regionie, dzięki stałemu połączeniu z rzeką i niskim zamuleniu. Charakteryzuje się znaczną głębokością i czystym, twardym dnem, co stwarza idealne warunki dla wielu gatunków ryb. Brzegi są bardzo dobrze dostępne, z licznymi pomostami i dogodnymi stanowiskami, co sprawia, że jest to popularne miejsce dla wędkarzy. W akwenie dominują drapieżniki, takie jak szczupak i sandacz, które znajdują tu obfitość pokarmu. Licznie występują tu również duże leszcze i okonie, a w głębszych partiach można spotkać suma. Stały przepływ wody eliminuje ryzyko przyduchy, co czyni łowisko atrakcyjnym przez cały rok. Jest to idealne miejsce zarówno dla początkujących, jak i doświadczonych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21583, 6, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Karp,Leszcz,Sum', 'Dobry, liczne pomosty i dogodne stanowiska', FALSE, 'Czyste dno, pojedyncze zaczepy', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21584, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21584', 'OXBOW', 51.7811245, 23.6250284, 'Województwo Lubelskie', 'Nowosiółki', 'To starorzecze, położone w okolicach Nowosiółek, charakteryzuje się umiarkowanym zamuleniem i zarośnięciem, co tworzy zróżnicowane środowisko dla ryb. Brzegi są umiarkowanie dostępne, z fragmentami porośniętymi trzciną, co zapewnia naturalne kryjówki dla ryb. Dno jest muliste, z twardszymi fragmentami, a roślinność podwodna, taka jak rdestnica, stanowi schronienie dla lina i płoci. Brak stałego połączenia z rzeką sprawia, że woda jest spokojna, idealna dla karpi. Wiosną i wczesną jesienią wędkarze mogą liczyć na udane połowy karpia, lina oraz szczupaka, który aktywnie żeruje w płytszych partiach. Ryzyko przyduchy jest niskie, co zapewnia stabilne warunki przez większość sezonu. Jest to idealne miejsce dla wędkarzy ceniących sobie spokój i obfitość ryb spokojnego żeru.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21584, 3, 1.6, 3.2, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karp,Płoć,Szczupak', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21585, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21585', 'OXBOW', 51.7751021, 23.6123885, 'Województwo Lubelskie', 'Nowosiółki', 'To niewielkie starorzecze w okolicach Nowosiółek to wymagające łowisko, charakteryzujące się wysokim stopniem zamulenia i silnym zarośnięciem. Brzegi są trudne do pokonania, często bagniste i gęsto porośnięte trzciną, co wymaga od wędkarzy użycia woderów. Dno jest bardzo miękkie, bogate w osady organiczne, co sprzyja rozwojowi lina i karasia pospolitego. Ze względu na brak stałego połączenia z rzeką i intensywną wegetację, w upalne lata istnieje ryzyko przyduchy, dlatego warto monitorować warunki. Najlepsze wyniki osiąga się tutaj późną wiosną i latem, polując na ryby żerujące w gęstwinie roślinności. Występują tu również liczne wzdręgi, które preferują takie środowiska. Jest to miejsce dla wędkarzy ceniących sobie wyzwania i dzikość przyrody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21585, 2.2, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty i gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna i zatopione gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21586, 'Starorzecze (Trawniki)', 'starorzecze-trawniki-trawniki-powiat-bochenski-21586', 'OXBOW', 50.1374376, 20.4081432, 'Województwo Małopolskie', 'Trawniki (powiat bocheński)', 'To duże i głębokie starorzecze w Trawnikach, w województwie małopolskim, jest jednym z najbardziej atrakcyjnych łowisk w regionie. Charakteryzuje się stałym połączeniem z Wisłą, co zapewnia doskonałą jakość wody i niskie zamulenie. Brzegi są dobrze dostępne, częściowo umocnione, co ułatwia wędkowanie i zapewnia komfortowe stanowiska. Dno jest zróżnicowane, od twardych, piaszczystych po muliste, z pojedynczymi zatopionymi drzewami stanowiącymi kryjówki dla ryb. W akwenie dominują duże sumy i sandacze, ale można tu również złowić okazałe karpie, leszcze i szczupaki. Stały przepływ wody minimalizuje ryzyko przyduchy, czyniąc to łowisko atrakcyjnym przez cały sezon. Jest to idealne miejsce dla wędkarzy poszukujących dużych drapieżników i ryb spokojnego żeru.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21586, 7.5, 3, 6, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Sandacz,Karp,Leszcz,Szczupak', 'Dobry, częściowo umocnione brzegi', FALSE, 'Pojedyncze zatopione drzewa', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21587, 'Starorzecze (Trawniki)', 'starorzecze-trawniki-trawniki-powiat-bochenski-21587', 'OXBOW', 50.1377526, 20.4064441, 'Województwo Małopolskie', 'Trawniki (powiat bocheński)', 'To rozległe starorzecze w Trawnikach, choć nieco mniejsze od sąsiedniego, również oferuje doskonałe warunki wędkarskie. Charakteryzuje się niskim zamuleniem i umiarkowanym zarośnięciem, co zapewnia zróżnicowane środowisko dla ryb. Brzegi są w większości dostępne, choć miejscami wymagają przetarcia ścieżek przez wyższą roślinność, co dodaje uroku dzikości. Podczas wysokich stanów wody starorzecze łączy się z Wisłą, co sprzyja migracji ryb i odświeżaniu ekosystemu. W akwenie dominują szczupaki i leszcze, ale licznie występują tu również płocie, karpie i okonie. Dno jest zróżnicowane, od twardych, piaszczystych po muliste, z pojedynczymi zatopionymi gałęziami. Jest to idealne miejsce dla wędkarzy ceniących sobie różnorodność gatunków i spokojne otoczenie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21587, 6.8, 2.8, 5.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Karp,Okoń', 'Dobry, ale miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i zatopione gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21588, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21588', 'OXBOW', 51.7976734, 23.6346817, 'Województwo Lubelskie', 'Hanna', 'To starorzecze w okolicach Hanny to spokojne i malownicze łowisko, charakteryzujące się średnim zamuleniem i umiarkowanym zarośnięciem. Brzegi są umiarkowanie dostępne, z fragmentami porośniętymi gęstą trzciną, co stanowi doskonałe kryjówki dla ryb i dodaje uroku dzikości. Dno jest muliste, z twardszymi fragmentami, a roślinność podwodna jest umiarkowana, co sprzyja rozwojowi lina i karpia. Brak stałego połączenia z rzeką oznacza stabilne warunki wodne, choć w upalne lata warto monitorować poziom tlenu. Najlepsze wyniki osiąga się tutaj późną wiosną i latem, kiedy ryby są najbardziej aktywne. Występują tu również leszcze i szczupaki, które chętnie żerują w okolicach zatopionych drzew i korzeni. Jest to idealne miejsce dla wędkarzy ceniących sobie ciszę i kontakt z naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21588, 4.5, 2, 4, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karp,Leszcz,Szczupak', 'Umiarkowany, miejscami zarośnięty trzciną', FALSE, 'Pojedyncze zatopione drzewa i korzenie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21589, 'Starorzecze (Hanna)', 'starorzecze-hanna-hanna-21589', 'OXBOW', 51.7972202, 23.6340588, 'Województwo Lubelskie', 'Hanna', 'To starorzecze w okolicach Hanny to popularne łowisko, oferujące dobre warunki do połowu różnorodnych gatunków ryb. Charakteryzuje się średnim zamuleniem i umiarkowanym zarośnięciem, co tworzy zróżnicowane środowisko dla ryb. Brzegi są dobrze dostępne, choć miejscami wymagają uwagi ze względu na wyższą roślinność, co dodaje uroku dzikości. Dno jest zróżnicowane, od twardszych, piaszczystych fragmentów po bardziej muliste, bogate w roślinność podwodną. Brak stałego połączenia z rzeką sprawia, że woda jest spokojna, idealna dla płoci i leszczy. Wiosną i wczesną jesienią wędkarze mogą liczyć na udane połowy płoci, leszczy oraz szczupaka, który aktywnie żeruje w płytszych partiach. Ryzyko przyduchy jest niskie, co zapewnia stabilne warunki przez większość sezonu. Jest to idealne miejsce dla wędkarzy ceniących sobie spokój i obfitość ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21589, 3.5, 1.8, 3.5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry, ale wymaga uwagi ze względu na roślinność', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21590, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21590', 'OXBOW', 51.7968059, 23.6336886, 'Województwo Lubelskie', 'Włodawa', 'To malownicze starorzecze rzeki Bug, charakteryzujące się spokojną taflą wody i bogatą bioróżnorodnością. Dno jest głównie muliste, z licznymi osadami organicznymi, co sprzyja rozwojowi gęstej roślinności podwodnej, takiej jak rogatek i moczarka. Brzegi są w większości porośnięte trzcinami i krzewami, co utrudnia swobodny dostęp, ale jednocześnie tworzy doskonałe kryjówki dla ryb. Wędkarze mogą tu liczyć na obfite połowy płoci, leszczy i karasi pospolitych, a także na spotkania z linem i wzdręgą. Łowisko jest szczególnie atrakcyjne wiosną i wczesną jesienią, kiedy aktywność ryb jest największa. Należy przygotować się na konieczność brodzenia i korzystania z pontonu lub łódki w niektórych miejscach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21590, 3.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Karaś pospolity,Lin,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21591, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21591', 'OXBOW', 51.7964157, 23.633165, 'Województwo Lubelskie', 'Włodawa', 'To starorzecze o wydłużonym kształcie, powstałe w wyniku meandrowania rzeki Bug, znane z obecności drapieżników. Dno akwenu jest zróżnicowane, z fragmentami piaszczystymi przeplatanymi z grubą warstwą mułu, a także z licznymi zatopionymi korzeniami i gałęziami. Roślinność brzegowa jest gęsta, tworząc naturalne bariery, jednak w kilku miejscach znajdują się dogodne stanowiska wędkarskie. Dominującymi gatunkami są szczupak i okoń, które aktywnie polują wśród podwodnych zarośli i zatopionych drzew. Poza drapieżnikami, można tu złowić piękne liny i karasie, szczególnie w cieplejszych miesiącach. Wędkowanie wymaga cierpliwości i precyzyjnych rzutów, a także odpowiedniego sprzętu do radzenia sobie z zaczepami. Najlepsze wyniki osiąga się późną wiosną i latem, zwłaszcza o świcie i zmierzchu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21591, 5.1, 2.1, 5, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Okoń,Lin,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21592, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21592', 'OXBOW', 51.7962419, 23.6333413, 'Województwo Lubelskie', 'Włodawa', 'To wymagające starorzecze, które jednak potrafi wynagrodzić wytrwałych wędkarzy okazałymi okazami ryb. Charakteryzuje się znacznym stopniem zamulenia dna, co sprawia, że jest ono miękkie i bogate w substancje odżywcze, idealne dla ryb karpiowatych. Brzegi są w wielu miejscach podmokłe i trudno dostępne, często zarośnięte wysokimi trawami i krzewami, co wymaga użycia wodoodpornego obuwia. Akwen obfituje w gęstą roślinność podwodną, która stanowi naturalne schronienie dla lina, karasia pospolitego i dużych leszczy. Występuje tu również szczupak, czyhający w zasadzkach. Wędkowanie z pontonu lub niewielkiej łódki może znacznie ułatwić dostęp do najbardziej obiecujących miejsc, szczególnie w okresach intensywnego wzrostu roślin. Ryzyko przyduchy jest umiarkowane, ale warto monitorować poziom tlenu w upalne lata.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21592, 2.8, 1.2, 3.1, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Leszcz,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21593, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21593', 'OXBOW', 51.7960698, 23.6330114, 'Województwo Lubelskie', 'Włodawa', 'To niewielkie, lecz głębokie starorzecze, które zaskakuje różnorodnością gatunków ryb. Dno charakteryzuje się zmienną strukturą, od piaszczystych płycizn po głębokie, muliste rynny, co sprzyja różnym formom życia. Brzegi są częściowo zarośnięte, ale znajdziemy tu również otwarte przestrzenie umożliwiające swobodne wędkowanie z gruntu. Akwen ten jest domem dla dorodnych leszczy i płoci, a także dla karasi srebrzystych, które dobrze czują się w jego wodach. W głębszych partiach można spotkać suma, zwłaszcza w cieplejszych miesiącach, co czyni to miejsce atrakcyjnym dla wędkarzy poszukujących większych okazów. Należy jednak pamiętać o zmiennym ukształtowaniu dna i możliwych zaczepach. Najlepsze efekty daje wędkowanie z łodzi, co pozwala na eksplorację całego łowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21593, 1.9, 2.5, 6.2, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karaś srebrzysty,Sum', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21594, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21594', 'OXBOW', 51.7957928, 23.631789, 'Województwo Lubelskie', 'Włodawa', 'To starorzecze o charakterze typowo nadrzecznym, z wyraźnymi wpływami wód Bugu podczas wysokich stanów. Dno jest przeważnie piaszczysto-muliste, z licznymi zagłębieniami i nierównościami, co tworzy zróżnicowane siedliska dla ryb. Brzegi są dość łatwo dostępne w wielu miejscach, choć lokalnie mogą występować strefy zarośnięte trzciną. W akwenie dominują płocie i leszcze, ale często trafiają się również jazie i klenie, które wpływają tu z rzeki. Obecność bolenia świadczy o czystości wody i jej połączeniu z głównym nurtem. Wędkowanie na spławik i grunt daje tu bardzo dobre rezultaty, a spinningiści mogą liczyć na bolenie i szczupaki. To łowisko szczególnie polecane dla wędkarzy ceniących sobie różnorodność gatunków i aktywny połów. Najlepsze warunki panują wczesną wiosną i jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21594, 4.5, 1.8, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Jaź,Boleń,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21595, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21595', 'OXBOW', 51.7933816, 23.6285307, 'Województwo Lubelskie', 'Włodawa', 'To płytkie i silnie zarośnięte starorzecze, będące ostoją dla wielu gatunków ryb spokojnego żeru. Dno jest niemal w całości pokryte grubą warstwą mułu i obfituje w podwodną roślinność, taką jak rzęsa wodna i grążele, co wymaga specjalistycznego sprzętu. Brzegi są trudno dostępne, często bagniste i mocno zarośnięte, co sprawia, że łowienie z brzegu jest wyzwaniem. Akwen jest idealnym miejscem dla lina i karasia pospolitego, które doskonale czują się w takich warunkach. Występuje tu również wzdręga, żerująca wśród roślinności nawodnej. Ze względu na dużą ilość biomasy, ryzyko przyduchy w upalne lato jest wysokie. Wędkowanie z pontonu lub brodzenie w woderach to często jedyna opcja, aby dotrzeć do obiecujących miejsc. Najlepsze wyniki osiąga się wczesnym latem, zanim roślinność osiągnie swój szczyt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21595, 2.5, 0.9, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21596, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21596', 'OXBOW', 51.7935114, 23.6281733, 'Województwo Lubelskie', 'Włodawa', 'To starorzecze o umiarkowanej głębokości, z dobrze rozwiniętą strefą litoralu, co sprzyja różnorodności gatunków. Dno jest mieszane, z przewagą mułu, ale z występującymi miejscami twardszymi, piaszczystymi. Brzegi są częściowo dostępne, z fragmentami porośniętymi trzciną i wierzbami, które stanowią naturalne osłony dla ryb. Akwen jest znany z populacji karpia, który regularnie odławiany jest przez wędkarzy, a także z dorodnych leszczy i płoci. Występują tu również szczupaki i okonie, polujące w pobliżu zarośli. Wędkowanie z gruntu i na spławik jest bardzo efektywne, zwłaszcza w miejscach z większą ilością roślinności. Jest to łowisko o dobrym potencjale, ale wymaga cierpliwości i znajomości miejscówek. Najlepsze rezultaty osiąga się w cieplejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21596, 3.8, 1.7, 4.1, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Leszcz,Płoć,Szczupak,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21597, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21597', 'OXBOW', 51.7933625, 23.6246617, 'Województwo Lubelskie', 'Włodawa', 'To starorzecze, które jest przykładem dynamicznego ekosystemu, z wyraźnymi zmianami w poziomie wody w zależności od pory roku. Dno jest zróżnicowane, z przewagą mułu, ale z licznymi zatopionymi gałęziami i roślinnością podwodną. Brzegi są dość trudne do pokonania, często bagniste i silnie zarośnięte, co wymaga odpowiedniego przygotowania. W akwenie dominują płocie i leszcze, ale często można tu złowić także liny i karasie pospolite, które dobrze adaptują się do zmiennych warunków. Występuje tu również okoń, polujący na mniejsze ryby. Wędkowanie wymaga cierpliwości i umiejętności odnajdywania wolnych od zaczepów miejsc. Ryzyko przyduchy jest realne w okresach suszy i upałów, dlatego warto zachować ostrożność. Łowisko jest najbardziej obiecujące wiosną i wczesną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21597, 3.5, 1.4, 3.6, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Płoć,Leszcz,Lin,Karaś pospolity,Okoń', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21598, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21598', 'OXBOW', 51.8135875, 23.6200737, 'Województwo Lubelskie', 'Włodawa', 'To rozległe starorzecze, charakteryzujące się dużą powierzchnią i zróżnicowaną głębokością, co sprzyja bogactwu ryb. Dno jest przeważnie muliste, ale z licznymi wypłyceniami i głębszymi rynnami, gdzie gromadzą się większe okazy. Brzegi są w wielu miejscach dostępne, choć lokalnie mogą być zarośnięte pasami trzcin i krzewów, co wymaga poszukiwania dogodnych stanowisk. Akwen jest idealnym miejscem dla wędkarzy poszukujących leszczy, płoci i karasi srebrzystych, które występują tu w dużych ilościach. Można tu również złowić szczupaka i okonia, szczególnie w pobliżu podwodnych przeszkód. Regularne połączenie z Bugiem podczas wysokiej wody zapewnia dopływ świeżej wody i nowych ryb. Wędkowanie z łodzi jest bardzo efektywne, pozwalając na dotarcie do najciekawszych miejsc. Cały sezon oferuje dobre warunki do wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21598, 12, 2, 5.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karaś srebrzysty,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21599, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21599', 'OXBOW', 51.8164744, 23.6177529, 'Województwo Lubelskie', 'Włodawa', 'To starorzecze o charakterze typowo lądowym, z niewielkim wpływem wód rzecznych, co sprzyja rozwojowi stabilnej populacji ryb. Dno jest w większości muliste, z grubą warstwą osadów, co jest typowe dla starorzeczy odciętych od głównego nurtu. Brzegi są gęsto porośnięte trzciną i inną roślinnością przybrzeżną, co wymaga poszukiwania dogodnych do łowienia miejsc. Akwen jest prawdziwym królestwem lina i karasia pospolitego, które osiągają tu imponujące rozmiary. Występuje tu również wzdręga i płoć, żerujące w płytszych partiach. Ze względu na bujną roślinność i ograniczoną cyrkulację wody, ryzyko przyduchy jest podwyższone, zwłaszcza w upalne lata. Wędkowanie z pomostu lub pontonu jest często najlepszym rozwiązaniem. Najlepsze wyniki osiąga się wczesnym latem i jesienią, kiedy ryby intensywnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21599, 6.3, 1.1, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21600, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21600', 'OXBOW', 51.8082255, 23.6265365, 'Województwo Lubelskie', 'Włodawa', 'To starorzecze o umiarkowanej wielkości, z dobrze rozwiniętymi strefami roślinności podwodnej, oferujące schronienie dla wielu gatunków ryb. Dno jest przeważnie muliste, ale z twardszymi fragmentami wzdłuż dawnego koryta rzeki, co tworzy ciekawe miejsca do wędkowania. Brzegi są częściowo dostępne, z licznymi miejscami do zarzucenia wędki, choć lokalnie mogą być zarośnięte. Akwen jest domem dla dorodnych leszczy, płoci i karasi srebrzystych, a także dla szczupaków i okoni, które aktywnie polują. Wędkowanie z gruntu i na spławik daje tu bardzo dobre rezultaty, zwłaszcza w pobliżu zarośli. Jest to łowisko o dużym potencjale, idealne dla wędkarzy poszukujących różnorodności gatunków. Najlepsze warunki panują wczesną wiosną i jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21600, 4.1, 1.6, 4, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karaś srebrzysty,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21601, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21601', 'OXBOW', 51.8071536, 23.6271192, 'Województwo Lubelskie', 'Włodawa', 'To starorzecze o umiarkowanej głębokości, z dobrze rozwiniętą strefą litoralu, co sprzyja różnorodności gatunków. Dno jest mieszane, z przewagą mułu, ale z występującymi miejscami twardszymi, piaszczystymi. Brzegi są częściowo dostępne, z fragmentami porośniętymi trzciną i wierzbami, które stanowią naturalne osłony dla ryb. Akwen ten jest domem dla dorodnych leszczy i płoci, a także dla karasi srebrzystych, które dobrze czują się w jego wodach. W głębszych partiach można spotkać suma, zwłaszcza w cieplejszych miesiącach, co czyni to miejsce atrakcyjnym dla wędkarzy poszukujących większych okazów. Występują tu również szczupaki i okonie, polujące w pobliżu zarośli. Wędkowanie z gruntu i na spławik jest bardzo efektywne, zwłaszcza w miejscach z większą ilością roślinności. Najlepsze rezultaty osiąga się w cieplejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21601, 3.8, 1.7, 4.1, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Leszcz,Płoć,Szczupak,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21602, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21602', 'OXBOW', 51.8079622, 23.6288344, 'Województwo Lubelskie', 'Włodawa', 'To starorzecze, które jest przykładem dynamicznego ekosystemu, z wyraźnymi zmianami w poziomie wody w zależności od pory roku. Dno jest zróżnicowane, z przewagą mułu, ale z licznymi zatopionymi gałęziami i roślinnością podwodną. Brzegi są dość trudne do pokonania, często bagniste i silnie zarośnięte, co wymaga odpowiedniego przygotowania. W akwenie dominują płocie i leszcze, ale często można tu złowić także liny i karasie pospolite, które dobrze adaptują się do zmiennych warunków. Występuje tu również okoń, polujący na mniejsze ryby. Wędkowanie wymaga cierpliwości i umiejętności odnajdywania wolnych od zaczepów miejsc. Ryzyko przyduchy jest realne w okresach suszy i upałów, dlatego warto zachować ostrożność. Łowisko jest najbardziej obiecujące wiosną i wczesną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21602, 3.5, 1.4, 3.6, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Płoć,Leszcz,Lin,Karaś pospolity,Okoń', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21603, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21603', 'OXBOW', 51.8099842, 23.6308307, 'Województwo Lubelskie', 'Włodawa', 'To starorzecze o znacznym stopniu zamulenia, będące idealnym środowiskiem dla ryb karpiowatych i linów. Dno jest miękkie i bogate w substancje organiczne, co sprzyja rozwojowi bujnej roślinności podwodnej. Brzegi są często podmokłe i trudno dostępne, z licznymi zaroślami, które wymagają ostrożności podczas poruszania się. Akwen jest znany z dużych linów i karasi pospolitych, a także dorodnych płoci i leszczy. Występuje tu również szczupak, czyhający w gęstych zaroślach. Wędkowanie z pontonu lub brodzenie w woderach jest często konieczne, aby dotrzeć do najlepszych miejscówek. Ze względu na płytkość i obfitość roślinności, ryzyko przyduchy w upalne lato jest wysokie. Najlepsze wyniki osiąga się wczesnym latem, gdy ryby intensywnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21603, 2.9, 1, 2.9, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Leszcz,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21604, 'Starorzecze Bugu k. Włodawy', 'starorzecze-bugu-k-wlodawy-wlodawa-21604', 'OXBOW', 51.8087159, 23.6338669, 'Województwo Lubelskie', 'Włodawa', 'To starorzecze o wyraźnym połączeniu z rzeką Bug podczas wysokich stanów wody, co zapewnia regularne zarybianie i dopływ świeżej wody. Dno jest zróżnicowane, z piaszczystymi fragmentami, żwirowymi spadkami i mulistymi zagłębieniami, co tworzy idealne warunki dla wielu gatunków. Brzegi są w większości łatwo dostępne, choć lokalnie mogą występować strefy zarośnięte drzewami i krzewami. Akwen jest znany z obecności sandacza, który wpływa tu z rzeki, a także z dorodnych leszczy, płoci i okoni. Można tu również złowić bolenia i jazia, szczególnie w miejscach z silniejszym prądem podczas połączenia z rzeką. Wędkowanie spinningowe i gruntowe jest bardzo efektywne. To łowisko dla wędkarzy ceniących sobie aktywne poszukiwanie ryb i różnorodność metod. Najlepsze warunki panują wiosną i jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21604, 6.8, 2.2, 6.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sandacz,Leszcz,Płoć,Okoń,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21605, 'Starorzecze Zbereże Północne', 'starorzecze-zbereze-polnocne-wlodawa-21605', 'OXBOW', 51.8084903, 23.6325761, 'Lubelskie', 'Włodawa', 'To starorzecze, położone w malowniczej dolinie Bugu, charakteryzuje się bogatą roślinnością brzegową, głównie trzciną i pałką wodną, co czyni je idealnym siedliskiem dla wielu gatunków ryb. Dno jest muliste, z licznymi zatopionymi korzeniami i gałęziami, co stwarza doskonałe kryjówki dla drapieżników. Średnia głębokość wynosi około 1.5 metra, ale w niektórych miejscach, zwłaszcza w rynnach, może dochodzić do 3 metrów. Wiosną, podczas wysokiego stanu wody, starorzecze łączy się z głównym nurtem rzeki, co sprzyja migracji ryb. Jest to łowisko typowo linowo-szczupakowe, z obfitością płoci i karasi. Dostęp do brzegów jest umiarkowany, często wymaga przedzierania się przez zarośla, co dodaje mu dzikiego charakteru.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21605, 3.2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Szczupak,Płoć,Karaś pospolity', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21606, 'Starorzecze Zbereże Środkowe', 'starorzecze-zbereze-srodkowe-wlodawa-21606', 'OXBOW', 51.8078117, 23.6326164, 'Lubelskie', 'Włodawa', 'To starorzecze, choć niewielkie, jest bardzo cenionym łowiskiem ze względu na swoją bioróżnorodność i stosunkowo łatwy dostęp w niektórych miejscach. Jego brzegi są częściowo zalesione, co zapewnia cień i schronienie dla ryb w upalne dni. Dno jest zróżnicowane, od twardego piasku po grube warstwy mułu w głębszych partiach, co sprzyja różnym gatunkom. Głębokość waha się od 0.8 do 2.5 metra, a woda jest zazwyczaj klarowna, z obfitością roślinności podwodnej, takiej jak rogatek czy moczarka. Połączenie z rzeką Bug jest sporadyczne, tylko przy bardzo wysokim stanie wody, co sprzyja stabilności populacji ryb. Jest to raj dla wędkarzy poszukujących lina, karasia i wzdręgi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21606, 1.8, 1.2, 2.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21607, 'Starorzecze Zbereże Zachodnie', 'starorzecze-zbereze-zachodnie-wlodawa-21607', 'OXBOW', 51.8066586, 23.6289672, 'Lubelskie', 'Włodawa', 'To starorzecze charakteryzuje się bardziej otwartymi brzegami, choć wciąż z licznymi kępami trzcin, które oferują schronienie dla drobnicy. Dno jest w większości piaszczysto-muliste, z rzadziej występującymi zaczepami, co ułatwia wędkowanie z gruntu. Głębokość średnia wynosi około 1.8 metra, z maksymalnymi dołkami sięgającymi 3.5 metra, gdzie chętnie przebywają większe osobniki. Akwen ten jest dość dobrze natleniony, co minimalizuje ryzyko przyduchy, nawet w upalne lata. Połączenie z Bugiem jest rzadkie, co sprzyja rozwojowi stabilnej populacji ryb, w tym dużych szczupaków i karpi. Dostęp do łowiska jest stosunkowo łatwy, z kilkoma dogodnymi stanowiskami wędkarskimi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21607, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Karp,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21608, 'Starorzecze Nowosiółki Duże', 'starorzecze-nowosiolki-duze-nowosiolki-21608', 'OXBOW', 51.7927433, 23.6069208, 'Lubelskie', 'Nowosiółki', 'Jedno z większych starorzeczy w okolicy Nowosiółek, znane z głębokich rynien i obfitości ryb drapieżnych, zwłaszcza sumów i dużych szczupaków. Brzegi są gęsto porośnięte trzciną i krzewami, co utrudnia dostęp, ale jednocześnie zapewnia doskonałe schronienie dla ryb. Dno jest nierówne, z licznymi zaczepami w postaci zatopionych drzew i gałęzi, co wymaga precyzyjnego wędkowania. Średnia głębokość oscyluje wokół 2.5 metra, z dołkami dochodzącymi nawet do 6 metrów, gdzie często żerują sumy. Akwen ten rzadko wysycha i utrzymuje stabilny poziom wody, co sprzyja rozwojowi dużych osobników. Wędkowanie tutaj to prawdziwe wyzwanie, ale nagroda w postaci okazowych ryb jest często tego warta.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21608, 8, 2.5, 6, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Sum,Szczupak,Okoń,Leszcz', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21609, 'Starorzecze Nowosiółki Małe', 'starorzecze-nowosiolki-male-nowosiolki-21609', 'OXBOW', 51.7945673, 23.612127, 'Lubelskie', 'Nowosiółki', 'To mniejsze starorzecze, położone nieco na uboczu, jest oazą spokoju i idealnym miejscem na relaksujące wędkowanie. Charakteryzuje się płytkimi brzegami, gęsto porośniętymi roślinnością zanurzoną, co stanowi doskonałe żerowisko dla drobnicy i lina. Dno jest w przeważającej części muliste, z niewielką ilością zaczepów, co ułatwia wędkowanie spławikowe. Średnia głębokość to zaledwie 1.0 metra, z maksymalnymi głębokościami nieprzekraczającymi 2 metrów, co sprawia, że woda szybko się nagrzewa. Połączenie z Bugiem jest bardzo rzadkie, co przyczynia się do niskiego ryzyka wahań poziomu wody. Jest to doskonałe łowisko na lina, karasia i wzdręgę, szczególnie w cieplejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21609, 2.5, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21610, 'Starorzecze Włodawa Północne', 'starorzecze-wlodawa-polnocne-wlodawa-21610', 'OXBOW', 51.800344, 23.6188573, 'Lubelskie', 'Włodawa', 'To starorzecze, zlokalizowane bliżej Włodawy, jest popularnym miejscem wśród lokalnych wędkarzy ze względu na łatwy dostęp i bogactwo ryb. Brzegi są częściowo utwardzone, z miejscami do rozstawienia sprzętu, choć nadal występują obszary z gęstą roślinnością. Dno jest zróżnicowane, od twardego żwiru po miękki muł, co przyciąga różnorodne gatunki ryb. Średnia głębokość wynosi około 1.7 metra, z głębszymi partiami do 3.5 metra, gdzie można spotkać większe leszcze i karpie. Połączenie z rzeką jest okresowe, co pozwala na odnawianie się populacji ryb. Akwen ten jest dobrze znany z obfitości leszczy i płoci, a także okazjonalnych karpi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21610, 4, 1.7, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21611, 'Starorzecze Włodawa Zachodnie', 'starorzecze-wlodawa-zachodnie-wlodawa-21611', 'OXBOW', 51.7988495, 23.6159364, 'Lubelskie', 'Włodawa', 'Charakteryzujące się długim i wąskim kształtem, to starorzecze jest pozostałością po meandrującym nurcie Bugu. Brzegi są gęsto zarośnięte drzewami i krzewami, co tworzy naturalne tunele i zacienione miejsca, idealne dla drapieżników. Dno jest w większości muliste, z licznymi zatopionymi konarami i liśćmi, co utrudnia wędkowanie gruntowe. Średnia głębokość wynosi około 1.4 metra, z maksymalnymi dołkami do 2.8 metra, gdzie często bytują szczupaki. Połączenie z rzeką jest rzadkie, co sprawia, że woda jest spokojna i sprzyja rozwojowi roślinności. Jest to idealne miejsce dla wędkarzy polujących na szczupaka, okonia i lina, wymagające jednak cierpliwości i precyzji.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21611, 2.9, 1.4, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Szczupak,Okoń,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21612, 'Starorzecze Włodawa Centralne', 'starorzecze-wlodawa-centralne-wlodawa-21612', 'OXBOW', 51.7988131, 23.6169758, 'Lubelskie', 'Włodawa', 'To starorzecze, położone w sąsiedztwie innych akwenów, wyróżnia się zróżnicowanym charakterem. W części północnej brzegi są bardziej dostępne, natomiast w południowej dominują gęste zarośla trzcin i krzewów. Dno jest mieszane, od piaszczystych płycizn po głębokie, muliste rynny, co sprzyja różnorodności gatunkowej. Średnia głębokość wynosi około 1.6 metra, z maksymalnymi dołkami sięgającymi 3.2 metra, gdzie można znaleźć większe okazy. Akwen ten ma sporadyczne połączenie z Bugiem, co od czasu do czasu wzbogaca jego faunę. Jest to dobre łowisko na leszcze, płocie i karasie, a także na drapieżniki takie jak szczupak i okoń.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21612, 3.8, 1.6, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karaś pospolity,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21613, 'Starorzecze Włodawa Południowe', 'starorzecze-wlodawa-poludniowe-wlodawa-21613', 'OXBOW', 51.7968291, 23.6174659, 'Lubelskie', 'Włodawa', 'To starorzecze jest jednym z bardziej zarośniętych w okolicy, co sprawia, że jest rajem dla lina i karasia. Brzegi są niemal całkowicie pokryte gęstą trzciną i roślinnością przybrzeżną, co utrudnia dostęp, ale zapewnia doskonałe warunki żerowania. Dno jest w przeważającej części bardzo muliste, z grubą warstwą osadów organicznych, co jest typowe dla starych, wolno zamulających się akwenów. Średnia głębokość to zaledwie 1.1 metra, z maksymalnymi głębokościami do 2.3 metra, a woda jest często mętna. Akwen ten rzadko łączy się z rzeką, co sprzyja rozwojowi specyficznej fauny i flory. Wędkowanie tutaj wymaga cierpliwości i umiejętności, ale nagradza pięknymi okazami lina i karasia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21613, 2.2, 1.1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21614, 'Starorzecze Zbereże Wschodnie', 'starorzecze-zbereze-wschodnie-wlodawa-21614', 'OXBOW', 51.8059036, 23.6351356, 'Lubelskie', 'Włodawa', 'To starorzecze, położone w bliskim sąsiedztwie Bugu, jest często zasilane przez rzekę podczas wiosennych roztopów, co utrzymuje jego żyzność. Brzegi są mieszane, z fragmentami piaszczystymi i obszarami porośniętymi trzciną, co oferuje różnorodne miejsca do wędkowania. Dno jest głównie piaszczysto-muliste, z mniejszą ilością zaczepów niż w innych, bardziej dzikich starorzeczach, co ułatwia prowadzenie przynęt. Średnia głębokość wynosi około 1.9 metra, z głębokimi partiami do 4.0 metrów, gdzie chętnie przebywają większe drapieżniki. Dzięki regularnemu połączeniu z rzeką, akwen ten charakteryzuje się bogatą populacją ryb, w tym sandacza i bolenia, które migrują z Bugu. Jest to atrakcyjne łowisko dla wędkarzy ceniących różnorodność gatunkową i dobry dostęp.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21614, 5.5, 1.9, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sandacz,Boleń,Szczupak,Leszcz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21615, 'Starorzecze Zbereże Południowe', 'starorzecze-zbereze-poludniowe-wlodawa-21615', 'OXBOW', 51.804811, 23.6359712, 'Lubelskie', 'Włodawa', 'To starorzecze, choć położone blisko innych, ma swój unikalny charakter, wyróżniając się stosunkowo czystą wodą i twardym, piaszczystym dnem w wielu miejscach. Brzegi są dość otwarte, z rzadkimi kępami trzcin, co ułatwia zarzucanie wędki z brzegu. Głębokość jest zmienna, od płytkich, słonecznych zatoczek o głębokości 0.5 metra, po głębsze rynny do 3.0 metrów. Akwen ten rzadko łączy się z Bugiem, co sprzyja rozwojowi stabilnej populacji karasi srebrzystych i płoci. Ryzyko przyduchy jest niskie, a woda jest zazwyczaj dobrze natleniona. Jest to idealne miejsce dla początkujących wędkarzy i rodzin, ze względu na łatwy dostęp i liczne brania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21615, 2.7, 1.3, 3, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Karaś srebrzysty,Płoć,Wzdręga,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21616, 'Starorzecze Włodawa Środkowe', 'starorzecze-wlodawa-srodkowe-wlodawa-21616', 'OXBOW', 51.8015976, 23.6271125, 'Lubelskie', 'Włodawa', 'To starorzecze jest przykładem akwenu, który powoli, ale sukcesywnie zamula się, tworząc idealne warunki dla ryb karpiowatych. Brzegi są gęsto porośnięte roślinnością, zwłaszcza trzciną i moczarką, co zapewnia doskonałe schronienie dla lina i karasia. Dno jest głęboko muliste, z licznymi osadami organicznymi, co jest typowe dla starorzeczy w zaawansowanym stadium sukcesji. Średnia głębokość wynosi około 1.2 metra, z maksymalnymi dołkami nieprzekraczającymi 2.5 metra. Akwen ten sporadycznie łączy się z rzeką, co pozwala na migrację ryb, ale główna populacja jest stabilna. Jest to doskonałe łowisko dla wędkarzy gruntowych, poszukujących dużych linów i karasi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21616, 3.5, 1.2, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karp,Karaś pospolity,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21617, 'Starorzecze Zbereże Wschodnie II', 'starorzecze-zbereze-wschodnie-ii-wlodawa-21617', 'OXBOW', 51.8054405, 23.6378923, 'Lubelskie', 'Włodawa', 'To starorzecze jest jednym z bardziej odizolowanych od głównego nurtu Bugu, co sprawia, że jego ekosystem jest bardzo stabilny i bogaty w roślinność. Brzegi są gęsto zalesione, co zapewnia cień i chłód, a także liczne zatopione drzewa, które stanowią doskonałe kryjówki. Dno jest zróżnicowane, od twardego piasku po grube warstwy mułu, z licznymi zaczepami. Średnia głębokość wynosi około 1.6 metra, z maksymalnymi dołkami do 3.0 metrów, gdzie można spotkać większe drapieżniki. Brak stałego połączenia z rzeką minimalizuje wahania poziomu wody i sprzyja rozwojowi dużych linów i szczupaków. Jest to łowisko dla cierpliwych wędkarzy, ceniących dzikość i spokój.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21617, 4.2, 1.6, 3, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Szczupak,Okoń,Karaś pospolity', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21618, 'Starorzecze Włodawa Południowe II', 'starorzecze-wlodawa-poludniowe-ii-wlodawa-21618', 'OXBOW', 51.8039167, 23.6316514, 'Lubelskie', 'Włodawa', 'To starorzecze jest cenione za swoją dostępność i różnorodność ryb, będąc popularnym miejscem wśród wędkarzy z Włodawy. Brzegi są częściowo zagospodarowane, z kilkoma pomostami i łatwymi dojściami, choć wciąż występują obszary z dziką roślinnością. Dno jest piaszczysto-muliste, z umiarkowaną ilością zaczepów, co sprzyja różnym technikom wędkowania. Średnia głębokość wynosi około 1.5 metra, z maksymalnymi dołkami do 3.0 metrów, gdzie można znaleźć większe leszcze i karpie. Akwen ten ma sporadyczne połączenie z Bugiem, co zapewnia dopływ świeżej wody i ryb. Jest to dobre łowisko na leszcze, płocie i karasie, a także na drapieżniki takie jak szczupak i okoń.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21618, 3.9, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21619, 'Starorzecze Włodawa Północne II', 'starorzecze-wlodawa-polnocne-ii-wlodawa-21619', 'OXBOW', 51.8050188, 23.6309259, 'Lubelskie', 'Włodawa', 'To starorzecze, choć położone w pobliżu innych, wyróżnia się głębszymi partiami i mniejszym stopniem zamulenia. Brzegi są częściowo zalesione, co zapewnia cień, a także liczne zatopione pnie i gałęzie, które stanowią doskonałe kryjówki dla ryb. Dno jest zróżnicowane, od twardego piasku po grube warstwy mułu, z licznymi zaczepami. Średnia głębokość wynosi około 2.0 metra, z maksymalnymi dołkami do 4.5 metra, gdzie chętnie żerują sumy i duże szczupaki. Połączenie z rzeką jest rzadkie, co sprzyja stabilności ekosystemu. Jest to łowisko dla doświadczonych wędkarzy, poszukujących okazowych ryb drapieżnych, wymagające jednak odpowiedniego sprzętu i technik.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21619, 6, 2, 4.5, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Sum,Szczupak,Leszcz,Okoń', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21620, 'Starorzecze Krzny (okolice Białej Podlaskiej)', 'starorzecze-krzny-okolice-bialej-podlaskiej-biala-podlaska-21620', 'OXBOW', 51.8038046, 23.6283047, 'Lubelskie', 'Biała Podlaska', 'To średniej wielkości starorzecze o wydłużonym kształcie, położone w malowniczej dolinie rzeki Krzny, charakteryzujące się spokojnym nurtem i obfitością roślinności wodnej. Dno jest przeważnie muliste, z twardszymi fragmentami przy brzegach, co sprzyja rozwojowi bogatej fauny dennej. Brzegi są częściowo zarośnięte trzciną i krzewami, co utrudnia dostęp w niektórych miejscach, ale jednocześnie zapewnia schronienie dla ryb. Jest to idealne siedlisko dla lina i karasia pospolitego, które znajdują tu doskonałe warunki do żerowania i rozmnażania. Wiosną, podczas wysokiego stanu wody, starorzecze łączy się z rzeką, co umożliwia migrację ryb. Wędkarze powinni przygotować się na łowienie w zaroślach, co może wymagać użycia mocniejszego sprzętu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21620, 3.2, 1.4, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Umiarkowany, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21621, 'Starorzecze Krzny (okolice Białej Podlaskiej)', 'starorzecze-krzny-okolice-bialej-podlaskiej-biala-podlaska-21621', 'OXBOW', 51.8039204, 23.6273525, 'Lubelskie', 'Biała Podlaska', 'Niewielkie, płytkie starorzecze, które stanowi doskonałe miejsce do obserwacji ptactwa wodnego oraz spokojnego wędkowania. Dno jest w większości piaszczysto-muliste, z licznymi zatopionymi gałęziami, które tworzą naturalne kryjówki dla ryb. Brzegi są łatwo dostępne w wielu miejscach, jednak gęste zarośla trzcinowe utrudniają swobodne przemieszczanie się. Roślinność podwodna jest bardzo obfita, co sprzyja występowaniu wzdręgi i karasia srebrzystego. Mimo niewielkich rozmiarów, starorzecze oferuje ciekawe możliwości wędkarskie, zwłaszcza dla miłośników spławika. Latem, w okresach suszy, poziom wody może znacznie spaść, co zwiększa ryzyko przyduchy. Wędkowanie z łodzi lub pontonu może być tutaj bardzo efektywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21621, 1.8, 0.9, 1.8, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Wzdręga,Karaś srebrzysty,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21622, 'Starorzecze Krzny (okolice Białej Podlaskiej)', 'starorzecze-krzny-okolice-bialej-podlaskiej-biala-podlaska-21622', 'OXBOW', 51.8018144, 23.628404, 'Lubelskie', 'Biała Podlaska', 'To urokliwe starorzecze jest klasycznym przykładem siedliska dla ryb spokojnego żeru, ale także dla drapieżników. Posiada twarde, gliniasto-piaszczyste dno z miejscowymi zagłębieniami, gdzie gromadzi się muł. Brzegi są częściowo dostępne, z licznymi pomostami wędkarskimi wykonanymi przez lokalnych wędkarzy, co ułatwia dostęp. Roślinność przybrzeżna jest umiarkowana, co pozwala na swobodne zarzucanie wędki, jednak pod wodą kryją się pojedyncze korzenie i gałęzie. Jest to doskonałe miejsce na leszcza i karpia, które chętnie żerują w spokojnych wodach. Starorzecze to jest znane z regularnych zarybień, co zwiększa szanse na udany połów. Warto odwiedzić je wczesną wiosną lub jesienią, kiedy ryby są najbardziej aktywne. Należy jednak uważać na zmienną głębokość i nierówności dna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21622, 2.5, 1.6, 3.5, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Płoć,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21623, 'Starorzecze Krzny (okolice Białej Podlaskiej)', 'starorzecze-krzny-okolice-bialej-podlaskiej-biala-podlaska-21623', 'OXBOW', 51.7988322, 23.6211694, 'Lubelskie', 'Biała Podlaska', 'Długie i wąskie starorzecze, które zachowało silne połączenie z głównym nurtem rzeki Krzny podczas wysokich stanów wody. Charakteryzuje się zróżnicowanym dnem, od piaszczystego po gęsto muliste, z licznymi dołkami i podwodnymi przeszkodami. Brzegi są trudne do pokonania, często bagniste i porośnięte gęstymi krzewami, co sprawia, że dostęp do wody jest wyzwaniem. Roślinność podwodna jest bardzo bogata, co tworzy idealne warunki dla szczupaka i okonia. Wędkowanie tutaj wymaga cierpliwości i umiejętności, ale może przynieść spektakularne rezultaty, zwłaszcza w poszukiwaniu drapieżników. Należy być przygotowanym na trudne warunki terenowe i konieczność brodzenia. Jest to starorzecze o dość dynamicznym charakterze, co wpływa na różnorodność gatunkową ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21623, 4.5, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Silne', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz,Wzdręga', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21624, 'Starorzecze Krzny (okolice Białej Podlaskiej)', 'starorzecze-krzny-okolice-bialej-podlaskiej-biala-podlaska-21624', 'OXBOW', 51.7994612, 23.6236893, 'Lubelskie', 'Biała Podlaska', 'To starorzecze wyróżnia się głębokimi partiami i stosunkowo czystym dnem, co jest rzadkością w tego typu akwenach. Dno jest głównie piaszczysto-żwirowe, z niewielkimi osadami mułu, co sprzyja czystości wody. Brzegi są umiarkowanie dostępne, z pojedynczymi miejscami do wygodnego rozłożenia sprzętu. Roślinność przybrzeżna nie jest zbyt gęsta, co ułatwia zarzucanie. Jest to dobre miejsce dla sandacza i suma, które preferują głębsze partie i czystsze dno. Wędkowanie z gruntu lub spinningowanie może przynieść tutaj najlepsze efekty. Akwen ten rzadko wysycha i ma stabilny poziom wody, co czyni go atrakcyjnym przez cały rok. Warto szukać ryb w okolicach zatopionych pni, które stanowią jedyne większe przeszkody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21624, 6, 2.2, 5, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Sandacz,Sum,Szczupak,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21625, 'Starorzecze Krzny (okolice Białej Podlaskiej)', 'starorzecze-krzny-okolice-bialej-podlaskiej-biala-podlaska-21625', 'OXBOW', 51.7983967, 23.623397, 'Lubelskie', 'Biała Podlaska', 'Płytkie i silnie zarośnięte starorzecze, które jest prawdziwym królestwem lina i karasia pospolitego. Dno jest gęsto muliste, z grubą warstwą osadów organicznych, co sprzyja rozwojowi bujnej roślinności podwodnej. Brzegi są niemal w całości pokryte gęstymi trzcinami i krzewami, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga użycia brodzaków. Ze względu na płytkość i obfitość roślinności, w upalne lata występuje wysokie ryzyko przyduchy. Wędkowanie tutaj to wyzwanie, ale nagrodą mogą być piękne okazy ryb spokojnego żeru. Najlepsze wyniki osiąga się wcześnie rano lub późnym wieczorem, kiedy ryby wychodzą na żer z zarośli. Należy unikać łowienia w najgorętszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21625, 2, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21626, 'Starorzecze Krzny (okolice Białej Podlaskiej)', 'starorzecze-krzny-okolice-bialej-podlaskiej-biala-podlaska-21626', 'OXBOW', 51.798732, 23.6247793, 'Lubelskie', 'Biała Podlaska', 'To starorzecze stanowi doskonałe miejsce dla wędkarzy poszukujących różnorodnych gatunków ryb, od spokojnego żeru po drapieżniki. Dno jest zróżnicowane, z przewagą mułu, ale z licznymi twardszymi fragmentami i lokalnymi zagłębieniami. Brzegi są miejscami łatwo dostępne, a w innych rejonach porośnięte drzewami i krzewami, które tworzą naturalne stanowiska. Roślinność podwodna jest umiarkowana, co pozwala na swobodne prowadzenie przynęt. Starorzecze to jest znane z obecności szczupaka i okonia, ale także dużych leszczy i płoci. Okresowo łączy się z rzeką, co wzbogaca jego faunę. Warto spróbować różnych metod wędkowania, od spławika po spinning, aby w pełni wykorzystać potencjał tego łowiska. Częste zmiany pogody mogą wpływać na aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21626, 3.8, 1.7, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Wzdręga', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21627, 'Starorzecze Krzny (okolice Białej Podlaskiej)', 'starorzecze-krzny-okolice-bialej-podlaskiej-biala-podlaska-21627', 'OXBOW', 51.7996926, 23.6273626, 'Lubelskie', 'Biała Podlaska', 'To starorzecze jest wyjątkowo atrakcyjne ze względu na swoje głębokie partie i obecność dużych drapieżników. Dno jest zróżnicowane, z przewagą piasku i żwiru w głębszych miejscach oraz mułu w płytszych zatoczkach. Brzegi są stosunkowo łatwo dostępne, z nielicznymi zaroślami, co umożliwia swobodne poruszanie się. Roślinność podwodna jest umiarkowana, ale występują gęste skupiska, które są idealnymi kryjówkami dla ryb. Akwen ten jest znany z dużych szczupaków i sandaczy, a także sporadycznie łowionych sumów. Wędkowanie z łodzi jest tutaj bardzo efektywne, zwłaszcza w poszukiwaniu ryb żerujących w toni. Warto eksperymentować z przynętami, aby znaleźć te, które najlepiej sprawdzą się w danym dniu. Dobrze jest mieć ze sobą echosondę do lokalizacji głębszych partii.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21627, 7.5, 2.5, 6, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Sum,Okoń,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21628, 'Starorzecze Krzny (okolice Białej Podlaskiej)', 'starorzecze-krzny-okolice-bialej-podlaskiej-biala-podlaska-21628', 'OXBOW', 51.7997568, 23.6296914, 'Lubelskie', 'Biała Podlaska', 'To starorzecze jest idealne dla wędkarzy ceniących spokój i kontakt z naturą, oferując jednocześnie dobre warunki do połowu ryb. Dno jest przeważnie muliste, ale stabilne, z licznymi podwodnymi góreczkami i zagłębieniami. Brzegi są dobrze dostępne, z utwardzonymi ścieżkami wzdłuż większości linii brzegowej. Roślinność przybrzeżna jest umiarkowana, z przewagą traw i pojedynczych krzewów. Akwen ten jest bogaty w płoć, leszcza i karasia pospolitego, które chętnie żerują na mulistym dnie. Brak bezpośredniego połączenia z rzeką sprawia, że woda jest spokojna i stabilna. Ze względu na niskie ryzyko przyduchy, jest to dobre miejsce do wędkowania przez większość sezonu. Warto zastosować delikatny sprzęt i naturalne przynęty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21628, 5, 1.9, 4.2, 'Brak', 'Średnie', 'Słabe', FALSE, FALSE, 'Płoć,Leszcz,Karaś pospolity,Lin', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21629, 'Starorzecze Krzny (okolice Białej Podlaskiej)', 'starorzecze-krzny-okolice-bialej-podlaskiej-biala-podlaska-21629', 'OXBOW', 51.8001375, 23.6361455, 'Lubelskie', 'Biała Podlaska', 'To starorzecze charakteryzuje się dużą powierzchnią i zróżnicowaną głębokością, co sprzyja występowaniu wielu gatunków ryb. Dno jest mozaiką piasku, żwiru i mułu, z licznymi zatopionymi drzewami i korzeniami, które stanowią doskonałe kryjówki. Brzegi są miejscami trudno dostępne z powodu gęstych zarośli i bagnistego terenu, ale są też odcinki z wygodnym dostępem. Roślinność podwodna jest umiarkowana, ale w płytszych zatokach może być bardzo gęsta. Akwen ten jest znany z obecności dużych szczupaków i sumów, a także bogatej populacji leszczy i karpi. Wędkowanie tutaj wymaga cierpliwości i znajomości terenu, ale może przynieść imponujące trofea. Połączenie z rzeką podczas wysokiej wody odświeża akwen i wprowadza nowe ryby.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21629, 10, 2, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sum,Leszcz,Karp,Okoń', 'Umiarkowany, miejscami zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21630, 'Starorzecze Krzny (okolice Białej Podlaskiej)', 'starorzecze-krzny-okolice-bialej-podlaskiej-biala-podlaska-21630', 'OXBOW', 51.7999808, 23.6353657, 'Lubelskie', 'Biała Podlaska', 'To starorzecze, choć położone blisko, oferuje nieco odmienny charakter niż sąsiednie akweny. Charakteryzuje się stabilnym połączeniem z rzeką, co zapewnia stałą wymianę wody i bogactwo gatunkowe. Dno jest przeważnie piaszczyste, z niewielkimi osadami mułu, co sprzyja czystości wody. Brzegi są łatwo dostępne, z licznymi miejscami do wędkowania, co czyni je popularnym łowiskiem. Roślinność podwodna jest słaba, co ułatwia prowadzenie spinningu. Jest to idealne miejsce dla bolenia, jazia i klenia, które chętnie żerują w prądzie. Występują tu również szczupaki i okonie. Wędkowanie tutaj jest dynamiczne i wymaga precyzji w zarzucaniu. Warto odwiedzić je wczesną wiosną, kiedy ryby są najbardziej aktywne po zimie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21630, 6.5, 2.1, 4.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Boleń,Jaź,Kleń,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21631, 'Starorzecze Krzny (okolice Białej Podlaskiej)', 'starorzecze-krzny-okolice-bialej-podlaskiej-biala-podlaska-21631', 'OXBOW', 51.799969, 23.6340923, 'Lubelskie', 'Biała Podlaska', 'To starorzecze jest doskonałym przykładem akwenu o zróżnicowanej głębokości i bogactwie podwodnych kryjówek. Dno jest muliste z licznymi dołkami i zatopionymi pniami, co stwarza idealne warunki dla drapieżników. Brzegi są częściowo zarośnięte, miejscami bagniste, co utrudnia dostęp, ale jednocześnie zapewnia spokój i ciszę. Roślinność podwodna jest umiarkowana, z kępami grążeli i moczarki. Jest to starorzecze znane z obecności dużych szczupaków i okoni, a także leszczy i karasi. Wędkowanie z gruntu lub spinningowanie wzdłuż brzegów może przynieść najlepsze rezultaty. Warto eksplorować miejsca z zatopionymi drzewami, które są naturalnymi ostojami ryb. Ryzyko przyduchy jest niskie, co zapewnia stabilne warunki przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21631, 4, 1.6, 3.6, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Karaś pospolity', 'Umiarkowany, miejscami zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21632, 'Starorzecze Krzny (okolice Białej Podlaskiej)', 'starorzecze-krzny-okolice-bialej-podlaskiej-biala-podlaska-21632', 'OXBOW', 51.7988225, 23.6345221, 'Lubelskie', 'Biała Podlaska', 'To starorzecze jest stosunkowo płytkie i charakteryzuje się wysokim poziomem zamulenia, co sprzyja rozwojowi gęstej roślinności. Dno jest w większości bardzo muliste, z grubą warstwą osadów organicznych. Brzegi są mocno zarośnięte trzciną i inną roślinnością przybrzeżną, co sprawia, że dostęp do wody jest bardzo trudny i wymaga użycia brodzaków lub pontonu. Roślinność podwodna jest silna, tworząc gęste dywany. Jest to idealne siedlisko dla lina, karasia pospolitego i wzdręgi, które doskonale czują się w takich warunkach. Wędkowanie tutaj to wyzwanie, ale może przynieść piękne okazy tych gatunków. Latem, w upalne dni, ryzyko przyduchy jest wysokie, dlatego najlepiej unikać wędkowania w tym okresie. Warto skupić się na wczesnej wiośnie i późnej jesieni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21632, 2.8, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21633, 'Starorzecze Krzny (okolice Białej Podlaskiej)', 'starorzecze-krzny-okolice-bialej-podlaskiej-biala-podlaska-21633', 'OXBOW', 51.791307, 23.6258573, 'Lubelskie', 'Biała Podlaska', 'To starorzecze jest mniejsze, ale zaskakująco głębokie w niektórych partiach, co czyni je interesującym łowiskiem. Dno jest zróżnicowane, od piaszczystego po muliste, z licznymi zatopionymi korzeniami i gałęziami. Brzegi są miejscami łatwo dostępne, a w innych rejonach porośnięte gęstymi krzewami, które zapewniają dobre osłony. Roślinność podwodna jest umiarkowana, ale występują skupiska moczarki i rogatka. Akwen ten jest znany z obecności szczupaka i okonia, które chętnie polują w okolicach przeszkód. Można tu również złowić leszcze i płocie. Wędkowanie spinningowe może być bardzo efektywne, zwłaszcza w poszukiwaniu drapieżników. Należy uważać na zaczepy, które są częste w tym łowisku. Jest to dobre miejsce na szybki wypad wędkarski.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21633, 2.2, 1.5, 3, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21634, 'Starorzecze Parośla (okolice Białej Podlaskiej)', 'starorzecze-parosla-okolice-bialej-podlaskiej-parosla-21634', 'OXBOW', 51.8195429, 23.6152705, 'Lubelskie', 'Parośla', 'To rozległe starorzecze, położone w pobliżu miejscowości Parośla, jest jednym z najbardziej cenionych łowisk w regionie. Charakteryzuje się głębokimi partiami i zróżnicowanym dnem, od twardego po muliste, z licznymi podwodnymi górkami i spadami. Brzegi są w większości łatwo dostępne, z miejscowymi pomostami i dogodnymi stanowiskami wędkarskimi. Roślinność podwodna jest umiarkowana, co pozwala na swobodne prowadzenie przynęt, ale jednocześnie zapewnia rybom schronienie. Jest to idealne siedlisko dla sandacza, suma, szczupaka i karpia, które osiągają tu imponujące rozmiary. Starorzecze to jest regularnie zarybiane i cieszy się dużą popularnością wśród wędkarzy. Warto poświęcić czas na dokładne zbadanie dna, aby znaleźć najlepsze miejsca do połowu. Wysokie stany wody mogą okresowo łączyć je z rzeką, co dodatkowo wzbogaca rybostan.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21634, 12.5, 2.8, 6, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sandacz,Sum,Szczupak,Karp,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21635, 'Starorzecze (Szostaki)', 'starorzecze-szostaki-szostaki-21635', 'OXBOW', 51.8192367, 23.6202843, 'lubelskie', 'Szostaki', 'To starorzecze, położone w malowniczej okolicy Szostak, charakteryzuje się dość rozległą powierzchnią i umiarkowaną głębokością, co sprzyja rozwojowi różnorodnej fauny i flory. Dno jest muliste z pojedynczymi twardymi fragmentami, a brzegi są częściowo zarośnięte trzciną i krzewami, co wymaga ostrożnego podejścia. Występuje tu bogata roślinność podwodna, stanowiąca doskonałe schronienie dla ryb, ale utrudniająca łowienie. Akwen jest domem dla licznych szczupaków, linów, leszczy i płoci, a także okoni. Dostęp do łowiska jest utrudniony ze względu na miejscami bagnisty teren, dlatego wędkarze często korzystają z brodzenia. Zatopione korzenie i gałęzie stanowią naturalne kryjówki dla ryb, ale mogą być przyczyną zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21635, 6.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Trudny, miejscami bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21636, 'Starorzecze (Jabłeczna) 1', 'starorzecze-jableczna-1-jableczna-21636', 'OXBOW', 51.7959711, 23.604197, 'lubelskie', 'Jabłeczna', 'Pierwsze z serii starorzeczy w okolicy Jabłecznej to niewielki, silnie zarośnięty akwen, idealny dla wędkarzy poszukujących spokoju. Dno jest bardzo muliste, a brzegi gęsto porośnięte trzciną i inną roślinnością, co czyni dostęp trudnym. Obfita roślinność podwodna stwarza doskonałe warunki dla lina, karasia pospolitego i wzdręgi, które są tu dominującymi gatunkami. Występuje tu wysokie ryzyko przyduchy w okresie letnim, co należy brać pod uwagę podczas planowania wyprawy. Ze względu na gęste zarośla, brodzenie w wodzie jest często konieczne. Łowisko to stanowi wyzwanie, ale oferuje satysfakcjonujące połowy dla cierpliwych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21636, 2.8, 1, 2.2, 'Podczas bardzo wysokiej wody', 'Wysokie', 'Bardzo silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21637, 'Starorzecze (Jabłeczna) 2', 'starorzecze-jableczna-2-jableczna-21637', 'OXBOW', 51.7987828, 23.6043439, 'lubelskie', 'Jabłeczna', 'To starorzecze, nieco większe od poprzedniego, również charakteryzuje się znacznym zarośnięciem i mulistym dnem. Brzegi są trudne do pokonania, porośnięte krzewami i wysokimi trawami, co wymaga od wędkarza determinacji. Akwen ten jest odcięty od głównego nurtu rzeki, co sprzyja stabilnym warunkom, ale jednocześnie zwiększa ryzyko niedoboru tlenu. Dominują tu karasie pospolite, wzdręgi, płocie i okonie, które doskonale radzą sobie w płytkich, ciepłych wodach. Wędkowanie z brzegu jest możliwe tylko w nielicznych, wydeptanych miejscach, dlatego brodzenie jest często najlepszą opcją. Gęsta roślinność podwodna stanowi wyzwanie, ale także kryjówkę dla ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21637, 3.5, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć,Okoń', 'Trudny, wymaga przedzierania się przez zarośla', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21638, 'Starorzecze (Jabłeczna) 3', 'starorzecze-jableczna-3-jableczna-21638', 'OXBOW', 51.7991697, 23.6024208, 'lubelskie', 'Jabłeczna', 'Trzecie starorzecze w Jabłecznej to bardzo płytki akwen, który w suchych latach może częściowo wysychać, co czyni go siedliskiem dla najbardziej odpornych gatunków ryb. Dno jest silnie zamulone, a brzegi są niestabilne i grząskie, co utrudnia dostęp. Występuje tu gęsta roślinność wodna, zarówno podwodna, jak i wynurzona, tworząc labirynt dla wędkarzy. Królują tu karasie srebrzyste i pospolite oraz wzdręgi, które doskonale adaptują się do trudnych warunków. Łowienie wymaga precyzji i umiejętności operowania sprzętem w gęstych zaroślach. Najlepsze wyniki osiąga się wiosną, zanim roślinność osiągnie pełny rozkwit.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21638, 1.5, 0.8, 1.5, 'Brak', 'Bardzo wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Karaś pospolity,Wzdręga', 'Trudny, brzegi muliste', TRUE, 'Zatopione gałęzie i muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21639, 'Starorzecze (Jabłeczna) 4', 'starorzecze-jableczna-4-jableczna-21639', 'OXBOW', 51.8004108, 23.6043339, 'lubelskie', 'Jabłeczna', 'To starorzecze w Jabłecznej wyróżnia się nieco większą głębokością w porównaniu do sąsiednich, co sprzyja różnorodności gatunkowej. Dno jest częściowo muliste, ale występują też twardsze fragmenty, a brzegi są dostępne z kilku wygodnych miejsc. Roślinność podwodna jest umiarkowana, co ułatwia łowienie, jednocześnie zapewniając rybom schronienie. Akwen ten jest regularnie zasilany wodą podczas większych wezbrań rzeki, co poprawia warunki tlenowe. Występują tu szczupaki, liny, leszcze, płocie i okonie, co czyni to miejsce atrakcyjnym dla wędkarzy spinningowych i gruntowych. Brak konieczności brodzenia jest dodatkowym atutem tego łowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21639, 4, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry z kilku miejsc', FALSE, 'Pojedyncze korzenie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21640, 'Starorzecze (Jabłeczna) 5', 'starorzecze-jableczna-5-jableczna-21640', 'OXBOW', 51.8020421, 23.6026119, 'lubelskie', 'Jabłeczna', 'Piąte starorzecze w Jabłecznej to wydłużony akwen, charakteryzujący się typowym dla starorzeczy kształtem i znacznym zarośnięciem. Dno jest muliste z licznymi zatopionymi drzewami i krzewami, które tworzą doskonałe kryjówki dla drapieżników. Brzegi są trudne do pokonania, miejscami gęsto zarośnięte, co wymaga od wędkarza cierpliwości i umiejętności. Akwen ten jest odcięty od rzeki, co sprawia, że w okresach upałów ryzyko przyduchy jest podwyższone. Dominują tu szczupaki, liny, okonie i płocie, które doskonale czują się w zaroślach. Wędkowanie wymaga użycia wodoodpornego obuwia i ostrożności ze względu na liczne zaczepy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21640, 5.5, 1.7, 3.2, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Okoń,Płoć', 'Trudny, miejscami zarośnięty', TRUE, 'Dużo zatopionych drzew i zarośli', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21641, 'Starorzecze (Jabłeczna) 6', 'starorzecze-jableczna-6-jableczna-21641', 'OXBOW', 51.8028714, 23.6018877, 'lubelskie', 'Jabłeczna', 'To starorzecze, będące częścią kompleksu wodnego w Jabłecznej, oferuje umiarkowane warunki do wędkowania. Dno jest muliste, ale stabilne, a brzegi, choć miejscami zarośnięte, pozwalają na względnie łatwy dostęp. Roślinność podwodna występuje w umiarkowanym stopniu, co sprzyja swobodnemu prowadzeniu przynęty. Akwen ten nie jest bezpośrednio połączony z rzeką, jednak jego głębokość minimalizuje ryzyko przyduchy. Występują tu głównie karasie pospolite, leszcze, płocie i okonie, co czyni go atrakcyjnym dla wędkarzy gruntowych. Wędkowanie jest przyjemne przez cały sezon, choć w upalne dni warto szukać głębszych miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21641, 3.8, 1.4, 2.8, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karaś pospolity,Leszcz,Płoć,Okoń', 'Umiarkowany, zarośnięte brzegi', TRUE, 'Pojedyncze zatopione gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21642, 'Starorzecze (Jabłeczna) 7', 'starorzecze-jableczna-7-jableczna-21642', 'OXBOW', 51.8036857, 23.6014854, 'lubelskie', 'Jabłeczna', 'Siódme starorzecze w Jabłecznej to stosunkowo niewielki i płytki zbiornik, charakteryzujący się bardzo trudnym dostępem. Dno jest silnie zamulone, a brzegi gęsto porośnięte roślinnością, co sprawia, że dotarcie do wody jest wyzwaniem. Ze względu na małą głębokość i silne zarośnięcie, ryzyko przyduchy jest tu wysokie, szczególnie w letnich miesiącach. Akwen ten jest idealnym siedliskiem dla lina, karasia pospolitego i wzdręgi, które doskonale radzą sobie w takich warunkach. Wędkowanie wymaga brodzenia i precyzyjnych rzutów, aby uniknąć zaczepów o gęstą roślinność podwodną. Najlepsze efekty można osiągnąć późną wiosną, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21642, 2, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Bardzo trudny, gęste zarośla', TRUE, 'Gęsta roślinność podwodna i korzenie', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21643, 'Starorzecze (Jabłeczna) 8', 'starorzecze-jableczna-8-jableczna-21643', 'OXBOW', 51.8048741, 23.6019668, 'lubelskie', 'Jabłeczna', 'Ósme starorzecze w Jabłecznej to najmniejszy i najpłytszy akwen z całej grupy, który w okresach suszy może całkowicie wysychać. Dno jest bardzo mocno zamulone, a brzegi są praktycznie niedostępne bez brodzenia, z powodu gęstych trzcinowisk i mulistego podłoża. Roślinność podwodna jest niezwykle obfita, tworząc skomplikowany labirynt dla wędkarzy i doskonałe schronienie dla ryb. Występują tu głównie karasie srebrzyste, wzdręgi i płocie, które są odporne na trudne warunki środowiskowe. Ze względu na ekstremalnie płytką wodę i zarośnięcie, ryzyko przyduchy jest bardzo wysokie. Wędkowanie jest tu prawdziwym wyzwaniem, ale może przynieść satysfakcję wczesną wiosną.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21643, 1.2, 0.7, 1.3, 'Brak', 'Bardzo wysokie', 'Bardzo silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Niemożliwy bez brodzenia', TRUE, 'Zatopione gałęzie i muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21644, 'Starorzecze (Parośla) 1', 'starorzecze-parosla-1-parosla-21644', 'OXBOW', 51.8110537, 23.6101985, 'lubelskie', 'Parośla', 'Pierwsze starorzecze w Parośli to duży i stosunkowo głęboki akwen, oferujący doskonałe warunki do wędkowania. Dno jest czyste, z niewielkim zamuleniem, a brzegi są łatwo dostępne z większości stron, co ułatwia komfortowe łowienie. Roślinność podwodna jest umiarkowana, co pozwala na swobodne prowadzenie przynęt i jednocześnie zapewnia rybom kryjówki. Akwen ten jest regularnie zasilany wodą podczas wysokich stanów rzeki, co utrzymuje dobre warunki tlenowe i sprzyja zdrowej populacji ryb. Występują tu liczne szczupaki, leszcze, karpie, liny i okonie, co czyni go atrakcyjnym dla różnych technik wędkarskich. Jest to jedno z najlepszych łowisk w regionie, dostępne przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21644, 7, 2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Karp,Lin,Okoń', 'Dobry z większości stron', FALSE, 'Czyste dno, pojedyncze rośliny', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21645, 'Starorzecze (Parośla) 2', 'starorzecze-parosla-2-parosla-21645', 'OXBOW', 51.8117233, 23.6112003, 'lubelskie', 'Parośla', 'Drugie starorzecze w Parośli, połączone z większym akwenem podczas wezbrań, jest nieco płytsze, ale wciąż oferuje dobre warunki wędkarskie. Dno jest średnio zamulone, z pojedyncymi zatopionymi pniami, co tworzy interesujące miejsca do łowienia. Brzegi są ogólnie dostępne, choć miejscami mogą być zarośnięte, wymagając niewielkiego wysiłku. Roślinność podwodna jest umiarkowana, co sprzyja zarówno rybom, jak i wędkarzom. Dzięki połączeniu z rzeką, ryzyko przyduchy jest niskie, a populacja ryb jest stabilna. Dominują tu liny, płocie, leszcze i szczupaki, co sprawia, że jest to wszechstronne łowisko. Wędkowanie jest przyjemne przez większość sezonu, z najlepszymi wynikami wiosną i jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21645, 4.5, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Płoć,Leszcz,Szczupak', 'Dobry, miejscami zarośnięty', FALSE, 'Pojedyncze zatopione pnie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21646, 'Starorzecze (Parośla) 3', 'starorzecze-parosla-3-parosla-21646', 'OXBOW', 51.812118, 23.61207, 'lubelskie', 'Parośla', 'Trzecie starorzecze w Parośli to końcowa część kompleksu, charakteryzująca się większym zamuleniem i silniejszym zarośnięciem. Dno jest muliste, a brzegi są trudne do pokonania, często grząskie i porośnięte gęstą roślinnością. Roślinność podwodna jest bardzo obfita, tworząc naturalne kryjówki, ale także utrudniając prowadzenie przynęt. Akwen ten jest również połączony z rzeką podczas wysokich wód, co zapobiega całkowitemu odcięciu, jednak ryzyko przyduchy w upały jest podwyższone. Występują tu karasie pospolite, wzdręgi, płocie i liny, które doskonale radzą sobie w takich warunkach. Wędkowanie wymaga brodzenia i cierpliwości, ale może przynieść udane połowy wczesną wiosną i latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21646, 3, 1.2, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć,Lin', 'Trudny, brzegi muliste', TRUE, 'Gęsta roślinność podwodna i muł', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21647, 'Starorzecze (Parośla) 4', 'starorzecze-parosla-4-parosla-21647', 'OXBOW', 51.8107892, 23.6079394, 'lubelskie', 'Parośla', 'Czwarte starorzecze w Parośli to odizolowany akwen, charakteryzujący się niewielką głębokością i ekstremalnym zarośnięciem. Dno jest bardzo silnie zamulone, a brzegi są praktycznie niedostępne bez specjalnego sprzętu i brodzenia, z powodu gęstych trzcinowisk. Roślinność podwodna jest niezwykle obfita, tworząc gąszcz, w którym ryby znajdują schronienie. Akwen ten nie ma stałego połączenia z rzeką i w suchych latach może częściowo wysychać, co zwiększa ryzyko przyduchy. Dominują tu karasie srebrzyste, wzdręgi i płocie, które są bardzo odporne na trudne warunki. Wędkowanie jest tu bardzo wymagające, ale dla miłośników dzikich miejsc może być satysfakcjonujące, zwłaszcza wczesną wiosną.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21647, 2.5, 1, 2, 'Brak', 'Wysokie', 'Bardzo silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Niemożliwy, gęste trzcinowiska', TRUE, 'Zatopione gałęzie i gęste zarośla', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21648, 'Starorzecze (okolice Szostak) 1', 'starorzecze-okolice-szostak-1-szostaki-21648', 'OXBOW', 51.8171281, 23.6213859, 'lubelskie', 'Szostaki', 'To starorzecze, położone w ustronnej okolicy Szostak, oferuje wędkarzom ciszę i spokój z dala od zgiełku. Akwen charakteryzuje się umiarkowaną głębokością i mulistym dnem z licznymi zatopionymi konarami, które stanowią doskonałe kryjówki dla ryb. Brzegi są trudne do pokonania, często wymagają przedzierania się przez zarośla i pola, co dodaje uroku dzikiego łowiska. Roślinność podwodna jest silna, ale nie uniemożliwia łowienia, tworząc bogate środowisko dla wielu gatunków. Występują tu szczupaki, liny, okonie i płocie, co sprawia, że jest to atrakcyjne miejsce dla wędkarzy spinningowych i spławikowych. Ze względu na utrudniony dostęp, brodzenie jest często konieczne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21648, 5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Okoń,Płoć', 'Trudny, wymaga podejścia przez pola', TRUE, 'Dużo zatopionych konarów', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21649, 'Starorzecze (okolice Szostak) 2', 'starorzecze-okolice-szostak-2-szostaki-21649', 'OXBOW', 51.8161137, 23.6231931, 'lubelskie', 'Szostaki', 'Drugie starorzecze w okolicy Szostak to akwen o umiarkowanej wielkości, charakteryzujący się znacznym zamuleniem, ale stabilnym poziomem wody. Dno jest muliste z pojedynczymi korzeniami i gęstą roślinnością podwodną, co wymaga precyzji w prowadzeniu przynęt. Brzegi są miejscami zarośnięte, ale ogólnie dostęp jest umiarkowany, co pozwala na wędkowanie bez konieczności brodzenia. Akwen ten nie ma stałego połączenia z rzeką, jednak jego głębokość i stabilność zmniejszają ryzyko przyduchy. Dominują tu leszcze, karpie, płocie i karasie pospolite, co czyni go atrakcyjnym dla wędkarzy gruntowych. Jest to łowisko, które oferuje dobre warunki przez cały sezon, zwłaszcza dla miłośników spokojnego wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21649, 4.2, 1.3, 2.7, 'Brak', 'Wysokie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Płoć,Karaś pospolity', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gęsta roślinność podwodna', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21650, 'Starorzecze (Szostaki) - Północne', 'starorzecze-szostaki-polnocne-szostaki-21650', 'OXBOW', 51.8192264, 23.6210833, 'Lubelskie', 'Szostaki', 'To starorzecze, położone w pobliżu miejscowości Szostaki, charakteryzuje się typowym dla tego regionu mulistym dnem, bogatym w detrytus. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je gęsta trzcina i pałka wodna, co utrudnia swobodne poruszanie się. Roślinność podwodna jest umiarkowana, tworząc idealne kryjówki dla drapieżników takich jak szczupak oraz białorybu. W zbiorniku dominują szczupaki, liny, płocie i leszcze, które znajdują tu dogodne warunki do żerowania i rozmnażania. Podczas wysokich stanów wody starorzecze łączy się z głównym nurtem rzeki, co sprzyja wymianie fauny, jednak zwiększa ryzyko niedoboru tlenu w upalne lata. Wędkarze powinni przygotować się na konieczność brodzenia, szczególnie w poszukiwaniu trudno dostępnych, ale obfitujących w ryby miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21650, 3.2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Płoć,Leszcz', 'Dobry z jednej strony, druga zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21651, 'Starorzecze (Szostaki) - Południowe', 'starorzecze-szostaki-poludniowe-szostaki-21651', 'OXBOW', 51.81796, 23.6250995, 'Lubelskie', 'Szostaki', 'To głębsze, ale silnie zarośnięte starorzecze w rejonie Szostak, stanowi prawdziwe wyzwanie dla wędkarzy. Dno jest bardzo muliste, a miejscami wręcz bagniste, co sprawia, że dostęp do wody jest utrudniony i wymaga użycia spodniobutów. Gęsta roślinność podwodna, w tym lilie wodne i rdestnice, pokrywa znaczną część zbiornika, tworząc labirynt kryjówek dla ryb. Dominują tu gatunki ciepłolubne i tolerujące niskie poziomy tlenu, takie jak lin, karaś pospolity, wzdręga i płoć. Brak stałego połączenia z rzeką sprawia, że zbiornik jest stabilnym ekosystemem, choć narażonym na deficyty tlenu w upalne lata. Łowienie wymaga precyzji i cierpliwości, ale może przynieść obfite połowy dorodnych okazów, szczególnie w strefach przybrzeżnych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21651, 2.8, 1.8, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21652, 'Starorzecze (Terespol) - Leśne', 'starorzecze-terespol-lesne-terespol-21652', 'OXBOW', 51.8160896, 23.6264874, 'Lubelskie', 'Terespol', 'To malownicze starorzecze, położone na skraju lasu w pobliżu Terespola, jest jednym z łatwiej dostępnych łowisk w regionie. Charakteryzuje się stosunkowo czystym, piaszczysto-mulistym dnem i niewielkim poziomem zamulenia. Brzegi są w większości stabilne i łatwo dostępne, co umożliwia wygodne wędkowanie bez konieczności brodzenia. Roślinność podwodna jest słaba, co sprzyja metodom wymagającym czystego dna. W zbiorniku występują głównie okonie, płocie, szczupaki i wzdręgi, które znajdują tu dobre warunki do rozwoju. Brak połączenia z rzeką i odpowiednia głębokość sprawiają, że ryzyko niedoboru tlenu jest niskie, a starorzecze nie wysycha nawet w okresach suszy. Jest to idealne miejsce dla początkujących wędkarzy oraz tych, którzy cenią sobie komfort i łatwość dostępu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21652, 4, 1, 2.5, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Okoń,Płoć,Szczupak,Wzdręga', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21653, 'Starorzecze (Terespol) - Kręte', 'starorzecze-terespol-krete-terespol-21653', 'OXBOW', 51.8153418, 23.6268543, 'Lubelskie', 'Terespol', 'To niewielkie, kręte starorzecze nieopodal Terespola, oferuje intymne warunki do wędkowania, choć wymaga nieco wysiłku. Dno jest muliste, typowe dla starorzeczy, z umiarkowanym poziomem zamulenia. Brzegi są mocno zarośnięte trzciną i inną roślinnością przybrzeżną, co sprawia, że dostęp do wody jest możliwy tylko w kilku miejscach lub wymaga brodzenia. Roślinność podwodna jest umiarkowana, tworząc atrakcyjne miejsca dla ryb. W zbiorniku dominują karasie pospolite, liny, płocie i okonie, które doskonale czują się w takim środowisku. Połączenie z rzeką podczas wysokich stanów wody zapewnia dopływ świeżej wody i ryb, ale jednocześnie zwiększa ryzyko niedoboru tlenu w upalne, bezdeszczowe okresy. Jest to idealne miejsce dla wędkarzy poszukujących spokoju i wyzwań związanych z łowieniem w zarośniętym środowisku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21653, 1.9, 1.3, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21654, 'Starorzecze (Szostaki) - Głębokie', 'starorzecze-szostaki-glebokie-szostaki-21654', 'OXBOW', 51.813801, 23.6249428, 'Lubelskie', 'Szostaki', 'To wyjątkowo głębokie jak na starorzecze łowisko w okolicach Szostak, wyróżnia się czystym dnem i dobrą dostępnością. Dno jest przeważnie twarde, piaszczysto-żwirowe, z minimalnym zamuleniem, co sprzyja różnorodności gatunkowej. Brzegi są łatwo dostępne z obu stron, co czyni to miejsce idealnym dla wędkarzy preferujących komfortowe warunki. Roślinność podwodna jest słaba, co ułatwia prowadzenie przynęt i minimalizuje ryzyko zaczepów. W zbiorniku występuje bogata populacja szczupaków, leszczy, karpi, płoci i okoni, które czerpią korzyści z czystej wody i głębokich partii. Brak połączenia z rzeką i znaczna głębokość gwarantują stabilne warunki tlenowe przez cały rok, a zbiornik nigdy nie wysycha. Jest to doskonałe miejsce dla wędkarzy poszukujących dużych okazów i komfortowych warunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21654, 3.5, 2.2, 4.5, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Leszcz,Karp,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21655, 'Starorzecze (Szostaki) - Zatokowe', 'starorzecze-szostaki-zatokowe-szostaki-21655', 'OXBOW', 51.8123848, 23.6247977, 'Lubelskie', 'Szostaki', 'To płytkie i silnie zamulone starorzecze w rejonie Szostak, jest typowym przykładem zbiornika o zmiennym charakterze. Dno jest bardzo muliste, a brzegi bagniste i trudno dostępne, co wymaga użycia spodniobutów. Gęsta roślinność podwodna i nawodna, w tym liczne kolonie lilii wodnych, pokrywa większą część powierzchni. W zbiorniku dominują gatunki odporne na trudne warunki, takie jak karaś srebrzysty, wzdręga i płoć, które doskonale radzą sobie w płytkiej i bogatej w roślinność wodzie. Połączenie z rzeką podczas wysokich stanów wody jest kluczowe dla utrzymania populacji ryb, jednak starorzecze ma tendencję do wysychania w upalne, suche lata. Ryzyko niedoboru tlenu jest wysokie, co sprawia, że najlepszym okresem na wędkowanie jest wiosna, kiedy woda jest jeszcze chłodna i dobrze natleniona.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21655, 2.1, 1, 2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21656, 'Starorzecze (Szostaki) - Środkowe', 'starorzecze-szostaki-srodkowe-szostaki-21656', 'OXBOW', 51.8182638, 23.6218809, 'Lubelskie', 'Szostaki', 'To starorzecze, położone w centralnej części kompleksu wodnego w Szostakach, charakteryzuje się umiarkowanym stopniem zamulenia i zróżnicowanym dnem. Brzegi są częściowo dostępne, choć miejscami występują gęste zarośla trzcinowe, wymagające użycia spodniobutów. Roślinność podwodna jest umiarkowana, tworząc mozaikę otwartych przestrzeni i kryjówek dla ryb. W zbiorniku można spotkać szczupaki, liny, leszcze i płocie, które dobrze prosperują w tym zróżnicowanym środowisku. Połączenie z rzeką podczas wysokich stanów wody zapewnia dopływ świeżej wody i narybku, ale również stwarza ryzyko deficytów tlenu w upalne lato. Wędkarze powinni eksplorować zarówno otwarte partie wody, jak i zarośnięte zatoczki, aby odnaleźć najlepsze miejsca do połowu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21656, 2.9, 1.6, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Płoć', 'Częściowo dostępny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21657, 'Starorzecze (Szostaki) - Zachodnie I', 'starorzecze-szostaki-zachodnie-i-szostaki-21657', 'OXBOW', 51.8256916, 23.5995118, 'Lubelskie', 'Szostaki', 'To jedno z większych starorzeczy w zachodniej części Szostak, wyróżniające się stałym połączeniem z rzeką, co zapewnia doskonałe warunki tlenowe i bogactwo ryb. Dno jest stosunkowo czyste, piaszczysto-muliste, z niewielkim zamuleniem, co sprzyja różnorodności gatunkowej. Brzegi są łatwo dostępne z obu stron, co ułatwia wędkowanie z brzegu bez konieczności brodzenia. Roślinność podwodna jest umiarkowana, tworząc naturalne kryjówki i żerowiska. W zbiorniku występują liczne szczupaki, okonie, leszcze, płocie oraz jazie, które regularnie wpływają z rzeki. Stały przepływ wody minimalizuje ryzyko niedoboru tlenu, a zbiornik nigdy nie wysycha. Jest to bardzo popularne i produktywne łowisko, idealne dla wędkarzy ceniących sobie komfort i różnorodność połowów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21657, 4.5, 2, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Jaź', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21658, 'Starorzecze (Szostaki) - Zachodnie II', 'starorzecze-szostaki-zachodnie-ii-szostaki-21658', 'OXBOW', 51.8289374, 23.6024878, 'Lubelskie', 'Szostaki', 'To kolejne starorzecze w zachodniej części Szostak, charakteryzujące się stałym połączeniem z rzeką i urozmaiconym dnem. Dno jest muliste, ale miejscami występują twardsze placki, a także liczne zatopione drzewa, które stanowią doskonałe kryjówki dla ryb. Brzegi są częściowo dostępne, jednak w niektórych miejscach gęste zarośla wymagają użycia spodniobutów, aby dotrzeć do najlepszych miejsc. Roślinność podwodna jest umiarkowana, tworząc zróżnicowane środowisko. W zbiorniku występują szczupaki, liny, leszcze, płocie i karpie, które korzystają z osłony zatopionych pni. Stałe połączenie z rzeką zapewnia dobrą cyrkulację wody i niskie ryzyko niedoboru tlenu. Jest to łowisko dla wędkarzy lubiących wyzwania związane z łowieniem w pobliżu zaczepów, gdzie często kryją się duże okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21658, 3.8, 1.7, 3.5, 'Stałe połączenie', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Karp', 'Dobry z jednej strony, druga zarośnięta', TRUE, 'Dużo zatopionych drzew', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21659, 'Starorzecze (Szostaki) - Zachodnie III', 'starorzecze-szostaki-zachodnie-iii-szostaki-21659', 'OXBOW', 51.829499, 23.6041253, 'Lubelskie', 'Szostaki', 'To mniejsze, ale bardzo malownicze starorzecze w zachodniej części Szostak, charakteryzujące się gęstą roślinnością i mulistym dnem. Dno jest miękkie i zamulone, co sprzyja rozwojowi bogatej flory wodnej. Brzegi są mocno zarośnięte trzciną i inną roślinnością, co sprawia, że dostęp do wody jest utrudniony i wymaga brodzenia. Gęsta roślinność podwodna tworzy doskonałe kryjówki dla ryb i utrudnia wędkowanie. W zbiorniku dominują liny, karasie pospolite, wzdręgi i okonie, które doskonale adaptują się do tego środowiska. Połączenie z rzeką podczas wysokich stanów wody jest nieregularne, co zwiększa ryzyko niedoboru tlenu w upalne dni. Jest to łowisko dla cierpliwych wędkarzy, którzy cenią sobie łowienie w naturalnym, dzikim środowisku i potrafią radzić sobie z zaczepami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21659, 2.5, 1.4, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21660, 'Starorzecze (Szostaki) - Wschodnie I', 'starorzecze-szostaki-wschodnie-i-szostaki-21660', 'OXBOW', 51.8258596, 23.6196306, 'Lubelskie', 'Szostaki', 'To starorzecze, zlokalizowane we wschodniej części kompleksu w Szostakach, jest cenione za dobrą dostępność i stabilne warunki. Dno jest przeważnie twarde, piaszczysto-muliste, z niskim poziomem zamulenia, co sprzyja różnorodności gatunkowej. Brzegi są łatwo dostępne z jednej strony, co umożliwia wygodne wędkowanie z brzegu, podczas gdy druga strona jest nieco bardziej zarośnięta. Roślinność podwodna jest umiarkowana, tworząc liczne kryjówki, ale nie utrudniając znacząco wędkowania. W zbiorniku dominują szczupaki, leszcze, płocie i okonie, które znajdują tu idealne warunki do żerowania. Brak połączenia z rzeką i odpowiednia głębokość minimalizują ryzyko niedoboru tlenu, a zbiornik nie wysycha. Jest to dobre miejsce dla wędkarzy poszukujących stabilnego łowiska z szansą na dorodne okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21660, 3, 1.9, 3.8, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń', 'Dobry z jednej strony', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21661, 'Starorzecze (Szostaki) - Wschodnie II', 'starorzecze-szostaki-wschodnie-ii-szostaki-21661', 'OXBOW', 51.8294588, 23.616393, 'Lubelskie', 'Szostaki', 'To starorzecze we wschodniej części Szostak, charakteryzuje się wysokim stopniem zarośnięcia i mulistym dnem. Dno jest miękkie i silnie zamulone, co sprzyja rozwojowi obfitej roślinności wodnej. Brzegi są bagniste i trudno dostępne, co wymaga od wędkarzy użycia spodniobutów i cierpliwości. Gęsta roślinność podwodna, w tym liczne grążele i rdestnice, stanowi wyzwanie dla wędkarzy, ale jednocześnie doskonałe schronienie dla ryb. W zbiorniku dominują liny, karasie pospolite, płocie i wzdręgi, które doskonale czują się w takim środowisku. Połączenie z rzeką podczas wysokich stanów wody jest nieregularne, co zwiększa ryzyko niedoboru tlenu w upalne lato. Jest to łowisko dla miłośników trudniejszych wyzwań, nagradzające wytrwałość pięknymi okazami białorybu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21661, 2.7, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21662, 'Starorzecze (Szostaki) - Północno-Wschodnie I', 'starorzecze-szostaki-polnocno-wschodnie-i-szostaki-21662', 'OXBOW', 51.8295901, 23.6091235, 'Lubelskie', 'Szostaki', 'To jedno z lepiej utrzymanych starorzeczy w północno-wschodniej części Szostak, z stałym połączeniem z rzeką. Dno jest przeważnie twarde, piaszczysto-muliste, z niskim poziomem zamulenia, co sprzyja różnorodności gatunkowej. Brzegi są łatwo dostępne z obu stron, co umożliwia komfortowe wędkowanie z brzegu. Roślinność podwodna jest umiarkowana, tworząc naturalne kryjówki dla ryb, ale nie utrudniając znacząco wędkowania. W zbiorniku występują liczne szczupaki, okonie, leszcze, płocie oraz bolenie, które regularnie wpływają z rzeki. Stały przepływ wody zapewnia doskonałe warunki tlenowe przez cały rok, a zbiornik nigdy nie wysycha. Jest to idealne miejsce dla wędkarzy ceniących sobie komfort, różnorodność ryb i szansę na spotkanie z drapieżnikami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21662, 3.3, 1.8, 3.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21663, 'Starorzecze (Szostaki) - Północno-Wschodnie II', 'starorzecze-szostaki-polnocno-wschodnie-ii-szostaki-21663', 'OXBOW', 51.8289223, 23.6060619, 'Lubelskie', 'Szostaki', 'To płytkie i silnie zamulone starorzecze w północno-wschodniej części Szostak, jest typowym przykładem zbiornika o zmiennym charakterze. Dno jest bardzo muliste, a brzegi bagniste i trudno dostępne, co wymaga użycia spodniobutów. Gęsta roślinność podwodna i nawodna, w tym liczne kolonie lilii wodnych, pokrywa większą część powierzchni. W zbiorniku dominują gatunki odporne na trudne warunki, takie jak karaś pospolity, lin i wzdręga, które doskonale radzą sobie w płytkiej i bogatej w roślinność wodzie. Połączenie z rzeką podczas wysokich stanów wody jest kluczowe dla utrzymania populacji ryb, jednak starorzecze ma tendencję do wysychania w upalne, suche lata. Ryzyko niedoboru tlenu jest wysokie, co sprawia, że najlepszym okresem na wędkowanie jest wiosna, kiedy woda jest jeszcze chłodna i dobrze natleniona.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21663, 2, 1.2, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21664, 'Starorzecze (Szostaki) - Północno-Wschodnie III', 'starorzecze-szostaki-polnocno-wschodnie-iii-szostaki-21664', 'OXBOW', 51.8285973, 23.6062986, 'Lubelskie', 'Szostaki', 'To starorzecze, zlokalizowane w północno-wschodniej części kompleksu wodnego w Szostakach, charakteryzuje się umiarkowanym stopniem zamulenia i zróżnicowanym dnem. Brzegi są częściowo dostępne, choć miejscami występują gęste zarośla trzcinowe, wymagające użycia spodniobutów. Roślinność podwodna jest umiarkowana, tworząc mozaikę otwartych przestrzeni i kryjówek dla ryb. W zbiorniku można spotkać szczupaki, liny, leszcze, płocie i okonie, które dobrze prosperują w tym zróżnicowanym środowisku. Brak stałego połączenia z rzeką sprawia, że zbiornik jest stabilnym ekosystemem, choć narażonym na deficyty tlenu w upalne lato. Wędkarze powinni eksplorować zarówno otwarte partie wody, jak i zarośnięte zatoczki, aby odnaleźć najlepsze miejsca do połowu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21664, 3.1, 1.6, 3.2, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Częściowo dostępny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21665, 'Starorzecze Szostaki A', 'starorzecze-szostaki-a-terespol-21665', 'OXBOW', 51.8280344, 23.6047319, 'Lubelskie', 'Terespol', 'Starorzecze Szostaki A to malowniczy zbiornik wodny położony w dolinie rzeki Bug, charakteryzujący się typową dla tego regionu obfitością roślinności wodnej i brzegowej. Dno jest muliste, z licznymi osadami dennymi, co sprzyja rozwojowi bogatej fauny bezkręgowców, stanowiącej bazę pokarmową dla ryb. Brzegi są w większości trudno dostępne, porośnięte gęstymi szuwarami i drzewami, co wymusza ostrożne podejście do łowiska. Wędkarze mogą spodziewać się tu przede wszystkim szczupaków, które czyhają w zaroślach, a także licznych linów i karasi pospolitych, żerujących w mulistym dnie. Ze względu na silne zarośnięcie i ryzyko przyduchy latem, najlepsze wyniki osiąga się wiosną i jesienią, kiedy woda jest lepiej natleniona. Wymagane są wodery, a także cierpliwość i precyzja w zarzucaniu zestawu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21665, 3.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21666, 'Starorzecze Szostaki B', 'starorzecze-szostaki-b-terespol-21666', 'OXBOW', 51.8276867, 23.6065764, 'Lubelskie', 'Terespol', 'To mniejsze starorzecze, będące częścią kompleksu Szostaki, charakteryzuje się płytszą wodą i znacznym zamuleniem dna. Brak stałego połączenia z rzeką główną sprawia, że jest ono bardziej podatne na wahania poziomu wody i okresowe wysychanie w upalne lata. Brzegi są częściowo dostępne, choć miejscami porasta je trzcina i krzewy. Dominującymi gatunkami ryb są karasie, zarówno pospolite, jak i srebrzyste, które doskonale radzą sobie w trudnych warunkach środowiskowych. Można tu również spotkać liny i wzdręgi, szczególnie w partiach z gęstą roślinnością podwodną. Wędkarstwo wymaga delikatności i użycia lekkiego sprzętu, a najlepsze brania przypadają na wiosnę, gdy woda jest świeża i bogata w tlen. Z uwagi na płytkość, latem ryzyko przyduchy jest wysokie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21666, 2.8, 1.2, 2.5, 'Brak', 'Wysokie', 'Umiarkowane', TRUE, TRUE, 'Karaś pospolity,Karaś srebrzysty,Lin,Wzdręga', 'Miejscami dobry, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21667, 'Starorzecze Szostaki C', 'starorzecze-szostaki-c-terespol-21667', 'OXBOW', 51.828315, 23.609642, 'Lubelskie', 'Terespol', 'Starorzecze Szostaki C wyróżnia się na tle innych zbiorników kompleksu stosunkowo czystym dnem i lepszą dostępnością brzegów, co czyni je atrakcyjnym miejscem dla wędkarzy. Jest to głębszy zbiornik, który podczas wysokiej wody łączy się z rzeką Bug, co zapewnia regularne zarybienia i dobrą wymianę wody. Dno jest mniej zamulone, a roślinność podwodna nie jest tak gęsta, co ułatwia prowadzenie zestawów. Dominują tu leszcze i płocie, często osiągające znaczne rozmiary, a także okonie i szczupaki, które polują na drobną rybę. Brak ryzyka przyduchy sprawia, że łowisko jest aktywne przez cały sezon wędkarski. Dostęp do wody jest komfortowy, nie wymaga użycia woderów, co dodatkowo zachęca do odwiedzin.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21667, 4.1, 1.8, 3.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21668, 'Starorzecze Szostaki D', 'starorzecze-szostaki-d-terespol-21668', 'OXBOW', 51.8274835, 23.6122782, 'Lubelskie', 'Terespol', 'To niewielkie i płytkie starorzecze, Starorzecze Szostaki D, jest przykładem zbiornika w zaawansowanym stadium zarastania i zamulania. Brak połączenia z rzeką główną powoduje, że jest ono bardzo wrażliwe na zmiany pogodowe, a w okresach suszy może całkowicie wysychać. Brzegi są praktycznie niedostępne bez woderów, gęsto porośnięte trzciną i inną roślinnością szuwarową. Dno jest bardzo muliste i pełne zatopionych resztek roślinnych, co stwarza idealne warunki dla karasi pospolitych i linów. Wzdręgi również licznie występują w gęstej roślinności podwodnej. Wędkarstwo tutaj to wyzwanie, wymagające cierpliwości i umiejętności łowienia w trudnych warunkach, a najlepsze efekty daje wczesną wiosną, zanim roślinność osiągnie pełnię rozwoju.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21668, 1.9, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21669, 'Starorzecze Szostaki E', 'starorzecze-szostaki-e-terespol-21669', 'OXBOW', 51.8255937, 23.6144084, 'Lubelskie', 'Terespol', 'Starorzecze Szostaki E to jeden z większych zbiorników w kompleksie, charakteryzujący się zróżnicowaną głębokością i umiarkowanym zamuleniem. Okresowe połączenie z Bugiem sprzyja migracji ryb i utrzymaniu dobrej jakości wody, minimalizując ryzyko przyduchy. Brzegi są miejscami łatwo dostępne, oferując wygodne stanowiska, choć w innych partiach mogą być zarośnięte. Występuje tu bogactwo gatunków, w tym okazałe szczupaki i okonie, a także duże leszcze i płocie, które są częstym celem wędkarzy spławikowych i gruntowych. Zdarzają się również sumy, szczególnie w głębszych partiach zbiornika. Łowisko jest atrakcyjne przez cały sezon, oferując różnorodne możliwości wędkowania, zarówno z brzegu, jak i z pontonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21669, 5.2, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Sum', 'Częściowo dobry, częściowo zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21670, 'Starorzecze Szostaki F', 'starorzecze-szostaki-f-terespol-21670', 'OXBOW', 51.8234543, 23.6107952, 'Lubelskie', 'Terespol', 'To starorzecze, Starorzecze Szostaki F, jest typowym przykładem zbiornika w zaawansowanym stadium sukcesji, z bardzo mulistym dnem i obfitością roślinności. Brak połączenia z rzeką główną sprawia, że woda jest tu cieplejsza i wolniej się wymienia, co zwiększa ryzyko przyduchy w upalne lata. Brzegi są bagniste i gęsto zarośnięte, co znacząco utrudnia dostęp do wody i wymaga użycia woderów. Dominującymi gatunkami są liny, karasie pospolite oraz wzdręgi, które doskonale czują się w tak trudnych warunkach. Wędkarstwo wymaga precyzji w zarzucaniu i umiejętności prowadzenia zestawów wśród podwodnych przeszkód. Najlepsze efekty można osiągnąć wczesną wiosną, gdy ryby są aktywne po zimie i przed intensywnym rozwojem roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21670, 2.2, 1.3, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna, zatopione krzewy', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21671, 'Starorzecze Szostaki G', 'starorzecze-szostaki-g-terespol-21671', 'OXBOW', 51.8247343, 23.6181599, 'Lubelskie', 'Terespol', 'Starorzecze Szostaki G wyróżnia się stałym połączeniem z rzeką Bug, co zapewnia ciągłą wymianę wody i bogactwo gatunkowe typowe dla rzek nizinnych. Dzięki temu, woda jest tu dobrze natleniona, a ryzyko przyduchy jest minimalne, co sprzyja aktywności ryb przez cały rok. Dno jest stosunkowo czyste, z umiarkowanym zamuleniem i roślinnością podwodną, co ułatwia wędkowanie. Oprócz typowych dla starorzeczy płoci, leszczy i okoni, można tu spotkać bardziej rzeczne gatunki, takie jak jazie i klenie, które wpływają z Bugu. Dostęp do łowiska jest dobry z jednej strony, oferując komfortowe stanowiska. Jest to idealne miejsce dla wędkarzy poszukujących różnorodności i stabilnych warunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21671, 3.8, 1.7, 3.2, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Jaź,Kleń', 'Dobry z jednej strony, zarośnięty z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21672, 'Starorzecze Szostaki H', 'starorzecze-szostaki-h-terespol-21672', 'OXBOW', 51.8229077, 23.614724, 'Lubelskie', 'Terespol', 'Starorzecze Szostaki H to zbiornik o charakterze dzikim, z licznymi zatopionymi drzewami i gęstą roślinnością brzegową, co czyni go wyzwaniem dla wędkarzy. Dno jest muliste i pełne zaczepów, co wymaga stosowania mocniejszego sprzętu i ostrożności. Połączenie z Bugiem następuje tylko podczas wysokich stanów wody, co wpływa na jego ekosystem. Wśród dominujących gatunków ryb znajdują się szczupaki, które doskonale maskują się w podwodnych strukturach, a także liny i karasie pospolite, żerujące w mulistym dnie. Zdarzają się również węgorze, zwłaszcza w cieplejszych miesiącach. Dostęp do wody jest trudny, często wymaga przedzierania się przez krzewy i użycia woderów. Najlepsze okresy połowów to wiosna i jesień, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21672, 2.5, 1.4, 2.9, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Węgorz', 'Trudny, zarośnięty krzewami', TRUE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21673, 'Starorzecze Szostaki I', 'starorzecze-szostaki-i-terespol-21673', 'OXBOW', 51.8220417, 23.6166302, 'Lubelskie', 'Terespol', 'To bardzo płytkie i mocno zarośnięte starorzecze, Starorzecze Szostaki I, jest typowym przykładem zbiornika w końcowym stadium życia, z silnym zamuleniem i gęstą roślinnością. Brak połączenia z rzeką główną i niewielka głębokość sprawiają, że jest ono bardzo podatne na wysychanie w okresach długotrwałych upałów. Brzegi są praktycznie niedostępne bez woderów, a wędkarstwo wymaga cierpliwości i umiejętności łowienia w gęstych zaroślach. Dominującymi gatunkami są odporne karasie srebrzyste i wzdręgi, a także pojedyncze liny, które potrafią przetrwać w trudnych warunkach. Łowisko to stanowi ostoję dla wielu gatunków płoci i drobnej ryby. Najlepsze efekty można osiągnąć wczesną wiosną, zanim roślinność wodna rozwinie się w pełni, utrudniając prowadzenie zestawów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21673, 1.5, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Lin', 'Mocno zarośnięty trzciną i roślinnością', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21674, 'Starorzecze Szostaki J', 'starorzecze-szostaki-j-terespol-21674', 'OXBOW', 51.8229125, 23.6171424, 'Lubelskie', 'Terespol', 'Starorzecze Szostaki J to zbiornik o umiarkowanych rozmiarach i głębokości, oferujący dobre warunki do wędkowania. Okresowe połączenie z rzeką Bug zapewnia świeżą wodę i migrację ryb, co pozytywnie wpływa na populację. Dno jest średnio zamulone, z umiarkowaną ilością roślinności podwodnej, co pozwala na różnorodne techniki połowu. Dostęp do łowiska jest dobry z jednej strony, co ułatwia rozstawienie sprzętu i komfortowe wędkowanie. Dominują tu płocie i leszcze, często w pokaźnych rozmiarach, a także drapieżne okonie i szczupaki, które można łowić na spinning lub żywca. Łowisko jest aktywne przez cały sezon, choć najlepsze brania często przypadają na okresy stabilnej pogody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21674, 2.9, 1.6, 3.1, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry z jednej strony', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21675, 'Starorzecze Szostaki K', 'starorzecze-szostaki-k-terespol-21675', 'OXBOW', 51.8225616, 23.6184381, 'Lubelskie', 'Terespol', 'To starorzecze, Starorzecze Szostaki K, jest głębsze niż niektóre sąsiednie, ale charakteryzuje się znacznym zamuleniem i gęstą roślinnością. Brak połączenia z Bugiem sprawia, że woda jest tu spokojniejsza i cieplejsza, co sprzyja rozwojowi bujnej flory i fauny. Dostęp do brzegów jest bardzo trudny, wymaga przedzierania się przez zarośla i użycia woderów, co czyni to łowisko idealnym dla poszukiwaczy dzikich, nietkniętych miejsc. Dominującymi gatunkami są liny i karasie pospolite, które doskonale czują się w mulistym dnie, a także wzdręgi i węgorze. Ryzyko przyduchy latem jest wysokie, dlatego najlepsze efekty osiąga się wiosną i wczesnym latem, zanim upały obniżą poziom tlenu w wodzie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21675, 3.2, 1.8, 3.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Węgorz', 'Trudny, bagnisty, zarośnięty', TRUE, 'Gęsta roślinność podwodna, muliste dno', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21676, 'Starorzecze Szostaki L', 'starorzecze-szostaki-l-terespol-21676', 'OXBOW', 51.8217485, 23.6205184, 'Lubelskie', 'Terespol', 'Starorzecze Szostaki L to jeden z głębszych i większych zbiorników w okolicy, z okresowym połączeniem z rzeką Bug, co zapewnia mu dobrą kondycję hydrologiczną. Dno jest stosunkowo czyste, z umiarkowaną ilością roślinności, co sprzyja różnorodności gatunkowej ryb. Brzegi są miejscami dobrze dostępne, co ułatwia wędkowanie z brzegu, choć w innych partiach mogą być zarośnięte. Wśród dominujących gatunków znajdują się okazałe szczupaki i okonie, a także duże leszcze i płocie. Zdarzają się tu również karpie, które wpływają z Bugu podczas wezbrań. Łowisko jest atrakcyjne przez cały sezon, oferując wędkarzom możliwość łowienia zarówno drapieżników, jak i ryb spokojnego żeru, w zależności od preferowanej techniki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21676, 4.5, 2.1, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Karp', 'Częściowo dobry, częściowo zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21677, 'Starorzecze Szostaki M', 'starorzecze-szostaki-m-terespol-21677', 'OXBOW', 51.821518, 23.620239, 'Lubelskie', 'Terespol', 'To niewielkie i bardzo płytkie starorzecze, Starorzecze Szostaki M, jest silnie zamulone i gęsto zarośnięte, co sprawia, że jest to łowisko dla wytrwałych. Brak połączenia z rzeką główną i niewielka głębokość czynią je bardzo podatnym na wysychanie w upalne lata, co ogranicza populacje ryb. Brzegi są praktycznie niedostępne bez woderów, porośnięte gęstą trzciną i inną roślinnością szuwarową. Dominującymi gatunkami są odporne karasie, zarówno pospolite, jak i srebrzyste, które doskonale radzą sobie w trudnych warunkach. Można tu również spotkać wzdręgi, szczególnie w partiach z gęstą roślinnością. Wędkarstwo wymaga delikatności i użycia lekkiego sprzętu, a najlepsze brania przypadają na wczesną wiosnę, zanim roślinność osiągnie pełnię rozwoju.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21677, 1.8, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Karaś srebrzysty,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21678, 'Starorzecze Szostaki N', 'starorzecze-szostaki-n-terespol-21678', 'OXBOW', 51.8208656, 23.6187313, 'Lubelskie', 'Terespol', 'Starorzecze Szostaki N to zbiornik o zróżnicowanej głębokości i umiarkowanym zamuleniu, oferujący dobre warunki do wędkowania. Okresowe połączenie z Bugiem zapewnia wymianę wody i migrację ryb, co utrzymuje zdrową populację. Dno jest średnio muliste, z umiarkowaną ilością roślinności podwodnej, co pozwala na różnorodne techniki połowu. Dostęp do łowiska jest dobry z jednej strony, co ułatwia rozstawienie sprzętu i komfortowe wędkowanie. Dominują tu liny i karasie pospolite, które żerują w mulistym dnie, a także płocie i okonie. Łowisko jest aktywne przez większość sezonu, oferując wędkarzom możliwość łowienia zarówno z brzegu, jak i z pontonu, w zależności od preferencji. Jest to miejsce cenione za spokój i obfitość ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21678, 2.6, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Płoć,Okoń', 'Dobry z jednej strony, zarośnięty z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21679, 'Starorzecze Parośla', 'starorzecze-parosla-terespol-21679', 'OXBOW', 51.816469, 23.6063824, 'Lubelskie', 'Terespol', 'Starorzecze Parośla to duży i głęboki zbiornik wodny, wyróżniający się stałym połączeniem z rzeką Bug, co zapewnia mu doskonałe warunki hydrologiczne i bogactwo gatunkowe. Dno jest stosunkowo czyste, z niewielkim zamuleniem i umiarkowaną roślinnością podwodną, co sprzyja rozwojowi dużych populacji ryb. Brzegi są łatwo dostępne z obu stron, oferując liczne, komfortowe stanowiska wędkarskie. Jest to łowisko znane z obecności okazałych szczupaków, leszczy i płoci, a także dużych karpi i sumów, które regularnie wpływają z rzeki. Występują tu również węgorze, zwłaszcza w cieplejszych miesiącach. Stabilne warunki i brak ryzyka przyduchy sprawiają, że Starorzecze Parośla jest atrakcyjne dla wędkarzy przez cały rok, niezależnie od preferowanej metody połowu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21679, 6, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Karp,Sum,Węgorz', 'Dobry z obu stron', FALSE, 'Czyste dno, pojedyncze zatopione pnie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21680, 'Starorzecze (Parośla)', 'starorzecze-parosla-jableczna-21680', 'OXBOW', 51.816578, 23.6110536, 'Lubelskie', 'Jabłeczna', 'To malownicze starorzecze, położone w pobliżu Jabłecznej, charakteryzuje się umiarkowanie zarośniętymi brzegami, co zapewnia zarówno miejsca do wędkowania, jak i schronienie dla ryb. Dno jest muliste z twardszymi fragmentami żwiru, a głębokość waha się od płytkich zatoczek do głębszych rynien. Wiosną i podczas obfitych opadów łączy się z rzeką, co sprzyja migracji ryb. Występuje tu bogata populacja szczupaka, lina oraz płoci i leszcza, co czyni je atrakcyjnym łowiskiem dla wielu wędkarzy. Roślinność podwodna, choć umiarkowana, stanowi idealne kryjówki dla drapieżników. Dostęp do łowiska jest stosunkowo łatwy, z kilkoma dogodnymi stanowiskami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21680, 3.2, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21681, 'Starorzecze (Parośla)', 'starorzecze-parosla-jableczna-21681', 'OXBOW', 51.8120624, 23.6049662, 'Lubelskie', 'Jabłeczna', 'To starorzecze, również w okolicy Jabłecznej, jest znacznie bardziej zarośnięte i zamulone niż jego sąsiad, co stwarza specyficzne warunki wędkarskie. Brzegi są bagniste i trudno dostępne, często wymagające użycia brodzaków. Dno jest w przeważającej części pokryte grubą warstwą mułu i gęstą roślinnością podwodną, co stanowi wyzwanie dla wędkarzy. Ze względu na brak stałego połączenia z rzeką i silne zarastanie, istnieje ryzyko przyduchy w okresie letnim. Dominują tu gatunki odporne na trudne warunki, takie jak karaś pospolity, lin, wzdręga i okoń. Jest to idealne miejsce dla wędkarzy poszukujących spokoju i wyzwań w naturalnym, dzikim środowisku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21681, 2.1, 1.5, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21682, 'Starorzecze (Jabłeczna)', 'starorzecze-jableczna-jableczna-21682', 'OXBOW', 51.7958077, 23.5961216, 'Lubelskie', 'Jabłeczna', 'Starorzecze Jabłeczna to rozległe i głębokie łowisko, które utrzymuje stałe połączenie z rzeką, co gwarantuje ciągłą wymianę wody i bogactwo gatunkowe. Brzegi są przeważnie stabilne i łatwo dostępne, z miejscowymi zaroślami trzcinowymi stanowiącymi schronienie dla ryb. Dno jest zróżnicowane, od piaszczystych płycizn po głębokie, muliste rynny z pojedynczymi zaczepami. Ze względu na stałe połączenie, ryzyko przyduchy jest minimalne, a poziom zamulenia niski. Jest to doskonałe miejsce do połowu szczupaka, leszcza, płoci, okonia, a także bolenia, który wpływa z rzeki. Łowisko oferuje komfortowe warunki dla wędkarzy przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21682, 4.5, 2, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21683, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21683', 'OXBOW', 51.7931367, 23.5959849, 'Lubelskie', 'Nowosiółki', 'To niewielkie starorzecze w Nowosiółkach charakteryzuje się silnym zarastaniem i umiarkowanym zamuleniem, co sprzyja rozwojowi bujnej roślinności wodnej. Brzegi są gęsto porośnięte trzciną i inną roślinnością przybrzeżną, utrudniając dostęp do wody bez brodzaków. Dno jest miękkie, muliste, z licznymi podwodnymi zaroślami, które stanowią doskonałe kryjówki dla ryb. Połączenie z rzeką następuje tylko podczas wysokiej wody, co ogranicza migracje i zwiększa ryzyko niedoboru tlenu latem. Dominują tu gatunki typowe dla płytkich, zarośniętych wód, takie jak karaś pospolity, lin i wzdręga. Jest to łowisko dla cierpliwych wędkarzy, ceniących dziką przyrodę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21683, 1.8, 1, 2, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21684, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21684', 'OXBOW', 51.7941907, 23.5983559, 'Lubelskie', 'Nowosiółki', 'To starorzecze, położone niedaleko Nowosiółek, wyróżnia się relatywnie czystym dnem i umiarkowanym zarastaniem, co ułatwia wędkowanie. Mimo braku stałego połączenia z rzeką, głębokość i ogólne warunki sprzyjają utrzymaniu dobrej jakości wody. Brzegi są łatwo dostępne, z dogodnymi miejscami do ustawienia sprzętu. Dno jest przeważnie twarde, piaszczysto-żwirowe, z nielicznymi zaczepami, co pozwala na różnorodne techniki połowu. Występuje tu zdrowa populacja szczupaka i okonia, a także płoci i leszcza. Łowisko jest cenione za komfortowe warunki i szansę na złowienie dorodnych drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21684, 2.5, 1.7, 3, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21685, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21685', 'OXBOW', 51.7946572, 23.5962916, 'Lubelskie', 'Nowosiółki', 'To starorzecze jest jednym z najpłytszych i najbardziej zarośniętych w okolicy Nowosiółek, co sprawia, że latem może częściowo wysychać. Dno jest bardzo muliste, a gęsta roślinność podwodna utrudnia prowadzenie przynęt. Brzegi są bagniste i trudno dostępne, często wymagając brodzenia. Ze względu na te warunki, ryzyko przyduchy jest wysokie, a populacja ryb ograniczona do gatunków najbardziej odpornych. Dominują tu karasie srebrzyste i wzdręgi, które dobrze radzą sobie w płytkich, ciepłych wodach. Jest to łowisko dla wędkarzy szukających specyficznych wyzwań i ceniących obserwację dzikiej przyrody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21685, 1.2, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21686, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21686', 'OXBOW', 51.7951393, 23.5948231, 'Lubelskie', 'Nowosiółki', 'To starorzecze w Nowosiółkach jest cenione za swoją głębokość i stosunkowo niewielkie zarastanie, co sprzyja różnorodnym technikom wędkarskim. Dno jest mieszane, z przewagą twardszych fragmentów, choć występują też miejsca z lekkim zamuleniem i pojedynczymi zaczepami. Brzegi są łatwo dostępne, oferując wiele komfortowych stanowisk. Połączenie z rzeką podczas wysokiej wody zapewnia regularne zasilanie w wodę i migrację ryb. Wśród dominujących gatunków można wymienić szczupaka, leszcza, karpia oraz płoci, co czyni je atrakcyjnym miejscem zarówno dla spinningistów, jak i wędkarzy gruntowych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21686, 3, 1.9, 3.8, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Leszcz,Karp,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21687, 'Starorzecze (Nowosiółki)', 'starorzecze-nowosiolki-nowosiolki-21687', 'OXBOW', 51.7946736, 23.5930294, 'Lubelskie', 'Nowosiółki', 'Kolejne starorzecze w pobliżu Nowosiółek, charakteryzujące się umiarkowanym zamuleniem i zarastaniem, co tworzy idealne warunki dla ryb ceniących osłonięte środowisko. Brzegi są miejscami trudno dostępne z powodu gęstych trzcin, wymagających użycia brodzaków dla komfortowego wędkowania. Dno jest muliste z licznymi podwodnymi zaroślami i zatopionymi gałęziami, stanowiącymi naturalne kryjówki. Brak stałego połączenia z rzeką może prowadzić do spadku poziomu tlenu w upalne lata. Dominujące gatunki to lin, karaś pospolity, okoń i wzdręga, co czyni je atrakcyjnym dla wędkarzy preferujących metody spławikowe i gruntowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21687, 2.8, 1.6, 3.2, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Okoń,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21688, 'Starorzecze (Witów)', 'starorzecze-witow-witow-21688', 'OXBOW', 49.3293926, 19.8289711, 'Małopolskie', 'Witów', 'To niewielkie starorzecze w Witowie, położone w malowniczej Małopolsce, jest płytkie i silnie zarośnięte, co sprawia, że w okresach suszy może całkowicie wysychać. Dno jest bardzo muliste, a gęsta roślinność podwodna i przybrzeżna tworzą labirynt dla wędkarzy. Brzegi są bagniste i trudno dostępne, często wymagając brodzenia. Ze względu na te ekstremalne warunki, ryzyko przyduchy jest bardzo wysokie. Występują tu głównie gatunki tolerujące trudne warunki, takie jak karaś srebrzysty i wzdręga. Jest to łowisko dla wędkarzy poszukujących unikalnych doświadczeń w dzikim, górskim krajobrazie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21688, 0.9, 0.7, 1.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21689, 'Starorzecze (Dąbrówka)', 'starorzecze-dabrowka-dabrowka-21689', 'OXBOW', 52.8949048, 21.418467, 'Mazowieckie', 'Dąbrówka', 'Starorzecze Dąbrówka na Mazowszu to imponujące łowisko o stałym połączeniu z rzeką, co zapewnia doskonałą jakość wody i bogactwo rybostanu. Charakteryzuje się znaczną głębokością i czystym, zróżnicowanym dnem, gdzie piaszczyste płycizny przeplatają się z głębszymi rynnami. Brzegi są łatwo dostępne, z licznymi dogodnymi stanowiskami wędkarskimi. Niskie zamulenie i słabe zarastanie sprawiają, że jest to idealne miejsce dla różnorodnych technik. Dominują tu drapieżniki takie jak szczupak i sandacz, a także liczny leszcz, płoć i węgorz. Jest to jedno z najlepszych starorzeczy w regionie, oferujące wędkarzom szansę na naprawdę duże okazy przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21689, 5, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Węgorz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21690, 'Starorzecze (Głęboczek)', 'starorzecze-gleboczek-gleboczek-21690', 'OXBOW', 52.8473932, 15.7652059, 'Lubuskie', 'Głęboczek', 'Starorzecze Głęboczek to rozległe i głębokie łowisko w Lubuskiem, znane z obecności dużych sumów i szczupaków. Charakteryzuje się zróżnicowanym dnem z licznymi zatopionymi drzewami, które stanowią doskonałe kryjówki dla ryb, ale mogą być wyzwaniem dla wędkarzy. Brzegi są łatwo dostępne, choć miejscami porośnięte roślinnością. Połączenie z rzeką podczas wysokiej wody sprzyja odnowie populacji ryb i utrzymaniu dobrej jakości wody. Oprócz sumów i szczupaków, łowisko obfituje w leszcze, karpie i płocie, co czyni je atrakcyjnym dla wędkarzy preferujących różne metody. Jest to miejsce z potencjałem na rekordowe okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21690, 6.5, 3, 6, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Leszcz,Karp,Płoć', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21691, 'Starorzecze (Szczepanki)', 'starorzecze-szczepanki-szczepanki-21691', 'OXBOW', 53.4764675, 19.0452516, 'Kujawsko-Pomorskie', 'Szczepanki', 'To starorzecze w Szczepankach na Kujawach charakteryzuje się silnym zarastaniem i umiarkowanym zamuleniem, co tworzy typowe warunki dla wód stojących. Brzegi są gęsto porośnięte trzciną, co utrudnia dostęp do wody i wymaga użycia brodzaków. Dno jest muliste, z licznymi podwodnymi zaroślami, które stanowią doskonałe kryjówki dla ryb, ale również pułapki dla przynęt. Brak połączenia z rzeką zwiększa ryzyko niedoboru tlenu w upalne miesiące. Dominujące gatunki to lin, karaś pospolity, wzdręga i okoń, które dobrze adaptują się do tego typu środowiska. Jest to łowisko dla wędkarzy ceniących spokój i wyzwania związane z gęstą roślinnością.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21691, 1.5, 1.2, 2.5, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21692, 'Starorzecze (Hermanowo)', 'starorzecze-hermanowo-hermanowo-21692', 'OXBOW', 53.4753415, 19.0500919, 'Kujawsko-Pomorskie', 'Hermanowo', 'Starorzecze w Hermanowie, niedaleko Grudziądza, to atrakcyjne łowisko o umiarkowanym zarastaniu i niskim poziomie zamulenia. Charakteryzuje się zróżnicowanym dnem z piaszczystymi fragmentami i miejscowymi zaczepami w postaci korzeni. Brzegi są łatwo dostępne, oferując komfortowe miejsca do wędkowania. Połączenie z rzeką podczas wysokiej wody zapewnia regularne zarybianie i utrzymanie zdrowej populacji ryb. Występują tu liczne szczupaki i okonie, a także płocie i leszcze, co sprawia, że jest to popularne miejsce dla wędkarzy spinningowych i spławikowych. Łowisko jest idealne na wiosenne i jesienne wyprawy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21692, 2, 1.5, 2.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21693, 'Starorzecze (Hermanowo)', 'starorzecze-hermanowo-hermanowo-21693', 'OXBOW', 53.4749496, 19.0515097, 'Kujawsko-Pomorskie', 'Hermanowo', 'To starorzecze, również w Hermanowie, jest znacznie płytsze i bardziej zarośnięte niż jego sąsiad, co stwarza odmienne warunki wędkarskie. Dno jest silnie zamulone i pokryte gęstą roślinnością podwodną, co wymaga precyzyjnego prowadzenia przynęt. Brzegi są bagniste i trudno dostępne, często wymagające użycia brodzaków. Brak połączenia z rzeką i obfita roślinność zwiększają ryzyko niedoboru tlenu w letnie upały. Dominują tu gatunki odporne na trudne warunki, takie jak karaś pospolity, lin i wzdręga. Jest to łowisko dla wędkarzy ceniących wyzwania i poszukujących spokoju w dzikim zakątku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21693, 1.8, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21694, 'Starorzecze (Hermanowo)', 'starorzecze-hermanowo-hermanowo-21694', 'OXBOW', 53.4743042, 19.0522073, 'Kujawsko-Pomorskie', 'Hermanowo', 'Ostatnie starorzecze w Hermanowie to przykład dobrze utrzymanego i łatwo dostępnego łowiska ze stałym połączeniem z rzeką. Charakteryzuje się czystym dnem, minimalnym zamuleniem i słabym zarastaniem, co sprzyja aktywnemu wędkowaniu. Głębokość jest umiarkowana, z miejscowymi zagłębieniami, które stanowią atrakcyjne miejsca dla ryb. Brzegi są stabilne i oferują wiele wygodnych stanowisk. Stały przepływ wody gwarantuje optymalne warunki tlenowe przez cały rok. Występują tu liczne szczupaki, okonie, leszcze, płocie, a także jaź, co czyni je atrakcyjnym dla wędkarzy preferujących różnorodne metody. To doskonałe miejsce na relaksujące wędkowanie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21694, 2.3, 1.7, 3, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Jaź', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21695, 'Starorzecze Słup 1', 'starorzecze-slup-1-slup-21695', 'OXBOW', 53.4696148, 19.0637895, 'Kujawsko-Pomorskie', 'Słup', 'To stosunkowo niewielkie starorzecze, położone w pobliżu Słupu, charakteryzuje się mulistym dnem i obfitością podwodnej roślinności. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je gęsta trzcina, co wymaga użycia woderów. Woda jest płytka, co sprzyja rozwojowi lina i karasia, a także populacji szczupaka. Akwen ten jest typowym, spokojnym łowiskiem, gdzie liczy się cierpliwość i znajomość miejscówek. W cieplejszych miesiącach istnieje umiarkowane ryzyko niedoboru tlenu. Najlepsze wyniki osiąga się wiosną i jesienią, kiedy roślinność jest mniej bujna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21695, 2.8, 1.2, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21696, 'Starorzecze Słup 2', 'starorzecze-slup-2-slup-21696', 'OXBOW', 53.4694812, 19.064001, 'Kujawsko-Pomorskie', 'Słup', 'Drugie starorzecze w rejonie Słupu wyróżnia się nieco większą głębokością w centralnej części, co sprzyja większym okazom ryb. Dno jest zróżnicowane, od mulistego po miejscami twardsze, piaszczyste plamy, co oferuje różnorodne środowiska. Brzegi są stosunkowo łatwo dostępne z jednej strony, natomiast z drugiej mocno zarośnięte drzewami i krzewami. Występuje tu bogata populacja leszcza i płoci, a także drapieżników takich jak okoń i szczupak. Wędkowanie utrudnia umiarkowane zarośnięcie podwodne i liczne zatopione gałęzie. Akwen jest popularny wśród lokalnych wędkarzy przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21696, 4.1, 1.8, 3.5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak', 'Dobry z jednej strony, trudny z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21697, 'Starorzecze Słup 3', 'starorzecze-slup-3-slup-21697', 'OXBOW', 53.4704198, 19.0601607, 'Kujawsko-Pomorskie', 'Słup', 'To starorzecze charakteryzuje się silnym zarośnięciem brzegów i dużą ilością roślinności podwodnej, co czyni je wymagającym łowiskiem dla doświadczonych wędkarzy. Dno jest w przeważającej części muliste, z licznymi osadami dennymi, co sprzyja rozwojowi specyficznych gatunków. Jest to idealne środowisko dla karasia pospolitego i lina, które często osiągają tu imponujące rozmiary. Dostęp do wody jest utrudniony, często wymaga przedzierania się przez gęste zarośla i użycia woderów. Wędkarze poszukujący spokoju i wyzwań znajdą tu swoje miejsce. W cieplejszych miesiącach należy zachować ostrożność ze względu na ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21697, 3.5, 1, 2.2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21698, 'Starorzecze Hermanowo', 'starorzecze-hermanowo-hermanowo-21698', 'OXBOW', 53.4734392, 19.0582931, 'Kujawsko-Pomorskie', 'Hermanowo', 'Starorzecze w Hermanowie to rozległy akwen z dobrze rozwiniętą linią brzegową, częściowo dostępną dla wędkarzy, co ułatwia wybór stanowiska. Dno jest zróżnicowane, z przewagą mułu, ale występują też twardsze partie, co sprzyja różnym gatunkom ryb. Zbiornik jest domem dla wielu gatunków, w tym dużych karpi i sumów, które znajdują tu dogodne warunki do życia i żerowania. Roślinność podwodna jest umiarkowana, co ułatwia wędkowanie, jednak w niektórych miejscach występują zatopione drzewa. Jest to popularne miejsce na weekendowe wypady, oferujące szansę na złowienie naprawdę dużego okazu. Poziom zamulenia jest średni, a ryzyko przyduchy niewielkie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21698, 7.5, 2.5, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Sum,Leszcz,Płoć,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21699, 'Starorzecze Słup 4', 'starorzecze-slup-4-slup-21699', 'OXBOW', 53.4740061, 19.0556548, 'Kujawsko-Pomorskie', 'Słup', 'To starorzecze jest jednym z bardziej dzikich w okolicy Słupu, charakteryzującym się bagnistymi brzegami i bardzo trudnym dostępem do wody. Dno jest głęboko muliste, a akwen jest silnie zarośnięty zarówno roślinnością przybrzeżną, jak i podwodną, co stanowi wyzwanie dla wędkarzy. Jest to królestwo lina i karasia pospolitego, które doskonale czują się w tych warunkach, osiągając często imponujące rozmiary. Wędkarstwo tutaj to prawdziwe wyzwanie, wymagające cierpliwości i odpowiedniego sprzętu, w tym woderów do brodzenia. Ze względu na płytkość i gęstą roślinność, ryzyko niedoboru tlenu jest wysokie latem. Najlepsze efekty można osiągnąć wiosną, gdy roślinność jest mniej bujna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21699, 2, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21700, 'Starorzecze Jabłonka', 'starorzecze-jablonka-jablonka-21700', 'OXBOW', 49.4654975, 19.7357348, 'Małopolskie', 'Jabłonka', 'Starorzecze w Jabłonce, położone w malowniczej Orawie, charakteryzuje się czystszą wodą niż typowe nizinne starorzecza, co wynika z górskiego charakteru rzek zasilających region. Dno jest mieszane, z przewagą piasku i żwiru, choć w zatokach występuje muł, zapewniając różnorodne środowiska. Brzegi są częściowo zalesione, oferując cień i dogodne stanowiska dla wędkarzy. W akwenie dominują gatunki takie jak płoć, okoń i leszcz, a także sporadycznie szczupak, co świadczy o zdrowym ekosystemie. Poziom zamulenia jest niski, a roślinność podwodna umiarkowana, co ułatwia wędkowanie. To doskonałe miejsce na relaks i aktywne spędzanie czasu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21700, 5, 2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Okoń,Leszcz,Szczupak', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21701, 'Starorzecze Witów', 'starorzecze-witow-witow-21701', 'OXBOW', 49.3342624, 19.8291971, 'Małopolskie', 'Witów', 'To unikalne starorzecze w Tatrach, niedaleko Witowa, wyróżnia się krystalicznie czystą, zimną wodą, typową dla regionów górskich. Dno jest głównie kamieniste i żwirowe, z niewielkimi osadami mulistymi w najgłębszych partiach, co zapewnia idealne warunki dla specyficznych gatunków. Brzegi są skaliste i zalesione, co zapewnia malownicze widoki, ale utrudnia dostęp w niektórych miejscach, często wymagając użycia woderów. W akwenie można spotkać pstrągi (jeśli jest połączenie z rzeką górską) oraz klenie i jazie, choć te ostatnie rzadziej. Roślinność podwodna jest bardzo skąpa. To łowisko dla wędkarzy ceniących trudniejsze warunki i dziką, górską przyrodę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21701, 1.5, 1, 2.5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Kleń,Jaź,Okoń', 'Trudny, skalisty', TRUE, 'Czyste dno', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21702, 'Starorzecze Harklowa 1', 'starorzecze-harklowa-1-harklowa-21702', 'OXBOW', 49.4741504, 20.1452655, 'Małopolskie', 'Harklowa', 'Starorzecze Harklowa 1, położone w dolinie Dunajca, jest zbiornikiem o umiarkowanej wielkości, z dnem pokrytym mieszanką piasku i mułu, co świadczy o jego dynamicznym charakterze. Brzegi są częściowo dostępne, z fragmentami porośniętymi trzciną oraz drzewami liściastymi, oferując różnorodne stanowiska. Woda jest stosunkowo czysta, a roślinność podwodna występuje w umiarkowanym stopniu, tworząc schronienia dla ryb. Jest to dobre miejsce na połów płoci, leszcza i okonia, a także sporadycznie szczupaka, co czyni je atrakcyjnym dla wielu wędkarzy. Akwen jest popularny wśród lokalnych ze względu na stabilne warunki i różnorodność gatunków. Poziom zamulenia jest niski.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21702, 6, 2.2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21703, 'Starorzecze Harklowa 2', 'starorzecze-harklowa-2-harklowa-21703', 'OXBOW', 49.4721128, 20.1876276, 'Małopolskie', 'Harklowa', 'To starorzecze, nieco oddalone od głównego nurtu Dunajca, charakteryzuje się bardziej mulistym dnem i większym zarośnięciem niż jego sąsiad. Brzegi są trudniej dostępne, z przewagą gęstej trzciny i bagnistych fragmentów, co wymaga od wędkarzy większego wysiłku. Jest to idealne środowisko dla lina i karasia pospolitego, które osiągają tu znaczne rozmiary, znajdując obfitość pokarmu. Roślinność podwodna jest bujna, co sprzyja rozwojowi narybku, ale utrudnia wędkowanie, często powodując zaczepy. Wędkarze poszukujący spokoju i walki z silnymi rybami znajdą tu coś dla siebie. W cieplejszych miesiącach istnieje umiarkowane ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21703, 3.8, 1.5, 3, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21704, 'Starorzecze Zabród 1', 'starorzecze-zabrod-1-zabrod-21704', 'OXBOW', 53.5103278, 14.8454296, 'Zachodniopomorskie', 'Zabród', 'Starorzecze Zabród 1, położone w rozległej dolinie Odry, to akwen o zróżnicowanej głębokości i dnie, gdzie dominują muły, ale występują też twardsze partie. Brzegi są częściowo dostępne, z fragmentami zalesionymi i porośniętymi trzciną, co zapewnia różnorodne stanowiska. Zbiornik ten jest znany z obfitości leszczy, płoci i okoni, a także drapieżników takich jak szczupak i sandacz, zwłaszcza po wysokich wodach. Połączenie z rzeką podczas wezbrań zapewnia stałe zarybienie i różnorodność gatunkową, wpływając na dynamikę łowiska. Wędkarstwo tutaj jest dynamiczne i oferuje szansę na złowienie wielu gatunków. Jest to popularne miejsce wśród wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21704, 10, 2.5, 6, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Sandacz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21705, 'Starorzecze Bącznik', 'starorzecze-bacznik-bacznik-21705', 'OXBOW', 53.49902, 14.8555695, 'Zachodniopomorskie', 'Bącznik', 'Starorzecze Bącznik to mniejszy, bardziej kameralny zbiornik, charakteryzujący się mulistym dnem i gęstą roślinnością podwodną, tworzącą idealne kryjówki dla ryb. Brzegi są zarośnięte, co utrudnia dostęp, ale jednocześnie sprzyja spokojnemu i dzikiemu charakterowi łowiska. Jest to doskonałe miejsce dla lina, karasia pospolitego i wzdręgi, które osiągają tu imponujące rozmiary. Zbiornik jest stosunkowo płytki, co sprawia, że w upalne lata istnieje ryzyko niedoboru tlenu, na co wędkarze powinni zwracać uwagę. Wędkarze ceniący spokój i bliski kontakt z naturą znajdą tu idealne warunki do wypoczynku. Najlepsze wyniki osiąga się wiosną i wczesną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21705, 3, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21706, 'Starorzecze Zabród 2', 'starorzecze-zabrod-2-zabrod-21706', 'OXBOW', 53.512068, 14.8435534, 'Zachodniopomorskie', 'Zabród', 'To starorzecze w pobliżu Zabród jest znane z dużej populacji dużych karpi i sumów, które znajdują tu obfitość pokarmu i schronienia, zwłaszcza w głębszych partiach. Dno jest głęboko muliste, z licznymi zatopionymi drzewami i korzeniami, co stanowi wyzwanie dla wędkarzy, ale i atrakcję. Brzegi są częściowo niedostępne ze względu na bagnisty teren i gęste zarośla, co wymaga użycia woderów. Połączenie z głównym nurtem Odry podczas wysokich stanów wody odgrywa kluczową rolę w odnawianiu populacji ryb. Wędkarstwo wymaga tu specjalistycznego sprzętu i dużej cierpliwości, ale nagrodą mogą być rekordowe okazy. Ryzyko niedoboru tlenu jest niskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21706, 8.5, 3, 7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Sum,Leszcz,Węgorz', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21707, 'Starorzecze Zabród 3', 'starorzecze-zabrod-3-zabrod-21707', 'OXBOW', 53.5144233, 14.8433409, 'Zachodniopomorskie', 'Zabród', 'To starorzecze jest mniejsze i płytsze niż inne w rejonie Zabród, co sprzyja szybkiemu nagrzewaniu się wody i intensywnemu rozwojowi roślinności. Dno jest jednolicie muliste, a brzegi są gęsto porośnięte trzciną i krzewami, co sprawia, że dostęp jest bardzo ograniczony. Jest to typowe łowisko dla karasia pospolitego, lina i wzdręgi, które doskonale prosperują w takich warunkach. Latem istnieje wysokie ryzyko niedoboru tlenu, a w skrajnych przypadkach zbiornik może częściowo wyschnąć, co jest wyzwaniem dla ekosystemu. Wędkarstwo tutaj to wyzwanie dla tych, którzy cenią sobie dziki charakter i spokój. Wymaga użycia woderów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21707, 1.8, 0.7, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21708, 'Starorzecze Zabród 4', 'starorzecze-zabrod-4-zabrod-21708', 'OXBOW', 53.5082457, 14.8460974, 'Zachodniopomorskie', 'Zabród', 'Starorzecze Zabród 4 to akwen o średniej wielkości, z dnem pokrytym grubą warstwą mułu, ale z wyraźnymi głębszymi rynnami, co tworzy zróżnicowane siedliska. Brzegi są zróżnicowane, od łatwo dostępnych fragmentów po gęsto zarośnięte trzciną, co pozwala na wybór stanowiska. Zbiornik jest domem dla licznych płoci, leszczy i okoni, a także okazjonalnie szczupaka, co czyni go atrakcyjnym dla wędkarzy. Umiarkowane połączenie z Odrą podczas wezbrań zapewnia dopływ świeżej wody i ryb, odnawiając populacje. Wędkarze mogą liczyć na stabilne połowy przez większość sezonu. Występują tu pojedyncze zatopione drzewa, które stanowią kryjówki dla ryb. Ryzyko niedoboru tlenu jest niskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21708, 5.5, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry z jednej strony, zarośnięty z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21709, 'Starorzecze Zabród 5', 'starorzecze-zabrod-5-zabrod-21709', 'OXBOW', 53.506268, 14.8491022, 'Zachodniopomorskie', 'Zabród', 'Ostatnie starorzecze w rejonie Zabród to długi, wąski akwen o charakterze rynnowym, z dnem głęboko mulistym, co sprzyja bogatej faunie dennej. Brzegi są w większości mocno zarośnięte drzewami i krzewami, co tworzy naturalne zacienienie i liczne zaczepy, stanowiące wyzwanie dla wędkarzy. Jest to idealne środowisko dla dużych szczupaków i sumów, które polują w ukryciu, a także dla lina i karasia srebrzystego. Wędkarstwo jest tu wymagające, często wymaga precyzyjnych rzutów i cierpliwości, ale nagradza dużymi okazami. Ze względu na zacienienie i głębokość, ryzyko niedoboru tlenu jest niskie. Wymaga użycia woderów ze względu na trudny dostęp.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21709, 4, 2, 4, 'Stałe połączenie', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sum,Lin,Karaś srebrzysty', 'Trudny, zarośnięty drzewami', TRUE, 'Dużo zatopionych drzew', 'Wiosna, późne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21710, 'Starorzecze Niedomice I', 'starorzecze-niedomice-i-tarnow-21710', 'OXBOW', 50.1053716, 20.8805206, 'Małopolskie', 'Tarnów', 'To starorzecze, położone w malowniczej dolinie Dunajca, stanowi klasyczny przykład łowiska o bogatej florze i faunie. Dno jest muliste, z licznymi osadami, co sprzyja rozwojowi roślinności podwodnej, takiej jak rdestnice i moczarka. Brzegi są częściowo zarośnięte trzciną i krzewami, co utrudnia dostęp w niektórych miejscach, ale jednocześnie zapewnia schronienie dla ryb. Wędkarze mogą liczyć na udane połowy lina, karasia pospolitego oraz szczupaka, który często czai się w zaroślach. Wiosną i wczesną jesienią woda jest czystsza, co sprzyja aktywności drapieżników. Należy jednak pamiętać o ryzyku przyduchy w upalne lata, ze względu na dużą ilość materii organicznej.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21710, 3, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć,Okoń', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21711, 'Starorzecze Niedomice II', 'starorzecze-niedomice-ii-tarnow-21711', 'OXBOW', 50.1049009, 20.8826977, 'Małopolskie', 'Tarnów', 'To mniejsze starorzecze jest bardziej odizolowane od głównego nurtu rzeki, co sprawia, że jego ekosystem jest bardziej wrażliwy na zmiany. Dno jest bardzo muliste i miękkie, co utrudnia brodzenie i wymaga ostrożności. Brzegi są gęsto porośnięte trzciną i pałką wodną, tworząc niemal nieprzeniknioną barierę dla wędkarzy. Roślinność podwodna jest bardzo silna, co zapewnia doskonałe kryjówki dla drobnicy i ryb spokojnego żeru. Dominują tu karasie pospolite i wzdręgi, które świetnie adaptują się do trudniejszych warunków. W upalne, bezdeszczowe lata istnieje realne ryzyko wyschnięcia zbiornika, co jest największą trudnością dla lokalnej fauny. Jest to idealne miejsce dla cierpliwych wędkarzy, szukających ciszy i spokoju.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21711, 2.5, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21712, 'Starorzecze Biskupice Radłowskie', 'starorzecze-biskupice-radlowskie-dabrowa-tarnowska-21712', 'OXBOW', 50.1375752, 20.8464323, 'Małopolskie', 'Dąbrowa Tarnowska', 'To rozległe starorzecze wyróżnia się większą głębokością i zróżnicowaniem terenu, co czyni je atrakcyjnym dla wielu gatunków ryb. Dno jest mieszane, miejscami twarde, żwirowe, a w zatokach muliste, co sprzyja różnorodności ekosystemu. Brzegi są stosunkowo łatwo dostępne, z naturalnymi miejscami do wędkowania, choć lokalnie mogą występować strefy zarośli. Obfitość roślinności podwodnej i zatopionych drzew stanowi idealne siedliska dla drapieżników, takich jak szczupak i okoń, a także dla dużych leszczy i karpi. Zbiornik ten jest zasilany podczas wysokich stanów wody, co zapewnia dobrą wymianę wody i minimalizuje ryzyko przyduchy. Występowanie suma świadczy o stabilnym i zasobnym środowisku. To łowisko oferuje możliwości dla wędkarzy preferujących różne metody, od spławika po spinning.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21712, 7, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Karp,Okoń,Sum', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21713, 'Starorzecze Sanoka', 'starorzecze-sanoka-tarnow-21713', 'OXBOW', 50.0816311, 20.8862611, 'Małopolskie', 'Tarnów', 'Starorzecze Sanoka to niewielki, urokliwy zbiornik, który zachował swój dziki charakter, będąc ostoją dla wielu gatunków ryb i ptaków wodnych. Dno jest w przeważającej części bardzo muliste i grząskie, co świadczy o zaawansowanym procesie sedymentacji. Brzegi są gęsto zarośnięte, co sprawia, że dostęp do wody jest trudny i wymaga przedzierania się przez gęstą roślinność. Bogata roślinność podwodna i nawodna, w tym lilie wodne, tworzy labirynt idealnych kryjówek. Zbiornik jest całkowicie odcięty od rzeki, co sprawia, że jego ekosystem jest bardzo stabilny, ale jednocześnie wrażliwy na susze. Dominują tu ryby dobrze znoszące niską zawartość tlenu, takie jak karaś pospolity i wzdręga. W upalne lata istnieje wysokie ryzyko wyschnięcia zbiornika, co jest poważnym wyzwaniem dla jego mieszkańców. To miejsce dla prawdziwych pasjonatów dzikiej przyrody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21713, 1.8, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21714, 'Starorzecze Siedlec I', 'starorzecze-siedlec-i-tarnow-21714', 'OXBOW', 50.0823307, 20.8936009, 'Małopolskie', 'Tarnów', 'Starorzecze Siedlec I to część większego kompleksu starorzeczy, charakteryzującego się dobrą jakością wody i zróżnicowanym środowiskiem. Dno jest w większości twarde, piaszczysto-żwirowe, z miejscowymi skupiskami mułu, co świadczy o regularnej wymianie wody. Brzegi są stosunkowo łatwo dostępne, z licznymi dogodnymi stanowiskami wędkarskimi, choć miejscami można napotkać na niewielkie zarośla. Roślinność podwodna jest umiarkowana, co sprzyja zarówno rybom spokojnego żeru, jak i drapieżnikom. Połączenie z rzeką podczas wysokich stanów wody zapewnia stałe zarybianie i odświeżanie ekosystemu. Łowisko to jest znane z obecności szczupaków, leszczy i płoci, a także okazałych okoni. Brak ryzyka przyduchy i stabilny poziom wody sprawiają, że jest to atrakcyjne miejsce przez cały sezon wędkarski.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21714, 4, 1.8, 3.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Lin,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21715, 'Starorzecze Siedlec II', 'starorzecze-siedlec-ii-tarnow-21715', 'OXBOW', 50.0811406, 20.8935178, 'Małopolskie', 'Tarnów', 'Sąsiadujące ze Starorzeczem Siedlec I, ten zbiornik jest nieco płytszy i bardziej zarośnięty, oferując odmienne wyzwania wędkarskie. Dno jest muliste, z grubą warstwą osadów organicznych, co sprzyja rozwojowi gęstej roślinności. Brzegi są trudniej dostępne, obrośnięte gęstymi krzewami i trzciną, co wymaga użycia wodoodpornego obuwia lub brodzenia. Roślinność podwodna jest bujna, tworząc liczne kryjówki dla ryb i utrudniając prowadzenie przynęt. Połączenie z rzeką podczas wezbrań zapewnia dopływ świeżej wody, choć ryzyko przyduchy w okresach suszy jest podwyższone. W zbiorniku dominują liny, karasie pospolite i płocie, które doskonale czują się w zarośniętych i spokojnych wodach. Jest to idealne miejsce do połowu ryb spokojnego żeru na spławik lub grunt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21715, 3.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć,Leszcz', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21716, 'Starorzecze Budzieszewice', 'starorzecze-budzieszewice-nowogard-21716', 'OXBOW', 53.6917659, 14.8507396, 'Zachodniopomorskie', 'Nowogard', 'Starorzecze Budzieszewice, położone w malowniczym krajobrazie Pomorza Zachodniego, jest stosunkowo dużym i głębokim zbiornikiem, oferującym doskonałe warunki wędkarskie. Dno jest zróżnicowane, od piaszczystych płycizn po muliste zagłębienia, co sprzyja różnorodności gatunkowej. Brzegi są w większości łatwo dostępne, z licznymi miejscami do rozstawienia sprzętu, choć miejscami występują pasy trzcin. Roślinność podwodna jest umiarkowana, co pozwala na swobodne prowadzenie przynęt i jednocześnie zapewnia kryjówki dla ryb. Połączenie z rzeką podczas wiosennych roztopów i jesiennych deszczy zapewnia regularne zasilanie w wodę i migrację ryb. Łowisko słynie z dużych szczupaków, sandaczy i okoni, a także dorodnych leszczy i płoci. Jest to idealne miejsce dla wędkarzy spinningowych i gruntowych, poszukujących rekordowych okazów. Stabilne warunki wodne sprawiają, że można tu łowić przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21716, 6, 2.2, 5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Płoć,Sandacz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21717, 'Starorzecze Sromowce Wyżne I', 'starorzecze-sromowce-wyzne-i-kroscienko-nad-dunajcem-21717', 'OXBOW', 49.4138074, 20.3309753, 'Małopolskie', 'Krościenko nad Dunajcem', 'To starorzecze, położone w malowniczej scenerii Pienin, charakteryzuje się krystalicznie czystą wodą i specyficznym, górskim charakterem. Dno jest głównie kamieniste i żwirowe, z miejscowymi osadami mułu, co odróżnia je od typowych starorzeczy nizinnych. Brzegi są zróżnicowane, od kamienistych po częściowo zarośnięte krzewami i drzewami, co utrudnia dostęp w niektórych miejscach. Roślinność podwodna jest umiarkowana, ale występują tu liczne kryjówki w postaci zatopionych kamieni i korzeni. Zbiornik jest zasilany podczas wysokich stanów Dunajca, co zapewnia dobrą wymianę wody i wysoką zawartość tlenu. Dominują tu ryby typowe dla wód nizinnych, ale także gatunki preferujące czystsze wody, takie jak kleń i jaź. Wędkarze mogą liczyć na udane połowy pstrągów, okoni i szczupaków. Wymaga to jednak cierpliwości i umiejętności poruszania się w trudniejszym terenie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21717, 1.5, 1.5, 3, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Okoń,Kleń,Jaź,Szczupak', 'Trudny, skalisty/zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21718, 'Starorzecze Sromowce Wyżne II', 'starorzecze-sromowce-wyzne-ii-kroscienko-nad-dunajcem-21718', 'OXBOW', 49.4132218, 20.3310407, 'Małopolskie', 'Krościenko nad Dunajcem', 'Sąsiadujące starorzecze, choć położone w tej samej górskiej scenerii, jest płytsze i bardziej zarośnięte, co nadaje mu bardziej intymny charakter. Dno jest muliste, z licznymi osadami, co sprzyja rozwojowi gęstej roślinności podwodnej. Brzegi są mocno zarośnięte trzciną i krzewami, co sprawia, że dostęp do wody jest utrudniony i wymaga użycia wodoodpornego obuwia. Bujna roślinność podwodna tworzy doskonałe kryjówki dla drobnicy i ryb spokojnego żeru, ale jednocześnie utrudnia prowadzenie przynęt. Zbiornik jest zasilany podczas wysokich stanów wody, ale jego niewielka głębokość i duża ilość materii organicznej zwiększają ryzyko przyduchy w upalne lata. Dominują tu płocie, wzdręgi, karasie pospolite i liny, które doskonale adaptują się do zarośniętych środowisk. To łowisko wymaga cierpliwości i precyzji w zarzucaniu. Jest to idealne miejsce dla wędkarzy ceniących spokój i kontakt z naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21718, 1.2, 1.2, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Płoć,Wzdręga,Karaś pospolity,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21719, 'Starorzecze Sromowce Wyżne III', 'starorzecze-sromowce-wyzne-iii-kroscienko-nad-dunajcem-21719', 'OXBOW', 49.4085598, 20.3735653, 'Małopolskie', 'Krościenko nad Dunajcem', 'Kolejne starorzecze w rejonie Sromowiec Wyżnych, charakteryzujące się nieco większą głębokością i bardziej otwartymi przestrzeniami. Dno jest mieszane, z przewagą żwiru i piasku, ale z mulistymi zatokami, co sprzyja różnorodności siedlisk. Brzegi są dostępne z jednej strony, natomiast z drugiej strony porośnięte gęstymi krzewami i drzewami, tworząc naturalne osłony. Roślinność podwodna jest umiarkowana, co ułatwia wędkowanie, a jednocześnie zapewnia kryjówki dla ryb. Regularne połączenie z Dunajcem podczas wezbrań zapewnia dopływ świeżej wody i ryb, a także minimalizuje ryzyko przyduchy. W zbiorniku występują szczupaki, okonie, klenie, jazie i płocie, co czyni go atrakcyjnym dla wędkarzy spinningowych i spławikowych. Jest to dobre miejsce na wiosenne i jesienne wyprawy, gdy ryby są najbardziej aktywne. Warto eksplorować różne partie zbiornika, aby znaleźć najlepsze miejsca.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21719, 2, 1.7, 3.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Kleń,Jaź,Płoć', 'Dobry z jednej strony, zarośnięty z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21720, 'Starorzecze Sromowce Wyżne IV', 'starorzecze-sromowce-wyzne-iv-kroscienko-nad-dunajcem-21720', 'OXBOW', 49.4082634, 20.3754173, 'Małopolskie', 'Krościenko nad Dunajcem', 'To bardzo małe i kameralne starorzecze, niemal oczko wodne, które jest schowane wśród gęstej roślinności, oferując prawdziwe wyzwanie dla wędkarzy. Dno jest głęboko muliste, z grubą warstwą osadów organicznych, co jest typowe dla zbiorników odciętych od głównego nurtu. Brzegi są całkowicie zarośnięte, bagniste i trudne do przejścia, co wymaga dużej ostrożności i odpowiedniego sprzętu. Roślinność podwodna i nawodna jest niezwykle bujna, tworząc gęste dywany i utrudniając prowadzenie jakichkolwiek przynęt. Zbiornik jest całkowicie odcięty od rzeki, co sprawia, że jest bardzo wrażliwy na zmiany poziomu wody i temperatury. W upalne lata ryzyko wyschnięcia jest bardzo wysokie, a przyduchy niemal pewne. Dominują tu karasie pospolite, wzdręgi i liny, które są odporne na trudne warunki. Jest to miejsce dla wędkarzy poszukujących unikalnych doświadczeń i ceniących dziką przyrodę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21720, 0.8, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21721, 'Starorzecze Sromowce Wyżne V', 'starorzecze-sromowce-wyzne-v-kroscienko-nad-dunajcem-21721', 'OXBOW', 49.4083377, 20.3748219, 'Małopolskie', 'Krościenko nad Dunajcem', 'To starorzecze jest częścią większego systemu wodnego w rejonie Sromowiec Wyżnych, charakteryzując się umiarkowaną głębokością i zróżnicowanym dnem. Dno jest mieszane, z przewagą mulistych osadów, ale z miejscowymi przejaśnieniami, co sprzyja różnorodności gatunkowej. Brzegi są trudne do przejścia, mocno zarośnięte trzciną i krzewami, co wymaga użycia wodoodpornego obuwia lub brodzenia. Roślinność podwodna jest umiarkowana, ale występują tu liczne kryjówki w postaci zatopionych gałęzi i korzeni. Zbiornik jest zasilany podczas wysokich stanów wody, co zapewnia dopływ świeżej wody, choć ryzyko przyduchy w okresach suszy jest podwyższone. W zbiorniku dominują płocie, okonie, liny i karasie pospolite, które doskonale czują się w zarośniętych i spokojnych wodach. Jest to dobre miejsce dla wędkarzy spławikowych i gruntowych, poszukujących ryb spokojnego żeru. Wiosna i wczesna jesień to najlepsze pory na udane połowy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21721, 1, 1.3, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Okoń,Lin,Karaś pospolity', 'Trudny, mocno zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21722, 'Starorzecze Sromowce Wyżne VI', 'starorzecze-sromowce-wyzne-vi-kroscienko-nad-dunajcem-21722', 'OXBOW', 49.4086163, 20.3743502, 'Małopolskie', 'Krościenko nad Dunajcem', 'To starorzecze, choć niewielkie, jest cenionym łowiskiem wśród lokalnych wędkarzy, oferującym dobre warunki do połowu na spławik. Dno jest głównie muliste, z licznymi osadami organicznymi, co sprzyja rozwojowi bogatej roślinności. Brzegi są mocno zarośnięte trzciną i krzewami, co wymaga cierpliwości i odpowiedniego przygotowania do dotarcia do wody. Roślinność podwodna jest umiarkowana, ale w niektórych miejscach tworzy gęste zarośla, które stanowią doskonałe kryjówki dla ryb. Zbiornik jest zasilany podczas wysokich stanów wody, co zapewnia dopływ świeżej wody, jednak ryzyko przyduchy w upalne lata jest podwyższone. Dominują tu płocie, okonie, liny i karasie pospolite, które doskonale czują się w spokojnych i zarośniętych wodach. Wiosna i wczesna jesień to najlepsze pory na udane połowy, gdy ryby są najbardziej aktywne. Jest to idealne miejsce dla wędkarzy preferujących spokojne metody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21722, 1.1, 1.4, 2.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Okoń,Lin,Karaś pospolity', 'Trudny, mocno zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21723, 'Starorzecze Sromowce Wyżne VII', 'starorzecze-sromowce-wyzne-vii-kroscienko-nad-dunajcem-21723', 'OXBOW', 49.408582, 20.3725937, 'Małopolskie', 'Krościenko nad Dunajcem', 'To największe ze starorzeczy w klastrze Sromowiec Wyżnych, oferujące bardziej zróżnicowane środowisko i większe możliwości wędkarskie. Dno jest mieszane, od żwirowych płycizn po muliste zagłębienia, co sprzyja różnorodności gatunkowej. Brzegi są dostępne z jednej strony, natomiast z drugiej strony porośnięte gęstymi krzewami i trzciną, tworząc naturalne osłony. Roślinność podwodna jest umiarkowana, co ułatwia wędkowanie, a jednocześnie zapewnia kryjówki dla ryb. Regularne połączenie z Dunajcem podczas wezbrań zapewnia dopływ świeżej wody i ryb, a także minimalizuje ryzyko przyduchy. W zbiorniku występują szczupaki, okonie, płocie, leszcze i liny, co czyni go atrakcyjnym dla wędkarzy spinningowych i spławikowych. Jest to dobre miejsce na całosezonowe wyprawy, oferujące możliwości dla różnych metod wędkowania. Warto eksplorować różne partie zbiornika, aby znaleźć najlepsze miejsca.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21723, 2.5, 1.8, 3.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz,Lin', 'Dobry z jednej strony, zarośnięty z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21724, 'Starorzecze Jajkowo', 'starorzecze-jajkowo-brodnica-21724', 'OXBOW', 53.3076312, 19.5227985, 'Kujawsko-Pomorskie', 'Brodnica', 'Starorzecze Jajkowo, będące dawnym fragmentem rzeki Drwęcy, to rozległy i głęboki zbiornik, ceniony przez wędkarzy za bogactwo ryb, zwłaszcza drapieżników. Dno jest zróżnicowane, od piaszczystych blatów po głębokie muliste rynny, co tworzy idealne warunki dla wielu gatunków. Brzegi są w większości łatwo dostępne, z licznymi miejscami do wędkowania, choć lokalnie mogą występować strefy zarośli. Roślinność podwodna jest umiarkowana, co pozwala na swobodne prowadzenie przynęt i jednocześnie zapewnia kryjówki dla ryb. Połączenie z rzeką podczas wysokich stanów wody zapewnia stałe zarybianie i odświeżanie ekosystemu, co minimalizuje ryzyko przyduchy. Łowisko słynie z dużych szczupaków, sandaczy i okoni, a także dorodnych leszczy i karpi. Jest to idealne miejsce dla wędkarzy spinningowych i gruntowych, poszukujących rekordowych okazów. Stabilne warunki wodne sprawiają, że można tu łowić przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21724, 5, 2.5, 6, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Okoń,Leszcz,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21725, 'Starorzecze Wielki Głęboczek 1', 'starorzecze-wielki-gleboczek-1-brodnica-21725', 'OXBOW', 53.3090119, 19.5213139, 'Kujawsko-Pomorskie', 'Brodnica', 'To starorzecze, położone w malowniczej dolinie rzeki Drwęcy, charakteryzuje się głębszymi partiami, co czyni je atrakcyjnym łowiskiem. Dno jest zróżnicowane, od mulistego w płytszych zatokach po twardsze, piaszczysto-żwirowe w rejonach dawnego nurtu. Brzegi są częściowo dostępne, lecz miejscami silnie zarośnięte trzciną i krzewami, co wymaga ostrożności. Roślinność podwodna jest bujna, tworząc doskonałe kryjówki dla ryb drapieżnych i spokojnego żeru. Występują tu liczne okazy lina, karasia pospolitego oraz szczupaka, a także płoci i leszczy. Wędkowanie może być utrudnione przez zaczepy i gęstą roślinność, ale nagradza obfitością brań.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21725, 4.5, 2.2, 5.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Karaś pospolity,Leszcz,Okoń', 'Trudny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21726, 'Starorzecze Wielki Głęboczek 2', 'starorzecze-wielki-gleboczek-2-brodnica-21726', 'OXBOW', 53.3105029, 19.5216642, 'Kujawsko-Pomorskie', 'Brodnica', 'Drugie starorzecze w kompleksie Wielki Głęboczek to nieco płytszy, ale równie atrakcyjny akwen, o charakterze bardziej mulistym i bogatej florze. Jego dno jest w większości miękkie, pokryte grubą warstwą osadów organicznych, co sprzyja rozwojowi bezkręgowców. Brzegi są gęsto porośnięte roślinnością szuwarową, co utrudnia dostęp, ale jednocześnie stanowi naturalne schronienie dla wielu gatunków. Woda jest stosunkowo płytka, co sprzyja szybkiemu nagrzewaniu się i intensywnemu rozwojowi roślinności. Dominują tu liny, karasie pospolite oraz wzdręgi, a także mniejsze płocie i okonie. Wędkowanie z pontonu lub brodzenie w woderach jest często najlepszą opcją, aby dotrzeć do interesujących miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21726, 3.8, 1.8, 4.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21727, 'Starorzecze Wielki Głęboczek 3', 'starorzecze-wielki-gleboczek-3-brodnica-21727', 'OXBOW', 53.3109436, 19.5208709, 'Kujawsko-Pomorskie', 'Brodnica', 'To starorzecze, będące częścią rozległego kompleksu, wyróżnia się nieco bardziej otwartymi przestrzeniami wodnymi, choć wciąż z licznymi zatokami i płyciznami. Dno jest mozaikowe, z obszarami piaszczystymi, mulistymi i fragmentami żwirowymi, co przyciąga różnorodne gatunki ryb. Brzegi są miejscami łatwo dostępne, zwłaszcza tam, gdzie prowadzą ścieżki wędkarskie, ale w innych rejonach dominują zarośla i podmokły teren. Roślinność podwodna jest umiarkowana, z większymi skupiskami w płytszych częściach i wzdłuż brzegów. Można tu liczyć na dobre brania szczupaka, okonia, a także leszcza i płoci. Okazjonalnie trafiają się również karpie, które znalazły tu idealne warunki do żerowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21727, 5.2, 2, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry z niektórych stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21728, 'Starorzecze Kuligi', 'starorzecze-kuligi-brodnica-21728', 'OXBOW', 53.3097875, 19.5196627, 'Kujawsko-Pomorskie', 'Brodnica', 'Starorzecze Kuligi to urokliwy, lecz wymagający akwen, położony w pobliżu miejscowości o tej samej nazwie, charakteryzujący się znacznym zarastaniem. Dno jest w przeważającej części muliste, z licznymi osadami organicznymi, co sprzyja rozwojowi bogatej fauny dennej. Brzegi są bardzo trudne do pokonania, gęsto porośnięte trzciną, krzewami i drzewami, tworząc niemal niedostępną barierę dla wędkarzy. Roślinność podwodna jest niezwykle bujna, tworząc podwodne łąki i labirynty, które są idealnym schronieniem dla ryb. Dominują tu liny, karasie pospolite oraz wzdręgi, a także licznie występujące płocie. Wędkowanie wymaga cierpliwości i precyzji, często z wykorzystaniem długich wędek lub pontonu, aby uniknąć zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21728, 2.7, 1.5, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21729, 'Starorzecze Żychlikowo', 'starorzecze-zychlikowo-stepnica-21729', 'OXBOW', 53.7067996, 14.9063272, 'Zachodniopomorskie', 'Stepnica', 'Starorzecze Żychlikowo to rozległy akwen, położony w pobliżu Zalewu Szczecińskiego, charakteryzujący się płaskim, mulistym dnem. Akwen jest pozostałością po dawnych meandrach rzeki Odry, co wpływa na jego bogactwo biologiczne. Brzegi są przeważnie niskie, miejscami podmokłe, z licznymi skupiskami trzcin i turzyc, które stanowią doskonałe siedliska dla ptactwa wodnego. Roślinność podwodna jest umiarkowana, ale w płytszych zatokach może być bardzo gęsta, tworząc idealne miejsca do bytowania drapieżników. W starorzeczu dominują leszcze, płocie, liny oraz szczupaki, a także często trafiają się karasie srebrzyste. Wędkowanie jest tu przyjemne, choć w niektórych miejscach dostęp może być utrudniony przez bagnisty teren.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21729, 12, 1.7, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Lin,Szczupak,Karaś srebrzysty', 'Dobry, miejscami podmokły', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21730, 'Starorzecze Biebrówek 1', 'starorzecze-biebrowek-1-stepnica-21730', 'OXBOW', 53.6949866, 14.9093431, 'Zachodniopomorskie', 'Stepnica', 'Pierwsze starorzecze w kompleksie Biebrówek to typowy akwen o charakterze jeziornym, z powolnym przepływem wody i bogatą roślinnością. Dno jest przeważnie muliste, z grubą warstwą osadów, co jest typowe dla starorzeczy w tej części Polski. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co utrudnia dostęp, ale jednocześnie tworzy schronienie dla wielu gatunków ryb. Roślinność podwodna, choć bujna, nie jest aż tak uciążliwa jak w niektórych mniejszych starorzeczach. Występują tu liczne leszcze, płocie, liny oraz karasie pospolite. Duże okazy szczupaka również są częstym łupem. Wędkowanie z gruntu lub spławikowo przynosi najlepsze rezultaty, zwłaszcza w wolnych od zaczepów miejscach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21730, 8.5, 1.9, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Lin,Karaś pospolity,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21731, 'Starorzecze Biebrówek 2', 'starorzecze-biebrowek-2-stepnica-21731', 'OXBOW', 53.6904344, 14.905848, 'Zachodniopomorskie', 'Stepnica', 'Drugie starorzecze w rejonie Biebrówka to bardziej odizolowany akwen, charakteryzujący się większym stopniem zamulenia i bujniejszą roślinnością. Dno jest głęboko muliste, co sprzyja rozwojowi fauny dennej, ale może być wyzwaniem dla wędkarzy. Brzegi są bagniste i bardzo trudne do pokonania, z gęstymi zaroślami i podmokłym terenem, co wymaga użycia wodoodpornego obuwia lub pontonu. Roślinność podwodna jest niezwykle gęsta, tworząc podwodne łąki, które są ostoją dla wielu gatunków ryb. Dominują tu karasie pospolite, liny, wzdręgi oraz sumy, które znajdują tu idealne warunki do ukrycia i żerowania. Wędkowanie jest tu prawdziwym wyzwaniem, ale może przynieść nagrodę w postaci dużych, walecznych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21731, 6, 1.5, 3, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Sum', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21732, 'Starorzecze Roztoka-Brzeziny 1', 'starorzecze-roztoka-brzeziny-1-grodek-nad-dunajcem-21732', 'OXBOW', 49.7913813, 20.699928, 'Małopolskie', 'Gródek nad Dunajcem', 'To starorzecze, zlokalizowane w malowniczej dolinie Dunajca, stanowi część dłuższego kompleksu, oferując zróżnicowane warunki wędkarskie. Dno jest zmienne, od piaszczystych płycizn po muliste zagłębienia, z elementami żwiru w miejscach dawnego nurtu. Brzegi są w większości dostępne, częściowo utwardzone, co ułatwia wędkowanie z brzegu, choć miejscami występują zarośla. Roślinność podwodna jest umiarkowana, skupiona głównie w płytszych partiach i wzdłuż linii brzegowej, tworząc schronienie dla narybku. Występują tu licznie płocie, leszcze, okonie oraz szczupaki, a także bolenie i klenie, które migrują z Dunajca. Akwen ten jest ceniony za swoje czyste wody i różnorodność gatunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21732, 2.5, 1.8, 4, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21733, 'Starorzecze Roztoka-Brzeziny 2', 'starorzecze-roztoka-brzeziny-2-grodek-nad-dunajcem-21733', 'OXBOW', 49.791501, 20.6993718, 'Małopolskie', 'Gródek nad Dunajcem', 'Drugie starorzecze w kompleksie Roztoka-Brzeziny to nieco głębszy akwen, charakteryzujący się spokojną wodą i czystym dnem. Dno jest głównie piaszczysto-żwirowe, z niewielkimi ilościami mułu w najgłębszych partiach, co sprzyja bytności ryb typowo rzecznych. Brzegi są dobrze dostępne, z licznymi miejscami do wędkowania, choć w niektórych rejonach mogą występować pojedyncze drzewa i krzewy. Roślinność podwodna jest skąpa, co ułatwia prowadzenie przynęt i minimalizuje ryzyko zaczepów. Dominują tu leszcze, płocie, okonie, a także sandacze i sumy, które znajdują tu doskonałe warunki do żerowania. To starorzecze jest idealne dla wędkarzy preferujących spinning lub gruntówkę w czystych wodach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21733, 3, 2.5, 5.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Sandacz,Sum', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21734, 'Starorzecze Roztoka-Brzeziny 3', 'starorzecze-roztoka-brzeziny-3-grodek-nad-dunajcem-21734', 'OXBOW', 49.7916058, 20.6985565, 'Małopolskie', 'Gródek nad Dunajcem', 'Trzecie starorzecze w tym malowniczym kompleksie to akwen o bardziej zarośniętych brzegach, ale wciąż z czystą wodą i urozmaiconym dnem. Dno jest mozaikowe, z przewagą piasku i żwiru, lecz z mulistymi enklawami w osłoniętych zatokach, sprzyjającymi rozwojowi życia wodnego. Brzegi są miejscami trudniejsze do pokonania ze względu na gęste krzewy i drzewa, co tworzy naturalne kryjówki dla ryb. Roślinność podwodna jest umiarkowana, z większymi skupiskami w płytszych częściach, gdzie stanowi schronienie dla drobnicy. Występują tu liczne płocie, leszcze, wzdręgi oraz szczupaki i okonie, polujące w pobliżu zarośli. Wędkowanie z gruntu lub na spinning wymaga precyzji, ale może przynieść obfite brania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21734, 2.8, 2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Wzdręga,Szczupak,Okoń', 'Trudny, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21735, 'Starorzecze Roztoka-Brzeziny 4', 'starorzecze-roztoka-brzeziny-4-grodek-nad-dunajcem-21735', 'OXBOW', 49.7917135, 20.6976594, 'Małopolskie', 'Gródek nad Dunajcem', 'To starorzecze, położone w centralnej części kompleksu Roztoka-Brzeziny, charakteryzuje się bardziej zróżnicowanym ukształtowaniem dna i brzegów. Dno jest mieszane, z przewagą piasku i żwiru, ale z głębszymi, mulistymi rynnami, które są pozostałością po dawnym nurcie rzeki. Brzegi są częściowo dostępne, z licznymi stanowiskami wędkarskimi, ale miejscami mogą być strome lub porośnięte krzewami. Roślinność podwodna jest umiarkowana, tworząc idealne miejsca do zasadzek dla drapieżników. Występują tu liczne płocie, leszcze, okonie, a także bolenie i jazie, które chętnie żerują na otwartych wodach. To doskonałe miejsce do wędkowania na spławik, grunt czy spinning, oferujące szeroki wachlarz możliwości.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21735, 3.2, 2.3, 4.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Boleń,Jaź', 'Dobry, miejscami stromy', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21736, 'Starorzecze Roztoka-Brzeziny 5', 'starorzecze-roztoka-brzeziny-5-grodek-nad-dunajcem-21736', 'OXBOW', 49.7917527, 20.6967846, 'Małopolskie', 'Gródek nad Dunajcem', 'Piąte starorzecze w tej serii to akwen o bardziej intymnym charakterze, z licznymi zatoczkami i płyciznami, idealny dla wędkarzy szukających spokoju. Dno jest głównie muliste, z bogatymi osadami, co sprzyja rozwojowi bezkręgowców, stanowiących pokarm dla ryb spokojnego żeru. Brzegi są gęsto porośnięte trzciną i krzewami, co wymaga poszukiwania dogodnych miejsc do zarzucenia wędki, ale jednocześnie zapewnia doskonałe kryjówki. Roślinność podwodna jest bujna, tworząc podwodne łąki, które są ostoją dla lina i karasia. Dominują tu liny, karasie pospolite, wzdręgi oraz szczupaki, które polują w zaroślach. Wędkowanie z brzegu jest możliwe, ale często wymaga brodzenia lub użycia pontonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21736, 2, 1.5, 3.5, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21737, 'Starorzecze Roztoka-Brzeziny 6', 'starorzecze-roztoka-brzeziny-6-grodek-nad-dunajcem-21737', 'OXBOW', 49.7917542, 20.6959206, 'Małopolskie', 'Gródek nad Dunajcem', 'To starorzecze, będące kolejnym ogniwem w łańcuchu akwenów Roztoka-Brzeziny, charakteryzuje się stabilnymi warunkami i umiarkowanym zarastaniem. Dno jest mieszane, z przewagą piasku i żwiru, ale z lokalnymi skupiskami mułu, co zapewnia różnorodność siedlisk dla ryb. Brzegi są stosunkowo łatwo dostępne, z naturalnymi miejscami do wędkowania, choć w niektórych rejonach mogą występować pojedyncze zarośla. Roślinność podwodna jest umiarkowana, tworząc dobre warunki dla ryb spokojnego żeru i drapieżników. Występują tu liczne płocie, leszcze, okonie oraz karpie, które chętnie żerują na dnie. To starorzecze jest popularne wśród wędkarzy ze względu na dobrą dostępność i różnorodność gatunków ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21737, 2.9, 2.1, 4.6, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21738, 'Starorzecze Roztoka-Brzeziny 7', 'starorzecze-roztoka-brzeziny-7-grodek-nad-dunajcem-21738', 'OXBOW', 49.7917262, 20.6951809, 'Małopolskie', 'Gródek nad Dunajcem', 'Siódme starorzecze w kompleksie Roztoka-Brzeziny to akwen o nieco głębszych partiach i bardziej wyraźnym wpływie rzeki Dunajec. Dno jest przeważnie piaszczysto-żwirowe, z mniejszą ilością mułu, co sprzyja rybom preferującym czyste i twarde podłoże. Brzegi są dobrze dostępne, z licznymi naturalnymi stanowiskami wędkarskimi, choć w niektórych rejonach mogą występować pojedyncze drzewa. Roślinność podwodna jest skąpa, co ułatwia prowadzenie przynęt i minimalizuje ryzyko zaczepów. Dominują tu leszcze, płocie, bolenie, jazie oraz sandacze, które chętnie polują w głębszych partiach. Akwen ten jest atrakcyjny dla wędkarzy spinningowych i tych preferujących metody gruntowe, ze względu na obecność silnych drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21738, 3.5, 2.7, 5.2, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Boleń,Jaź,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21739, 'Starorzecze Roztoka-Brzeziny 8', 'starorzecze-roztoka-brzeziny-8-grodek-nad-dunajcem-21739', 'OXBOW', 49.7916341, 20.6945796, 'Małopolskie', 'Gródek nad Dunajcem', 'Ostatnie starorzecze w tym kompleksie to akwen o zróżnicowanej głębokości i bogatej strukturze podwodnej, oferujący wiele możliwości wędkarskich. Dno jest mozaikowe, z obszarami piaszczystymi, żwirowymi i mulistymi, co przyciąga różnorodne gatunki ryb. Brzegi są częściowo dostępne, z licznymi zatokami i przesmykami, gdzie można znaleźć dogodne miejsca do wędkowania. Roślinność podwodna jest umiarkowana, z większymi skupiskami w osłoniętych partiach, tworząc schronienie i miejsca żerowania. Występują tu liczne płocie, leszcze, okonie, szczupaki oraz sumy, które chętnie bytują w głębszych dołach. Akwen ten jest idealny dla wędkarzy poszukujących różnorodności i wyzwań, z możliwością złowienia wielu gatunków ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21739, 3.8, 2.4, 5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak,Sum', 'Dobry, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21740, 'Starorzecze Roztoka-Brzeziny (1)', 'starorzecze-roztoka-brzeziny-1-tropie-21740', 'OXBOW', 49.791519, 20.6939536, 'Małopolskie', 'Tropie', 'Starorzecze Roztoka-Brzeziny, położone w malowniczej dolinie Dunajca, charakteryzuje się dość nieregularną linią brzegową i różnorodnością siedlisk. Dno jest przeważnie muliste, z twardszymi fragmentami żwirowymi w głębszych partiach, co sprzyja rozwojowi bogatej fauny dennej. Brzegi są w większości porośnięte gęstą roślinnością szuwarową, taką jak trzcina i pałka wodna, co utrudnia dostęp do wody, ale jednocześnie stanowi doskonałe schronienie dla ryb. Wiosną i jesienią, po obfitych opadach, starorzecze łączy się z rzeką, co sprzyja migracji gatunków i odświeżeniu akwenu. Dominujące gatunki to szczupak, lin, płoć i leszcz, które znajdują tu idealne warunki do żerowania i rozmnażania. Wędkarstwo wymaga cierpliwości i często brodzenia, ale nagrodą są piękne okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21740, 3.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Płoć,Leszcz', 'Trudny, miejscami bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21741, 'Starorzecze Roztoka-Brzeziny (2)', 'starorzecze-roztoka-brzeziny-2-tropie-21741', 'OXBOW', 49.7914145, 20.6933448, 'Małopolskie', 'Tropie', 'To starorzecze, choć niewielkie, stanowi prawdziwy raj dla miłośników wędkarstwa gruntowego i spławikowego, poszukujących ciszy i spokoju. Charakteryzuje się bardzo płytkim i mocno zamulonym dnem, co sprzyja obfitemu wzrostowi roślinności podwodnej, takiej jak moczarka kanadyjska i rdestnica. Brzegi są niemal w całości otoczone gęstymi pasami trzcin i krzewów, co sprawia, że dostęp do wody jest utrudniony i wymaga specjalnego przygotowania. Ze względu na brak stałego połączenia z główną rzeką, woda w starorzeczu jest spokojna, ale latem istnieje ryzyko niedoboru tlenu, zwłaszcza podczas upałów. Dominującymi gatunkami ryb są lin, karaś pospolity, wzdręga i płoć, które doskonale radzą sobie w takich warunkach. Łowienie tutaj to wyzwanie, ale często owocuje pięknymi, zdrowymi rybami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21741, 2.8, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21742, 'Starorzecze Tropie (1)', 'starorzecze-tropie-1-tropie-21742', 'OXBOW', 49.7913322, 20.6926705, 'Małopolskie', 'Tropie', 'Starorzecze Tropie (1) to jedno z bardziej dostępnych i uregulowanych łowisk w regionie, oferujące dogodne warunki dla wędkarzy. Posiada stałe połączenie z Dunajcem, co zapewnia regularną wymianę wody i utrzymuje niskie zamulenie dna, które jest przeważnie piaszczysto-żwirowe. Brzegi są stosunkowo łatwo dostępne, częściowo umocnione, z nielicznymi zaroślami, co umożliwia swobodne poruszanie się. Roślinność podwodna jest umiarkowana, skupiona głównie w płytszych zatoczkach, co tworzy idealne kryjówki dla drapieżników. Jest to doskonałe miejsce na połów szczupaka, okonia, leszcza, płoci, a także bolenia, który często wpływa tu z rzeki. Łowisko to jest popularne przez cały sezon, oferując komfortowe warunki i szansę na różnorodne połowy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21742, 4.2, 1.8, 3.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21743, 'Starorzecze Tropie (2)', 'starorzecze-tropie-2-tropie-21743', 'OXBOW', 49.791338, 20.6919351, 'Małopolskie', 'Tropie', 'Starorzecze Tropie (2) to urokliwy, lecz wymagający akwen, idealny dla wędkarzy ceniących dziki charakter łowiska. Dno jest mieszane, z przewagą mułu, ale występują też twardsze fragmenty, co sprzyja rozwojowi różnorodnej roślinności wodnej. Brzegi są miejscami strome i zarośnięte krzewami, co utrudnia dostęp, ale jednocześnie zapewnia spokój i odosobnienie. W okresie wysokich stanów wody, starorzecze łączy się z Dunajcem, co wzbogaca jego ichtiofaunę i odświeża wodę. Dominują tu gatunki takie jak lin, karaś pospolity, płoć i wzdręga, które doskonale czują się w zarośniętych i spokojnych wodach. Łowienie wymaga użycia brodów i cierpliwości, ale daje szansę na złowienie pięknych, zdrowych ryb w naturalnym środowisku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21743, 3, 1, 2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Trudny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21744, 'Starorzecze Bobrowniki', 'starorzecze-bobrowniki-bobrowniki-21744', 'OXBOW', 50.9578584, 19.8359514, 'Śląskie', 'Bobrowniki', 'Starorzecze w Bobrownikach to popularne łowisko, cenione za swoją dostępność i różnorodność gatunkową. Dno jest zróżnicowane, od piaszczystych płycizn po muliste zagłębienia, co sprzyja występowaniu wielu gatunków ryb. Brzegi są w większości dobrze utrzymane, z licznymi stanowiskami wędkarskimi, a jedynie w niektórych miejscach występują gęstsze zarośla. Podczas wiosennych roztopów akwen łączy się z rzeką Wartą, co odświeża wodę i wzbogaca populację ryb. W starorzeczu dominują szczupaki, leszcze, okonie, karpie i płocie, które są regularnie odławiane przez wędkarzy. Jest to idealne miejsce zarówno dla początkujących, jak i doświadczonych wędkarzy, oferujące komfortowe warunki i szansę na udane połowy przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21744, 5.1, 2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Karp,Płoć', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21745, 'Starorzecze Piaski Drużków', 'starorzecze-piaski-druzkow-zakliczyn-21745', 'OXBOW', 49.8172002, 20.6854346, 'Małopolskie', 'Zakliczyn', 'Starorzecze w Piaskach Drużków to niewielki, ale urokliwy zbiornik o bardzo dzikim charakterze, stanowiący wyzwanie dla wędkarzy. Dno jest w przeważającej części mocno zamulone, co sprzyja bujnemu rozwojowi roślinności podwodnej, która tworzy gęste podwodne łąki. Brzegi są trudnodostępne, otoczone gęstymi zaroślami trzcin i krzewów, wymagającymi często przedzierania się. Brak stałego połączenia z rzeką sprawia, że woda jest stojąca, a w okresie letnich upałów może wystąpić deficyt tlenu. Dominujące gatunki to lin, karaś pospolity, wzdręga i płoć, które doskonale adaptują się do tych trudnych warunków. Jest to idealne miejsce dla wędkarzy szukających spokoju i prawdziwej przygody w dzikiej scenerii, gdzie liczy się precyzja i znajomość łowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21745, 2.5, 1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną i krzewami', TRUE, 'Gęsta roślinność podwodna', 'Wczesna wiosna, późna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21746, 'Starorzecze Pratkowice (1)', 'starorzecze-pratkowice-1-koniecpol-21746', 'OXBOW', 51.0275788, 19.8627669, 'Śląskie', 'Koniecpol', 'Starorzecze Pratkowice (1) to średniej wielkości akwen, oferujący ciekawe warunki do wędkowania w malowniczej okolicy. Dno jest zróżnicowane, z przewagą mułu w głębszych partiach i piaszczystymi fragmentami bliżej brzegów, co sprzyja różnorodności fauny. Brzegi są częściowo dostępne, z licznymi dogodnymi miejscami do rozłożenia sprzętu, choć miejscami występują zarośla trzcinowe. W okresie wiosennych wezbrań starorzecze łączy się z rzeką Wartą, co pozytywnie wpływa na odnowienie populacji ryb i wymianę wody. Dominujące gatunki to szczupak, okoń, leszcz i płoć, które znajdują tu obfitość pokarmu i dogodne miejsca do bytowania. Łowisko jest cenione za spokój i możliwość złowienia ładnych okazów, szczególnie w cieplejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21746, 3.8, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21747, 'Starorzecze Rączki', 'starorzecze-raczki-koniecpol-21747', 'OXBOW', 51.0267561, 19.8668698, 'Śląskie', 'Koniecpol', 'Niewielkie starorzecze w Rączkach to prawdziwa perełka dla wędkarzy poszukujących dzikich i kameralnych łowisk. Charakteryzuje się bardzo płytkim i mocno zamulonym dnem, które w całości pokryte jest gęstą roślinnością podwodną, tworzącą skomplikowany labirynt. Brzegi są niezwykle trudnodostępne, bagniste i zarośnięte gęstą trzciną oraz inną roślinnością szuwarową, co wymaga użycia brodów. Brak połączenia z rzeką sprawia, że woda jest stojąca, a w upalne lata istnieje wysokie ryzyko przyduchy. Dominują tu gatunki odporne na trudne warunki, takie jak lin, karaś pospolity i wzdręga, które doskonale odnajdują się w tym środowisku. Łowienie tutaj to prawdziwa przygoda, wymagająca cierpliwości i umiejętności, ale często nagradzana unikalnymi okazami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21747, 1.9, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Mocno zarośnięty, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21748, 'Starorzecze Pratkowice (2)', 'starorzecze-pratkowice-2-koniecpol-21748', 'OXBOW', 51.0281525, 19.8673158, 'Śląskie', 'Koniecpol', 'Starorzecze Pratkowice (2) to jedno z większych i lepiej zagospodarowanych łowisk w okolicy, idealne dla wędkarzy ceniących komfort i różnorodność. Posiada stałe połączenie z rzeką Wartą, co zapewnia ciągłą wymianę wody i utrzymuje dno w dobrej kondycji, z przewagą piasku i żwiru. Brzegi są łatwo dostępne, z licznymi wygodnymi stanowiskami, a roślinność szuwarowa jest ograniczona do niewielkich pasów. Niskie zamulenie i dobra cyrkulacja wody sprawiają, że ryzyko przyduchy jest minimalne. W starorzeczu obficie występują szczupaki, leszcze, okonie, płocie, a także karpie, które regularnie są tu zarybiane. Łowisko to jest popularne przez cały rok, oferując doskonałe warunki do wędkowania spinningowego, spławikowego i gruntowego.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21748, 4.5, 2.1, 4, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Płoć,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21749, 'Starorzecze Biskupice Melsztyńskie', 'starorzecze-biskupice-melsztynskie-zakliczyn-21749', 'OXBOW', 49.8551462, 20.7227251, 'Małopolskie', 'Zakliczyn', 'Starorzecze w Biskupicach Melsztyńskich to spokojny akwen, który zachował swój naturalny charakter, będąc ostoją dla wielu gatunków ryb. Dno jest przeważnie muliste, z lokalnymi twardszymi fragmentami, co sprzyja rozwojowi bogatej roślinności podwodnej, oferującej schronienie i pokarm. Brzegi są miejscami strome i mocno zarośnięte trzciną oraz krzewami, co wymaga od wędkarzy cierpliwości i poszukiwania dogodnych miejsc. Brak stałego połączenia z Dunajcem sprawia, że woda jest spokojna, a środowisko stabilne, choć wymaga to uwagi w okresach suszy. Dominują tu lin, karaś pospolity, płoć i wzdręga, które doskonale czują się w zarośniętych i płytkich wodach. Jest to idealne miejsce dla wędkarzy szukających ciszy i kontaktu z naturą, gotowych na pewne utrudnienia w dostępie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21749, 3.1, 1.4, 2.8, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Trudny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21750, 'Starorzecze Domosławice', 'starorzecze-domoslawice-zakliczyn-21750', 'OXBOW', 49.8558525, 20.7267462, 'Małopolskie', 'Zakliczyn', 'Starorzecze w Domosławicach to niewielki, mocno zarośnięty akwen, który stanowi wyzwanie dla wędkarzy, ale jednocześnie oferuje unikalne doświadczenia. Dno jest w przeważającej części mocno zamulone i pokryte gęstymi dywanami roślinności podwodnej, co utrudnia prowadzenie przynęt. Brzegi są niezwykle trudnodostępne, bagniste i gęsto porośnięte trzciną, co sprawia, że łowienie z brzegu jest praktycznie niemożliwe bez brodzenia. W okresach wysokiej wody starorzecze łączy się z Dunajcem, co pomaga odświeżyć wodę, jednak latem ryzyko niedoboru tlenu jest wysokie. Dominują tu gatunki takie jak lin, karaś pospolity, wzdręga i płoć, które doskonale adaptują się do tego środowiska. To łowisko dla prawdziwych pasjonatów, ceniących dzikość i gotowych na trudności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21750, 2.7, 1.1, 2.3, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21751, 'Starorzecze Hrubieszów', 'starorzecze-hrubieszow-hrubieszow-21751', 'OXBOW', 50.8088008, 23.8948519, 'Lubelskie', 'Hrubieszów', 'Starorzecze Hrubieszów to duży i głęboki akwen, posiadający stałe połączenie z rzeką Bug, co czyni go jednym z najbardziej atrakcyjnych łowisk w regionie. Dno jest zróżnicowane, z głębokimi rynnami, piaszczystymi blatami i mulistymi zagłębieniami, co sprzyja bogactwu gatunkowemu. Brzegi są w większości łatwo dostępne, z licznymi pomostami i stanowiskami, choć miejscami występują naturalne zarośla. Stała cyrkulacja wody zapewnia doskonałe warunki tlenowe i niskie zamulenie. W starorzeczu występują liczne okazy szczupaka, sandacza, leszcza, płoci, okonia, a także suma, który wpływa tu z rzeki. Jest to łowisko idealne dla wędkarzy preferujących różne metody, od spinningu po grunt, oferujące szansę na naprawdę dużą rybę przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21751, 6, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Okoń,Sum', 'Dobry z wielu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21752, 'Starorzecze Derło (1)', 'starorzecze-derlo-1-wlodawa-21752', 'OXBOW', 52.1820527, 23.3818265, 'Lubelskie', 'Włodawa', 'Starorzecze Derło (1) to malowniczy, lecz wymagający akwen, charakteryzujący się dzikim charakterem i obfitością podwodnych przeszkód. Dno jest zróżnicowane, z przewagą mułu, ale z licznymi zatopionymi drzewami i gałęziami, które stanowią doskonałe kryjówki dla ryb. Brzegi są miejscami strome, gęsto zarośnięte krzewami i drzewami, co utrudnia dostęp, ale jednocześnie zapewnia spokój i odosobnienie. W okresach wysokiej wody starorzecze łączy się z rzeką Bug, co sprzyja migracji ryb i odświeżeniu akwenu. Dominujące gatunki to szczupak, okoń, lin i płoć, które doskonale radzą sobie w tym środowisku pełnym naturalnych schronień. Łowienie tutaj to wyzwanie dla wędkarzy, którzy cenią sobie dzikość i są gotowi na częste zaczepy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21752, 4, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Lin,Płoć', 'Trudny, zarośnięty, miejscami stromy', TRUE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21753, 'Starorzecze Derło (2)', 'starorzecze-derlo-2-wlodawa-21753', 'OXBOW', 52.1819242, 23.3747924, 'Lubelskie', 'Włodawa', 'Starorzecze Derło (2) to typowy płytki i mocno zarośnięty zbiornik, będący ostoją dla gatunków ciepłolubnych i odpornych na trudne warunki. Dno jest niemal w całości pokryte grubą warstwą mułu i gęstą roślinnością podwodną, tworzącą rozległe podwodne łąki. Brzegi są niezwykle trudnodostępne, bagniste i gęsto porośnięte trzciną, co sprawia, że łowienie wymaga użycia brodów lub pływadeł. Brak połączenia z rzeką Bug i niewielka głębokość powodują, że latem występuje wysokie ryzyko niedoboru tlenu. Dominujące gatunki to lin, karaś pospolity, wzdręga i płoć, które doskonale adaptują się do tego specyficznego środowiska. Jest to idealne miejsce dla wędkarzy poszukujących spokoju i ceniących sobie wyzwania, jakie stawia dzika natura.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21753, 3.2, 1.3, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną i bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wczesna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21754, 'Starorzecze Derło (3)', 'starorzecze-derlo-3-wlodawa-21754', 'OXBOW', 52.1822992, 23.3759614, 'Lubelskie', 'Włodawa', 'To starorzecze, położone w pobliżu Derła, jest jednym z najbardziej wymagających i specyficznych akwenów w regionie. Charakteryzuje się bardzo płytkim dnem, które w całości pokryte jest grubą warstwą mułu i bujną roślinnością podwodną, co stanowi wyzwanie dla wędkarzy. Brzegi są niemal całkowicie niedostępne, bagniste i gęsto zarośnięte trzciną, co sprawia, że łowienie z brzegu jest praktycznie niemożliwe. Brak połączenia z rzeką Bug i ekstremalnie mała głębokość powodują, że w okresach suszy starorzecze potrafi całkowicie wyschnąć, co znacząco wpływa na populację ryb. Dominujące gatunki to karaś pospolity, wzdręga i lin, które są najbardziej odporne na tak zmienne warunki. Jest to łowisko dla prawdziwych koneserów, ceniących unikalne wyzwania i gotowych na trudności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21754, 2.9, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Mocno zarośnięty trzciną, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21755, 'Starorzecze (Zaczopki)', 'starorzecze-zaczopki-terespol-21755', 'OXBOW', 52.174326, 23.3916324, 'Lubelskie', 'Terespol', 'To malownicze starorzecze, położone w pobliżu miejscowości Zaczopki, charakteryzuje się dość dzikim i naturalnym krajobrazem. Dno jest przeważnie muliste, miejscami twarde, co sprzyja rozwojowi bogatej roślinności podwodnej, takiej jak rdestnice i moczarka. Brzegi są częściowo zarośnięte trzciną i wierzbami, co utrudnia dostęp w niektórych miejscach, ale jednocześnie zapewnia schronienie dla ryb. Jest to doskonałe łowisko dla wędkarzy ceniących spokój i kontakt z naturą. Występują tu liczne zaczepy w postaci zatopionych gałęzi i korzeni, co wymaga ostrożności podczas wędkowania. Wiosną i jesienią, podczas wyższych stanów wody, starorzecze łączy się z rzeką Bug, co sprzyja migracji ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21755, 3.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Leszcz,Okoń', 'Trudny, miejscami zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21756, 'Starorzecze (Derło)', 'starorzecze-derlo-terespol-21756', 'OXBOW', 52.1778549, 23.3864966, 'Lubelskie', 'Terespol', 'Starorzecze w Derle to typowe łowisko nizinne, charakteryzujące się płytkim dnem i bogatą roślinnością wodną, w tym grążelem białym i liliami wodnymi. Brzegi są stosunkowo łagodne, ale miejscami bagniste i mocno zarośnięte trzciną, co wymaga użycia wodoodpornego obuwia lub brodzenia. Dno jest w większości muliste, z pojedynczymi twardszymi partiami. To idealne miejsce dla miłośników łowienia lina i karasia, które znajdują tu doskonałe warunki do żerowania i rozrodu. Latem, przy niskim poziomie wody, ryzyko przyduchy jest podwyższone, co może wpływać na aktywność ryb. Wędkowanie utrudniają liczne zaczepy w postaci podwodnej roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21756, 2.1, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21757, 'Starorzecze (Derło)', 'starorzecze-derlo-terespol-21757', 'OXBOW', 52.1777783, 23.3890294, 'Lubelskie', 'Terespol', 'To jedno z kilku starorzeczy w okolicy Derła, wyróżniające się nieco większą głębokością w centralnej części. Charakteryzuje się zróżnicowanym dnem – od piaszczystych płycizn po muliste zagłębienia, co przyciąga różnorodne gatunki ryb. Brzegi są dostępne w kilku miejscach, głównie od strony pól, ale większość linii brzegowej jest gęsto porośnięta krzewami i drzewami. Wiosną, po roztopach, woda jest krystalicznie czysta, co pozwala na obserwację podwodnego życia. W lecie, bujna roślinność wodna, taka jak rogatek i moczarka, stanowi doskonałe kryjówki dla drapieżników. Należy uważać na liczne zatopione konary, które mogą powodować utratę zestawów. To starorzecze oferuje dobre warunki do łowienia zarówno białej ryby, jak i drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21757, 2.8, 1.8, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Karp,Płoć,Okoń', 'Dobry w wybranych miejscach', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21758, 'Starorzecze (Derło)', 'starorzecze-derlo-terespol-21758', 'OXBOW', 52.1826474, 23.3778269, 'Lubelskie', 'Terespol', 'To starorzecze, położone nieco dalej od głównych dróg, jest prawdziwym rajem dla wędkarzy poszukujących ciszy i odosobnienia. Charakteryzuje się czystą wodą i twardym, miejscami żwirowym dnem, co jest rzadkością w tego typu akwenach. Brzegi są strome i porośnięte starymi drzewami, które tworzą naturalne stanowiska wędkarskie. Roślinność wodna jest umiarkowana, głównie w postaci pasów trzcin przy brzegach. Jest to idealne miejsce do łowienia drapieżników, szczególnie szczupaka i okonia, które często patrolują głębsze partie akwenu. Mimo dobrego dostępu w niektórych punktach, dojście do łowiska może być utrudnione przez nierówny teren. Ryzyko zaczepów jest niewielkie w centralnej części, ale wzrasta przy brzegach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21758, 1.9, 2, 4.5, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Węgorz,Płoć', 'Trudny, strome brzegi', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21759, 'Starorzecze (Isep)', 'starorzecze-isep-wojnicz-21759', 'OXBOW', 49.9445962, 20.8603754, 'Małopolskie', 'Wojnicz', 'Starorzecze w Isepiu to rozległy akwen o nieregularnym kształcie, będący pozostałością po rzece Dunajec. Jego dno jest zróżnicowane, od piaszczysto-żwirowego po muliste zagłębienia, co sprzyja bytności wielu gatunków ryb. Brzegi są łatwo dostępne w większości miejsc, choć miejscami występują pasy trzcin. Roślinność wodna jest umiarkowana, z przewagą rdestnic i moczarki w płytszych partiach. To popularne łowisko wśród lokalnych wędkarzy, znane z obfitości leszczy i płoci. W cieplejszych miesiącach należy zachować ostrożność ze względu na ryzyko zakwitów wody. Występują tu pojedyncze zaczepy w postaci zatopionych gałęzi, szczególnie w pobliżu starych drzew.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21759, 7.5, 1.7, 3.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Leszcz,Płoć,Karaś srebrzysty,Karp,Szczupak', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21760, 'Starorzecze (Dąbrówka Szczepanowska)', 'starorzecze-dabrowka-szczepanowska-wojnicz-21760', 'OXBOW', 49.9328977, 20.8520953, 'Małopolskie', 'Wojnicz', 'To starorzecze, położone w malowniczej okolicy Dąbrówki Szczepanowskiej, jest stosunkowo płytkie, z dominującym mulistym dnem. Brzegi są mocno zarośnięte trzciną i krzewami, co wymaga cierpliwości i często brodzenia, aby znaleźć dogodne stanowisko. Bogata roślinność wodna, taka jak grążele i moczarka, tworzy idealne siedliska dla ryb spokojnego żeru. To raj dla miłośników lina i karasia pospolitego, które osiągają tu imponujące rozmiary. Niestety, w upalne lata, ze względu na płytkość i gęste zarośla, istnieje podwyższone ryzyko przyduchy. Wędkowanie jest tu wyzwaniem ze względu na liczne zaczepy w postaci roślinności podwodnej.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21760, 2.5, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21761, 'Starorzecze (Dąbrówka Szczepanowska)', 'starorzecze-dabrowka-szczepanowska-wojnicz-21761', 'OXBOW', 49.9316585, 20.8513644, 'Małopolskie', 'Wojnicz', 'Drugie starorzecze w Dąbrówce Szczepanowskiej, choć sąsiadujące z poprzednim, ma nieco inny charakter. Jest ono głębsze w centralnej części i posiada bardziej zróżnicowane dno, z twardszymi partiami piasku i żwiru. Brzegi są miejscami strome, porośnięte drzewami, które tworzą naturalne cienie i kryjówki dla ryb. Roślinność wodna jest umiarkowana, co ułatwia prowadzenie przynęt. To dobre miejsce do łowienia szczupaka i okonia, które często patrolują głębsze rejony. Dostęp do wody jest możliwy w kilku punktach, ale wymaga ostrożności ze względu na nierówny teren. Wiosną i jesienią, kiedy woda jest chłodniejsza, drapieżniki są szczególnie aktywne. Wędkarze powinni przygotować się na pojedyncze zaczepy w postaci zatopionych gałęzi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21761, 1.8, 1.6, 3.5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Karaś srebrzysty', 'Trudny, strome brzegi', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21762, 'Starorzecze (Isep)', 'starorzecze-isep-wojnicz-21762', 'OXBOW', 49.9528473, 20.8726819, 'Małopolskie', 'Wojnicz', 'To starorzecze w Isepiu jest przykładem akwenu o stałym połączeniu z rzeką Dunajec, co zapewnia ciągłą wymianę wody i bogactwo gatunkowe. Dno jest przeważnie piaszczysto-żwirowe, z niewielkimi mulistymi osadami, co sprzyja rozwojowi czystej wody. Brzegi są łatwo dostępne i w większości pozbawione gęstych zarośli, co ułatwia wędkowanie z brzegu. Roślinność wodna jest słaba, głównie w postaci nielicznych pasów trzcin. Jest to doskonałe miejsce dla wędkarzy poszukujących boleni, jazi i kleni, które często wpływają tu z rzeki. Występują tu również sandacze i sumy, szczególnie w głębszych partiach. Brak jest znaczących zaczepów, co sprawia, że łowienie jest komfortowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21762, 4.1, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Boleń,Jaź,Kleń,Sandacz,Sum', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21763, 'Starorzecze (Isep)', 'starorzecze-isep-wojnicz-21763', 'OXBOW', 49.9541644, 20.8730794, 'Małopolskie', 'Wojnicz', 'Mniejsze starorzecze w Isepiu, charakteryzujące się płytkim dnem i bogatą roślinnością przybrzeżną. Dno jest muliste, z dużą ilością detrytusu, co sprzyja rozwojowi bezkręgowców, stanowiących pokarm dla ryb. Brzegi są gęsto porośnięte trzciną i pałką wodną, co utrudnia dostęp, ale tworzy doskonałe kryjówki dla ryb. To idealne miejsce dla wędkarzy ceniących łowienie lina i karasia pospolitego, które osiągają tu znaczne rozmiary. W letnie upały, ze względu na płytkość i gęste zarośla, woda może być uboga w tlen, co wpływa na aktywność ryb. Wędkowanie wymaga cierpliwości i precyzji ze względu na liczne zaczepy w roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21763, 1.5, 0.8, 1.9, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21764, 'Starorzecze (Isep)', 'starorzecze-isep-wojnicz-21764', 'OXBOW', 49.9547826, 20.873272, 'Małopolskie', 'Wojnicz', 'To starorzecze w Isepiu, choć niewielkie, jest bardzo urokliwe i pełne życia. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem w większości partii, co jest korzystne dla wielu gatunków ryb. Brzegi są częściowo dostępne, z niewielkimi pasami trzcin i pojedynczymi drzewami zapewniającymi cień. Roślinność wodna jest umiarkowana, głównie w postaci pasów trzcin przy brzegach i sporadycznych skupisk moczarki. To dobre miejsce do łowienia okonia i płoci, a także szczupaka, który poluje na mniejsze ryby. Wiosną i jesienią akwen tętni życiem, oferując dobre brania. Ryzyko zaczepów jest niskie, co sprzyja komfortowemu wędkowaniu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21764, 1.2, 1.3, 2.8, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Okoń,Płoć,Szczupak,Wzdręga', 'Dobry, miejscami zarośnięty', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21765, 'Starorzecze (Sieciechowice)', 'starorzecze-sieciechowice-wojnicz-21765', 'OXBOW', 49.9930337, 20.8826526, 'Małopolskie', 'Wojnicz', 'Starorzecze w Sieciechowicach to dość rozległy akwen o zróżnicowanym dnie, gdzie muliste osady przeplatają się z twardszymi, piaszczystymi partiami. Brzegi są częściowo dostępne, ale w wielu miejscach gęsto zarośnięte trzciną i krzewami, co wymaga poszukiwania dogodnych stanowisk. Roślinność wodna jest obfita, z dominacją grążeli i moczarki, tworząc idealne schronienia dla ryb. To doskonałe łowisko dla leszczy, płoci i karpi, które osiągają tu piękne rozmiary. W cieplejszych miesiącach należy uważać na ryzyko zakwitów wody, które mogą wpływać na aktywność ryb. Liczne zaczepy w postaci zatopionych gałęzi i podwodnej roślinności wymagają stosowania mocniejszych zestawów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21765, 5.5, 1.6, 3.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Leszcz,Karp,Płoć,Szczupak,Karaś srebrzysty', 'Dobry w wybranych miejscach', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21766, 'Starorzecze (Sieciechowice)', 'starorzecze-sieciechowice-wojnicz-21766', 'OXBOW', 49.9894592, 20.886793, 'Małopolskie', 'Wojnicz', 'To starorzecze, choć mniejsze, jest bardzo ciekawe pod względem wędkarskim. Charakteryzuje się dość głębokim korytem w centralnej części i piaszczysto-mulistym dnem. Brzegi są strome i porośnięte gęstym lasem, co zapewnia cień i spokój. Roślinność wodna jest umiarkowana, głównie w postaci pasów trzcin przy brzegach. To doskonałe miejsce do łowienia szczupaka i okonia, które często ukrywają się w głębszych partiach. Dostęp do wody jest utrudniony ze względu na strome i zarośnięte brzegi, co sprawia, że łowisko jest mniej oblegane. Wędkowanie wymaga precyzji i ostrożności ze względu na pojedyncze zaczepy w postaci korzeni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21766, 2, 2.2, 4.8, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Węgorz,Leszcz', 'Trudny, strome brzegi', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21767, 'Starorzecze (Sieciechowice)', 'starorzecze-sieciechowice-wojnicz-21767', 'OXBOW', 49.989374, 20.8872647, 'Małopolskie', 'Wojnicz', 'Trzecie starorzecze w Sieciechowicach to płytki, silnie zarośnięty akwen, idealny dla ryb spokojnego żeru. Dno jest w całości muliste, z grubą warstwą osadów organicznych. Brzegi są całkowicie niedostępne, porośnięte gęstą trzciną i bagnistą roślinnością, co wymaga użycia pontonu lub brodzenia w specjalistycznym sprzęcie. Roślinność wodna jest ekstremalnie bujna, z dominacją grążeli, rdestnic i moczarki, tworząc labirynt podwodnych kryjówek. To raj dla lina, karasia pospolitego i wzdręgi, które osiągają tu imponujące rozmiary. W upalne lata ryzyko przyduchy jest bardzo wysokie, co może prowadzić do śnięcia ryb. Wędkowanie jest tu bardzo trudne ze względu na gęste zaczepy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21767, 1.7, 0.7, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21768, 'Starorzecze (Sieciechowice)', 'starorzecze-sieciechowice-wojnicz-21768', 'OXBOW', 49.9910438, 20.8876677, 'Małopolskie', 'Wojnicz', 'To starorzecze w Sieciechowicach ma charakterystyczny, wydłużony kształt i zróżnicowane dno, od piaszczystego po muliste. Brzegi są dość dostępne, z pojedynczymi pasami trzcin i drzewami dającymi cień. Roślinność wodna jest umiarkowana, z przewagą rdestnic w płytszych partiach. Jest to popularne łowisko dla leszczy, płoci i karpi, które często żerują wzdłuż brzegów. Wiosną, po roztopach, woda jest krystalicznie czysta, co pozwala na obserwację podwodnego życia. Wędkowanie jest tu stosunkowo łatwe, z niewielką ilością zaczepów. Akwen jest dobrze zarządzany, co sprzyja utrzymaniu zdrowej populacji ryb. Wędkarze mogą liczyć na dobre brania przez większą część sezonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21768, 3, 1.4, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Karaś srebrzysty', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21769, 'Starorzecze (Sieciechowice)', 'starorzecze-sieciechowice-wojnicz-21769', 'OXBOW', 49.9914002, 20.8880343, 'Małopolskie', 'Wojnicz', 'Ostatnie z opisywanych starorzeczy w Sieciechowicach to kameralny akwen o krystalicznie czystej wodzie i twardym, piaszczysto-żwirowym dnie. Brzegi są łatwo dostępne, z nielicznymi zaroślami, co ułatwia swobodne poruszanie się. Roślinność wodna jest słaba, głównie w postaci niewielkich skupisk moczarki. To doskonałe miejsce do łowienia okonia i szczupaka, które aktywnie polują w czystej wodzie. Występują tu również płocie i wzdręgi, które stanowią bazę pokarmową dla drapieżników. Brak jest znaczących zaczepów, co sprawia, że łowienie jest komfortowe i rzadko kończy się utratą sprzętu. Wędkowanie jest tu przyjemnością, szczególnie wczesnym rankiem i późnym popołudniem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21769, 1, 1.8, 3.5, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Okoń,Szczupak,Płoć,Wzdręga', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21770, 'Starorzecze Bogumiłowice A', 'starorzecze-bogumilowice-a-bogumilowice-21770', 'OXBOW', 50.0056441, 20.8864554, 'Małopolskie', 'Bogumiłowice', 'To starorzecze, zlokalizowane w malowniczej dolinie Wisły, charakteryzuje się typowym dla tego typu zbiorników mulistym dnem i bogatą roślinnością przybrzeżną. Dominują tu szerokie pasy trzcin i pałki wodnej, które stanowią doskonałe schronienie dla ryb, ale utrudniają dostęp do wody. Niewielka głębokość sprzyja szybkiemu nagrzewaniu się wody latem, co może prowadzić do niedoborów tlenu w upalne dni. Jest to idealne miejsce dla wędkarzy poszukujących lina, karasia pospolitego oraz szczupaka, który często czyha w zaroślach. Wiosną i jesienią żerują tu również dorodne płocie i leszcze, zwłaszcza po obfitych opadach, gdy woda jest świeższa. Brzegi są miejscami podmokłe, co wymaga odpowiedniego obuwia, a liczne zatopione gałęzie stanowią naturalne kryjówki dla ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21770, 3.2, 1.5, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21771, 'Starorzecze Bogumiłowice B', 'starorzecze-bogumilowice-b-bogumilowice-21771', 'OXBOW', 50.0059519, 20.8864566, 'Małopolskie', 'Bogumiłowice', 'Drugie starorzecze w okolicy Bogumiłowic, nieco mniejsze i bardziej płytkie, ale równie atrakcyjne pod względem wędkarskim. Dno jest tu głównie muliste, z lokalnymi twardszymi fragmentami, co pozwala na różnorodne techniki połowu. Roślinność podwodna jest bujna, tworząc podwodne łąki, które są siedliskiem dla wielu gatunków bezkręgowców i narybku. Brzegi są miejscami trudnodostępne ze względu na podmokły teren i gęste zarośla, co wymaga użycia wodoodpornego obuwia. Wędkarze mogą liczyć na obfite połowy płoci, leszczy i wzdręg, a także na okazy lina i karasia pospolitego. Latem, w upalne dni, należy zachować ostrożność ze względu na ryzyko przyduchy, jednak regularne opady poprawiają sytuację tlenową. Warto poszukać głębszych rynien, które często kryją większe drapieżniki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21771, 2.1, 1, 2.2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Płoć,Leszcz,Wzdręga,Lin,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21772, 'Starorzecze Łukanowice A', 'starorzecze-lukanowice-a-lukanowice-21772', 'OXBOW', 49.9659733, 20.8794867, 'Małopolskie', 'Łukanowice', 'To starorzecze, położone niedaleko Łukanowic, jest typowym zbiornikiem starorzecznym o wydłużonym kształcie. Charakteryzuje się przeważnie mulistym dnem, miejscami pokrytym drobnym żwirem, co świadczy o dawnych nurtach rzeki. Roślinność przybrzeżna jest umiarkowana, z dominacją trzcin i sitowia, co zapewnia dogodne miejsca do wędkowania z brzegu. Głębokość jest zmienna, z wyraźnymi rynnami i płytszymi zatokami, co stwarza różnorodne siedliska dla ryb. W zbiorniku tym dominują populacje płoci, leszczy i karasi srebrzystych, często osiągających imponujące rozmiary. Można tu również trafić na lina i szczupaka, zwłaszcza w okolicach podwodnych zarośli. W okresach suszy poziom wody może nieco spadać, ale starorzecze rzadko wysycha całkowicie, oferując stabilne warunki dla ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21772, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Karaś srebrzysty,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21773, 'Starorzecze Łukanowice B', 'starorzecze-lukanowice-b-lukanowice-21773', 'OXBOW', 49.9657275, 20.8795949, 'Małopolskie', 'Łukanowice', 'Mniejsze z dwóch starorzeczy w okolicy Łukanowic, to urokliwe łowisko charakteryzuje się bardziej zarośniętymi brzegami i bogatą roślinnością wodną. Dno jest w większości muliste, z licznymi zatopionymi gałęziami i korzeniami, które tworzą idealne kryjówki dla drapieżników. Dostęp do wody jest utrudniony w wielu miejscach przez gęste zarośla, co wymaga cierpliwości i często brodzenia w wodzie. Jest to raj dla wędkarzy ceniących sobie spokój i poszukujących lina, karasia pospolitego oraz okonia. Wiosną i jesienią aktywne są tu również płocie i wzdręgi. Ze względu na płytkość i obfitość materii organicznej, ryzyko niedoboru tlenu w upalne lata jest podwyższone. Warto szukać głębszych miejsc w centrum zbiornika, gdzie ryby często gromadzą się w trudniejszych warunkach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21773, 1.8, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Okoń,Wzdręga', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21774, 'Starorzecze Cisna A', 'starorzecze-cisna-a-cisna-21774', 'OXBOW', 49.2255251, 22.7137319, 'Podkarpackie', 'Cisna', 'Starorzecze położone w malowniczym regionie Bieszczadów, charakteryzuje się krystalicznie czystą wodą i kamienistym dnem, co jest rzadkością dla tego typu zbiorników. Otoczone jest gęstymi lasami bukowymi i jodłowymi, co nadaje mu unikalny, dziki charakter. Dostęp do brzegu jest miejscami utrudniony przez strome zbocza i powalone drzewa, ale widoki rekompensują wszelkie niedogodności. W starorzeczu tym można spotkać klenie i jazie, doskonale przystosowane do bystrego nurtu, a także okonie i płocie. Ze względu na górski charakter, woda jest dobrze natleniona, a ryzyko przyduchy jest minimalne. Wędkarstwo tutaj to prawdziwe wyzwanie, ale i nagroda w postaci pięknych, dzikich ryb. Warto szukać głębszych partii przy zwalonych drzewach, gdzie ryby często ukrywają się przed drapieżnikami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21774, 2.9, 1.7, 3.8, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Kleń,Jaź,Płoć,Okoń', 'Trudny, strome zbocza', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21775, 'Starorzecze Cisna B', 'starorzecze-cisna-b-cisna-21775', 'OXBOW', 49.2243602, 22.7132055, 'Podkarpackie', 'Cisna', 'To starorzecze, również w Bieszczadach, jest nieco bardziej odizolowane i ma charakter typowego zbiornika leśnego. Dno jest mieszane, z przewagą piasku i żwiru, ale z lokalnymi osadami mułu. Brzegi są porośnięte gęstą roślinnością leśną, a dostęp do wody jest możliwy tylko w kilku wyznaczonych miejscach. Woda jest przejrzysta, a jej temperatura utrzymuje się na niższym poziomie niż w nizinnych starorzeczach. Występują tu głównie gatunki ryb związane z górskimi rzekami, takie jak klenie i jazie, ale także okonie i płocie, które dobrze czują się w chłodniejszej wodzie. Ze względu na bliskość lasu, w wodzie często znajdują się zatopione konary i gałęzie, które stanowią doskonałe kryjówki. Jest to idealne miejsce dla wędkarzy szukających spokoju i kontaktu z dziką naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21775, 1.5, 1.2, 2.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Kleń,Jaź,Okoń,Płoć', 'Trudny, zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21776, 'Starorzecze Cisna C', 'starorzecze-cisna-c-cisna-21776', 'OXBOW', 49.2245913, 22.7133697, 'Podkarpackie', 'Cisna', 'Kolejne starorzecze w Bieszczadach, charakteryzujące się niewielkim rozmiarem, ale dużą głębokością jak na starorzecze, co wynika z jego położenia w wąskiej dolinie. Dno jest głównie kamieniste i żwirowe, z minimalną ilością mułu. Roślinność wodna jest skąpa, co sprzyja przejrzystości wody i dobrym warunkom tlenowym przez cały rok. Brzegi są strome i skaliste, z ograniczonym dostępem do wody, co wymaga ostrożności i odpowiedniego sprzętu. Jest to idealne miejsce dla wędkarzy poszukujących klenia i jazia, które doskonale czują się w bystrym nurcie. Ze względu na głębokość i czystość wody, można tu również spotkać okonie i sporadycznie szczupaki. Woda jest tu zazwyczaj chłodna, co sprzyja aktywności ryb nawet w cieplejsze dni. Warto eksplorować miejsca przy zwalonych drzewach, które oferują schronienie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21776, 0.8, 2, 4.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Kleń,Jaź,Okoń,Szczupak', 'Trudny, strome zbocza', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21777, 'Starorzecze Cisna D', 'starorzecze-cisna-d-cisna-21777', 'OXBOW', 49.2249931, 22.7135898, 'Podkarpackie', 'Cisna', 'To starorzecze, choć niewielkie, jest prawdziwą perłą Bieszczadów, oferującą unikalne warunki wędkarskie. Jego dno jest mozaiką kamieni, żwiru i piasku, z niewielkimi kieszeniami mułu. Otoczone jest dziewiczym lasem, a dostęp do wody jest możliwy jedynie w kilku miejscach, co zapewnia intymność i spokój. Woda jest krystalicznie czysta i dobrze natleniona, co sprzyja występowaniu ryb typowych dla górskich strumieni, takich jak klenie i jazie. Można tu również trafić na okonia, który preferuje chłodniejsze, dobrze natlenione wody. Niewielka presja wędkarska sprawia, że ryby są ostrożne, ale ich złowienie daje ogromną satysfakcję. Warto szukać głębszych partii w pobliżu zwalonych drzew, które stanowią naturalne schronienie i miejsca żerowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21777, 0.6, 1, 2, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Kleń,Jaź,Okoń', 'Trudny, zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21778, 'Starorzecze Gościencin', 'starorzecze-gosciencin-gosciencin-21778', 'OXBOW', 50.9179512, 19.8364602, 'Łódzkie', 'Gościencin', 'Starorzecze w Gościencinie to typowy zbiornik nizinny, charakteryzujący się mulistym dnem i obfitą roślinnością wodną. Brzegi są miejscami podmokłe i porośnięte gęstymi trzcinami, co utrudnia swobodny dostęp do wody. Jest to jednak raj dla wędkarzy ceniących sobie spokój i poszukujących lina, karasia pospolitego oraz dorodnych płoci. W cieplejszych miesiącach można tu również liczyć na okonia i szczupaka, który często czyha w zaroślach. Ze względu na płytkość i bogactwo materii organicznej, ryzyko przyduchy w upalne lata jest wysokie, dlatego najlepsze okresy na wędkowanie to wiosna i jesień. Warto szukać miejsc z twardszym dnem, gdzie ryby często żerują. Starorzecze to jest dobrym przykładem zbiornika, który wymaga cierpliwości i znajomości terenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21778, 3.8, 1.3, 2.6, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21779, 'Starorzecze Kwisy (Leśna)', 'starorzecze-kwisy-lesna-lesna-21779', 'OXBOW', 51.1015983, 15.2991091, 'Dolnośląskie', 'Leśna', 'Starorzecze Kwisy to rozległy zbiornik położony w malowniczej dolinie rzeki, charakteryzujący się urozmaiconym dnem z przewagą piasku i żwiru, ale z mulistymi zatokami. Brzegi są stosunkowo łatwo dostępne, miejscami porośnięte trawą i pojedynczymi krzewami, co sprzyja wędkowaniu z brzegu. Woda jest tu zazwyczaj czysta, a dzięki połączeniu z rzeką, dobrze natleniona przez większość roku. Jest to doskonałe łowisko dla wędkarzy poszukujących leszczy, płoci, a także szczupaków i okoni. Można tu również trafić na bolenie i jazie, które wpływają z rzeki. W okresie wiosennych roztopów i po intensywnych opadach, poziom wody może znacznie wzrosnąć, co sprzyja migracji ryb. Warto eksplorować miejsca na styku rzeki i starorzecza, które są często bogate w ryby.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21779, 12, 2, 4.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21780, 'Starorzecze Antonin', 'starorzecze-antonin-antonin-21780', 'OXBOW', 52.7121318, 22.5647585, 'Mazowieckie', 'Antonin', 'Starorzecze w Antoninie to typowy zbiornik nizinny, charakteryzujący się mulistym dnem i gęstą roślinnością wodną, zarówno wynurzoną, jak i zanurzoną. Brzegi są w większości trudno dostępne, porośnięte trzcinami i krzewami, co wymaga cierpliwości i często brodzenia. Jest to idealne miejsce dla wędkarzy poszukujących lina, karasia pospolitego oraz dużych płoci. Latem, w upalne dni, ryzyko przyduchy jest wysokie, co może wpływać na aktywność ryb. Wędkowanie z pontonu lub brodzenie w woderach jest często najlepszą opcją, aby dotrzeć do atrakcyjnych miejsc. Warto szukać głębszych rynien i prześwitów w roślinności, gdzie ryby często żerują. Starorzecze to jest znane z dorodnych okazów lina, które wymagają finezyjnego podejścia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21780, 5.5, 1.6, 3, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21781, 'Starorzecze Kraski Górne A', 'starorzecze-kraski-gorne-a-kraski-gorne-21781', 'OXBOW', 51.6924339, 21.4710387, 'Mazowieckie', 'Kraski Górne', 'To starorzecze, położone w pobliżu Krasek Górnych, jest typowym zbiornikiem nizinnego charakteru, z dnem pokrytym grubą warstwą mułu. Brzegi są miejscami podmokłe i zarośnięte, choć w niektórych rejonach dostęp jest łatwiejszy. Obfita roślinność wodna tworzy liczne kryjówki dla ryb, ale jednocześnie utrudnia prowadzenie zestawów. W wodach starorzecza dominują płocie, leszcze i karasie srebrzyste, które często osiągają znaczne rozmiary. Można tu również trafić na lina i okonia, zwłaszcza w rejonach z większą ilością roślinności. Ze względu na płytkość i brak silnego nurtu, w upalne lato może wystąpić ryzyko niedoboru tlenu. Jest to idealne miejsce dla wędkarzy ceniących sobie spokój i poszukujących ryb spokojnego żeru.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21781, 4.1, 1.1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Płoć,Leszcz,Karaś srebrzysty,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21782, 'Starorzecze Kraski Górne B', 'starorzecze-kraski-gorne-b-kraski-gorne-21782', 'OXBOW', 51.7072578, 21.4685069, 'Mazowieckie', 'Kraski Górne', 'Drugie starorzecze w okolicy Krasek Górnych, charakteryzujące się nieco większą powierzchnią i bardziej zróżnicowanym dnem, gdzie muł przeplata się z twardszymi fragmentami. Brzegi są częściowo dostępne, choć w wielu miejscach porastają je gęste zarośla i trzciny. Akwen ten jest znany z obfitości leszczy i płoci, a także z dorodnych karasi pospolitych. Wędkarze spinningowi mogą liczyć na szczupaka i okonia, które czyhają w zaroślach i przy zatopionych drzewach. Połączenie z rzeką podczas wysokiej wody zapewnia regularne zarybienia i dobrą wymianę wody, co minimalizuje ryzyko przyduchy. Warto poszukać głębszych miejsc w centrum zbiornika, które są często ostoją dla większych ryb. Jest to atrakcyjne łowisko dla wędkarzy poszukujących różnorodności gatunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21782, 6.8, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karaś pospolity,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21783, 'Starorzecze Antoniówka Świerżowska', 'starorzecze-antoniowka-swierzowska-antoniowka-swierzowska-21783', 'OXBOW', 51.6797639, 21.4833749, 'Mazowieckie', 'Antoniówka Świerżowska', 'Starorzecze w Antoniówce Świerżowskiej to niewielki, ale głęboki zbiornik, położony w otoczeniu pól i lasów. Dno jest głównie muliste, z licznymi zatopionymi gałęziami i korzeniami, które stanowią schronienie dla ryb. Brzegi są miejscami strome i porośnięte gęstą roślinnością, co utrudnia dostęp. Jest to idealne miejsce dla wędkarzy poszukujących lina, karasia pospolitego oraz okonia. Wiosną i jesienią aktywne są tu również płocie i leszcze. Ze względu na głębokość i stosunkowo niewielką powierzchnię, ryzyko niedoboru tlenu jest umiarkowane, ale w ekstremalnie upalne lata może wystąpić. Warto eksperymentować z różnymi technikami, aby dotrzeć do ryb ukrywających się w zaroślach. Starorzecze to jest znane z okazałych linów, które wymagają cierpliwości i precyzji.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21783, 2.5, 1.9, 3.8, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Okoń,Płoć', 'Trudny, mocno zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21784, 'Starorzecze Kraski Górne C', 'starorzecze-kraski-gorne-c-kraski-gorne-21784', 'OXBOW', 51.6990386, 21.4718701, 'Mazowieckie', 'Kraski Górne', 'To starorzecze, trzecie w okolicy Krasek Górnych, jest najbardziej odizolowane i ma charakter dzikiego łowiska. Dno jest w przeważającej części muliste, z dużą ilością zgnitej materii organicznej, co sprzyja rozwojowi bujnej roślinności podwodnej. Brzegi są bagniste i niemal całkowicie porośnięte trzcinami i krzewami, co sprawia, że dostęp do wody jest niezwykle trudny i wymaga użycia woderów. Jest to jednak raj dla wędkarzy poszukujących lina i karasia pospolitego, które osiągają tu imponujące rozmiary. Można tu również trafić na szczupaka i okonia, które czują się doskonale w tak zarośniętym środowisku. Ze względu na płytkość i obfitość roślinności, ryzyko przyduchy w upalne lata jest bardzo wysokie. Wędkowanie z pontonu jest tu często jedyną skuteczną metodą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21784, 3.5, 0.8, 1.6, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21785, 'Starorzecze (Kraski Górne)', 'starorzecze-kraski-gorne-garwolin-21785', 'OXBOW', 51.6973699, 21.4656592, 'Mazowieckie', 'Garwolin', 'Długie i wąskie starorzecze o charakterystycznym kształcie, położone w dolinie Wisły. Dno jest przeważnie muliste, z miejscowymi twardszymi plamami piasku i żwiru. Brzegi są gęsto porośnięte trzciną, tatarakiem oraz licznymi krzewami i drzewami, co utrudnia dostęp do wody. W akwenie występuje obfita roślinność podwodna, w tym grążele i rdestnice, stanowiące doskonałe kryjówki dla ryb. Jest to idealne łowisko na lina, karasia i szczupaka, choć wymaga cierpliwości i precyzji w zarzucaniu. Wędkarze powinni być przygotowani na liczne zaczepy i konieczność użycia długich wędek.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21785, 3.2, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew i gęstej roślinności', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21786, 'Starorzecze (Kraski Górne)', 'starorzecze-kraski-gorne-garwolin-21786', 'OXBOW', 51.6987959, 21.4649667, 'Mazowieckie', 'Garwolin', 'To fragment rozległego kompleksu starorzeczy wiślanych, charakteryzujący się spokojną wodą i bogatym ekosystemem. Dno jest zróżnicowane, od miękkiego mułu po twardsze, piaszczyste odcinki, szczególnie w płytszych partiach. Brzegi są częściowo dostępne, jednak w większości porośnięte pasem trzcin i krzewów, co wymaga poszukiwania dogodnych stanowisk. Obfitość roślinności wodnej, takiej jak lilie wodne i moczarka, tworzy schronienie dla wielu gatunków ryb. Akwen ten jest znany z dużych okazów lina i karasia, a także z obecności drapieżników takich jak szczupak i okoń. Wędkowanie tutaj to prawdziwe wyzwanie, ale nagroda w postaci pięknej ryby jest często warta wysiłku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21786, 2.8, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Okoń,Płoć,Leszcz', 'Trudny, miejscami bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21787, 'Starorzecze (Kraski Górne)', 'starorzecze-kraski-gorne-garwolin-21787', 'OXBOW', 51.7005769, 21.465085, 'Mazowieckie', 'Garwolin', 'Kolejne malownicze starorzecze w rejonie Krasek Górnych, oferujące unikalne doświadczenia wędkarskie. Charakteryzuje się dość płytkim dnem, które w większości pokryte jest grubą warstwą mułu, jednak w niektórych miejscach można znaleźć twardsze podłoże. Brzegi są silnie zarośnięte gęstą trzciną i bujną roślinnością przybrzeżną, co wymaga cierpliwości w poszukiwaniu wolnych stanowisk. W wodzie dominuje roślinność zanurzona i wynurzona, tworząc idealne warunki dla ryb spokojnego żeru oraz drapieżników. Jest to doskonałe miejsce na połów karasia, wzdręgi i lina, a także mniejszych szczupaków. Ze względu na gęste zarośla, najlepiej sprawdza się tu metoda spławikowa lub delikatne zestawy gruntowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21787, 1.9, 1.2, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Lin,Płoć', 'Bardzo trudny, gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21788, 'Starorzecze (Konstancin-Jeziorna)', 'starorzecze-konstancin-jeziorna-konstancin-jeziorna-21788', 'OXBOW', 52.0874099, 21.1075589, 'Mazowieckie', 'Konstancin-Jeziorna', 'Starorzecze to jest częścią kompleksu wodnego w pobliżu Konstancina-Jeziorny, charakteryzującego się malowniczym położeniem i stosunkowo łatwym dostępem. Dno jest przeważnie muliste, ale miejscami występują twardsze, piaszczyste fragmenty, zwłaszcza wzdłuż dawnego koryta rzeki. Brzegi są zróżnicowane – od fragmentów zalesionych po otwarte polany, choć dominują zarośla trzcinowe. Woda jest bogata w roślinność zanurzoną, co sprzyja rozwojowi populacji ryb. Akwen ten jest znany z obfitości leszczy i płoci, a także z występowania szczupaków i okoni. Mimo bliskości miasta, zachowuje dziki charakter, oferując wędkowanie w spokojnej atmosferze.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21788, 4.5, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń', 'Dobry z niektórych stron, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21789, 'Starorzecze (Konstancin-Jeziorna)', 'starorzecze-konstancin-jeziorna-konstancin-jeziorna-21789', 'OXBOW', 52.0882276, 21.1105724, 'Mazowieckie', 'Konstancin-Jeziorna', 'To jedno z większych starorzeczy w okolicy Konstancina-Jeziorny, charakteryzujące się znaczną długością i zróżnicowaną głębokością. Dno jest przeważnie muliste, z głębszymi rynnami, gdzie osadza się więcej osadów, oraz płytszymi partiami z twardszym dnem. Brzegi są w większości porośnięte gęstą roślinnością, w tym trzciną i krzewami, co wymaga cierpliwości w poszukiwaniu dogodnych miejsc do wędkowania. Woda jest bogata w roślinność podwodną, tworząc idealne środowisko dla wielu gatunków ryb. Akwen ten słynie z obfitości płoci, leszczy, a także z występowania karpi i sumów w głębszych partiach. Jest to popularne miejsce zarówno dla wędkarzy spławikowych, jak i gruntowych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21789, 6.1, 2.5, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Karp,Sum,Szczupak', 'Dobry w niektórych miejscach, inne zarośnięte', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21790, 'Starorzecze (Konstancin-Jeziorna)', 'starorzecze-konstancin-jeziorna-konstancin-jeziorna-21790', 'OXBOW', 52.0884893, 21.1118873, 'Mazowieckie', 'Konstancin-Jeziorna', 'Ten odcinek starorzecza w Konstancinie-Jeziornie jest typowym zbiornikiem starorzecznym, charakteryzującym się spokojną wodą i bogatym życiem biologicznym. Dno jest w większości muliste, ale wzdłuż brzegów można natrafić na twardsze, piaszczyste podłoże. Brzegi są częściowo dostępne, jednak w dużej mierze porośnięte trzciną i przybrzeżnymi drzewami, co dodaje uroku, ale utrudnia swobodne przemieszczanie się. W akwenie występuje umiarkowana ilość roślinności podwodnej, co sprzyja rozwojowi populacji ryb. Jest to dobre miejsce na połów płoci, leszczy, a także okoni i mniejszych szczupaków. Wędkarze mogą liczyć na udane połowy, szczególnie wczesnym rankiem i wieczorem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21790, 3.8, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Miejscami dobry, inne zarośnięte', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21791, 'Starorzecze (Konstancin-Jeziorna)', 'starorzecze-konstancin-jeziorna-konstancin-jeziorna-21791', 'OXBOW', 52.0887335, 21.1159953, 'Mazowieckie', 'Konstancin-Jeziorna', 'To starorzecze, położone nieco dalej od centrum Konstancina-Jeziorny, zachowuje bardziej dziki charakter. Dno jest w dużej mierze pokryte grubą warstwą mułu, co świadczy o zaawansowanym procesie sedymentacji. Brzegi są gęsto zarośnięte drzewami, krzewami i trzciną, co sprawia, że dostęp do wody jest utrudniony i wymaga przygotowania. W akwenie dominuje bogata roślinność podwodna, tworząca idealne kryjówki dla ryb. Jest to doskonałe łowisko dla wędkarzy poszukujących lina, karasia pospolitego oraz dużych wzdręg. Ze względu na trudny dostęp i liczne zaczepy, zaleca się stosowanie mocniejszych zestawów i cierpliwości.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21791, 2.9, 1.5, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Bardzo trudny, gęsto zarośnięty', TRUE, 'Dużo zatopionych drzew i gęstej roślinności', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21792, 'Starorzecze (Ostrów)', 'starorzecze-ostrow-garwolin-21792', 'OXBOW', 51.7631758, 21.4345778, 'Mazowieckie', 'Garwolin', 'Starorzecze w Ostrowie to stosunkowo płytki zbiornik, który zachował swój naturalny, dziki charakter. Dno jest w większości muliste, z licznymi fragmentami pokrytymi opadłymi liśćmi i resztkami roślinności. Brzegi są gęsto porośnięte trzciną, krzewami i drzewami, co sprawia, że dostęp do wody jest ograniczony i wymaga często brodzenia. W akwenie występuje obfita roślinność podwodna, w tym grążele i lilie wodne, tworzące idealne schronienie dla ryb. Jest to doskonałe miejsce na połów karasia pospolitego, lina i wzdręgi, a także mniejszych okoni. Wędkarze powinni być przygotowani na liczne zaczepy i konieczność stosowania delikatnych zestawów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21792, 2.1, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21793, 'Starorzecze (Bączki)', 'starorzecze-baczki-garwolin-21793', 'OXBOW', 51.7705609, 21.4430932, 'Mazowieckie', 'Garwolin', 'Ten odcinek starorzecza w Bączkach to typowy, silnie zarośnięty zbiornik polodowcowy, charakteryzujący się bogactwem flory i fauny. Dno jest w przeważającej części muliste, z miejscowymi twardszymi fragmentami, szczególnie w pobliżu dawnego koryta rzeki. Brzegi są gęsto porośnięte trzciną, olchami i wierzbami, co utrudnia swobodny dostęp, ale tworzy urokliwe, dzikie zakątki. W akwenie dominuje roślinność podwodna, taka jak rdestnice i moczarka, stanowiąca idealne schronienie dla ryb. Jest to doskonałe łowisko na lina, karasia pospolitego oraz szczupaka, który często czyha w zaroślach. Wędkarze powinni przygotować się na cierpliwość i precyzję.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21793, 3.5, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew i gęstej roślinności', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21794, 'Starorzecze (Bączki)', 'starorzecze-baczki-garwolin-21794', 'OXBOW', 51.770399, 21.443658, 'Mazowieckie', 'Garwolin', 'To starorzecze w Bączkach jest mniejszym, ale równie atrakcyjnym zbiornikiem, idealnym dla wędkarzy ceniących spokój i dziką przyrodę. Dno jest w większości muliste, z warstwą opadłych liści, co sprzyja rozwojowi bogatej mikrofauny. Brzegi są gęsto porośnięte trzciną i krzewami, co utrudnia dostęp, ale jednocześnie chroni łowisko przed nadmierną presją wędkarską. W akwenie występuje obfita roślinność podwodna, tworząca idealne kryjówki dla ryb. Jest to doskonałe miejsce na połów karasia pospolitego, lina i wzdręgi, które osiągają tu imponujące rozmiary. Wędkarze powinni zabrać ze sobą woderosy, aby móc swobodnie poruszać się wzdłuż brzegów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21794, 1.5, 1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Bardzo trudny, gęsto zarośnięty i podmokły', TRUE, 'Gęsta roślinność podwodna i pojedyncze korzenie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21795, 'Starorzecze (Kraski Górne)', 'starorzecze-kraski-gorne-garwolin-21795', 'OXBOW', 51.7141345, 21.4635446, 'Mazowieckie', 'Garwolin', 'To starorzecze w Kraskach Górnych charakteryzuje się dość dużą powierzchnią i zróżnicowanym dnem, co czyni je atrakcyjnym dla wielu gatunków ryb. Dno jest przeważnie muliste, ale wzdłuż brzegów i w płytszych partiach można znaleźć twardsze, piaszczyste odcinki. Brzegi są częściowo dostępne, choć w wielu miejscach porośnięte gęstą trzciną i drzewami, co wymaga poszukiwania dogodnych stanowisk. W akwenie występuje umiarkowana ilość roślinności podwodnej, tworząc schronienie dla ryb. Jest to doskonałe łowisko na leszcza, płoć, a także na szczupaka i okonia. Dobre miejsce zarówno dla wędkarzy spławikowych, jak i tych preferujących metody gruntowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21795, 5, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń', 'Miejscami dobry, inne zarośnięte', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21796, 'Starorzecze (Kraski Górne)', 'starorzecze-kraski-gorne-garwolin-21796', 'OXBOW', 51.6998215, 21.4598234, 'Mazowieckie', 'Garwolin', 'Mniejsze starorzecze w Kraskach Górnych, charakteryzujące się spokojną wodą i intymną atmosferą. Dno jest w większości muliste, z licznymi osadami organicznymi, co sprzyja rozwojowi bogatej mikroflory i mikrofauny. Brzegi są gęsto porośnięte trzciną, tatarakiem oraz krzewami, co sprawia, że dostęp do wody jest utrudniony i wymaga cierpliwości. W akwenie występuje obfita roślinność podwodna, w tym grążele i lilie wodne, tworzące idealne kryjówki dla ryb. Jest to doskonałe miejsce na połów lina, karasia pospolitego i wzdręgi, które często żerują wśród roślinności. Wędkarze powinni być przygotowani na konieczność brodzenia i ostrożnego poruszania się.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21796, 2.3, 1.3, 2.7, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21797, 'Starorzecze (Drwinia)', 'starorzecze-drwinia-drwinia-21797', 'OXBOW', 50.0844482, 20.3649676, 'Małopolskie', 'Drwinia', 'Starorzecze w Drwini to malowniczy zbiornik, położony w dolinie Wisły, charakteryzujący się stosunkowo czystą wodą i urozmaiconym dnem. Dno jest piaszczysto-muliste, z miejscowymi twardszymi fragmentami, co sprzyja występowaniu różnych gatunków ryb. Brzegi są częściowo zalesione, a częściowo porośnięte trzciną, co zapewnia dobre kryjówki dla ryb i dogodne miejsca do wędkowania. W akwenie występuje umiarkowana ilość roślinności podwodnej, tworzącej naturalne środowisko dla wielu gatunków. Jest to doskonałe łowisko na leszcza, płoć, a także na okonia i szczupaka. Wędkarze mogą liczyć na udane połowy, szczególnie wczesnym rankiem i wieczorem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21797, 4, 2.2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Boleń', 'Dobry z niektórych stron, inne zarośnięte', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21798, 'Starorzecze (Ispina)', 'starorzecze-ispina-ispina-21798', 'OXBOW', 50.1059347, 20.3567757, 'Małopolskie', 'Ispina', 'To starorzecze w Ispinie, położone blisko Wisły, jest cenionym łowiskiem ze względu na swoją głębokość i bogactwo ryb. Dno jest zróżnicowane, od piaszczystych płycizn po głębokie rynny z mulistym dnem. Brzegi są w większości porośnięte trzciną i krzewami, ale istnieją również łatwo dostępne stanowiska. W akwenie występuje umiarkowana ilość roślinności podwodnej, co sprzyja rozwojowi populacji ryb. Jest to doskonałe miejsce na połów leszcza, płoci, a także drapieżników takich jak szczupak, sandacz i sum. Wędkarze mogą liczyć na duże okazy, szczególnie w głębszych partiach zbiornika.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21798, 7.5, 3, 6, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Sandacz,Sum', 'Dobry z niektórych stron, inne zarośnięte', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21799, 'Starorzecze (Kraski Górne)', 'starorzecze-kraski-gorne-garwolin-21799', 'OXBOW', 51.7016955, 21.4694663, 'Mazowieckie', 'Garwolin', 'Ostatnie starorzecze w rejonie Krasek Górnych to typowy, silnie zarośnięty zbiornik, charakteryzujący się bogactwem flory i fauny. Dno jest w przeważającej części muliste, z miejscowymi twardszymi fragmentami, szczególnie w pobliżu dawnego koryta rzeki. Brzegi są gęsto porośnięte trzciną, olchami i wierzbami, co utrudnia swobodny dostęp, ale tworzy urokliwe, dzikie zakątki. W akwenie dominuje roślinność podwodna, taka jak rdestnice i moczarka, stanowiąca idealne schronienie dla ryb. Jest to doskonałe łowisko na lina, karasia pospolitego oraz szczupaka, który często czyha w zaroślach. Wędkarze powinni przygotować się na cierpliwość i precyzję.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21799, 3, 1.7, 3.3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew i gęstej roślinności', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21800, 'Starorzecze (Antoniówka Świerżowska)', 'starorzecze-antoniowka-swierzowska-antoniowka-swierzowska-21800', 'OXBOW', 51.6841335, 21.4740698, 'Mazowieckie', 'Antoniówka Świerżowska', 'To urokliwe starorzecze, położone w malowniczej dolinie Wisły, stanowi idealne miejsce dla wędkarzy ceniących spokój i kontakt z naturą. Dno jest przeważnie muliste, z licznymi zatopionymi konarami i gałęziami, które tworzą doskonałe kryjówki dla drapieżników. Brzegi są gęsto porośnięte trzciną i pałką wodną, co utrudnia dostęp, ale jednocześnie zapewnia naturalne schronienie dla ryb. Roślinność podwodna jest obfita, zwłaszcza w płytszych zatoczkach, gdzie dominują grążele i moczarka kanadyjska. Wędkując tutaj, można liczyć na spotkanie z dorodnymi szczupakami, ostrożnymi linami oraz licznymi płociami i okoniami. Wiosna i wczesna jesień to najlepsze pory na udane połowy, szczególnie metodą spławikową lub spinningową.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21800, 3.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Płoć,Okoń,Karaś pospolity', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21801, 'Starorzecze (Trzciana)', 'starorzecze-trzciana-trzciana-21801', 'OXBOW', 49.4921686, 21.7130342, 'Podkarpackie', 'Trzciana', 'To starorzecze, położone w górskiej scenerii Podkarpacia, charakteryzuje się czystą wodą i kamienisto-żwirowym dnem, które przechodzi w muliste osady w głębszych partiach. Jest to pozostałość po dawnej rzece, która wciąż zachowuje pewne cechy górskiego potoku, zwłaszcza po ulewnych deszczach. Brzegi są zróżnicowane, od łatwo dostępnych piaszczystych plażek po strome, zadrzewione skarpy, oferując różnorodne stanowiska wędkarskie. Roślinność wodna jest umiarkowana, skupiając się głównie w płytszych zatokach i przy brzegach. W tym starorzeczu dominują gatunki takie jak płoć, leszcz, a także drapieżniki jak okoń i szczupak. Wędkowanie gruntowe i spławikowe jest tutaj bardzo popularne, a spokojna atmosfera sprzyja relaksowi nad wodą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21801, 2.8, 2, 4.5, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry z niektórych stron, miejscami stromy', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21802, 'Starorzecze (Antoniówka Świerżowska)', 'starorzecze-antoniowka-swierzowska-antoniowka-swierzowska-21802', 'OXBOW', 51.6692384, 21.5048609, 'Mazowieckie', 'Antoniówka Świerżowska', 'Starorzecze to jest częścią kompleksu wodnego w okolicach Antoniówki Świerżowskiej, charakteryzujące się silnym zarośnięciem i obfitością podwodnej roślinności. Dno jest mocno zamulone, co sprzyja rozwojowi bogatej flory i fauny bezkręgowców, stanowiących bazę pokarmową dla ryb. Brzegi są trudno dostępne, gęsto porośnięte krzewami i wysoką trzciną, co wymaga cierpliwości i odpowiedniego przygotowania od wędkarza. Woda w okresie letnim może być cieplejsza, co sprzyja rozwojowi ryb ciepłolubnych. Głównymi mieszkańcami tego akwenu są liny, karasie pospolite oraz liczne płocie i wzdręgi. Wędkowanie spławikowe i gruntowe w lukach między roślinnością to najskuteczniejsze metody połowu. To idealne miejsce dla poszukiwaczy spokoju i miłośników dzikiej przyrody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21802, 1.9, 1, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21803, 'Starorzecze (Bobrowniki)', 'starorzecze-bobrowniki-bobrowniki-21803', 'OXBOW', 51.8333117, 15.7516342, 'Lubuskie', 'Bobrowniki', 'To rozległe starorzecze w pobliżu Bobrownik jest typowym zbiornikiem połączonym z Odrą podczas większych wezbrań, co sprzyja migracji ryb i wzbogaca ichtiofaunę. Dno jest zróżnicowane, od piaszczysto-żwirowego po muliste, z licznymi dołkami i podwodnymi górkami. Brzegi są częściowo dostępne, z miejscami do wygodnego rozłożenia sprzętu, ale także z zarośniętymi odcinkami, które oferują intymność. Roślinność wodna jest umiarkowana, z przewagą trzcin i grążeli w płytszych partiach. W starorzeczu występują liczne leszcze, płocie, okonie, a także drapieżniki takie jak szczupak i sandacz. Wędkowanie z gruntu i na spinning przynosi tutaj najlepsze efekty, zwłaszcza w okolicach podwodnych przeszkód i spowolnień nurtu. To popularne łowisko dla wędkarzy poszukujących różnorodności gatunkowej.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21803, 12.5, 2.2, 6, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Sandacz', 'Dobry z niektórych stron, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21804, 'Starorzecze (Głogów)', 'starorzecze-glogow-glogow-21804', 'OXBOW', 51.6717532, 16.0883622, 'Dolnośląskie', 'Głogów', 'To starorzecze, położone w bliskim sąsiedztwie Głogowa, jest łatwo dostępne i często odwiedzane przez lokalnych wędkarzy. Charakteryzuje się dnem mulistym, z niewielką ilością zatopionych drzew, co ułatwia łowienie. Brzegi są przeważnie stabilne i dostępne, z licznymi pomostami i stanowiskami wędkarskimi, choć niektóre odcinki mogą być zarośnięte. Roślinność wodna jest umiarkowana, skoncentrowana głównie w płytszych strefach brzegowych. W starorzeczu dominują leszcze, płocie, karasie srebrzyste oraz okonie, a także sporadycznie karpie. Wędkowanie spławikowe i gruntowe to najpopularniejsze metody, przynoszące dobre rezultaty przez większość sezonu. Jest to idealne miejsce dla rodzin z dziećmi oraz początkujących wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21804, 5.1, 1.8, 4, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karaś srebrzysty,Okoń,Karp', 'Dobry z większości stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21805, 'Starorzecze (Stare Serby)', 'starorzecze-stare-serby-stare-serby-21805', 'OXBOW', 51.674171, 16.1165691, 'Dolnośląskie', 'Stare Serby', 'Malownicze starorzecze w pobliżu Starych Serbów to ostoja spokoju, idealna dla wędkarzy poszukujących dzikiego charakteru łowiska. Dno jest mocno zamulone, z licznymi podwodnymi przeszkodami w postaci zatopionych gałęzi i korzeni, co stanowi wyzwanie, ale i szansę na większą rybę. Brzegi są w większości trudno dostępne, gęsto porośnięte trzciną i bujną roślinnością brzegową, co wymaga poszukiwania dogodnych miejsc. Roślinność podwodna jest bardzo silna, tworząc gęste dywany w płytszych partiach, utrudniając prowadzenie przynęty. W akwenie dominują liny, karasie pospolite, wzdręgi oraz szczupaki, które czają się wśród zarośli. Wędkowanie z pontonu lub brodzenie w woderach może znacznie zwiększyć skuteczność połowów. To łowisko wymaga cierpliwości i doświadczenia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21805, 2.1, 1.3, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21806, 'Starorzecze (Grodziec Mały)', 'starorzecze-grodziec-maly-grodziec-maly-21806', 'OXBOW', 51.676298, 16.0607428, 'Dolnośląskie', 'Grodziec Mały', 'Starorzecze to, położone w Grodźcu Małym, charakteryzuje się umiarkowanym zarośnięciem i dostępnymi brzegami, co czyni je atrakcyjnym dla wędkarzy. Dno jest mieszane, od piaszczysto-mulistego po żwirowe, z nielicznymi zatopionymi przeszkodami. Brzegi są w większości łatwo dostępne, z naturalnymi miejscami do wędkowania, choć lokalnie mogą występować kępy trzcin. Roślinność podwodna jest średnio rozwinięta, z przewagą rdestnic i moczarki. W akwenie spotkać można leszcze, płocie, okonie, a także karpie i liny, które dobrze czują się w zróżnicowanym środowisku. Wędkowanie gruntowe i spławikowe to najbardziej efektywne metody, a spinning również może przynieść sukcesy. To dobre miejsce na całodniowy wypad wędkarski.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21806, 4.5, 1.7, 3.5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Karp,Lin', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21807, 'Starorzecze (Ceber)', 'starorzecze-ceber-ceber-21807', 'OXBOW', 51.6796588, 16.0294425, 'Dolnośląskie', 'Ceber', 'To starorzecze w miejscowości Ceber wyróżnia się stosunkowo głębokimi partiami i czystszą wodą, co sprzyja występowaniu drapieżników. Dno jest twarde, piaszczysto-żwirowe, z miejscowymi osadami mułu w głębszych dołach. Brzegi są łatwo dostępne, z nielicznymi zaroślami, co umożliwia swobodne poruszanie się wzdłuż akwenu. Roślinność wodna jest skąpa, co sprzyja wędkarstwu spinningowemu i gruntowemu. W starorzeczu dominują szczupaki, okonie, sandacze, a także duże płocie i leszcze. To doskonałe miejsce dla wędkarzy poszukujących dużych drapieżników, szczególnie wczesną wiosną i jesienią. Warto eksplorować głębsze partie i okolice nielicznych zatopionych pni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21807, 6.8, 2.5, 5.5, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Sandacz,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21808, 'Starorzecze (Grodziec Mały)', 'starorzecze-grodziec-maly-grodziec-maly-21808', 'OXBOW', 51.6778485, 16.0658562, 'Dolnośląskie', 'Grodziec Mały', 'Kolejne starorzecze w Grodźcu Małym to mniejszy, bardziej intymny zbiornik, idealny dla wędkarzy ceniących spokój i kameralną atmosferę. Dno jest głównie muliste, z licznymi zatopionymi roślinami i drobnymi gałęziami, tworzącymi schronienia dla ryb. Brzegi są częściowo zarośnięte, ale da się znaleźć dogodne miejsca do zarzucenia wędki, szczególnie od strony polnej drogi. Roślinność podwodna jest bujna, co sprzyja rozwojowi lina i karasia. W akwenie dominują liny, karasie pospolite, płocie oraz wzdręgi, a także mniejsze okonie. Wędkowanie spławikowe i gruntowe z użyciem naturalnych przynęt to najlepsza taktyka. Jest to typowe łowisko białorybu, wymagające cierpliwości i precyzji.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21808, 1.5, 1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21809, 'Starorzecze (Grodziec Mały)', 'starorzecze-grodziec-maly-grodziec-maly-21809', 'OXBOW', 51.6776872, 16.0676613, 'Dolnośląskie', 'Grodziec Mały', 'To starorzecze, również w rejonie Grodźca Małego, wyróżnia się nieco większymi głębokościami w centralnej części, co pozwala na zimowanie większych ryb. Dno jest zróżnicowane, od twardych, piaszczystych płycizn po głębokie, muliste rynny. Brzegi są częściowo dostępne, z miejscowymi zaroślami, które zapewniają osłonę przed słońcem i wiatrem. Roślinność podwodna jest umiarkowana, skoncentrowana głównie w strefie brzegowej. W akwenie występują leszcze, płocie, szczupaki, okonie, a także sporadycznie karpie. Wędkowanie gruntowe i spławikowe jest skuteczne, a spinning wzdłuż brzegów może przynieść sukces w poszukiwaniu drapieżników. To wszechstronne łowisko dla różnych technik.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21809, 3.9, 1.9, 4.2, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Karp', 'Dobry z niektórych stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21810, 'Starorzecze (Stare Serby)', 'starorzecze-stare-serby-stare-serby-21810', 'OXBOW', 51.6713487, 16.1389017, 'Dolnośląskie', 'Stare Serby', 'To starorzecze, zlokalizowane blisko Starych Serbów, charakteryzuje się płytkimi, silnie zarośniętymi partiami, co czyni je idealnym siedliskiem dla gatunków preferujących płytkie wody. Dno jest w całości pokryte grubą warstwą mułu i rozkładającej się roślinności, co wymaga delikatnego podejścia podczas wędkowania. Brzegi są niemal w całości otoczone gęstą trzciną i krzewami, co znacznie utrudnia dostęp do wody, ale zapewnia doskonałe kryjówki dla ryb. Roślinność podwodna jest ekstremalnie bujna, tworząc podwodne łąki. W akwenie dominują karasie pospolite, liny, wzdręgi oraz niewielkie szczupaki. Wędkowanie na spławik w małych prześwitach lub z pontonu to jedyne skuteczne metody. To łowisko dla prawdziwych miłośników dzikich miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21810, 1.2, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną, trudny', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21811, 'Starorzecze (Stare Serby)', 'starorzecze-stare-serby-stare-serby-21811', 'OXBOW', 51.6710231, 16.1429743, 'Dolnośląskie', 'Stare Serby', 'Kolejne starorzecze w okolicy Starych Serbów, nieco większe od poprzedniego, oferuje bardziej zróżnicowane warunki. Dno jest muliste, ale z miejscowymi twardymi blatami, co pozwala na różnorodne techniki wędkarskie. Brzegi są częściowo dostępne, z naturalnymi miejscami do wędkowania, choć wciąż dominują trzcinowiska. Roślinność podwodna jest umiarkowana, z większymi skupiskami w płytszych zatoczkach. W akwenie występują płocie, leszcze, liny, karasie srebrzyste oraz okonie, a także sporadycznie szczupaki. Wędkowanie gruntowe i spławikowe to najpopularniejsze metody, a wczesnym rankiem można liczyć na dobre brania. To łowisko o średnim stopniu trudności, odpowiednie dla większości wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21811, 2.7, 1.4, 2.9, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Lin,Karaś srebrzysty,Okoń', 'Częściowo dostępny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21812, 'Starorzecze (Klucze)', 'starorzecze-klucze-klucze-21812', 'OXBOW', 51.6709082, 16.1450422, 'Dolnośląskie', 'Klucze', 'Starorzecze w Kluczach to niewielki, ale głęboki akwen, który wyróżnia się swoją klarowną wodą i dużą ilością zatopionych drzew. Dno jest twarde, piaszczysto-żwirowe, z licznymi głazami i korzeniami, co tworzy idealne kryjówki dla drapieżników. Brzegi są strome i w większości zalesione, co utrudnia dostęp, ale jednocześnie zapewnia cień i spokój. Roślinność podwodna jest słaba, co sprzyja wędkarstwu spinningowemu i gruntowemu na otwartej wodzie. W akwenie dominują szczupaki, okonie, leszcze oraz płocie, a także sporadycznie sumy. Wędkowanie z łodzi lub pontonu jest bardzo skuteczne ze względu na trudny dostęp z brzegu. To łowisko dla doświadczonych wędkarzy poszukujących wyzwań i dużych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21812, 3, 2.8, 6.5, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Sum', 'Trudny, stromy i zalesiony', FALSE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21813, 'Starorzecze (Klucze)', 'starorzecze-klucze-klucze-21813', 'OXBOW', 51.6711479, 16.1477411, 'Dolnośląskie', 'Klucze', 'To starorzecze, położone w Kluczach, jest mniejsze i bardziej płytkie niż sąsiednie, ale równie atrakcyjne dla wędkarzy. Dno jest muliste, z licznymi skupiskami roślinności podwodnej, co sprzyja rozwojowi drobnego białorybu. Brzegi są miejscami zarośnięte, ale da się znaleźć dogodne stanowiska, zwłaszcza od strony pól uprawnych. Roślinność podwodna jest umiarkowana do silnej, tworząc schronienia dla ryb. W akwenie dominują płocie, wzdręgi, karasie pospolite oraz liny, a także mniejsze okonie. Wędkowanie spławikowe i gruntowe z lekkim zestawem to najlepsza taktyka, szczególnie w okresach wzmożonej aktywności ryb. To dobre miejsce na szybki wypad po białoryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21813, 0.9, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Płoć,Wzdręga,Karaś pospolity,Lin,Okoń', 'Częściowo dostępny, miejscami zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21814, 'Starorzecze (Bobrowniki)', 'starorzecze-bobrowniki-bobrowniki-21814', 'OXBOW', 51.8359375, 15.7533087, 'Lubuskie', 'Bobrowniki', 'To starorzecze w Bobrownikach jest przykładem akwenu o dużym znaczeniu ekologicznym, silnie zarośniętego i bogatego w faunę. Dno jest w większości muliste, z licznymi zatopionymi drzewami i krzewami, które stanowią schronienie dla wielu gatunków ryb. Brzegi są bardzo trudno dostępne, gęsto porośnięte trzciną, krzewami i drzewami, co wymaga od wędkarza determinacji i specjalistycznego sprzętu. Roślinność podwodna jest niezwykle bujna, tworząc gęste zarośla. W akwenie dominują liny, karasie pospolite, wzdręgi, a także duże szczupaki, które polują w ukryciu. Wędkowanie z pontonu lub brodzenie w woderach to praktycznie jedyne skuteczne metody. To łowisko dla wędkarzy poszukujących prawdziwie dzikiej przygody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21814, 4.8, 1.6, 3.3, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak,Okoń', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Dużo zatopionych drzew, gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21815, 'Starorzecze w Osieku Grodkowskim', 'starorzecze-w-osieku-grodkowskim-osiek-grodkowski-21815', 'OXBOW', 50.7121743, 17.5007674, 'Opolskie', 'Osiek Grodkowski', 'To malownicze starorzecze, zlokalizowane w pobliżu Osieku Grodkowskiego, charakteryzuje się typowym dla takich zbiorników mulistym dnem, które miejscami przechodzi w twardsze, piaszczyste podłoże. Brzegi są w większości zarośnięte bujną roślinnością, w tym trzciną i krzewami, co utrudnia dostęp do wody, choć istnieją nieliczne, wydeptane stanowiska wędkarskie. Roślinność podwodna jest umiarkowana, z przewagą rdestnic i grążeli, tworzących naturalne kryjówki dla ryb. W starorzeczu dominują gatunki takie jak szczupak, lin, karaś pospolity, płoć oraz okoń, które znajdują tu idealne warunki do bytowania. Wędkowanie wymaga często użycia wodery, zwłaszcza przy próbach dotarcia do mniej uczęszczanych miejsc. W okresach upałów istnieje ryzyko przyduchy, dlatego najlepsze efekty osiąga się wiosną i wczesną jesienią, kiedy woda jest lepiej natleniona.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21815, 4.5, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć,Okoń', 'Częściowo dostępny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21816, 'Starorzecze w Łojach', 'starorzecze-w-lojach-maciejowice-21816', 'OXBOW', 51.5533658, 21.7199019, 'Mazowieckie', 'Maciejowice', 'To niewielkie starorzecze w pobliżu Łojów, charakteryzuje się bardzo mulistym dnem i silnym zarastaniem, co czyni je trudnym, lecz potencjalnie bardzo atrakcyjnym łowiskiem. Brzegi są bagniste i gęsto porośnięte trzciną oraz inną roślinnością szuwarową, co wymaga użycia woderów i cierpliwości w poszukiwaniu dogodnych miejsc. Roślinność podwodna jest niezwykle bujna, tworząc liczne schronienia dla ryb, ale jednocześnie utrudniając prowadzenie przynęty. W zbiorniku tym dominują gatunki takie jak lin, karaś pospolity, wzdręga i płoć, które doskonale radzą sobie w płytkich i zarośniętych wodach. Ze względu na brak stałego połączenia z rzeką i niewielką głębokość, starorzecze jest narażone na wysychanie w upalne lata i wysokie ryzyko przyduchy. Najlepsze efekty wędkarskie można osiągnąć późną wiosną i latem, koncentrując się na miejscach z wolną wodą wśród zarośli.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21816, 2.8, 1.5, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21817, 'Starorzecze w Przewozie', 'starorzecze-w-przewozie-maciejowice-21817', 'OXBOW', 51.5561161, 21.7457247, 'Mazowieckie', 'Maciejowice', 'To rozległe starorzecze w Przewozie oferuje doskonałe warunki do wędkowania przez cały sezon, dzięki stosunkowo czystemu dnu i dobremu dostępowi do brzegów. Dno jest głównie muliste, ale w wielu miejscach twardsze, co sprzyja różnorodności gatunków ryb. Brzegi są w większości łatwo dostępne, z nielicznymi zaroślami trzcinowymi, co ułatwia swobodne poruszanie się wzdłuż akwenu. Roślinność podwodna jest umiarkowana, skupiając się w płytszych zatokach, co tworzy idealne kryjówki dla drapieżników. W starorzeczu licznie występują szczupaki, leszcze, okonie, płocie, a także karpie, które stanowią atrakcyjny cel dla wędkarzy. Dzięki okresowemu połączeniu z rzeką podczas wysokiej wody, zbiornik jest regularnie zasilany w świeżą wodę i nowe populacje ryb. Jest to łowisko, które nie wymaga użycia woderów i jest polecane dla wędkarzy szukających komfortowych warunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21817, 6, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Płoć,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21818, 'Starorzecze w Kępicach (północne)', 'starorzecze-w-kepicach-polnocne-maciejowice-21818', 'OXBOW', 51.5513835, 21.7632425, 'Mazowieckie', 'Maciejowice', 'To niewielkie i płytkie starorzecze w Kępicach jest typowym przykładem zbiornika o wysokim stopniu zamulenia i silnego zarastania. Dno jest niemal w całości pokryte grubą warstwą mułu, co sprzyja rozwojowi bujnej roślinności wodnej, takiej jak lilie wodne i moczarka. Brzegi są wyjątkowo trudne do pokonania, gęsto porośnięte wysokimi trzcinami i krzewami, co wymaga użycia woderów i często maczety, aby dotrzeć do wody. Wędkowanie tutaj to prawdziwe wyzwanie, ale nagrodą mogą być piękne okazy karasia pospolitego, lina oraz wzdręgi, które doskonale czują się w tych specyficznych warunkach. Ze względu na brak połączenia z rzeką i niewielką głębokość, zbiornik jest bardzo wrażliwy na susze i wysokie temperatury, co zwiększa ryzyko przyduchy i wysychania. Najlepszym okresem na wędkowanie jest późna wiosna, kiedy ryby są aktywne, a roślinność nie osiągnęła jeszcze szczytu swojego rozwoju.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21818, 1.2, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21819, 'Starorzecze w Kępicach (południowe)', 'starorzecze-w-kepicach-poludniowe-maciejowice-21819', 'OXBOW', 51.5518449, 21.7626714, 'Mazowieckie', 'Maciejowice', 'To małe starorzecze, położone nieco na południe od poprzedniego w Kępicach, dzieli podobne cechy, będąc płytkim i silnie zarośniętym akwenem. Dno jest w przeważającej części muliste, a obfitość detrytusu sprzyja rozwojowi gęstej roślinności podwodnej i szuwarowej. Brzegi są niezwykle trudne do podejścia, często bagniste i gęsto porośnięte trzciną, co wymaga od wędkarza determinacji i odpowiedniego sprzętu, takiego jak wodery. W zbiorniku tym królują ryby odporne na trudne warunki, takie jak karaś pospolity, lin i wzdręga, które znajdują tu doskonałe warunki do żerowania i rozmnażania. Brak połączenia z rzeką sprawia, że woda jest tu często cieplejsza, ale jednocześnie bardziej podatna na niedobory tlenu w upalne dni i ryzyko wysychania. Najlepsze wyniki osiąga się w okresie późnej wiosny, kiedy ryby są aktywne, a presja wędkarska jest niższa ze względu na trudny dostęp.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21819, 0.9, 0.9, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21820, 'Starorzecze w Prażmowie', 'starorzecze-w-prazmowie-maciejowice-21820', 'OXBOW', 51.5732333, 21.6967351, 'Mazowieckie', 'Maciejowice', 'Starorzecze w Prażmowie to średniej wielkości zbiornik, który dzięki okresowemu połączeniu z rzeką utrzymuje stosunkowo dobrą jakość wody, choć muliste dno jest typowe dla tego typu akwenów. Brzegi są zróżnicowane – w niektórych miejscach łatwo dostępne, w innych gęsto zarośnięte trzciną i krzewami, co wymaga od wędkarzy poszukiwania dogodnych stanowisk. Roślinność podwodna jest umiarkowana, tworząc naturalne struktury i kryjówki dla ryb, szczególnie w płytszych partiach i zatokach. Wśród dominujących gatunków ryb znajdziemy szczupaka, lina, płoć, leszcza oraz okonia, co czyni to łowisko atrakcyjnym dla różnych technik wędkarskich. Wędkowanie w zarośniętych zatokach często wymaga użycia woderów, aby skutecznie obłowić obiecujące miejsca. Mimo okresowego połączenia, w upalne lata istnieje ryzyko niedoborów tlenu, dlatego najlepsze wyniki osiąga się wiosną i jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21820, 3.5, 1.7, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Płoć,Leszcz,Okoń', 'Częściowo dostępny, zarośnięty w zatokach', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21821, 'Starorzecze w Brzeźcach', 'starorzecze-w-brzezcach-maciejowice-21821', 'OXBOW', 51.5713464, 21.7032181, 'Mazowieckie', 'Maciejowice', 'To niewielkie starorzecze w Brzeźcach stanowi typowy przykład płytkiego i silnie zarośniętego zbiornika, gdzie dominują warunki sprzyjające gatunkom odpornym na niedobory tlenu. Dno jest w przeważającej części muliste, z grubą warstwą osadów, co jest idealnym podłożem dla bujnej roślinności wodnej. Brzegi są mocno zarośnięte trzciną i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga użycia woderów. W starorzeczu tym licznie występują lin, karaś srebrzysty, płoć i wzdręga, które doskonale odnajdują się w gęstych zaroślach i płytkiej wodzie. Brak połączenia z rzeką oraz niewielka głębokość czynią ten akwen szczególnie wrażliwym na letnie upały, co zwiększa ryzyko przyduchy i okresowego wysychania. Najlepsze efekty wędkarskie można osiągnąć późną wiosną i latem, skupiając się na niewielkich prześwitach w roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21821, 1.8, 1.3, 2.9, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś srebrzysty,Płoć,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21822, 'Starorzecze w Maciejowicach (Staszów północne)', 'starorzecze-w-maciejowicach-staszow-polnocne-maciejowice-21822', 'OXBOW', 51.5661633, 21.6809946, 'Mazowieckie', 'Maciejowice', 'To stosunkowo duże starorzecze w okolicach Maciejowic, charakteryzuje się dobrą jakością wody i niewielkim zamuleniem, co sprzyja różnorodności gatunków ryb. Dno jest w większości twarde, z domieszką piasku i żwiru, co jest nietypowe dla starorzeczy i świadczy o silniejszym prądzie podczas połączeń z rzeką. Brzegi są łatwo dostępne z obu stron, z nielicznymi zaroślami, co umożliwia komfortowe wędkowanie. Roślinność podwodna jest umiarkowana, skupiająca się głównie w płytszych zatokach, tworząc naturalne schronienia dla ryb. W starorzeczu licznie występują szczupaki, leszcze, płocie, okonie, a także bolenie, które cenią sobie czystszą wodę. Dzięki regularnym połączeniom z rzeką podczas wysokiej wody, zbiornik jest dobrze natleniony i nie grozi mu przyducha ani wysychanie. Jest to idealne łowisko dla wędkarzy ceniących sobie komfort i różnorodność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21822, 5, 2.2, 5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21823, 'Starorzecze w Maciejowicach (Staszów środkowe)', 'starorzecze-w-maciejowicach-staszow-srodkowe-maciejowice-21823', 'OXBOW', 51.5641857, 21.683555, 'Mazowieckie', 'Maciejowice', 'To starorzecze, zlokalizowane w środkowej części kompleksu akwenów koło Maciejowic, charakteryzuje się mulistym dnem i umiarkowanym zarastaniem, typowym dla zbiorników bez stałego połączenia z rzeką. Brzegi są częściowo dostępne, choć w wielu miejscach porasta je gęsta trzcina i krzewy, co wymaga od wędkarzy poszukiwania wygodnych stanowisk lub użycia woderów. Roślinność podwodna, w tym grążele i rdestnice, tworzy cenne kryjówki dla ryb i miejsca żerowania. W zbiorniku dominują lin, karaś pospolity, płoć oraz okoń, które doskonale adaptują się do warunków starorzecza. Ze względu na brak stałego przepływu, w okresie letnich upałów istnieje ryzyko niedoborów tlenu, co może wpływać na aktywność ryb. Najlepsze efekty wędkarskie osiąga się wiosną i wczesnym latem, kiedy ryby są najbardziej aktywne, a warunki tlenowe są stabilne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21823, 3, 1.6, 3.5, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Okoń', 'Częściowo dostępny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21824, 'Starorzecze w Maciejowicach (Staszów południowe)', 'starorzecze-w-maciejowicach-staszow-poludniowe-maciejowice-21824', 'OXBOW', 51.5625452, 21.6863214, 'Mazowieckie', 'Maciejowice', 'To niewielkie starorzecze w południowej części kompleksu Maciejowic jest płytkim i silnie zarośniętym akwenem, idealnym dla gatunków ryb odpornych na trudne warunki. Dno jest w przeważającej części pokryte grubą warstwą mułu, co sprzyja rozwojowi bujnej roślinności wodnej, takiej jak lilie wodne i moczarka. Brzegi są wyjątkowo trudne do pokonania, często bagniste i gęsto porośnięte wysokimi trzcinami i krzewami, co wymaga użycia woderów. Wędkowanie tutaj to prawdziwe wyzwanie, ale nagrodą mogą być piękne okazy karasia pospolitego, lina oraz wzdręgi, które doskonale czują się w tych specyficznych warunkach. Ze względu na brak połączenia z rzeką i niewielką głębokość, zbiornik jest bardzo wrażliwy na susze i wysokie temperatury, co zwiększa ryzyko przyduchy i wysychania. Najlepszym okresem na wędkowanie jest późna wiosna, kiedy ryby są aktywne, a roślinność nie osiągnęła jeszcze szczytu swojego rozwoju.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21824, 2.5, 1.4, 3, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21825, 'Starorzecze w Maciejowicach (północno-zachodnie 1)', 'starorzecze-w-maciejowicach-polnocno-zachodnie-1-maciejowice-21825', 'OXBOW', 51.571326, 21.6668134, 'Mazowieckie', 'Maciejowice', 'To średniej wielkości starorzecze w północno-zachodniej części kompleksu Maciejowic, charakteryzujące się mulistym dnem z miejscowymi twardszymi partiami. Brzegi są w większości dostępne, choć miejscami mogą być porośnięte trzciną, co wymaga krótkiego spaceru wzdłuż linii brzegowej. Roślinność podwodna jest umiarkowana, tworząc naturalne schronienia dla ryb, szczególnie w płytszych zatokach. W zbiorniku tym licznie występują szczupaki, leszcze, płocie, okonie, a także karpie, co czyni go atrakcyjnym dla wędkarzy preferujących różne metody. Dzięki okresowemu połączeniu z rzeką podczas wysokiej wody, zbiornik jest regularnie zasilany w świeżą wodę i nowe populacje ryb. Niskie ryzyko wysychania i przyduchy sprawia, że jest to łowisko stabilne przez większość sezonu. Wędkowanie tutaj jest komfortowe i nie wymaga użycia woderów, co jest dodatkowym atutem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21825, 4, 1.9, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Karp', 'Dobry z niektórych stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21826, 'Starorzecze w Maciejowicach (północno-zachodnie 2)', 'starorzecze-w-maciejowicach-polnocno-zachodnie-2-maciejowice-21826', 'OXBOW', 51.5734821, 21.6681975, 'Mazowieckie', 'Maciejowice', 'To jedno z największych i najgłębszych starorzeczy w rejonie Maciejowic, charakteryzujące się stałym połączeniem z rzeką, co zapewnia doskonałą jakość wody i bogactwo rybostanu. Dno jest w przeważającej części twarde, z niewielką ilością mułu, co świadczy o regularnym przepływie wody i sprzyja występowaniu drapieżników. Brzegi są łatwo dostępne z obu stron, z minimalnym zarastaniem, co umożliwia swobodne poruszanie się i wybór dogodnych stanowisk. Roślinność podwodna jest słaba, co ułatwia prowadzenie przynęt i ogranicza zaczepy. W starorzeczu dominują szczupaki, sandacze, leszcze, płocie i bolenie, co czyni je idealnym miejscem dla wędkarzy spinningowych i gruntowych. Dzięki stałemu połączeniu z rzeką, zbiornik jest dobrze natleniony przez cały rok, eliminując ryzyko przyduchy i wysychania. Jest to łowisko o dużym potencjale, dostępne dla każdego wędkarza.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21826, 5.5, 2.5, 5.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21827, 'Starorzecze w Maciejowicach (północno-zachodnie 3)', 'starorzecze-w-maciejowicach-polnocno-zachodnie-3-maciejowice-21827', 'OXBOW', 51.5728749, 21.6697294, 'Mazowieckie', 'Maciejowice', 'To starorzecze, położone w północno-zachodniej części kompleksu Maciejowic, charakteryzuje się mulistym dnem i umiarkowanym zarastaniem, typowym dla zbiorników okresowo połączonych z rzeką. Brzegi są częściowo dostępne, choć w wielu miejscach porasta je gęsta trzcina i krzewy, co wymaga od wędkarzy poszukiwania wygodnych stanowisk lub użycia woderów. Roślinność podwodna, w tym grążele i rdestnice, tworzy cenne kryjówki dla ryb i miejsca żerowania. W zbiorniku dominują lin, karaś pospolity, płoć oraz okoń, które doskonale adaptują się do warunków starorzecza. Ze względu na brak stałego przepływu, w okresie letnich upałów istnieje ryzyko niedoborów tlenu, co może wpływać na aktywność ryb. Najlepsze efekty wędkarskie osiąga się wiosną i wczesnym latem, kiedy ryby są najbardziej aktywne, a warunki tlenowe są stabilne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21827, 3.2, 1.5, 3.3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Okoń', 'Częściowo dostępny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21828, 'Starorzecze w Maciejowicach (środkowo-zachodnie 1)', 'starorzecze-w-maciejowicach-srodkowo-zachodnie-1-maciejowice-21828', 'OXBOW', 51.5699893, 21.6726591, 'Mazowieckie', 'Maciejowice', 'To niewielkie starorzecze w środkowo-zachodniej części kompleksu Maciejowic jest płytkim i silnie zarośniętym akwenem, idealnym dla gatunków ryb odpornych na trudne warunki. Dno jest w przeważającej części pokryte grubą warstwą mułu, co sprzyja rozwojowi bujnej roślinności wodnej, takiej jak lilie wodne i moczarka. Brzegi są wyjątkowo trudne do pokonania, często bagniste i gęsto porośnięte wysokimi trzcinami i krzewami, co wymaga użycia woderów. Wędkowanie tutaj to prawdziwe wyzwanie, ale nagrodą mogą być piękne okazy karasia pospolitego, lina oraz wzdręgi, które doskonale czują się w tych specyficznych warunkach. Ze względu na brak połączenia z rzeką i niewielką głębokość, zbiornik jest bardzo wrażliwy na susze i wysokie temperatury, co zwiększa ryzyko przyduchy i wysychania. Najlepszym okresem na wędkowanie jest późna wiosna, kiedy ryby są aktywne, a roślinność nie osiągnęła jeszcze szczytu swojego rozwoju.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21828, 2, 1.2, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21829, 'Starorzecze w Maciejowicach (środkowo-zachodnie 2)', 'starorzecze-w-maciejowicach-srodkowo-zachodnie-2-maciejowice-21829', 'OXBOW', 51.5712524, 21.6713602, 'Mazowieckie', 'Maciejowice', 'To średniej wielkości starorzecze w środkowo-zachodniej części kompleksu Maciejowic, charakteryzujące się mulistym dnem z miejscowymi twardszymi partiami. Brzegi są w większości dostępne, choć miejscami mogą być porośnięte trzciną, co wymaga krótkiego spaceru wzdłuż linii brzegowej. Roślinność podwodna jest umiarkowana, tworząc naturalne schronienia dla ryb, szczególnie w płytszych zatokach. W zbiorniku tym licznie występują szczupaki, leszcze, płocie, okonie, a także karpie, co czyni go atrakcyjnym dla wędkarzy preferujących różne metody. Dzięki okresowemu połączeniu z rzeką podczas wysokiej wody, zbiornik jest regularnie zasilany w świeżą wodę i nowe populacje ryb. Niskie ryzyko wysychania i przyduchy sprawia, że jest to łowisko stabilne przez większość sezonu. Wędkowanie tutaj jest komfortowe i nie wymaga użycia woderów, co jest dodatkowym atutem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21829, 2.7, 1.4, 3.1, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Płoć,Okoń', 'Częściowo dostępny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21830, 'Starorzecze (Kępice) - zachodnie', 'starorzecze-kepice-zachodnie-kepice-21830', 'OXBOW', 51.5513327, 21.765833, 'Lubelskie', 'Kępice', 'To płytkie starorzecze charakteryzuje się silnym zarastaniem i mulistym dnem, co sprzyja rozwojowi bogatej roślinności wodnej. Brzegi są gęsto porośnięte trzciną i inną roślinnością przybrzeżną, utrudniając dostęp do wody. Wędkowanie jest tutaj wyzwaniem, ale nagradza obfitością ryb spokojnego żeru, takich jak lin i karaś pospolity. Występują tu również płocie i wzdręgi, a w zaroślach często czai się szczupak. Ze względu na płytkość i gęste zarośla, ryzyko przyduchy tlenowej w upalne lata jest wysokie. Dostęp do łowiska jest trudny i wymaga brodzenia, dlatego wodery są niezbędne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21830, 3.2, 1, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21831, 'Starorzecze (Kępice) - centralne', 'starorzecze-kepice-centralne-kepice-21831', 'OXBOW', 51.5505943, 21.7697977, 'Lubelskie', 'Kępice', 'To starorzecze jest nieco głębsze i bardziej otwarte niż jego zachodni sąsiad, oferując lepsze warunki do wędkowania. Dno jest zróżnicowane, z miejscami mulistymi i piaszczystymi, a brzegi są częściowo dostępne, choć miejscami występują gęste zarośla. Jest to doskonałe miejsce dla wędkarzy poszukujących leszczy, płoci oraz okoni. W gęstszych partiach roślinności można spotkać również szczupaki, które aktywnie polują. Połączenie z rzeką podczas wysokiej wody sprzyja odświeżaniu populacji ryb. Dostęp jest dobry z jednej strony, co ułatwia rozstawienie sprzętu i komfortowe wędkowanie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21831, 4.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń', 'Dobry z jednej strony, druga zarośnięta', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21832, 'Starorzecze (Kępice) - wschodnie', 'starorzecze-kepice-wschodnie-kepice-21832', 'OXBOW', 51.5495898, 21.7750025, 'Lubelskie', 'Kępice', 'Starorzecze to jest przykładem klasycznego łowiska, z urozmaiconymi głębokościami i bogatą strukturą dna. Charakteryzuje się niskim poziomem zamulenia i umiarkowanym zarastaniem, co sprzyja różnorodności gatunków ryb. Brzegi są dostępne w wielu miejscach, z naturalnymi przesmykami i stanowiskami wędkarskimi. Jest to raj dla wędkarzy poszukujących szczupaków, leszczy, płoci, linów i okoni, które znajdują tu idealne warunki do życia. Okresowe połączenia z rzeką zapewniają stałe zasilanie w świeżą wodę i migrację ryb. Łowisko jest stosunkowo łatwe w dostępie, a wodery nie są zazwyczaj potrzebne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21832, 5.1, 1.8, 3.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Lin,Okoń', 'Dobry z obu stron w wyznaczonych miejscach', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21833, 'Starorzecze (Kępice) - długie', 'starorzecze-kepice-dlugie-kepice-21833', 'OXBOW', 51.5484604, 21.7769711, 'Lubelskie', 'Kępice', 'To wydłużone starorzecze, charakteryzujące się zmienną szerokością i zróżnicowanymi głębokościami, oferuje wiele interesujących miejsc do wędkowania. Dno jest głównie muliste, z twardymi fragmentami w niektórych partiach, a brzegi są miejscami dostępne, a miejscami silnie zarośnięte. Występuje tu bogata populacja leszczy, płoci i linów, a także liczne szczupaki, które wykorzystują zatopione drzewa jako kryjówki. Wędkowanie może być utrudnione przez liczne zaczepy, zwłaszcza na końcach zbiornika. Dostęp do wody jest zróżnicowany, dlatego wodery mogą okazać się przydatne do eksploracji mniej dostępnych zakamarków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21833, 6, 1.6, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Lin,Szczupak', 'Miejscami dobry, miejscami zarośnięty', TRUE, 'Dużo zatopionych drzew na końcach', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21834, 'Starorzecze (Kępice) - południowe', 'starorzecze-kepice-poludniowe-kepice-21834', 'OXBOW', 51.5472496, 21.7770437, 'Lubelskie', 'Kępice', 'To starorzecze, będące częścią kompleksu Kępickiego, wyróżnia się znacznym zamuleniem i silnym zarastaniem. Płytkie partie zbiornika są gęsto porośnięte roślinnością podwodną, tworząc idealne schronienia dla drobnych ryb. Brzegi są trudne do pokonania, często bagniste i gęsto zarośnięte, co wymaga od wędkarzy użycia woderów. Dominują tu gatunki takie jak karaś pospolity, lin, wzdręga i płoć, które doskonale radzą sobie w takich warunkach. Wysokie ryzyko przyduchy tlenowej w okresie letnim jest wyzwaniem dla ekosystemu. Mimo trudności, łowisko oferuje unikalne doświadczenia dla cierpliwych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21834, 2.8, 1.3, 2.8, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna i muł', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21835, 'Starorzecze (Kępice) - odizolowane', 'starorzecze-kepice-odizolowane-kepice-21835', 'OXBOW', 51.5472398, 21.7784724, 'Lubelskie', 'Kępice', 'To niewielkie, bardzo odizolowane starorzecze stanowi dziki i trudnodostępny akwen. Charakteryzuje się bardzo wysokim poziomem zamulenia oraz silnym zarastaniem, co sprawia, że jest to środowisko idealne dla najbardziej odpornych gatunków ryb. Brzegi są niezwykle trudne do pokonania, gęsto porośnięte krzewami i drzewami, wymagającymi przedzierania się. Występuje tu głównie karaś pospolity, lin i wzdręga, które doskonale radzą sobie w płytkiej, bogatej w roślinność wodzie. Niestety, w okresach długotrwałej suszy zbiornik potrafi całkowicie wyschnąć. Wędkarstwo w tym miejscu to prawdziwa przygoda, wymagająca pełnego zaangażowania i specjalistycznego sprzętu, w tym woderów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21835, 1.5, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Bardzo trudny, gęste zarośla', TRUE, 'Gęsta roślinność podwodna i zatopione gałęzie', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21836, 'Starorzecze (Nagórnik) - północne', 'starorzecze-nagornik-polnocne-nagornik-21836', 'OXBOW', 51.5395632, 21.7890693, 'Lubelskie', 'Nagórnik', 'To duże starorzecze w pobliżu Nagórnika jest znane z dużej stabilności i zróżnicowanej populacji ryb. Charakteryzuje się niskim poziomem zamulenia i umiarkowanym zarastaniem, co sprzyja rozwojowi ekosystemu. Brzegi są dobrze dostępne w wielu miejscach, z wydeptanymi ścieżkami wędkarskimi, co ułatwia dotarcie do wody. Jest to idealne miejsce dla wędkarzy poszukujących leszczy, płoci, okoni, szczupaków, a nawet sandaczy. Okresowe połączenia z rzeką podczas wysokiej wody zapewniają odświeżenie wód i wzbogacenie ichtiofauny. Łowisko jest popularne i oferuje komfortowe warunki do wędkowania przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21836, 8, 2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Sandacz', 'Dobry z wielu miejsc, ścieżki wędkarskie', FALSE, 'Pojedyncze zatopione drzewa', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21837, 'Starorzecze (Opactwo)', 'starorzecze-opactwo-opactwo-21837', 'OXBOW', 51.5355735, 21.7774425, 'Lubelskie', 'Opactwo', 'To średniej wielkości starorzecze w okolicach Opactwa, charakteryzujące się nieco większą głębokością i czystym dnem w większości partii. Umiarkowane zamulenie i zarastanie sprawiają, że jest to atrakcyjne miejsce zarówno dla drapieżników, jak i ryb spokojnego żeru. Brzegi są dobrze dostępne z obu stron, co umożliwia swobodne przemieszczanie się wzdłuż łowiska. Występuje tu bogata populacja szczupaków i okoni, a także liczne leszcze i karpie, które znajdują tu odpowiednie warunki do rozwoju. Łowisko jest regularnie zasilane świeżą wodą podczas wyższych stanów rzeki. Brak konieczności użycia woderów czyni je komfortowym dla wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21837, 5.5, 1.7, 3.3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno w większości, zarośla na brzegach', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21838, 'Starorzecze (Kępice) - wschodnie odgałęzienie', 'starorzecze-kepice-wschodnie-odgalezienie-kepice-21838', 'OXBOW', 51.5454955, 21.7792801, 'Lubelskie', 'Kępice', 'To starorzecze stanowi odgałęzienie kompleksu Kępickiego, charakteryzujące się znacznym zarastaniem i mulistym dnem. Płytkie partie zbiornika są gęsto porośnięte roślinnością podwodną, tworząc idealne schronienia dla drobnych ryb. Brzegi są trudne do pokonania, mocno zarośnięte, co wymaga od wędkarzy użycia woderów. Dominują tu gatunki takie jak lin, karaś pospolity, płoć i wzdręga, które doskonale radzą sobie w takich warunkach. Wysokie ryzyko przyduchy tlenowej w okresie letnim jest wyzwaniem dla ekosystemu. Mimo trudności, łowisko oferuje unikalne doświadczenia dla cierpliwych wędkarzy, poszukujących dzikich miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21838, 3.8, 1.4, 2.9, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21839, 'Starorzecze (Głusiec) - zachodnie', 'starorzecze-glusiec-zachodnie-glusiec-21839', 'OXBOW', 51.5538973, 21.8155881, 'Lubelskie', 'Głusiec', 'To starorzecze położone dalej na wschód, charakteryzuje się znaczną izolacją od głównego nurtu rzeki i wysokim stopniem zamulenia. Jest to płytki akwen, silnie zarośnięty roślinnością wodną, co sprzyja rozwojowi specyficznych gatunków ryb. Brzegi są trudne do pokonania, bagniste i gęsto zarośnięte, co wymaga od wędkarzy użycia woderów. Dominują tu karaś pospolity, lin, wzdręga i płoć, które doskonale adaptują się do tych warunków. W okresach długotrwałych susz zbiornik może całkowicie wyschnąć, co stanowi poważne zagrożenie dla populacji ryb. Wędkowanie w tym miejscu to wyzwanie, ale może przynieść satysfakcję z łowienia w dzikim środowisku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21839, 4, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty, gęste zarośla', TRUE, 'Gęsta roślinność podwodna i muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21840, 'Starorzecze (Zajezierze)', 'starorzecze-zajezierze-zajezierze-21840', 'OXBOW', 51.5569491, 21.8249103, 'Mazowieckie', 'Zajezierze', 'To jedno z większych i głębszych starorzeczy w regionie, oferujące doskonałe warunki dla różnorodnych gatunków ryb. Charakteryzuje się niskim poziomem zamulenia i umiarkowanym zarastaniem, co sprzyja bogactwu ekosystemu. Brzegi są dobrze dostępne z wielu miejsc, a łowisko jest popularne wśród wędkarzy, oferując liczne stanowiska. Jest to raj dla drapieżników takich jak szczupak, sandacz i sum, ale także dla leszczy i płoci. Stałe lub bardzo częste połączenie z rzeką zapewnia ciągłe odświeżanie wody i migrację ryb. Łowisko jest dostępne przez cały sezon i nie wymaga użycia woderów, co czyni je bardzo komfortowym.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21840, 10, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Sum,Leszcz,Płoć', 'Dobry z wielu miejsc, popularne łowisko', FALSE, 'Pojedyncze zatopione drzewa, miejscami czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21841, 'Starorzecze (Głusiec) - północne', 'starorzecze-glusiec-polnocne-glusiec-21841', 'OXBOW', 51.5639192, 21.8028703, 'Lubelskie', 'Głusiec', 'To starorzecze o średniej wielkości, stanowiące typowy akwen tego typu, idealny do zróżnicowanego wędkowania. Charakteryzuje się umiarkowanym zamuleniem i zarastaniem, co tworzy dogodne warunki dla wielu gatunków ryb. Brzegi są częściowo dostępne, z wydeptanymi ścieżkami, choć w niektórych miejscach mogą być zarośnięte. Występuje tu obfitość leszczy, płoci i okoni, a także liczne szczupaki, które znajdują schronienie w podwodnej roślinności. Połączenie z rzeką podczas wysokiej wody zapewnia regularne zasilanie. Łowisko jest atrakcyjne przez większość sezonu, a dostęp do niego nie wymaga zazwyczaj specjalistycznego sprzętu, takiego jak wodery.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21841, 6.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak', 'Dobry w części, reszta zarośnięta', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21842, 'Starorzecze (Głusiec) - północno-zachodnie', 'starorzecze-glusiec-polnocno-zachodnie-glusiec-21842', 'OXBOW', 51.5641212, 21.8013137, 'Lubelskie', 'Głusiec', 'To starorzecze, będące częścią większego kompleksu w Głuscu, jest nieco płytsze i silniej zarośnięte niż sąsiednie akweny. Charakteryzuje się średnim zamuleniem i obfitą roślinnością podwodną, która tworzy schronienia dla ryb. Brzegi są trudne do pokonania, mocno zarośnięte trzciną, co wymaga od wędkarzy użycia woderów. Dominują tu gatunki takie jak lin, karaś pospolity, płoć i wzdręga, doskonale przystosowane do płytkich i zarośniętych wód. Ryzyko przyduchy tlenowej w upalne lata jest podwyższone ze względu na płytkość i gęste zarośla. Wędkowanie w tym miejscu wymaga cierpliwości i odpowiedniego sprzętu, ale oferuje satysfakcję z łowienia w dzikim środowisku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21842, 5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21843, 'Starorzecze (Głusiec) - wschodnie', 'starorzecze-glusiec-wschodnie-glusiec-21843', 'OXBOW', 51.5628074, 21.8079298, 'Lubelskie', 'Głusiec', 'To starorzecze, będące kolejnym elementem kompleksu w Głuscu, oferuje dobre warunki do eksploracji i zróżnicowanego wędkowania. Charakteryzuje się niskim poziomem zamulenia i umiarkowanym zarastaniem, co sprzyja rozwojowi bogatej ichtiofauny. Brzegi są dostępne z kilku miejsc, jednak w pozostałych partiach wymagają przedzierania się przez zarośla. Występuje tu obfitość szczupaków, leszczy, okoni i karpi, które znajdują tu dogodne warunki do życia. Okresowe połączenia z rzeką podczas wysokiej wody zapewniają odświeżenie wód i wzbogacenie populacji ryb. Łowisko jest atrakcyjne przez cały sezon, a dostęp do niego nie wymaga użycia woderów we wszystkich miejscach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21843, 7, 1.9, 3.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Karp', 'Dobry z kilku miejsc, reszta wymaga przedzierania', FALSE, 'Pojedyncze zatopione pnie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21844, 'Starorzecze (Nagórnik) - południowe', 'starorzecze-nagornik-poludniowe-nagornik-21844', 'OXBOW', 51.5351127, 21.7867362, 'Lubelskie', 'Nagórnik', 'Ta głębsza sekcja kompleksu starorzeczy w Nagórniku oferuje bardziej zróżnicowane możliwości wędkowania. Charakteryzuje się niskim poziomem zamulenia i umiarkowanym zarastaniem, co sprzyja rozwojowi dużych okazów ryb. Brzegi są dobrze dostępne, z łatwo osiągalnymi stanowiskami, co czyni to łowisko bardzo komfortowym. Jest to doskonałe miejsce dla wędkarzy poszukujących sumów, sandaczy, szczupaków, leszczy i karpi, które znajdują tu obfitość pokarmu. Połączenie z rzeką podczas wysokiej wody zapewnia stałe zasilanie w wodę i migrację ryb. Łowisko jest atrakcyjne przez cały sezon, a jego czyste dno minimalizuje ryzyko zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21844, 9.5, 2.2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Sandacz,Szczupak,Leszcz,Karp', 'Dobry, łatwo dostępne stanowiska', FALSE, 'Czyste dno, z nielicznymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21845, 'Starorzecze (Nagórnik)', 'starorzecze-nagornik-deblin-21845', 'OXBOW', 51.5379802, 21.7879067, 'Mazowieckie', 'Dęblin', 'To starorzecze, położone w pobliżu miejscowości Nagórnik, charakteryzuje się typowym dla tego typu zbiorników, bogatym ekosystemem. Dno jest muliste z licznymi zatopionymi korzeniami i gałęziami, co tworzy idealne kryjówki dla ryb. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je gęsta trzcina i inna roślinność wodna, utrudniając dostęp do wody. Wiosną i jesienią bywa połączone z Wisłą podczas wyższych stanów wody, co sprzyja migracji ryb. Zbiornik jest domem dla wielu gatunków, a jego umiarkowane zamulenie i silne zarastanie świadczą o naturalnym procesie sukcesji. Wędkarstwo tutaj wymaga cierpliwości i znajomości specyfiki płytkich, zarośniętych wód.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21845, 7.8, 1.5, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21846, 'Starorzecze (Borek)', 'starorzecze-borek-pulawy-21846', 'OXBOW', 51.5305485, 21.8182051, 'Lubelskie', 'Puławy', 'To starorzecze w okolicach Borku to klasyczny przykład zbiornika śródleśnego, charakteryzującego się spokojną i zaciszną atmosferą. Dno jest głównie piaszczysto-muliste, z licznymi miejscami porośniętymi liliami wodnymi i grążelami. Brzegi są miejscami bagniste i trudno dostępne, co sprzyja zachowaniu dzikiej przyrody. Zbiornik nie ma stałego połączenia z główną rzeką, co czyni go ostoją dla ryb preferujących wody stojące. Poziom zamulenia jest średni, a zarastanie umiarkowane, co pozwala na różnorodne metody wędkowania. Występuje tu bogata populacja karasi i linów, a także drapieżników. Wędkarze cenią sobie to miejsce za spokój i możliwość obcowania z naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21846, 4.2, 1.8, 4, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21847, 'Starorzecze (Borek)', 'starorzecze-borek-pulawy-21847', 'OXBOW', 51.5317292, 21.8192291, 'Lubelskie', 'Puławy', 'Jest to jedno z mniejszych starorzeczy w rejonie Borku, charakteryzujące się stosunkowo płytką wodą i intensywnym zarastaniem. Dno jest w większości muliste, z grubą warstwą osadów organicznych, co jest typowe dla zbiorników o słabym przepływie. Brzegi są gęsto porośnięte roślinnością szuwarową, co utrudnia dostęp, ale jednocześnie stanowi doskonałe schronienie dla ryb i ptactwa wodnego. Zbiornik jest odizolowany od Wisły, co sprzyja rozwojowi specyficznej ichtiofauny. Pomimo ryzyka niedoboru tlenu w upalne lata, populacje karasi i wzdręg są tu liczne. Wędkarstwo wymaga precyzji i umiejętności operowania w zarośniętych miejscach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21847, 2.1, 0.9, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21848, 'Starorzecze (Borek)', 'starorzecze-borek-pulawy-21848', 'OXBOW', 51.5321346, 21.819212, 'Lubelskie', 'Puławy', 'To starorzecze, zlokalizowane blisko poprzedniego, wyróżnia się nieco większą głębokością w centralnej części, co sprzyja większej różnorodności gatunkowej ryb. Dno jest zróżnicowane, od piaszczystych płycizn po muliste zagłębienia, z pojedynczymi zatopionymi pniami. Dostęp do brzegów jest umiarkowany, z kilkoma dogodnymi stanowiskami wędkarskimi, ale większość linii brzegowej jest gęsto zarośnięta. Zbiornik nie ma bezpośredniego połączenia z rzeką, co zapewnia stabilne warunki wodne. Umiarkowane zamulenie i zarastanie tworzą dobre warunki dla ryb spokojnego żeru oraz drapieżników. Jest to popularne miejsce dla wędkarzy szukających karpi i leszczy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21848, 3.5, 1.4, 3.8, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Leszcz,Okoń,Płoć', 'Dobry z kilku stanowisk', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21849, 'Starorzecze (Borek)', 'starorzecze-borek-pulawy-21849', 'OXBOW', 51.5318471, 21.8128211, 'Lubelskie', 'Puławy', 'To starorzecze, położone w malowniczym otoczeniu, jest jednym z bardziej dostępnych łowisk w regionie Borek. Charakteryzuje się stosunkowo czystym dnem w części centralnej, choć przy brzegach dominują osady muliste i roślinność. Brzegi są w większości dobrze dostępne, z licznymi naturalnymi przesmykami między trzcinami, co ułatwia wędkowanie z brzegu. Zbiornik jest sporadycznie zasilany wodą z Wisły podczas bardzo wysokich stanów, co sprzyja odświeżaniu wody. Poziom zamulenia jest niski, a zarastanie umiarkowane, co czyni go atrakcyjnym dla wielu gatunków. Jest to doskonałe miejsce na połów płoci i leszczy, a także okazjonalnie szczupaków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21849, 5.1, 1.7, 4.5, 'Podczas bardzo wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21850, 'Starorzecze (Nagórnik)', 'starorzecze-nagornik-deblin-21850', 'OXBOW', 51.5303969, 21.7943572, 'Mazowieckie', 'Dęblin', 'To starorzecze w pobliżu Nagórnika jest znane z dużej populacji linów i karasi, które znajdują tu idealne warunki do życia. Dno jest gęsto pokryte mułem i resztkami roślinnymi, co sprzyja rozwojowi bogatej flory podwodnej. Brzegi są miejscami podmokłe i zarośnięte, co utrudnia swobodny dostęp, ale jednocześnie chroni zbiornik przed nadmierną presją wędkarską. Zbiornik jest całkowicie odcięty od Wisły, co sprawia, że jego ekosystem jest bardzo stabilny, choć narażony na niedobory tlenu latem. Wysoki poziom zamulenia i silne zarastanie to jego cechy charakterystyczne. Wędkarze poszukujący okazowych linów znajdą tu swoje miejsce.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21850, 6.3, 1.3, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21851, 'Starorzecze (Zajezierze)', 'starorzecze-zajezierze-deblin-21851', 'OXBOW', 51.5495554, 21.8254796, 'Lubelskie', 'Dęblin', 'Starorzecze w Zajezierzu to rozległy zbiornik, który zachował silne połączenie z Wisłą, szczególnie podczas wyższych stanów wody. Dno jest zróżnicowane, od piaszczystych płycizn po głębsze rynny z mulistym osadem, co sprzyja różnorodności gatunkowej ryb. Brzegi są w większości stabilne i dostępne, choć miejscami występują zarośla trzcinowe i krzewy. Dzięki regularnemu połączeniu z rzeką, zbiornik jest dobrze natleniony, a ryzyko przyduchy jest niskie. Niskie zamulenie i umiarkowane zarastanie sprawiają, że jest to atrakcyjne łowisko dla wielu wędkarzy. Można tu spotkać zarówno ryby typowe dla wód stojących, jak i te migrujące z rzeki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21851, 12.5, 2.2, 5.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Sandacz,Jaź', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21852, 'Starorzecze (Zajezierze)', 'starorzecze-zajezierze-deblin-21852', 'OXBOW', 51.5389265, 21.8216312, 'Lubelskie', 'Dęblin', 'To starorzecze, położone również w rejonie Zajezierza, charakteryzuje się bardziej odizolowanym charakterem niż jego większy sąsiad. Dno jest głównie muliste, z licznymi zatopionymi drzewami i gałęziami, które stanowią doskonałe kryjówki dla drapieżników. Brzegi są trudno dostępne, gęsto zarośnięte krzewami i drzewami, co dodaje miejscu dzikiego uroku. Brak stałego połączenia z rzeką sprawia, że woda jest tu spokojna i ciepła, co sprzyja rozwojowi bujnej roślinności. Wysokie zamulenie i silne zarastanie to wyzwanie dla wędkarzy, ale jednocześnie gwarancja obecności dużych szczupaków i sumów. Wymaga to specjalistycznego sprzętu i technik.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21852, 8.9, 2, 4.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Szczupak,Sum,Lin,Okoń', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21853, 'Starorzecze (gmina Lidzbark Warmiński)', 'starorzecze-gmina-lidzbark-warminski-lidzbark-warminski-21853', 'OXBOW', 54.0934256, 20.4385262, 'Warmińsko-Mazurskie', 'Lidzbark Warmiński', 'To malownicze starorzecze, zlokalizowane w gminie Lidzbark Warmiński, jest przykładem zbiornika o charakterze bardziej jeziornym, typowym dla pojezierzy. Dno jest zróżnicowane, z fragmentami piaszczystymi, żwirowymi oraz mulistymi, co sprzyja różnorodności siedlisk. Brzegi są częściowo zagospodarowane, z kilkoma dogodnymi pomostami i miejscami do wędkowania, ale są też odcinki dzikie, porośnięte trzciną. Zbiornik posiada słabe połączenie z lokalną rzeką, co zapewnia delikatny przepływ wody. Niskie zamulenie i umiarkowane zarastanie sprawiają, że woda jest czysta i bogata w tlen. Jest to doskonałe miejsce na połów leszczy, płoci, a także drapieżników takich jak szczupak i sandacz.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21853, 15, 2.5, 7, 'Słabe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Sandacz,Okoń', 'Dobry z kilku pomostów', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21854, 'Starorzecze (Wólka Wojcieszkowska)', 'starorzecze-wolka-wojcieszkowska-pulawy-21854', 'OXBOW', 51.5310676, 21.8087802, 'Lubelskie', 'Puławy', 'Starorzecze w Wólce Wojcieszkowskiej to typowy zbiornik śródleśny, charakteryzujący się dużą ilością zwalonych drzew i podwodnych przeszkód. Dno jest głęboko muliste, z grubą warstwą osadów organicznych, co jest idealne dla ryb żerujących w mule. Brzegi są w większości trudno dostępne, gęsto zarośnięte olchami i wierzbami, które tworzą naturalne zadaszenie nad wodą. Zbiornik jest odizolowany od głównego nurtu rzeki, co sprzyja rozwojowi specyficznego ekosystemu. Wysokie zamulenie i silne zarastanie to jego dominujące cechy. Jest to raj dla wędkarzy poszukujących dużych linów i karasi, a także ostoi dla sumów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21854, 9.5, 1.6, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Sum,Szczupak', 'Trudny, mocno zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21855, 'Starorzecze (Wólka Wojcieszkowska)', 'starorzecze-wolka-wojcieszkowska-pulawy-21855', 'OXBOW', 51.5201818, 21.8045968, 'Lubelskie', 'Puławy', 'To starorzecze w pobliżu Wólki Wojcieszkowskiej jest mniejszym, ale bardzo urokliwym zbiornikiem, idealnym dla wędkarzy ceniących ciszę i spokój. Dno jest w większości muliste, ale z miejscowymi przejaśnieniami piaszczystymi, szczególnie w płytszych partiach. Brzegi są miejscami dostępne, ale w wielu odcinkach mocno zarośnięte trzciną i krzewami. Zbiornik nie ma stałego połączenia z rzeką, co sprzyja rozwojowi stabilnej populacji ryb spokojnego żeru. Umiarkowane zamulenie i zarastanie tworzą dobre warunki dla płoci, wzdręg i okoni. Jest to również dobre miejsce na połów karasia pospolitego.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21855, 3, 1.1, 2.7, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Wzdręga,Karaś pospolity,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21856, 'Starorzecze (Wólka Wojcieszkowska)', 'starorzecze-wolka-wojcieszkowska-pulawy-21856', 'OXBOW', 51.5188815, 21.8069322, 'Lubelskie', 'Puławy', 'To starorzecze, sąsiadujące z poprzednim, wyróżnia się nieco większą powierzchnią i bardziej zróżnicowaną linią brzegową. Dno jest muliste, z licznymi zatopionymi gałęziami i trawami, co stanowi doskonałe schronienie dla mniejszych ryb. Brzegi są miejscami dostępne, ale większość wymaga przedzierania się przez gęste zarośla. Zbiornik jest odcięty od głównego nurtu, co sprzyja stabilizacji warunków wodnych. Średnie zamulenie i silne zarastanie to typowe cechy tego łowiska. Występuje tu bogata populacja płoci, leszczy i karasi, a także szczupaków. Wędkarstwo wymaga użycia spławika lub lekkiego gruntu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21856, 5.5, 1.5, 3, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Płoć,Leszcz,Karaś pospolity,Szczupak', 'Trudny, mocno zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21857, 'Starorzecze (Borek)', 'starorzecze-borek-pulawy-21857', 'OXBOW', 51.5249829, 21.8156592, 'Lubelskie', 'Puławy', 'To starorzecze w Borku jest jednym z bardziej uregulowanych, z częściowo umocnionymi brzegami w niektórych miejscach. Dno jest twarde, piaszczysto-żwirowe w centralnej części, z mulistymi zagłębieniami przy brzegach. Dostęp do brzegów jest stosunkowo dobry, z kilkoma otwartymi przestrzeniami, co ułatwia wędkowanie. Zbiornik ma sporadyczne połączenie z Wisłą, co sprzyja odświeżaniu wody i migracji ryb. Niskie zamulenie i słabe zarastanie sprawiają, że woda jest przejrzysta, a ryzyko niedoboru tlenu minimalne. Jest to doskonałe miejsce na połów leszczy, płoci, a także drapieżników takich jak sandacz i okoń.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21857, 7, 2, 5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21858, 'Starorzecze (Zajezierze)', 'starorzecze-zajezierze-deblin-21858', 'OXBOW', 51.5471728, 21.8056231, 'Lubelskie', 'Dęblin', 'To starorzecze w Zajezierzu, położone na lubelskiej stronie Wisły, blisko Dęblina, charakteryzuje się rozległą powierzchnią i stosunkowo płytką wodą, z dnem mocno zarośniętym roślinnością podwodną. Brzegi są miejscami trudno dostępne, z licznymi zatopionymi pniami i gałęziami, co wymaga ostrożności. Zbiornik posiada słabe połączenie z Wisłą, co zapewnia minimalny przepływ wody i sprzyja rozwojowi bujnej roślinności. Średnie zamulenie i silne zarastanie to cechy typowe dla tego łowiska. Jest to idealne miejsce dla wędkarzy poszukujących szczupaków, linów i dużych karasi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21858, 10.2, 1.4, 3, 'Słabe połączenie', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21859, 'Starorzecze (Borek)', 'starorzecze-borek-pulawy-21859', 'OXBOW', 51.5140666, 21.8308826, 'Lubelskie', 'Puławy', 'To starorzecze w Borku jest jednym z najbardziej odizolowanych i dzikich zbiorników w okolicy, położonym w gęstym lesie. Dno jest głęboko muliste, z grubą warstwą osadów organicznych i licznymi zatopionymi pniami, co tworzy skomplikowane środowisko podwodne. Brzegi są praktycznie niedostępne, bagniste i gęsto zarośnięte, co skutecznie chroni zbiornik przed ludzką ingerencją. Całkowity brak połączenia z rzeką sprawia, że woda jest tu bardzo spokojna, a ekosystem stabilny, choć narażony na przyduchy. Wysokie zamulenie i ekstremalne zarastanie to jego cechy dominujące. Jest to idealne miejsce dla karasi pospolitych, linów i sumów, które doskonale radzą sobie w takich warunkach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21859, 6.8, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Sum,Węgorz', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21860, 'Starorzecze (Borek)', 'starorzecze-borek-borek-21860', 'OXBOW', 51.5137323, 21.8305412, 'Lubelskie', 'Borek', 'To starorzecze charakteryzuje się płytką wodą i bogatą roślinnością, co czyni je idealnym siedliskiem dla wielu gatunków ryb. Dno jest muliste, z licznymi zatopionymi gałęziami i liśćmi, co sprzyja rozwojowi bezkręgowców. Brzegi są częściowo dostępne, lecz w wielu miejscach porasta je gęsta trzcina i krzewy, utrudniając swobodne poruszanie się. Wiosną i jesienią woda bywa klarowna, latem natomiast może występować zakwit glonów. Wędkarstwo spławikowe i gruntowe przynosi tu najlepsze efekty, zwłaszcza na liny i karasie. Należy uważać na liczne zaczepy, które mogą utrudniać holowanie większych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21860, 3.2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21861, 'Starorzecze (Sławczyn)', 'starorzecze-slawczyn-slawczyn-21861', 'OXBOW', 51.4986121, 21.7929217, 'Lubelskie', 'Sławczyn', 'Niewielkie starorzecze o charakterze typowo nizinnego zbiornika, położone w bliskim sąsiedztwie Wisły. Woda jest tu zazwyczaj dość mętna, zwłaszcza po obfitych deszczach, co utrudnia obserwację dna. Dno jest głównie piaszczysto-muliste, z lokalnymi zagłębieniami i twardymi odcinkami. Brzegi są dość strome i porośnięte krzewami, co sprawia, że dostęp do wody jest ograniczony. Zbiornik jest ceniony przez wędkarzy za liczną populację płoci i leszczy, które dobrze reagują na zanęty. Warto spróbować także spinningu na okonie, szczególnie w okolicach zwalonych drzew.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21861, 2.1, 1.8, 3.5, 'Podczas wysokiej wody', 'Umiarkowane', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Karp', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21862, 'Starorzecze (Sławczyn)', 'starorzecze-slawczyn-slawczyn-21862', 'OXBOW', 51.4950037, 21.7913922, 'Lubelskie', 'Sławczyn', 'To starorzecze stanowi urokliwy zakątek dla wędkarzy poszukujących spokoju i kontaktu z naturą. Akwen charakteryzuje się dość głęboką rynną w centralnej części oraz szerokimi, płytszymi blatami przy brzegach. Dno jest zróżnicowane, od twardego piasku po miękki muł, co sprzyja różnorodności gatunkowej ryb. Brzegi są w większości stabilne i łatwo dostępne, choć miejscami występują kępy trzcin. Jest to doskonałe miejsce na zasiadkę gruntową, zwłaszcza na duże leszcze i karpie. Warto również poszukać szczupaków w głębszych partiach zbiornika, gdzie chowają się wśród podwodnej roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21862, 4.5, 2.2, 4.8, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Szczupak,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21863, 'Starorzecze (Sławczyn)', 'starorzecze-slawczyn-slawczyn-21863', 'OXBOW', 51.4946939, 21.79173, 'Lubelskie', 'Sławczyn', 'Bezpośrednio sąsiadujące z innym starorzeczem, ten zbiornik jest nieco mniejszy, ale równie atrakcyjny wędkarsko. Charakteryzuje się płytkimi zatokami i głębszym korytem, co tworzy różnorodne środowisko dla ryb. Dno jest głównie muliste, z licznymi podwodnymi zaroślami, które stanowią kryjówki dla drobnicy i drapieżników. Brzegi są częściowo zarośnięte, ale istnieją dogodne miejsca do wędkowania z brzegu. W tym starorzeczu dominują gatunki takie jak lin i karaś, które doskonale czują się w ciepłej, płytkiej wodzie. Warto spróbować szczęścia z wędką spławikową lub feederem, szczególnie wczesnym rankiem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21863, 1.8, 1.3, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21864, 'Starorzecze (Borowa)', 'starorzecze-borowa-borowa-21864', 'OXBOW', 51.5327755, 21.8409966, 'Lubelskie', 'Borowa', 'To rozległe starorzecze wyróżnia się dużą powierzchnią i stosunkowo stabilnym poziomem wody. Charakteryzuje się zróżnicowaną linią brzegową, z licznymi zatokami i półwyspami, które oferują wiele miejsc do wędkowania. Dno jest mieszane, od piaszczystych płycizn po głębokie, muliste rynny, co sprzyja różnorodności ichtiofauny. Brzegi są w większości łatwo dostępne, choć w niektórych miejscach występują pojedyncze zarośla. Jest to doskonałe miejsce na połów leszczy, płoci, a także drapieżników takich jak szczupak i okoń. Warto zabrać ze sobą łódkę, aby dotrzeć do najciekawszych miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21864, 8.7, 2.5, 5.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21865, 'Starorzecze (Borowa)', 'starorzecze-borowa-borowa-21865', 'OXBOW', 51.5302566, 21.8408708, 'Lubelskie', 'Borowa', 'Mniejsze, ale urokliwe starorzecze, które stanowi ostoję dla wielu gatunków ryb spokojnego żeru. Woda jest tu zazwyczaj czysta, co pozwala na obserwację podwodnego świata. Dno jest twarde, piaszczysto-żwirowe, z niewielkimi obszarami mulistymi w głębszych partiach. Brzegi są niskie i łatwo dostępne, otoczone łąkami, co sprzyja rodzinnej rekreacji. Jest to idealne miejsce na wędkowanie spławikowe, szczególnie na wzdręgi i płocie, które licznie zamieszkują ten akwen. Warto spróbować także spinningu na okonie, które często patrolują brzegi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21865, 1.5, 1, 2, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Wzdręga,Płoć,Okoń,Karaś pospolity', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21866, 'Starorzecze (Borowa)', 'starorzecze-borowa-borowa-21866', 'OXBOW', 51.5289031, 21.8423255, 'Lubelskie', 'Borowa', 'To starorzecze charakteryzuje się głęboką wodą i stromymi brzegami, co odróżnia je od wielu innych zbiorników w okolicy. Dno jest zróżnicowane, z przewagą twardego podłoża i nielicznymi zaczepami. Woda jest tu zazwyczaj klarowna, co sprzyja rozwojowi podwodnej roślinności w płytszych partiach. Brzegi są trudniej dostępne, miejscami porośnięte gęstymi krzewami i drzewami. Jest to doskonałe miejsce na połów sandaczy i sumów, które lubią głębokie i czyste wody. Wędkarze gruntowi znajdą tu również duże leszcze i karpie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21866, 6.3, 3, 6, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sandacz,Sum,Leszcz,Karp,Szczupak', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21867, 'Starorzecze (Borek)', 'starorzecze-borek-borek-21867', 'OXBOW', 51.5311553, 21.8331811, 'Lubelskie', 'Borek', 'Mniejsze starorzecze, które jest prawdziwą perłą dla miłośników spokojnego wędkowania. Charakteryzuje się bardzo płytką wodą i gęstą roślinnością podwodną, co tworzy idealne warunki dla linów i karasi. Dno jest w całości muliste, z grubą warstwą osadów organicznych. Brzegi są bagniste i mocno zarośnięte trzciną, co wymaga użycia specjalistycznego sprzętu lub brodzenia. Wiosną i latem zbiornik ożywa, oferując obfite połowy. Warto szukać ryb w przerwach między roślinnością, gdzie często żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21867, 0.9, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21868, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-podmiescie-21868', 'OXBOW', 51.4732772, 21.8593353, 'Lubelskie', 'Podmieście', 'To starorzecze, położone w malowniczej okolicy, jest znane z obfitości ryb spokojnego żeru. Akwen ma umiarkowaną głębokość i zróżnicowane dno, z przewagą mulistego podłoża i miejscowymi twardymi plamami. Brzegi są częściowo dostępne, ale w wielu miejscach porasta je gęsta roślinność przybrzeżna. Jest to doskonałe miejsce na połów leszczy i płoci, które często tworzą duże ławice. Warto poszukać także karpi, które lubią żerować w pobliżu zarośli. Wędkarstwo gruntowe i spławikowe przynosi tu najlepsze rezultaty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21868, 5, 1.9, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Okoń', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21869, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-podmiescie-21869', 'OXBOW', 51.4748674, 21.8535606, 'Lubelskie', 'Podmieście', 'Niewielkie, ale głębokie starorzecze, które oferuje ciekawe możliwości dla wędkarzy. Akwen charakteryzuje się stromymi brzegami i twardym, gliniastym dnem, co jest rzadkością w tej okolicy. Woda jest zazwyczaj klarowna, co sprzyja rozwojowi podwodnej roślinności w płytszych partiach. Brzegi są trudno dostępne, z licznymi zwalonymi drzewami i krzewami. To idealne miejsce na połów drapieżników, takich jak szczupak i sandacz, które często ukrywają się w głębinach. Warto spróbować także na suma, zwłaszcza po zmroku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21869, 2.8, 2.8, 5.8, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Sum,Okoń', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21870, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-podmiescie-21870', 'OXBOW', 51.472547, 21.8572172, 'Lubelskie', 'Podmieście', 'To starorzecze jest typowym zbiornikiem nizinnego charakteru, z licznymi płytkimi zatokami i mulistym dnem. Woda jest tu często mętna, zwłaszcza po intensywnych opadach deszczu. Brzegi są niskie i podmokłe, porośnięte gęstą trzciną, co utrudnia swobodny dostęp. Jest to doskonałe miejsce dla miłośników wędkowania na liny i karasie, które licznie występują w tym akwenie. Warto poszukać także wzdręg i płoci w płytszych partiach zbiornika, gdzie żerują wśród roślinności. Należy przygotować się na liczne zaczepy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21870, 3.5, 1.4, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21871, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-podmiescie-21871', 'OXBOW', 51.4726725, 21.8562096, 'Lubelskie', 'Podmieście', 'Niewielkie starorzecze o charakterze typowo rekreacyjnym, często odwiedzane przez lokalnych wędkarzy. Akwen ma umiarkowaną głębokość i zróżnicowane dno, z przewagą twardego podłoża w centralnej części. Woda jest zazwyczaj czysta, co sprzyja rozwojowi podwodnej roślinności. Brzegi są częściowo zagospodarowane, z kilkoma dogodnymi miejscami do wędkowania z brzegu. Jest to dobre miejsce na połów płoci i leszczy, a także mniejszych karpi. Warto spróbować także spinningu na okonie, które często polują w pobliżu zarośli.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21871, 1.2, 1.6, 3, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Karp,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21872, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-podmiescie-21872', 'OXBOW', 51.4750152, 21.8513009, 'Lubelskie', 'Podmieście', 'To starorzecze jest jednym z głębszych w okolicy, co sprzyja występowaniu większych okazów ryb. Akwen charakteryzuje się twardym, piaszczysto-żwirowym dnem i stromymi, zalesionymi brzegami. Woda jest tu zazwyczaj klarowna, co pozwala na obserwację podwodnego świata. Brzegi są trudno dostępne, z licznymi zwalonymi drzewami, co tworzy doskonałe kryjówki dla drapieżników. Jest to idealne miejsce na połów sandaczy i sumów, a także dużych szczupaków. Wędkarstwo gruntowe i spinningowe przynosi tu najlepsze rezultaty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21872, 4.8, 3.2, 6.5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Sandacz,Sum,Szczupak,Okoń,Leszcz', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21873, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-podmiescie-21873', 'OXBOW', 51.4742667, 21.8646406, 'Lubelskie', 'Podmieście', 'Rozległe starorzecze o zmiennym charakterze, które oferuje wiele możliwości wędkarskich. Akwen ma zróżnicowaną głębokość, od płytkich zatok po głębokie rynny, co sprzyja bogactwu gatunkowemu. Dno jest mieszane, z przewagą mulistego podłoża i licznymi podwodnymi zaroślami. Brzegi są częściowo dostępne, ale w wielu miejscach porośnięte gęstą roślinnością. Jest to doskonałe miejsce na połów leszczy, płoci, a także linów i karasi. Warto spróbować także spinningu na szczupaki, które często patrolują brzegi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21873, 7.5, 2, 4.5, 'Stałe połączenie', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Lin,Karaś pospolity,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21874, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-podmiescie-21874', 'OXBOW', 51.4744623, 21.8619986, 'Lubelskie', 'Podmieście', 'To starorzecze jest znane z bujnej roślinności wodnej i przybrzeżnej, co tworzy specyficzne warunki do wędkowania. Akwen jest stosunkowo płytki, z mulistym dnem i licznymi zatopionymi gałęziami. Woda jest często mętna, zwłaszcza latem, kiedy występują zakwity glonów. Brzegi są bagniste i bardzo trudno dostępne, co wymaga użycia pontonu lub brodzenia. Jest to raj dla linów, karasi i wzdręg, które doskonale czują się w takim środowisku. Warto spróbować także na szczupaki, które czają się w zaroślach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21874, 2.5, 1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21875, 'Starorzecze w Gołębiu', 'starorzecze-w-golebiu-pulawy-21875', 'OXBOW', 51.4904607, 21.8548193, 'Lubelskie', 'Puławy', 'To malownicze starorzecze, położone w pobliżu miejscowości Gołąb, jest popularnym miejscem wśród lokalnych wędkarzy. Charakteryzuje się dość zróżnicowanym dnem, gdzie piaszczyste płycizny przeplatają się z mulistymi zagłębieniami. Brzegi są w większości stabilne i łatwo dostępne, porośnięte trawą oraz sporadycznie kępami trzcin. W akwenie występuje umiarkowana ilość roślinności podwodnej, co stwarza idealne warunki dla drapieżników takich jak szczupak oraz ryb spokojnego żeru, w tym lina i płoci. Wędkowanie utrudniają jedynie pojedyncze zatopione konary, które jednak stanowią świetne kryjówki dla ryb. Jest to łowisko idealne na wiosenne i jesienne wypady, oferujące relaks i szansę na ładny okaz.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21875, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21876, 'Starorzecze w Zajezierzu', 'starorzecze-w-zajezierzu-deblin-21876', 'OXBOW', 51.5355869, 21.8304287, 'Lubelskie', 'Dęblin', 'To rozległe starorzecze w Zajezierzu jest typowym łowiskiem dla miłośników trudnych wyzwań i dziewiczej przyrody. Dno jest w dużej mierze muliste, z licznymi osadami, co sprzyja rozwojowi bujnej roślinności podwodnej, zwłaszcza w cieplejszych miesiącach. Brzegi są często bagniste i porośnięte gęstą trzciną, co utrudnia dostęp, dlatego wodery są tu niemal niezbędne. Starorzecze to jest ostoją dla lina i karasia pospolitego, które doskonale czują się w zarośniętych partiach wody. Ryzyko przyduchy, zwłaszcza w upalne lata, jest zauważalne, co wymaga uwagi. Mimo trudności, łowisko oferuje spokój i szansę na naprawdę piękne okazy ryb, szczególnie wczesnym latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21876, 7.2, 2.2, 4.8, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Leszcz,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21877, 'Starorzecze w Borku (1)', 'starorzecze-w-borku-1-deblin-21877', 'OXBOW', 51.5333937, 21.8286145, 'Lubelskie', 'Dęblin', 'To niewielkie starorzecze w Borku charakteryzuje się płytkim, ale stabilnym dnem, z przewagą mułu. Brzegi są gęsto porośnięte trzciną, co wymaga użycia woderów i często przecierania sobie drogi do wody. Roślinność podwodna jest umiarkowana, tworząc naturalne kryjówki dla ryb. Jest to doskonałe miejsce do połowu karasi pospolitych, płoci oraz okoni. Brak bezpośredniego połączenia z rzeką sprawia, że woda jest spokojna, a ryby dobrze adaptują się do lokalnych warunków. Mimo pewnych trudności z dostępem, łowisko jest cenione za obfitość ryb i spokój, co czyni je atrakcyjnym przez cały sezon wędkarski. Należy jednak pamiętać o zabraniu odpowiedniego sprzętu do przedzierania się przez zarośla.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21877, 2.8, 1.5, 2.8, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karaś pospolity,Płoć,Wzdręga,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21878, 'Starorzecze w Borku (2)', 'starorzecze-w-borku-2-deblin-21878', 'OXBOW', 51.5333284, 21.8298312, 'Lubelskie', 'Dęblin', 'Drugie starorzecze w Borku to przykład dobrze utrzymanego i łatwo dostępnego łowiska. Dno jest przeważnie piaszczyste z niewielkimi obszarami mułu, co sprzyja czystości wody i słabej roślinności podwodnej. Brzegi są suche i dobrze dostępne, idealne do wędkowania z brzegu bez konieczności użycia woderów. Łowisko to jest szczególnie atrakcyjne dla wędkarzy poszukujących szczupaków i okoni, które znajdują tu dogodne warunki do żerowania. Okresowe połączenie z rzeką podczas wysokiej wody wzbogaca populację ryb i zapewnia dopływ świeżej wody. Brak większych zaczepów sprawia, że jest to idealne miejsce dla początkujących wędkarzy oraz tych, którzy cenią sobie komfort i łatwość dostępu. Najlepsze efekty osiąga się tu wiosną i wczesną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21878, 3.1, 1.7, 3.2, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21879, 'Starorzecze w Borku (3)', 'starorzecze-w-borku-3-deblin-21879', 'OXBOW', 51.5335228, 21.8310548, 'Lubelskie', 'Dęblin', 'To niewielkie i płytkie starorzecze w Borku jest typowym przykładem zbiornika o silnym zamuleniu i bujnej roślinności. Dno jest niemal w całości pokryte grubą warstwą mułu, co w połączeniu z płytką wodą prowadzi do silnego zarastania. Brzegi są trudne do pokonania, często bagniste i gęsto zarośnięte, co wymaga użycia woderów. W upalne lata istnieje wysokie ryzyko przyduchy, a nawet całkowitego wyschnięcia akwenu, co wpływa na populację ryb. Dominują tu gatunki odporne, takie jak karaś srebrzysty, wzdręga i płoć, które doskonale radzą sobie w trudnych warunkach. Mimo wyzwań, łowisko może zaskoczyć obfitością tych ryb, szczególnie po obfitych deszczach, które uzupełniają poziom wody. Wędkowanie tutaj to prawdziwe wyzwanie dla cierpliwych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21879, 1.9, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21880, 'Starorzecze w Borku (4)', 'starorzecze-w-borku-4-deblin-21880', 'OXBOW', 51.5321898, 21.8292596, 'Lubelskie', 'Dęblin', 'To starorzecze w Borku wyróżnia się stałym połączeniem z rzeką, co zapewnia ciągły dopływ świeżej wody i ryb. Dno jest różnorodne, z przewagą piasku i żwiru, co sprzyja zdrowej populacji ryb i umiarkowanej roślinności. Brzegi są łatwo dostępne i stabilne, co pozwala na komfortowe wędkowanie z brzegu. Jest to idealne miejsce dla wędkarzy szukających drapieżników, takich jak szczupak, okoń i boleń, które często wpływają tu z głównego nurtu rzeki. Stałe połączenie minimalizuje ryzyko przyduchy i zapewnia stabilne warunki przez cały rok. Łowisko jest popularne ze względu na swoją dostępność i różnorodność gatunków, co czyni je atrakcyjnym o każdej porze roku. Warto eksplorować miejsca przy połączeniu z rzeką.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21880, 5, 2, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21881, 'Starorzecze w Borku (5)', 'starorzecze-w-borku-5-deblin-21881', 'OXBOW', 51.5277263, 21.8313712, 'Lubelskie', 'Dęblin', 'Kolejne starorzecze w Borku jest zbiornikiem o typowo ''linowym'' charakterze. Dno jest muliste i bogate w osady, co sprzyja rozwojowi gęstej roślinności podwodnej, zwłaszcza moczarki i wywłócznika. Brzegi są mocno zarośnięte trzciną i inną roślinnością przybrzeżną, co utrudnia dostęp i wymaga użycia woderów. Akwen jest domem dla licznych linów, karasi pospolitych i wzdręg, które doskonale maskują się w gęstwinie. W upalne lata, ze względu na brak połączenia z rzeką i obfitą roślinność, istnieje zwiększone ryzyko przyduchy. Wędkowanie tutaj wymaga cierpliwości i precyzji, ale nagrodą mogą być piękne okazy tych ryb. Najlepsze wyniki osiąga się w ciepłych miesiącach, stosując metody spławikowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21881, 3.8, 1.6, 3, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21882, 'Starorzecze w Borku (6)', 'starorzecze-w-borku-6-deblin-21882', 'OXBOW', 51.5213215, 21.8400152, 'Lubelskie', 'Dęblin', 'To głębokie i rozległe starorzecze w Borku jest prawdziwym rajem dla wędkarzy poszukujących drapieżników. Dno jest zróżnicowane, z głębokimi rynnami i zatopionymi drzewami, które stanowią idealne kryjówki dla ryb. Brzegi są łatwo dostępne, a roślinność przybrzeżna nie utrudnia wędkowania. Okresowe połączenie z rzeką wprowadza do akwenu świeżą wodę i nowe ryby, w tym sandacze, które obok szczupaków i okoni są głównymi celami wędkarzy. Duża ilość zaczepów wymaga ostrożności i odpowiedniego sprzętu, ale zwiększa szanse na złowienie dużego okazu. Jest to łowisko wymagające, ale bardzo satysfakcjonujące, szczególnie w chłodniejszych miesiącach roku. Zaleca się użycie echosondy do lokalizacji zatopionych struktur.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21882, 6.5, 2.5, 5.5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21883, 'Starorzecze w Borku (7)', 'starorzecze-w-borku-7-deblin-21883', 'OXBOW', 51.5208254, 21.8385478, 'Lubelskie', 'Dęblin', 'Siódme starorzecze w Borku to popularne łowisko karpiowe, choć obfituje również w inne gatunki. Dno jest muliste, ale z twardymi fragmentami, co sprzyja żerowaniu karpi i leszczy. Brzegi są w większości dobrze dostępne, z miejscami do rozłożenia sprzętu i wygodnego wędkowania. Roślinność podwodna jest umiarkowana, tworząc naturalne schronienia dla ryb. Brak bezpośredniego połączenia z rzeką sprawia, że woda jest spokojna, a ryby są mniej płochliwe. Oprócz karpi, wędkarze mogą liczyć na leszcze, płocie i liny. Jest to łowisko wszechstronne, odpowiednie do różnych metod wędkowania i atrakcyjne przez cały sezon. Warto przygotować zanęty pod karpie i leszcze.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21883, 4, 1.9, 3.8, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Leszcz,Płoć,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21884, 'Starorzecze w Oleksowie (1)', 'starorzecze-w-oleksowie-1-pulawy-21884', 'OXBOW', 51.494834, 21.8147927, 'Lubelskie', 'Puławy', 'Pierwsze starorzecze w Oleksowie jest niewielkim, silnie zamulonym zbiornikiem, którego dno pokrywa gruba warstwa osadów. Charakteryzuje się bujną roślinnością podwodną, tworzącą gęste zarośla, co sprawia, że jest to idealne środowisko dla karasi pospolitych i wzdręg. Brzegi są często bagniste i trudno dostępne, wymagając użycia woderów, aby dotrzeć do wody. W upalne miesiące istnieje podwyższone ryzyko przyduchy ze względu na płytkość i dużą ilość materii organicznej. Wędkowanie tutaj to wyzwanie, ale dla miłośników spokojnego żerowania i dzikiej przyrody może być bardzo satysfakcjonujące. Najlepsze efekty osiąga się wczesnym latem, stosując lekkie zestawy spławikowe. Warto szukać przejaśnień w roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21884, 2.3, 1.4, 2.7, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21885, 'Starorzecze w Oleksowie (2)', 'starorzecze-w-oleksowie-2-pulawy-21885', 'OXBOW', 51.4947604, 21.8143191, 'Lubelskie', 'Puławy', 'Drugie starorzecze w Oleksowie to bardzo płytki zbiornik, silnie zamulony i gęsto zarośnięty. Dno jest miękkie i pełne osadów, co w połączeniu z płytkością prowadzi do intensywnego rozwoju roślinności. Brzegi są niemal nieprzejezdne, obficie porośnięte trzciną i inną roślinnością wodną, co sprawia, że wodery są absolutnie konieczne. Akwen ten jest szczególnie narażony na wyschnięcie w okresach długotrwałej suszy oraz na przyduchę podczas upałów. Dominują tu gatunki najbardziej odporne, takie jak karaś srebrzysty i wzdręga, które są w stanie przetrwać w tak ekstremalnych warunkach. Wędkowanie jest tu trudne, ale może przynieść satysfakcję z połowu rzadziej spotykanych w innych miejscach okazów. To miejsce dla prawdziwych entuzjastów dzikich łowisk.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21885, 1.8, 1.1, 2.1, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21886, 'Starorzecze w Oleksowie (3)', 'starorzecze-w-oleksowie-3-pulawy-21886', 'OXBOW', 51.4944757, 21.8143802, 'Lubelskie', 'Puławy', 'Trzecie starorzecze w Oleksowie to stosunkowo łatwo dostępne łowisko o umiarkowanej głębokości. Dno jest mieszane, z fragmentami piaszczystymi i mulistymi, co sprzyja różnorodności gatunków ryb. Brzegi są w większości stabilne i dobrze dostępne, co pozwala na komfortowe wędkowanie z brzegu. Roślinność podwodna jest umiarkowana, tworząc naturalne kryjówki dla płoci, leszczy, linów i okoni. Brak bezpośredniego połączenia z rzeką zapewnia stabilne warunki wodne przez większość roku, minimalizując ryzyko nagłych zmian. Jest to dobre miejsce dla rodzin i początkujących wędkarzy, oferujące szansę na złowienie różnych gatunków ryb spokojnego żeru. Łowisko jest atrakcyjne przez cały sezon, choć w upalne dni warto szukać ryb w głębszych partiach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21886, 2, 1.3, 2.5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Lin,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21887, 'Starorzecze w Oleksowie (4)', 'starorzecze-w-oleksowie-4-pulawy-21887', 'OXBOW', 51.4903697, 21.8048969, 'Lubelskie', 'Puławy', 'Czwarte starorzecze w Oleksowie to rozległy akwen z czystą wodą i słabym zamuleniem. Dno jest w większości piaszczyste, z twardymi fragmentami, co sprzyja rozwojowi populacji drapieżników. Brzegi są łatwo dostępne i nie wymagają specjalnego sprzętu, co ułatwia wędkowanie. Okresowe połączenie z rzeką podczas wysokiej wody zapewnia dopływ świeżej wody i ryb, takich jak szczupaki, okonie i jazie. Roślinność podwodna jest skąpa, co ułatwia prowadzenie przynęt spinningowych. Jest to idealne miejsce dla wędkarzy preferujących metody aktywne, poszukujących drapieżników oraz dużych płoci i leszczy. Łowisko jest szczególnie atrakcyjne w okresie wiosennym i wczesnojesiennym, kiedy ryby intensywnie żerują. Warto spróbować spinningu lub metody gruntowej.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21887, 5.5, 2.1, 4.2, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Jaź', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21888, 'Starorzecze w Oleksowie (5)', 'starorzecze-w-oleksowie-5-pulawy-21888', 'OXBOW', 51.4901084, 21.8055854, 'Lubelskie', 'Puławy', 'Piąte starorzecze w Oleksowie to zbiornik o umiarkowanej głębokości i zróżnicowanym dnie, gdzie muliste obszary przeplatają się z twardszymi partiami. Jest to popularne miejsce dla wędkarzy karpiowych, ale także dla tych, którzy szukają linów i dużych leszczy. Brzegi są dobrze dostępne, co ułatwia rozstawienie sprzętu i komfortowe wędkowanie. Roślinność podwodna jest umiarkowana, tworząc dogodne kryjówki dla ryb, ale nie utrudnia znacząco łowienia. Brak połączenia z rzeką sprawia, że woda jest spokojna, co sprzyja rozwojowi stabilnej populacji ryb. Łowisko jest atrakcyjne przez cały sezon, ale najlepsze efekty osiąga się w późnej wiosnie i lecie, kiedy ryby spokojnego żeru są najbardziej aktywne. Warto stosować zanęty oparte na kukurydzy i pelletach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21888, 3, 1.5, 3, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Lin,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21889, 'Starorzecze w Regowie Starym', 'starorzecze-w-regowie-starym-pulawy-21889', 'OXBOW', 51.5018088, 21.8445234, 'Lubelskie', 'Puławy', 'To największe i najgłębsze starorzecze w Regowie Starym, zlokalizowane w pobliżu Puław, jest prawdziwą perłą dla wędkarzy. Charakteryzuje się stałym połączeniem z Wisłą, co zapewnia ciągły dopływ świeżej wody i migrację ryb. Dno jest zróżnicowane, z głębokimi rynnami, zatopionymi drzewami i twardymi, piaszczystymi fragmentami, stanowiąc idealne siedlisko dla suma, szczupaka i sandacza. Brzegi są dobrze dostępne, co pozwala na komfortowe wędkowanie z wielu miejsc. Niska roślinność podwodna ułatwia prowadzenie przynęt, choć liczne zatopione drzewa mogą stanowić wyzwanie. Jest to łowisko wymagające, ale oferujące szansę na złowienie naprawdę dużych okazów drapieżników przez cały rok. Warto przygotować się na silne brania i użyć solidnego sprzętu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21889, 8, 2.8, 6, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Szczupak,Sandacz,Leszcz,Boleń', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21890, 'Starorzecze Borowa', 'starorzecze-borowa-deblin-21890', 'OXBOW', 51.5433651, 21.8336604, 'Lubelskie', 'Dęblin', 'To malownicze starorzecze, położone w pobliżu Borowej, jest typowym łowiskiem dla wędkarzy ceniących spokój i kontakt z naturą. Dno jest w większości muliste, z licznymi zatopionymi gałęziami i roślinnością podwodną, co stanowi doskonałe schronienie dla ryb, ale jednocześnie wymaga precyzji w zarzucaniu. Brzegi są częściowo dostępne, jednak w wielu miejscach porastają je gęste trzciny i krzewy, utrudniając swobodne poruszanie się. Występuje tu bogata populacja lina, karasia pospolitego oraz szczupaka, który często czyha w zaroślach. Wędkowanie na tym akwenie wymaga cierpliwości i często użycia brodzenia, zwłaszcza w poszukiwaniu głębszych miejsc. Jest to idealne miejsce na wiosenne i jesienne wypady, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21890, 3.8, 1.5, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21891, 'Starorzecze Regów Stary', 'starorzecze-regow-stary-deblin-21891', 'OXBOW', 51.4773961, 21.8349189, 'Lubelskie', 'Dęblin', 'Starorzecze w okolicach Regów Starych to klasyczny przykład meandru rzeki, charakteryzujący się wydłużonym kształtem i zróżnicowaną głębokością. Dno jest głównie piaszczysto-muliste, z miejscowymi skupiskami podwodnej roślinności i pojedynczymi zaczepami. Brzegi są łatwo dostępne na większości odcinków, choć miejscami występują kępy trzcin, które stanowią naturalne kryjówki dla drobnicy. Akwen ten jest znany z obfitości leszcza i płoci, a także z występowania okazałych karpi, które żerują w spokojniejszych zatokach. Wędkarze często łowią tu również okonie i wzdręgi, zwłaszcza w cieplejszych miesiącach. To łowisko oferuje dobre warunki zarówno dla początkujących, jak i doświadczonych wędkarzy, z uwagi na różnorodność dostępnych technik. Najlepsze efekty osiąga się tu wczesnym latem i jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21891, 6.2, 2, 4.5, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Okoń,Wzdręga', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21892, 'Starorzecze Oleksów', 'starorzecze-oleksow-deblin-21892', 'OXBOW', 51.4841353, 21.8034985, 'Lubelskie', 'Dęblin', 'Starorzecze w Oleksowie to stosunkowo płytki, ale bardzo żyzny akwen, idealny dla wędkarzy preferujących łowienie gatunków spokojnego żeru. Dno jest w przeważającej części muliste, z grubą warstwą osadów dennych, co sprzyja rozwojowi bogatej roślinności podwodnej. Brzegi są gęsto porośnięte trzciną i pałką wodną, co utrudnia dostęp do wielu miejsc, ale jednocześnie tworzy doskonałe środowisko dla ryb. Dominują tu karasie pospolite i srebrzyste, a także liny, które często żerują w strefach przybrzeżnych. Wiosną i latem można tu również złowić wzdręgi i płocie. Wędkowanie wymaga precyzyjnego zarzucania i często użycia długich tyczek lub brodzenia, aby dotrzeć do otwartych lusterek wody. Ryzyko przyduchy w upalne lata jest umiarkowane. Najlepszy okres na wędkowanie to późna wiosna i lato.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21892, 2.5, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Karaś srebrzysty,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21893, 'Starorzecze Wólka Bachańska', 'starorzecze-wolka-bachanska-deblin-21893', 'OXBOW', 51.4820973, 21.7558674, 'Lubelskie', 'Dęblin', 'To starorzecze, położone w malowniczej okolicy Wólki Bachańskiej, wyróżnia się dużą bioróżnorodnością i jest cenione przez wędkarzy za swoje rybostany. Dno jest zróżnicowane, od piaszczystych płycizn po muliste zagłębienia, z licznymi korzeniami drzew i zatopionymi gałęziami, które tworzą idealne kryjówki dla drapieżników. Brzegi są częściowo dostępne, z licznymi pomostami wędkarskimi i wykoszonymi stanowiskami, jednak część akwenu otoczona jest gęstymi zaroślami. Występuje tu bogata populacja szczupaka, okonia oraz leszcza, a także węgorza, który często żeruje nocą. Wędkowanie wymaga zróżnicowanych technik, od spiningu po metody gruntowe. Akwen jest dobrze zarybiony i regularnie odwiedzany przez lokalnych wędkarzy. Najlepsze efekty można osiągnąć od wiosny do jesieni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21893, 8.5, 2.2, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Węgorz,Karp', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21894, 'Starorzecze Kościelec', 'starorzecze-koscielec-kolo-21894', 'OXBOW', 52.2021389, 18.5675572, 'Wielkopolskie', 'Koło', 'Starorzecze w Kościelcu to urokliwy zbiornik wodny, który zachował wiele cech naturalnego środowiska rzeki, z której powstał. Dno jest twarde, żwirowo-piaszczyste w płytszych partiach, przechodząc w muliste osady w głębszych dołach. Brzegi są w większości dobrze dostępne, z licznymi miejscami do wędkowania, choć lokalnie występują skupiska trzcin. Akwen słynie z populacji sandacza i suma, które często przebywają w głębszych rynnach. Można tu również złowić duże leszcze i płocie, a także bolenie i jazie, szczególnie w miejscach o szybszym przepływie wody podczas połączeń z rzeką. Wędkowanie wymaga użycia echosondy do lokalizacji ryb i znajomości topografii dna. Jest to łowisko dla wędkarzy szukających wyzwań i okazów. Wiosna i jesień to najlepsze pory na drapieżniki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21894, 12, 2.8, 6, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Sandacz,Sum,Leszcz,Boleń,Jaź', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21895, 'Starorzecze obręb Dzierawy', 'starorzecze-obreb-dzierawy-kolo-21895', 'OXBOW', 52.1943343, 18.5829186, 'Wielkopolskie', 'Koło', 'To starorzecze, położone w obrębie Dzieraw, jest mniejszym, ale bardzo produktywnym akwenem, który często zaskakuje wędkarzy obfitością ryb. Dno jest przeważnie muliste, z dużą ilością zgnilizny i roślinności, co sprzyja rozwojowi bezkręgowców, będących pokarmem dla ryb. Brzegi są mocno zarośnięte trzciną i krzewami, co sprawia, że dostęp do wody jest utrudniony i wymaga przygotowania. Występuje tu liczna populacja lina, karasia pospolitego oraz płoci, które osiągają tu imponujące rozmiary. Wędkowanie na tym akwenie wymaga cierpliwości i często brodzenia, aby dotrzeć do dogodnych stanowisk. Ze względu na gęstą roślinność, najlepiej sprawdza się tu metoda spławikowa lub gruntowa z krótkim zestawem. Ryzyko przyduchy w upalne lato jest wysokie. Najlepsze pory to późna wiosna i lato.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21895, 2, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21896, 'Starorzecze Gozdów (pierwsze)', 'starorzecze-gozdow-pierwsze-kolo-21896', 'OXBOW', 52.1948553, 18.5862192, 'Wielkopolskie', 'Koło', 'Starorzecze w Gozdowie to rozległy i głęboki zbiornik, który zachował silne połączenie z rzeką, co zapewnia stały dopływ świeżej wody i ryb. Dno jest zróżnicowane, od piaszczystych łach po głębokie rynny z mulistym osadem i licznymi zaczepami w postaci zatopionych drzew. Brzegi są częściowo dostępne, z licznymi naturalnymi stanowiskami, jednak w niektórych miejscach występują strome skarpy i gęste zarośla. Akwen jest znany z obfitości szczupaka, sandacza i suma, które chętnie polują w głębszych partiach. Występuje tu również duża populacja leszcza i karpia, które żerują na płytszych wodach. Wędkowanie wymaga znajomości akwenu i często użycia łodzi do dotarcia do najlepszych miejsc. Jest to łowisko dla wędkarzy szukających dużych okazów. Najlepsze pory to wiosna i jesień.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21896, 15, 3.5, 7, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Sum,Leszcz,Karp', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21897, 'Starorzecze Gozdów (drugie)', 'starorzecze-gozdow-drugie-kolo-21897', 'OXBOW', 52.2030999, 18.6007603, 'Wielkopolskie', 'Koło', 'Drugie starorzecze w Gozdowie to mniejszy, ale równie atrakcyjny akwen, charakteryzujący się spokojną wodą i bogatą roślinnością. Dno jest w większości muliste, z grubą warstwą osadów i licznymi skupiskami roślinności podwodnej, co sprzyja rozwojowi drobnicy. Brzegi są częściowo zarośnięte trzciną i krzewami, ale istnieją wykoszone stanowiska, które ułatwiają dostęp do wody. Występuje tu obficie karaś pospolity, lin i płoć, które są głównymi celami wędkarzy. W cieplejszych miesiącach można tu również złowić wzdręgi i niewielkie okonie. Wędkowanie na tym starorzeczu jest relaksujące i często przynosi dobre wyniki, zwłaszcza przy użyciu delikatnych zestawów spławikowych. Akwen jest idealny dla rodzin i początkujących wędkarzy. Najlepsze pory to późna wiosna i lato.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21897, 4.5, 1.8, 3, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21898, 'Starorzecze Podmieście (pierwsze)', 'starorzecze-podmiescie-pierwsze-deblin-21898', 'OXBOW', 51.4652359, 21.851818, 'Lubelskie', 'Dęblin', 'To starorzecze w Podmieściu jest jednym z wielu w tej okolicy, wyróżniającym się umiarkowaną wielkością i zróżnicowanym charakterem. Dno jest piaszczysto-muliste, z licznymi zatopionymi korzeniami i gałęziami, co stanowi doskonałe kryjówki dla ryb. Brzegi są dobrze dostępne na większości odcinków, choć miejscami występują kępy trzcin i krzewów. Akwen jest domem dla szczupaka, okonia oraz leszcza, które są najczęściej łowionymi gatunkami. W cieplejszych miesiącach można tu również złowić karpia i lina, szczególnie w spokojniejszych zatokach. Wędkowanie jest tu przyjemne i często obfituje w brania, zarówno na spinning, jak i na metody gruntowe. To popularne miejsce wśród lokalnych wędkarzy. Najlepsze pory to wiosna i wczesna jesień.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21898, 5, 1.9, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21899, 'Starorzecze Podmieście (drugie)', 'starorzecze-podmiescie-drugie-deblin-21899', 'OXBOW', 51.4672071, 21.8626315, 'Lubelskie', 'Dęblin', 'Drugie starorzecze w Podmieściu to wąski, lecz głęboki zbiornik, który charakteryzuje się dynamicznym środowiskiem, zwłaszcza po wysokich wodach. Dno jest głównie muliste, ale w niektórych miejscach występują twarde, piaszczyste fragmenty, świadczące o silnych prądach w przeszłości. Brzegi są strome i miejscami trudne do przejścia, z gęstymi zaroślami i drzewami, które tworzą liczne zaczepy. Występuje tu silna populacja bolenia i jazia, które cenią sobie miejsca o większym przepływie. Można tu również złowić duże okonie i szczupaki, które polują w pobliżu zatopionych przeszkód. Wędkowanie wymaga precyzji i często użycia lekkiego spinningu lub metody spławikowej. To łowisko dla wędkarzy szukających aktywnego połowu. Najlepsze pory to wiosna i lato.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21899, 3.2, 2.5, 5.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Boleń,Jaź,Okoń,Szczupak', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21900, 'Starorzecze Podmieście (trzecie)', 'starorzecze-podmiescie-trzecie-deblin-21900', 'OXBOW', 51.4687787, 21.8581718, 'Lubelskie', 'Dęblin', 'To starorzecze w Podmieściu jest stosunkowo płytkim, ale bardzo żyznym akwenem, który jest prawdziwym rajem dla wędkarzy ceniących sobie łowienie ryb spokojnego żeru. Dno jest w całości muliste, z grubą warstwą osadów i obfitą roślinnością podwodną, w tym grążelem i rzęsą. Brzegi są gęsto porośnięte trzciną i pałką wodną, co sprawia, że dostęp do wody jest bardzo ograniczony i wymaga brodzenia. Dominują tu karasie pospolite i liny, które osiągają tu imponujące rozmiary. Można tu również złowić duże płocie i wzdręgi. Wędkowanie wymaga cierpliwości i często użycia długich tyczek lub metody spławikowej w otwartych oczkach wody. Ze względu na płytkość i gęstą roślinność, ryzyko przyduchy w upalne lato jest wysokie. Najlepsze efekty osiąga się w późnej wiośnie i lecie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21900, 2.8, 1.2, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21901, 'Starorzecze Podmieście (czwarte)', 'starorzecze-podmiescie-czwarte-deblin-21901', 'OXBOW', 51.4703041, 21.8618191, 'Lubelskie', 'Dęblin', 'To starorzecze w Podmieściu charakteryzuje się bardziej otwartym terenem i łatwiejszym dostępem, co czyni je popularnym miejscem dla wędkarzy. Dno jest zróżnicowane, od piaszczystych płycizn po muliste doły, z pojedynczymi zaczepami w postaci korzeni i gałęzi. Brzegi są w większości dobrze dostępne, z licznymi wykoszonymi stanowiskami, choć w niektórych miejscach występują skupiska trzcin. Akwen jest znany z obfitości leszcza, płoci i karpia, które chętnie żerują na otwartych przestrzeniach. Występuje tu również okoń i szczupak, które polują w pobliżu roślinności. Wędkowanie jest tu komfortowe i często przynosi dobre wyniki, zarówno na metody gruntowe, jak i spławikowe. Jest to dobre miejsce na całosezonowe wypady. Najlepsze pory to wiosna i jesień.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21901, 7, 2, 4.2, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21902, 'Starorzecze Podmieście (piąte)', 'starorzecze-podmiescie-piate-deblin-21902', 'OXBOW', 51.4702982, 21.865206, 'Lubelskie', 'Dęblin', 'Piąte starorzecze w Podmieściu to stosunkowo niewielki, ale głęboki i tajemniczy akwen, otoczony gęstym lasem i zaroślami. Dno jest w dużej mierze muliste, z licznymi zatopionymi drzewami i gałęziami, co tworzy idealne kryjówki dla drapieżników. Brzegi są trudno dostępne, bagniste i mocno zarośnięte, co wymaga od wędkarzy dużego wysiłku, aby dotrzeć do wody. Występuje tu silna populacja szczupaka, suma i okonia, które cenią sobie te niedostępne miejsca. Można tu również złowić lina i karasia, które żerują w spokojniejszych zatokach. Wędkowanie wymaga użycia brodzenia i często pontonu lub łodzi, aby dotrzeć do najlepszych miejsc. To łowisko dla wędkarzy szukających wyzwań i ceniących dziką przyrodę. Najlepsze pory to wiosna i jesień.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21902, 4, 2.8, 6, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Sum,Okoń,Lin', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21903, 'Starorzecze Podmieście (szóste)', 'starorzecze-podmiescie-szoste-deblin-21903', 'OXBOW', 51.4695724, 21.8647159, 'Lubelskie', 'Dęblin', 'Szóste starorzecze w Podmieściu to płytki, ale bardzo żyzny zbiornik, który jest idealnym miejscem dla miłośników łowienia na spławik. Dno jest w całości pokryte grubą warstwą mulistego osadu i gęstą roślinnością podwodną, co sprzyja rozwojowi drobnicy. Brzegi są mocno zarośnięte trzciną i pałką wodną, co sprawia, że dostęp do wody jest utrudniony i wymaga brodzenia. Występuje tu obficie karaś pospolity, karaś srebrzysty oraz lin, które są głównymi celami wędkarzy. Można tu również złowić duże płocie i wzdręgi. Wędkowanie wymaga precyzyjnego zarzucania i często użycia długich tyczek lub metody spławikowej w otwartych oczkach wody. Ze względu na płytkość, ryzyko przyduchy w upalne lato jest wysokie. Najlepsze efekty osiąga się w późnej wiośnie i lecie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21903, 2.3, 0.9, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Karaś srebrzysty,Lin,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21904, 'Starorzecze Podmieście (siódme)', 'starorzecze-podmiescie-siodme-deblin-21904', 'OXBOW', 51.4696141, 21.8659765, 'Lubelskie', 'Dęblin', 'Siódme starorzecze w Podmieściu to niewielki, ale urokliwy zbiornik, który stanowi ostoję dla wielu gatunków ryb i dzikiej zwierzyny. Dno jest zróżnicowane, od piaszczystych fragmentów po muliste zagłębienia, z pojedynczymi zaczepami w postaci korzeni i gałęzi. Brzegi są częściowo dostępne, z kilkoma wykoszonymi stanowiskami, ale w większości otoczone są gęstymi zaroślami i trzcinami. Występuje tu obficie płoć, leszcz i okoń, które są najczęściej łowionymi gatunkami. W cieplejszych miesiącach można tu również złowić lina i karasia pospolitego. Wędkowanie jest tu relaksujące i często przynosi dobre wyniki, zwłaszcza przy użyciu delikatnych zestawów spławikowych. Jest to dobre miejsce na całosezonowe wypady, szczególnie dla wędkarzy ceniących spokój. Najlepsze pory to wiosna i jesień.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21904, 3, 1.5, 3, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Lin,Karaś pospolity', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21905, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-pulawy-21905', 'OXBOW', 51.4698437, 21.86939, 'Lubelskie', 'Puławy', 'To starorzecze, położone w pobliżu Puław, charakteryzuje się umiarkowanym połączeniem z głównym nurtem rzeki, zazwyczaj podczas wysokich stanów wody. Dno jest muliste z pojedynczymi korzeniami i gałęziami, co wymaga ostrożności przy zarzucaniu zestawu. Brzegi są częściowo dostępne, choć miejscami mogą być nieco zarośnięte, co utrudnia swobodne poruszanie się. W zbiorniku występuje umiarkowana roślinność podwodna i przybrzeżna, taka jak trzciny i grążele, stanowiąca doskonałe kryjówki dla ryb. Wędkowanie na tym łowisku może być wyzwaniem ze względu na ryzyko przyduchy w upalne lata, jednak populacja lina, szczupaka, płoci i leszcza jest stabilna. Najlepsze efekty osiąga się wiosną i wczesną jesienią, kiedy ryby intensywnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21905, 3.5, 1.8, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Płoć,Leszcz', 'Częściowo dostępny, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21906, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-pulawy-21906', 'OXBOW', 51.4712066, 21.8722272, 'Lubelskie', 'Puławy', 'To niewielkie starorzecze w Puławach jest typowym zbiornikiem izolowanym, bez stałego połączenia z rzeką, co sprzyja silnemu zamuleniu i bujnej roślinności. Dno jest gęsto pokryte osadami organicznymi oraz obfituje w podwodną roślinność, co sprawia, że brodzenie jest często konieczne. Brzegi są mocno zarośnięte trzciną i inną roślinnością przybrzeżną, co znacznie utrudnia dostęp do wody. Wędkowanie tutaj to prawdziwe wyzwanie, ale nagrodą mogą być piękne okazy karasia pospolitego, lina oraz wzdręgi. Istnieje wysokie ryzyko przyduchy, zwłaszcza w okresie letnich upałów, dlatego najlepsze wyniki osiąga się późną wiosną i latem, gdy ryby są aktywne. Ze względu na trudny dostęp i gęste zarośla, zaleca się użycie sprzętu do brodzenia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21906, 2.8, 1.5, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Okoń', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21907, 'Starorzecze (Opatkowice)', 'starorzecze-opatkowice-opatkowice-21907', 'OXBOW', 51.464568, 21.8772285, 'Lubelskie', 'Opatkowice', 'Starorzecze w Opatkowicach to dynamiczne łowisko ze stałym połączeniem z rzeką, co zapewnia regularną wymianę wody i niskie zamulenie dna. Dno jest stosunkowo czyste, z niewielką ilością zaczepów, co ułatwia wędkowanie różnymi technikami. Brzegi są dobrze dostępne z obu stron, co pozwala na swobodne przemieszczanie się i wybór dogodnych stanowisk. Umiarkowana roślinność podwodna i przybrzeżna tworzy idealne warunki dla drapieżników i ryb spokojnego żeru. W zbiorniku dominują szczupak, leszcz, płoć, okoń, a także sandacz, co czyni go atrakcyjnym dla wędkarzy spinningowych i gruntowych. Brak ryzyka przyduchy i czyste dno sprawiają, że łowisko jest aktywne przez cały sezon, oferując stabilne warunki do wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21907, 5.1, 2.1, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21908, 'Starorzecze (Opatkowice)', 'starorzecze-opatkowice-opatkowice-21908', 'OXBOW', 51.4643025, 21.8797263, 'Lubelskie', 'Opatkowice', 'To niewielkie starorzecze w Opatkowicach charakteryzuje się całkowitym brakiem połączenia z rzeką, co prowadzi do intensywnego zamulenia i silnego zarastania. Dno jest bardzo muliste i obfituje w zatopione drzewa oraz inne zaczepy, co czyni wędkowanie niezwykle trudnym. Brzegi są bagniste i mocno zarośnięte, co praktycznie uniemożliwia dostęp bez użycia brodzaków i maczety. Niestety, w okresach suszy zbiornik ma tendencję do wysychania, co negatywnie wpływa na populację ryb. Dominujące gatunki to niezwykle odporny karaś pospolity, lin i wzdręga, które potrafią przetrwać w trudnych warunkach. Najlepszy okres na wędkowanie to wczesna wiosna, zanim zbiornik nadmiernie zarośnie i temperatura wody wzrośnie, zwiększając ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21908, 1.9, 1, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21909, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-pulawy-21909', 'OXBOW', 51.4674598, 21.8539623, 'Lubelskie', 'Puławy', 'To starorzecze w Puławach, podobnie jak wiele innych w okolicy, łączy się z rzeką głównie podczas wysokich stanów wody, co wpływa na jego charakter. Dno jest średnio zamulone, z rozproszonymi korzeniami i gałęziami, które mogą stanowić zaczepy, ale też kryjówki dla ryb. Brzegi są w większości dostępne, choć lokalnie mogą występować utrudnienia w postaci gęstszych zarośli. Roślinność wodna jest umiarkowana, tworząc mozaikę otwartych przestrzeni i trzcinowisk. Wśród dominujących gatunków można wymienić szczupaka, lina, płoć i leszcza, które dobrze czują się w tych warunkach. Ryzyko przyduchy istnieje w upalne lata, dlatego warto monitorować poziom tlenu w wodzie. Wiosna i wczesna jesień to najlepsze pory na udane połowy, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21909, 4.2, 1.7, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Płoć,Leszcz', 'Częściowo dostępny, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21910, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-pulawy-21910', 'OXBOW', 51.4696199, 21.860822, 'Lubelskie', 'Puławy', 'To starorzecze w Puławach wyróżnia się stałym połączeniem z głównym nurtem rzeki, co gwarantuje dobrą jakość wody i niskie zamulenie dna. Dno jest przeważnie czyste, co ułatwia prowadzenie przynęt i minimalizuje ryzyko zaczepów. Brzegi są dobrze dostępne, oferując wiele dogodnych miejsc do wędkowania dla każdego. Roślinność wodna jest umiarkowana, z pasami trzcin i grążeli, które stanowią schronienie dla licznych gatunków ryb. W akwenie występują liczne okazy szczupaka, sandacza, leszcza, płoci i okonia, co czyni go atrakcyjnym dla wędkarzy preferujących różne metody. Dzięki stabilnym warunkom i braku ryzyka przyduchy, łowisko jest bardzo produktywne przez cały rok. To idealne miejsce na całosezonowe wyprawy wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21910, 6, 2.2, 4.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21911, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-pulawy-21911', 'OXBOW', 51.4717017, 21.8595202, 'Lubelskie', 'Puławy', 'Niewielkie starorzecze w Puławach jest przykładem zbiornika całkowicie odciętego od głównego nurtu, co skutkuje znacznym zamuleniem i silnym zarastaniem. Dno jest bardzo miękkie i gęsto porośnięte roślinnością podwodną, co sprawia, że brodzenie jest często niezbędne. Brzegi są niemal w całości pokryte gęstymi trzcinami i inną roślinnością, co drastycznie ogranicza dostęp do wody. Wędkowanie w tym miejscu wymaga cierpliwości i umiejętności, ale może przynieść satysfakcję w postaci karasi pospolitych, linów i wzdręg. Zbiornik jest podatny na przyduchy w upalne lata, co wymaga uwagi ze strony wędkarzy. Najlepszy czas na wędkowanie to późna wiosna i lato, kiedy ryby żerują aktywnie w cieplejszej wodzie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21911, 2, 1.1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21912, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-pulawy-21912', 'OXBOW', 51.4725173, 21.8630454, 'Lubelskie', 'Puławy', 'To starorzecze w Puławach charakteryzuje się okresowym połączeniem z rzeką, głównie podczas wysokich stanów wody, co sprzyja różnorodności środowiska. Dno jest średnio zamulone, z rozsianymi korzeniami i gałęziami, które stanowią naturalne kryjówki dla ryb i mogą być wyzwaniem dla wędkarzy. Brzegi są w miarę dostępne, choć miejscami występują zarośla, które mogą utrudniać swobodne poruszanie się. Umiarkowana roślinność podwodna i przybrzeżna tworzy dogodne warunki dla rozwoju populacji ryb. W zbiorniku dominują szczupak, lin, płoć i leszcz, co czyni go atrakcyjnym dla wędkarzy preferujących różne metody. Istnieje ryzyko przyduchy w upalne lata, dlatego warto śledzić prognozy pogody i kondycję wody. Najlepsze wyniki osiąga się wiosną i wczesną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21912, 3.8, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Płoć,Leszcz', 'Częściowo dostępny, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21913, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-pulawy-21913', 'OXBOW', 51.4736342, 21.8682377, 'Lubelskie', 'Puławy', 'To duże starorzecze w Puławach jest jednym z najbardziej atrakcyjnych łowisk w regionie, dzięki stałemu połączeniu z rzeką i dużej głębokości. Dno jest przeważnie czyste, z niewielką ilością zaczepów, co sprzyja różnorodnym technikom wędkowania. Brzegi są dobrze dostępne, oferując liczne miejsca do wędkowania z brzegu, zarówno dla początkujących, jak i doświadczonych wędkarzy. Roślinność wodna jest umiarkowana, tworząc idealne środowisko dla bogatej ichtiofauny. W zbiorniku występują imponujące okazy suma, szczupaka, leszcza, karpia i sandacza, co przyciąga wielu wędkarzy. Dzięki stałemu przepływowi wody, ryzyko przyduchy jest minimalne, a łowisko jest aktywne przez cały sezon. To doskonałe miejsce na poszukiwanie medalowych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21913, 7.5, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Leszcz,Karp,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21914, 'Starorzecze (Opatkowice)', 'starorzecze-opatkowice-opatkowice-21914', 'OXBOW', 51.454089, 21.8782257, 'Lubelskie', 'Opatkowice', 'To małe starorzecze w Opatkowicach jest całkowicie odcięte od rzeki, co prowadzi do silnego zamulenia i intensywnego zarastania. Dno jest bardzo miękkie, z dużą ilością zatopionych drzew i gałęzi, co sprawia, że wędkowanie jest niezwykle trudne i wymaga brodzenia. Brzegi są bagniste i gęsto zarośnięte, co znacząco utrudnia dostęp do wody. Niestety, w okresach długotrwałej suszy, zbiornik ma tendencję do całkowitego wysychania, co stanowi poważne zagrożenie dla ryb. W tych trudnych warunkach najlepiej radzą sobie karaś pospolity, wzdręga i lin, które są wyjątkowo wytrzymałe. Wędkowanie jest najbardziej efektywne wczesną wiosną, zanim roślinność osiągnie pełny rozkwit, a poziom wody znacznie spadnie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21914, 1.5, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21915, 'Starorzecze (Opatkowice)', 'starorzecze-opatkowice-opatkowice-21915', 'OXBOW', 51.4544855, 21.8773519, 'Lubelskie', 'Opatkowice', 'Starorzecze w Opatkowicach charakteryzuje się okresowym połączeniem z rzeką, co zapewnia odświeżenie wody i umiarkowane zamulenie dna. Dno jest średnio twarde, z pojedynczymi korzeniami i gałęziami, które mogą służyć rybom jako schronienie. Brzegi są w większości dostępne, choć miejscami mogą być nieco podmokłe, szczególnie po opadach. Roślinność wodna jest umiarkowana, z przewagą trzcin i grążeli, które tworzą atrakcyjne miejsca do wędkowania. Wśród dominujących gatunków ryb znajdują się lin, szczupak, okoń i płoć, co oferuje różnorodne możliwości dla wędkarzy. Ryzyko przyduchy jest obecne w upalne lata, dlatego warto być świadomym warunków. Najlepsze efekty wędkarskie osiąga się późną wiosną i latem, gdy ryby są bardzo aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21915, 2.3, 1.2, 2.3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Okoń,Płoć', 'Częściowo dostępny, miejscami podmokły', FALSE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21916, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-pulawy-21916', 'OXBOW', 51.4642114, 21.8662861, 'Lubelskie', 'Puławy', 'To starorzecze w Puławach jest dobrze utrzymanym łowiskiem ze stałym połączeniem z rzeką, co zapewnia ciągłą wymianę wody i niskie zamulenie. Dno jest czyste, z minimalną ilością zaczepów, co sprzyja zarówno spinningowaniu, jak i wędkarstwu gruntowemu. Brzegi są dobrze dostępne z większości stron, co pozwala na łatwe przemieszczanie się i wybór najlepszych miejsc. Umiarkowana roślinność wodna, z pasami trzcin i podwodnych łąk, stanowi idealne środowisko dla ryb. W zbiorniku można spotkać szczupaka, leszcza, płoć, okonia i karpia, co gwarantuje udane połowy. Dzięki stabilnym warunkom środowiskowym i braku ryzyka przyduchy, łowisko jest atrakcyjne przez cały sezon. To doskonałe miejsce na relaksujące wędkowanie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21916, 4.8, 1.9, 3.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Karp', 'Dobry z większości stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21917, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-pulawy-21917', 'OXBOW', 51.47085, 21.8483234, 'Lubelskie', 'Puławy', 'To starorzecze w Puławach jest zbiornikiem całkowicie odciętym od głównego nurtu rzeki, co skutkuje wysokim poziomem zamulenia i silnym zarastaniem. Dno jest bardzo miękkie i gęsto porośnięte roślinnością podwodną, co sprawia, że wędkowanie z brzegu jest trudne, a brodzenie często niezbędne. Brzegi są mocno zarośnięte trzciną i inną roślinnością, co drastycznie ogranicza dostęp do wody. Wędkowanie w tym miejscu wymaga cierpliwości i odpowiedniego sprzętu, ale może przynieść satysfakcję w postaci karasi pospolitych, linów, wzdręg i okoni. Zbiornik jest podatny na przyduchy w upalne lata, dlatego warto być ostrożnym. Najlepszy czas na wędkowanie to późna wiosna i lato, kiedy ryby żerują aktywnie w cieplejszej wodzie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21917, 3, 1.4, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21918, 'Starorzecze (Podmieście)', 'starorzecze-podmiescie-pulawy-21918', 'OXBOW', 51.4727292, 21.8464506, 'Lubelskie', 'Puławy', 'To starorzecze w Puławach charakteryzuje się okresowym połączeniem z rzeką, głównie w czasie wysokich stanów wody, co odświeża jego ekosystem. Dno jest średnio zamulone, z rozproszonymi korzeniami i gałęziami, które stanowią naturalne kryjówki dla ryb, ale mogą być też źródłem zaczepów. Brzegi są w większości dostępne, choć lokalnie mogą występować gęstsze zarośla, które utrudniają swobodne poruszanie się. Umiarkowana roślinność wodna tworzy mozaikę otwartych przestrzeni i trzcinowisk, idealnych dla ryb. Wśród dominujących gatunków można wymienić szczupaka, leszcza, płoć i karpia, które dobrze czują się w tych warunkach. Istnieje ryzyko przyduchy w upalne lata, dlatego warto monitorować poziom tlenu w wodzie. Wiosna i wczesna jesień to najlepsze pory na udane połowy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21918, 5.5, 2, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Leszcz,Płoć,Karp', 'Częściowo dostępny, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21919, 'Starorzecze (Regów Stary)', 'starorzecze-regow-stary-regow-stary-21919', 'OXBOW', 51.4769777, 21.8425888, 'Lubelskie', 'Regów Stary', 'To rozległe starorzecze w Regowie Starym jest jednym z najgłębszych i najbardziej produktywnych łowisk w okolicy, ze stałym połączeniem z rzeką. Dno jest przeważnie czyste, z minimalną ilością zaczepów, co sprzyja różnorodnym technikom wędkowania, w tym trollingowi. Brzegi są łatwo dostępne z większości stron, oferując liczne dogodne miejsca dla wędkarzy. Roślinność wodna jest słaba, co sprzyja drapieżnikom i rybom dennym, a także ułatwia prowadzenie przynęt. W zbiorniku występują imponujące okazy suma, szczupaka, sandacza, leszcza i węgorza, co przyciąga wielu wędkarzy poszukujących dużych ryb. Dzięki stałemu przepływowi wody i dużej objętości, ryzyko przyduchy jest znikome, a łowisko jest aktywne przez cały sezon. To doskonałe miejsce na ambitne wyprawy wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21919, 8, 2.8, 5.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Szczupak,Sandacz,Leszcz,Węgorz', 'Dobry z większości stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21920, 'Starorzecze (Borowa)', 'starorzecze-borowa-golab-21920', 'OXBOW', 51.5283699, 21.8519313, 'Lubelskie', 'Gołąb', 'To starorzecze, zlokalizowane w pobliżu miejscowości Borowa, charakteryzuje się typowym dla starorzeczy Wisły, mulistym dnem, bogatym w osady organiczne. Brzegi są w większości porośnięte gęstą trzciną i inną roślinnością przybrzeżną, co utrudnia dostęp do wody w wielu miejscach. Podwodna roślinność jest obfita, tworząc idealne kryjówki dla wielu gatunków ryb, ale jednocześnie stanowiąc wyzwanie dla wędkarzy. Jest to doskonałe łowisko na lina i karasia pospolitego, które znajdują tu idealne warunki do rozwoju. Występują tu również szczupaki i okonie, polujące w zaroślach. Wędkarze powinni przygotować się na konieczność użycia pontonu lub brodzenia, aby dotrzeć do najlepszych miejsc. W cieplejszych miesiącach należy uważać na ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21920, 3.8, 1.8, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna i pojedyncze korzenie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21921, 'Starorzecze (Borowa)', 'starorzecze-borowa-golab-21921', 'OXBOW', 51.5251219, 21.8607516, 'Lubelskie', 'Gołąb', 'To starorzecze, położone w bliskim sąsiedztwie Borowej, jest nieco bardziej otwarte niż sąsiednie, z fragmentami brzegów dostępnych z lądu. Dno jest zróżnicowane, od mulistego po twardsze, piaszczysto-żwirowe odcinki, szczególnie w miejscach dawnych zakrętów rzeki. Roślinność podwodna jest umiarkowana, ale wciąż zapewnia dobre schronienie dla ryb, nie utrudniając znacznie wędkowania. Jest to świetne miejsce na połów płoci i leszcza, które licznie tu żerują. W głębszych partiach można natknąć się na większe okonie i szczupaki, zwłaszcza w okolicach zatopionych drzew. Wędkowanie z gruntu i spławikowe przynosi tu najlepsze rezultaty, choć spinning również ma swoich zwolenników. Dostęp do wody jest stosunkowo łatwy w wielu punktach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21921, 5.1, 2.1, 5, 'Brak', 'Umiarkowane', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Umiarkowany, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21922, 'Starorzecze (Gołąb)', 'starorzecze-golab-golab-21922', 'OXBOW', 51.5072347, 21.8609223, 'Lubelskie', 'Gołąb', 'Starorzecze to, zlokalizowane blisko miejscowości Gołąb, wyróżnia się znacznym stopniem zarastania i płytkimi, mulistymi brzegami. Dno jest w przeważającej części miękkie, bogate w detrytus, co sprzyja rozwojowi bentosu i obfitości pokarmu. Gęste zarośla trzcinowe i pałki wodnej tworzą labirynty, w których wędkarze muszą wykazać się cierpliwością i precyzją. Jest to raj dla karasia pospolitego i lina, które osiągają tu imponujące rozmiary, dzięki stabilnym warunkom. W ciepłych miesiącach należy uważać na ryzyko przyduchy, zwłaszcza w najpłytszych częściach zbiornika, co może wpływać na aktywność ryb. Dostęp do wody jest utrudniony, często wymaga przedzierania się przez gęstą roślinność, dlatego ponton lub wodery są niezbędne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21922, 2.9, 1.5, 3.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Bardzo trudny, mocno zarośnięty i bagnisty', TRUE, 'Gęsta roślinność podwodna i muł', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21923, 'Starorzecze (Gołąb)', 'starorzecze-golab-golab-21923', 'OXBOW', 51.5003822, 21.854734, 'Lubelskie', 'Gołąb', 'To starorzecze, choć niewielkie, oferuje wędkarzom unikalne doświadczenia ze względu na swoje częściowe połączenie z Wisłą podczas większych wezbrań. Dno jest tu bardziej zróżnicowane, z fragmentami piaszczystymi i żwirowymi, co przyciąga różnorodne gatunki ryb, w tym te migrujące z rzeki. Brzegi są częściowo dostępne, choć miejscami również zarośnięte, co wymaga ostrożności. Można tu spotkać zarówno typowe dla starorzeczy liny i karasie, jak i ryby z nurtu Wisły, takie jak leszcze czy płocie. Woda jest stosunkowo czysta, a ryzyko przyduchy mniejsze niż w całkowicie odciętych zbiornikach, co sprzyja aktywności ryb. Jest to dobre miejsce na wędkowanie z gruntu, a także na spinning, zwłaszcza po opadnięciu wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21923, 1.7, 2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Lin,Okoń', 'Dobry z jednej strony, miejscami zarośnięty', FALSE, 'Pojedyncze gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21924, 'Starorzecze (Gołąb)', 'starorzecze-golab-golab-21924', 'OXBOW', 51.5051603, 21.8601075, 'Lubelskie', 'Gołąb', 'To starorzecze, położone w kompleksie starorzeczy koło Gołębia, jest przykładem zbiornika o umiarkowanym stopniu zarastania, co ułatwia dostęp wędkarzom. Dno jest głównie muliste, ale stabilne, z pojedynczymi twardszymi fragmentami, co sprzyja różnym technikom wędkowania. Brzegi są dostępne w wielu miejscach, choć zaleca się ostrożność ze względu na miękkie podłoże. Występuje tu bogata populacja płoci i leszczy, a także okazałych linów, które preferują spokojne, zasobne w pokarm wody. Wędkarstwo spławikowe i gruntowe są najbardziej efektywne, oferując dobre wyniki. Latem w godzinach wieczornych można zaobserwować żerujące sumy, które migrują tu z pobliskiej Wisły, co stanowi dodatkową atrakcję.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21924, 4.2, 2.3, 5.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Lin,Sum', 'Dobry z obu stron, miejscami grząski', TRUE, 'Pojedyncze zatopione gałęzie', 'Wiosna, lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21925, 'Starorzecze (Gołąb)', 'starorzecze-golab-golab-21925', 'OXBOW', 51.5036219, 21.8583593, 'Lubelskie', 'Gołąb', 'To starorzecze charakteryzuje się dość głębokim korytem, jak na tego typu zbiornik, co sprzyja występowaniu większych drapieżników. Dno jest zróżnicowane, z głębszymi rynnami i płytszymi blatami, a także licznymi zatopionymi drzewami, które stanowią doskonałe kryjówki. Brzegi są strome i zarośnięte, co utrudnia dostęp, ale jednocześnie zapewnia spokój i ciszę, idealną dla wędkarzy. Jest to idealne miejsce dla poszukujących szczupaka i sandacza, które często ukrywają się w zatopionych przeszkodach, czekając na ofiarę. Występują tu również duże okonie i leszcze, stanowiące bazę pokarmową dla drapieżników. Wędkarstwo spinningowe jest tu bardzo popularne, ale wymaga precyzji ze względu na liczne zaczepy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21925, 3.5, 2.8, 6, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Okoń,Leszcz', 'Trudny, strome i zarośnięte brzegi', TRUE, 'Dużo zatopionych drzew i korzeni', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21926, 'Starorzecze (Gołąb)', 'starorzecze-golab-golab-21926', 'OXBOW', 51.5104056, 21.8583748, 'Lubelskie', 'Gołąb', 'To starorzecze jest jednym z bardziej odciętych od głównego nurtu Wisły, co skutkuje stabilnym poziomem wody, ale i większym zarastaniem. Dno jest w przeważającej części muliste, z grubą warstwą osadów organicznych, co sprzyja rozwojowi specyficznej fauny. Brzegi są gęsto porośnięte trzciną i inną roślinnością, tworząc naturalne schronienie dla ryb, ale utrudniając dostęp wędkarzom. Jest to typowe łowisko karasiowo-linowe, gdzie ryby te osiągają znaczne rozmiary, dzięki obfitości pokarmu. Występują tu również wzdręgi i płocie, które żerują w strefie przybrzeżnej, poszukując owadów. Ze względu na izolację, w upalne lata może wystąpić ryzyko przyduchy, co należy brać pod uwagę podczas planowania wyprawy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21926, 2.2, 1.7, 3.9, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Bardzo trudny, gęsta trzcina i muł', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21927, 'Starorzecze (Gołąb)', 'starorzecze-golab-golab-21927', 'OXBOW', 51.5121774, 21.8586925, 'Lubelskie', 'Gołąb', 'To starorzecze, będące częścią dłuższego ciągu wodnego, charakteryzuje się umiarkowanym przepływem podczas wysokich stanów wody, co wpływa na jego ekosystem. Dno jest mieszane, z przewagą mułu, ale z twardszymi, piaszczystymi fragmentami w nurcie, co zapewnia różnorodność siedlisk. Brzegi są zróżnicowane, od łatwo dostępnych, trawiastych, po mocno zarośnięte, oferując różne możliwości wędkowania. Można tu liczyć na połów leszczy, płoci i krąpi, a także na drapieżniki takie jak szczupak i okoń, które polują w zaroślach i na otwartej wodzie. Wędkarstwo gruntowe jest tu bardzo efektywne, zwłaszcza na większych, spokojniejszych odcinkach. Warto szukać miejsc z zatopionymi gałęziami, które są naturalnymi kryjówkami dla ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21927, 4.8, 2, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń', 'Dobry z jednej strony, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21928, 'Starorzecze (Gołąb)', 'starorzecze-golab-golab-21928', 'OXBOW', 51.5125606, 21.8573585, 'Lubelskie', 'Gołąb', 'To starorzecze jest stosunkowo płytkie i mocno zarośnięte, co czyni je idealnym siedliskiem dla gatunków ciepłolubnych i odpornych na niedobory tlenu. Dno jest gęsto pokryte roślinnością podwodną i grubą warstwą mułu, co utrudnia wędkowanie, ale sprzyja życiu biologicznemu. Brzegi są bardzo trudne do pokonania, porośnięte gęstymi krzewami i trzciną, co wymaga użycia pontonu lub brodzenia, aby dotrzeć do wody. Jest to doskonałe miejsce na karasia pospolitego i lina, które osiągają tu rekordowe rozmiary, dzięki obfitości pokarmu i braku presji drapieżników. Występują tu również wzdręgi i małe okonie. Ryzyko przyduchy jest wysokie, zwłaszcza w upalne lata i pod pokrywą lodu, co jest głównym wyzwaniem dla ekosystemu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21928, 1.9, 1.2, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Bardzo trudny, gęste zarośla i bagnisty muł', TRUE, 'Gęsta roślinność podwodna i muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21929, 'Starorzecze (Gołąb)', 'starorzecze-golab-golab-21929', 'OXBOW', 51.5133256, 21.8584942, 'Lubelskie', 'Gołąb', 'To starorzecze jest jednym z bardziej uregulowanych, z częściowo umocnionymi brzegami, co ułatwia dostęp w niektórych miejscach. Dno jest zróżnicowane, z fragmentami piaszczystymi i żwirowymi, co przyciąga różnorodne gatunki ryb, a także ułatwia lokalizowanie żerowisk. Roślinność podwodna jest umiarkowana, skupiona głównie w płytszych zatokach, nie utrudniając znacząco wędkowania. Jest to dobre miejsce na połów leszcza, płoci i krąpi, a także na spotkanie z karpiem, który często żeruje w spokojnych, zasobnych w pokarm wodach. Wędkarstwo gruntowe z koszyczkiem zanętowym jest tu bardzo efektywne, przynosząc regularne brania. Warto szukać głębszych dołków, gdzie ryby gromadzą się w chłodniejszych miesiącach, szukając schronienia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21929, 3.1, 2.5, 5.2, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Okoń', 'Dobry z jednej strony, miejscami umocniony', FALSE, 'Czyste dno, pojedyncze gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21930, 'Starorzecze (Gołąb)', 'starorzecze-golab-golab-21930', 'OXBOW', 51.5144089, 21.8579938, 'Lubelskie', 'Gołąb', 'To starorzecze charakteryzuje się dość dużą powierzchnią i zmienną głębokością, co sprzyja różnorodności gatunkowej ryb. Dno jest w większości muliste, ale z twardszymi fragmentami wzdłuż dawnego nurtu rzeki, co tworzy zróżnicowane siedliska. Brzegi są zróżnicowane, od łatwo dostępnych, po gęsto zarośnięte trzciną, co wymaga od wędkarza elastyczności. Jest to doskonałe łowisko na szczupaka i okonia, które znajdują tu obfitość kryjówek i pokarmu, polując na drobną rybę. Występują tu również duże płocie i leszcze, stanowiące główny pokarm drapieżników. Wędkarstwo spinningowe i na żywca jest tu bardzo popularne, zwłaszcza w okolicach podwodnych górek i dołków. Warto eksplorować różne partie zbiornika, aby znaleźć najbardziej aktywne żerowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21930, 6.5, 2.4, 5.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Umiarkowany, miejscami zarośnięty trzciną', TRUE, 'Pojedyncze zatopione drzewa i gęsta roślinność podwodna', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21931, 'Starorzecze (Gołąb)', 'starorzecze-golab-golab-21931', 'OXBOW', 51.5179745, 21.8594484, 'Lubelskie', 'Gołąb', 'To starorzecze jest jednym z bardziej malowniczych, otoczone starodrzewem, co zapewnia cień i spokój, idealne dla relaksującego wędkowania. Dno jest głównie muliste, ale z licznymi zatopionymi konarami i gałęziami, które stanowią schronienie dla ryb, ale i potencjalne zaczepy. Brzegi są strome i miejscami trudne do pokonania, ale oferują wiele naturalnych stanowisk wędkarskich, często wymagających cierpliwości. Jest to idealne miejsce dla wędkarzy poszukujących lina i karasia pospolitego, które osiągają tu imponujące rozmiary, dzięki obfitości pokarmu. Występują tu również sumy, które często ukrywają się w zatopionych drzewach, czekając na ofiarę. Wędkarstwo gruntowe i spławikowe są najbardziej efektywne, zwłaszcza w spokojne, ciepłe dni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21931, 2.8, 1.9, 4.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Sum,Wzdręga', 'Trudny, strome i zarośnięte brzegi', TRUE, 'Dużo zatopionych drzew i gałęzi', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21932, 'Starorzecze (Gołąb)', 'starorzecze-golab-golab-21932', 'OXBOW', 51.5138607, 21.8616488, 'Lubelskie', 'Gołąb', 'To starorzecze charakteryzuje się stosunkowo czystą wodą i twardszym, piaszczysto-żwirowym dnem w porównaniu do innych zbiorników w okolicy. Jest to efekt sporadycznego, ale silnego połączenia z Wisłą podczas bardzo wysokich stanów wody, co odświeża wodę. Brzegi są częściowo dostępne, z fragmentami piaszczystymi, idealnymi do rozłożenia sprzętu i komfortowego wędkowania. Występują tu liczne populacje płoci, leszczy i jazi, które doceniają czystą wodę i dostępność pokarmu, a także obecność prądów. Można tu również liczyć na spotkanie z boleniem, który pojawia się w starorzeczu w poszukiwaniu drobnicy, szczególnie w cieplejszych miesiącach. Wędkarstwo gruntowe i spławikowe są tu bardzo efektywne, oferując dobre wyniki przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21932, 3.9, 2.2, 5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Płoć,Leszcz,Jaź,Boleń,Okoń', 'Dobry z jednej strony, piaszczyste odcinki', FALSE, 'Czyste dno, pojedyncze kamienie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21933, 'Starorzecze (Gołąb)', 'starorzecze-golab-golab-21933', 'OXBOW', 51.5160512, 21.8574902, 'Lubelskie', 'Gołąb', 'To starorzecze jest typowym, płytkim zbiornikiem, mocno zarośniętym, co stwarza idealne warunki dla karasi i linów. Dno jest w całości pokryte grubą warstwą mułu i roślinności podwodnej, co jest wyzwaniem dla wędkarzy. Brzegi są bardzo trudne do pokonania, z gęstymi zaroślami trzciny i bagnistym podłożem, co wymaga specjalnego przygotowania. Wędkarze muszą przygotować się na brodzenie lub użycie pontonu, aby dotrzeć do otwartych lusterek wody, gdzie ryby często żerują. Jest to raj dla karasia pospolitego i lina, które osiągają tu imponujące rozmiary, dzięki obfitości pokarmu i schronienia. Występują tu również wzdręgi i małe okonie. Ze względu na płytkość i zarastanie, ryzyko przyduchy jest bardzo wysokie, szczególnie zimą, co wpływa na populację ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21933, 2.1, 1.4, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Bardzo trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna i muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21934, 'Starorzecze (Gołąb)', 'starorzecze-golab-golab-21934', 'OXBOW', 51.5175937, 21.8560349, 'Lubelskie', 'Gołąb', 'To starorzecze, choć położone blisko innych, wyróżnia się nieco większą głębokością i mniejszym stopniem zarastania, co czyni je atrakcyjnym dla drapieżników. Dno jest zróżnicowane, z głębszymi rynnami i zatopionymi konarami, które stanowią doskonałe kryjówki i miejsca do żerowania. Brzegi są częściowo dostępne, z miejscami do wygodnego rozłożenia sprzętu, co ułatwia wędkowanie. Jest to świetne łowisko na szczupaka i sandacza, które polują w głębszych partiach wody, wykorzystując naturalne przeszkody. Występują tu również duże okonie i leszcze, stanowiące obfity pokarm dla drapieżników. Wędkarstwo spinningowe jest tu bardzo popularne, ale wymaga cierpliwości i znajomości topografii dna, aby unikać zaczepów. Warto zwrócić uwagę na zmiany głębokości, które często wskazują na miejsca gromadzenia się ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21934, 4.5, 2.7, 6.5, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Okoń,Leszcz', 'Umiarkowany, miejscami stromy', FALSE, 'Pojedyncze zatopione drzewa i korzenie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21935, 'Starorzecze Gołąb 1', 'starorzecze-golab-1-golab-21935', 'OXBOW', 51.5190099, 21.8543096, 'Lubelskie', 'Gołąb', 'To malownicze starorzecze, zlokalizowane w zakolu Wisły, stanowi typowy przykład ekosystemu rzecznego. Dno jest muliste, z domieszką piasku w płytszych partiach, co sprzyja rozwojowi bogatej roślinności podwodnej. Brzegi są częściowo dostępne, jednak w wielu miejscach porastają je gęste zarośla krzewów i trzcin, utrudniając swobodne poruszanie się. W akwenie dominują gatunki ryb ciepłolubnych, takie jak lin, karaś pospolity, płoć oraz drapieżny szczupak, które znajdują tu idealne warunki do bytowania. Wędkarze powinni przygotować się na łowienie w zarośniętych miejscach, co wymaga precyzji i często użycia sprzętu do brodzenia. Okresowo, przy niskim poziomie wody, może występować zwiększone ryzyko niedoboru tlenu, zwłaszcza w upalne dni lata.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21935, 3.2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Dobry z niektórych stron, miejscami utrudniony', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21936, 'Starorzecze Gołąb 2', 'starorzecze-golab-2-golab-21936', 'OXBOW', 51.5207437, 21.8533301, 'Lubelskie', 'Gołąb', 'To niewielkie, mocno zarośnięte starorzecze charakteryzuje się płytkim, mulistym dnem, które sprzyja bujnemu rozwojowi roślinności wodnej. Brzegi są trudno dostępne, często bagniste i porośnięte gęstą trzciną, co sprawia, że łowienie jest sporym wyzwaniem. Ze względu na brak stałego połączenia z rzeką i intensywne zamulanie, woda w starorzeczu jest często ciepła, a w okresie letnim występuje wysokie ryzyko deficytu tlenu. Dominujące gatunki to karaś pospolity, wzdręga i płoć, które doskonale radzą sobie w takich warunkach. Wędkarze poszukujący spokoju i nietypowych wrażeń znajdą tu swoje miejsce, ale muszą być przygotowani na trudności terenowe i konieczność brodzenia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21936, 2.8, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21937, 'Starorzecze Gołąb 3', 'starorzecze-golab-3-golab-21937', 'OXBOW', 51.5223069, 21.851652, 'Lubelskie', 'Gołąb', 'To jedno z lepiej zachowanych starorzeczy w okolicy Gołębia, posiadające stałe połączenie z głównym nurtem rzeki, co zapewnia dobrą wymianę wody. Dno jest twarde, piaszczysto-żwirowe, z niewielkimi obszarami mulistymi, co sprzyja różnorodności fauny dennej. Brzegi są łatwo dostępne, częściowo utwardzone, z licznymi dogodnymi stanowiskami wędkarskimi. Akwen obfituje w takie gatunki jak leszcz, płoć, okoń, a także większe szczupaki i jazie, które regularnie wpływają z rzeki. Dzięki dobrej cyrkulacji wody, ryzyko przyduchy jest minimalne, co czyni to miejsce atrakcyjnym przez cały rok. To idealne łowisko dla wędkarzy ceniących komfort i różnorodność gatunkową.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21937, 4.1, 1.8, 3.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Jaź', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21938, 'Starorzecze Gołąb 4', 'starorzecze-golab-4-golab-21938', 'OXBOW', 51.5229726, 21.8507686, 'Lubelskie', 'Gołąb', 'To małe i płytkie starorzecze stanowi wyzwanie dla każdego wędkarza ze względu na swoje specyficzne warunki. Dno jest całkowicie muliste i bardzo miękkie, co sprzyja intensywnemu zarastaniu przez roślinność wodną. Brzegi są mocno zarośnięte trzciną i inną roślinnością przybrzeżną, a dostęp do wody jest możliwy jedynie w nielicznych miejscach lub z użyciem brodzenia. Akwen ten jest domem głównie dla karasia pospolitego, wzdręgi i płoci, które są odporne na trudne warunki środowiskowe. Ze względu na płytkość i brak połączenia z rzeką, starorzecze to jest narażone na wysychanie w upalne lata oraz na silne niedobory tlenu. Łowienie tutaj wymaga cierpliwości i umiejętności radzenia sobie z gęstą roślinnością.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21938, 1.9, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna, pojedyncze zatopione drzewa', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21939, 'Starorzecze Stężyca 1', 'starorzecze-stezyca-1-stezyca-21939', 'OXBOW', 51.5670851, 21.7304006, 'Lubelskie', 'Stężyca', 'To rozległe starorzecze w pobliżu Stężycy oferuje doskonałe warunki do wędkarstwa, szczególnie dla drapieżników. Dno jest zróżnicowane, z partiami piaszczystymi, mulistymi i żwirowymi, co sprzyja bytowania wielu gatunków ryb. Brzegi są stosunkowo łatwo dostępne, z licznymi polankami umożliwiającymi swobodne zarzucanie wędki. Wiosną i jesienią dominują tu szczupaki i okonie, które żerują aktywnie, natomiast w cieplejszych miesiącach można liczyć na leszcze, płocie i liny. Połączenie z rzeką podczas wysokiej wody odświeża akwen i wprowadza nowe populacje ryb. Ryzyko niedoboru tlenu jest niskie, co zapewnia stabilne warunki przez większość roku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21939, 5.5, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Lin', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21940, 'Starorzecze Stężyca 2', 'starorzecze-stezyca-2-stezyca-21940', 'OXBOW', 51.5668725, 21.744334, 'Lubelskie', 'Stężyca', 'To płytkie i silnie zarośnięte starorzecze jest typowym przykładem akwenu w końcowej fazie sukcesji ekologicznej. Dno jest grubo muliste, bogate w materię organiczną, co sprzyja rozwojowi gęstej roślinności zanurzonej i wynurzonej. Brzegi są niemal całkowicie niedostępne z lądu, porośnięte wysoką trzciną i krzewami, co wymaga użycia brodzenia lub pontonu. W starorzeczu dominują gatunki ryb odpornych na trudne warunki, takie jak karaś srebrzysty, wzdręga i płoć, które świetnie radzą sobie w płytkich, ciepłych wodach. Wysokie zamulenie i bujna roślinność zwiększają ryzyko niedoboru tlenu w okresie letnim. Łowienie tutaj to prawdziwe wyzwanie, ale nagrodą mogą być piękne okazy karasi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21940, 2.1, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21941, 'Starorzecze Stężyca 3', 'starorzecze-stezyca-3-stezyca-21941', 'OXBOW', 51.5670674, 21.7398398, 'Lubelskie', 'Stężyca', 'To starorzecze stanowi atrakcyjne łowisko dla wędkarzy poszukujących różnorodności gatunkowej i ciekawych miejscówek. Dno jest mieszane, z przewagą mułu, ale także z twardszymi fragmentami, co sprzyja rozwojowi zróżnicowanej roślinności podwodnej. Brzegi są w większości dostępne, choć miejscami występują zarośla, które mogą wymagać lekkiego przedzierania się. W wodach akwenu można spotkać liny, karpie, leszcze oraz szczupaki, które chętnie polują w okolicach zatopionych drzew i konarów. Połączenie z rzeką podczas wysokiej wody wzbogaca populację ryb i odświeża akwen. W upalne, bezwietrzne dni istnieje umiarkowane ryzyko spadku poziomu tlenu, dlatego warto monitorować warunki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21941, 3.8, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karp,Leszcz,Szczupak', 'Dobry, miejscami zarośnięty', FALSE, 'Pojedyncze zatopione drzewa i konary', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21942, 'Starorzecze Stężyca 4', 'starorzecze-stezyca-4-stezyca-21942', 'OXBOW', 51.5664561, 21.7415247, 'Lubelskie', 'Stężyca', 'To niewielkie starorzecze jest jednym z najbardziej dzikich i trudno dostępnych w okolicy Stężycy. Dno jest całkowicie pokryte grubą warstwą mułu, co w połączeniu z płytkością sprzyja niemal całkowitemu zarastaniu przez roślinność wodną. Brzegi są niezwykle trudne do pokonania, często bagniste i gęsto porośnięte, co czyni to miejsce idealnym dla poszukujących prawdziwej dziczy. Dominujące gatunki ryb to karaś pospolity, wzdręga i płoć, które są odporne na ekstremalne warunki. Ze względu na brak połączenia z rzeką i niewielką głębokość, starorzecze to jest bardzo podatne na wysychanie w okresach suszy oraz na silne niedobory tlenu. Łowienie tutaj to wyzwanie, które wynagradza obcowaniem z nieskażoną naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21942, 1.5, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21943, 'Starorzecze Stężyca 5', 'starorzecze-stezyca-5-stezyca-21943', 'OXBOW', 51.5638483, 21.7516631, 'Lubelskie', 'Stężyca', 'To jedno z większych i głębszych starorzeczy w regionie, charakteryzujące się stałym połączeniem z Wisłą, co gwarantuje doskonałą jakość wody. Dno jest przeważnie piaszczysto-żwirowe, z niewielkimi osadami mułu, co sprzyja bytowaniu drapieżników. Brzegi są dobrze dostępne, z wieloma wygodnymi miejscami do wędkowania, a lokalna infrastruktura jest przyjazna wędkarzom. Akwen jest znany z dużych sumów i szczupaków, a także sandaczy, które regularnie wpływają z rzeki. Obficie występują tu również leszcze i karpie, stanowiąc pokarm dla drapieżników. Dzięki stałemu przepływowi wody, ryzyko przyduchy jest praktycznie zerowe, co czyni to łowisko atrakcyjnym przez cały rok. To doskonałe miejsce dla wędkarzy szukających dużych ryb i komfortowych warunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21943, 6, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Szczupak,Leszcz,Karp,Sandacz', 'Dobry z wielu stron, miejscami utwardzony', FALSE, 'Pojedyncze korzenie, czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21944, 'Starorzecze Stężyca 6', 'starorzecze-stezyca-6-stezyca-21944', 'OXBOW', 51.5643406, 21.7563737, 'Lubelskie', 'Stężyca', 'To starorzecze, choć pozbawione stałego połączenia z rzeką, zachowuje urok dzikiego i nieco zapomnianego łowiska. Dno jest muliste, z licznymi zatopionymi korzeniami i konarami, które stanowią doskonałe kryjówki dla ryb. Brzegi są trudne do pokonania, często bagniste i porośnięte gęstą roślinnością, co wymaga użycia brodzenia lub poszukiwania nielicznych, otwartych stanowisk. W akwenie dominują lin, karaś pospolity i płoć, a także pojawiają się węgorze, które znajdują tu obfitość pokarmu. Ze względu na ograniczoną cyrkulację wody, w upalne dni lata istnieje podwyższone ryzyko deficytu tlenu. Łowienie tutaj to wyzwanie dla cierpliwych wędkarzy, ale może przynieść satysfakcjonujące rezultaty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21944, 2.9, 1.3, 2.8, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Węgorz', 'Trudny, miejscami bagnisty', TRUE, 'Pojedyncze zatopione drzewa, gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21945, 'Starorzecze Niepołomice 1', 'starorzecze-niepolomice-1-niepolomice-21945', 'OXBOW', 50.0445167, 20.2338795, 'Małopolskie', 'Niepołomice', 'To popularne starorzecze w pobliżu Niepołomic jest cenionym łowiskiem, oferującym dobre warunki zarówno dla początkujących, jak i doświadczonych wędkarzy. Dno jest zróżnicowane, z partiami mulistymi i twardszymi, piaszczystymi, co zapewnia różnorodność siedlisk dla ryb. Brzegi są w dużej mierze łatwo dostępne, z licznymi utwardzonymi stanowiskami i pomostami, co ułatwia wędkowanie. Akwen ten jest bogaty w leszcze, płocie, karpie oraz drapieżniki takie jak szczupak i okoń. Połączenie z Wisłą podczas wysokiej wody sprzyja odświeżaniu wody i zasilaniu populacji ryb. Ryzyko niedoboru tlenu jest niskie, co zapewnia stabilne warunki przez większość roku. To idealne miejsce na rodzinny wypad wędkarski.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21945, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Okoń', 'Dobry, częściowo zagospodarowany', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21946, 'Starorzecze Niepołomice 2', 'starorzecze-niepolomice-2-niepolomice-21946', 'OXBOW', 50.0444372, 20.2301084, 'Małopolskie', 'Niepołomice', 'To starorzecze, choć położone blisko miasta, zachowało swój dziki charakter, stanowiąc wyzwanie dla wędkarzy. Dno jest bardzo muliste i miękkie, co sprzyja bujnemu rozwojowi roślinności wodnej, tworzącej podwodne łąki. Brzegi są mocno zarośnięte trzciną i krzewami, a dostęp do wody jest utrudniony, często wymagając brodzenia przez płytkie partie. W akwenie dominują gatunki takie jak karaś pospolity, lin i wzdręga, które świetnie adaptują się do warunków ze sporą ilością roślinności. Ze względu na brak połączenia z rzeką i obfitość materii organicznej, w okresie letnim występuje wysokie ryzyko niedoboru tlenu. Łowienie tutaj to prawdziwa szkoła precyzji i cierpliwości, ale może przynieść piękne okazy ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21946, 3, 1.5, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna, pojedyncze zatopione pnie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21947, 'Starorzecze Niepołomice 3', 'starorzecze-niepolomice-3-niepolomice-21947', 'OXBOW', 50.0447422, 20.2290765, 'Małopolskie', 'Niepołomice', 'To starorzecze, choć mniejsze, oferuje ciekawe możliwości wędkarskie, zwłaszcza dla miłośników białej ryby i średnich drapieżników. Dno jest mieszane, z przewagą mułu, ale także z twardszymi fragmentami, gdzie roślinność jest mniej intensywna. Brzegi są częściowo dostępne, jednak w niektórych miejscach występują zarośla, które mogą wymagać użycia brodzenia. W akwenie dominują płoć, leszcz, okoń oraz szczupak, które znajdują tu dogodne warunki do żerowania i rozmnażania. Połączenie z rzeką podczas wysokiej wody odświeża akwen i wspiera populacje ryb. W upalne dni lata istnieje umiarkowane ryzyko spadku poziomu tlenu, co jest typowe dla płytkich starorzeczy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21947, 2.5, 1.2, 2.5, 'Podczas wysokiej wody', 'Umiarkowane', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry z niektórych stron', TRUE, 'Pojedyncze korzenie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21948, 'Starorzecze Niepołomice 4', 'starorzecze-niepolomice-4-niepolomice-21948', 'OXBOW', 50.0442028, 20.2290102, 'Małopolskie', 'Niepołomice', 'To starorzecze wyróżnia się stałym połączeniem z Wisłą, co zapewnia dynamiczny przepływ wody i sprzyja bytowaniu ryb typowych dla nurtu rzecznego. Dno jest twarde, piaszczysto-żwirowe, z niewielkimi zagłębieniami, co stanowi idealne środowisko dla drapieżników i ryb rzecznych. Brzegi są łatwo dostępne, z wieloma wygodnymi miejscami do wędkowania, a także z utwardzonymi ścieżkami. Akwen jest znany z obecności boleni, jazi i kleni, które regularnie wpływają z rzeki, a także okoni i szczupaków. Dzięki stałej wymianie wody, ryzyko niedoboru tlenu jest minimalne, co czyni to miejsce atrakcyjnym przez cały sezon. To doskonałe łowisko dla wędkarzy ceniących aktywność i różnorodność gatunkową, zwłaszcza ryb typowych dla rzek.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21948, 3.5, 1.6, 3.1, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Boleń,Jaź,Kleń,Okoń,Szczupak', 'Dobry, częściowo utwardzony', FALSE, 'Czyste dno, pojedyncze kamienie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21949, 'Starorzecze Przyjmy', 'starorzecze-przyjmy-przyjmy-21949', 'OXBOW', 52.6214047, 21.6151042, 'Mazowieckie', 'Przyjmy', 'To obszerne starorzecze, położone w malowniczej okolicy Przyjm, stanowi doskonałe łowisko dla wędkarzy poszukujących dużych ryb. Dno jest zróżnicowane, z głębokimi rynnami i zatopionymi drzewami, które tworzą idealne kryjówki dla drapieżników. Brzegi są w większości łatwo dostępne, częściowo leśne, z naturalnymi stanowiskami wędkarskimi. Akwen jest znany z obecności dużych sumów i szczupaków, które chętnie żerują w okolicach przeszkód podwodnych. Można tu również złowić okazałe karpie, leszcze oraz węgorze, które znajdują tu obfitość pokarmu. Połączenie z rzeką podczas wysokiej wody zapewnia regularne zasilanie w świeżą wodę i ryby. Ryzyko niedoboru tlenu jest niskie, co czyni to łowisko stabilnym i atrakcyjnym przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21949, 5, 2.2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Karp,Leszcz,Węgorz', 'Dobry z większości stron, miejscami leśny', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21950, 'Starorzecze Janowice Północne', 'starorzecze-janowice-polnocne-janowice-21950', 'OXBOW', 51.3040973, 21.8653237, 'Lubelskie', 'Janowice', 'To starorzecze, położone w malowniczej okolicy Janowic, charakteryzuje się typową dla starorzeczy Wisły bujną roślinnością brzegową, głównie trzciną i pałką wodną. Dno jest muliste, choć w niektórych miejscach można natrafić na twardsze, piaszczyste fragmenty, pozostałości po dawnym korycie rzeki. Poziom zamulenia jest średni, co sprzyja rozwojowi bogatej fauny dennej, stanowiącej bazę pokarmową dla ryb. Akwen łączy się z rzeką głównie podczas wiosennych roztopów i wysokich stanów wody, co umożliwia migrację ryb. Dominujące gatunki to szczupak, lin, karaś pospolity, płoć i okoń, które znajdują tu idealne warunki do żerowania i rozmnażania. Brzegi są trudno dostępne, często bagniste i mocno zarośnięte, co wymaga użycia wodery dla komfortowego wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21950, 3.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21951, 'Starorzecze Kazimierz Dolny', 'starorzecze-kazimierz-dolny-kazimierz-dolny-21951', 'OXBOW', 51.3077789, 21.8981451, 'Lubelskie', 'Kazimierz Dolny', 'To malownicze starorzecze, zlokalizowane w pobliżu Kazimierza Dolnego, jest popularnym łowiskiem wśród lokalnych wędkarzy. Charakteryzuje się stosunkowo głębszą wodą niż inne okoliczne starorzecza, co sprzyja bytności większych okazów ryb. Dno jest w większości muliste, ale miejscami występują twardsze, żwirowe fragmenty, zwłaszcza wzdłuż dawnego koryta Wisły. Roślinność podwodna jest umiarkowana, co ułatwia prowadzenie przynęty. Połączenie z Wisłą następuje podczas wiosennych wezbrań, odświeżając wodę i wzbogacając populację ryb. Wśród dominujących gatunków można wymienić leszcza, płoć, lina, szczupaka oraz karpia. Brzegi są dobrze dostępne, co czyni to miejsce idealnym dla rodzinnych wypadów wędkarskich, nie wymagając użycia woderów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21951, 5.2, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Lin,Szczupak,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21952, 'Starorzecze Janowiec Północne', 'starorzecze-janowiec-polnocne-janowiec-21952', 'OXBOW', 51.3156491, 21.9073722, 'Lubelskie', 'Janowiec', 'To niewielkie starorzecze w pobliżu Janowca jest typowym przykładem akwenu o wysokim stopniu naturalnej sukcesji. Charakteryzuje się bardzo silnym zarośnięciem zarówno brzegów, jak i dna, co tworzy trudne warunki do wędkowania, ale jednocześnie doskonałe schronienie dla ryb. Brak stałego połączenia z rzeką sprawia, że woda jest tu spokojna i ciepła, co sprzyja rozwojowi roślinności i powolnemu procesowi zamulania. Dno jest głęboko muliste, bogate w materię organiczną. Istnieje podwyższone ryzyko niedoboru tlenu w okresie letnich upałów. Wśród dominujących gatunków ryb królują karaś pospolity, lin, wzdręga oraz płoć, które doskonale radzą sobie w tak specyficznych warunkach. Dostęp do wody jest utrudniony ze względu na bagniste i gęsto zarośnięte brzegi, co czyni wodery niezbędnym elementem wyposażenia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21952, 2.8, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21953, 'Starorzecze Brześce-Kolonia', 'starorzecze-brzesce-kolonia-brzesce-kolonia-21953', 'OXBOW', 51.2974818, 21.8595229, 'Lubelskie', 'Brześce-Kolonia', 'Starorzecze w Brześcach-Kolonii to średniej wielkości zbiornik, który zachował wiele cech dawnego koryta Wisły. Woda jest tu klarowna, a dno w wielu miejscach twarde, piaszczysto-żwirowe, co wyróżnia je na tle innych starorzeczy. Brzegi są stosunkowo łatwo dostępne, z miejscami do rozstawienia sprzętu wędkarskiego. Połączenie z głównym nurtem rzeki następuje podczas wiosennych wezbrań, co sprzyja odświeżeniu wody i migracji ryb. Roślinność podwodna jest umiarkowana, co pozwala na różnorodne techniki wędkarskie. W akwenie dominują szczupaki, liny, leszcze i okonie, a ich populacje są stabilne. Jest to doskonałe miejsce dla wędkarzy ceniących sobie komfortowy dostęp i różnorodność gatunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21953, 4.1, 1.8, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21954, 'Starorzecze Janowice Południowe', 'starorzecze-janowice-poludniowe-janowice-21954', 'OXBOW', 51.3005801, 21.8648095, 'Lubelskie', 'Janowice', 'To niewielkie i płytkie starorzecze w Janowicach jest przykładem akwenu o zaawansowanym stadium sukcesji. Charakteryzuje się bardzo wysokim poziomem zamulenia i silnym zarośnięciem, co sprawia, że jest to środowisko trudne do wędkowania, ale cenne dla specyficznych gatunków ryb. Zbiornik jest całkowicie odcięty od głównego nurtu Wisły, co prowadzi do szybkiego nagrzewania się wody i wysokiego ryzyka przyduchy w upalne lata. Niestety, w okresach długotrwałej suszy zdarza się, że starorzecze wysycha niemal całkowicie. Dominujące gatunki to niezwykle odporny karaś pospolity, wzdręga oraz płoć. Brzegi są bagniste i gęsto porośnięte, co wymaga użycia woderów i cierpliwości.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21954, 2.3, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21955, 'Starorzecze Janowice Zachodnie', 'starorzecze-janowice-zachodnie-janowice-21955', 'OXBOW', 51.2994943, 21.8606007, 'Lubelskie', 'Janowice', 'Kolejne z janowickich starorzeczy, to zachodnie, charakteryzuje się niewielkimi rozmiarami i małą głębokością, co czyni je szczególnie wrażliwym na zmiany klimatyczne. Poziom zamulenia jest bardzo wysoki, a dno w całości pokryte grubą warstwą mułu. Roślinność podwodna i brzegowa jest niezwykle bujna, tworząc gęste zarośla trzcin i grążeli, co utrudnia dostęp do wody. Brak połączenia z Wisłą powoduje, że woda jest tu stojąca i szybko nagrzewa się latem, zwiększając ryzyko przyduchy. W okresach suszy starorzecze potrafi niemal całkowicie wyschnąć. Dominujące gatunki ryb to odporne karasie srebrzyste, wzdręgi i płocie. Wędkowanie wymaga cierpliwości i umiejętności poruszania się w gęstej roślinności, a wodery są absolutnie konieczne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21955, 1.8, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21956, 'Starorzecze Janowiec Centralne', 'starorzecze-janowiec-centralne-janowiec-21956', 'OXBOW', 51.3045384, 21.8784385, 'Lubelskie', 'Janowiec', 'To jedno z większych i głębszych starorzeczy w okolicy Janowca, cenione przez wędkarzy poszukujących większych okazów. Charakteryzuje się zróżnicowanym dnem, gdzie muliste partie przeplatają się z twardszymi, żwirowymi fragmentami, pozostałościami po dawnym nurcie Wisły. Brzegi są w większości łatwo dostępne, co umożliwia komfortowe wędkowanie z gruntu i na spinning. Starorzecze ma okresowe połączenie z Wisłą, co zapewnia dopływ świeżej wody i migrację ryb, w tym dużych sumów. Roślinność podwodna jest umiarkowana, co sprzyja różnorodnym metodom wędkowania. Dominujące gatunki to sum, szczupak, leszcz, karp i lin, które osiągają tu imponujące rozmiary. Jest to łowisko atrakcyjne przez cały sezon, oferujące wiele możliwości.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21956, 6, 2.2, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Leszcz,Karp,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21957, 'Starorzecze Janowiec Zachodnie', 'starorzecze-janowiec-zachodnie-janowiec-21957', 'OXBOW', 51.3050075, 21.8765125, 'Lubelskie', 'Janowiec', 'Starorzecze Janowiec Zachodnie to akwen o średniej wielkości, charakteryzujący się dość szybkim procesem zamulania i umiarkowanym zarośnięciem. Jego dno jest w dużej mierze pokryte miękkim mułem, co sprzyja występowaniu ryb żerujących przy dnie. Brak bezpośredniego połączenia z rzeką sprawia, że woda jest tu spokojniejsza, ale jednocześnie bardziej podatna na wahania poziomu tlenu, szczególnie w upalne dni. Brzegi są trudno dostępne, gęsto porośnięte trzciną i inną roślinnością, co wymaga użycia woderów. Dominujące gatunki ryb to lin, karaś pospolity, szczupak i okoń, które znajdują tu dogodne warunki do życia. Wędkowanie jest najbardziej efektywne w późnej wiośnie i lecie, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21957, 3, 1.7, 3.5, 'Brak', 'Wysokie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21958, 'Starorzecze Janowiec Wschodnie', 'starorzecze-janowiec-wschodnie-janowiec-21958', 'OXBOW', 51.3071837, 21.8787939, 'Lubelskie', 'Janowiec', 'To starorzecze w Janowcu, zlokalizowane po wschodniej stronie, jest znane z dobrego dostępu i bogatej populacji ryb. Charakteryzuje się zróżnicowanym dnem, z partiami mulistymi i twardszymi, piaszczystymi, które są pozostałościami po dawnym korycie rzeki. Brzegi są stosunkowo łatwo dostępne, co sprawia, że jest to popularne miejsce dla wędkarzy. Akwen ma okresowe połączenie z Wisłą, co sprzyja odświeżeniu wody i migracji ryb, w tym węgorzy. Roślinność podwodna jest umiarkowana, co ułatwia prowadzenie przynęt. Dominujące gatunki to leszcz, płoć, karp, szczupak i węgorz, które zapewniają emocjonujące łowy. Jest to łowisko atrakcyjne przez cały sezon, oferujące komfortowe warunki wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21958, 4.5, 1.9, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Węgorz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21959, 'Starorzecze Ceber Północne', 'starorzecze-ceber-polnocne-ceber-21959', 'OXBOW', 51.6997135, 15.9908021, 'Lubuskie', 'Ceber', 'Starorzecze Ceber Północne to jedno z większych i głębszych starorzeczy w województwie lubuskim, położone w pobliżu Odry. Charakteryzuje się stosunkowo twardym, piaszczysto-żwirowym dnem i niskim poziomem zamulenia, co świadczy o jego dobrej kondycji hydrologicznej. Akwen ma okresowe połączenie z Odrą podczas wezbrań, co zapewnia dopływ świeżej wody i migrację wielu gatunków ryb, w tym dużych sumów i sandaczy. Brzegi są w większości łatwo dostępne, co czyni to miejsce idealnym dla wędkarzy preferujących komfortowe warunki. Roślinność podwodna jest umiarkowana, co pozwala na różnorodne techniki wędkarskie. Dominujące gatunki to sum, szczupak, sandacz, leszcz i karp. To łowisko o dużym potencjale, atrakcyjne przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21959, 7, 2.5, 6, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Sandacz,Leszcz,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21960, 'Starorzecze Ceber Centralne', 'starorzecze-ceber-centralne-ceber-21960', 'OXBOW', 51.6966803, 15.9958196, 'Lubuskie', 'Ceber', 'To starorzecze w Cebrze, mimo braku stałego połączenia z Odrą, utrzymuje stabilny poziom wody, choć jest bardziej podatne na zamulanie. Dno jest w większości muliste, z lokalnymi skupiskami podwodnej roślinności, która stanowi schronienie dla ryb. Brzegi są częściowo zarośnięte trzciną, co utrudnia dostęp w niektórych miejscach, ale jednocześnie tworzy ciche zakątki dla wędkarzy. W okresach letnich upałów może występować podwyższone ryzyko niedoboru tlenu. Wśród dominujących gatunków ryb znajdują się szczupak, lin, karaś pospolity, płoć i okoń. Wędkowanie z użyciem woderów jest zalecane, aby dotrzeć do najlepszych miejscówek, szczególnie wiosną i wczesną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21960, 4.8, 1.8, 3.5, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21961, 'Starorzecze Ceber Południowe', 'starorzecze-ceber-poludniowe-ceber-21961', 'OXBOW', 51.6971061, 16.0028394, 'Lubuskie', 'Ceber', 'Starorzecze Ceber Południowe to rozległy akwen, który zachował dobrą kondycję hydrologiczną dzięki okresowym połączeniom z Odrą. Dno jest zróżnicowane, z przewagą twardszych, piaszczysto-żwirowych fragmentów, co sprzyja występowaniu różnorodnych gatunków ryb. Brzegi są w większości łatwo dostępne, z licznymi miejscami do wędkowania z brzegu. Umiarkowana roślinność podwodna tworzy doskonałe kryjówki dla ryb, nie utrudniając jednocześnie wędkowania. W akwenie dominują leszcz, karp, szczupak, okoń, a także węgorz, który migruje z Odry. Jest to łowisko o dużej popularności, oferujące emocjonujące łowy przez cały sezon, bez konieczności użycia woderów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21961, 6.5, 2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Szczupak,Okoń,Węgorz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21962, 'Starorzecze Husinka Północne', 'starorzecze-husinka-polnocne-husinka-21962', 'OXBOW', 52.0466354, 23.3275356, 'Lubelskie', 'Husinka', 'To starorzecze w Husince, położone w pobliżu rzeki Bug, jest przykładem akwenu o zaawansowanym stadium sukcesji ekologicznej. Charakteryzuje się wysokim poziomem zamulenia i silnym zarośnięciem, zarówno brzegów, jak i dna, co tworzy specyficzne środowisko. Brak połączenia z Bugiem sprawia, że woda jest tu spokojna i ciepła, ale jednocześnie bardziej podatna na niedobory tlenu w upalne lata. Dno jest głęboko muliste, bogate w materię organiczną. Dostęp do wody jest utrudniony ze względu na bagniste i gęsto porośnięte brzegi, wymagające użycia woderów. Dominujące gatunki ryb to karaś pospolity, lin, wzdręga oraz płoć, które doskonale adaptują się do tych warunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21962, 2.5, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21963, 'Starorzecze Horbów-Kolonia', 'starorzecze-horbow-kolonia-horbow-kolonia-21963', 'OXBOW', 52.0519804, 23.3297346, 'Lubelskie', 'Horbów-Kolonia', 'Starorzecze w Horbowie-Kolonii to atrakcyjne łowisko o umiarkowanych rozmiarach, położone w dorzeczu Bugu. Charakteryzuje się zróżnicowanym dnem, gdzie muliste partie przeplatają się z twardszymi, piaszczystymi fragmentami, pozostałościami po dawnym korycie rzeki. Akwen ma okresowe połączenie z Bugiem, co zapewnia dopływ świeżej wody i migrację ryb, co pozytywnie wpływa na ich populacje. Brzegi są w większości łatwo dostępne, co umożliwia komfortowe wędkowanie z gruntu i na spinning. Roślinność podwodna jest umiarkowana, tworząc dobre kryjówki dla drapieżników. Dominujące gatunki to szczupak, okoń, leszcz, płoć i lin. Jest to doskonałe miejsce na wiosenne i jesienne wyprawy wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21963, 3.8, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21964, 'Starorzecze Husinka Południowe', 'starorzecze-husinka-poludniowe-husinka-21964', 'OXBOW', 52.0451558, 23.3237835, 'Lubelskie', 'Husinka', 'To najmniejsze i najpłytsze z omawianych starorzeczy w Husince, charakteryzujące się bardzo zaawansowanym stadium zanikania. Dno jest całkowicie pokryte grubą warstwą mułu, a roślinność podwodna i brzegowa jest niezwykle bujna, tworząc gęste zarośla trzcin i grążeli. Brak połączenia z rzeką Bug sprawia, że woda jest tu stojąca i szybko nagrzewa się latem, co prowadzi do wysokiego ryzyka przyduchy. W okresach długotrwałej suszy starorzecze wysycha niemal całkowicie, co ogranicza populację ryb do najbardziej odpornych gatunków. Dominujące gatunki to karaś srebrzysty i wzdręga, które doskonale radzą sobie w ekstremalnych warunkach. Wędkowanie jest tu wyzwaniem, wymagającym cierpliwości, a wodery są niezbędne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21964, 1.5, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21965, 'Karuch 1', 'karuch-1-sokolow-podlaski-21965', 'OXBOW', 52.3695625, 22.8523981, 'Mazowieckie', 'Sokołów Podlaski', 'Starorzecze Karuch 1 to malowniczy zbiornik, położony w dolinie rzeki Bug, charakteryzujący się wydłużonym kształtem. Dno jest zróżnicowane, od twardego piasku po muliste osady w głębszych partiach, co sprzyja różnorodności gatunkowej. Brzegi są częściowo dostępne, miejscami porośnięte trzciną i krzewami, co zapewnia dobre miejsca do ukrycia się ryb. Roślinność podwodna jest umiarkowana, tworząc idealne środowisko dla drapieżników i białorybu. Dominujące gatunki to szczupak, lin, leszcz, płoć oraz okoń, które licznie zasiedlają te wody. Wędkowanie może być utrudnione w okresie silnego zarośnięcia latem, ale ogólnie łowisko jest przystępne i oferuje dobre perspektywy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21965, 3.5, 1.8, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry z niektórych stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21966, 'Karuch 2', 'karuch-2-sokolow-podlaski-21966', 'OXBOW', 52.3706885, 22.8504657, 'Mazowieckie', 'Sokołów Podlaski', 'Starorzecze Karuch 2 to mniejszy, bardziej zaciszny zbiornik, charakteryzujący się intensywnym zarośnięciem. Dno jest w większości muliste, z grubą warstwą osadów organicznych, co sprzyja rozwojowi roślinności wodnej. Brzegi są bagniste i mocno porośnięte trzciną, co znacząco utrudnia dostęp do wody dla wędkarzy. Gęsta roślinność podwodna stanowi doskonałe schronienie dla lina, karasia pospolitego oraz wzdręgi, które świetnie adaptują się do takich warunków. Występuje tu również licznie płoć, dostosowana do trudniejszych warunków środowiskowych. Ze względu na obfitość roślinności i płytkość, istnieje ryzyko przyduchy w upalne lata, co wymaga uwagi i monitorowania. Wymagane są wodery i cierpliwość, aby dotrzeć do najlepszych miejscówek i cieszyć się wędkowaniem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21966, 2.8, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21967, 'Starorzecze Zajęczniki 1', 'starorzecze-zajeczniki-1-sokolow-podlaski-21967', 'OXBOW', 52.3911559, 22.7110735, 'Mazowieckie', 'Sokołów Podlaski', 'To starorzecze w okolicach Zajęczników jest jednym z głębszych w regionie, oferując zróżnicowane warunki dla wędkarzy. Dno jest twarde w wielu miejscach, z lokalnymi zagłębieniami pokrytymi mułem, co sprzyja różnorodności gatunkowej ryb. Brzegi są stosunkowo łatwo dostępne, częściowo trawiaste, a miejscami z pasmami trzcin, co ułatwia wybór stanowiska. Roślinność wodna jest umiarkowana, skupiona głównie w płytszych zatoczkach i przy brzegach, nie utrudniając zbytnio wędkowania. W wodach tych dominują szczupaki, leszcze, płocie, okonie oraz rzadziej spotykane węgorze, które doceniają czystą wodę. Wędkowanie jest komfortowe przez większość roku, a brak silnego zamulenia sprzyja utrzymaniu dobrej jakości wody w zbiorniku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21967, 4.1, 2.1, 5, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Węgorz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21968, 'Starorzecze Zajęczniki 2', 'starorzecze-zajeczniki-2-sokolow-podlaski-21968', 'OXBOW', 52.3919413, 22.7089272, 'Mazowieckie', 'Sokołów Podlaski', 'Mniejsze starorzecze w Zajęcznikach to typowy zbiornik o charakterze mocno zarośniętym i płytkim. Dno jest niemal w całości pokryte grubą warstwą mułu, co świadczy o zaawansowanym procesie sedymentacji i sukcesji. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest bardzo trudny i wymaga użycia woderów. Silne zarośnięcie roślinnością podwodną ogranicza przestrzeń dla ryb, ale sprzyja gatunkom takim jak karaś pospolity, lin i wzdręga, które świetnie adaptują się do takich warunków. Z uwagi na płytkość i zamulenie, starorzecze to jest narażone na wysychanie w okresach długotrwałej suszy oraz na przyduchy latem. Wędkowanie tutaj to wyzwanie dla cierpliwych i doświadczonych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21968, 1.9, 1.1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21969, 'Starorzecze Wólka Zamkowa 1', 'starorzecze-wolka-zamkowa-1-sokolow-podlaski-21969', 'OXBOW', 52.4032573, 22.5908271, 'Mazowieckie', 'Sokołów Podlaski', 'Starorzecze w Wólce Zamkowej to rozległy i głęboki zbiornik z silnym połączeniem z głównym nurtem rzeki, co zapewnia stały dopływ świeżej wody. Dno jest przeważnie piaszczysto-żwirowe, z niewielkimi obszarami mulistymi w spokojniejszych zatokach, co sprzyja różnym gatunkom. Brzegi są dobrze utrzymane i łatwo dostępne, co czyni to miejsce idealnym dla wędkarzy poszukujących komfortu. Roślinność wodna jest słaba, co sprzyja drapieżnikom i swobodnemu przemieszczaniu się ryb, ułatwiając zarazem wędkowanie. W starorzeczu tym licznie występują szczupaki, leszcze, płocie, a także karpie i bolenie, które często wpływają z rzeki. Czyste dno i dobra cyrkulacja wody zapewniają doskonałe warunki tlenowe przez cały rok, czyniąc to łowisko jednym z bardziej cenionych w okolicy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21969, 6, 2.5, 5.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Karp,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21970, 'Starorzecze Wólka Zamkowa 2', 'starorzecze-wolka-zamkowa-2-sokolow-podlaski-21970', 'OXBOW', 52.4011512, 22.5862328, 'Mazowieckie', 'Sokołów Podlaski', 'To starorzecze, choć bliskie pierwszemu, ma nieco inny charakter, z bardziej urozmaiconym dnem i brzegami. Dno jest mieszane, z przewagą mułu w płytszych partiach i twardszym podłożem w głębszych miejscach, co sprzyja różnorodności fauny. Brzegi są miejscami bagniste i zarośnięte, co wymaga ostrożności i czasem użycia woderów, aby dotrzeć do wody. Roślinność wodna jest umiarkowana, tworząc schronienia dla ryb i atrakcyjne miejsca do wędkowania na spławik. Wśród dominujących gatunków ryb znajdziemy liny, karpie, leszcze, płocie i okonie, które licznie występują w tym zbiorniku. Połączenie z rzeką podczas wysokiej wody sprzyja odświeżaniu zbiornika i migracji ryb, wzbogacając populację. Łowisko to oferuje dobre możliwości dla wędkarzy poszukujących różnorodnych gatunków i ceniących spokój.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21970, 4.5, 1.9, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karp,Leszcz,Płoć,Okoń', 'Trudny, bagnisty w niektórych miejscach', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21971, 'Starorzecze Bełcz Wielki 1', 'starorzecze-belcz-wielki-1-glogow-21971', 'OXBOW', 51.6220515, 16.3470211, 'Dolnośląskie', 'Głogów', 'Starorzecze w Bełczu Wielkim to jeden z największych i najgłębszych zbiorników w regionie, z wyraźnym połączeniem z Odrą. Dno jest przeważnie twarde, żwirowo-piaszczyste, z kilkoma głębokimi rynnami, co sprzyja występowaniu sandaczy i innych drapieżników. Brzegi są łatwo dostępne, z licznymi dogodnymi stanowiskami wędkarskimi, otoczone malowniczym lasem łęgowym. Roślinność wodna jest bardzo słaba, co umożliwia swobodne wędkowanie spinningowe i gruntowe bez zaczepów. W wodach tych dominują szczupaki, sandacze, leszcze, płocie i okonie, często osiągające znaczne rozmiary. Stałe połączenie z rzeką zapewnia doskonałe warunki tlenowe i regularne zasilanie w nowe ryby. Jest to idealne miejsce dla wędkarzy poszukujących dużych drapieżników i ceniących komfort.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21971, 7.2, 2.8, 6, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21972, 'Starorzecze Bełcz Wielki 2', 'starorzecze-belcz-wielki-2-glogow-21972', 'OXBOW', 51.6232624, 16.3423264, 'Dolnośląskie', 'Głogów', 'To starorzecze charakteryzuje się bardziej zróżnicowanym środowiskiem niż jego sąsiad, z większą ilością roślinności i mulistych stref. Dno jest mieszane, z twardymi fragmentami i miękkim mułem, szczególnie w płytszych częściach, co sprzyja różnym gatunkom. Brzegi są miejscami trudno dostępne z powodu bagien i zarośli, co wymaga użycia woderów i poszukiwania dogodnych miejscówek. Roślinność wodna jest umiarkowana, tworząc idealne środowisko dla karpi i linów, które znajdują tu obfitość pokarmu. W starorzeczu tym często spotyka się karpie, liny, leszcze, płocie, a także sumy, które migrują z Odry podczas wylewów. Akwen ten jest atrakcyjny dla wędkarzy preferujących spokojniejsze łowiska i poszukujących dużych ryb karpiowatych i sumów. Wymaga jednak cierpliwości i odpowiedniego przygotowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21972, 5.5, 2.2, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Lin,Leszcz,Płoć,Sum', 'Trudny, bagnisty w niektórych zatokach', TRUE, 'Pojedyncze zatopione drzewa', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21973, 'Starorzecze Mozów 1', 'starorzecze-mozow-1-krosno-odrzanskie-21973', 'OXBOW', 52.0459029, 15.5004673, 'Lubuskie', 'Krosno Odrzańskie', 'Starorzecze w Mozowie to typowy, mocno zarośnięty zbiornik, charakteryzujący się dużą ilością roślinności wodnej i brzegowej. Dno jest w większości muliste, z grubą warstwą osadów, co sprzyja rozwojowi bogatej flory podwodnej. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co utrudnia dostęp do wody i wymaga użycia woderów. Silne zarośnięcie stwarza idealne warunki dla lina, karasia pospolitego i wzdręgi, które świetnie czują się w takich środowiskach. Płoć również licznie występuje, adaptując się do gęstych zarośli i znajdując tam schronienie. Z uwagi na płytkość i zamulenie, istnieje podwyższone ryzyko przyduchy w upalne, bezwietrzne dni. Wędkowanie tutaj wymaga precyzji, cierpliwości i odpowiedniego sprzętu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21973, 3, 1.7, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21974, 'Starorzecze Mozów 2', 'starorzecze-mozow-2-krosno-odrzanskie-21974', 'OXBOW', 52.0468755, 15.4980488, 'Lubuskie', 'Krosno Odrzańskie', 'To starorzecze w Mozowie jest nieco bardziej otwarte i mniej zarośnięte niż jego sąsiad, co czyni je atrakcyjnym dla wędkarzy spinningowych. Dno jest zróżnicowane, od twardszych partii piaszczysto-żwirowych po muliste zagłębienia, co sprzyja różnorodności gatunkowej. Brzegi są miejscami łatwo dostępne, z trawiastymi odcinkami przeplatanymi kępami trzcin, ułatwiając zajęcie stanowiska. Roślinność wodna jest umiarkowana, tworząc dobre kryjówki dla drapieżników, takich jak szczupak i okoń. W wodach tych dominują szczupaki i okonie, które aktywnie polują w czystszych partiach zbiornika. Leszcze i płocie również są licznie reprezentowane, stanowiąc bazę pokarmową. Brak stałego połączenia z rzeką oznacza stabilniejsze warunki wodne, choć wahania poziomu wody mogą występować. Jest to dobre miejsce na szybki wypad na ryby, oferujące przyjemne wędkowanie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21974, 2.5, 1.4, 3, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z niektórych stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21975, 'Starorzecze Mozów 3', 'starorzecze-mozow-3-krosno-odrzanskie-21975', 'OXBOW', 52.0475287, 15.4970983, 'Lubuskie', 'Krosno Odrzańskie', 'Trzecie starorzecze w Mozowie to bardzo płytki i silnie zamulony zbiornik, który w upalne lata bywa narażony na wysychanie. Dno jest niemal w całości pokryte grubą warstwą miękkiego mułu, co świadczy o zaawansowanym procesie sukcesji. Brzegi są bagniste i gęsto zarośnięte, co sprawia, że dostęp do wody jest wyjątkowo trudny i konieczne jest użycie woderów. Roślinność podwodna jest bardzo silna, tworząc gęste dywany, w których doskonale czują się karasie pospolite i srebrzyste oraz wzdręgi. Ryzyko przyduchy jest wysokie, co wymaga monitorowania warunków, zwłaszcza w okresie letnim. Jest to łowisko dla wędkarzy poszukujących specyficznych gatunków i gotowych na trudne warunki terenowe oraz wyzwania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21975, 1.8, 1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Karaś srebrzysty,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21976, 'Starorzecze Pomorsko 1', 'starorzecze-pomorsko-1-krosno-odrzanskie-21976', 'OXBOW', 52.0484071, 15.4961116, 'Lubuskie', 'Krosno Odrzańskie', 'Pierwsze starorzecze w Pomorsku to zbiornik o umiarkowanej głębokości i zróżnicowanym dnie, z okresowym połączeniem z rzeką Odrą. Dno jest mieszane, od twardych fragmentów po muliste zagłębienia, co sprzyja różnorodności gatunkowej ryb. Brzegi są częściowo dostępne, z trawiastymi odcinkami i pasmami trzcin, co ułatwia zajęcie dogodnego stanowiska. Roślinność wodna jest umiarkowana, tworząc dobre miejsca do ukrycia się ryb i polowania drapieżników. W wodach tych dominują szczupaki, leszcze, płocie oraz okonie, które są tu licznie reprezentowane i osiągają dobre rozmiary. Połączenie z rzeką podczas wysokiej wody odświeża zbiornik i wzbogaca go o nowe gatunki. Jest to atrakcyjne łowisko dla wędkarzy preferujących różnorodne metody, od spławika po spinning.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21976, 4, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń', 'Dobry z niektórych stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21977, 'Starorzecze Pomorsko 2', 'starorzecze-pomorsko-2-krosno-odrzanskie-21977', 'OXBOW', 52.0505899, 15.4941477, 'Lubuskie', 'Krosno Odrzańskie', 'Drugie starorzecze w Pomorsku to typowy, mocno zarośnięty zbiornik, charakteryzujący się dużą ilością roślinności wodnej i brzegowej. Dno jest w większości muliste, z grubą warstwą osadów, co sprzyja rozwojowi bogatej flory podwodnej. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co utrudnia dostęp do wody i wymaga użycia woderów. Silne zarośnięcie stwarza idealne warunki dla lina, karasia pospolitego i wzdręgi, które świetnie czują się w takich środowiskach. Płoć również licznie występuje, adaptując się do gęstych zarośli i znajdując w nich schronienie. Z uwagi na płytkość i zamulenie, istnieje podwyższone ryzyko przyduchy w upalne, bezwietrzne dni. Wędkowanie tutaj wymaga precyzji, cierpliwości i odpowiedniego sprzętu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21977, 3.2, 1.6, 3.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21978, 'Starorzecze Pomorsko 3', 'starorzecze-pomorsko-3-krosno-odrzanskie-21978', 'OXBOW', 52.0523542, 15.4908475, 'Lubuskie', 'Krosno Odrzańskie', 'Trzecie starorzecze w Pomorsku to bardzo płytki i silnie zamulony zbiornik, który w upalne lata bywa narażony na wysychanie. Dno jest niemal w całości pokryte grubą warstwą miękkiego mułu, co świadczy o zaawansowanym procesie sukcesji. Brzegi są bagniste i gęsto zarośnięte, co sprawia, że dostęp do wody jest wyjątkowo trudny i konieczne jest użycie woderów. Roślinność podwodna jest bardzo silna, tworząc gęste dywany, w których doskonale czują się karasie pospolite i srebrzyste oraz liny. Ryzyko przyduchy jest wysokie, co wymaga monitorowania warunków, zwłaszcza w okresie letnim. Jest to łowisko dla wędkarzy poszukujących specyficznych gatunków i gotowych na trudne warunki terenowe oraz wyzwania. Wędkowanie tutaj to prawdziwa przygoda.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21978, 2, 1.2, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Karaś srebrzysty,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21979, 'Starorzecze Pomorsko 4', 'starorzecze-pomorsko-4-krosno-odrzanskie-21979', 'OXBOW', 52.0522725, 15.4920763, 'Lubuskie', 'Krosno Odrzańskie', 'Czwarte starorzecze w Pomorsku to stosunkowo głęboki zbiornik z dobrym połączeniem z rzeką Odrą, co zapewnia stały dopływ świeżej wody i ryb. Dno jest zróżnicowane, z twardszymi partiami żwirowymi i piaszczystymi, przeplatanymi mulistymi zagłębieniami, co sprzyja różnorodności. Brzegi są łatwo dostępne, z licznymi dogodnymi miejscami do wędkowania, otoczone luźnym drzewostanem, zapewniającym cień. Roślinność wodna jest umiarkowana, skupiona głównie przy brzegach, nie utrudniając w znacznym stopniu wędkowania. W wodach tych dominują szczupaki, sandacze, leszcze, płocie oraz karpie, które często migrują z głównego nurtu rzeki. Akwen ten jest ceniony za stabilne warunki i różnorodność gatunkową, co czyni go atrakcyjnym dla wielu wędkarzy. Jest to idealne miejsce zarówno dla spinningistów, jak i wędkarzy gruntowych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21979, 3.8, 2.3, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze zatopione drzewa', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21980, 'Starorzecze Pomorsko', 'starorzecze-pomorsko-sulechow-21980', 'OXBOW', 52.0487709, 15.4911024, 'Lubuskie', 'Sulechów', 'To malownicze starorzecze, położone w pobliżu Pomorska, charakteryzuje się umiarkowaną wielkością i głębokością, będąc idealnym miejscem dla wędkarzy ceniących spokój. Dno jest przeważnie muliste, z licznymi zatopionymi gałęziami i korzeniami, co stanowi doskonałe kryjówki dla ryb. Brzegi są częściowo zarośnięte trzciną i krzewami, co zapewnia naturalne stanowiska wędkarskie, choć dostęp do niektórych partii może być utrudniony. Wiosną i podczas wysokich stanów wody, starorzecze łączy się z pobliską rzeką Odrą, co sprzyja migracji ryb i wzbogaca populację. Występuje tu bogata roślinność podwodna, szczególnie grążele i moczarka, które są siedliskiem dla wielu gatunków. Wędkarze mogą liczyć na obfite połowy lina, leszcza, płoci oraz drapieżników takich jak szczupak i okoń, które aktywnie żerują w tych wodach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21980, 7.8, 1.8, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Leszcz,Płoć,Szczupak,Okoń', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21981, 'Starorzecze Zaczopki A', 'starorzecze-zaczopki-a-wlodawa-21981', 'OXBOW', 52.1685899, 23.4133406, 'Lubelskie', 'Włodawa', 'Starorzecze Zaczopki A to dziki i urokliwy zbiornik, będący pozostałością po rzece Bug, położony w malowniczej, słabo zaludnionej okolicy. Charakteryzuje się stosunkowo niewielką głębokością i bardzo mulistym dnem, które obfituje w gęstą roślinność podwodną, stanowiącą idealne schronienie dla ryb. Brzegi są mocno zarośnięte trzciną i krzewami, co czyni dostęp do wody wyzwaniem, ale jednocześnie gwarantuje spokój i ciszę. Wędkarze mogą spodziewać się tu przede wszystkim okazałych karasi pospolitych i linów, które doskonale czują się w tych warunkach. Duże okazy szczupaka i suma również są częstymi gośćmi, zwłaszcza w głębszych partiach. Ze względu na bujną roślinność i ograniczony przepływ, w upalne lata istnieje ryzyko przyduchy, co należy wziąć pod uwagę planując wyprawę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21981, 4.5, 1, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Szczupak,Sum', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21982, 'Starorzecze Zaczopki B', 'starorzecze-zaczopki-b-wlodawa-21982', 'OXBOW', 52.168788, 23.4198253, 'Lubelskie', 'Włodawa', 'To starorzecze, podobnie jak jego sąsiedzi, jest częścią rozległego systemu starorzeczy Bugu i oferuje zróżnicowane warunki wędkarskie. Charakteryzuje się średnią głębokością i dnem pokrytym warstwą mułu, miejscami przechodzącym w piaszczyste płaty, co sprzyja różnorodności gatunkowej. Roślinność brzegowa jest gęsta, lecz istnieją liczne, naturalne prześwity, które ułatwiają dostęp do wody i umożliwiają komfortowe wędkowanie. W starorzeczu tym dominują płocie i leszcze, często osiągające imponujące rozmiary, a także wzdręgi, które chętnie żerują wśród podwodnej roślinności. Drapieżniki, takie jak okoń i szczupak, są aktywne przez cały sezon, polując na mniejsze ryby. To doskonałe miejsce dla wędkarzy szukających zarówno ryb spokojnego żeru, jak i emocjonujących pojedynków z drapieżnikami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21982, 6.2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Wzdręga,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21983, 'Starorzecze Zaczopki C', 'starorzecze-zaczopki-c-wlodawa-21983', 'OXBOW', 52.167628, 23.4217822, 'Lubelskie', 'Włodawa', 'Starorzecze Zaczopki C to mniejszy, bardziej intymny zbiornik, który zachował swój dziki charakter, będąc rajem dla wędkarzy ceniących naturę. Jego płytkie wody i bardzo gęsta roślinność podwodna tworzą idealne środowisko dla gatunków preferujących takie warunki. Dno jest w większości bardzo muliste i miękkie, co utrudnia brodzenie, ale jednocześnie sprzyja rozwojowi bogatego ekosystemu. Brzegi są silnie zarośnięte, co wymaga cierpliwości i wysiłku, aby znaleźć dogodne miejsce do zarzucenia wędki. Głównymi mieszkańcami są tutaj karasie pospolite i liny, które osiągają tu imponujące rozmiary. Wzdręgi licznie występują wśród roślinności, a szczupaki często patrolują płytsze partie w poszukiwaniu pokarmu. Ze względu na płytkość i gęste zarośla, latem istnieje wysokie ryzyko niedoboru tlenu, co może wpływać na aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21983, 3.1, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21984, 'Starorzecze Derło', 'starorzecze-derlo-wlodawa-21984', 'OXBOW', 52.1795235, 23.3843658, 'Lubelskie', 'Włodawa', 'Starorzecze Derło to rozległy i zróżnicowany zbiornik, będący dawnym korytem Bugu, oferujący wędkarzom wiele możliwości. Charakteryzuje się zmienną głębokością, z głębszymi rynnami i płytszymi zatokami, co sprzyja różnorodności gatunków ryb. Dno jest mozaiką mułu, piasku i żwiru, a liczne zatopione drzewa i korzenie tworzą doskonałe kryjówki dla drapieżników. Brzegi są dostępne w wielu miejscach, choć lokalnie mogą być zarośnięte, co dodaje uroku dzikości. Jest to doskonałe łowisko dla miłośników szczupaków i sumów, które osiągają tu znaczne rozmiary. Leszcze i płocie również są licznie reprezentowane, a okonie aktywnie żerują w pobliżu podwodnych przeszkód. Starorzecze to jest cenione za duży potencjał na rekordowe okazy i urozmaicony krajobraz.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21984, 11.5, 2.2, 5.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sum,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21985, 'Starorzecze Brodnica A', 'starorzecze-brodnica-a-brodnica-21985', 'OXBOW', 53.2644143, 19.4457376, 'Kujawsko-Pomorskie', 'Brodnica', 'Starorzecze Brodnica A, położone w malowniczej okolicy Pojezierza Brodnickiego, jest częścią dawnego koryta rzeki Drwęcy i wyróżnia się stosunkowo czystą wodą. Charakteryzuje się umiarkowaną głębokością i dnem, które jest mieszanką piasku i delikatnego mułu, co sprzyja rozwojowi zróżnicowanej fauny dennej. Roślinność podwodna jest umiarkowana, ale występują tu kępy moczarki i ramienic, tworzące schronienia dla ryb. Brzegi są w większości łatwo dostępne, z kilkoma miejscami porośniętymi trzciną, co zapewnia dobre stanowiska wędkarskie. Wędkarze mogą liczyć na obfite połowy płoci i leszczy, a także jaźów i kleni, które chętnie żerują w czystszych wodach. Szczupak jest tu również częstym łupem, polującym na mniejsze ryby w pobliżu roślinności. To starorzecze jest idealne dla wędkarzy ceniących sobie zarówno spokój, jak i możliwość złowienia różnorodnych gatunków ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21985, 5.7, 1.7, 3.8, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Płoć,Leszcz,Jaź,Kleń,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21986, 'Starorzecze Hrubieszów', 'starorzecze-hrubieszow-hrubieszow-21986', 'OXBOW', 50.802933, 23.8731805, 'Lubelskie', 'Hrubieszów', 'Starorzecze Hrubieszów to żyzny i bogaty w składniki odżywcze zbiornik, będący reliktem dawnego koryta rzeki Bug lub Huczwy, położony w pobliżu miasta. Charakteryzuje się umiarkowaną głębokością i bardzo produktywnym, mulistym dnem, które jest idealne dla gatunków preferujących takie warunki. Roślinność brzegowa jest gęsta, składająca się głównie z trzcin i pałek wodnych, co tworzy liczne kryjówki i utrudnia dostęp do wody w niektórych miejscach. Jest to prawdziwy raj dla wędkarzy poszukujących karpia i lina, które osiągają tu imponujące rozmiary. Karasie pospolite i leszcze również są bardzo liczne, stanowiąc podstawę populacji ryb spokojnego żeru. Szczupak jest dominującym drapieżnikiem, aktywnie polującym w zaroślach. To starorzecze jest znane z obfitości ryb i wymaga cierpliwości w poszukiwaniu odpowiedniego stanowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21986, 9.3, 1.9, 4.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karp,Lin,Karaś pospolity,Leszcz,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21987, 'Starorzecze Baranów', 'starorzecze-baranow-pulawy-21987', 'OXBOW', 51.5676049, 22.1322834, 'Lubelskie', 'Puławy', 'Starorzecze Baranów to duży i zróżnicowany zbiornik, będący częścią rozległego systemu starorzeczy Wisły, położony niedaleko Puław. Charakteryzuje się znaczną głębokością w niektórych partiach oraz dnem, które oferuje mozaikę mułu, piasku i twardych gliniastych fragmentów, co sprzyja różnorodności gatunkowej. Brzegi są w większości dostępne, choć miejscami porośnięte drzewami i krzewami, tworząc naturalne zacienione stanowiska. Jest to doskonałe łowisko dla miłośników leszczy i płoci, które występują tu w dużych ilościach. Sandacz i sum są głównymi drapieżnikami, często polującymi w głębszych wodach i przy zatopionych przeszkodach. Węgorz również jest obecny, co świadczy o dobrej jakości wody i połączeniu z systemem rzecznym. Wędkowanie tutaj wymaga znajomości dna i cierpliwości, ale może przynieść spektakularne efekty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21987, 14, 2.5, 6, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Sandacz,Sum,Węgorz', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21988, 'Starorzecze Osiecznica', 'starorzecze-osiecznica-boleslawiec-21988', 'OXBOW', 51.3152562, 15.425204, 'Dolnośląskie', 'Bolesławiec', 'Starorzecze Osiecznica, położone w malowniczej okolicy Dolnego Śląska, to urokliwy zbiornik będący pozostałością po rzece Kwisie lub Bobrze. Wyróżnia się stosunkowo czystą wodą i dnem, które jest mieszanką piasku i drobnego żwiru, z mniejszą ilością mułu niż w typowych starorzeczach. Roślinność podwodna jest umiarkowana, co ułatwia prowadzenie przynęt, ale jednocześnie zapewnia wystarczające schronienia dla ryb. Brzegi są w większości łatwo dostępne, z miejscowymi zaroślami, które dodają uroku dzikości. W starorzeczu tym dominują płocie i okonie, które aktywnie żerują w czystej wodzie. Szczupak jest również częstym mieszkańcem, polującym na mniejsze ryby. Boleń i jaź, typowe dla rzek, również pojawiają się tu, zwłaszcza po okresach wysokiej wody, co świadczy o dobrej łączności z głównym nurtem. To idealne miejsce dla wędkarzy ceniących sobie aktywny połów i różnorodność gatunkową.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21988, 6.5, 1.6, 3.5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Płoć,Okoń,Szczupak,Boleń,Jaź', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21989, 'Starorzecze Burzenin', 'starorzecze-burzenin-sieradz-21989', 'OXBOW', 51.4637692, 18.8393677, 'Łódzkie', 'Sieradz', 'Starorzecze Burzenin, leżące w dorzeczu Warty, to żyzny zbiornik o typowo starorzecznym charakterze, ceniony przez wędkarzy za obfitość ryb spokojnego żeru. Charakteryzuje się umiarkowaną głębokością i miękkim, mulistym dnem, które jest bogate w substancje odżywcze, sprzyjające rozwojowi bujnej roślinności wodnej. Brzegi są częściowo zarośnięte trzciną i krzewami, co zapewnia naturalne stanowiska, ale wymaga cierpliwości w poszukiwaniu dogodnych miejsc do wędkowania. W tym starorzeczu dominują leszcze i płocie, często osiągające znaczne rozmiary, a także liny i karasie pospolite, które doskonale czują się w zaroślach. Karpie również są obecne, stanowiąc wyzwanie dla wędkarzy. Jest to idealne miejsce dla miłośników spławika i gruntu, gdzie można cieszyć się spokojem i pięknem natury, a także szansą na złowienie naprawdę dużych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21989, 8.1, 1.5, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Leszcz,Płoć,Lin,Karaś pospolity,Karp', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21990, 'Starorzecze Brodnica B', 'starorzecze-brodnica-b-brodnica-21990', 'OXBOW', 53.2335975, 19.360493, 'Kujawsko-Pomorskie', 'Brodnica', 'Starorzecze Brodnica B to mniejszy, bardziej intymny zbiornik, położony w kompleksie starorzeczy Drwęcy w okolicach Brodnicy, idealny dla wędkarzy szukających ustronnych miejsc. Charakteryzuje się stosunkowo płytką wodą i dnem, które jest mieszanką mułu i piasku, z licznymi kępami roślinności podwodnej. Brzegi są gęsto porośnięte krzewami i trzciną, co nadaje miejscu dziki charakter i wymaga od wędkarza cierpliwości w poszukiwaniu dogodnych stanowisk. Jest to doskonałe łowisko dla linów i karasi pospolitych, które doskonale czują się w zaroślach. Wzdręgi licznie występują wśród roślinności, a szczupak jest dominującym drapieżnikiem, często polującym w płytszych partiach. Ze względu na swój charakter, starorzecze to jest szczególnie atrakcyjne w okresie wiosennym i wczesnojesiennym, gdy ryby intensywnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21990, 3.8, 1.1, 2.5, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21991, 'Starorzecze Brodnica C', 'starorzecze-brodnica-c-brodnica-21991', 'OXBOW', 53.233858, 19.3612751, 'Kujawsko-Pomorskie', 'Brodnica', 'To niewielkie starorzecze, zlokalizowane w sąsiedztwie innych zbiorników w okolicach Brodnicy, stanowi urokliwe miejsce dla szybkiego wypadu na ryby. Charakteryzuje się płytką i stosunkowo czystą wodą, z dnem pokrytym piaskiem i miejscowymi skupiskami mułu. Roślinność podwodna jest umiarkowana, co sprzyja aktywnemu wędkowaniu, a brzegi są dość łatwo dostępne, choć miejscami można natknąć się na pojedyncze zarośla. W starorzeczu tym dominują płocie i okonie, które chętnie żerują w czystej wodzie. Wzdręgi licznie występują wśród rzadkiej roślinności, a szczupak jest drapieżnikiem, który często patroluje płytsze partie. Jest to idealne miejsce dla wędkarzy preferujących lżejszy sprzęt i poszukujących ryb aktywnie żerujących. Krótki czas połączenia z Drwęcą podczas wysokiej wody zapewnia regularne zarybienie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21991, 2.5, 0.9, 2, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Płoć,Okoń,Wzdręga,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21992, 'Starorzecze Mszano A', 'starorzecze-mszano-a-mszano-21992', 'OXBOW', 53.2322072, 19.3591783, 'Kujawsko-Pomorskie', 'Mszano', 'Starorzecze Mszano A to średniej wielkości zbiornik, położony w pobliżu wsi Mszano, w kompleksie starorzeczy Drwęcy, oferujący zróżnicowane warunki wędkarskie. Charakteryzuje się dobrą zmiennością głębokości, z głębszymi rynnami i płytszymi zatokami, co sprzyja różnorodności gatunków ryb. Dno jest mieszanką mułu i piasku, z lokalnymi skupiskami podwodnej roślinności, tworzącej kryjówki. Brzegi są w większości łatwo dostępne, z kilkoma miejscami porośniętymi trzciną, co zapewnia naturalne stanowiska wędkarskie. Wędkarze mogą liczyć na obfite połowy leszczy i płoci, często osiągających imponujące rozmiary. Liny i okonie również są licznie reprezentowane, a szczupak jest dominującym drapieżnikiem, aktywnie polującym w zaroślach. To starorzecze jest cenione za swój potencjał na rekordowe okazy i urozmaicony krajobraz, idealny na dłuższe wyprawy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21992, 7.1, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Lin,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21993, 'Starorzecze Mszano B', 'starorzecze-mszano-b-mszano-21993', 'OXBOW', 53.2310894, 19.3569316, 'Kujawsko-Pomorskie', 'Mszano', 'Starorzecze Mszano B to ustronny i dziki zbiornik, położony w zacisznej okolicy niedaleko Mszana, idealny dla wędkarzy poszukujących spokoju i bliskości natury. Charakteryzuje się płytką wodą i bardzo mulistym dnem, które obfituje w gęstą roślinność podwodną, stanowiącą doskonałe schronienie dla ryb. Brzegi są mocno zarośnięte trzciną i krzewami, co czyni dostęp do wody wyzwaniem, ale jednocześnie gwarantuje ciszę i brak tłumów. Wędkarze mogą spodziewać się tu przede wszystkim okazałych linów i karasi pospolitych, które doskonale czują się w tych warunkach. Duże okazy szczupaka i okonia również są częstymi gośćmi, zwłaszcza w głębszych, bardziej otwartych partiach. Ze względu na bujną roślinność i ograniczony przepływ, w upalne lata istnieje ryzyko przyduchy, co należy wziąć pod uwagę planując wyprawę. Jest to miejsce dla prawdziwych pasjonatów, gotowych na wyzwania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21993, 4.1, 1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21994, 'Starorzecze Trzebicz', 'starorzecze-trzebicz-drezdenko-21994', 'OXBOW', 52.8390886, 15.7730413, 'Lubuskie', 'Drezdenko', 'Starorzecze Trzebicz to duży i zróżnicowany zbiornik, będący częścią dawnego koryta rzeki Noteć lub Warty, położony w malowniczej okolicy Drezdenka. Charakteryzuje się znaczną głębokością w niektórych partiach oraz dnem, które oferuje mozaikę mułu, piasku i twardych gliniastych fragmentów, co sprzyja różnorodności gatunkowej. Brzegi są w większości dostępne, choć miejscami porośnięte drzewami i krzewami, tworząc naturalne zacienione stanowiska. Jest to doskonałe łowisko dla miłośników leszczy i płoci, które występują tu w dużych ilościach. Szczupak i sandacz są głównymi drapieżnikami, często polującymi w głębszych wodach i przy zatopionych przeszkodach. Węgorz również jest obecny, co świadczy o dobrej jakości wody i połączeniu z systemem rzecznym. To starorzecze jest cenione za duży potencjał na rekordowe okazy i urozmaicony krajobraz, idealny na dłuższe wyprawy wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21994, 12, 2.3, 5.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Sandacz,Węgorz', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21995, 'Starorzecze (Trzebicz)', 'starorzecze-trzebicz-trzebicz-21995', 'OXBOW', 52.8297423, 15.7642596, 'Lubuskie', 'Trzebicz', 'Średniej wielkości starorzecze o charakterystycznym, wydłużonym kształcie, typowym dla dawnych meandrów Warty. Dno jest muliste, z licznymi zatopionymi gałęziami i trawami podwodnymi, co stanowi doskonałe schronienie dla ryb. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je gęsta trzcina i krzewy, utrudniające dojście do wody. Wiosną i jesienią woda jest stosunkowo czysta, latem jednak może pojawić się zakwit glonów. Jest to idealne miejsce dla wędkarzy poszukujących lina, karasia pospolitego oraz szczupaka. Należy uważać na liczne zaczepy, które mogą utrudniać wędkowanie. Wymaga to często użycia mocniejszego sprzętu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21995, 3.2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, miejscami zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21996, 'Starorzecze (Trzebicz)', 'starorzecze-trzebicz-trzebicz-21996', 'OXBOW', 52.8263341, 15.7630634, 'Lubuskie', 'Trzebicz', 'To starorzecze leży w bezpośrednim sąsiedztwie poprzedniego, tworząc z nim częściowy system połączonych akwenów podczas wysokiego stanu wody. Charakteryzuje się bardziej otwartymi brzegami po jednej stronie, co ułatwia dostęp wędkarzom. Dno jest tu nieco twardsze, piaszczysto-muliste, z rzadziej występującymi zaczepami, choć wciąż obecnymi. Woda jest zazwyczaj czystsza, co sprzyja rozwojowi populacji okonia i leszcza. Roślinność podwodna jest umiarkowana, ale wzdłuż brzegów rosną kępy trzcin i pałki wodnej. Jest to łowisko o dużym potencjale, zwłaszcza dla miłośników spławika i lekkiej gruntówki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21996, 2.8, 1.8, 3.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Okoń,Leszcz,Płoć,Szczupak', 'Dobry z jednej strony, zarośnięty z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21997, 'Starorzecze (Trzebicz)', 'starorzecze-trzebicz-trzebicz-21997', 'OXBOW', 52.8216015, 15.7602337, 'Lubuskie', 'Trzebicz', 'Niewielkie, płytkie starorzecze, które jest silnie narażone na wysychanie w upalne lata. Jego dno jest w całości pokryte grubą warstwą mułu, co utrudnia wędkowanie i sprzyja bujnej roślinności podwodnej. Brzegi są bagniste i całkowicie zarośnięte, co sprawia, że dostęp do wody jest niezwykle trudny. Mimo tych trudności, jest to ostoją dla karasia pospolitego i wzdręgi, które doskonale radzą sobie w takich warunkach. Wędkowanie wymaga cierpliwości i specjalistycznego sprzętu, często z użyciem pontonu lub brodzenia w woderach. Ryzyko przyduchy jest wysokie, zwłaszcza zimą pod lodem, co wpływa na populację ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21997, 1.1, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21998, 'Starorzecze (Trzebicz)', 'starorzecze-trzebicz-trzebicz-21998', 'OXBOW', 52.8193906, 15.7603088, 'Lubuskie', 'Trzebicz', 'To malownicze starorzecze charakteryzuje się dość regularnym kształtem i umiarkowaną głębokością, co czyni je atrakcyjnym dla wielu gatunków ryb. Dno jest zróżnicowane, od twardych, piaszczystych fragmentów po bardziej muliste zatoczki, gdzie gromadzą się liny i karasie. Brzegi są przeważnie stabilne, choć miejscami występują kępy trzcin, oferujące schronienie dla drobnicy i drapieżników. Woda jest zazwyczaj klarowna, co sprzyja obserwacji żerujących ryb. Jest to łowisko o dużym potencjale, zwłaszcza dla wędkarzy spławikowych i spinningowych, poszukujących szczupaków. Wymaga to jednak precyzyjnego rzutu ze względu na lokalne zarośla.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21998, 2, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (21999, 'Starorzecze (Trzebicz)', 'starorzecze-trzebicz-trzebicz-21999', 'OXBOW', 52.8183741, 15.7620234, 'Lubuskie', 'Trzebicz', 'Długie i wąskie starorzecze, które w przeszłości było głównym nurtem rzeki, co widać po jego wyprofilowaniu. Dno jest tu twarde, piaszczysto-żwirowe w części środkowej, z mulistymi zatokami przy brzegach. Brzegi są wysokie i stabilne, porośnięte starymi drzewami, które tworzą zacienione miejsca i potencjalne zaczepy. Woda jest dobrze natleniona, nawet latem, dzięki sporadycznym połączeniom z głównym nurtem rzeki podczas większych wezbrań. Jest to doskonałe miejsce dla boleni, jazi i kleni, które polują na drobną rybę. Występują tu również sandacze, co podnosi atrakcyjność łowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (21999, 4.5, 2.5, 5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Boleń,Jaź,Kleń,Sandacz,Okoń', 'Dobry, miejscami utrudniony przez drzewa', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22000, 'Starorzecze (Głęboczek)', 'starorzecze-gleboczek-gleboczek-22000', 'OXBOW', 52.8494178, 15.7691198, 'Lubuskie', 'Głęboczek', 'To starorzecze, położone w pobliżu miejscowości Głęboczek, charakteryzuje się znaczną głębokością w centralnej części, co jest rzadkością w tego typu akwenach. Dno jest zróżnicowane, od piaszczystych płycizn po głębokie, muliste rynny, będące ostoją dla większych ryb. Brzegi są strome i częściowo zadrzewione, co zapewnia cień i kryjówki. Woda jest zazwyczaj czysta, a poziom natlenienia dobry, co sprzyja zdrowej populacji ryb. Jest to idealne miejsce dla wędkarzy poszukujących dużych leszczy, karpi, a także sumów, które znajdują tu dogodne warunki do życia. Dostęp do wody jest dobry w kilku wyznaczonych miejscach, co ułatwia komfortowe wędkowanie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22000, 6, 3, 6.5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Karp,Sum,Sandacz,Płoć', 'Dobry w wyznaczonych miejscach', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22001, 'Starorzecze (Górzyska)', 'starorzecze-gorzyska-gorzyska-22001', 'OXBOW', 52.851381, 15.7707828, 'Lubuskie', 'Górzyska', 'To niewielkie starorzecze w okolicach Górzysk jest typowym przykładem płytkiego zbiornika, który ulega powolnemu zarastaniu. Dno jest w większości muliste, z gęstą roślinnością podwodną, taką jak rogatek i wywłócznik, co utrudnia wędkowanie. Brzegi są mocno zarośnięte trzciną i krzewami, co wymaga użycia woderów lub szukania nielicznych, otwartych stanowisk. Jest to jednak raj dla karasi pospolitych, linów i wzdręg, które doskonale czują się w takich warunkach. Wędkowanie tutaj wymaga cierpliwości i precyzji, ale może przynieść satysfakcjonujące rezultaty w postaci pięknych okazów. Ryzyko przyduchy jest wysokie, zwłaszcza w okresach upałów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22001, 1.5, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22002, 'Starorzecze (Głęboczek)', 'starorzecze-gleboczek-gleboczek-22002', 'OXBOW', 52.8512417, 15.764029, 'Lubuskie', 'Głęboczek', 'Starorzecze to charakteryzuje się średnią głębokością i umiarkowanym zarośnięciem, co czyni je atrakcyjnym łowiskiem dla wielu gatunków ryb. Dno jest mieszane, z przewagą mułu, ale z twardszymi fragmentami wzdłuż dawnego nurtu. Brzegi są dostępne w wielu miejscach, choć lokalnie mogą występować kępy trzcin. Woda jest zazwyczaj klarowna, a jej natlenienie jest stabilne dzięki podziemnym źródłom lub okresowym połączeniom z rzeką. Jest to dobre miejsce na szczupaka, okonia oraz leszcza, które często żerują w tych wodach. Wędkarze spławikowi i gruntowi znajdą tu swoje ulubione stanowiska, oferujące komfortowe warunki do połowu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22002, 3.8, 1.9, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Lin', 'Dobry, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22003, 'Starorzecze (Głęboczek)', 'starorzecze-gleboczek-gleboczek-22003', 'OXBOW', 52.8488318, 15.7587612, 'Lubuskie', 'Głęboczek', 'To starorzecze jest częścią większego kompleksu wodnego w pobliżu Głęboczka, charakteryzującego się bogatą bioróżnorodnością. Dno jest głównie muliste, ale z twardymi, piaszczystymi blatami w pobliżu brzegów, gdzie woda jest płytsza. Brzegi są w większości łatwo dostępne, choć w niektórych miejscach występują pojedyncze krzewy i drzewa, dające cień. Woda jest regularnie zasilana, co zapewnia dobre natlenienie i ogranicza ryzyko przyduchy. Jest to doskonałe miejsce na karasia srebrzystego, leszcza i płocie, a także sporadycznie karpia. Wędkowanie jest tu komfortowe, a ryby często aktywnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22003, 2.5, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karaś srebrzysty,Leszcz,Płoć,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22004, 'Starorzecze (Głęboczek)', 'starorzecze-gleboczek-gleboczek-22004', 'OXBOW', 52.8445937, 15.7527959, 'Lubuskie', 'Głęboczek', 'Długie i stosunkowo płytkie starorzecze, które w okresach suszy może znacząco zmniejszyć swoją powierzchnię. Dno jest w przeważającej części pokryte grubą warstwą mułu, co sprzyja rozwojowi bujnej roślinności wodnej, takiej jak lilie wodne i moczarka. Brzegi są bagniste i trudno dostępne, wymagające użycia woderów lub pontonu do skutecznego wędkowania. Mimo trudności, jest to ostoja dla lina, karasia pospolitego i wzdręgi, które doskonale adaptują się do tych warunków. Ryzyko niedoboru tlenu jest wysokie, szczególnie latem i zimą, co należy brać pod uwagę planując wyprawę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22004, 2.1, 1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22005, 'Starorzecze (Głęboczek)', 'starorzecze-gleboczek-gleboczek-22005', 'OXBOW', 52.8462023, 15.7529032, 'Lubuskie', 'Głęboczek', 'To starorzecze jest połączone z poprzednim systemem wodnym, ale charakteryzuje się nieco większą głębokością i mniejszym zarośnięciem. Dno jest zróżnicowane, z mulistymi zatokami i twardszymi, piaszczystymi fragmentami w centralnej części. Brzegi są częściowo dostępne, z pojedynczymi drzewami i krzewami, które zapewniają cień. Woda jest zazwyczaj przejrzysta, a jej natlenienie jest dobre, co sprzyja różnorodności gatunkowej. Jest to dobre miejsce na szczupaka, okonia i leszcza. Wędkarze mogą tu liczyć na udane połowy, szczególnie wczesną wiosną i jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22005, 2.7, 1.5, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z jednej strony, zarośnięty z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22006, 'Starorzecze (Trzebicz)', 'starorzecze-trzebicz-trzebicz-22006', 'OXBOW', 52.8209967, 15.7472571, 'Lubuskie', 'Trzebicz', 'To starorzecze w pobliżu Trzebicza jest niewielkim, ale głębokim zbiornikiem, który stanowi doskonałą kryjówkę dla drapieżników. Dno jest w dużej mierze muliste, ale z licznymi zatopionymi drzewami i korzeniami, co tworzy idealne siedliska dla ryb. Brzegi są strome i zarośnięte, co utrudnia dostęp, ale jednocześnie zapewnia spokój i ciszę. Woda jest zazwyczaj ciemna i dobrze natleniona, sprzyjając dużym okazom. Jest to wymarzone miejsce dla wędkarzy poszukujących sumów i dużych szczupaków, które często tu żerują. Wędkowanie z pontonu jest zalecane, aby dotrzeć do najlepszych miejscówek.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22006, 1.8, 2.2, 4.5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Okoń,Lin', 'Trudny, zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22007, 'Starorzecze (Trzebicz)', 'starorzecze-trzebicz-trzebicz-22007', 'OXBOW', 52.822655, 15.7543597, 'Lubuskie', 'Trzebicz', 'To starorzecze charakteryzuje się otwartymi brzegami i stosunkowo czystym dnem, co ułatwia wędkowanie z brzegu. Dno jest piaszczysto-muliste, z niewielką ilością roślinności podwodnej, co sprzyja drapieżnikom polującym na otwartej wodzie. Brzegi są łatwo dostępne, z nielicznymi kępami trzcin, które stanowią schronienie dla mniejszych ryb. Woda jest dobrze natleniona i zazwyczaj klarowna, co sprzyja widoczności. Jest to idealne miejsce dla wędkarzy poszukujących okoni, płoci oraz leszczy, a także mniejszych szczupaków. Można tu liczyć na aktywne żerowanie ryb przez większość sezonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22007, 3, 1.7, 3.3, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Okoń,Płoć,Leszcz,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22008, 'Starorzecze (Santok)', 'starorzecze-santok-santok-22008', 'OXBOW', 52.7425735, 15.4593915, 'Lubuskie', 'Santok', 'Duże i rozległe starorzecze w pobliżu Santoka, które zachowało wiele cech dawnego nurtu rzeki. Dno jest zróżnicowane, od piaszczysto-żwirowych płycizn po głębokie rynny z mulistym dnem, idealne dla dużych ryb. Brzegi są w większości stabilne i dostępne, z nielicznymi zaroślami trzcinowymi. Woda jest dobrze natleniona i często zasilana przez podziemne źródła, co sprzyja rozwojowi bogatej fauny. Jest to doskonałe łowisko dla leszczy, karpi, sumów i sandaczy, a także boleni. Wędkowanie jest tu bardzo urozmaicone, oferując szansę na złowienie wielu gatunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22008, 8.5, 2.8, 6, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Karp,Sum,Sandacz,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22009, 'Starorzecze (Ludzisławice)', 'starorzecze-ludzislawice-ludzislawice-22009', 'OXBOW', 52.7393209, 15.4845651, 'Lubuskie', 'Ludzisławice', 'To starorzecze, położone niedaleko Ludzisławic, jest przykładem akwenu o umiarkowanym stopniu zarośnięcia i zróżnicowanej głębokości. Dno jest piaszczysto-muliste, z licznymi zagłębieniami i podwodnymi górkami, które są atrakcyjne dla ryb. Brzegi są częściowo dostępne, choć w niektórych miejscach występują gęste zarośla i trzciny. Woda jest zazwyczaj klarowna, a jej natlenienie jest dobre, co sprzyja rozwojowi populacji ryb. Jest to dobre miejsce na szczupaka, okonia, lina oraz karasia pospolitego. Wędkarze spławikowi i spinningowi znajdą tu wiele ciekawych stanowisk, oferujących zróżnicowane możliwości połowu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22009, 4, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Lin,Karaś pospolity,Płoć', 'Dobry, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22010, 'Starorzecze w Makowie Podhalańskim 1', 'starorzecze-w-makowie-podhalanskim-1-makow-podhalanski-22010', 'OXBOW', 49.7303364, 19.6375239, 'Małopolskie', 'Maków Podhalański', 'To malownicze starorzecze, zlokalizowane w dolinie rzeki Skawy, oferuje spokojne warunki do wędkowania. Dno jest muliste z miejscowymi twardymi plackami, co sprzyja bytności lina i karasia. Brzegi są częściowo dostępne, ale w wielu miejscach porasta je gęsta trzcina i krzewy, utrudniające podejście. Roślinność podwodna jest umiarkowana, tworząc schronienie dla drapieżników takich jak szczupak i okoń. Wiosną i jesienią, gdy roślinność nie jest jeszcze tak bujna, łowisko jest najbardziej atrakcyjne. Należy jednak pamiętać o ryzyku przyduchy w upalne lata, co może wpływać na aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22010, 2.8, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Okoń,Płoć', 'Dobry z jednej strony, reszta zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22011, 'Starorzecze w Makowie Podhalańskim 2', 'starorzecze-w-makowie-podhalanskim-2-makow-podhalanski-22011', 'OXBOW', 49.7300046, 19.6384834, 'Małopolskie', 'Maków Podhalański', 'To niewielkie starorzecze charakteryzuje się wysokim poziomem zamulenia i silnym zarośnięciem, co czyni je idealnym siedliskiem dla karasi i linów. Dno jest w przeważającej części miękkie i muliste, z licznymi zatopionymi roślinami. Brzegi są trudnodostępne, często bagniste i gęsto porośnięte trzciną, co wymaga użycia wodoodpornych spodni. Mimo trudności, w cieplejszych miesiącach, zwłaszcza późną wiosną i latem, można liczyć na obfite brania. Należy liczyć się z koniecznością dokładnego sondowania łowiska i precyzyjnego zarzucania zestawu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22011, 1.9, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22012, 'Starorzecze w Makowie Podhalańskim 3', 'starorzecze-w-makowie-podhalanskim-3-makow-podhalanski-22012', 'OXBOW', 49.7292521, 19.636488, 'Małopolskie', 'Maków Podhalański', 'To średniej wielkości starorzecze, o bardziej otwartym charakterze niż sąsiednie, oferuje komfortowe warunki wędkowania. Dno jest zróżnicowane, z przewagą twardszych partii i miejscowymi osadami mułu, co sprzyja bytności leszczy i płoci. Brzegi są łatwo dostępne z obu stron, co ułatwia wybór stanowiska i swobodne poruszanie się. Roślinność podwodna nie jest zbyt gęsta, co pozwala na swobodne prowadzenie zestawów i minimalizuje ryzyko zaczepów. Połączenie z rzeką podczas wysokiej wody zapewnia regularne zarybienia, co przekłada się na dobrą populację ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22012, 3.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22013, 'Starorzecze w Makowie Podhalańskim 4', 'starorzecze-w-makowie-podhalanskim-4-makow-podhalanski-22013', 'OXBOW', 49.7298915, 19.6290374, 'Małopolskie', 'Maków Podhalański', 'To płytkie i silnie zarośnięte starorzecze jest wyzwaniem dla wędkarzy, ale jednocześnie kryje w sobie obfitość karasi i wzdręg. Dno jest niemal w całości pokryte grubą warstwą mułu i gęstą roślinnością, co wymaga stosowania specjalistycznych technik. Brzegi są niezwykle trudne do pokonania, porośnięte wysoką trzciną i bagniste, co zmusza do użycia wodoodpornych spodni. W upalne lata istnieje ryzyko całkowitego wyschnięcia zbiornika, dlatego najlepszym okresem na wędkowanie jest wiosna. Mimo trudności, doświadczeni wędkarze cenią to miejsce za dziki charakter i możliwość złowienia pięknych, dzikich karasi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22013, 2.1, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22014, 'Starorzecze w Makowie Podhalańskim 5', 'starorzecze-w-makowie-podhalanskim-5-makow-podhalanski-22014', 'OXBOW', 49.7308867, 19.6384466, 'Małopolskie', 'Maków Podhalański', 'To jedno z większych i lepiej utrzymanych starorzeczy w okolicy, charakteryzujące się stałym połączeniem z rzeką Skawą. Dzięki temu połączeniu, woda jest dobrze natleniona, a populacja ryb jest zróżnicowana i liczna, obejmując szczupaki, leszcze i jazie. Dno jest w większości twarde, piaszczysto-żwirowe, z niewielkimi osadami mułu, co ułatwia wędkowanie. Brzegi są łatwo dostępne i zadbane, idealne do rodzinnych wypadów. Roślinność podwodna jest znikoma, co minimalizuje ryzyko zaczepów i pozwala na swobodne użycie różnych technik. To łowisko jest atrakcyjne przez cały sezon, oferując stabilne warunki i dobre brania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22014, 4, 2, 4, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Płoć,Jaź', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22015, 'Starorzecze w Makowie Podhalańskim 6', 'starorzecze-w-makowie-podhalanskim-6-makow-podhalanski-22015', 'OXBOW', 49.7306071, 19.636871, 'Małopolskie', 'Maków Podhalański', 'To starorzecze o umiarkowanej wielkości, zlokalizowane w malowniczej okolicy, oferuje typowe warunki dla tego typu zbiorników. Dno jest muliste, z licznymi zatopionymi roślinami, co sprzyja bytności ryb spokojnego żeru, takich jak lin i karaś pospolity. Brzegi są miejscami trudne do podejścia, bagniste i porośnięte krzewami, co wymaga użycia wodoodpornych spodni. Roślinność podwodna jest umiarkowana, tworząc naturalne kryjówki dla okoni i wzdręg. Połączenie z rzeką podczas wysokiej wody odświeża wodę, ale latem istnieje ryzyko niedoboru tlenu. Najlepsze wyniki można osiągnąć wiosną i wczesnym latem, zanim roślinność osiągnie pełną bujność.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22015, 2.3, 1.4, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Okoń,Wzdręga', 'Trudny, miejscami bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22016, 'Starorzecze w Pilchowicach', 'starorzecze-w-pilchowicach-pilchowice-22016', 'OXBOW', 50.965238, 15.6403719, 'Dolnośląskie', 'Pilchowice', 'To rozległe starorzecze w pobliżu Pilchowic, charakteryzujące się stałym połączeniem z rzeką Bóbr, co zapewnia doskonałe warunki dla różnorodnych gatunków ryb. Dno jest zróżnicowane, z przewagą piasku i żwiru, a także miejscowymi osadami mułu, co sprzyja bytności drapieżników takich jak szczupak, okoń i sandacz. Brzegi są łatwo dostępne z obu stron, z licznymi wygodnymi stanowiskami dla wędkarzy. Roślinność podwodna jest słaba, co ułatwia prowadzenie przynęt i minimalizuje ryzyko zaczepów. Dzięki stałemu przepływowi wody, ryzyko niedoboru tlenu jest niskie, co czyni to łowisko atrakcyjnym przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22016, 5.5, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Sandacz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22017, 'Starorzecze w Zembrzycach 1', 'starorzecze-w-zembrzycach-1-zembrzyce-22017', 'OXBOW', 49.7667576, 19.5972937, 'Małopolskie', 'Zembrzyce', 'To starorzecze w Zembrzycach, usytuowane w malowniczej okolicy, stanowi typowe łowisko dla miłośników spokojnego żeru i drapieżników. Dno jest muliste z licznymi zatopionymi roślinami, tworzącymi idealne schronienie dla linów i karasi pospolitych. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je gęsta roślinność, wymagająca użycia wodoodpornych spodni. Roślinność podwodna jest umiarkowana, co sprzyja bytności szczupaków i okoni. Połączenie z rzeką podczas wysokiej wody odświeża zbiornik, ale w upalne lato należy liczyć się z ryzykiem niedoboru tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22017, 3, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Częściowo dostępny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22018, 'Starorzecze w Zembrzycach 2', 'starorzecze-w-zembrzycach-2-zembrzyce-22018', 'OXBOW', 49.7763846, 19.592052, 'Małopolskie', 'Zembrzyce', 'To mniejsze starorzecze w Zembrzycach charakteryzuje się wysokim poziomem zamulenia i gęstą roślinnością, co czyni je ostoją dla karasi i wzdręg. Dno jest miękkie i bardzo muliste, z licznymi podwodnymi zaroślami, które stanowią wyzwanie dla wędkarzy. Brzegi są niemal niedostępne, bagniste i silnie zarośnięte trzciną, co wymaga dużej determinacji i odpowiedniego sprzętu. Brak połączenia z rzeką zwiększa ryzyko niedoboru tlenu w cieplejszych miesiącach. Mimo trudności, wędkarze poszukujący dzikich karasi i wzdręg znajdą tu satysfakcję, szczególnie w okresie od późnej wiosny do lata.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22018, 2.2, 1.3, 2.7, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22019, 'Starorzecze w Ostrowie', 'starorzecze-w-ostrowie-ostrow-22019', 'OXBOW', 51.7676553, 21.4375591, 'Mazowieckie', 'Ostrów', 'To spore starorzecze w okolicach Ostrowa na Mazowszu, znane z obfitości ryb drapieżnych i spokojnego żeru, takich jak szczupaki, karpie i sumy. Dno jest zróżnicowane, z głębszymi rynienkami i licznymi zatopionymi drzewami, które stanowią doskonałe kryjówki dla ryb. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je gęsta roślinność, co wymaga użycia wodoodpornych spodni. Roślinność podwodna jest umiarkowana, tworząc idealne warunki do zasadzek drapieżników. Połączenie z rzeką podczas wysokiej wody sprzyja migracjom ryb i utrzymuje dobrą jakość wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22019, 6, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Karp,Sum', 'Dobry z jednej strony, reszta zarośnięta', TRUE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22020, 'Starorzecze w Komorowie', 'starorzecze-w-komorowie-komorow-22020', 'OXBOW', 50.3654195, 21.109278, 'Podkarpackie', 'Komorów', 'To starorzecze w Komorowie, choć pozbawione stałego połączenia z rzeką, oferuje urokliwe warunki dla wędkarzy ceniących spokój. Dno jest muliste z licznymi zatopionymi roślinami, co sprzyja bytności linów i karasi pospolitych. Brzegi są miejscami trudne do podejścia, porośnięte gęstą roślinnością i krzewami, co wymaga użycia wodoodpornych spodni. Roślinność podwodna jest umiarkowana, tworząc naturalne kryjówki dla okoni i wzdręg. W upalne lata istnieje ryzyko niedoboru tlenu, dlatego najlepszym okresem na wędkowanie jest późna wiosna i wczesne lato.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22020, 4.2, 1.8, 3.8, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Trudny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22021, 'Starorzecze w Zielonej Górze', 'starorzecze-w-zielonej-gorze-zielona-gora-22021', 'OXBOW', 52.0247264, 15.5367943, 'Lubuskie', 'Zielona Góra', 'To duże i popularne starorzecze, położone w bliskiej odległości od Zielonej Góry, charakteryzuje się stałym połączeniem z Odrą. Dzięki temu połączeniu, woda jest dobrze natleniona, a populacja ryb jest bardzo zróżnicowana i liczna, obejmując szczupaki, leszcze, karpie i okonie. Dno jest zróżnicowane, z twardszymi partiami i miejscowymi osadami mułu, co sprzyja różnorodności gatunków. Brzegi są łatwo dostępne z obu stron, z licznymi wygodnymi stanowiskami dla wędkarzy. Roślinność podwodna jest słaba, co ułatwia prowadzenie przynęt i minimalizuje ryzyko zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22021, 7.5, 2.2, 4.8, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22022, 'Starorzecze Bużek', 'starorzecze-buzek-hrubieszow-22022', 'OXBOW', 50.6974595, 24.0596891, 'Lubelskie', 'Hrubieszów', 'Starorzecze Bużek, położone w malowniczej dolinie Bugu, jest jednym z największych i najgłębszych w regionie, co czyni je rajem dla wędkarzy poszukujących dużych drapieżników. Dno jest bardzo zróżnicowane, z głębokimi rynienkami, zatopionymi drzewami i twardymi blatami, co sprzyja bytności sumów, szczupaków i sandaczy. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je gęsta roślinność i krzewy. Roślinność podwodna jest umiarkowana, tworząc idealne kryjówki dla ryb. Stałe połączenie z Bugiem zapewnia ciągły dopływ świeżej wody i migracje ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22022, 10, 3, 6, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Sandacz,Leszcz,Karp', 'Dobry z jednej strony, miejscami trudny', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22023, 'Starorzecze Podkowa', 'starorzecze-podkowa-milejow-osada-22023', 'OXBOW', 51.2228869, 22.9217034, 'Lubelskie', 'Milejów-Osada', 'Starorzecze Podkowa, położone w pobliżu Milejowa-Osady, to urokliwe, choć wymagające łowisko o kształcie podkowy. Dno jest muliste z licznymi podwodnymi zaroślami i zatopionymi gałęziami, co wymaga precyzyjnego wędkowania. Brzegi są trudne do podejścia, gęsto porośnięte trzciną i krzewami, co zmusza do użycia wodoodpornych spodni. Roślinność podwodna jest umiarkowana do silnej, tworząc idealne schronienie dla linów, karasi i wzdręg. Połączenie z rzeką podczas wysokiej wody odświeża zbiornik, ale w upalne lato istnieje ryzyko niedoboru tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22023, 3.8, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć,Okoń', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22024, 'Starorzecze w Milejowie-Osadzie', 'starorzecze-w-milejowie-osadzie-milejow-osada-22024', 'OXBOW', 51.2223365, 22.9209369, 'Lubelskie', 'Milejów-Osada', 'To niewielkie i bardzo płytkie starorzecze, położone w Milejowie-Osadzie, stanowi typowe siedlisko dla ryb odpornych na trudne warunki. Dno jest niemal w całości pokryte grubą warstwą mułu i gęstą roślinnością podwodną, co wymaga stosowania specjalistycznych technik. Brzegi są niezwykle trudne do pokonania, porośnięte wysoką trzciną i bardzo bagniste, co zmusza do użycia wodoodpornych spodni. W upalne lata istnieje wysokie ryzyko całkowitego wyschnięcia zbiornika, dlatego najlepszym okresem na wędkowanie jest wczesna wiosna. Mimo trudności, wędkarze cenią to miejsce za dziki charakter i możliwość złowienia pięknych, dzikich karasi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22024, 2.7, 1.3, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22025, 'Starorzecze (Milejów-Osada)', 'starorzecze-milejow-osada-milejow-osada-22025', 'OXBOW', 51.2218943, 22.9174228, 'Lubelskie', 'Milejów-Osada', 'To starorzecze, zlokalizowane w pobliżu Milejowa-Osady, charakteryzuje się podłużnym kształtem i umiarkowaną wielkością, oferując spokojne warunki do wędkowania. Dno jest muliste z licznymi osadami, co sprzyja rozwojowi bogatej flory podwodnej, a brzegi są częściowo dostępne, choć miejscami bagniste i porośnięte gęstą roślinnością. W akwenie dominują gatunki takie jak lin, karaś pospolity, szczupak oraz płoć, które znajdują tu idealne warunki do żerowania i rozmnażania. Gęste zarośla trzcin i roślinność wynurzona stanowią doskonałe kryjówki dla ryb, ale jednocześnie utrudniają zarzucanie przynęty i prowadzenie zestawu. Ze względu na sporadyczne połączenie z rzeką podczas wysokiej wody, ryzyko deficytu tlenowego jest obecne, szczególnie w upalne lata, co wymaga uwagi wędkarzy. Wędkowanie z brodzeniem jest często konieczne, aby dotrzeć do najlepszych miejscówek, szczególnie w strefach zarośniętych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22025, 3.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Dobry z jednej strony, druga bagnista', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22026, 'Starorzecze (Milejów)', 'starorzecze-milejow-milejow-22026', 'OXBOW', 51.2290179, 22.9159558, 'Lubelskie', 'Milejów', 'To starorzecze w Milejowie to większy akwen o otwartym charakterze, idealny dla wędkarzy ceniących przestrzeń i różnorodność łowiska. Dno jest tu mniej zamulone niż w typowych starorzeczach, składające się głównie z piasku i żwiru, co wpływa na czystość wody. Brzegi są stosunkowo łatwo dostępne z obu stron, z nielicznymi zaroślami, co ułatwia swobodne poruszanie się. Wśród dominujących gatunków ryb znajdziemy leszcze, płocie, okonie i szczupaki, które dobrze czują się w tych warunkach. Roślinność podwodna jest umiarkowana, co pozwala na efektywne stosowanie różnych technik wędkarskich, od spławikowych po spinningowe. Ze względu na brak stałego połączenia z rzeką i niskie zamulenie, ryzyko przyduchy jest minimalne, co czyni to miejsce atrakcyjnym przez cały rok. Akwen ten jest doskonałym wyborem dla wędkarzy poszukujących zróżnicowanej populacji ryb i komfortowych warunków dostępu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22026, 5.8, 2, 4.5, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22027, 'Starorzecze (Milejów-Osada)', 'starorzecze-milejow-osada-milejow-osada-22027', 'OXBOW', 51.2243267, 22.9181905, 'Lubelskie', 'Milejów-Osada', 'To niewielkie starorzecze w Milejowie-Osadzie charakteryzuje się intymnym charakterem, będąc prawdziwą oazą spokoju dla wędkarzy. Dno jest silnie zamulone, bogate w materię organiczną, co sprzyja rozwojowi gęstej roślinności wodnej. Brzegi są trudne do pokonania, często bagniste i mocno zarośnięte trzciną oraz krzewami, co wymaga od wędkarzy cierpliwości i odpowiedniego sprzętu. W akwenie królują gatunki takie jak karaś pospolity, lin i wzdręga, które doskonale adaptują się do płytkich i zarośniętych środowisk. Silne zarośnięcie roślinnością podwodną tworzy liczne zaczepy, co jest wyzwaniem dla każdego wędkarza, ale jednocześnie zapewnia rybom obfitość pożywienia i schronienia. Ze względu na płytkość i gęstą roślinność, ryzyko przyduchy jest wysokie, szczególnie w letnie upały, dlatego warto monitorować warunki. Wędkowanie tutaj wymaga brodzenia i precyzyjnego zarzucania przynęty w wolne przestrzenie między roślinnością.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22027, 1.8, 1, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22028, 'Starorzecze (Milejów-Osada)', 'starorzecze-milejow-osada-milejow-osada-22028', 'OXBOW', 51.2240089, 22.9098277, 'Lubelskie', 'Milejów-Osada', 'To starorzecze w Milejowie-Osadzie wyróżnia się wydłużonym kształtem, przypominającym wolno płynący odcinek rzeki, co nadaje mu unikalny charakter. Dno jest zróżnicowane, od piaszczystych płycizn po muliste zagłębienia, co sprzyja różnym gatunkom ryb. Brzegi są w większości dostępne, choć miejscami mogą być porośnięte roślinnością, co wymaga znalezienia dogodnych stanowisk. Akwen zamieszkują płocie, leszcze, okonie, szczupaki i jazie, co świadczy o jego bogactwie ichtiologicznym i zróżnicowanych warunkach. Roślinność wodna występuje umiarkowanie, koncentrując się w płytszych partiach, co zapewnia rybom schronienie, a wędkarzom klarowne przestrzenie do łowienia. Okresowe połączenie z rzeką podczas wysokiej wody zapewnia dopływ świeżej wody i ryb, minimalizując ryzyko niedoboru tlenu. Wędkarze mogą spodziewać się pojedynczych korzeni i gałęzi na dnie, które mogą stanowić zaczepy, ale również atrakcyjne miejsca żerowania drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22028, 4.1, 1.8, 4, 'Stałe połączenie (sezonowe)', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak,Jaź', 'Dobry z większości brzegów', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22029, 'Starorzecze (Milejów-Osada)', 'starorzecze-milejow-osada-milejow-osada-22029', 'OXBOW', 51.2232422, 22.9112919, 'Lubelskie', 'Milejów-Osada', 'To płytkie starorzecze w Milejowie-Osadzie to klasyczne łowisko karpiowo-linowe, charakteryzujące się spokojną wodą i bogactwem życia. Dno jest mocno zamulone, co w połączeniu z płytkością akwenu sprzyja intensywnemu wzrostowi roślinności wodnej. Brzegi są gęsto porośnięte trzciną, co utrudnia dostęp, ale jednocześnie tworzy naturalne kryjówki dla ryb. Wśród dominujących gatunków znajdują się lin, karaś pospolity, karp oraz wzdręga, które doskonale czują się w tak zarośniętych i ciepłych wodach. Gęsta roślinność podwodna stanowi zarówno wyzwanie dla wędkarzy, jak i bogate źródło pożywienia dla ryb, tworząc idealne warunki do ich rozwoju. Ze względu na płytkość i brak stałego przepływu, akwen ten jest narażony na wysychanie w upalne lata oraz wysokie ryzyko przyduchy. Wędkowanie z brodzeniem jest tu niemal obowiązkowe, aby skutecznie dotrzeć do otwartych przestrzeni i uniknąć zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22029, 2.5, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Karp,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22030, 'Starorzecze (Klarów)', 'starorzecze-klarow-klarow-22030', 'OXBOW', 51.2272351, 22.9424897, 'Lubelskie', 'Klarów', 'Starorzecze w Klarowie to akwen o stosunkowo dużej głębokości jak na tego typu zbiornik, z wyczuwalnym wpływem prądów rzecznych podczas połączeń. Dno jest mieszane, z przewagą piasku i żwiru w głębszych partiach, a mulistymi osadami w płytszych zatokach. Brzegi są częściowo utwardzone, co zapewnia dobry dostęp do wody, jednak w niektórych miejscach mogą być zarośnięte. W tym starorzeczu dominują drapieżniki takie jak szczupak i okoń, a także leszcze, płocie i sandacze, co czyni je atrakcyjnym dla spinningistów. Umiarkowana roślinność podwodna tworzy idealne kryjówki dla ryb, nie utrudniając jednocześnie zbytnio wędkowania. Okresowe połączenia z rzeką podczas wysokiej wody zapewniają stałe odświeżanie wody i minimalizują ryzyko niedoboru tlenu. Na dnie występują liczne zatopione drzewa, które stanowią doskonałe miejsca żerowania i schronienia dla ryb, ale mogą być źródłem zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22030, 6.5, 2.2, 5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Sandacz', 'Dobry z utwardzonych miejsc', FALSE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22031, 'Starorzecze (Cupel)', 'starorzecze-cupel-cupel-22031', 'OXBOW', 52.5178475, 21.1018099, 'Mazowieckie', 'Cupel', 'Starorzecze w Cupelu to rozległy akwen wiślany, charakteryzujący się dużą różnorodnością środowiskową i bogactwem ichtiofauny. Dno jest zróżnicowane, od piaszczystych ławic po głębsze, muliste rynny, co sprzyja wielu gatunkom ryb. Brzegi są w większości dobrze dostępne, z licznymi piaszczystymi plażami i miejscami do wędkowania, co czyni je popularnym łowiskiem. Akwen ten jest domem dla suma, sandacza, bolenia, leszcza i szczupaka, co przyciąga zarówno wędkarzy gruntowych, jak i spinningistów. Roślinność wodna jest słaba, co pozwala na swobodne prowadzenie przynęt i eksplorowanie rozległych obszarów. Stałe połączenie z Wisłą gwarantuje doskonałą jakość wody i minimalne ryzyko deficytu tlenowego, a także regularne zarybienia naturalne. Na dnie można sporadycznie natknąć się na pojedyncze korzenie i gałęzie, które są naturalnymi kryjówkami dla ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22031, 15, 2.5, 6, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Sandacz,Boleń,Leszcz,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22032, 'Starorzecze (Tarnica)', 'starorzecze-tarnica-tarnica-22032', 'OXBOW', 50.6672184, 17.4936387, 'Opolskie', 'Tarnica', 'To starorzecze w Tarnicy to typowy akwen Nysy Kłodzkiej, charakteryzujący się spokojną wodą i bogactwem roślinności, tworząc idealne środowisko dla wielu gatunków ryb. Dno jest muliste, z grubą warstwą osadów, co sprzyja rozwojowi bujnej flory podwodnej. Brzegi są trudne do pokonania, często bagniste i gęsto zarośnięte, co wymaga od wędkarzy cierpliwości i odpowiedniego przygotowania. W akwenie dominują lin, karaś pospolity, wzdręga i płoć, które znajdują tu obfitość pożywienia i schronienia wśród roślin. Gęsta roślinność podwodna stanowi liczne zaczepy, ale jednocześnie jest kluczowym elementem ekosystemu, zapewniając rybom bezpieczeństwo. Ze względu na brak stałego połączenia z rzeką, istnieje ryzyko deficytu tlenu, zwłaszcza w okresie letnim, co należy brać pod uwagę podczas planowania wędkowania. Wędkowanie z brodzeniem jest często niezbędne, aby dotrzeć do najciekawszych miejscówek i skutecznie operować zestawem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22032, 2.8, 1.3, 3, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, miejscami bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22033, 'Starorzecze (Tarnica)', 'starorzecze-tarnica-tarnica-22033', 'OXBOW', 50.6699778, 17.4937482, 'Opolskie', 'Tarnica', 'Drugie starorzecze w Tarnicy to akwen, który podczas powodzi łączy się z rzeką, co sprzyja migracjom ryb i wzbogaca jego populację, szczególnie drapieżników. Dno jest stosunkowo czyste, z mniejszą ilością mułu niż w innych starorzeczach, co świadczy o lepszej cyrkulacji wody. Brzegi są dobrze dostępne z utwardzonych miejsc, co ułatwia wędkarzom zajmowanie stanowisk i swobodne poruszanie się. W akwenie dominują szczupaki, okonie, leszcze i jazie, które znajdują tu doskonałe warunki do żerowania i rozwoju. Roślinność podwodna jest słaba, co umożliwia swobodne prowadzenie przynęt i skuteczne łowienie spinningowe. Dzięki okresowym połączeniom z rzeką, ryzyko niedoboru tlenu jest niskie, a woda jest regularnie odświeżana. Na dnie występują jedynie pojedyncze korzenie i gałęzie, które mogą stanowić naturalne kryjówki dla ryb, ale rzadko są źródłem uciążliwych zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22033, 4.5, 1.7, 4.2, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Jaź', 'Dobry z utwardzonych brzegów', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22034, 'Starorzecze (Tłustoręby)', 'starorzecze-tlustoreby-tlustoreby-22034', 'OXBOW', 50.6629559, 17.4907955, 'Opolskie', 'Tłustoręby', 'To starorzecze w Tłustorębach jest stosunkowo płytkie i podatne na zamulenie, co czyni je doskonałym siedliskiem dla ryb żerujących przy dnie. Dno jest silnie muliste, z grubą warstwą osadów organicznych, co sprzyja rozwojowi gęstej roślinności wodnej. Brzegi są mocno zarośnięte trzciną i inną roślinnością, co utrudnia dostęp, ale jednocześnie tworzy ciche i spokojne miejsca do wędkowania. W akwenie dominują karaś pospolity, lin, karp i płoć, które doskonale adaptują się do płytkich i bogatych w roślinność środowisk. Gęsta roślinność podwodna stanowi liczne zaczepy, co jest wyzwaniem dla wędkarzy, ale jednocześnie zapewnia rybom obfitość pożywienia i schronienia. Ze względu na płytkość i silne zamulenie, ryzyko przyduchy jest wysokie, szczególnie w upalne miesiące letnie, co wymaga ostrożności. Wędkowanie z brodzeniem jest często konieczne, aby dotrzeć do otwartych przestrzeni i skutecznie prowadzić zestaw.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22034, 3, 1.1, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Karp,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22035, 'Starorzecze (Tłustoręby)', 'starorzecze-tlustoreby-tlustoreby-22035', 'OXBOW', 50.6614233, 17.4889404, 'Opolskie', 'Tłustoręby', 'Drugie starorzecze w Tłustorębach charakteryzuje się głębszymi partiami i czystszą wodą, co odróżnia je od wielu innych starorzeczy i sprzyja różnorodności gatunków ryb. Dno jest zróżnicowane, z przewagą piasku i żwiru w głębszych miejscach oraz mulistymi osadami w płytszych zatokach. Brzegi są w większości dobrze dostępne, co ułatwia wędkarzom zajmowanie stanowisk i swobodne poruszanie się wzdłuż akwenu. Wśród dominujących gatunków znajdziemy leszcze, płocie, okonie, szczupaki i węgorze, co świadczy o bogactwie ichtiofauny. Umiarkowana roślinność podwodna zapewnia rybom schronienie, jednocześnie nie utrudniając zbytnio prowadzenia przynęt. Okresowe połączenia z rzeką podczas wysokiej wody zapewniają dopływ świeżej wody i minimalizują ryzyko niedoboru tlenu, co sprzyja zdrowej populacji ryb. Na dnie występują liczne zatopione drzewa, które stanowią doskonałe miejsca żerowania dla drapieżników, choć mogą być źródłem zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22035, 5.2, 2.1, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Węgorz', 'Dobry z większości brzegów', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22036, 'Starorzecze (Kopice)', 'starorzecze-kopice-kopice-22036', 'OXBOW', 50.6841089, 17.4955977, 'Opolskie', 'Kopice', 'Starorzecze w Kopicach to średniej wielkości akwen, który oferuje dobrą równowagę między otwartą wodą a strefami z roślinnością, co czyni go atrakcyjnym łowiskiem. Dno jest zróżnicowane, od piaszczystych fragmentów po muliste zagłębienia, co sprzyja różnorodności gatunków ryb. Brzegi są dobrze dostępne, a w niektórych miejscach nawet wyposażone w pomosty, co ułatwia wędkowanie i relaks nad wodą. W akwenie dominują szczupaki, okonie, leszcze, płocie i liny, co zapewnia wędkarzom szerokie możliwości wyboru techniki. Umiarkowana roślinność podwodna stanowi doskonałe kryjówki dla ryb, nie utrudniając jednocześnie zbytnio zarzucania przynęty. Ze względu na brak stałego połączenia z rzeką i umiarkowane zamulenie, ryzyko niedoboru tlenu jest niskie, a woda utrzymuje dobrą jakość. Na dnie występują jedynie pojedyncze korzenie i gałęzie, które mogą stanowić zaczepy, ale są również naturalnymi punktami koncentracji ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22036, 7, 1.9, 4, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Lin', 'Dobry, miejscami z pomostami', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22037, 'Starorzecze (Radoszowice)', 'starorzecze-radoszowice-radoszowice-22037', 'OXBOW', 50.6918917, 17.5028305, 'Opolskie', 'Radoszowice', 'To starorzecze w Radoszowicach jest długie i wąskie, przypominające wolno płynący odcinek rzeki, co nadaje mu unikalny charakter i specyficzne warunki do wędkowania. Dno jest zróżnicowane, od piaszczystych płycizn po muliste zagłębienia, co sprzyja różnym gatunkom ryb. Brzegi są dostępne z jednej strony, natomiast druga jest mocno zarośnięta, co wymaga od wędkarzy planowania podejścia. W akwenie dominują jazie, klenie, płocie i okonie, które dobrze czują się w wodach o lekkim przepływie. Umiarkowana roślinność podwodna zapewnia rybom schronienie, jednocześnie nie utrudniając zbytnio zarzucania przynęty. Dzięki stałemu połączeniu z małym strumieniem, ryzyko deficytu tlenu jest niskie, a woda jest regularnie odświeżana. Na dnie występuje dużo zatopionych drzew, które stanowią doskonałe kryjówki dla ryb, ale mogą być źródłem licznych zaczepów, wymagając od wędkarzy odpowiedniego sprzętu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22037, 3.5, 1.6, 3.5, 'Stałe połączenie (mały strumień)', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Jaź,Kleń,Płoć,Okoń', 'Dobry z jednej strony, druga zarośnięta', TRUE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22038, 'Starorzecze (Radoszowice)', 'starorzecze-radoszowice-radoszowice-22038', 'OXBOW', 50.6924146, 17.5047839, 'Opolskie', 'Radoszowice', 'Drugie starorzecze w Radoszowicach to mniejszy, bardziej ustronny akwen, idealny dla wędkarzy ceniących ciszę i możliwość skradania się do ryb. Dno jest silnie muliste, z grubą warstwą osadów, co sprzyja rozwojowi gęstej roślinności wodnej. Brzegi są trudne do pokonania, mocno zarośnięte trzciną i inną roślinnością, co wymaga od wędkarzy cierpliwości i odpowiedniego przygotowania. W akwenie dominują karaś pospolity, lin i wzdręga, które doskonale czują się w tak zarośniętych i spokojnych wodach. Gęsta roślinność podwodna stanowi liczne zaczepy, ale jednocześnie jest kluczowym elementem ekosystemu, zapewniając rybom obfitość pożywienia i schronienia. Ze względu na płytkość i brak stałego połączenia z rzeką, istnieje wysokie ryzyko deficytu tlenu, zwłaszcza w okresie letnim, co należy brać pod uwagę podczas planowania wędkowania. Wędkowanie z brodzeniem jest tu niemal obowiązkowe, aby skutecznie dotrzeć do otwartych przestrzeni i uniknąć zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22038, 1.5, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22039, 'Starorzecze (Osiek Grodkowski)', 'starorzecze-osiek-grodkowski-osiek-grodkowski-22039', 'OXBOW', 50.7180131, 17.5045663, 'Opolskie', 'Osiek Grodkowski', 'Starorzecze w Osieku Grodkowskim to duży i otwarty akwen, charakteryzujący się dobrym dostępem i zróżnicowaną populacją ryb, co czyni go atrakcyjnym dla wielu wędkarzy. Dno jest zróżnicowane, od piaszczystych fragmentów po głębsze, muliste rynny, co sprzyja różnorodności gatunków ryb. Brzegi są dobrze dostępne z większości stron, z nielicznymi zaroślami, co ułatwia swobodne poruszanie się i zajmowanie stanowisk. W akwenie dominują szczupaki, sandacze, leszcze, okonie i sumy, co przyciąga zarówno spinningistów, jak i wędkarzy gruntowych. Roślinność wodna jest słaba, co pozwala na efektywne stosowanie różnych technik wędkarskich i eksplorowanie rozległych obszarów. Okresowe połączenia z rzeką podczas wysokiej wody zapewniają dopływ świeżej wody i ryb, minimalizując ryzyko niedoboru tlenu. Na dnie występują jedynie pojedyncze korzenie i gałęzie, które są naturalnymi kryjówkami dla ryb, ale rzadko stanowią uciążliwe zaczepy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22039, 9, 2.3, 5.5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Okoń,Sum', 'Dobry z większości brzegów', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22040, 'Starorzecze Osiek Grodkowski A', 'starorzecze-osiek-grodkowski-a-grodkow-22040', 'OXBOW', 50.7182172, 17.5058809, 'Opolskie', 'Grodków', 'To starorzecze, położone w malowniczej okolicy Osieka Grodkowskiego, charakteryzuje się podłużnym kształtem i umiarkowaną wielkością. Dno jest muliste, z licznymi osadami, co sprzyja rozwojowi roślinności podwodnej. Brzegi są w dużej mierze zarośnięte trzciną i inną roślinnością szuwarową, co utrudnia dostęp do wody, lecz jednocześnie stanowi doskonałe schronienie dla ryb. Wśród dominujących gatunków można spotkać liny, szczupaki, płocie oraz leszcze, które dobrze czują się w tym środowisku. Wędkowanie z brzegu wymaga użycia wodery, a najlepsze efekty osiąga się w miejscach z prześwitami w roślinności. Łowisko to, choć wymagające, oferuje szansę na złowienie naprawdę pięknych okazów, zwłaszcza w cieplejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22040, 3.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Płoć,Leszcz', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22041, 'Starorzecze Osiek Grodkowski B', 'starorzecze-osiek-grodkowski-b-grodkow-22041', 'OXBOW', 50.7203051, 17.5079996, 'Opolskie', 'Grodków', 'Drugie starorzecze w rejonie Osieka Grodkowskiego to mniejszy, bardziej płytki zbiornik o silnym stopniu zamulenia. Dno jest grząskie i bogate w osady organiczne, co sprzyja intensywnemu rozwojowi roślinności wodnej. Brzegi są bardzo trudne do przebycia, bagniste i gęsto zarośnięte, co czyni dostęp do wody wyzwaniem dla wędkarzy. Jest to idealne środowisko dla karasi pospolitych, linów i wzdręg, które doskonale adaptują się do takich warunków. Ze względu na płytkość i brak stałego połączenia z rzeką, istnieje ryzyko wysychania w okresach suszy oraz niedoboru tlenu. Wymagane są wodery, a wędkarstwo to typowa ''przebijanka'' przez zarośla.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22041, 2.8, 1.2, 3, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22042, 'Starorzecze Michałów', 'starorzecze-michalow-grodkow-22042', 'OXBOW', 50.7251438, 17.5100948, 'Opolskie', 'Grodków', 'Starorzecze w Michałowie to rozległe i stosunkowo głębokie łowisko, które oferuje zróżnicowane warunki. Dno jest częściowo muliste, ale występują też twardsze partie, zwłaszcza w głębszych rejonach. Brzegi są umiarkowanie zarośnięte, co zapewnia stosunkowo dobry dostęp do wody w wielu miejscach, choć niektóre fragmenty wymagają ostrożności. W zbiorniku dominują szczupaki, okonie, leszcze, karpie i płocie, co czyni go atrakcyjnym dla wędkarzy preferujących różne metody. Połączenie z rzeką podczas wysokiej wody sprzyja wymianie genetycznej i uzupełnianiu populacji ryb. To łowisko nie stwarza dużych trudności w dostępie i jest polecane na cały sezon wędkarski.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22042, 5.1, 2, 5.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Karp,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22043, 'Starorzecze Sarny Wielkie A', 'starorzecze-sarny-wielkie-a-grodkow-22043', 'OXBOW', 50.7112518, 17.5065668, 'Opolskie', 'Grodków', 'To niewielkie starorzecze w Sarnach Wielkich charakteryzuje się znacznym stopniem zamulenia i płytkością. Dno jest miękkie, bogate w osady organiczne, co sprzyja gęstemu zarastaniu zbiornika. Brzegi są trudne do przebycia, często bagniste i gęsto porośnięte roślinnością szuwarową, co praktycznie uniemożliwia wędkowanie bez odpowiedniego sprzętu. Wśród ryb dominują gatunki odporne na trudne warunki, takie jak karaś pospolity, lin i wzdręga. Ze względu na brak połączenia z rzeką i małą głębokość, łowisko to jest podatne na niedobory tlenu oraz może wysychać w czasie długotrwałych upałów. Wędkarstwo tutaj wymaga cierpliwości i użycia woderów, a najlepsze efekty można osiągnąć wczesną wiosną.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22043, 1.8, 0.9, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22044, 'Starorzecze Radoszowice A', 'starorzecze-radoszowice-a-grodkow-22044', 'OXBOW', 50.7042211, 17.5068153, 'Opolskie', 'Grodków', 'Pierwsze ze starorzeczy w Radoszowicach to zbiornik o średniej wielkości, charakteryzujący się mulistym dnem i umiarkowanym stopniem zarośnięcia. Brzegi są w dużej mierze porośnięte trzciną, co wymaga od wędkarzy cierpliwości i znalezienia dogodnych stanowisk. Połączenie z rzeką podczas wysokiej wody zapewnia dopływ świeżej wody i sprzyja zdrowej populacji ryb. Dominujące gatunki to szczupak, lin, leszcz i płoć, które znajdują tu dogodne warunki do żerowania i rozmnażania. Wędkowanie z brzegu często wymaga użycia woderów, zwłaszcza w celu dotarcia do lepszych miejsc. Pomimo pewnych trudności w dostępie, łowisko to jest cenione za potencjał dużych okazów przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22044, 4, 1.8, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22045, 'Starorzecze Radoszowice B', 'starorzecze-radoszowice-b-grodkow-22045', 'OXBOW', 50.7025984, 17.5071542, 'Opolskie', 'Grodków', 'To mniejsze starorzecze w Radoszowicach to typowe, płytkie łowisko z bardzo wysokim stopniem zamulenia. Dno jest miękkie i grząskie, co utrudnia brodzenie, a gęsta roślinność podwodna stanowi wyzwanie dla wędkarzy. Brzegi są trudne do przebycia, często bagniste i mocno zarośnięte trzciną i krzewami. Brak stałego połączenia z rzeką sprawia, że zbiornik jest podatny na wahania poziomu wody i niedobory tlenu, a w okresach suszy może całkowicie wyschnąć. Dominujące gatunki to karaś srebrzysty, wzdręga i płoć, które dobrze radzą sobie w takich warunkach. Wędkowanie tutaj wymaga użycia woderów i często polega na łowieniu w niewielkich prześwitach roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22045, 2.5, 1, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22046, 'Starorzecze Radoszowice C', 'starorzecze-radoszowice-c-grodkow-22046', 'OXBOW', 50.6985751, 17.5045396, 'Opolskie', 'Grodków', 'To największe i najgłębsze starorzecze w rejonie Radoszowic, charakteryzujące się stałym połączeniem z rzeką, co zapewnia doskonałe warunki wodne. Dno jest przeważnie czyste, z niewielkim zamuleniem, co sprzyja różnorodności gatunkowej. Brzegi są łatwo dostępne z obu stron, z minimalnym zarośnięciem, co ułatwia wędkowanie z brzegu. Jest to idealne łowisko dla drapieżników, takich jak szczupak, sandacz i okoń, ale także dla leszczy i boleni. Stały przepływ wody minimalizuje ryzyko niedoboru tlenu i wysychania, czyniąc je stabilnym ekosystemem. Łowisko to jest cenione przez wędkarzy za komfort i obfitość ryb przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22046, 6, 2.5, 6, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Okoń,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22047, 'Starorzecze Głębocko', 'starorzecze-glebocko-grodkow-22047', 'OXBOW', 50.6929447, 17.4980432, 'Opolskie', 'Grodków', 'Starorzecze w Głębocku to imponujący zbiornik o znacznej powierzchni i głębokości, zasilany wodą podczas większych wezbrań rzeki. Dno jest zróżnicowane, z partiami mulistymi i piaszczystymi, a także licznymi zatopionymi drzewami, które stanowią doskonałe kryjówki dla dużych ryb. Brzegi są częściowo zarośnięte trzciną, co utrudnia dostęp, ale jednocześnie tworzy naturalne stanowiska. Jest to znane łowisko sumów, szczupaków, leszczy, karpi i węgorzy, przyciągające wędkarzy szukających rekordowych okazów. Mimo pewnych trudności w dostępie, jego głębokość i okresowe połączenie z rzeką minimalizują ryzyko deficytu tlenu. Wędkowanie tutaj wymaga woderów i często specjalistycznego sprzętu na duże ryby.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22047, 7.5, 2.8, 6.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Leszcz,Karp,Węgorz', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22048, 'Starorzecze Radoszowice D', 'starorzecze-radoszowice-d-grodkow-22048', 'OXBOW', 50.6886131, 17.5004101, 'Opolskie', 'Grodków', 'Kolejne starorzecze w Radoszowicach to zbiornik o średniej wielkości, charakteryzujący się umiarkowanym zamuleniem i dobrą dostępnością brzegów. Dno jest przeważnie muliste, ale bez nadmiernej warstwy osadów, co pozwala na rozwój zróżnicowanej roślinności. Brzegi są w większości dostępne, z pojedynczymi zaroślami, które nie stanowią większej przeszkody. Brak stałego połączenia z rzeką może prowadzić do okresowych niedoborów tlenu, jednak zbiornik rzadko wysycha. Dominujące gatunki to lin, karaś pospolity, szczupak i płoć, które znajdują tu dogodne warunki. To łowisko jest stosunkowo łatwe do wędkowania z brzegu i polecane jest na wiosnę oraz wczesną jesień.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22048, 3.5, 1.6, 3.9, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22049, 'Starorzecze Radoszowice E', 'starorzecze-radoszowice-e-grodkow-22049', 'OXBOW', 50.6874411, 17.5023657, 'Opolskie', 'Grodków', 'To najmniejsze i najbardziej płytkie starorzecze w kompleksie Radoszowic, charakteryzujące się bardzo wysokim stopniem zamulenia. Dno jest grząskie i bogate w osady organiczne, co sprzyja intensywnemu rozwojowi gęstej roślinności podwodnej. Brzegi są niezwykle trudne do przebycia, bagniste i mocno zarośnięte, co czyni dostęp do wody bardzo ograniczonym. Brak połączenia z rzeką oraz mała głębokość sprawiają, że zbiornik jest bardzo podatny na niedobory tlenu i może wysychać w okresach suszy. Dominujące gatunki to karaś pospolity, wzdręga i płoć, które doskonale adaptują się do tych trudnych warunków. Wędkowanie wymaga użycia woderów i dużej cierpliwości, najlepiej wczesną wiosną, gdy roślinność nie jest jeszcze tak bujna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22049, 1.5, 0.8, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22050, 'Starorzecze Sarny Wielkie B', 'starorzecze-sarny-wielkie-b-grodkow-22050', 'OXBOW', 50.7154441, 17.5074063, 'Opolskie', 'Grodków', 'Drugie starorzecze w Sarnach Wielkich to zbiornik o umiarkowanej wielkości i głębokości, który okresowo łączy się z rzeką podczas wysokiej wody. Dno jest muliste, z licznymi osadami, ale bez nadmiernego zamulenia, co sprzyja różnorodności środowiska. Brzegi są częściowo zarośnięte trzciną, co utrudnia dostęp, ale tworzy też naturalne schronienia dla ryb. Wśród dominujących gatunków znajdują się szczupaki, okonie, leszcze i liny, co czyni to miejsce atrakcyjnym dla wędkarzy preferujących różne techniki. Połączenie z rzeką zapewnia wymianę wody i minimalizuje ryzyko niedoboru tlenu. Wędkowanie wymaga użycia woderów i poszukiwania dogodnych prześwitów w roślinności, ale oferuje dobre perspektywy przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22050, 4.5, 1.9, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22051, 'Starorzecze Sarny Wielkie C', 'starorzecze-sarny-wielkie-c-grodkow-22051', 'OXBOW', 50.7213911, 17.5152736, 'Opolskie', 'Grodków', 'Trzecie starorzecze w Sarnach Wielkich to niewielki, płytki zbiornik charakteryzujący się bardzo wysokim stopniem zamulenia. Dno jest grząskie i bogate w osady organiczne, co sprzyja intensywnemu rozwojowi gęstej roślinności podwodnej. Brzegi są niezwykle trudne do przebycia, bagniste i mocno zarośnięte, co sprawia, że dostęp do wody jest bardzo ograniczony. Brak połączenia z rzeką oraz mała głębokość czynią zbiornik podatnym na niedobory tlenu i ryzyko wysychania w okresach suszy. Dominujące gatunki to karaś pospolity, wzdręga i płoć, które doskonale radzą sobie w tych specyficznych warunkach. Wędkowanie wymaga użycia woderów i skupienia się na łowieniu w nielicznych prześwitach roślinności, najlepiej w późnej wiośnie i lecie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22051, 2, 1.1, 2.9, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22052, 'Starorzecze Ptakowice', 'starorzecze-ptakowice-grodkow-22052', 'OXBOW', 50.7373837, 17.5549013, 'Opolskie', 'Grodków', 'Starorzecze w Ptakowicach to rozległe i głębokie łowisko ze stałym połączeniem z rzeką, co gwarantuje doskonałe warunki wodne. Dno jest przeważnie czyste, z minimalnym zamuleniem, co sprzyja bogactwu gatunkowemu. Brzegi są łatwo dostępne z obu stron, z niewielkim zarośnięciem, co ułatwia komfortowe wędkowanie. Jest to raj dla wędkarzy poszukujących dużych drapieżników, takich jak sum, szczupak i sandacz, a także leszczy i węgorzy. Stały przepływ wody eliminuje ryzyko niedoboru tlenu i wysychania, zapewniając stabilny i zdrowy ekosystem. Łowisko to jest wysoko cenione za swoje walory wędkarskie i komfortowe warunki przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22052, 8, 3, 7, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Szczupak,Sandacz,Leszcz,Węgorz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22053, 'Starorzecze Kantorowice A', 'starorzecze-kantorowice-a-grodkow-22053', 'OXBOW', 50.742348, 17.5960102, 'Opolskie', 'Grodków', 'Pierwsze starorzecze w Kantorowicach to zbiornik o średniej wielkości, który okresowo łączy się z rzeką podczas wysokiej wody. Dno jest muliste, z licznymi zatopionymi drzewami, co stanowi doskonałe kryjówki dla ryb, ale również utrudnia wędkowanie. Brzegi są mocno zarośnięte trzciną, co wymaga od wędkarzy użycia woderów i znalezienia dogodnych stanowisk. Wśród dominujących gatunków można znaleźć szczupaki, karpie, leszcze, płocie i okonie. Okresowe połączenie z rzeką zapewnia dopływ świeżej wody i minimalizuje ryzyko niedoboru tlenu. Łowisko to jest wymagające, ale oferuje szansę na złowienie naprawdę dużych okazów, szczególnie w późnej wiośnie i lecie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22053, 5.5, 2.2, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Karp,Leszcz,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22054, 'Starorzecze Kantorowice B', 'starorzecze-kantorowice-b-grodkow-22054', 'OXBOW', 50.741379, 17.5942856, 'Opolskie', 'Grodków', 'Drugie starorzecze w Kantorowicach to mniejszy zbiornik charakteryzujący się wysokim stopniem zamulenia i gęstą roślinnością. Dno jest grząskie i bogate w osady organiczne, co sprzyja bujnemu rozwojowi roślinności podwodnej. Brzegi są trudne do przebycia, bagniste i mocno zarośnięte, co czyni dostęp do wody wyzwaniem dla wędkarzy. Brak stałego połączenia z rzeką sprawia, że zbiornik jest podatny na niedobory tlenu, choć rzadko wysycha całkowicie. Dominujące gatunki to lin, karaś pospolity, wzdręga i płoć, które doskonale adaptują się do takich warunków. Wędkowanie wymaga użycia woderów i poszukiwania wolnych od roślinności miejsc, a najlepsze efekty osiąga się wiosną i wczesną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22054, 3, 1.4, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22055, 'Starorzecze (Lewin Brzeski)', 'starorzecze-lewin-brzeski-lewin-brzeski-22055', 'OXBOW', 50.7541338, 17.6541361, 'Opolskie', 'Lewin Brzeski', 'To starorzecze, położone w malowniczej okolicy Lewina Brzeskiego, stanowi typowe łowisko dla wędkarzy ceniących spokój i bliskość natury. Dno jest muliste z licznymi osadami organicznymi, co sprzyja rozwojowi bogatej roślinności podwodnej. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je gęsta trzcina i krzewy, utrudniając swobodne poruszanie się. Występuje tu obficie roślinność wynurzona, taka jak grążele i lilie wodne, tworząc idealne kryjówki dla ryb. Dominujące gatunki to lin, karaś pospolity i płoć, a wśród drapieżników często spotyka się szczupaka i okonia, które żerują wśród zarośli. Wędkowanie wymaga cierpliwości i często użycia sprzętu do łowienia w zarośniętych miejscach, co stanowi pewne wyzwanie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22055, 3.2, 1.7, 3.1, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak,Okoń', 'Trudny, miejscami bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22056, 'Starorzecze (Lewin Brzeski) - Wschodnie', 'starorzecze-lewin-brzeski-wschodnie-lewin-brzeski-22056', 'OXBOW', 50.7541815, 17.6560263, 'Opolskie', 'Lewin Brzeski', 'Wschodnia część starorzecza w Lewinie Brzeskim charakteryzuje się nieco większą głębokością w centralnej części, co sprzyja występowaniu większych okazów ryb. Dno jest zróżnicowane, od twardych fragmentów żwirowych po miękkie, muliste osady. Brzegi są gęsto porośnięte roślinnością szuwarową, głównie trzciną i pałką wodną, co sprawia, że dostęp do wody jest utrudniony i wymaga użycia brodzących. Podwodna roślinność jest bujna, oferując liczne kryjówki dla białorybu i drapieżników. W starorzeczu tym z powodzeniem można łowić leszcze, karasie srebrzyste oraz wzdręgi. Wśród drapieżników dominują szczupaki, które aktywnie polują w gęstwinie roślin. Wędkowanie z pontonu lub długimi wędkami jest tutaj szczególnie efektywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22056, 2.8, 2, 3.5, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Leszcz,Karaś srebrzysty,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22057, 'Starorzecze (Mikolin)', 'starorzecze-mikolin-mikolin-22057', 'OXBOW', 50.8042523, 17.6657534, 'Opolskie', 'Mikolin', 'Starorzecze w Mikolinie to rozległy akwen o charakterze typowo nizinnego zbiornika wodnego, otoczonego polami uprawnymi i nielicznymi zadrzewieniami. Dno jest w przeważającej części muliste, z licznymi zatopionymi gałęziami i korzeniami, co stanowi wyzwanie, ale i atrakcję dla wędkarzy. Brzegi są dość strome i miejscami podmokłe, jednak w kilku punktach istnieją dogodne stanowiska wędkarskie. Roślinność wodna, zarówno wynurzona, jak i zanurzona, jest obfita, tworząc doskonałe środowisko dla wielu gatunków ryb. Dominują tu karpie, liny i duże płocie, a także okonie i sumy, które znajdują schronienie w głębszych partiach. Wędkowanie często wymaga precyzyjnego zarzucania zestawu, aby uniknąć zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22057, 5.1, 2.2, 4, 'Podczas wysokiej wody', 'Wysokie', 'Umiarkowane', TRUE, FALSE, 'Karp,Lin,Płoć,Okoń,Sum', 'Trudny, miejscami stromy', TRUE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22058, 'Starorzecze (Wronów)', 'starorzecze-wronow-wronow-22058', 'OXBOW', 50.79531, 17.6677144, 'Opolskie', 'Wronów', 'To starorzecze w pobliżu Wronowa to stosunkowo płytki, ale bogaty w życie zbiornik, idealny dla wędkarzy poszukujących karasi i płoci. Dno jest jednolite, pokryte grubą warstwą mułu i detrytusu, co sprzyja rozwojowi bentosu. Brzegi są niskie i w większości łatwo dostępne, choć miejscami mogą być podmokłe po obfitych deszczach. Roślinność szuwarowa jest obecna, ale nie dominuje, pozwalając na swobodne zarzucanie. W zbiorniku tym z powodzeniem łowi się karasia pospolitego, leszcza i płoć, które osiągają tu imponujące rozmiary. Od czasu do czasu można złowić okonia lub mniejszego szczupaka, które polują na drobną rybę. Łowisko jest idealne do metod spławikowych i gruntowych, szczególnie w cieplejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22058, 2.5, 1.5, 2.8, 'Brak', 'Wysokie', 'Słabe', TRUE, FALSE, 'Karaś pospolity,Leszcz,Płoć,Okoń', 'Dobry z większości stron', FALSE, 'Czyste dno', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22059, 'Starorzecze (Zaczopki)', 'starorzecze-zaczopki-zaczopki-22059', 'OXBOW', 52.1706874, 23.393578, 'Lubelskie', 'Zaczopki', 'Starorzecze w Zaczopkach to malowniczy, wydłużony zbiornik, charakteryzujący się dzikim i naturalnym krajobrazem, typowym dla doliny Bugu. Dno jest zmienne, od piaszczystych płycizn po głębsze, muliste rynny, często z licznymi zaczepami w postaci zatopionych drzew. Brzegi są w większości trudno dostępne, gęsto porośnięte lasem łęgowym i krzewami, co wymaga poszukiwania dogodnych miejsc. Roślinność wodna jest bogata, zwłaszcza w płytszych partiach, tworząc schronienie dla różnorodnych gatunków ryb. Dominują tu leszcze, płocie, jazie i klenie, a także drapieżniki takie jak szczupak i boleń. Wędkowanie jest tu prawdziwym wyzwaniem, ale nagradza pięknymi okazami i niezapomnianymi wrażeniami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22059, 4.8, 2.5, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Jaź,Szczupak,Boleń', 'Trudny, zarośnięty lasem łęgowym', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22060, 'Starorzecze (Klarów)', 'starorzecze-klarow-klarow-22060', 'OXBOW', 51.2257609, 22.9416483, 'Lubelskie', 'Klarów', 'Starorzecze w Klarowie to niewielki, ale urokliwy zbiornik, położony w zacisznej okolicy, idealny dla wędkarzy ceniących kameralną atmosferę. Dno jest w większości muliste, z lokalnymi twardszymi fragmentami, co sprzyja bytności różnych gatunków ryb. Brzegi są częściowo dostępne, choć w wielu miejscach porasta je gęsta roślinność szuwarowa. Roślinność podwodna jest bujna, zwłaszcza w płytszych partiach, oferując obfitość naturalnego pokarmu. Najczęściej łowionymi gatunkami są lin, karaś pospolity oraz wzdręga, które świetnie czują się w zarośniętym środowisku. Z drapieżników sporadycznie pojawia się okoń. Łowisko to jest doskonałe do łowienia na spławik, szczególnie w ciepłe dni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22060, 1.9, 1.4, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Umiarkowany, zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22061, 'Starorzecze (Klarów) - Południowe', 'starorzecze-klarow-poludniowe-klarow-22061', 'OXBOW', 51.2245298, 22.9408319, 'Lubelskie', 'Klarów', 'Południowa odnoga starorzecza w Klarowie to nieco głębszy fragment, który zachowuje więcej wody w okresach suszy, co czyni go bardziej stabilnym ekosystemem. Dno jest mieszane, z przewagą mułu, ale także z twardszymi fragmentami, co sprzyja różnorodności fauny dennej. Brzegi są podobnie jak w części północnej, zarośnięte, ale znajdziemy tu kilka dogodnych, wydeptanych stanowisk. Roślinność wodna jest obfita, tworząc idealne schronienia dla ryb. W tym starorzeczu z powodzeniem łowi się leszcze, płocie i karasie srebrzyste, które często osiągają znaczne rozmiary. Występują również szczupaki, które polują na białoryb w gęstwinie roślin. Wędkowanie z gruntu lub na spławik z dalekim zarzucaniem przynosi najlepsze efekty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22061, 2.1, 1.8, 2.9, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Leszcz,Płoć,Karaś srebrzysty,Szczupak', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22062, 'Starorzecze (Łukowa)', 'starorzecze-lukowa-lukowa-22062', 'OXBOW', 50.3968329, 22.9591285, 'Lubelskie', 'Łukowa', 'Starorzecze w Łukowej to jeden z większych i bardziej dzikich zbiorników w regionie, otoczony gęstymi lasami i łąkami, co zapewnia spokój i ciszę. Dno jest bardzo zróżnicowane, od piaszczystych blatów po głębokie, muliste doły z licznymi zatopionymi drzewami, co sprzyja różnorodności gatunkowej ryb. Brzegi są trudno dostępne, często bagniste i gęsto porośnięte, wymagające od wędkarza wysiłku w dotarciu do dobrych miejsc. Roślinność wodna jest niezwykle bujna, tworząc prawdziwą dżunglę podwodną, idealną dla dużych okazów. Dominują tu sumy, karpie, liny, a także sandacze i szczupaki, które znajdują tu idealne warunki do życia. Łowienie jest wymagające, ale może przynieść spektakularne efekty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22062, 7.5, 3, 6, 'Podczas wysokiej wody', 'Średnie', 'Silne', FALSE, FALSE, 'Sum,Karp,Lin,Sandacz,Szczupak', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22063, 'Starorzecze (Michałów)', 'starorzecze-michalow-michalow-22063', 'OXBOW', 50.7282851, 17.507621, 'Opolskie', 'Michałów', 'Starorzecze w Michałowie to typowy, niewielki zbiornik o charakterze stawu, położony w bliskiej odległości od zabudowań, ale zachowujący swój dziki urok. Dno jest w całości muliste, z grubą warstwą osadów, co sprzyja rozwojowi karasi i linów. Brzegi są w większości łatwo dostępne, choć miejscami mogą być porośnięte trzciną, co wymaga znalezienia odpowiedniego stanowiska. Roślinność wodna jest obfita, zwłaszcza grążele i lilie wodne, tworzące idealne kryjówki dla ryb. Dominujące gatunki to karaś pospolity, lin i płoć, które osiągają tu zadowalające rozmiary. Wędkowanie jest tu relaksujące, idealne dla rodzin z dziećmi, a najlepsze efekty daje metoda spławikowa.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22063, 1.5, 1, 2, 'Brak', 'Wysokie', 'Umiarkowane', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć', 'Dobry, miejscami zarośnięty', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22064, 'Starorzecze (Osiek Grodkowski) - Północne', 'starorzecze-osiek-grodkowski-polnocne-osiek-grodkowski-22064', 'OXBOW', 50.7267777, 17.5080403, 'Opolskie', 'Osiek Grodkowski', 'Północna część starorzecza w Osieku Grodkowskim to stosunkowo głęboki odcinek, który często bywa połączony z rzeką podczas wiosennych roztopów, co wpływa na jego bioróżnorodność. Dno jest zróżnicowane, od piaszczystych łach po muliste zagłębienia, z pojedynczymi zaczepami. Brzegi są częściowo dostępne, choć w wielu miejscach porasta je gęsta roślinność. Roślinność podwodna jest umiarkowana, z przewagą traw wodnych i moczarki. W tym starorzeczu często spotyka się leszcze, płocie i karpie, które wpływają z rzeki. Drapieżniki takie jak szczupak i okoń również są obecne, polując na białoryb. Łowisko jest popularne wśród wędkarzy gruntowych, szczególnie w okresie powodziowym.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22064, 2.7, 2.1, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Okoń', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22065, 'Starorzecze (Michałów) - Południowe', 'starorzecze-michalow-poludniowe-michalow-22065', 'OXBOW', 50.7243287, 17.50612, 'Opolskie', 'Michałów', 'Południowa odnoga starorzecza w Michałowie jest bardziej zarośnięta i płytsza niż jej północny odpowiednik, co sprzyja rozwojowi specyficznych gatunków ryb. Dno jest gęsto pokryte mułem i rozkładającą się roślinnością, tworząc bogate siedlisko dla bezkręgowców. Brzegi są trudne do pokonania, gęsto porośnięte trzciną i krzewami, co wymaga od wędkarza cierpliwości i odpowiedniego sprzętu. Roślinność wodna jest dominująca, tworząc gęste dywany grążeli i moczarki. W tym starorzeczu królują liny, karasie pospolite i wzdręgi, które doskonale maskują się w gęstwinie. Wędkowanie jest tu prawdziwym wyzwaniem, ale może przynieść piękne okazy, zwłaszcza wczesnym rankiem lub wieczorem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22065, 1.8, 1.2, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22066, 'Starorzecze (Osiek Grodkowski) - Centralne', 'starorzecze-osiek-grodkowski-centralne-osiek-grodkowski-22066', 'OXBOW', 50.7221517, 17.5048122, 'Opolskie', 'Osiek Grodkowski', 'Centralna część starorzecza w Osieku Grodkowskim to obszar o umiarkowanej głębokości, charakteryzujący się stabilnymi warunkami środowiskowymi. Dno jest przeważnie muliste, z pojedynczymi twardszymi fragmentami, co sprzyja różnorodności gatunków. Brzegi są stosunkowo łatwo dostępne w wybranych miejscach, choć w innych porastają je krzewy i trzcina. Roślinność wodna jest umiarkowana, tworząc zróżnicowane środowisko dla ryb. W tym starorzeczu często łowi się leszcze, płocie i karpie, które znajdują tu obfitość pokarmu. Z drapieżników obecne są szczupaki i okonie, które patrolują brzegowe zarośla. Łowisko jest idealne do wędkowania spławikowego i gruntowego, oferując dobre warunki przez większość sezonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22066, 2.9, 1.9, 3.2, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22067, 'Starorzecze (Osiek Grodkowski) - Zachodnie', 'starorzecze-osiek-grodkowski-zachodnie-osiek-grodkowski-22067', 'OXBOW', 50.7185931, 17.5025304, 'Opolskie', 'Osiek Grodkowski', 'Zachodni fragment starorzecza w Osieku Grodkowskim to płytki, silnie zarośnięty zbiornik, który w okresach suszy może częściowo wysychać, co wpływa na jego ekosystem. Dno jest gęsto pokryte mułem i obfituje w rozkładającą się materię organiczną, co sprzyja rozwojowi karasi. Brzegi są w większości trudno dostępne, gęsto porośnięte roślinnością szuwarową i krzewami, co wymaga od wędkarza dużej determinacji. Roślinność wodna jest dominująca, tworząc gęste dywany grążeli i moczarki, idealne dla ryb ciepłolubnych. Głównymi gatunkami są karaś pospolity i wzdręga, które świetnie adaptują się do trudnych warunków. Wędkowanie jest tu wyzwaniem, ale może przynieść satysfakcjonujące efekty dla miłośników łowienia w zarośniętych miejscach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22067, 1.5, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22068, 'Starorzecze (Osiek Grodkowski) - Południowo-Zachodnie', 'starorzecze-osiek-grodkowski-poludniowo-zachodnie-osiek-grodkowski-22068', 'OXBOW', 50.714896, 17.4983507, 'Opolskie', 'Osiek Grodkowski', 'Ten południowo-zachodni odcinek starorzecza w Osieku Grodkowskim to stosunkowo długi i wąski zbiornik, charakteryzujący się zmienną głębokością i zróżnicowanym dnem. Dno jest mieszane, od piaszczystych fragmentów po muliste zagłębienia, z licznymi zatopionymi gałęziami, co stanowi atrakcję dla wędkarzy. Brzegi są częściowo dostępne, choć w wielu miejscach porasta je gęsta roślinność, co wymaga poszukiwania dogodnych stanowisk. Roślinność wodna jest umiarkowana, z przewagą traw wodnych i moczarki. W tym starorzeczu często łowi się leszcze, płocie i karpie, które wpływają z rzeki. Drapieżniki takie jak szczupak i okoń również są obecne, polując na białoryb. Łowisko jest popularne wśród wędkarzy gruntowych, szczególnie w okresie powodziowym.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22068, 3.1, 1.7, 2.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Okoń', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22069, 'Starorzecze (Gościejowice)', 'starorzecze-gosciejowice-gosciejowice-22069', 'OXBOW', 50.6575017, 17.618045, 'Opolskie', 'Gościejowice', 'Starorzecze w Gościejowicach to rozległy, malowniczy zbiornik, otoczony łąkami i polami, co czyni go łatwo dostępnym i popularnym wśród lokalnych wędkarzy. Dno jest w przeważającej części muliste, z lokalnymi twardszymi fragmentami, co sprzyja różnorodności gatunków ryb. Brzegi są niskie i w większości łatwo dostępne, choć w niektórych miejscach porasta je trzcina, oferując naturalne kryjówki. Roślinność wodna jest umiarkowana, z przewagą traw wodnych i grążeli, tworząc idealne warunki do żerowania. Dominują tu leszcze, płocie i karasie srebrzyste, które osiągają imponujące rozmiary. Wśród drapieżników często spotyka się szczupaka i sandacza, które polują w głębszych partiach. Łowisko jest idealne do metod spławikowych i gruntowych, a także spinningu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22069, 4.5, 2.3, 4.2, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karaś srebrzysty,Szczupak,Sandacz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22070, 'Starorzecze (Stare Serby 1)', 'starorzecze-stare-serby-1-glogow-22070', 'OXBOW', 51.6676401, 16.1128713, 'Dolnośląskie', 'Głogów', 'To starorzecze charakteryzuje się dość stabilnym poziomem wody, co sprzyja rozwojowi bogatej ichtiofauny. Dno jest muliste w głębszych partiach, natomiast płytsze obszary pokryte są piaskiem i drobnym żwirem. Brzegi są w większości łatwo dostępne, porośnięte trawami i pojedynczymi krzewami, co ułatwia wędkowanie z brzegu. Roślinność podwodna jest umiarkowana, tworząc idealne kryjówki dla drapieżników, takich jak szczupaki i okonie. W starorzeczu dominują płocie, leszcze i liny, a także można spotkać okazałe szczupaki. Wędkowanie utrudniają jedynie sporadyczne zaczepy w postaci zatopionych gałęzi, które wymagają ostrożności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22070, 3.2, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Szczupak,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22071, 'Starorzecze (Stare Serby 2)', 'starorzecze-stare-serby-2-glogow-22071', 'OXBOW', 51.6691101, 16.1160123, 'Dolnośląskie', 'Głogów', 'To starorzecze jest znacznie bardziej zarośnięte i płytkie, co sprzyja rozwojowi roślinności wodnej. Dno jest w przeważającej części mocno zamulone, z grubą warstwą osadów organicznych, co utrudnia poruszanie się. Brzegi są trudne do pokonania, często bagniste i gęsto porośnięte trzciną oraz krzewami, co wymaga użycia wodoodpornego obuwia. Silne zarośnięcie sprawia, że dostęp do wody jest ograniczony, a wędkowanie z brzegu wymaga znalezienia wolnych prześwitów. Występuje tu bogata populacja karasia pospolitego, lina oraz wzdręgi, a także mniejsze płocie. Latem istnieje ryzyko przyduchy z powodu niedoboru tlenu, co może wpłynąć na aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22071, 2.8, 1.5, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22072, 'Starorzecze (Stare Serby 3)', 'starorzecze-stare-serby-3-glogow-22072', 'OXBOW', 51.676793, 16.1226823, 'Dolnośląskie', 'Głogów', 'To starorzecze charakteryzuje się stałym połączeniem z rzeką, co zapewnia ciągłą wymianę wody i stabilne warunki ekologiczne. Dno jest przeważnie piaszczyste z domieszką żwiru, a zamulenie jest minimalne, co sprzyja czystości wody. Brzegi są łatwo dostępne, często utwardzone i porośnięte niską roślinnością, co sprzyja swobodnemu poruszaniu się wędkarzy. Roślinność podwodna jest rzadka, co ułatwia prowadzenie przynęt i minimalizuje ryzyko zaczepów. W starorzeczu licznie występują leszcze, płocie, okonie, a także drapieżniki takie jak sandacze i bolenie. Jest to idealne miejsce dla wędkarzy preferujących spinning lub gruntówkę, poszukujących różnorodności gatunkowej.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22072, 4.5, 2.1, 5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Sandacz,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22073, 'Starorzecze (Stare Serby 4)', 'starorzecze-stare-serby-4-glogow-22073', 'OXBOW', 51.6766504, 16.1197274, 'Dolnośląskie', 'Głogów', 'To niewielkie starorzecze jest dość płytkie i w okresach długotrwałej suszy może częściowo wysychać, co wpływa na skład gatunkowy ryb. Dno jest muliste, z licznymi skupiskami roślinności podwodnej, która stanowi schronienie dla drobnicy. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co utrudnia dostęp do wody i wymaga brodzenia. Wędkowanie z brzegu jest możliwe tylko w nielicznych, wykoszonych miejscach, co wymaga cierpliwości. W starorzeczu dominują karasie srebrzyste, wzdręgi i płocie, które dobrze znoszą zmienne warunki środowiskowe. Ze względu na płytkość, wędkarze powinni zachować ostrożność, aby nie spłoszyć ryb, zwłaszcza w upalne dni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22073, 1.9, 1, 2.5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22074, 'Starorzecze (Stare Serby 5)', 'starorzecze-stare-serby-5-glogow-22074', 'OXBOW', 51.6764668, 16.118634, 'Dolnośląskie', 'Głogów', 'To starorzecze jest cenionym łowiskiem, charakteryzującym się czystą wodą i umiarkowaną głębokością, co sprzyja rozwojowi ryb. Dno jest zróżnicowane, z przewagą piasku i żwiru, a jedynie w najgłębszych miejscach występuje cienka warstwa mułu. Brzegi są łatwo dostępne, porośnięte trawą i pojedynczymi drzewami, które zapewniają cień w upalne dni i komfort wędkowania. Roślinność podwodna jest sporadyczna, co ułatwia prowadzenie przynęt i minimalizuje ryzyko zaczepów. W starorzeczu licznie występują szczupaki i okonie, a także leszcze i płocie, stanowiące podstawę ich diety. Wędkowanie jest komfortowe, a szanse na złowienie dorodnego okazu są wysokie, szczególnie dla spinningistów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22074, 3.8, 2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22075, 'Starorzecze (Stare Serby 6)', 'starorzecze-stare-serby-6-glogow-22075', 'OXBOW', 51.6760915, 16.1201165, 'Dolnośląskie', 'Głogów', 'To starorzecze jest typowym zbiornikiem o charakterze silnie zarastającym, z bardzo mulistym dnem, co świadczy o zaawansowanym procesie sedymentacji. Ze względu na brak stałego połączenia z rzeką, woda jest tu często cieplejsza i uboższa w tlen, co zwiększa ryzyko przyduchy w upalne lato. Brzegi są bardzo trudne do pokonania, gęsto porośnięte trzciną, pałką wodną i inną roślinnością szuwarową, tworząc niemal nieprzeniknioną barierę. Wędkowanie wymaga użycia wodoodpornego obuwia i często poszukiwania niewielkich, otwartych przestrzeni. Dominują tu gatunki odporne na trudne warunki, takie jak liny, karasie pospolite i wzdręgi. Jest to wyzwanie dla wędkarzy ceniących dzikie i trudno dostępne łowiska, oferujące jednak unikalne doświadczenia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22075, 2.1, 1.3, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22076, 'Starorzecze (Stare Serby 7)', 'starorzecze-stare-serby-7-glogow-22076', 'OXBOW', 51.6761978, 16.1263426, 'Dolnośląskie', 'Głogów', 'To największe z opisywanych starorzeczy, posiadające stałe połączenie z rzeką, co przekłada się na bogactwo gatunkowe i wielkość ryb. Dno jest zróżnicowane, z głębokimi rynnami i zatopionymi drzewami, które stanowią doskonałe kryjówki dla dużych drapieżników. Brzegi są przeważnie łatwo dostępne, choć miejscami występują zarośla, które mogą utrudniać swobodne przemieszczanie się. Roślinność podwodna jest umiarkowana, ale liczne zatopione drzewa mogą stanowić wyzwanie dla wędkarzy, zwiększając ryzyko zaczepów. W starorzeczu występują okazałe leszcze, karpie, sumy, szczupaki, a nawet węgorze, co czyni je bardzo atrakcyjnym łowiskiem. Wędkowanie gruntowe i spinningowe jest tu szczególnie efektywne ze względu na strukturę dna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22076, 5, 2.5, 5.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Sum,Szczupak,Węgorz', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22077, 'Starorzecze (Stare Serby 8)', 'starorzecze-stare-serby-8-glogow-22077', 'OXBOW', 51.6759318, 16.1268698, 'Dolnośląskie', 'Głogów', 'To starorzecze charakteryzuje się umiarkowanym zamuleniem i zróżnicowanym dnem, co tworzy dogodne warunki dla wielu gatunków ryb. Połączenie z rzeką podczas wysokiej wody sprzyja odświeżaniu zbiornika i migracji ryb, wzbogacając jego populację. Brzegi są w większości łatwo dostępne, porośnięte trawą i pojedynczymi drzewami, co zapewnia komfortowe warunki do wędkowania. Roślinność podwodna jest umiarkowana, tworząc naturalne schronienia, ale nie utrudniając nadmiernie łowienia. W starorzeczu licznie występują płocie, leszcze i okonie, a także liny, które preferują spokojniejsze rejony. Wędkarze mogą liczyć na udane połowy białorybu oraz drapieżników, szczególnie w okresach wzmożonej aktywności ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22077, 2.9, 1.7, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22078, 'Starorzecze (Stare Serby 9)', 'starorzecze-stare-serby-9-glogow-22078', 'OXBOW', 51.6754581, 16.1283206, 'Dolnośląskie', 'Głogów', 'To bardzo płytkie i silnie zamulone starorzecze, które często wysycha w okresach długotrwałej suszy, co czyni je trudnym łowiskiem. Dno jest niemal całkowicie pokryte grubą warstwą mułu i obficie porośnięte roślinnością wodną, która ogranicza przestrzeń do wędkowania. Brzegi są bagniste i gęsto zarośnięte, co praktycznie uniemożliwia dostęp bez specjalistycznego sprzętu i wodoodpornego obuwia. Ze względu na ekstremalne warunki, populacja ryb jest ograniczona do najbardziej odpornych gatunków, takich jak karasie pospolite i wzdręgi. Wędkowanie jest tu wyzwaniem i wymaga cierpliwości oraz dostosowania technik do specyfiki zbiornika, najlepiej wczesną wiosną.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22078, 1.5, 0.8, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22079, 'Starorzecze (Stare Serby 10)', 'starorzecze-stare-serby-10-glogow-22079', 'OXBOW', 51.6741594, 16.1325469, 'Dolnośląskie', 'Głogów', 'To starorzecze cechuje się stałym połączeniem z rzeką, co gwarantuje wysoką jakość wody i bogactwo ryb, w tym dużych drapieżników. Dno jest przeważnie piaszczysto-żwirowe, z niewielkim zamuleniem, co sprzyja rozwojowi zdrowej ichtiofauny. Brzegi są łatwo dostępne, często z naturalnymi stanowiskami wędkarskimi, porośnięte trawą i pojedynczymi drzewami, oferując komfort. Roślinność podwodna jest skąpa, co ułatwia prowadzenie przynęt i minimalizuje ryzyko zaczepów, co jest atutem dla spinningistów. W starorzeczu licznie występują drapieżniki, takie jak szczupaki, sandacze i okonie, a także popularne gatunki białorybu, jak leszcze i płocie. Jest to doskonałe miejsce dla wędkarzy ceniących komfort i różnorodność połowów przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22079, 4, 2.2, 4.8, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Okoń,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22080, 'Starorzecze (Stare Serby 11)', 'starorzecze-stare-serby-11-glogow-22080', 'OXBOW', 51.6736742, 16.1334457, 'Dolnośląskie', 'Głogów', 'To starorzecze, choć połączone z rzeką jedynie podczas wysokiej wody, utrzymuje stabilny poziom i różnorodność gatunkową. Dno jest muliste w głębszych partiach, a płytsze obszary są piaszczyste, z umiarkowaną ilością roślinności podwodnej. Brzegi są miejscami mocno zarośnięte trzciną, co utrudnia dostęp, ale jednocześnie tworzy cenne kryjówki dla ryb i dodaje uroku łowisku. Wędkowanie wymaga cierpliwości i często brodzenia, aby dotrzeć do najlepszych stanowisk, szczególnie w poszukiwaniu lina. W starorzeczu dominują liny i karasie pospolite, ale można spotkać także płocie, leszcze i mniejsze szczupaki. To idealne miejsce dla wędkarzy poszukujących spokoju i wyzwań w otoczeniu natury.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22080, 3.5, 1.9, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Płoć,Leszcz,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22081, 'Starorzecze (Stare Serby 12)', 'starorzecze-stare-serby-12-glogow-22081', 'OXBOW', 51.6731705, 16.1345819, 'Dolnośląskie', 'Głogów', 'To starorzecze charakteryzuje się znacznym zamuleniem i gęstą roślinnością podwodną, co sprawia, że jest to trudne, ale potencjalnie satysfakcjonujące łowisko. Brak połączenia z rzeką oznacza, że zbiornik jest bardziej podatny na wahania poziomu wody i temperatury, co należy brać pod uwagę. Brzegi są bagniste i gęsto zarośnięte, co wymaga użycia wodoodpornego obuwia i poszukiwania otwartych przestrzeni do wędkowania. Występuje tu ryzyko przyduchy w upalne lata, co wpływa na populację ryb, dlatego najlepsze są chłodniejsze pory. Dominują tu odporne gatunki, takie jak karasie srebrzyste, wzdręgi i płocie, które doskonale radzą sobie w takich warunkach. Wędkowanie tutaj to prawdziwe wyzwanie dla cierpliwych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22081, 2.7, 1.4, 3.1, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22082, 'Starorzecze (Stare Serby 13)', 'starorzecze-stare-serby-13-glogow-22082', 'OXBOW', 51.6744205, 16.1337991, 'Dolnośląskie', 'Głogów', 'To starorzecze oferuje zróżnicowane warunki wędkarskie, z umiarkowanym zamuleniem dna i dobrze rozwiniętą roślinnością brzegową. Połączenie z rzeką podczas wysokiej wody sprzyja wzbogacaniu zbiornika w składniki odżywcze i nowe osobniki ryb, co zwiększa szanse na udany połów. Dostęp do brzegów jest ogólnie dobry, choć miejscami występują kępy trzcin, które mogą stanowić naturalne kryjówki dla ryb. W starorzeczu licznie występują płocie, leszcze i liny, a także okonie, które często polują w pobliżu roślinności. Wędkarze mogą liczyć na udane połowy, szczególnie w pobliżu zatopionych gałęzi i podwodnych przeszkód, które stanowią atrakcyjne miejsca żerowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22082, 3, 1.6, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Lin,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22083, 'Starorzecze (Grodziec Mały 1)', 'starorzecze-grodziec-maly-1-grodziec-maly-22083', 'OXBOW', 51.6750647, 16.0856441, 'Dolnośląskie', 'Grodziec Mały', 'To starorzecze, położone w pobliżu Grodźca Małego, jest jednym z głębszych i bardziej zróżnicowanych łowisk w okolicy. Stałe połączenie z rzeką zapewnia obfitość tlenu i stabilne środowisko, sprzyjające dużym rybom, takim jak sumy i karpie. Dno jest urozmaicone, z głębokimi dołami, zatopionymi drzewami i piaszczystymi blatami, co tworzy idealne warunki dla sumów, karpi i sandaczy. Brzegi są w większości łatwo dostępne, choć miejscami występują naturalne zarośla, które mogą stanowić dodatkowe kryjówki. Jest to doskonałe miejsce dla wędkarzy spinningowych i gruntowych, poszukujących dużych okazów. Należy jednak uważać na liczne zaczepy w postaci zatopionych pni i gałęzi, które mogą utrudnić połów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22083, 4.2, 2.3, 5.2, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Karp,Leszcz,Szczupak,Sandacz', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22084, 'Starorzecze (Grodziec Mały 2)', 'starorzecze-grodziec-maly-2-grodziec-maly-22084', 'OXBOW', 51.6817812, 16.0318569, 'Dolnośląskie', 'Grodziec Mały', 'To starorzecze, choć bez stałego połączenia z rzeką, jest bogate w ryby i oferuje ciekawe wyzwania wędkarskie. Dno jest muliste z domieszką piasku, a roślinność podwodna tworzy liczne kryjówki dla drobnicy i drapieżników, co sprzyja rozwojowi ekosystemu. Brzegi są częściowo zarośnięte trzciną, co wymaga znalezienia dogodnych miejsc do zarzucenia wędki lub użycia wodoodpornego obuwia, aby dotrzeć do wody. W starorzeczu dominują liny i karasie pospolite, a także szczupaki i okonie, które chętnie polują w zaroślach. Jest to idealne miejsce dla wędkarzy ceniących spokój i kontakt z naturą, z dala od zgiełku, szukających gatunków typowych dla starorzeczy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22084, 3.7, 1.7, 3.9, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22085, 'Starorzecze (Gubin)', 'starorzecze-gubin-gubin-22085', 'OXBOW', 51.9330846, 14.7469334, 'Lubuskie', 'Gubin', 'To malownicze starorzecze, położone w dolinie Nysy Łużyckiej, charakteryzuje się umiarkowaną wielkością i głębokością, oferując różnorodne warunki dla wędkarzy. Dno jest muliste z twardymi fragmentami, a brzegi są częściowo dostępne, choć miejscami porośnięte gęstą roślinnością przybrzeżną. Woda jest czysta, a podwodna roślinność nie jest zbyt obfita, co ułatwia prowadzenie przynęt. Akwen jest domem dla licznych szczupaków, dorodnych linów, leszczy oraz płoci, które znajdują tu idealne warunki do żerowania. Połączenie z rzeką główną podczas wysokiej wody zapewnia regularne zarybianie naturalnymi drogami. Wędkowanie utrudniają jedynie sporadyczne zaczepy w postaci zatopionych gałęzi, jednak ogólny dostęp jest dobry. Jest to idealne miejsce na wiosenne i jesienne wyprawy wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22085, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Płoć', 'Dobry z jednej strony, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22086, 'Starorzecze (Ruda Północne)', 'starorzecze-ruda-polnocne-ruda-22086', 'OXBOW', 51.9791201, 20.2368289, 'Mazowieckie', 'Ruda', 'Starorzecze to jest częścią kompleksu wodnego w dolinie Pilicy, charakteryzującego się płytką wodą i bogatym ekosystemem. Dno jest w większości muliste, co sprzyja rozwojowi bujnej roślinności podwodnej, stanowiącej schronienie dla wielu gatunków ryb. Brzegi są trudnodostępne, często bagniste i mocno zarośnięte trzciną, co wymaga użycia wodery. Akwen ten jest rajem dla linów i karasi pospolitych, a także szczupaków i płoci, które dobrze czują się w zarośniętych partiach. Połączenie z rzeką podczas wysokiej wody odświeża wodę i zasila starorzecze nowymi osobnikami. Ze względu na gęstą roślinność podwodną, wędkarstwo wymaga cierpliwości i precyzji w wyborze miejsca oraz metody. Najlepsze efekty osiąga się tu późną wiosną i latem, zwłaszcza na spławik.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22086, 2.8, 1.5, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, miejscami bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22087, 'Starorzecze (Ruda Centralne)', 'starorzecze-ruda-centralne-ruda-22087', 'OXBOW', 51.9814645, 20.237464, 'Mazowieckie', 'Ruda', 'To centralne starorzecze w Rudzie, choć niewielkie, oferuje stabilne warunki wodne i jest cenione przez lokalnych wędkarzy. Dno jest mieszane, z przewagą mułu, ale z twardszymi fragmentami wzdłuż niektórych brzegów. Dostęp do wody jest dobry z jednej strony, gdzie znajdują się dogodne stanowiska wędkarskie, choć reszta linii brzegowej jest gęsto porośnięta trzciną. Roślinność podwodna jest umiarkowana, co pozwala na różnorodne techniki połowu. Dominującymi gatunkami są tu leszcze, płocie, liny oraz okonie, które chętnie żerują w pobliżu zarośli. Połączenie z rzeką Pilicą podczas wiosennych roztopów wpływa pozytywnie na populację ryb i jakość wody. Starorzecze to jest dostępne przez cały sezon, oferując stabilne brania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22087, 3.2, 1.7, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Lin,Okoń', 'Dobry z jednej strony, zarośnięty trzciną', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22088, 'Starorzecze (Ruda Wschodnie)', 'starorzecze-ruda-wschodnie-ruda-22088', 'OXBOW', 51.981251, 20.2389228, 'Mazowieckie', 'Ruda', 'To niewielkie i płytkie starorzecze wschodnie w Rudzie jest silnie zamulone i charakteryzuje się bardzo bujną roślinnością. Dno jest niemal w całości pokryte grubą warstwą mułu, co sprawia, że wędkarstwo jest tutaj wyzwaniem. Brzegi są mocno zarośnięte trzciną i inną roślinnością, utrudniając dostęp do wody i wymagając użycia woderów. W okresach upałów istnieje wysokie ryzyko przyduchy ze względu na płytkość i gęstą roślinność. Mimo to, akwen jest domem dla karasi pospolitych, wzdręg i linów, które dobrze radzą sobie w trudnych warunkach. Połączenie z rzeką podczas wysokiej wody jest nieregularne, co przyczynia się do większego zamulenia. Najlepszy okres na połów to wczesna wiosna, zanim roślinność osiągnie pełnię rozwoju.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22088, 2.1, 1.2, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Mocno zarośnięty trzciną, trudny', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22089, 'Starorzecze (Ruda Południowe)', 'starorzecze-ruda-poludniowe-ruda-22089', 'OXBOW', 51.9791136, 20.2392511, 'Mazowieckie', 'Ruda', 'Starorzecze południowe w Rudzie to mały i bardzo płytki zbiornik, który z biegiem lat staje się coraz bardziej odizolowany od rzeki głównej. Brak stałego połączenia z rzeką oraz wysoki stopień zamulenia sprawiają, że akwen jest podatny na wysychanie w okresach suszy. Dno jest w całości pokryte grubą warstwą osadów, a brzegi są bagniste i trudnodostępne, wymagając użycia woderów. Gęsta roślinność podwodna i duża ilość zatopionych drzew tworzą liczne zaczepy, ale jednocześnie doskonałe kryjówki dla ryb. Występuje tu wysokie ryzyko przyduchy w lecie, co sprzyja gatunkom odpornym, takim jak karaś srebrzysty, wzdręga i płoć. Wędkowanie jest tutaj wyzwaniem, ale może przynieść satysfakcję wczesną wiosną, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22089, 1.9, 1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22090, 'Starorzecze (Dąbrowica Zachodnie)', 'starorzecze-dabrowica-zachodnie-dabrowica-22090', 'OXBOW', 50.3047058, 22.5703312, 'Podkarpackie', 'Dąbrowica', 'To rozległe starorzecze w Dąbrowicy jest jednym z lepiej zachowanych akwenów w dolinie Sanu, z głębszymi partiami i czystszą wodą. Dno jest zróżnicowane, od piaszczystych płycizn po muliste zagłębienia, co sprzyja różnorodności fauny dennej. Brzegi są ogólnie dobrze dostępne, co ułatwia swobodne poruszanie się wzdłuż linii brzegowej. Roślinność podwodna jest umiarkowana, skupiając się głównie w płytszych zatoczkach i przy brzegach. Akwen ten słynie z populacji szczupaków, dorodnych leszczy, płoci, okoni, a także karpi, które znajdują tu obfitość pokarmu. Połączenie z rzeką podczas wysokiej wody zapewnia stałe odświeżanie wody i migrację ryb. To doskonałe łowisko na cały sezon, oferujące komfortowe warunki wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22090, 6, 2.2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22091, 'Starorzecze (Dąbrowica Wschodnie)', 'starorzecze-dabrowica-wschodnie-dabrowica-22091', 'OXBOW', 50.3060431, 22.5739483, 'Podkarpackie', 'Dąbrowica', 'Wschodnie starorzecze w Dąbrowicy jest nieco mniejsze od swojego zachodniego odpowiednika, ale równie atrakcyjne dla wędkarzy. Dno jest głównie muliste, z twardymi fragmentami wzdłuż zewnętrznego zakola, co tworzy zróżnicowane środowisko. Brzegi są miejscami zarośnięte, ale ogólnie dostępne, co pozwala na wygodne wędkowanie z brzegu. Umiarkowana roślinność podwodna zapewnia kryjówki dla ryb, nie utrudniając jednocześnie prowadzenia przynęt. Akwen ten jest bogaty w liny, karasie pospolite, szczupaki i leszcze, które dobrze czują się w spokojnych wodach. Brak stałego połączenia z rzeką główną sprawia, że woda jest bardziej stabilna termicznie, choć podczas dużych opadów może dochodzić do przelewów. To idealne miejsce na wiosenne i letnie zasiadki, szczególnie dla miłośników spławika.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22091, 5.5, 2, 3.8, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Szczupak,Leszcz', 'Miejscami zarośnięty, dostępny', FALSE, 'Gęsta roślinność podwodna', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22092, 'Starorzecze (Charubiny)', 'starorzecze-charubiny-charubiny-22092', 'OXBOW', 53.4003594, 21.7874964, 'Mazowieckie', 'Charubiny', 'Starorzecze w Charubinach, położone w rozległej dolinie Narwi, to akwen o znaczącej powierzchni, ale stosunkowo płytki, z silnym rozwojem roślinności. Dno jest w przeważającej części muliste, co sprzyja gęstym zaroślom podwodnym, tworzącym idealne środowisko dla wielu gatunków ryb. Brzegi są trudnodostępne, mocno zarośnięte trzciną i inną roślinnością, co wymaga użycia woderów do skutecznego wędkowania. W okresach letnich istnieje ryzyko niedoboru tlenu, jednak połączenie z rzeką podczas wysokiej wody pomaga w jego odświeżaniu. Dominują tu szczupaki, liny, karasie pospolite, płocie i wzdręgi. Wędkarstwo jest tu wyzwaniem ze względu na liczne zaczepy i bujną roślinność, ale nagradza dorodnymi egzemplarzami. Najlepsze wyniki osiąga się wiosną i wczesnym latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22092, 7, 1.9, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć,Wzdręga', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna, pojedyncze korzenie', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22093, 'Starorzecze (Popiołki Południowe)', 'starorzecze-popiolki-poludniowe-popiolki-22093', 'OXBOW', 53.4119698, 21.7877207, 'Mazowieckie', 'Popiołki', 'To niewielkie starorzecze w Popiołkach, odizolowane od głównego nurtu Narwi, charakteryzuje się wysokim stopniem zamulenia i bujną roślinnością. Dno jest bardzo miękkie i muliste, co utrudnia poruszanie się i prowadzenie przynęt. Brzegi są wyjątkowo trudnodostępne, bagniste i gęsto zarośnięte, co czyni wodery absolutnie niezbędnymi. W akwenie występuje wysokie ryzyko przyduchy, zwłaszcza w upalne lata, co prowadzi do okresowego wysychania płytszych partii. Mimo trudnych warunków, starorzecze to jest ostoją dla karasi pospolitych, linów i wzdręg, które doskonale adaptują się do tego środowiska. Duża ilość zatopionych drzew stanowi zarówno schronienie, jak i liczne zaczepy. Najlepsze brania można uzyskać wczesną wiosną, zanim roślinność zdominuje akwen.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22093, 3, 1.4, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Bardzo trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22094, 'Starorzecze (Popiołki Centralne)', 'starorzecze-popiolki-centralne-popiolki-22094', 'OXBOW', 53.4206042, 21.7953104, 'Mazowieckie', 'Popiołki', 'Centralne starorzecze w Popiołkach to akwen o umiarkowanej wielkości, oferujący bardziej zróżnicowane warunki niż jego południowy odpowiednik. Dno jest muliste, ale z twardszymi fragmentami, co sprzyja różnorodności gatunków ryb. Dostęp do wody jest dobry z jednej strony, gdzie znajdują się dogodne stanowiska, choć inne partie brzegowe są miejscami zarośnięte. Roślinność podwodna jest umiarkowana, co ułatwia prowadzenie przynęt i pozwala na stosowanie różnych technik wędkarskich. Akwen ten jest domem dla szczupaków, płoci, leszczy i okoni, które znajdują tu dobre warunki do żerowania i ukrycia. Połączenie z rzeką Narew podczas wysokiej wody zapewnia regularne odświeżanie wody i zarybianie. Jest to atrakcyjne łowisko przez cały sezon, oferujące stabilne brania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22094, 4.2, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Płoć,Leszcz,Okoń', 'Dobry z jednej strony, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22095, 'Starorzecze (Popiołki Północne)', 'starorzecze-popiolki-polnocne-popiolki-22095', 'OXBOW', 53.4206011, 21.7962362, 'Mazowieckie', 'Popiołki', 'Północne starorzecze w Popiołkach to akwen o charakterze typowym dla starorzeczy Narwi, z wysokim stopniem zamulenia i gęstą roślinnością. Dno jest w większości muliste, co sprzyja rozwojowi bogatej flory podwodnej, oferującej schronienie dla ryb. Brzegi są trudnodostępne i bagniste, co wymaga użycia woderów, aby dotrzeć do najlepszych miejscówek. Brak stałego połączenia z rzeką Narew sprawia, że akwen jest bardziej podatny na wahania poziomu wody i ryzyko przyduchy w upalne lata. Występują tu głównie liny, karasie pospolite, wzdręgi i płocie, które doskonale radzą sobie w tych warunkach. Gęsta roślinność podwodna stanowi liczne zaczepy, ale jednocześnie jest kluczowym elementem ekosystemu. Najlepszy okres na wędkowanie to późna wiosna i lato, kiedy ryby są najbardziej aktywne w zaroślach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22095, 3.8, 1.5, 2.9, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22096, 'Starorzecze (Górszczyzna)', 'starorzecze-gorszczyzna-gorszczyzna-22096', 'OXBOW', 53.427805, 21.8127975, 'Mazowieckie', 'Górszczyzna', 'Starorzecze w Górszczyźnie to jeden z większych akwenów w tej części doliny Narwi, charakteryzujący się stabilnymi warunkami i dobrym dostępem. Dno jest zróżnicowane, z mulistymi i piaszczystymi partiami, co tworzy idealne warunki dla wielu gatunków ryb. Brzegi są dobrze dostępne z obu stron, a w niektórych miejscach nawet częściowo utwardzone, co ułatwia wędkowanie. Roślinność podwodna jest umiarkowana, z czystszymi partiami dna, co sprzyja łowieniu na spinning. Akwen jest zasobny w szczupaki, leszcze, karpie, płocie i okonie, które znajdują tu obfitość pokarmu. Połączenie z rzeką podczas wysokiej wody zapewnia regularne odświeżanie wody i dopływ nowych ryb. To doskonałe łowisko na cały sezon, cenione za różnorodność rybostanu i komfortowe stanowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22096, 6.5, 2.1, 3.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Karp,Płoć,Okoń', 'Dobry z obu stron, częściowo utwardzony', FALSE, 'Czyste dno, miejscami roślinność podwodna', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22097, 'Starorzecze (Kozioł)', 'starorzecze-koziol-koziol-22097', 'OXBOW', 53.4281235, 21.8165006, 'Mazowieckie', 'Kozioł', 'Starorzecze w Kozioł to akwen o średniej wielkości, charakteryzujący się wysokim stopniem zamulenia i bardzo bujną roślinnością. Dno jest w dużej mierze pokryte miękkim mułem, co sprzyja rozwojowi gęstych zarośli podwodnych i przybrzeżnych. Brzegi są trudnodostępne i mocno zarośnięte, co wymaga użycia woderów do przedostania się do wody. W akwenie występuje wysokie ryzyko przyduchy w okresach letnich upałów, co wpływa na aktywność ryb. Mimo to, jest to doskonałe miejsce dla linów, karasi pospolitych, wzdręg i szczupaków, które dobrze czują się w zaroślach i licznych zatopionych drzewach. Zatoki i płycizny obfitują w życie, stanowiąc schronienie i żerowisko. Najlepsze efekty osiąga się tu wiosną, kiedy roślinność nie jest jeszcze tak gęsta.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22097, 5, 1.8, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, mocno zarośnięty', TRUE, 'Dużo zatopionych drzew, gęsta roślinność', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22098, 'Starorzecze (Piotrowice)', 'starorzecze-piotrowice-piotrowice-22098', 'OXBOW', 51.6019164, 21.6591368, 'Mazowieckie', 'Piotrowice', 'Starorzecze w Piotrowicach, położone w rozległej dolinie Wisły, to jeden z większych i głębszych akwenów tego typu, oferujący doskonałe warunki dla drapieżników i dużych ryb spokojnego żeru. Dno jest zróżnicowane, z piaszczystymi płyciznami, twardymi grądzikami i mulistymi rynnami, co sprzyja bogactwu gatunkowemu. Brzegi są w większości dobrze dostępne, miejscami z piaszczystymi plażami, co ułatwia wędkowanie z brzegu. Roślinność podwodna jest umiarkowana, co pozwala na swobodne prowadzenie przynęt. Akwen słynie z obecności sumów, sandaczy, dużych szczupaków, leszczy i karpi. Połączenie z Wisłą podczas wysokiej wody zapewnia regularny dopływ świeżej wody i migrację ryb. To idealne miejsce na całosezonowe wyprawy, szczególnie dla wędkarzy poszukujących dużych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22098, 9.5, 2.5, 5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Sandacz,Szczupak,Leszcz,Karp', 'Dobry, miejscami piaszczyste brzegi', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22099, 'Starorzecze (Kobylnica)', 'starorzecze-kobylnica-kobylnica-22099', 'OXBOW', 54.4289607, 17.0214814, 'Pomorskie', 'Kobylnica', 'Starorzecze w Kobylnicy to akwen o znaczącej powierzchni, położony w pobliżu Słupska, charakteryzujący się umiarkowaną głębokością i zróżnicowanym środowiskiem. Dno jest w większości muliste, ale z twardszymi fragmentami, co sprzyja rozwojowi gęstej roślinności podwodnej. Dostęp do wody jest dobry z jednej strony, natomiast pozostała linia brzegowa jest gęsto zarośnięta, co utrudnia poruszanie się. Roślinność podwodna jest obfita, tworząc liczne kryjówki dla ryb i stanowiąc wyzwanie dla wędkarzy. W akwenie nie ma stałego połączenia z rzeką, jednak stabilne warunki wodne minimalizują ryzyko przyduchy. Dominującymi gatunkami są szczupaki, okonie, liny, leszcze i węgorze, które dobrze czują się w tym zarośniętym środowisku. Jest to doskonałe miejsce na wiosenne i jesienne wyprawy, oferujące szansę na złowienie dorodnych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22099, 8, 2, 4, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Lin,Leszcz,Węgorz', 'Dobry z jednej strony, reszta zarośnięta', FALSE, 'Gęsta roślinność podwodna', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22100, 'Starorzecze (Słupsk)', 'starorzecze-slupsk-slupsk-22100', 'OXBOW', 54.4263086, 17.0305299, 'Pomorskie', 'Słupsk', 'To starorzecze, położone na obrzeżach Słupska, stanowi popularne miejsce dla wędkarzy ceniących sobie bliskość miasta. Charakteryzuje się umiarkowanym zarośnięciem brzegów i dnem, które miejscami pokryte jest warstwą mułu, a miejscami twardsze, piaszczysto-żwirowe. Wędkarze mogą liczyć na dobre warunki dostępu do łowiska z obu stron, co ułatwia wybór stanowiska. W wodzie występują pojedyncze korzenie i gałęzie, które stanowią naturalne kryjówki dla ryb drapieżnych, takich jak szczupak i okoń. Wśród gatunków dominujących znajdują się również płocie, leszcze i liny, które preferują spokojne wody starorzeczy. Należy jednak pamiętać o ryzyku przyduchy w okresach upałów lub pod grubą warstwą lodu, co jest typowe dla płytkich, stojących wód. Najlepsze wyniki wędkarskie osiąga się tu wiosną i wczesną jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22100, 5.2, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22101, 'Starorzecze (Łosino)', 'starorzecze-losino-losino-22101', 'OXBOW', 54.426442, 17.0274059, 'Pomorskie', 'Łosino', 'To starorzecze w pobliżu Łosina to typowy akwen o charakterze mocno zarośniętym i zamulonym, co czyni go wyzwaniem dla wędkarzy. Brzegi są bagniste i trudne do przejścia, często wymagające użycia woderów, aby dotrzeć do dogodnego miejsca. Dno jest w większości pokryte grubą warstwą mułu, a pod wodą króluje gęsta roślinność, tworząca idealne schronienia dla ryb. Wśród dominujących gatunków ryb znajdziemy liny, karasie pospolite, wzdręgi oraz płocie, które doskonale czują się w takich warunkach. Ze względu na płytkość i obfitość materii organicznej, istnieje wysokie ryzyko przyduchy, zwłaszcza w upalne lata. Mimo trudnego dostępu, starorzecze to oferuje szansę na złowienie pięknych okazów ryb typowych dla wód stojących, a najlepsze wyniki osiąga się tu późną wiosną i latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22101, 3.8, 1.5, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22102, 'Starorzecze (Łosino)', 'starorzecze-losino-losino-22102', 'OXBOW', 54.4136614, 17.0213042, 'Pomorskie', 'Łosino', 'To niewielkie starorzecze koło Łosina jest typowym przykładem płytkiego akwenu, który w okresach suszy może całkowicie wyschnąć, co wpływa na jego biologię. Brzegi są mocno zarośnięte trzciną, co utrudnia dostęp do wody i często wymaga użycia woderów, aby dotrzeć do dogodnego miejsca. Dno jest muliste i obfituje w gęstą roślinność podwodną, stanowiącą doskonałe środowisko dla ryb. Dominujące gatunki to przede wszystkim karasie pospolite, płocie i wzdręgi, które dobrze adaptują się do zmiennych warunków. Ze względu na płytkość i bogatą roślinność, ryzyko przyduchy jest bardzo wysokie, szczególnie w letnie miesiące. Wędkowanie tutaj to wyzwanie, ale może przynieść satysfakcję w postaci pięknych karasi. Najlepszy czas na połów to późna wiosna i lato, gdy woda jest cieplejsza i ryby żerują intensywniej.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22102, 2.1, 1, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Płoć,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22103, 'Starorzecze (Zajączkowo)', 'starorzecze-zajaczkowo-zajaczkowo-22103', 'OXBOW', 54.4014499, 17.0270752, 'Pomorskie', 'Zajączkowo', 'To rozległe starorzecze w Zajączkowie wyróżnia się stałym połączeniem z rzeką, co zapewnia stałą wymianę wody i niskie ryzyko przyduchy. Dno jest zróżnicowane, od piaszczysto-żwirowego po miejsca z niewielką warstwą mułu, z pojedynczymi korzeniami i gałęziami stanowiącymi kryjówki. Brzegi są łatwo dostępne, co umożliwia komfortowe wędkowanie z wielu miejsc. Woda jest umiarkowanie zarośnięta, co sprzyja różnorodności gatunków ryb. Dominują tu szczupaki, leszcze, płocie, okonie, a nawet sandacze, które wpływają z rzeki. Dzięki stabilnym warunkom, łowisko to jest atrakcyjne przez cały sezon wędkarski. Stałe połączenie z rzeką gwarantuje także świeżą wodę i lepsze natlenienie, co pozytywnie wpływa na kondycję ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22103, 7.5, 2.2, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Sandacz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22104, 'Starorzecze (Zajączkowo)', 'starorzecze-zajaczkowo-zajaczkowo-22104', 'OXBOW', 54.3926524, 17.0313615, 'Pomorskie', 'Zajączkowo', 'To niewielkie starorzecze w Zajączkowie jest typowym przykładem akwenu o wysokim stopniu zamulenia i silnym zarośnięciu, co stanowi wyzwanie dla wędkarzy. Brzegi są bagniste i trudno dostępne, często wymagające użycia woderów, aby dotrzeć do wody. Dno jest w przeważającej części pokryte grubą warstwą mułu, a pod wodą dominuje gęsta roślinność, która stanowi schronienie dla ryb. Wśród dominujących gatunków ryb znajdziemy liny, karasie srebrzyste oraz wzdręgi, które doskonale odnajdują się w takich warunkach. Ze względu na płytkość i obfitość materii organicznej, istnieje wysokie ryzyko przyduchy, zwłaszcza w upalne lata. Mimo trudności, starorzecze to oferuje szansę na złowienie pięknych okazów ryb typowych dla wód stojących, a najlepsze wyniki osiąga się tu późną wiosną i latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22104, 1.8, 1.1, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś srebrzysty,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22105, 'Starorzecze (Zajączkowo)', 'starorzecze-zajaczkowo-zajaczkowo-22105', 'OXBOW', 54.3934325, 17.0311701, 'Pomorskie', 'Zajączkowo', 'To starorzecze w Zajączkowie, choć umiarkowanie zarośnięte, oferuje ciekawe możliwości wędkarskie, szczególnie dla poszukujących drapieżników. Akwen łączy się z rzeką podczas wysokiej wody, co zapewnia okresowe odświeżenie wody i wpływanie nowych ryb. Brzegi są mocno zarośnięte trzciną, co wymaga użycia woderów i cierpliwości w poszukiwaniu dogodnych miejsc. Dno jest średnio zamulone, z pojedynczymi korzeniami i gałęziami stanowiącymi naturalne kryjówki dla ryb. Dominujące gatunki to szczupak, lin, płoć i okoń. Ryzyko przyduchy jest obecne w okresach długotrwałego upału. Najlepsze wyniki osiąga się tu wiosną i wczesną jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22105, 2.5, 1.3, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22106, 'Starorzecze (Zajączkowo)', 'starorzecze-zajaczkowo-zajaczkowo-22106', 'OXBOW', 54.3945456, 17.0292062, 'Pomorskie', 'Zajączkowo', 'To bardzo małe i płytkie starorzecze w Zajączkowie jest akwenem o ekstremalnie trudnych warunkach wędkarskich, często wysychającym w okresach suszy. Brzegi są bagniste i praktycznie niedostępne bez woderów, a całe dno pokryte jest grubą warstwą mułu i gęstą roślinnością podwodną. Woda jest silnie zarośnięta, co sprawia, że wędkowanie jest prawdziwym wyzwaniem. Dominujące gatunki ryb to odporne karasie pospolite i wzdręgi, które potrafią przetrwać w tak trudnych warunkach. Ryzyko przyduchy jest tu najwyższe, niemal pewne w upalne lato. Mimo wszystko, dla entuzjastów dzikich łowisk, może to być miejsce na złowienie wyjątkowo pięknego karasia, choć wymaga to determinacji. Najlepszy, choć krótki, okres na wędkowanie to środek lata, gdy poziom wody jest jeszcze wystarczający.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22106, 0.9, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22107, 'Starorzecze (Krępa Słupska)', 'starorzecze-krepa-slupska-krepa-slupska-22107', 'OXBOW', 54.4086506, 17.0249337, 'Pomorskie', 'Krępa Słupska', 'To starorzecze w Krępie Słupskiej jest średniej wielkości akwenem, który łączy się z rzeką podczas wysokich stanów wody, co sprzyja odświeżaniu ekosystemu. Charakteryzuje się umiarkowanym zarośnięciem i dnem, które miejscami jest muliste, a miejscami twardsze, z pojedynczymi korzeniami i gałęziami. Dostęp do brzegów jest dobry z obu stron, co ułatwia wędkarzom wybór stanowiska. W wodzie można spotkać szczupaki, liny, leszcze, płocie i okonie, co czyni to łowisko atrakcyjnym dla różnych technik wędkarskich. Pomimo umiarkowanego zarośnięcia, ryzyko przyduchy istnieje w upalne lata, dlatego warto monitorować warunki. Najlepsze efekty wędkarskie osiąga się tu wiosną i wczesną jesienią, kiedy ryby intensywnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22107, 4, 1.6, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22108, 'Starorzecze (Łosino)', 'starorzecze-losino-losino-22108', 'OXBOW', 54.4245534, 17.0288283, 'Pomorskie', 'Łosino', 'To rozległe starorzecze w Łosinie wyróżnia się stałym połączeniem z główną rzeką, co gwarantuje ciągłą wymianę wody i doskonałe natlenienie, minimalizując ryzyko przyduchy. Dno jest w dużej mierze czyste, z niewielką ilością mułu, co sprzyja różnorodności gatunków ryb. Brzegi są łatwo dostępne z obu stron, co czyni to łowisko bardzo komfortowym dla wędkarzy. Roślinność wodna jest słaba, co ułatwia prowadzenie przynęt i manewrowanie sprzętem. Wśród dominujących gatunków ryb znajdziemy szczupaki, okonie, leszcze, płocie, a także węgorze, które swobodnie migrują z rzeki. Dzięki stabilnym warunkom i obfitości ryb, starorzecze to jest atrakcyjne przez cały sezon wędkarski, oferując wspaniałe doświadczenia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22108, 6.1, 2, 4.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Węgorz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22109, 'Starorzecze (Łysomiczki)', 'starorzecze-lysomiczki-lysomiczki-22109', 'OXBOW', 54.3573063, 17.1786397, 'Pomorskie', 'Łysomiczki', 'To niewielkie starorzecze w Łysomiczkach jest płytkim i silnie zarośniętym akwenem, który w okresach długotrwałej suszy może całkowicie wyschnąć. Brzegi są mocno zarośnięte trzciną i trudno dostępne, co wymaga użycia woderów, aby dotrzeć do otwartych partii wody. Dno jest bardzo muliste i gęsto pokryte roślinnością podwodną, co stanowi wyzwanie dla wędkarzy. Dominujące gatunki ryb to karasie pospolite i wzdręgi, które są odporne na trudne warunki środowiskowe. Ze względu na płytkość i dużą ilość materii organicznej, ryzyko przyduchy jest bardzo wysokie, szczególnie w upalne miesiące. Mimo to, dla cierpliwych wędkarzy, starorzecze to może zaoferować satysfakcjonujące połowy karasi. Najlepszy, choć krótki, okres na wędkowanie to środek lata, gdy poziom wody jest jeszcze odpowiedni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22109, 1.5, 0.9, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22110, 'Starorzecze (Łysomiczki)', 'starorzecze-lysomiczki-lysomiczki-22110', 'OXBOW', 54.3575073, 17.1647683, 'Pomorskie', 'Łysomiczki', 'To starorzecze w Łysomiczkach, o średnim stopniu zamulenia, łączy się z rzeką podczas wysokich stanów wody, co sprzyja odświeżaniu środowiska. Brzegi są bagniste i trudne do przejścia, co często wymaga użycia woderów, aby dotrzeć do dogodnego miejsca. Dno jest zróżnicowane, z miejscami mulistymi i pojedynczymi korzeniami oraz gałęziami, które stanowią kryjówki dla ryb. W wodzie panuje umiarkowane zarośnięcie, co sprzyja zarówno drapieżnikom, jak i rybom spokojnego żeru. Dominujące gatunki to lin, szczupak, płoć i okoń. Ryzyko przyduchy jest obecne w okresach długotrwałego upału. Najlepsze efekty wędkarskie osiąga się tu wiosną i wczesną jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22110, 3, 1.4, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Płoć,Okoń', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22111, 'Starorzecze (Łysomiczki)', 'starorzecze-lysomiczki-lysomiczki-22111', 'OXBOW', 54.3569113, 17.1680447, 'Pomorskie', 'Łysomiczki', 'To starorzecze w Łysomiczkach jest akwenem o umiarkowanym zarośnięciu i średnim stopniu zamulenia, oferującym dobre warunki do wędkowania. Mimo braku stałego połączenia z rzeką, jego rozmiar pozwala na utrzymanie stabilnych warunków. Dno jest zróżnicowane, z miejscami mulistymi i gęstą roślinnością podwodną, która stanowi schronienie i żerowisko dla ryb. Dostęp do brzegów jest dobry z obu stron, co ułatwia znalezienie dogodnego miejsca. Wśród dominujących gatunków ryb znajdziemy leszcze, płocie, liny i karpie, które dobrze czują się w spokojnych wodach starorzeczy. Ryzyko przyduchy jest umiarkowane, ale w upalne lata warto zachować ostrożność. Łowisko jest atrakcyjne przez cały sezon, zwłaszcza dla miłośników ryb spokojnego żeru.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22111, 4.5, 1.7, 3.8, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Leszcz,Płoć,Lin,Karp', 'Dobry z obu stron', FALSE, 'Gęsta roślinność podwodna', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22112, 'Starorzecze (Lubuń)', 'starorzecze-lubun-lubun-22112', 'OXBOW', 54.3855327, 17.0448241, 'Pomorskie', 'Lubuń', 'To starorzecze w Lubuniu jest wyzwaniem dla wędkarzy ze względu na silne zarośnięcie brzegów trzciną i dużą ilość zatopionych drzew. Akwen łączy się z rzeką podczas wysokiej wody, co zapewnia okresowe odświeżenie środowiska. Dno jest mocno zamulone, a liczne zatopione drzewa tworzą idealne kryjówki dla ryb, ale jednocześnie utrudniają wędkowanie. Dostęp do wody jest trudny i często wymaga użycia woderów. Dominujące gatunki ryb to lin, karaś pospolity, a także szczupak i okoń, które polują wśród podwodnych przeszkód. Ze względu na płytkość i dużą ilość materii organicznej, ryzyko przyduchy jest wysokie. Najlepsze wyniki osiąga się tu wiosną i wczesną jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22112, 2.8, 1.2, 2.7, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22113, 'Starorzecze (Lubuń)', 'starorzecze-lubun-lubun-22113', 'OXBOW', 54.384173, 17.0456911, 'Pomorskie', 'Lubuń', 'To bardzo płytkie i mocno zamulone starorzecze w Lubuniu jest akwenem, który w okresach suszy może całkowicie wyschnąć, co wpływa na jego biologię. Brzegi są bagniste i trudno dostępne, co często wymaga użycia woderów, aby dotrzeć do wody. Dno jest w przeważającej części pokryte grubą warstwą mułu i gęstą roślinnością podwodną. Wśród dominujących gatunków ryb znajdziemy odporne karasie pospolite, wzdręgi oraz płocie, które doskonale adaptują się do zmiennych warunków. Ze względu na płytkość i obfitość materii organicznej, istnieje wysokie ryzyko przyduchy, zwłaszcza w upalne lata. Mimo trudnych warunków, starorzecze to oferuje szansę na złowienie pięknych okazów, szczególnie w środku lata, gdy woda jest jeszcze obecna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22113, 1.2, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22114, 'Starorzecze (Kwakowo)', 'starorzecze-kwakowo-kwakowo-22114', 'OXBOW', 54.3877287, 17.0419568, 'Pomorskie', 'Kwakowo', 'To duże i głębokie starorzecze w Kwakowie wyróżnia się stałym połączeniem z rzeką, co zapewnia doskonałe natlenienie i minimalizuje ryzyko przyduchy. Dno jest zróżnicowane, od piaszczysto-żwirowego po miejsca z niewielką warstwą mułu, z pojedynczymi korzeniami i gałęziami. Brzegi są łatwo dostępne z obu stron, co umożliwia komfortowe wędkowanie. Woda jest umiarkowanie zarośnięta, co sprzyja różnorodności gatunków ryb, w tym dużym drapieżnikom. Dominują tu sumy, szczupaki, leszcze, karpie, a także węgorze, które swobodnie migrują z rzeki. Dzięki stabilnym warunkom i obfitości ryb, łowisko to jest atrakcyjne przez cały sezon wędkarski, oferując szansę na złowienie naprawdę dużych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22114, 5.8, 2.5, 5.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Leszcz,Karp,Węgorz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22115, 'Starorzecze Sielpia Wielka', 'starorzecze-sielpia-wielka-sielpia-wielka-22115', 'OXBOW', 51.1166142, 20.3689269, 'Świętokrzyskie', 'Sielpia Wielka', 'To malownicze starorzecze, położone w pobliżu popularnej miejscowości wypoczynkowej Sielpia Wielka, stanowi oazę spokoju dla wędkarzy. Charakteryzuje się piaszczysto-mulistym dnem, z licznymi zatopionymi korzeniami i gałęziami, co tworzy idealne kryjówki dla ryb. Brzegi są częściowo dostępne, choć miejscami porasta je gęsta trzcina i pałka wodna. Wiosną i jesienią można tu liczyć na dobre brania szczupaków i okoni, natomiast latem dominuje leszcz i płoć. Wędkowanie wymaga cierpliwości i precyzji ze względu na liczne zaczepy. Woda jest stosunkowo czysta, ale w upalne lata ryzyko przyduchy wzrasta.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22115, 3.2, 1.8, 3.5, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń', 'Częściowo dostępny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22116, 'Starorzecze Słowików (północne)', 'starorzecze-slowikow-polnocne-slowikow-22116', 'OXBOW', 51.4538122, 20.8879441, 'Mazowieckie', 'Słowików', 'To jedno z kilku starorzeczy w okolicy Słowików, charakteryzujące się rozległym, mulistym dnem, idealnym dla ryb karpiowatych. Brzegi są stosunkowo łagodne, ale w większości mocno zarośnięte trzciną i inną roślinnością przybrzeżną, co utrudnia dostęp do wody. Wędkowanie z gruntu jest tu bardzo efektywne, zwłaszcza na liny i karasie, które licznie zamieszkują te wody. Wiosną, podczas wysokich stanów wody, starorzecze łączy się z głównym nurtem rzeki, co sprzyja migracji ryb. Latem roślinność podwodna staje się bardzo gęsta, tworząc liczne kryjówki, ale i utrudniając prowadzenie przynęty. Ryzyko przyduchy jest umiarkowane.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22116, 5.8, 1.5, 2.8, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Leszcz', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22117, 'Starorzecze Słowików (środkowe)', 'starorzecze-slowikow-srodkowe-slowikow-22117', 'OXBOW', 51.4536877, 20.8868457, 'Mazowieckie', 'Słowików', 'Drugie z serii starorzeczy w Słowikach, wyróżniające się nieco większą głębokością w centralnej części, co sprzyja występowaniu większych drapieżników. Dno jest mieszane – od mulistego po twardsze, piaszczyste fragmenty, szczególnie wzdłuż dawnego koryta rzeki. Dostęp do brzegów jest umiarkowanie trudny, z miejscowymi prześwitami wśród drzew i krzewów. Jest to doskonałe miejsce na zasiadki karpiowe, a także na spinning za szczupakiem i okoniem. Starorzecze to rzadko łączy się z rzeką, co sprzyja stabilizacji populacji ryb. Należy uważać na liczne zatopione gałęzie, które mogą powodować zaczepy. Woda utrzymuje dobry poziom tlenu przez większość roku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22117, 4.1, 2, 4, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Szczupak,Okoń,Leszcz', 'Umiarkowanie trudny, z prześwitami', TRUE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22118, 'Starorzecze Słowików (południowe)', 'starorzecze-slowikow-poludniowe-slowikow-22118', 'OXBOW', 51.4536233, 20.8717154, 'Mazowieckie', 'Słowików', 'Najmniejsze i najbardziej dzikie z kompleksu starorzeczy w Słowikach, charakteryzujące się płytkim, silnie zamulonym dnem. Brzegi są niemal całkowicie niedostępne, otoczone gęstymi zaroślami i podmokłym terenem, co czyni je idealnym schronieniem dla dzikich ryb. Jest to raj dla wędkarzy poszukujących karasia pospolitego oraz wzdręgi. Wędkowanie wymaga użycia długich tyczek lub pontonu, aby dotrzeć do otwartych lusterek wody. Ze względu na niewielką głębokość i obfitość roślinności, ryzyko niedoboru tlenu w upalne dni jest bardzo wysokie. Starorzecze to nigdy nie łączy się z rzeką, co sprzyja izolacji i naturalnemu rozwojowi ekosystemu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22118, 2.5, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin,Płoć', 'Trudny, bagnisty, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna i pojedyncze konary', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22119, 'Starorzecze Jarentowskie Pole (północne)', 'starorzecze-jarentowskie-pole-polnocne-pulawy-22119', 'OXBOW', 51.2132961, 21.7822312, 'Lubelskie', 'Puławy', 'To rozległe starorzecze w pobliżu Jarentowskiego Pola, charakteryzujące się urozmaiconym dnem, od piaszczystych płycizn po głębsze, muliste rynny. Jest to popularne łowisko ze względu na dobrą populację leszcza i płoci, a także drapieżników takich jak szczupak i sandacz. Brzegi są dość łatwo dostępne w wielu miejscach, co sprzyja weekendowym wypadom. Okresowo, przy wysokim stanie wody w Wiśle, starorzecze łączy się z głównym nurtem, co odświeża wodę i wprowadza nowe gatunki ryb. Latem dno pokrywa się umiarkowaną ilością roślinności, która stanowi schronienie dla drobnicy. Wędkowanie z gruntu i na spławik daje tu najlepsze rezultaty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22119, 12, 2.2, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Sandacz,Okoń', 'Dobry z wielu stron', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22120, 'Starorzecze Jarentowskie Pole (środkowe zachodnie)', 'starorzecze-jarentowskie-pole-srodkowe-zachodnie-pulawy-22120', 'OXBOW', 51.2077944, 21.7888684, 'Lubelskie', 'Puławy', 'Mniejsze i bardziej dzikie niż sąsiednie starorzecza, to łowisko jest prawdziwą gratką dla miłośników spokoju i kontaktu z naturą. Dno jest w większości muliste, z licznymi zatopionymi drzewami i krzewami, co wymaga od wędkarzy doświadczenia i odpowiedniego sprzętu. Brzegi są trudno dostępne, gęsto zarośnięte, co sprawia, że wędkarstwo z pontonu jest często najlepszym rozwiązaniem. Występuje tu bogata populacja lina i karasia pospolitego, a także okazowe sumy, które znajdują schronienie wśród zaczepów. Starorzecze to jest odcięte od Wisły, co sprzyja stabilizacji warunków wodnych i rozwojowi specyficznej ichtiofauny. W upalne lata może występować ryzyko przyduchy, zwłaszcza w płytkich zatokach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22120, 4.5, 1.5, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Sum,Szczupak', 'Trudny, bagnisty, mocno zarośnięty', TRUE, 'Dużo zatopionych drzew i gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22121, 'Starorzecze Jarentowskie Pole (środkowe wschodnie)', 'starorzecze-jarentowskie-pole-srodkowe-wschodnie-pulawy-22121', 'OXBOW', 51.2029632, 21.7835657, 'Lubelskie', 'Puławy', 'To starorzecze charakteryzuje się bardziej otwartym charakterem niż jego sąsiedzi, z mniejszą ilością roślinności podwodnej w centralnej części. Dno jest piaszczysto-muliste, z twardszymi fragmentami, co jest atrakcyjne dla różnorodnych gatunków ryb. Dostęp do brzegów jest dobry z jednej strony, gdzie znajduje się niewielka polanka, idealna na rodzinne wędkowanie. Starorzecze to jest znane z obfitości płoci i leszcza, a także z występowania dużych karpi. Połączenie z rzeką jest rzadkie, co sprzyja rozwojowi stabilnej populacji ryb. Wędkarze powinni przygotować się na sporadyczne zaczepy, szczególnie w pobliżu zarośniętych brzegów. Woda zazwyczaj utrzymuje dobrą jakość.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22121, 6, 1.9, 3.8, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Karp,Okoń', 'Dobry z jednej strony, pozostałe zarośnięte', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22122, 'Starorzecze Jarentowskie Pole (południowe)', 'starorzecze-jarentowskie-pole-poludniowe-pulawy-22122', 'OXBOW', 51.2133556, 21.7886116, 'Lubelskie', 'Puławy', 'To starorzecze jest najdłuższe w kompleksie, rozciągające się wzdłuż dawnego koryta rzeki, co nadaje mu specyficzny, rynnowy kształt. Dno jest mocno zamulone, z licznymi zagłębieniami i wypłyceniami, które tworzą zróżnicowane siedliska dla ryb. Brzegi są zróżnicowane – od łatwo dostępnych fragmentów po gęsto zarośnięte i bagniste odcinki. Jest to doskonałe miejsce na połów lina, karasia i leszcza, a także węgorza, który znajduje tu idealne warunki do żerowania. Połączenie z Wisłą następuje jedynie podczas bardzo wysokich wód, co sprawia, że ekosystem jest względnie stabilny. Należy uważać na liczne zaczepy i gęstą roślinność podwodną, szczególnie latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22122, 8.5, 1.7, 3.2, 'Podczas bardzo wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Leszcz,Węgorz', 'Zróżnicowany, miejscami trudny', TRUE, 'Gęsta roślinność podwodna i liczne zatopione gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22123, 'Starorzecze Dzierlin (północne)', 'starorzecze-dzierlin-polnocne-sieradz-22123', 'OXBOW', 51.6354822, 18.7017339, 'Łódzkie', 'Sieradz', 'To starorzecze, położone w malowniczej okolicy Dzierlina, charakteryzuje się dość twardym, piaszczysto-mulistym dnem, z nielicznymi zaczepami, co sprzyja różnym technikom wędkowania. Brzegi są dobrze dostępne, częściowo utwardzone, co ułatwia dotarcie do wody i rozłożenie sprzętu. Jest to popularne łowisko dla wędkarzy szukających płoci, leszcza i okonia, a także okazjonalnie szczupaka. Starorzecze to ma stałe, choć wąskie połączenie z rzeką Wartą, co zapewnia stały przepływ wody i odświeżanie łowiska. Roślinność podwodna jest umiarkowana, co ułatwia prowadzenie przynęt. Ryzyko przyduchy jest niskie dzięki stałemu połączeniu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22123, 7, 2.5, 5.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak,Jaź', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22124, 'Starorzecze Dzigorzew', 'starorzecze-dzigorzew-sieradz-22124', 'OXBOW', 51.6350987, 18.7024731, 'Łódzkie', 'Sieradz', 'To niewielkie, ale głębokie starorzecze w pobliżu Dzigorzewa jest prawdziwą perełką dla wędkarzy. Charakteryzuje się głęboką rynną w centralnej części i mulistym dnem, obfitującym w zatopione drzewa i korzenie. Brzegi są strome i gęsto zarośnięte, co sprawia, że dostęp jest trudny, ale nagradza wędkarzy szukających dużych okazów. Jest to idealne miejsce na połów suma i węgorza, które znajdują tu doskonałe warunki do życia. Starorzecze to jest odcięte od głównego nurtu rzeki, co sprzyja stabilizacji warunków i rozwojowi dużych ryb. Wędkowanie wymaga cierpliwości i umiejętności omijania zaczepów. Ryzyko niedoboru tlenu jest niskie ze względu na głębokość.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22124, 2.8, 3, 6, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Sum,Węgorz,Szczupak,Lin', 'Trudny, strome i zarośnięte brzegi', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22125, 'Starorzecze Dzierlin (środkowe)', 'starorzecze-dzierlin-srodkowe-sieradz-22125', 'OXBOW', 51.6358181, 18.700767, 'Łódzkie', 'Sieradz', 'Środkowe starorzecze w Dzierlinie to typowe łowisko karpiowe, z rozległymi płyciznami i głębszymi dołkami. Dno jest zróżnicowane, od twardego piasku po miękki muł, co sprzyja różnorodności gatunkowej. Brzegi są częściowo dostępne, z miejscami do rozłożenia sprzętu, choć miejscami występują gęste zarośla. Jest to doskonałe miejsce na karpia, lina i karasia pospolitego, które licznie występują w tych wodach. Starorzecze to łączy się z rzeką tylko podczas bardzo wysokich stanów wody, co pozwala na okresowe odświeżenie ekosystemu. Roślinność podwodna jest umiarkowana, ale latem może być problematyczna. Wędkowanie z gruntu daje najlepsze efekty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22125, 6.5, 1.6, 3, 'Podczas bardzo wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Karp,Lin,Karaś pospolity,Płoć', 'Częściowo dostępny', TRUE, 'Pojedyncze korzenie i gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22126, 'Starorzecze Dzierlin (południowe)', 'starorzecze-dzierlin-poludniowe-sieradz-22126', 'OXBOW', 51.6387756, 18.6989239, 'Łódzkie', 'Sieradz', 'To starorzecze jest najbardziej zarośnięte w kompleksie Dzierlina, co czyni je idealnym siedliskiem dla ryb lubiących kryjówki. Dno jest w większości muliste, z grubą warstwą osadów organicznych i licznymi zatopionymi gałęziami. Brzegi są niemal całkowicie niedostępne, otoczone gęstą trzciną i krzewami, co wymaga użycia pontonu lub specjalistycznego sprzętu. Jest to raj dla wędkarzy poszukujących lina, karasia pospolitego i dużych wzdręg. Starorzecze to jest całkowicie odcięte od rzeki, co sprzyja rozwojowi specyficznej flory i fauny. W upalne lata ryzyko przyduchy jest bardzo wysokie ze względu na płytkość i obfitość roślinności. Wędkowanie jest tu wyzwaniem, ale nagradza pięknymi okazami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22126, 3, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, mocno zarośnięty trzciną i bagnisty', TRUE, 'Gęsta roślinność podwodna i liczne zatopione gałęzie', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22127, 'Starorzecze Biskupice (północne)', 'starorzecze-biskupice-polnocne-sieradz-22127', 'OXBOW', 51.6514176, 18.6887892, 'Łódzkie', 'Sieradz', 'To starorzecze w Biskupicach charakteryzuje się stosunkowo czystym, piaszczysto-mulistym dnem i umiarkowaną głębokością, co czyni je atrakcyjnym dla wielu gatunków ryb. Brzegi są dobrze dostępne z kilku stron, z wygodnymi stanowiskami dla wędkarzy, co sprzyja rekreacyjnemu wędkowaniu. Jest to doskonałe miejsce na połów płoci, leszcza i okonia, a także bolenia, który bywa tu widywany podczas żerowania. Starorzecze to ma okresowe połączenie z rzeką, co zapewnia dopływ świeżej wody i migrację ryb. Roślinność podwodna jest umiarkowana, co ułatwia prowadzenie przynęt spinningowych. Ryzyko przyduchy jest niskie dzięki dobrej cyrkulacji wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22127, 9, 2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Boleń,Jaź', 'Dobry z kilku stron', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22128, 'Starorzecze Biskupice (środkowe)', 'starorzecze-biskupice-srodkowe-sieradz-22128', 'OXBOW', 51.649484, 18.6827156, 'Łódzkie', 'Sieradz', 'To starorzecze jest głębsze niż sąsiednie, z wyraźną rynną wzdłuż dawnego koryta rzeki, co sprzyja występowaniu większych drapieżników i ryb dennych. Dno jest muliste, z licznymi zatopionymi drzewami i korzeniami, co tworzy idealne kryjówki. Brzegi są strome i gęsto zarośnięte, co utrudnia dostęp, ale nagradza wędkarzy szukających dzikich okazów. Jest to doskonałe miejsce na połów suma, szczupaka i węgorza, a także dużych karpi. Starorzecze to jest odcięte od rzeki, co sprzyja stabilizacji warunków i rozwojowi dużych ryb. Wędkowanie wymaga cierpliwości i umiejętności omijania zaczepów, ale może przynieść imponujące rezultaty. Ryzyko przyduchy jest niskie ze względu na głębokość.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22128, 5, 2.8, 5.5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Węgorz,Karp', 'Trudny, strome i zarośnięte brzegi', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22129, 'Starorzecze Biskupice (południowe)', 'starorzecze-biskupice-poludniowe-sieradz-22129', 'OXBOW', 51.6487257, 18.6839247, 'Łódzkie', 'Sieradz', 'Najmniejsze z kompleksu starorzeczy w Biskupicach, to łowisko charakteryzuje się płytkim, silnie zamulonym dnem i bardzo gęstą roślinnością podwodną. Brzegi są niemal całkowicie niedostępne, otoczone gęstymi zaroślami i podmokłym terenem, co sprawia, że jest to idealne schronienie dla drobnicy i ryb spokojnego żeru. Jest to raj dla wędkarzy poszukujących karasia pospolitego, lina i wzdręgi. Wędkowanie wymaga użycia długich tyczek lub pontonu, aby dotrzeć do otwartych lusterek wody. Starorzecze to jest całkowicie odcięte od rzeki, co sprzyja izolacji i naturalnemu rozwojowi ekosystemu. Ze względu na niewielką głębokość i obfitość roślinności, ryzyko niedoboru tlenu w upalne dni jest bardzo wysokie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22129, 1.8, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna i pojedyncze konary', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22130, 'Starorzecze Biskupice A', 'starorzecze-biskupice-a-biskupice-22130', 'OXBOW', 51.6495898, 18.6850816, 'Wielkopolskie', 'Biskupice', 'To malownicze starorzecze, położone w pobliżu Biskupic, stanowi atrakcyjne łowisko dla wielu wędkarzy. Charakteryzuje się umiarkowanym zarośnięciem brzegów i dnem częściowo pokrytym mułem, co sprzyja rozwojowi bogatej fauny dennej. Dostęp do wody jest stosunkowo łatwy, a brzegi są stabilne, co pozwala na komfortowe wędkowanie z gruntu i na spławik. Podczas wysokich stanów wody zbiornik łączy się z głównym korytem rzeki, co wzbogaca populację ryb o nowe osobniki. Dominują tu szczupaki, liny i płocie, które można z powodzeniem łowić przez większą część sezonu. Miejscami występują zatopione gałęzie, które stanowią doskonałe kryjówki dla drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22130, 2.3, 1.5, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Płoć,Leszcz,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22131, 'Starorzecze Biskupice B', 'starorzecze-biskupice-b-biskupice-22131', 'OXBOW', 51.6506435, 18.6871754, 'Wielkopolskie', 'Biskupice', 'Starorzecze Biskupice B to niewielki, silnie zarośnięty zbiornik wodny, idealny dla miłośników spokojnego wędkowania w otoczeniu natury. Jego dno jest mocno zamulone, co w połączeniu z bujną roślinnością podwodną tworzy doskonałe środowisko dla karasi pospolitych i linów. Dostęp do brzegu jest utrudniony przez gęste trzcinowiska i wymaga użycia wodoodpornych spodniobutów. Ze względu na brak stałego połączenia z rzeką i wysoki poziom zamulenia, istnieje ryzyko przyduchy w upalne lata. Najlepsze efekty wędkarskie osiąga się tu wiosną i latem, skupiając się na łowieniu z powierzchni lub w wolnych od zarośli zatoczkach. W zbiorniku występują również szczupaki, które polują wśród podwodnych łąk.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22131, 1.8, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22132, 'Starorzecze Biskupice C', 'starorzecze-biskupice-c-biskupice-22132', 'OXBOW', 51.6498172, 18.6863823, 'Wielkopolskie', 'Biskupice', 'To starorzecze charakteryzuje się stosunkowo czystym dnem i niewielkim zarośnięciem, co ułatwia wędkowanie i eksplorację łowiska. Głębokość zbiornika jest zróżnicowana, z kilkoma głębszymi rynnami, które stanowią schronienie dla większych ryb. Brzegi są łatwo dostępne, umożliwiając wygodne zarzucanie wędki z wielu miejsc. Okresowe połączenie z rzeką zapewnia stałe zasilanie w wodę i wzbogacanie ichtiofauny. Dominują tu leszcze, płocie i okonie, a także sporadycznie trafiają się węgorze. Jest to idealne miejsce do wędkowania przez cały rok, oferujące dobre warunki zarówno dla wędkarzy spławikowych, jak i gruntowych. Brak większych zaczepów sprawia, że jest to łowisko przyjazne dla początkujących.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22132, 3.1, 1.8, 4, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Węgorz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22133, 'Starorzecze Biskupice D', 'starorzecze-biskupice-d-biskupice-22133', 'OXBOW', 51.6504582, 18.6891491, 'Wielkopolskie', 'Biskupice', 'Starorzecze Biskupice D to płytki zbiornik o średnim zamuleniu, otoczony bagnistymi brzegami, co sprawia, że dostęp do wody jest dość wymagający. Wymaga to użycia wodoodpornych spodniobutów, aby dotrzeć do dogodnych miejsc wędkarskich. Roślinność podwodna jest umiarkowana, tworząc mozaikę otwartych przestrzeni i zarośli. Ze względu na brak połączenia z rzeką i stosunkowo niewielką głębokość, w upalne lata istnieje ryzyko niedoboru tlenu. W akwenie dominują karasie srebrzyste, wzdręgi i liny, a także spotkać można okonie. Najlepsze wyniki osiąga się tu w cieplejszych miesiącach, celując w strefy brzegowe i płycizny. Warto szukać zatopionych korzeni, które często stanowią kryjówki dla ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22133, 2.5, 1.2, 2.8, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Karaś srebrzysty,Wzdręga,Lin,Okoń', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22134, 'Starorzecze Brześce-Kolonia A', 'starorzecze-brzesce-kolonia-a-brzesce-kolonia-22134', 'OXBOW', 51.2895293, 21.8534908, 'Lubelskie', 'Brześce-Kolonia', 'To duże starorzecze, położone w pobliżu Brześc-Kolonii, charakteryzuje się stałym połączeniem z rzeką Wisłą, co zapewnia ciągły przepływ wody i bogactwo gatunkowe. Dno jest przeważnie czyste, piaszczysto-żwirowe, z niewielkim zamuleniem w głębszych partiach. Brzegi są łatwo dostępne i stabilne, co czyni to miejsce bardzo popularnym wśród wędkarzy. Jest to prawdziwa gratka dla łowców dużych okazów, gdyż w starorzeczu występują okazałe leszcze, karpie, a także sumy i sandacze. Okresowo wpływają tu również bolenie i jazie z głównego nurtu rzeki. Łowisko jest aktywne przez cały sezon, oferując różnorodne metody wędkowania, od spławika po spinning. Brak większych zaczepów ułatwia holowanie ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22134, 5.5, 2, 4.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sum,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22135, 'Starorzecze Brześce-Kolonia B', 'starorzecze-brzesce-kolonia-b-brzesce-kolonia-22135', 'OXBOW', 51.2874325, 21.8522559, 'Lubelskie', 'Brześce-Kolonia', 'Starorzecze Brześce-Kolonia B to zbiornik o umiarkowanej głębokości, z brzegami porośniętymi gęstymi trzcinami, co wymaga użycia wodoodpornych spodniobutów. Dno jest zróżnicowane, z miejscami zamulonymi i licznymi zatopionymi drzewami, które stanowią schronienie dla ryb. Połączenie z Wisłą następuje jedynie podczas wysokich stanów wody, co wpływa na dynamikę populacji ryb. Wędkarze mogą liczyć na udane połowy szczupaków i okoni, które aktywnie polują wśród zaczepów. Występują tu również leszcze i płocie, a także sporadycznie węgorze. Najlepsze okresy na wędkowanie to wiosna i wczesna jesień, kiedy ryby są najbardziej aktywne. Trzeba być przygotowanym na trudności z holowaniem ryb z uwagi na zaczepy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22135, 4.2, 1.7, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Węgorz', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22136, 'Starorzecze Zajączków', 'starorzecze-zajaczkow-zajaczkow-22136', 'OXBOW', 51.2399788, 21.6644011, 'Lubelskie', 'Zajączków', 'Starorzecze Zajączków to rozległy i głęboki zbiornik, cieszący się opinią jednego z najlepszych łowisk w regionie. Posiada stałe połączenie z rzeką, co gwarantuje obfitość ryb i dobrą jakość wody. Dno jest przeważnie twarde, piaszczyste, z nielicznymi zaczepami, co ułatwia wędkowanie. Brzegi są łatwo dostępne, a wokół zbiornika znajdują się liczne miejsca do biwakowania. W starorzeczu dominują duże leszcze, płocie i karpie, ale prawdziwą atrakcją są sandacze i bolenie, które regularnie wpływają z rzeki. Jest to łowisko całoroczne, oferujące doskonałe warunki zarówno dla wędkarzy gruntowych, jak i spinningistów. Warto poświęcić czas na dokładne zbadanie dna, aby znaleźć najlepsze miejscówki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22136, 6.8, 2.2, 5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sandacz,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22137, 'Starorzecze Stężyca A', 'starorzecze-stezyca-a-stezyca-22137', 'OXBOW', 51.5697756, 21.8150995, 'Lubelskie', 'Stężyca', 'Starorzecze Stężyca A to zbiornik o umiarkowanej wielkości, charakteryzujący się bagnistymi i trudno dostępnymi brzegami, co wymaga użycia wodoodpornych spodniobutów. Dno jest częściowo zamulone, z licznymi zatopionymi drzewami i korzeniami, które stanowią doskonałe kryjówki dla ryb. Połączenie z rzeką następuje jedynie podczas wysokich stanów wody, co wpływa na zmienność populacji. W starorzeczu dominują szczupaki i okonie, które aktywnie polują wśród zaczepów, a także liny i karasie pospolite. Łowisko jest idealne dla wędkarzy poszukujących dzikich, nieuregulowanych miejsc i wyzwań. Najlepsze wyniki osiąga się tu wczesną wiosną i jesienią, kiedy drapieżniki są najbardziej żerujące. Warto używać mocnego sprzętu, aby uniknąć strat w zaczepach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22137, 3.5, 1.6, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Lin,Karaś pospolity', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22138, 'Starorzecze Toruń A', 'starorzecze-torun-a-torun-22138', 'OXBOW', 53.0045588, 18.574405, 'Kujawsko-Pomorskie', 'Toruń', 'To jedno z toruńskich starorzeczy, zlokalizowane blisko miasta, ale oferujące ucieczkę od zgiełku. Posiada stałe połączenie z Wisłą, co zapewnia regularne zarybienia i dobrą jakość wody. Dno jest przeważnie twarde, z niewielkim zamuleniem, a brzegi są łatwo dostępne i często uczęszczane przez wędkarzy. W zbiorniku dominują leszcze, płocie i okonie, a także często trafiają się karpie i szczupaki. Jest to łowisko całoroczne, popularne zarówno wśród mieszkańców Torunia, jak i przyjezdnych. Doskonałe warunki do wędkowania spławikowego, gruntowego oraz spinningowego. Mimo bliskości miasta, można tu liczyć na spokojny dzień nad wodą i udane połowy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22138, 2.8, 1.8, 4, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22139, 'Starorzecze Toruń B', 'starorzecze-torun-b-torun-22139', 'OXBOW', 53.0046324, 18.5727576, 'Kujawsko-Pomorskie', 'Toruń', 'Mniejsze starorzecze w okolicach Torunia, charakteryzujące się umiarkowanym zarośnięciem i dnem częściowo pokrytym mułem. Dostęp do brzegu jest utrudniony przez gęste trzcinowiska, co wymaga użycia wodoodpornych spodniobutów. Połączenie z Wisłą następuje jedynie podczas wysokich stanów wody, co sprzyja wymianie ryb. W zbiorniku dominują liny, karasie pospolite i wzdręgi, które doskonale czują się w zarośniętych partiach. Można tu również spotkać mniejsze okonie. Łowisko jest idealne dla wędkarzy ceniących ciszę i spokój, preferujących delikatne metody połowu. Najlepsze efekty osiąga się w cieplejszych miesiącach, zwłaszcza wczesnym rankiem lub wieczorem. Warto szukać wolnych przestrzeni między roślinnością.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22139, 1.5, 1.2, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22140, 'Starorzecze Toruń C', 'starorzecze-torun-c-torun-22140', 'OXBOW', 53.0045461, 18.5694329, 'Kujawsko-Pomorskie', 'Toruń', 'Starorzecze Toruń C to płytki i silnie zamulony zbiornik, otoczony bagnistymi brzegami, co sprawia, że dostęp do wody jest bardzo trudny. Wymaga to dużej ostrożności i użycia wodoodpornych spodniobutów. Roślinność podwodna jest bardzo bujna, tworząc gęste łąki. Ze względu na brak połączenia z rzeką i wysokie zamulenie, ryzyko przyduchy w upalne lata jest znaczące. W zbiorniku dominują karasie srebrzyste, wzdręgi i liny, które doskonale adaptują się do trudnych warunków. Łowisko jest przeznaczone dla wędkarzy poszukujących wyzwań i ceniących dziką przyrodę. Najlepsze wyniki osiąga się w cieplejszych miesiącach, skupiając się na łowieniu w niewielkich prześwitach. Warto używać lekkiego sprzętu i delikatnych zestawów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22140, 2, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś srebrzysty,Wzdręga,Lin,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22141, 'Starorzecze Toruń D', 'starorzecze-torun-d-torun-22141', 'OXBOW', 53.0043943, 18.5670445, 'Kujawsko-Pomorskie', 'Toruń', 'Kolejne z toruńskich starorzeczy, znane z dobrej populacji drapieżników i ryb spokojnego żeru. Posiada stałe połączenie z Wisłą, co zapewnia stały dopływ świeżej wody i różnorodność gatunkową. Dno jest przeważnie twarde, z miejscowymi osadami mułu i pojedynczymi zaczepami. Brzegi są łatwo dostępne, a wokół zbiornika znajdują się liczne dogodne miejsca do wędkowania. W starorzeczu dominują szczupaki i okonie, które aktywnie polują, a także leszcze, płocie i sandacze. Jest to łowisko całoroczne, atrakcyjne dla wędkarzy preferujących różne techniki. Warto szukać ryb w pobliżu zatopionych korzeni i na skraju głębszych rynien. To miejsce oferuje wiele możliwości na udane wędkowanie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22141, 3.2, 2, 4.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Sandacz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22142, 'Starorzecze Zielonka Nowa', 'starorzecze-zielonka-nowa-zielonka-nowa-22142', 'OXBOW', 51.3471536, 21.6100328, 'Lubelskie', 'Zielonka Nowa', 'Starorzecze w Zielonce Nowej to malowniczy zbiornik o umiarkowanej głębokości, z brzegami porośniętymi gęstymi trzcinami, co wymaga użycia wodoodpornych spodniobutów do swobodnego poruszania się. Dno jest zróżnicowane, z miejscami zamulonymi i licznymi zatopionymi drzewami, które stanowią doskonałe kryjówki dla ryb. Połączenie z rzeką następuje jedynie podczas wysokich stanów wody, co sprzyja migracji ryb. W zbiorniku dominują szczupaki, liny i leszcze, a także płocie i karpie. Łowisko jest idealne dla wędkarzy poszukujących dzikich, nieuregulowanych miejsc. Najlepsze efekty osiąga się tu wczesną wiosną i jesienią, kiedy ryby są najbardziej aktywne. Warto używać mocnego sprzętu, aby uniknąć strat w zaczepach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22142, 4.8, 1.9, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Karp', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22143, 'Starorzecze Stężyca B', 'starorzecze-stezyca-b-stezyca-22143', 'OXBOW', 51.5744004, 21.7359198, 'Lubelskie', 'Stężyca', 'To mniejsze starorzecze w pobliżu Stężycy charakteryzuje się wysokim poziomem zamulenia i silnym zarośnięciem, co sprawia, że jest to łowisko wymagające. Dostęp do brzegów jest trudny i bagnisty, co wymusza użycie wodoodpornych spodniobutów. Ze względu na brak połączenia z rzeką i stosunkowo niewielką głębokość, w upalne lata istnieje ryzyko niedoboru tlenu. W akwenie dominują liny, karasie pospolite i wzdręgi, które doskonale czują się w zarośniętych partiach. Można tu również spotkać mniejsze szczupaki, które polują wśród roślinności. Najlepsze wyniki osiąga się w cieplejszych miesiącach, celując w wolne od zarośli zatoczki. Warto używać lekkiego sprzętu, aby uniknąć frustracji z zaczepami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22143, 2.9, 1.4, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22144, 'Starorzecze Stężyca C', 'starorzecze-stezyca-c-stezyca-22144', 'OXBOW', 51.5751766, 21.7388858, 'Lubelskie', 'Stężyca', 'Najmniejsze i najpłytsze z starorzeczy w okolicach Stężycy, charakteryzujące się bardzo wysokim zamuleniem i silnym zarośnięciem trzciną. Dostęp do wody jest mocno utrudniony, a bagniste brzegi wymagają użycia wodoodpornych spodniobutów. Ze względu na niewielką głębokość i brak połączenia z rzeką, zbiornik ten ma tendencję do wysychania w okresach długotrwałej suszy. Ryzyko przyduchy jest bardzo wysokie. W akwenie dominują odporne karasie srebrzyste, wzdręgi i liny, które potrafią przetrwać w trudnych warunkach. Jest to łowisko dla cierpliwych wędkarzy, poszukujących unikalnych doświadczeń. Najlepsze wyniki osiąga się w cieplejszych miesiącach, wczesnym rankiem lub późnym wieczorem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22144, 1.7, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22145, 'Starorzecze (Stężyca) 1', 'starorzecze-stezyca-1-stezyca-22145', 'OXBOW', 51.5752934, 21.7414508, 'Lubelskie', 'Stężyca', 'To starorzecze, położone w malowniczej dolinie Wisły, charakteryzuje się płytkim dnem i bogatą roślinnością podwodną, co czyni je idealnym siedliskiem dla wielu gatunków ryb spokojnego żeru. Brzegi są w większości porośnięte trzciną i krzewami, co utrudnia dostęp, ale jednocześnie zapewnia schronienie dla wędkarzy. Dno jest muliste z licznymi zatopionymi korzeniami i gałęziami, wymagającymi ostrożności podczas wędkowania. Wiosną i jesienią, po wyższych stanach wody, starorzecze może mieć chwilowe połączenie z głównym nurtem rzeki, co wzbogaca jego ichtiofaunę. Jest to doskonałe miejsce na połów lina i karasia, szczególnie w cieplejszych miesiącach roku. Ze względu na płytkość i obfitość materii organicznej, istnieje umiarkowane ryzyko przyduchy w upalne lata.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22145, 3.2, 1.1, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22146, 'Starorzecze (Stężyca) 2', 'starorzecze-stezyca-2-stezyca-22146', 'OXBOW', 51.5758086, 21.7445042, 'Lubelskie', 'Stężyca', 'To starorzecze, będące częścią kompleksu starorzeczy wiślanych, charakteryzuje się bardziej otwartymi przestrzeniami niż jego sąsiedzi, choć brzegi nadal są gęsto porośnięte. Dno jest zróżnicowane, od piaszczystych płycizn po muliste zagłębienia, co sprzyja różnorodności gatunkowej ryb. Wędkarze mogą liczyć na dobre wyniki w połowie płoci i leszcza, a także drapieżników takich jak okoń czy szczupak, które czają się wśród podwodnej roślinności. Połączenie z rzeką matką jest rzadkie i występuje tylko podczas wyjątkowo wysokich stanów wody, co sprzyja stabilizacji ekosystemu. Starorzecze jest dość głębokie jak na tego typu akwen, co ogranicza ryzyko przyduchy. Dostęp do wody jest umiarkowany, z kilkoma dogodnymi stanowiskami wędkarskimi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22146, 5.1, 1.8, 4.5, 'Podczas bardzo wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak,Wzdręga', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22147, 'Starorzecze (Stężyca) 3', 'starorzecze-stezyca-3-stezyca-22147', 'OXBOW', 51.575006, 21.7490462, 'Lubelskie', 'Stężyca', 'To starorzecze jest typowym, mocno zarośniętym akwenem, gdzie królują gatunki preferujące płytkie, ciepłe wody. Brzegi są niemal w całości otoczone gęstymi pasami trzcin i pałki wodnej, co skutecznie utrudnia dostęp do otwartej wody. Dno jest jednolicie muliste, z grubą warstwą osadów organicznych, co sprzyja rozwojowi bujnej roślinności podwodnej. Wędkarze szukający lina, karasia pospolitego czy wzdręgi znajdą tu doskonałe warunki, choć wymagana jest cierpliwość i umiejętność łowienia w trudnym terenie. Ze względu na płytkość i intensywne zarośnięcie, ryzyko niedoboru tlenu w okresie letnim jest wysokie, co może wpływać na aktywność ryb. Połączenie z Wisłą jest sporadyczne i krótkotrwałe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22147, 2.8, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22148, 'Starorzecze (Stężyca) 4', 'starorzecze-stezyca-4-stezyca-22148', 'OXBOW', 51.5760638, 21.7571952, 'Lubelskie', 'Stężyca', 'Ostatnie z serii starorzeczy w okolicach Stężycy, to wyróżnia się nieco większą głębokością i bardziej stabilnym poziomem wody. Brzegi są częściowo dostępne, z fragmentami porośniętymi drzewami i krzewami, które zapewniają cień i kryjówki dla ryb. Dno jest mieszane, z obszarami mulistymi przeplatanymi twardszymi, piaszczystymi fragmentami, zwłaszcza w głębszych partiach. Jest to atrakcyjne łowisko dla wędkarzy poszukujących leszczy, płoci, a także większych szczupaków i okoni. Starorzecze to jest dość dobrze izolowane od głównego nurtu Wisły, co sprzyja rozwojowi własnego, stabilnego ekosystemu. Ryzyko przyduchy jest niskie, a warunki do wędkowania utrzymują się przez większą część roku. Warto eksplorować je z pontonu w miejscach niedostępnych z brzegu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22148, 4.5, 1.6, 3.8, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń', 'Dobry w niektórych miejscach, reszta zarośnięta', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22149, 'Starorzecze (Kolonia Raj)', 'starorzecze-kolonia-raj-kolonia-raj-22149', 'OXBOW', 51.1097065, 21.7847747, 'Lubelskie', 'Kolonia Raj', 'To starorzecze, położone w pobliżu Kolonii Raj, jest stosunkowo płytkim, ale rozległym akwenem, charakteryzującym się silnym zarośnięciem brzegów i dna. Gęsta roślinność podwodna i nawodna tworzy idealne schronienie dla drobnicy oraz drapieżników. Dno jest w większości muliste, z licznymi osadami organicznymi, co sprzyja występowaniu lina i karasia pospolitego. Wędkarze mogą również liczyć na spotkanie ze szczupakiem, który poluje wśród zarośli. Dostęp do wody jest trudny, często wymaga brodzenia, a najlepiej sprawdza się łowienie z pontonu lub specjalnie przygotowanych pomostów. Ze względu na płytkość i bogactwo materii organicznej, w miesiącach letnich istnieje ryzyko przyduchy. Połączenie z rzeką jest minimalne, co sprzyja stabilizacji populacji ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22149, 7.5, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22150, 'Starorzecze (Topiłówka)', 'starorzecze-topilowka-topilowka-22150', 'OXBOW', 53.9402099, 22.8908304, 'Podlaskie', 'Topiłówka', 'Starorzecze w Topiłówce, położone w regionie Puszczy Augustowskiej, to akwen o umiarkowanej głębokości i czystej wodzie, otoczony lasami. Brzegi są przeważnie piaszczyste lub żwirowe, z nielicznymi zaroślami, co zapewnia dobry dostęp do łowiska. Dno jest zróżnicowane, od piaszczystych blatów po głębsze partie z pojedynczymi zatopionymi drzewami. Jest to doskonałe miejsce dla wędkarzy poszukujących okonia, płoci i leszcza, a także szczupaka. Akwen ten jest stosunkowo dobrze natleniony i nie grozi mu przyducha, co sprzyja aktywności ryb przez cały sezon. Połączenie z rzeką jest rzadkie, co przekłada się na stabilność populacji ryb. Cisza i spokój tego miejsca przyciągają miłośników wędkowania w otoczeniu natury.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22150, 6.8, 2, 5.5, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Okoń,Płoć,Leszcz,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22151, 'Starorzecze (Kwakowo)', 'starorzecze-kwakowo-kwakowo-22151', 'OXBOW', 54.386729, 17.0393821, 'Pomorskie', 'Kwakowo', 'Starorzecze w Kwakowie to płytkie i mocno zarośnięte jezioro, idealne dla wędkarzy ceniących sobie spokój i naturalne środowisko. Brzegi są gęsto porośnięte trzciną i inną roślinnością przybrzeżną, co wymaga pewnego wysiłku w dotarciu do wody. Dno jest muliste, z bogatą florą podwodną, co stanowi doskonałe środowisko dla lina, karasia pospolitego i wzdręgi. Występują tu również szczupaki, które czają się w gęstych zaroślach. Akwen ten jest dość odizolowany, co sprzyja rozwojowi stabilnej populacji ryb, choć w upalne lata może pojawić się ryzyko przyduchy. Wędkowanie z pontonu lub woderów jest zalecane, aby dotrzeć do najlepszych miejscówek. To miejsce to prawdziwy raj dla wędkarzy preferujących spokojne gatunki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22151, 4.1, 0.9, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22152, 'Starorzecze (Zajączkowo)', 'starorzecze-zajaczkowo-zajaczkowo-22152', 'OXBOW', 54.4010598, 17.0300055, 'Pomorskie', 'Zajączkowo', 'Starorzecze w Zajączkowie to akwen o umiarkowanej głębokości, z częściowo dostępnymi brzegami i zróżnicowanym dnem. Występują tu zarówno obszary piaszczyste, jak i muliste, co sprzyja różnorodności gatunkowej ryb. Gęste zarośla trzcinowe przeplatają się z otwartymi przestrzeniami, oferującymi dogodne miejsca do wędkowania. Wędkarze mogą liczyć na połów leszczy, płoci, okoni, a także karpi. Akwen ten jest dobrze natleniony, a ryzyko przyduchy jest niskie. Połączenie z rzeką jest sporadyczne, co pomaga w utrzymaniu stabilnego ekosystemu. Warto eksplorować je zarówno z brzegu, jak i z łodzi, aby dotrzeć do ukrytych zakamarków, gdzie często przebywają większe okazy. To atrakcyjne miejsce dla wędkarzy preferujących różnorodne metody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22152, 5.5, 1.5, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Karp', 'Dobry w niektórych miejscach', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22153, 'Starorzecze (Łosino)', 'starorzecze-losino-losino-22153', 'OXBOW', 54.4272041, 17.0237368, 'Pomorskie', 'Łosino', 'Starorzecze w Łosinie to głębszy akwen o czystej wodzie i zróżnicowanym ukształtowaniu dna, co czyni go atrakcyjnym dla wielu gatunków ryb. Brzegi są w dużej mierze dostępne, z fragmentami porośniętymi drzewami liściastymi, które zapewniają cień. Dno jest twarde, piaszczyste lub żwirowe, z nielicznymi zaczepami w postaci zatopionych gałęzi. Jest to doskonałe miejsce na połów leszcza, płoci, a także sandacza i suma, które znajdują tu odpowiednie warunki do bytowania. Akwen jest dobrze natleniony, a ryzyko przyduchy jest minimalne. Połączenie z rzeką jest bardzo rzadkie, co sprzyja stabilności ekosystemu. Wędkowanie z brzegu jest wygodne, a w głębszych partiach można z powodzeniem stosować metody gruntowe. To starorzecze to prawdziwa gratka dla wędkarzy szukających większych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22153, 8.2, 2.5, 6, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Sandacz,Sum,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22154, 'Starorzecze (Słupsk)', 'starorzecze-slupsk-slupsk-22154', 'OXBOW', 54.4481036, 17.027529, 'Pomorskie', 'Słupsk', 'Starorzecze w pobliżu Słupska to akwen o umiarkowanej głębokości, z brzegami częściowo dostępnymi, a częściowo porośniętymi zaroślami. Dno jest zróżnicowane, z fragmentami mulistymi i piaszczystymi, co sprzyja różnorodności gatunków ryb. Wędkarze mogą tu liczyć na połów płoci, leszczy, okoni, a także szczupaków. Akwen ten jest stosunkowo dobrze natleniony, a ryzyko przyduchy jest niskie. Połączenie z rzeką jest sporadyczne, występujące głównie podczas wiosennych roztopów. Dostęp do łowiska jest ułatwiony w niektórych miejscach dzięki utwardzonym ścieżkom. Jest to popularne miejsce rekreacji dla mieszkańców Słupska, oferujące dobre warunki do wędkowania przez większość roku. Warto zabrać ze sobą sprzęt na różne metody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22154, 6, 1.7, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry w niektórych miejscach', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22155, 'Starorzecze (Charnowo)', 'starorzecze-charnowo-charnowo-22155', 'OXBOW', 54.5518113, 16.9276835, 'Pomorskie', 'Charnowo', 'Starorzecze w Charnowie to malowniczy, choć płytki akwen, charakteryzujący się bardzo silnym zarośnięciem brzegów i dna. Gęste zarośla trzcinowe i roślinność podwodna tworzą idealne schronienie dla lina, karasia pospolitego i wzdręgi. Dno jest bardzo muliste, z grubą warstwą osadów organicznych, co sprzyja rozwojowi bujnej flory. Wędkarze poszukujący drapieżników mogą liczyć na spotkanie ze szczupakiem, który doskonale kamufluje się w zaroślach. Dostęp do wody jest bardzo trudny i często wymaga brodzenia w woderach. Ze względu na płytkość i intensywne zarośnięcie, ryzyko przyduchy w upalne lata jest wysokie. Jest to miejsce dla cierpliwych wędkarzy ceniących dziką przyrodę i łowienie w trudnym terenie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22155, 3.8, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22156, 'Starorzecze (Białobiel)', 'starorzecze-bialobiel-bialobiel-22156', 'OXBOW', 53.1036966, 21.577656, 'Mazowieckie', 'Białobiel', 'Starorzecze w Białobieli to rozległy akwen o umiarkowanej głębokości, z brzegami częściowo dostępnymi, a częściowo porośniętymi drzewami i krzewami. Dno jest zróżnicowane, od piaszczystych płycizn po muliste zagłębienia, co sprzyja różnorodności gatunkowej ryb. Wędkarze mogą tu liczyć na połów leszczy, płoci, okoni, a także karpi i szczupaków. Akwen jest dobrze natleniony, a ryzyko przyduchy jest niskie, co zapewnia stabilne warunki do wędkowania przez cały sezon. Połączenie z rzeką Narew jest możliwe podczas wysokich stanów wody, co wzbogaca populację ryb. Dostęp do łowiska jest stosunkowo dobry, z kilkoma dogodnymi stanowiskami. To popularne miejsce dla wędkarzy ceniących sobie różnorodność połowów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22156, 9.5, 1.9, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Karp,Szczupak', 'Dobry w niektórych miejscach', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22157, 'Starorzecze (Drzewica)', 'starorzecze-drzewica-drzewica-22157', 'OXBOW', 51.451142, 20.4838424, 'Łódzkie', 'Drzewica', 'Starorzecze w Drzewicy to stosunkowo płytki, ale urokliwy akwen, otoczony gęstymi zaroślami i drzewami. Brzegi są w większości trudno dostępne, porośnięte trzciną i krzewami, co wymaga cierpliwości i determinacji od wędkarzy. Dno jest muliste, z bogatą roślinnością podwodną, stanowiącą idealne schronienie dla lina, karasia pospolitego i wzdręgi. Występują tu również szczupaki, które polują w gęstych zaroślach. Ze względu na płytkość i obfitość materii organicznej, w okresie letnim istnieje umiarkowane ryzyko przyduchy. Akwen ten jest dość odizolowany, co sprzyja stabilizacji populacji ryb. Wędkowanie z pontonu lub brodzenie w woderach jest zalecane, aby dotrzeć do najlepszych miejscówek. To miejsce to prawdziwy raj dla miłośników dzikiej przyrody i spokojnego wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22157, 2.5, 1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22158, 'Starorzecze (Odrzywół)', 'starorzecze-odrzywol-odrzywol-22158', 'OXBOW', 51.5103149, 20.5703723, 'Mazowieckie', 'Odrzywół', 'Starorzecze w Odrzywole to akwen o umiarkowanej głębokości, z brzegami częściowo dostępnymi i zróżnicowanym dnem. Występują tu zarówno obszary piaszczyste, jak i muliste, co sprzyja różnorodności gatunkowej ryb. Gęste zarośla trzcinowe przeplatają się z otwartymi przestrzeniami, oferującymi dogodne miejsca do wędkowania. Wędkarze mogą liczyć na połów leszczy, płoci, okoni, a także karpi. Akwen ten jest dobrze natleniony, a ryzyko przyduchy jest niskie. Połączenie z rzeką jest sporadyczne, występujące głównie podczas wiosennych roztopów, co pomaga w utrzymaniu stabilnego ekosystemu. Warto eksplorować je zarówno z brzegu, jak i z łodzi, aby dotrzeć do ukrytych zakamarków, gdzie często przebywają większe okazy. To atrakcyjne miejsce dla wędkarzy preferujących różnorodne metody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22158, 4.9, 1.6, 3.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Karp', 'Dobry w niektórych miejscach', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22159, 'Starorzecze (Kobylnica)', 'starorzecze-kobylnica-kobylnica-22159', 'OXBOW', 51.6651104, 21.5516168, 'Mazowieckie', 'Kobylnica', 'Starorzecze w Kobylnicy to akwen o umiarkowanej głębokości, z brzegami częściowo dostępnymi i zróżnicowanym dnem. Występują tu zarówno obszary piaszczyste, jak i muliste, co sprzyja różnorodności gatunkowej ryb. Gęste zarośla trzcinowe przeplatają się z otwartymi przestrzeniami, oferującymi dogodne miejsca do wędkowania. Wędkarze mogą liczyć na połów leszczy, płoci, okoni, a także karpi. Akwen ten jest dobrze natleniony, a ryzyko przyduchy jest niskie. Połączenie z rzeką jest sporadyczne, występujące głównie podczas wiosennych roztopów, co pomaga w utrzymaniu stabilnego ekosystemu. Warto eksplorować je zarówno z brzegu, jak i z łodzi, aby dotrzeć do ukrytych zakamarków, gdzie często przebywają większe okazy. To atrakcyjne miejsce dla wędkarzy preferujących różnorodne metody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22159, 5.8, 1.7, 3.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Karp', 'Dobry w niektórych miejscach', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22160, 'Starorzecze (Kępa Skórecka)', 'starorzecze-kepa-skorecka-maciejowice-22160', 'OXBOW', 51.8165283, 21.3793597, 'Mazowieckie', 'Maciejowice', 'To malownicze starorzecze, położone w pobliżu Kępy Skóreckiej, jest typowym przykładem dawnego koryta Wisły, odciętego od głównego nurtu. Charakteryzuje się dość stabilnym poziomem wody i umiarkowanym zamuleniem dna, które w większości jest piaszczysto-muliste. Brzegi są stosunkowo łatwo dostępne, miejscami porośnięte pojedynczymi krzewami i kępami trzcin, co tworzy dogodne stanowiska dla wędkarzy. Roślinność podwodna jest umiarkowana, co sprzyja rozwojowi populacji szczupaka i okonia, a także lina i karasia pospolitego. Wiosną i wczesną jesienią można liczyć na udane połowy drapieżników oraz płoci i leszczy, które licznie zamieszkują to łowisko. Brak jest większych trudności z dojazdem, co czyni je atrakcyjnym miejscem na weekendowy wypad.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22160, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22161, 'Starorzecze (Stare Podole)', 'starorzecze-stare-podole-wilga-22161', 'OXBOW', 51.840693, 21.3220776, 'Mazowieckie', 'Wilga', 'Starorzecze w Starym Podolu to urokliwe, lecz wymagające łowisko, będące reliktem dawnego biegu Wisły. Dno jest tu głównie muliste, z licznymi osadami dennymi, co świadczy o średnim stopniu zamulenia. Brzegi są trudne do pokonania, często bagniste i gęsto porośnięte wysoką roślinnością szuwarową, co wymaga użycia wodoodpornego obuwia lub brodzenia. Akwen ten charakteryzuje się bogatą roślinnością podwodną, stanowiącą doskonałe schronienie dla lina, karasia pospolitego oraz wzdręgi. Występują tu również szczupaki, które polują wśród zarośli. Najlepsze efekty wędkarskie osiąga się późną wiosną i latem, kiedy ryby żerują aktywnie w cieplejszych wodach, a dostępność brzegów jest nieco lepsza, choć nadal wymaga wysiłku. Jest to idealne miejsce dla wędkarzy ceniących dziką przyrodę i wyzwania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22161, 3.2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22162, 'Starorzecze (Stare Podole)', 'starorzecze-stare-podole-wilga-22162', 'OXBOW', 51.8442849, 21.311585, 'Mazowieckie', 'Wilga', 'To starorzecze, położone w bliskiej odległości od poprzedniego, jest bardziej odizolowane od nurtu Wisły, co skutkuje brakiem stałego połączenia z rzeką. Charakteryzuje się wysokim stopniem zamulenia dna, które jest miękkie i bogate w osady organiczne. Brzegi są mocno zarośnięte trzciną i inną roślinnością przybrzeżną, co znacznie utrudnia dostęp do wody i wymaga brodzenia. Silne zarośnięcie podwodne tworzy idealne warunki dla ryb typowych dla płytkich, ciepłych wód, takich jak karaś pospolity, lin i wzdręga. Ze względu na izolację, istnieje podwyższone ryzyko deficytów tlenowych, szczególnie w gorące lata i pod pokrywą lodu. Wędkarstwo tutaj to prawdziwe wyzwanie, ale nagrodą mogą być piękne okazy ryb, które doskonale czują się w tym środowisku. Najlepsze połowy przypadają na późną wiosnę i lato, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22162, 2.8, 1.3, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22163, 'Starorzecze (Stężyca)', 'starorzecze-stezyca-stezyca-22163', 'OXBOW', 51.5754299, 21.7475154, 'Mazowieckie', 'Stężyca', 'Starorzecze w okolicach Stężycy to rozległe i głębsze łowisko, które w okresach wysokiej wody łączy się z głównym nurtem Wisły, co sprzyja odświeżaniu wody i migracji ryb. Dno jest zróżnicowane, od piaszczystych płycizn po muliste zagłębienia, a roślinność podwodna występuje w umiarkowanym natężeniu, tworząc idealne kryjówki dla drapieżników. Brzegi są stosunkowo łatwo dostępne, co umożliwia komfortowe wędkowanie z wielu miejsc. Akwen ten słynie z obfitości leszczy i płoci, a także z dużych szczupaków i okoni, które często patrolują strefy brzegowe i okolice zatopionych przeszkód. Regularne połączenie z rzeką minimalizuje ryzyko deficytów tlenowych, zapewniając stabilne warunki bytowania ryb. Jest to doskonałe miejsce na wędkowanie przez większą część sezonu, ze szczególnym uwzględnieniem wiosny i wczesnej jesieni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22163, 5.1, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Lin,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22164, 'Starorzecze (Domaszew)', 'starorzecze-domaszew-ryki-22164', 'OXBOW', 51.7302861, 21.4905315, 'Lubelskie', 'Ryki', 'Starorzecze w Domaszewie jest typowym, nieco dzikim akwenem wiślanym, charakteryzującym się średnim stopniem zamulenia i bogatą roślinnością podwodną. Dno jest w przeważającej części muliste, z twardymi fragmentami w rejonie dawnych prądów. Brzegi są trudne do pokonania, często bagniste i gęsto porośnięte trzciną, co wymaga użycia wodoodpornego obuwia i przygotowania się na brodzenie. Wiosenne i jesienne wylewy Wisły odświeżają wodę, co sprzyja zdrowej populacji ryb, w tym lina, karasia pospolitego i dużych płoci. Można tu również spotkać szczupaki, które czatują w zaroślach. Łowisko to jest cenione przez wędkarzy szukających spokoju i kontaktu z naturą, a największe szanse na sukces są późną wiosną i latem, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22164, 3.8, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22165, 'Starorzecze (Piła)', 'starorzecze-pila-pila-22165', 'OXBOW', 53.090535, 16.7493119, 'Wielkopolskie', 'Piła', 'To starorzecze w okolicach Piły jest akwenem o stałym połączeniu z rzeką Gwdą, co zapewnia ciągły przepływ wody i niskie zamulenie dna, które jest głównie piaszczysto-żwirowe. Brzegi są dobrze dostępne, miejscami utwardzone, co ułatwia wędkowanie z brzegu. Roślinność podwodna jest umiarkowana, skupiając się w zatokach i płytszych partiach. Występuje tu bogata populacja ryb rzecznych, takich jak płoć, leszcz, okoń, a także liczne szczupaki i bolenie, które chętnie polują na drobną rybę. Stałe połączenie z rzeką eliminuje ryzyko deficytów tlenowych i sprzyja zdrowej kondycji ryb. To łowisko jest atrakcyjne przez cały sezon, oferując różnorodne możliwości połowu zarówno dla spinningistów, jak i wędkarzy gruntowych. Jest to idealne miejsce dla wędkarzy ceniących komfort i różnorodność gatunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22165, 2.1, 1.5, 3, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22166, 'Starorzecze (Piła)', 'starorzecze-pila-pila-22166', 'OXBOW', 53.0889569, 16.7494557, 'Wielkopolskie', 'Piła', 'To starorzecze w pobliżu Piły, choć blisko głównego nurtu, łączy się z nim jedynie podczas wysokiej wody, co sprawia, że jest bardziej odizolowane. Dno jest średnio zamulone, z przewagą mułu i resztek roślinnych, co sprzyja rozwojowi bogatej roślinności podwodnej. Brzegi są mocno zarośnięte trzciną, co utrudnia dostęp i wymaga użycia wodoodpornego obuwia. Akwen ten jest domem dla licznych płoci, leszczy, a także cenionych przez wędkarzy linów i karasi pospolitych. Mimo braku stałego połączenia, okresowe wlewy wody z rzeki zapobiegają poważnym deficytom tlenowym. Jest to łowisko dla wędkarzy poszukujących spokoju i ryb lubiących zaciszne, zarośnięte miejsca. Najlepsze wyniki osiąga się późną wiosną i latem, kiedy ryby intensywnie żerują w cieplejszych wodach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22166, 1.8, 1.2, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Lin,Karaś pospolity', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22167, 'Starorzecze (Piła)', 'starorzecze-pila-pila-22167', 'OXBOW', 53.090126, 16.7518397, 'Wielkopolskie', 'Piła', 'Kolejne starorzecze w rejonie Piły, charakteryzujące się regularnym, choć nie stałym, połączeniem z rzeką podczas wysokich stanów wody. Dno jest zróżnicowane, od twardszych fragmentów piaszczystych po muliste zagłębienia, a roślinność podwodna jest umiarkowana, koncentrując się w płytszych strefach. Brzegi są dobrze dostępne, co ułatwia wędkowanie z różnych stanowisk. Jest to doskonałe miejsce na połów szczupaka i okonia, które licznie występują w tym akwenie, a także płoci i leszczy. Okresowe połączenie z rzeką zapewnia wymianę wody, co korzystnie wpływa na ekosystem i minimalizuje ryzyko problemów z tlenem. Łowisko jest szczególnie polecane wędkarzom poszukującym drapieżników wczesną wiosną i jesienią, kiedy ryby są najbardziej aktywne. Jest to przyjemne miejsce na relaks z wędką.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22167, 2.3, 1.6, 3.1, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22168, 'Starorzecze (Byszki)', 'starorzecze-byszki-byszki-22168', 'OXBOW', 53.0745617, 16.7466168, 'Wielkopolskie', 'Byszki', 'To niewielkie starorzecze w Byszkach jest całkowicie odcięte od głównego nurtu rzeki, co sprawia, że jego ekosystem jest bardzo specyficzny. Dno jest mocno zamulone i miękkie, a roślinność podwodna jest silna i gęsta, tworząc prawdziwy labirynt dla ryb. Brzegi są trudne do pokonania, często bagniste i nieprzystępne, co wymaga użycia wodoodpornego obuwia. Akwen ten jest królestwem karasia pospolitego, lina i wzdręgi, które doskonale radzą sobie w trudnych warunkach. Ze względu na izolację i płytkość, starorzecze to jest narażone na wysokie ryzyko deficytów tlenowych, a w skrajnych przypadkach może wysychać w czasie długotrwałych upałów. Jest to łowisko dla wytrwałych wędkarzy, poszukujących rzadkich gatunków i ceniących dzikie ostępy. Najlepszy okres na połów to późna wiosna i lato.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22168, 1.5, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22169, 'Starorzecze (Byszki)', 'starorzecze-byszki-byszki-22169', 'OXBOW', 53.0749938, 16.7472585, 'Wielkopolskie', 'Byszki', 'To bardzo płytkie i silnie zarośnięte starorzecze w Byszkach jest całkowicie odizolowane od rzeki, co czyni je unikalnym, ale również wymagającym środowiskiem. Dno jest ekstremalnie zamulone, a gęsta roślinność podwodna i przybrzeżna tworzy niemalże nieprzeniknioną barierę. Brzegi są mocno zarośnięte trzciną, co sprawia, że dostęp do wody jest bardzo trudny i praktycznie niemożliwy bez brodzenia. W takich warunkach doskonale radzą sobie jedynie najbardziej odporne gatunki, takie jak karaś pospolity, wzdręga i lin, które osiągają tu imponujące rozmiary. Ze względu na małą głębokość i brak połączenia z rzeką, ryzyko deficytów tlenowych jest wysokie, a w okresach suszy akwen może wysychać. Wędkowanie jest tu prawdziwym wyzwaniem, ale dla cierpliwych wędkarzy może przynieść satysfakcjonujące rezultaty, zwłaszcza latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22169, 1.2, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22170, 'Starorzecze (Byszki)', 'starorzecze-byszki-byszki-22170', 'OXBOW', 53.0741385, 16.7461383, 'Wielkopolskie', 'Byszki', 'To miniaturowe starorzecze w Byszkach jest jednym z najbardziej dzikich i niedostępnych łowisk. Całkowity brak połączenia z rzeką i znaczne zamulenie dna sprawiają, że jest to środowisko skrajnie trudne dla większości gatunków ryb. Brzegi są praktycznie nieprzeniknione, bagniste i gęsto zarośnięte, co wymaga nie tylko brodzenia, ale i przedzierania się przez gęstwinę. W akwenie tym znajduje się dużo zatopionych drzew i gałęzi, co dodatkowo utrudnia wędkowanie, ale jednocześnie stanowi doskonałe kryjówki dla ryb. Dominują tu karaś pospolity i wzdręga, które doskonale adaptują się do trudnych warunków. Wysokie ryzyko deficytów tlenowych i możliwość całkowitego wyschnięcia w upalne lata sprawiają, że jest to łowisko dla prawdziwych pasjonatów, ceniących wyzwania i dziką przyrodę. Najlepsze połowy można osiągnąć późną wiosną.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22170, 1, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22171, 'Starorzecze (Byszki)', 'starorzecze-byszki-byszki-22171', 'OXBOW', 53.0734525, 16.7462944, 'Wielkopolskie', 'Byszki', 'To starorzecze w Byszkach, podobnie jak sąsiednie, jest odizolowane od głównego nurtu rzeki i charakteryzuje się wysokim stopniem zamulenia dna. Jest to płytki akwen z gęstą roślinnością podwodną, która stanowi doskonałe schronienie dla ryb. Brzegi są mocno zarośnięte trzciną i inną roślinnością, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga brodzenia. Występują tu głównie karaś pospolity, lin i wzdręga, które doskonale radzą sobie w tym środowisku. Ze względu na brak połączenia z rzeką i niewielką głębokość, istnieje wysokie ryzyko deficytów tlenowych, a w skrajnych przypadkach starorzecze może wysychać. Mimo trudności w dostępie, jest to łowisko, które może zaskoczyć pięknymi okazami ryb, szczególnie w miesiącach letnich, kiedy ryby intensywnie żerują. Wędkarze ceniący dzikie miejsca znajdą tu coś dla siebie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22171, 1.3, 0.9, 1.9, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22172, 'Starorzecze (Piła)', 'starorzecze-pila-pila-22172', 'OXBOW', 53.0696545, 16.7418773, 'Wielkopolskie', 'Piła', 'To starorzecze w okolicach Piły jest akwenem o średniej wielkości, który w okresach wysokiej wody łączy się z rzeką, co sprzyja wymianie wody i odświeżaniu ekosystemu. Dno jest średnio zamulone, z twardszymi fragmentami w rejonie dawnych prądów, a roślinność podwodna występuje w umiarkowanym natężeniu, tworząc dobre kryjówki dla ryb. Brzegi są dobrze dostępne, co ułatwia wędkowanie z różnych stanowisk. Występuje tu bogata populacja szczupaków i okoni, a także leszczy i płoci. Okresowe połączenie z rzeką minimalizuje ryzyko deficytów tlenowych i sprzyja zdrowej kondycji ryb. To łowisko jest szczególnie atrakcyjne dla spinningistów poszukujących drapieżników wczesną wiosną i jesienią. Jest to przyjemne miejsce na spędzenie czasu z wędką, oferujące różnorodne możliwości połowu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22172, 2, 1.4, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22173, 'Starorzecze (Ujście)', 'starorzecze-ujscie-ujscie-22173', 'OXBOW', 53.0638711, 16.7409716, 'Wielkopolskie', 'Ujście', 'Starorzecze w Ujściu to jedno z najbardziej atrakcyjnych łowisk w regionie, charakteryzujące się stałym połączeniem z rzeką Noteć, co zapewnia doskonałą jakość wody i niskie zamulenie dna. Dno jest przeważnie czyste, piaszczysto-żwirowe, z niewielką ilością roślinności podwodnej, co ułatwia swobodne prowadzenie przynęt. Brzegi są dobrze dostępne z obu stron, co umożliwia komfortowe wędkowanie z brzegu. Akwen ten słynie z obfitości drapieżników, takich jak szczupak, sandacz i okoń, a także z dużych leszczy i płoci. Stałe połączenie z rzeką gwarantuje stabilne warunki tlenowe i sprzyja zdrowej populacji ryb. Jest to łowisko, które oferuje doskonałe warunki do wędkowania przez cały sezon, zarówno dla spinningistów, jak i wędkarzy gruntowych. To idealne miejsce na udane połowy i relaks nad wodą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22173, 3.5, 1.8, 3.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22174, 'Starorzecze (Zameczek-Kolonia)', 'starorzecze-zameczek-kolonia-przysucha-22174', 'OXBOW', 51.4707296, 20.9265813, 'Mazowieckie', 'Przysucha', 'Starorzecze w Zameczku-Kolonii to niewielki, odizolowany akwen, który nie posiada połączenia z żadną większą rzeką, co nadaje mu kameralny charakter. Dno jest mocno zamulone i miękkie, a gęsta roślinność podwodna i przybrzeżna tworzy liczne kryjówki dla ryb. Brzegi są trudne do pokonania, często bagniste i zarośnięte, co wymaga użycia wodoodpornego obuwia i przygotowania na brodzenie. W tym środowisku doskonale czują się karaś pospolity, lin, wzdręga oraz płoć. Ze względu na izolację i niewielką głębokość, istnieje podwyższone ryzyko deficytów tlenowych, szczególnie w gorących okresach letnich. Jest to łowisko dla wędkarzy ceniących ciszę i spokój, poszukujących ryb typowych dla starorzeczy, które osiągają tu imponujące rozmiary. Najlepsze połowy przypadają na późną wiosnę i lato.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22174, 1.9, 1.1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22175, 'Starorzecze Stubienko', 'starorzecze-stubienko-przemysl-22175', 'OXBOW', 49.9031467, 22.9280415, 'Podkarpackie', 'Przemyśl', 'Starorzecze Stubienko to urokliwy zbiornik wodny położony w dolinie Sanu, charakteryzujący się typową dla starorzeczy bogatą florą i fauną. Dno jest muliste z twardszymi fragmentami żwiru, zwłaszcza w głębszych partiach. Brzegi są częściowo dostępne, lecz miejscami silnie zarośnięte trzciną i krzewami, co wymaga użycia wodoodpornego obuwia. Wiosenne i jesienne wylewy Sanu zapewniają okresowe połączenie z rzeką, co sprzyja migracji ryb i odświeżeniu wody. Łowisko to jest znane z populacji szczupaka i lina, a także obfitości płoci, okoni i leszczy. Wędkowanie utrudniają liczne podwodne zaczepy, zwłaszcza w strefach zarośniętych, co wymaga precyzji w rzutach i doborze sprzętu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22175, 3.8, 1.8, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Płoć,Okoń,Leszcz', 'Umiarkowany, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22176, 'Starorzecze Sieradzkie I', 'starorzecze-sieradzkie-i-sieradz-22176', 'OXBOW', 51.6066262, 18.7373098, 'Łódzkie', 'Sieradz', 'Pierwsze z serii starorzeczy w okolicach Sieradza, położone w dolinie Warty. Charakteryzuje się dość płytkim, mulistym dnem, które w niektórych miejscach przechodzi w twardsze podłoże. Brzegi są częściowo dostępne, z jednym brzegiem oferującym wygodne stanowiska wędkarskie, podczas gdy drugi jest bardziej zarośnięty. Okresowe połączenie z Wartą zapewnia odświeżenie wody i wzbogacenie populacji ryb. Jest to doskonałe łowisko dla wędkarzy szukających płoci, leszczy i okoni, a także karasia pospolitego. Roślinność podwodna jest umiarkowana, co ułatwia wędkowanie, jednak w cieplejszych miesiącach może pojawić się ryzyko obniżonego poziomu tlenu w płytkich zatokach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22176, 2.1, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Karaś pospolity', 'Dobry z jednego brzegu, drugi zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22177, 'Starorzecze Sieradzkie II', 'starorzecze-sieradzkie-ii-sieradz-22177', 'OXBOW', 51.6065764, 18.7383255, 'Łódzkie', 'Sieradz', 'Drugie starorzecze w kompleksie sieradzkim to bardziej odizolowany zbiornik, charakteryzujący się silnym zamuleniem i gęstą roślinnością. Dno jest w większości miękkie, bogate w osady organiczne, co sprzyja rozwojowi makrofitów. Brzegi są trudne do pokonania, często bagniste i silnie zarośnięte trzciną oraz inną roślinnością przybrzeżną. Brak stałego połączenia z rzeką sprawia, że woda jest tu cieplejsza i bardziej podatna na deficyty tlenowe w upalne lata. Jest to idealne miejsce dla lina i karasia pospolitego, a także wzdręgi i płoci, które doskonale radzą sobie w takich warunkach. Wędkowanie wymaga cierpliwości i umiejętności poruszania się w trudnym terenie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22177, 1.8, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22178, 'Starorzecze Sieradzkie III', 'starorzecze-sieradzkie-iii-sieradz-22178', 'OXBOW', 51.6071239, 18.7358645, 'Łódzkie', 'Sieradz', 'To starorzecze wyróżnia się lepszą dostępnością brzegów, z kilkoma dogodnymi miejscami do wędkowania, a nawet niewielkimi pomostami. Dno jest zróżnicowane, od mulistego po twardsze, piaszczysto-żwirowe fragmenty. Okresowe wylewy Warty zapewniają wymianę wody i utrzymują zdrową populację ryb. Jest to cenione łowisko dla wędkarzy polujących na szczupaka i okonia, a także leszcza i płoci, które osiągają tu imponujące rozmiary. Roślinność podwodna jest umiarkowana, co sprzyja różnorodnym technikom wędkarskim. Zbiornik jest stosunkowo głęboki jak na starorzecze, co minimalizuje ryzyko niedoboru tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22178, 3.1, 1.9, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z obu stron, miejscami z pomostami', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22179, 'Starorzecze Sieradzkie IV', 'starorzecze-sieradzkie-iv-sieradz-22179', 'OXBOW', 51.6076547, 18.7338331, 'Łódzkie', 'Sieradz', 'To starorzecze charakteryzuje się stosunkowo czystym dnem i słabym zarośnięciem, co czyni je atrakcyjnym dla wędkarzy preferujących swobodne rzuty. Dno jest piaszczysto-żwirowe, z niewielką ilością mułu. Brzegi są łatwo dostępne z obu stron, bez większych utrudnień. Częste połączenia z Wartą podczas wezbrań sprawiają, że w zbiorniku można spotkać gatunki typowo rzeczne, takie jak boleń i jaź, obok szczupaków, płoci i okoni. Niskie zamulenie i dobra cyrkulacja wody minimalizują ryzyko deficytów tlenowych. To idealne miejsce na aktywne wędkowanie spinningowe lub spławikowe przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22179, 2.5, 1.6, 3.2, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Boleń,Jaź,Płoć,Okoń', 'Dobry z obu stron, bez większych przeszkód', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22180, 'Starorzecze Sieradzkie V', 'starorzecze-sieradzkie-v-sieradz-22180', 'OXBOW', 51.6094396, 18.7308656, 'Łódzkie', 'Sieradz', 'To jedno z większych i głębszych starorzeczy w kompleksie sieradzkim, posiadające stałe połączenie z rzeką Wartą. Charakteryzuje się zróżnicowanym dnem, od twardego żwiru po muliste zagłębienia, z wyraźnymi spadami. Brzegi są dobrze dostępne, miejscami utwardzone, co ułatwia dostęp do wody. Stała wymiana wody sprzyja obecności dużych drapieżników, takich jak sum i sandacz, a także szczupaka. W zbiorniku występują również liczne leszcze i karpie, które znajdują tu dogodne warunki do życia. Umiarkowana roślinność podwodna tworzy doskonałe kryjówki dla ryb. Jest to łowisko o dużym potencjale dla wędkarzy preferujących różnorodne techniki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22180, 4.5, 2.2, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Sandacz,Szczupak,Leszcz,Karp', 'Dobry z obu stron, miejscami utwardzony', FALSE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22181, 'Starorzecze Sieradzkie VI', 'starorzecze-sieradzkie-vi-sieradz-22181', 'OXBOW', 51.610415, 18.7280916, 'Łódzkie', 'Sieradz', 'To najmniejsze i najbardziej płytkie starorzecze w grupie sieradzkiej, charakteryzujące się znacznym zamuleniem i silnym zarośnięciem. Dno jest miękkie, pokryte grubą warstwą osadów organicznych. Brzegi są praktycznie niedostępne bez specjalistycznego sprzętu i wodoodpornego obuwia, z powodu gęstych trzcinowisk i bagnistego terenu. Brak połączenia z Wartą sprawia, że jest bardzo podatne na wysychanie w okresach suszy i na deficyty tlenowe. Występują tu głównie gatunki odporne na trudne warunki, takie jak karaś pospolity, wzdręga, lin i płoć. Wędkowanie jest wyzwaniem, ale może przynieść satysfakcjonujące efekty dla cierpliwych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22181, 1.5, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin,Płoć', 'Bardzo trudny, gęsto zarośnięty i bagnisty', TRUE, 'Gęsta roślinność podwodna i zatopione gałęzie', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22182, 'Starorzecze Gnojno I', 'starorzecze-gnojno-i-terespol-22182', 'OXBOW', 52.2801586, 23.1617691, 'Lubelskie', 'Terespol', 'Pierwsze z trzech starorzeczy w okolicy Gnojna, położone w pobliżu rzeki Bug. Charakteryzuje się mulistym dnem z twardszymi fragmentami w głębszych partiach. Brzegi są częściowo dostępne, z jednym brzegiem oferującym łatwiejszy dostęp, natomiast drugi jest bardziej zarośnięty i wymaga użycia wodoodpornego obuwia. Okresowe wylewy Bugu zapewniają połączenie z rzeką, co sprzyja migracji ryb i odświeżeniu wody. Łowisko to jest znane z populacji szczupaka i okonia, a także obfitości leszczy i płoci. Roślinność podwodna jest umiarkowana, co ułatwia wędkowanie, jednak w cieplejszych miesiącach może pojawić się ryzyko obniżonego poziomu tlenu w płytkich zatokach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22182, 2.7, 1.7, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z jednego brzegu, drugi wymaga wodoodpornego obuwia', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22183, 'Starorzecze Gnojno II', 'starorzecze-gnojno-ii-terespol-22183', 'OXBOW', 52.2803323, 23.1691325, 'Lubelskie', 'Terespol', 'To mniejsze i bardziej odizolowane starorzecze w okolicy Gnojna, charakteryzujące się silnym zamuleniem i gęstą roślinnością. Dno jest w większości miękkie, bogate w osady organiczne, co sprzyja rozwojowi makrofitów. Brzegi są bardzo trudne do pokonania, często bagniste i silnie zarośnięte trzciną oraz inną roślinnością przybrzeżną. Brak stałego połączenia z Bugiem sprawia, że woda jest tu cieplejsza i bardziej podatna na deficyty tlenowe w upalne lata. Jest to idealne miejsce dla lina i karasia pospolitego, a także wzdręgi, które doskonale radzą sobie w takich warunkach. Wędkowanie wymaga cierpliwości i umiejętności poruszania się w trudnym terenie, często z koniecznością brodzenia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22183, 1.9, 1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty i mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22184, 'Starorzecze Gnojno III', 'starorzecze-gnojno-iii-terespol-22184', 'OXBOW', 52.2800268, 23.1718457, 'Lubelskie', 'Terespol', 'Trzecie starorzecze w kompleksie Gnojna jest jednym z większych i głębszych, posiadającym stałe połączenie z rzeką Bug. Charakteryzuje się zróżnicowanym dnem, od twardego żwiru po muliste zagłębienia, z wyraźnymi spadami. Brzegi są dobrze dostępne, miejscami utwardzone, co ułatwia dostęp do wody. Stała wymiana wody sprzyja obecności dużych drapieżników, takich jak sum i sandacz, a także szczupaka. W zbiorniku występują również liczne leszcze i karpie, które znajdują tu dogodne warunki do życia. Umiarkowana roślinność podwodna tworzy doskonałe kryjówki dla ryb. Jest to łowisko o dużym potencjale dla wędkarzy preferujących różnorodne techniki, w tym gruntowe i spinningowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22184, 3.5, 2, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Sandacz,Szczupak,Leszcz,Karp', 'Dobry z obu stron, miejscami utwardzony', FALSE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22185, 'Starorzecze Drohiczyn', 'starorzecze-drohiczyn-drohiczyn-22185', 'OXBOW', 52.3873512, 22.6615745, 'Podlaskie', 'Drohiczyn', 'Starorzecze w Drohiczynie to rozległy i malowniczy zbiornik, położony w bezpośrednim sąsiedztwie rzeki Bug. Charakteryzuje się zróżnicowanym dnem, od piaszczystych płycizn po głębokie, muliste rynny. Brzegi są w większości dobrze dostępne, choć w niektórych miejscach mogą być zarośnięte, co dodaje łowisku dzikiego charakteru. Okresowe połączenie z Bugiem podczas wezbrań zapewnia stały dopływ świeżej wody i migrację ryb. Jest to doskonałe miejsce dla wędkarzy szukających szczupaka i sandacza, a także licznych leszczy, płoci i okoni. Niskie zamulenie i dobra głębokość minimalizują ryzyko niedoboru tlenu. Łowisko to jest popularne wśród lokalnych wędkarzy ze względu na swoje bogactwo rybostanu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22185, 5.2, 2.5, 5.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Okoń', 'Dobry z większości brzegów, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22186, 'Starorzecze Pieczyska', 'starorzecze-pieczyska-biala-podlaska-22186', 'OXBOW', 52.2137827, 23.2537128, 'Lubelskie', 'Biała Podlaska', 'Starorzecze w Pieczyskach to typowy zbiornik starorzeczny, charakteryzujący się mulistym dnem i obfitą roślinnością. Położone jest w dolinie Bugu, z którym łączy się podczas większych wezbrań. Brzegi są trudne do pokonania, często bagniste i gęsto zarośnięte wysokimi trzcinami, co wymaga użycia wodoodpornego obuwia i cierpliwości. W zbiorniku znajduje się wiele zatopionych drzew i gałęzi, stanowiących doskonałe kryjówki dla ryb, ale jednocześnie utrudniających wędkowanie. Jest to idealne miejsce dla lina i karasia pospolitego, a także płoci i okoni. Ze względu na liczne zaczepy, zaleca się stosowanie mocniejszego sprzętu i odpowiednich technik. Wędkowanie tutaj to prawdziwe wyzwanie, ale nagrodą mogą być piękne okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22186, 3, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Płoć,Okoń', 'Trudny, bagnisty i mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22187, 'Starorzecze Zychorzyn', 'starorzecze-zychorzyn-opoczno-22187', 'OXBOW', 51.4597227, 20.536918, 'Łódzkie', 'Opoczno', 'Starorzecze Zychorzyn to atrakcyjne łowisko położone w pobliżu rzeki Pilicy, charakteryzujące się zróżnicowanym dnem i brzegami. Dno jest mieszane, od piaszczystych płycizn po głębsze, muliste partie. Brzegi są umiarkowanie dostępne, z wyznaczonymi stanowiskami wędkarskimi, choć w niektórych miejscach roślinność przybrzeżna może wymagać użycia wodoodpornego obuwia. Okresowe połączenie z Pilicą zapewnia dopływ świeżej wody i sprzyja migracji ryb. W zbiorniku dominują szczupaki, leszcze i karpie, a także liczne płocie i okonie. Umiarkowane zarośnięcie i brak nadmiernego zamulenia sprawiają, że jest to przyjemne łowisko dla wędkarzy preferujących różne metody. Ryzyko niedoboru tlenu jest niskie dzięki dobrej głębokości.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22187, 4.1, 2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Karp,Płoć,Okoń', 'Umiarkowany, miejscami zarośnięty, ale są dostępne stanowiska', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22188, 'Starorzecze Chrośle', 'starorzecze-chrosle-nowe-miasto-lubawskie-22188', 'OXBOW', 53.4795104, 19.597602, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Starorzecze w Chroślu to urokliwy, choć wymagający zbiornik, położony w bliskiej odległości od rzeki Drwęcy. Charakteryzuje się mulistym dnem i bardzo silnym zarośnięciem, zarówno roślinnością podwodną, jak i przybrzeżną. Brzegi są trudne do pokonania, gęsto porośnięte trzciną i krzewami, co wymaga użycia wodoodpornego obuwia do dotarcia do wody. Brak stałego połączenia z Drwęcą sprawia, że woda jest tu cieplejsza i bardziej podatna na deficyty tlenowe w upalne lata. Jest to idealne miejsce dla lina i karasia pospolitego, a także wzdręgi i płoci, które doskonale radzą sobie w takich warunkach. Wędkowanie jest wyzwaniem, ale może przynieść satysfakcjonujące efekty dla cierpliwych wędkarzy preferujących łowienie w zarośniętych łowiskach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22188, 2.8, 1.4, 2.8, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, mocno zarośnięty trzciną i krzewami', TRUE, 'Gęsta roślinność podwodna i pojedyncze korzenie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22189, 'Starorzecze Łąki Bratiańskie', 'starorzecze-laki-bratianskie-nowe-miasto-lubawskie-22189', 'OXBOW', 53.4809001, 19.6007824, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Starorzecze Łąki Bratiańskie to zbiornik położony bardzo blisko rzeki Drwęcy, z którą łączy się podczas wiosennych i jesiennych wezbrań. Charakteryzuje się zróżnicowanym dnem, od mulistego po twardsze, piaszczyste fragmenty. Brzegi są umiarkowanie dostępne, z miejscami porośniętymi trzciną, co wymaga czasem użycia wodoodpornego obuwia. Okresowe połączenie z Drwęcą zapewnia odświeżenie wody i sprzyja migracji ryb, w tym drapieżników. Jest to dobre łowisko dla szczupaka i okonia, a także leszczy i płoci. Roślinność podwodna jest umiarkowana, tworząc schronienie dla ryb, ale nie utrudnia znacząco wędkowania. Jest to popularne miejsce na wędkowanie spławikowe i spinningowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22189, 3.3, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Umiarkowany, miejscami zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22190, 'Starorzecze Chrośle A', 'starorzecze-chrosle-a-ilawa-22190', 'OXBOW', 53.4775456, 19.5977771, 'Warmińsko-Mazurskie', 'Iława', 'Starorzecze w Chroślu, położone w malowniczym krajobrazie Warmii i Mazur, stanowi typowe łowisko nizinne. Jego dno jest zróżnicowane, z przewagą mułu, ale z twardszymi miejscami w pobliżu dawnego nurtu rzeki. Brzegi są częściowo dostępne, porośnięte trawami i drzewami liściastymi, co zapewnia dogodne stanowiska wędkarskie. Roślinność podwodna jest umiarkowana, z pasami trzcin i grążeli, tworzącymi idealne kryjówki dla ryb. Wśród dominujących gatunków można spotkać szczupaki, liny, płocie, leszcze oraz karasie pospolite, co czyni to miejsce atrakcyjnym dla wędkarzy. Starorzecze łączy się z rzeką podczas wysokiej wody, co sprzyja migracji ryb i odświeżaniu ekosystemu. Wędkowanie tutaj nie nastręcza większych trudności, choć znalezienie najlepszych miejsc wymaga cierpliwości i obserwacji.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22190, 4.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Płoć,Leszcz,Karaś pospolity', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22191, 'Starorzecze Chrośle B', 'starorzecze-chrosle-b-ilawa-22191', 'OXBOW', 53.4761106, 19.5969852, 'Warmińsko-Mazurskie', 'Iława', 'To mniejsze starorzecze w Chroślu charakteryzuje się bardziej odizolowanym środowiskiem, bez stałego połączenia z głównym nurtem rzeki. Dno jest w dużej mierze zamulone, co sprzyja bujnej roślinności podwodnej i brzegowej. Brzegi są trudno dostępne, często bagniste i mocno zarośnięte trzciną oraz krzewami, co wymaga użycia wodoodpornych spodniobutów. Silne zarastanie i brak przepływu wody zwiększają ryzyko przyduchy, zwłaszcza w upalne lata. Mimo tych trudności, starorzecze jest ostoją dla wielu gatunków ryb, w tym dużych linów, karasi pospolitych, wzdręg i płoci. Wędkowanie tutaj jest wyzwaniem, ale może przynieść satysfakcjonujące efekty, szczególnie dla miłośników spokojnego łowienia w dzikich zakątkach. Zaleca się stosowanie metody spławikowej lub lekkiego gruntu w otwartych okienkach wśród roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22191, 3.1, 1.2, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22192, 'Starorzecze Jastrzębia', 'starorzecze-jastrzebia-radom-22192', 'OXBOW', 51.5263261, 21.2480079, 'Mazowieckie', 'Radom', 'Starorzecze Jastrzębia, położone w bliskości Radomia, wyróżnia się stałym połączeniem z rzeką, co zapewnia regularną wymianę wody i bogactwo gatunkowe. Dno jest stosunkowo czyste, z niewielkim zamuleniem, co sprzyja rozwojowi zróżnicowanej fauny dennej. Brzegi są łatwo dostępne, częściowo utwardzone, z licznymi dogodnymi miejscami do wędkowania. Roślinność wodna jest umiarkowana, skupiona głównie w płytszych zatoczkach, stanowiąc schronienie dla narybku. W tym starorzeczu dominują drapieżniki takie jak szczupak i okoń, ale również licznie występują leszcze, płocie oraz karpie, często osiągające imponujące rozmiary. Ze względu na stały przepływ wody, ryzyko przyduchy jest minimalne, co gwarantuje stabilne warunki przez cały rok. Łowisko jest popularne wśród lokalnych wędkarzy i oferuje dobre warunki do połowów przez większość sezonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22192, 6.5, 1.8, 4.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22193, 'Starorzecze Grzybniczka A', 'starorzecze-grzybniczka-a-sianow-22193', 'OXBOW', 54.0727727, 16.421009, 'Zachodniopomorskie', 'Sianów', 'Starorzecze Grzybniczka A, położone w pobliżu Sianowa, to płytkie i mocno zarośnięte łowisko, charakterystyczne dla starorzeczy Pomorza. Dno jest w przeważającej części muliste, z grubą warstwą osadów organicznych, co sprzyja rozwojowi bujnej roślinności. Brzegi są trudno dostępne, gęsto porośnięte trzciną i inną roślinnością szuwarową, co wymaga użycia specjalistycznego sprzętu, takiego jak wodery. Połączenie z rzeką następuje tylko podczas wysokiej wody, co ogranicza wymianę tlenu i zwiększa ryzyko przyduchy w okresach suszy i upałów. Dominujące gatunki ryb to lin, karaś pospolity, wzdręga i płoć, które doskonale adaptują się do tych warunków. Wędkowanie tutaj to wyzwanie, ale nagrodą mogą być piękne, zdrowe ryby. Najlepsze wyniki osiąga się wczesnym rankiem lub późnym wieczorem, w otwartych okienkach wśród roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22193, 2.8, 1, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22194, 'Starorzecze Grzybniczka B', 'starorzecze-grzybniczka-b-sianow-22194', 'OXBOW', 54.0743825, 16.4227166, 'Zachodniopomorskie', 'Sianów', 'Drugie starorzecze w rejonie Grzybniczki, podobnie jak sąsiednie, cechuje się znacznym zamuleniem i intensywnym zarastaniem. Brak stałego połączenia z rzeką sprawia, że jest to środowisko o ograniczonej wymianie wody, co zwiększa ryzyko niedoboru tlenu. Dno jest miękkie i muliste, z licznymi zatopionymi roślinami i gałęziami, co utrudnia wędkowanie na grunt. Brzegi są przeważnie bagniste i gęsto porośnięte, co czyni dostęp do wody bardzo trudnym i wymaga użycia woderów. Mimo tych wyzwań, starorzecze jest domem dla licznych populacji linów, karasi pospolitych, wzdręg i płoci, które dobrze radzą sobie w takich warunkach. Wędkowanie jest najbardziej efektywne w cieplejszych miesiącach, kiedy ryby są aktywne w płytkich, zarośniętych rejonach. To idealne miejsce dla wędkarzy poszukujących dzikich, nieuregulowanych łowisk.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22194, 3.5, 1.3, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22195, 'Starorzecze Grzybniczka C', 'starorzecze-grzybniczka-c-sianow-22195', 'OXBOW', 54.0739764, 16.4383317, 'Zachodniopomorskie', 'Sianów', 'To starorzecze Grzybniczka C, nieco większe i głębsze od sąsiednich, oferuje bardziej zróżnicowane warunki. Połączenie z rzeką podczas wysokiej wody sprzyja odświeżaniu wody i migracji ryb, co pozytywnie wpływa na populację drapieżników. Dno jest mieszane, z obszarami mulistymi i twardszymi, piaszczystymi fragmentami. Brzegi są w większości łatwo dostępne, z miejscami do rozstawienia sprzętu, choć lokalnie mogą występować zarośla. Roślinność podwodna jest umiarkowana, z pasami trzcin i lilii wodnych, tworzącymi naturalne kryjówki. W starorzeczu występują szczupaki, okonie, leszcze i płocie, co czyni je atrakcyjnym dla wędkarzy preferujących różne metody połowu. Brak wysokiego ryzyka przyduchy i stosunkowo dobre warunki dostępności sprawiają, że jest to popularne miejsce na weekendowe wypady. Wędkowanie jest skuteczne zarówno z brzegu, jak i z pontonu w cieplejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22195, 5.1, 1.6, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22196, 'Starorzecze Grzybnica A', 'starorzecze-grzybnica-a-sianow-22196', 'OXBOW', 54.0727439, 16.4397766, 'Zachodniopomorskie', 'Sianów', 'Starorzecze Grzybnica A, położone w malowniczej okolicy Sianowa, charakteryzuje się umiarkowanym zamuleniem i zróżnicowaną strukturą dna. Jest to łowisko o średniej wielkości, które podczas wysokich stanów wody łączy się z głównym nurtem rzeki, co sprzyja bogactwu gatunkowemu. Brzegi są w większości łatwo dostępne, porośnięte trawami i drzewami, oferując liczne stanowiska dla wędkarzy. Roślinność podwodna jest umiarkowana, z pasami trzcin i grążeli, które stanowią doskonałe kryjówki dla ryb. Wśród dominujących gatunków można spotkać szczupaki, liny, leszcze i płocie, co sprawia, że łowisko jest atrakcyjne dla różnych technik wędkarskich. Ryzyko przyduchy jest niskie, co zapewnia stabilne warunki przez większość sezonu. To popularne miejsce do rekreacyjnego wędkowania, cenione za spokój i urokliwe otoczenie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22196, 4.7, 1.4, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22197, 'Starorzecze Grzybnica B', 'starorzecze-grzybnica-b-sianow-22197', 'OXBOW', 54.0716146, 16.4397028, 'Zachodniopomorskie', 'Sianów', 'To niewielkie starorzecze Grzybnica B jest typowym, płytkim akwenem o znacznym zamuleniu i silnym zarastaniu. Brak połączenia z rzeką i niewielka głębokość sprawiają, że jest ono szczególnie podatne na wysychanie w upalne lata oraz na przyduchy. Dno jest miękkie, muliste, z grubą warstwą osadów organicznych. Brzegi są bardzo trudno dostępne, bagniste i gęsto porośnięte trzciną, co wymaga użycia woderów i często przecierania drogi. Mimo tych trudności, starorzecze jest ostoją dla wytrzymałych gatunków ryb, takich jak karaś pospolity, wzdręga i lin, które doskonale adaptują się do trudnych warunków. Wędkowanie jest wyzwaniem, ale dla miłośników dzikich łowisk może przynieść satysfakcję w postaci pięknych, zdrowych ryb. Najlepsze efekty osiąga się wczesnym latem, zanim roślinność osiągnie maksymalny rozwój.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22197, 2.1, 0.9, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22198, 'Starorzecze Ciechanów A', 'starorzecze-ciechanow-a-glogow-22198', 'OXBOW', 51.5753129, 16.4392434, 'Dolnośląskie', 'Głogów', 'Starorzecze Ciechanów A, położone w pobliżu Głogowa, jest dużym i głębokim akwenem z stałym połączeniem z Odrą, co zapewnia doskonałe warunki dla różnorodnych gatunków ryb. Dno jest zróżnicowane, z twardszymi, piaszczystymi fragmentami oraz obszarami mulistymi, co sprzyja występowaniu zarówno drapieżników, jak i ryb spokojnego żeru. Brzegi są łatwo dostępne, częściowo utwardzone, z licznymi dogodnymi miejscami do wędkowania. Roślinność wodna jest umiarkowana, skupiona głównie w płytszych zatoczkach, stanowiąc schronienie dla narybku. W starorzeczu dominują szczupaki, sandacze, leszcze, płocie i okonie, często osiągające imponujące rozmiary. Ze względu na stały przepływ wody, ryzyko przyduchy jest minimalne, co gwarantuje stabilne warunki przez cały rok. To popularne łowisko, cenione za obfitość ryb i komfortowe warunki dla wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22198, 8.5, 2, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22199, 'Starorzecze Ciechanów B', 'starorzecze-ciechanow-b-glogow-22199', 'OXBOW', 51.5737057, 16.4439871, 'Dolnośląskie', 'Głogów', 'Drugie starorzecze Ciechanów B, choć nieco mniejsze, również oferuje dobre warunki wędkarskie, łącząc się z Odrą podczas wysokich stanów wody. Dno jest mieszane, z przewagą mulu, ale z twardszymi fragmentami, gdzie można liczyć na lepsze brania. Brzegi są łatwo dostępne, częściowo zalesione, co zapewnia cień w upalne dni. Roślinność podwodna jest umiarkowana, z pasami trzcin i grążeli, które stanowią naturalne kryjówki dla ryb. W starorzeczu występują szczupaki, leszcze, płocie, karpie i liny, co sprawia, że jest to łowisko atrakcyjne dla różnych metod połowu. Ryzyko przyduchy jest niskie dzięki okresowemu połączeniu z rzeką. Wędkowanie jest najbardziej efektywne wczesną wiosną i jesienią, kiedy ryby są aktywne i żerują intensywniej. To doskonałe miejsce na relaks z wędką w ręku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22199, 6, 1.7, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Karp,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22200, 'Starorzecze Ciechanów C', 'starorzecze-ciechanow-c-glogow-22200', 'OXBOW', 51.5743386, 16.4432489, 'Dolnośląskie', 'Głogów', 'Starorzecze Ciechanów C to jedno z głębszych i bardziej dynamicznych łowisk w regionie Głogowa, z zapewnionym stałym połączeniem z rzeką Odrą. Charakteryzuje się czystym dnem z minimalnym zamuleniem, co sprzyja występowaniu ryb drapieżnych i karpiowatych. Brzegi są bardzo dobrze dostępne, z licznymi polankami i miejscami do rozstawienia sprzętu, co ułatwia wędkowanie. Roślinność podwodna jest słaba, co ułatwia prowadzenie przynęt i minimalizuje zaczepy. W starorzeczu dominują sumy, sandacze, szczupaki, leszcze i karpie, często osiągające znaczne rozmiary, co przyciąga wędkarzy poszukujących dużych okazów. Stały przepływ wody eliminuje ryzyko przyduchy, zapewniając stabilne i korzystne warunki przez cały rok. To idealne miejsce dla wędkarzy preferujących łowienie na spinning, grunt lub z zasiadki na karpia i suma.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22200, 7.2, 1.9, 4.8, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Sandacz,Szczupak,Leszcz,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22201, 'Starorzecze Zakrzewo A', 'starorzecze-zakrzewo-a-mielno-22201', 'OXBOW', 54.4386332, 16.4694296, 'Zachodniopomorskie', 'Mielno', 'Starorzecze Zakrzewo A, położone w malowniczej okolicy Mielna, to średniej wielkości zbiornik, który okresowo łączy się z rzeką, co sprzyja dynamicznej populacji ryb. Dno jest zróżnicowane, z obszarami mulistymi i twardszymi, piaszczystymi fragmentami, co pozwala na różnorodne metody połowu. Brzegi są w większości łatwo dostępne, z naturalnymi pomostami i polankami, idealnymi do rozstawienia sprzętu. Roślinność podwodna jest umiarkowana, z pasami trzcin i lilii wodnych, tworzącymi naturalne kryjówki dla ryb. W starorzeczu występują szczupaki, okonie, leszcze, płocie i wzdręgi, co czyni je atrakcyjnym dla wędkarzy preferujących zarówno drapieżniki, jak i ryby spokojnego żeru. Ryzyko przyduchy jest niskie dzięki okresowemu połączeniu z rzeką. To popularne miejsce na weekendowe wypady, cenione za spokój i urokliwe otoczenie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22201, 5.5, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Wzdręga', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22202, 'Starorzecze Zakrzewo B', 'starorzecze-zakrzewo-b-mielno-22202', 'OXBOW', 54.4408337, 16.4774361, 'Zachodniopomorskie', 'Mielno', 'To starorzecze Zakrzewo B charakteryzuje się brakiem stałego połączenia z rzeką, co sprawia, że jest to środowisko o ograniczonej wymianie wody i znacznym zamuleniu. Dno jest miękkie i muliste, z grubą warstwą osadów organicznych, co sprzyja bujnej roślinności. Brzegi są trudno dostępne, gęsto porośnięte trzciną i inną roślinnością szuwarową, co wymaga użycia woderów i często przecierania drogi. Silne zarastanie i brak przepływu wody zwiększają ryzyko przyduchy, zwłaszcza w upalne lata. Mimo tych trudności, starorzecze jest ostoją dla wytrzymałych gatunków ryb, takich jak lin, karaś pospolity, wzdręga i płoć, które doskonale adaptują się do tych warunków. Wędkowanie jest wyzwaniem, ale może przynieść satysfakcjonujące efekty, szczególnie dla miłośników spokojnego łowienia w dzikich zakątkach. Zaleca się stosowanie metody spławikowej w otwartych okienkach wśród roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22202, 4, 1.5, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22203, 'Starorzecze Zakrzewo C', 'starorzecze-zakrzewo-c-mielno-22203', 'OXBOW', 54.438721, 16.4823773, 'Zachodniopomorskie', 'Mielno', 'Starorzecze Zakrzewo C to płytki i mocno zamulony zbiornik, całkowicie odizolowany od głównego nurtu rzeki. Jego niewielka głębokość i brak połączenia z rzeką sprawiają, że jest on bardzo podatny na wysychanie w okresach suszy oraz na przyduchy w upalne lata. Dno jest miękkie, z grubą warstwą osadów organicznych i gęstą roślinnością podwodną. Brzegi są trudne do pokonania, często bagniste i gęsto porośnięte trzciną, co wymaga użycia woderów i cierpliwości. W tych trudnych warunkach najlepiej czują się karasie pospolite, karasie srebrzyste i wzdręgi, które są bardzo odporne na niedobory tlenu. Wędkowanie jest wyzwaniem, ale dla wędkarzy szukających dzikich, nieuregulowanych łowisk, może przynieść unikalne doświadczenia. Zaleca się lekkie zestawy spławikowe i naturalne przynęty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22203, 3.2, 1.1, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Karaś srebrzysty,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22204, 'Starorzecze Zakrzewo D', 'starorzecze-zakrzewo-d-mielno-22204', 'OXBOW', 54.438332, 16.483887, 'Zachodniopomorskie', 'Mielno', 'Starorzecze Zakrzewo D wyróżnia się stałym połączeniem z rzeką, co gwarantuje stabilne warunki wodne i bogactwo ichtiofauny. Jest to jedno z większych i głębszych starorzeczy w okolicy Mielna, z dnem stosunkowo czystym i zróżnicowanym. Brzegi są łatwo dostępne, z licznymi dogodnymi miejscami do wędkowania, co sprawia, że jest to popularne miejsce wśród lokalnych wędkarzy. Roślinność podwodna jest słaba, co ułatwia prowadzenie przynęt i minimalizuje zaczepy, szczególnie dla spinningistów. W starorzeczu dominują szczupaki, okonie, leszcze, płocie oraz węgorze, które doceniają stały przepływ wody i dostęp do rzeki. Niskie ryzyko przyduchy i komfortowe warunki sprawiają, że można tu łowić przez cały sezon, z dobrymi wynikami zarówno wczesną wiosną, jak i późną jesienią. To idealne miejsce dla wędkarzy poszukujących różnorodnych gatunków ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22204, 6.8, 2.1, 4.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Węgorz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22205, 'Starorzecze (Zakrzewo) #1', 'starorzecze-zakrzewo-1-sianow-22205', 'OXBOW', 54.4370376, 16.4866067, 'Zachodniopomorskie', 'Sianów', 'To starorzecze charakteryzuje się płytkim, mulistym dnem, idealnym dla rozwoju bogatej roślinności podwodnej i wynurzonej. Brzegi są w większości porośnięte gęstymi trzcinami i szuwarami, co utrudnia dostęp do wody, ale jednocześnie stanowi doskonałe schronienie dla ryb. Wędkarze mogą spodziewać się tu licznych zaczepów w postaci zatopionych gałęzi i kęp roślinności, co wymaga precyzyjnych rzutów. Dominującymi gatunkami ryb są lin, karaś pospolity oraz płoć, które znajdują tu idealne warunki do żerowania i rozrodu. Wiosną i wczesną jesienią woda jest przejrzysta, jednak latem, przy wysokich temperaturach, może dochodzić do zakwitów, co zwiększa ryzyko przyduchy. Łowisko to wymaga cierpliwości i często brodzenia, ale nagradza pięknymi okazami ryb spokojnego żeru.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22205, 2.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22206, 'Starorzecze (Zakrzewo) #2', 'starorzecze-zakrzewo-2-sianow-22206', 'OXBOW', 54.4364065, 16.4872573, 'Zachodniopomorskie', 'Sianów', 'To niewielkie starorzecze, położone w bliskiej odległości od poprzedniego, jest znacznie płytsze i bardziej zarośnięte. Dno jest grząskie i mocno zailone, co sprzyja rozwojowi bujnej roślinności wodnej, takiej jak rzęsa i moczarka kanadyjska. Brzegi są praktycznie niedostępne bez brodzenia, z powodu gęstych pasów trzcin i krzewów. Wędkarstwo tutaj to wyzwanie, ale obfituje w liczne populacje karasia pospolitego i wzdręgi. Latem, przy niskim poziomie wody i wysokich temperaturach, istnieje podwyższone ryzyko przyduchy, co może wpływać na aktywność ryb. Jest to idealne miejsce dla miłośników dzikiego wędkarstwa, którzy cenią sobie spokój i kontakt z naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22206, 1.9, 1.2, 2.8, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć,Lin', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22207, 'Starorzecze (Zakrzewo) #3', 'starorzecze-zakrzewo-3-sianow-22207', 'OXBOW', 54.4367513, 16.4883301, 'Zachodniopomorskie', 'Sianów', 'To starorzecze charakteryzuje się umiarkowanym poziomem zamulenia i nieco lepszym dostępem do brzegów w porównaniu do sąsiednich zbiorników. Dno jest zróżnicowane, od mulistego po twardsze, piaszczyste partie, co sprzyja różnorodności gatunków ryb. Roślinność podwodna jest obecna, ale nie tak gęsta jak w innych starorzeczach, co ułatwia prowadzenie przynęt. Brak stałego połączenia z rzeką sprawia, że woda jest spokojna, ale jednocześnie bardziej podatna na wahania poziomu tlenu. Można tu liczyć na liny, karasie pospolite, płocie oraz okonie, szczególnie w miejscach z pojedynczymi zaczepami. Wędkarstwo z brzegu jest możliwe w kilku wyznaczonych miejscach, choć brodzenie otwiera nowe perspektywy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22207, 2.1, 1.6, 3, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Okoń', 'Dobry z jednej strony, zarośnięty z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22208, 'Starorzecze (Zielnowo) #1', 'starorzecze-zielnowo-1-sianow-22208', 'OXBOW', 54.4437195, 16.500519, 'Zachodniopomorskie', 'Sianów', 'Starorzecze w Zielnowie to większy zbiornik, który zachował częściowe połączenie z rzeką Dzierżęcinką podczas wysokich stanów wody, co wpływa na jego dynamikę i różnorodność biologiczną. Dno jest mniej zamulone niż w mniejszych starorzeczach, z przewagą osadów dennych i miejscami twardszym podłożem. Brzegi są częściowo dostępne, z licznymi zatoczkami i miejscami porośniętymi roślinnością wodną, taką jak lilie i grążele. W zbiorniku tym występują liczne szczupaki, liny, leszcze i płocie, a także okonie. Ze względu na większą głębokość i przepływ wody, ryzyko przyduchy jest tu niższe. Jest to atrakcyjne łowisko zarówno dla spinningistów, jak i wędkarzy gruntowych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22208, 3.5, 2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22209, 'Starorzecze (Drozdowo)', 'starorzecze-drozdowo-sianow-22209', 'OXBOW', 54.44525, 16.5088102, 'Zachodniopomorskie', 'Sianów', 'To starorzecze charakteryzuje się stałym połączeniem z rzeką, co zapewnia stały dopływ świeżej wody i niski poziom zamulenia. Jest to jedno z głębszych starorzeczy w okolicy, z urozmaiconym dnem, gdzie twardsze partie przeplatają się z niewielkimi obszarami mulistymi. Brzegi są w większości dobrze dostępne, choć miejscami mogą być strome, oferując dogodne stanowiska wędkarskie. Roślinność podwodna jest umiarkowana, z przewagą zanurzonej w głębszych partiach i trzcin w płytszych zatokach. Występują tu liczne drapieżniki, takie jak szczupak i okoń, a także duże populacje leszczy, płoci i jazi. Łowisko jest cenione przez wędkarzy ze względu na stabilne warunki i możliwość złowienia okazałych ryb przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22209, 4.2, 2.2, 4.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Płoć,Jaź', 'Dobry z jednej strony, utrudniony z drugiej', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22210, 'Starorzecze (Zielnowo) #2', 'starorzecze-zielnowo-2-sianow-22210', 'OXBOW', 54.440235, 16.494557, 'Zachodniopomorskie', 'Sianów', 'To starorzecze stanowi klasyczny przykład zbiornika z okresowym połączeniem z rzeką, co zapewnia regularne odświeżanie wody. Dno jest średnio zamulone, z licznymi zatopionymi drzewami i gałęziami, które tworzą doskonałe kryjówki dla ryb. Brzegi są gęsto porośnięte trzcinami i inną roślinnością szuwarową, co utrudnia dostęp, ale jednocześnie tworzy idealne warunki do bytowania lina i karasia. Wiosną i jesienią woda jest czysta, natomiast w upalne lato może dochodzić do silnego zakwitu glonów, zwiększając ryzyko niedoboru tlenu. Łowisko to wymaga cierpliwości i umiejętności łowienia w zarośniętych miejscach, oferując jednak szansę na złowienie okazałych egzemplarzy ryb spokojnego żeru i drapieżników. Jest to raj dla wędkarzy ceniących dzikie i wymagające tereny.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22210, 2.9, 1.7, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak,Wzdręga', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22211, 'Starorzecze (Zakrzewo) #4', 'starorzecze-zakrzewo-4-sianow-22211', 'OXBOW', 54.4412036, 16.4816737, 'Zachodniopomorskie', 'Sianów', 'To niewielkie i bardzo odizolowane starorzecze, które nie posiada stałego połączenia z żadną rzeką, co czyni je wyjątkowo wrażliwym na warunki atmosferyczne. Dno jest silnie zamulone i grząskie, z grubą warstwą osadów organicznych, co sprzyja bujnemu rozwojowi roślinności wodnej. Brzegi są mocno zarośnięte trzcinami i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest niezwykle trudny i wymaga brodzenia. Wędkarstwo skupia się tu głównie na karasiu pospolitym i wzdrędze, które doskonale radzą sobie w tych warunkach. W okresach suszy i upałów zbiornik ten jest zagrożony wyschnięciem, co drastycznie wpływa na populację ryb. Jest to łowisko dla prawdziwych pasjonatów, gotowych na wyzwania i ceniących dziką przyrodę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22211, 1.5, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22212, 'Starorzecze (Wólka Smolana) #1', 'starorzecze-wolka-smolana-1-kielce-22212', 'OXBOW', 51.1087103, 20.370038, 'Świętokrzyskie', 'Kielce', 'To duże starorzecze, będące częścią kompleksu wodnego Biała Nida, charakteryzuje się stałym połączeniem z rzeką, co zapewnia doskonałą jakość wody i niski poziom zamulenia. Dno jest zróżnicowane, z twardszymi partiami piaszczysto-żwirowymi i głębszymi dołkami z mulistym osadem. Brzegi są dobrze dostępne, z licznymi miejscami do wędkowania, choć miejscami porastają je drzewa i krzewy. Obfita roślinność podwodna stanowi schronienie dla licznych gatunków ryb, w tym dużych szczupaków, sumów, karpi i leszczy. Ze względu na rozmiar i stałe połączenie, ryzyko przyduchy jest minimalne. Łowisko to jest bardzo popularne wśród wędkarzy, oferując doskonałe warunki do połowu wielu gatunków ryb przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22212, 6, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Karp,Sum,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22213, 'Starorzecze (Wólka Smolana) #2', 'starorzecze-wolka-smolana-2-kielce-22213', 'OXBOW', 51.1080171, 20.3693392, 'Świętokrzyskie', 'Kielce', 'Drugie starorzecze w Wólce Smolanej, choć również połączone z Białą Nidą, jest nieco mniejsze i charakteryzuje się bardziej zarośniętymi brzegami. Dno jest średnio zamulone, z licznymi podwodnymi zaczepami w postaci zatopionych konarów i kęp roślinności, co wymaga ostrożności podczas wędkowania. Roślinność wodna jest obfita, tworząc idealne środowisko dla lina, karpia i leszcza. Pomimo połączenia z rzeką, w niektórych płytszych zatokach latem może występować umiarkowane ryzyko spadku poziomu tlenu. Dostęp do wody jest dobry w wielu miejscach, ale niektóre partie brzegów są trudniejsze do przejścia. Jest to doskonałe miejsce dla wędkarzy poszukujących dużych okazów karpia i lina w naturalnym środowisku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22213, 4.8, 2, 4.2, 'Stałe połączenie', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Lin,Płoć,Szczupak', 'Dobry, ale miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22214, 'Starorzecze (Jagielno)', 'starorzecze-jagielno-darlowo-22214', 'OXBOW', 54.0749097, 16.2611215, 'Zachodniopomorskie', 'Darłowo', 'Starorzecze w Jagielnie to typowy zbiornik z okresowym połączeniem z rzeką Wieprzą, charakteryzujący się dzikim i naturalnym charakterem. Dno jest muliste, z dużą ilością detrytusu i zatopionych drzew, co stanowi wyzwanie dla wędkarzy, ale jednocześnie doskonałe schronienie dla ryb. Brzegi są w większości bagniste i mocno zarośnięte trzciną, co wymaga użycia brodów lub specjalistycznego sprzętu. Roślinność wodna jest bardzo obfita, tworząc gęste dywany lilii wodnych i grążeli. W starorzeczu dominują lin, karaś pospolity, płoć oraz szczupak, które znajdują tu idealne warunki do rozwoju. Latem, przy wysokich temperaturach, zbiornik jest podatny na przyduchy. To łowisko dla wędkarzy ceniących dzikość i ciszę, gotowych na trudny dostęp w zamian za obfite połowy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22214, 3.2, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22215, 'Starorzecze (Kamosowo)', 'starorzecze-kamosowo-bialogard-22215', 'OXBOW', 53.9896376, 15.8835597, 'Zachodniopomorskie', 'Białogard', 'Starorzecze w Kamosowie to duży i głęboki zbiornik ze stałym połączeniem z rzeką Parsętą, co zapewnia doskonałe warunki wodne przez cały rok. Dno jest zróżnicowane, z twardszymi partiami piaszczysto-żwirowymi i głębszymi dołkami, gdzie gromadzi się mulisty osad. Brzegi są dobrze dostępne, z licznymi dogodnymi stanowiskami wędkarskimi, choć miejscami mogą być porośnięte roślinnością. Roślinność podwodna jest umiarkowana, z przewagą zanurzonej w głębszych partiach i trzcin w płytszych zatokach. Występują tu liczne drapieżniki, takie jak szczupak, okoń i węgorz, a także duże populacje leszczy i karpi. Łowisko jest cenione przez wędkarzy ze względu na stabilne warunki i możliwość złowienia okazałych ryb przez cały sezon, w tym rzadziej spotykanych węgorzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22215, 5.5, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Karp,Węgorz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22216, 'Starorzecze (Nasutowo) #1', 'starorzecze-nasutowo-1-bialogard-22216', 'OXBOW', 53.9914132, 15.8722769, 'Zachodniopomorskie', 'Białogard', 'To starorzecze w Nasutowie, choć blisko połączone z Parsętą podczas wysokich wód, zachowuje charakter spokojnej, bogatej w roślinność ostoi. Dno jest średnio zamulone, z licznymi zatopionymi drzewami i gałęziami, które stanowią doskonałe kryjówki dla ryb. Brzegi są miejscami trudne do przejścia z powodu gęstych zarośli i trzcin, co wymaga brodzenia lub poszukiwania otwartych stanowisk. Roślinność wodna jest obfita, tworząc liczne tarliska i miejsca żerowania dla ryb. W zbiorniku dominują lin, leszcz, płoć, szczupak oraz karaś srebrzysty. W cieplejszych miesiącach, przy niższym poziomie wody, może wystąpić ryzyko niedoboru tlenu. To łowisko dla wędkarzy ceniących dzikość i gotowych na wyzwania w poszukiwaniu ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22216, 3.8, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Leszcz,Płoć,Szczupak,Karaś srebrzysty', 'Trudny, miejscami zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22217, 'Starorzecze (Nasutowo) #2', 'starorzecze-nasutowo-2-bialogard-22217', 'OXBOW', 53.9905057, 15.8704303, 'Zachodniopomorskie', 'Białogard', 'Kolejne starorzecze w Nasutowie, podobnie jak sąsiednie, łączy się z Parsętą podczas wysokich stanów wody, co wpływa na jego ekosystem. Dno jest umiarkowanie zamulone, z pojedynczymi korzeniami i gałęziami, które mogą stanowić zaczepy, ale nie utrudniają znacząco wędkowania. Brzegi są dostępne z jednej strony, natomiast z drugiej są bardziej zarośnięte, oferując różnorodne miejsca do wędkowania. Roślinność podwodna jest obecna, ale nie jest nadmiernie gęsta, co pozwala na swobodne prowadzenie przynęt. Występują tu szczupaki, okonie, leszcze, płocie i liny, które dobrze czują się w tych warunkach. Ryzyko przyduchy jest umiarkowane, głównie w okresach długotrwałych upałów. Jest to wszechstronne łowisko, odpowiednie zarówno dla wędkarzy gruntowych, jak i spinningistów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22217, 4, 2.1, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Lin', 'Dobry z jednej strony, trudny z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22218, 'Starorzecze (Poborszów) #1', 'starorzecze-poborszow-1-kedzierzyn-kozle-22218', 'OXBOW', 50.3897436, 18.1017322, 'Opolskie', 'Kędzierzyn-Koźle', 'To rozległe starorzecze w Poborszowie jest jednym z największych w regionie i posiada stałe, szerokie połączenie z Odrą, co gwarantuje doskonałe warunki wodne. Dno jest zróżnicowane, z głębokimi rynnami, twardszymi partiami piaszczystymi i mulistymi zatokami, oferując bogate siedliska dla wielu gatunków ryb. Brzegi są w większości dobrze dostępne, z licznymi polankami i miejscami do wędkowania, choć w niektórych partiach mogą występować zarośla. Roślinność podwodna jest umiarkowana, co sprzyja zarówno drapieżnikom, jak i rybom spokojnego żeru. W zbiorniku tym występują okazałe sumy, karpie, leszcze, sandacze i szczupaki, co czyni go rajem dla wędkarzy. Jest to łowisko o stabilnych warunkach, idealne na całoroczne wyprawy wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22218, 7, 3, 6, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Karp,Leszcz,Sandacz,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie, zatopione konary', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22219, 'Starorzecze (Poborszów) #2', 'starorzecze-poborszow-2-kedzierzyn-kozle-22219', 'OXBOW', 50.3822493, 18.1030148, 'Opolskie', 'Kędzierzyn-Koźle', 'Drugie starorzecze w Poborszowie, również stale połączone z Odrą, jest nieco mniejsze, ale równie atrakcyjne pod względem wędkarskim. Charakteryzuje się czystym dnem w głębszych partiach, z nielicznymi zaczepami, co ułatwia prowadzenie przynęt. Brzegi są dobrze dostępne, choć miejscami mogą być strome, oferując ciekawe stanowiska dla wędkarzy. Roślinność podwodna jest umiarkowana, tworząc idealne środowisko dla ryb, ale nie utrudniając łowienia. W zbiorniku tym można spotkać duże sumy, karpie, leszcze, bolenie i szczupaki, które korzystają z bliskości głównego nurtu rzeki. Dzięki stałemu połączeniu, ryzyko przyduchy jest minimalne, a warunki do wędkowania są stabilne przez cały rok. To doskonałe miejsce dla wędkarzy poszukujących różnorodnych gatunków ryb rzecznych i starorzecznych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22219, 6.5, 2.8, 5.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Karp,Leszcz,Boleń,Szczupak', 'Dobry, ale miejscami strome brzegi', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22220, 'Starorzecze (Stubno)', 'starorzecze-stubno-stubno-22220', 'OXBOW', 49.9022681, 22.9278706, 'Podkarpackie', 'Stubno', 'Klasyczne starorzecze Sanu, charakteryzujące się spokojną wodą i bogatą roślinnością brzegową. Dno jest muliste, z licznymi zatopionymi gałęziami i korzeniami, co sprzyja rozwojowi wielu gatunków ryb. Brzegi są częściowo dostępne, ale w niektórych miejscach silnie zarośnięte trzciną i krzewami. Wędkowanie wymaga cierpliwości i często użycia brodzenia, zwłaszcza gdy chcemy dotrzeć do najlepszych miejscówek. Jest to idealne miejsce dla wędkarzy poszukujących ciszy i kontaktu z naturą, z szansą na złowienie okazałych egzemplarzy drapieżników i ryb spokojnego żeru. Warto spróbować metody spławikowej lub gruntowej w okolicach podwodnych przeszkód.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22220, 4.8, 1.5, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Szczupak,Karaś pospolity,Płoć', 'Trudny, miejscami zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22221, 'Starorzecze (Staniewice)', 'starorzecze-staniewice-staniewice-22221', 'OXBOW', 54.4408167, 16.7508495, 'Zachodniopomorskie', 'Staniewice', 'To starorzecze, położone w malowniczej okolicy Staniewic, jest płytkim zbiornikiem z dnem pokrytym grubą warstwą mułu. Charakteryzuje się bujną roślinnością podwodną i brzegową, która stanowi doskonałe schronienie dla ryb, ale utrudnia wędkowanie. Dostęp do wody jest ograniczony w wielu miejscach ze względu na gęste zarośla i podmokłe brzegi, wymagając często brodzenia. Wędkowanie z brzegu jest wyzwaniem, często wymagającym użycia podbieraka z długą rączką lub specjalistycznego sprzętu. Mimo trudności, starorzecze obfituje w ryby typowe dla płytkich, zarośniętych wód, takie jak liny czy karasie. To idealne miejsce dla cierpliwych wędkarzy, ceniących sobie dziką przyrodę i spokojne łowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22221, 2.1, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22222, 'Starorzecze (Staniewice)', 'starorzecze-staniewice-staniewice-22222', 'OXBOW', 54.4400935, 16.7526193, 'Zachodniopomorskie', 'Staniewice', 'Niewielkie starorzecze w pobliżu Staniewic, charakteryzujące się spokojnym charakterem i znacznym stopniem zarośnięcia, co czyni je trudnym łowiskiem. Dno jest przeważnie muliste, z licznymi płyciznami i podwodnymi przeszkodami w postaci roślinności, która gęsto porasta całą powierzchnię. Brzegi są trudnodostępne, często podmokłe i porośnięte gęstymi krzewami oraz trzciną, co utrudnia swobodne poruszanie się i zarzucanie zestawu. Jest to idealne środowisko dla ryb preferujących płytkie, ciepłe wody, takie jak wzdręgi czy karasie. Wędkowanie wymaga precyzji, często krótkich zestawów i umiejętności łowienia w zarośniętych miejscach. W upalne lata istnieje ryzyko przesuszenia się płytszych partii zbiornika.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22222, 1.8, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22223, 'Starorzecze (Pieszcz)', 'starorzecze-pieszcz-pieszcz-22223', 'OXBOW', 54.4502569, 16.747335, 'Zachodniopomorskie', 'Pieszcz', 'To starorzecze w Pieszczu to urokliwy zbiornik wodny, często odwiedzany przez lokalnych wędkarzy ze względu na łatwość dostępu. Charakteryzuje się piaszczysto-mulistym dnem i umiarkowanym zarośnięciem, co ułatwia wędkowanie z brzegu i z łodzi. Woda jest stosunkowo czysta, a brzegi są stabilne i dostępne w wielu miejscach, oferując komfortowe warunki. Występują tu zarówno gatunki typowe dla starorzeczy, jak i ryby, które sporadycznie wpływają z pobliskich cieków podczas wyższych stanów wody. Jest to doskonałe miejsce na rodzinne wypady wędkarskie, oferujące relaks i szansę na złowienie różnorodnych ryb, od płoci po szczupaki. Regularne zarybienia przyczyniają się do utrzymania wysokiej populacji rybnej.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22223, 3.5, 1.4, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22224, 'Starorzecze (Pińczów)', 'starorzecze-pinczow-pinczow-22224', 'OXBOW', 50.4995436, 20.543231, 'Świętokrzyskie', 'Pińczów', 'To starorzecze Nidy koło Pińczowa to typowy zbiornik o charakterze rzecznym, z wolno płynącą wodą w okresach wzmożonych opadów. Dno jest zróżnicowane, od piaszczysto-żwirowego po muliste w zatokach, co sprzyja różnym technikom wędkowania. Brzegi są przeważnie stabilne, z łatwym dostępem w wielu miejscach, co sprzyja wędkowaniu spinningowemu i gruntowemu. Bogata roślinność brzegowa i podwodna tworzy doskonałe kryjówki dla drapieżników, takich jak szczupaki i okonie. Jest to popularne łowisko, cenione za różnorodność gatunków ryb i piękne krajobrazy Ponidzia. Warto spróbować tutaj metody feederowej na leszcze i płocie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22224, 7.3, 1.8, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22225, 'Starorzecze (Pińczów)', 'starorzecze-pinczow-pinczow-22225', 'OXBOW', 50.4982334, 20.5514268, 'Świętokrzyskie', 'Pińczów', 'Niewielkie, ale głębokie starorzecze Nidy, charakteryzujące się czystą wodą i twardym, gliniastym dnem w większości obszarów, co jest rzadkością w starorzeczach. Brzegi są strome i porośnięte drzewami, co tworzy cień i sprzyja występowaniu drapieżników oraz dużych ryb spokojnego żeru. Dostęp jest miejscami utrudniony ze względu na wysoką roślinność i zwalone drzewa, wymagając ostrożności. Wędkowanie z gruntu i na spławik daje dobre rezultaty, zwłaszcza w głębszych partiach, gdzie często przebywają sumy i karpie. To miejsce jest znane z występowania dużych okazów karpi i sumów, które znajdują tu idealne warunki do żerowania. Ze względu na głębokość i stabilne dno, ryzyko przyduchy jest niskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22225, 3.1, 2.5, 5.5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Karp,Leszcz,Szczupak', 'Trudny, strome brzegi', FALSE, 'Dużo zatopionych drzew', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22226, 'Starorzecze (Pińczów)', 'starorzecze-pinczow-pinczow-22226', 'OXBOW', 50.5017635, 20.5451407, 'Świętokrzyskie', 'Pińczów', 'To starorzecze Nidy to płytki, silnie zarośnięty zbiornik, idealny dla gatunków preferujących ciepłe i spokojne wody, takie jak lin czy karaś. Dno jest w całości pokryte grubą warstwą mułu i obfituje w roślinność podwodną, taką jak grążele i rdestnice, co utrudnia zarzucanie. Brzegi są bagniste i trudno dostępne, co wymaga ostrożności i często użycia brodzenia lub pontonu, aby dotrzeć do ryb. Mimo trudności, jest to raj dla wędkarzy poszukujących lina i karasia, które osiągają tu imponujące rozmiary. Wędkowanie z pontonu lub środka pływającego jest tutaj najbardziej efektywne i pozwala na precyzyjne umieszczenie przynęty. W upalne, bezwietrzne dni może wystąpić deficyt tlenu w wodzie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22226, 5.2, 1.2, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22227, 'Starorzecze (Staniewice)', 'starorzecze-staniewice-staniewice-22227', 'OXBOW', 54.4325918, 16.7445935, 'Zachodniopomorskie', 'Staniewice', 'To starorzecze w Staniewicach to płytki akwen o charakterze bagiennym, zdominowany przez gęstą roślinność wodną, co czyni go trudnym do wędkowania. Dno jest bardzo miękkie i muliste, co sprawia, że poruszanie się po brzegach jest niezwykle trudne i ryzykowne. Wędkowanie jest tutaj prawdziwym wyzwaniem, często wymagającym użycia pontonu lub specjalnych platform, aby uniknąć zapadnięcia się. Mimo trudności, zbiornik jest ostoją dla wielu gatunków ryb, które znajdują tu idealne warunki do życia i rozrodu, zwłaszcza dla karasi i linów. Należy zachować szczególną ostrożność ze względu na ryzyko zapadnięcia się w grząskie dno i potencjalne zagrożenie. Wiosną i jesienią poziom wody może znacznie się wahać.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22227, 2.7, 0.7, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22228, 'Starorzecze (Przeworsk)', 'starorzecze-przeworsk-przeworsk-22228', 'OXBOW', 50.0619351, 22.48232, 'Podkarpackie', 'Przeworsk', 'Rozległe starorzecze Wisłoka w okolicach Przeworska, znane z dużej różnorodności ryb i stosunkowo dobrego dostępu. Charakteryzuje się piaszczysto-mulistym dnem i zmiennym stopniem zarośnięcia w zależności od pory roku i poziomu wody. Brzegi są w większości dostępne, z licznymi dogodnymi miejscami do wędkowania z brzegu, zarówno na spławik, jak i grunt. W okresach wysokiej wody starorzecze łączy się z rzeką, co sprzyja migracji ryb i wzbogaca jego ichtiofaunę o nowe gatunki. Jest to popularne miejsce dla wędkarzy gruntowych i spławikowych, oferujące szansę na złowienie dorodnych okazów, w tym leszczy i karpi. Należy jednak uważać na liczne podwodne zaczepy, zwłaszcza w rejonie dawnego koryta rzeki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22228, 10.5, 1.7, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Sandacz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22229, 'Starorzecze (Giełczyn)', 'starorzecze-gielczyn-gielczyn-22229', 'OXBOW', 53.2610768, 22.4701253, 'Podlaskie', 'Giełczyn', 'To starorzecze Narwi w Giełczynie to typowy, silnie zarośnięty zbiornik, będący ostoją dla wielu gatunków ryb, szczególnie tych preferujących spokojne wody. Dno jest głęboko muliste, a woda często mętna z powodu rozkładającej się roślinności, co wpływa na widoczność. Brzegi są trudnodostępne, porośnięte gęstą trzciną i krzewami, co sprawia, że wędkowanie z brzegu jest prawdziwym wyzwaniem. Mimo to, jest to doskonałe miejsce dla wędkarzy poszukujących lina, karasia i szczupaka w trudnych, ale bardzo rybnych warunkach. Wymaga to cierpliwości, odpowiedniego sprzętu i często spławiania przynęty w niewielkich okienkach między roślinnością. W upalne lata istnieje wysokie ryzyko przyduchy ze względu na małą głębokość i obfitość materii organicznej.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22229, 6.3, 1.3, 2.9, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22230, 'Starorzecze (Wrocław)', 'starorzecze-wroclaw-wroclaw-22230', 'OXBOW', 51.1565583, 16.8875804, 'Dolnośląskie', 'Wrocław', 'To starorzecze Odry w granicach Wrocławia to popularne łowisko miejskie, łatwo dostępne dla wędkarzy, co czyni je idealnym miejscem na szybki wypad. Charakteryzuje się zróżnicowanym dnem, od piaszczystego po muliste, i umiarkowanym zarośnięciem, co daje wiele możliwości wędkowania. Brzegi są w większości uregulowane i dobrze utrzymane, co zapewnia komfortowe warunki do wędkowania z brzegu. Mimo bliskości miasta, starorzecze utrzymuje bogatą ichtiofaunę, a regularne zarybienia zwiększają szanse na udane połowy. Jest to doskonałe miejsce na szybki wypad na ryby po pracy, oferujące relaks i kontakt z naturą w miejskim otoczeniu. Można tu spotkać zarówno ryby spokojnego żeru, jak i drapieżniki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22230, 9, 2, 4.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22231, 'Starorzecze (Stocki Młyn)', 'starorzecze-stocki-mlyn-stocki-mlyn-22231', 'OXBOW', 53.8817724, 18.710772, 'Pomorskie', 'Stocki Młyn', 'To rozległe starorzecze Wisły w Stockim Młynie to raj dla wędkarzy poszukujących spokoju i dużych ryb, szczególnie sumów i sandaczy. Charakteryzuje się głębokimi rynnami i piaszczysto-mulistym dnem, z licznymi podwodnymi przeszkodami w postaci zatopionych drzew. Brzegi są częściowo zarośnięte, ale w wielu miejscach dostęp jest dobry, zwłaszcza z wykorzystaniem łodzi, która jest tu bardzo przydatna. Woda jest stosunkowo czysta, a bogata roślinność podwodna i brzegowa stanowi idealne środowisko dla drapieżników. Jest to łowisko cenione za obecność dużych sumów i sandaczy, które żerują w głębszych partiach. Warto korzystać z echosondy, aby zlokalizować najlepsze miejscówki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22231, 15, 2.8, 6, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Sum,Sandacz,Szczupak,Leszcz,Karp', 'Dobry z łodzi, ograniczony z brzegu', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22232, 'Starorzecze (Stocki Młyn)', 'starorzecze-stocki-mlyn-stocki-mlyn-22232', 'OXBOW', 53.8810201, 18.7125571, 'Pomorskie', 'Stocki Młyn', 'Niewielkie, urokliwe starorzecze w Stockim Młynie, idealne dla wędkarzy preferujących kameralne łowiska i spokojne warunki. Dno jest mieszane, z przewagą mułu w głębszych partiach i piasku na płyciznach, co sprzyja różnym gatunkom ryb. Brzegi są łatwo dostępne w większości miejsc, co sprzyja wędkowaniu spławikowemu i gruntowemu z brzegu. Roślinność brzegowa jest umiarkowana, a podwodna tworzy liczne kryjówki dla drobnicy i mniejszych drapieżników. Jest to doskonałe miejsce na relaks i złowienie płoci, leszczy czy karasi, które występują tu w obfitości. Wiosną i wczesną jesienią można liczyć na dobre brania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22232, 2.5, 1.5, 3, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Karaś pospolity,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22233, 'Starorzecze (Stocki Młyn)', 'starorzecze-stocki-mlyn-stocki-mlyn-22233', 'OXBOW', 53.8780978, 18.7093161, 'Pomorskie', 'Stocki Młyn', 'To starorzecze w Stockim Młynie charakteryzuje się głębokimi dołami i twardym, gliniastym dnem, co jest nietypowe dla tego typu zbiorników i sprzyja większym rybom. Brzegi są strome, porośnięte starymi drzewami, które tworzą zacienione miejsca, idealne dla drapieżników i dużych karpi. Dostęp do wody jest utrudniony ze względu na nierówny teren i zwalone pnie, co wymaga ostrożności i sprawności. Wędkowanie z łodzi jest tutaj najbardziej efektywne, zwłaszcza przy poszukiwaniu większych okazów szczupaków i sumów. To łowisko jest znane z obecności dużych szczupaków i okoni, które polują w pobliżu zatopionych przeszkód. Ze względu na głębokość i twarde dno, ryzyko przyduchy jest minimalne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22233, 4, 2.2, 4.8, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Sum,Karp', 'Trudny, strome brzegi', FALSE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22234, 'Starorzecze (Gogolewo)', 'starorzecze-gogolewo-gogolewo-22234', 'OXBOW', 53.8491446, 18.7774554, 'Pomorskie', 'Gogolewo', 'To starorzecze w Gogolewie to rozległy, płytki zbiornik, silnie zarośnięty roślinnością wodną i brzegową, co stanowi jego główną cechę. Dno jest w przeważającej części muliste, z licznymi płyciznami i podwodnymi górami, które utrudniają prowadzenie zestawu. Brzegi są bagniste i trudno dostępne, co wymaga użycia brodzenia lub pontonu, aby skutecznie dotrzeć do ryb. Mimo trudnych warunków, starorzecze jest niezwykle rybne, oferując doskonałe warunki dla lina, karasia i wzdręgi, które osiągają tu spore rozmiary. Wędkowanie tutaj to prawdziwe wyzwanie, ale nagroda w postaci okazałych ryb jest często gwarantowana dla wytrwałych. W upalne dni należy liczyć się z ryzykiem deficytu tlenu w wodzie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22234, 8.2, 1.1, 2.6, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22235, 'Starorzecze (Gogolewo)', 'starorzecze-gogolewo-gogolewo-22235', 'OXBOW', 53.8475804, 18.7780045, 'Pomorskie', 'Gogolewo', 'To starorzecze, położone w malowniczej okolicy Gogolewa, stanowi typowy przykład dawnego koryta Wisły, charakteryzującego się spokojną wodą i bogatą przyrodą. Dno jest muliste z licznymi osadami, co sprzyja rozwojowi bujnej roślinności podwodnej, takiej jak rogatek i moczarka kanadyjska. Brzegi są gęsto porośnięte trzciną i pałką wodną, co utrudnia dostęp do wody, ale jednocześnie tworzy doskonałe kryjówki dla ryb. Wędkowanie tutaj wymaga cierpliwości i często użycia brodzącego sprzętu. Dominujące gatunki ryb to szczupak, lin, karaś pospolity, płoć i leszcz, które znajdują tu idealne warunki do bytowania. Należy być przygotowanym na trudności związane z zaczepami o podwodną roślinność.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22235, 5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć,Leszcz', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22236, 'Starorzecze Wierzyca (Gogolewo)', 'starorzecze-wierzyca-gogolewo-gogolewo-22236', 'OXBOW', 53.8398919, 18.779452, 'Pomorskie', 'Gogolewo', 'Starorzecze Wierzyca, położone w sąsiedztwie Gogolewa, jest kolejnym przykładem fragmentu dawnego biegu rzeki, oferującym unikalne warunki wędkarskie. Charakteryzuje się mulistym dnem z miejscowymi twardymi fragmentami, co sprzyja różnorodności gatunkowej. Brzegi są częściowo dostępne, jednak w wielu miejscach grząskie i bagniste, co wymaga ostrożności i odpowiedniego obuwia. Roślinność wodna jest umiarkowana, z przewagą grążeli i lilii wodnych, tworzących atrakcyjne stanowiska dla drapieżników. Występują tu głównie szczupaki, liny, karasie pospolite, leszcze i okonie, ceniące sobie te zaciszne wody. Wędkowanie może być utrudnione przez lokalne zaczepy w postaci pojedynczych korzeni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22236, 7, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Leszcz,Okoń', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22237, 'Starorzecze (Czerwieńsk)', 'starorzecze-czerwiensk-czerwiensk-22237', 'OXBOW', 52.0410979, 15.3939539, 'Lubuskie', 'Czerwieńsk', 'To starorzecze w okolicy Czerwieńska jest typowym zbiornikiem po dawnej Odrze, silnie zamulonym i z tendencją do szybkiego zarastania. Dno jest w większości miękkie, pokryte grubą warstwą mułu, co utrudnia tradycyjne metody wędkowania. Brzegi są niemal całkowicie zarośnięte gęstą trzciną i inną roślinnością przybrzeżną, co czyni dostęp do wody bardzo trudnym. Występuje tu obfita roślinność podwodna, stanowiąca naturalne schronienie dla ryb, ale i wyzwanie dla wędkarzy. Głównymi gatunkami są karaś pospolity, lin, wzdręga i płoć, które dobrze adaptują się do tych warunków. Wysokie ryzyko niedoboru tlenu latem sprawia, że najlepsze są chłodniejsze miesiące.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22237, 4.5, 1.2, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22238, 'Starorzecze (Dąbie k. Krosna Odrzańskiego)', 'starorzecze-dabie-k-krosna-odrzanskiego-dabie-22238', 'OXBOW', 52.0396399, 15.1559953, 'Lubuskie', 'Dąbie', 'Starorzecze w Dąbiu, nieopodal Krosna Odrzańskiego, to dynamiczny akwen z umiarkowanym zamuleniem, odzwierciedlający dawny bieg rzeki Odry. Dno charakteryzuje się zmienną strukturą, od mulistych zagłębień po twardsze, piaszczyste odcinki, co sprzyja różnorodności biologicznej. Brzegi są stosunkowo dobrze dostępne, co ułatwia wędkowanie z brzegu, choć lokalnie mogą występować zarośla. Roślinność wodna jest umiarkowana, z przewagą grążeli i trzcin w płytszych partiach, oferując schronienie dla ryb. W łowisku dominują szczupak, lin, leszcz, płoć i okoń, często żerujące w pobliżu podwodnych przeszkód. Jest to łowisko o zróżnicowanych możliwościach, dostępne przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22238, 6, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22239, 'Starorzecze (Połupin)', 'starorzecze-polupin-polupin-22239', 'OXBOW', 52.0323353, 15.1206529, 'Lubuskie', 'Połupin', 'To starorzecze w Połupinie to płytki i silnie zamulony zbiornik, będący reliktem dawnego koryta Odry, charakteryzujący się brakiem stałego połączenia z rzeką. Dno jest w całości pokryte grubą warstwą miękkiego mułu, co czyni je trudnym do brodzenia. Brzegi są grząskie i bagniste, co znacznie utrudnia dostęp do wody i wymaga specjalistycznego sprzętu. Roślinność wodna jest bardzo obfita, tworząc gęste zarośla podwodne, które są idealnym środowiskiem dla ryb, ale jednocześnie stanowią wyzwanie dla wędkarzy. Występują tu głównie gatunki odporne na trudne warunki, takie jak karaś pospolity, wzdręga i płoć. Ze względu na ryzyko wysychania i niedoboru tlenu, najlepszym okresem na wędkowanie jest wiosna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22239, 3, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22240, 'Starorzecze (Dąbie k. Krosna Odrzańskiego, północne)', 'starorzecze-dabie-k-krosna-odrzanskiego-polnocne-dabie-22240', 'OXBOW', 52.0486505, 15.1672053, 'Lubuskie', 'Dąbie', 'To północne starorzecze w Dąbiu, choć niewielkie, oferuje ciekawe warunki dla wędkarzy preferujących kameralne łowiska. Dno jest muliste z licznymi fragmentami zatopionej roślinności, co sprzyja rozwojowi bujnej flory podwodnej. Brzegi są mocno zarośnięte trzciną i inną roślinnością szuwarową, co wymaga użycia brodzących spodni dla komfortowego dostępu. Pomimo umiarkowanego zamulenia, starorzecze utrzymuje stabilny poziom wody, zasilane podczas większych wezbrań Odry. Wśród dominujących gatunków ryb znajdują się lin, karaś pospolity, płoć i wzdręga, doskonale przystosowane do środowiska. Wędkowanie tutaj najlepiej sprawdza się późną wiosną i latem, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22240, 2.5, 1.1, 2.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22241, 'Starorzecze (Dąbie k. Krosna Odrzańskiego, południowe)', 'starorzecze-dabie-k-krosna-odrzanskiego-poludniowe-dabie-22241', 'OXBOW', 52.0447475, 15.1589066, 'Lubuskie', 'Dąbie', 'Południowe starorzecze w Dąbiu to większy akwen, który zachował wiele cech dawnego koryta Odry, z regularnym połączeniem podczas wysokich stanów wody. Dno jest zróżnicowane, od mulistych zatok po twardsze, piaszczyste wyniesienia, co sprzyja różnorodności rybostanu. Brzegi są w większości łatwo dostępne, co umożliwia swobodne wędkowanie z wielu miejsc. Roślinność wodna występuje w umiarkowanym stopniu, tworząc naturalne kryjówki, ale nie utrudniając nadmiernie łowienia. Wśród dominujących gatunków znajdziemy szczupaka, lina, leszcza, okonia i płoć, które obficie występują w tym starorzeczu. Akwen ten jest atrakcyjny dla wędkarzy przez cały rok, oferując dobre warunki do połowów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22241, 5.5, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Okoń,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22242, 'Starorzecze (Słubice)', 'starorzecze-slubice-slubice-22242', 'OXBOW', 52.0744141, 14.8417419, 'Lubuskie', 'Słubice', 'To starorzecze w okolicach Słubic jest jednym z większych i głębszych akwenów po Odrze, charakteryzującym się relatywnie niskim poziomem zamulenia. Dno jest zróżnicowane, z twardszymi partiami piaszczysto-żwirowymi i mulistymi zagłębieniami, co sprzyja występowaniu wielu gatunków ryb. Brzegi są dobrze dostępne, co ułatwia wędkowanie z różnych stanowisk, zarówno dla spinningistów, jak i wędkarzy gruntowych. Roślinność wodna jest umiarkowana, z pasami trzcin i grążeli, które stanowią doskonałe miejsca na zasadzki dla drapieżników. Wśród dominujących ryb są szczupak, leszcz, płoć, okoń i sum, ceniące sobie stabilne warunki. Brak wysokiego ryzyka niedoboru tlenu sprawia, że jest to łowisko całoroczne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22242, 9, 2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Sum', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22243, 'Starorzecze (Rybojedzko)', 'starorzecze-rybojedzko-rybojedzko-22243', 'OXBOW', 52.1633599, 14.706035, 'Lubuskie', 'Rybojedzko', 'Starorzecze w Rybojedzku, blisko Kostrzyna nad Odrą, to akwen o umiarkowanym zamuleniu, który zachował wiele naturalnych cech dawnego koryta rzeki. Dno jest w dużej mierze muliste, ale występują też twardsze fragmenty, co sprzyja różnorodności gatunkowej ryb. Brzegi są trudne do pokonania, często grząskie i bagniste, co wymaga użycia wodoodpornego obuwia lub brodzących spodni. Roślinność podwodna jest gęsta, tworząc idealne kryjówki dla ryb, ale również liczne zaczepy dla wędkarzy. Wśród dominujących gatunków znajdują się szczupak, leszcz, płoć, okoń i lin, które obficie występują w tych wodach. Najlepsze wyniki wędkarskie osiąga się wiosną i wczesną jesienią, unikając letnich upałów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22243, 7.5, 1.9, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22244, 'Starorzecze (Kłopot, północne)', 'starorzecze-klopot-polnocne-klopot-22244', 'OXBOW', 52.1486031, 14.6886606, 'Lubuskie', 'Kłopot', 'Północne starorzecze w Kłopocie to płytki i silnie zamulony zbiornik, będący częścią kompleksu dawnych koryt Odry, bez stałego połączenia z rzeką. Dno jest w całości pokryte grubą warstwą miękkiego mułu, co sprawia, że jest to trudne łowisko dla wędkarzy gruntowych. Brzegi są mocno zarośnięte trzciną i inną roślinnością szuwarową, co znacznie utrudnia dostęp do wody. Roślinność podwodna jest bardzo gęsta, tworząc liczne zaczepy, ale jednocześnie zapewniając schronienie dla ryb. Dominujące gatunki to karaś pospolity, lin, wzdręga i płoć, które dobrze znoszą te warunki. Ze względu na wysokie zamulenie i ryzyko niedoboru tlenu, najlepszy czas na wędkowanie to późna wiosna i lato.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22244, 4, 1.4, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22245, 'Starorzecze (Kłopot, środkowe)', 'starorzecze-klopot-srodkowe-klopot-22245', 'OXBOW', 52.1394797, 14.682683, 'Lubuskie', 'Kłopot', 'Środkowe starorzecze w Kłopocie to kolejny płytki akwen, charakteryzujący się bardzo wysokim poziomem zamulenia i brakiem bezpośredniego połączenia z Odrą. Dno jest jednolicie muliste, co wymaga specjalnych technik wędkarskich i lekkich zestawów. Brzegi są grząskie i bagniste, a dostęp do wody jest bardzo utrudniony przez gęste zarośla trzcin i krzewów. Obfita roślinność podwodna, w tym moczarka i rogatek, stanowi doskonałe kryjówki dla ryb, ale również liczne zaczepy. Występują tu głównie gatunki takie jak karaś pospolity, lin, płoć i wzdręga, które są odporne na trudne warunki środowiskowe. Ze względu na ryzyko niedoboru tlenu, najlepiej wędkować w cieplejszych miesiącach, ale unikać upałów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22245, 3.5, 1.3, 2.6, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22246, 'Starorzecze (Kłopot, południowe)', 'starorzecze-klopot-poludniowe-klopot-22246', 'OXBOW', 52.1426377, 14.6850242, 'Lubuskie', 'Kłopot', 'Południowe starorzecze w Kłopocie jest nieco większe i głębsze od swoich sąsiadów, z umiarkowanym zamuleniem i okresowym połączeniem z Odrą. Dno jest zróżnicowane, z mulistymi partiami i twardszymi fragmentami, co sprzyja różnorodności rybostanu. Brzegi są mocno zarośnięte trzciną, co utrudnia dostęp, ale tworzy też naturalne stanowiska dla drapieżników. Roślinność wodna jest umiarkowana, z pasami grążeli i trzcin, które są idealnymi kryjówkami dla ryb. Wśród dominujących gatunków znajdują się szczupak, lin, leszcz, płoć i okoń, które obficie żerują w tych wodach. Wędkowanie tutaj jest najbardziej efektywne wiosną i wczesną jesienią, gdy ryby są aktywne, a warunki pogodowe sprzyjające.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22246, 5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22247, 'Starorzecze (Miedniewice)', 'starorzecze-miedniewice-miedniewice-22247', 'OXBOW', 51.9683582, 20.2458239, 'Mazowieckie', 'Miedniewice', 'Starorzecze w Miedniewicach to niewielki i bardzo płytki zbiornik, będący reliktem dawnego koryta lokalnej rzeki, charakteryzujący się brakiem połączenia z głównym nurtem. Dno jest w całości pokryte grubą warstwą miękkiego mułu, co sprawia, że jest to łowisko o bardzo trudnych warunkach. Brzegi są grząskie i bagniste, a gęsta roślinność szuwarowa niemal całkowicie uniemożliwia dostęp do wody z brzegu. Obfita roślinność podwodna, w połączeniu z płytkością, stwarza wysokie ryzyko niedoboru tlenu w okresach letnich. Występują tu głównie odporne gatunki, takie jak karaś pospolity, wzdręga i płoć. Ze względu na tendencję do wysychania, najlepszym okresem na wędkowanie jest wczesna wiosna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22247, 2, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22248, 'Starorzecze (Maciejowice)', 'starorzecze-maciejowice-maciejowice-22248', 'OXBOW', 51.7095087, 21.5622295, 'Mazowieckie', 'Maciejowice', 'To rozległe starorzecze w Maciejowicach to jeden z piękniejszych akwenów po Wiśle, charakteryzujący się umiarkowanym zamuleniem i stabilnym połączeniem z rzeką podczas wysokich wód. Dno jest zróżnicowane, z głębszymi mulistymi rynnami i twardszymi, piaszczystymi płyciznami, co sprzyja bogactwu gatunkowemu. Brzegi są w większości dobrze dostępne, oferując wiele dogodnych miejsc do wędkowania. Roślinność wodna jest umiarkowana, z pasami trzcin i zatopionymi drzewami, które stanowią doskonałe kryjówki dla ryb. Wśród dominujących gatunków znajdują się szczupak, leszcz, płoć, okoń, sum i sandacz, co czyni to łowisko bardzo atrakcyjnym. Jest to łowisko całoroczne, oferujące dobre warunki do połowów przez większość sezonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22248, 12, 2.5, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Sum,Sandacz', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22249, 'Starorzecze (Krężce)', 'starorzecze-krezce-krezce-22249', 'OXBOW', 51.9413791, 20.0970239, 'Łódzkie', 'Krężce', 'Starorzecze w Krężcach to stosunkowo niewielki, ale głębszy akwen po dawnej rzece, charakteryzujący się wysokim poziomem zamulenia i brakiem stałego połączenia z głównym nurtem. Dno jest w większości muliste, z lokalnymi twardszymi fragmentami, co sprzyja występowaniu ryb spokojnego żeru. Brzegi są mocno zarośnięte trzciną i inną roślinnością szuwarową, co utrudnia dostęp do wody i wymaga użycia brodzących spodni. Obfita roślinność podwodna, w tym grążele i lilie wodne, tworzy liczne zaczepy, ale jednocześnie stanowi idealne schronienie dla ryb. Wśród dominujących gatunków znajdują się lin, karaś pospolity, wzdręga i płoć. Najlepszy okres na wędkowanie to późna wiosna i lato, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22249, 3, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22250, 'Starorzecze Mnichów', 'starorzecze-mnichow-turek-22250', 'OXBOW', 51.6289971, 18.7278566, 'Wielkopolskie', 'Turek', 'To malownicze starorzecze, położone w cichej okolicy, charakteryzuje się umiarkowanym stopniem zamulenia dna. Brzegi są stosunkowo łatwo dostępne, choć w niektórych miejscach porasta je gęsta roślinność szuwarowa. Dno jest mulisto-piaszczyste, z licznymi zatopionymi korzeniami, co sprzyja bytności drapieżników. W starorzeczu dominują takie gatunki jak Lin, Szczupak, Okoń oraz Płoć, które znajdują tu idealne warunki do żerowania i rozrodu. Wędkowanie wymaga precyzji ze względu na zaczepy, ale potrafi wynagrodzić cierpliwość pięknymi okazami. Najlepsze efekty osiąga się wczesną wiosną i jesienią, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22250, 3.5, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Szczupak,Okoń,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22251, 'Starorzecze Grądy (północne)', 'starorzecze-grady-polnocne-turek-22251', 'OXBOW', 51.6377565, 18.7135326, 'Wielkopolskie', 'Turek', 'To starorzecze jest silnie zarośnięte i charakteryzuje się wysokim stopniem zamulenia dna. Brzegi są trudne do pokonania, często bagniste i porośnięte gęstymi trzcinami, co utrudnia dostęp do wody. Dno jest miękkie, muliste, z dużą ilością roślinności podwodnej, tworzącej idealne kryjówki dla ryb. Wśród dominujących gatunków można wymienić Karasia pospolitego, Lina, Wzdręgę oraz Płoć, które doskonale radzą sobie w takich warunkach. Ze względu na silne zarośnięcie i bagniste brzegi, wędkowanie z brodzeniem jest często konieczne. Ryzyko niedoboru tlenu w upalne lata jest podwyższone, co może wpływać na aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22251, 2.1, 1.5, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22252, 'Starorzecze Grądy (środkowe)', 'starorzecze-grady-srodkowe-turek-22252', 'OXBOW', 51.6376818, 18.7141678, 'Wielkopolskie', 'Turek', 'Środkowa część kompleksu starorzeczy Grądy to zbiornik o umiarkowanym zamuleniu i dobrym dostępie do brzegów. Dno jest zróżnicowane, od piaszczysto-mulistego po twardsze fragmenty, co sprzyja różnorodności fauny dennej. Roślinność brzegowa składa się głównie z trzcin i pojedynczych drzew, oferując miejsca do ukrycia i cień. W wodach tego starorzecza można spotkać Leszcza, Płoć, Okonia oraz sporadycznie Suma, szczególnie w głębszych partiach. Łowisko jest popularne wśród wędkarzy ze względu na stosunkowo łatwy dostęp i szansę na złowienie większych ryb. Najlepsze wyniki osiąga się w cieplejszych miesiącach, stosując metody spławikowe i gruntowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22252, 2.8, 1.7, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Sum', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22253, 'Starorzecze Grądy (wschodnie)', 'starorzecze-grady-wschodnie-turek-22253', 'OXBOW', 51.6375118, 18.7151995, 'Wielkopolskie', 'Turek', 'Wschodnie starorzecze Grądy to płytki zbiornik z silnym zamuleniem i bujną roślinnością podwodną. Brzegi są częściowo zarośnięte trzciną, ale miejscami można znaleźć dogodne stanowiska do wędkowania z brzegu. Dno jest bardzo miękkie, co utrudnia brodzenie, ale stanowi idealne środowisko dla wielu gatunków ryb. Dominują tu Karaś pospolity, Wzdręga, Płoć i Lin, które dobrze adaptują się do płytkich i bogatych w roślinność wód. Jest to idealne miejsce dla wędkarzy poszukujących spokojnego łowiska z dużą ilością drobnicy oraz szansą na dorodnego karasia. Wymaga delikatnego podejścia i lekkiego sprzętu, aby uniknąć zaczepów w roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22253, 1.9, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22254, 'Starorzecze Grądy (południowe)', 'starorzecze-grady-poludniowe-turek-22254', 'OXBOW', 51.6370696, 18.7162678, 'Wielkopolskie', 'Turek', 'Południowe starorzecze Grądy to wydłużony zbiornik o umiarkowanej głębokości i średnim poziomie zamulenia. Brzegi są dość dostępne, z mozaiką trzcinowisk i otwartych przestrzeni, co ułatwia wędkowanie. Dno jest głównie mulisto-piaszczyste, z lokalnymi skupiskami podwodnej roślinności. W tym starorzeczu można liczyć na spotkanie z Leszczem, Płocią, Okoniem oraz Szczupakiem, szczególnie w pobliżu zarośli. Jest to łowisko o dobrym potencjale na ryby średniej wielkości, wymagające od wędkarza umiejętności dostosowania techniki do zmieniających się warunków. Wiosna i jesień to najlepsze pory na drapieżniki, lato sprzyja białorybowi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22254, 2.3, 1.6, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22255, 'Starorzecze Biskupice (górne)', 'starorzecze-biskupice-gorne-turek-22255', 'OXBOW', 51.6534965, 18.6784824, 'Wielkopolskie', 'Turek', 'Górne starorzecze w Biskupicach to rozległy, stosunkowo głęboki zbiornik z czystym dnem i ograniczonym zamuleniem. Brzegi są częściowo zalesione, co zapewnia cień i schronienie, a miejscami są łatwo dostępne. Dno jest twardsze, piaszczysto-żwirowe, z niewielką ilością roślinności podwodnej, co sprzyja drapieżnikom. W wodach tych dominują Szczupak, Sandacz, Okoń oraz Leszcz, które znajdują tu doskonałe warunki do życia. Stałe połączenie z rzeką zapewnia regularne zarybienia i migrację ryb, co czyni to łowisko atrakcyjnym dla wędkarzy. Jest to miejsce, gdzie można liczyć na naprawdę duże okazy, szczególnie wczesną wiosną i późną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22255, 5, 2.5, 6, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Okoń,Leszcz,Węgorz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22256, 'Starorzecze Biskupice (środkowe)', 'starorzecze-biskupice-srodkowe-turek-22256', 'OXBOW', 51.6583548, 18.6755072, 'Wielkopolskie', 'Turek', 'Środkowe starorzecze Biskupice to zbiornik o umiarkowanej głębokości i średnim zamuleniu, z brzegami porośniętymi trzciną i krzewami. Dostęp do wody jest utrudniony w wielu miejscach, co wymaga brodzenia lub poszukiwania otwartych stanowisk. Dno jest muliste, z licznymi zatopionymi gałęziami i korzeniami, stanowiącymi idealne kryjówki dla ryb. Wśród dominujących gatunków można wymienić Lina, Karasia pospolitego, Płoć i Okonia, które doskonale czują się w zarośniętych wodach. Łowisko to jest wyzwaniem dla wędkarzy, ale oferuje szansę na złowienie dorodnych ryb w dzikim, naturalnym środowisku. Najlepsze efekty daje wędkowanie w okresie letnim, szczególnie wczesnym rankiem lub późnym wieczorem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22256, 4.2, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Płoć,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22257, 'Starorzecze Biskupice (dolne)', 'starorzecze-biskupice-dolne-turek-22257', 'OXBOW', 51.6581754, 18.677707, 'Wielkopolskie', 'Turek', 'Dolne starorzecze w Biskupicach to płytki, silnie zarośnięty zbiornik, charakteryzujący się wysokim stopniem zamulenia. Brzegi są bagniste i trudno dostępne, porośnięte gęstą roślinnością szuwarową, co wymaga użycia wodoodpornego obuwia. Dno jest bardzo miękkie, z dużą ilością mułu i rozkładającej się materii organicznej, tworzącej bogate środowisko dla bezkręgowców. W tym starorzeczu dominują Karaś pospolity, Wzdręga, Płoć oraz Lin, które doskonale radzą sobie w płytkich i ciepłych wodach. Jest to idealne miejsce dla wędkarzy poszukujących spokoju i łowiących na spławik lub lekką gruntówkę. W upalne lata istnieje ryzyko przyduchy, co może wpływać na kondycję ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22257, 3, 1.2, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22258, 'Starorzecze Bużka', 'starorzecze-buzka-drohiczyn-22258', 'OXBOW', 52.3603545, 22.8792563, 'Podlaskie', 'Drohiczyn', 'Starorzecze Bużka to urokliwy zbiornik, charakteryzujący się umiarkowanym zamuleniem i pięknymi, zielonymi brzegami. Dno jest zróżnicowane, od mulistych zagłębień po twardsze, piaszczyste miejsca, co sprzyja różnorodności gatunkowej. Roślinność brzegowa jest bujna, ale nie utrudnia dostępu do wody, oferując wiele urokliwych stanowisk. W wodach Bużki królują Leszcz, Płoć, Karp oraz Szczupak, które znajdują tu obfitość pokarmu i schronienia. Stałe połączenie z rzeką Bug zapewnia świeżą wodę i migrację ryb, co czyni to łowisko bardzo dynamicznym. Jest to doskonałe miejsce zarówno dla wędkarzy gruntowych, jak i spinningistów, ceniących sobie dziką przyrodę i potencjał na dużą rybę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22258, 6, 2.2, 5.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22259, 'Starorzecze Kózki (północne)', 'starorzecze-kozki-polnocne-drohiczyn-22259', 'OXBOW', 52.36052, 22.8719368, 'Podlaskie', 'Drohiczyn', 'Północne starorzecze Kózki to płytki zbiornik o silnie zamulonym dnie i bujnej roślinności podwodnej. Brzegi są mocno zarośnięte trzciną i krzewami, co sprawia, że dostęp do wody jest trudny i wymaga brodzenia. Dno jest bardzo miękkie, z grubą warstwą mułu, co sprzyja rozwojowi bogatej fauny bezkręgowców. Wśród dominujących gatunków ryb znajdziemy Karasia pospolitego, Lina, Wzdręgę oraz Płoć, które doskonale adaptują się do płytkich i ciepłych wód. Jest to idealne miejsce dla wędkarzy poszukujących spokoju i łowiących na metody spławikowe w zarośniętych partiach. W upalne lata należy liczyć się z ryzykiem niedoboru tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22259, 1.5, 0.8, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22260, 'Starorzecze Kózki (środkowe-zachodnie)', 'starorzecze-kozki-srodkowe-zachodnie-drohiczyn-22260', 'OXBOW', 52.3598875, 22.8709023, 'Podlaskie', 'Drohiczyn', 'Ta część starorzecza Kózki charakteryzuje się umiarkowanym zamuleniem i zróżnicowanymi brzegami, od dostępnych po częściowo zarośnięte. Dno jest mulisto-piaszczyste, z pojedynczymi zaczepami w postaci korzeni i gałęzi, co tworzy dobre kryjówki dla ryb. Roślinność podwodna jest umiarkowana, ale wystarczająca do zapewnienia schronienia. W wodach tych dominują Szczupak, Okoń, Płoć i Leszcz, które chętnie żerują w pobliżu podwodnych struktur. Łowisko oferuje dobre warunki dla spinningistów i wędkarzy gruntowych, szukających różnorodności. Wiosna i jesień to najlepsze pory na drapieżniki, natomiast lato sprzyja łowieniu białorybu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22260, 2, 1.7, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22261, 'Starorzecze Kózki (środkowe-centralne)', 'starorzecze-kozki-srodkowe-centralne-drohiczyn-22261', 'OXBOW', 52.3595376, 22.8703493, 'Podlaskie', 'Drohiczyn', 'Centralna część starorzecza Kózki to zbiornik o umiarkowanej głębokości i średnim zamuleniu, z brzegami częściowo bagnistymi i porośniętymi trzciną. Dostęp do wody jest miejscami utrudniony, ale są też otwarte przestrzenie. Dno jest muliste, z lokalnymi skupiskami roślinności podwodnej i zatopionymi gałęziami. Wśród dominujących gatunków można wymienić Lina, Karasia pospolitego, Płoć i Wzdręgę, które dobrze czują się w takim środowisku. Jest to łowisko dla cierpliwych wędkarzy, którzy potrafią wykorzystać naturalne kryjówki ryb. Wędkowanie z brodzeniem może być pomocne w dotarciu do najlepszych miejscówek.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22261, 1.8, 1.5, 3, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22262, 'Starorzecze Kózki (środkowe-wschodnie)', 'starorzecze-kozki-srodkowe-wschodnie-drohiczyn-22262', 'OXBOW', 52.3599721, 22.8700819, 'Podlaskie', 'Drohiczyn', 'Wschodnia część starorzecza Kózki to płytki zbiornik o wysokim stopniu zamulenia i silnym zarośnięciu. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co znacznie utrudnia dostęp do wody. Dno jest bardzo miękkie, z grubą warstwą mułu i obfitością roślinności podwodnej, tworzącej labirynt kryjówek. W tym starorzeczu dominują Karaś pospolity, Lin, Wzdręga i Płoć, które doskonale radzą sobie w płytkich, ciepłych i bogatych w roślinność wodach. Wędkowanie tutaj to wyzwanie, ale może przynieść satysfakcję w postaci pięknych karasi i linów. Z uwagi na płytkość i zarośnięcie, ryzyko niedoboru tlenu w lecie jest wysokie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22262, 1.6, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22263, 'Starorzecze Kózki (południowe)', 'starorzecze-kozki-poludniowe-drohiczyn-22263', 'OXBOW', 52.3592965, 22.8683578, 'Podlaskie', 'Drohiczyn', 'Południowe starorzecze Kózki to wydłużony zbiornik o umiarkowanej głębokości, charakteryzujący się średnim zamuleniem. Brzegi są zróżnicowane, z fragmentami łatwo dostępnymi i miejscami porośniętymi trzciną, co zapewnia wiele stanowisk. Dno jest mulisto-piaszczyste, z pojedynczymi zaczepami w postaci zatopionych gałęzi i korzeni. W wodach tego starorzecza można spotkać Szczupaka, Okonia, Leszcza oraz Płoć, które aktywnie żerują w pobliżu zarośli i podwodnych przeszkód. Jest to dobre łowisko dla wędkarzy preferujących różne metody, od spławikowej po spinning. Najlepsze efekty osiąga się wczesną wiosną i jesienią, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22263, 2.5, 1.9, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22264, 'Starorzecze Kózki (wschodnie)', 'starorzecze-kozki-wschodnie-drohiczyn-22264', 'OXBOW', 52.3604754, 22.8746588, 'Podlaskie', 'Drohiczyn', 'Wschodnie starorzecze Kózki to zbiornik o umiarkowanej głębokości i stosunkowo niskim zamuleniu, z łatwo dostępnymi brzegami. Dno jest twardsze, piaszczysto-muliste, z niewielką ilością roślinności podwodnej, co sprzyja drapieżnikom. Brzegi są częściowo zalesione, co zapewnia cień i schronienie dla wędkarzy. W wodach tych dominują Szczupak, Sandacz, Okoń oraz Leszcz, które znajdują tu doskonałe warunki do żerowania. Stałe połączenie z rzeką Bug, choć okresowe, wzbogaca populację ryb i zapewnia świeżą wodę. Jest to atrakcyjne łowisko dla spinningistów i wędkarzy gruntowych, szukających większych okazów. Najlepsze wyniki osiąga się wczesną wiosną i późną jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22264, 3, 2.1, 4.2, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Okoń,Leszcz,Węgorz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22265, 'Starorzecze Bużka I', 'starorzecze-buzka-i-mielnik-22265', 'OXBOW', 52.3607788, 22.8842146, 'Podlaskie', 'Mielnik', 'To starorzecze, położone w malowniczej dolinie Bugu niedaleko Mielnika, jest typowym łowiskiem o umiarkowanym charakterze. Dno jest muliste, z miejscowymi twardymi fragmentami, a brzegi są częściowo dostępne, choć jedna strona jest bardziej zarośnięta. Wokół zbiornika rośnie gęsta roślinność przybrzeżna, w tym trzciny i pałki wodne, stanowiące doskonałe kryjówki dla ryb. Można tu liczyć na udane połowy lina i szczupaka, a także płoci i karasia pospolitego. Wędkowanie wymaga cierpliwości, zwłaszcza w miejscach z pojedynczymi zaczepami w postaci korzeni. Najlepsze wyniki osiąga się wiosną i wczesną jesienią, kiedy aktywność ryb jest największa.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22265, 3.2, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Płoć,Karaś pospolity', 'Dobry z jednej strony, druga zarośnięta', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22266, 'Starorzecze Bużka II', 'starorzecze-buzka-ii-mielnik-22266', 'OXBOW', 52.3610854, 22.8850974, 'Podlaskie', 'Mielnik', 'Ten fragment starorzecza Bużka to płytkie i silnie zarośnięte łowisko, idealne dla miłośników spokojnego wędkowania. Dno jest w większości muliste i bardzo zamulone, co sprzyja rozwojowi bogatej roślinności podwodnej, takiej jak rdestnice i moczarka. Brzegi są trudne do pokonania, często bagniste i gęsto porośnięte trzciną, co wymaga użycia wodery. W zbiorniku dominują karasie pospolite, liny oraz wzdręgi i płocie, które doskonale czują się w tak zacisznych warunkach. Istnieje ryzyko przyduchy w upalne lata, dlatego ryby są najbardziej aktywne późną wiosną i latem. Liczne zaczepy w postaci gęstej roślinności podwodnej stanowią wyzwanie dla wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22266, 2.8, 1.5, 3.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22267, 'Starorzecze Bużka III', 'starorzecze-buzka-iii-mielnik-22267', 'OXBOW', 52.3606349, 22.8834949, 'Podlaskie', 'Mielnik', 'To rozległe starorzecze, choć oddalone od głównego nurtu Bugu, oferuje doskonałe warunki do wędkowania przez cały sezon. Dno jest zróżnicowane, od twardych, piaszczystych fragmentów po miejscowe osady muliste, co sprzyja różnorodności gatunków ryb. Brzegi są ogólnie dobrze dostępne, co ułatwia wędkowanie z brzegu, a roślinność przybrzeżna jest umiarkowana. W wodach starorzecza pływają liczne szczupaki i okonie, a także duże leszcze i płocie. Ze względu na stabilne warunki wodne, ryzyko przyduchy jest niskie, co zapewnia komfortowe warunki dla ryb. Niewielka ilość zaczepów pozwala na swobodne prowadzenie przynęt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22267, 4.1, 2, 4.5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22268, 'Starorzecze Malowa Góra I', 'starorzecze-malowa-gora-i-terespol-22268', 'OXBOW', 52.1043878, 23.4748006, 'Lubelskie', 'Terespol', 'Starorzecze Malowa Góra I, położone w bliskim sąsiedztwie Terespola, to zbiornik o umiarkowanej głębokości i zróżnicowanym dnie, gdzie muliste osady przeplatają się z twardszymi fragmentami. Brzegi są dostępne z kilku przygotowanych stanowisk, choć miejscami mogą być zarośnięte. Roślinność wodna i przybrzeżna jest umiarkowana, tworząc dobre kryjówki dla drapieżników i ryb spokojnego żeru. Dominującymi gatunkami są szczupak, leszcz, płoć oraz karp, co czyni to miejsce atrakcyjnym dla różnych technik wędkarskich. Łowisko to łączy się z rzeką podczas wysokiej wody, co zapewnia regularne zarybienia naturalne. Najlepsze efekty osiąga się wiosną i jesienią, kiedy ryby intensywnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22268, 5.5, 2.2, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Karp', 'Dobry z kilku stanowisk', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22269, 'Starorzecze Malowa Góra II', 'starorzecze-malowa-gora-ii-terespol-22269', 'OXBOW', 52.1044876, 23.4613069, 'Lubelskie', 'Terespol', 'To starorzecze charakteryzuje się wysokim poziomem zamulenia i silnym zarośnięciem, co czyni je wymagającym, ale obfitującym w ryby łowiskiem. Dno jest bardzo miękkie i grubo pokryte mułem, a obfita roślinność podwodna, taka jak grążele i lilie wodne, pokrywa znaczną część powierzchni. Brzegi są mocno zarośnięte trzciną i trudno dostępne, co wymusza użycie wodery dla efektywnego wędkowania. Królują tu lin i karaś pospolity, a także liczne wzdręgi, doskonale przystosowane do trudnych warunków. Ze względu na brak stałego połączenia z rzeką i silne zarośnięcie, istnieje wysokie ryzyko przyduchy w upalne lato. Wędkowanie jest najbardziej efektywne późną wiosną i latem, gdy ryby są aktywne mimo trudności terenowych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22269, 3.8, 1.7, 3.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna i zatopione gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22270, 'Starorzecze Malowa Góra III', 'starorzecze-malowa-gora-iii-terespol-22270', 'OXBOW', 52.1043479, 23.4625718, 'Lubelskie', 'Terespol', 'To jedno z większych i głębszych starorzeczy w okolicy Terespola, charakteryzujące się stałym połączeniem z rzeką, co zapewnia doskonałą wymianę wody i bogactwo gatunkowe. Dno jest stosunkowo czyste, z niewielkim zamuleniem, a brzegi są dobrze dostępne, co ułatwia wędkowanie z niemal każdego miejsca. Roślinność przybrzeżna jest słaba, co pozwala na swobodne rzuty i manewrowanie sprzętem. W starorzeczu tym można spotkać drapieżniki takie jak boleń, jaź i kleń, a także szczupaki i płocie, które korzystają z przepływowej wody. Niskie ryzyko przyduchy i czyste dno sprawiają, że jest to łowisko atrakcyjne przez cały sezon. Brak większych zaczepów to dodatkowy atut dla wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22270, 6.1, 2.5, 5.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Boleń,Jaź,Kleń,Szczupak,Płoć', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22271, 'Starorzecze Malowa Góra IV', 'starorzecze-malowa-gora-iv-terespol-22271', 'OXBOW', 52.1043353, 23.4640226, 'Lubelskie', 'Terespol', 'To starorzecze jest znane z dużej ilości zatopionych drzew i gałęzi, co tworzy doskonałe kryjówki dla ryb, ale jednocześnie stanowi wyzwanie dla wędkarzy. Dno jest muliste, z licznymi zaczepami, a brzegi są miejscami bagniste i trudne do przejścia, wymagając użycia wodery. Roślinność wodna jest umiarkowana, ale jej skupiska są często połączone z zatopionymi przeszkodami. W wodach tych dominują leszcze, płocie, karpie oraz karasie srebrzyste, które chętnie żerują w pobliżu zatopionych pni. Aktywne połączenie z rzeką podczas wysokiej wody sprzyja odnawianiu populacji ryb. Najlepsze pory na wędkowanie to wiosna i lato, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22271, 4.2, 1.9, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Leszcz,Płoć,Karp,Karaś srebrzysty', 'Trudny, miejscami bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22272, 'Starorzecze Malowa Góra V', 'starorzecze-malowa-gora-v-terespol-22272', 'OXBOW', 52.1043414, 23.463569, 'Lubelskie', 'Terespol', 'To płytkie i silnie zamulone starorzecze, które w okresach suszy może wysychać, co czyni je łowiskiem o zmiennym charakterze. Dno jest bardzo miękkie, pokryte grubą warstwą mułu, a roślinność podwodna jest gęsta, tworząc prawdziwy podwodny labirynt. Brzegi są mocno zarośnięte trzciną i krzewami, co sprawia, że dostęp jest bardzo utrudniony i wymaga użycia wodery. W zbiorniku dominują odporne gatunki takie jak karaś pospolity, wzdręga i płoć, które dobrze radzą sobie w trudnych warunkach. Wysokie ryzyko przyduchy i możliwość wysychania sprawiają, że najlepszym okresem na wędkowanie jest późna wiosna. Liczne zaczepy w postaci gęstej roślinności podwodnej są codziennością.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22272, 2.9, 1.4, 3, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną i krzewami', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22273, 'Starorzecze Malowa Góra VI', 'starorzecze-malowa-gora-vi-terespol-22273', 'OXBOW', 52.1048137, 23.4678198, 'Lubelskie', 'Terespol', 'To największe ze starorzeczy w kompleksie Malowej Góry, charakteryzujące się znaczną głębokością i stałym połączeniem z rzeką, co zapewnia doskonałe warunki dla dużych drapieżników. Dno jest zróżnicowane, z twardszymi partiami i miejscowymi zagłębieniami, a brzegi są dobrze dostępne, z kilkoma pomostami ułatwiającymi wędkowanie. Roślinność wodna jest słaba, co sprzyja swobodnemu poruszaniu się ryb i wędkarzy. W wodach tych można spotkać suma, sandacza i szczupaka, a także duże leszcze, co czyni łowisko bardzo atrakcyjnym. Niskie zamulenie i brak ryzyka przyduchy sprawiają, że jest to doskonałe miejsce na wędkowanie przez cały rok. Pojedyncze zatopione pnie stanowią naturalne kryjówki dla drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22273, 7, 2.8, 6, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sum,Sandacz,Szczupak,Leszcz', 'Dobry, dostępne pomosty', FALSE, 'Pojedyncze zatopione pnie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22274, 'Starorzecze Malowa Góra VII', 'starorzecze-malowa-gora-vii-terespol-22274', 'OXBOW', 52.1048569, 23.4641301, 'Lubelskie', 'Terespol', 'To starorzecze charakteryzuje się umiarkowanym zamuleniem i gęstą roślinnością podwodną, co sprawia, że jest to idealne siedlisko dla okoni i szczupaków. Dno jest muliste, z licznymi skupiskami roślinności, a dostęp do brzegów jest ograniczony, choć istnieją wydeptane ścieżki wędkarskie. Roślinność przybrzeżna jest umiarkowana, ale tworzy skuteczne osłony dla wędkarzy. W wodach tych dominują okonie, szczupaki, płocie oraz wzdręgi, które doskonale prosperują w takich warunkach. Połączenie z rzeką podczas wysokiej wody zapewnia dopływ świeżej wody i ryb, jednak istnieje ryzyko przyduchy w upalne lato. Wędkowanie jest najbardziej owocne wiosną i wczesnym latem, zanim roślinność osiągnie pełnię rozkwitu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22274, 4.8, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Okoń,Szczupak,Płoć,Wzdręga', 'Dostęp ograniczony, ścieżki wędkarskie', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22275, 'Starorzecze Neple', 'starorzecze-neple-terespol-22275', 'OXBOW', 52.1321714, 23.521147, 'Lubelskie', 'Terespol', 'Starorzecze Neple to rozległy i głęboki zbiornik, cieszący się stałym połączeniem z rzeką, co gwarantuje stabilne warunki wodne i bogactwo ichtiofauny. Dno jest zróżnicowane, z twardymi fragmentami i głębokimi rynnami, a brzegi są ogólnie dobrze dostępne, z wieloma wygodnymi stanowiskami i pomostami. Roślinność wodna jest umiarkowana, co pozwala na swobodne wędkowanie, a jednocześnie zapewnia schronienie dla ryb. W starorzeczu można spotkać imponujące okazy suma, sandacza, szczupaka, leszcza, a nawet węgorza, co czyni je prawdziwym rajem dla wędkarzy. Niskie zamulenie i brak ryzyka przyduchy sprawiają, że jest to łowisko atrakcyjne przez cały rok. Pojedyncze zatopione drzewa stanowią naturalne punkty orientacyjne i kryjówki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22275, 9.5, 3, 7, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Sandacz,Szczupak,Leszcz,Węgorz', 'Dobry z wielu stron, miejscami pomosty', FALSE, 'Pojedyncze zatopione drzewa', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22276, 'Starorzecze Bystrzycy Dusznickiej', 'starorzecze-bystrzycy-dusznickiej-duszniki-zdroj-22276', 'OXBOW', 50.4235407, 16.5679516, 'Dolnośląskie', 'Duszniki-Zdrój', 'To niewielkie i płytkie starorzecze, położone w malowniczej okolicy Dusznik-Zdroju, charakteryzuje się silnym zarośnięciem i bagnistymi brzegami. Dno jest mocno zamulone i pokryte gęstą roślinnością podwodną, co utrudnia wędkowanie, ale zapewnia doskonałe warunki dla niektórych gatunków. Brzegi są bardzo trudne do pokonania, często bagniste i gęsto porośnięte, co wymaga użycia wodery i dużej ostrożności. W zbiorniku dominują karasie pospolite, liny, wzdręgi oraz płocie, które doskonale adaptują się do płytkich i zarośniętych wód. Ze względu na niewielką głębokość i silne zarośnięcie, istnieje wysokie ryzyko wysychania w okresach suszy i przyduchy latem. Wędkowanie jest najbardziej efektywne późną wiosną i latem, zanim zbiornik nadmiernie się nagrzeje.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22276, 1.8, 1, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty, zarośnięty', TRUE, 'Gęsta roślinność podwodna, liczne gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22277, 'Starorzecze Zbrudzewo', 'starorzecze-zbrudzewo-srem-22277', 'OXBOW', 52.1182186, 17.0066072, 'Wielkopolskie', 'Śrem', 'Starorzecze Zbrudzewo to jedno z większych i bardziej znanych łowisk w regionie Wielkopolski, charakteryzujące się stałym połączeniem z Wartą. Dno jest zróżnicowane, od piaszczystych płycizn po głębokie rynny z mulistym osadem, a brzegi są dobrze dostępne, z licznymi przygotowanymi stanowiskami. Roślinność wodna jest umiarkowana, co sprzyja różnorodności gatunków ryb i ułatwia wędkowanie. W zbiorniku występują liczne okazy karpia, leszcza, płoci, szczupaka i okonia, co czyni go atrakcyjnym dla wędkarzy preferujących różne metody. Niskie zamulenie i brak ryzyka przyduchy zapewniają stabilne warunki przez cały rok. Pojedyncze zatopione pnie stanowią naturalne kryjówki i punkty zaczepowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22277, 12, 2.5, 6, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Karp,Leszcz,Płoć,Szczupak,Okoń', 'Dobry, dostępne liczne stanowiska', FALSE, 'Pojedyncze zatopione pnie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22278, 'Starorzecze Psarskie I', 'starorzecze-psarskie-i-srem-22278', 'OXBOW', 52.1114923, 17.001831, 'Wielkopolskie', 'Śrem', 'To starorzecze, położone w pobliżu Psarskiego koło Śremu, jest łowiskiem o umiarkowanej głębokości i zróżnicowanym dnie, gdzie muliste fragmenty przeplatają się z twardszym podłożem. Dostęp do brzegów jest dobry z jednej strony, natomiast druga jest bardziej zarośnięta i trudniej dostępna. Roślinność wodna jest umiarkowana, tworząc idealne środowisko dla lina i szczupaka, a także karasia pospolitego i płoci. Połączenie z rzeką podczas wysokiej wody zapewnia regularne zarybienia naturalne i świeżą wodę. Istnieje umiarkowane ryzyko przyduchy w upalne lato, dlatego najlepsze efekty osiąga się wiosną i wczesną jesienią. Wędkowanie wymaga uwagi ze względu na pojedyncze korzenie i gałęzie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22278, 5, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Karaś pospolity,Płoć', 'Dobry z jednej strony, druga zarośnięta', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22279, 'Starorzecze Psarskie II', 'starorzecze-psarskie-ii-srem-22279', 'OXBOW', 52.1124768, 17.0002754, 'Wielkopolskie', 'Śrem', 'To mniejsze starorzecze, charakteryzujące się wysokim poziomem zamulenia i silnym zarośnięciem, jest typowym łowiskiem dla gatunków preferujących płytkie i ciepłe wody. Dno jest bardzo miękkie, pokryte grubą warstwą mułu, a gęsta roślinność podwodna, wraz z zatopionymi gałęziami, tworzy liczne zaczepy. Brzegi są trudne do pokonania, bagniste i mocno zarośnięte, co wymaga użycia wodery dla efektywnego dotarcia do wody. Dominującymi gatunkami są karaś pospolity, wzdręga i płoć, które doskonale radzą sobie w tych specyficznych warunkach. Ze względu na brak połączenia z rzeką i niewielką głębokość, starorzecze to może wysychać w okresach suszy i jest narażone na przyduchę. Najlepszy czas na wędkowanie to późna wiosna i lato, zanim warunki staną się zbyt trudne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22279, 3.5, 1.5, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna i zatopione gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22280, 'Starorzecze (Zbrudzewo)', 'starorzecze-zbrudzewo-srem-22280', 'OXBOW', 52.1103867, 17.0149331, 'Wielkopolskie', 'Śrem', 'To starorzecze charakteryzuje się dość płytkim dnem, które w większości pokrywa gruba warstwa mułu. Brzegi są miejscami podmokłe, porośnięte trzciną i pałką wodną, co utrudnia dostęp do wody. Roślinność podwodna jest umiarkowana, tworząc idealne kryjówki dla drapieżników. Akwen ten jest znany z populacji lina i karasia pospolitego, a także szczupaków. Wędkarze powinni przygotować się na trudności z dotarciem do najlepszych miejscówek, często wymagające brodzenia. Istnieje ryzyko przyduchy w okresie letnim, szczególnie w upalne dni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22280, 3.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, miejscami bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22281, 'Starorzecze (Zbrudzewo)', 'starorzecze-zbrudzewo-srem-22281', 'OXBOW', 52.1117747, 17.011684, 'Wielkopolskie', 'Śrem', 'To niewielkie starorzecze jest bardzo płytkie i silnie zamulone, co sprzyja rozwojowi bujnej roślinności wodnej. Brzegi są gęsto porośnięte trzciną, co sprawia, że dostęp do wody jest bardzo utrudniony i często wymaga użycia pontonu lub brodzenia. Dominują tu gatunki ryb ciepłolubnych i odpornych na niską zawartość tlenu, takie jak karaś pospolity i lin. Wędkowanie utrudniają liczne zaczepy w postaci podwodnej roślinności. Akwen ten jest szczególnie wrażliwy na przyduchy, zwłaszcza podczas upalnego lata i mroźnych zim.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22281, 2.8, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22282, 'Starorzecze (Zbrudzewo)', 'starorzecze-zbrudzewo-srem-22282', 'OXBOW', 52.1172152, 17.0175517, 'Wielkopolskie', 'Śrem', 'To starorzecze charakteryzuje się bardziej zróżnicowaną głębokością niż sąsiednie akweny, z dnem częściowo mulistym, a częściowo twardszym. Brzegi są w miarę dostępne, choć miejscami występują zarośla. Roślinność podwodna jest umiarkowana, co pozwala na różnorodne techniki wędkarskie. Występuje tu bogata populacja leszcza, płoci i okonia, a także okazowe karpie. Połączenie z rzeką podczas wysokich stanów wody zapewnia stałe odnawianie populacji ryb. Jest to atrakcyjne łowisko dla wędkarzy ceniących sobie komfort i różnorodność gatunkową.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22282, 4.1, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Karp', 'Dobry z niektórych stron, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22283, 'Starorzecze (Czmoniec)', 'starorzecze-czmoniec-kornik-22283', 'OXBOW', 52.1809899, 16.9925461, 'Wielkopolskie', 'Kórnik', 'To rozległe starorzecze wyróżnia się stosunkowo czystym dnem i dobrą dostępnością brzegów, z kilkoma dogodnymi miejscami do wędkowania. Głębokość jest zróżnicowana, co sprzyja bytności wielu gatunków ryb. Roślinność podwodna nie jest zbyt gęsta, co ułatwia prowadzenie przynęt. W akwenie tym można spotkać duże populacje leszczy, płoci i okoni, a także okazałe szczupaki i węgorze. Połączenie z Wartą podczas wezbrań pozytywnie wpływa na bioróżnorodność i kondycję ryb. Jest to popularne łowisko, cenione za stabilne warunki i obfitość ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22283, 6.2, 2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Węgorz', 'Dobry, miejscami pomosty', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22284, 'Starorzecze (Czmoniec)', 'starorzecze-czmoniec-kornik-22284', 'OXBOW', 52.1869561, 16.9952675, 'Wielkopolskie', 'Kórnik', 'To starorzecze jest typowym zbiornikiem starorzecznym z mulistym dnem i silnym zarastaniem roślinnością wodną. Brzegi są bardzo trudne do pokonania, często bagniste i gęsto porośnięte trzciną, co wymaga użycia wodoodpornego obuwia lub pontonu. Akwen ten jest domem dla licznych populacji lina, karasia pospolitego i wzdręgi, a także szczupaków, które czyhają w gęstwinie. Wędkowanie jest tu wyzwaniem ze względu na liczne zaczepy i ograniczony dostęp. Istnieje podwyższone ryzyko przyduchy w okresach długotrwałych upałów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22284, 5.5, 1.7, 3.2, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, bagnisty i zarośnięty', TRUE, 'Gęsta roślinność podwodna, pojedyncze zatopione drzewa', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22285, 'Starorzecze (Orkowo)', 'starorzecze-orkowo-kornik-22285', 'OXBOW', 52.1727214, 16.9943192, 'Wielkopolskie', 'Kórnik', 'To starorzecze w Orkowo jest płytkim i silnie zamulonym zbiornikiem, charakteryzującym się bardzo bujną roślinnością wodną. Brzegi są niemal całkowicie niedostępne z lądu, gęsto porośnięte trzcinami i krzewami, co czyni wędkowanie z brzegu niezwykle trudnym. Dominują tu gatunki takie jak lin, karaś pospolity i wzdręga, które doskonale radzą sobie w trudnych warunkach. Z powodu izolacji i płytkości, ryzyko przyduchy jest wysokie, szczególnie w letnie upały. Jest to łowisko dla cierpliwych wędkarzy, poszukujących dzikich i nieuczęszczanych miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22285, 3.1, 1.4, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Mocno zarośnięty trzciną i krzewami', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22286, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-mosina-22286', 'OXBOW', 52.2213981, 16.9301623, 'Wielkopolskie', 'Mosina', 'To jedno z większych starorzeczy w Rogalinie, posiadające stałe połączenie z rzeką Wartą, co zapewnia doskonałą wymianę wody i bogactwo gatunkowe. Dno jest zróżnicowane, od piaszczystego po muliste, z niewielką ilością roślinności podwodnej. Brzegi są łatwo dostępne, a w niektórych miejscach znajdują się nawet utwardzone stanowiska wędkarskie. Akwen jest znany z dużych populacji leszczy, płoci, karpi, a także okazowych sumów i sandaczy. Jest to idealne miejsce dla wędkarzy ceniących sobie komfort i różnorodność metod połowu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22286, 7.8, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sum,Sandacz', 'Dobry z wielu stron, częściowo utwardzony', FALSE, 'Czyste dno, pojedyncze zaczepy', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22287, 'Starorzecze (Rogalin)', 'starorzecze-rogalin-mosina-22287', 'OXBOW', 52.2191536, 16.9320412, 'Wielkopolskie', 'Mosina', 'To starorzecze charakteryzuje się dość dużą powierzchnią i zróżnicowaną głębokością, z dnem przeważnie twardym, miejscami pokrytym cienką warstwą mułu. Brzegi są umiarkowanie dostępne, choć w niektórych miejscach wymagają przedzierania się przez zarośla. Roślinność podwodna jest umiarkowana, tworząc dobre kryjówki dla ryb. Akwen jest ceniony przez wędkarzy spinningowych ze względu na liczne szczupaki i okonie, a także bolenie wpływające z Warty. Połączenie z rzeką podczas wezbrań wzbogaca populację ryb. Jest to łowisko oferujące dobre warunki do aktywnego wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22287, 6.5, 2.2, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Boleń', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i zatopione gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22288, 'Starorzecze (Świątniki)', 'starorzecze-swiatniki-mosina-22288', 'OXBOW', 52.2197106, 16.9431469, 'Wielkopolskie', 'Mosina', 'To niewielkie i bardzo płytkie starorzecze jest silnie zamulone i gęsto zarośnięte roślinnością wodną, co sprawia, że jest to środowisko ekstremalne dla ryb. Brzegi są praktycznie niedostępne, bagniste i porośnięte gęstą trzciną, co uniemożliwia wędkowanie z lądu. Dominują tu jedynie najbardziej odporne gatunki, takie jak karaś pospolity i wzdręga, które potrafią przetrwać w trudnych warunkach. Akwen ten ma tendencję do wysychania w okresach suszy i jest bardzo podatny na przyduchy. Jest to łowisko tylko dla najbardziej wytrwałych wędkarzy, poszukujących dzikich ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22288, 2, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Bardzo trudny, bagnisty i gęsto zarośnięty', TRUE, 'Gęsta roślinność podwodna, muł', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22289, 'Starorzecze (Świątniki)', 'starorzecze-swiatniki-mosina-22289', 'OXBOW', 52.2185817, 16.9370663, 'Wielkopolskie', 'Mosina', 'To starorzecze charakteryzuje się umiarkowaną głębokością i dnem częściowo mulistym, częściowo twardszym. Brzegi są dostępne w niektórych miejscach, jednak często wymagane jest brodzenie w wodzie. Roślinność podwodna jest umiarkowana, tworząc dobre schronienia dla ryb. W akwenie tym występują liczne populacje płoci, leszczy i okoni, a także szczupaki, które polują w zaroślach. Połączenie z rzeką podczas wysokich stanów wody zapewnia regularne zarybienia naturalne. Jest to łowisko o przyjemnym charakterze, oferujące różnorodne możliwości wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22289, 3.8, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Umiarkowany, miejscami wymaga brodzenia', TRUE, 'Pojedyncze zatopione gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22290, 'Starorzecze (Świątniki)', 'starorzecze-swiatniki-mosina-22290', 'OXBOW', 52.2165375, 16.934301, 'Wielkopolskie', 'Mosina', 'To starorzecze, dzięki stałemu połączeniu z Wartą, utrzymuje dobrą jakość wody i bogatą populację ryb. Dno jest przeważnie twarde, z niewielką ilością mułu, a roślinność podwodna jest słaba, co sprzyja różnym technikom wędkarskim. Brzegi są łatwo dostępne, z dobrze wydeptanymi ścieżkami i stanowiskami. W akwenie tym można liczyć na obfite połowy leszczy, płoci, karpi, a także sandaczy i sumów, które regularnie wpływają z rzeki. Jest to jedno z najbardziej atrakcyjnych łowisk w okolicy, cenione za komfort i obfitość ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22290, 4.5, 2, 4, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sandacz,Sum', 'Dobry, wydeptane ścieżki', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22291, 'Starorzecze (Świątniki)', 'starorzecze-swiatniki-mosina-22291', 'OXBOW', 52.2170469, 16.9297117, 'Wielkopolskie', 'Mosina', 'To starorzecze charakteryzuje się większą głębokością i zróżnicowanym dnem, z miejscami twardymi i żwirowymi, a także mulistymi. Brzegi są dostępne w wielu punktach, choć miejscami występują zarośla. Roślinność podwodna jest umiarkowana, tworząc dobre struktury dla drapieżników. Akwen jest szczególnie atrakcyjny dla wędkarzy spinningowych, ze względu na obecność szczupaków, okoni, boleni, jazi i kleni, które wpływają z Warty. Połączenie z rzeką podczas wezbrań zapewnia stałe wzbogacanie populacji ryb. Jest to łowisko dla aktywnych wędkarzy, poszukujących silnych wrażeń.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22291, 5, 2.3, 4.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Boleń,Jaź,Kleń', 'Dobry z niektórych stron, miejscami zarośnięty', FALSE, 'Pojedyncze zatopione drzewa i korzenie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22292, 'Starorzecze (Radzewice)', 'starorzecze-radzewice-kornik-22292', 'OXBOW', 52.218608, 16.9638616, 'Wielkopolskie', 'Kórnik', 'To starorzecze jest płytkim i silnie zamulonym zbiornikiem, charakteryzującym się bardzo bujną roślinnością wodną, która pokrywa dużą część powierzchni. Brzegi są niezwykle trudne do pokonania, gęsto porośnięte trzcinami i krzewami, co wymaga użycia pontonu lub brodzenia. Dominują tu gatunki takie jak lin, karaś pospolity i wzdręga, które doskonale radzą sobie w trudnych warunkach. Z powodu izolacji i płytkości, ryzyko przyduchy jest wysokie, szczególnie w letnie upały. Jest to łowisko dla wytrwałych wędkarzy, poszukujących dzikich i rzadko odwiedzanych miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22292, 3, 1.3, 2.7, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, bardzo zarośnięty', TRUE, 'Gęsta roślinność podwodna, muł', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22293, 'Starorzecze (Bychowo)', 'starorzecze-bychowo-scinawa-22293', 'OXBOW', 51.4929496, 16.8616537, 'Dolnośląskie', 'Ścinawa', 'To duże starorzecze, położone w malowniczej okolicy, posiada stałe połączenie z Odrą, co zapewnia doskonałą wymianę wody i bogactwo gatunkowe. Dno jest zróżnicowane, od piaszczystego po twarde, z umiarkowaną ilością roślinności podwodnej. Brzegi są łatwo dostępne, z licznymi pomostami i miejscami do wędkowania. Akwen jest znany z dużych populacji sumów i sandaczy, a także okazałych karpi i leszczy. Jest to idealne miejsce dla wędkarzy ceniących sobie komfort i możliwość połowu dużych drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22293, 8, 2.8, 5.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Sandacz,Karp,Leszcz,Płoć', 'Dobry, miejscami pomosty i plaże', FALSE, 'Czyste dno, pojedyncze zaczepy', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22294, 'Starorzecze (Domaszków)', 'starorzecze-domaszkow-glogow-22294', 'OXBOW', 51.3291546, 16.4714237, 'Dolnośląskie', 'Głogów', 'To rozległe starorzecze jest jednym z najgłębszych w regionie i ma stałe, szerokie połączenie z rzeką Odrą, co gwarantuje stabilne warunki wodne. Dno jest przeważnie twarde, piaszczysto-żwirowe, z minimalną ilością mułu i słabą roślinnością podwodną. Brzegi są bardzo dobrze dostępne, z licznymi, wygodnymi stanowiskami wędkarskimi. Akwen jest prawdziwym eldorado dla miłośników dużych drapieżników, takich jak sandacze, sumy i bolenie, a także karpi i leszczy. Jest to łowisko o wysokim potencjale wędkarskim, odpowiednie dla wszystkich metod połowu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22294, 10.5, 3, 6, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sandacz,Sum,Boleń,Karp,Leszcz', 'Bardzo dobry, liczne miejsca do wędkowania', FALSE, 'Czyste dno, miejscami kamienie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22295, 'Starorzecze Wola Życińska 1', 'starorzecze-wola-zycinska-1-czestochowa-22295', 'OXBOW', 50.9508148, 19.8311865, 'Śląskie', 'Częstochowa', 'To starorzecze, położone w malowniczej dolinie Warty, charakteryzuje się typowym dla tego typu zbiorników mulistym dnem, bogatym w osady organiczne. Brzegi są w większości porośnięte gęstymi szuwarami trzciny oraz krzewami wierzbowymi, co utrudnia dostęp do wody, ale jednocześnie stanowi doskonałe schronienie dla ryb. W płytkich partiach dominują lilie wodne i rdestnice, tworząc podwodne łąki. Jest to idealne siedlisko dla lina, karasia pospolitego oraz wzdręgi, a także dla drapieżników takich jak szczupak i okoń, które polują w zaroślach. Wędkarstwo wymaga cierpliwości i często użycia brodzących butów ze względu na bagniste podłoże przy brzegach. Okresowo, podczas wiosennych roztopów, starorzecze może mieć połączenie z rzeką, co sprzyja migracji ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22295, 3.8, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć,Okoń', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22296, 'Starorzecze Wola Życińska 2', 'starorzecze-wola-zycinska-2-czestochowa-22296', 'OXBOW', 50.9520151, 19.8339506, 'Śląskie', 'Częstochowa', 'Drugie starorzecze w okolicy Woli Życińskiej jest nieco mniejsze, ale równie atrakcyjne dla wędkarzy. Charakteryzuje się piaszczysto-mulistym dnem w głębszych partiach i mocno zamulonym w płytszych zatokach. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je gęsta trzcina i pałka wodna, co wymaga poszukiwania dogodnych stanowisk. Roślinność podwodna jest bujna, z dominacją moczarki kanadyjskiej i wywłócznika, stanowiąc idealne kryjówki dla drobnicy. W starorzeczu licznie występują płocie, leszcze i wzdręgi, a także drapieżniki takie jak szczupak i duży okoń. Wędkarstwo gruntowe i spławikowe przynosi najlepsze rezultaty, zwłaszcza na przełomie wiosny i lata. Zimą istnieje ryzyko przyduchy ze względu na grubą warstwę lodu i dużą ilość rozkładającej się materii organicznej.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22296, 2.5, 1, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Szczupak,Okoń,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22297, 'Głusza', 'glusza-wegrow-22297', 'OXBOW', 52.6066514, 21.4870951, 'Mazowieckie', 'Węgrów', 'Starorzecze Głusza to rozległy akwen o nieregularnym kształcie, położony w dolinie Liwca. Dno jest zróżnicowane, od piaszczystych płycizn po głębokie, muliste rynny, będące pozostałością po dawnym korycie rzeki. Brzegi są łatwo dostępne w niektórych miejscach, jednak w większości porośnięte są pasami trzcin i olch. Obfita roślinność zanurzona, taka jak rogatek i moczarka, tworzy doskonałe tarliska i żerowiska. W Głuszy królują leszcze, płocie i karasie pospolite, a także dorodne szczupaki i sumy, które migrują z rzeki podczas wylewów. Wędkarstwo spinningowe i gruntowe jest tutaj bardzo popularne. Latem, w upalne dni, należy zachować ostrożność ze względu na możliwość niedoboru tlenu w płytkich partiach, co może wpływać na aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22297, 12, 2, 6, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Sum,Karaś pospolity', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22298, 'Starorzecze Tomaszów Mazowiecki 1', 'starorzecze-tomaszow-mazowiecki-1-tomaszow-mazowiecki-22298', 'OXBOW', 51.5358331, 20.0682453, 'Łódzkie', 'Tomaszów Mazowiecki', 'Starorzecze to jest częścią kompleksu starorzeczy Pilicy, charakteryzuje się dnem pokrytym grubą warstwą mułu i rozkładającej się materii organicznej. Brzegi są przeważnie strome i trudnodostępne, porośnięte gęstymi krzewami i drzewami, co tworzy naturalne zacienienie. Woda jest stosunkowo płytka, ale bogata w roślinność zanurzoną, taką jak wywłócznik i rzęsa wodna, co sprzyja rozwojowi drobnych organizmów. Dominującymi gatunkami ryb są lin, karaś pospolity i wzdręga, które doskonale czują się w zarośniętych i spokojnych wodach. Wędkarstwo spławikowe w przerwach między roślinnością jest najbardziej efektywne. Ze względu na dużą ilość mułu i roślinności, w okresie letnich upałów może występować ryzyko niedoboru tlenu, zwłaszcza w nocy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22298, 1.8, 1, 2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22299, 'Starorzecze Tomaszów Mazowiecki 2', 'starorzecze-tomaszow-mazowiecki-2-tomaszow-mazowiecki-22299', 'OXBOW', 51.5357951, 20.0793118, 'Łódzkie', 'Tomaszów Mazowiecki', 'Kolejne starorzecze w okolicy Tomaszowa Mazowieckiego jest nieco głębsze i posiada bardziej zróżnicowane dno, z miejscami piaszczystymi i mulistymi. Brzegi są łatwiej dostępne na krótkich odcinkach, choć w większości są zarośnięte trzciną i olchami, zapewniającymi cień. W zbiorniku występuje umiarkowana ilość roślinności podwodnej, co ułatwia prowadzenie przynęt. Jest to doskonałe miejsce dla szczupaków i okoni, które polują wśród podwodnych struktur. Licznie występują również leszcze i płocie, stanowiące bazę pokarmową dla drapieżników. Wędkarze często stosują tutaj metody spinningowe oraz gruntowe z lekkimi zestawami. Wiosną, po roztopach, starorzecze łączy się z rzeką, co wzbogaca jego ichtiofaunę o nowe gatunki ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22299, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Mocno zarośnięty trzciną', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22300, 'Starorzecze Tomaszów Mazowiecki 3', 'starorzecze-tomaszow-mazowiecki-3-tomaszow-mazowiecki-22300', 'OXBOW', 51.5344256, 20.0813772, 'Łódzkie', 'Tomaszów Mazowiecki', 'To starorzecze jest najbardziej zarośnięte ze wszystkich w okolicy Tomaszowa Mazowieckiego, co czyni je prawdziwą ostoją dla ryb ceniących spokój. Dno jest w całości pokryte grubą warstwą mułu, a głębokość rzadko przekracza dwa metry. Brzegi są niemal całkowicie niedostępne z powodu gęstych zarośli i bagnistego terenu, co wymaga od wędkarzy znalezienia nielicznych, przetartych ścieżek. Woda jest bogata w roślinność wodną, tworzącą gęste dywany na powierzchni i pod wodą. Dominujące gatunki to lin, karaś pospolity, wzdręga oraz małe płocie. Jest to idealne miejsce dla wędkarzy poszukujących ciszy i kontaktu z naturą, gotowych na wyzwania związane z trudnym dostępem. Wysokie temperatury latem mogą prowadzić do znacznego spadku poziomu tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22300, 2.1, 0.8, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22301, 'Starorzecze koło Zielonej Góry (nieznanej okolicy)', 'starorzecze-kolo-zielonej-gory-nieznanej-okolicy-zielona-gora-22301', 'OXBOW', 52.0158702, 15.5119795, 'Lubuskie', 'Zielona Góra', 'To starorzecze, choć jego dokładna nazwa jest nieznana, jest typowym przykładem akwenu polodowcowego, który został odcięty od głównego nurtu rzeki. Charakteryzuje się dnem piaszczysto-mulistym, z licznymi zatopionymi korzeniami i gałęziami, które stanowią schronienie dla ryb. Brzegi są w większości porośnięte lasem łęgowym, co zapewnia cień i stabilność, ale utrudnia swobodne poruszanie się. W zbiorniku występuje umiarkowana roślinność podwodna, skupiająca się głównie w płytszych zatokach. Występują tu szczupaki, okonie, leszcze oraz płocie. Wędkarstwo spinningowe i gruntowe są najskuteczniejsze. Starorzecze to jest cenione za dziki charakter i możliwość złowienia dużych okazów drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22301, 6, 2.2, 4.5, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22302, 'Starorzecze Wysokie', 'starorzecze-wysokie-zielona-gora-22302', 'OXBOW', 52.0201418, 15.5007773, 'Lubuskie', 'Zielona Góra', 'Starorzecze Wysokie to malowniczy zbiornik, który zachował swój naturalny charakter, będąc pozostałością po dawnej Odrze. Dno jest zróżnicowane, od twardych, żwirowych odcinków po miękkie, muliste zagłębienia. Brzegi są w większości stabilne i dostępne, choć miejscami porośnięte gęstymi krzewami i drzewami. Roślinność podwodna jest bujna, szczególnie w płytszych partiach, tworząc idealne środowisko dla ryb. W starorzeczu licznie występują leszcze, płocie, karpie oraz drapieżniki takie jak szczupak i sandacz. Jest to popularne miejsce dla wędkarzy gruntowych i spławikowych, ceniących sobie różnorodność gatunkową. Podczas wysokiej wody starorzecze łączy się z Odrą, co sprzyja wymianie ichtiofauny i pojawianiu się nowych, dużych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22302, 8.5, 2.5, 5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22303, 'Starorzecze Przecza', 'starorzecze-przecza-opole-22303', 'OXBOW', 50.743341, 17.6431755, 'Opolskie', 'Opole', 'Starorzecze Przecza to niewielki, ale urokliwy zbiornik położony w pobliżu Odry. Dno jest w większości muliste, z licznymi zaczepami w postaci zatopionych gałęzi i drzew, co wymaga ostrożności podczas wędkowania. Brzegi są mocno zarośnięte trzciną i krzewami, co sprawia, że dostęp do wody jest utrudniony i wymaga poszukiwania prześwitów. Roślinność podwodna jest gęsta, tworząc idealne kryjówki dla ryb i miejsc do żerowania. W starorzeczu dominują lin, karaś pospolity, wzdręga oraz szczupak, który poluje z zasadzki. Wędkarstwo spławikowe i gruntowe z krótkimi zestawami jest tutaj najbardziej efektywne. Ze względu na płytkość i dużą ilość roślinności, w upalne lata może występować ryzyko przyduchy, co wpływa na kondycję ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22303, 1.5, 0.9, 2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22304, 'Starorzecze Dębki', 'starorzecze-debki-wladyslawowo-22304', 'OXBOW', 54.83283, 18.0635571, 'Pomorskie', 'Władysławowo', 'Starorzecze w Dębkach to unikalny zbiornik, położony blisko wybrzeża Bałtyku, będący pozostałością po dawnej rzece Piaśnicy. Dno jest piaszczysto-muliste, z lokalnymi zagłębieniami i twardszymi partiami. Brzegi są częściowo dostępne, choć w wielu miejscach porastają je nadmorskie zarośla i trzciny. Woda jest nieco zasolona, co wpływa na specyfikę ichtiofauny, choć dominują gatunki słodkowodne. Występują tu płocie, leszcze, okonie, a także szczupaki i węgorze, które mogą migrować z morza. Wędkarstwo jest możliwe przez cały sezon, z najlepszymi wynikami na wiosnę i jesień. Ze względu na bliskość morza, zbiornik jest narażony na silne wiatry, co może utrudniać wędkowanie, jednak jego urok rekompensuje te niedogodności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22304, 7, 1.7, 3.2, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak,Węgorz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22305, 'Starorzecze Zielona Góra 1', 'starorzecze-zielona-gora-1-zielona-gora-22305', 'OXBOW', 52.0230144, 15.5667085, 'Lubuskie', 'Zielona Góra', 'Pierwsze ze starorzeczy w okolicy Zielonej Góry to zbiornik o charakterze leśnym, z dnem pokrytym głównie mułem i opadłymi liśćmi. Brzegi są w większości zalesione, strome i trudno dostępne, co sprzyja zachowaniu dzikiego charakteru łowiska. Woda jest stosunkowo płytka, ale w niektórych miejscach występują głębsze rynny, będące pozostałością po dawnym nurcie. Roślinność podwodna jest umiarkowana, ale występują liczne zatopione gałęzie i pnie drzew. W starorzeczu dominują lin, karaś pospolity, wzdręga oraz szczupak, który poluje z zasadzki. Wędkarstwo wymaga cierpliwości i umiejętności poruszania się w trudnym terenie. Zimą, pod grubą warstwą lodu, istnieje ryzyko przyduchy ze względu na dużą ilość materii organicznej.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22305, 3, 1.3, 2.8, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22306, 'Starorzecze Zielona Góra 2', 'starorzecze-zielona-gora-2-zielona-gora-22306', 'OXBOW', 52.0239123, 15.5708528, 'Lubuskie', 'Zielona Góra', 'Drugie starorzecze w pobliżu Zielonej Góry jest nieco większe i bardziej otwarte niż poprzednie, co ułatwia dostęp w niektórych miejscach. Dno jest zróżnicowane, z fragmentami piaszczystymi i mulistymi, a także z pojedynczymi zaczepami. Brzegi są częściowo porośnięte trzciną, ale istnieją również odcinki z twardszym dojściem. Roślinność podwodna jest umiarkowana, z przewagą rdestnic i moczarki. W starorzeczu licznie występują płocie, leszcze, okonie oraz szczupaki, które znajdują tu dogodne warunki do żerowania. Wędkarstwo spławikowe i spinningowe przynosi dobre rezultaty, zwłaszcza wczesną wiosną i jesienią. Okresowo, przy wysokim stanie wody w Odrze, starorzecze może mieć z nią połączenie, co sprzyja migracji ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22306, 5.5, 1.6, 3, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22307, 'Starorzecze Paniowice', 'starorzecze-paniowice-wroclaw-22307', 'OXBOW', 51.2113729, 16.91353, 'Dolnośląskie', 'Wrocław', 'Starorzecze w Paniowicach to rozległy akwen, będący pozostałością po dawnej Odrze, charakteryzujący się zróżnicowanym dnem – od piaszczystych płycizn po głębokie, muliste rynny. Brzegi są w większości dobrze dostępne, choć w niektórych miejscach porastają je gęste zarośla i drzewa, zapewniające cień. Obfita roślinność podwodna, taka jak grążele i moczarka, tworzy dogodne schronienia dla ryb. W starorzeczu licznie występują leszcze, płocie, karpie, a także dorodne szczupaki i sandacze. Jest to popularne miejsce dla wędkarzy gruntowych, spławikowych i spinningistów. Starorzecze ma stałe połączenie z Odrą, co zapewnia ciągły dopływ świeżej wody i migrację ryb, utrzymując wysoką bioróżnorodność i minimalizując ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22307, 15, 2.8, 7, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22308, 'Starorzecze Biała Podlaska 1', 'starorzecze-biala-podlaska-1-biala-podlaska-22308', 'OXBOW', 52.0313814, 23.1428517, 'Lubelskie', 'Biała Podlaska', 'Pierwsze ze starorzeczy w okolicy Białej Podlaskiej to typowy akwen śródleśny, z dnem pokrytym grubą warstwą mułu i rozkładającej się materii organicznej. Brzegi są mocno zarośnięte drzewami i krzewami, co sprawia, że dostęp do wody jest bardzo trudny i wymaga przedzierania się przez gęste zarośla. Woda jest stosunkowo płytka, z obfitą roślinnością podwodną, tworzącą gęste zarośla. W starorzeczu dominują lin, karaś pospolity, wzdręga oraz małe płocie. Jest to idealne miejsce dla wędkarzy ceniących dzikość i spokój, gotowych na wyzwania. Ze względu na dużą ilość mułu i roślinności, w okresie letnich upałów i zimą pod lodem, istnieje wysokie ryzyko niedoboru tlenu, co może wpływać na kondycję ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22308, 2, 0.7, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22309, 'Starorzecze Biała Podlaska 2', 'starorzecze-biala-podlaska-2-biala-podlaska-22309', 'OXBOW', 52.0312605, 23.1418861, 'Lubelskie', 'Biała Podlaska', 'Drugie starorzecze w okolicach Białej Podlaskiej jest nieco większe i bardziej otwarte niż poprzednie, choć nadal zachowuje swój dziki charakter. Dno jest muliste, z pojedynczymi zatopionymi korzeniami i gałęziami, które stanowią schronienie dla ryb. Brzegi są częściowo dostępne, ale w większości porośnięte gęstą trzciną i wierzbami. Roślinność podwodna jest umiarkowana, co sprzyja różnorodności gatunkowej. W starorzeczu występują płocie, leszcze, okonie oraz szczupaki, które polują w zaroślach. Wędkarstwo spławikowe i spinningowe są tutaj najbardziej efektywne. Starorzecze to, choć rzadko łączy się z główną rzeką, utrzymuje stabilny poziom wody i jest cenione za obfitość ryb i spokój. Warto pamiętać o środkach odstraszających komary w sezonie letnim.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22309, 4, 1.2, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak,Karaś srebrzysty', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22310, 'Starorzecze (Łokacz Wielki)', 'starorzecze-lokacz-wielki-drezdenko-22310', 'OXBOW', 52.8833264, 15.9779091, 'Lubuskie', 'Drezdenko', 'To starorzecze, położone w malowniczej okolicy Łokacza Wielkiego, jest typowym zbiornikiem połączonym z systemem rzeki Noteć. Charakteryzuje się mulistym dnem, które w głębszych partiach pokryte jest warstwą detrytusu, a w płytszych liczną roślinnością podwodną. Brzegi są w większości trudno dostępne, porośnięte gęstymi trzcinami i krzewami, co wymaga cierpliwości od wędkarza. Akwen jest ostoją dla lina, karasia pospolitego oraz płoci, a w poszukiwaniu pokarmu często patrolują go szczupaki. Wędkowanie z gruntu lub na spławik w miejscach prześwitów roślinności daje najlepsze rezultaty, choć wymaga precyzji. Ze względu na umiarkowane zarastanie i średnie zamulenie, w okresach upałów istnieje ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22310, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Płoć,Karaś pospolity', 'Trudny, miejscami bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22311, 'Starorzecze (Lipki Małe)', 'starorzecze-lipki-male-gorzow-wielkopolski-22311', 'OXBOW', 52.7647436, 15.5764419, 'Lubuskie', 'Gorzów Wielkopolski', 'Starorzecze w Lipkach Małych to niewielki, ale urokliwy zbiornik, który utracił stałe połączenie z głównym nurtem rzeki. Jego dno jest silnie zamulone, a płytkie partie niemal całkowicie pokryte dywanem roślinności wodnej, co tworzy idealne warunki dla ryb ciepłolubnych. Brzegi są gęsto porośnięte trzcinami i szuwarami, co sprawia, że dostęp do wody jest bardzo utrudniony i często wymaga brodzenia. Dominującymi gatunkami są tu karaś pospolity, lin oraz wzdręga, a także liczna populacja płoci. Wędkowanie jest wyzwaniem, ale nagradza cierpliwych obfitymi braniami, szczególnie na spławik lub lekką gruntówkę. Ze względu na silne zarastanie i brak dopływu świeżej wody, latem występuje wysokie ryzyko niedoboru tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22311, 3.2, 1.5, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22312, 'Starorzecze (Nowe Dwory)', 'starorzecze-nowe-dwory-krzyz-wielkopolski-22312', 'OXBOW', 52.8874263, 16.2930165, 'Wielkopolskie', 'Krzyż Wielkopolski', 'To starorzecze w Nowych Dworach, leżące w bliskim sąsiedztwie Warty, wyróżnia się stosunkowo dobrym połączeniem z rzeką podczas wiosennych wezbrań, co sprzyja wymianie rybostanu. Dno jest urozmaicone, z twardszymi partiami żwirowo-piaszczystymi przeplatanymi z mulistymi zatoczkami, co tworzy idealne siedliska dla różnorodnych gatunków. Brzegi są w dużej mierze dostępne, z licznymi pomostami i dogodnymi stanowiskami wędkarskimi, choć miejscami występują pasy trzcin. Jest to doskonałe łowisko dla spinningistów polujących na szczupaki i okonie, a także dla wędkarzy gruntowych, którzy mogą liczyć na dorodne leszcze, płocie i karpie. Niskie zamulenie i regularne odświeżanie wody sprawiają, że ryzyko przyduchy jest minimalne, co pozwala na udane wędkowanie przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22312, 6.8, 2.2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22313, 'Starorzecze (Branków)', 'starorzecze-brankow-warka-22313', 'OXBOW', 51.6963025, 21.0191752, 'Mazowieckie', 'Warka', 'Starorzecze w Brankowie to malowniczy zakątek, będący częścią dawnego koryta Wisły, charakteryzujący się dynamicznym charakterem ze względu na bliskość rzeki. Dno jest zróżnicowane, od piaszczystych płycizn po głębsze, muliste rynny, a obecność zatopionych drzew i gałęzi tworzy doskonałe kryjówki dla ryb. Brzegi są częściowo dostępne, jednak miejscami gęsto porośnięte krzewami i trzcinami, co wymaga poszukiwania dogodnych stanowisk. Akwen ten słynie z występowania dużych leszczy i płoci, a także silnych karpi i sumów, które migrują tu podczas wezbrań. Szczupak również jest częstym gościem w zarośniętych partiach. Wędkowanie wymaga ostrożności ze względu na liczne zaczepy, ale może przynieść spektakularne efekty, zwłaszcza wiosną i jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22313, 5.1, 1.9, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Leszcz,Płoć,Karp,Sum,Szczupak', 'Miejscami dostępny, zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22314, 'Starorzecze (Brzeźce)', 'starorzecze-brzezce-warka-22314', 'OXBOW', 51.6773984, 21.0042914, 'Mazowieckie', 'Warka', 'Starorzecze w Brzeźcach to typowy zbiornik powodziowy, charakteryzujący się dynamicznym połączeniem z Wisłą podczas większych wezbrań, co odświeża wodę i zasila rybostan. Dno jest w przeważającej części muliste, z licznymi płyciznami i zaroślami, które stanowią schronienie dla drobnicy i drapieżników. Brzegi są niestety trudne do pokonania, często bagniste i gęsto porośnięte trzcinami, co wymaga od wędkarza użycia woderów i poszukiwania nielicznych prześwitów. W akwenie dominują płocie, leszcze i wzdręgi, a także liczne okonie, które aktywnie żerują w zaroślach. Wędkowanie spławikowe i lekkie spinningowe są najbardziej efektywne. Mimo okresowego połączenia z rzeką, w upalne lata może wystąpić ryzyko niedoboru tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22314, 4.8, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Wzdręga,Okoń', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22315, 'Starorzecze (Kępa Niemojewska)', 'starorzecze-kepa-niemojewska-glowaczow-22315', 'OXBOW', 51.7427004, 21.1363291, 'Mazowieckie', 'Głowaczów', 'Starorzecze w Kępie Niemojewskiej to wyjątkowy akwen, który zachował stałe połączenie z Wisłą, co czyni go dynamicznym i bogatym w różnorodne gatunki ryb. Dno jest przeważnie piaszczysto-żwirowe, z nielicznymi osadami mułu w spokojniejszych zatokach, co sprzyja występowaniu ryb rzecznych. Brzegi są łatwo dostępne, z naturalnymi plażami i miejscami do wędkowania, co czyni to łowisko bardzo popularnym. Jest to raj dla wędkarzy spinningowych, którzy mogą liczyć na bolenie, jazie, klenie, sandacze oraz szczupaki, często wpływające z głównego nurtu rzeki. Akwen charakteryzuje się dobrą przejrzystością wody i brakiem silnego zarastania, co ułatwia wędkowanie. Stałe połączenie z Wisłą minimalizuje ryzyko przyduchy, zapewniając stabilne warunki przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22315, 9.5, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Boleń,Jaź,Kleń,Sandacz,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22316, 'Starorzecze (Policko)', 'starorzecze-policko-konin-22316', 'OXBOW', 52.2006587, 17.8715506, 'Wielkopolskie', 'Konin', 'To niewielkie starorzecze w Policku, jedno z kilku w okolicy, jest typowym, izolowanym zbiornikiem o charakterze silnie zarastającym. Dno jest bardzo mocno zamulone, z grubą warstwą osadów organicznych, a płytkie partie są niemal całkowicie pokryte roślinnością wodną, co utrudnia wędkowanie. Brzegi są gęsto porośnięte trzcinami i szuwarami, co sprawia, że dostęp do wody jest bardzo ograniczony i często wymaga brodzenia w woderach. Dominującymi gatunkami są karaś srebrzysty, wzdręga, lin oraz płoć, które doskonale radzą sobie w trudnych warunkach. Ze względu na niewielką głębokość, silne zarastanie i brak dopływu świeżej wody, zbiornik jest narażony na całkowite wysychanie w upalne lata i wysokie ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22316, 2.8, 1.4, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Lin,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22317, 'Starorzecze (Policko)', 'starorzecze-policko-konin-22317', 'OXBOW', 52.2003507, 17.8656341, 'Wielkopolskie', 'Konin', 'Drugie starorzecze w kompleksie Policka charakteryzuje się nieco większą głębokością i okresowym połączeniem z rzeką Wartą podczas wiosennych wezbrań. Dno jest muliste, ale z twardszymi fragmentami, a roślinność podwodna występuje w umiarkowanym stopniu, tworząc schronienia dla ryb. Brzegi są częściowo dostępne, choć miejscami nadal gęsto zarośnięte trzciną, co wymaga cierpliwości od wędkarza. Akwen ten jest atrakcyjny dla spinningistów, którzy mogą liczyć na szczupaki i okonie, a także dla wędkarzy spławikowych i gruntowych, polujących na leszcze, płocie i karasie pospolite. Okresowe połączenie z rzeką poprawia warunki tlenowe, jednak w długie, upalne lata wciąż istnieje ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22317, 3.5, 1.8, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karaś pospolity', 'Miejscami dostępny, zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22318, 'Starorzecze (Policko)', 'starorzecze-policko-konin-22318', 'OXBOW', 52.1984211, 17.8619762, 'Wielkopolskie', 'Konin', 'To starorzecze w Policku jest najmniejsze i najbardziej izolowane z lokalnego kompleksu, co skutkuje jego szybkim zarastaniem i zamulaniem. Dno jest niemal całkowicie pokryte grubą warstwą mułu i gęstą roślinnością podwodną, tworząc trudne warunki do wędkowania. Brzegi są bardzo trudno dostępne, często bagniste i niemal całkowicie zarośnięte trzciną i inną roślinnością szuwarową. W akwenie dominują gatunki odporne na trudne warunki, takie jak karaś pospolity, lin i wzdręga, które znajdują tu schronienie. Wędkowanie jest tu prawdziwym wyzwaniem, wymagającym precyzji i lekkiego sprzętu, najlepiej wczesną wiosną lub późną jesienią. Ze względu na niewielką głębokość i brak dopływu, zbiornik jest bardzo podatny na wysychanie i przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22318, 2.1, 1.2, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22319, 'Starorzecze (Policko)', 'starorzecze-policko-konin-22319', 'OXBOW', 52.1888362, 17.8546915, 'Wielkopolskie', 'Konin', 'Ostatnie z opisywanych starorzeczy w Policku wyróżnia się stosunkowo dobrą kondycją i okresowym połączeniem z rzeką Wartą, co zapewnia stabilne warunki środowiskowe. Dno jest zróżnicowane, z twardszymi partiami w pobliżu dawnego nurtu i mulistymi zagłębieniami, gdzie gromadzą się ryby. Jeden z brzegów jest łatwo dostępny, oferując dogodne miejsca do wędkowania, natomiast drugi jest bardziej dziki i zarośnięty. Jest to atrakcyjne łowisko dla wędkarzy poszukujących szczupaków i okoni, a także dla miłośników białorybu, którzy mogą liczyć na dorodne leszcze, płocie i karpie. Umiarkowane zarastanie i regularne odświeżanie wody sprawiają, że ryzyko przyduchy jest niskie. Wędkowanie jest tu przyjemne i obfituje w różnorodne gatunki przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22319, 4, 2, 3.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry z jednej strony, zarośnięty z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22320, 'Starorzecze (Porosiuki)', 'starorzecze-porosiuki-biala-podlaska-22320', 'OXBOW', 52.0168869, 23.05332, 'Lubelskie', 'Biała Podlaska', 'Starorzecze w Porosiukach, położone w dorzeczu Krzny, jest typowym zbiornikiem charakteryzującym się dynamicznym połączeniem z rzeką podczas wiosennych wezbrań. Dno jest zróżnicowane, z mulistymi zagłębieniami i twardszymi fragmentami, a liczne zatopione drzewa i konary tworzą doskonałe kryjówki dla ryb. Brzegi są miejscami dostępne, jednak w wielu rejonach gęsto porośnięte trzcinami i krzewami, co wymaga użycia woderów i poszukiwania dogodnych stanowisk. Akwen ten jest znany z obfitości lina i karasia pospolitego, a także z licznych szczupaków i okoni, które aktywnie żerują w zaroślach. Wędkowanie jest tu wyzwaniem ze względu na zaczepy, ale może przynieść imponujące efekty, szczególnie na spławik lub żywca. W okresach suszy i upałów występuje ryzyko niedoboru tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22320, 7, 2.3, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń,Leszcz', 'Miejscami dostępny, zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22321, 'Starorzecze (Jaźwiny)', 'starorzecze-jazwiny-biala-podlaska-22321', 'OXBOW', 52.012669, 23.0410343, 'Lubelskie', 'Biała Podlaska', 'To starorzecze w Jaźwinach, będące częścią kompleksu dawnych koryt Krzny, jest zbiornikiem bez stałego połączenia z rzeką, co sprzyja jego szybkiemu zarastaniu. Dno jest silnie zamulone, a płytkie partie są gęsto pokryte roślinnością wodną, tworząc idealne środowisko dla gatunków ciepłolubnych i odpornych. Brzegi są bardzo trudno dostępne, niemal całkowicie zarośnięte trzcinami i szuwarami, co sprawia, że wędkowanie z brzegu jest praktycznie niemożliwe bez brodzenia. Dominującymi gatunkami są karaś pospolity, lin, wzdręga oraz płoć, które doskonale radzą sobie w tych warunkach. Wędkowanie wymaga cierpliwości i precyzji, najlepiej na spławik w miejscach prześwitów. Ze względu na silne zarastanie i brak dopływu świeżej wody, latem występuje wysokie ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22321, 3, 1.6, 2.9, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22322, 'Starorzecze (Jaźwiny)', 'starorzecze-jazwiny-biala-podlaska-22322', 'OXBOW', 52.0135015, 23.0439945, 'Lubelskie', 'Biała Podlaska', 'Drugie starorzecze w Jaźwinach to mniejszy i płytszy zbiornik, charakteryzujący się bardzo silnym zamuleniem i bujną roślinnością wodną, która niemal całkowicie pokrywa jego powierzchnię. Brak stałego połączenia z rzeką sprawia, że jego ekosystem jest bardzo wrażliwy na zmiany warunków pogodowych. Brzegi są ekstremalnie trudne do pokonania, często bagniste i gęsto zarośnięte, co skutecznie zniechęca wędkarzy bez odpowiedniego sprzętu. W akwenie dominują gatunki takie jak karaś srebrzysty, wzdręga i płoć, które są odporne na niskie stężenie tlenu. Ze względu na niewielką głębokość i brak dopływu świeżej wody, zbiornik jest bardzo podatny na wysychanie w okresach długotrwałej suszy i wysokie ryzyko przyduchy. Wędkowanie jest tu prawdziwym wyzwaniem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22322, 2.5, 1.4, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22323, 'Starorzecze (Jaźwiny)', 'starorzecze-jazwiny-biala-podlaska-22323', 'OXBOW', 52.0137929, 23.0430885, 'Lubelskie', 'Biała Podlaska', 'To starorzecze w Jaźwinach jest jednym z lepiej zachowanych w kompleksie, z okresowym połączeniem z rzeką Krzną podczas wiosennych wezbrań, co sprzyja wymianie rybostanu. Dno jest muliste, ale z twardszymi fragmentami, a roślinność podwodna występuje w umiarkowanym stopniu, tworząc liczne kryjówki dla ryb. Brzegi są częściowo dostępne, choć miejscami nadal gęsto zarośnięte trzciną, co wymaga cierpliwości od wędkarza. Akwen ten jest atrakcyjny dla spinningistów, którzy mogą liczyć na szczupaki i okonie, a także dla wędkarzy spławikowych i gruntowych, polujących na liny i leszcze. Okresowe połączenie z rzeką poprawia warunki tlenowe, jednak w długie, upalne lata wciąż istnieje ryzyko przyduchy. Wędkowanie jest tu najbardziej efektywne w chłodniejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22323, 3.8, 1.9, 3.3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Szczupak,Okoń,Leszcz', 'Miejscami dostępny, zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22324, 'Starorzecze (Jaźwiny)', 'starorzecze-jazwiny-biala-podlaska-22324', 'OXBOW', 52.01437, 23.0453138, 'Lubelskie', 'Biała Podlaska', 'Ostatnie z opisywanych starorzeczy w Jaźwinach to największy i najgłębszy zbiornik w lokalnym kompleksie, charakteryzujący się dobrym połączeniem z rzeką Krzną podczas wysokich stanów wody. Dno jest zróżnicowane, z głębokimi rynnami i zatopionymi drzewami, które stanowią doskonałe kryjówki dla dużych ryb. Jeden z brzegów jest stosunkowo łatwo dostępny, oferując dogodne miejsca do wędkowania, podczas gdy drugi jest bardziej dziki i zarośnięty. Jest to doskonałe łowisko dla wędkarzy poszukujących dużych szczupaków i okoni, a także dla miłośników gruntówki, którzy mogą liczyć na dorodne leszcze, karpie i sumy wpływające z rzeki. Umiarkowane zarastanie i regularne odświeżanie wody sprawiają, że ryzyko przyduchy jest niskie. Wędkowanie jest tu produktywne przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22324, 4.2, 2.1, 3.9, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Karp,Sum', 'Dobry z jednej strony, trudny z drugiej', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22325, 'Starorzecze (Podłąka)', 'starorzecze-podlaka-biala-podlaska-22325', 'OXBOW', 52.0142042, 23.0347302, 'Lubelskie', 'Biała Podlaska', 'To starorzecze, położone w malowniczej dolinie rzeki Krzny, charakteryzuje się typowym dla tego typu zbiorników wydłużonym kształtem. Dno jest tu w przeważającej części muliste, z lokalnymi twardszymi partiami piaskowo-gliniastymi, co sprzyja rozwojowi bogatej roślinności podwodnej. Brzegi są zróżnicowane, miejscami łatwo dostępne, a w innych rejonach mocno zarośnięte trzciną i krzewami, co może utrudniać swobodne poruszanie się. Występuje tu obficie rzęsa wodna, lilie wodne oraz moczarka kanadyjska, tworząc idealne schronienia dla ryb. Wśród dominujących gatunków ryb można wymienić liny, karasie pospolite oraz szczupaki, które chętnie polują w zaroślach. Wędkarze powinni przygotować się na możliwość zaczepów o podwodną roślinność, zwłaszcza w cieplejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22325, 3.2, 1.5, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22326, 'Starorzecze (Podłąka)', 'starorzecze-podlaka-biala-podlaska-22326', 'OXBOW', 52.0150974, 23.0175781, 'Lubelskie', 'Biała Podlaska', 'Ten fragment starorzecza, oddalony nieco od głównego koryta rzeki, charakteryzuje się większą izolacją i stabilniejszym poziomem wody. Dno jest tu głównie piaszczysto-muliste, z licznymi zatopionymi gałęziami i korzeniami, które stanowią doskonałe kryjówki dla ryb. Brzegi są częściowo zalesione, co zapewnia cień i tworzy sprzyjające warunki dla wędkowania z brzegu, choć miejscami dostęp może być utrudniony przez gęste podszycie. Roślinność podwodna jest umiarkowana, z przewagą wywłócznika i rogatka, co ułatwia prowadzenie przynęt. Występują tu głównie leszcze, płocie oraz okonie, a także sporadycznie większe karpie. Trudnością może być dotarcie do niektórych, bardziej obiecujących stanowisk, zwłaszcza po obfitych opadach deszczu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22326, 2.1, 1.8, 3.5, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Karp', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22327, 'Starorzecze (Styrzyniec)', 'starorzecze-styrzyniec-biala-podlaska-22327', 'OXBOW', 52.0160113, 23.015751, 'Lubelskie', 'Biała Podlaska', 'Starorzecze w Styrzyńcu to rozległy akwen o nieregularnym kształcie, głęboko wcięty w teren, co zapewnia mu pewną ochronę przed silnymi wiatrami. Dno jest tu bardzo zróżnicowane, od twardych, żwirowych blatów po głębokie, muliste rynny, będące pozostałością po dawnym nurcie rzeki. Brzegi są w większości strome i piaszczyste, z nielicznymi miejscami do wygodnego zejścia, często porośnięte starymi wierzbami i topolami. Roślinność wodna koncentruje się głównie w płytszych zatokach, tworząc zwarte łany trzcin i pałki wodnej. To idealne miejsce dla drapieżników takich jak szczupak i sandacz, ale też dla dużych leszczy i karpi. Wędkarze powinni być przygotowani na konieczność dalekich rzutów i precyzyjnego umieszczania przynęty w miejscach wolnych od zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22327, 7.5, 2.2, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Karp,Okoń', 'Trudny, bagnisty', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22328, 'Starorzecze (Styrzyniec)', 'starorzecze-styrzyniec-biala-podlaska-22328', 'OXBOW', 52.0167831, 23.0152612, 'Lubelskie', 'Biała Podlaska', 'To mniejsze, bardziej kameralne starorzecze charakteryzuje się dużą ilością podwodnych przeszkód i bogatą roślinnością. Dno jest w większości miękkie, z grubą warstwą osadów organicznych, co sprzyja rozwojowi lina i karasia. Brzegi są niskie, często podmokłe i gęsto porośnięte olchami oraz krzewami, co utrudnia dostęp do wody, ale jednocześnie tworzy wiele ustronnych miejsc. Roślinność podwodna jest bardzo silna, z dominacją moczarki i rdestnic, co wymaga stosowania odpowiednich zestawów. Wśród ryb dominują liny, karasie pospolite oraz wzdręgi, a także mniejsze szczupaki. Wędkowanie tutaj to wyzwanie ze względu na liczne zaczepy i konieczność precyzyjnego zarzucania przynęty w wolne od roślinności okna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22328, 1.8, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22329, 'Starorzecze (Styrzyniec)', 'starorzecze-styrzyniec-biala-podlaska-22329', 'OXBOW', 52.0172324, 23.0146665, 'Lubelskie', 'Biała Podlaska', 'Ten odcinek starorzecza wyróżnia się stosunkowo czystym dnem i głębszymi partiami wody, co czyni go atrakcyjnym dla wędkarzy poszukujących większych ryb. Dno jest przeważnie piaszczysto-gliniaste, z pojedynczymi skupiskami kamieni i zatopionych gałęzi. Brzegi są łatwiej dostępne niż w sąsiednich odcinkach, z kilkoma dogodnymi stanowiskami wędkarskimi, choć nadal występują obszary zarośnięte trzciną. Roślinność wodna jest umiarkowana, głównie w postaci pasów trzcin przy brzegach i rzadkich kęp moczarki. Występuje tu bogata populacja płoci, leszczy i okoni, a także dorodne karpie i sumy. Wędkowanie nie nastręcza większych trudności, jednak warto pamiętać o zachowaniu ciszy, aby nie spłoszyć ostrożnych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22329, 4.1, 2.5, 4.5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Karp,Sum', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22330, 'Starorzecze (Styrzyniec)', 'starorzecze-styrzyniec-biala-podlaska-22330', 'OXBOW', 52.0155601, 23.0080576, 'Lubelskie', 'Biała Podlaska', 'To starorzecze to typowy, silnie zarośnięty akwen, będący rajem dla miłośników lina i karasia. Dno jest bardzo muliste, z grubą warstwą osadów organicznych, co sprzyja bujnemu rozwojowi roślinności. Brzegi są niskie, podmokłe i gęsto porośnięte trzciną oraz krzewami, co znacząco utrudnia dostęp do wody, wymagając często użycia brodzących. Roślinność podwodna jest dominująca, tworząc gęste dywany rzęsy, wywłócznika i moczarki, co sprawia, że łowienie wymaga precyzji i cierpliwości. Występują tu głównie liny, karasie pospolite i wzdręgi, które doskonale czują się w takim środowisku. Wędkowanie jest trudne ze względu na liczne zaczepy i konieczność poszukiwania wolnych miejsc do zarzucenia przynęty, ale nagrodą mogą być piękne okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22330, 2.7, 1.2, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22331, 'Starorzecze (Styrzyniec)', 'starorzecze-styrzyniec-biala-podlaska-22331', 'OXBOW', 52.0155165, 22.9992181, 'Lubelskie', 'Biała Podlaska', 'Ten odcinek starorzecza charakteryzuje się bardziej otwartym charakterem i mniejszą ilością roślinności, co ułatwia wędkowanie. Dno jest przeważnie piaszczysto-gliniaste, z miejscowymi osadami mułu, co sprzyja różnorodności gatunków ryb. Brzegi są stosunkowo łatwo dostępne, z kilkoma wygodnymi dojściami, choć miejscami mogą być porośnięte trawami i niskimi krzewami. Roślinność podwodna jest umiarkowana, z dominacją rdestnic i pojedynczych kęp moczarki, co pozwala na swobodne prowadzenie przynęt. Występują tu liczne płocie, leszcze i okonie, a także bolenie i jazie, które chętnie żerują na otwartych wodach. Trudności mogą wynikać z płochliwości ryb w bardziej otwartych miejscach, dlatego zaleca się ostrożność i cichy podchód.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22331, 3.5, 1.7, 3, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Boleń,Jaź', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22332, 'Starorzecze (Styrzyniec)', 'starorzecze-styrzyniec-biala-podlaska-22332', 'OXBOW', 52.0153837, 23.0004999, 'Lubelskie', 'Biała Podlaska', 'Ten fragment starorzecza to głębszy i bardziej rozległy akwen, idealny dla wędkarzy poszukujących większych drapieżników i karpi. Dno jest zróżnicowane, od twardych, gliniastych partii po głębokie, muliste doły, będące doskonałymi kryjówkami dla sumów. Brzegi są częściowo zalesione, zapewniając cień i schronienie, ale w niektórych miejscach dostęp może być utrudniony przez gęste podszycie i powalone drzewa. Roślinność podwodna jest umiarkowana, z przewagą wywłócznika i rdestnic, co nie utrudnia zbytnio wędkowania. Występują tu duże szczupaki, sandacze, sumy oraz dorodne karpie i leszcze. Wędkowanie może wymagać użycia mocniejszego sprzętu ze względu na potencjalnie duże ryby i możliwość zaczepów o zatopione konary.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22332, 6, 2.8, 6, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Sum,Karp,Leszcz', 'Trudny, bagnisty', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22333, 'Starorzecze (Styrzyniec)', 'starorzecze-styrzyniec-biala-podlaska-22333', 'OXBOW', 52.0151523, 22.9954777, 'Lubelskie', 'Biała Podlaska', 'To starorzecze to typowy, płytki i silnie zarośnięty zbiornik, będący ostoją dla drobniejszych ryb i karasi. Dno jest bardzo muliste, z grubą warstwą osadów organicznych, co sprzyja bujnemu rozwojowi roślinności. Brzegi są niskie, podmokłe i gęsto porośnięte trzciną oraz krzewami, co znacząco utrudnia dostęp do wody, często wymagając użycia brodzących. Roślinność podwodna jest dominująca, tworząc gęste dywany rzęsy, wywłócznika i moczarki, co sprawia, że łowienie wymaga precyzji i cierpliwości. Występują tu głównie karasie pospolite, wzdręgi i liny, które doskonale czują się w takim środowisku. Wędkowanie jest trudne ze względu na liczne zaczepy i konieczność poszukiwania wolnych miejsc do zarzucenia przynęty, ale nagrodą mogą być piękne okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22333, 1.5, 0.8, 1.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22334, 'Starorzecze (Loretto)', 'starorzecze-loretto-wyszkow-22334', 'OXBOW', 52.5539402, 21.5963021, 'Mazowieckie', 'Wyszków', 'Starorzecze w Loretto to malowniczy, wydłużony zbiornik, będący pozostałością po dawnej Narwi, charakteryzujący się spokojną i płytką wodą. Dno jest w większości muliste, z licznymi osadami organicznymi, co sprzyja rozwojowi bogatej roślinności podwodnej. Brzegi są zróżnicowane, miejscami łatwo dostępne, a w innych rejonach mocno zarośnięte trzciną i krzewami, co może utrudniać swobodne poruszanie się. Występuje tu obficie rzęsa wodna, lilie wodne oraz moczarka kanadyjska, tworząc idealne schronienia dla ryb. Wśród dominujących gatunków ryb można wymienić liny, karasie pospolite oraz płocie, a także mniejsze szczupaki. Wędkarze powinni przygotować się na możliwość zaczepów o podwodną roślinność, zwłaszcza w cieplejszych miesiącach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22334, 4.5, 1.3, 2.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22335, 'Starorzecze (Loretto)', 'starorzecze-loretto-wyszkow-22335', 'OXBOW', 52.5702389, 21.5844249, 'Mazowieckie', 'Wyszków', 'Ten fragment starorzecza, położony nieco dalej od głównego nurtu, charakteryzuje się większą głębokością i czystszym dnem, co przyciąga większe drapieżniki. Dno jest tu głównie piaszczysto-gliniaste, z miejscowymi osadami mułu i zatopionymi korzeniami, które stanowią doskonałe kryjówki dla ryb. Brzegi są częściowo zalesione, co zapewnia cień i tworzy sprzyjające warunki dla wędkowania z brzegu, choć miejscami dostęp może być utrudniony przez gęste podszycie. Roślinność podwodna jest umiarkowana, z przewagą wywłócznika i rogatka, co ułatwia prowadzenie przynęt. Występują tu głównie szczupaki, okonie oraz leszcze, a także sporadycznie większe karpie. Trudnością może być dotarcie do niektórych, bardziej obiecujących stanowisk, zwłaszcza po obfitych opadach deszczu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22335, 3.8, 2, 4, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Karp', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22336, 'Starorzecze (Jankowice)', 'starorzecze-jankowice-radom-22336', 'OXBOW', 51.4998406, 21.0309671, 'Mazowieckie', 'Radom', 'Starorzecze w Jankowicach to rozległy, choć płytki akwen, będący idealnym miejscem dla wędkarzy poszukujących karasi i linów. Dno jest bardzo muliste, z grubą warstwą osadów organicznych, co sprzyja bujnemu rozwojowi roślinności wodnej. Brzegi są niskie, często podmokłe i gęsto porośnięte trzciną oraz krzewami, co znacząco utrudnia dostęp do wody, wymagając często użycia brodzących. Roślinność podwodna jest dominująca, tworząc gęste dywany rzęsy, wywłócznika i moczarki, co sprawia, że łowienie wymaga precyzji i cierpliwości. Występują tu głównie karasie pospolite, karasie srebrzyste, liny oraz wzdręgi, które doskonale czują się w takim środowisku. Wędkowanie jest trudne ze względu na liczne zaczepy i konieczność poszukiwania wolnych miejsc do zarzucenia przynęty, ale nagrodą mogą być piękne okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22336, 5, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Karaś srebrzysty,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22337, 'Starorzecze (Bartodzieje)', 'starorzecze-bartodzieje-radom-22337', 'OXBOW', 51.5191556, 21.2182254, 'Mazowieckie', 'Radom', 'Starorzecze w Bartodziejach to dynamiczny akwen, który podczas wysokiej wody łączy się z głównym nurtem rzeki, co sprzyja migracji ryb i urozmaica populację. Dno jest zróżnicowane, od twardych, piaszczystych blatów po głębsze, muliste rynny, będące pozostałością po dawnym nurcie. Brzegi są w większości strome i piaszczyste, z nielicznymi miejscami do wygodnego zejścia, często porośnięte starymi wierzbami i topolami. Roślinność wodna koncentruje się głównie w płytszych zatokach, tworząc zwarte łany trzcin i pałki wodnej. To idealne miejsce dla drapieżników takich jak szczupak i okoń, ale też dla dużych leszczy i płoci. Wędkarze powinni być przygotowani na konieczność dalekich rzutów i precyzyjnego umieszczania przynęty w miejscach wolnych od zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22337, 6.5, 1.9, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Boleń', 'Trudny, bagnisty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22338, 'Starorzecze (Burzenin)', 'starorzecze-burzenin-sieradz-22338', 'OXBOW', 51.4532166, 18.8394574, 'Łódzkie', 'Sieradz', 'To starorzecze w Burzeninie to typowy, silnie zarośnięty akwen, będący rajem dla miłośników lina i karasia. Dno jest bardzo muliste, z grubą warstwą osadów organicznych, co sprzyja bujnemu rozwojowi roślinności. Brzegi są niskie, podmokłe i gęsto porośnięte trzciną oraz krzewami, co znacząco utrudnia dostęp do wody, wymagając często użycia brodzących. Roślinność podwodna jest dominująca, tworząc gęste dywany rzęsy, wywłócznika i moczarki, co sprawia, że łowienie wymaga precyzji i cierpliwości. Występują tu głównie liny, karasie pospolite i wzdręgi, które doskonale czują się w takim środowisku. Wędkowanie jest trudne ze względu na liczne zaczepy i konieczność poszukiwania wolnych miejsc do zarzucenia przynęty, ale nagrodą mogą być piękne okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22338, 2.9, 1.1, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22339, 'Starorzecze (Burzenin)', 'starorzecze-burzenin-sieradz-22339', 'OXBOW', 51.4536222, 18.8380361, 'Łódzkie', 'Sieradz', 'Ten fragment starorzecza, choć położony w pobliżu poprzedniego, charakteryzuje się nieco większą głębokością i mniejszym stopniem zarośnięcia, co czyni go atrakcyjnym dla wędkarzy poszukujących większych ryb. Dno jest przeważnie piaszczysto-muliste, z lokalnymi twardszymi partiami i pojedynczymi zatopionymi korzeniami. Brzegi są częściowo zalesione, co zapewnia cień i schronienie, ale w niektórych miejscach dostęp może być utrudniony przez gęste podszycie i powalone drzewa. Roślinność podwodna jest umiarkowana, z przewagą wywłócznika i rdestnic, co nie utrudnia zbytnio wędkowania. Występują tu duże szczupaki, okonie oraz dorodne karpie i leszcze. Wędkowanie może wymagać użycia mocniejszego sprzętu ze względu na potencjalnie duże ryby i możliwość zaczepów o zatopione konary.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22339, 3.1, 1.6, 3, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Karp,Leszcz', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22340, 'Starorzecze (Burzenin)', 'starorzecze-burzenin-burzenin-22340', 'OXBOW', 51.45061, 18.8279786, 'Łódzkie', 'Burzenin', 'To niewielkie starorzecze, położone w malowniczej okolicy Burzenina, charakteryzuje się typowym dla takich zbiorników mulistym dnem. Brzegi są w większości łatwo dostępne, choć miejscami porastają je kępy trzcin i pałki wodnej, tworząc naturalne schronienia dla ryb. W wodzie dominuje roślinność zanurzona, co sprzyja rozwojowi populacji lina i karasia pospolitego. Wędkowanie tutaj wymaga cierpliwości, ale oferuje szansę na złowienie dorodnych płoci i leszczy, a także okazowego szczupaka. Łowisko jest stosunkowo płytkie, co latem może prowadzić do spadku poziomu tlenu, szczególnie w cieplejsze dni. Mimo to, jest to urokliwe miejsce na spokojne zasiadki, idealne dla wędkarzy ceniących sobie ciszę i kontakt z naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22340, 1.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Lin,Karaś pospolity,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22341, 'Starorzecze (Burzenin)', 'starorzecze-burzenin-burzenin-22341', 'OXBOW', 51.4489407, 18.8271216, 'Łódzkie', 'Burzenin', 'To starorzecze, położone nieopodal Burzenina, stanowi nieco większy akwen o zróżnicowanej głębokości. Dno jest głównie muliste, z twardszymi fragmentami wzdłuż dawnego koryta rzeki, co sprzyja różnorodności gatunkowej. Brzegi są przeważnie dostępne, choć w niektórych miejscach występują gęste zarośla krzewów i pojedynczych drzew, oferując naturalne schronienia. Roślinność podwodna jest umiarkowana, co sprzyja zarówno rybom spokojnego żeru, jak i drapieżnikom. Wędkowanie na tym łowisku może przynieść sukces w postaci okazałych leszczy, płoci, a także drapieżnych okoni i szczupaków. Połączenie z rzeką podczas wysokiej wody zapewnia regularne zarybienia naturalne i odświeżanie wody. Jest to popularne miejsce wśród lokalnych wędkarzy, oferujące dobre warunki przez większość sezonu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22341, 2.1, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Lin,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22342, 'Starorzecze (Burzenin)', 'starorzecze-burzenin-burzenin-22342', 'OXBOW', 51.448156, 18.8271668, 'Łódzkie', 'Burzenin', 'To starorzecze wyróżnia się silnym zarastaniem i bagnistymi brzegami, co czyni je trudniejszym, ale i bardziej dzikim łowiskiem, idealnym dla poszukiwaczy przygód. Dno jest głęboko muliste, idealne dla gatunków preferujących takie środowisko i bogate w substancje odżywcze. Rozległe pasy trzcin i grążeli utrudniają dostęp do wody, ale jednocześnie stanowią doskonałe kryjówki dla ryb i miejsca do zasadzek. Wędkowanie wymaga użycia wodoodpornych spodni i umiejętności precyzyjnego zarzucania w wąskie okna w roślinności. Dominują tu karasie pospolite, liny oraz wzdręgi, które osiągają imponujące rozmiary. Mimo trudności, to miejsce oferuje niezapomniane wrażenia dla wędkarzy ceniących sobie spokój i obfitość naturalnego środowiska. W cieplejszych miesiącach ryzyko przyduchy jest podwyższone, co należy mieć na uwadze.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22342, 1.8, 1.5, 3, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22343, 'Starorzecze (Burzenin)', 'starorzecze-burzenin-burzenin-22343', 'OXBOW', 51.4470296, 18.8254603, 'Łódzkie', 'Burzenin', 'To jedno z głębszych starorzeczy w rejonie Burzenina, co czyni je atrakcyjnym dla wędkarzy poszukujących większych ryb i drapieżników. Dno jest zróżnicowane, z twardszymi partiami i miejscami pokrytymi grubszym osadem, tworząc bogate siedliska. Brzegi są dobrze dostępne, z nielicznymi zaroślami, co ułatwia swobodne poruszanie się i znalezienie dogodnego stanowiska. Umiarkowana roślinność podwodna sprzyja drapieżnikom, takim jak szczupak i okoń, które często patrolują głębsze partie zbiornika w poszukiwaniu pokarmu. Można tu również liczyć na obfite połowy leszczy i płoci, a także spotkać suma. Brak stałego połączenia z rzeką, lecz woda w czasie przyborów odświeża akwen, co pozytywnie wpływa na kondycję ryb. Łowisko to jest cenione za potencjał na rekordowe okazy i stabilne warunki wodne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22343, 2.8, 2.5, 5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Sum', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22344, 'Starorzecze (Majaczewice)', 'starorzecze-majaczewice-majaczewice-22344', 'OXBOW', 51.4456931, 18.8234223, 'Łódzkie', 'Majaczewice', 'To rozległe starorzecze w pobliżu Majaczewic oferuje doskonałe warunki do wędkowania dla szerokiego grona wędkarzy, zarówno początkujących, jak i doświadczonych. Dno jest przeważnie piaszczysto-muliste, z czystymi fragmentami, co ułatwia prowadzenie przynęt i pozwala na różnorodne techniki. Brzegi są dobrze utrzymane i łatwo dostępne z wielu stron, co sprzyja zarówno spinningistom, jak i wędkarzom spławikowym. Roślinność wodna jest obecna, ale nie utrudnia znacząco łowienia, tworząc idealne miejsca do zasadzek drapieżników. W starorzeczu tym można złowić dorodne płocie, leszcze, liny, a także spotkać okazałe karpie i szczupaki. Regularne połączenie z rzeką podczas wyższych stanów wody zapewnia stały dopływ świeżej wody i różnorodność gatunkową. Jest to łowisko o dużej presji wędkarskiej, ale wciąż bardzo rybne i atrakcyjne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22344, 3.2, 2.2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Lin,Karp,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22345, 'Starorzecze (Burzenin)', 'starorzecze-burzenin-burzenin-22345', 'OXBOW', 51.4629707, 18.8385446, 'Łódzkie', 'Burzenin', 'To starorzecze, położone w bardziej dzikiej i odizolowanej części okolic Burzenina, charakteryzuje się brakiem stałego połączenia z rzeką, co nadaje mu unikalny charakter. Dno jest silnie zamulone, a brzegi są bagniste i gęsto zarośnięte, co wymaga od wędkarzy determinacji i użycia wodoodpornych spodni. Dominująca roślinność wodna, w tym trzciny i grążele, tworzy labirynt idealnych kryjówek dla ryb, ale także liczne zaczepy. Wędkowanie jest tu wyzwaniem, ale nagrodą mogą być piękne okazy karasi pospolitych, linów i wzdręg, które doskonale czują się w tym środowisku. Ze względu na ograniczoną wymianę wody, ryzyko przyduchy w upalne lato jest wysokie, co należy wziąć pod uwagę planując zasiadkę. To miejsce dla tych, którzy cenią sobie spokój i obcowanie z nieskażoną naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22345, 1.9, 1.7, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22346, 'Starorzecze (Burzenin)', 'starorzecze-burzenin-burzenin-22346', 'OXBOW', 51.4642038, 18.8398582, 'Łódzkie', 'Burzenin', 'To starorzecze wyróżnia się stałym połączeniem z głównym nurtem rzeki, co zapewnia doskonałą jakość wody i bogactwo gatunkowe, niespotykane w innych akwenach. Dno jest zróżnicowane, z twardszymi partiami żwiru i piasku, przeplatanymi miejscami z mulistym osadem, co tworzy idealne siedliska. Brzegi są w większości łatwo dostępne, z naturalnymi stanowiskami wędkarskimi i umiarkowaną ilością roślinności, ułatwiającymi poruszanie się. Dzięki stałemu przepływowi wody, zbiornik jest domem dla wielu gatunków, w tym dużych szczupaków, okoni, leszczy, płoci, a także jazi i kleni. Wędkowanie jest tu bardzo urozmaicone i satysfakcjonujące przez cały rok, oferując szansę na złowienie naprawdę dużych okazów. Jest to jedno z najbardziej cenionych łowisk w regionie ze względu na stabilne warunki i obfitość ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22346, 4, 2.8, 5.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Jaź,Kleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22347, 'Starorzecze (Majaczewice)', 'starorzecze-majaczewice-majaczewice-22347', 'OXBOW', 51.445215, 18.8243371, 'Łódzkie', 'Majaczewice', 'To starorzecze, położone w sąsiedztwie Majaczewic, stanowi atrakcyjne łowisko o średniej wielkości, idealne na rodzinne wyprawy wędkarskie. Dno jest przeważnie piaszczysto-muliste, z nielicznymi zaczepami, co sprzyja różnym technikom wędkarskim i minimalizuje ryzyko utraty sprzętu. Brzegi są dobrze dostępne, z miejscami porośniętymi trawą i pojedynczymi krzewami, oferując komfortowe stanowiska i cień w upalne dni. Roślinność podwodna jest umiarkowana, co pozwala na swobodne prowadzenie przynęt, jednocześnie zapewniając rybom schronienie i miejsca do żerowania. W starorzeczu tym dominują płocie, leszcze i liny, ale można również natknąć się na okazałe karasie pospolite i szczupaki. Połączenie z rzeką podczas wysokiej wody odświeża zbiornik, utrzymując dobrą kondycję ryb. Jest to łowisko idealne na spokojne popołudniowe zasiadki, z dużym potencjałem na udane połowy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22347, 2.9, 2, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Lin,Karaś pospolity,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22348, 'Starorzecze (Burzenin)', 'starorzecze-burzenin-burzenin-22348', 'OXBOW', 51.4525303, 18.8303555, 'Łódzkie', 'Burzenin', 'To starorzecze w Burzeninie to średniej wielkości akwen o typowym dla starorzeczy charakterze, z bogatą florą i fauną. Dno jest głównie muliste, z lokalnymi twardszymi fragmentami, co tworzy różnorodne siedliska dla ryb i bezkręgowców. Brzegi są w większości dostępne, choć miejscami występują pasy trzcin, które wymagają ostrożności i mogą stanowić wyzwanie dla wędkarzy. Roślinność wodna jest umiarkowana, co sprzyja zarówno rybom spokojnego żeru, jak i drapieżnikom, które znajdują tu obfitość pokarmu. Wędkowanie tutaj jest często nagradzane złowieniem płoci, leszczy, linów i okoni, a także okazjonalnie większych drapieżników. Połączenie z rzeką podczas wysokiej wody zapewnia regularną wymianę wody, jednak w cieplejsze okresy, przy braku opadów, może wystąpić ryzyko niedoboru tlenu. To dobre miejsce na relaksujące wędkowanie, oferujące spokój i kontakt z naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22348, 2.3, 1.9, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Lin,Okoń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22349, 'Starorzecze (Burzenin)', 'starorzecze-burzenin-burzenin-22349', 'OXBOW', 51.4528296, 18.8308548, 'Łódzkie', 'Burzenin', 'To starorzecze charakteryzuje się silnym zarastaniem i wysokim poziomem zamulenia, co czyni je wymagającym łowiskiem, ale jednocześnie bardzo obfitującym w ryby. Brzegi są trudno dostępne, gęsto porośnięte trzciną i inną roślinnością przybrzeżną, wymagającą brodzenia i cierpliwości. Dno jest głęboko muliste, idealne dla gatunków takich jak karaś pospolity i lin, które doskonale czują się w takich warunkach i osiągają tu imponujące rozmiary. Gęsta roślinność podwodna stanowi liczne zaczepy, co wymaga precyzji w zarzucaniu i prowadzeniu przynęty, ale jest też doskonałą kryjówką. Mimo trudności, wędkarze mogą liczyć na obfite połowy płoci i wzdręg. W upalne lato ryzyko przyduchy jest znaczące, dlatego najlepiej odwiedzać to miejsce w chłodniejszych porach roku. To idealne miejsce dla miłośników dzikiego wędkowania, ceniących sobie wyzwania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22349, 1.7, 1.6, 3, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22350, 'Starorzecze (Burzenin)', 'starorzecze-burzenin-burzenin-22350', 'OXBOW', 51.4530822, 18.8330505, 'Łódzkie', 'Burzenin', 'To starorzecze, położone w okolicach Burzenina, jest cenione przez wędkarzy karpiowych i tych szukających dużych leszczy, oferując im realne szanse na sukces. Dno jest zróżnicowane, z mulistymi zatokami i twardszymi fragmentami na otwartej wodzie, co tworzy różnorodne strefy żerowania. Brzegi są dobrze dostępne, z miejscami do rozstawienia sprzętu, choć lokalnie występują skupiska trzcin, które mogą służyć za naturalne schronienia. Umiarkowana roślinność podwodna zapewnia rybom kryjówki, a jednocześnie nie utrudnia zbytnio wędkowania, pozwalając na swobodne prowadzenie przynęt. Oprócz karpi i leszczy, można tu złowić piękne liny i płocie, a także okazowe szczupaki. Połączenie z rzeką podczas wysokiej wody odświeża akwen, zapewniając dobrą kondycję ryb i stały dopływ świeżej wody. Jest to łowisko o umiarkowanej presji, oferujące szansę na naprawdę satysfakcjonujące połowy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22350, 2.5, 2.1, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Leszcz,Lin,Płoć,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22351, 'Starorzecze (Burzenin)', 'starorzecze-burzenin-burzenin-22351', 'OXBOW', 51.4521689, 18.8296741, 'Łódzkie', 'Burzenin', 'To niewielkie i intymne starorzecze, ukryte wśród bujnej roślinności w pobliżu Burzenina, jest prawdziwą perełką dla miłośników dzikiej przyrody. Charakteryzuje się bardzo silnym zarastaniem brzegów trzciną i gęstą roślinnością podwodną, co sprawia, że dostęp do wody jest mocno utrudniony i wymaga przygotowania. Dno jest głęboko muliste, idealne dla gatunków preferujących spokojne i zarośnięte akweny, gdzie znajdują obfitość pokarmu. Wędkowanie wymaga użycia wodoodpornych spodni i precyzyjnego zarzucania w wąskie okna w roślinności, co stanowi dodatkowe wyzwanie. Dominują tu karasie pospolite, wzdręgi, liny i płocie, które osiągają tu często imponujące rozmiary. Ze względu na brak połączenia z rzeką, w upalne lato istnieje wysokie ryzyko przyduchy, dlatego najlepiej łowić tu w chłodniejszych miesiącach. To prawdziwa gratka dla miłośników dzikich, nieuciążliwych łowisk, ceniących sobie spokój i wyzwania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22351, 1.2, 1.5, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Lin,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22352, 'Starorzecze (Burzenin)', 'starorzecze-burzenin-burzenin-22352', 'OXBOW', 51.4556169, 18.8339731, 'Łódzkie', 'Burzenin', 'To jedno z większych starorzeczy w rejonie Burzenina, oferujące przestronne i otwarte tereny do wędkowania, idealne dla spinningistów i wędkarzy gruntowych. Dno jest przeważnie twarde, piaszczyste, z niewielką ilością mułu, co sprzyja różnorodnym technikom i ułatwia prowadzenie przynęt. Brzegi są łatwo dostępne, z naturalnymi miejscami do zasiadek, a roślinność przybrzeżna jest umiarkowana, nie utrudniając dostępu. Niskie zamulenie i umiarkowane zarastanie podwodne tworzą idealne warunki dla drapieżników, takich jak szczupak i okoń, które często patrolują otwarte wody w poszukiwaniu pokarmu. Można tu również liczyć na obfite połowy leszczy, płoci i karpi. Połączenie z rzeką podczas wysokiej wody zapewnia regularny dopływ świeżej wody i ryb, co utrzymuje ich dobrą kondycję. Jest to łowisko o dużym potencjale na rekordowe okazy i komfortowe warunki wędkowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22352, 3.5, 2.3, 4.8, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22353, 'Starorzecze (Borów)', 'starorzecze-borow-borow-22353', 'OXBOW', 51.2439598, 21.3860478, 'Lubelskie', 'Borów', 'To imponujące starorzecze, położone w Borowie, w malowniczym krajobrazie Lubelszczyzny, charakteryzuje się stałym połączeniem z Wisłą, co gwarantuje bogactwo gatunkowe. Dno jest zróżnicowane, z głębokimi rynnami i twardszymi, piaszczystymi blatami, co tworzy idealne warunki dla wielu gatunków ryb. Brzegi są w większości dobrze dostępne, choć w niektórych miejscach występują zwalone drzewa i krzewy, stanowiące doskonałe kryjówki dla ryb i miejsca do zasadzek. Niskie zamulenie i umiarkowana roślinność podwodna sprzyjają drapieżnikom, takim jak szczupak, sandacz i sum, które osiągają tu znaczne rozmiary. Wędkowanie jest tu bardzo urozmaicone, oferując szansę na złowienie dorodnych leszczy, płoci, a także boleni. To jedno z najbardziej cenionych starorzeczy w regionie, ze względu na bogactwo ryb i malownicze otoczenie, przyciągające wędkarzy z całej Polski.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22353, 5, 3, 6, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Sum,Leszcz,Płoć,Boleń', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22354, 'Starorzecze (Ceteń)', 'starorzecze-ceten-ceten-22354', 'OXBOW', 51.5352151, 20.5780447, 'Mazowieckie', 'Ceteń', 'To rozległe starorzecze, zlokalizowane w miejscowości Ceteń, jest dawnym korytem Pilicy, co wpływa na jego bogactwo ichtiofauny i różnorodność. Dno jest zróżnicowane, z głębszymi partiami i mieliznami, a także mulistymi i piaszczystymi fragmentami, tworząc idealne siedliska. Brzegi są w większości dobrze dostępne, z naturalnymi przesmykami i miejscami do wędkowania, choć lokalnie występują zarośla, stanowiące kryjówki. Umiarkowana roślinność podwodna stanowi idealne schronienia dla ryb i miejsca do zasadzek drapieżników, takich jak szczupak czy sandacz. W starorzeczu tym można złowić okazałe szczupaki, okonie i sandacze, a także liczyć na obfite połowy leszczy, płoci i jazi. Połączenie z Pilicą podczas wysokiej wody zapewnia regularne zarybienia naturalne i odświeżanie akwenu, co utrzymuje ryby w doskonałej kondycji. To łowisko o dużym potencjale, cenione przez wędkarzy za swoje walory.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22354, 4.5, 2.7, 5.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Sandacz,Leszcz,Płoć,Jaź', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22355, 'Starorzecze Niemczewo Północne', 'starorzecze-niemczewo-polnocne-bytow-22355', 'OXBOW', 54.3170063, 17.2290551, 'Pomorskie', 'Bytów', 'To malownicze starorzecze, położone w bliskim sąsiedztwie Bytowa, charakteryzuje się podłużnym kształtem i umiarkowaną powierzchnią, będąc pozostałością po dawnej rzece. Dno jest zróżnicowane, od mulistego w płytszych partiach po twardsze, piaszczysto-żwirowe w głębszych rynnach. Brzegi są częściowo dostępne, porośnięte trzciną i krzewami, co tworzy idealne kryjówki dla ryb. W wodach starorzecza dominują szczupaki, liny, płocie oraz okonie, które znajdują tu obfitość naturalnego pokarmu. Wędkowanie wymaga cierpliwości i często użycia pontonu lub brodzenia, aby dotrzeć do najlepszych miejsc. Ze względu na bogatą roślinność podwodną, zaleca się stosowanie przynęt odpornych na zaczepy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22355, 3.2, 2.1, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Płoć,Okoń,Leszcz', 'Dobry z jednej strony, druga zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22356, 'Starorzecze Niemczewo Południowe', 'starorzecze-niemczewo-poludniowe-bytow-22356', 'OXBOW', 54.3160038, 17.2305464, 'Pomorskie', 'Bytów', 'Mniejsze starorzecze, położone na południe od głównego zbiornika w Niemczewie, charakteryzuje się bardziej zamkniętym charakterem i mniejszą głębokością. Dno jest w większości muliste, z licznymi zatopionymi gałęziami i liśćmi, co sprzyja rozwojowi makrofauny dennej. Brzegi są gęsto porośnięte trzciną i roślinnością szuwarową, utrudniając dostęp, ale jednocześnie zapewniając schronienie dla ryb. Jest to idealne środowisko dla karasi pospolitych, linów i wzdręg, które doskonale czują się w zarośniętych wodach. Wędkowanie z brzegu jest wyzwaniem, często wymagającym brodzenia lub użycia niewielkiej łodzi. Ze względu na ryzyko przyduchy latem, najlepsze efekty daje wczesna wiosna i późna jesień.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22356, 1.8, 1.5, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, późna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22357, 'Starorzecze Ruda Południowe', 'starorzecze-ruda-poludniowe-rawa-mazowiecka-22357', 'OXBOW', 51.9857293, 20.2257429, 'Łódzkie', 'Rawa Mazowiecka', 'To starorzecze, położone w malowniczej okolicy Rudy koło Rawy Mazowieckiej, jest typowym przykładem zbiornika o charakterze silnie zarastającym. Dno jest w przeważającej części muliste, z licznymi osadami organicznymi, co sprzyja rozwojowi bogatej roślinności wodnej. Brzegi są bagniste i trudno dostępne, porośnięte gęstymi zaroślami, co stanowi wyzwanie dla wędkarzy. W starorzeczu królują liny, karasie pospolite oraz spore płocie, a także sporadycznie pojawiające się szczupaki. Wędkowanie najlepiej prowadzić z pomostów lub z brodzenia, z uwagi na trudny dostęp do wody. Wysokie ryzyko przyduchy w okresie letnim wymaga monitorowania warunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22357, 2.5, 1.2, 2.8, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22358, 'Starorzecze Grodzanów', 'starorzecze-grodzanow-zlotoryja-22358', 'OXBOW', 51.2523969, 16.5809823, 'Dolnośląskie', 'Złotoryja', 'Starorzecze Grodzanów to rozległy i głęboki zbiornik, będący pozostałością po meandrach dużej rzeki, położony w pobliżu Złotoryi. Dno jest zróżnicowane, z twardymi, żwirowymi odcinkami oraz głębokimi, mulistymi rynnami, co tworzy idealne warunki dla wielu gatunków ryb. Brzegi są stosunkowo łatwo dostępne, miejscami piaszczyste, a miejscami porośnięte drzewami i krzewami. W wodach starorzecza dominują duże leszcze, płocie, okonie oraz okazałe szczupaki, a także sandacze, które znajdują tu dogodne warunki do żerowania. Wędkowanie jest komfortowe, z możliwością zastosowania różnych technik, zarówno gruntowych, spławikowych, jak i spinningowych. Zbiornik jest ceniony za swoje zasoby rybne i malownicze otoczenie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22358, 5.8, 2.8, 5.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Sandacz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22359, 'Starorzecze Krzętów Zachodnie', 'starorzecze-krzetow-zachodnie-radomsko-22359', 'OXBOW', 51.011758, 19.8451347, 'Łódzkie', 'Radomsko', 'To starorzecze, położone w rejonie Krzętowa koło Radomska, charakteryzuje się dość głęboką rynną i umiarkowanym zarośnięciem, co czyni je atrakcyjnym łowiskiem. Dno jest mieszane, z przewagą mułu w zatokach i twardszym podłożem w głównym nurcie, co sprzyja różnorodności gatunkowej. Brzegi są miejscami strome, porośnięte starodrzewiem, co tworzy cień i schronienie dla ryb. W starorzeczu można spotkać szczupaki, leszcze, liny, karpie oraz sumy, które osiągają tu imponujące rozmiary. Wędkowanie z brzegu jest możliwe, ale wymaga ostrożności ze względu na liczne zaczepy i zwalone drzewa. Wiosna i jesień to najlepsze pory na drapieżniki, natomiast lato sprzyja białorybowi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22359, 4.5, 2.5, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Lin,Karp,Sum', 'Dobry, ale miejscami zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22360, 'Starorzecze Krzętów Wschodnie', 'starorzecze-krzetow-wschodnie-radomsko-22360', 'OXBOW', 51.0102196, 19.8591949, 'Łódzkie', 'Radomsko', 'Mniejsze, bardziej płytkie starorzecze wschodnie w Krzętowie, odznacza się dużą ilością roślinności podwodnej i mulistym dnem. To idealne miejsce dla ryb preferujących płytkie, ciepłe wody i obfitość naturalnego pokarmu. Brzegi są bardzo zarośnięte, co utrudnia dostęp, ale jednocześnie tworzy liczne kryjówki dla drobnicy i drapieżników. W starorzeczu dominują liny, karasie pospolite, wzdręgi oraz liczne płocie, a także mniejsze szczupaki. Wędkowanie wymaga precyzji i cierpliwości, często z użyciem delikatnych zestawów i naturalnych przynęt. Ze względu na silne zarośnięcie, wędkarze często korzystają z pontonów lub łodzi, aby dotrzeć do otwartych lusterek wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22360, 2.8, 1.4, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22361, 'Starorzecze Łukowa Zachodnie', 'starorzecze-lukowa-zachodnie-bilgoraj-22361', 'OXBOW', 50.3954066, 22.9600257, 'Lubelskie', 'Biłgoraj', 'To urokliwe starorzecze, położone w okolicach Łukowej w województwie lubelskim, jest przykładem zbiornika o stosunkowo czystej wodzie i piaszczystym dnie. Akwen charakteryzuje się licznymi płyciznami i głębszymi rynnami, co sprzyja różnorodności środowiskowej. Brzegi są częściowo dostępne, miejscami porośnięte trzciną, a miejscami otwarte, co ułatwia wędkowanie. W starorzeczu licznie występują liny, karasie pospolite, płocie oraz okonie, a także szczupaki, które polują w zaroślach. Wędkowanie jest przyjemne, z możliwością stosowania zarówno spławika, jak i lekkiego spinningu. Zbiornik jest idealny na rodzinne wypady, oferując spokój i kontakt z naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22361, 2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Płoć,Okoń,Szczupak', 'Dobry, ale miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22362, 'Starorzecze Łukowa Wschodnie', 'starorzecze-lukowa-wschodnie-bilgoraj-22362', 'OXBOW', 50.3949841, 22.9623849, 'Lubelskie', 'Biłgoraj', 'Starorzecze wschodnie w Łukowej to mniejszy, bardziej zaciszny zbiornik, który charakteryzuje się bogatą roślinnością zanurzoną i pływającą. Dno jest w przeważającej części muliste, z grubą warstwą osadów, co tworzy doskonałe środowisko dla ryb dennych. Brzegi są trudne do pokonania, gęsto porośnięte krzewami i drzewami, co utrudnia dostęp do wody. W starorzeczu dominują karasie pospolite i srebrzyste, wzdręgi oraz liny, które doskonale czują się w tak zarośniętych wodach. Wędkowanie jest wyzwaniem, wymagającym cierpliwości i umiejętności łowienia w trudnych warunkach, często z użyciem długich wędek lub delikatnych zestawów. Wskazane jest użycie pontonu dla lepszego dostępu do łowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22362, 1.5, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Karaś srebrzysty,Wzdręga,Lin', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22363, 'Starorzecze Ruda Północne', 'starorzecze-ruda-polnocne-rawa-mazowiecka-22363', 'OXBOW', 51.9914776, 20.2214766, 'Łódzkie', 'Rawa Mazowiecka', 'Północne starorzecze w Rudzie to zbiornik o umiarkowanej wielkości, charakteryzujący się stosunkowo czystą wodą i zróżnicowanym dnem. Występują tu zarówno piaszczyste płycizny, jak i głębsze partie z mulistym podłożem, co sprzyja różnorodności gatunkowej. Brzegi są częściowo dostępne, z licznymi zatoczkami i miejscami porośniętymi trzciną, co tworzy dogodne warunki do wędkowania. W starorzeczu można liczyć na leszcze, płocie, okonie oraz szczupaki, które aktywnie żerują wzdłuż brzegów. Wędkowanie z brzegu jest wygodne, a w niektórych miejscach można również brodzić. Zbiornik jest popularny wśród wędkarzy szukających zarówno białorybu, jak i drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22363, 3, 1.8, 3.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22364, 'Starorzecze Ruda Środkowe', 'starorzecze-ruda-srodkowe-rawa-mazowiecka-22364', 'OXBOW', 51.9955743, 20.2218418, 'Łódzkie', 'Rawa Mazowiecka', 'To starorzecze, położone centralnie w kompleksie zbiorników w Rudzie, jest nieco głębsze od sąsiednich, co sprzyja występowaniu większych okazów ryb. Dno jest urozmaicone, z twardszymi partiami żwirowymi i mulistymi zagłębieniami, gdzie gromadzi się pokarm. Brzegi są miejscami strome, porośnięte olchami i wierzbami, co zapewnia cień i tworzy schronienie dla ryb. W wodach starorzecza dominują szczupaki, sandacze (szczególnie w głębszych partiach), leszcze i płocie. Wędkowanie jest atrakcyjne dla spinningistów i wędkarzy gruntowych, poszukujących większych ryb. Dostęp do wody jest dobry, choć miejscami wymaga przebrnięcia przez zarośla.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22364, 3.8, 2.2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Okoń', 'Dobry, ale miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22365, 'Starorzecze Ruda Wschodnie', 'starorzecze-ruda-wschodnie-rawa-mazowiecka-22365', 'OXBOW', 51.9964418, 20.222822, 'Łódzkie', 'Rawa Mazowiecka', 'Wschodnie starorzecze w Rudzie to niewielki, ale urokliwy zbiornik, charakteryzujący się bardzo gęstą roślinnością wodną i płytkimi brzegami. Dno jest w większości muliste, z grubą warstwą osadów, co jest typowe dla starorzeczy o ograniczonym przepływie. Brzegi są mocno zarośnięte trzciną i krzewami, co sprawia, że dostęp do wody jest utrudniony, ale jednocześnie tworzy doskonałe kryjówki dla ryb. W starorzeczu licznie występują liny, karasie pospolite, wzdręgi oraz małe okonie, które doskonale czują się w zaroślach. Wędkowanie wymaga cierpliwości i precyzji, często z użyciem długich wędek lub brodzenia. Ze względu na płytkość, w upalne lata może występować ryzyko przyduchy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22365, 1.7, 0.9, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22366, 'Starorzecze Ruda Zachodnie', 'starorzecze-ruda-zachodnie-rawa-mazowiecka-22366', 'OXBOW', 51.9982459, 20.2217672, 'Łódzkie', 'Rawa Mazowiecka', 'Zachodnie starorzecze w Rudzie to zbiornik o nieregularnym kształcie, charakteryzujący się umiarkowaną głębokością i zróżnicowanym dnem. Występują tu zarówno partie muliste, jak i twardsze, piaszczyste odcinki, co sprzyja różnym gatunkom ryb. Brzegi są częściowo dostępne, z licznymi zatoczkami i miejscami porośniętymi roślinnością szuwarową. W starorzeczu można spotkać leszcze, płocie, okonie oraz szczupaki, które aktywnie żerują wzdłuż zarośli. Wędkowanie jest komfortowe, zarówno z brzegu, jak i z pontonu, oferując dobre warunki dla wędkarzy spławikowych i spinningistów. Zbiornik jest ceniony za stabilne populacje ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22366, 2.9, 1.7, 3.3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Lin', 'Dobry z jednej strony, druga zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22367, 'Starorzecze Krzętów Centralne', 'starorzecze-krzetow-centralne-radomsko-22367', 'OXBOW', 51.0066137, 19.8548827, 'Łódzkie', 'Radomsko', 'To centralnie położone starorzecze w Krzętowie jest jednym z większych i głębszych zbiorników w okolicy, co sprzyja występowaniu dużych okazów ryb. Dno jest zróżnicowane, z głębokimi rynnami i mulistymi zatokami, a także twardszymi, piaszczystymi fragmentami. Brzegi są dobrze utrzymane, z licznymi miejscami do wędkowania, choć miejscami porośnięte drzewami i krzewami. W starorzeczu dominują szczupaki, sandacze, sumy, karpie oraz duże leszcze, które przyciągają wędkarzy z całej okolicy. Wędkowanie jest bardzo atrakcyjne, zarówno dla miłośników drapieżników, jak i białorybu. Zbiornik jest znany z obfitości i różnorodności rybostanu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22367, 7, 3, 6, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Sum,Karp,Leszcz', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22368, 'Starorzecze Krzętów Północne', 'starorzecze-krzetow-polnocne-radomsko-22368', 'OXBOW', 51.0112886, 19.860196, 'Łódzkie', 'Radomsko', 'Północne starorzecze w Krzętowie to zbiornik o wydłużonym kształcie, charakteryzujący się umiarkowaną głębokością i zróżnicowanym dnem. Występują tu zarówno piaszczyste płycizny, jak i głębsze partie z mulistym podłożem, co sprzyja różnorodności gatunkowej. Brzegi są częściowo dostępne, z licznymi zatoczkami i miejscami porośniętymi trzciną, co tworzy dogodne warunki do wędkowania. W starorzeczu można liczyć na leszcze, płocie, okonie oraz szczupaki, które aktywnie żerują wzdłuż brzegów. Wędkowanie z brzegu jest wygodne, a w niektórych miejscach można również brodzić. Zbiornik jest popularny wśród wędkarzy szukających zarówno białorybu, jak i drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22368, 4, 2.3, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Lin', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22369, 'Starorzecze Krzętów Południowe', 'starorzecze-krzetow-poludniowe-radomsko-22369', 'OXBOW', 51.0110717, 19.8595483, 'Łódzkie', 'Radomsko', 'Południowe starorzecze w Krzętowie to mniejszy, bardziej zaciszny zbiornik, który charakteryzuje się bogatą roślinnością zanurzoną i pływającą. Dno jest w przeważającej części muliste, z grubą warstwą osadów, co tworzy doskonałe środowisko dla ryb dennych. Brzegi są trudne do pokonania, gęsto porośnięte krzewami i drzewami, co utrudnia dostęp do wody. W starorzeczu dominują karasie pospolite i srebrzyste, wzdręgi oraz liny, które doskonale czują się w tak zarośniętych wodach. Wędkowanie jest wyzwaniem, wymagającym cierpliwości i umiejętności łowienia w trudnych warunkach, często z użyciem długich wędek lub delikatnych zestawów. Wskazane jest użycie pontonu dla lepszego dostępu do łowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22369, 3.5, 1.6, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Karaś srebrzysty,Wzdręga,Lin', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22370, 'Starorzecze Borów I', 'starorzecze-borow-i-borow-22370', 'OXBOW', 50.7828653, 21.9274723, 'Lubelskie', 'Borów', 'To starorzecze, położone w malowniczej okolicy Borowa w województwie lubelskim, jest typowym łowiskiem o zmiennym charakterze. Dno jest muliste, z miejscowymi twardszymi partiami, co sprzyja bytowania różnorodnych gatunków ryb. Brzegi są częściowo dostępne, zwłaszcza od strony pól, jednak w wielu miejscach porastają je gęste zarośla i trzciny, utrudniające dostęp do wody. Roślinność podwodna jest umiarkowana, tworząc dobre kryjówki dla drapieżników. W starorzeczu dominują szczupaki, liny, karasie pospolite, płocie oraz okonie, co czyni je atrakcyjnym dla wędkarzy preferujących różne metody połowu. Wiosna i jesień to najlepsze pory na wędkowanie, zwłaszcza gdy poziom wody jest stabilny.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22370, 3.2, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć,Okoń', 'Dobry z jednej strony, reszta zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22371, 'Starorzecze Borów II', 'starorzecze-borow-ii-borow-22371', 'OXBOW', 50.7847175, 21.9266349, 'Lubelskie', 'Borów', 'Drugie starorzecze w Borowie charakteryzuje się bardziej zarośniętymi brzegami i dnem pokrytym grubą warstwą mułu. Jest to idealne środowisko dla gatunków preferujących spokojne, ciepłe wody. Roślinność podwodna jest bardzo bujna, tworząc gęste dywany i podwodne łąki, co utrudnia wędkowanie, ale zapewnia doskonałe schronienie dla ryb. Połączenie z rzeką macierzystą jest sporadyczne, tylko przy bardzo wysokich stanach wody, co sprzyja stabilizacji ekosystemu. Występują tu głównie liny, karasie pospolite i srebrzyste, wzdręgi oraz sumy, co przyciąga wędkarzy poszukujących ryb spokojnego żeru. Wymaga to cierpliwości i często użycia brodzenia, aby dotrzeć do najlepszych miejscówek.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22371, 2.5, 1.5, 3.2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Karaś srebrzysty,Wzdręga,Sum', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22372, 'Starorzecze Borów III', 'starorzecze-borow-iii-borow-22372', 'OXBOW', 50.7836871, 21.9264796, 'Lubelskie', 'Borów', 'To starorzecze, choć niewielkie, jest cennym miejscem dla wędkarzy ceniących ciszę i obfitość ryb. Charakteryzuje się dość głębokim dnem jak na starorzecze, z wyraźnymi rynnami i zatopionymi drzewami, które stanowią kryjówki dla dużych drapieżników. Brzegi są zróżnicowane – od łatwo dostępnych, trawiastych, po te porośnięte gęstymi krzewami i trzcinami. Brak stałego połączenia z rzeką sprawia, że woda jest tu zazwyczaj czystsza, ale jednocześnie bardziej podatna na wahania poziomu tlenu latem. Dominujące gatunki to szczupaki, okonie, leszcze i płocie, co oferuje różnorodne możliwości połowu. Wędkowanie tutaj jest najbardziej efektywne w chłodniejszych miesiącach, gdy ryby są bardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22372, 1.9, 2.2, 4.5, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z jednej strony, zarośnięty z drugiej', FALSE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22373, 'Starorzecze Wiślica', 'starorzecze-wislica-wislica-22373', 'OXBOW', 50.345409, 20.6767208, 'Świętokrzyskie', 'Wiślica', 'Starorzecze w Wiślicy to rozległe i płytkie łowisko, silnie zarośnięte roślinnością wodną i przybrzeżną. Dno jest w większości muliste, ale miejscami można znaleźć twardsze, piaszczyste plamy, szczególnie w głębszych rynnach. Brzegi są trudno dostępne, bagniste i mocno porośnięte trzciną, co sprawia, że wędkowanie z brzegu jest wyzwaniem. Połączenie z rzeką Nida następuje jedynie podczas wysokich stanów wody, co wzbogaca populację ryb. Występuje tu bogactwo karasi pospolitych i srebrzystych, płoci, linów i wzdręg, a także sporadycznie większych karpi. Jest to idealne miejsce dla wędkarzy ceniących spokój i poszukujących ryb spokojnego żeru, choć wymaga cierpliwości i odpowiedniego sprzętu, takiego jak brodzenie czy ponton.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22373, 12, 1.2, 2.8, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Karaś srebrzysty,Płoć,Lin,Karp', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna i pojedyncze konary', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22374, 'Starorzecze Antoniówka Świerżowska', 'starorzecze-antoniowka-swierzowska-antoniowka-swierzowska-22374', 'OXBOW', 51.6764963, 21.4854747, 'Mazowieckie', 'Antoniówka Świerżowska', 'To starorzecze, położone w pobliżu Antoniówki Świerżowskiej, jest stosunkowo niewielkim, ale głębokim zbiornikiem. Charakteryzuje się zróżnicowanym dnem, gdzie muliste partie przeplatają się z twardszymi, piaszczystymi obszarami, a także licznymi zatopionymi drzewami i korzeniami. Brzegi są umiarkowanie dostępne, z miejscowymi zaroślami, które jednak nie utrudniają znacząco dostępu do wody. Brak bezpośredniego połączenia z rzeką sprawia, że woda jest stabilna, ale wymaga monitorowania poziomu tlenu w upalne lata. Jest to doskonałe łowisko dla drapieżników, takich jak szczupak, okoń i sandacz, ale znajdziemy tu również dorodne płocie i leszcze. Wędkarze powinni przygotować się na trudności z zaczepami, które jednak często wskazują na obecność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22374, 4.5, 2.5, 5.5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Sandacz,Płoć,Leszcz', 'Umiarkowany, miejscowo zarośnięty', FALSE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22375, 'Starorzecze Ziemiary I', 'starorzecze-ziemiary-i-ziemiary-22375', 'OXBOW', 52.0296699, 20.1996358, 'Mazowieckie', 'Ziemiary', 'Pierwsze starorzecze w Ziemiarach to typowe, płytkie i silnie zarośnięte łowisko, idealne dla gatunków ciepłolubnych. Dno jest niemal w całości pokryte grubą warstwą mułu, co sprzyja rozwojowi bujnej roślinności podwodnej. Brzegi są bardzo trudne do pokonania, gęsto porośnięte trzciną i krzewami, wymagające użycia brodzenia lub pontonu. Połączenie z Wisłą następuje jedynie podczas wysokich wód, co sezonowo zasila akwen w nowe populacje ryb. Dominują tu liny, karasie pospolite, wzdręgi i płocie, które doskonale czują się w tym środowisku. Wędkarstwo w tym miejscu wymaga cierpliwości i umiejętności łowienia w zarośniętych wodach, ale nagrodą mogą być piękne okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22375, 2.8, 1, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22376, 'Starorzecze Ziemiary II', 'starorzecze-ziemiary-ii-ziemiary-22376', 'OXBOW', 52.0292697, 20.1989832, 'Mazowieckie', 'Ziemiary', 'To starorzecze, sąsiadujące z Ziemiarami, charakteryzuje się nieco większą głębokością i bardziej zróżnicowanym dnem. Oprócz mulistych partii, można znaleźć tu miejsca z twardszym podłożem, co sprzyja różnorodności gatunkowej. Brzegi są dostępne w kilku punktach, jednak w większości porośnięte są gęstymi zaroślami. Brak stałego połączenia z rzeką sprawia, że jest to spokojne łowisko, jednak w upalne lata istnieje ryzyko niedoboru tlenu. Występują tu szczupaki, okonie, leszcze, płocie oraz karpie, co czyni je atrakcyjnym dla wędkarzy preferujących różne metody. Wędkowanie jest najbardziej owocne wiosną i jesienią, gdy ryby są aktywne i żerują bliżej brzegu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22376, 3.5, 1.7, 3.8, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Umiarkowany, miejscowo zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22377, 'Starorzecze Bartniki I', 'starorzecze-bartniki-i-bartniki-22377', 'OXBOW', 52.0278155, 20.1999853, 'Mazowieckie', 'Bartniki', 'Starorzecze w Bartnikach to malownicze łowisko o umiarkowanej głębokości, z dnem pokrytym mieszanką mułu i piasku. Charakteryzuje się licznymi zatopionymi drzewami i gałęziami, które stanowią doskonałe kryjówki dla drapieżników. Brzegi są dość dobrze dostępne, z kilkoma dogodnymi stanowiskami wędkarskimi, choć miejscami występują zarośla. Połączenie z rzeką macierzystą jest nieregularne, co pomaga w utrzymaniu stabilnej populacji ryb. Głównymi gatunkami są szczupaki, sandacze, okonie, leszcze i płocie, co przyciąga zarówno spinningistów, jak i wędkarzy gruntowych. Najlepsze efekty można osiągnąć wczesną wiosną i późną jesienią, kiedy drapieżniki są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22377, 5, 2, 4.2, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Okoń,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22378, 'Starorzecze Bartniki II', 'starorzecze-bartniki-ii-bartniki-22378', 'OXBOW', 52.0252247, 20.201949, 'Mazowieckie', 'Bartniki', 'Drugie starorzecze w Bartnikach jest mniejsze i bardziej kameralne, z dnem typowo mulistym i bogatą roślinnością przybrzeżną. Jest to idealne środowisko dla ryb spokojnego żeru, które znajdują tu obfitość pokarmu i schronienia. Brzegi są trudno dostępne, gęsto zarośnięte trzciną i krzewami, co wymaga cierpliwości i często brodzenia, aby dotrzeć do wody. Brak połączenia z rzeką oznacza, że zbiornik jest bardziej stabilny, ale w upalne lata może cierpieć na niedobór tlenu. Dominują tu liny, karasie pospolite i srebrzyste, wzdręgi oraz płocie, które osiągają tu imponujące rozmiary. Wędkarze powinni przygotować się na łowienie w trudnych warunkach, ale nagrodą mogą być piękne, zdrowe ryby.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22378, 1.7, 1.3, 2.9, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22379, 'Starorzecze Ziemiary III', 'starorzecze-ziemiary-iii-ziemiary-22379', 'OXBOW', 52.0350376, 20.2028711, 'Mazowieckie', 'Ziemiary', 'To starorzecze w Ziemiarach charakteryzuje się wydłużonym kształtem i umiarkowaną głębokością, z dnem częściowo mulistym, a częściowo twardym. Brzegi są zróżnicowane, oferując zarówno łatwo dostępne miejsca, jak i te gęsto porośnięte krzewami i trzcinami. Połączenie z Wisłą jest sporadyczne, co sprzyja rozwojowi stabilnej populacji ryb, ale jednocześnie ogranicza napływ nowych okazów. Występują tu głównie leszcze, płocie, karpie, a także szczupaki i okonie, co czyni je atrakcyjnym dla wędkarzy preferujących różnorodne metody. Wędkowanie jest najbardziej efektywne w okresie od wiosny do jesieni, z uwzględnieniem aktywności poszczególnych gatunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22379, 6, 2.1, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Szczupak,Okoń', 'Umiarkowany, miejscowo zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22380, 'Starorzecze Ziemiary IV', 'starorzecze-ziemiary-iv-ziemiary-22380', 'OXBOW', 52.0353873, 20.2025058, 'Mazowieckie', 'Ziemiary', 'Starorzecze Ziemiary IV to płytki, silnie zarośnięty zbiornik, który jest rajem dla ryb preferujących ciepłe i spokojne wody. Dno jest niemal w całości pokryte grubą warstwą mułu i bujną roślinnością podwodną, co stanowi wyzwanie dla wędkarzy. Brzegi są trudno dostępne, mocno zarośnięte trzciną i krzewami, wymagające użycia brodzenia. Brak stałego połączenia z rzeką sprawia, że woda jest tu zazwyczaj cieplejsza, ale latem istnieje wysokie ryzyko niedoboru tlenu. Dominują tu liny, karasie pospolite, wzdręgi i płocie, które doskonale adaptują się do tych warunków. Wędkowanie jest najbardziej efektywne w ciepłych miesiącach, jednak wymaga precyzji i umiejętności łowienia w zaroślach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22380, 2.1, 0.9, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22381, 'Starorzecze Ziemiary V', 'starorzecze-ziemiary-v-ziemiary-22381', 'OXBOW', 52.0355795, 20.202081, 'Mazowieckie', 'Ziemiary', 'Ostatnie starorzecze w Ziemiarach jest średniej wielkości zbiornikiem o zróżnicowanym charakterze. Dno jest mozaiką mulistych osadów i twardszych, piaszczystych fragmentów, co sprzyja różnorodności fauny dennej. Brzegi są umiarkowanie dostępne, z miejscowymi zaroślami, które jednak nie stanowią większej przeszkody dla wędkarzy. Połączenie z Wisłą jest sporadyczne, co wpływa na zasilanie akwenu w nowe gatunki ryb. Występują tu szczupaki, okonie, leszcze, płocie oraz karpie, co oferuje szerokie spektrum możliwości połowowych. Wędkarze mogą liczyć na udane połowy przez większą część sezonu, z najlepszymi wynikami wiosną i jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22381, 3.8, 1.9, 4.1, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Umiarkowany, miejscowo zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22382, 'Starorzecze Kępa Radwankowska', 'starorzecze-kepa-radwankowska-kepa-radwankowska-22382', 'OXBOW', 51.9656066, 21.2734429, 'Mazowieckie', 'Kępa Radwankowska', 'Starorzecze w Kępie Radwankowskiej to rozległy i głęboki zbiornik, charakteryzujący się czystą wodą i zróżnicowanym dnem. Obok mulistych osadów, można tu znaleźć piaszczyste i żwirowe partie, a także liczne podwodne górki i rowy. Brzegi są w większości łatwo dostępne, z kilkoma dogodnymi stanowiskami, choć miejscami występują gęste zarośla. Stałe połączenie z Wisłą zapewnia regularne zasilanie w świeżą wodę i migrację ryb, co sprzyja bogactwu gatunkowemu. Występują tu sandacze, szczupaki, sumy, leszcze, płocie i bolenie, co czyni je atrakcyjnym dla wędkarzy szukających dużych okazów. Jest to łowisko wymagające, ale oferujące szansę na naprawdę imponujące zdobycze.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22382, 15, 3, 6, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sandacz,Szczupak,Sum,Leszcz,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22383, 'Starorzecze Czersk I', 'starorzecze-czersk-i-czersk-22383', 'OXBOW', 51.9691397, 21.2692286, 'Mazowieckie', 'Czersk', 'Pierwsze starorzecze w Czersku to zbiornik o umiarkowanej wielkości i głębokości, z dnem pokrytym głównie mułem i licznymi zatopionymi gałęziami. Charakteryzuje się dość gęstą roślinnością podwodną, która stanowi doskonałe schronienie dla ryb, ale utrudnia wędkowanie. Brzegi są częściowo dostępne, z miejscowymi zaroślami i trzcinami. Połączenie z Wisłą następuje jedynie podczas wysokich stanów wody, co sezonowo wzbogaca populację ryb. Dominują tu szczupaki, okonie, liny, karasie pospolite i płocie, co oferuje różnorodne możliwości połowowe. Wędkarze powinni przygotować się na łowienie w zaroślach, co wymaga precyzji i cierpliwości, ale może przynieść satysfakcjonujące rezultaty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22383, 4, 1.6, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Lin,Karaś pospolity,Płoć', 'Umiarkowany, miejscowo zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie, gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22384, 'Starorzecze Czersk II', 'starorzecze-czersk-ii-czersk-22384', 'OXBOW', 51.9694071, 21.2694751, 'Mazowieckie', 'Czersk', 'Drugie starorzecze w Czersku to mniejszy, ale głębszy zbiornik, z dnem zróżnicowanym – od mulistego po twardsze, piaszczyste fragmenty. Charakteryzuje się obecnością zatopionych drzew i krzewów, które tworzą doskonałe kryjówki dla drapieżników. Brzegi są dobrze dostępne z jednej strony, natomiast z drugiej mocno zarośnięte trzciną, co wymaga znalezienia odpowiednich stanowisk. Brak stałego połączenia z rzeką sprawia, że woda jest tu zazwyczaj czysta, ale w upalne lata może dojść do spadku poziomu tlenu. Występują tu szczupaki, okonie, leszcze, płocie i karpie, co przyciąga zarówno spinningistów, jak i wędkarzy gruntowych. Wędkarstwo jest najbardziej efektywne w chłodniejszych miesiącach, gdy ryby intensywnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22384, 2.3, 2, 4.3, 'Brak', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry z jednej strony, mocno zarośnięty trzciną z drugiej', FALSE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22385, 'Starorzecze Czerskie I', 'starorzecze-czerskie-i-czersk-22385', 'OXBOW', 51.9663751, 21.2728582, 'Mazowieckie', 'Czersk', 'To malownicze starorzecze, położone w pobliżu Czerska, charakteryzuje się typowym dla Wisły, mulistym dnem. Brzegi są częściowo dostępne, lecz w wielu miejscach porastają je gęste trzcinowiska i krzewy, utrudniające dostęp do wody. Roślinność podwodna jest umiarkowana, co sprzyja rozwojowi wielu gatunków ryb. Można tu z powodzeniem łowić szczupaki, liny, karasie pospolite, płocie oraz leszcze. Należy jednak uważać na ryzyko przyduchy w okresie letnim, zwłaszcza po obfitych opadach deszczu. Dostęp do niektórych stanowisk wymaga użycia brodów, a na dnie sporadycznie występują zatopione gałęzie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22385, 3.2, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć,Leszcz', 'Dobry z jednej strony, reszta zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22386, 'Starorzecze Czerskie II', 'starorzecze-czerskie-ii-czersk-22386', 'OXBOW', 51.9667213, 21.2713484, 'Mazowieckie', 'Czersk', 'To niewielkie, silnie zarastające starorzecze koło Czerska to prawdziwy raj dla wędkarzy ceniących dzikie łowiska. Dno jest bardzo muliste i płytkie, co sprzyja intensywnemu rozwojowi roślinności wodnej, tworząc idealne schronienia dla ryb. Brzegi są trudno dostępne, często bagniste i porośnięte gęstymi krzewami oraz trzcinami, wymagającymi użycia brodów. Dominującymi gatunkami są tu liny, karasie pospolite, wzdręgi i płocie, które doskonale czują się w tym środowisku. Ze względu na silne zarastanie i niewielką głębokość, istnieje wysokie ryzyko przyduchy, zwłaszcza w upalne dni. Wędkowanie tutaj to wyzwanie, ale nagrodą są piękne okazy ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22386, 2.8, 1.5, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22387, 'Starorzecze Czerskie III', 'starorzecze-czerskie-iii-czersk-22387', 'OXBOW', 51.9673648, 21.2705486, 'Mazowieckie', 'Czersk', 'To jedno z bardziej dostępnych starorzeczy w okolicy Czerska, idealne dla rodzinnego wędkowania. Charakteryzuje się stosunkowo czystym dnem i umiarkowaną ilością roślinności podwodnej, co ułatwia prowadzenie przynęt. Brzegi są dobrze dostępne, miejscami nawet utwardzone, co pozwala na komfortowe wędkowanie bez potrzeby użycia brodów. Starorzecze to ma połączenie z Wisłą podczas wysokiej wody, co zapewnia regularne zarybianie i różnorodność gatunkową. Dominują tu szczupaki, okonie, leszcze, płocie oraz karpie. Ryzyko przyduchy jest niskie dzięki większej głębokości i lepszemu przepływowi wody. Jest to doskonałe miejsce na relaksujący dzień nad wodą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22387, 4.1, 2, 4.2, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry, miejscami utwardzony', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22388, 'Starorzecze Czerskie IV', 'starorzecze-czerskie-iv-czersk-22388', 'OXBOW', 51.9677642, 21.270122, 'Mazowieckie', 'Czersk', 'To niewielkie i bardzo płytkie starorzecze w pobliżu Czerska, które w okresach suszy potrafi całkowicie wyschnąć. Dno jest silnie zamulone, a cała powierzchnia wody gęsto porośnięta roślinnością wodną, co czyni je trudnym łowiskiem. Brzegi są praktycznie niedostępne bez brodów, otoczone gęstymi trzcinowiskami. Mimo tych trudności, jest to ostaniec dla karasia pospolitego, wzdręgi i płoci, które doskonale radzą sobie w tak ekstremalnych warunkach. Ryzyko przyduchy jest bardzo wysokie, dlatego najlepiej wędkować tu wczesną wiosną, gdy poziom wody jest wyższy, a temperatura niższa. Wędkowanie tutaj to prawdziwe wyzwanie, ale może przynieść satysfakcjonujące rezultaty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22388, 1.9, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22389, 'Starorzecze Kępa Radwankowska I', 'starorzecze-kepa-radwankowska-i-kepa-radwankowska-22389', 'OXBOW', 51.9643905, 21.2769757, 'Mazowieckie', 'Kępa Radwankowska', 'To rozległe starorzecze w okolicy Kępy Radwankowskiej utrzymuje stałe połączenie z Wisłą, co zapewnia ciągły dopływ świeżej wody i ryb. Dno jest zróżnicowane, od piaszczystego po lekko muliste, z minimalnym zamuleniem. Roślinność podwodna jest słaba, co ułatwia wędkowanie spinningowe i gruntowe. Brzegi są w większości łatwo dostępne z obu stron, bez konieczności użycia brodów. Jest to idealne miejsce dla wędkarzy poszukujących szczupaków, boleni, jazi, leszczy i płoci. Dzięki stałemu połączeniu z rzeką, ryzyko przyduchy jest praktycznie zerowe. To jedno z najbardziej atrakcyjnych łowisk w regionie, oferujące doskonałe warunki przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22389, 5.5, 2.2, 4.8, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Boleń,Jaź,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22390, 'Starorzecze Kępa Radwankowska II', 'starorzecze-kepa-radwankowska-ii-kepa-radwankowska-22390', 'OXBOW', 51.9648074, 21.2756894, 'Mazowieckie', 'Kępa Radwankowska', 'To starorzecze w Kępie Radwankowskiej, choć mniejsze, oferuje ciekawe wyzwania wędkarskie. Jego dno jest muliste, a woda w nim osiąga średnią głębokość, z maksymalnymi dołkami do 3.2 metra. Brzegi są miejscami trudno dostępne, zarośnięte krzewami i pojedynczymi drzewami, co utrudnia swobodne poruszanie się. W zbiorniku tym występuje sporo zatopionych drzew i gałęzi, stanowiących doskonałe kryjówki dla ryb, ale również potencjalne zaczepy. Starorzecze łączy się z rzeką tylko podczas wysokich stanów wody. Można tu liczyć na liny, karpie, leszcze, płocie i okonie, jednak trzeba być przygotowanym na częste zaczepy. Wymagane są brody ze względu na bagniste odcinki brzegu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22390, 3.8, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karp,Leszcz,Płoć,Okoń', 'Trudny, miejscami zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22391, 'Starorzecze Brzumin', 'starorzecze-brzumin-brzumin-22391', 'OXBOW', 51.9431787, 21.2528947, 'Mazowieckie', 'Brzumin', 'Starorzecze Brzumin to duży i głęboki zbiornik, cieszący się stałym połączeniem z Wisłą, co gwarantuje bogactwo ichtiofauny. Dno jest zróżnicowane, z przewagą piasku i żwiru, a zamulenie jest minimalne. Roślinność wodna występuje sporadycznie, głównie w płytszych zatoczkach, co sprzyja różnym technikom wędkowania. Brzegi są łatwo dostępne z obu stron, często piaszczyste, idealne do rozstawienia sprzętu. Jest to doskonałe miejsce na połów szczupaków, sandaczy, dużych leszczy, płoci oraz węgorzy. Dzięki głębokości i stałemu przepływowi wody, ryzyko przyduchy jest bardzo niskie. Wędkarze cenią to miejsce za jego potencjał i komfortowe warunki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22391, 6, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Węgorz', 'Dobry z obu stron, miejscami piaszczysty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22392, 'Starorzecze Chałupy I', 'starorzecze-chalupy-i-chalupy-22392', 'OXBOW', 51.0477568, 19.8712802, 'Śląskie', 'Chałupy', 'To urokliwe, choć wymagające starorzecze w Chałupach, położone w malowniczym krajobrazie Śląska. Dno jest muliste i charakteryzuje się średnim zamuleniem, co sprzyja rozwojowi bogatej roślinności wodnej. Brzegi są często bagniste i trudno dostępne, wymagające użycia brodów do komfortowego wędkowania. Zbiornik łączy się z rzeką Pilicą jedynie podczas wysokich stanów wody, co wpływa na jego ekosystem. Dominującymi gatunkami są tu liny, karasie pospolite, płocie i okonie. Ze względu na płytkość i obfitość roślinności, istnieje ryzyko przyduchy w gorące, bezdeszczowe lata. Wędkowanie tutaj to prawdziwa przygoda w dzikim otoczeniu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22392, 2.1, 1.3, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22393, 'Starorzecze Chałupy II', 'starorzecze-chalupy-ii-chalupy-22393', 'OXBOW', 51.0470575, 19.8699872, 'Śląskie', 'Chałupy', 'Niewielkie i bardzo płytkie starorzecze w Chałupach, które w okresach letniej suszy regularnie wysycha. Dno jest silnie zamulone, a cała powierzchnia wody gęsto porośnięta trzciną i roślinnością podwodną, co sprawia, że jest to łowisko dla wytrwałych. Brzegi są praktycznie niedostępne bez specjalistycznego sprzętu i brodów. Mimo trudnych warunków, jest to enklawa dla karasia pospolitego, wzdręgi i płoci, które przystosowały się do tego środowiska. Ryzyko przyduchy jest ekstremalnie wysokie, dlatego najlepszym okresem na wędkowanie jest wczesna wiosna. To miejsce dla prawdziwych pasjonatów, szukających wyzwań i bliskiego kontaktu z naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22393, 1.5, 0.9, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22394, 'Starorzecze Chałupy III', 'starorzecze-chalupy-iii-chalupy-22394', 'OXBOW', 51.0494685, 19.8723545, 'Śląskie', 'Chałupy', 'To średniej wielkości starorzecze w Chałupach oferuje zróżnicowane warunki wędkarskie. Dno jest muliste, z umiarkowanym zamuleniem, a roślinność podwodna występuje w skupiskach, tworząc ciekawe struktury dla ryb. Dostęp do brzegu jest dobry tylko z jednej strony, pozostałe odcinki są mocno zarośnięte, wymagając użycia brodów. Starorzecze łączy się z rzeką Pilicą podczas wiosennych roztopów i jesiennych wezbrań. Można tu z powodzeniem łowić szczupaki, liny, karpie, leszcze i okonie. Istnieje ryzyko przyduchy w upalne lata, dlatego warto monitorować warunki. To łowisko dla wędkarzy, którzy cenią sobie różnorodność i są gotowi na trochę wysiłku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22394, 3, 1.6, 3.1, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Karp,Leszcz,Okoń', 'Dobry z jednej strony, reszta zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22395, 'Starorzecze Chałupy IV', 'starorzecze-chalupy-iv-chalupy-22395', 'OXBOW', 51.0505316, 19.874091, 'Śląskie', 'Chałupy', 'To kolejne starorzecze w okolicy Chałup, charakteryzujące się znacznym zamuleniem i bujną roślinnością. Dno jest bardzo miękkie, a średnia głębokość nie przekracza półtora metra, co sprzyja szybkiemu zarastaniu. Brzegi są bagniste i mocno zarośnięte, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga użycia brodów. Zbiornik nie ma stałego połączenia z rzeką, co czyni go bardziej wrażliwym na zmiany warunków. Występują tu głównie liny, karasie pospolite, wzdręgi i płocie. Ze względu na izolację i silne zarastanie, ryzyko przyduchy jest wysokie, szczególnie w upalne lata. To łowisko dla cierpliwych wędkarzy, którzy potrafią odnaleźć ryby w gęstwinie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22395, 2.5, 1.4, 2.9, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22396, 'Starorzecze Chałupy V', 'starorzecze-chalupy-v-chalupy-22396', 'OXBOW', 51.0508518, 19.8746223, 'Śląskie', 'Chałupy', 'To niewielkie i płytkie starorzecze w Chałupach, które jest szczególnie narażone na wysychanie w okresach suszy. Dno jest bardzo mocno zamulone, a cała powierzchnia zbiornika jest gęsto porośnięta trzcinami i roślinnością wodną, co sprawia, że jest to trudne łowisko. Brzegi są praktycznie niedostępne bez brodów, otoczone gęstymi zaroślami. Występują tu głównie karasie pospolite, wzdręgi i płocie, które są odporne na trudne warunki środowiskowe. Ze względu na niewielką głębokość i brak połączenia z rzeką, ryzyko przyduchy jest bardzo wysokie. Najlepszym okresem na wędkowanie jest wczesna wiosna, kiedy poziom wody jest stabilniejszy. To wyzwanie dla wędkarzy szukających dzikich i nietypowych miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22396, 1.8, 1.1, 2.6, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22397, 'Starorzecze Chałupy VI', 'starorzecze-chalupy-vi-chalupy-22397', 'OXBOW', 51.0472278, 19.870778, 'Śląskie', 'Chałupy', 'To starorzecze w Chałupach, choć średniej wielkości, oferuje ciekawe możliwości wędkarskie. Dno jest muliste z umiarkowanym zamuleniem, a roślinność podwodna tworzy mozaikę otwartych przestrzeni i gęstych zarośli. Dostęp do brzegu jest dobry tylko z jednej strony, pozostałe odcinki są bagniste i wymagają użycia brodów. Zbiornik łączy się z rzeką Pilicą podczas wiosennych roztopów i jesiennych wezbrań, co wpływa na jego populację ryb. Można tu z powodzeniem łowić szczupaki, liny, okonie i płocie. Istnieje ryzyko przyduchy w upalne lata, dlatego warto monitorować warunki. To łowisko dla wędkarzy, którzy cenią sobie różnorodność i są gotowi na trochę wysiłku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22397, 2.3, 1.2, 2.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Okoń,Płoć', 'Dobry z jednej strony, reszta bagnista', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22398, 'Starorzecze Ruda', 'starorzecze-ruda-ruda-22398', 'OXBOW', 52.0027438, 20.2177303, 'Łódzkie', 'Ruda', 'Starorzecze Ruda to malownicze i stosunkowo głębokie łowisko, położone w województwie Łódzkim, w pobliżu rzeki Rawki. Dno jest zróżnicowane, od piaszczystego po lekko muliste, z niskim poziomem zamulenia. Roślinność podwodna występuje umiarkowanie, co zapewnia dobre warunki do wędkowania różnymi metodami. Brzegi są łatwo dostępne z obu stron, często prowadzą do nich leśne ścieżki, co ułatwia dotarcie. Zbiornik łączy się z Rawką podczas wysokich stanów wody, co wzbogaca jego populację ryb. Można tu liczyć na szczupaki, leszcze, karpie, płocie i okonie. Ryzyko przyduchy jest niskie dzięki dobrej głębokości i okresowemu połączeniu z rzeką.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22398, 4.5, 2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Karp,Płoć,Okoń', 'Dobry z obu stron, miejscami leśny', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22399, 'Starorzecze Rawka', 'starorzecze-rawka-ruda-22399', 'OXBOW', 52.0039034, 20.2140192, 'Łódzkie', 'Ruda', 'To starorzecze, nazwane ''Rawka'', stanowi integralną część ekosystemu rzeki Rawki, z którą utrzymuje stałe połączenie. Dno jest zróżnicowane, z przewagą piasku i żwiru, choć miejscami występuje średnie zamulenie. Roślinność podwodna jest umiarkowana, co tworzy idealne warunki dla drapieżników i ryb spokojnego żeru. Brzegi są w większości łatwo dostępne, choć miejscami mogą być zarośnięte. Wędkarze mogą liczyć na obfitość szczupaków, boleni, jazi, płoci i okoni. Dzięki stałemu połączeniu z rzeką, przepływ wody jest zapewniony, co minimalizuje ryzyko przyduchy. To doskonałe miejsce do wędkowania przez większą część roku, oferujące zarówno emocje, jak i relaks.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22399, 3.5, 1.5, 3, 'Stałe połączenie', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Boleń,Jaź,Płoć,Okoń', 'Dobry, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22400, 'Starorzecze Bydgoszcz (Północne)', 'starorzecze-bydgoszcz-polnocne-bydgoszcz-22400', 'OXBOW', 53.197038, 18.187823, 'Kujawsko-Pomorskie', 'Bydgoszcz', 'To starorzecze, położone w północnej części Bydgoszczy, stanowi atrakcyjne łowisko dla wędkarzy poszukujących spokoju. Dno jest zróżnicowane, z mulistymi obszarami przeplatanymi twardszymi fragmentami, co sprzyja różnorodności gatunkowej ryb. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je gęsta trzcina i inna roślinność wodna, utrudniająca dostęp do wody. W starorzeczu dominują gatunki takie jak szczupak, lin, płoć i leszcz, które znajdują tu idealne warunki do żerowania i rozmnażania. W okresach letnich, szczególnie podczas upałów, istnieje ryzyko przyduchy z powodu obfitej roślinności podwodnej. Wędkarstwo z brodzeniem jest często konieczne, aby dotrzeć do najlepszych miejscówek, zwłaszcza w głębszych partiach akwenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22400, 3.2, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Płoć,Leszcz', 'Dobry z jednej strony, reszta zarośnięta', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22401, 'Starorzecze Bydgoszcz (Południowe)', 'starorzecze-bydgoszcz-poludniowe-bydgoszcz-22401', 'OXBOW', 53.1962898, 18.1878748, 'Kujawsko-Pomorskie', 'Bydgoszcz', 'Drugie z bydgoskich starorzeczy charakteryzuje się bardziej zamkniętym charakterem i brakiem stałego połączenia z rzeką. Dno jest w większości muliste, z grubą warstwą osadów, co sprzyja rozwojowi bujnej roślinności podwodnej i nawodnej. Brzegi są niemal całkowicie porośnięte gęstymi pasami trzcin i krzewów, co czyni dostęp do wody bardzo utrudnionym i wymaga użycia brodów. Wśród dominujących gatunków ryb znajdziemy lina, karasia pospolitego, wzdręgę oraz płoć, które doskonale adaptują się do płytkich i bogatych w roślinność siedlisk. W upalne lata ryzyko przyduchy jest wysokie, co może wpływać na aktywność ryb. Jest to idealne miejsce dla cierpliwych wędkarzy preferujących łowienie spławikowe w zaroślach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22401, 2.8, 1.5, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22402, 'Starorzecze Umianowice (Północne)', 'starorzecze-umianowice-polnocne-umianowice-22402', 'OXBOW', 50.5693981, 20.5082845, 'Świętokrzyskie', 'Umianowice', 'To malownicze starorzecze w okolicach Umianowic jest popularnym miejscem wśród lokalnych wędkarzy. Charakteryzuje się dość zróżnicowanym dnem, gdzie partie muliste przeplatają się z twardszymi, piaszczystymi odcinkami, co tworzy idealne warunki dla wielu gatunków ryb. Brzegi są w większości łatwo dostępne, choć w niektórych miejscach pojawiają się skupiska trzcin i krzewów, zapewniające schronienie dla ryb. Wśród dominujących gatunków ryb można wymienić szczupaka, okonia, leszcza i płoć, które często osiągają tu imponujące rozmiary. Starorzecze jest zasilane wodą podczas wiosennych roztopów, co sprzyja odnowie populacji i utrzymaniu dobrej jakości wody. Wędkarze mogą liczyć na udane połowy przez większą część roku, szczególnie na spinning lub spławik.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22402, 4.5, 2, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry z obu stron, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22403, 'Starorzecze Umianowice (Wschodnie)', 'starorzecze-umianowice-wschodnie-umianowice-22403', 'OXBOW', 50.5700078, 20.5099862, 'Świętokrzyskie', 'Umianowice', 'To starorzecze, położone na wschód od Umianowic, jest typowym akwenem o charakterze starorzecza, z silnym zamuleniem dna i bujną roślinnością. Dno jest głęboko muliste, co sprzyja rozwojowi gęstych łanów lilii wodnych i innych roślin. Brzegi są w większości bagniste i trudno dostępne, co wymaga od wędkarzy użycia brodów lub poszukiwania nielicznych, utwardzonych miejsc. Wśród dominujących gatunków ryb znajdziemy lina, karasia pospolitego, wzdręgę oraz karpia, które doskonale czują się w takim środowisku. Ze względu na dużą ilość materii organicznej i ograniczoną cyrkulację wody, ryzyko przyduchy w okresie letnim jest znaczne. Jest to wyzwanie dla wędkarzy, ale jednocześnie szansa na złowienie okazałych egzemplarzy ryb typowych dla starorzeczy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22403, 3.8, 1.7, 4.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Karp', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna, zatopione gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22404, 'Starorzecze Skowronno Górne (Południowe)', 'starorzecze-skowronno-gorne-poludniowe-skowronno-gorne-22404', 'OXBOW', 50.5604499, 20.4992148, 'Świętokrzyskie', 'Skowronno Górne', 'To mniejsze starorzecze w Skowronnie Górnym jest płytkim i silnie zarośniętym akwenem, co czyni je wymagającym łowiskiem. Dno jest niemal całkowicie pokryte grubą warstwą mułu i gęstą roślinnością podwodną, która w lecie potrafi opanować całą taflę wody. Brzegi są bardzo trudno dostępne, często bagniste i gęsto porośnięte trzciną, co wymaga od wędkarzy dużego wysiłku. Wśród dominujących gatunków ryb znajdziemy karasia pospolitego, wzdręgę i płoć, które doskonale radzą sobie w trudnych warunkach. W okresach suszy i upałów starorzecze może częściowo wysychać, co wpływa na populację ryb. Wędkarstwo w tym miejscu wymaga precyzji i cierpliwości, ale może nagrodzić poławiacza pięknymi okazami karasi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22404, 2.5, 1.2, 3, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22405, 'Starorzecze Skowronno Górne (Północne)', 'starorzecze-skowronno-gorne-polnocne-skowronno-gorne-22405', 'OXBOW', 50.5579191, 20.4974093, 'Świętokrzyskie', 'Skowronno Górne', 'To starorzecze, położone w północnej części Skowronna Górnego, jest bardziej otwarte i głębsze niż jego południowy odpowiednik. Dno jest zróżnicowane, z mulistymi zatoczkami i twardszymi, gliniastymi fragmentami w głębszych partiach, co sprzyja różnorodności siedlisk. Brzegi są częściowo dostępne, z kilkoma dogodnymi stanowiskami dla wędkarzy, choć wciąż występują obszary zarośnięte trzciną. Wśród dominujących gatunków ryb można wymienić szczupaka, lina, okonia i leszcza, które osiągają tu zadowalające rozmiary. Połączenie z rzeką podczas wysokiej wody zapewnia regularne zarybienia i dobrą jakość wody, minimalizując ryzyko przyduchy. Wędkarstwo spinningowe i spławikowe są tu najbardziej efektywne, oferując emocjonujące chwile.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22405, 3, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Okoń,Leszcz', 'Dobry z jednej strony, reszta zarośnięta', TRUE, 'Pojedyncze zatopione drzewa', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22406, 'Starorzecze Stawy (Północne)', 'starorzecze-stawy-polnocne-stawy-22406', 'OXBOW', 50.5742626, 20.5014744, 'Świętokrzyskie', 'Stawy', 'To jedno z najbardziej atrakcyjnych starorzeczy w okolicy Stawów, charakteryzujące się stałym połączeniem z rzeką, co zapewnia doskonałą wymianę wody. Dno jest twarde, piaszczysto-żwirowe, z nielicznymi osadami mułu, co sprzyja występowaniu drapieżników. Brzegi są łatwo dostępne z obu stron, z licznymi dogodnymi stanowiskami wędkarskimi, pozbawionymi gęstych zarośli. Wśród dominujących gatunków ryb znajdziemy szczupaka, sandacza, leszcza, płoć i bolenia, które migrują z rzeki. Dzięki stałemu przepływowi wody ryzyko przyduchy jest minimalne, a ryby są aktywne przez cały rok. To idealne miejsce dla wędkarzy preferujących łowienie na spinning, grunt lub feeder, z szansą na złowienie dużej ryby.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22406, 5, 2.2, 5.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Sandacz,Leszcz,Płoć,Boleń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22407, 'Starorzecze Stawy (Wschodnie)', 'starorzecze-stawy-wschodnie-stawy-22407', 'OXBOW', 50.5763524, 20.5026452, 'Świętokrzyskie', 'Stawy', 'Drugie starorzecze w okolicach Stawów to akwen o umiarkowanym zamuleniu i zróżnicowanej roślinności. Dno jest mieszane, z partiami mulistymi i twardszymi, co tworzy różnorodne siedliska dla ryb. Brzegi są częściowo dostępne, z kilkoma dogodnymi miejscami do wędkowania, ale w wielu obszarach porasta je trzcina. Wśród dominujących gatunków ryb znajdziemy okonia, płoć, leszcza i karpia, które dobrze czują się w tym środowisku. Połączenie z rzeką podczas wysokiej wody zapewnia świeżą wodę i migrację ryb. Ryzyko przyduchy jest niskie, co sprzyja stabilnej populacji ryb przez cały sezon. Wędkarze mogą liczyć na udane połowy różnymi metodami, od spławika po grunt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22407, 4.2, 1.9, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Okoń,Płoć,Leszcz,Karp', 'Dobry z jednej strony, reszta zarośnięta', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22408, 'Starorzecze Umianowice (Środkowe)', 'starorzecze-umianowice-srodkowe-umianowice-22408', 'OXBOW', 50.5761117, 20.5057417, 'Świętokrzyskie', 'Umianowice', 'To starorzecze w centralnej części Umianowic jest typowym, mocno zarośniętym zbiornikiem, idealnym dla miłośników łowienia w trudnych warunkach. Dno jest głęboko muliste, z bogatą warstwą osadów organicznych, co sprzyja rozwojowi gęstej roślinności wodnej. Brzegi są niemal całkowicie niedostępne bez brodów, pokryte pasami trzcin i krzewów, które tworzą naturalne schronienia dla ryb. Wśród dominujących gatunków ryb znajdziemy lina, karasia pospolitego, wzdręgę oraz płoć, które doskonale adaptują się do płytkich i bogatych w roślinność siedlisk. W upalne lata ryzyko przyduchy jest wysokie, co wymaga monitorowania warunków. To miejsce dla cierpliwych wędkarzy, którzy potrafią wykorzystać zarośla jako atut.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22408, 3, 1.6, 3.9, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22409, 'Starorzecze Umianowice (Zachodnie)', 'starorzecze-umianowice-zachodnie-umianowice-22409', 'OXBOW', 50.5749866, 20.5056646, 'Świętokrzyskie', 'Umianowice', 'To starorzecze na zachód od Umianowic charakteryzuje się umiarkowanym zamuleniem i zmiennym dostępem do brzegów. Dno jest zróżnicowane, z mulistymi zatoczkami i twardszymi fragmentami, co tworzy różnorodne siedliska dla ryb. Brzegi są częściowo dostępne, jednak w wielu miejscach są bagniste i wymagają ostrożności lub użycia brodów. Wśród dominujących gatunków ryb znajdziemy szczupaka, okonia, płoć i lina, które znajdują tu dobre warunki do żerowania. Połączenie z rzeką podczas wysokiej wody zapewnia dopływ świeżej wody i ryb, jednak w okresach suszy ryzyko przyduchy wzrasta. Wędkarstwo spinningowe i spławikowe są tutaj popularne, oferując szansę na złowienie ładnych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22409, 2.7, 1.3, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Płoć,Lin', 'Częściowo dostępny, miejscami bagnisty', TRUE, 'Pojedyncze zatopione gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22410, 'Starorzecze Umianowice (Południowe)', 'starorzecze-umianowice-poludniowe-umianowice-22410', 'OXBOW', 50.5743644, 20.5055259, 'Świętokrzyskie', 'Umianowice', 'Ostatnie z umianowickich starorzeczy to głębszy, ale mocno zarośnięty akwen, stanowiący wyzwanie dla wędkarzy. Dno jest w przeważającej części muliste, z dużą ilością zgnilizny i materii organicznej, co sprzyja bujnej roślinności. Brzegi są bardzo trudno dostępne, niemal całkowicie pokryte gęstymi zaroślami trzcin i krzewów, wymagającymi brodzenia. Wśród dominujących gatunków ryb znajdziemy karpia, lina, karasia srebrzystego oraz leszcza, które dobrze czują się w bogatym w pokarm środowisku. Ze względu na brak stałego połączenia z rzeką i obfitą roślinność, ryzyko przyduchy w lecie jest wysokie. Jest to idealne miejsce dla wędkarzy gruntowych, którzy cenią sobie spokój i możliwość złowienia dużych karpi i linów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22410, 3.5, 1.8, 4.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karp,Lin,Karaś srebrzysty,Leszcz', 'Mocno zarośnięty trzciną, trudny', TRUE, 'Gęsta roślinność podwodna, zatopione korzenie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22411, 'Starorzecze Stawy (Południowe)', 'starorzecze-stawy-poludniowe-stawy-22411', 'OXBOW', 50.5672361, 20.4947015, 'Świętokrzyskie', 'Stawy', 'To jedno z większych i głębszych starorzeczy w okolicach Stawów, zasilane przez stałe połączenie z rzeką. Dno jest zróżnicowane, z twardszymi partiami żwirowymi i głębokimi rynnami, co sprzyja występowaniu dużych drapieżników. Brzegi są łatwo dostępne z obu stron, z wieloma dogodnymi stanowiskami wędkarskimi, choć miejscami występują kępy trzcin. Wśród dominujących gatunków ryb znajdziemy suma, szczupaka, sandacza, leszcza i jazia, które regularnie migrują z rzeki. Dzięki dobrej wymianie wody ryzyko przyduchy jest minimalne, co zapewnia stabilne warunki dla ryb. To doskonałe miejsce dla wędkarzy poszukujących dużych okazów, szczególnie na spinning, trollingu lub metodą gruntową.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22411, 6, 2.5, 6, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Szczupak,Sandacz,Leszcz,Jaź', 'Dobry z obu stron', FALSE, 'Pojedyncze zatopione drzewa', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22412, 'Starorzecze Stawy (Zachodnie Północne)', 'starorzecze-stawy-zachodnie-polnocne-stawy-22412', 'OXBOW', 50.5715505, 20.4966485, 'Świętokrzyskie', 'Stawy', 'To starorzecze, położone w zachodniej części Stawów, jest akwenem o umiarkowanym zamuleniu i zróżnicowanym dostępem do brzegów. Dno jest mieszane, z partiami mulistymi i twardszymi, co tworzy różnorodne siedliska dla ryb. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je trzcina i krzewy, które mogą utrudniać dostęp. Wśród dominujących gatunków ryb znajdziemy szczupaka, okonia, płoć i lina, które dobrze czują się w tym środowisku. Połączenie z rzeką podczas wysokiej wody zapewnia dopływ świeżej wody i migrację ryb, co sprzyja zdrowej populacji. Wędkarze spinningowi i spławikowi znajdą tu wiele ciekawych miejscówek, szczególnie w pobliżu zatopionych przeszkód.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22412, 3.5, 1.7, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Lin', 'Częściowo dostępny, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22413, 'Starorzecze Stawy (Zachodnie Południowe)', 'starorzecze-stawy-zachodnie-poludniowe-stawy-22413', 'OXBOW', 50.5699928, 20.4959799, 'Świętokrzyskie', 'Stawy', 'Ostatnie starorzecze w Stawach to mniejszy, silnie zarośnięty i zamulony zbiornik, idealny dla wędkarzy poszukujących spokoju i wyzwań. Dno jest głęboko muliste, z obfitą roślinnością podwodną, która tworzy gęste zarośla. Brzegi są bardzo trudno dostępne, często bagniste i gęsto porośnięte trzciną, co wymaga użycia brodów. Wśród dominujących gatunków ryb znajdziemy lina, karasia pospolitego, wzdręgę oraz karpia, które doskonale adaptują się do trudnych warunków. Ze względu na brak połączenia z rzeką i dużą ilość materii organicznej, ryzyko przyduchy w lecie jest znaczne. Jest to miejsce dla cierpliwych wędkarzy, którzy cenią sobie łowienie w naturalnym, dzikim środowisku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22413, 2.8, 1.4, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Karp', 'Trudny, bagnisty, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna, zatopione gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22414, 'Starorzecze Motkowice', 'starorzecze-motkowice-motkowice-22414', 'OXBOW', 50.5814848, 20.507073, 'Świętokrzyskie', 'Motkowice', 'Starorzecze w Motkowicach to atrakcyjne łowisko o umiarkowanym zamuleniu i dobrych warunkach dla wędkarzy. Dno jest zróżnicowane, z partiami mulistymi i twardszymi, co sprzyja różnorodności gatunkowej ryb. Brzegi są w większości łatwo dostępne, choć w niektórych miejscach pojawiają się skupiska trzcin i krzewów, zapewniające schronienie dla ryb. Wśród dominujących gatunków ryb można wymienić szczupaka, leszcza, płoć, okonia i klenia, które często osiągają tu zadowalające rozmiary. Starorzecze jest zasilane wodą podczas wiosennych roztopów, co sprzyja odnowie populacji i utrzymaniu dobrej jakości wody. Wędkarze mogą liczyć na udane połowy przez większą część roku, szczególnie na spinning lub spławik, w zależności od preferencji.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22414, 4, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Kleń', 'Dobry z jednej strony, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22415, 'Starorzecze (Umianowice)', 'starorzecze-umianowice-pinczow-22415', 'OXBOW', 50.5770223, 20.5084582, 'Świętokrzyskie', 'Pińczów', 'To malownicze starorzecze rzeki Nidy, położone w pobliżu Umianowic, stanowi prawdziwą ostoję spokoju dla wędkarzy. Charakteryzuje się bujną roślinnością brzegową, głównie trzciną i pałką wodną, która tworzy liczne kryjówki dla ryb. Dno jest muliste, z lokalnymi twardymi plamami żwiru, co sprzyja bytności karpiowatych i linów. Łowisko jest stosunkowo płytkie, jednak posiada głębsze rynny i dołki, które są atrakcyjne dla drapieżników, takich jak szczupak i okoń. Wiosną i jesienią woda jest czysta, co ułatwia obserwację żerujących ryb, natomiast latem może pojawić się zakwit. Wędkowanie wymaga precyzji ze względu na liczne zaczepy podwodne w postaci zwalonych drzew i gęstej roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22415, 3.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Szczupak,Karaś pospolity,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22416, 'Starorzecze (Pratkowice) 1', 'starorzecze-pratkowice-1-radomsko-22416', 'OXBOW', 51.0262377, 19.861621, 'Łódzkie', 'Radomsko', 'To jedno z licznych starorzeczy Warty w okolicy Pratkowic, oferujące zróżnicowane warunki wędkarskie. Brzegi są częściowo dostępne, choć miejscami porośnięte gęstymi krzewami i wysoką trawą. Dno jest przeważnie muliste, z bogatą roślinnością podwodną, taką jak rogatek i moczarka, co sprzyja rozwojowi populacji białorybu. W głębszych partiach starorzecza można liczyć na spotkanie z większymi egzemplarzami leszczy i karpi. Okresowo, przy wyższym stanie wody, starorzecze łączy się z rzeką, co wpływa na migrację ryb i zwiększa bioróżnorodność. Wędkowanie na spławik i grunt jest najskuteczniejsze, zwłaszcza w okolicach podwodnych górek i zarośli. Należy uważać na liczne zaczepy w postaci zatopionych gałęzi.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22416, 4.5, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Okoń', 'Dobry z jednej strony, trudny z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22417, 'Starorzecze (Pratkowice) 2', 'starorzecze-pratkowice-2-radomsko-22417', 'OXBOW', 51.0265472, 19.861924, 'Łódzkie', 'Radomsko', 'Kolejne starorzecze w kompleksie Pratkowic, nieco mniejsze i bardziej płytkie niż sąsiednie, co czyni je idealnym siedliskiem dla karasia i wzdręgi. Charakteryzuje się bardzo silnym zarastaniem, zwłaszcza latem, kiedy to powierzchnia wody bywa pokryta kożuchem roślinności pływającej. Dno jest jednolicie muliste, z grubą warstwą osadów, co wymaga delikatnego podejścia do wyboru miejsca i techniki wędkowania. Brzegi są niskie i podmokłe, często trudno dostępne bez odpowiedniego obuwia. Wiosną, przed pełnym rozwojem roślinności, jest to doskonałe miejsce na połów lina i szczupaka, który poluje wśród młodych pędów. Wędkarze powinni być przygotowani na walkę z zaczepami i gęstą roślinnością.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22417, 2.1, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Lin,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22418, 'Starorzecze (Pratkowice) 3', 'starorzecze-pratkowice-3-radomsko-22418', 'OXBOW', 51.0327393, 19.8620411, 'Łódzkie', 'Radomsko', 'To starorzecze, choć blisko innych, wyróżnia się nieco większą głębokością i mniejszym stopniem zamulenia, co sprzyja występowaniu większych drapieżników. Brzegi są stabilniejsze, częściowo umocnione, z dogodnymi stanowiskami wędkarskimi, zwłaszcza od strony pól. Dno charakteryzuje się zmienną strukturą, od twardego piasku po miękki muł, z pojedynczymi zatopionymi pniami drzew, które stanowią doskonałe kryjówki. Wiosną i jesienią można tu liczyć na udany połów sandacza, który wchodzi z rzeki podczas wyższych stanów wody, oraz dużych okoni. Roślinność podwodna jest umiarkowana, co ułatwia prowadzenie przynęt spinningowych. Wymaga to jednak znajomości miejscówek i cierpliwości.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22418, 5.8, 2.5, 6, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sandacz,Okoń,Szczupak,Leszcz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22419, 'Starorzecze (Pratkowice) 4', 'starorzecze-pratkowice-4-radomsko-22419', 'OXBOW', 51.0315221, 19.8630019, 'Łódzkie', 'Radomsko', 'Mniejsze, ale bardzo urokliwe starorzecze, otoczone gęstymi zaroślami i drzewami, co zapewnia cień i spokój. Jest to typowe łowisko linowo-karasiowe, z płytką wodą i grubą warstwą mułu na dnie. Roślinność brzegowa jest bardzo obfita, co utrudnia dostęp, ale jednocześnie tworzy idealne warunki dla ryb spokojnego żeru. Woda jest często mętna z powodu rozkładającej się materii organicznej, co sprzyja rozwojowi karasi i linów. Latem ryzyko przyduchy jest podwyższone, dlatego najlepsze wyniki osiąga się wiosną i jesienią. Wymaga to cichego podejścia i precyzyjnego zarzucania zestawu w wolne od roślinności okna. Wędkarze powinni być przygotowani na trudny teren.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22419, 1.8, 0.8, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22420, 'Starorzecze (Pratkowice) 5', 'starorzecze-pratkowice-5-radomsko-22420', 'OXBOW', 51.0321277, 19.8625427, 'Łódzkie', 'Radomsko', 'To starorzecze charakteryzuje się stosunkowo stałym połączeniem z rzeką Wartą, co zapewnia regularną wymianę wody i swobodną migrację ryb. Dzięki temu populacja ryb jest bardziej zróżnicowana i dynamiczna. Dno jest częściowo piaszczyste, z fragmentami żwiru i kamieni, co jest rzadkością w starorzeczach. Brzegi są łatwo dostępne, z naturalnymi miejscami do wędkowania, choć bez specjalnie przygotowanych stanowisk. Można tu liczyć na leszcze, płocie, a także bolenie i jazie, które wpływają z głównego nurtu rzeki. Wędkowanie gruntowe i spławikowe przynosi najlepsze rezultaty, zwłaszcza w miejscach o zmiennym nurcie. Jest to idealne miejsce dla wędkarzy ceniących różnorodność gatunkową.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22420, 6.5, 2.8, 5.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Boleń,Jaź,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22421, 'Starorzecze (Bieńki)', 'starorzecze-bienki-szczytno-22421', 'OXBOW', 53.7257512, 21.2395994, 'Warmińsko-Mazurskie', 'Szczytno', 'Położone w malowniczej Krainie Tysiąca Jezior, to starorzecze wyróżnia się czystą wodą i bogactwem podwodnych struktur. Brzegi są częściowo zalesione, co zapewnia cień i schronienie, a także utrudnia dostęp w niektórych miejscach. Dno jest zróżnicowane, od piaszczystych płycizn po głębokie, muliste dołki, idealne dla suma i węgorza. Roślinność podwodna jest umiarkowana, z przewagą rdestnic i moczarki, tworzących doskonałe kryjówki dla szczupaków i okoni. Ze względu na położenie w regionie jeziornym, starorzecze charakteryzuje się dobrą jakością wody i mniejszym ryzykiem przyduchy. Wędkowanie z łodzi lub pontonu jest tu bardzo efektywne, pozwalając na dotarcie do trudno dostępnych miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22421, 7, 3, 7, 'Brak', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Sum,Węgorz,Płoć', 'Trudny, zarośnięty lasem', TRUE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22422, 'Starorzecze (Nowe Kraski)', 'starorzecze-nowe-kraski-maciejowice-22422', 'OXBOW', 51.7210219, 21.4528351, 'Mazowieckie', 'Maciejowice', 'To rozległe starorzecze Wisły w okolicach Nowych Krasek jest znane z bogactwa ryb karpiowatych i drapieżników. Charakteryzuje się zmiennym poziomem wody, zależnym od Wisły, z którą łączy się podczas większych wezbrań. Brzegi są w większości otwarte, piaszczyste lub trawiaste, co zapewnia dobry dostęp, choć miejscami mogą być podmokłe. Dno jest piaszczysto-muliste, z licznymi zatopionymi korzeniami i gałęziami, które stanowią doskonałe kryjówki. Wiosną i jesienią można tu liczyć na duże karpie i amury, które żerują na rozległych płyciznach. Latem, w cieplejszych miesiącach, dominują leszcze i płocie, a także sandacze polujące na drobnicę. To łowisko wymaga cierpliwości i umiejętności odczytywania wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22422, 12.5, 2.2, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Leszcz,Sandacz,Płoć,Szczupak', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22423, 'Starorzecze (Sobowice)', 'starorzecze-sobowice-pinczow-22423', 'OXBOW', 50.5650255, 20.4876384, 'Świętokrzyskie', 'Pińczów', 'Starorzecze Nidy w Sobowicach to klasyczne łowisko dla miłośników lina i karasia, charakteryzujące się spokojną, płytką wodą. Brzegi są gęsto porośnięte trzciną i krzewami, co wymaga od wędkarza znalezienia dogodnego miejsca do zarzucenia. Dno jest w przeważającej części muliste, z grubą warstwą osadów organicznych, sprzyjających rozwojowi bezkręgowców. Roślinność podwodna jest bardzo bujna, co tworzy idealne warunki do życia dla ryb spokojnego żeru. Wiosną, po tarle, można tu liczyć na obfite brania płoci i wzdręgi. Wędkarstwo spławikowe jest najbardziej efektywne, często z użyciem długich wędek. Należy zachować ciszę i ostrożność, aby nie spłoszyć płochliwych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22423, 2.8, 1.2, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22424, 'Starorzecze (Kopernia) 1', 'starorzecze-kopernia-1-pinczow-22424', 'OXBOW', 50.5218613, 20.4666062, 'Świętokrzyskie', 'Pińczów', 'To starorzecze Nidy w Koperni to średniej wielkości zbiornik, który oferuje dobre warunki do wędkowania przez większą część roku. Brzegi są częściowo dostępne, z licznymi kępami trzcin i pojedynczymi drzewami dającymi cień. Dno jest zróżnicowane, od twardych, piaszczystych fragmentów po miękkie, muliste zagłębienia, gdzie gromadzą się leszcze. Roślinność podwodna jest umiarkowana, co pozwala na swobodne prowadzenie przynęt. W starorzeczu tym regularnie występują szczupaki i okonie, które polują na drobnicę wśród podwodnych struktur. Wędkowanie gruntowe na białoryb jest bardzo skuteczne, zwłaszcza w cieplejszych miesiącach. Warto poszukać głębszych miejscówek, które są ostoją dla większych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22424, 4, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń', 'Dobry z jednej strony, zarośnięty z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22425, 'Starorzecze (Kopernia) 2', 'starorzecze-kopernia-2-pinczow-22425', 'OXBOW', 50.5208914, 20.4678131, 'Świętokrzyskie', 'Pińczów', 'Mniejsze i bardziej intymne starorzecze w Koperni, idealne dla wędkarzy szukających spokoju i trudniej dostępnych miejsc. Charakteryzuje się bardzo gęstą roślinnością brzegową i podwodną, co wymaga precyzyjnego zarzucania. Dno jest jednolicie muliste, z dużą ilością rozkładającej się materii organicznej, co sprzyja rozwojowi lina i karasia pospolitego. Latem woda może być bardzo ciepła i uboższa w tlen, co zwiększa ryzyko przyduchy. Wiosną i jesienią jest to jednak doskonałe miejsce na połów okazałych linów, które żerują blisko trzcin. Wędkarstwo spławikowe i delikatne gruntowe są tu najbardziej efektywne, najlepiej z użyciem naturalnych przynęt. Wymagane jest ciche podejście i cierpliwość.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22425, 1.5, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22426, 'Starorzecze (Ziemiary) 1', 'starorzecze-ziemiary-1-sochaczew-22426', 'OXBOW', 52.0459572, 20.2019893, 'Mazowieckie', 'Sochaczew', 'To starorzecze w Ziemiarach, położone w pobliżu Bzury, jest znane z bogactwa ryb karpiowatych i drapieżników. Charakteryzuje się dość stabilnym poziomem wody i umiarkowanym stopniem zamulenia. Brzegi są częściowo dostępne, z licznymi drzewami i krzewami, które zapewniają cień. Dno jest zróżnicowane, od piaszczystych płycizn po głębsze, muliste rynny. Roślinność podwodna jest obecna, ale nie utrudnia znacząco wędkowania, tworząc idealne kryjówki dla okoni i szczupaków. Wiosną i jesienią można tu liczyć na udany połów karpi i leszczy, które żerują na dnie. Wędkowanie gruntowe i spinningowe są tu najbardziej popularne i efektywne. Jest to łowisko o dużym potencjale dla doświadczonych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22426, 6, 2.5, 5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Leszcz,Szczupak,Okoń,Płoć', 'Dobry z jednej strony, zarośnięty z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22427, 'Starorzecze (Ziemiary) 2', 'starorzecze-ziemiary-2-sochaczew-22427', 'OXBOW', 52.0400112, 20.2005206, 'Mazowieckie', 'Sochaczew', 'Mniejsze i bardziej zarośnięte starorzecze w Ziemiarach, stanowiące ostoję dla ryb spokojnego żeru. Brzegi są niskie i podmokłe, często trudno dostępne bez odpowiedniego obuwia, gęsto porośnięte trzciną. Dno jest jednolicie muliste, z grubą warstwą osadów, co sprzyja rozwojowi lina i karasia pospolitego. Roślinność podwodna jest bardzo bujna, co utrudnia wędkowanie, ale jednocześnie tworzy idealne warunki do życia dla ryb. Latem, ze względu na płytkość i obfitość roślinności, istnieje wysokie ryzyko przyduchy. Najlepsze wyniki osiąga się wiosną i wczesną jesienią, kiedy woda jest chłodniejsza i czystsza. Wędkowanie na spławik w małych oknach w roślinności jest najbardziej efektywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22427, 2, 1, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22428, 'Starorzecze (Pratkowice) 6', 'starorzecze-pratkowice-6-radomsko-22428', 'OXBOW', 51.0197536, 19.8609821, 'Łódzkie', 'Radomsko', 'To starorzecze jest częścią większego kompleksu wodnego w Pratkowicach i charakteryzuje się umiarkowanym stopniem zarastania. Brzegi są zróżnicowane – od łatwo dostępnych, trawiastych odcinków po gęste zarośla trzcinowe. Dno jest muliste, ale z licznymi twardymi plamami, które są atrakcyjne dla karpi i leszczy. Roślinność podwodna, choć obecna, nie stanowi większego problemu dla wędkarzy, a wręcz tworzy naturalne schronienia dla ryb. Wiosną i jesienią można tu z powodzeniem łowić szczupaki i okonie, które polują na drobnicę. Wędkowanie gruntowe i spławikowe jest tu bardzo efektywne, zwłaszcza w miejscach o zmiennym ukształtowaniu dna. Jest to łowisko o dobrym potencjale dla wędkarzy preferujących różnorodne techniki.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22428, 3.8, 1.7, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Leszcz,Szczupak,Okoń,Płoć', 'Dobry z jednej strony, mocno zarośnięty trzciną z drugiej', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22429, 'Starorzecze (Pratkowice) 7', 'starorzecze-pratkowice-7-radomsko-22429', 'OXBOW', 51.0212305, 19.861527, 'Łódzkie', 'Radomsko', 'Ostatnie z opisywanych starorzeczy w Pratkowicach, to stosunkowo płytki zbiornik z dominującą roślinnością brzegową i podwodną. Jest to idealne środowisko dla lina, karasia pospolitego oraz wzdręgi. Brzegi są niskie, często podmokłe i trudno dostępne, co sprzyja zachowaniu dzikiego charakteru łowiska. Dno jest w całości pokryte grubą warstwą mułu, a głębsze partie są nieliczne. Wiosną, przed pełnym rozwojem roślinności, można tu liczyć na udane połowy, jednak latem wędkowanie staje się wyzwaniem z powodu gęstych zarośli i ryzyka przyduchy. Wymaga to cierpliwości, cichego podejścia i umiejętności precyzyjnego zarzucania zestawu w wolne od roślinności miejsca.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22429, 2.3, 0.9, 2.1, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22430, 'Starorzecze Pratkowickie Południowe', 'starorzecze-pratkowickie-poludniowe-czestochowa-22430', 'OXBOW', 51.0242198, 19.8635722, 'Śląskie', 'Częstochowa', 'To malownicze starorzecze, położone w pobliżu Pratkowic, charakteryzuje się umiarkowanym poziomem zarośnięcia i średnim zamuleniem dna. Dostęp do brzegów jest utrudniony ze względu na bagnisty teren, co wymaga użycia wodoodpornych spodniobutów. Wiosną i wczesną jesienią wędkarze mogą liczyć na udane połowy lina, karasia pospolitego, płoci oraz szczupaka, który czai się wśród podwodnych przeszkód. Dno, choć w większości czyste, skrywa pojedyncze korzenie i gałęzie, stanowiące doskonałe kryjówki dla ryb. Połączenie z rzeką Wartą następuje jedynie podczas wysokiego stanu wody, co wpływa na stabilność ekosystemu. Istnieje umiarkowane ryzyko niedoboru tlenu w okresach upałów, co warto brać pod uwagę podczas planowania wyprawy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22430, 3.8, 1.4, 2.9, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Trudny, bagnisty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22431, 'Starorzecze Pratkowickie Środkowe 1', 'starorzecze-pratkowickie-srodkowe-1-czestochowa-22431', 'OXBOW', 51.0247019, 19.8636732, 'Śląskie', 'Częstochowa', 'To niewielkie, silnie zarośnięte starorzecze, zlokalizowane blisko Częstochowy, stanowi prawdziwe wyzwanie dla wędkarzy. Brak bezpośredniego połączenia z rzeką i wysoki poziom zamulenia dna sprzyjają bujnej roślinności podwodnej, która jest domem dla licznych wzdręg i karasi pospolitych. Brzegi są gęsto porośnięte trzciną, co znacząco utrudnia dostęp i wymaga brodzenia. Ze względu na płytkość i silne zarośnięcie, istnieje wysokie ryzyko niedoboru tlenu w cieplejszych miesiącach, co może wpływać na aktywność ryb. Wędkowanie tutaj to sztuka precyzji i cierpliwości, najlepiej sprawdza się w późnej wiośnie i lecie. Dominują tu gatunki odporne na trudne warunki, takie jak płoć i karaś pospolity.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22431, 2.1, 1.1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22432, 'Starorzecze Pratkowickie Środkowe 2', 'starorzecze-pratkowickie-srodkowe-2-czestochowa-22432', 'OXBOW', 51.0252752, 19.8629922, 'Śląskie', 'Częstochowa', 'To starorzecze, leżące w bezpośrednim sąsiedztwie Częstochowy, oferuje wędkarzom komfortowe warunki dzięki dobremu dostępowi do brzegów z obu stron. Charakteryzuje się umiarkowanym poziomem zarośnięcia i średnim zamuleniem dna, co sprzyja różnorodności gatunków ryb. Regularne połączenie z rzeką podczas wysokiej wody zapewnia świeżą wodę i migrację ryb, co minimalizuje ryzyko niedoboru tlenu. W tym łowisku dominują leszcz, płoć, lin, a także drapieżniki takie jak szczupak i okoń. Dno jest w dużej mierze czyste, co ułatwia wędkowanie i minimalizuje ryzyko zaczepów. Jest to idealne miejsce na wędkowanie przez cały sezon, od wiosny do jesieni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22432, 4.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Lin,Szczupak,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22433, 'Starorzecze Pratkowickie Północne', 'starorzecze-pratkowickie-polnocne-czestochowa-22433', 'OXBOW', 51.0260807, 19.8622674, 'Śląskie', 'Częstochowa', 'To płytkie i silnie zamulone starorzecze, położone na północ od Pratkowic, jest typowym przykładem zbiornika o trudnych warunkach. Brak połączenia z rzeką i wysokie zarośnięcie sprzyjają szybkiemu wysychaniu w okresach suszy, co czyni je łowiskiem sezonowym. Dostęp do brzegów jest bardzo trudny ze względu na bagnisty teren i gęstą roślinność, wymagając użycia wodoodpornych spodniobutów. Dominujące gatunki ryb to odporne karasie srebrzyste, wzdręgi i płocie, które dobrze znoszą zmienne warunki środowiskowe. Ze względu na płytkość i brak przepływu, ryzyko niedoboru tlenu jest bardzo wysokie. Najlepsze wyniki można osiągnąć późną wiosną, zanim zbiornik nadmiernie się nagrzeje i zacznie wysychać.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22433, 1.9, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22434, 'Starorzecze Chodlewskie', 'starorzecze-chodlewskie-rawicz-22434', 'OXBOW', 51.5116874, 16.814638, 'Wielkopolskie', 'Rawicz', 'Starorzecze Chodlewskie, zlokalizowane niedaleko Rawicza, to rozległe i głębokie łowisko o stałym połączeniu z rzeką, co zapewnia doskonałe warunki wodne. Charakteryzuje się niskim poziomem zamulenia i słabym zarośnięciem, co ułatwia wędkowanie i eksplorację. Brzegi są łatwo dostępne z obu stron, co jest dużym atutem dla wędkarzy. Bogactwo gatunków ryb obejmuje leszcze, płocie, okonie, a także cenne drapieżniki takie jak sandacz i sum. Czyste dno minimalizuje ryzyko zaczepów, czyniąc to miejsce idealnym dla różnych technik wędkarskich. Dzięki stałemu przepływowi, ryzyko niedoboru tlenu jest praktycznie zerowe, co gwarantuje aktywność ryb przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22434, 7.2, 2, 4.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Sandacz,Sum', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22435, 'Starorzecze Ziemiarskie', 'starorzecze-ziemiarskie-skierniewice-22435', 'OXBOW', 52.0362493, 20.2028203, 'Łódzkie', 'Skierniewice', 'Starorzecze Ziemiarskie, położone w pobliżu Skierniewic, to atrakcyjne łowisko o umiarkowanym zarośnięciu i średnim zamuleniu dna. Dostęp do brzegów jest dobry, co ułatwia przygotowanie stanowiska wędkarskiego. Łowisko łączy się z rzeką jedynie podczas wysokiego stanu wody, co wpływa na jego ekosystem, ale nie prowadzi do niedoborów tlenu. W wodach starorzecza dominują karpie, liny, leszcze oraz szczupaki, które znajdują tu dogodne warunki do żerowania i rozwoju. Na dnie można natrafić na pojedyncze korzenie i gałęzie, które stanowią kryjówki dla ryb. Najlepsze efekty wędkarskie osiąga się tutaj wiosną i latem, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22435, 5.1, 1.7, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Lin,Leszcz,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22436, 'Starorzecze Młynki Wschodnie', 'starorzecze-mlynki-wschodnie-starogard-gdanski-22436', 'OXBOW', 53.868251, 18.3525222, 'Pomorskie', 'Starogard Gdański', 'To niewielkie, silnie zarośnięte starorzecze w Młynkach, blisko Starogardu Gdańskiego, jest prawdziwym rajem dla wędkarzy poszukujących karasi pospolitych, linów i wzdręg. Brak połączenia z rzeką i wysoki poziom zamulenia dna sprzyjają bujnej roślinności podwodnej, która stanowi schronienie dla ryb. Brzegi są gęsto porośnięte trzciną, co wymaga cierpliwości i użycia wodoodpornych spodniobutów. Ze względu na te warunki, istnieje wysokie ryzyko niedoboru tlenu w gorących miesiącach. Wędkowanie tutaj najlepiej sprawdza się późną wiosną, kiedy roślinność nie jest jeszcze zbyt gęsta, a ryby aktywne po zimie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22436, 2.8, 1.3, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22437, 'Starorzecze Młynki Południowe', 'starorzecze-mlynki-poludniowe-starogard-gdanski-22437', 'OXBOW', 53.8672773, 18.3532856, 'Pomorskie', 'Starogard Gdański', 'To bardzo płytkie i silnie zamulone starorzecze w Młynkach, które w okresach suszy może całkowicie wyschnąć. Brak połączenia z rzeką i ekstremalnie wysoki poziom zarośnięcia sprawiają, że jest to łowisko dla najbardziej wytrwałych. Dostęp do brzegów jest niezwykle trudny, wymaga brodzenia w bagnistym terenie i przedzierania się przez gęstą roślinność. Dominują tu jedynie najbardziej odporne gatunki, takie jak karaś srebrzysty i wzdręga, które potrafią przetrwać w tak ekstremalnych warunkach. Wysokie ryzyko niedoboru tlenu i możliwość wyschnięcia zbiornika sprawiają, że najlepszym okresem na wędkowanie jest wczesna wiosna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22437, 1.5, 0.8, 1.6, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś srebrzysty,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22438, 'Starorzecze Borzechowo Centralne', 'starorzecze-borzechowo-centralne-starogard-gdanski-22438', 'OXBOW', 53.8708117, 18.3445966, 'Pomorskie', 'Starogard Gdański', 'Starorzecze Borzechowo Centralne, położone niedaleko Starogardu Gdańskiego, to przestronne łowisko z umiarkowanym zarośnięciem i niskim zamuleniem dna. Połączenie z rzeką podczas wysokiej wody zapewnia regularną wymianę wody, co wpływa na zdrowy ekosystem i minimalizuje ryzyko niedoboru tlenu. Brzegi są łatwo dostępne z obu stron, co jest dużym udogodnieniem dla wędkarzy. W wodach starorzecza można spotkać szczupaki, okonie, leszcze, liny i płocie, które znajdują tu bogate żerowiska. Dno jest w większości czyste, choć miejscami występują pojedyncze korzenie i gałęzie, stanowiące naturalne kryjówki dla ryb. Jest to doskonałe miejsce na wędkowanie przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22438, 6, 2.2, 4, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Lin,Płoć', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22439, 'Starorzecze Młynki Zachodnie', 'starorzecze-mlynki-zachodnie-starogard-gdanski-22439', 'OXBOW', 53.8686852, 18.3327497, 'Pomorskie', 'Starogard Gdański', 'To starorzecze w zachodniej części Młynek to typowe, płytkie łowisko o silnym zarośnięciu i średnim zamuleniu dna. Brak połączenia z rzeką sprawia, że jest to zbiornik wrażliwy na zmiany warunków pogodowych, z podwyższonym ryzykiem niedoboru tlenu. Dostęp do brzegów jest utrudniony ze względu na bagnisty teren i gęstą roślinność, co wymaga użycia specjalistycznego sprzętu. Dominujące gatunki to lin, karaś pospolity i wzdręga, które doskonale radzą sobie w takich warunkach. Gęsta roślinność podwodna stanowi zarówno schronienie dla ryb, jak i wyzwanie dla wędkarzy. Najlepsze wyniki można osiągnąć późną wiosną i latem, stosując techniki dopasowane do zarośniętego środowiska.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22439, 3.1, 1, 2.1, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22440, 'Starorzecze Osowo Leśne Południowe', 'starorzecze-osowo-lesne-poludniowe-starogard-gdanski-22440', 'OXBOW', 53.8698533, 18.330397, 'Pomorskie', 'Starogard Gdański', 'To starorzecze w Osowie Leśnym, zlokalizowane blisko Starogardu Gdańskiego, oferuje wędkarzom dobre warunki do połowu. Charakteryzuje się umiarkowanym zarośnięciem i średnim zamuleniem dna, co zapewnia stabilne środowisko dla ryb. Dostęp do brzegów jest łatwy z obu stron, co sprzyja komfortowemu wędkowaniu. Połączenie z rzeką podczas wysokiej wody wspomaga odnowę biologiczną zbiornika i minimalizuje ryzyko niedoboru tlenu. W wodach starorzecza dominują leszcze, płocie, okonie i szczupaki, co czyni je atrakcyjnym miejscem dla wędkarzy preferujących różne metody. Dno jest w większości czyste, co dodatkowo ułatwia łowienie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22440, 4, 1.6, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22441, 'Starorzecze Borzechowo Północne', 'starorzecze-borzechowo-polnocne-starogard-gdanski-22441', 'OXBOW', 53.8719153, 18.332399, 'Pomorskie', 'Starogard Gdański', 'Starorzecze Borzechowo Północne to jedno z bardziej atrakcyjnych łowisk w regionie Starogardu Gdańskiego, charakteryzujące się stałym połączeniem z rzeką. Niskie zamulenie i słabe zarośnięcie sprzyjają występowaniu wielu gatunków ryb, w tym cennym drapieżnikom takim jak sandacz i sum. Dostęp do brzegów jest bardzo dobry, co ułatwia wędkowanie z brzegu i z łodzi. Dzięki stałemu przepływowi wody, ryzyko niedoboru tlenu jest minimalne, co zapewnia stabilne warunki przez cały rok. Oprócz sandaczy i sumów, wędkarze mogą liczyć na leszcze, płocie i węgorze. Czyste dno sprawia, że jest to idealne miejsce dla różnych technik wędkarskich.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22441, 5.5, 1.9, 3.8, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sandacz,Sum,Leszcz,Płoć,Węgorz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22442, 'Starorzecze Osowo Leśne Centralne', 'starorzecze-osowo-lesne-centralne-starogard-gdanski-22442', 'OXBOW', 53.874949, 18.3290872, 'Pomorskie', 'Starogard Gdański', 'To centralne starorzecze w Osowie Leśnym to płytki i silnie zarośnięty zbiornik, charakteryzujący się wysokim poziomem zamulenia. Brak połączenia z rzeką sprawia, że jest to środowisko podatne na wahania poziomu wody i niedobory tlenu, szczególnie w upalne lata. Dostęp do brzegów jest trudny, wymaga przedzierania się przez gęstą roślinność i brodzenia w bagnistym terenie. Dominujące gatunki to odporne karasie pospolite, liny i wzdręgi, które doskonale adaptują się do takich warunków. Gęsta roślinność podwodna stanowi naturalne kryjówki, ale jednocześnie utrudnia wędkowanie. Najlepsze wyniki osiąga się tutaj późną wiosną, zanim roślinność stanie się zbyt bujna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22442, 2.4, 1.2, 2.4, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22443, 'Starorzecze Osowo Leśne Zachodnie', 'starorzecze-osowo-lesne-zachodnie-starogard-gdanski-22443', 'OXBOW', 53.8748276, 18.3247816, 'Pomorskie', 'Starogard Gdański', 'Starorzecze Osowo Leśne Zachodnie, położone w pobliżu Starogardu Gdańskiego, to interesujące łowisko z umiarkowanym zarośnięciem i średnim zamuleniem. Charakteryzuje się obecnością wielu zatopionych drzew, które stanowią doskonałe kryjówki dla ryb, ale również wyzwanie dla wędkarzy. Dostęp do brzegów jest trudny i wymaga użycia wodoodpornych spodniobutów. Łowisko łączy się z rzeką podczas wysokiej wody, co zapewnia regularną wymianę wody i minimalizuje ryzyko niedoboru tlenu. Dominujące gatunki to szczupak, okoń, płoć i leszcz. Najlepsze wyniki osiąga się wiosną i wczesną jesienią, kiedy drapieżniki są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22443, 3.3, 1.5, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22444, 'Starorzecze Borzechowo Północno-Zachodnie', 'starorzecze-borzechowo-polnocno-zachodnie-starogard-gdanski-22444', 'OXBOW', 53.8756118, 18.324006, 'Pomorskie', 'Starogard Gdański', 'To starorzecze, zlokalizowane na północny zachód od Borzechowa, jest jednym z głębszych i lepiej utrzymanych zbiorników w regionie. Posiada stałe połączenie z rzeką, co gwarantuje doskonałą jakość wody i minimalne zamulenie. Słabe zarośnięcie i czyste dno sprawiają, że jest to idealne miejsce dla wędkarzy ceniących komfort i różnorodność gatunków. Dostęp do brzegów jest bardzo dobry z obu stron. W wodach starorzecza dominują sandacze, sumy i węgorze, a także liczne leszcze i płocie. Stały dopływ świeżej wody eliminuje ryzyko niedoboru tlenu, co zapewnia aktywność ryb przez cały rok. To doskonałe łowisko dla wędkarzy poszukujących dużych drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22444, 4.8, 2, 3.9, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sandacz,Sum,Węgorz,Leszcz,Płoć', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22445, 'Starorzecze (Osowo Leśne)', 'starorzecze-osowo-lesne-osowo-lesne-22445', 'OXBOW', 53.8753922, 18.3269302, 'Województwo Pomorskie', 'Osowo Leśne', 'To starorzecze, położone w malowniczej okolicy Osowa Leśnego, charakteryzuje się typowym dla tego regionu mulistym dnem, miejscami przechodzącym w twardsze, piaszczyste podłoże. Brzegi są gęsto porośnięte trzciną i pałką wodną, co utrudnia dostęp do wody, ale jednocześnie stanowi doskonałe schronienie dla ryb. Podwodna roślinność jest umiarkowana, tworząc idealne środowisko dla drapieżników takich jak szczupak i okoń, które aktywnie polują wśród zarośli. Lin i karaś pospolity znajdują tu obfitość pokarmu w mule, a liczne płocie i leszcze żerują na otwartych partiach wody. Wędkowanie wymaga cierpliwości i często użycia brodźców, szczególnie w poszukiwaniu głębszych rynien. Najlepsze wyniki osiąga się wczesną wiosną i jesienią, kiedy ryby intensywnie żerują przed i po okresie letniego spowolnienia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22445, 3.5, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć,Leszcz', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22446, 'Starorzecze (Osowo Leśne)', 'starorzecze-osowo-lesne-osowo-lesne-22446', 'OXBOW', 53.874105, 18.3149454, 'Województwo Pomorskie', 'Osowo Leśne', 'To płytkie starorzecze w pobliżu Osowa Leśnego jest silnie zamulone, a jego dno pokrywa gruba warstwa osadów organicznych, co sprzyja rozwojowi bujnej roślinności podwodnej i nawodnej. Brzegi są tu szczególnie trudne, bagniste i niemal w całości zarośnięte, co sprawia, że dostęp do wody jest bardzo ograniczony i wymaga specjalistycznego sprzętu, takiego jak brodzce. Takie warunki są rajem dla lina i karasia pospolitego, które doskonale czują się w ciepłej, płytkiej wodzie bogatej w pokarm. Wzdręga i płoć również licznie występują, żerując wśród gęstych zarośli. Ze względu na silne zarastanie i dużą ilość materii organicznej, istnieje wysokie ryzyko przyduchy, zwłaszcza w upalne lata. Wędkowanie jest tu wyzwaniem, ale może przynieść satysfakcjonujące efekty, szczególnie na grunt i spławik w miejscach z mniejszym zagęszczeniem roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22446, 2.8, 1, 2.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22447, 'Starorzecze (Osowo Leśne)', 'starorzecze-osowo-lesne-osowo-lesne-22447', 'OXBOW', 53.8707014, 18.3066445, 'Województwo Pomorskie', 'Osowo Leśne', 'To starorzecze, położone nieco na zachód od Osowa Leśnego, charakteryzuje się brakiem stałego połączenia z rzeką, co przyczynia się do stabilności poziomu wody i umiarkowanego zamulenia. Dno jest zróżnicowane, z mulistymi zatokami i twardszymi, gliniastymi fragmentami, co sprzyja różnorodności gatunkowej. Brzegi są stosunkowo łatwo dostępne, co ułatwia wędkowanie z lądu, jednak miejscami porasta je pas trzcin. Akwen ten jest domem dla sporej populacji szczupaka i okonia, które wykorzystują podwodną roślinność jako kryjówki do polowań. Liczne leszcze i płocie żerują na otwartych przestrzeniach, a w płytszych, cieplejszych partiach można spotkać okazałe karasie pospolite. Wędkowanie jest tu możliwe przez cały sezon, oferując dobre warunki zarówno dla spinningistów, jak i wędkarzy spławikowych czy gruntowych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22447, 4, 1.8, 3.5, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Lin,Leszcz,Okoń,Karaś pospolity', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22448, 'Starorzecze (Osowo Leśne)', 'starorzecze-osowo-lesne-osowo-lesne-22448', 'OXBOW', 53.8693588, 18.3035242, 'Województwo Pomorskie', 'Osowo Leśne', 'To niewielkie i bardzo płytkie starorzecze w okolicy Osowa Leśnego jest silnie zamulone i zagrożone wysychaniem w okresach długotrwałej suszy. Jego dno to głównie gruba warstwa mułu, a brzegi są gęsto zarośnięte trzciną i inną roślinnością bagienną, co sprawia, że dostęp do wody jest niezwykle utrudniony. Akwen ten stanowi idealne środowisko dla karasia pospolitego i srebrzystego, które doskonale adaptują się do trudnych warunków tlenowych i wysokich temperatur. Wzdręga i płoć również licznie występują, żerując wśród gęstych zarośli. Niska głębokość i obfitość materii organicznej powodują wysokie ryzyko przyduchy w lecie, co wpływa na populację ryb. Wędkowanie jest tu specyficzne, wymagające precyzyjnego zarzucania w małe okna w roślinności, najlepiej w późnej wiośnie i latem, gdy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22448, 2, 0.8, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Karaś srebrzysty,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22449, 'Starorzecze (Mały Bukowiec)', 'starorzecze-maly-bukowiec-maly-bukowiec-22449', 'OXBOW', 53.8688122, 18.2801509, 'Województwo Pomorskie', 'Mały Bukowiec', 'To rozległe starorzecze w pobliżu Małego Bukowca wyróżnia się stałym połączeniem z głównym nurtem rzeki, co zapewnia dobrą cyrkulację wody i niskie zamulenie dna. Dno jest tu zróżnicowane, z twardszymi, piaszczysto-żwirowymi fragmentami oraz mulistymi zagłębieniami, co sprzyja bogactwu gatunkowemu. Brzegi są łatwo dostępne z obu stron, co jest dużym atutem dla wędkarzy, umożliwiając swobodne poruszanie się wzdłuż łowiska. Akwen ten jest znany z obfitości szczupaka i okonia, które znajdują tu doskonałe warunki do polowań, a także z dużych leszczy i płoci. Karpie również dobrze prosperują w tym środowisku, korzystając z obfitości naturalnego pokarmu. Brak ryzyka przyduchy sprawia, że wędkarstwo jest tu owocne przez cały sezon, oferując różnorodne możliwości dla spinningistów i wędkarzy gruntowych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22449, 5, 2, 4, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Płoć,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22450, 'Starorzecze (Sowi Dół)', 'starorzecze-sowi-dol-maly-bukowiec-22450', 'OXBOW', 53.8662698, 18.2779285, 'Województwo Pomorskie', 'Mały Bukowiec', 'To niewielkie starorzecze w rejonie Sowiego Dołu jest mocno zamulone, a jego płytkie dno pokrywa gruba warstwa osadów organicznych, co sprzyja intensywnemu rozwojowi roślinności wodnej. Brzegi są trudne do pokonania, bagniste i gęsto zarośnięte, co wymaga użycia brodźców i cierpliwości w poszukiwaniu dogodnych stanowisk. Akwen ten jest idealnym siedliskiem dla lina i karasia pospolitego, które doskonale czują się w ciepłej, płytkiej wodzie pełnej roślinności. Wzdręga również licznie występuje, żerując na powierzchni i wśród pływających liści. Ze względu na silne zarastanie i płytkość, ryzyko przyduchy jest wysokie, szczególnie w upalne, bezwietrzne dni. Wędkowanie jest tu wyzwaniem, ale celowanie w liny i karasie przy użyciu delikatnych zestawów spławikowych może przynieść sukces, zwłaszcza w późnej wiośnie i latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22450, 1.5, 0.9, 2.2, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22451, 'Starorzecze (Sowi Dół)', 'starorzecze-sowi-dol-maly-bukowiec-22451', 'OXBOW', 53.8643603, 18.2764742, 'Województwo Pomorskie', 'Mały Bukowiec', 'To starorzecze w okolicy Sowiego Dołu charakteryzuje się umiarkowanym zamuleniem i zróżnicowanym dnem, gdzie muliste fragmenty przeplatają się z twardszymi partiami. Brzegi są mocno zarośnięte trzciną, co utrudnia dostęp do wody i wymaga użycia brodźców, jednak tworzy doskonałe kryjówki dla ryb. Wśród dominujących gatunków ryb znajdziemy szczupaka i okonia, które aktywnie polują w gęstych zaroślach i na skraju otwartej wody. Płoć i karaś srebrzysty również licznie występują, żerując w różnych partiach akwenu. Pomimo umiarkowanego zamulenia, w cieplejszych miesiącach istnieje ryzyko niedoboru tlenu, co może wpływać na aktywność ryb. Wędkowanie jest najbardziej efektywne wiosną i wczesną jesienią, kiedy ryby są najbardziej aktywne, a roślinność nie jest jeszcze zbyt bujna.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22451, 2.2, 1.1, 2.8, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Płoć,Karaś srebrzysty', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22452, 'Starorzecze (Sowi Dół)', 'starorzecze-sowi-dol-maly-bukowiec-22452', 'OXBOW', 53.8637715, 18.2717988, 'Województwo Pomorskie', 'Mały Bukowiec', 'To starorzecze w rejonie Sowiego Dołu jest jednym z głębszych w okolicy, z dnem bogatym w zatopione drzewa i korzenie, które stanowią doskonałe kryjówki dla dużych ryb. Posiada połączenie z rzeką podczas wysokiej wody, co zapewnia odświeżenie wód i niższe ryzyko przyduchy. Brzegi są stosunkowo dobrze dostępne, co ułatwia wędkowanie z brzegu, choć miejscami występują pojedyncze zarośla. Akwen ten jest znany z dużych leszczy i płoci, które żerują na mulistych i twardszych fragmentach dna, a także z karpi, które często bywają tu łowione. Co ciekawe, w tym starorzeczu można spotkać także suma, co jest rzadkością w mniejszych zbiornikach, ale świadczy o jego połączeniu z rzeką i odpowiedniej głębokości. Wędkowanie jest tu owocne przez cały sezon, oferując emocjonujące doznania, zwłaszcza przy łowieniu drapieżników i dużych białorybów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22452, 3, 1.4, 3.2, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sum', 'Dobry z obu stron', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22453, 'Starorzecze (Sowi Dół)', 'starorzecze-sowi-dol-maly-bukowiec-22453', 'OXBOW', 53.8636064, 18.2675809, 'Województwo Pomorskie', 'Mały Bukowiec', 'To bardzo płytkie i silnie zamulone starorzecze w okolicy Sowiego Dołu jest praktycznie odcięte od głównego nurtu rzeki, co prowadzi do jego szybkiego zarastania i wysokiego ryzyka wysychania w upalne lata. Dno pokrywa gruba warstwa osadów organicznych, a brzegi są bagniste i niezwykle trudne do pokonania, wymagając użycia brodźców. W tych ekstremalnych warunkach doskonale radzą sobie karasie pospolite i wzdręgi, które są odporne na niedobory tlenu i wysokie temperatury. Płoć również występuje, ale w mniejszej liczebności. Ze względu na płytkość i brak cyrkulacji wody, ryzyko przyduchy jest bardzo wysokie, co ogranicza populację ryb do najbardziej wytrzymałych gatunków. Wędkowanie jest tu wyzwaniem, głównie w późnej wiośnie i latem, skupiając się na niewielkich okienkach w gęstej roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22453, 1.8, 0.7, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22454, 'Starorzecze (Sowi Dół)', 'starorzecze-sowi-dol-maly-bukowiec-22454', 'OXBOW', 53.861271, 18.2591265, 'Województwo Pomorskie', 'Mały Bukowiec', 'To starorzecze w rejonie Sowiego Dołu, charakteryzuje się umiarkowanym zamuleniem i zróżnicowanym dnem, z mulistymi zatokami i twardszymi partiami. Posiada połączenie z rzeką podczas wysokiej wody, co zapewnia regularne odświeżanie wód i sprzyja zdrowej populacji ryb. Brzegi są mocno zarośnięte trzciną, co utrudnia dostęp, ale jednocześnie stanowi doskonałe kryjówki dla ryb i wymaga użycia brodźców dla efektywnego wędkowania. Akwen jest domem dla licznych szczupaków i okoni, które polują wśród podwodnej roślinności, a także dla linów i płoci, żerujących w mulistych partiach. Ryzyko niedoboru tlenu jest niskie dzięki okresowym połączeniom z rzeką, co sprzyja aktywności ryb. Najlepsze sezony na wędkowanie to wiosna i wczesna jesień, kiedy ryby są najbardziej aktywne i łatwiej dostępne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22454, 2.5, 1.2, 2.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Lin,Okoń,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22455, 'Starorzecze (Sowi Dół)', 'starorzecze-sowi-dol-maly-bukowiec-22455', 'OXBOW', 53.8605694, 18.2562588, 'Województwo Pomorskie', 'Mały Bukowiec', 'To starorzecze w okolicy Sowiego Dołu jest jednym z bardziej przejrzystych i głębszych w regionie, z czystym dnem pozbawionym większych zaczepów, co ułatwia wędkowanie. Okresowe połączenia z rzeką podczas wysokiej wody zapewniają stały dopływ świeżej wody i niski poziom zamulenia, eliminując ryzyko przyduchy. Brzegi są dobrze dostępne z obu stron, co pozwala na swobodne poruszanie się i wybór najlepszych stanowisk. Akwen ten jest ceniony przez wędkarzy za obfitość leszczy i karpi, które osiągają tu imponujące rozmiary, a także za obecność szczupaka. Co więcej, w głębszych partiach starorzecza można spotkać sandacza, co świadczy o dobrej jakości wody i połączeniu z rzeką. Wędkowanie jest tu owocne przez cały sezon, oferując doskonałe warunki zarówno dla wędkarzy gruntowych, jak i spinningistów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22455, 3.2, 1.6, 3.8, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Leszcz,Karp,Szczupak,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22456, 'Starorzecze (Iwiczno)', 'starorzecze-iwiczno-iwiczno-22456', 'OXBOW', 53.857768, 18.2560194, 'Województwo Pomorskie', 'Iwiczno', 'To starorzecze, położone w malowniczej okolicy Iwiczna, charakteryzuje się stałym połączeniem z rzeką, co gwarantuje doskonałą jakość wody i niskie zamulenie dna. Dno jest zróżnicowane, z twardszymi, piaszczysto-żwirowymi fragmentami oraz mulistymi zagłębieniami, co sprzyja bogactwu gatunkowemu. Brzegi są łatwo dostępne z obu stron, co ułatwia wędkowanie i eksplorację łowiska. Akwen ten jest prawdziwym rajem dla drapieżników, takich jak szczupak, okoń i sandacz, które znajdują tu idealne warunki do polowań i rozrodu. Ponadto, licznie występują tu leszcze i płocie, a wędkarze mają szansę na złowienie węgorza, co świadczy o dobrej drożności połączenia z rzeką. Wędkowanie jest tu bardzo efektywne wiosną i wczesną jesienią, oferując szerokie możliwości dla różnych technik, od spinningu po grunt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22456, 4.5, 1.9, 4.2, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Leszcz,Okoń,Sandacz,Węgorz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22457, 'Starorzecze (Mały Bukowiec)', 'starorzecze-maly-bukowiec-maly-bukowiec-22457', 'OXBOW', 53.8690416, 18.2792146, 'Województwo Pomorskie', 'Mały Bukowiec', 'To starorzecze w pobliżu Małego Bukowca charakteryzuje się umiarkowanym zamuleniem i zróżnicowanym dnem, gdzie muliste fragmenty przeplatają się z twardszymi partiami. Posiada połączenie z rzeką podczas wysokiej wody, co zapewnia regularne odświeżanie wód, ale nie eliminuje całkowicie ryzyka przyduchy w upalne lato. Brzegi są mocno zarośnięte trzciną, co utrudnia dostęp do wody i wymaga użycia brodźców, jednak tworzy doskonałe kryjówki dla ryb. Akwen jest domem dla licznych linów i karasi pospolitych, które doskonale czują się w zarośniętych, mulistych partiach. Płoć i okoń również licznie występują, żerując w różnych częściach łowiska. Wędkowanie jest najbardziej efektywne w późnej wiośnie i latem, kiedy ryby są aktywne, a roślinność wodna zapewnia im schronienie.', NULL);
