INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22458, 'Starorzecze (Mały Bukowiec)', 'starorzecze-maly-bukowiec-maly-bukowiec-22458', 'OXBOW', 53.869647, 18.2816678, 'Województwo Pomorskie', 'Mały Bukowiec', 'To starorzecze w pobliżu Małego Bukowca wyróżnia się stałym połączeniem z głównym nurtem rzeki, co zapewnia doskonałą jakość wody i niskie zamulenie dna. Dno jest zróżnicowane, z twardszymi, piaszczystymi fragmentami oraz mulistymi zagłębieniami, co sprzyja bogactwu gatunkowemu. Brzegi są łatwo dostępne z obu stron, co jest dużym atutem dla wędkarzy, umożliwiając swobodne poruszanie się wzdłuż łowiska. Akwen ten jest znany z obfitości szczupaka i okonia, które znajdują tu doskonałe warunki do polowań, a także z dużych leszczy i płoci. Karpie również dobrze prosperują w tym środowisku, a wędkarze mają szansę na złowienie bolenia, co świadczy o dobrym połączeniu z rzeką. Brak ryzyka przyduchy sprawia, że wędkarstwo jest tu owocne przez cały sezon, oferując różnorodne możliwości dla spinningistów i wędkarzy gruntowych.', NULL);
