INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22459, 'Starorzecze (Mały Bukowiec)', 'starorzecze-maly-bukowiec-maly-bukowiec-22459', 'OXBOW', 53.8705839, 18.2977606, 'Województwo Pomorskie', 'Mały Bukowiec', 'To starorzecze w pobliżu Małego Bukowca charakteryzuje się umiarkowanym zamuleniem i zróżnicowanym dnem, gdzie muliste fragmenty przeplatają się z twardszymi partiami. Jest to akwen bez stałego połączenia z rzeką, co prowadzi do jego stopniowego zarastania i zwiększonego ryzyka przyduchy w okresach upałów. Brzegi są mocno zarośnięte trzciną i inną roślinnością, co utrudnia dostęp do wody i wymaga użycia brodźców dla efektywnego wędkowania. Akwen jest domem dla licznych linów i karasi pospolitych, które doskonale czują się w zarośniętych, mulistych partiach. Płoć i wzdręga również licznie występują, żerując w różnych częściach łowiska. Wędkowanie jest najbardziej efektywne w późnej wiośnie i latem, kiedy ryby są aktywne, a roślinność wodna zapewnia im schronienie i pokarm.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22459, 2.9, 1.4, 3.1, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22460, 'Starorzecze Czarne', 'starorzecze-czarne-czarna-woda-22460', 'OXBOW', 53.8493302, 18.2521567, 'Pomorskie', 'Czarna Woda', 'To starorzecze, położone w malowniczej okolicy Czarnej Wody, charakteryzuje się typowym dla tego typu zbiorników, mulistym dnem. Brzegi są częściowo dostępne, choć miejscami gęsto porośnięte trzciną i inną roślinnością przybrzeżną. Wiosną i podczas wyższych stanów wody starorzecze łączy się z pobliską rzeką, co sprzyja migracji ryb. Silne zarośnięcie roślinnością podwodną tworzy doskonałe kryjówki dla drapieżników, takich jak szczupak, oraz dla ryb spokojnego żeru, w tym lina i karasia pospolitego. Wędkowanie wymaga cierpliwości i często brodzenia, zwłaszcza w cieplejszych miesiącach, kiedy roślinność jest najbujniejsza. Jest to idealne miejsce dla wędkarzy ceniących dziką przyrodę i spokojne łowienie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22460, 3.8, 1.5, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Karaś pospolity,Płoć,Leszcz', 'Trudny, miejscami zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22461, 'Starorzecze Szałas', 'starorzecze-szalas-szalas-22461', 'OXBOW', 51.0478824, 20.6612506, 'Świętokrzyskie', 'Szałas', 'Starorzecze w pobliżu miejscowości Szałas to niewielki, ale urokliwy zbiornik wodny o charakterystycznym dla terenów nizinnych dnie, pokrytym warstwą mułu. Brzegi są w większości łatwo dostępne, choć lokalnie mogą występować strefy bagniste, utrudniające podejście. Łowisko to jest domem dla wielu gatunków ryb, w tym dużych okazów karasia pospolitego, lina oraz wzdręgi. Roślinność wodna jest umiarkowana, co ułatwia wędkowanie, ale jednocześnie zapewnia rybom wystarczające schronienie. Zbiornik nie ma stałego połączenia z rzeką, co czyni go bardziej stabilnym, ale jednocześnie naraża na ryzyko spadku poziomu tlenu w upalne lata. Wędkowanie tutaj jest przyjemne i relaksujące, idealne dla poszukiwaczy spokojnego łowienia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22461, 2.1, 1, 2.5, 'Brak', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Okoń,Płoć', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22462, 'Starorzecze Młynki (1)', 'starorzecze-mlynki-1-mlynki-22462', 'OXBOW', 53.8665483, 18.3590756, 'Pomorskie', 'Młynki', 'To jedno z kilku starorzeczy w okolicy Młynek, charakteryzujące się piaszczysto-mulistym dnem. Brzegi są umiarkowanie zarośnięte, co pozwala na dostęp do wody z wielu miejsc. Akwen ten jest bogaty w roślinność podwodną, stanowiącą idealne schronienie dla ryb, zwłaszcza dla lina i szczupaka. Połączenie z rzeką Wierzycą występuje sporadycznie, głównie podczas wiosennych roztopów, co sprzyja odświeżaniu wody i zarybianiu. Występuje tu liczna populacja płoci i leszczy, które dobrze czują się w spokojnych wodach starorzecza. Wędkowanie wymaga precyzji ze względu na liczne zaczepy, ale obfitość ryb wynagradza trudności. Jest to popularne miejsce wśród lokalnych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22462, 1.5, 1.8, 3, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Lin,Szczupak', 'Umiarkowany', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22463, 'Starorzecze Młynki (2)', 'starorzecze-mlynki-2-mlynki-22463', 'OXBOW', 53.8653255, 18.3612745, 'Pomorskie', 'Młynki', 'Kolejne starorzecze w kompleksie Młynek, wyróżniające się nieco większą głębokością i bardziej zróżnicowanym dnem. Dominują tu miejscami piaszczyste płycizny przechodzące w głębsze, muliste rynny. Dostęp do brzegów jest dobry, choć w niektórych miejscach utrudniony przez gęste krzewy i drzewa. W zbiorniku tym można spotkać dorodne okazy leszczy i płoci, a także drapieżniki takie jak szczupak i okoń, które polują wśród podwodnej roślinności. Połączenie z rzeką jest rzadsze niż w sąsiednich starorzeczach, co sprzyja stabilizacji populacji ryb. Ryzyko przyduchy jest niskie dzięki naturalnym procesom samooczyszczania. To doskonałe miejsce dla wędkarzy lubiących różnorodność łowisk.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22463, 2, 2.2, 4, 'Sporadyczne', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń', 'Dobry z większości stron', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22464, 'Starorzecze Młynki (3)', 'starorzecze-mlynki-3-mlynki-22464', 'OXBOW', 53.8642463, 18.3616684, 'Pomorskie', 'Młynki', 'To starorzecze, zlokalizowane w obrębie kompleksu Młynek, jest stosunkowo płytkie, z dominującym mulistym dnem. Charakteryzuje się bardzo silnym zarośnięciem brzegów trzciną i pałką wodną, co sprawia, że dostęp do wody jest utrudniony i często wymaga brodzenia. Jest to idealne środowisko dla lina, karasia pospolitego i wzdręgi, które znajdują tu obfitość pokarmu i schronienia. Połączenie z rzeką jest rzadkie, co może prowadzić do okresowego spadku poziomu tlenu w upalne, bezwietrzne dni. Mimo trudności w dostępie, łowisko to oferuje wspaniałe możliwości dla wędkarzy specjalizujących się w łowieniu w zarośniętych wodach. Cierpliwość i odpowiedni sprzęt są kluczem do sukcesu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22464, 1.2, 0.8, 2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22465, 'Starorzecze Młynki (4)', 'starorzecze-mlynki-4-mlynki-22465', 'OXBOW', 53.86137, 18.3635677, 'Pomorskie', 'Młynki', 'To starorzecze w Młynkach jest jednym z dłuższych i węższych w okolicy, z dnem typowym dla starorzeczy, czyli mieszanym – od piaszczystego po muliste. Brzegi są częściowo dostępne, z licznymi pomostami wędkarskimi i wydeptanymi ścieżkami, co ułatwia dostęp. Akwen ten jest regularnie zasilany przez wody gruntowe i rzadko łączy się z rzeką, co zapewnia stabilne warunki. Występują tu liczne populacje płoci, leszczy oraz okoni, a także szczupaki, które preferują takie środowiska. Roślinność podwodna jest umiarkowana, co pozwala na skuteczne wędkowanie z gruntu i na spławik. Jest to doskonałe miejsce na rodzinne wypady wędkarskie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22465, 2.5, 1.7, 3.5, 'Brak', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry, z licznymi stanowiskami', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22466, 'Starorzecze Młynki (5)', 'starorzecze-mlynki-5-mlynki-22466', 'OXBOW', 53.860837, 18.3645838, 'Pomorskie', 'Młynki', 'To starorzecze w kompleksie Młynek jest charakteryzowane przez stosunkowo czyste, piaszczyste dno z niewielkimi obszarami mulistymi. Brzegi są dobrze utrzymane i w większości łatwo dostępne, co czyni je popularnym miejscem wśród wędkarzy. Jest to akwen, w którym można spotkać karpie, liny oraz leszcze, a także drapieżne okonie. Połączenie z rzeką jest sporadyczne, co sprzyja rozwojowi stabilnej populacji ryb. Roślinność wodna jest słaba, co ułatwia prowadzenie przynęt i minimalizuje ryzyko zaczepów. Ryzyko niedoboru tlenu jest niskie, co zapewnia komfortowe warunki dla ryb przez cały rok. To idealne miejsce dla początkujących wędkarzy i tych, którzy cenią łatwość dostępu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22466, 1.8, 1.5, 3, 'Sporadyczne', 'Niskie', 'Słabe', FALSE, FALSE, 'Karp,Lin,Leszcz,Okoń', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22467, 'Starorzecze Młynki (6)', 'starorzecze-mlynki-6-mlynki-22467', 'OXBOW', 53.8602677, 18.3640569, 'Pomorskie', 'Młynki', 'Ostatnie z serii starorzeczy w Młynkach, to akwen o mulistym dnie i gęsto zarośniętych brzegach, szczególnie od strony lasu. Dostęp do wody jest trudny, wymaga przedzierania się przez gęste zarośla i często brodzenia. Jest to idealne środowisko dla dużych okazów lina i karasia pospolitego, które znajdują tu spokój i obfitość naturalnego pokarmu. Połączenie z rzeką jest praktycznie zerowe, co sprawia, że zbiornik jest odizolowany, ale też bardziej stabilny pod względem hydrologicznym. Wysokie zarośnięcie roślinnością podwodną sprzyja występowaniu szczupaków. Mimo trudności, to starorzecze oferuje wyjątkowe możliwości dla wędkarzy szukających prawdziwej dziczy i rzadziej odwiedzanych miejsc. Wymaga to jednak odpowiedniego przygotowania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22467, 1, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga', 'Trudny, mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna, zatopione gałęzie', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22468, 'Starorzecze Kamion (1)', 'starorzecze-kamion-1-kamion-22468', 'OXBOW', 51.9504027, 20.2562859, 'Mazowieckie', 'Kamion', 'Starorzecze w Kamionie to malowniczy zbiornik wodny, którego dno jest zróżnicowane, z przewagą mułu, ale także z twardszymi, piaszczystymi odcinkami. Brzegi są dobrze dostępne, częściowo utwardzone, co ułatwia wędkowanie. Akwen ten jest domem dla wielu gatunków ryb, w tym dużych karpi, leszczy i linów, a także drapieżników takich jak szczupak i okoń. Połączenie z rzeką Bzurą występuje sporadycznie, głównie podczas wiosennych wezbrań, co sprzyja migracji ryb i odświeżaniu wody. Roślinność wodna jest umiarkowana, co zapewnia rybom schronienie, ale nie utrudnia zbytnio wędkowania. Jest to popularne łowisko, cenione za obfitość ryb i łatwość dostępu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22468, 4.5, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Lin,Szczupak,Leszcz,Okoń', 'Dobry z większości stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22469, 'Starorzecze Kamion (2)', 'starorzecze-kamion-2-kamion-22469', 'OXBOW', 51.9503423, 20.2553902, 'Mazowieckie', 'Kamion', 'Drugie starorzecze w Kamionie to nieco mniejszy zbiornik, charakteryzujący się bardziej mulistym dnem i gęstszym zarośnięciem brzegów. Dostęp do wody jest miejscami utrudniony przez gęste krzewy i trzcinę, co wymaga brodzenia. Jest to idealne środowisko dla lina, karasia pospolitego i wzdręgi, które znajdują tu spokój i obfitość pokarmu. Ze względu na brak stałego połączenia z rzeką, zbiornik jest bardziej podatny na wahania poziomu tlenu w upalne lata. Mimo tych wyzwań, starorzecze oferuje wspaniałe możliwości dla wędkarzy ceniących dzikie łowiska. Wymaga to jednak odpowiedniego sprzętu i cierpliwości, aby dotrzeć do najlepszych miejscówek.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22469, 2.8, 1.5, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22470, 'Starorzecze Odrzykoń', 'starorzecze-odrzykon-odrzykon-22470', 'OXBOW', 49.7399157, 21.7224785, 'Podkarpackie', 'Odrzykoń', 'Starorzecze w Odrzykoniu to akwen o dnie mieszanym, z przewagą żwiru i piasku, co jest typowe dla starorzeczy rzek podgórskich, takich jak Wisłok. Brzegi są dobrze dostępne, z licznymi dogodnymi miejscami do wędkowania. W zbiorniku tym można spotkać zarówno ryby typowo rzeczne, jak kleń i jaź, które migrują podczas wysokich stanów wody, jak i gatunki starorzeczne, takie jak płoć i leszcz. Połączenie z rzeką Wisłok jest częste podczas wezbrań, co zapewnia stałe odświeżanie wody i różnorodność gatunkową. Niskie zarośnięcie roślinnością podwodną ułatwia prowadzenie przynęt. Jest to atrakcyjne łowisko dla wędkarzy poszukujących różnorodnych gatunków ryb w malowniczym otoczeniu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22470, 3, 1.8, 3.8, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Płoć,Leszcz,Kleń,Jaź,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22471, 'Starorzecze Łazy (1)', 'starorzecze-lazy-1-lazy-22471', 'OXBOW', 53.0913908, 21.5109282, 'Mazowieckie', 'Łazy', 'Starorzecze w Łazach to rozległy akwen o mulistym dnie, charakterystyczny dla doliny Narwi. Brzegi są gęsto porośnięte trzciną i inną roślinnością, co sprawia, że dostęp do wody jest utrudniony i wymaga brodzenia. Jest to raj dla szczupaków, linów i sumów, które znajdują tu obfitość pokarmu i schronienia w rozległej roślinności. Połączenie z rzeką Narew występuje podczas wysokich stanów wody, co sprzyja migracji ryb i odświeżaniu wody. Silne zarośnięcie roślinnością podwodną tworzy liczne zaczepy, ale jednocześnie zapewnia doskonałe warunki do żerowania i ukrywania się ryb. Wędkowanie tutaj jest wyzwaniem, ale może przynieść spektakularne efekty, zwłaszcza w poszukiwaniu dużych drapieżników.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22471, 5.2, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Sum,Leszcz,Płoć', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew i gęsta roślinność', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22472, 'Starorzecze Łazy (2)', 'starorzecze-lazy-2-lazy-22472', 'OXBOW', 53.0920213, 21.5104153, 'Mazowieckie', 'Łazy', 'To starorzecze w Łazach jest nieco mniejsze, ale równie atrakcyjne, z dnem typowym dla akwenów doliny Narwi – mulistym, z miejscowymi twardszymi fragmentami. Dostęp do brzegów jest umiarkowany, z kilkoma wydeptanymi stanowiskami wędkarskimi. W zbiorniku tym można spotkać liczne populacje płoci i leszczy, a także dorodne okazy karpia i lina. Połączenie z rzeką Narew jest rzadsze niż w sąsiednich starorzeczach, co sprzyja stabilizacji populacji ryb. Roślinność wodna jest umiarkowana, co ułatwia wędkowanie, ale jednocześnie zapewnia rybom wystarczające schronienie. Ryzyko niedoboru tlenu jest niskie, co zapewnia komfortowe warunki dla ryb. Jest to dobre miejsce na spokojne łowienie białorybu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22472, 3.5, 1.8, 3.5, 'Sporadyczne', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Karp,Lin,Okoń', 'Umiarkowany', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22473, 'Starorzecze Łazy (3)', 'starorzecze-lazy-3-lazy-22473', 'OXBOW', 53.0929484, 21.5099276, 'Mazowieckie', 'Łazy', 'Starorzecze w Łazach to akwen o głębszych partiach i zróżnicowanym dnie, gdzie muliste obszary przeplatają się z twardszymi. Brzegi są miejscami trudnodostępne z powodu gęstych zarośli, ale istnieją też otwarte przestrzenie. Jest to idealne środowisko dla sandacza i suma, które znajdują tu głębsze partie do bytowania, a także dla leszczy i płoci. Stałe połączenie z rzeką Narew występuje podczas większych wezbrań, co zapewnia regularne odświeżanie wody i sprzyja migracji ryb. Roślinność podwodna jest umiarkowana, ale w głębszych partiach występują zatopione drzewa, stanowiące doskonałe kryjówki. Wędkowanie wymaga znajomości łowiska i często użycia echosondy, ale może przynieść imponujące rezultaty.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22473, 4, 2.5, 5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sandacz,Sum,Leszcz,Płoć,Szczupak', 'Umiarkowany, miejscami trudny', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22474, 'Starorzecze Łazy (4)', 'starorzecze-lazy-4-lazy-22474', 'OXBOW', 53.0933016, 21.5084694, 'Mazowieckie', 'Łazy', 'Ostatnie z serii starorzeczy w Łazach to płytki, ale długi zbiornik o bardzo mulistym dnie i silnie zarośniętych brzegach. Dostęp do wody jest wyjątkowo trudny, wymagający brodzenia przez gęste trzciny i często przedzierania się przez zarośla. Jest to idealne środowisko dla karasia pospolitego, lina i wzdręgi, które doskonale czują się w takich warunkach. Brak stałego połączenia z rzeką i płytkość zbiornika sprawiają, że jest on podatny na ryzyko niedoboru tlenu w upalne lata. Mimo tych trudności, to starorzecze oferuje wyjątkowe możliwości dla wędkarzy ceniących dzikie i nieuczęszczane miejsca. Wymaga to odpowiedniego przygotowania i cierpliwości, ale może nagrodzić pięknymi okazami ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22474, 2.2, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22475, 'Starorzecze (Wasilków)', 'starorzecze-wasilkow-wasilkow-22475', 'OXBOW', 53.1932567, 23.2002483, 'Podlaskie', 'Wasilków', 'To malownicze starorzecze, położone w pobliżu Wasilkowa, charakteryzuje się urozmaiconym dnem, gdzie piaszczyste płycizny przeplatają się z mulistymi głębiami. Brzegi są częściowo dostępne, choć miejscami porasta je gęsta roślinność szuwarowa, zwłaszcza trzciny i pałki wodne. Woda w zbiorniku jest zazwyczaj czysta, a jego połączenie z rzeką Narew podczas wiosennych wylewów zapewnia stałe zarybianie. Dominującymi gatunkami ryb są tu płocie, leszcze, szczupaki oraz liny, które dobrze czują się w zarośniętych partiach. Wędkarze mogą spodziewać się udanych połowów, choć lokalne zaczepy w postaci zatopionych gałęzi wymagają uwagi. Jest to łowisko idealne do spędzania czasu na łonie natury, oferujące zarówno spokojne miejsca, jak i te bardziej wymagające.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22475, 3.5, 1.8, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Szczupak,Lin,Okoń', 'Dobry w niektórych miejscach, lokalnie zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22476, 'Starorzecze (Dereczanka)', 'starorzecze-dereczanka-koden-22476', 'OXBOW', 52.075791, 23.4314654, 'Lubelskie', 'Kodeń', 'Starorzecze to, zlokalizowane w okolicach Dereczanki, stanowi typowy przykład dzikiego, nadrzecznego zbiornika w dolinie Bugu. Dno jest tu w przeważającej części muliste, z licznymi zagłębieniami i podwodnymi roślinami, które tworzą doskonałe kryjówki dla ryb. Brzegi są trudnodostępne, często bagniste i gęsto zarośnięte olchami oraz wysokimi trzcinami, co wymaga użycia wodoodpornego obuwia. Wiosenne wylewy rzeki Bug regularnie zasilają starorzecze świeżą wodą, co pozytywnie wpływa na populację ryb. Dominują tu liny, karasie pospolite, szczupaki oraz wzdręgi, które znajdują tu idealne warunki do życia. Wędkowanie jest tu wyzwaniem, ale nagrodą są często piękne, dzikie okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22476, 2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga', 'Trudny, miejscami bagnisty', TRUE, 'Dużo zatopionych drzew i gęstej roślinności podwodnej', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22477, 'Starorzecze (Dereczanka)', 'starorzecze-dereczanka-koden-22477', 'OXBOW', 52.07786, 23.4324254, 'Lubelskie', 'Kodeń', 'Ten niewielki zbiornik w rejonie Dereczanki charakteryzuje się silnym zamuleniem dna, co sprzyja rozwojowi bujnej roślinności podwodnej i szuwarowej. Brzegi są mocno zarośnięte trzciną i krzewami, co sprawia, że dostęp do wody jest utrudniony i wymaga przygotowania. Okresowe połączenia z rzeką Bug podczas wezbrań wód pozwalają na odświeżenie ekosystemu, ale ogólnie jest to łowisko o charakterze izolowanym. Wysoki poziom zarośnięcia i płytkość zbiornika zwiększają ryzyko przyduchy w upalne lata. Dominującymi gatunkami są tu liny, karasie pospolite, wzdręgi oraz płocie, które dobrze znoszą trudne warunki. Wędkowanie wymaga cierpliwości i często użycia sprzętu pływającego lub brodzenia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22477, 1.8, 1.3, 2.8, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną, trudny', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22478, 'Starorzecze (Dobryń Duży)', 'starorzecze-dobryn-duzy-koden-22478', 'OXBOW', 52.0828252, 23.4370068, 'Lubelskie', 'Kodeń', 'Starorzecze w okolicach Dobrynia Dużego to średniej wielkości zbiornik, który zachował wiele naturalnych cech doliny Bugu. Dno jest zróżnicowane, od piaszczystych blatów po muliste zagłębienia, co sprzyja różnorodności gatunkowej. Brzegi są częściowo dostępne, z fragmentami porośniętymi drzewami i krzewami, które zapewniają cień i schronienie. Połączenie z rzeką podczas wiosennych roztopów jest kluczowe dla odnowienia populacji ryb i utrzymania dobrej jakości wody. Wśród ryb dominują płocie, leszcze, szczupaki, okonie i liny, co czyni to łowisko atrakcyjnym dla wędkarzy. Jest to miejsce, gdzie można liczyć na ciekawe brania, szczególnie w pobliżu podwodnych zarośli i zatopionych przeszkód.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22478, 2.5, 1.6, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Szczupak,Okoń,Lin', 'Dobry w niektórych miejscach, lokalnie zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22479, 'Starorzecze (Gunice)', 'starorzecze-gunice-police-22479', 'OXBOW', 53.5550387, 14.4397504, 'Zachodniopomorskie', 'Police', 'To rozległe starorzecze, położone niedaleko Polic w rejonie Gunice, charakteryzuje się stałym połączeniem z Odrą, co zapewnia regularną wymianę wody i bogactwo gatunkowe. Dno jest przeważnie piaszczysto-muliste, z nielicznymi zaczepami, co sprzyja różnym technikom wędkarskim. Brzegi są dobrze dostępne, z licznymi pomostami i dogodnymi miejscami do rozłożenia sprzętu, co czyni je popularnym łowiskiem. Silne prądy są rzadkością, a woda jest zazwyczaj klarowna, co ułatwia obserwację. Wśród dominujących gatunków ryb znajdziemy tu szczupaki, okonie, leszcze, płocie oraz sandacze, które chętnie żerują w tym środowisku. Łowisko jest odpowiednie dla wędkarzy na każdym poziomie zaawansowania, oferując komfortowe warunki i szansę na okazałe ryby.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22479, 4, 2, 4.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22480, 'Starorzecze (Gunice)', 'starorzecze-gunice-police-22480', 'OXBOW', 53.555865, 14.4468208, 'Zachodniopomorskie', 'Police', 'To drugie starorzecze w pobliżu Gunice, równie atrakcyjne jak jego sąsiad, z podobnym, stałym połączeniem z Odrą. Dno charakteryzuje się mieszanką piasku i mułu, z nielicznymi, ale potencjalnie rybnymi zaczepami. Brzegi są łatwo dostępne, co ułatwia dotarcie do wielu stanowisk wędkarskich i pozwala na swobodne przemieszczanie się. Jakość wody jest wysoka, a umiarkowane zarośnięcie sprzyja występowaniu różnorodnych gatunków ryb. Można tu liczyć na udane połowy szczupaków, okoni, leszczy, płoci, a także sandaczy, które chętnie polują w tych wodach. To doskonałe miejsce dla wędkarzy ceniących sobie komfort i bogactwo rybostanu przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22480, 3.8, 1.9, 4.2, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22481, 'Starorzecze (Orchówek)', 'starorzecze-orchowek-wlodawa-22481', 'OXBOW', 51.5270042, 23.5910041, 'Lubelskie', 'Włodawa', 'Starorzecze zlokalizowane w rejonie Orchówka to dziki i malowniczy zbiornik, będący częścią ekosystemu doliny Bugu. Dno jest w dużej mierze muliste i bogate w roślinność podwodną, co stanowi idealne środowisko dla wielu gatunków ryb. Brzegi są trudnodostępne, często bagniste i gęsto zarośnięte drzewami oraz wysokimi szuwarami, co sprawia, że wędkowanie bywa wyzwaniem. Połączenia z rzeką Bug podczas wezbrań wód są kluczowe dla utrzymania bioróżnorodności i zarybiania zbiornika. Wśród dominujących ryb znajdziemy tu liny, karasie pospolite, szczupaki, wzdręgi oraz leszcze. To łowisko dla wędkarzy szukających prawdziwie dzikiego doświadczenia, gdzie natura gra pierwsze skrzypce.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22481, 2.2, 1.7, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga,Leszcz', 'Trudny, bagnisty i gęsto zarośnięty', TRUE, 'Dużo zatopionych drzew i gęsta roślinność podwodna', 'Wiosna, wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22482, 'Starorzecze (Wereszczyn)', 'starorzecze-wereszczyn-urszulin-22482', 'OXBOW', 51.3653245, 23.2278923, 'Lubelskie', 'Urszulin', 'To niewielkie starorzecze w okolicach Wereszczyna charakteryzuje się płytkim, silnie zamulonym dnem, co sprzyja intensywnemu rozwojowi roślinności wodnej. Brzegi są mocno zarośnięte trzciną, pałką wodną i innymi szuwarami, przez co dostęp do wody jest bardzo ograniczony i wymaga specjalnego przygotowania. Brak stałego połączenia z rzeką sprawia, że zbiornik jest bardziej podatny na wahania poziomu wody i stężenia tlenu. Pomimo tych trudności, jest to ostoją dla wielu gatunków ryb, zwłaszcza tych odpornych na trudne warunki. Dominują tu karasie pospolite, liny, wzdręgi i płocie, które doskonale odnajdują się w zarośniętych partiach. Wędkowanie jest tu wyzwaniem, ale może przynieść satysfakcję w postaci dzikich, walecznych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22482, 1.5, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną, dostęp tylko z pomostów lub z łodzi', TRUE, 'Gęsta roślinność podwodna i muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22483, 'Starorzecze (Wereszczyn)', 'starorzecze-wereszczyn-urszulin-22483', 'OXBOW', 51.3647146, 23.227869, 'Lubelskie', 'Urszulin', 'Drugie starorzecze w pobliżu Wereszczyna to bardzo płytki i silnie zamulony zbiornik, charakteryzujący się ekstremalnym zarośnięciem. Dno jest niemal w całości pokryte grubą warstwą mułu i gęstą roślinnością podwodną, co utrudnia wędkowanie. Brzegi są praktycznie niedostępne z uwagi na rozległe mokradła i gęste szuwary, wymagające brodzenia w wodzie. Całkowity brak połączenia z rzeką sprawia, że zbiornik jest bardzo wrażliwy na susze i ryzyko przyduchy jest wysokie. W takich warunkach najlepiej czują się karasie pospolite, wzdręgi i liny, które są odporne na niedobory tlenu. Łowienie tutaj to prawdziwa szkoła przetrwania dla wędkarza, nagradzająca jednak spotkaniem z rybami z dzikiej populacji.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22483, 1.2, 0.9, 2.2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Bardzo trudny, gęste zarośla i muł', TRUE, 'Gęsta roślinność podwodna i zalegający muł', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22484, 'Starorzecze (Wereszczyn)', 'starorzecze-wereszczyn-urszulin-22484', 'OXBOW', 51.3659562, 23.2273307, 'Lubelskie', 'Urszulin', 'To najmniejsze ze starorzeczy w okolicy Wereszczyna, charakteryzujące się skrajnie płytkim dnem i bardzo wysokim stopniem zamulenia. Roślinność podwodna i nawodna jest tu niezwykle bujna, tworząc niemalże pływające wyspy. Dostęp do wody jest praktycznie niemożliwy bez specjalistycznego sprzętu, a brodzenie jest koniecznością. Całkowite odcięcie od głównego nurtu rzeki sprawia, że zbiornik jest niezwykle wrażliwy na warunki atmosferyczne, a ryzyko wyschnięcia jest realne. W tych ekstremalnych warunkach przetrwają jedynie najbardziej wytrzymałe gatunki, takie jak karasie pospolite i wzdręgi. Wędkarstwo tutaj to prawdziwa przygoda dla poszukiwaczy dzikich, nieuciśnionych ryb, wymagająca jednak dużej determinacji.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22484, 1, 0.8, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga', 'Praktycznie brak dostępu z brzegu', TRUE, 'Gęsta roślinność podwodna, muł i zatopione gałęzie', 'Wczesna wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22485, 'Starorzecze koło Recza', 'starorzecze-kolo-recza-stargard-22485', 'OXBOW', 52.9894138, 15.9551116, 'Zachodniopomorskie', 'Stargard', 'To starorzecze, zlokalizowane w malowniczej okolicy koło Recza, jest przykładem zbiornika o umiarkowanym stopniu naturalności. Dno jest zróżnicowane, z piaszczystymi fragmentami i mulistymi zagłębieniami, co sprzyja różnorodności siedlisk. Brzegi są częściowo dostępne, choć miejscami występują zarośla, które mogą utrudniać swobodne wędkowanie. Okresowe połączenia z pobliską rzeką Drawą podczas wysokich stanów wody zapewniają dopływ świeżej wody i migrację ryb. Dominującymi gatunkami są tu szczupaki, okonie, płocie, leszcze i liny, które dobrze czują się w tym środowisku. Łowisko oferuje dobre warunki do spędzania czasu na łonie natury, z szansą na ciekawe połowy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22485, 2.8, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz,Lin', 'Dobry w niektórych miejscach', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22486, 'Starorzecze (Czarnolesie)', 'starorzecze-czarnolesie-stargard-22486', 'OXBOW', 52.992675, 15.9503017, 'Zachodniopomorskie', 'Stargard', 'Starorzecze w pobliżu Czarnolesia to atrakcyjne łowisko o dobrze utrzymanym charakterze, zlokalizowane w pięknej scenerii. Dno jest w większości czyste, z domieszką piasku i niewielkimi obszarami mulistymi, co ułatwia prowadzenie przynęt. Brzegi są w większości dobrze dostępne, z licznymi, dogodnymi stanowiskami dla wędkarzy, co sprzyja komfortowemu spędzaniu czasu. Połączenie z rzeką Drawą jest okresowe, co zapewnia odświeżenie wód i uzupełnienie rybostanu po zimie. Wśród dominujących gatunków ryb znajdziemy tu szczupaki, okonie, płocie, leszcze i liny, które występują w zdrowych populacjach. Jest to łowisko idealne dla wędkarzy ceniących sobie zarówno komfort, jak i różnorodność potencjalnych zdobyczy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22486, 3, 1.6, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz,Lin', 'Dobry z większości stron', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Wiosna, lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22487, 'Starorzecze (Kępa Kiełpińska)', 'starorzecze-kepa-kielpinska-lomianki-22487', 'OXBOW', 52.3764625, 20.8765436, 'Mazowieckie', 'Łomianki', 'To jedno z najbardziej znanych starorzeczy Wisły w okolicach Kępy Kiełpińskiej, cenione przez wędkarzy za bogactwo rybostanu. Dno jest zróżnicowane, od piaszczystych płycizn po głębokie rynny z mulistym osadem, oferując różnorodne siedliska. Brzegi są łatwo dostępne, z wieloma wydeptanymi ścieżkami i stanowiskami, co sprzyja wygodnemu wędkowaniu. Połączenie z Wisłą podczas wysokich stanów wody jest regularne i zapewnia stałe zasilanie w wodę oraz migrację ryb. Wśród dominujących gatunków ryb znajdziemy tu leszcze, płocie, szczupaki, okonie, sandacze, a nawet sumy, co czyni to łowisko niezwykle atrakcyjnym. Jest to miejsce, gdzie każdy wędkarz, niezależnie od preferowanej metody, znajdzie coś dla siebie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22487, 5, 2.5, 6, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Sandacz,Sum', 'Dobry, często z wydeptanymi ścieżkami', FALSE, 'Pojedyncze zatopione drzewa, ale ogólnie czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22488, 'Starorzecze (Dziekanów Polski)', 'starorzecze-dziekanow-polski-lomianki-22488', 'OXBOW', 52.3772596, 20.874558, 'Mazowieckie', 'Łomianki', 'Starorzecze w pobliżu Dziekanowa Polskiego to kolejne popularne łowisko nad Wisłą, charakteryzujące się dużą powierzchnią i zróżnicowaną głębokością. Dno jest mieszane, z przewagą piasku i żwiru na płyciznach oraz mulistymi osadami w głębszych partiach, co sprzyja różnym gatunkom ryb. Brzegi są bardzo dobrze dostępne, z licznymi, przygotowanymi stanowiskami wędkarskimi, co czyni to miejsce idealnym dla rodzin i początkujących. Okresowe połączenia z Wisłą gwarantują dobrą jakość wody i stałe zarybianie naturalnymi drogami. Dominującymi gatunkami są leszcze, płocie, szczupaki, okonie, sandacze i sumy, co zapewnia emocjonujące wędkowanie. To łowisko o wysokiej kulturze wędkarskiej, oferujące komfortowe warunki i dużą szansę na sukces.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22488, 4.8, 2.4, 5.5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Sandacz,Sum', 'Dobry, z licznymi stanowiskami wędkarskimi', FALSE, 'Pojedyncze zatopione drzewa', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22489, 'Starorzecze (Hruszew)', 'starorzecze-hruszew-drohiczyn-22489', 'OXBOW', 52.3153942, 22.7223619, 'Podlaskie', 'Drohiczyn', 'Starorzecze w okolicach Hruszewa to typowy zbiornik doliny Bugu, charakteryzujący się dzikim i malowniczym otoczeniem. Dno jest w dużej mierze muliste, z licznymi zagłębieniami i obszarami porośniętymi roślinnością podwodną, co stanowi idealne kryjówki dla ryb. Brzegi są dostępne, choć miejscami mogą być zarośnięte krzewami i trzciną, co dodaje łowisku naturalnego uroku. Połączenie z rzeką Bug podczas wiosennych wezbrań jest kluczowe dla odświeżenia wód i zapewnienia różnorodności gatunkowej. Dominującymi gatunkami są tu leszcze, płocie, liny, szczupaki i okonie, które dobrze adaptują się do zmiennych warunków. To łowisko dla wędkarzy ceniących sobie spokój i bliskość natury, z szansą na złowienie pięknych okazów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22489, 3, 1.8, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Lin,Szczupak,Okoń', 'Dostępny, miejscami zarośnięty', FALSE, 'Pojedyncze zatopione korzenie i gałęzie', 'Wiosna, lato, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22490, 'Starorzecze Hruszewskie A', 'starorzecze-hruszewskie-a-drohiczyn-22490', 'OXBOW', 52.3162308, 22.7229161, 'Podlaskie', 'Drohiczyn', 'To starorzecze, położone w malowniczej okolicy Hruszewa, charakteryzuje się dość zróżnicowanym dnem, gdzie piaszczyste płycizny przeplatają się z mulistymi zagłębieniami. Brzegi są częściowo dostępne, jednak w wielu miejscach porasta je gęsta trzcina i krzewy, co utrudnia swobodne poruszanie się. Roślinność podwodna jest umiarkowana, tworząc idealne kryjówki dla drapieżników. Akwen ten jest znany z populacji lina i karasia pospolitego, a także okazowych szczupaków. Wędkowanie z brzegu wymaga często użycia długiej wędki lub brodzenia, zwłaszcza w poszukiwaniu ryb żerujących bliżej środka. Ryzyko przyduchy istnieje, szczególnie w upalne lata, co może wpływać na aktywność ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22490, 3.2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Dobry z jednej strony, druga bagnista', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22491, 'Starorzecze Hruszewskie B', 'starorzecze-hruszewskie-b-drohiczyn-22491', 'OXBOW', 52.316827, 22.7212101, 'Podlaskie', 'Drohiczyn', 'Drugie starorzecze w rejonie Hruszewa oferuje nieco głębsze partie i mniej zarośnięte brzegi, co czyni je bardziej przystępnym łowiskiem. Dno jest tu głównie piaszczysto-żwirowe, z niewielkimi osadami mułu, co sprzyja rozwojowi populacji ryb drapieżnych, takich jak szczupak i okoń. Roślinność podwodna jest rzadsza, skupiona głównie w płytszych zatoczkach, gdzie chętnie żerują płocie i leszcze. Dostęp do wody jest stosunkowo łatwy, z kilkoma dogodnymi stanowiskami wędkarskimi. Połączenie z rzeką podczas wiosennych roztopów zapewnia regularne zasilanie w świeżą wodę i migrację ryb. To doskonałe miejsce dla wędkarzy ceniących sobie komfort i różnorodność gatunków.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22491, 2.8, 1.8, 3.5, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć', 'Dobry, miejscami lekko zarośnięty', FALSE, 'Czyste dno z pojedynczymi zaczepami', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22492, 'Starorzecze Hruszewskie C', 'starorzecze-hruszewskie-c-drohiczyn-22492', 'OXBOW', 52.3174827, 22.7213501, 'Podlaskie', 'Drohiczyn', 'To najbardziej dzikie i wymagające starorzecze w kompleksie Hruszewa, charakteryzujące się znacznym zamuleniem i bardzo silnym porostem roślinności, zarówno na brzegach, jak i pod wodą. Głębia jest niewielka, a dno w większości pokryte grubą warstwą osadów organicznych, co sprzyja występowaniu karasia pospolitego i wzdręgi. Dostęp do wody jest niezwykle trudny, wymaga przedzierania się przez gęste zarośla i brodzenia w bagnistym terenie. W upalne lata istnieje ryzyko całkowitego wyschnięcia płytszych partii, co wpływa na populację ryb. Mimo trudności, dla cierpliwych wędkarzy akwen ten może zaoferować piękne okazy lina i karasia, szczególnie w miejscach z otwartymi ''oknami'' w roślinności.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22492, 4.1, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin,Płoć', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Dużo zatopionych drzew i gęsta roślinność', 'Późna wiosna i wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22493, 'Starorzecze Borki', 'starorzecze-borki-kedzierzyn-kozle-22493', 'OXBOW', 50.4142983, 18.0845954, 'Opolskie', 'Kędzierzyn-Koźle', 'Starorzecze w Borkach to rozległy akwen z regularnym połączeniem z rzeką, co zapewnia stałą cyrkulację wody i bogactwo gatunkowe. Dno jest zróżnicowane, z przewagą piaszczysto-mulistego podłoża i licznymi podwodnymi górkami. Brzegi są łatwo dostępne, z dobrze utrzymanymi stanowiskami wędkarskimi, co sprzyja komfortowemu łowieniu. Wędkarze mogą liczyć na obfite połowy leszczy, karpi, a także okazowych sumów, które znajdują tu idealne warunki do życia. Roślinność podwodna jest umiarkowana, tworząc schronienie dla drobnicy i drapieżników. Jest to popularne łowisko, które oferuje dobre warunki zarówno dla początkujących, jak i doświadczonych wędkarzy przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22493, 7.5, 2.2, 4.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Sum,Szczupak,Płoć', 'Dobry, z licznymi stanowiskami', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22494, 'Starorzecze Ziemiary', 'starorzecze-ziemiary-sochaczew-22494', 'OXBOW', 52.0586356, 20.1930784, 'Mazowieckie', 'Sochaczew', 'Starorzecze Ziemiary to typowe łowisko starorzeczne, charakteryzujące się bujną roślinnością brzegową i podwodną, która tworzy labirynt idealnych kryjówek dla ryb. Dno jest w większości muliste, z licznymi zatopionymi roślinami i gałęziami, co wymaga precyzyjnego umieszczenia zestawu. Dostęp do wody jest utrudniony przez gęste pasy trzcin, dlatego brodzenie jest często konieczne. Akwen ten jest rajem dla lina i karasia pospolitego, a także kryje w sobie spore szczupaki, które polują wśród zarośli. W upalne dni należy liczyć się z ryzykiem przyduchy, co może wpływać na żerowanie ryb. To wyzwanie dla wędkarzy szukających dzikich i spokojnych miejsc.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22494, 5.8, 1.7, 3.2, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Wzdręga', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna i pojedyncze pnie', 'Wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22495, 'Starorzecze Warszawskie (Północne)', 'starorzecze-warszawskie-polnocne-warszawa-22495', 'OXBOW', 52.3208197, 20.9260286, 'Mazowieckie', 'Warszawa', 'To starorzecze, położone w północnej części Warszawy, jest popularnym miejscem wśród miejskich wędkarzy. Charakteryzuje się zróżnicowanym dnem, gdzie piaszczyste płycizny przechodzą w muliste rynny, oferując różnorodne siedliska dla ryb. Brzegi są w większości łatwo dostępne, a w niektórych miejscach znajdują się kładki i pomosty. Akwen ten łączy się z rzeką podczas wysokich stanów wody, co sprzyja regularnemu zarybianiu i migracji ryb. Dominują tu leszcze, płocie i okonie, a także można złowić ładne karpie i szczupaki. Umiarkowane zarośnięcie pozwala na swobodne wędkowanie, a bliskość miasta sprawia, że jest to idealne miejsce na szybki wypad na ryby.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22495, 6.1, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Karp', 'Dobry, częściowo zagospodarowany', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22496, 'Starorzecze Warszawskie (Południowe)', 'starorzecze-warszawskie-poludniowe-warszawa-22496', 'OXBOW', 52.3187447, 20.9275399, 'Mazowieckie', 'Warszawa', 'Południowa część starorzecza warszawskiego to bardziej dziki i mniej dostępny obszar, idealny dla wędkarzy ceniących sobie spokój i wyzwania. Dno jest mocno zamulone, z licznymi zaczepami w postaci zatopionych drzew i gęstej roślinności podwodnej. Brzegi są trudno dostępne, często bagniste i porośnięte gęstą trzciną, co wymaga brodzenia lub poszukiwania nielicznych, otwartych stanowisk. Akwen ten jest domem dla licznych linów i karasi srebrzystych, a także wzdręg i płoci. Mimo połączenia z rzeką podczas wezbrań, wysoki poziom zamulenia i roślinności zwiększa ryzyko przyduchy w gorących miesiącach. To łowisko dla cierpliwych i wytrwałych wędkarzy, którzy potrafią odnaleźć ryby w trudnych warunkach.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22496, 4.9, 1.8, 3.5, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty i gęsto zarośnięty', TRUE, 'Dużo zatopionych drzew i gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22497, 'Starorzecze Paniowice A', 'starorzecze-paniowice-a-wroclaw-22497', 'OXBOW', 51.2125755, 16.9139276, 'Dolnośląskie', 'Wrocław', 'Starorzecze Paniowice A to jedno z bardziej atrakcyjnych łowisk w okolicach Wrocławia, charakteryzujące się stałym połączeniem z rzeką, co gwarantuje dobrą jakość wody i bogactwo ryb. Dno jest zróżnicowane, z głębokimi rynnami i piaszczystymi blatami, idealnymi dla sandacza i szczupaka. Brzegi są dobrze dostępne, z wieloma wygodnymi stanowiskami dla wędkarzy. Roślinność podwodna jest umiarkowana, tworząc naturalne kryjówki, ale nie utrudniając wędkowania. Oprócz drapieżników, akwen ten obfituje w leszcze i karpie, które osiągają tu imponujące rozmiary. To idealne miejsce zarówno dla spławikowców, gruntowców, jak i spinningistów, poszukujących różnorodnych wrażeń przez cały rok.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22497, 8, 2.5, 5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sandacz,Szczupak,Leszcz,Karp,Sum', 'Dobry, z dogodnymi miejscami', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22498, 'Starorzecze Paniowice B', 'starorzecze-paniowice-b-wroclaw-22498', 'OXBOW', 51.211505, 16.9124136, 'Dolnośląskie', 'Wrocław', 'Drugie starorzecze w Paniowicach to bardziej kameralny i zarośnięty akwen, idealny dla wędkarzy ceniących sobie spokój i wyzwania. Dno jest w większości muliste, z licznymi zatopionymi drzewami i gęstą roślinnością podwodną, co stanowi doskonałe schronienie dla ryb, ale utrudnia wędkowanie. Brzegi są trudno dostępne, często bagniste i porośnięte gęstą trzciną, co wymaga brodzenia lub poszukiwania otwartych ''okien''. Akwen ten łączy się z rzeką tylko podczas wysokich stanów wody, co sprawia, że jest bardziej odizolowany. Dominują tu liny i karasie pospolite, a także można złowić ładne szczupaki i okonie. Ryzyko przyduchy jest realne w upalne lata, co należy brać pod uwagę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22498, 6.5, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Trudny, bagnisty i mocno zarośnięty', TRUE, 'Dużo zatopionych drzew i gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22499, 'Starorzecze Kotowice', 'starorzecze-kotowice-wroclaw-22499', 'OXBOW', 51.2149588, 16.9150061, 'Dolnośląskie', 'Wrocław', 'Starorzecze Kotowice to duży i głęboki akwen z doskonałym połączeniem z rzeką, co gwarantuje stabilne warunki i obfitość ryb. Dno jest twarde, piaszczysto-żwirowe, z wyraźnymi spadami i głębokimi rynnami, idealnymi dla sandacza i suma. Brzegi są w większości łatwo dostępne, z szerokimi pasami trawy i licznymi miejscami do wędkowania. Roślinność podwodna jest minimalna, co ułatwia prowadzenie przynęt i ogranicza zaczepy. Akwen ten jest słynie z rekordowych sumów i sandaczy, a także dużych karpi i leszczy. To doskonałe miejsce dla wędkarzy preferujących cięższy sprzęt i polujących na duże okazy. Łowisko jest popularne przez cały rok, oferując niezapomniane emocje.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22499, 9.2, 2.8, 6, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Sandacz,Sum,Karp,Leszcz,Szczupak', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22500, 'Starorzecze Krzętów', 'starorzecze-krzetow-radomsko-22500', 'OXBOW', 51.0045738, 19.8596421, 'Łódzkie', 'Radomsko', 'Starorzecze w Krzętowie to niewielki, ale urokliwy zbiornik, który z biegiem lat stał się ostoją dla ryb typowych dla płytkich, zarośniętych wód. Dno jest mocno zamulone, a głębokość niewielka, co sprzyja rozwojowi gęstej roślinności podwodnej. Brzegi są trudno dostępne, często bagniste i porośnięte gęstą trzciną i krzewami, co wymaga cierpliwości i brodzenia. Akwen ten jest domem dla licznych karasi pospolitych i linów, które doskonale czują się w tych warunkach. W upalne lata istnieje ryzyko całkowitego wyschnięcia płytszych partii oraz przyduchy, co może wpływać na aktywność ryb. To idealne miejsce dla wędkarzy poszukujących spokoju i dzikiej przyrody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22500, 4, 1.4, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty i gęsto zarośnięty', TRUE, 'Dużo zatopionych gałęzi i gęsta roślinność podwodna', 'Późna wiosna i wczesne lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22501, 'Dawne Koryto Warty A', 'dawne-koryto-warty-a-slupca-22501', 'OXBOW', 52.1527779, 17.6900312, 'Wielkopolskie', 'Słupca', 'Pierwszy odcinek Dawnego Koryta Warty w okolicach Słupcy to rozległy akwen z doskonałym połączeniem z obecnym nurtem rzeki, co zapewnia stałą wymianę wody i obfitość ryb. Dno jest zróżnicowane, z piaszczystymi blatami, mulistymi rynnami i twardymi spadami, oferując idealne warunki dla wielu gatunków. Brzegi są w większości łatwo dostępne, z licznymi, dobrze utrzymanymi stanowiskami wędkarskimi. Akwen ten słynie z populacji leszczy, karpi i szczupaków, a także można złowić okazałe okonie i sumy. Umiarkowana roślinność podwodna tworzy naturalne kryjówki, nie utrudniając jednak wędkowania. To popularne łowisko, które oferuje szeroki wachlarz możliwości dla każdego wędkarza.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22501, 10.5, 2.3, 4.8, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Karp,Szczupak,Okoń,Sum', 'Dobry, z licznymi stanowiskami', FALSE, 'Pojedyncze korzenie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22502, 'Dawne Koryto Warty B', 'dawne-koryto-warty-b-slupca-22502', 'OXBOW', 52.1478339, 17.6877183, 'Wielkopolskie', 'Słupca', 'Drugi odcinek Dawnego Koryta Warty to bardziej dziki i wymagający akwen, który łączy się z rzeką tylko podczas wiosennych wezbrań. Dno jest w większości muliste, z licznymi zatopionymi drzewami i gęstą roślinnością podwodną, co stanowi wyzwanie dla wędkarzy. Brzegi są trudno dostępne, często bagniste i porośnięte gęstą trzciną, co wymaga brodzenia lub poszukiwania nielicznych, otwartych miejsc. Akwen ten jest rajem dla lina i karasia pospolitego, a także kryje w sobie spore szczupaki i leszcze. W upalne lata istnieje ryzyko przyduchy, co może wpływać na aktywność ryb. Jest to łowisko dla cierpliwych i doświadczonych wędkarzy, którzy cenią sobie spokój i dziką przyrodę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22502, 8.8, 2, 4.2, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć,Leszcz', 'Trudny, bagnisty i mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew i gęsta roślinność', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22503, 'Dawne Koryto Warty C', 'dawne-koryto-warty-c-slupca-22503', 'OXBOW', 52.1466183, 17.6835439, 'Wielkopolskie', 'Słupca', 'Trzeci odcinek Dawnego Koryta Warty to najbardziej odizolowana i płytka część kompleksu, gdzie procesy starzenia się starorzecza są najbardziej zaawansowane. Dno jest mocno zamulone, a głębokość niewielka, co sprzyja rozwojowi bardzo gęstej roślinności podwodnej. Brzegi są praktycznie niedostępne bez brodzenia, porośnięte gęstą trzciną i inną roślinnością. Akwen ten jest domem dla licznych karasi pospolitych, linów i wzdręg, które doskonale adaptują się do trudnych warunków. W upalne lata istnieje wysokie ryzyko całkowitego wyschnięcia płytszych partii oraz przyduchy. To łowisko dla wędkarzy poszukujących ryb w ekstremalnych warunkach i ceniących sobie dziką przygodę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22503, 7.1, 1.7, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną, miejscami bagnisty', TRUE, 'Gęsta roślinność podwodna i muł', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22504, 'Dawne Koryto Warty D', 'dawne-koryto-warty-d-slupca-22504', 'OXBOW', 52.1474063, 17.6785143, 'Wielkopolskie', 'Słupca', 'Ostatni odcinek Dawnego Koryta Warty to interesujące łowisko, które oferuje zróżnicowane warunki wędkarskie. Dno jest mieszane, z piaszczystymi fragmentami i mulistymi zagłębieniami, a głębokość umiarkowana. Brzegi są częściowo dostępne, z kilkoma dogodnymi miejscami, jednak druga strona jest bardziej zarośnięta. Akwen ten łączy się z rzeką podczas wysokich stanów wody, co sprzyja migracji ryb, zwłaszcza drapieżników. Dominują tu szczupaki i okonie, które polują wśród umiarkowanej roślinności podwodnej, a także liczne płocie i leszcze. W upalne lata należy liczyć się z ryzykiem przyduchy, co może wpływać na aktywność ryb. To dobre miejsce dla spinningistów i wędkarzy spławikowych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22504, 6.3, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Szczupak,Okoń,Płoć,Leszcz', 'Dobry z jednej strony, druga zarośnięta', FALSE, 'Pojedyncze korzenie i gęsta roślinność w płytszych partiach', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22505, 'Starorzecze (Okołowice)', 'starorzecze-okolowice-okolowice-22505', 'OXBOW', 50.8177924, 19.7124151, 'Województwo śląskie', 'Okołowice', 'To niewielkie starorzecze, położone w malowniczej okolicy Okołowic, charakteryzuje się dużą izolacją od głównego nurtu rzeki. Dno jest muliste i bogate w osady organiczne, co sprzyja rozwojowi bujnej roślinności podwodnej i nawodnej. Brzegi są często podmokłe i trudno dostępne, gęsto porośnięte trzciną i krzewami, co wymaga użycia wodoodpornego obuwia lub brodzenia. Jest to idealne łowisko dla wędkarzy poszukujących lina, karasia pospolitego i wzdręgi, które znajdują tu doskonałe warunki do życia. Występują tu również szczupaki, które polują wśród zarośli, jednak ich łowienie jest wyzwaniem ze względu na liczne zaczepy. W upalne lata istnieje ryzyko przyduchy, co może wpływać na aktywność ryb, dlatego najlepiej łowić tu wiosną i wczesnym latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22505, 2, 1.5, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22506, 'Starorzecze (Bobrowniki)', 'starorzecze-bobrowniki-bobrowniki-22506', 'OXBOW', 50.9638802, 19.8381072, 'Województwo łódzkie', 'Bobrowniki', 'Starorzecze w Bobrownikach to rozległe i urozmaicone łowisko, będące dawnym korytem Warty, okresowo łączące się z rzeką podczas wysokich stanów wody. Dno jest zróżnicowane, z fragmentami mulistymi i piaszczystymi, a brzegi są przeważnie stabilne i dobrze dostępne, choć miejscami porośnięte trzciną. Roślinność podwodna jest umiarkowana, tworząc idealne kryjówki dla wielu gatunków ryb. Akwen ten słynie z obfitości leszczy i płoci, a także dużych okazów karpi, które chętnie żerują na otwartych przestrzeniach. Wśród zarośli i zatopionych gałęzi można z powodzeniem łowić okonie i szczupaki, które są tu liczne. To doskonałe miejsce do wędkowania przez cały sezon, oferujące różnorodne możliwości dla wędkarzy spławikowych, gruntowych i spinningistów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22506, 7.5, 2, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22507, 'Starorzecze (Boćki)', 'starorzecze-bocki-bocki-22507', 'OXBOW', 52.6497468, 23.038924, 'Województwo podlaskie', 'Boćki', 'To malownicze starorzecze w okolicy Bociek to prawdziwa perła dla miłośników dzikiej przyrody i wędkarstwa. Charakteryzuje się czystą wodą i stosunkowo niskim poziomem zamulenia, co sprzyja różnorodności fauny. Brzegi są często dzikie, bagniste i trudno dostępne, co wymaga przygotowania na brodzenie i poruszanie się w trudnym terenie. Roślinność podwodna jest umiarkowana, ale występują liczne zatopione drzewa i konary, stanowiące doskonałe kryjówki dla drapieżników. Akwen jest bogaty w szczupaki i okonie, a także leszcze, płocie i liny, które dobrze czują się w tym naturalnym środowisku. Wędkowanie tutaj to prawdziwe wyzwanie, ale nagrodą są często piękne, zdrowe ryby. Najlepsze efekty osiąga się wiosną i wczesną jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22507, 10, 2.5, 5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Lin', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22508, 'Stare Koryto Warty', 'stare-koryto-warty-ladek-22508', 'OXBOW', 52.1848172, 17.7094107, 'Województwo wielkopolskie', 'Lądek', 'To rozległe stare koryto Warty to jedno z najbardziej znanych i cenionych łowisk w regionie, charakteryzujące się stałym, choć zmiennym, połączeniem z rzeką. Dno jest przeważnie twarde, piaszczysto-żwirowe, z miejscowymi osadami mułu, a brzegi są łatwo dostępne, co ułatwia wędkowanie z brzegu. Roślinność wodna jest umiarkowana, tworząc idealne warunki dla różnorodnych gatunków ryb. Akwen jest domem dla dużych populacji leszczy, płoci i karpi, a także sumów i szczupaków, które osiągają tu imponujące rozmiary. Występują również sandacze i bolenie, szczególnie w miejscach o szybszym nurcie lub w pobliżu połączeń z Wartą. To łowisko oferuje wędkarzom wiele możliwości przez cały sezon, od wiosny do późnej jesieni.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22508, 15, 2.2, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Karp,Sum,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22509, 'Starorzecze (Brzeszcze)', 'starorzecze-brzeszcze-brzeszcze-22509', 'OXBOW', 49.9746277, 19.1134529, 'Województwo małopolskie', 'Brzeszcze', 'Starorzecze w Brzeszczach to niewielki, ale urokliwy zbiornik, który utracił stałe połączenie z Wisłą, co sprzyja stabilizacji warunków wodnych. Charakteryzuje się mulistym dnem i wysokim poziomem zamulenia, co idealnie odpowiada rybom karpiowatym. Brzegi są mocno zarośnięte trzciną i krzewami, co utrudnia dostęp do wody i wymaga cierpliwości od wędkarzy. Gęsta roślinność podwodna stanowi schronienie dla licznych populacji karasi pospolitych, linów i wzdręg, a także płoci. Wędkowanie tutaj jest wyzwaniem, ale może przynieść satysfakcjonujące rezultaty, zwłaszcza dla miłośników wędkarstwa spławikowego. W upalne lata istnieje ryzyko niedoboru tlenu, dlatego najlepsze okresy to późna wiosna i wczesne lato, zanim upały staną się zbyt intensywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22509, 3, 1.8, 3.5, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Płoć,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22510, 'Starorzecze (Siedlisko)', 'starorzecze-siedlisko-siedlisko-22510', 'OXBOW', 51.7669671, 15.7897065, 'Województwo lubuskie', 'Siedlisko', 'To starorzecze w Siedlisku, będące dawnym fragmentem Odry, to popularne łowisko z okresowym połączeniem z rzeką. Dno jest zróżnicowane, z przewagą mułu i piasku, a brzegi są ogólnie dobrze dostępne, co sprzyja swobodnemu poruszaniu się wędkarzy. Umiarkowana roślinność podwodna tworzy dogodne warunki dla wielu gatunków ryb, zapewniając zarówno kryjówki, jak i żerowiska. Akwen słynie z licznych leszczy, płoci i karpi, a także drapieżników takich jak szczupak i okoń, które aktywnie żerują na mniejszych rybach. Wędkowanie jest tu możliwe przez cały sezon, od wczesnej wiosny do późnej jesieni, oferując różnorodne doznania. To idealne miejsce zarówno dla początkujących, jak i doświadczonych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22510, 6, 2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Szczupak,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22511, 'Starorzecze (Siedlisko)', 'starorzecze-siedlisko-siedlisko-22511', 'OXBOW', 51.7665004, 15.7907141, 'Województwo lubuskie', 'Siedlisko', 'To drugie starorzecze w Siedlisku, choć blisko poprzedniego, jest bardziej izolowane i charakteryzuje się odmiennym charakterem. Dno jest silnie zamulone, a brzegi są bagniste i trudno dostępne, gęsto porośnięte trzciną, co wymaga użycia wodoodpornego obuwia. Silne zarośnięcie roślinnością podwodną sprawia, że jest to idealne siedlisko dla ryb ciepłolubnych i odpornych na trudne warunki. Akwen ten jest królestwem lina, karasia pospolitego i wzdręgi, a także płoci, które znajdują tu obfitość pokarmu i schronienia. W upalne lata ryzyko przyduchy jest wysokie, co może wpływać na aktywność ryb. Najlepsze wyniki osiąga się w późnej wiośnie i wczesnym lecie, zanim temperatura wody osiągnie szczyt.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22511, 4.5, 1.7, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22512, 'Starorzecze (Załuże)', 'starorzecze-zaluze-zaluze-22512', 'OXBOW', 51.3255383, 19.1262069, 'Województwo łódzkie', 'Załuże', 'Starorzecze w Załużu to typowe łowisko poodrzańskie, które okresowo łączy się z głównym nurtem Warty podczas podwyższonych stanów wody. Dno jest mieszane, z przewagą mułu i piasku, a brzegi są stosunkowo łatwo dostępne, choć miejscami mogą być zarośnięte. Roślinność podwodna jest umiarkowana, tworząc mozaikę otwartych przestrzeni i ukryć dla ryb. Akwen ten jest bogaty w leszcze, płocie i karpie, a także drapieżniki takie jak szczupak i okoń, które aktywnie polują wzdłuż brzegów i na płytszych partiach. Wędkowanie tutaj jest przyjemne i często obfituje w brania, zarówno dla miłośników metod gruntowych, jak i spinningowych. Najlepsze okresy to wiosna i wczesna jesień, kiedy ryby intensywnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22512, 5, 1.9, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22513, 'Starorzecze (Sudzinek)', 'starorzecze-sudzinek-sudzinek-22513', 'OXBOW', 50.9231669, 19.8342366, 'Województwo łódzkie', 'Sudzinek', 'To starorzecze w Sudzinku to niewielkie i silnie zamulone łowisko, które utraciło stałe połączenie z rzeką, co sprzyja rozwojowi specyficznej fauny. Dno jest bardzo muliste, a brzegi mocno zarośnięte trzciną i inną roślinnością, co sprawia, że dostęp do wody jest utrudniony i często wymaga brodzenia. Gęsta roślinność podwodna stanowi idealne środowisko dla karasi pospolitych, linów i wzdręg, a także mniejszych płoci. Wędkowanie tutaj jest wyzwaniem ze względu na liczne zaczepy i ograniczoną przestrzeń do zarzucania. W upalne lata istnieje ryzyko niedoboru tlenu, dlatego najlepsze efekty osiąga się w późnej wiośnie i wczesnym lecie, gdy ryby są najbardziej aktywne. To miejsce dla cierpliwych wędkarzy ceniących spokój i dziką przyrodę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22513, 2.8, 1.6, 3.1, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22514, 'Starorzecze (Sudzinek)', 'starorzecze-sudzinek-sudzinek-22514', 'OXBOW', 50.9288029, 19.8422095, 'Województwo łódzkie', 'Sudzinek', 'Drugie starorzecze w Sudzinku jest nieco większe i charakteryzuje się okresowym połączeniem z rzeką, co wpływa na większą różnorodność gatunkową. Dno jest mniej zamulone niż w sąsiednich, bardziej izolowanych zbiornikach, a brzegi są lepiej dostępne, choć miejscami porośnięte roślinnością. Umiarkowana roślinność podwodna tworzy dobre warunki do żerowania i ukrywania się ryb. W akwenie dominują lin, płoć i leszcz, a także szczupak, który poluje na mniejsze ryby. Wędkowanie jest tu bardziej komfortowe, a szanse na złowienie większych okazów są realne. Brak ryzyka przyduchy sprawia, że łowisko jest stabilne. Najlepsze okresy to wiosna i wczesna jesień, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22514, 3.5, 1.8, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Płoć,Leszcz,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22515, 'Starorzecze (Gościencin)', 'starorzecze-gosciencin-gosciencin-22515', 'OXBOW', 50.9198279, 19.8387466, 'Województwo łódzkie', 'Gościencin', 'To małe starorzecze w Gościencinie jest wysoce izolowane i charakteryzuje się płytką wodą oraz intensywnym zamuleniem dna. Brzegi są trudne do pokonania, często bagniste i gęsto zarośnięte, co wymaga użycia wodoodpornego obuwia. Silne zarośnięcie roślinnością podwodną sprawia, że jest to idealne siedlisko dla ryb odpornych na trudne warunki. Akwen ten jest domem dla karasia pospolitego, wzdręgi i lina, które doskonale radzą sobie w tym środowisku. Ze względu na niewielką głębokość i izolację, starorzecze jest narażone na wysychanie w okresach długotrwałej suszy oraz na przyduchę. Wędkowanie jest tu możliwe głównie w późnej wiośnie i wczesnym lecie, zanim poziom wody znacząco spadnie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22515, 1.5, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22516, 'Starorzecze (Gościencin)', 'starorzecze-gosciencin-gosciencin-22516', 'OXBOW', 50.9200886, 19.8388099, 'Województwo łódzkie', 'Gościencin', 'Drugie starorzecze w Gościencinie, choć niewielkie, oferuje nieco lepsze warunki niż jego sąsiad, dzięki okresowemu połączeniu z rzeką. Dno jest muliste, ale poziom zamulenia jest umiarkowany, a brzegi są mocno zarośnięte trzciną, co utrudnia dostęp, ale tworzy doskonałe kryjówki. Umiarkowana roślinność podwodna zapewnia schronienie i żerowiska dla lina, płoci i karasia pospolitego. Wędkowanie tutaj wymaga cierpliwości i precyzji ze względu na gęste zarośla. W upalne lata istnieje ryzyko przyduchy, dlatego najlepsze efekty osiąga się w późnej wiośnie i wczesnym lecie, gdy ryby są najbardziej aktywne. To idealne miejsce dla wędkarzy ceniących wyzwania i spokój.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22516, 2, 1.5, 2.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Płoć,Karaś pospolity', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22517, 'Starorzecze (Borzęckie)', 'starorzecze-borzeckie-borzeckie-22517', 'OXBOW', 51.3949266, 18.6814895, 'Województwo łódzkie', 'Borzęckie', 'Starorzecze w Borzęckim to rozległe i dynamiczne łowisko, charakteryzujące się stałym połączeniem z rzeką Wartą, co zapewnia ciągły dopływ świeżej wody i ryb. Dno jest twarde, piaszczysto-żwirowe, z nielicznymi osadami mułu, a brzegi są łatwo dostępne, co sprzyja swobodnemu wędkowaniu. Roślinność podwodna jest umiarkowana, tworząc zróżnicowane środowisko dla wielu gatunków. Akwen ten jest rajem dla drapieżników, takich jak szczupak, okoń i boleń, które licznie występują w silniejszym nurcie i przy zaroślach. Obficie występują tu również leszcze i płocie, stanowiąc bazę pokarmową dla większych ryb. To idealne miejsce dla wędkarzy przez cały sezon, oferujące emocjonujące brania i duże okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22517, 8, 2.1, 4.2, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Boleń', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22518, 'Starorzecze (Ruda Maleniecka)', 'starorzecze-ruda-maleniecka-ruda-maleniecka-22518', 'OXBOW', 51.16389, 20.2127908, 'Województwo świętokrzyskie', 'Ruda Maleniecka', 'Starorzecze w Rudzie Malenieckiej to urokliwe łowisko, które okresowo łączy się z rzeką Pilicą podczas wysokich stanów wody, co wzbogaca jego faunę. Dno jest zróżnicowane, z przewagą piasku i niewielkich osadów mułu, a brzegi są dobrze dostępne, co ułatwia wędkowanie z wielu miejsc. Umiarkowana roślinność podwodna tworzy idealne warunki dla różnorodnych gatunków ryb, zapewniając zarówno schronienie, jak i żerowiska. Akwen ten jest domem dla licznych płoci, leszczy i linów, a także drapieżników takich jak okoń i szczupak, które aktywnie polują wzdłuż brzegów. Wędkowanie tutaj jest przyjemne i często obfituje w brania, zarówno dla miłośników metod gruntowych, jak i spinningowych. Najlepsze okresy to wiosna i wczesna jesień, kiedy ryby intensywnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22518, 4, 1.9, 3.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Lin,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22519, 'Starorzecze (Janówek)', 'starorzecze-janowek-janowek-22519', 'OXBOW', 51.5040892, 20.5689488, 'Województwo łódzkie', 'Janówek', 'To starorzecze w Janówku jest niewielkim i dość izolowanym zbiornikiem, który utracił stałe połączenie z Pilicą, co sprzyja rozwojowi specyficznej fauny. Dno jest muliste i charakteryzuje się wysokim poziomem zamulenia, a brzegi są mocno zarośnięte trzciną i inną roślinnością, co sprawia, że dostęp do wody jest utrudniony. Silne zarośnięcie roślinnością podwodną stanowi idealne środowisko dla karasia pospolitego, lina i wzdręgi, a także mniejszych płoci. Wędkowanie tutaj jest wyzwaniem ze względu na liczne zaczepy i ograniczoną przestrzeń do zarzucania. W upalne lata istnieje ryzyko niedoboru tlenu, dlatego najlepsze efekty osiąga się w późnej wiośnie i wczesnym lecie, gdy ryby są najbardziej aktywne. To miejsce dla wędkarzy ceniących spokój i dziką przyrodę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22519, 3.2, 1.6, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22520, 'Starorzecze (Pogalewo Wielkie)', 'starorzecze-pogalewo-wielkie-pogalewo-wielkie-22520', 'OXBOW', 51.2482581, 16.6419744, 'Dolnośląskie', 'Pogalewo Wielkie', 'To starorzecze, położone w malowniczej okolicy Pogalewa Wielkiego, charakteryzuje się typowym dla tego typu zbiorników mulistym dnem, które sprzyja rozwojowi bogatej roślinności podwodnej. Brzegi są miejscami trudno dostępne, często bagniste i porośnięte gęstymi pasami trzcin, co utrudnia swobodne poruszanie się wzdłuż linii brzegowej. Jest to idealne środowisko dla lina i karasia pospolitego, które znajdują tu obfitość pokarmu i schronienie. Można również liczyć na spotkanie ze szczupakiem, czającym się w zaroślach, oraz liczną populacją płoci. Ze względu na ograniczoną cyrkulację wody, zwłaszcza w upalne lata, istnieje ryzyko przyduchy, dlatego wędkarze powinni być przygotowani na zmienne warunki. Wędkowanie tutaj wymaga cierpliwości i często użycia woderów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22520, 3.5, 1.8, 3.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22521, 'Stare Koryto Warty', 'stare-koryto-warty-pyzdry-22521', 'OXBOW', 52.1899177, 17.7214993, 'Wielkopolskie', 'Pyzdry', 'To rozległe starorzecze, będące fragmentem dawnego koryta Warty w okolicach Pyzdr, oferuje wędkarzom zróżnicowane łowisko. Dno jest tu głównie mulisto-piaszczyste, z licznymi zagłębieniami i pojedynczymi zaczepami w postaci zatopionych konarów. Brzegi są w większości dobrze dostępne, choć miejscami występują pasy trzcin i tataraku, stanowiące doskonałe kryjówki dla ryb. Wędkując tutaj, można spodziewać się obfitych brań leszczy i płoci, a także drapieżników takich jak szczupak i okoń, które aktywnie polują w toni wodnej. W głębszych partiach starorzecza, zwłaszcza w pobliżu dawnego nurtu, pojawiają się również sumy. Regularne połączenie z Wartą podczas wysokich stanów wody zapewnia stałe odświeżanie zbiornika i minimalizuje ryzyko przyduchy, co czyni to miejsce atrakcyjnym przez cały sezon.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22521, 7.2, 2.5, 4.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Sum', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22522, 'Stare Koryto Warty', 'stare-koryto-warty-pyzdry-22522', 'OXBOW', 52.1831202, 17.7202737, 'Wielkopolskie', 'Pyzdry', 'Kolejny fragment starego koryta Warty w rejonie Pyzdr, nieco mniejszy, lecz równie atrakcyjny dla wędkarzy. Charakteryzuje się stabilnym dnem, przeważnie mulisto-piaszczystym, z mniejszą ilością roślinności podwodnej niż w bardziej płytkich starorzeczach. Brzegi są łatwo dostępne, co ułatwia wybór stanowiska do wędkowania. Dominującymi gatunkami są leszcz i płoć, które osiągają tu imponujące rozmiary, a także szczupak i okoń, często spotykane na skraju roślinności. W zbiorniku występują również karpie, które chętnie żerują w mulistych zatoczkach. Okresowe połączenie z rzeką Warta zapewnia odpowiednie natlenienie i zasilanie w pokarm, co sprzyja zdrowej populacji ryb i czyni to miejsce godnym polecenia. Warto odwiedzić to starorzecze, szczególnie wiosną i jesienią.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22522, 5.8, 2.1, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22523, 'Starorzecze (Anusin)', 'starorzecze-anusin-anusin-22523', 'OXBOW', 51.8158705, 18.928747, 'Łódzkie', 'Anusin', 'Starorzecze w Anusinie to klasyczny przykład zbiornika o charakterze silnie zarośniętym i płytkim, co czyni go ostoją dla ryb ciepłolubnych. Dno jest w przeważającej części muliste, z grubą warstwą osadów dennych, co jest typowe dla starorzeczy o słabej cyrkulacji wody. Brzegi są gęsto porośnięte trzciną i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest utrudniony i często wymaga brodzenia. W zbiorniku dominują lin, karaś pospolity oraz wzdręga, które doskonale czują się w tak bujnym środowisku. Mimo silnego zarastania, można tu również spotkać szczupaki, które wykorzystują gęstwinę jako miejsce do zasadzki. W upalne lata istnieje wysokie ryzyko przyduchy, co należy brać pod uwagę planując wędkowanie. To idealne miejsce na połów na spławik.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22523, 2.8, 1.5, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22524, 'Starorzecze (Pietrzyków)', 'starorzecze-pietrzykow-pietrzykow-22524', 'OXBOW', 52.1912533, 17.7399805, 'Wielkopolskie', 'Pietrzyków', 'Starorzecze w Pietrzykowie to średniej wielkości zbiornik, który łączy w sobie cechy łowiska spokojnego i dynamicznego, dzięki okresowemu połączeniu z główną rzeką. Dno jest zróżnicowane, od mulistego po piaszczysto-muliste, z pojedynczymi zatopionymi korzeniami, które stanowią doskonałe kryjówki dla ryb. Brzegi są w większości łatwo dostępne, co umożliwia komfortowe wędkowanie z brzegu. Głównymi mieszkańcami tego starorzecza są płoć, leszcz oraz okoń, które występują w dużych ilościach i często osiągają znaczne rozmiary. W zaroślach i na skraju otwartej wody aktywnie poluje szczupak. Dzięki regularnemu odświeżaniu wody podczas wysokich stanów, zbiornik jest dobrze natleniony, co sprzyja zdrowej populacji ryb przez cały rok. To atrakcyjne miejsce dla spinningistów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22524, 4.1, 1.9, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22525, 'Starorzecze (Pietrzyków-Kolonia)', 'starorzecze-pietrzykow-kolonia-pietrzykow-kolonia-22525', 'OXBOW', 52.1930933, 17.7512811, 'Wielkopolskie', 'Pietrzyków-Kolonia', 'To starorzecze, położone w Pietrzykowie-Kolonii, jest nieco bardziej zaciszne i trudniej dostępne niż sąsiednie akweny. Dno jest wyraźnie muliste, z licznymi podwodnymi zaczepami w postaci gęstej roślinności i zatopionych gałęzi. Brzegi są często bagniste i porośnięte gęstą roślinnością, co wymaga użycia wodery do dotarcia do lepszych miejscówek. W wodach starorzecza dominują płoć, leszcz i lin, które znajdują tu idealne warunki do żerowania i rozwoju. Szczupaki również chętnie zasiedlają ten zbiornik, wykorzystując gęste zarośla do zasadzek. Ze względu na częściową izolację i bujną roślinność, w okresach upałów pojawia się ryzyko niedoboru tlenu, jednak okresowe połączenie z rzeką poprawia sytuację. To idealne miejsce na poszukiwanie lina i karpia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22525, 3.8, 1.7, 3.1, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Płoć,Leszcz,Lin,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22526, 'Starorzecze (Gościencin)', 'starorzecze-gosciencin-gosciencin-22526', 'OXBOW', 50.9118665, 19.8227787, 'Łódzkie', 'Gościencin', 'To niewielkie i płytkie starorzecze w Gościencinie stanowi typowy przykład zbiornika o wysokim stopniu zamulenia i silnym zarośnięciu. Dno jest w całości pokryte grubą warstwą mułu, co sprzyja bujnemu rozwojowi roślinności wodnej, takiej jak lilie i grążele. Brzegi są niemal całkowicie zarośnięte trzciną i inną roślinnością szuwarową, co sprawia, że dostęp do wody jest bardzo trudny i często wymaga przedzierania się przez gęste zarośla. W tak specyficznym środowisku doskonale czują się karaś pospolity i wzdręga, które są głównymi gatunkami występującymi w zbiorniku. Ze względu na małą głębokość i brak połączenia z rzeką, starorzecze to jest bardzo podatne na wysychanie w okresach suszy oraz na przyduchę w upalne lata. Wędkowanie tutaj to wyzwanie dla cierpliwych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22526, 2.1, 1.2, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22527, 'Starorzecze (Maluszyn)', 'starorzecze-maluszyn-maluszyn-22527', 'OXBOW', 50.9086238, 19.8114958, 'Łódzkie', 'Maluszyn', 'Starorzecze w Maluszynie to płytki i mocno zamulony akwen, idealny dla gatunków ryb preferujących ciepłe i gęsto zarośnięte wody. Dno jest miękkie, pokryte grubą warstwą osadów organicznych, co jest typowe dla starorzeczy pozbawionych stałego przepływu. Brzegi są trudne do pokonania, często bagniste i gęsto porośnięte trzciną, co wymaga od wędkarza cierpliwości i odpowiedniego sprzętu, takiego jak wodery. W zbiorniku dominują karaś pospolity, wzdręga i lin, które znajdują tu obfitość pokarmu i bezpieczne schronienie. Ze względu na małą głębokość i brak połączenia z rzeką, starorzecze to jest narażone na wysychanie w czasie długotrwałych susz oraz na ryzyko przyduchy, zwłaszcza w letnie upały. To prawdziwa ostoja dla karasia.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22527, 1.8, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22528, 'Starorzecze (Sudzinek)', 'starorzecze-sudzinek-sudzinek-22528', 'OXBOW', 50.9173616, 19.8359895, 'Łódzkie', 'Sudzinek', 'Starorzecze w Sudzinku to przykład zbiornika o znacznym stopniu zamulenia i silnym zarośnięciu, charakteryzującego się specyficznym mikroklimatem. Dno jest miękkie, muliste, z licznymi podwodnymi zaczepami w postaci gęstej roślinności i zatopionych gałęzi. Brzegi są trudne do pokonania, gęsto porośnięte trzciną, co sprawia, że wędkowanie z brzegu jest wyzwaniem i często wymaga użycia woderów. W wodach starorzecza doskonale czują się lin, karaś pospolity i płoć, które znajdują tu obfitość pokarmu i bezpieczne schronienie. Wśród zarośli można również spotkać szczupaka, który poluje na mniejsze ryby. Ze względu na brak stałego połączenia z rzeką i bujną roślinność, w upalne lata istnieje zwiększone ryzyko niedoboru tlenu. To łowisko dla wytrwałych wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22528, 2.3, 1.3, 2.7, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22529, 'Starorzecze (Dębowa Góra)', 'starorzecze-debowa-gora-debowa-gora-22529', 'OXBOW', 51.3051674, 19.9906064, 'Łódzkie', 'Dębowa Góra', 'Starorzecze w Dębowej Górze to jeden z większych i głębszych akwenów tego typu w regionie, oferujący doskonałe warunki do wędkowania. Dno jest zróżnicowane, od mulistego po piaszczyste, z pojedynczymi, naturalnymi zaczepami w postaci zatopionych konarów, które stanowią kryjówki dla ryb. Brzegi są w większości dobrze dostępne, co ułatwia wybór dogodnego miejsca do łowienia. W zbiorniku dominują drapieżniki, takie jak szczupak i okoń, które osiągają tu imponujące rozmiary, a także liczne populacje leszczy, płoci i karpi. Okresowe połączenie z pobliską rzeką zapewnia regularne odświeżanie wody i dopływ świeżego narybku, co minimalizuje ryzyko przyduchy i utrzymuje wysoką jakość łowiska przez cały sezon. To świetne miejsce dla spinningistów i wędkarzy gruntowych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22529, 6, 2.2, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22530, 'Starorzecze (Gościencin)', 'starorzecze-gosciencin-gosciencin-22530', 'OXBOW', 50.9049736, 19.8072065, 'Łódzkie', 'Gościencin', 'To starorzecze w Gościencinie to bardzo płytki i silnie zamulony zbiornik, który w okresach suszy może całkowicie wysychać. Dno jest pokryte grubą warstwą miękkiego mułu, co sprzyja rozwojowi bujnej roślinności wodnej, takiej jak rdestnice i moczarki. Brzegi są niemal całkowicie zarośnięte trzciną, co sprawia, że dostęp do wody jest niezwykle trudny i wymaga brodzenia w woderach. W tak ekstremalnych warunkach najlepiej radzą sobie karaś pospolity i wzdręga, które są głównymi gatunkami ryb występującymi w tym akwenie. Ze względu na małą głębokość i brak jakiegokolwiek połączenia z rzeką, zbiornik jest bardzo podatny na wysychanie i silne niedotlenienie wody w upalne, bezdeszczowe lata. Wędkowanie jest tu prawdziwym wyzwaniem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22530, 1.5, 0.9, 1.8, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22531, 'Starorzecze (Gościencin)', 'starorzecze-gosciencin-gosciencin-22531', 'OXBOW', 50.9056387, 19.8090093, 'Łódzkie', 'Gościencin', 'Kolejne starorzecze w Gościencinie, charakteryzujące się znacznym stopniem zamulenia i gęstym zarośnięciem. Dno jest miękkie i muliste, z dużą ilością rozkładających się resztek roślinnych, co tworzy bogate środowisko dla bezkręgowców. Brzegi są często bagniste i mocno zarośnięte, co utrudnia wędkowanie z lądu i wymaga użycia woderów, aby dotrzeć do otwartych partii wody. W zbiorniku dominują karaś pospolity, wzdręga i lin, które doskonale przystosowały się do tych warunków. Mimo trudnego dostępu, starorzecze to oferuje szansę na złowienie pięknych okazów ryb spokojnego żeru. W okresach letnich, z powodu braku cyrkulacji wody, istnieje wysokie ryzyko przyduchy, co należy brać pod uwagę. To łowisko dla miłośników natury.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22531, 1.7, 1, 2, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22532, 'Starorzecze (Gościencin)', 'starorzecze-gosciencin-gosciencin-22532', 'OXBOW', 50.9075485, 19.8163458, 'Łódzkie', 'Gościencin', 'To starorzecze w Gościencinie, choć niewielkie, jest cennym łowiskiem dla miłośników spokojnego żeru. Dno jest silnie zamulone, z grubą warstwą osadów, co sprzyja rozwojowi bujnej roślinności podwodnej i szuwarowej. Brzegi są mocno zarośnięte trzciną, co sprawia, że dostęp jest utrudniony i często wymaga brodzenia, jednak to właśnie te zarośla stanowią schronienie dla ryb. W wodach starorzecza dominują lin, karaś pospolity i płoć, które znajdują tu obfitość pokarmu i bezpieczne kryjówki. Wśród roślinności można również spotkać mniejsze szczupaki. Ze względu na brak stałego połączenia z rzeką i dużą ilość materii organicznej, w upalne lata zbiornik jest narażony na niedobór tlenu. Wędkowanie z pontonu może być dobrym rozwiązaniem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22532, 2, 1.1, 2.3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Płoć', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22533, 'Starorzecze (Maluszyn)', 'starorzecze-maluszyn-maluszyn-22533', 'OXBOW', 50.9084963, 19.7999733, 'Łódzkie', 'Maluszyn', 'Drugie starorzecze w Maluszynie to płytki, mocno zamulony zbiornik, który w okresach długotrwałej suszy może wysychać, co wpływa na jego ekosystem. Dno jest miękkie, pokryte grubą warstwą mułu i rozkładających się roślin, co stanowi idealne środowisko dla specyficznych gatunków ryb. Brzegi są bagniste i gęsto porośnięte roślinnością szuwarową, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga użycia woderów. W zbiorniku dominują karaś pospolity, wzdręga i lin, które doskonale przystosowały się do tych trudnych warunków. Mimo wyzwań związanych z dostępem, dla cierpliwego wędkarza starorzecze to może zaoferować satysfakcjonujące połowy. W lecie istnieje wysokie ryzyko przyduchy z powodu ograniczonej cyrkulacji wody. Warto spróbować połowu na spławik.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22533, 1.9, 1, 2.1, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22534, 'Starorzecze (Lubiel)', 'starorzecze-lubiel-lubiel-22534', 'OXBOW', 51.5102941, 16.7613808, 'Dolnośląskie', 'Lubiel', 'Starorzecze w Lubielu to atrakcyjne łowisko o umiarkowanej wielkości, charakteryzujące się okresowym połączeniem z rzeką, co sprzyja utrzymaniu zdrowej populacji ryb. Dno jest zróżnicowane, od mulistego po piaszczysto-żwirowe w miejscach bliżej dawnego nurtu, z pojedynczymi zaczepami w postaci zatopionych konarów. Brzegi są w większości dobrze dostępne, choć miejscami występują pasy trzcin, które stanowią naturalne schronienia dla ryb. W wodach starorzecza dominują szczupak i okoń, które aktywnie polują na mniejsze ryby, a także liczne populacje leszczy, płoci i karpi. Regularne odświeżanie wody podczas wysokich stanów minimalizuje ryzyko przyduchy i zapewnia dobre warunki do wędkowania przez większą część roku. To doskonałe miejsce zarówno dla spinningistów, jak i wędkarzy spławikowych.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22534, 4.5, 2, 3.7, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Karp', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22535, 'Starorzecze (Żmigródek)', 'starorzecze-zmigrodek-zmigrod-22535', 'OXBOW', 51.4857441, 16.8941671, 'Dolnośląskie', 'Żmigród', 'To starorzecze, choć niezbyt duże, oferuje zróżnicowane warunki do wędkowania. Dno jest muliste, z miejscowymi twardymi plamami, co sprzyja bytności leszczy i płoci. Brzegi są stosunkowo łatwo dostępne, choć miejscami można natrafić na pojedyncze zarośla i gałęzie. Akwen łączy się z rzeką podczas wysokich stanów wody, co wzbogaca populację ryb i zapobiega nadmiernemu odtlenieniu. Wśród dominujących gatunków znajdziemy płoć, leszcza, lina oraz szczupaka, który chętnie poluje w zaroślach. Wędkarze mogą spodziewać się udanych połowów przez cały sezon, zwłaszcza przy użyciu metod gruntowych i spinningu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22535, 3.2, 1.5, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Lin,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22536, 'Starorzecze (Żmigródek)', 'starorzecze-zmigrodek-zmigrod-22536', 'OXBOW', 51.4870235, 16.8892814, 'Dolnośląskie', 'Żmigród', 'To płytkie starorzecze charakteryzuje się silnym zarośnięciem, co stanowi wyzwanie, ale i schronienie dla wielu gatunków ryb. Dno jest mocno zamulone, a brzegi są trudne do pokonania, często bagniste, wymagające użycia brodzących spodni. Akwen łączy się z rzeką jedynie podczas wysokich wód, co w połączeniu z gęstą roślinnością podwodną stwarza ryzyko odtlenienia w upalne lata. Dominują tu karasie pospolite, liny, wzdręgi i płocie, które doskonale czują się w takim środowisku. Wędkarstwo wymaga cierpliwości i precyzji, najlepiej sprawdzą się lekkie zestawy spławikowe. Najlepsze wyniki osiąga się wiosną i wczesną jesienią, zanim roślinność osiągnie szczyt rozwoju.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22536, 2.8, 1.2, 3, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22537, 'Starorzecze (Garbce)', 'starorzecze-garbce-zmigrod-22537', 'OXBOW', 51.4953244, 16.8741196, 'Dolnośląskie', 'Żmigród', 'To starorzecze jest całkowicie odcięte od głównego nurtu rzeki, co sprzyja stabilizacji populacji ryb, ale również prowadzi do wysokiego poziomu zamulenia. Dno jest grząskie, a brzegi mocno zarośnięte trzciną, utrudniając dostęp do wody. W akwenie znajduje się dużo zatopionych drzew i gałęzi, tworzących doskonałe kryjówki dla większych ryb. Brak połączenia z rzeką i umiarkowane zarośnięcie mogą powodować ryzyko odtlenienia w gorące, bezwietrzne dni. Dominującymi gatunkami są leszcz, karaś srebrzysty, karp i sum, które dobrze radzą sobie w takim środowisku. Wędkarstwo wymaga cierpliwości i umiejętności omijania zaczepów, najlepiej późną wiosną i latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22537, 4.5, 1.8, 4.5, 'Brak', 'Wysokie', 'Umiarkowane', TRUE, FALSE, 'Leszcz,Karaś srebrzysty,Karp,Sum', 'Mocno zarośnięty trzciną', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22538, 'Starorzecze (Żmigródek)', 'starorzecze-zmigrodek-zmigrod-22538', 'OXBOW', 51.4941784, 16.8755237, 'Dolnośląskie', 'Żmigród', 'To niewielkie starorzecze to typowy, płytki zbiornik, który z czasem ulega silnemu zamuleniu i zarośnięciu. Brak połączenia z rzeką sprawia, że jego ekosystem jest bardzo wrażliwy, a w upalne lata istnieje wysokie ryzyko odtlenienia, a nawet całkowitego wyschnięcia. Dno jest grząskie, a brzegi niezwykle trudne do pokonania, często bagniste i gęsto porośnięte. Dominują tu gatunki odporne na trudne warunki, takie jak karaś pospolity, wzdręga i lin, które potrafią przetrwać w płytkich, ciepłych wodach. Wędkarstwo jest tu wyzwaniem, wymaga brodzących spodni i cierpliwości, najlepiej sprawdza się wczesną wiosną, zanim roślinność całkowicie opanuje akwen. Liczba ryb jest mocno zależna od warunków pogodowych w danym roku.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22538, 1.9, 1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Wzdręga,Lin', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22539, 'Starorzecze (Człopki)', 'starorzecze-czlopki-konin-22539', 'OXBOW', 51.9727854, 18.7334093, 'Wielkopolskie', 'Konin', 'To duże i głębokie starorzecze wyróżnia się stałym połączeniem z rzeką, co zapewnia doskonałą wymianę wody i niskie zamulenie dna. Brzegi są łatwo dostępne z obu stron, a roślinność przybrzeżna jest słabo rozwinięta, co ułatwia swobodne wędkowanie. Akwen posiada czyste dno, wolne od większych zaczepów, co jest atutem dla wielu technik wędkarskich. Dzięki stałemu przepływowi wody, ryzyko odtlenienia jest minimalne, co sprzyja zdrowej populacji ryb. Dominują tu drapieżniki takie jak szczupak, okoń i sandacz, a także liczny leszcz i płoć. Jest to idealne łowisko na cały sezon, oferujące komfortowe warunki i szansę na naprawdę okazałe okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22539, 7.1, 2.2, 5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Płoć,Sandacz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22540, 'Starorzecze (Odrzywół)', 'starorzecze-odrzywol-odrzywol-22540', 'OXBOW', 51.5108834, 20.5717409, 'Mazowieckie', 'Odrzywół', 'To malownicze starorzecze charakteryzuje się umiarkowanym zarośnięciem i średnim poziomem zamulenia, tworząc sprzyjające warunki dla wielu gatunków ryb. Akwen łączy się z rzeką podczas wysokich stanów wody, co zapewnia regularne zasilanie w świeżą wodę i migrację ryb. Brzegi są miejscami mocno zarośnięte trzciną, co może utrudniać dostęp, ale jednocześnie tworzy naturalne kryjówki dla ryb. Na dnie występują pojedyncze korzenie i gałęzie, które stanowią atrakcyjne miejsca żerowania dla drapieżników. Wśród dominujących gatunków znajdziemy lina, karasia pospolitego, płoć oraz szczupaka. Najlepsze rezultaty wędkarskie osiąga się wiosną i wczesną jesienią, kiedy ryby są najbardziej aktywne.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22540, 3.8, 1.7, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Lin,Karaś pospolity,Płoć,Szczupak', 'Mocno zarośnięty trzciną', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22541, 'Starorzecze (Odrzywół)', 'starorzecze-odrzywol-odrzywol-22541', 'OXBOW', 51.5118091, 20.5702763, 'Mazowieckie', 'Odrzywół', 'To płytkie starorzecze jest mocno zamulone i silnie zarośnięte, co stawia przed wędkarzami spore wyzwania. Dostęp do brzegów jest trudny, często bagnisty i wymaga użycia brodzących spodni, aby dotrzeć do otwartych partii wody. Akwen łączy się z rzeką tylko podczas wysokich wód, co w połączeniu z gęstą roślinnością podwodną znacząco zwiększa ryzyko odtlenienia w upalne lato. Dominujące gatunki to karaś srebrzysty, wzdręga i płoć, które doskonale adaptują się do trudnych warunków środowiskowych. Wędkarstwo w tym miejscu wymaga delikatnych zestawów spławikowych i precyzyjnego zarzucania. Najlepsze okresy to późna wiosna i lato, jednak należy uważać na wahania poziomu tlenu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22541, 2.1, 1.1, 2.8, 'Podczas wysokiej wody', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś srebrzysty,Wzdręga,Płoć', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22542, 'Starorzecze (Wykowo)', 'starorzecze-wykowo-plock-22542', 'OXBOW', 52.4712804, 19.8617243, 'Mazowieckie', 'Płock', 'To duże i głębokie starorzecze charakteryzuje się stałym połączeniem z Wisłą, co gwarantuje doskonałą jakość wody i bogactwo gatunkowe. Dno jest przeważnie twarde, z miejscowymi osadami mułu i pojedynczymi korzeniami, które stanowią kryjówki dla ryb. Brzegi są łatwo dostępne, co sprzyja komfortowemu wędkowaniu z brzegu. Dzięki ciągłemu przepływowi wody, ryzyko odtlenienia jest minimalne, co pozwala na utrzymanie zdrowej i silnej populacji ryb. Akwen słynie z obecności dużych sumów i sandaczy, a także obfitych populacji leszczy, karpi i szczupaków. Jest to doskonałe łowisko na cały sezon, oferujące różnorodne możliwości dla wędkarzy. Warto przygotować się na silne brania.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22542, 6, 2.5, 6, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Sum,Sandacz,Leszcz,Karp,Szczupak', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22543, 'Starorzecze (Kępa Polska)', 'starorzecze-kepa-polska-plock-22543', 'OXBOW', 52.4311161, 19.9642811, 'Mazowieckie', 'Płock', 'To starorzecze o umiarkowanej wielkości i głębokości, które łączy się z rzeką podczas wysokich stanów wody, co sprzyja odświeżaniu ekosystemu. Dno jest średnio zamulone, z miejscowymi twardszymi partiami, a podwodna roślinność jest dość gęsta, tworząc idealne schronienia dla ryb. Brzegi są mocno zarośnięte trzciną, co wymaga cierpliwości i często brodzących spodni, aby znaleźć dogodne stanowisko wędkarskie. Brak ryzyka odtlenienia sprawia, że ryby czują się tu komfortowo przez większość roku. Dominujące gatunki to płoć, leszcz, lin i okoń, które są licznie reprezentowane. Najlepsze sezony na połów to wiosna i wczesna jesień, kiedy ryby intensywnie żerują.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22543, 4.2, 1.6, 3.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Lin,Okoń', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna, wczesna jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22544, 'Starorzecze (Zakrzewo Kościelne)', 'starorzecze-zakrzewo-koscielne-plock-22544', 'OXBOW', 52.4037568, 19.9984094, 'Mazowieckie', 'Płock', 'To starorzecze, choć stosunkowo głębokie, jest całkowicie odcięte od głównego nurtu rzeki, co wpływa na jego specyficzny charakter. Dno jest średnio zamulone, a w wodzie znajduje się dużo zatopionych drzew i gałęzi, które stanowią zarówno wyzwanie, jak i atrakcję dla wędkarzy poszukujących dużych okazów. Brzegi są trudne do pokonania, często bagniste i gęsto zarośnięte, co wymaga przygotowania i odpowiedniego sprzętu. Silne zarośnięcie i brak połączenia z rzeką zwiększają ryzyko odtlenienia w upalne, bezdeszczowe okresy. Dominują tu karpie, liny, karasie pospolite oraz sumy, które doskonale wykorzystują zatopione przeszkody jako kryjówki. Wędkarstwo jest tu najbardziej efektywne późną wiosną i latem, zwłaszcza na zasiadki karpiowe.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22544, 5.5, 2, 4.8, 'Brak', 'Średnie', 'Silne', TRUE, FALSE, 'Karp,Lin,Karaś pospolity,Sum', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22545, 'Starorzecze (Kępa Polska)', 'starorzecze-kepa-polska-plock-22545', 'OXBOW', 52.4487613, 19.9299035, 'Mazowieckie', 'Płock', 'To niewielkie, ale bardzo atrakcyjne starorzecze charakteryzuje się niskim poziomem zamulenia i słabym zarośnięciem, co ułatwia wędkowanie. Akwen łączy się z rzeką podczas wysokich stanów wody, co zapewnia regularne zasilanie w świeżą wodę i migracje ryb. Brzegi są łatwo dostępne z większości stron, a dno jest czyste, co sprzyja różnym technikom wędkarskim. Brak ryzyka odtlenienia pozwala na utrzymanie zdrowej populacji ryb przez cały rok. Dominujące gatunki to szczupak i okoń, które aktywnie polują w czystej wodzie, a także liczne płocie i wzdręgi. Jest to idealne łowisko na cały sezon, szczególnie dla miłośników spinningu i wędkarstwa spławikowego.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22545, 3, 1.3, 3.2, 'Podczas wysokiej wody', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Płoć,Wzdręga', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22546, 'Starorzecze (Wola Załężna)', 'starorzecze-wola-zalezna-opoczno-22546', 'OXBOW', 51.3916702, 20.3324877, 'Łódzkie', 'Opoczno', 'To starorzecze jest typowym przykładem akwenu odciętego od rzeki, charakteryzującego się wysokim poziomem zamulenia i silnym zarośnięciem roślinnością wodną. Brzegi są mocno zarośnięte trzciną, co sprawia, że dostęp do wody jest bardzo utrudniony i wymaga użycia brodzących spodni. W upalne lata istnieje wysokie ryzyko odtlenienia, a zbiornik może nawet całkowicie wyschnąć, co wpływa na niestabilność populacji ryb. Dominują tu gatunki wyjątkowo odporne na trudne warunki, takie jak karaś pospolity, lin i wzdręga. Wędkarstwo jest tu najbardziej efektywne wczesną wiosną, zanim roślinność osiągnie szczyt rozwoju, a poziom wody jest jeszcze wystarczający. Należy liczyć się z trudnymi warunkami.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22546, 2.7, 1.4, 3, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Karaś pospolity,Lin,Wzdręga', 'Mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Wiosna');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22547, 'Starorzecze (Radzice Duże)', 'starorzecze-radzice-duze-opoczno-22547', 'OXBOW', 51.4551936, 20.3965025, 'Łódzkie', 'Opoczno', 'To rozległe starorzecze oferuje zróżnicowane warunki, które sprzyjają bytności wielu gatunków ryb. Akwen łączy się z rzeką podczas wysokich stanów wody, co zapewnia regularne odświeżanie wody i migracje ryb, wzbogacając ekosystem. Dno jest średnio zamulone, z twardszymi fragmentami, a pojedyncze korzenie i gałęzie stanowią atrakcyjne kryjówki. Brzegi są łatwo dostępne, co pozwala na komfortowe wędkowanie z wielu miejsc. Dzięki okresowym połączeniom z rzeką, ryzyko odtlenienia jest minimalne. Dominujące gatunki to leszcz, płoć, szczupak, sandacz oraz węgorz, co czyni to łowisko atrakcyjnym dla wędkarzy preferujących różne metody. Jest to doskonałe miejsce na połów przez cały sezon, z szansą na naprawdę okazałe okazy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22547, 6.5, 2.1, 5.2, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Sandacz,Węgorz', 'Dobry z obu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22548, 'Starorzecze (Dąbrówka)', 'starorzecze-dabrowka-opoczno-22548', 'OXBOW', 51.4606988, 20.4416953, 'Łódzkie', 'Opoczno', 'To starorzecze jest całkowicie odcięte od głównego nurtu rzeki, co prowadzi do znacznego zamulenia dna i silnego zarośnięcia. W wodzie znajduje się dużo zatopionych drzew i gałęzi, tworzących liczne zaczepy, ale jednocześnie doskonałe schronienia dla dużych ryb. Brzegi są trudne do pokonania, często bagniste i gęsto porośnięte, co wymaga brodzących spodni i determinacji. Brak połączenia z rzeką i gęsta roślinność podwodna zwiększają ryzyko odtlenienia w okresach upałów. Dominują tu karasie srebrzyste, liny, karpie i sumy, które doskonale czują się w takim środowisku. Wędkarstwo jest tu wyzwaniem, ale może przynieść satysfakcję w postaci dużych okazów, zwłaszcza późną wiosną i latem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22548, 3.5, 1.6, 3.7, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś srebrzysty,Lin,Karp,Sum', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22549, 'Starorzecze (Złocieniec)', 'starorzecze-zlocieniec-zlocieniec-22549', 'OXBOW', 53.5414775, 16.0186526, 'Zachodniopomorskie', 'Złocieniec', 'To największe i najgłębsze starorzecze w zestawieniu, charakteryzujące się stałym połączeniem z rzeką, co zapewnia doskonałą jakość wody i bogactwo ichtiofauny. Dno jest przeważnie czyste, z niewielkim zamuleniem, a roślinność przybrzeżna jest słabo rozwinięta, co ułatwia dostęp i swobodne wędkowanie. Brak ryzyka odtlenienia sprawia, że zbiornik jest stabilnym środowiskiem dla ryb przez cały rok. Akwen jest znany z obfitości drapieżników, takich jak szczupak, okoń i sandacz, a także licznych leszczy i węgorzy. Jest to idealne łowisko na cały sezon, oferujące komfortowe warunki i szansę na pobicie osobistego rekordu. To miejsce jest prawdziwym rajem dla wędkarzy.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22549, 8, 2.8, 6.5, 'Stałe połączenie', 'Niskie', 'Słabe', FALSE, FALSE, 'Szczupak,Okoń,Leszcz,Sandacz,Węgorz', 'Dobry z obu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22550, 'Stary Bug', 'stary-bug-wyszkow-22550', 'OXBOW', 52.516641, 21.1023677, 'Mazowieckie', 'Wyszków', 'To rozległe starorzecze rzeki Bug, charakteryzujące się bogatą roślinnością brzegową i podwodną, co stanowi idealne środowisko dla wielu gatunków ryb. Dno jest muliste, z licznymi zatopionymi drzewami i gałęziami, szczególnie w głębszych partiach. Brzegi są często strome i gliniaste, miejscami porośnięte gęstymi krzewami i trzciną, utrudniającymi dostęp do wody. Łowisko jest znane z populacji dużych szczupaków i linów, które znajdują tu schronienie w zaroślach. Występują tu również liczne płocie i leszcze, stanowiące bazę pokarmową dla drapieżników. Wiosenne i jesienne miesiące oferują najlepsze warunki do wędkowania, zwłaszcza na spinning lub spławik, wymagając od wędkarza cierpliwości i umiejętności. Należy przygotować się na trudności z dostępem do wody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22550, 14.5, 2.1, 5.8, 'Podczas wysokiej wody', 'Średnie', 'Silne', TRUE, FALSE, 'Szczupak,Lin,Płoć,Leszcz,Okoń', 'Trudny, miejscami zarośnięty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22551, 'Łacha Drachalska', 'lacha-drachalska-kozienice-22551', 'OXBOW', 51.5860678, 21.6717688, 'Mazowieckie', 'Kozienice', 'Łacha Drachalska to typowe starorzecze Wisły, położone w malowniczej okolicy, z dala od zgiełku cywilizacji. Charakteryzuje się płytkimi, mulistymi brzegami oraz dnem pokrytym grubą warstwą osadów organicznych, co sprzyja rozwojowi bujnej roślinności wodnej. Jest to idealne siedlisko dla karasia pospolitego i lina, które często osiągają tu imponujące rozmiary. Dostęp do łowiska jest umiarkowany, z kilkoma dogodnymi stanowiskami, jednak w wielu miejscach brzegi są podmokłe i zarośnięte, co wymaga odpowiedniego przygotowania. Wędkowanie wymaga cierpliwości i precyzji, zwłaszcza przy łowieniu wśród gęstych zarośli, gdzie ryby mają wiele kryjówek. Należy spodziewać się również obfitości wzdręg i płoci.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22551, 7.2, 1.5, 3.2, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Karaś pospolity,Lin,Wzdręga,Płoć', 'Umiarkowany, miejscami podmokły', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22552, 'Starorzecze Krakowskie', 'starorzecze-krakowskie-krakow-22552', 'OXBOW', 50.0623924, 19.9571566, 'Małopolskie', 'Kraków', 'To starorzecze Wisły, położone w bliskiej odległości od Krakowa, stanowi popularne miejsce rekreacji i wędkowania dla mieszkańców regionu. Charakteryzuje się zróżnicowanym dnem, od piaszczystych płycizn po głębsze partie z mulistym podłożem, co sprzyja różnorodności gatunków. Brzegi są w większości łatwo dostępne, częściowo zagospodarowane, co ułatwia wędkowanie z gruntu i spławika. Roślinność wodna jest umiarkowana, skupiona głównie przy brzegach i w zatokach, tworząc naturalne schronienia. Występują tu liczne leszcze, płocie i okonie, a także sporadycznie karpie, które są cennym łupem. Należy jednak pamiętać o presji wędkarskiej, zwłaszcza w weekendy, co może wymagać wczesnego przybycia. Łowisko jest łatwo dostępne i nie wymaga specjalistycznego sprzętu.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22552, 9.8, 1.8, 4.1, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Karp', 'Dobry z wielu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22553, 'Starorzecze Kostrzyńskie', 'starorzecze-kostrzynskie-kostrzyn-nad-odra-22553', 'OXBOW', 52.5961707, 14.7148037, 'Lubuskie', 'Kostrzyn nad Odrą', 'To starorzecze Odry, położone w obszarze objętym ochroną, charakteryzuje się dzikim i naturalnym krajobrazem, co stanowi o jego unikalności. Dno jest zróżnicowane, z licznymi zagłębieniami i zatopionymi pniami, co tworzy idealne kryjówki dla drapieżników. Brzegi są trudno dostępne, często bagniste i porośnięte gęstymi zaroślami, co dodaje łowisku dzikiego charakteru i wymaga przygotowania. Występują tu okazałe szczupaki, sandacze oraz sumy, a także duże leszcze i płocie, co czyni je atrakcyjnym dla wielu wędkarzy. Wędkowanie wymaga dobrej znajomości terenu i często użycia pontonu lub łodzi, aby dotrzeć do najlepszych miejsc, niedostępnych z brzegu. Jest to prawdziwe wyzwanie dla poszukujących dużych ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22553, 18.2, 2.5, 6.5, 'Stałe połączenie', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Szczupak,Sandacz,Sum,Leszcz,Płoć', 'Trudny, bagnisty', TRUE, 'Dużo zatopionych drzew', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22554, 'Starorzecze Grochalskie', 'starorzecze-grochalskie-zakroczym-22554', 'OXBOW', 52.4212409, 20.582411, 'Mazowieckie', 'Zakroczym', 'Starorzecze to, położone w pobliżu Nowych Grochali, jest typowym przykładem dawnego koryta Wisły, które z czasem uległo izolacji. Charakteryzuje się mulistym dnem, obfitością roślinności podwodnej i brzegowej, co zapewnia schronienie dla wielu gatunków ryb. Brzegi są częściowo dostępne, lecz miejscami silnie zarośnięte trzciną i krzewami, co wymaga poszukiwania dogodnych stanowisk. Jest to doskonałe miejsce na liny i karasie, które znajdują tu idealne warunki do rozwoju. Występują tu również drapieżniki takie jak szczupak i okoń, polujące w gęstych zaroślach. Wędkowanie z pontonu lub brodzenie w woderach może znacznie zwiększyć szanse na sukces, omijając trudności brzegowe. Łowisko oferuje spokój i kontakt z naturą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22554, 5.1, 1.4, 3, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Szczupak,Okoń', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22555, 'Starorzecze Kamieniec', 'starorzecze-kamieniec-bydgoszcz-22555', 'OXBOW', 53.093706, 18.224931, 'Kujawsko-Pomorskie', 'Bydgoszcz', 'To starorzecze Wisły w okolicy Kamieńca, cechuje się dość głęboką rynną i zróżnicowanym dnem, gdzie muł przeplata się z twardszymi partiami, co tworzy ciekawe środowisko. Brzegi są w większości stabilne, choć miejscami porośnięte drzewami i krzewami, co wymaga ostrożności podczas poruszania się. Roślinność wodna jest umiarkowana, co sprzyja zarówno drapieżnikom, jak i rybom spokojnego żeru. Łowisko jest znane z dużych leszczy, płoci oraz szczupaków, które są celem wielu wędkarzy. Wędkowanie gruntowe i spławikowe przynosi tu dobre rezultaty, zwłaszcza w miejscach o zmiennym dnie. Jest to miejsce oferujące relaks i szansę na złowienie okazałych egzemplarzy, z umiarkowanym dostępem.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22555, 10.5, 2.2, 4.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Okoń', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22556, 'Starorzecze Ruszczańskie', 'starorzecze-ruszczanskie-tykocin-22556', 'OXBOW', 53.1532991, 22.9339178, 'Podlaskie', 'Tykocin', 'Położone w malowniczej dolinie Narwi, to starorzecze jest prawdziwą ostoją dzikiej przyrody, gdzie natura dominuje nad ingerencją człowieka. Charakteryzuje się gęstą roślinnością wodną, która pokrywa dużą część powierzchni, oraz mulistym dnem, co tworzy bogate siedlisko. Brzegi są zazwyczaj trudno dostępne, bagniste i silnie zarośnięte trzciną, co sprawia, że łowisko jest idealne dla wędkarzy ceniących spokój i wyzwania. Jest to królestwo lina, karasia pospolitego i wzdręgi, a także licznych szczupaków i okoni, które doskonale czują się w tych warunkach. Wędkowanie z pontonu lub łodzi jest tu często koniecznością, aby dotrzeć do najlepszych, ukrytych miejsc. Warto przygotować się na komary i dziką przyrodę.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22556, 6.8, 1.3, 2.9, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak,Okoń', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22557, 'Doły Kajzera', 'doly-kajzera-torun-22557', 'OXBOW', 52.9490741, 18.7028896, 'Kujawsko-Pomorskie', 'Toruń', '"Doły Kajzera" to kompleks starorzeczy Wisły, znany z głębokich rynien i zróżnicowanego dna, gdzie występują zarówno twarde, piaszczyste partie, jak i grube warstwy mułu. Brzegi są częściowo dostępne, z licznymi drzewami i krzewami, które zapewniają cień i schronienie dla wędkarzy. Jest to popularne miejsce dla wędkarzy poszukujących dużych karpi, leszczy i sandaczy, które są tu licznie reprezentowane. Występują tu również sumy i węgorze, zwłaszcza w głębszych dołach, co dodaje atrakcyjności łowisku. Ze względu na zróżnicowany charakter, łowisko oferuje wiele możliwości zarówno dla wędkarzy gruntowych, jak i spinningistów, gwarantując niezapomniane wrażenia. To jedno z bardziej znanych starorzeczy w regionie.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22557, 16, 3, 7.5, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Karp,Leszcz,Sandacz,Sum,Węgorz', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Dużo zatopionych drzew', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22558, 'Starorzecze Wola Uhruska', 'starorzecze-wola-uhruska-wola-uhruska-22558', 'OXBOW', 51.3242281, 23.6322203, 'Lubelskie', 'Wola Uhruska', 'To starorzecze Bugu, położone w malowniczej, przygranicznej okolicy, charakteryzuje się płytkim, mulistym dnem i bardzo obfitą roślinnością wodną, co tworzy idealne warunki dla ryb. Brzegi są zazwyczaj bagniste i mocno zarośnięte trzciną, co utrudnia dostęp do wody, ale jednocześnie tworzy idealne warunki dla ryb, chroniąc je przed presją. Jest to doskonałe miejsce na liny, karasie pospolite i wzdręgi, które często osiągają tu imponujące rozmiary. Występują również szczupaki i okonie, polujące w gęstych zaroślach, co czyni je atrakcyjnym dla spinningistów. Wędkowanie wymaga cierpliwości i umiejętności poruszania się w trudnym terenie, często z użyciem brodzaków. W okresach suszy może częściowo wysychać, wpływając na populację ryb.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22558, 4.5, 1.1, 2.5, 'Brak', 'Wysokie', 'Silne', TRUE, TRUE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, bagnisty', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22559, 'Starorzecze Kostrzyńskie', 'starorzecze-kostrzynskie-gorzow-wielkopolski-22559', 'OXBOW', 52.6066174, 14.8287284, 'Lubuskie', 'Gorzów Wielkopolski', 'To starorzecze Odry, położone w pobliżu Kostrzyna nad Odrą, charakteryzuje się umiarkowaną głębokością i mulistym dnem, z licznymi zatopionymi drzewami i korzeniami. Brzegi są w większości zarośnięte, ale znajdą się miejsca z łatwiejszym dostępem, szczególnie dla wędkarzy z pontonem lub łodzią. Roślinność wodna jest obfita, co sprzyja rozwojowi populacji ryb spokojnego żeru oraz drapieżników. Jest to dobre łowisko na leszcze, płocie, liny i szczupaki, które są tu licznie reprezentowane. Wędkowanie z gruntu i na spinning daje tu najlepsze efekty, zwłaszcza w okolicach zatopionych przeszkód. Należy pamiętać o ryzyku zaczepów.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22559, 8.7, 1.9, 4, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', TRUE, FALSE, 'Leszcz,Płoć,Lin,Szczupak,Okoń', 'Umiarkowany, miejscami zarośnięty', TRUE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, jesień');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22560, 'Starorzecze Cerkawizna', 'starorzecze-cerkawizna-czestochowa-22560', 'OXBOW', 51.0220381, 19.4238765, 'Śląskie', 'Częstochowa', 'To starorzecze, położone w pobliżu Cerkawizny, jest stosunkowo niewielkie, ale głębokie, z dnem pokrytym grubą warstwą mułu, co świadczy o jego wieku. Brzegi są strome i w większości porośnięte gęstymi krzewami i drzewami, co utrudnia dostęp do wody, ale zapewnia rybom doskonałe schronienie. Roślinność wodna jest umiarkowana, ale w niektórych partiach tworzy zwarte dywany, gdzie ukrywają się ryby. Jest to dobre miejsce na liny, karasie pospolite oraz węgorze, które znajdują tu idealne warunki do życia i żerowania. Występują również szczupaki i okonie, polujące w głębszych partiach starorzecza. Wędkowanie wymaga cierpliwości i często poszukiwania dogodnych stanowisk, które mogą być trudno dostępne. To urokliwe, choć wymagające łowisko.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22560, 3.2, 2, 4.5, 'Brak', 'Wysokie', 'Umiarkowane', TRUE, FALSE, 'Lin,Karaś pospolity,Węgorz,Szczupak', 'Trudny, strome brzegi', TRUE, 'Dużo zatopionych drzew', 'Wiosna, lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22561, 'Starorzecze Brochowskie', 'starorzecze-brochowskie-sochaczew-22561', 'OXBOW', 52.31415, 20.2638316, 'Mazowieckie', 'Sochaczew', 'To starorzecze, położone w malowniczej okolicy Brochowa, charakteryzuje się zróżnicowanym dnem, od piaszczystych płycizn po głębsze, muliste partie, co sprzyja różnorodności fauny. Brzegi są w większości łatwo dostępne, częściowo zagospodarowane, co sprawia, że jest to popularne miejsce dla rodzin z dziećmi i początkujących wędkarzy. Roślinność wodna jest umiarkowana, skupiona głównie w zatokach i przy brzegach, tworząc naturalne kryjówki. Występują tu liczne płocie, leszcze i okonie, a także sporadycznie karpie i szczupaki, które stanowią cenne trofea. Łowisko jest idealne do wędkowania spławikowego i gruntowego, oferując relaks i szansę na złowienie różnorodnych gatunków. Jest to miejsce, gdzie można spędzić przyjemny dzień nad wodą.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22561, 7.8, 1.7, 3.8, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Płoć,Leszcz,Okoń,Karp,Szczupak', 'Dobry z wielu stron', FALSE, 'Czyste dno', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22562, 'Starorzecze Chylickie', 'starorzecze-chylickie-konstancin-jeziorna-22562', 'OXBOW', 52.0677681, 21.0443841, 'Mazowieckie', 'Konstancin-Jeziorna', 'To starorzecze, położone w pobliżu Chylice-Pólko, jest stosunkowo płytkie, z mulistym dnem i bardzo bujną roślinnością wodną, co czyni je idealnym siedliskiem dla ryb spokojnego żeru. Brzegi są w większości trudno dostępne, mocno zarośnięte trzciną i inną roślinnością, co wymaga poszukiwania dogodnych stanowisk i odpowiedniego przygotowania. Jest to doskonałe miejsce na liny, karasie pospolite i wzdręgi, które często osiągają tu imponujące rozmiary, znajdując obfitość pokarmu. Występują również szczupaki i okonie, polujące w gęstych zaroślach, co przyciąga spinningistów. Wędkowanie z pontonu lub brodzenie w woderach jest tu często koniecznością, aby skutecznie dotrzeć do ryb. Łowisko to cenią sobie wędkarze poszukujący ciszy i dzikiej przyrody.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22562, 6, 1.2, 2.8, 'Brak', 'Wysokie', 'Silne', TRUE, FALSE, 'Lin,Karaś pospolity,Wzdręga,Szczupak', 'Trudny, mocno zarośnięty trzciną', TRUE, 'Gęsta roślinność podwodna', 'Późna wiosna i lato');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22563, 'Łacha Kuligowska', 'lacha-kuligowska-kuligow-22563', 'OXBOW', 52.1932621, 21.1234293, 'Mazowieckie', 'Kuligów', 'Łacha Kuligowska to rozległe starorzecze Bugu, charakteryzujące się zróżnicowanym dnem, od piaszczystych płycizn po głębsze partie z mulistym podłożem. Brzegi są w większości łatwo dostępne, częściowo zagospodarowane, co ułatwia wędkowanie z gruntu i spławika. Roślinność wodna jest umiarkowana, skupiona głównie przy brzegach i w zatokach, tworząc naturalne schronienia. Występują tu liczne leszcze, płocie i okonie, a także sporadycznie karpie i bolenie, zwłaszcza w miejscach o silniejszym nurcie podczas połączenia z rzeką. Łowisko jest popularne, ale oferuje wiele dogodnych miejsc, dzięki czemu każdy wędkarz znajdzie coś dla siebie. Jest to idealne miejsce na całodniową wyprawę wędkarską.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22563, 12, 2, 4.3, 'Podczas wysokiej wody', 'Średnie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Okoń,Karp,Boleń', 'Dobry z wielu stron', FALSE, 'Pojedyncze korzenie i gałęzie', 'Cały sezon');
INSERT INTO map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (22564, 'Starorzecze Zabród', 'starorzecze-zabrod-gryfino-22564', 'OXBOW', 53.5266443, 14.8429829, 'Zachodniopomorskie', 'Gryfino', 'To starorzecze Odry, położone w pobliżu Zabrodu, charakteryzuje się dość głęboką rynną i zróżnicowanym dnem, gdzie muł przeplata się z twardszymi partiami, co tworzy ciekawe środowisko. Brzegi są w większości stabilne, choć miejscami porośnięte drzewami i krzewami, co wymaga ostrożności podczas poruszania się. Roślinność wodna jest umiarkowana, co sprzyja zarówno drapieżnikom, jak i rybom spokojnego żeru, zapewniając im obfitość pokarmu. Łowisko jest znane z dużych leszczy, płoci oraz szczupaków i sandaczy, zwłaszcza w miejscach o zmiennym dnie, które są atrakcyjne dla spinningistów. Wędkowanie gruntowe i spinningowe przynosi tu dobre rezultaty, oferując szansę na złowienie okazałych egzemplarzy. To popularne, ale jednocześnie wymagające łowisko.', NULL);
INSERT INTO map_oxbows (id, area_hectares, avg_depth, max_depth, river_connection, silting_level, overgrowth_level, oxygen_depletion_risk, dries_up, dominant_fish, shore_access, waders_required, snags_level, best_seasons) VALUES (22564, 11.5, 2.3, 5, 'Podczas wysokiej wody', 'Niskie', 'Umiarkowane', FALSE, FALSE, 'Leszcz,Płoć,Szczupak,Sandacz,Okoń', 'Umiarkowany, miejscami zarośnięty', FALSE, 'Pojedyncze korzenie i gałęzie', 'Wiosna, lato, jesień');
